UPDATE location_pages SET travel_ideas_json = '[{"title": "Adana Merkez Park", "summary": "Seyhan Nehri kıyısında uzanan bu büyük şehir parkı, yürüyüş ve bisiklet yolları, göleti ve yeşil alanlarıyla Çukurova ilçesinde en çok ziyaret edilen dinlenme ve eğlence alanlarından biridir.", "place_query": "Adana Merkez Park, Çukurova, Adana"}, {"title": "Adana Bilim ve Teknoloji Üniversitesi Kampüsü", "summary": "Modern mimarisi ve geniş kampüs alanıyla dikkat çeken bu üniversite, özellikle teknoloji ve bilim meraklıları için ilgi çekici bir gezi noktasıdır.", "place_query": "Adana Bilim ve Teknoloji Üniversitesi, Çukurova, Adana"}, {"title": "Çukurova Üniversitesi Kampüsü", "summary": "Türkiye''nin en büyük kampüslerinden birine sahip olan Çukurova Üniversitesi, botanik bahçesi ve çeşitli sosyal tesisleriyle doğa ve akademik atmosferi bir arada sunar.", "place_query": "Çukurova Üniversitesi Kampüsü, Çukurova, Adana"}, {"title": "Seyhan Baraj Gölü ve Çevresi", "summary": "Seyhan Nehri üzerinde yer alan baraj gölü, çevresindeki yürüyüş yolları ve piknik alanlarıyla hem doğa severler hem de şehirden kaçmak isteyenler için popüler bir kaçış noktasıdır.", "place_query": "Seyhan Baraj Gölü, Çukurova, Adana"}, {"title": "Adana Devlet Tiyatrosu (Çukurova Sahnesi)", "summary": "Kültür sanat etkinlikleri için önemli bir merkez olan bu tiyatro sahnesi, yıl boyunca çeşitli oyun ve gösterilere ev sahipliği yaparak ziyaretçilere keyifli anlar yaşatır.", "place_query": "Adana Devlet Tiyatrosu Çukurova Sahnesi, Adana"}, {"title": "Çukurova AVM", "summary": "Geniş mağaza yelpazesi, yeme-içme alanları ve sinema salonlarıyla bölgenin en büyük alışveriş merkezlerinden biri olan Çukurova AVM, alışveriş ve eğlence için ideal bir duraktır.", "place_query": "Çukurova AVM, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8ae1e71b-6999-4a8d-9810-b105c9809291'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Feke Kalesi", "summary": "Tarihi bir Bizans kalesi olan Feke Kalesi, ilçe merkezine hakim bir tepe üzerinde yer alır. Zamana meydan okuyan surları ve etkileyici manzarasıyla tarih ve doğa severler için benzersiz bir durak noktasıdır.", "place_query": "Feke Kalesi, Feke, Adana"}, {"title": "Feke Barajı ve Mesire Alanı", "summary": "Göksu Nehri üzerinde kurulu baraj gölü, çevresindeki piknik alanları ve yemyeşil doğasıyla serinlemek ve huzur bulmak isteyenler için idealdir. Özellikle yaz aylarında yerli halkın uğrak noktasıdır.", "place_query": "Feke Barajı, Feke, Adana"}, {"title": "Göksu Nehri Kenarı (Feke)", "summary": "İlçe merkezinden geçen Göksu Nehri''nin berrak suları ve çevresindeki doğal yürüyüş parkurları, doğa ile iç içe vakit geçirmek isteyenler için mükemmel bir ortam sunar. Nehir kenarında kamp kurmak da popülerdir.", "place_query": "Göksu Nehri Feke Adana"}, {"title": "Akarca Şelalesi", "summary": "Feke ilçe merkezine yaklaşık 10 kilometre uzaklıkta bulunan bu şelale, yemyeşil bitki örtüsü arasından dökülen sularıyla görsel bir şölen sunar. Doğa yürüyüşleri ve fotoğrafçılık için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Akarca Şelalesi Feke Adana"}, {"title": "Feke Taş Köprü", "summary": "Tarihi bir Roma veya Osmanlı dönemi yapısı olduğu tahmin edilen bu taş köprü, ilçenin simge yapılarından biridir. Göksu Nehri üzerinde yer alan köprü, hem mimari güzelliği hem de çevresindeki doğal manzara ile dikkat çeker.", "place_query": "Feke Taş Köprü Feke Adana"}, {"title": "Feke Yaylaları (Örneğin; Süphandere Yaylası)", "summary": "İlçe genelinde yaylacılık kültürü yaygındır; özellikle Süphandere Yaylası, yemyeşil çam ormanları ve temiz havasıyla şehrin gürültüsünden kaçmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Süphandere Yaylası Feke Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '721cd6dd-a824-4fc6-bc81-cbfacaed732c'::uuid;
