UPDATE location_pages SET travel_ideas_json = '[{"title": "Kozan Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu görkemli kale, bölgeye hakim manzarası ve Orta Çağ''dan kalma surlarıyla ziyaretçilerine eşsiz bir tarih ve doğa deneyimi sunuyor.", "place_query": "Kozan Kalesi, Kozan, Adana"}, {"title": "Anavarza Antik Kenti", "summary": "Roma İmparatorluğu döneminde önemli bir yerleşim olan bu antik kent, etkileyici kalıntıları, zafer takı ve mozaikleriyle tarih meraklıları için büyüleyici bir durak.", "place_query": "Anavarza Antik Kenti, Kozan, Adana"}, {"title": "Şahmeran Türbesi", "summary": "Efsanelere konu olan Şahmeran''ın türbesi olarak bilinen bu kutsal alan, hem mistik atmosferi hem de bölge halkı için taşıdığı manevi değerle sıkça ziyaret ediliyor.", "place_query": "Şahmeran Türbesi, Kozan, Adana"}, {"title": "Kozan Barajı ve Mesire Alanı", "summary": "Doğal güzellikleriyle öne çıkan bu baraj gölü çevresi, piknik yapmak, yürüyüşe çıkmak ve huzurlu bir gün geçirmek isteyenler için ideal bir kaçış noktası.", "place_query": "Kozan Barajı, Kozan, Adana"}, {"title": "Kozan Ulu Camii", "summary": "Osmanlı dönemine ait zarif mimarisi ve taş işçiliğiyle dikkat çeken bu cami, şehrin merkezinde yer alarak hem ibadet hem de tarihi bir yapı olarak ilgi görüyor.", "place_query": "Kozan Ulu Camii, Kozan, Adana"}, {"title": "Kozan Taş Köprü", "summary": "Tarihi Roma dönemine kadar uzanan bu taş köprü, günümüzde hala kullanılmakta olup, bölgenin geçmişine tanıklık eden önemli bir mimari eserdir.", "place_query": "Kozan Taş Köprü, Kozan, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '011e1b69-53ee-4166-b429-d6359049ed26'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pozantı Kalesi", "summary": "Tarihi İpek Yolu üzerinde stratejik bir noktada yer alan bu Orta Çağ kalesi, bölgenin hakim bir tepesinden muhteşem manzaralar sunar. Ziyaretçiler hem tarihi dokuyu hissedebilir hem de çevredeki Toros Dağları''nın eşsiz görüntüsünü izleyebilir.", "place_query": "Pozantı Kalesi, Pozantı, Adana"}, {"title": "Pozantı Kapısı (Gülek Boğazı)", "summary": "Toros Dağları''nı aşan tarihi Gülek Boğazı''nın en dar ve etkileyici noktasıdır. Doğa yürüyüşleri ve fotoğrafçılık için popüler olan bu geçit, binlerce yıllık tarihi yolculuğa tanıklık etmek isteyenler için ideal bir duraktır.", "place_query": "Gülek Boğazı, Pozantı, Adana"}, {"title": "Pozantı Eski Çarşı ve Tarihi Evler", "summary": "İlçe merkezinde yer alan bu bölge, Osmanlı döneminden kalma taş ve ahşap mimarisiyle dikkat çeker. Dar sokaklarında yürürken geçmişin izlerini sürebilir ve yöresel ürünler satan dükkanları keşfedebilirsiniz.", "place_query": "Pozantı Eski Çarşı, Pozantı, Adana"}, {"title": "Armutoluk Yaylası", "summary": "Pozantı''nın serin ve yeşil yaylalarından biri olan Armutoluk, özellikle yaz aylarında şehir gürültüsünden kaçmak isteyenler için huzurlu bir kaçış noktasıdır. Çam ormanları arasında piknik yapabilir ve temiz havanın tadını çıkarabilirsiniz.", "place_query": "Armutoluk Yaylası, Pozantı, Adana"}, {"title": "Sarımsak Dağı Doğal Yaşam Alanı", "summary": "Bölgenin en yüksek zirvelerinden biri olan Sarımsak Dağı, zengin bitki örtüsü ve yaban hayatıyla doğa severler için keşfedilmeyi bekleyen bir cennettir. Trekking ve kamp yapmak isteyenler için zorlu ama ödüllendirici rotalar sunar.", "place_query": "Sarımsak Dağı, Pozantı, Adana"}, {"title": "Pozantı Mesire Alanı", "summary": "İlçe merkezine yakın, akarsu kenarında kurulu bu mesire alanı, aileler ve gruplar için ideal bir piknik ve dinlenme noktasıdır. Yeşillikler içinde mangal keyfi yapabilir veya dere kenarında vakit geçirebilirsiniz.", "place_query": "Pozantı Mesire Alanı, Pozantı, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '54170e9c-f7a0-4e8d-80de-c13c9b11c705'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saimbeyli Kalesi", "summary": "Tarihi bir kaya üzerine inşa edilmiş olan bu kale, bölgeye hakim manzarası ve Orta Çağ''dan kalma yapısıyla dikkat çeker. Ziyaretçiler hem tarihi dokuyu hissedebilir hem de çevrenin panoramik fotoğraflarını çekebilir.", "place_query": "Saimbeyli Kalesi, Saimbeyli, Adana"}, {"title": "Obruk Şelalesi", "summary": "Doğal bir kanyon içinde yer alan Obruk Şelalesi, yemyeşil doğası ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle yaz aylarında bölge halkının uğrak yeridir.", "place_query": "Obruk Şelalesi, Saimbeyli, Adana"}, {"title": "Saimbeyli Eski Evleri", "summary": "Taş ve ahşap mimarisiyle dikkat çeken bu tarihi evler, ilçenin kültürel geçmişini yansıtır. Dar sokaklarda yürüyerek geleneksel Adana mimarisini yakından görebilirsiniz.", "place_query": "Saimbeyli Eski Evleri, Saimbeyli, Adana"}, {"title": "Yerköprü Şelalesi ve Mesire Alanı", "summary": "Doğal bir köprü oluşumu ve şelalesiyle ünlü bu alan, kamp ve piknik yapmak isteyenler için huzurlu bir ortam sunar. Çevresindeki yürüyüş parkurları doğa severler için keşfedilmeyi bekler.", "place_query": "Yerköprü Şelalesi, Saimbeyli, Adana"}, {"title": "Saimbeyli Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgenin arkeolojik ve etnografik eserlerini sergiler. Hitit, Roma ve Osmanlı dönemlerine ait buluntular ilçenin tarihine ışık tutar.", "place_query": "Saimbeyli Müzesi, Saimbeyli, Adana"}, {"title": "Kızıldağ Yaylası", "summary": "Yemyeşil çam ormanları ve temiz havasıyla ünlü olan bu yayla, özellikle yaz sıcağından kaçmak isteyenler için serin bir kaçış noktasıdır. Yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Kızıldağ Yaylası, Saimbeyli, Adana"}, {"title": "Himmetli Yaylası", "summary": "Doğal güzellikleri ve sakin atmosferiyle bilinen Himmetli Yaylası, doğa yürüyüşü ve kamp için popüler bir duraktır. Bölgedeki endemik bitki türleri doğa fotoğrafçılarını cezbeder.", "place_query": "Himmetli Yaylası, Saimbeyli, Adana"}, {"title": "Saimbeyli Pazarı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu pazar, ilçenin kültürel dokusunu yansıtır. Özellikle organik meyve-sebze ve el yapımı hediyelik eşyalar için ziyaret edilebilir.", "place_query": "Saimbeyli Pazarı, Saimbeyli, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '56857762-540d-4165-8f4e-8fa684246eab'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Adana Bilim ve Teknoloji Üniversitesi Kampüsü", "summary": "Modern mimarisi ve geniş yeşil alanlarıyla dikkat çeken kampüs, özellikle fotoğrafçılık ve doğa yürüyüşü için popülerdir. İçerisinde bulunan gölet ve yürüyüş yolları ziyaretçilere huzurlu bir ortam sunar.", "place_query": "Adana Bilim ve Teknoloji Üniversitesi Kampüsü, Sarıçam, Adana"}, {"title": "Sarıçam Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla hafta sonu kaçamakları için ideal olan bu gölet, piknik alanları ve çocuk oyun parklarıyla aileler tarafından sıkça tercih edilir. Etrafındaki çam ağaçları sayesinde serin bir atmosfer sunar.", "place_query": "Sarıçam Göleti Mesire Alanı, Sarıçam, Adana"}, {"title": "Adana Etnografya Müzesi (Kurtuluş Caddesi''ndeki şube)", "summary": "Adana''nın zengin kültürel geçmişini yansıtan bu müze, yöresel kıyafetler, takılar ve günlük yaşam eşyalarıyla dikkat çeker. Sarıçam ilçesine bağlı olmasa da yakın mesafede bulunması nedeniyle sıkça ziyaret edilir.", "place_query": "Adana Etnografya Müzesi, Kurtuluş Caddesi, Adana"}, {"title": "Çatalan Barajı ve Çevresi", "summary": "Sarıçam sınırları içinde yer alan Çatalan Barajı, su sporları ve balıkçılık için uygun bir ortam sunar. Baraj çevresindeki yeşil alanlar ise doğa yürüyüşleri ve manzara fotoğrafçılığı için idealdir.", "place_query": "Çatalan Barajı, Sarıçam, Adana"}, {"title": "Adana Organize Sanayi Bölgesi (AOSB) Rekreasyon Alanı", "summary": "Sanayi bölgesi içinde beklenmedik bir yeşil vaha olan bu alan, çalışanlar ve ziyaretçiler için dinlenme imkanı sunar. Küçük bir gölet ve yürüyüş parkurlarıyla dikkat çeker.", "place_query": "Adana Organize Sanayi Bölgesi Rekreasyon Alanı, Sarıçam, Adana"}, {"title": "Sarıçam Belediyesi Millet Bahçesi", "summary": "Yeni düzenlenen bu millet bahçesi, geniş çim alanları, yürüyüş yolları ve çocuk oyun alanlarıyla ailelerin uğrak noktasıdır. Özellikle akşam saatlerinde aydınlatmasıyla keyifli bir atmosfer sunar.", "place_query": "Sarıçam Belediyesi Millet Bahçesi, Sarıçam, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ea40593d-e66e-420e-bf5b-a59b06f4ab75'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sabancı Merkez Camii", "summary": "Adana''nın simgesi haline gelmiş bu görkemli cami, Osmanlı ve Selçuklu mimarisinin modern yorumuyla dikkat çeker. Altı minaresi ve devasa ana kubbesiyle hem ibadet hem de ziyaretçi akınına uğrar.", "place_query": "Sabancı Merkez Camii, Seyhan, Adana"}, {"title": "Adana Arkeoloji Müzesi", "summary": "Misis ve Tarsus bölgesinden çıkarılan Hitit, Roma ve Bizans dönemine ait eserlerin sergilendiği bu müze, tarih meraklıları için eşsiz bir durak. Lahitler, mozaikler ve heykeller en dikkat çeken parçalar arasında.", "place_query": "Adana Arkeoloji Müzesi, Seyhan, Adana"}, {"title": "Taşköprü (Adana Taşköprü)", "summary": "Roma İmparatorluğu döneminde inşa edilen bu 2000 yıllık köprü, Seyhan Nehri üzerinde uzanır ve günümüzde hâlâ yaya trafiğine açıktır. Özellikle gün batımında nehir manzarasıyla büyüleyici bir atmosfer sunar.", "place_query": "Taşköprü, Seyhan, Adana"}, {"title": "Büyük Saat Kulesi", "summary": "Adana''nın kalbindeki bu tarihi saat kulesi, 1882 yılında inşa edilmiş olup kentin en önemli sembollerinden biridir. Çevresindeki tarihi çarşı ve kafelerle birlikte şehrin nabzını tutan bir buluşma noktasıdır.", "place_query": "Büyük Saat Kulesi, Seyhan, Adana"}, {"title": "Merkez Park", "summary": "Seyhan Nehri kıyısında uzanan bu geniş park, yürüyüş yolları, bisiklet parkuru ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme alanıdır. Nehir kenarındaki kafelerde çay içip manzaranın tadını çıkarabilirsiniz.", "place_query": "Merkez Park, Seyhan, Adana"}, {"title": "Atatürk Evi Müzesi", "summary": "Atatürk''ün Adana ziyaretlerinde kaldığı bu tarihi konak, günümüzde müze olarak hizmet vermektedir. O döneme ait eşyalar ve fotoğraflarla Kurtuluş Savaşı''nın izlerini yakından görebilirsiniz.", "place_query": "Atatürk Evi Müzesi, Seyhan, Adana"}, {"title": "Ramazanoğlu Konağı", "summary": "Adana''nın en eski sivil mimari örneklerinden biri olan bu konak, restore edilerek kültür merkezine dönüştürülmüştür. Avlusunda geleneksel Adana evlerinin atmosferini soluyabilir, sergilere katılabilirsiniz.", "place_query": "Ramazanoğlu Konağı, Seyhan, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '93a1b413-2323-4ec7-899f-c9fd61236066'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şar Ören Yeri (Comona)", "summary": "Hitit ve Roma dönemlerine ait kalıntılarıyla ünlü antik kent. Özellikle kaya mezarları ve su kemerleri dikkat çeker; tarih meraklıları için önemli bir duraktır.", "place_query": "Şar Ören Yeri, Tufanbeyli, Adana"}, {"title": "Tufanbeyli Kalesi", "summary": "Orta Çağ''dan kalma bu kale, bölgeye hakim bir tepe üzerinde yer alır. Çevresindeki doğal manzara ve tarihi atmosfer ziyaretçileri cezbeder.", "place_query": "Tufanbeyli Kalesi, Tufanbeyli, Adana"}, {"title": "Meryemçil Köyü Mağaraları", "summary": "Doğal oluşumlu mağaralar, bölgenin jeolojik yapısını gözler önüne serer. Mağara turizmi ve doğa yürüyüşü için idealdir.", "place_query": "Meryemçil Köyü Mağaraları, Tufanbeyli, Adana"}, {"title": "Tufanbeyli Yaylaları (Örneğin: Kızılağaç Yaylası)", "summary": "Serin havası ve yeşil doğasıyla yaz aylarında kaçış noktasıdır. Yayla evleri, piknik alanları ve doğa yürüyüşleri popülerdir.", "place_query": "Kızılağaç Yaylası, Tufanbeyli, Adana"}, {"title": "Tufanbeyli Göleti", "summary": "Çevresinde mesire alanı bulunan bu gölet, piknik ve olta balıkçılığı için tercih edilir. Sakin bir doğa kaçamağı sunar.", "place_query": "Tufanbeyli Göleti, Tufanbeyli, Adana"}, {"title": "Pınarlar Köyü Tarihi Kilisesi", "summary": "Bölgedeki Rumlardan kalma taş yapılı bir kilisedir. Mimari detayları ve tarihi dokusuyla fotoğrafçıların ilgisini çeker.", "place_query": "Pınarlar Köyü Kilisesi, Tufanbeyli, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2460cd24-5e81-4a37-ad9d-add469969a03'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yumurtalık Sahili ve Plajları", "summary": "Adana''nın en güzel doğal plajlarına ev sahipliği yapan Yumurtalık Sahili, uzun kumsalı ve berrak deniziyle yüzme, güneşlenme ve deniz keyfi için ideal bir noktadır.", "place_query": "Yumurtalık Plajı, Adana"}, {"title": "Aegeus Antik Kenti", "summary": "Helenistik ve Roma dönemlerine ait kalıntılarıyla ünlü Aegeus Antik Kenti, Yumurtalık merkezinde yer alır ve bölgenin zengin tarihine ışık tutan önemli bir arkeolojik alandır.", "place_query": "Aegeus Antik Kenti, Yumurtalık, Adana"}, {"title": "Yumurtalık Kalesi", "summary": "Deniz kıyısında yükselen bu tarihi kale, Orta Çağ''dan kalma surları ve etkileyici manzarasıyla ziyaretçilere hem tarih hem de panoramik bir deniz görüşü sunar.", "place_query": "Yumurtalık Kalesi, Adana"}, {"title": "Şeytan Deresi", "summary": "Doğal güzelliği ve serin sularıyla ünlü Şeytan Deresi, özellikle yaz aylarında piknik ve doğa yürüyüşü yapmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Şeytan Deresi, Yumurtalık, Adana"}, {"title": "Yumurtalık Lagünü (Akyatan Lagünü)", "summary": "Kuş gözlemciliği için önemli bir alan olan bu lagün, flamingolar ve diğer su kuşlarına ev sahipliği yapar; doğaseverler için eşsiz bir ekosistem sunar.", "place_query": "Akyatan Lagünü, Yumurtalık, Adana"}, {"title": "Çamlık Piknik Alanı", "summary": "Çam ağaçlarıyla kaplı bu geniş alan, aileler ve gruplar için mangal, piknik ve dinlenme imkanı sağlayan popüler bir mesire yeridir.", "place_query": "Çamlık Piknik Alanı, Yumurtalık, Adana"}, {"title": "Yumurtalık Marina", "summary": "Modern bir yat limanı olan Yumurtalık Marina, deniz tutkunları için bağlama ve hizmet imkanı sunarken, çevresindeki kafe ve restoranlarla da keyifli bir gezinti alanıdır.", "place_query": "Yumurtalık Marina, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '95db693e-4ffa-4329-9ae2-fe540f6bd011'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Besni Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu kale, bölgeye hakim manzarası ve antik kalıntılarıyla ziyaretçilerine eşsiz bir tarih ve doğa deneyimi sunar.", "place_query": "Besni Kalesi, Besni, Adıyaman"}, {"title": "Sofraz Höyük", "summary": "Önemli bir arkeolojik alan olan Sofraz Höyük, Hitit ve Roma dönemlerine ait buluntularıyla tarih meraklıları için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Sofraz Höyük, Besni, Adıyaman"}, {"title": "Şambayat Barajı", "summary": "Doğa ile iç içe huzurlu bir ortam arayanlar için ideal olan baraj, piknik alanları ve çevresindeki yeşil doğasıyla hafta sonu kaçamakları için popüler bir duraktır.", "place_query": "Şambayat Barajı, Besni, Adıyaman"}, {"title": "Besni Ulu Camii", "summary": "Osmanlı dönemi mimarisinin güzel bir örneği olan bu tarihi cami, taş işçiliği ve sade yapısıyla dikkat çeker; hem ibadet hem de tarihi doku için ziyaret edilir.", "place_query": "Besni Ulu Camii, Besni, Adıyaman"}, {"title": "Kesmetepe Köprüsü", "summary": "Tarihi bir taş köprü olan Kesmetepe Köprüsü, çevresindeki doğal manzara ile fotoğrafçılar ve tarih tutkunları için ilgi çekici bir noktadır.", "place_query": "Kesmetepe Köprüsü, Besni, Adıyaman"}, {"title": "Besni Müzesi", "summary": "Bölgenin arkeolojik ve etnografik zenginliklerini sergileyen bu küçük müze, özellikle Sofraz Höyük''ten çıkarılan eserlerle tarihe ışık tutar.", "place_query": "Besni Müzesi, Besni, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '265dd9ef-bd13-4fb2-bc75-d5900b7d4bcc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çelikhan Kanyonu", "summary": "Doğal güzelliği ve yürüyüş parkurlarıyla ünlü olan bu kanyon, ziyaretçilerine eşsiz bir doğa deneyimi sunar. Özellikle bahar aylarında yeşilin her tonunu görebilirsiniz.", "place_query": "Çelikhan Kanyonu, Adıyaman"}, {"title": "Çelikhan Merkez Camii", "summary": "Tarihi dokusu ve mimarisiyle dikkat çeken bu cami, ilçenin en önemli ibadet ve kültür merkezlerinden biridir.", "place_query": "Çelikhan Merkez Camii, Adıyaman"}, {"title": "Kızılin Köprüsü", "summary": "Tarihi bir taş köprü olan Kızılin Köprüsü, bölgenin geçmişine ışık tutan önemli bir yapıdır. Çevresindeki doğal manzara da fotoğrafçılar için idealdir.", "place_query": "Kızılin Köprüsü, Çelikhan, Adıyaman"}, {"title": "Çelikhan Şelalesi", "summary": "Şehir merkezine yakın konumuyla kolayca ulaşılabilen bu şelale, piknik ve dinlenme alanlarıyla aileler için popüler bir kaçış noktasıdır.", "place_query": "Çelikhan Şelalesi, Adıyaman"}, {"title": "Sülüklü Göl", "summary": "Doğal bir göl olan Sülüklü Göl, sakin atmosferi ve çevresindeki yürüyüş yollarıyla doğa severlerin uğrak noktasıdır.", "place_query": "Sülüklü Göl, Çelikhan, Adıyaman"}, {"title": "Çelikhan Yaylası", "summary": "Yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için ideal olan bu yayla, muhteşem manzaralar sunar.", "place_query": "Çelikhan Yaylası, Adıyaman"}, {"title": "Pınarbaşı Mesire Alanı", "summary": "Piknik ve kamp yapmak için uygun olan bu mesire alanı, temiz havası ve doğal su kaynağıyla bilinir.", "place_query": "Pınarbaşı Mesire Alanı, Çelikhan, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f9beae5e-f088-40ce-b388-f3263170a89e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gerger Kalesi", "summary": "Kommagene Krallığı dönemine ait bu tarihi kale, ilçe merkezine hakim bir tepede yer alır. Ziyaretçilerine hem muhteşem bir manzara hem de antik dönemin izlerini görme fırsatı sunar.", "place_query": "Gerger Kalesi, Gerger, Adıyaman"}, {"title": "Sesönk Yaylası", "summary": "Doğal güzellikleriyle ünlü bu yayla, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler için idealdir. Yemyeşil bitki örtüsü ve temiz havasıyla huzur verir.", "place_query": "Sesönk Yaylası, Gerger, Adıyaman"}, {"title": "Gerger Çayı", "summary": "İlçenin ortasından geçen bu akarsu, çevresindeki piknik alanları ve doğal yapısıyla yerli halkın ve ziyaretçilerin uğrak noktasıdır. Özellikle sıcak günlerde serinlemek için idealdir.", "place_query": "Gerger Çayı, Gerger, Adıyaman"}, {"title": "Gümüşkaş Köyü Kaya Mezarları", "summary": "Antik dönemden kalma bu kaya mezarları, bölgenin tarihine ışık tutan önemli arkeolojik kalıntılardır. Tarih meraklıları için keşfedilmeyi bekleyen etkileyici bir duraktır.", "place_query": "Gümüşkaş Köyü Kaya Mezarları, Gerger, Adıyaman"}, {"title": "Gerger Ulu Camii", "summary": "Tarihi bir yapı olan bu cami, ilçenin merkezinde yer alır ve mimarisiyle dikkat çeker. Hem ibadet hem de tarihi bir mekan olarak ziyaret edilebilir.", "place_query": "Gerger Ulu Camii, Gerger, Adıyaman"}, {"title": "Gerger Şelalesi", "summary": "Doğa ile iç içe bir ortam sunan bu şelale, özellikle bahar aylarında suyunun coşmasıyla görsel bir şölen yaratır. Piknik ve fotoğrafçılık için popüler bir noktadır.", "place_query": "Gerger Şelalesi, Gerger, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '723ffdc9-78b7-4635-aad0-61ed46bc91b8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölbaşı Gölü (Azaplı Gölü)", "summary": "İlçe merkezine yakın konumda bulunan bu doğal göl, kuş gözlemciliği ve piknik için ideal bir alandır. Özellikle göçmen kuşların uğrak noktası olan göl, huzurlu atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Gölbaşı Gölü, Gölbaşı, Adıyaman"}, {"title": "Gölbaşı Şelalesi", "summary": "İlçenin doğal güzelliklerinden biri olan şelale, özellikle bahar aylarında coşkun akışıyla görsel bir şölen sunar. Çevresindeki yeşil alanlar mesire yeri olarak kullanılmaktadır.", "place_query": "Gölbaşı Şelalesi, Gölbaşı, Adıyaman"}, {"title": "Gölbaşı Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale kalıntıları, bölgenin antik dönemlerine ışık tutar. Zirveden ilçe ve çevresinin panoramik manzarası izlenebilir.", "place_query": "Gölbaşı Kalesi, Gölbaşı, Adıyaman"}, {"title": "Karadağ Kaya Mezarları", "summary": "Gölbaşı yakınlarındaki bu arkeolojik alan, Roma dönemine ait kaya oyma mezarlarıyla dikkat çeker. Tarih meraklıları için önemli bir keşif noktasıdır.", "place_query": "Karadağ Kaya Mezarları, Gölbaşı, Adıyaman"}, {"title": "Gölbaşı Mesire Alanı", "summary": "Aileler ve doğa severler için düzenlenmiş bu mesire yeri, yeşillikler içinde yürüyüş yapma ve mangal keyfi imkanı sunar. Hafta sonu kaçamakları için popüler bir duraktır.", "place_query": "Gölbaşı Mesire Alanı, Gölbaşı, Adıyaman"}, {"title": "Aktopraklı Höyüğü", "summary": "İlçe sınırlarında yer alan bu höyük, erken dönem yerleşim izleri taşıyan arkeolojik bir sit alanıdır. Bölgenin eski çağlardaki yaşamına dair ipuçları sunar.", "place_query": "Aktopraklı Höyüğü, Gölbaşı, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '80db0bf7-df53-45f1-87a4-0f0dad243ad6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nemrut Dağı Ören Yeri", "summary": "UNESCO Dünya Mirası listesinde yer alan bu eşsiz dağ, Kral I. Antiochos''un dev heykelleri ve tümülüsüyle ünlüdür. Gün doğumu ve gün batımı manzaraları, ziyaretçilere unutulmaz bir deneyim sunar.", "place_query": "Nemrut Dağı Ören Yeri, Kahta, Adıyaman"}, {"title": "Cendere Köprüsü", "summary": "Roma İmparatorluğu döneminde inşa edilen bu tarihi köprü, 2000 yılı aşkın süredir ayakta durmaktadır. Kahta Çayı üzerindeki görkemli yapısı ve çevresindeki doğal güzellikler fotoğrafçılar için idealdir.", "place_query": "Cendere Köprüsü, Kahta, Adıyaman"}, {"title": "Arsameia Ören Yeri (Eski Kale)", "summary": "Kommagene Krallığı''nın önemli şehirlerinden biri olan Arsameia, kaya kabartmaları ve antik kalıntılarıyla tarih meraklılarını cezbeder. Özellikle Antiochos-Herakles tokalaşma steli burada görülmeye değerdir.", "place_query": "Arsameia Ören Yeri, Kahta, Adıyaman"}, {"title": "Kahta Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde bulunan bu ortaçağ kalesi, hem tarihi dokusu hem de panoramik Kahta manzarasıyla dikkat çeker. Kale içindeki yapı kalıntıları ve surlar keşfedilmeyi bekler.", "place_query": "Kahta Kalesi, Kahta, Adıyaman"}, {"title": "Atatürk Barajı ve Gölü", "summary": "Türkiye''nin en büyük barajlarından biri olan Atatürk Barajı, devasa gölü ve çevresindeki piknik alanlarıyla doğa tutkunlarına huzurlu bir kaçış sunar. Tekne turları ve balıkçılık da popüler aktiviteler arasındadır.", "place_query": "Atatürk Barajı, Kahta, Adıyaman"}, {"title": "Karakuş Tümülüsü", "summary": "Kommagene Krallığı''na ait bir diğer önemli mezar anıtı olan Karakuş Tümülüsü, üzerinde kartal heykeli bulunan sütunlarıyla tanınır. Burası, Nemrut Dağı''nın gölgesinde kalmış olsa da tarihi atmosferiyle etkileyicidir.", "place_query": "Karakuş Tümülüsü, Kahta, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '824f8f1e-507f-4872-a656-4aa64f16cd5d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nemrut Dağı Ören Yeri", "summary": "UNESCO Dünya Mirası listesinde yer alan bu eşsiz antik alan, Kommagene Krallığı''na ait dev heykelleri ve gün doğumu/gün batımı manzarasıyla ünlüdür. Ziyaretçiler, 2150 metre yükseklikteki bu mistik atmosferde tarihe tanıklık eder.", "place_query": "Nemrut Dağı Ören Yeri, Adıyaman"}, {"title": "Cendere Köprüsü", "summary": "Roma İmparatorluğu döneminden kalma bu etkileyici taş köprü, 2000 yıllık geçmişiyle ayakta kalmayı başarmıştır. Kahta Çayı üzerinde yer alan köprü, özellikle fotoğrafçılar ve tarih meraklıları için popüler bir duraktır.", "place_query": "Cendere Köprüsü, Kahta, Adıyaman"}, {"title": "Arsameia Antik Kenti", "summary": "Kommagene Krallığı''nın ikinci büyük kenti olan Arsameia, kaya kabartmaları ve antik tünelleriyle dikkat çeker. Burada bulunan Antiochos-Theos heykeli ve kraliyet yazıtları, bölgenin zengin tarihini gözler önüne serer.", "place_query": "Arsameia Antik Kenti, Kahta, Adıyaman"}, {"title": "Adıyaman Müzesi", "summary": "Bölgedeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği bu modern müze, Nemrut Dağı ve çevresindeki antik kentlerden getirilen heykel, mozaik ve yazıtlara ev sahipliği yapar. Tarih meraklılarının mutlaka görmesi gereken bir noktadır.", "place_query": "Adıyaman Müzesi, Adıyaman Merkez"}, {"title": "Perre Antik Kenti", "summary": "Adıyaman şehir merkezine sadece 5 km uzaklıkta bulunan bu antik kent, Roma ve Bizans dönemine ait kaya mezarları, mozaikler ve kalıntılarıyla ünlüdür. Özellikle devasa kaya mezarları, ziyaretçileri büyüler.", "place_query": "Perre Antik Kenti, Adıyaman Merkez"}, {"title": "Gerger Kalesi", "summary": "Sarp bir kaya üzerine inşa edilmiş olan bu tarihi kale, Fırat Nehri manzarasıyla nefes kesicidir. Kommagene Krallığı dönemine ait kalıntılar ve kral mezarı, kaleyi tarih ve doğa tutkunları için cazip kılar.", "place_query": "Gerger Kalesi, Gerger, Adıyaman"}, {"title": "Atatürk Barajı ve Gölü", "summary": "Türkiye''nin en büyük barajlarından biri olan Atatürk Barajı, devasa gölü ve çevresindeki piknik alanlarıyla doğa severler için ideal bir kaçış noktasıdır. Tekne turları ve balıkçılık gibi aktiviteler de yapılabilmektedir.", "place_query": "Atatürk Barajı, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aaee7e97-c2d4-47f5-8b89-40a9241257b4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Samsat Höyüğü (Antik Kommagene Kraliyet Merkezi)", "summary": "Samsat''ın en önemli tarihi alanı olan höyük, Kommagene Krallığı''nın başkenti Samosata''nın kalıntılarını barındırır. Atatürk Barajı suları altında kalmış olsa da, bölgedeki kazı çalışmaları ve yükseltideki görünümüyle tarih meraklıları için eşsiz bir durak noktasıdır.", "place_query": "Samsat Höyüğü, Samsat, Adıyaman"}, {"title": "Samsat Kalesi", "summary": "Fırat Nehri kıyısında stratejik bir noktada yer alan tarihi kale, Roma ve Bizans dönemlerinde önemli bir savunma yapısı olarak kullanılmıştır. Kalıntılar arasında yürüyüş yaparken Fırat Nehri manzarası eşliğinde bölgenin binlerce yıllık geçmişine tanıklık edebilirsiniz.", "place_query": "Samsat Kalesi, Samsat, Adıyaman"}, {"title": "Atatürk Barajı ve Gölü (Samsat Kıyısı)", "summary": "Türkiye''nin en büyük baraj göllerinden biri olan Atatürk Barajı''nın Samsat kıyıları, huzurlu bir doğa kaçamağı arayanlar için idealdir. Gökyüzü ile suyun buluştuğu bu manzarada piknik yapabilir, fotoğrafçılıkla ilgilenebilir veya sakin bir yürüyüşün tadını çıkarabilirsiniz.", "place_query": "Atatürk Barajı Samsat Kıyısı, Adıyaman"}, {"title": "Samsat Müzesi (Adıyaman Müzesi Samsat Bölümü)", "summary": "Samsat Höyüğü''nde yapılan kazılarda ortaya çıkarılan eserlerin sergilendiği bu müze, bölgenin zengin tarihini gözler önüne seriyor. Hitit, Roma ve Kommagene dönemlerine ait heykelcikler, seramikler ve sikkeler, ziyaretçilere antik dünyaya kısa bir yolculuk vaat ediyor.", "place_query": "Adıyaman Müzesi, Adıyaman Merkez"}, {"title": "Samsat Şehir Merkezi ve Çarşı", "summary": "Küçük bir ilçe olmasına rağmen Samsat''ın merkezi, yöresel ürünler ve samimi bir atmosfer sunar. Özellikle Fırat Nehri kıyısında balık lokantalarında taze balık yiyebilir, yöresel el işi ürünlerden hediyelik eşyalar satın alabilirsiniz.", "place_query": "Samsat Merkez, Adıyaman"}, {"title": "Gerger Kalesi (Samsat''a Yakın Tarihi Durak)", "summary": "Samsat''a yaklaşık 40 km mesafedeki bu etkileyici kale, Kommagene Krallığı dönemine ait anıtsal bir yapıdır. Sarp kayalıklar üzerine inşa edilmiş olan kale, hem tarihi dokusu hem de zirveden Fırat Vadisi''ne bakan nefes kesen manzarasıyla mutlaka görülmeli.", "place_query": "Gerger Kalesi, Gerger, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a71b23c8-3432-49e7-ad7c-90a4ca3b98a1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nemrut Dağı", "summary": "UNESCO Dünya Mirası listesinde yer alan bu etkileyici dağ, Kommagene Krallığı''na ait dev heykelleri ve tümülüsüyle ünlüdür. Özellikle gün doğumu ve gün batımı manzaraları ziyaretçileri büyüler.", "place_query": "Nemrut Dağı, Adıyaman"}, {"title": "Cendere Köprüsü", "summary": "Roma döneminden kalma bu görkemli köprü, dört büyük sütunu ve kesme taş işçiliğiyle dikkat çeker. Antik dünyanın en sağlam kalmış köprülerinden biridir.", "place_query": "Cendere Köprüsü, Adıyaman"}, {"title": "Arsameia Antik Kenti", "summary": "Kommagene Krallığı''nın yazlık başkenti olan bu antik kent, kaya kabartmaları ve tünelleriyle tarih meraklıları için eşsiz bir duraktır.", "place_query": "Arsameia Antik Kenti, Adıyaman"}, {"title": "Atatürk Barajı", "summary": "Türkiye''nin en büyük barajlarından biri olan Atatürk Barajı, devasa gölü ve çevresindeki piknik alanlarıyla hem doğa hem de mühendislik harikası görmek isteyenler için idealdir.", "place_query": "Atatürk Barajı, Adıyaman"}, {"title": "Perre Antik Kenti", "summary": "Adıyaman şehir merkezine yakın konumdaki bu antik kent, kayalara oyulmuş mezarları ve mağaralarıyla Kommagene dönemine ışık tutar.", "place_query": "Perre Antik Kenti, Adıyaman"}, {"title": "Gerger Kalesi", "summary": "Sincik ilçesine yakın olan bu tarihi kale, Fırat Nehri manzarasına hakim kayalık bir tepe üzerinde yer alır. Kaleye çıkarken görülen manzara oldukça etkileyicidir.", "place_query": "Gerger Kalesi, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8d694e75-22be-4cb5-9e6a-7a6883699b03'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tut Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin stratejik önemini yansıtır. Ziyaretçiler, kalenin surları arasında dolaşırken Adıyaman Ovası''nın muhteşem manzarasını izleyebilir.", "place_query": "Tut Kalesi, Tut, Adıyaman"}, {"title": "Tut Şelalesi", "summary": "Doğal güzelliğiyle öne çıkan şelale, özellikle bahar ve yaz aylarında serinlemek ve piknik yapmak isteyenlerin uğrak noktasıdır. Çevresindeki yeşil alanlar, doğa yürüyüşü için idealdir.", "place_query": "Tut Şelalesi, Tut, Adıyaman"}, {"title": "Tut Cami (Merkez Cami)", "summary": "İlçe merkezinde bulunan tarihi cami, mimarisi ve huzurlu atmosferiyle dikkat çeker. Yöre halkı tarafından sıkça ziyaret edilen cami, manevi bir durak olarak öne çıkar.", "place_query": "Tut Merkez Cami, Tut, Adıyaman"}, {"title": "Tut Yaylası (Güzel Yayla)", "summary": "Şehir hayatından uzaklaşmak isteyenler için ideal olan yayla, temiz havası ve geniş çayırlarıyla ünlüdür. Yaz aylarında düzenlenen yayla şenlikleri, bölgeye ayrı bir renk katar.", "place_query": "Güzel Yayla, Tut, Adıyaman"}, {"title": "Tut Barajı", "summary": "Çevredeki tarım arazilerini sulamak amacıyla kurulan baraj, aynı zamanda piknik ve balık tutma etkinlikleri için popüler bir mekandır. Gün batımında baraj manzarası oldukça etkileyicidir.", "place_query": "Tut Barajı, Tut, Adıyaman"}, {"title": "Tut Eski Çarşı", "summary": "İlçenin tarihi dokusunu yansıtan eski çarşı, küçük dükkanları ve samimi atmosferiyle ziyaretçilerine nostaljik bir alışveriş deneyimi sunar. El yapımı ürünler ve yöresel lezzetler burada bulunabilir.", "place_query": "Tut Eski Çarşı, Tut, Adıyaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '47ce3c4c-5905-4395-b527-398e75ea4da1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Başmakçı Göleti", "summary": "İlçe merkezine yakın mesafede bulunan bu gölet, piknik alanları ve doğal çevresiyle hafta sonu kaçamaklarının favori noktasıdır. Sakin atmosferi ve yeşil dokusuyla ziyaretçilere huzurlu bir gün geçirme imkanı sunar.", "place_query": "Başmakçı Göleti, Başmakçı, Afyonkarahisar"}, {"title": "Başmakçı Merkez Camii", "summary": "İlçenin simge yapılarından biri olan bu cami, Osmanlı dönemi mimari izlerini taşıyan sade ve etkileyici bir yapıdır. Özellikle ramazan aylarında ve dini bayramlarda yoğun ilgi görür.", "place_query": "Başmakçı Merkez Camii, Başmakçı, Afyonkarahisar"}, {"title": "Yukarı Yayla (Yaylabaşı)", "summary": "Başmakçı''nın yüksek kesimlerinde yer alan bu yayla, serin havası ve geniş otlaklarıyla yaz aylarında kaçış noktasıdır. Doğa yürüyüşleri ve kamp için elverişli bir alandır.", "place_query": "Yaylabaşı Yaylası, Başmakçı, Afyonkarahisar"}, {"title": "Karakuyu Köyü Şelalesi", "summary": "İlçe sınırları içinde kalan bu şelale, özellikle bahar aylarında coşan suyu ve çevresindeki yeşil örtüyle fotoğrafçıların ve doğaseverlerin uğrak noktasıdır.", "place_query": "Karakuyu Köyü Şelalesi, Başmakçı, Afyonkarahisar"}, {"title": "Başmakçı Eski Çarşı", "summary": "İlçenin tarihi dokusunu yansıtan bu çarşı, küçük dükkanları ve yöresel ürünleriyle ziyaretçilere nostaljik bir alışveriş deneyimi sunar. Özellikle el dokuması kilimler ve yöresel peynirler dikkat çeker.", "place_query": "Başmakçı Eski Çarşı, Başmakçı, Afyonkarahisar"}, {"title": "Başmakçı Höyüğü", "summary": "İlçe merkezinde yer alan bu höyük, çevredeki en eski yerleşim izlerini barındıran arkeolojik alanlardan biridir. Bölgenin tarihine ilgi duyanlar için önemli bir duraktır.", "place_query": "Başmakçı Höyüğü, Başmakçı, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b8bfb404-8d04-4871-92dd-4bf7cc104375'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bayat Kaya Mezarları", "summary": "Bayat ilçe merkezinde bulunan bu tarihi kaya mezarları, Frig dönemine ait olup bölgenin en önemli arkeolojik kalıntıları arasındadır. Kayalara oyulmuş etkileyici yapılarıyla tarih meraklıları için görülmeye değer bir noktadır.", "place_query": "Bayat Kaya Mezarları, Bayat, Afyonkarahisar"}, {"title": "Bayat Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan Bayat Kalesi, Bizans dönemine tarihlenen sur kalıntıları ve geniş bir alana yayılan yapısıyla dikkat çeker. Kaleye çıktığınızda Bayat Ovası''nın muhteşem manzarasını izleyebilirsiniz.", "place_query": "Bayat Kalesi, Bayat, Afyonkarahisar"}, {"title": "Bayat Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumdaki bu yapay gölet, piknik yapmak, doğa yürüyüşü gerçekleştirmek ve huzurlu bir gün geçirmek için idealdir. Çevresindeki yeşil alanlar ve temiz havasıyla ailelerin sıkça tercih ettiği bir dinlenme noktasıdır.", "place_query": "Bayat Göleti, Bayat, Afyonkarahisar"}, {"title": "Bayat Ulu Camii", "summary": "Selçuklu mimarisinin izlerini taşıyan bu tarihi cami, ilçenin en eski yapılarından biridir. Ahşap işçiliği ve sade mimarisiyle dikkat çeken cami, ibadet ve ziyaret amaçlı önemli bir duraktır.", "place_query": "Bayat Ulu Camii, Bayat, Afyonkarahisar"}, {"title": "Körpınar Yaylası", "summary": "Bayat''a bağlı köylerden birinde yer alan Körpınar Yaylası, yemyeşil doğası, serin suları ve yayla evleriyle özellikle yaz aylarında doğa severlerin ilgisini çeker. Kamp ve doğa yürüyüşleri için uygun bir ortam sunar.", "place_query": "Körpınar Yaylası, Bayat, Afyonkarahisar"}, {"title": "Bayat Merkez Hamamı", "summary": "Tarihi bir Osmanlı hamamı olan yapı, günümüzde de hizmet vermeye devam etmektedir. Geleneksel hamam kültürünü deneyimlemek ve yorgunluk atmak isteyenler için ilçe merkezinde bulunan önemli bir mekandır.", "place_query": "Bayat Merkez Hamamı, Bayat, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '49fb2ce4-aeee-4782-9fe1-3a89ab476ad2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bolvadin Kaya Mezarları", "summary": "Frig dönemine ait bu kaya mezarları, ilçenin tarihi dokusunu gözler önüne serer. Kayalara oyulmuş odaları ve bölgenin antik geçmişine dair ipuçları sunar.", "place_query": "Bolvadin Kaya Mezarları, Bolvadin, Afyonkarahisar"}, {"title": "Bolvadin Ulu Cami", "summary": "Selçuklu döneminden kalma bu tarihi cami, ahşap işçiliği ve sade mimarisiyle dikkat çeker. İlçenin manevi ve kültürel mirasının önemli bir parçasıdır.", "place_query": "Bolvadin Ulu Cami, Bolvadin, Afyonkarahisar"}, {"title": "Bolvadin Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgedeki arkeolojik kazılardan çıkan eserleri ve etnografik objeleri sergiler. Tarihe ilgi duyanlar için keyifli bir duraktır.", "place_query": "Bolvadin Müzesi, Bolvadin, Afyonkarahisar"}, {"title": "Kocaçay Mesire Alanı", "summary": "Kocaçay Deresi kenarında yer alan bu mesire alanı, piknik ve doğa yürüyüşleri için idealdir. Yeşil alanları ve akan suyun sesiyle huzurlu bir kaçış noktası sunar.", "place_query": "Kocaçay Mesire Alanı, Bolvadin, Afyonkarahisar"}, {"title": "Eber Gölü", "summary": "Bolvadin sınırları içinde yer alan Eber Gölü, kuş gözlemciliği ve doğal güzellikleriyle ünlüdür. Özellikle göç dönemlerinde çok sayıda kuş türüne ev sahipliği yapar.", "place_query": "Eber Gölü, Bolvadin, Afyonkarahisar"}, {"title": "Bolvadin Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle bahar aylarında coşkun akan sularıyla görsel bir şölen sunar. Çevresindeki doğal alan, kısa doğa yürüyüşleri için uygundur.", "place_query": "Bolvadin Şelalesi, Bolvadin, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1d8053ca-e014-4381-9956-a95a8d24a13c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eber Gölü", "summary": "Afyonkarahisar''ın önemli sulak alanlarından biri olan Eber Gölü, kuş gözlemciliği ve doğa fotoğrafçılığı için ideal bir noktadır. Özellikle göç dönemlerinde çok sayıda kuş türüne ev sahipliği yapar.", "place_query": "Eber Gölü, Çay, Afyonkarahisar"}, {"title": "Çay İlçe Merkezi ve Tarihi Evler", "summary": "Çay ilçe merkezinde bulunan geleneksel Türk evleri ve tarihi yapılar, ilçenin kültürel dokusunu yansıtır. Arnavut kaldırımlı sokaklarda yürüyüş yaparak geçmişe yolculuk edebilirsiniz.", "place_query": "Çay İlçe Merkezi, Afyonkarahisar"}, {"title": "Karamık Gölü", "summary": "Çay ilçesi sınırları içinde yer alan Karamık Gölü, doğal güzelliği ve zengin biyolojik çeşitliliği ile bilinir. Göl çevresinde piknik yapabilir ve huzurlu bir doğa deneyimi yaşayabilirsiniz.", "place_query": "Karamık Gölü, Çay, Afyonkarahisar"}, {"title": "Çay Ulu Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Çay Ulu Camii, mimarisi ve süslemeleriyle dikkat çeker. İlçenin en önemli dini yapılarından biridir ve ibadete açıktır.", "place_query": "Çay Ulu Camii, Afyonkarahisar"}, {"title": "Sultan Dağları", "summary": "Çay ilçesinin güneyinde yükselen Sultan Dağları, doğa yürüyüşü ve trekking için popüler rotalar sunar. Dağların eteklerindeki köylerde geleneksel yaşamı gözlemleyebilirsiniz.", "place_query": "Sultan Dağları, Çay, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '161dd336-5423-4615-b05e-6f7dd3c7d4d5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çobanlar Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve kısa bir yürüyüş yapmak için idealdir. Çocuk oyun alanları ve yeşil alanlarıyla ailelerin uğrak noktasıdır.", "place_query": "Çobanlar Belediye Parkı, Çobanlar, Afyonkarahisar"}, {"title": "Çobanlar Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale kalıntıları, ilçeye hakim bir tepede yer alır. Bölgenin tarihine tanıklık etmek ve panoramik manzara izlemek için ziyaret edilebilir.", "place_query": "Çobanlar Kalesi, Çobanlar, Afyonkarahisar"}, {"title": "Kocaçay Mesire Alanı", "summary": "Çobanlar yakınlarında doğayla iç içe bir piknik ve mesire alanıdır. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için tercih edilir.", "place_query": "Kocaçay Mesire Alanı, Çobanlar, Afyonkarahisar"}, {"title": "Çobanlar Merkez Camii", "summary": "İlçenin en büyük ve en bilinen camisidir. Osmanlı ve Selçuklu mimarisinden izler taşıyan yapı, dini ve kültürel bir ziyaret noktasıdır.", "place_query": "Çobanlar Merkez Camii, Çobanlar, Afyonkarahisar"}, {"title": "Akharım Köyü Tarihi Evleri", "summary": "Çobanlar''a bağlı Akharım köyünde yer alan geleneksel taş ve ahşap evler, kırsal mimariyi yansıtır. Fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Akharım Köyü Tarihi Evleri, Çobanlar, Afyonkarahisar"}, {"title": "Çobanlar Göleti", "summary": "İlçe sınırları içinde bulunan küçük bir gölettir. Çevresindeki yeşil alanlar ve sakin atmosferiyle doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Çobanlar Göleti, Çobanlar, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f2ce0e21-ab17-4a67-938c-f59c8ae1b5f6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dazkırı Kaplıcaları", "summary": "Şifalı termal sularıyla ünlü bu kaplıcalar, romatizma ve cilt hastalıklarına iyi geldiği düşünülen sıcak su kaynaklarıyla ziyaretçilerine sağlık ve huzur dolu bir deneyim sunar.", "place_query": "Dazkırı Kaplıcaları, Dazkırı, Afyonkarahisar"}, {"title": "Gökçe Barajı Mesire Alanı", "summary": "Baraj çevresinde yer alan bu mesire alanı, piknik yapmak, doğa yürüyüşü gerçekleştirmek ve huzurlu bir gün geçirmek isteyenler için ideal bir noktadır.", "place_query": "Gökçe Barajı, Dazkırı, Afyonkarahisar"}, {"title": "Dazkırı Merkez Camii", "summary": "İlçenin tarihi ve mimari açıdan önemli yapılarından biri olan cami, sade ve etkileyici tasarımıyla dikkat çeker.", "place_query": "Dazkırı Merkez Camii, Dazkırı, Afyonkarahisar"}, {"title": "Kızılören Mağarası", "summary": "Dazkırı''ya yaklaşık 25 km uzaklıktaki bu mağara, sarkıt ve dikitleriyle doğa severler için keşfedilmeyi bekleyen bir doğal güzelliktir.", "place_query": "Kızılören Mağarası, Kızılören, Afyonkarahisar"}, {"title": "Acıgöl Kuş Cenneti (Dazkırı Kıyıları)", "summary": "Acıgöl''ün Dazkırı sınırları içindeki kıyıları, özellikle flamingolar olmak üzere birçok kuş türüne ev sahipliği yapar; doğa gözlemcileri için eşsiz bir rotadır.", "place_query": "Acıgöl, Dazkırı, Afyonkarahisar"}, {"title": "Yukarı Yenice Köyü Tarihi Evleri", "summary": "Yöresel mimariyi yansıtan bu tarihi evler, geleneksel taş ve ahşap işçiliğiyle ziyaretçilere geçmişe kısa bir yolculuk imkanı sunar.", "place_query": "Yukarı Yenice Köyü, Dazkırı, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cf7519ac-2e62-4650-8d97-378796b4533d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dinar İlçe Merkezi ve Atatürk Evi Müzesi", "summary": "Dinar''ın merkezinde yer alan Atatürk Evi Müzesi, Atatürk''ün ilçeyi ziyareti sırasında kaldığı tarihi yapıdır ve Kurtuluş Savaşı''na dair önemli belgeler ile eşyalar sergilenmektedir.", "place_query": "Atatürk Evi Müzesi, Dinar, Afyonkarahisar"}, {"title": "Dinar Kaplıcaları (Ilıca Kaplıcası)", "summary": "Romatizmal hastalıklara iyi geldiğine inanılan sıcak su kaynaklarıyla ünlü Dinar Kaplıcaları, doğal güzellikler içinde şifa arayan ziyaretçiler için popüler bir dinlenme noktasıdır.", "place_query": "Dinar Kaplıcaları, Dinar, Afyonkarahisar"}, {"title": "Apameia Antik Kenti (Dinar)", "summary": "Helenistik ve Roma dönemlerine ait kalıntıları barındıran Apameia Antik Kenti, Dinar''ın tarihi zenginliğini gözler önüne seren önemli bir arkeolojik alandır.", "place_query": "Apameia Antik Kenti, Dinar, Afyonkarahisar"}, {"title": "Çiğiltepe Şehitliği ve Anıtı", "summary": "Kurtuluş Savaşı''nda önemli bir direniş noktası olan Çiğiltepe, şehitler anısına yapılan anıtı ve panoramik manzarasıyla tarih ve doğa tutkunlarını bir araya getirir.", "place_query": "Çiğiltepe Şehitliği, Dinar, Afyonkarahisar"}, {"title": "Dinar Kaya Mezarları", "summary": "Frig dönemine ait olduğu düşünülen Dinar Kaya Mezarları, kayalara oyulmuş etkileyici yapılarıyla bölgenin antik geçmişine ışık tutar.", "place_query": "Dinar Kaya Mezarları, Dinar, Afyonkarahisar"}, {"title": "Karanlık Dere Kanyonu", "summary": "Doğa yürüyüşü ve fotoğrafçılık için ideal olan Karanlık Dere Kanyonu, yemyeşil bitki örtüsü ve derin vadisiyle Dinar''ın saklı doğal güzelliklerindendir.", "place_query": "Karanlık Dere Kanyonu, Dinar, Afyonkarahisar"}, {"title": "Eber Gölü (Dinar Kıyıları)", "summary": "Kuş gözlemciliği ve doğa fotoğrafçılığı için önemli bir sulak alan olan Eber Gölü''nün Dinar kıyıları, huzurlu atmosferi ve zengin biyolojik çeşitliliğiyle ziyaretçileri cezbeder.", "place_query": "Eber Gölü, Dinar, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '64c8179e-9c64-46c3-b477-c62472c03d9e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Emirdağ Belediye Parkı", "summary": "Şehir merkezinde yer alan bu park, dinlenmek ve yürüyüş yapmak için ideal bir alandır. İçerisindeki gölet ve yeşil alanlar, aileler ve çocuklar için popüler bir buluşma noktasıdır.", "place_query": "Emirdağ Belediye Parkı, Emirdağ, Afyonkarahisar"}, {"title": "Emirdağ Kalesi", "summary": "Tarihi bir tepe üzerinde konumlanan bu kale, ilçeye hakim bir manzara sunar. Bölgenin antik dönemlerine tanıklık eden yapı, tarih meraklıları için önemli bir duraktır.", "place_query": "Emirdağ Kalesi, Emirdağ, Afyonkarahisar"}, {"title": "Emirdağ Müzesi", "summary": "İlçenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bu müze, arkeolojik buluntular ve etnografik objelerle zengin bir koleksiyona sahiptir. Ziyaretçilere bölgenin geçmişine dair kapsamlı bir bakış sunar.", "place_query": "Emirdağ Müzesi, Emirdağ, Afyonkarahisar"}, {"title": "Yukarı Piribeyli Göleti", "summary": "Emirdağ''ın doğal güzelliklerinden biri olan bu gölet, piknik ve doğa yürüyüşleri için tercih edilen bir yerdir. Çevresindeki yeşil alanlar ve sakin atmosferiyle huzurlu bir kaçış noktasıdır.", "place_query": "Yukarı Piribeyli Göleti, Emirdağ, Afyonkarahisar"}, {"title": "Bademli Kanyonu", "summary": "Doğa sporları ve trekking için ideal olan bu kanyon, etkileyici kaya oluşumları ve yemyeşil bitki örtüsüyle dikkat çeker. Macera arayan ziyaretçiler için keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "Bademli Kanyonu, Emirdağ, Afyonkarahisar"}, {"title": "Emirdağ Termal Tesisleri", "summary": "Şifalı sularıyla bilinen bu tesisler, termal turizm açısından önemli bir yere sahiptir. Romatizmal hastalıklara iyi geldiği düşünülen suları ve konforlu konaklama imkanlarıyla ziyaretçilerine keyifli bir deneyim sunar.", "place_query": "Emirdağ Termal Tesisleri, Emirdağ, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '50ae2469-353d-420c-89f7-a33c4f11b49f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Evciler Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kale kalıntısıdır. Bölgenin savunma tarihine ışık tutar ve çevresindeki doğal manzara ile ziyaretçilere keyifli bir gezi imkanı sunar.", "place_query": "Evciler Kalesi, Evciler, Afyonkarahisar"}, {"title": "Göldağı Tabiat Parkı", "summary": "Evciler''e bağlı Gölcük köyü yakınlarında bulunan bu tabiat parkı, zengin bitki örtüsü ve yürüyüş parkurlarıyla doğa severler için idealdir. Piknik alanları ve temiz havasıyla ünlüdür.", "place_query": "Göldağı Tabiat Parkı, Evciler, Afyonkarahisar"}, {"title": "Evciler Merkez Camii", "summary": "İlçenin en eski ve mimari açıdan dikkat çeken camilerinden biridir. Osmanlı dönemi izlerini taşıyan yapı, hem ibadet hem de tarihi bir durak olarak öne çıkar.", "place_query": "Evciler Merkez Camii, Evciler, Afyonkarahisar"}, {"title": "Küçük Evciler Göleti", "summary": "İlçe merkezine kısa bir mesafede bulunan bu gölet, çevresindeki yeşil alanlar ve sakin atmosferiyle huzurlu bir kaçış noktasıdır. Balık tutma ve doğa yürüyüşü için popülerdir.", "place_query": "Küçük Evciler Göleti, Evciler, Afyonkarahisar"}, {"title": "Evciler Taşhanı", "summary": "Tarihi bir kervansaray olan Taşhan, ilçenin kültürel mirasını yansıtan önemli bir yapıdır. Restorasyonuyla dikkat çeken han, geçmişe yolculuk yapmak isteyenler için görülmeye değerdir.", "place_query": "Evciler Taşhanı, Evciler, Afyonkarahisar"}, {"title": "Seyir Tepesi (Evciler)", "summary": "İlçeye hakim bir tepede yer alan bu seyir noktası, Evciler ve çevresinin panoramik manzarasını sunar. Özellikle gün batımında fotoğrafçılar için ideal bir duraktır.", "place_query": "Seyir Tepesi, Evciler, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0ed4ebce-824d-4f9f-ba8b-72d6dbaee581'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hocalar Merkez Camii ve Çarşı", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki çarşı, Hocalar''ın sosyal ve kültürel hayatının kalbidir. Yöresel ürünleri keşfetmek ve sakin bir atmosferde vakit geçirmek için idealdir.", "place_query": "Hocalar Merkez Camii, Hocalar, Afyonkarahisar"}, {"title": "Hocalar Kalesi", "summary": "İlçe merkezine yakın bir tepede yer alan bu tarihi kale kalıntıları, bölgenin antik dönemlerine ışık tutar. Zirveden Hocalar ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "Hocalar Kalesi, Hocalar, Afyonkarahisar"}, {"title": "Kırkgöz Köprüsü", "summary": "İlçe sınırları içinde bulunan bu tarihi taş köprü, Osmanlı dönemi mimarisinin güzel bir örneğidir. Çevresindeki doğal alan, piknik ve kısa yürüyüşler için uygundur.", "place_query": "Kırkgöz Köprüsü, Hocalar, Afyonkarahisar"}, {"title": "Yaylacık Yaylası", "summary": "Hocalar''ın serin ve yeşil yaylalarından biri olan Yaylacık, özellikle yaz aylarında doğa yürüyüşleri ve kamp için tercih edilir. Temiz havası ve huzurlu ortamıyla bilinir.", "place_query": "Yaylacık Yaylası, Hocalar, Afyonkarahisar"}, {"title": "Hocalar İçmeleri", "summary": "İlçedeki doğal su kaynakları ve içmeler, şifalı sularıyla ünlüdür. Yöre halkı tarafından sıkça ziyaret edilen bu noktalar, sağlık turizmi açısından da önem taşır.", "place_query": "Hocalar İçmeleri, Hocalar, Afyonkarahisar"}, {"title": "Akpınar Göleti", "summary": "Hocalar yakınlarındaki bu küçük gölet, çevresindeki yeşil alanlarla birlikte piknik ve olta balıkçılığı için popüler bir yerdir. Sessiz ve sakin bir gün geçirmek isteyenler için idealdir.", "place_query": "Akpınar Göleti, Hocalar, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '196e6cc5-935b-49a2-971d-ff314a75a23b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayazini Köyü ve Peri Bacaları", "summary": "Tarihi Frig yerleşimi olan Ayazini, kayalara oyulmuş evleri, kiliseleri ve peri bacalarıyla ünlüdür. Doğal kaya oluşumları arasında yürüyüş yapabilir, bölgenin eşsiz manzaralarını keşfedebilirsiniz.", "place_query": "Ayazini Köyü, İhsaniye, Afyonkarahisar"}, {"title": "Emre Gölü", "summary": "Sessiz ve huzurlu bir doğa kaçamağı arayanlar için ideal olan Emre Gölü, çevresindeki yeşil alanlar ve piknik alanlarıyla ziyaretçilerine dinlendirici bir atmosfer sunar. Gölet kenarında yürüyüş yapabilir veya kuş gözlemi yapabilirsiniz.", "place_query": "Emre Gölü, İhsaniye, Afyonkarahisar"}, {"title": "İhsaniye Kalesi", "summary": "Bölgeye hakim bir tepe üzerinde yer alan tarihi İhsaniye Kalesi, Frig dönemine ait kalıntılarıyla dikkat çeker. Kaleye tırmanarak çevrenin panoramik manzarasını izleyebilirsiniz.", "place_query": "İhsaniye Kalesi, İhsaniye, Afyonkarahisar"}, {"title": "Döğer Köyü ve Tarihi Evleri", "summary": "Geleneksel Afyonkarahisar mimarisini yansıtan tarihi taş evleriyle ünlü Döğer Köyü, dar sokakları ve otantik atmosferiyle fotoğraf tutkunları için harika bir rotadır.", "place_query": "Döğer Köyü, İhsaniye, Afyonkarahisar"}, {"title": "Gazlıgöl Kaplıcaları", "summary": "Termal suları ve şifalı çamurlarıyla bilinen Gazlıgöl Kaplıcaları, romatizma ve cilt hastalıklarına iyi geldiği düşünülen kaplıca tesisleriyle yıl boyunca ziyaretçi ağırlar. Konforlu otelleriyle konaklama imkanı da sunar.", "place_query": "Gazlıgöl Kaplıcaları, İhsaniye, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a66d2fe4-1f29-4152-a9f7-37df84394a30'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İscehisar Yeraltı Şehri", "summary": "Frigler döneminden kalma bu yeraltı şehri, kayalar oyularak yapılmış odaları, tünelleri ve sarnıçlarıyla ziyaretçileri büyüler. Tarih öncesi dönemlere uzanan mistik atmosferiyle keşfedilmeyi bekleyen eşsiz bir yapıdır.", "place_query": "İscehisar Yeraltı Şehri, İscehisar, Afyonkarahisar"}, {"title": "Ayazini Köyü", "summary": "Peribacalarını andıran kaya oluşumları ve tarihi kaya kiliseleriyle ünlü bu köy, doğa ve tarih tutkunları için harika bir rota sunar. Aynı zamanda Frig vadilerinin en güzel manzaralarından birine ev sahipliği yapar.", "place_query": "Ayazini Köyü, İscehisar, Afyonkarahisar"}, {"title": "Frig Vadisi (İscehisar Bölümü)", "summary": "Tarihi Frig uygarlığına ait kaya anıtları, mezarlar ve yerleşim kalıntılarıyla dolu bu vadi, doğa yürüyüşleri ve fotoğrafçılık için idealdir. Özellikle Aslantaş ve Yılantaş anıtları görülmeye değerdir.", "place_query": "Frig Vadisi, İscehisar, Afyonkarahisar"}, {"title": "Emre Gölü", "summary": "Sessiz ve sakin doğasıyla piknik ve dinlenme alanı olarak tercih edilen bu göl, çevresindeki yeşil alanlarla huzurlu bir kaçış noktası sunar. Göçmen kuşların uğrak noktası olması da ayrı bir cazibe katar.", "place_query": "Emre Gölü, İscehisar, Afyonkarahisar"}, {"title": "İscehisar Kalesi", "summary": "Tepede yer alan bu tarihi kale kalıntısı, bölgenin panoramik manzarasını izlemek için en güzel noktalardan biridir. Frig ve Roma dönemlerine ait izler taşıyan kale, tarih meraklıları için ilgi çekicidir.", "place_query": "İscehisar Kalesi, İscehisar, Afyonkarahisar"}, {"title": "Seydiler Köyü Kaya Mezarları", "summary": "Friglerden kalan bu kaya mezarları, bölgenin zengin tarihini gözler önüne seren etkileyici yapılardır. Doğal kaya oluşumlarıyla iç içe geçmiş bu alan, arkeoloji tutkunları için önemli bir duraktır.", "place_query": "Seydiler Köyü Kaya Mezarları, İscehisar, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3f4b4488-a0cd-4858-b741-1fe8c595a035'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızılören Kaplıcaları", "summary": "Kızılören ilçe merkezinde bulunan bu doğal kaplıca, şifalı termal sularıyla bilinir. Romatizma ve cilt rahatsızlıklarına iyi geldiği düşünülen suları, ziyaretçilere dinlendirici bir deneyim sunar.", "place_query": "Kızılören Kaplıcaları, Kızılören, Afyonkarahisar"}, {"title": "Kızılören Göleti", "summary": "İlçe merkezine yakın konumdaki bu yapay gölet, piknik ve doğa yürüyüşü için idealdir. Çevresindeki yeşil alanlar ve temiz havasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Kızılören Göleti, Kızılören, Afyonkarahisar"}, {"title": "Kızılören Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu kale kalıntıları, bölgenin antik dönemlerine ışık tutar. Ziyaretçiler, kaleye tırmanarak çevredeki geniş manzarayı izleyebilir.", "place_query": "Kızılören Kalesi, Kızılören, Afyonkarahisar"}, {"title": "Kızılören Merkez Camii", "summary": "İlçenin en önemli dini yapılarından biri olan bu cami, Osmanlı dönemi mimarisinin izlerini taşır. Sade ve huzurlu atmosferiyle hem ibadet hem de kültürel ziyaretler için uygundur.", "place_query": "Kızılören Merkez Camii, Kızılören, Afyonkarahisar"}, {"title": "Kızılören Çarşısı", "summary": "Küçük ama otantik bir çarşı olan bu alan, yöresel el sanatları ve ürünlerin satıldığı dükkanlarıyla dikkat çeker. Ziyaretçiler, Afyonkarahisar''a özgü lezzetleri ve hediyelik eşyaları burada bulabilir.", "place_query": "Kızılören Çarşısı, Kızılören, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '71166355-be56-46b8-9c48-26f54aa76a87'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Afyonkarahisar Kalesi", "summary": "Şehrin simgesi olan 226 metre yüksekliğindeki volkanik kaya kütlesi üzerine kurulu tarihi kale, muhteşem şehir manzarası sunar ve Hititlerden Osmanlıya kadar birçok medeniyete ev sahipliği yapmıştır.", "place_query": "Afyonkarahisar Kalesi, Merkez, Afyonkarahisar"}, {"title": "Afyon Müzesi (Arkeoloji Müzesi)", "summary": "Frig, Roma ve Bizans dönemine ait eserlerin sergilendiği müze, özellikle ünlü ''Afyon Tazısı'' heykeli ve zengin mermer koleksiyonuyla ziyaretçileri büyüler.", "place_query": "Afyon Müzesi, Merkez, Afyonkarahisar"}, {"title": "Zafer Anıtı ve Zafer Müzesi", "summary": "Büyük Taarruz''un 100. yılı anısına yapılan anıt ve yanındaki müze, Kurtuluş Savaşı''nın izlerini taşıyan panoramik bir deneyim sunar.", "place_query": "Zafer Anıtı, Merkez, Afyonkarahisar"}, {"title": "Ulu Cami (Afyonkarahisar Ulu Camii)", "summary": "Anadolu''daki en eski ve en büyük ahşap direkli camilerden biri olan yapı, 1272 yılında inşa edilmiş olup eşsiz ahşap işçiliği ve kalem işi süslemeleriyle dikkat çeker.", "place_query": "Afyonkarahisar Ulu Camii, Merkez, Afyonkarahisar"}, {"title": "Afyonkarahisar Termal Kaplıcaları (Hüdai Kaplıcası vb.)", "summary": "Şifalı sularıyla ünlü kaplıcalar, romatizma ve cilt hastalıklarına iyi gelir; modern tesislerde termal havuz keyfi yapabilir, doğal güzelliklerle iç içe dinlenebilirsiniz.", "place_query": "Hüdai Kaplıcası, Merkez, Afyonkarahisar"}, {"title": "Gedik Ahmet Paşa Camii ve Külliyesi", "summary": "Osmanlı dönemi eseri olan külliye, cami, medrese, hamam ve imarethaneden oluşur; taş işçiliği ve avlusundaki tarihi atmosferiyle görülmeye değerdir.", "place_query": "Gedik Ahmet Paşa Camii, Merkez, Afyonkarahisar"}, {"title": "Afyonkarahisar Evleri (Tarihi Konaklar)", "summary": "Kurtuluş Savaşı''nda karargah olarak kullanılmış, restore edilmiş tarihi konaklar; dar sokaklarında yürürken Osmanlı mimarisinin izlerini görebilirsiniz.", "place_query": "Tarihi Afyonkarahisar Evleri, Merkez, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '51af7104-5034-478b-a8bd-830e60b8c7a9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sandıklı Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan ve şehre hakim manzarasıyla bilinen bu kale, bölgenin en önemli tarihi yapılarından biridir. Ziyaretçiler hem tarihi dokuyu keşfedebilir hem de çevreyi kuşbakışı izleyebilir.", "place_query": "Sandıklı Kalesi, Sandıklı, Afyonkarahisar"}, {"title": "Hüdai Kaplıcaları", "summary": "Termal turizmin gözde noktalarından biri olan Hüdai Kaplıcaları, şifalı suları ve modern tesisleriyle ünlüdür. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan bu kaplıcalar, yıl boyunca yoğun ilgi görür.", "place_query": "Hüdai Kaplıcaları, Sandıklı, Afyonkarahisar"}, {"title": "Sandıklı Belediye Müzesi", "summary": "İlçenin kültürel mirasını sergileyen bu müze, arkeolojik eserler ve etnografik objelerle zengin bir koleksiyona sahiptir. Özellikle tarih meraklıları için keyifli bir duraktır.", "place_query": "Sandıklı Belediye Müzesi, Sandıklı, Afyonkarahisar"}, {"title": "Akdağ Tabiat Parkı", "summary": "Doğal güzellikleri ve yürüyüş parkurlarıyla öne çıkan bu tabiat parkı, piknik ve kamp yapmak isteyenler için idealdir. Zengin bitki örtüsü ve temiz havasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Akdağ Tabiat Parkı, Sandıklı, Afyonkarahisar"}, {"title": "Sandıklı Ulu Camii", "summary": "Selçuklu mimarisinin izlerini taşıyan bu tarihi cami, zarif taş işçiliği ve sade atmosferiyle dikkat çeker. İlçenin merkezinde yer alan cami, hem ibadet hem de ziyaret amaçlı uğranabilecek önemli bir yapıdır.", "place_query": "Sandıklı Ulu Camii, Sandıklı, Afyonkarahisar"}, {"title": "Küçük Çay Barajı ve Mesire Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için popüler bir mesire alanıdır. Baraj gölü manzarası eşliğinde yürüyüş yapabilir, piknik yapabilir veya balık tutabilirsiniz.", "place_query": "Küçük Çay Barajı, Sandıklı, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '57bb0847-2d43-4617-81a9-2933331eb246'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akşar Kaplıcaları", "summary": "Sinanpaşa ilçe merkezine yakın konumdaki bu kaplıcalar, romatizmal rahatsızlıklara iyi gelen termal sularıyla ünlüdür. Bölge halkı tarafından sıkça ziyaret edilen doğal bir şifa merkezidir.", "place_query": "Akşar Kaplıcaları, Sinanpaşa, Afyonkarahisar"}, {"title": "Sinanpaşa Evleri", "summary": "İlçe merkezinde yer alan geleneksel Türk sivil mimarisinin güzel örneklerindendir. Tarihi dokuyu yansıtan bu evler, fotoğraf tutkunları için ilgi çekici bir duraktır.", "place_query": "Sinanpaşa Evleri, Sinanpaşa, Afyonkarahisar"}, {"title": "Karahisar Kalesi (Afyonkarahisar Kalesi)", "summary": "Sinanpaşa sınırları içinde olmamakla birlikte ilçeye en yakın ve en meşhur tarihi yapılardan biridir. Şehrin simgesi olan bu volkanik kaya kütlesi üzerindeki kale, muhteşem bir manzaraya sahiptir.", "place_query": "Afyonkarahisar Kalesi, Afyonkarahisar Merkez"}, {"title": "Küçük Hacet Çeşmesi", "summary": "Sinanpaşa''da bulunan ve halk arasında dilek çeşmesi olarak bilinen tarihi bir yapıdır. Çevresindeki mesire alanıyla birlikte piknik ve dinlenme amaçlı ziyaret edilmektedir.", "place_query": "Küçük Hacet Çeşmesi, Sinanpaşa, Afyonkarahisar"}, {"title": "Sandıklı Akdağ Tabiat Parkı", "summary": "Sinanpaşa''ya komşu Sandıklı ilçesinde yer alan bu tabiat parkı, zengin bitki örtüsü ve temiz havasıyla doğa yürüyüşleri için idealdir. Piknik alanları ve kamp yapma imkanı sunar.", "place_query": "Sandıklı Akdağ Tabiat Parkı, Sandıklı, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '302d79d4-c9e2-44f5-bf62-1d166913ef11'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şuhut Atatürk Evi ve Kurtuluş Savaşı Müzesi", "summary": "Atatürk''ün Büyük Taarruz öncesi karargah olarak kullandığı tarihi ev, günümüzde müze olarak ziyaretçilere açıktır. Kurtuluş Savaşı''na ait eşyalar ve fotoğraflar sergilenir.", "place_query": "Atatürk Evi Müzesi, Şuhut, Afyonkarahisar"}, {"title": "Büyük Taarruz Karargahı", "summary": "26 Ağustos 1922 sabahı Büyük Taarruz''un fiilen başlatıldığı tarihi karargah binasıdır. Milli mücadele ruhunu hissetmek için önemli bir duraktır.", "place_query": "Büyük Taarruz Karargahı, Şuhut, Afyonkarahisar"}, {"title": "Şuhut Kaplıcaları", "summary": "Romatizmal hastalıklara iyi geldiği bilinen termal sularıyla ünlü kaplıca tesisleri, doğal güzellik içinde şifa arayanları ağırlar.", "place_query": "Şuhut Kaplıcaları, Afyonkarahisar"}, {"title": "Karahöyük Höyüğü", "summary": "Hitit dönemine ait olduğu düşünülen arkeolojik höyük, bölgenin antik geçmişine ışık tutar. Tarih meraklıları için keşfedilmeyi bekleyen bir alandır.", "place_query": "Karahöyük Höyüğü, Şuhut, Afyonkarahisar"}, {"title": "Adakale (Şuhut Kalesi)", "summary": "Şuhut''un sembolü haline gelmiş, kayalık bir tepe üzerinde yer alan tarihi kale kalıntısıdır. Çevresinden şehir manzarası izlenebilir.", "place_query": "Adakale Şuhut, Afyonkarahisar"}, {"title": "Kumalar Dağı Milli Parkı", "summary": "Şuhut sınırları içinde kalan bu milli park, zengin bitki örtüsü ve yürüyüş rotalarıyla doğa severler için idealdir. Temiz havası ve manzarasıyla ünlüdür.", "place_query": "Kumalar Dağı Milli Parkı, Şuhut, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7e2d8b0e-0e19-4f37-b7d9-c365e29fec1d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sultandağı Kaya Mezarları", "summary": "Antik Frigya dönemine ait bu kaya mezarları, ilçe merkezine yakın bir tepede yer alır ve bölgenin tarihine ışık tutar. Ziyaretçiler, kayalara oyulmuş bu etkileyici yapıları görürken aynı zamanda Sultandağı manzarasının keyfini çıkarır.", "place_query": "Sultandağı Kaya Mezarları, Sultandağı, Afyonkarahisar"}, {"title": "Eber Gölü", "summary": "Sultandağı''nın hemen kuzeyinde bulunan Eber Gölü, kuş gözlemciliği ve doğa yürüyüşleri için ideal bir sulak alandır. Göçmen kuşlara ev sahipliği yapan göl, özellikle ilkbahar ve sonbaharda ziyaretçilerine huzurlu bir atmosfer sunar.", "place_query": "Eber Gölü, Sultandağı, Afyonkarahisar"}, {"title": "Sultandağı Kiraz Festivali Alanı", "summary": "Her yıl haziran ayında düzenlenen ünlü Kiraz Festivali''ne ev sahipliği yapan bu alan, ilçenin en renkli etkinlik noktasıdır. Festival zamanı dışında da yeşil alanları ve yöresel ürün stantları ile gezilebilir.", "place_query": "Sultandağı Kiraz Festivali Alanı, Sultandağı, Afyonkarahisar"}, {"title": "Sultandağı Seyir Tepesi", "summary": "İlçeye hakim bir noktada bulunan bu seyir tepesi, Eber Gölü ve çevredeki dağların panoramik manzarasını sunar. Özellikle gün batımında fotoğrafçılar için eşsiz bir kare yakalama fırsatı verir.", "place_query": "Sultandağı Seyir Tepesi, Sultandağı, Afyonkarahisar"}, {"title": "Çiğiltepe Şehitliği ve Anıtı", "summary": "Kurtuluş Savaşı''nda önemli bir yere sahip olan Çiğiltepe, şehitler anısına yapılmış anıtı ve ziyaretçi merkezi ile tarihi bir durak noktasıdır. Tepeden çevrenin görünümü de etkileyici olup, vatanseverlik duygularını pekiştiren bir atmosfere sahiptir.", "place_query": "Çiğiltepe Şehitliği, Sultandağı, Afyonkarahisar"}, {"title": "Sultandağı Merkez Camii ve Tarihi Çarşı", "summary": "Osmanlı dönemi mimarisini yansıtan Merkez Camii ve çevresindeki tarihi çarşı, ilçenin kültürel dokusunu keşfetmek isteyenler için idealdir. Çarşıda yöresel el sanatları ve Sultandağı kirazı gibi ürünleri bulabilirsiniz.", "place_query": "Sultandağı Merkez Camii, Sultandağı, Afyonkarahisar"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'af9f67df-3f45-45dc-a383-b6c6df9fdf22'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Diyadin Kaplıcaları", "summary": "Doğal termal sularıyla ünlü bu kaplıcalar, romatizma ve cilt hastalıklarına iyi geldiği düşünülen şifalı sularıyla ziyaretçilerini ağırlıyor. Bölgenin en önemli sağlık turizmi noktalarından biridir.", "place_query": "Diyadin Kaplıcaları, Diyadin, Ağrı"}, {"title": "Diyadin Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale, çevresine hakim manzarası ve geçmişten günümüze taşıdığı izlerle dikkat çekiyor. Özellikle fotoğrafçılar için etkileyici bir seyir noktasıdır.", "place_query": "Diyadin Kalesi, Diyadin, Ağrı"}, {"title": "Murat Nehri (Diyadin Bölümü)", "summary": "Bölgeden geçen Murat Nehri''nin Diyadin civarındaki kıvrımları, doğa yürüyüşleri ve piknik için huzurlu bir ortam sunar. Nehir kenarındaki yeşil alanlar yerel halkın sıkça tercih ettiği dinlenme noktalarındandır.", "place_query": "Murat Nehri Diyadin, Ağrı"}, {"title": "Diyadin İlçe Merkezi Tarihi Evler", "summary": "İlçe merkezinde yer alan geleneksel taş ve ahşap yapılı evler, yöresel mimariyi yansıtarak ziyaretçilere geçmişe kısa bir yolculuk imkanı verir. Dar sokaklarda yürüyüş yapmak keyiflidir.", "place_query": "Diyadin tarihi evler, Ağrı"}, {"title": "Günbulan Köyü Yaylası", "summary": "Diyadin''e bağlı Günbulan köyü yakınlarındaki bu yayla, yemyeşil doğası ve temiz havasıyla doğa severler için ideal bir kaçış noktasıdır. Yaz aylarında yayla şenliklerine de ev sahipliği yapabilir.", "place_query": "Günbulan Yaylası, Diyadin, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4d64f25a-c1d8-4e7f-9786-21b1367ce07f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İshak Paşa Sarayı", "summary": "Osmanlı döneminin en görkemli yapılarından biri olan saray, hem mimarisi hem de tarihi önemiyle Doğubayazıt''ın en çok ziyaret edilen noktasıdır. İçerisinde cami, harem, divan salonu ve türbe gibi birçok bölüm bulunur.", "place_query": "İshak Paşa Sarayı, Doğubayazıt, Ağrı"}, {"title": "Doğubayazıt Kalesi", "summary": "Şehre tepeden bakan bu tarihi kale, Urartu döneminden kalma olup muhteşem bir manzaraya sahiptir. Özellikle gün batımında Ağrı Dağı''nın görüntüsü eşliğinde fotoğrafçıların uğrak noktasıdır.", "place_query": "Doğubayazıt Kalesi, Doğubayazıt, Ağrı"}, {"title": "Ağrı Dağı (Doğubayazıt Cephesi)", "summary": "Türkiye''nin en yüksek dağı olan Ağrı Dağı''na tırmanışlar genellikle Doğubayazıt üzerinden yapılır. Dağın eteklerindeki buzullar ve eşsiz doğa manzarası macera tutkunlarını cezbeder.", "place_query": "Ağrı Dağı, Doğubayazıt, Ağrı"}, {"title": "Ahmed-i Hani Türbesi", "summary": "Ünlü Kürt şair ve düşünür Ahmed-i Hani''nin türbesi, Doğubayazıt''ta manevi bir atmosfer sunar. Ziyaretçiler hem tarihi yapıyı görmek hem de şairin anısına saygı duruşunda bulunmak için buraya gelir.", "place_query": "Ahmed-i Hani Türbesi, Doğubayazıt, Ağrı"}, {"title": "Doğubayazıt Meteor Çukuru", "summary": "Dünyanın en büyük ikinci meteor çukuru olarak bilinen bu doğal oluşum, bilimsel ve turistik açıdan büyük ilgi çeker. Çevresindeki düzlükler ve eşsiz görüntüsüyle ziyaretçilere farklı bir deneyim sunar.", "place_query": "Doğubayazıt Meteor Çukuru, Doğubayazıt, Ağrı"}, {"title": "Balık Gölü", "summary": "Doğubayazıt yakınlarında bulunan bu doğal krater gölü, berrak suları ve çevresindeki yaylalarla huzurlu bir kaçış noktasıdır. Piknik, kamp ve doğa yürüyüşü için idealdir.", "place_query": "Balık Gölü, Doğubayazıt, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '16c2fee2-f63f-49d1-bd4c-08177fa9ac36'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eleşkirt Kalesi", "summary": "Tarihi bir kaledir ve bölgenin en önemli tarihi yapılarından biridir. Ziyaretçiler hem tarihi atmosferi soluyabilir hem de çevredeki doğal güzellikleri görebilir.", "place_query": "Eleşkirt Kalesi, Eleşkirt, Ağrı"}, {"title": "Murat Nehri", "summary": "Bölgenin en büyük akarsularından biri olan Murat Nehri, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşleri için idealdir.", "place_query": "Murat Nehri, Eleşkirt, Ağrı"}, {"title": "Eleşkirt Şelalesi", "summary": "Doğa ile iç içe huzurlu bir ortam sunan şelale, özellikle yaz aylarında serinlemek ve fotoğraf çekmek için tercih edilmektedir.", "place_query": "Eleşkirt Şelalesi, Eleşkirt, Ağrı"}, {"title": "Eleşkirt Merkez Camii", "summary": "İlçenin merkezinde yer alan tarihi bir camidir. Mimari yapısı ve manevi atmosferiyle ziyaretçilerin ilgisini çeker.", "place_query": "Eleşkirt Merkez Camii, Eleşkirt, Ağrı"}, {"title": "Eleşkirt Yaylaları", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü yaylalar, doğa yürüyüşleri ve kamp yapmak isteyenler için harika bir seçenektir.", "place_query": "Eleşkirt Yaylaları, Eleşkirt, Ağrı"}, {"title": "Eleşkirt Eski Hamamı", "summary": "Tarihi bir Osmanlı hamamı olan bu yapı, ilçenin kültürel mirasını yansıtmaktadır. Restore edilmiş haliyle ziyaret edilebilir.", "place_query": "Eleşkirt Eski Hamamı, Eleşkirt, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '02743916-ea67-45bb-8b56-7e032b9609a1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hamur Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin stratejik önemini gözler önüne serer. Ziyaretçiler, kaleye tırmanarak hem tarihi dokuyu keşfedebilir hem de Muş Ovası''nın etkileyici manzarasını izleyebilir.", "place_query": "Hamur Kalesi, Hamur, Ağrı"}, {"title": "Murat Nehri Kıyıları", "summary": "Hamur''dan geçen Murat Nehri''nin çevresi, özellikle bahar aylarında yeşilin ve suyun huzur veren birleşimini sunar. Piknik yapmak, doğa yürüyüşü yapmak ve fotoğraf çekmek için ideal bir noktadır.", "place_query": "Murat Nehri, Hamur, Ağrı"}, {"title": "Hamur Merkez Camii", "summary": "İlçenin en eski ve önemli ibadet yapılarından biri olan cami, sade mimarisi ve huzur dolu atmosferiyle dikkat çeker. Tarihi cami, ilçe merkezinde kolayca ziyaret edilebilecek bir konumdadır.", "place_query": "Hamur Merkez Camii, Hamur, Ağrı"}, {"title": "Karakale (Karakale Köyü)", "summary": "Hamur ilçesine bağlı Karakale köyünde bulunan bu tarihi yapı, geçmişte bir gözetleme kulesi olarak kullanılmıştır. Bölge, tarih meraklıları ve doğa yürüyüşçüleri için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Karakale Köyü, Hamur, Ağrı"}, {"title": "Hamur Yaylaları", "summary": "Yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için Hamur yaylaları mükemmel bir seçenektir. Zümrüt yeşili çayırlar, rengarenk kır çiçekleri ve temiz havasıyla ünlüdür.", "place_query": "Hamur Yaylaları, Hamur, Ağrı"}, {"title": "Abdal Kale (Abdal Köyü)", "summary": "Hamur''a bağlı Abdal köyü yakınlarında bulunan bu tarihi kale, bölgenin savunma tarihine ışık tutar. Kalıntılar arasında yapılacak bir gezi, ziyaretçilere geçmişe yolculuk yapma fırsatı verir.", "place_query": "Abdal Kale, Hamur, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e1e87324-f15d-471c-978c-49b0a7b0e22d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ağrı Dağı", "summary": "Türkiye''nin en yüksek zirvesi olan bu heybetli dağ, Nuh''un Gemisi efsanesine ev sahipliği yapmasıyla ünlüdür. Doğa sporları ve dağcılık tutkunları için eşsiz bir rota sunar.", "place_query": "Ağrı Dağı, Ağrı, Türkiye"}, {"title": "İshak Paşa Sarayı", "summary": "Osmanlı döneminin en görkemli yapılarından biri olan saray, Doğu mimarisinin en güzel örneklerini barındırır. Tarihi dokusu ve muhteşem manzarasıyla ziyaretçileri büyüler.", "place_query": "İshak Paşa Sarayı, Doğubayazıt, Ağrı"}, {"title": "Doğubayazıt Kalesi", "summary": "Urartu dönemine kadar uzanan tarihiyle bu kale, bölgenin stratejik önemini gözler önüne serer. Eteklerindeki İshak Paşa Sarayı ile birlikte görülmeye değerdir.", "place_query": "Doğubayazıt Kalesi, Doğubayazıt, Ağrı"}, {"title": "Ağrı Müzesi", "summary": "Bölgenin zengin arkeolojik ve etnografik eserlerini sergileyen müze, Urartu ve Osmanlı dönemlerine ait önemli buluntulara ev sahipliği yapar. Tarih meraklıları için ideal bir duraktır.", "place_query": "Ağrı Müzesi, Merkez, Ağrı"}, {"title": "Balık Gölü", "summary": "Bölgenin en büyük doğal gölü olan Balık Gölü, çevresindeki yaylalar ve zengin kuş çeşitliliğiyle doğa severler için huzurlu bir kaçış noktasıdır. Piknik ve kamp yapmak için de elverişlidir.", "place_query": "Balık Gölü, Taşlıçay, Ağrı"}, {"title": "Ahmed-i Hani Türbesi", "summary": "Ünlü Kürt şair ve filozof Ahmed-i Hani''nin türbesi, Doğubayazıt''ta yer alır ve manevi bir atmosfere sahiptir. Ziyaretçiler için hem tarihi hem de kültürel bir durak noktasıdır.", "place_query": "Ahmed-i Hani Türbesi, Doğubayazıt, Ağrı"}, {"title": "Tutak Kaplıcaları", "summary": "Şifalı sularıyla bilinen Tutak Kaplıcaları, romatizmal hastalıklara iyi geldiğine inanılan termal kaynaklarıyla sağlık turizmi açısından önemli bir yerdir. Doğal güzellikler içinde dinlenme imkanı sunar.", "place_query": "Tutak Kaplıcaları, Tutak, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a91c46af-a37c-4ecd-8e91-4ea15f62b1e6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Patnos Kalesi", "summary": "Urartu dönemine ait bu tarihi kale, ilçe merkezine hakim bir tepede yer alır. Bölgenin antik tarihine tanıklık etmek ve çevreyi kuşbakışı görmek isteyenler için önemli bir duraktır.", "place_query": "Patnos Kalesi, Patnos, Ağrı"}, {"title": "Azat Köyü Kaya Mezarları", "summary": "Urartu medeniyetinden günümüze ulaşan bu kaya mezarları, tarihi dokuyu yakından görmek isteyen ziyaretçiler için etkileyici bir açık hava müzesi niteliğindedir.", "place_query": "Azat Köyü Kaya Mezarları, Patnos, Ağrı"}, {"title": "Süphan Dağı", "summary": "Türkiye''nin en yüksek volkanik dağlarından biri olan Süphan Dağı, doğa yürüyüşü ve dağcılık tutkunları için eşsiz bir rotadır. Patnos ilçe sınırları içinde kalan etekleri, kamp ve trekking için idealdir.", "place_query": "Süphan Dağı, Patnos, Ağrı"}, {"title": "Patnos Ulu Camii", "summary": "Selçuklu ve Osmanlı dönemi izlerini taşıyan bu tarihi cami, ilçenin merkezinde yer alır. Mimari detayları ve manevi atmosferiyle ziyaretçilerini etkiler.", "place_query": "Patnos Ulu Camii, Patnos, Ağrı"}, {"title": "Balıklı Göl (Patnos)", "summary": "Bölgede doğal güzelliğiyle bilinen bu küçük göl, çevresindeki yeşil alanlarla piknik ve dinlenme amaçlı ziyaret edilir. Özellikle bahar aylarında huzurlu bir kaçış noktasıdır.", "place_query": "Balıklı Göl, Patnos, Ağrı"}, {"title": "Kotan Çayı Vadisi", "summary": "Patnos yakınlarındaki bu vadi, doğal yapısı ve akarsu boyunca uzanan yürüyüş parkurlarıyla doğaseverler için keşfedilmeyi bekleyen bir alandır.", "place_query": "Kotan Çayı Vadisi, Patnos, Ağrı"}, {"title": "Patnos Müzesi", "summary": "İlçede bulunan bu küçük müze, Urartu dönemine ait arkeolojik eserler ve yöresel etnografik objeleri sergileyerek bölgenin kültürel tarihine ışık tutar.", "place_query": "Patnos Müzesi, Patnos, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bb4ae669-5a8f-4e84-a1da-0d0ba934ffd3'::uuid;
