UPDATE location_pages SET travel_ideas_json = '[{"title": "Tutak Kalesi", "summary": "İlçe merkezinde bulunan tarihi bir kaledir. Bölgenin savunma amaçlı kullanılan yapılarından biri olup, çevresindeki doğal manzarasıyla dikkat çeker.", "place_query": "Tutak Kalesi, Tutak, Ağrı"}, {"title": "Murat Nehri Vadisi", "summary": "Tutak''tan geçen Murat Nehri''nin oluşturduğu verimli vadi, doğa yürüyüşleri ve piknik için ideal bir alandır. Bölgenin en önemli akarsu kaynaklarından biridir.", "place_query": "Murat Nehri, Tutak, Ağrı"}, {"title": "Tutak Ulu Camii", "summary": "İlçenin tarihi camilerinden olan Ulu Camii, Osmanlı dönemi mimarisini yansıtan önemli bir dini yapıdır. Halk arasında sıkça ziyaret edilmektedir.", "place_query": "Tutak Ulu Camii, Tutak, Ağrı"}, {"title": "Tutak Çayı Mesire Alanı", "summary": "Tutak Çayı kenarında yer alan bu mesire alanı, piknik ve dinlenme imkanı sunar. Özellikle yaz aylarında yerli halkın uğrak noktasıdır.", "place_query": "Tutak Çayı Mesire Alanı, Tutak, Ağrı"}, {"title": "Tutak Höyüğü", "summary": "İlçe sınırlarında bulunan arkeolojik bir höyüktür. Bölgenin tarih öncesi dönemlerine ışık tutan kalıntılar barındırmaktadır.", "place_query": "Tutak Höyüğü, Tutak, Ağrı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b8719ad2-799d-42fa-931c-d1fd16df2514'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ağaçören Merkez Camii", "summary": "İlçenin tarihi dokusunu yansıtan merkezi bir ibadet yapısıdır. Osmanlı dönemi mimari özelliklerini taşıyan cami, sade ve huzurlu atmosferiyle ziyaretçilerini ağırlar.", "place_query": "Ağaçören Merkez Camii, Aksaray"}, {"title": "Ağaçören Kalesi", "summary": "İlçe merkezine yakın bir tepede yer alan tarihi kale kalıntılarıdır. Bölgenin stratejik önemini gösteren bu alan, çevreye hakim manzarasıyla fotoğrafçılar için idealdir.", "place_query": "Ağaçören Kalesi, Aksaray"}, {"title": "Ağaçören Göleti", "summary": "Doğal güzelliği ve piknik alanlarıyla bilinen bu gölet, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Ağaçören Göleti, Aksaray"}, {"title": "Ağaçören Tarihi Çarşı", "summary": "İlçenin eski ticaret merkezi olan bu çarşı, geleneksel dükkanları ve samimi atmosferiyle yöresel ürünleri keşfetmek için güzel bir duraktır.", "place_query": "Ağaçören Tarihi Çarşı, Aksaray"}, {"title": "Ağaçören Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü yayla, doğa yürüyüşleri ve kamp için ideal bir ortam sunar. Özellikle bahar aylarında rengarenk kır çiçekleriyle büyüler.", "place_query": "Ağaçören Yaylası, Aksaray"}, {"title": "Ağaçören Höyüğü", "summary": "Bölgedeki önemli arkeolojik alanlardan biri olan höyük, tarih öncesi dönemlere ait izler taşır. Tarih meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Ağaçören Höyüğü, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e2378fb1-6f7e-4190-9ad2-58c066a4d095'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eskil Gölü (Eşmekaya Gölü)", "summary": "Aksaray''ın en önemli sulak alanlarından biri olan bu göl, kuş gözlemciliği için ideal bir noktadır. Özellikle göç dönemlerinde yüzlerce kuş türüne ev sahipliği yapar ve doğa fotoğrafçıları için eşsiz manzaralar sunar.", "place_query": "Eşmekaya Gölü, Eskil, Aksaray"}, {"title": "Eskil Kervansarayı", "summary": "Selçuklu döneminden kalma tarihi bir kervansaray olan yapı, İpek Yolu üzerinde önemli bir durak noktasıydı. Günümüzde restore edilerek ziyarete açılan kervansaray, bölgenin tarihi dokusunu yansıtmaktadır.", "place_query": "Eskil Kervansarayı, Eskil, Aksaray"}, {"title": "Eskil Atatürk Evi ve Müzesi", "summary": "Mustafa Kemal Atatürk''ün 1925 yılında Eskil''i ziyareti sırasında konakladığı ev, günümüzde müze olarak hizmet vermektedir. Ziyaretçiler, hem tarihi atmosferi hissedebilir hem de o döneme ait eşyaları görebilirler.", "place_query": "Atatürk Evi Müzesi, Eskil, Aksaray"}, {"title": "Eskil Yeraltı Şehri", "summary": "Bölgedeki en büyüleyici tarihi yapılardan biri olan yeraltı şehri, erken Hristiyanlık döneminde sığınak olarak kullanılmıştır. Dar koridorlar, yaşam alanları ve su sarnıçlarıyla keşfedilmeyi bekleyen bir labirenttir.", "place_query": "Eskil Yeraltı Şehri, Eskil, Aksaray"}, {"title": "Eskil Kaya Mezarları", "summary": "Roma ve Bizans dönemlerine ait olan bu kaya mezarları, bölgenin antik tarihine ışık tutmaktadır. Doğal kaya oluşumlarına oyulmuş mezarlar, tarih meraklıları için ilgi çekici bir duraktır.", "place_query": "Eskil Kaya Mezarları, Eskil, Aksaray"}, {"title": "Eskil Piknik Alanı ve Mesire Yeri", "summary": "Şehir merkezine yakın konumuyla ailelerin ve doğa severlerin uğrak noktası olan bu alan, yeşil örtüsü ve temiz havasıyla huzurlu bir kaçış sunar. Piknik yapmak, yürüyüş yapmak ve dinlenmek için idealdir.", "place_query": "Eskil Mesire Alanı, Eskil, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '983b03f0-ec7c-4a24-9900-9efb8e8a3669'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ihlara Vadisi", "summary": "Aksaray''ın Güzelyurt ilçesinde yer alan bu eşsiz kanyon, volkanik tüflere oyulmuş yüzlerce kilise ve şapeliyle ünlüdür. Melendiz Çayı''nın oluşturduğu vadi boyunca yürüyüş yapabilir, doğa ve tarihi bir arada deneyimleyebilirsiniz.", "place_query": "Ihlara Vadisi, Güzelyurt, Aksaray"}, {"title": "Gülağaç Kaya Mezarları", "summary": "Gülağaç ilçe merkezinde bulunan bu kaya mezarları, Roma dönemine ait önemli bir arkeolojik alandır. Kayalara oyulmuş etkileyici yapılarıyla tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Gülağaç Kaya Mezarları, Aksaray"}, {"title": "Selime Katedrali", "summary": "Kapadokya bölgesinin en büyük kaya kilisesi olan Selime Katedrali, Güzelyurt ilçesinde yer alır. İçindeki freskler ve devasa boyutlarıyla ziyaretçileri büyüler; aynı zamanda muhteşem bir vadi manzarası sunar.", "place_query": "Selime Katedrali, Güzelyurt, Aksaray"}, {"title": "Gümüşler Manastırı", "summary": "Aksaray merkeze bağlı Gümüşler köyünde bulunan bu manastır, Kapadokya''nın en iyi korunmuş kaya manastırlarından biridir. Freskleri ve mimarisiyle Bizans dönemine ışık tutar.", "place_query": "Gümüşler Manastırı, Aksaray"}, {"title": "Aksaray Müzesi", "summary": "Aksaray şehir merkezinde bulunan bu müze, bölgenin zengin tarihini gözler önüne seren eserlere ev sahipliği yapar. Paleolitik çağdan Osmanlı dönemine kadar uzanan geniş bir koleksiyon ziyaretçileri bekliyor.", "place_query": "Aksaray Müzesi, Aksaray Merkez"}, {"title": "Sultanhanı Kervansarayı", "summary": "Aksaray''ın Sultanhanı ilçesinde bulunan bu muhteşem Selçuklu kervansarayı, Anadolu''nun en büyük ve en iyi korunmuş kervansaraylarından biridir. Tarihi İpek Yolu üzerinde önemli bir durak olan yapı, etkileyici taş işçiliğiyle dikkat çeker.", "place_query": "Sultanhanı Kervansarayı, Aksaray"}, {"title": "Tuz Gölü", "summary": "Aksaray sınırları içinde de yer alan Tuz Gölü, Türkiye''nin ikinci büyük gölü olup eşsiz bir doğal güzellik sunar. Özellikle gün batımında pembe ve beyaz renkleriyle büyüleyici manzaralar oluşturur; yaz aylarında yürüyüş yapmak ve fotoğraf çekmek için idealdir.", "place_query": "Tuz Gölü, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e6bdad19-8b90-4d1b-a315-ecc3315ded46'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ihlara Vadisi", "summary": "Aksaray''ın en ünlü doğal güzelliklerinden olan Ihlara Vadisi, derin kanyonu ve içindeki kaya oyma kiliseleriyle ziyaretçilerine eşsiz bir doğa ve tarih deneyimi sunar. Vadide yürüyüş yapabilir, Melendiz Çayı kenarında dinlenebilirsiniz.", "place_query": "Ihlara Vadisi, Güzelyurt, Aksaray"}, {"title": "Güzelyurt (Gelveri) Evleri", "summary": "Tarihi taş ve ahşap mimarisiyle ünlü Güzelyurt''un Gelveri Evleri, dar sokakları ve restore edilmiş konaklarıyla zamanda yolculuk hissi verir. Bölgenin en otantik yerleşim alanlarından biridir.", "place_query": "Güzelyurt Gelveri Evleri, Aksaray"}, {"title": "Selime Katedrali (Selime Manastırı)", "summary": "Kapadokya''nın en büyük kaya oyma manastırlarından biri olan Selime Katedrali, etkileyici freskleri ve devasa salonlarıyla dikkat çeker. Ihlara Vadisi''nin girişinde yer alır ve mutlaka görülmelidir.", "place_query": "Selime Katedrali, Güzelyurt, Aksaray"}, {"title": "Güzelyurt Yeraltı Şehri", "summary": "Erken Hristiyanlık döneminde sığınak olarak kullanılan bu yeraltı şehri, labirent benzeri odaları ve tünelleriyle gizemli bir atmosfere sahiptir. Bölgenin tarihi dokusunu keşfetmek için ideal bir noktadır.", "place_query": "Güzelyurt Yeraltı Şehri, Aksaray"}, {"title": "Kızıl Kilise", "summary": "Kırmızı taşlardan inşa edilmiş bu tarihi Bizans kilisesi, eşsiz mimarisi ve doğal çevresiyle fotoğrafçıların favori mekanlarındandır. Güzelyurt''un sembol yapılarından biridir.", "place_query": "Kızıl Kilise, Güzelyurt, Aksaray"}, {"title": "Sivişli Kilise", "summary": "Ihlara Vadisi''ndeki en önemli kaya kiliselerinden biri olan Sivişli Kilise, içindeki canlı freskler ve haç planlı yapısıyla ziyaretçileri büyüler. Vadideki yürüyüş rotalarında mutlaka uğranması gereken bir duraktır.", "place_query": "Sivişli Kilise, Ihlara Vadisi, Güzelyurt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bd0c1202-e361-4585-98d7-288101facf1a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ihlara Vadisi", "summary": "Aksaray''ın Güzelyurt ilçesinde yer alan bu eşsiz kanyon, volkanik tüflere oyulmuş yüzlerce kaya kilisesi ve şapeliyle ünlüdür. Melendiz Çayı boyunca uzanan yürüyüş parkuru, doğa ve tarih tutkunları için unutulmaz bir deneyim sunar.", "place_query": "Ihlara Vadisi, Güzelyurt, Aksaray"}, {"title": "Aksaray Kızıl Kilise", "summary": "Selçuklu döneminden kalma bu tarihi yapı, kırmızı renkli taşlarıyla dikkat çeker ve bölgenin en önemli dini mimari örneklerinden biridir. Hem mimarisi hem de huzurlu atmosferi ile ziyaretçileri kendine çeker.", "place_query": "Kızıl Kilise, Aksaray Merkez"}, {"title": "Aksaray Müzesi", "summary": "Hitit, Roma, Bizans ve Selçuklu dönemlerine ait zengin arkeolojik eserlerin sergilendiği müze, bölgenin binlerce yıllık tarihine ışık tutar. Özellikle Aşıklı Höyük buluntuları ve mumyalar bölümü oldukça ilgi çekicidir.", "place_query": "Aksaray Müzesi, Merkez, Aksaray"}, {"title": "Hasan Dağı", "summary": "Aksaray''ın simgesi haline gelmiş sönmüş bir volkan olan Hasan Dağı, doğa yürüyüşleri ve dağcılık için popüler bir rotadır. Zirvesinden çevredeki geniş ova ve tuz göllerinin muhteşem manzarası izlenebilir.", "place_query": "Hasan Dağı, Aksaray"}, {"title": "Aşıklı Höyük", "summary": "Kapadokya bölgesinin en eski yerleşimlerinden biri olan bu höyük, günümüzden yaklaşık 10 bin yıl öncesine tarihlenir. Açık hava müzesi olarak düzenlenen alan, ilk köy yaşamına dair önemli kalıntılar sunar.", "place_query": "Aşıklı Höyük, Kızılkaya, Aksaray"}, {"title": "Selime Katedrali", "summary": "Güzelyurt ilçesinde bulunan bu devasa kaya kilisesi, Kapadokya''nın en büyük katedrali olarak kabul edilir. İçindeki freskler ve etkileyici mimarisiyle ziyaretçilerini büyüler.", "place_query": "Selime Katedrali, Güzelyurt, Aksaray"}, {"title": "Güzelyurt Evleri", "summary": "Tarihi taş ve ahşap mimarisiyle ünlü Güzelyurt ilçesi, dar sokakları ve restore edilmiş Rum evleriyle görülmeye değerdir. Sessiz ve huzurlu atmosferi, ziyaretçilere zamanda yolculuk hissi verir.", "place_query": "Güzelyurt Evleri, Güzelyurt, Aksaray"}, {"title": "Yılanlı Dağ Tabiat Parkı", "summary": "Aksaray merkeze yakın konumdaki bu tabiat parkı, piknik alanları, yürüyüş parkurları ve zengin bitki örtüsüyle doğa severler için ideal bir kaçış noktasıdır. Şehir gürültüsünden uzaklaşmak için harika bir seçenektir.", "place_query": "Yılanlı Dağ Tabiat Parkı, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0ec3cc03-13e9-45a9-9caa-0000c010d4c9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ihlara Vadisi", "summary": "Aksaray''ın en ünlü doğal harikalarından biri olan Ihlara Vadisi, derin kanyonu, kaya oyma kiliseleri ve yemyeşil doğasıyla ziyaretçilerine eşsiz bir yürüyüş ve keşif deneyimi sunar.", "place_query": "Ihlara Vadisi, Aksaray"}, {"title": "Selime Katedrali", "summary": "Peribacalarıyla ünlü Selime Köyü''nde bulunan bu dev kaya oyma yapı, tarihi bir manastır ve katedral olarak Kapadokya''nın en etkileyici dini mimari örneklerinden biridir.", "place_query": "Selime Katedrali, Aksaray"}, {"title": "Güzelyurt (Gelveri)", "summary": "Tarihi taş evleri, dar sokakları ve Rum mimarisinin izlerini taşıyan bu şirin kasaba, sakin atmosferi ve manastırlarıyla huzur dolu bir gezi rotasıdır.", "place_query": "Güzelyurt, Aksaray"}, {"title": "Aksaray Müzesi", "summary": "Bölgenin zengin tarihini gözler önüne seren müze, Hitit, Roma, Bizans ve Selçuklu dönemlerine ait eserlerle Aksaray''ın kültürel mirasına ışık tutar.", "place_query": "Aksaray Müzesi, Aksaray"}, {"title": "Hasan Dağı", "summary": "Kapadokya''nın en yüksek zirvelerinden biri olan Hasan Dağı, doğa yürüyüşleri ve kamp severler için ideal bir rota olup, zirvesinden muhteşem manzaralar sunar.", "place_query": "Hasan Dağı, Aksaray"}, {"title": "Kızıl Kilise", "summary": "Güzelyurt yakınlarında bulunan bu tarihi kilise, kırmızı taşları ve etkileyici mimarisiyle dikkat çeker; özellikle fotoğraf tutkunları için popüler bir duraktır.", "place_query": "Kızıl Kilise, Güzelyurt, Aksaray"}, {"title": "Yılanlı Kilise", "summary": "Ihlara Vadisi içerisinde yer alan bu küçük kaya kilisesi, freskleri ve duvarlarındaki yılan figürüyle bilinir; vadideki en ilgi çekici dini yapılardan biridir.", "place_query": "Yılanlı Kilise, Ihlara Vadisi, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '71832b8d-ad21-4395-9696-f23ce9591322'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıyahşi Kaya Mezarları", "summary": "Bölgenin tarihi zenginliğini yansıtan bu kaya mezarları, Helenistik ve Roma dönemlerine ait olup, doğal kaya oluşumlarına oyulmuş etkileyici yapılardır. Tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "Sarıyahşi Kaya Mezarları, Aksaray"}, {"title": "Sarıyahşi Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla özellikle yaz aylarında ziyaretçilerin uğrak noktası olan şelale, piknik ve doğa yürüyüşü için idealdir. Çevresindeki yeşil alanlar huzurlu bir ortam sunar.", "place_query": "Sarıyahşi Şelalesi, Aksaray"}, {"title": "Sarıyahşi Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale, bölgeye hakim bir manzara sunar. Geçmişte savunma amaçlı kullanılan bu yapı, günümüzde ziyaretçilere tarihi bir yolculuk ve panoramik fotoğraf fırsatı verir.", "place_query": "Sarıyahşi Kalesi, Aksaray"}, {"title": "Aksaray Mamasun Barajı (Sarıyahşi Kıyısı)", "summary": "Mamasun Barajı''nın Sarıyahşi sınırlarındaki kıyı şeridi, doğa ile iç içe bir gün geçirmek isteyenler için idealdir. Balık tutma, kamp ve yürüyüş gibi aktiviteler için sakin bir ortam sağlar.", "place_query": "Mamasun Barajı, Sarıyahşi, Aksaray"}, {"title": "Sarıyahşi Merkez Camii ve Tarihi Çevresi", "summary": "İlçe merkezinde yer alan bu cami, Osmanlı dönemi mimarisinin izlerini taşır. Çevresindeki tarihi evler ve dar sokaklar, geleneksel Anadolu atmosferini hissettirir.", "place_query": "Sarıyahşi Merkez Camii, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b4c4f696-d72e-45ab-848a-f54276b85435'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sultanhanı Kervansarayı", "summary": "Selçuklu döneminin en büyük ve en iyi korunmuş kervansaraylarından biridir. Taş işçiliği, anıtsal kapısı ve tarihi atmosferiyle ziyaretçilerini büyüler.", "place_query": "Sultanhanı Kervansarayı, Sultanhanı, Aksaray"}, {"title": "Sultanhanı Halı ve Kilim Müzesi", "summary": "Yöreye özgü el dokuması halı ve kilimlerin sergilendiği bu müze, geleneksel Türk dokuma sanatını yakından tanıma fırsatı sunar.", "place_query": "Sultanhanı Halı ve Kilim Müzesi, Sultanhanı, Aksaray"}, {"title": "Sultanhanı Ulu Camii", "summary": "Selçuklu mimarisinin güzel örneklerinden biri olan cami, sade ve etkileyici yapısıyla dikkat çeker. Tarihi doku içinde huzurlu bir ziyaret noktasıdır.", "place_query": "Sultanhanı Ulu Camii, Sultanhanı, Aksaray"}, {"title": "Sultanhanı Kurtuluş Savaşı Müzesi", "summary": "Milli Mücadele dönemine ait fotoğraflar, belgeler ve objelerin sergilendiği müze, bölgenin tarihine ışık tutar.", "place_query": "Sultanhanı Kurtuluş Savaşı Müzesi, Sultanhanı, Aksaray"}, {"title": "Sultanhanı Eski Çarşı", "summary": "Tarihi taş yapılar arasında yer alan çarşı, el sanatları ürünleri ve yöresel lezzetler satan dükkanlarıyla keyifli bir alışveriş deneyimi sunar.", "place_query": "Sultanhanı Eski Çarşı, Sultanhanı, Aksaray"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f2681a1c-05a3-4cd2-b9b6-ed40263a66c1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göynücek Kalesi", "summary": "Tarihi bir kale olup bölgenin hakim noktasında yer alır. Ziyaretçilere hem tarihi bir atmosfer hem de çevrenin panoramik manzarasını sunar.", "place_query": "Göynücek Kalesi, Göynücek, Amasya"}, {"title": "Gediksaray Köprüsü", "summary": "Tarihi bir taş köprü olup Osmanlı dönemi mimarisini yansıtır. Çevresindeki doğal güzelliklerle birlikte fotoğrafçılar için popüler bir duraktır.", "place_query": "Gediksaray Köprüsü, Göynücek, Amasya"}, {"title": "Göynücek Şelalesi", "summary": "Doğal bir şelale olup piknik ve doğa yürüyüşü için idealdir. Serin suları ve yeşil çevresiyle özellikle yaz aylarında ziyaretçi çeker.", "place_query": "Göynücek Şelalesi, Göynücek, Amasya"}, {"title": "Sarıkaya Kaplıcası", "summary": "Termal su kaynaklarıyla bilinen bir kaplıcadır. Romatizmal hastalıklara iyi geldiği düşünülen suları ve doğal ortamıyla sağlık turizmine hizmet eder.", "place_query": "Sarıkaya Kaplıcası, Göynücek, Amasya"}, {"title": "Göynücek Merkez Camii", "summary": "Tarihi bir cami olup yöresel mimari özellikler taşır. İlçenin merkezinde yer almasıyla ziyaretçilerin sık uğradığı bir dini ve kültürel yapıdır.", "place_query": "Göynücek Merkez Camii, Göynücek, Amasya"}, {"title": "İmirler Barajı", "summary": "Çevresindeki yeşil alanlar ve su manzarasıyla doğa severler için popüler bir noktadır. Balık tutma ve piknik gibi aktiviteler için uygundur.", "place_query": "İmirler Barajı, Göynücek, Amasya"}, {"title": "Göynücek Yaylası", "summary": "Serin havası ve doğal bitki örtüsüyle bilinen bir yayladır. Özellikle yaz aylarında şehir gürültüsünden kaçmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Göynücek Yaylası, Göynücek, Amasya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0ad12698-625a-4992-a727-e696d3be27f2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gümüşhacıköy Kaya Mezarları", "summary": "Helenistik ve Roma dönemine ait bu kaya mezarları, ilçenin en önemli tarihi kalıntılarındandır. Kayalara oyulmuş etkileyici yapılarıyla ziyaretçilerine tarih öncesine yolculuk yapma fırsatı sunar.", "place_query": "Gümüşhacıköy Kaya Mezarları, Amasya"}, {"title": "Gümüşhacıköy Saat Kulesi", "summary": "1900''lü yılların başında inşa edilen bu tarihi saat kulesi, ilçe merkezinde yer alır ve Osmanlı mimarisinin zarif bir örneğidir. Çevresindeki tarihi yapılarla birlikte keyifli bir gezinti rotası oluşturur.", "place_query": "Gümüşhacıköy Saat Kulesi, Amasya"}, {"title": "Gümüşhacıköy Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını sergileyen bu müze, arkeolojik eserler ve etnografik objelerle doludur. Ziyaretçiler, bölgenin geçmişine dair kapsamlı bilgi edinebilir.", "place_query": "Gümüşhacıköy Müzesi, Amasya"}, {"title": "Haliliye Medresesi", "summary": "13. yüzyıldan kalma bu tarihi medrese, Selçuklu dönemi mimarisini yansıtan nadide bir yapıdır. Taş işçiliği ve avlusuyla huzur veren bir atmosfere sahiptir.", "place_query": "Haliliye Medresesi, Gümüşhacıköy, Amasya"}, {"title": "Gümüşhacıköy Kapalı Çarşısı", "summary": "Osmanlı döneminden kalma bu kapalı çarşı, yöresel ürünler ve el sanatları satan dükkanlarıyla ünlüdür. Dar sokaklarında dolaşırken tarihi bir alışveriş deneyimi yaşayabilirsiniz.", "place_query": "Gümüşhacıköy Kapalı Çarşısı, Amasya"}, {"title": "Gümüşhacıköy Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale, ilçeye hakim bir manzara sunar. Kalıntıları arasında yürüyüş yaparken hem doğanın hem de tarihin tadını çıkarabilirsiniz.", "place_query": "Gümüşhacıköy Kalesi, Amasya"}, {"title": "Çağlayan Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir yerdir. Özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır.", "place_query": "Çağlayan Şelalesi, Gümüşhacıköy, Amasya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a32ab01e-b911-4699-bd6c-36d54e7bbdb3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hamamözü Şelalesi", "summary": "İlçenin en bilinen doğal güzelliği olan şelale, yemyeşil bir vadi içinde çağlayarak akar. Piknik alanları ve yürüyüş parkurlarıyla doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Hamamözü Şelalesi, Hamamözü, Amasya"}, {"title": "Kızılca Köyü Kaya Mezarları", "summary": "Bölgedeki tarihi kalıntılar arasında yer alan kaya mezarları, Helenistik ve Roma dönemlerine ait izler taşır. Tarih meraklıları için keşfedilmeyi bekleyen etkileyici bir arkeolojik alandır.", "place_query": "Kızılca Köyü Kaya Mezarları, Hamamözü, Amasya"}, {"title": "Yukarı Baraklı Köyü Tarihi Evleri", "summary": "Geleneksel Amasya mimarisini yansıtan bu köy evleri, taş ve ahşap işçiliğiyle dikkat çeker. Köyün sakin atmosferi ve doğal manzarası, fotoğraf tutkunları için güzel kareler sunar.", "place_query": "Yukarı Baraklı Köyü, Hamamözü, Amasya"}, {"title": "Hamamözü Göleti", "summary": "Çevresi ağaçlarla kaplı olan bu küçük gölet, balık tutma ve doğa yürüyüşü için idealdir. Sessiz bir gün geçirmek isteyenler için huzur dolu bir ortam sağlar.", "place_query": "Hamamözü Göleti, Hamamözü, Amasya"}, {"title": "Derebaşı Yaylası", "summary": "İlçe merkezine yakın konumdaki yayla, temiz havası ve geniş çayırlarıyla ünlüdür. Yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için sıkça tercih edilir.", "place_query": "Derebaşı Yaylası, Hamamözü, Amasya"}, {"title": "Hamamözü Merkez Cami", "summary": "Osmanlı dönemine ait tarihi bir yapı olan cami, sade mimarisi ve huzur veren atmosferiyle öne çıkar. İlçenin kültürel dokusunu yansıtan önemli bir dini yapıdır.", "place_query": "Hamamözü Merkez Cami, Hamamözü, Amasya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '75875319-415e-4116-bc6f-2f5970cf6691'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Amasya Kalesi", "summary": "Harşena Dağı''nın zirvesinde yer alan tarihi kale, Pontus Krallarına ait kaya mezarları ve muhteşem şehir manzarasıyla ziyaretçilerini büyüler.", "place_query": "Amasya Kalesi, Amasya Merkez"}, {"title": "Kral Kaya Mezarları", "summary": "Helenistik dönem Pontus krallarına ait kayalara oyulmuş anıtsal mezarlar, Yeşilırmak Nehri kıyısında görkemli bir siluet oluşturur.", "place_query": "Kral Kaya Mezarları, Amasya Merkez"}, {"title": "Yeşilırmak Nehri ve Yalıboyu Evleri", "summary": "Nehir kenarında sıralanmış geleneksel Osmanlı dönemi ahşap evler, romantik yürüyüş yolları ve çay bahçeleriyle huzurlu bir atmosfer sunar.", "place_query": "Yalıboyu Evleri, Amasya Merkez"}, {"title": "Amasya Arkeoloji Müzesi", "summary": "Hitit, Frig, Roma ve Osmanlı dönemlerine ait zengin eser koleksiyonu ile bölgenin binlerce yıllık tarihine ışık tutar.", "place_query": "Amasya Arkeoloji Müzesi, Amasya Merkez"}, {"title": "Hazeranlar Konağı", "summary": "19. yüzyıldan kalma restore edilmiş geleneksel bir konak olan yapı, etnografya müzesi olarak hizmet verir ve dönemin yaşamını sergiler.", "place_query": "Hazeranlar Konağı, Amasya Merkez"}, {"title": "Saraydüzü Kışla Binası (Amasya Tamimi Müzesi)", "summary": "Milli Mücadele''nin önemli kararlarının alındığı tarihi bina, günümüzde müze olarak ziyaretçilere açıktır ve kurtuluş hikayesini anlatır.", "place_query": "Saraydüzü Kışla Binası, Amasya Merkez"}, {"title": "Büyük Ağa Medresesi", "summary": "Selçuklu döneminden kalma taş işçiliğiyle dikkat çeken tarihi medrese, avlusundaki şadırvanı ve sakin atmosferiyle görülmeye değerdir.", "place_query": "Büyük Ağa Medresesi, Amasya Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1968cdad-fb82-47dd-8192-b0b031c80967'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Merzifon Tarihi Saat Kulesi", "summary": "Merzifon''un simgesi haline gelmiş bu tarihi saat kulesi, 19. yüzyılda yapılmış olup şehrin merkezinde yer alır. Ziyaretçiler, hem mimari dokuyu görmek hem de çevresindeki tarihi atmosferi hissetmek için bu noktayı sıkça ziyaret eder.", "place_query": "Merzifon Saat Kulesi, Merzifon, Amasya"}, {"title": "Merzifon Müzesi", "summary": "Eski bir medrese binasında hizmet veren müze, bölgenin arkeolojik ve etnografik eserlerini sergiler. Hitit, Roma, Bizans ve Osmanlı dönemlerine ait buluntular ile yöresel kıyafet ve eşyalar görülmeye değerdir.", "place_query": "Merzifon Müzesi, Merzifon, Amasya"}, {"title": "Kara Mustafa Paşa Külliyesi", "summary": "Osmanlı Sadrazamı Merzifonlu Kara Mustafa Paşa tarafından yaptırılan külliye; cami, medrese, hamam ve çarşıdan oluşur. Tarihi taş işçiliği ve avlusundaki huzur veren atmosferiyle ilçenin en önemli yapılarındandır.", "place_query": "Kara Mustafa Paşa Külliyesi, Merzifon, Amasya"}, {"title": "Merzifon Çelebi Mehmet Medresesi", "summary": "15. yüzyıldan kalma bu tarihi medrese, Osmanlı dönemi eğitim yapılarının güzel bir örneğidir. Günümüzde restore edilerek kültürel etkinliklere ev sahipliği yapmakta olup fotoğrafçılar için de ideal bir mekandır.", "place_query": "Çelebi Mehmet Medresesi, Merzifon, Amasya"}, {"title": "Merzifon Yalıboyu Evleri", "summary": "Tarihi ahşap ve taş mimarinin izlerini taşıyan bu Osmanlı dönemi evleri, dar sokaklar boyunca sıralanır. Özellikle yürüyüş yapmak ve nostaljik bir atmosfer yaşamak isteyenler için popüler bir güzergahtır.", "place_query": "Yalıboyu Evleri, Merzifon, Amasya"}, {"title": "Merzifon Kalesi (Kale Tepe)", "summary": "Şehre hakim bir tepe üzerinde bulunan kalıntılar, antik dönemden günümüze ulaşmıştır. Kaleye tırmanan ziyaretçiler, Merzifon''un panoramik manzarasını izleyebilir ve tarih öncesi döneme ait izleri keşfedebilir.", "place_query": "Merzifon Kalesi, Merzifon, Amasya"}, {"title": "Merzifon Kapalı Çarşısı", "summary": "Osmanlı döneminde inşa edilen tarihi kapalı çarşı, yöresel ürünler ve el sanatları satan dükkanlarıyla bilinir. Ziyaretçiler, burada Merzifon''a özgü leblebi ve diğer yöresel tatları tadabilir, hediyelik eşya alabilir.", "place_query": "Merzifon Kapalı Çarşısı, Merzifon, Amasya"}, {"title": "Sultan II. Bayezid Camii", "summary": "15. yüzyılda yapılan bu tarihi cami, kesme taştan inşa edilmiş olup zarif minaresiyle dikkat çeker. İç mekanındaki sade ama etkileyici süslemeleri ve geniş avlusuyla ibadet ve ziyaret için önemli bir duraktır.", "place_query": "Sultan II. Bayezid Camii, Merzifon, Amasya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '80c9c34f-065d-41c6-b41b-e981ad1815fe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Suluova Kapalı Pazar Yeri", "summary": "İlçenin en hareketli noktalarından biri olan bu pazar yeri, özellikle haftalık kurulan pazar günlerinde yöresel ürünler, taze sebze ve meyvelerle dolup taşar. Ziyaretçiler burada hem alışveriş yapabilir hem de Amasya''nın kırsal yaşamına dair otantik bir deneyim yaşayabilir.", "place_query": "Suluova Kapalı Pazar Yeri, Suluova, Amasya"}, {"title": "Suluova Şehir Stadı", "summary": "İlçenin spor ve etkinlik merkezi olarak bilinen bu stadyum, özellikle yerel futbol maçları ve açık hava etkinlikleri sırasında canlı bir atmosfere sahiptir. Suluova''nın sosyal hayatını gözlemlemek için iyi bir noktadır.", "place_query": "Suluova Şehir Stadı, Suluova, Amasya"}, {"title": "Suluova Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla bilinen bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için idealdir. Yeşil alanları ve temiz havasıyla özellikle hafta sonları aileler tarafından tercih edilir.", "place_query": "Suluova Mesire Alanı, Suluova, Amasya"}, {"title": "Suluova Atatürk Parkı", "summary": "İlçenin merkezinde yer alan bu park, dinlenme ve yürüyüş yapma imkanı sunar. Heykeli ve yeşil dokusuyla hem yerel halkın hem de ziyaretçilerin uğrak noktasıdır.", "place_query": "Suluova Atatürk Parkı, Suluova, Amasya"}, {"title": "Suluova Cami (Merkez Cami)", "summary": "İlçenin en büyük ve en eski camilerinden biri olan Merkez Cami, mimarisi ve manevi atmosferiyle dikkat çeker. Tarihi dokuyu hissetmek ve huzurlu bir an yaşamak isteyenler için önemli bir duraktır.", "place_query": "Suluova Merkez Cami, Suluova, Amasya"}, {"title": "Suluova Hükümet Konağı ve Çevresi", "summary": "İlçenin idari merkezi olan bu yapı, çevresindeki meydan ve kafelerle birlikte şehrin kalbini oluşturur. Tarihi bir bina olmasa da Suluova''nın modern yüzünü yansıtan önemli bir noktadır.", "place_query": "Suluova Hükümet Konağı, Suluova, Amasya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fdb366ae-3874-45a3-9ae0-8e5d69d3080c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Borabay Gölü Tabiat Parkı", "summary": "Taşova''nın 15 km kuzeydoğusunda, çam ormanlarıyla çevrili heyelan set gölüdür. Piknik, kamp, yürüyüş ve fotoğrafçılık için popüler bir doğa kaçamağıdır.", "place_query": "Borabay Gölü Tabiat Parkı, Taşova, Amasya"}, {"title": "Taşova Müzesi", "summary": "İlçe merkezinde yer alan müze, bölgedeki arkeolojik ve etnografik eserleri sergileyerek Taşova''nın tarihine ışık tutar.", "place_query": "Taşova Müzesi, Amasya"}, {"title": "Kızılkaya Köprüsü", "summary": "Kızılkaya Köyü yakınlarındaki tarihi taş köprü, Osmanlı dönemi mimarisini yansıtır ve çevresindeki doğal manzara ile dikkat çeker.", "place_query": "Kızılkaya Köprüsü, Taşova, Amasya"}, {"title": "Yeşilırmak Kenarı Mesire Alanı", "summary": "Taşova merkezinden geçen Yeşilırmak boyunca uzanan yürüyüş yolları ve piknik alanları, huzurlu bir gün geçirmek için idealdir.", "place_query": "Yeşilırmak Kenarı, Taşova, Amasya"}, {"title": "Derecik Göleti", "summary": "Derecik köyü yakınlarındaki bu gölet, balık tutma ve doğa yürüyüşü gibi aktiviteler için sakin bir ortam sunar.", "place_query": "Derecik Göleti, Taşova, Amasya"}, {"title": "Yemişli Köyü Yaylası", "summary": "Yayla havasını solumak ve doğa ile baş başa kalmak isteyenler için Yemişli Köyü yaylası, yeşil alanları ve temiz havasıyla öne çıkar.", "place_query": "Yemişli Köyü Yaylası, Taşova, Amasya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c24e2475-d126-4d1c-a15e-1d081fa8a1bc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akyurt Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale, bölgenin en önemli kültürel miraslarından biridir. Ziyaretçiler, kaleyi keşfederken çevredeki doğal güzellikleri de izleme fırsatı bulur.", "place_query": "Akyurt Kalesi, Ankara"}, {"title": "Akyurt Göleti ve Mesire Alanı", "summary": "Doğa ile iç içe huzurlu bir ortam sunan gölet, piknik ve yürüyüş için idealdir. Hafta sonu kaçamaklarında sıkça tercih edilen bu alan, aileler için popüler bir dinlenme noktasıdır.", "place_query": "Akyurt Göleti, Ankara"}, {"title": "Büyük Ayı Mağarası", "summary": "Doğal oluşumuyla dikkat çeken mağara, macera arayan ziyaretçiler için ilgi çekici bir duraktır. Mağaranın içindeki sarkıt ve dikitler, doğa tutkunlarını büyüler.", "place_query": "Büyük Ayı Mağarası, Akyurt, Ankara"}, {"title": "Akyurt Halk Pazarı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı pazar, bölgenin kültürel dokusunu yansıtır. Taze meyve, sebze ve hediyelik eşya almak isteyenler için canlı bir alışveriş noktasıdır.", "place_query": "Akyurt Halk Pazarı, Ankara"}, {"title": "Akyurt Parkı", "summary": "Şehir merkezinde yer alan bu park, yeşil alanları ve yürüyüş yollarıyla dinlenmek isteyenler için idealdir. Çocuk oyun alanları ve oturma banklarıyla ailelerin uğrak noktasıdır.", "place_query": "Akyurt Parkı, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '46da2357-aaee-4709-b427-b574e24ea928'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Anadolu Medeniyetleri Müzesi", "summary": "Tarih öncesi çağlardan Osmanlı''ya uzanan eşsiz bir koleksiyona ev sahipliği yapan müze, dünyanın en önemli müzeleri arasında sayılır. Hitit, Frig ve Urartu eserleri mutlaka görülmelidir.", "place_query": "Anadolu Medeniyetleri Müzesi, Altındağ, Ankara"}, {"title": "Ankara Kalesi", "summary": "Şehrin en yüksek noktasındaki tarihi kale, panoramik Ankara manzarası sunar. İçindeki dar sokaklar, geleneksel evler ve sanat atölyeleri ile keşfedilmeye değerdir.", "place_query": "Ankara Kalesi, Altındağ, Ankara"}, {"title": "Rahmi M. Koç Müzesi", "summary": "Eski bir tarihi handa yer alan müze, endüstri, ulaşım ve iletişim tarihine ait geniş bir koleksiyon sergiler. Özellikle nostaljik araçlar ve denizaltı bölümü oldukça ilgi çekicidir.", "place_query": "Rahmi M. Koç Müzesi, Altındağ, Ankara"}, {"title": "Hacı Bayram-ı Veli Camii", "summary": "Ankara''nın en kutsal ve tarihi mekanlarından biri olan cami, 15. yüzyıldan kalma bir Osmanlı eseridir. Yanı başındaki Augustus Tapınağı ile birlikte farklı din ve kültürlerin izlerini taşır.", "place_query": "Hacı Bayram-ı Veli Camii, Altındağ, Ankara"}, {"title": "Ulus Cumhuriyet Meydanı ve Kurtuluş Savaşı Müzesi", "summary": "Cumhuriyet''in kalbi sayılan meydan, 1. Türkiye Büyük Millet Meclisi binasını barındıran Kurtuluş Savaşı Müzesi''ne ev sahipliği yapar. Milli mücadele ruhunu en iyi yansıtan noktalardan biridir.", "place_query": "Kurtuluş Savaşı Müzesi, Ulus, Altındağ, Ankara"}, {"title": "Gençlik Parkı", "summary": "Ankara''nın en eski ve büyük parklarından biri olan Gençlik Parkı, yapay gölü, lunaparkı ve yürüyüş yollarıyla aileler için ideal bir dinlenme alanıdır. Geceleri renkli ışıklandırmasıyla ayrı bir güzellik sunar.", "place_query": "Gençlik Parkı, Altındağ, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '85885b8f-32de-4adf-ae34-b68076b7391f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayaş Kaplıcaları", "summary": "Ankara''ya yakınlığıyla bilinen bu kaplıcalar, romatizmal ve cilt rahatsızlıklarına iyi gelen termal sularıyla ünlüdür. Ziyaretçiler hem şifalı sularda yıkanabilir hem de dinlenme tesislerinde vakit geçirebilir.", "place_query": "Ayaş Kaplıcaları, Ayaş, Ankara"}, {"title": "Ayaş Müzesi", "summary": "Tarihi bir konakta hizmet veren bu müze, yöresel kıyafetler, mutfak eşyaları ve arkeolojik eserlerle Ayaş''ın kültürel mirasını sergiliyor. Geçmişe yolculuk yapmak isteyenler için ideal bir durak.", "place_query": "Ayaş Müzesi, Ayaş, Ankara"}, {"title": "Ayaş Kalesi", "summary": "Tarihi Roma dönemine kadar uzanan bu kale, ilçeye hakim bir tepe üzerinde yer alır. Kaleyi çevreleyen surlar ve manzarası, fotoğraf ve tarih meraklıları için ilgi çekicidir.", "place_query": "Ayaş Kalesi, Ayaş, Ankara"}, {"title": "Hıdırlık Tepesi", "summary": "Ayaş''ın panoramik manzarasını izleyebileceğiniz bu tepe, özellikle piknik ve doğa yürüyüşleri için tercih edilir. Yeşil alanları ve temiz havasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Hıdırlık Tepesi, Ayaş, Ankara"}, {"title": "Karakaya Mağarası", "summary": "İlçe merkezine yakın konumdaki bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Macera arayanlar ve doğa sporlarıyla ilgilenenler için keşfedilmeyi bekleyen bir yeraltı güzelliğidir.", "place_query": "Karakaya Mağarası, Ayaş, Ankara"}, {"title": "Ayaş Çarşı Hamamı", "summary": "Osmanlı döneminden kalma bu tarihi hamam, geleneksel mimarisi ve hala kullanılıyor olmasıyla öne çıkar. Termal suyu sayesinde hem kültürel bir deneyim hem de sağlıklı bir yıkanma imkanı sunar.", "place_query": "Ayaş Çarşı Hamamı, Ayaş, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '01237f00-c452-4ae6-8b96-8409436c8b1d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bala Kalesi", "summary": "Tarihi bir kalıntı olan Bala Kalesi, ilçenin en bilinen tarihi yapılarından biridir. Ziyaretçiler burada geçmişe yolculuk yapabilir ve çevredeki manzarayı izleyebilir.", "place_query": "Bala Kalesi, Bala, Ankara"}, {"title": "Bala Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, mimarisi ve huzurlu atmosferiyle dikkat çeker. Yöre halkı ve ziyaretçiler için önemli bir ibadet ve kültür noktasıdır.", "place_query": "Bala Merkez Camii, Bala, Ankara"}, {"title": "Kesikköprü Barajı ve Mesire Alanı", "summary": "Kızılırmak üzerinde kurulu bu baraj, piknik ve doğa yürüyüşleri için ideal bir ortam sunar. Su manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Kesikköprü Barajı, Bala, Ankara"}, {"title": "Bala Göleti", "summary": "Doğal güzelliği ve çevresindeki yeşil alanlarıyla bilinen Bala Göleti, balık tutma ve dinlenme aktiviteleri için popülerdir. Sessiz bir kaçamak arayanlar için biçilmiş kaftandır.", "place_query": "Bala Göleti, Bala, Ankara"}, {"title": "Afşar Köyü Tarihi Evleri", "summary": "Geleneksel Ankara mimarisini yansıtan bu tarihi köy evleri, taş ve ahşap işçiliğiyle göz kamaştırır. Köy atmosferinde keyifli bir yürüyüş yapabilirsiniz.", "place_query": "Afşar Köyü, Bala, Ankara"}, {"title": "Bala Yaylası", "summary": "Temiz havası ve geniş otlaklarıyla ünlü Bala Yaylası, doğa severler için harika bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek ve manzaranın tadını çıkarmak için idealdir.", "place_query": "Bala Yaylası, Bala, Ankara"}, {"title": "Karakeçili Köyü ve Çevresi", "summary": "Bala''ya bağlı bu köy, bozkır manzaraları ve geleneksel köy yaşamını deneyimlemek isteyenler için güzel bir duraktır. Doğa yürüyüşleri ve fotoğrafçılık için uygundur.", "place_query": "Karakeçili Köyü, Bala, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cccccb5e-efc5-426b-bb66-15090db892a3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beypazarı Evleri", "summary": "Tarihi Beypazarı evleri, Osmanlı döneminden kalma ahşap ve kerpiç mimarisiyle ünlüdür. Dar sokaklarda yürürken bu restore edilmiş konakların zarafetini yakından görebilirsiniz.", "place_query": "Beypazarı Evleri, Beypazarı, Ankara"}, {"title": "Beypazarı Tarihi Çarşı", "summary": "Yüzyıllık bakırcılar, yemeniciler ve el sanatları dükkanlarının bulunduğu tarihi çarşı, yöresel ürünler alışverişi için ideal bir duraktır.", "place_query": "Beypazarı Tarihi Çarşı, Beypazarı, Ankara"}, {"title": "Hıdırlık Tepesi", "summary": "Beypazarı''nın panoramik manzarasını sunan bu tepe, özellikle gün batımında muhteşem bir seyir noktasıdır. Piknik alanları ve dinlenme tesisleriyle ziyaretçileri ağırlar.", "place_query": "Hıdırlık Tepesi, Beypazarı, Ankara"}, {"title": "İnözü Vadisi", "summary": "Doğal kaya oluşumları ve mağaralarıyla ünlü bu vadi, doğa yürüyüşleri ve fotoğrafçılık için popüler bir yerdir. Vadideki tarihi kilise kalıntıları da ilgi çeker.", "place_query": "İnözü Vadisi, Beypazarı, Ankara"}, {"title": "Beypazarı Müzesi", "summary": "Eski bir konakta hizmet veren müze, bölgenin arkeolojik ve etnografik eserlerini sergiler. Beypazarı''nın tarihini ve kültürünü yakından tanımak için mutlaka görülmelidir.", "place_query": "Beypazarı Müzesi, Beypazarı, Ankara"}, {"title": "Taş Mektep", "summary": "Osmanlı döneminde eğitim yapısı olarak inşa edilen bu tarihi bina, günümüzde kültür merkezi olarak kullanılmaktadır. Mimari detayları ve içindeki sergiler dikkat çeker.", "place_query": "Taş Mektep, Beypazarı, Ankara"}, {"title": "Beypazarı Kurum ve Havuçlu Tarhana Üretim Tesisleri", "summary": "Beypazarı''nın meşhur kurusu ve havuçlu tarhanasının üretildiği bu tesisler, yöresel lezzetleri tatmak ve satın almak için ziyaret edilebilir.", "place_query": "Beypazarı Kurum ve Havuçlu Tarhana Üretim Tesisleri, Beypazarı, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ebf5cccb-482e-4e52-9903-ec57fdfe2936'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamlıdere Şelalesi", "summary": "Orman içinde yer alan bu şelale, serinletici atmosferi ve doğal güzelliğiyle piknik ve doğa yürüyüşü için idealdir.", "place_query": "Çamlıdere Şelalesi, Çamlıdere, Ankara"}, {"title": "Çamlıdere Kent Ormanı", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve mesire yerleriyle ailece vakit geçirmek için popüler bir doğal alandır.", "place_query": "Çamlıdere Kent Ormanı, Çamlıdere, Ankara"}, {"title": "Aydıncık Köyü Eski Evleri", "summary": "Tarihi taş ve ahşap mimarisiyle dikkat çeken bu köy evleri, geleneksel yaşamı gözlemlemek isteyenler için güzel bir duraktır.", "place_query": "Aydıncık Köyü, Çamlıdere, Ankara"}, {"title": "Çamlıdere Yaylası", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü olan yayla, özellikle yaz aylarında kamp ve doğa tutkunlarının uğrak noktasıdır.", "place_query": "Çamlıdere Yaylası, Çamlıdere, Ankara"}, {"title": "Peçenek Barajı", "summary": "Çamlıdere sınırlarında yer alan bu baraj gölü, kuş gözlemi ve huzurlu bir doğa kaçamağı arayanlar için idealdir.", "place_query": "Peçenek Barajı, Çamlıdere, Ankara"}, {"title": "Çamlıdere Merkez Camii", "summary": "Osmanlı mimari izlerini taşıyan bu tarihi cami, ilçenin merkezinde yer alır ve dini turizm açısından önemlidir.", "place_query": "Çamlıdere Merkez Camii, Çamlıdere, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4f7a198d-04fc-4d96-bd6f-b56b29f84ec1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Anıtkabir", "summary": "Mustafa Kemal Atatürk''ün anıt mezarı ve müzesidir. Türkiye Cumhuriyeti''nin kurucusuna saygı duruşunda bulunmak ve etkileyici mimariyi görmek için ziyaret edilir.", "place_query": "Anıtkabir, Çankaya, Ankara"}, {"title": "Ankara Kalesi", "summary": "Şehrin tarihi çekirdeğini oluşturan, Roma ve Osmanlı dönemlerinden izler taşıyan surlarla çevrili bir tepedir. Kale içindeki dar sokaklar, geleneksel evler ve panoramik Ankara manzarası görülmeye değerdir.", "place_query": "Ankara Kalesi, Altındağ, Ankara"}, {"title": "Atakule", "summary": "Çankaya''nın simgesi haline gelmiş, 125 metre yüksekliğindeki bu kuleden Ankara''nın kuşbakışı manzarası izlenebilir. Tepesindeki döner restoran da popüler bir duraktır.", "place_query": "Atakule, Çankaya, Ankara"}, {"title": "Anadolu Medeniyetleri Müzesi", "summary": "Paleolitik Çağ''dan Osmanlı''ya kadar Anadolu topraklarında yaşamış uygarlıklara ait eşsiz eserlerin sergilendiği dünyaca ünlü bir müzedir. Hitit, Frig ve Urartu koleksiyonları özellikle dikkat çekicidir.", "place_query": "Anadolu Medeniyetleri Müzesi, Altındağ, Ankara"}, {"title": "Gençlik Parkı", "summary": "Ankara''nın en büyük ve en eski parklarından biri olup, yapay gölü, lunaparkı ve yeşil alanlarıyla aileler için ideal bir dinlenme ve eğlence mekanıdır.", "place_query": "Gençlik Parkı, Altındağ, Ankara"}, {"title": "Botanik Parkı", "summary": "Çankaya''da yer alan bu huzurlu park, binlerce bitki türü, yürüyüş yolları ve göletiyle doğaseverler için kaçış noktasıdır. Özellikle bahar aylarında rengarenk çiçeklerle kaplanır.", "place_query": "Botanik Parkı, Çankaya, Ankara"}, {"title": "Kocatepe Camii", "summary": "Ankara''nın en büyük ve en görkemli camilerinden biri olan Kocatepe, Osmanlı ve Selçuklu mimari tarzlarını yansıtan etkileyici yapısıyla dikkat çeker. Hem ibadet hem de mimari ziyaretler için popülerdir.", "place_query": "Kocatepe Camii, Çankaya, Ankara"}, {"title": "Seğmenler Parkı", "summary": "Çankaya''nın göbeğinde yer alan büyük bir yeşil alandır. Heykelleri, yürüyüş yolları ve kafeleriyle hafta sonu piknikleri ve açık hava etkinlikleri için sıkça tercih edilir.", "place_query": "Seğmenler Parkı, Çankaya, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bdc8c98d-f603-4b69-8bc3-adabfd5639e9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aydos Kalesi", "summary": "Tarihi bir Bizans kalesi olan Aydos Kalesi, Ankara''nın Çubuk ilçesi sınırları içinde yer alır. Ziyaretçiler, kalenin surları ve burçları arasında dolaşarak bölgenin tarihine tanıklık edebilir ve çevredeki doğal manzaranın keyfini çıkarabilir.", "place_query": "Aydos Kalesi, Çubuk, Ankara"}, {"title": "Çubuk Barajı ve Mesire Alanı", "summary": "Şehir merkezine yakınlığıyla bilinen Çubuk Barajı, piknik alanları, yürüyüş parkurları ve huzurlu göl manzarasıyla doğa severler için popüler bir kaçış noktasıdır. Hafta sonu aile ziyaretleri için idealdir.", "place_query": "Çubuk Barajı, Çubuk, Ankara"}, {"title": "Çubuk Şehir Ormanı", "summary": "Geniş çam ağaçları ve temiz havasıyla bilinen Çubuk Şehir Ormanı, doğa yürüyüşleri ve kampçılık için uygun bir ortam sunar. Ziyaretçiler, şehir gürültüsünden uzaklaşarak kuş sesleri eşliğinde dinlenme fırsatı bulur.", "place_query": "Çubuk Şehir Ormanı, Çubuk, Ankara"}, {"title": "Çubuk Tarihi Hamamı", "summary": "Osmanlı döneminden kalma bu tarihi hamam, geleneksel mimarisi ve hâlâ kullanılan orijinal dokusuyla dikkat çeker. Çubuk''un kültürel mirasını yakından görmek isteyenler için önemli bir duraktır.", "place_query": "Çubuk Tarihi Hamamı, Çubuk, Ankara"}, {"title": "Karacakaya Göleti", "summary": "Çubuk ilçe merkezine kısa bir mesafede yer alan Karacakaya Göleti, çevresindeki yeşil alanlar ve gölet manzarasıyla sakin bir piknik ve balık tutma noktasıdır. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Karacakaya Göleti, Çubuk, Ankara"}, {"title": "Çubuk Yaylası (Köşk Yaylası)", "summary": "Yüksek rakımı ve serin havasıyla yaz aylarında sıkça ziyaret edilen Çubuk Yaylası, doğa yürüyüşleri ve kamp için idealdir. Yayla evleri ve geniş otlaklarıyla huzurlu bir doğa deneyimi sunar.", "place_query": "Çubuk Yaylası, Çubuk, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c6b4cb5d-7447-4860-9b84-e1a95b622132'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Elmadağ Kayak Merkezi", "summary": "Ankara''ya en yakın kayak merkezi olan Elmadağ Kayak Merkezi, kış aylarında kayak ve snowboard yapmak isteyenler için popüler bir destinasyondur. Şehre yakınlığı ve günübirlik tesisleri sayesinde hem yeni başlayanlar hem de deneyimli sporcular için idealdir.", "place_query": "Elmadağ Kayak Merkezi, Elmadağ, Ankara"}, {"title": "Hasanoğlan Köyü ve Köy Enstitüsü", "summary": "Tarihi Hasanoğlan Köy Enstitüsü, Türkiye''nin eğitim tarihinde önemli bir yere sahiptir. Köyün kendine özgü atmosferi ve enstitü binasının mimarisi, ziyaretçilere geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Hasanoğlan Köy Enstitüsü, Elmadağ, Ankara"}, {"title": "Elmadağ Göleti ve Mesire Alanı", "summary": "Doğayla iç içe bir piknik ve dinlenme alanı arayanlar için Elmadağ Göleti ideal bir seçenektir. Gölet çevresinde yürüyüş yapabilir, ailenizle keyifli vakit geçirebilirsiniz.", "place_query": "Elmadağ Göleti, Elmadağ, Ankara"}, {"title": "İdris Dağı Tabiat Parkı", "summary": "Elmadağ sınırları içinde yer alan İdris Dağı Tabiat Parkı, zengin bitki örtüsü ve temiz havasıyla doğa yürüyüşleri ve kampçılık için popüler bir noktadır. Şehir gürültüsünden uzaklaşmak isteyenler için huzurlu bir kaçış sunar.", "place_query": "İdris Dağı Tabiat Parkı, Elmadağ, Ankara"}, {"title": "Elmadağ Merkez Camii ve Tarihi Çarşı", "summary": "Elmadağ''ın merkezinde bulunan tarihi cami ve çevresindeki çarşı, ilçenin kültürel dokusunu yansıtır. Caminin mimarisi ve çarşıdaki yerel esnaf, ziyaretçilere otantik bir deneyim yaşatır.", "place_query": "Elmadağ Merkez Camii, Elmadağ, Ankara"}, {"title": "Kuşcu Köyü Mağaraları", "summary": "Doğa ve macera severler için Kuşcu Köyü''ndeki mağaralar keşfedilmeyi bekleyen gizli güzelliklerdendir. Bölgedeki kireçtaşı oluşumları ve sarkıtlar, mağara araştırmalarına ilgi duyanları cezbeder.", "place_query": "Kuşcu Köyü Mağaraları, Elmadağ, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e255cf8c-e10d-49aa-97a9-da4d1b53b17d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Etimesgut Belediyesi Atatürk Parkı", "summary": "İlçenin en büyük ve en popüler parkı olup, yürüyüş yolları, göleti ve yeşil alanlarıyla aileler için ideal bir dinlenme ve piknik alanıdır.", "place_query": "Etimesgut Belediyesi Atatürk Parkı, Ankara"}, {"title": "Göksu Parkı", "summary": "Ankara''nın en büyük parklarından biri olan Göksu Parkı, geniş yürüyüş parkurları, bisiklet yolları ve göletiyle hafta sonu kaçamakları için popüler bir noktadır.", "place_query": "Göksu Parkı, Etimesgut, Ankara"}, {"title": "Etimesgut Hamamı (Tarihi Etimesgut Hamamı)", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan hamam, restore edilerek günümüzde hizmet vermeye devam etmektedir ve ilçenin kültürel mirasını yansıtır.", "place_query": "Tarihi Etimesgut Hamamı, Ankara"}, {"title": "Etimesgut Kent Müzesi", "summary": "İlçenin tarihini, kültürünü ve gelişimini sergileyen müze, ziyaretçilere Etimesgut''un geçmişine dair keyifli bir yolculuk sunar.", "place_query": "Etimesgut Kent Müzesi, Ankara"}, {"title": "Etimesgut Şelalesi ve Mesire Alanı", "summary": "Yapay şelalesi, piknik alanları ve kafeteryasıyla ailelerin ve doğa severlerin sıkça tercih ettiği, şehir içinde huzurlu bir kaçış noktasıdır.", "place_query": "Etimesgut Şelalesi ve Mesire Alanı, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3efdf363-ff69-4af9-89ed-79c5b0415573'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Evren Gölü", "summary": "Doğal güzelliği ve kuş gözlemi için popüler bir sulak alan. Ziyaretçiler huzurlu bir doğa yürüyüşü yapabilir ve çeşitli kuş türlerini gözlemleyebilir.", "place_query": "Evren Gölü, Evren, Ankara"}, {"title": "Evren Kalesi", "summary": "Tarihi bir kalıntı olan yapı, bölgenin geçmişine ışık tutar. Tepe üzerindeki konumuyla çevreye hakim bir manzara sunar.", "place_query": "Evren Kalesi, Evren, Ankara"}, {"title": "Hırfanlı Barajı", "summary": "Evren sınırları içinde yer alan büyük bir baraj. Balık tutma, piknik ve doğa ile baş başa vakit geçirmek için ideal bir noktadır.", "place_query": "Hırfanlı Barajı, Evren, Ankara"}, {"title": "Evren Merkez Camii", "summary": "İlçenin merkezinde bulunan tarihi ve mimari açıdan dikkat çeken bir cami. Hem ibadet hem de kültürel ziyaret için uğranabilir.", "place_query": "Evren Merkez Camii, Evren, Ankara"}, {"title": "Kızılırmak Nehri Kıyıları", "summary": "Evren''den geçen Kızılırmak''ın kıyıları, doğa yürüyüşleri ve fotoğrafçılık için güzel rotalar sunar. Sakin atmosferiyle bilinir.", "place_query": "Kızılırmak Nehri, Evren, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8d1f8f3f-8d3c-4c21-92ef-fca77897e75e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mogan Gölü", "summary": "Ankara''ya yakınlığıyla bilinen Mogan Gölü, yürüyüş yolları, bisiklet parkurları ve piknik alanlarıyla doğa severler için ideal bir kaçış noktasıdır. Gölde sandal ve tekne turları da popüler aktiviteler arasındadır.", "place_query": "Mogan Gölü, Gölbaşı, Ankara"}, {"title": "Gölbaşı Belediyesi Seyir Tepesi", "summary": "Gölbaşı manzarasını kuşbakışı görebileceğiniz bu seyir tepesi, özellikle gün batımında muhteşem bir fotoğraf karesi sunar. Huzurlu atmosferiyle ziyaretçilerine keyifli anlar yaşatır.", "place_query": "Gölbaşı Seyir Tepesi, Ankara"}, {"title": "Hacı Bayram-ı Veli Türbesi (Gölbaşı)", "summary": "Ankara''nın manevi değerlerinden Hacı Bayram-ı Veli''nin adını taşıyan bu türbe, Gölbaşı ilçesinde yer alır ve ziyaretçiler tarafından sıkça uğranan bir dini mekandır. Çevresi bakımlı bahçelerle çevrilidir.", "place_query": "Hacı Bayram-ı Veli Türbesi, Gölbaşı, Ankara"}, {"title": "Gölbaşı Eymir Gölü", "summary": "Eymir Gölü, ODTÜ kampüsü sınırları içinde kalan ve doğa sporlarına elverişli bir alandır. Yürüyüş, koşu ve bisiklet parkurlarının yanı sıra gölde kano ve yelken gibi su sporları da yapılabilir.", "place_query": "Eymir Gölü, Gölbaşı, Ankara"}, {"title": "Gölbaşı Mogan Parkı", "summary": "Mogan Gölü kıyısında yer alan bu büyük park, çocuk oyun alanları, kafeteryalar ve dinlenme banklarıyla aileler için popüler bir hafta sonu rotasıdır. Göl manzarası eşliğinde yürüyüş yapmak mümkündür.", "place_query": "Mogan Parkı, Gölbaşı, Ankara"}, {"title": "Gölbaşı İlçe Merkezi Tarihi Çarşı", "summary": "Gölbaşı''nın eski çarşı bölgesinde yer alan bu tarihi alan, yöresel ürünler ve el sanatları satan dükkanlarıyla dikkat çeker. Ziyaretçiler burada yöresel lezzetleri tadabilir ve küçük hediyelik eşyalar satın alabilir.", "place_query": "Gölbaşı Tarihi Çarşı, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd6f6fe3c-dc5a-4bf3-840a-1bfc9e515c89'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güdül Evleri", "summary": "Güdül''ün tarihi dokusunu yansıtan, restore edilmiş geleneksel Osmanlı evleri. Dar sokaklarında yürürken geçmişe yolculuk yapabilirsiniz.", "place_query": "Güdül Evleri, Güdül, Ankara"}, {"title": "Kirmir Çayı", "summary": "Güdül''ün içinden geçen, doğal güzelliğiyle ünlü bir akarsu. Özellikle yaz aylarında serinlemek ve piknik yapmak için idealdir.", "place_query": "Kirmir Çayı, Güdül, Ankara"}, {"title": "Güdül Kalesi", "summary": "Tarihi bir kalıntı olan Güdül Kalesi, ilçeye hakim bir tepede yer alır. Çevresindeki manzara, fotoğrafçılar ve doğa severler için eşsizdir.", "place_query": "Güdül Kalesi, Güdül, Ankara"}, {"title": "Sorgun Göleti", "summary": "Güdül''e bağlı Sorgun köyünde bulunan bu gölet, piknik alanları ve yürüyüş parkurları ile hafta sonu kaçamakları için popüler bir noktadır.", "place_query": "Sorgun Göleti, Güdül, Ankara"}, {"title": "Güdül Merkez Camii", "summary": "Osmanlı döneminden kalma tarihi bir cami olup, mimarisi ve süslemeleriyle dikkat çeker. İlçenin manevi ve kültürel merkezlerinden biridir.", "place_query": "Güdül Merkez Camii, Güdül, Ankara"}, {"title": "Çağa Şelalesi", "summary": "Güdül sınırları içinde yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla doğa yürüyüşçülerinin uğrak noktasıdır.", "place_query": "Çağa Şelalesi, Güdül, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '01f7b07a-4dcf-44f8-b8a5-65eb857b4fa5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Haymana Kaplıcaları", "summary": "Termal suları ve şifalı çamurlarıyla ünlü Haymana Kaplıcaları, romatizma ve cilt hastalıklarına iyi gelen doğal bir termal merkezdir. Bölgede birçok otel ve kaplıca tesisi bulunur.", "place_query": "Haymana Kaplıcaları, Haymana, Ankara"}, {"title": "Haymana Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan Haymana Kalesi, çevreye hakim manzarasıyla dikkat çeker. Kale kalıntıları, bölgenin antik geçmişine tanıklık etmek isteyen ziyaretçiler için ilgi çekicidir.", "place_query": "Haymana Kalesi, Haymana, Ankara"}, {"title": "Kurtuluş Savaşı Müzesi (Haymana)", "summary": "Haymana''da bulunan bu müze, Kurtuluş Savaşı dönemine ait belge, fotoğraf ve eşyaları sergiler. Bölgenin savaştaki stratejik önemini anlamak için ziyaret edilebilir.", "place_query": "Kurtuluş Savaşı Müzesi, Haymana, Ankara"}, {"title": "Sınırören Göleti", "summary": "Doğal güzelliği ve huzur veren ortamıyla Sınırören Göleti, piknik ve doğa yürüyüşü için idealdir. Gölet çevresinde kuş gözlemi yapmak da mümkündür.", "place_query": "Sınırören Göleti, Haymana, Ankara"}, {"title": "Boyalık Mağarası", "summary": "Bölgenin doğal oluşumlarından biri olan Boyalık Mağarası, sarkıt ve dikitleriyle dikkat çeker. Mağara, doğa severler ve macera arayanlar için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Boyalık Mağarası, Haymana, Ankara"}, {"title": "Çaldağ Tabiat Parkı", "summary": "Haymana sınırları içinde yer alan Çaldağ Tabiat Parkı, zengin bitki örtüsü ve temiz havasıyla kamp ve doğa yürüyüşü için popüler bir destinasyondur. Park, şehir gürültüsünden uzaklaşmak isteyenler için biçilmiş kaftandır.", "place_query": "Çaldağ Tabiat Parkı, Haymana, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0df9afad-0f29-4be4-b62d-6a588dde25cb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kahramankazan Şelalesi", "summary": "Ankara''ya yakın doğal bir kaçış noktası olan şelale, piknik alanları ve yürüyüş parkurlarıyla hafta sonu ziyaretçilerini ağırlar. Sessiz bir doğa deneyimi sunar.", "place_query": "Kahramankazan Şelalesi, Kahramankazan, Ankara"}, {"title": "Kahramankazan İlçe Merkezi (Cumhuriyet Meydanı)", "summary": "İlçenin kalbi sayılan meydan, çevresindeki kafeler ve tarihi dokuyla kısa bir mola için idealdir. Yerel halkın buluşma noktasıdır.", "place_query": "Cumhuriyet Meydanı, Kahramankazan, Ankara"}, {"title": "Rüya Bahçesi Mesire Alanı", "summary": "Geniş yeşil alanları ve çocuk oyun parklarıyla aileler için popüler bir mesire yeridir. Mangal yapmak ve dinlenmek için tercih edilir.", "place_query": "Rüya Bahçesi Mesire Alanı, Kahramankazan, Ankara"}, {"title": "Karaşar Yaylası", "summary": "Kahramankazan''a bağlı bu yayla, temiz havası ve doğal manzaralarıyla doğa yürüyüşçüleri ve kampçılar için huzurlu bir rotadır.", "place_query": "Karaşar Yaylası, Kahramankazan, Ankara"}, {"title": "Kılıçlar Köyü Göleti", "summary": "Sakin bir gölet çevresinde piknik ve olta balıkçılığı yapabileceğiniz bu alan, şehirden uzaklaşmak isteyenler için idealdir.", "place_query": "Kılıçlar Köyü Göleti, Kahramankazan, Ankara"}, {"title": "Kahramankazan Belediyesi Kent Ormanı", "summary": "Yürüyüş ve bisiklet parkurları, seyir terasları ve piknik masaları ile donatılmış bu ormanlık alan, doğayla iç içe vakit geçirmek için güzel bir seçenektir.", "place_query": "Kahramankazan Kent Ormanı, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '947b5c99-6298-4822-a141-f1f3851f8636'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kalecik Kalesi", "summary": "Ankara''nın Kalecik ilçesinin sembolü olan tarihi kale, Kızılırmak Vadisi''ne hakim bir tepe üzerinde yer alır. Ziyaretçilere hem tarihi bir atmosfer hem de muhteşem bir manzara sunar.", "place_query": "Kalecik Kalesi, Kalecik, Ankara"}, {"title": "Kızılırmak Vadisi", "summary": "Kalecik''ten geçen Kızılırmak Nehri''nin oluşturduğu bu vadi, doğal güzelliği ve yürüyüş rotalarıyla doğaseverler için ideal bir noktadır. Özellikle gün batımında eşsiz manzaralar izlenebilir.", "place_query": "Kızılırmak Vadisi, Kalecik, Ankara"}, {"title": "Kalecik Bağları ve Şarap Evi", "summary": "Kalecik Karası üzümüyle ünlü ilçede, bağlar arasında gezinti yapabilir ve yöresel şarap evlerinde tadım yapabilirsiniz. Bölgenin bağcılık kültürünü yakından tanıma fırsatı sunar.", "place_query": "Kalecik Bağları ve Şarap Evi, Kalecik, Ankara"}, {"title": "Çandır Kalesi", "summary": "Kalecik ilçe merkezine yakın konumdaki bu tarihi kale, Roma ve Bizans dönemlerine ait izler taşır. Sarp kayalıklar üzerine kurulu yapısıyla dikkat çeker ve çevresindeki doğa yürüyüşleri popülerdir.", "place_query": "Çandır Kalesi, Kalecik, Ankara"}, {"title": "Hacılar Kalesi", "summary": "Kalecik''in Hacılar Mahallesi''nde bulunan bu kale, bölgenin savunma yapıları arasında önemli bir yere sahiptir. Tarihi dokusu ve çevresindeki kırsal manzarasıyla ziyaretçileri cezbeder.", "place_query": "Hacılar Kalesi, Kalecik, Ankara"}, {"title": "Kalecik Ulu Camii", "summary": "Tarihi bir Osmanlı camisi olan Kalecik Ulu Camii, ilçenin merkezinde yer alır ve mimari detaylarıyla dikkat çeker. Hem ibadet hem de tarihi bir mekan olarak ziyaret edilebilir.", "place_query": "Kalecik Ulu Camii, Kalecik, Ankara"}, {"title": "Kalecik Şelalesi", "summary": "İlçe merkezine kısa bir mesafede bulunan bu doğal şelale, piknik alanları ve serin sularıyla özellikle yaz aylarında ziyaretçi akınına uğrar. Doğayla iç içe huzurlu bir kaçış noktasıdır.", "place_query": "Kalecik Şelalesi, Kalecik, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fb5c507a-a0eb-4ec3-86e2-ea8647020a9f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Rahmi M. Koç Müzesi Ankara", "summary": "Keçiören''de bulunan bu müze, sanayi, ulaşım ve iletişim tarihine ait geniş bir koleksiyona ev sahipliği yapar. Açık hava sergi alanı ve interaktif deneyimlerle ziyaretçilere keyifli bir öğrenme ortamı sunar.", "place_query": "Rahmi M. Koç Müzesi Ankara, Keçiören, Ankara"}, {"title": "Harikalar Diyarı", "summary": "Keçiören''in en büyük ve en popüler parkı olan Harikalar Diyarı, yürüyüş yolları, gölet, çocuk oyun alanları ve piknik alanlarıyla aileler için ideal bir dinlenme yeridir.", "place_query": "Harikalar Diyarı, Keçiören, Ankara"}, {"title": "Keçiören Teleferik ve Seyir Tepesi", "summary": "Keçiören''den başlayarak Ankara manzarasını kuşbakışı izleme imkanı sunan teleferik hattı, zirvedeki seyir terası ve kafe ile şehrin stresinden uzaklaşmak için harika bir seçenektir.", "place_query": "Keçiören Teleferik, Ankara"}, {"title": "Estergon Kalesi ve Türk Kültür Merkezi", "summary": "Macaristan''daki Estergon Kalesi''nin bir benzeri olarak inşa edilen bu yapı, içerisindeki müze ve kültür merkeziyle tarihi bir atmosfer sunar. Kale surlarından Ankara manzarası izlenebilir.", "place_query": "Estergon Kalesi, Keçiören, Ankara"}, {"title": "Keçiören Belediyesi Doğal Yaşam Parkı", "summary": "Çeşitli hayvan türlerine ev sahipliği yapan bu park, özellikle çocuklu aileler için eğitici ve eğlenceli bir gezi imkanı sağlar. Doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Keçiören Doğal Yaşam Parkı, Ankara"}, {"title": "Pursaklar Kalesi (Keçiören sınırında)", "summary": "Keçiören''e yakın konumda bulunan bu tarihi kale, restore edilmiş yapısı ve çevresindeki yeşil alanlarla hem tarih hem de doğa severler için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Pursaklar Kalesi, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1610c214-a578-4de9-9408-b33e4cffbaa8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızılcahamam Soğuksu Milli Parkı", "summary": "Ankara''ya yakınlığıyla bilinen bu milli park, zengin bitki örtüsü, yürüyüş parkurları ve piknik alanlarıyla doğa severler için ideal bir kaçış noktasıdır. İçerisinde bulunan kaplıcalar ve kamp alanları da ziyaretçilere farklı aktiviteler sunar.", "place_query": "Soğuksu Milli Parkı, Kızılcahamam, Ankara"}, {"title": "Kızılcahamam Kaplıcaları", "summary": "Şifalı termal sularıyla ünlü olan Kızılcahamam kaplıcaları, romatizma ve cilt hastalıklarına iyi geldiği düşünülen doğal kaynaklara ev sahipliği yapar. Bölgede birçok termal otel ve hamam bulunur.", "place_query": "Kızılcahamam Kaplıcaları, Ankara"}, {"title": "Çamlıdere Şelalesi", "summary": "Kızılcahamam ve Çamlıdere sınırında yer alan bu şelale, yemyeşil doğası ve serin sularıyla özellikle yaz aylarında piknik ve doğa yürüyüşü için popüler bir duraktır.", "place_query": "Çamlıdere Şelalesi, Ankara"}, {"title": "Kızılcahamam Belediye Parkı ve Seyir Tepesi", "summary": "İlçe merkezinde yer alan bu park, yürüyüş yolları ve göletiyle huzurlu bir ortam sunar. Yakınındaki seyir tepesi ise Kızılcahamam''ın kuşbakışı manzarasını izlemek için en güzel noktalardan biridir.", "place_query": "Kızılcahamam Belediye Parkı, Ankara"}, {"title": "Karagöl Tabiat Parkı", "summary": "Kızılcahamam''a yaklaşık 30 km uzaklıktaki bu krater gölü, çam ormanlarıyla çevrili eşsiz bir doğal güzelliktir. Piknik, kamp ve fotoğrafçılık için sıkça tercih edilen sakin bir alandır.", "place_query": "Karagöl Tabiat Parkı, Kızılcahamam, Ankara"}, {"title": "Güvem Örenyeri (Antik Kent)", "summary": "Kızılcahamam''ın Güvem köyü yakınlarında bulunan bu antik yerleşim, Roma ve Bizans dönemine ait kalıntılarıyla tarih meraklıları için ilgi çekicidir. Bölgede kaya mezarları ve yapı temelleri görülebilir.", "place_query": "Güvem Örenyeri, Kızılcahamam, Ankara"}, {"title": "Işık Dağı Kayak Merkezi", "summary": "Kızılcahamam sınırları içindeki Işık Dağı, kış aylarında kayak ve snowboard yapmak isteyenler için Ankara''ya en yakın kayak merkezlerinden biridir. Yazın ise doğa yürüyüşü ve dağ bisikleti için uygundur.", "place_query": "Işık Dağı Kayak Merkezi, Kızılcahamam, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c5ec99b6-70e3-4cb1-acc8-5f8e1fbf732e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ankara Kalesi", "summary": "Şehrin simgelerinden biri olan tarihi kale, Mamak ilçesine kısa bir mesafede yer alır ve Ankara manzarasını kuşbakışı izleme imkanı sunar.", "place_query": "Ankara Kalesi, Altındağ, Ankara"}, {"title": "Mamak Evleri", "summary": "Geleneksel Ankara mimarisini yansıtan restore edilmiş tarihi evler, ilçenin kültürel dokusunu keşfetmek isteyenler için ideal bir duraktır.", "place_query": "Mamak Evleri, Mamak, Ankara"}, {"title": "Mamak Ağaçlandırma Sahası", "summary": "Geniş yeşil alanları ve yürüyüş parkurlarıyla doğayla iç içe vakit geçirmek isteyenlerin tercih ettiği, piknik ve spor yapmaya uygun bir rekreasyon bölgesidir.", "place_query": "Mamak Ağaçlandırma Sahası, Mamak, Ankara"}, {"title": "Hüseyin Gazi Türbesi", "summary": "Mamak sınırlarındaki Hüseyin Gazi Tepesi''nde bulunan bu türbe, hem dini ziyaretler hem de şehir manzarası için sıkça uğranan bir noktadır.", "place_query": "Hüseyin Gazi Türbesi, Mamak, Ankara"}, {"title": "Mamak 100. Yıl Parkı", "summary": "Çocuk oyun alanları, yürüyüş yolları ve oturma alanlarıyla ailelerin keyifli vakit geçirebileceği modern bir şehir parkıdır.", "place_query": "Mamak 100. Yıl Parkı, Mamak, Ankara"}, {"title": "Anadolu Medeniyetleri Müzesi", "summary": "Mamak''a yakın konumdaki bu ünlü müze, Paleolitik çağdan Osmanlı''ya uzanan zengin arkeolojik koleksiyonuyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "Anadolu Medeniyetleri Müzesi, Altındağ, Ankara"}, {"title": "Kurtuluş Savaşı Müzesi (I. TBMM Binası)", "summary": "Ulus''ta yer alan bu tarihi bina, Milli Mücadele dönemine tanıklık etmiş olup Mamak''tan kolayca ulaşılabilir önemli bir kültürel miras alanıdır.", "place_query": "Kurtuluş Savaşı Müzesi, Ulus, Altındağ, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e5856290-e3cf-4dd6-99f2-cd3cf093407e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nallıhan Kuş Cenneti", "summary": "Türkiye''nin önemli kuş gözlem noktalarından biri olan bu alan, yüzlerce kuş türüne ev sahipliği yapar. Özellikle göç dönemlerinde eşsiz bir doğa şöleni sunar.", "place_query": "Nallıhan Kuş Cenneti, Nallıhan, Ankara"}, {"title": "Nallıhan Kalesi", "summary": "Tarihi bir Bizans kalesi olan yapı, Nallıhan''ın en yüksek noktasında yer alır ve çevrenin panoramik manzarasını izlemek için idealdir.", "place_query": "Nallıhan Kalesi, Nallıhan, Ankara"}, {"title": "Nallıhan İpek Böcekçiliği Müzesi", "summary": "Bölgenin geleneksel ipek böcekçiliği kültürünü tanıtan bu müze, tarihi ipek üretim sürecini ve araçlarını sergiler.", "place_query": "Nallıhan İpek Böcekçiliği Müzesi, Nallıhan, Ankara"}, {"title": "Sarıkaya Kaplıcaları", "summary": "Romatizmal hastalıklara iyi geldiği bilinen şifalı sularıyla ünlü bu kaplıca, doğal ortamında dinlenmek isteyenler için popüler bir duraktır.", "place_query": "Sarıkaya Kaplıcaları, Nallıhan, Ankara"}, {"title": "Nallıhan Evleri", "summary": "Tarihi Osmanlı dönemi mimarisini yansıtan ahşap ve taş yapılar, dar sokaklarıyla ilçenin otantik atmosferini yaşatır.", "place_query": "Nallıhan Evleri, Nallıhan, Ankara"}, {"title": "Çayırhan Barajı ve Mesire Alanı", "summary": "Baraj gölü çevresinde piknik ve doğa yürüyüşü yapılabilecek bu alan, huzurlu bir gün geçirmek için idealdir.", "place_query": "Çayırhan Barajı, Nallıhan, Ankara"}, {"title": "Nallıhan Tarihi Çarşı", "summary": "El dokuması halılar, bakır işlemeleri ve yöresel ürünlerin satıldığı bu çarşı, alışveriş ve kültürel keşif için canlı bir noktadır.", "place_query": "Nallıhan Tarihi Çarşı, Nallıhan, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b2e773bd-70c6-45d6-93cc-8ef786006c5a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gordion Antik Kenti (Yassıhöyük)", "summary": "Frigya Krallığı''nın başkenti olan bu antik kent, ünlü Kral Midas ile özdeşleşmiştir. Büyük Tümülüs, antik surlar ve kazı alanı, tarih meraklıları için eşsiz bir deneyim sunar.", "place_query": "Gordion Antik Kenti, Yassıhöyük, Polatlı, Ankara"}, {"title": "Polatlı Müzesi", "summary": "Kurtuluş Savaşı''na ait önemli eserlerin ve Gordion kazılarından çıkarılan arkeolojik buluntuların sergilendiği bu müze, bölgenin zengin tarihini keşfetmek için ideal bir duraktır.", "place_query": "Polatlı Müzesi, Polatlı, Ankara"}, {"title": "Sakarya Meydan Muharebesi Tarihi Milli Parkı", "summary": "Türk Kurtuluş Savaşı''nın dönüm noktalarından birine ev sahipliği yapan bu milli park, anıtları, şehitlikleri ve yürüyüş rotalarıyla hem tarihi hem de doğal bir ziyaret noktasıdır.", "place_query": "Sakarya Meydan Muharebesi Tarihi Milli Parkı, Polatlı, Ankara"}, {"title": "Duatepe Anıtı ve Şehitliği", "summary": "Sakarya Meydan Muharebesi sırasında büyük kahramanlıkların yaşandığı bu tepe, Mustafa Kemal Atatürk''ün anıtı ve şehitlikleriyle milli duyguları canlı tutan önemli bir ziyaret noktasıdır.", "place_query": "Duatepe Anıtı, Polatlı, Ankara"}, {"title": "Türk Yıldızları Anıtı", "summary": "Sakarya Meydan Muharebesi''nde Türk havacılarının kahramanlıklarını anmak için yapılan bu anıt, pilot figürleri ve etkileyici manzarasıyla dikkat çeker.", "place_query": "Türk Yıldızları Anıtı, Polatlı, Ankara"}, {"title": "Çeltikçi Göleti ve Mesire Alanı", "summary": "Polatlı''ya yaklaşık 30 km uzaklıkta bulunan bu gölet, piknik alanları ve doğal güzelliğiyle hafta sonu kaçamakları için huzurlu bir ortam sunar.", "place_query": "Çeltikçi Göleti, Polatlı, Ankara"}, {"title": "Polatlı Tarihi Evleri", "summary": "İlçe merkezinde yer alan bu geleneksel Türk evleri, Osmanlı dönemi mimarisinin izlerini taşır ve fotoğraf tutkunları için güzel kareler vaat eder.", "place_query": "Polatlı Tarihi Evleri, Polatlı, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1c3fb3e2-69fd-45c2-8c34-f526b7b0b856'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pursaklar Belediyesi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla ailelerin keyifli vakit geçirebileceği modern bir park. İlçenin en popüler dinlenme ve piknik noktalarından biridir.", "place_query": "Pursaklar Belediyesi Millet Bahçesi, Pursaklar, Ankara"}, {"title": "Pursaklar Mesire Alanı", "summary": "Şehir merkezine yakın, ağaçlık alan içerisinde piknik masaları ve mangal yapma imkanı sunan bir mesire alanı. Hafta sonları doğayla iç içe vakit geçirmek isteyenler tarafından sıkça tercih edilir.", "place_query": "Pursaklar Mesire Alanı, Pursaklar, Ankara"}, {"title": "Pursaklar Kültür ve Sanat Merkezi", "summary": "Tiyatro gösterileri, konserler ve sergilere ev sahipliği yapan modern bir kültür merkezi. İlçenin sanatsal ve kültürel etkinliklerinin kalbi konumundadır.", "place_query": "Pursaklar Kültür ve Sanat Merkezi, Pursaklar, Ankara"}, {"title": "Pursaklar Kapalı Pazar Yeri", "summary": "Geniş ve düzenli bir alana kurulan kapalı pazar, özellikle hafta sonları taze meyve, sebze ve giyim ürünleri için yoğun ilgi görür. Yerel halkın alışveriş ihtiyacını karşılayan önemli bir merkezdir.", "place_query": "Pursaklar Kapalı Pazar Yeri, Pursaklar, Ankara"}, {"title": "Pursaklar Göleti ve Çevresi", "summary": "Sakin bir doğa kaçamağı arayanlar için ideal olan gölet, çevresindeki yürüyüş yolu ve banklarla huzurlu bir atmosfer sunar. Özellikle akşam yürüyüşleri ve fotoğraf çekimleri için tercih edilir.", "place_query": "Pursaklar Göleti, Pursaklar, Ankara"}, {"title": "Fatih Sultan Mehmet Camii", "summary": "Modern mimarisi ve geniş avlusuyla ilçenin en büyük ve en bilinen camilerinden biridir. Hem ibadet hem de çevresindeki yeşil alanlarla sosyal bir buluşma noktasıdır.", "place_query": "Fatih Sultan Mehmet Camii, Pursaklar, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0c794fff-bcbc-4c36-b6b7-be32ec3c0df0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tuz Gölü", "summary": "Türkiye''nin en büyük ikinci gölü olan Tuz Gölü, Şereflikoçhisar sınırları içinde yer alır. Özellikle yaz aylarında suyun çekilmesiyle oluşan beyaz tuz tabakası ve flamingo manzaraları ile ünlüdür.", "place_query": "Tuz Gölü, Şereflikoçhisar, Ankara"}, {"title": "Şereflikoçhisar Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale, ilçeye hakim bir manzara sunar. Bölgenin savunma amaçlı kullanılan eski yapılarından biri olup, çevresindeki doğal doku ile dikkat çeker.", "place_query": "Şereflikoçhisar Kalesi, Ankara"}, {"title": "Şereflikoçhisar Müzesi", "summary": "İlçe merkezinde bulunan müze, bölgedeki arkeolojik kazılardan çıkarılan eserleri sergiler. Tuz Gölü çevresindeki antik yerleşimlere ait buluntuları görmek için idealdir.", "place_query": "Şereflikoçhisar Müzesi, Ankara"}, {"title": "Akgöl (Kulu-Şereflikoçhisar Sınırı)", "summary": "Tuz Gölü''ne yakın konumdaki bu sulak alan, kuş gözlemcileri için önemli bir duraktır. Özellikle flamingo ve diğer su kuşlarını doğal ortamlarında izleme fırsatı sunar.", "place_query": "Akgöl, Şereflikoçhisar, Ankara"}, {"title": "Pınarbaşı Mesire Alanı", "summary": "İlçe merkezine yakın bir konumda bulunan bu mesire alanı, piknik ve doğa yürüyüşü için tercih edilir. Yeşil alanları ve temiz havası ile hafta sonu kaçamakları için uygundur.", "place_query": "Pınarbaşı Mesire Alanı, Şereflikoçhisar"}, {"title": "Hacı Bektaş-ı Veli Türbesi (Şereflikoçhisar)", "summary": "İlçede bulunan bu türbe, yerel halk tarafından sıkça ziyaret edilen manevi bir mekandır. Tarihi ve dini önemi nedeniyle bölgeye gelen ziyaretçilerin uğrak noktalarından biridir.", "place_query": "Hacı Bektaş-ı Veli Türbesi, Şereflikoçhisar, Ankara"}, {"title": "Şereflikoçhisar Saat Kulesi", "summary": "İlçe merkezinde yer alan bu tarihi saat kulesi, Şereflikoçhisar''ın simgelerinden biridir. Çevresindeki alan, dinlenmek ve fotoğraf çekmek için popüler bir noktadır.", "place_query": "Şereflikoçhisar Saat Kulesi, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8989149b-965f-4ede-beb8-2a8d49031c4b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ankara Kalesi", "summary": "Ankara''nın simgelerinden biri olan tarihi kale, şehir merkezine hakim bir tepe üzerinde yer alır. İçerisinde geleneksel Ankara evleri ve müzeler bulunur, şehir manzarası eşsizdir.", "place_query": "Ankara Kalesi, Altındağ, Ankara"}, {"title": "Anadolu Medeniyetleri Müzesi", "summary": "Dünyanın en zengin arkeoloji müzelerinden biri olan bu müze, Paleolitik çağdan Osmanlı''ya kadar uzanan geniş bir koleksiyona ev sahipliği yapar. Özellikle Hitit eserleriyle ünlüdür.", "place_query": "Anadolu Medeniyetleri Müzesi, Altındağ, Ankara"}, {"title": "Anıtkabir", "summary": "Mustafa Kemal Atatürk''ün anıt mezarı olan Anıtkabir, görkemli mimarisi ve duygusal atmosferiyle her yıl milyonlarca ziyaretçi ağırlar. Barış Parkı ve müzeleriyle de görülmeye değerdir.", "place_query": "Anıtkabir, Çankaya, Ankara"}, {"title": "Gençlik Parkı", "summary": "Ankara''nın en eski ve en büyük parklarından biri olan Gençlik Parkı, yapay gölü, lunaparkı ve yeşil alanlarıyla aileler için ideal bir dinlenme ve eğlence noktasıdır.", "place_query": "Gençlik Parkı, Altındağ, Ankara"}, {"title": "Hacı Bayram Veli Camii", "summary": "Ankara''nın manevi merkezlerinden biri olan bu cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Augustus Tapınağı''nın hemen yanında yer almasıyla tarihi bir bütünlük sunar.", "place_query": "Hacı Bayram Veli Camii, Altındağ, Ankara"}, {"title": "Kuğulu Park", "summary": "Ankara''nın en popüler ve sevimli parklarından biri olan Kuğulu Park, adını göletindeki kuğulardan alır. Özellikle bahar ve yaz aylarında yürüyüş yapmak ve dinlenmek için harika bir yerdir.", "place_query": "Kuğulu Park, Çankaya, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b76591d6-88dd-411c-a083-24924abc7e59'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Atatürk Orman Çiftliği (AOÇ)", "summary": "Ankara''nın simge yapılarından biri olan AOÇ, hem tarihi hem de doğal güzellikleriyle ünlüdür. Ziyaretçiler burada Atatürk''ün mirası olan geniş yeşil alanlarda yürüyüş yapabilir, hayvanat bahçesini gezebilir ve meşhur süt ürünleri ile dondurmasını tadabilir.", "place_query": "Atatürk Orman Çiftliği, Yenimahalle, Ankara"}, {"title": "Ankara Millet Bahçesi", "summary": "Yenimahalle''deki bu büyük şehir parkı, modern peyzajı ve geniş yürüyüş yollarıyla aileler ve sporcular için popüler bir kaçış noktasıdır. Göleti, bisiklet yolları ve çocuk oyun alanlarıyla huzurlu bir gün geçirmek için idealdir.", "place_query": "Ankara Millet Bahçesi, Yenimahalle, Ankara"}, {"title": "Harikalar Diyarı", "summary": "Avrupa''nın en büyük parklarından biri olan Harikalar Diyarı, Yenimahalle sınırları içinde yer alır. Yapay göleti, piknik alanları, kafeleri ve yürüyüş parkurlarıyla hafta sonu keyfi yapmak isteyenlerin ilk tercihlerindendir.", "place_query": "Harikalar Diyarı, Yenimahalle, Ankara"}, {"title": "Kuğulu Park", "summary": "Ankara''nın en ikonik parklarından biri olan Kuğulu Park, özellikle göletindeki kuğuları ve ördekleriyle tanınır. Şehrin merkezinde küçük bir vaha olan park, kısa bir yürüyüş veya dinlenme molası vermek için idealdir.", "place_query": "Kuğulu Park, Yenimahalle, Ankara"}, {"title": "Ankapark (Wonderland Eurasia)", "summary": "Ankara''nın en büyük eğlence parklarından biri olan Ankapark, heyecan verici lunapark aletleri ve temalı bölümleriyle aileler ve gençler için popüler bir destinasyondur. Özellikle yaz aylarında su parkı da ziyaretçilere hitap eder.", "place_query": "Ankapark Wonderland Eurasia, Yenimahalle, Ankara"}, {"title": "MTA Şehit Cuma Dağ Tabiat Tarihi Müzesi", "summary": "Yenimahalle''de bulunan bu müze, etkileyici fosil koleksiyonları ve devasa dinozor iskeletleriyle hem çocuklar hem de yetişkinler için büyüleyici bir deneyim sunar. Ücretsiz girişi ve interaktif sergileriyle eğitici bir gezi yapmak isteyenlerin mutlaka görmesi gereken bir yerdir.", "place_query": "MTA Tabiat Tarihi Müzesi, Yenimahalle, Ankara"}, {"title": "Batıkent Göleti ve Millet Bahçesi", "summary": "Yenimahalle''nin Batıkent semtinde yer alan bu gölet ve çevresindeki millet bahçesi, yürüyüş yapmak ve doğayla iç içe vakit geçirmek için sakin bir ortam sağlar. Etrafındaki kafelerde oturup manzaranın tadını çıkarabilirsiniz.", "place_query": "Batıkent Göleti, Yenimahalle, Ankara"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9c2014c4-cad5-4d70-8c37-2c4946c84ae0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akseki Kalesi", "summary": "Akseki merkezinde yükselen tarihi bir kaledir. Bölgenin savunma amaçlı kullanılan bu yapısı, etkileyici manzarası ve tarihi dokusuyla ziyaretçilerini cezbeder.", "place_query": "Akseki Kalesi, Akseki, Antalya"}, {"title": "Cevizli (Sülek) Mağarası", "summary": "Akseki''ye bağlı Cevizli köyünde yer alan bu mağara, sarkıt ve dikitleriyle doğa tutkunları için ideal bir keşif noktasıdır. İçerisindeki göller ve traverten oluşumları dikkat çeker.", "place_query": "Cevizli Mağarası, Akseki, Antalya"}, {"title": "Akseki Evleri", "summary": "Yöresel mimarinin en güzel örneklerinden olan tarihi Akseki evleri, ahşap ve taş işçiliğiyle ünlüdür. Dar sokaklarda yürüyerek bu geleneksel yapıları yakından görebilirsiniz.", "place_query": "Akseki Evleri, Akseki, Antalya"}, {"title": "Sarıhacılar Köyü ve Yaylası", "summary": "Doğal güzellikleri ve serin havasıyla bilinen Sarıhacılar Yaylası, yaz aylarında kaçış noktasıdır. Köy meydanındaki tarihi çeşme ve ahşap evler fotoğraf severler için idealdir.", "place_query": "Sarıhacılar Köyü, Akseki, Antalya"}, {"title": "Güzelsu Köprüsü (Şarapsa Köprüsü)", "summary": "Akseki yakınlarındaki Güzelsu Köyü''nde bulunan bu tarihi köprü, Roma dönemine ait olup Manavgat Çayı üzerinde yer alır. Doğa ile iç içe tarihi bir yapı arayanlar için güzel bir duraktır.", "place_query": "Güzelsu Köprüsü, Akseki, Antalya"}, {"title": "Bademli Köyü ve Bademli Mağarası", "summary": "Bademli Köyü yakınlarındaki bu mağara, henüz çok bilinmeyen doğal bir oluşumdur. Çevresindeki yemyeşil ormanlık alan ve köyün sakin atmosferi doğa yürüyüşleri için uygundur.", "place_query": "Bademli Mağarası, Akseki, Antalya"}, {"title": "Akseki Müzesi", "summary": "İlçe merkezinde yer alan bu küçük müze, Akseki ve çevresinin etnografik ve arkeolojik eserlerini sergiler. Yörenin kültürel geçmişine dair ipuçları sunar.", "place_query": "Akseki Müzesi, Akseki, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9f40f1bb-7c2a-446e-a757-fcd9628c4b2b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kurşunlu Şelalesi Tabiat Parkı", "summary": "Antalya''nın en popüler doğal güzelliklerinden biri olan şelale, yemyeşil doğası ve 18 metre yüksekten dökülen sularıyla ziyaretçilerine huzur dolu bir ortam sunar. İçerisinde yürüyüş yolları, piknik alanları ve restoranlar bulunur.", "place_query": "Kurşunlu Şelalesi, Aksu, Antalya"}, {"title": "Perge Antik Kenti", "summary": "Pamfilya''nın en görkemli antik kentlerinden biri olan Perge, etkileyici tiyatrosu, stadyumu ve sütunlu caddeleriyle tarih meraklıları için eşsiz bir açık hava müzesidir. Antalya''ya çok yakın konumuyla kolayca ulaşılabilir.", "place_query": "Perge Antik Kenti, Aksu, Antalya"}, {"title": "Aksu Belediyesi Kent Ormanı", "summary": "Şehir hayatından kaçmak isteyenler için geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla ideal bir dinlenme noktasıdır. Hafta sonu aile piknikleri için sıkça tercih edilir.", "place_query": "Aksu Belediyesi Kent Ormanı, Aksu, Antalya"}, {"title": "Antalya Aquarium (Akvaryum)", "summary": "Dünyanın en büyük tünel akvaryumlarından birine ev sahipliği yapan bu merkez, binlerce deniz canlısını ve dev köpekbalıklarını yakından görme imkanı sunar. Aynı zamanda buz müzesi ve mağara deneyimi gibi ek aktiviteler de bulunur.", "place_query": "Antalya Aquarium, Aksu, Antalya"}, {"title": "Aksu Sahili (Kundu Plajı)", "summary": "Uzun ve geniş kumsalıyla ünlü Kundu Plajı, birçok lüks otelin önünde yer almasına rağmen halka açık bölümleriyle de deniz ve güneş keyfi yapmak isteyenleri ağırlar. Berrak denizi ve altın sarısı kumuyla dikkat çeker.", "place_query": "Kundu Plajı, Aksu, Antalya"}, {"title": "Antalya Bilim Merkezi", "summary": "Özellikle çocuklu aileler için interaktif deneyler, bilim atölyeleri ve sergilerle dolu eğitici bir mekandır. Evrenin sırlarını keşfetmek isteyenler için ufuk açıcı bir durak.", "place_query": "Antalya Bilim Merkezi, Aksu, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '84e99ac5-48b3-4f2f-9594-bccb7a12fcc3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Damlatas Mağarası", "summary": "Astım hastalarına iyi geldiğine inanılan nemli ve iyonize havasıyla ünlü bu mağara, Alanya''nın simge yapılarından biridir. İçerideki sarkıt ve dikitler büyüleyici bir atmosfer sunar.", "place_query": "Damlatas Mağarası, Alanya, Antalya"}, {"title": "Alanya Kalesi", "summary": "Selçuklu döneminden kalma bu görkemli kale, tepeden tüm Alanya''yı ve Akdeniz''i kuşbakışı görmenizi sağlar. Surlar, sarnıçlar ve tarihi yapılarıyla keşfedilmeyi bekler.", "place_query": "Alanya Kalesi, Alanya, Antalya"}, {"title": "Kleopatra Plajı", "summary": "Mısır kraliçesi Kleopatra''nın yüzdüğü rivayet edilen bu plaj, incecik kumu ve berrak deniziyle Alanya''nın en popüler sahillerindendir. Mavi bayraklı plaj, yüzme ve güneşlenmek için idealdir.", "place_query": "Kleopatra Plajı, Alanya, Antalya"}, {"title": "Dim Çayı", "summary": "Toroslar''dan doğarak Alanya''ya ulaşan bu serin akarsu, çevresindeki çay bahçeleri ve restoranlarla ünlüdür. Özellikle yaz aylarında ayaklarınızı suya sokup doğal güzelliğin tadını çıkarabilirsiniz.", "place_query": "Dim Çayı, Alanya, Antalya"}, {"title": "Syedra Antik Kenti", "summary": "Alanya''nın doğusunda yer alan bu antik kent, Roma ve Bizans dönemine ait kalıntılarıyla tarih meraklılarını cezbeder. Agora, hamam ve sarnıç kalıntıları arasında dolaşmak eşsiz bir deneyim sunar.", "place_query": "Syedra Antik Kenti, Alanya, Antalya"}, {"title": "Alanya Teleferik ve Tepeleri", "summary": "Alanya Merkez''den başlayan teleferik hattıyla kale tepesine çıkabilir, panoramik manzaranın keyfini sürebilirsiniz. Tepede bulunan kafe ve seyir terasları özellikle gün batımında büyüleyicidir.", "place_query": "Alanya Teleferik, Alanya, Antalya"}, {"title": "Sapadere Kanyonu", "summary": "Alanya''ya yaklaşık 40 km uzaklıktaki bu kanyon, yemyeşil doğası ve şelaleleriyle doğa yürüyüşçüleri için harika bir rotadır. Ahşap yürüyüş yolları sayesinde kanyonun derinliklerine kadar ulaşabilirsiniz.", "place_query": "Sapadere Kanyonu, Alanya, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '53a44c64-2587-481d-ba9b-676232051ee1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Demre Myra Antik Kenti", "summary": "Likya döneminin en önemli şehirlerinden biri olan Myra, etkileyici kaya mezarları ve büyük bir Roma tiyatrosuyla ziyaretçilerini büyüler. Antik kent, tarihi dokusuyla Demre''nin en çok ziyaret edilen ören yeridir.", "place_query": "Myra Antik Kenti, Demre, Antalya"}, {"title": "Noel Baba Kilisesi (St. Nicholas Anıt Müzesi)", "summary": "Dünyaca ünlü Noel Baba (Aziz Nikolaos)''nın yaşadığı ve piskoposluk yaptığı tarihi kilise, mozaikleri ve freskleriyle önemli bir hac merkezidir. Her yıl binlerce turist bu kutsal mekanı görmek için Demre''ye akın eder.", "place_query": "Noel Baba Kilisesi, Demre, Antalya"}, {"title": "Andriake Antik Kenti", "summary": "Myra''nın liman kenti olan Andriake, günümüze ulaşan tahıl ambarı (horrea) ve agora kalıntılarıyla dikkat çeker. Sakin atmosferi ve tarihi kalıntıları arasında yürüyüş yapmak için idealdir.", "place_query": "Andriake Antik Kenti, Demre, Antalya"}, {"title": "Demre Çayağzı Plajı", "summary": "Uzun kumsalı ve berrak deniziyle yerli halkın ve turistlerin uğrak noktası olan bu plaj, özellikle yaz aylarında serinlemek ve güneşlenmek için popülerdir. Deniz kaplumbağalarının da yuvalama alanıdır.", "place_query": "Çayağzı Plajı, Demre, Antalya"}, {"title": "Kaleüçağız (Kekova) Koyu", "summary": "Demre''ye bağlı bu şirin balıkçı köyü, Kekova Adası manzarası ve batık şehir turlarının başlangıç noktası olmasıyla ünlüdür. Tekne turlarıyla bölgenin eşsiz doğal ve tarihi güzelliklerini keşfedebilirsiniz.", "place_query": "Kaleüçağız Köyü, Demre, Antalya"}, {"title": "Demre (Kale) Köyü ve Likya Yolu", "summary": "Tarihi Likya Yolu''nun Demre etabı, Myra antik kentinden başlayarak muhteşem doğa manzaraları eşliğinde yürüyüş rotası sunar. Doğa severler için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Likya Yolu Demre, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f77dc5f5-650e-4dca-b0bb-369ca5b56848'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Döşemealtı Halı Pazarı", "summary": "Antalya''nın ünlü Döşemealtı halılarının sergilendiği ve satıldığı bu pazar, el dokuması halı ve kilimleriyle ünlüdür. Ziyaretçiler hem alışveriş yapabilir hem de geleneksel dokuma kültürünü yakından gözlemleyebilir.", "place_query": "Döşemealtı Halı Pazarı, Antalya"}, {"title": "Kırkgöz Hanı", "summary": "Selçuklu döneminden kalma tarihi bir kervansaray olan Kırkgöz Hanı, restore edilmiş yapısıyla bölgenin en önemli tarihi miraslarındandır. İç avlusu ve taş işçiliğiyle fotoğrafçılar için de eşsiz bir mekandır.", "place_query": "Kırkgöz Hanı, Döşemealtı, Antalya"}, {"title": "Kırkgöz Göleti ve Mesire Alanı", "summary": "Doğal güzelliği ve piknik alanlarıyla ünlü Kırkgöz Göleti, özellikle bahar ve yaz aylarında aileler için popüler bir kaçış noktasıdır. Gölet çevresinde yürüyüş yapabilir, kuş sesleri eşliğinde dinlenebilirsiniz.", "place_query": "Kırkgöz Göleti, Döşemealtı, Antalya"}, {"title": "Döşemealtı Mağarası", "summary": "Bölgenin en etkileyici doğal oluşumlarından biri olan bu mağara, sarkıt ve dikitleriyle ziyaretçileri büyüler. Mağara içindeki serin hava ve mistik atmosfer, doğa severler için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Döşemealtı Mağarası, Antalya"}, {"title": "Yeşilbayır Köyü", "summary": "Antalya''nın yayla kültürünü yansıtan Yeşilbayır Köyü, doğal yapısı ve geleneksel mimarisiyle dikkat çeker. Köyde yöresel ürünler tadabilir, temiz hava eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Yeşilbayır Köyü, Döşemealtı, Antalya"}, {"title": "Kovanlık Köyü Şelalesi", "summary": "Saklı bir cennet olan Kovanlık Köyü Şelalesi, yeşillikler içinde akan serin sularıyla doğa yürüyüşçüleri ve piknikçiler için idealdir. Şelalenin sesi eşliğinde stresten uzaklaşabilirsiniz.", "place_query": "Kovanlık Köyü Şelalesi, Döşemealtı, Antalya"}, {"title": "Döşemealtı Kent Ormanı", "summary": "Geniş yürüyüş parkurları ve piknik alanlarıyla şehir hayatından kaçmak isteyenler için biçilmiş kaftandır. Kent ormanı, özellikle hafta sonları ailelerin ve spor yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Döşemealtı Kent Ormanı, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ac61c7fd-80b9-4807-b1b9-0b060801d97a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Elmalı Müzesi", "summary": "Bölgenin zengin tarihini gözler önüne seren bu müze, Likya, Roma ve Bizans dönemlerine ait eserlerin yanı sıra yöresel etnografik objeleri sergiler. Özellikle ''Elmalı Definesi'' olarak bilinen antik sikke koleksiyonu büyük ilgi çeker.", "place_query": "Elmalı Müzesi, Elmalı, Antalya"}, {"title": "Özdemirler Konağı", "summary": "Tarihi bir Elmalı evi olan bu konak, geleneksel Türk mimarisinin güzel bir örneğidir. Günümüzde kafe ve restoran olarak hizmet veren mekan, otantik atmosferi ve yöresel lezzetleriyle ziyaretçileri ağırlar.", "place_query": "Özdemirler Konağı, Elmalı, Antalya"}, {"title": "Elmalı Çınarı", "summary": "Elmalı''nın sembolü haline gelmiş, yüzlerce yıllık dev bir çınar ağacıdır. Şehir merkezinde bulunan bu anıtsal ağaç, gölgesinde dinlenmek ve fotoğraf çektirmek için popüler bir durak noktasıdır.", "place_query": "Elmalı Çınarı, Elmalı, Antalya"}, {"title": "Tekke Köyü ve Bektaşi Tekkesi", "summary": "Elmalı''ya bağlı Tekke Köyü''nde bulunan bu tarihi dergah, Abdal Musa ve Kaygusuz Abdal gibi önemli Bektaşi şahsiyetlerinin türbelerine ev sahipliği yapar. Hem dini hem de kültürel bir ziyaret noktasıdır.", "place_query": "Tekke Köyü Bektaşi Tekkesi, Elmalı, Antalya"}, {"title": "Gömbe Yaylası", "summary": "Elmalı''nın serin ve yeşil yaylalarından biri olan Gömbe, özellikle yaz aylarında şehrin gürültüsünden kaçmak isteyenler için idealdir. Yayla evleri, temiz havası ve doğal güzellikleriyle huzurlu bir kaçış sunar.", "place_query": "Gömbe Yaylası, Elmalı, Antalya"}, {"title": "Kızılkaya Mağarası", "summary": "Elmalı sınırlarında yer alan bu mağara, etkileyici sarkıt ve dikitleriyle doğa severlerin ilgisini çeker. İçerisindeki gölü ve damlataş oluşumlarıyla görülmeye değer bir doğal oluşumdur.", "place_query": "Kızılkaya Mağarası, Elmalı, Antalya"}, {"title": "Söğle Yaylası", "summary": "Elmalı''nın en popüler yaylalarından biri olan Söğle, özellikle kampçılık ve doğa yürüyüşleri için tercih edilir. Yemyeşil çam ormanları ve temiz havasıyla doğayla baş başa kalmak isteyenler için biçilmiş kaftandır.", "place_query": "Söğle Yaylası, Elmalı, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7a45ef35-dfb6-49ed-9310-532483a74ebe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Limyra Antik Kenti", "summary": "Likya Birliği''nin önemli şehirlerinden biri olan Limyra, etkileyici kaya mezarları, Roma dönemi tiyatrosu ve heroon anıtıyla tarih meraklıları için eşsiz bir açık hava müzesidir.", "place_query": "Limyra Antik Kenti, Finike, Antalya"}, {"title": "Finike Plajı", "summary": "Uzun ve ince kumsalı, berrak denizi ve çevresindeki palmiye ağaçlarıyla Finike''nin en popüler yüzme ve güneşlenme noktasıdır.", "place_query": "Finike Plajı, Finike, Antalya"}, {"title": "Arykanda Antik Kenti", "summary": "Yemyeşil bir vadiye kurulu bu antik kent, tiyatrosu, hamamı ve agora kalıntılarıyla doğa ile tarihin iç içe geçtiği etkileyici bir destinasyondur.", "place_query": "Arykanda Antik Kenti, Finike, Antalya"}, {"title": "Finike Portakalı Bahçeleri", "summary": "Meşhur Finike portakalının yetiştiği bu bahçeler, özellikle bahar aylarında çiçek açan ağaçların mis kokusu ve yeşil manzaralarıyla huzur verici bir doğa deneyimi sunar.", "place_query": "Finike Portakal Bahçeleri, Finike, Antalya"}, {"title": "Suluin Mağarası", "summary": "İçindeki sarkıt ve dikitleriyle görsel bir şölen sunan bu mağara, doğa sporları ve keşif tutkunları için ilgi çekici bir duraktır.", "place_query": "Suluin Mağarası, Finike, Antalya"}, {"title": "Finike Limanı ve Sahil Yürüyüş Yolu", "summary": "Teknelerin ve balıkçıların hareketliliğiyle canlı bir atmosfere sahip olan liman, sahil boyunca uzanan yürüyüş yolu ve kafeleriyle keyifli bir gezi rotasıdır.", "place_query": "Finike Limanı, Finike, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9b8ba04d-d337-4852-838c-a59e31dfd48f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gazipaşa Sahili ve Plajları", "summary": "Antalya''nın en temiz ve sakin plajlarına sahip olan Gazipaşa Sahili, uzun kumsalı ve berrak deniziyle yüzme ve güneşlenme için idealdir. Özellikle Muzkent Plajı ve Koru Plajı, doğal güzellikleriyle öne çıkar.", "place_query": "Gazipaşa Sahili, Antalya"}, {"title": "Selinus Antik Kenti", "summary": "Gazipaşa merkezinde bulunan Selinus Antik Kenti, Roma dönemine ait kalıntıları ve etkileyici akropolü ile tarih meraklıları için önemli bir duraktır. Antik tiyatro ve hamam kalıntıları görülmeye değerdir.", "place_query": "Selinus Antik Kenti, Gazipaşa, Antalya"}, {"title": "Kaledran Koyu", "summary": "Gazipaşa''nın doğal güzelliklerinden biri olan Kaledran Koyu, sakin ve huzurlu atmosferiyle bilinir. Çevresindeki yemyeşil doğa ve berrak denizi, doğa ile baş başa kalmak isteyenler için mükemmeldir.", "place_query": "Kaledran Koyu, Gazipaşa, Antalya"}, {"title": "Gazipaşa Muz Festivali Alanı", "summary": "Her yıl düzenlenen Gazipaşa Muz Festivali''ne ev sahipliği yapan bu alan, bölgenin en önemli tarım ürünü olan muzu tanıtmak için kurulmuştur. Festival zamanı dışında da yöresel ürünlerin tadılabileceği bir noktadır.", "place_query": "Gazipaşa Muz Festivali Alanı, Antalya"}, {"title": "Güney Köyü ve Şelalesi", "summary": "Gazipaşa''ya bağlı Güney Köyü''nde yer alan şelale, serin suları ve çevresindeki piknik alanlarıyla doğaseverler için popüler bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek için idealdir.", "place_query": "Güney Köyü Şelalesi, Gazipaşa, Antalya"}, {"title": "Antiphellos Antik Kenti (Kaş''a bağlı olmakla birlikte yakın)", "summary": "Gazipaşa sınırları içinde olmasa da bölge ziyaretlerinde sıkça uğranan Antiphellos, Likya dönemine ait etkileyici kaya mezarları ve antik tiyatrosuyla ünlüdür. Gazipaşa''ya arabayla yaklaşık 1 saat uzaklıktadır.", "place_query": "Antiphellos Antik Kenti, Kaş, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3993d862-16bb-4560-9bac-b9c30d334545'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gündoğmuş Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla ünlü bu şelale, piknik ve doğa yürüyüşü için ideal bir noktadır. Çevresindeki yeşil alanlar ve oluşturduğu doğal havuz, özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır.", "place_query": "Gündoğmuş Şelalesi, Gündoğmuş, Antalya"}, {"title": "Gündoğmuş Yaylaları (Gödene Yaylası, Çamlıca Yaylası vb.)", "summary": "Toros Dağları''nın eteklerinde yer alan bu yaylalar, temiz havası, muhteşem manzaraları ve doğal bitki örtüsüyle huzur verici bir kaçış noktasıdır. Özellikle Gödene Yaylası, kamp ve doğa yürüyüşleri için popülerdir.", "place_query": "Gödene Yaylası, Gündoğmuş, Antalya"}, {"title": "Gündoğmuş Kalesi", "summary": "Tarihi bir kalıntı olan Gündoğmuş Kalesi, ilçe merkezine hakim bir tepe üzerinde yer alır. Çevredeki vadi ve dağ manzarasını gözler önüne seren kale, tarih ve doğayı bir arada sunar.", "place_query": "Gündoğmuş Kalesi, Gündoğmuş, Antalya"}, {"title": "Alara Han", "summary": "Selçuklu dönemine ait tarihi bir kervansaray olan Alara Han, ilçe sınırları içinde yer alır. Taş işçiliği ve mimari yapısıyla dikkat çeken yapı, bölgenin tarihi ticaret yollarına ışık tutar.", "place_query": "Alara Han, Gündoğmuş, Antalya"}, {"title": "Gündoğmuş Baraj Gölü", "summary": "Yapay bir göl olan Gündoğmuş Baraj Gölü, çevresindeki piknik alanları ve sakin atmosferiyle aileler için keyifli bir günübirlik gezi noktasıdır. Gölde olta balıkçılığı da yapılabilmektedir.", "place_query": "Gündoğmuş Baraj Gölü, Gündoğmuş, Antalya"}, {"title": "Ortakonuş Yaylası", "summary": "Yemyeşil çam ormanlarıyla çevrili Ortakonuş Yaylası, doğa yürüyüşleri ve kampçılık için elverişli bir ortam sunar. Yayla evleri ve tertemiz havası, şehir hayatından kaçmak isteyenler için idealdir.", "place_query": "Ortakonuş Yaylası, Gündoğmuş, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e69a710f-95cf-43d1-97f9-99c393df0c48'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Altınbeşik Mağarası", "summary": "Türkiye''nin en büyük yer altı gölüne sahip bu mağara, eşsiz sarkıt ve dikitleriyle ünlüdür. Tekne turlarıyla keşfedilen mağara, doğa severler için büyüleyici bir deneyim sunar.", "place_query": "Altınbeşik Mağarası, İbradı, Antalya"}, {"title": "Ürünlü Yaylası", "summary": "Toroslar''ın serin yaylalarından biri olan Ürünlü, yemyeşil çam ormanları ve temiz havasıyla kampçıların ve doğa yürüyüşçülerinin uğrak noktasıdır.", "place_query": "Ürünlü Yaylası, İbradı, Antalya"}, {"title": "İbradı Tarihi Evleri", "summary": "Taş ve ahşap mimarinin güzel örneklerini sergileyen bu geleneksel evler, dar sokakları ve otantik atmosferiyle ziyaretçilere zamanda yolculuk hissi yaşatır.", "place_query": "İbradı Tarihi Evleri, İbradı, Antalya"}, {"title": "Akseki-İbradı Havzası", "summary": "Benzersiz doğal yapısı ve biyolojik çeşitliliğiyle dikkat çeken bu havza, özellikle fotoğrafçılar ve doğa gözlemcileri için ideal bir rotadır.", "place_query": "Akseki İbradı Havzası, Antalya"}, {"title": "Bademli Köyü", "summary": "Tarihi dokusunu koruyan Bademli Köyü, taş evleri ve doğal güzellikleriyle huzurlu bir kaçış noktasıdır. Köy çevresinde yürüyüş yapabilir, yöresel lezzetleri tadabilirsiniz.", "place_query": "Bademli Köyü, İbradı, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '13c3d102-ec7c-4dfb-981f-0bf04b73823f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Antiphellos Antik Kenti", "summary": "Kaş''ın merkezinde yer alan bu antik kent, Likya dönemine ait kalıntıları ve etkileyici tiyatrosuyla tarih meraklıları için eşsiz bir durak. Şehrin dokusuyla iç içe geçmiş olan kalıntılar, yürüyerek keşfedilebilir.", "place_query": "Antiphellos Antik Tiyatrosu, Kaş, Antalya"}, {"title": "Kaputaş Plajı", "summary": "Kaş ile Kalkan arasındaki bu ikonik plaj, turkuaz rengi denizi ve yüksek kayalıklardan inen merdivenleriyle ünlüdür. Dar kumsalına rağmen eşsiz manzarası ve berrak suyu ile mutlaka görülmeli.", "place_query": "Kaputaş Plajı, Kaş, Antalya"}, {"title": "Patara Antik Kenti ve Plajı", "summary": "Likya Birliği''nin başkenti olan Patara, hem 12 kilometrelik muhteşem plajı hem de antik tiyatro, meclis binası ve zafer takı gibi etkileyici kalıntılarıyla ziyaretçilerine iki farklı deneyim sunar.", "place_query": "Patara Antik Kenti, Kaş, Antalya"}, {"title": "Saklıkent Kanyonu", "summary": "Kaş''a yaklaşık 50 km uzaklıktaki bu dev kanyon, yıl boyunca akan buz gibi suları ve dar geçitleriyle doğa severler için ideal bir macera noktasıdır. Kanyon içinde yürüyüş yapabilir veya şelale kenarında dinlenebilirsiniz.", "place_query": "Saklıkent Kanyonu, Kaş, Antalya"}, {"title": "Kekova Sualtı Şehri ve Simena", "summary": "Kaş''tan düzenlenen tekne turlarıyla ulaşılan bu bölge, depremle sular altında kalmış antik şehir kalıntılarını cam tabanlı teknelerden izleme fırsatı sunar. Simena Köyü''ndeki kale ve Likya kaya mezarları da görülmeye değerdir.", "place_query": "Kekova Sualtı Şehri, Kaş, Antalya"}, {"title": "Kaş Dalış Merkezleri ve Batıklar", "summary": "Kaş, Türkiye''nin en önemli dalış noktalarından biridir. Berrak sular altında batıklar, mağaralar ve zengin deniz canlılarıyla dolu bir dünya sizi bekliyor; ister tüplü ister şnorkelle dalış deneyimi yaşayabilirsiniz.", "place_query": "Kaş Dalış Merkezleri, Antalya"}, {"title": "Xanthos Antik Kenti", "summary": "UNESCO Dünya Mirası Listesi''ndeki bu antik kent, Likya uygarlığının en önemli merkezlerinden biridir. Etkileyici kaya mezarları, nekropol ve Harpy Anıtı ile tarihe tanıklık etmek isteyenler için idealdir.", "place_query": "Xanthos Antik Kenti, Kaş, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd8ac3a78-e943-4f85-bdeb-d0fe8f4a0f54'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Olympos Antik Kenti", "summary": "Likya Birliği''nin önemli liman kentlerinden biri olan Olympos, sahile sıfır konumuyla tarih ve doğayı birleştiriyor. Antik kalıntılar arasında yürürken, Caretta caretta kaplumbağalarının yuvalama alanı olan plajında mola verebilirsiniz.", "place_query": "Olympos Antik Kenti, Çıralı, Kemer, Antalya"}, {"title": "Çıralı Plajı", "summary": "Uzun kumsalı, turkuaz denizi ve doğal güzelliğiyle ünlü Çıralı Plajı, Olympos Antik Kenti''nin hemen yanında yer alır. Caretta caretta kaplumbağalarının yumurtlama alanı olmasıyla da bilinir ve huzurlu bir tatil sunar.", "place_query": "Çıralı Plajı, Kemer, Antalya"}, {"title": "Yanartaş (Kimera Ateşi)", "summary": "Çıralı sahilinin hemen üzerinde, kayalıklardan doğal olarak çıkan alevlerle ünlü Yanartaş, efsanelere konu olmuş mistik bir noktadır. Gece ziyaret edildiğinde manzarası daha etkileyici olan bu yer, Likya yolunun popüler bir durağıdır.", "place_query": "Yanartaş, Çıralı, Kemer, Antalya"}, {"title": "Göynük Kanyonu", "summary": "Kemer merkeze yaklaşık 10 km uzaklıktaki Göynük Kanyonu, doğa yürüyüşü ve tırmanış için ideal bir rotadır. İçinden geçen soğuk dere ve yemyeşil doğası, şehirden kaçış arayanlar için mükemmel bir ortam sunar.", "place_query": "Göynük Kanyonu, Göynük, Kemer, Antalya"}, {"title": "Tahtalı Dağı Teleferik", "summary": "2365 metre yüksekliğindeki Tahtalı Dağı''na çıkan teleferik, eşsiz bir dağ ve deniz manzarası sunar. Zirvede, özellikle gün batımında Antalya Körfezi''nin panoramik görüntüsü unutulmaz bir deneyim yaşatır.", "place_query": "Olympos Teleferik, Tahtalı Dağı, Kemer, Antalya"}, {"title": "Phaselis Antik Kenti", "summary": "Üç ayrı limana sahip Likya kenti Phaselis, çam ormanlarıyla çevrili plajları ve tarihi kalıntılarıyla ünlüdür. Antik tiyatro, agoralar ve su kemerleri arasında yürürken aynı anda denize girebilme imkanı sunar.", "place_query": "Phaselis Antik Kenti, Tekirova, Kemer, Antalya"}, {"title": "Kemer Merkez (Cumhuriyet Meydanı ve Marina)", "summary": "Kemer''in kalbi sayılan merkez, hareketli çarşısı, restoranları ve barlarıyla canlı bir atmosfere sahiptir. Marina çevresinde yürüyüş yapabilir, deniz kenarında yemek yiyebilir ve şehrin enerjisini hissedebilirsiniz.", "place_query": "Kemer Merkez, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd233bfd4-a2f5-46eb-98f9-15d25b126c35'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dokuma Parkı", "summary": "Antalya''nın en büyük şehir parklarından biri olan Dokuma Parkı, eski bir dokuma fabrikasının dönüştürülmesiyle oluşmuştur. İçerisinde yürüyüş yolları, gölet, çocuk oyun alanları, kafeler ve Antalya Bilim Merkezi gibi birçok aktivite alanı bulunur.", "place_query": "Dokuma Parkı, Kepez, Antalya"}, {"title": "Antalya Bilim Merkezi", "summary": "Dokuma Parkı içerisinde yer alan bu modern bilim merkezi, interaktif sergileri, planetaryumu ve atölyeleriyle özellikle çocuklu aileler için popüler bir eğitim ve eğlence noktasıdır.", "place_query": "Antalya Bilim Merkezi, Kepez, Antalya"}, {"title": "Kepez Belediyesi Kent Ormanı", "summary": "Şehir merkezine yakın geniş bir yeşil alan olan Kent Ormanı, piknik alanları, yürüyüş parkurları ve manzarasıyla doğayla iç içe vakit geçirmek isteyenler için idealdir.", "place_query": "Kepez Kent Ormanı, Antalya"}, {"title": "Kepez Kapalı Yüzme Havuzu ve Spor Kompleksi", "summary": "Modern bir tesis olan bu spor kompleksi, olimpik yüzme havuzu, spor salonları ve çeşitli aktivite alanlarıyla spor tutkunlarının uğrak noktasıdır.", "place_query": "Kepez Kapalı Yüzme Havuzu, Antalya"}, {"title": "Pınarbaşı Mesire Alanı", "summary": "Kepez ilçesinde yer alan bu mesire alanı, doğal güzellikleri, piknik masaları ve çocuk oyun alanlarıyla hafta sonu kaçamakları için sakin bir ortam sunar.", "place_query": "Pınarbaşı Mesire Alanı, Kepez, Antalya"}, {"title": "Yeni Doğan Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun gruplarıyla ailelerin sıkça tercih ettiği bir mahalle parkıdır.", "place_query": "Yeni Doğan Parkı, Kepez, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2164b73e-f3ac-4e48-850e-30fc94ba0edf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Konyaaltı Plajı", "summary": "Antalya''nın en popüler plajlarından biri olan Konyaaltı Plajı, uzun kumsalı, berrak denizi ve yürüyüş yoluyla ünlüdür. Plaj boyunca kafeler, restoranlar ve parklar bulunur, ayrıca gün batımı manzarası muhteşemdir.", "place_query": "Konyaaltı Plajı, Antalya"}, {"title": "Antalya Akvaryum", "summary": "Dünyanın en büyük tünel akvaryumlarından birine sahip olan bu merkez, binlerce deniz canlısına ev sahipliği yapar. Özellikle çocuklu aileler için eğlenceli bir ziyaret noktasıdır.", "place_query": "Antalya Akvaryum, Konyaaltı, Antalya"}, {"title": "Aktur Park", "summary": "Konyaaltı sahilinde geniş bir alana yayılan bu park, yürüyüş ve bisiklet yolları, oyun alanları ve dinlenme bölgeleriyle popülerdir. Deniz kenarında huzurlu bir vakit geçirmek için idealdir.", "place_query": "Aktur Park, Konyaaltı, Antalya"}, {"title": "Antalya Müzesi", "summary": "Türkiye''nin en önemli arkeoloji müzelerinden biri olan Antalya Müzesi, Perge, Side ve Aspendos gibi antik kentlerden çıkarılan eserleri sergiler. Tarih meraklıları için mutlaka görülmesi gereken bir yerdir.", "place_query": "Antalya Müzesi, Konyaaltı, Antalya"}, {"title": "Düden Şelalesi (Aşağı Düden)", "summary": "Antalya''nın simgelerinden olan Aşağı Düden Şelalesi, denize dökülen suları ve çevresindeki parkıyla ünlüdür. Özellikle yaz aylarında serinlemek ve doğa manzarası eşliğinde vakit geçirmek için tercih edilir.", "place_query": "Düden Şelalesi Aşağı, Konyaaltı, Antalya"}, {"title": "Konyaaltı Sahil Yürüyüş Yolu", "summary": "Konyaaltı Plajı boyunca uzanan bu yürüyüş yolu, bisiklet sürmek, koşu yapmak veya deniz manzarası eşliğinde yürümek için harika bir rotadır. Akşam saatlerinde canlı atmosferiyle keyifli bir deneyim sunar.", "place_query": "Konyaaltı Sahil Yürüyüş Yolu, Antalya"}, {"title": "Minicity Antalya", "summary": "Türkiye''nin önemli yapılarının minyatürlerinin sergilendiği bu açık hava müzesi, aileler ve çocuklar için eğlenceli bir gezi noktasıdır. Konyaaltı''nda kolayca ulaşılabilir bir konumdadır.", "place_query": "Minicity Antalya, Konyaaltı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '94fa886e-9075-4500-8e11-94156260d486'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Korkuteli Şelalesi", "summary": "İlçe merkezine yaklaşık 20 km uzaklıkta, doğa içinde serinlemek ve piknik yapmak için ideal bir noktadır. Şelalenin çevresi çam ormanlarıyla kaplı olup, özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Korkuteli Şelalesi, Korkuteli, Antalya"}, {"title": "Yelten Yaylası", "summary": "Antalya''nın serin yaylalarından biri olan Yelten, muhteşem doğa manzarası ve temiz havasıyla ünlüdür. Yayla evleri ve doğa yürüyüşü rotalarıyla huzurlu bir kaçamak sunar.", "place_query": "Yelten Yaylası, Korkuteli, Antalya"}, {"title": "Korkuteli Saat Kulesi", "summary": "İlçe merkezinde bulunan tarihi saat kulesi, Korkuteli''nin simgelerinden biridir. 20. yüzyıl başlarında inşa edilen kule, çevresindeki meydan ile birlikte şehrin buluşma noktasıdır.", "place_query": "Korkuteli Saat Kulesi, Korkuteli, Antalya"}, {"title": "Bozova Mağarası", "summary": "Korkuteli ilçe merkezine yaklaşık 30 km mesafede, doğal oluşumlu bir mağaradır. İçindeki sarkıt ve dikitler ile mağara turizmi için keşfedilmeyi bekleyen bir güzelliktir.", "place_query": "Bozova Mağarası, Korkuteli, Antalya"}, {"title": "Kızılcadağ Göleti", "summary": "Doğa ile iç içe bir piknik ve kamp alanı olan Kızılcadağ Göleti, çam ormanları arasında huzurlu bir atmosfer sunar. Gölet çevresinde yürüyüş yapabilir ve kuş gözlemi yapabilirsiniz.", "place_query": "Kızılcadağ Göleti, Korkuteli, Antalya"}, {"title": "Söğüt Yaylası", "summary": "Özellikle yaz aylarında serinlemek için tercih edilen Söğüt Yaylası, geniş çayırları ve yayla şenlikleriyle bilinir. Doğa yürüyüşleri ve kamp için elverişli bir ortam sağlar.", "place_query": "Söğüt Yaylası, Korkuteli, Antalya"}, {"title": "Korkuteli Tarihi Evleri", "summary": "İlçe merkezinde Osmanlı döneminden kalma taş ve ahşap yapılı tarihi evler, mimari meraklıları için ilgi çekicidir. Dar sokaklarda yürüyerek geçmişe yolculuk yapabilirsiniz.", "place_query": "Korkuteli Tarihi Evleri, Korkuteli, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f8cadc8a-39bd-4097-bdb1-d4a33043195c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Olympos Antik Kenti", "summary": "Likya Birliği''nin önemli liman kentlerinden biri olan Olympos, sahil boyunca uzanan antik kalıntıları ve plajıyla ünlüdür. Ziyaretçiler, tarihi yapıları keşfederken aynı anda denize girebilir.", "place_query": "Olympos Antik Kenti, Kumluca, Antalya"}, {"title": "Çıralı Plajı", "summary": "Olympos''un yanı başındaki bu uzun plaj, caretta caretta kaplumbağalarının yuvalama alanı olarak bilinir. Sakin denizi ve doğal güzelliğiyle huzurlu bir tatil sunar.", "place_query": "Çıralı Plajı, Kumluca, Antalya"}, {"title": "Yanartaş (Chimaera)", "summary": "Olympos''un kuzeyindeki bu eşsiz doğa olayında, kayaların arasından sürekli olarak alevler çıkar. Antik çağda ateş püskürten canavar Chimera efsanesine ev sahipliği yapar.", "place_query": "Yanartaş, Kumluca, Antalya"}, {"title": "Adrasan Plajı", "summary": "Kumluca''ya bağlı Adrasan Mahallesi''ndeki bu uzun kumsal, çam ormanlarıyla çevrilidir. Sakin atmosferi ve berrak deniziyle doğa severler için idealdir.", "place_query": "Adrasan Plajı, Kumluca, Antalya"}, {"title": "Suluada Adası", "summary": "Adrasan açıklarındaki bu küçük ada, beyaz kumlu plajları ve turkuaz rengi deniziyle ''Maldivler''in Türkiye versiyonu'' olarak anılır. Tekne turlarıyla ulaşılır.", "place_query": "Suluada Adası, Kumluca, Antalya"}, {"title": "Mavikent Plajı", "summary": "Kumluca merkeze yakın bu geniş plaj, ince kumu ve dalgasız deniziyle aileler tarafından tercih edilir. Çevresinde konaklama ve yeme-içme seçenekleri bulunur.", "place_query": "Mavikent Plajı, Kumluca, Antalya"}, {"title": "Gelidonya Feneri", "summary": "Antalya''nın en güney ucundaki bu tarihi deniz feneri, etkileyici manzarasıyla trekking rotalarının popüler bir durağıdır. Yürüyüş parkuru boyunca eşsiz koy manzaraları sunar.", "place_query": "Gelidonya Feneri, Kumluca, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '329e9f2c-c872-481a-97cd-4bf4e4f0f891'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Manavgat Şelalesi", "summary": "Antalya''nın en ünlü doğal güzelliklerinden biri olan şelale, geniş ve gürül gürül akan sularıyla ziyaretçilerine serinletici bir atmosfer sunar. Çevresindeki yürüyüş yolları, piknik alanları ve kafeler sayesinde aileler için ideal bir günübirlik gezi noktasıdır.", "place_query": "Manavgat Şelalesi, Manavgat, Antalya"}, {"title": "Side Antik Kenti", "summary": "Antalya''nın en önemli antik kentlerinden biri olan Side, görkemli Apollon Tapınağı, antik tiyatro ve liman kalıntılarıyla tarih meraklılarını büyüler. Deniz kenarındaki konumu sayesinde hem kültürel bir yolculuk hem de sahil keyfi bir arada yaşanabilir.", "place_query": "Side Antik Kenti, Manavgat, Antalya"}, {"title": "Titreyengöl", "summary": "Side''ye sadece birkaç kilometre uzaklıkta bulunan bu göl, doğal güzelliği ve çevresindeki lüks otellerle tanınır. Kuş cıvıltıları eşliğinde yürüyüş yapabilir, göl kenarındaki restoranlarda huzur dolu anlar yaşayabilirsiniz.", "place_query": "Titreyengöl, Manavgat, Antalya"}, {"title": "Manavgat Barajı ve Hidroelektrik Santrali", "summary": "Bölgenin en büyük barajlarından biri olan Manavgat Barajı, etkileyici manzarası ve geniş su yüzeyiyle dikkat çeker. Baraj gölü çevresinde doğa yürüyüşleri yapabilir ve piknik alanlarında vakit geçirebilirsiniz.", "place_query": "Manavgat Barajı, Manavgat, Antalya"}, {"title": "Köprülü Kanyon Milli Parkı", "summary": "Manavgat ilçe sınırları içinde yer alan bu milli park, derin vadisi, zümrüt yeşili nehri ve tarihi Roma köprüsüyle ünlüdür. Rafting, trekking ve kamp gibi doğa sporları için Türkiye''nin en popüler adreslerinden biridir.", "place_query": "Köprülü Kanyon Milli Parkı, Manavgat, Antalya"}, {"title": "Side Müzesi", "summary": "Antik kentin hemen yanında yer alan Side Müzesi, Roma ve Bizans dönemine ait heykeller, lahitler ve günlük kullanım eşyalarını sergiler. Tarihi bir hamam binasında hizmet veren müze, Side''nin zengin geçmişine ışık tutar.", "place_query": "Side Müzesi, Manavgat, Antalya"}, {"title": "Sorgun Tabiat Parkı", "summary": "Manavgat merkeze yaklaşık 20 km mesafedeki bu tabiat parkı, kızılçam ormanları ve temiz havasıyla doğaseverler için bir cennettir. Piknik masaları, yürüyüş parkurları ve kamp alanlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Sorgun Tabiat Parkı, Manavgat, Antalya"}, {"title": "İncekum Plajı", "summary": "Adını incecik kumlarından alan bu plaj, sığ ve berrak deniziyle özellikle çocuklu aileler için güvenli bir yüzme alanı sunar. Çevresindeki tesisler ve kum zenginliği sayesinde yaz aylarında yoğun ilgi görür.", "place_query": "İncekum Plajı, Manavgat, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '13c35dc3-3ece-4099-a542-0e7d1b2fe3a9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karaalioğlu Parkı", "summary": "Deniz manzaralı bu tarihi park, Antalya''nın simgelerinden biridir. İçinde yürüyüş yapabilir, Hıdırlık Kulesi''ni görebilir ve eşsiz gün batımı manzarasının tadını çıkarabilirsiniz.", "place_query": "Karaalioğlu Parkı, Muratpaşa, Antalya"}, {"title": "Hıdırlık Kulesi", "summary": "Roma döneminden kalma bu kule, hem tarihi bir yapı hem de şehir merkezinde panoramik bir seyir noktasıdır. Özellikle akşam saatlerinde ışıklandırmasıyla büyüleyici bir atmosfer sunar.", "place_query": "Hıdırlık Kulesi, Muratpaşa, Antalya"}, {"title": "Kaleiçi (Antalya''nın Tarihi Merkezi)", "summary": "Dar sokakları, tarihi Osmanlı evleri, butik otelleri ve canlı restoranlarıyla ünlü Kaleiçi, Antalya''nın en popüler turistik bölgesidir. Yat limanı ve Hadrian Kapısı da burada yer alır.", "place_query": "Kaleiçi, Muratpaşa, Antalya"}, {"title": "Hadrian Kapısı (Üçkapılar)", "summary": "Roma İmparatoru Hadrianus onuruna yapılmış bu görkemli zafer takı, Antalya''nın en iyi korunmuş antik yapılarından biridir. Kaleiçi girişinde yer alır ve fotoğrafçılar için vazgeçilmez bir noktadır.", "place_query": "Hadrian Kapısı, Muratpaşa, Antalya"}, {"title": "Antalya Müzesi", "summary": "Türkiye''nin en önemli müzelerinden biri olan Antalya Müzesi, Perge, Aspendos ve Side gibi antik kentlerden çıkarılan eserleri sergiler. Heykel, lahit ve mozaik koleksiyonlarıyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "Antalya Müzesi, Muratpaşa, Antalya"}, {"title": "Konyaaltı Plajı", "summary": "Muratpaşa ilçesinin batı kıyısında uzanan bu halk plajı, berrak denizi ve yürüyüş yoluyla ünlüdür. Plaj boyunca kafeler, bisiklet yolları ve parklar bulunur; aileler ve gençler için ideal bir dinlenme alanıdır.", "place_query": "Konyaaltı Plajı, Muratpaşa, Antalya"}, {"title": "Düden Şelalesi (Aşağı Düden)", "summary": "Şehir merkezine sadece birkaç kilometre uzaklıktaki bu şelale, kayalıklardan doğrudan denize dökülür. Özellikle bahar aylarında debisi artan şelale, muhteşem bir doğa manzarası sunar.", "place_query": "Aşağı Düden Şelalesi, Muratpaşa, Antalya"}, {"title": "Antalya Akvaryum", "summary": "Dünyanın en büyük tünel akvaryumlarından birine sahip olan bu merkez, binlerce deniz canlısını ve dev köpekbalıklarını yakından görme imkanı sunar. Çocuklu aileler ve deniz yaşamı meraklıları için popüler bir duraktır.", "place_query": "Antalya Akvaryum, Muratpaşa, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c40ba123-7eea-4048-8230-aa73bc0b362e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köprülü Kanyon Milli Parkı", "summary": "Doğa sporları ve doğa yürüyüşü sevenler için eşsiz bir park. Kanyon boyunca rafting yapabilir, antik Roma köprüsünü görebilirsiniz.", "place_query": "Köprülü Kanyon Milli Parkı, Serik, Antalya"}, {"title": "Aspendos Antik Kenti", "summary": "Dünyanın en iyi korunmuş Roma tiyatrolarından birine ev sahipliği yapar. Tiyatronun akustiği ve görkemi her yıl binlerce ziyaretçiyi çeker.", "place_query": "Aspendos Antik Kenti, Serik, Antalya"}, {"title": "Belek Plajı", "summary": "Uzun kumsalı, ince kumu ve turkuaz deniziyle tatilcilerin favori noktalarındandır. Çevresindeki lüks oteller ve golf sahalarıyla ünlüdür.", "place_query": "Belek Plajı, Serik, Antalya"}, {"title": "Taşlık Plajı", "summary": "Sakin ve berrak deniziyle yerli halkın tercih ettiği bir plajdır. Çam ağaçları arasında kamp yapma imkanı da sunar.", "place_query": "Taşlık Plajı, Serik, Antalya"}, {"title": "Zeytinada Koyu", "summary": "Doğal güzelliği ve sakin atmosferiyle bilinen, çam ormanlarıyla çevrili küçük bir koydur. Yüzme ve doğa ile baş başa kalmak için idealdir.", "place_query": "Zeytinada Koyu, Serik, Antalya"}, {"title": "Serik Merkez Camii ve Çarşısı", "summary": "İlçe merkezinde yer alan tarihi cami ve etrafındaki geleneksel çarşı, yöresel ürünler almak ve kültürel bir mola vermek için güzel bir duraktır.", "place_query": "Serik Merkez Camii, Serik, Antalya"}, {"title": "Boğazkent Plajı", "summary": "Caretta caretta kaplumbağalarının yumurtlama alanı olarak bilinen bu plaj, doğal yapısıyla dikkat çeker. Sakin ve korunaklı bir yüzme deneyimi sunar.", "place_query": "Boğazkent Plajı, Serik, Antalya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '865ffa19-f4a9-4536-975e-298d5bc46f93'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çıldır Gölü", "summary": "Ardahan''ın incisi olan bu büyük tatlı su gölü, muhteşem manzarası ve kışın donan yüzeyinde yapılan atlı kızak gezileriyle ünlüdür. Yazın ise kuş gözlemciliği ve piknik için idealdir.", "place_query": "Çıldır Gölü, Çıldır, Ardahan"}, {"title": "Çıldır Kalesi", "summary": "Göl kıyısında, tarihi İpek Yolu üzerinde yer alan bu Orta Çağ kalesi, bölgeye hakim bir tepede kuruludur ve ziyaretçilere hem tarihi bir yolculuk hem de eşsiz bir göl manzarası sunar.", "place_query": "Çıldır Kalesi, Çıldır, Ardahan"}, {"title": "Akçakale Adası", "summary": "Çıldır Gölü''nün ortasında bulunan bu küçük ada, üzerindeki tarihi şapel kalıntıları ve doğal güzelliğiyle dikkat çeker. Tekne turlarıyla ulaşılabilen popüler bir gezi noktasıdır.", "place_query": "Akçakale Adası, Çıldır, Ardahan"}, {"title": "Çıldır Gölü Kuş Cenneti", "summary": "Özellikle ilkbahar ve sonbahar göç dönemlerinde yüzlerce kuş türüne ev sahipliği yapan bu alan, doğa fotoğrafçıları ve kuş gözlemcileri için önemli bir duraktır.", "place_query": "Çıldır Gölü Kuş Cenneti, Çıldır, Ardahan"}, {"title": "Kenarbel Yaylası", "summary": "Çıldır''a bağlı bu yayla, tertemiz havası, yeşil doğası ve geleneksel yayla şenlikleriyle bilinir. Doğa yürüyüşü yapmak ve yöresel lezzetleri tatmak için idealdir.", "place_query": "Kenarbel Yaylası, Çıldır, Ardahan"}, {"title": "Şeytan Kalesi", "summary": "Çıldır ilçe merkezine yaklaşık 20 km uzaklıkta, sarp kayalıklar üzerine inşa edilmiş bu tarihi kale, mimarisi ve zorlu ulaşımıyla macera arayan gezginlerin ilgisini çeker.", "place_query": "Şeytan Kalesi, Çıldır, Ardahan"}, {"title": "Çıldır Müzesi", "summary": "İlçe merkezinde yer alan bu küçük müze, bölgedeki arkeolojik kazılardan çıkarılan eserler ve etnografik objelerle Çıldır''ın zengin tarihine ışık tutmaktadır.", "place_query": "Çıldır Müzesi, Çıldır, Ardahan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9f94ce89-60fc-482f-8ff0-89d7c5908584'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Damal Oyuklu Taşlar (Kaya Mezarları)", "summary": "Damal ilçe merkezine yakın konumdaki bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutan etkileyici bir arkeolojik alandır. Ziyaretçiler, kayalara oyulmuş bu yapıları ve çevresindeki doğal manzarayı keşfedebilir.", "place_query": "Oyuklu Taşlar Kaya Mezarları, Damal, Ardahan"}, {"title": "Damal Kalesi", "summary": "İlçe merkezinde yer alan bu tarihi kale, Ardahan''ın stratejik noktalarından biridir ve bölgenin savunma tarihine tanıklık eder. Kaleye çıktığınızda Damal Ovası ve çevre dağların panoramik manzarasını izleyebilirsiniz.", "place_query": "Damal Kalesi, Damal, Ardahan"}, {"title": "Seyit Tepesi ve Seyit Köyü", "summary": "Damal''a bağlı Seyit Köyü''nde bulunan bu tepe, özellikle yaz aylarında düzenlenen geleneksel şenliklere ev sahipliği yapar. Doğal güzelliği ve temiz havasıyla piknik ve doğa yürüyüşü için idealdir.", "place_query": "Seyit Köyü, Damal, Ardahan"}, {"title": "Damal Merkez Camii ve Tarihi Evler", "summary": "İlçe merkezindeki tarihi cami ve çevresindeki geleneksel Ardahan evleri, yöresel mimariyi yansıtan önemli yapılardır. Dar sokaklarda yürüyerek bölgenin kültürel dokusunu hissedebilirsiniz.", "place_query": "Damal Merkez Camii, Damal, Ardahan"}, {"title": "Çıldır Gölü (Damal Kıyıları)", "summary": "Türkiye''nin en soğuk göllerinden biri olan Çıldır Gölü''nün Damal sınırları içindeki kıyıları, doğal güzelliği ve kuş gözlemciliği için popülerdir. Kış aylarında donan gölde buz üstünde yürüyüş yapmak mümkündür.", "place_query": "Çıldır Gölü, Damal, Ardahan"}, {"title": "Damal Yaylaları (Örneğin: Yurtseven Yaylası)", "summary": "Damal çevresindeki yaylalar, yeşil doğası ve serin havasıyla yaz aylarında kaçış noktasıdır. Yayla evlerinde konaklayabilir, yöresel ürünlerin tadına bakabilirsiniz.", "place_query": "Yurtseven Yaylası, Damal, Ardahan"}, {"title": "Kura Nehri Vadisi (Damal Bölümü)", "summary": "Kura Nehri''nin Damal yakınlarından geçen bölümü, doğa yürüyüşleri ve fotoğrafçılık için huzurlu bir ortam sunar. Vadi boyunca uzanan patikalarda yürüyerek nehir sesi eşliğinde zaman geçirebilirsiniz.", "place_query": "Kura Nehri, Damal, Ardahan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cc65bd74-54b3-4065-9c88-f196b3b41a6a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göle Yaylaları", "summary": "Ardahan''ın yüksek rakımlı yaylaları, yemyeşil doğası ve serin havasıyla yaz aylarında doğa yürüyüşleri ve kamp için idealdir. Bölge, zengin bitki örtüsü ve geleneksel yayla kültürünü deneyimlemek isteyen ziyaretçileri cezbeder.", "place_query": "Göle Yaylaları, Ardahan"}, {"title": "Küçük Göle Gölü", "summary": "Göle ilçe merkezine yakın konumda bulunan bu doğal göl, kuş gözlemciliği ve huzurlu bir doğa kaçamağı arayanlar için popüler bir duraktır. Çevresi yeşilliklerle kaplı olan göl, özellikle ilkbahar ve yaz aylarında ziyaret edilir.", "place_query": "Küçük Göle Gölü, Göle, Ardahan"}, {"title": "Göle Kalesi", "summary": "Tarihi bir yapı olan Göle Kalesi, bölgenin geçmişine ışık tutar ve çevresindeki manzara ile dikkat çeker. Kalıntıları günümüze ulaşan kale, tarih meraklıları için önemli bir ziyaret noktasıdır.", "place_query": "Göle Kalesi, Ardahan"}, {"title": "Harmanlı Şelalesi", "summary": "Göle ilçesi sınırlarında yer alan Harmanlı Şelalesi, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için tercih edilir. Şelale, özellikle yaz aylarında bölge halkı ve ziyaretçiler için popüler bir kaçış noktasıdır.", "place_query": "Harmanlı Şelalesi, Göle, Ardahan"}, {"title": "Göle Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, mimarisi ve manevi atmosferi ile dikkat çeker. Ziyaretçiler, caminin çevresindeki geleneksel dokuyla birlikte huzurlu bir gezi yapabilir.", "place_query": "Göle Merkez Camii, Ardahan"}, {"title": "Çıldır Gölü (Göle Kıyıları)", "summary": "Ardahan''ın en büyük gölü olan Çıldır Gölü''nün Göle ilçesine kıyısı bulunan bölümleri, doğa fotoğrafçılığı ve kuş gözlemi için idealdir. Kış aylarında donan göl yüzeyi farklı bir güzellik sunar.", "place_query": "Çıldır Gölü, Göle, Ardahan"}, {"title": "Göle Eski Hamamı", "summary": "Tarihi bir Osmanlı dönemi hamamı olan yapı, ilçenin kültürel mirasını yansıtır. Günümüzde kısmen ayakta olan hamam, tarihi dokuya ilgi duyanlar için görülmeye değerdir.", "place_query": "Göle Eski Hamamı, Ardahan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f392aaf2-5093-4b01-ac4d-a7791b26f414'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çıldır Gölü", "summary": "Ardahan''ın en büyük gölü olan Çıldır Gölü, muhteşem doğal güzelliği ve kış aylarında donan yüzeyinde yapılan atlı kızak gezileriyle ünlüdür. Ziyaretçiler, göl çevresinde yürüyüş yapabilir ve eşsiz manzaraların tadını çıkarabilir.", "place_query": "Çıldır Gölü, Ardahan"}, {"title": "Hanak Şelalesi", "summary": "Hanak ilçe merkezine yaklaşık 15 kilometre uzaklıkta bulunan bu şelale, yemyeşil doğası ve serin sularıyla doğa severler için ideal bir kaçış noktasıdır. Özellikle yaz aylarında piknik ve doğa yürüyüşleri için sıkça ziyaret edilir.", "place_query": "Hanak Şelalesi, Hanak, Ardahan"}, {"title": "Akçakale Adası", "summary": "Ardahan''ın Çıldır ilçesi sınırlarında yer alan ve Çıldır Gölü içindeki bu küçük ada, tarihi bir kilise kalıntısına ev sahipliği yapmaktadır. Göl manzarası eşliğinde huzurlu bir gezi için popüler bir duraktır.", "place_query": "Akçakale Adası, Çıldır, Ardahan"}, {"title": "Ardahan Kalesi", "summary": "Şehir merkezinde bulunan bu tarihi kale, Ardahan''ın en önemli simge yapılarından biridir. Selçuklu ve Osmanlı dönemlerine ait izler taşıyan kale, tepeden şehir manzarasını izlemek için de güzel bir noktadır.", "place_query": "Ardahan Kalesi, Ardahan"}, {"title": "Yalnızçam Kayak Merkezi", "summary": "Ardahan merkeze yaklaşık 30 kilometre mesafedeki bu kayak merkezi, doğal karlı pistleri ve sakin atmosferiyle kış sporları tutkunlarını ağırlar. Özellikle hafta sonu kaçamakları için tercih edilen bir destinasyondur.", "place_query": "Yalnızçam Kayak Merkezi, Ardahan"}, {"title": "Kura Nehri Kenarı", "summary": "Ardahan şehir merkezinden geçen Kura Nehri boyunca uzanan yürüyüş yolları ve yeşil alanlar, yerli halkın ve ziyaretçilerin dinlenmek için tercih ettiği sakin bir bölgedir. Nehir kenarında yürüyüş yapabilir veya piknik yapabilirsiniz.", "place_query": "Kura Nehri, Ardahan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '48ca7423-64b2-4850-8904-feec2465dd01'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ardahan Kalesi", "summary": "Şehir merkezinde yer alan bu tarihi kale, Ardahan''ın simgesi konumundadır. Selçuklu ve Osmanlı dönemlerine tanıklık eden yapı, şehre hakim bir tepede konumlanmıştır.", "place_query": "Ardahan Kalesi, Ardahan Merkez"}, {"title": "Çıldır Gölü", "summary": "Ardahan''ın en önemli doğal güzelliklerinden biri olan Çıldır Gölü, kış aylarında donarak buz üzerinde atlı kızak gezintilerine olanak tanır. Yazın ise kuş gözlemi ve doğa yürüyüşleri için idealdir.", "place_query": "Çıldır Gölü, Ardahan"}, {"title": "Şeytan Kalesi", "summary": "Ardahan Merkez''e bağlı bir bölgede bulunan Şeytan Kalesi, sarp kayalıklar üzerine kurulmuş tarihi bir savunma yapısıdır. Eşsiz manzarası ve gizemli atmosferiyle ziyaretçilerini büyüler.", "place_query": "Şeytan Kalesi, Ardahan"}, {"title": "Ardahan Müzesi", "summary": "Şehir merkezinde yer alan müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Kafkasya ve Anadolu kültürlerinin kesiştiği noktada tarihi eserleri yakından görebilirsiniz.", "place_query": "Ardahan Müzesi, Merkez, Ardahan"}, {"title": "Yalnızçam Kayak Merkezi", "summary": "Ardahan Merkez''e yaklaşık 30 km mesafede bulunan kayak merkezi, doğal karla kaplı pistleri ve bakir doğasıyla kış turizmi için popüler bir destinasyondur.", "place_query": "Yalnızçam Kayak Merkezi, Ardahan"}, {"title": "Kura Nehri Kenarı", "summary": "Şehir merkezinden geçen Kura Nehri''nin çevresi, yürüyüş ve piknik yapmak için ideal bir alandır. Nehir boyunca uzanan parklar, Ardahan''ın sakin atmosferini hissetmek için güzel bir rotadır.", "place_query": "Kura Nehri, Ardahan Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '23a977c0-1dd8-4c31-98ef-238f9e5cb896'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Posof Kalesi", "summary": "İlçe merkezine hakim bir tepede bulunan tarihi kale, bölgenin savunma yapılarına güzel bir örnektir. Ziyaretçilerine Posof ve çevresinin panoramik manzarasını sunar.", "place_query": "Posof Kalesi, Posof, Ardahan"}, {"title": "Cemal Gürsel Caddesi", "summary": "Posof''un en işlek caddesi olup, ilçenin sosyal ve ticari hayatının kalbidir. Burada yöresel ürünler satın alabilir ve Posof halkının günlük yaşamına tanıklık edebilirsiniz.", "place_query": "Cemal Gürsel Caddesi, Posof, Ardahan"}, {"title": "Suskap Yaylası", "summary": "Posof sınırları içinde yer alan bu yayla, yemyeşil doğası ve temiz havasıyla ünlüdür. Özellikle yaz aylarında doğa yürüyüşleri ve kamp için ideal bir noktadır.", "place_query": "Suskap Yaylası, Posof, Ardahan"}, {"title": "Posof Merkez Camii", "summary": "İlçe merkezinde bulunan bu cami, mimarisi ve huzur veren atmosferiyle dikkat çeker. Bölge tarihine tanıklık eden yapılardan biridir.", "place_query": "Posof Merkez Camii, Posof, Ardahan"}, {"title": "Yalnızçam Kayak Merkezi", "summary": "Posof''a yaklaşık 30 km mesafede bulunan bu kayak merkezi, kış aylarında kayak ve snowboard tutkunları için popüler bir destinasyondur. Doğal güzellikleriyle de fotoğrafçıların ilgisini çeker.", "place_query": "Yalnızçam Kayak Merkezi, Ardahan"}, {"title": "Gönülaçan Göleti", "summary": "Posof ilçesindeki bu küçük gölet, piknik ve doğa ile baş başa vakit geçirmek isteyenler için sakin bir ortam sunar. Çevresindeki yeşil alanlar yürüyüş için elverişlidir.", "place_query": "Gönülaçan Göleti, Posof, Ardahan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5d9bccd6-eb77-4dc5-8d6f-cc4910519b11'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ardanuç Kalesi", "summary": "Tarihi bir Orta Çağ kalesi olup, Artvin''in en önemli yapılarından biridir. Ziyaretçiler, kale surları ve burçları arasında gezerken eşsiz vadi manzaraları eşliğinde tarihe yolculuk yapabilir.", "place_query": "Ardanuç Kalesi, Ardanuç, Artvin"}, {"title": "Ardanuç Cehennem Deresi Kanyonu", "summary": "Doğal güzelliği ve yürüyüş parkurlarıyla ünlü bu kanyon, ziyaretçilerine huzur dolu bir doğa deneyimi sunar. Kanyon içindeki şelaleler ve berrak dere suyu fotoğrafçılar için de idealdir.", "place_query": "Cehennem Deresi Kanyonu, Ardanuç, Artvin"}, {"title": "Ardanuç Yaylaları (ör. Ferhatlı Yaylası)", "summary": "Yeşilin her tonunu barındıran yaylalar, doğa yürüyüşü ve kamp için popülerdir. Özellikle yaz aylarında serin havası ve yöresel kültürüyle ziyaretçileri kendine çeker.", "place_query": "Ferhatlı Yaylası, Ardanuç, Artvin"}, {"title": "Ardanuç Şelalesi", "summary": "Çevresindeki zengin bitki örtüsüyle çevrili bu şelale, piknik ve dinlenme için ideal bir noktadır. Su sesi eşliğinde doğayla baş başa vakit geçirmek isteyenler için biçilmiş kaftandır.", "place_query": "Ardanuç Şelalesi, Ardanuç, Artvin"}, {"title": "Ardanuç Merkez Camii ve Tarihi Evler", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki geleneksel Artvin evleri, bölgenin kültürel mirasını yansıtır. Dar sokaklarda yapılan bir yürüyüş, geçmişe kısa bir yolculuk sağlar.", "place_query": "Ardanuç Merkez Camii, Ardanuç, Artvin"}, {"title": "Ardanuç Göleti", "summary": "Sakin ve huzurlu atmosferiyle bilinen bu gölet, özellikle olta balıkçılığı ve doğa yürüyüşü yapanların uğrak noktasıdır. Gölet çevresindeki yeşil alanlar, günübirlik piknikçiler için de uygundur.", "place_query": "Ardanuç Göleti, Ardanuç, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '02bc73e7-15a6-46f7-87e9-fdfe34973b9d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mençuna Şelalesi", "summary": "Arhavi''nin simgelerinden biri olan bu muhteşem şelale, yemyeşil doğanın içinde 60 metre yükseklikten dökülür. Çevresindeki yürüyüş parkurları ve ahşap seyir teraslarıyla doğa tutkunları için eşsiz bir deneyim sunar.", "place_query": "Mençuna Şelalesi, Arhavi, Artvin"}, {"title": "Arhavi Sahili ve Plajları", "summary": "Karadeniz''in serin sularına nazır bu sahil şeridi, yürüyüş yapmak ve deniz manzarasının tadını çıkarmak için idealdir. Yaz aylarında yerli ve yabancı turistlerin uğrak noktası olan plajlar, doğal güzelliğiyle büyüler.", "place_query": "Arhavi Sahili, Arhavi, Artvin"}, {"title": "Kireçburnu Tabiat Parkı", "summary": "Arhavi merkeze yakın konumuyla dikkat çeken bu tabiat parkı, zengin bitki örtüsü ve kamp alanlarıyla doğayla iç içe vakit geçirmek isteyenler için harika bir seçenektir. Piknik alanları ve yürüyüş yollarıyla huzurlu bir kaçış noktasıdır.", "place_query": "Kireçburnu Tabiat Parkı, Arhavi, Artvin"}, {"title": "Arhavi Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, ilçeye hakim bir tepede konumlanmıştır. Kalıntıları günümüze ulaşan yapı, hem tarih meraklılarına hem de muhteşem bir Arhavi ve deniz manzarası arayanlara hitap eder.", "place_query": "Arhavi Kalesi, Arhavi, Artvin"}, {"title": "Soğucak Yaylası", "summary": "Arhavi''nin en popüler yaylalarından biri olan Soğucak, yemyeşil çayırları ve geleneksel yayla evleriyle ünlüdür. Doğa yürüyüşleri ve yayla şenlikleri için sıkça ziyaret edilen bu nokta, serin havasıyla yaz aylarında kaçış noktasıdır.", "place_query": "Soğucak Yaylası, Arhavi, Artvin"}, {"title": "Ortacalar Yaylası", "summary": "Arhavi''nin en yüksek ve en bakir yaylalarından biri olan Ortacalar, bozulmamış doğası ve nefes kesen manzaralarıyla öne çıkar. Özellikle trekking ve kamp severler için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Ortacalar Yaylası, Arhavi, Artvin"}, {"title": "Cenker Yaylası", "summary": "Arhavi''nin en güzel yaylalarından biri kabul edilen Cenker, zengin florası ve yöresel mimarisiyle dikkat çeker. Yayla turizmi için ideal olan bu yer, huzur dolu atmosferiyle ziyaretçilerini büyüler.", "place_query": "Cenker Yaylası, Arhavi, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4ea0fc5f-2ecf-4273-92db-65c1b13e22ab'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Borçka Karagöl", "summary": "Yemyeşil ormanların ortasında, krater gölü oluşumuyla büyüleyici bir doğa harikası. Çevresindeki yürüyüş parkurları ve piknik alanlarıyla doğa severlerin uğrak noktasıdır.", "place_query": "Borçka Karagöl, Artvin"}, {"title": "Camili (Macahel) Biyosfer Rezervi", "summary": "UNESCO tarafından koruma altına alınan bu bölge, eşsiz biyolojik çeşitliliği ve geleneksel ahşap evleriyle ünlüdür. Bal ormanları ve el değmemiş doğasıyla keşfedilmeyi bekler.", "place_query": "Camili Macahel Biyosfer Rezervi, Borçka, Artvin"}, {"title": "Borçka Barajı ve Hidroelektrik Santrali", "summary": "Çoruh Nehri üzerinde yükselen bu devasa baraj, etkileyici manzarası ve mühendislik harikası yapısıyla dikkat çeker. Baraj gölü çevresinde fotoğrafçılık ve doğa yürüyüşü yapılabilir.", "place_query": "Borçka Barajı, Artvin"}, {"title": "Erenler Tepesi", "summary": "Borçka''nın panoramik manzarasını izleyebileceğiniz en güzel seyir noktalarından biridir. Özellikle gün batımında Çoruh Vadisi ve yeşil örtü muhteşem bir görüntü sunar.", "place_query": "Erenler Tepesi, Borçka, Artvin"}, {"title": "Borçka Merkez Camii", "summary": "Osmanlı döneminden kalma tarihi ahşap cami, ince işçiliği ve mimarisiyle dikkat çeker. Restore edilmiş yapısıyla hem ibadet hem de kültürel ziyaret için idealdir.", "place_query": "Borçka Merkez Camii, Artvin"}, {"title": "Çoruh Nehri Rafting Parkuru", "summary": "Türkiye''nin en hızlı akan nehirlerinden biri olan Çoruh, rafting ve kano gibi su sporları için popüler bir destinasyondur. Macera arayanlar için adrenalin dolu bir deneyim sunar.", "place_query": "Çoruh Nehri Rafting, Borçka, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f869fdf5-b30b-414f-a809-e7067f5b4f3d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hopa Kalesi", "summary": "Denize hakim bir tepede yer alan tarihi kale, Hopa''nın simgelerinden biridir. Ziyaretçilerine eşsiz bir Karadeniz manzarası sunar ve bölgenin tarihine dair izler taşır.", "place_query": "Hopa Kalesi, Hopa, Artvin"}, {"title": "Hopa Sahili ve Plajları", "summary": "Karadeniz''in serin sularına kıyısı olan Hopa sahil şeridi, yürüyüş yapmak ve deniz keyfi yaşamak için idealdir. Özellikle yaz aylarında yerli ve yabancı turistlerin uğrak noktasıdır.", "place_query": "Hopa Sahili, Hopa, Artvin"}, {"title": "Kopmuş Dağı (Kop Dağı)", "summary": "Hopa''nın hemen yanı başında yükselen bu dağ, doğa yürüyüşleri ve kampçılık için popüler bir rotadır. Zirvesinden Hopa ve çevresinin nefes kesen panoramik manzarası izlenebilir.", "place_query": "Kop Dağı, Hopa, Artvin"}, {"title": "Hopa Kapalı Çarşı ve Çarşı Camii", "summary": "Hopa''nın merkezinde yer alan tarihi çarşı, yöresel ürünler ve hediyelik eşyalar için uğrak noktasıdır. Çarşı Camii ise bölgenin Osmanlı dönemi mimarisini yansıtan önemli bir yapıdır.", "place_query": "Hopa Kapalı Çarşı, Hopa, Artvin"}, {"title": "Sundura Yaylası", "summary": "Hopa''ya bağlı yaylalardan biri olan Sundura, yemyeşil doğası ve temiz havasıyla ünlüdür. Özellikle yayla turizmi sevenler için kaçırılmayacak bir duraktır.", "place_query": "Sundura Yaylası, Hopa, Artvin"}, {"title": "Hopa Müzesi", "summary": "Eski bir hükümet konağında hizmet veren müze, Artvin ve Hopa''nın tarihini, kültürünü ve etnografik yapısını sergiler. Bölgeyi daha yakından tanımak için ideal bir noktadır.", "place_query": "Hopa Müzesi, Hopa, Artvin"}, {"title": "Çamlı Köyü ve Çamlı Şelalesi", "summary": "Hopa merkeze yaklaşık 15 km mesafedeki Çamlı Köyü''nde bulunan şelale, doğa tutkunlarının sıkça ziyaret ettiği bir yerdir. Çevresindeki yeşil alanlar piknik ve dinlenme için uygundur.", "place_query": "Çamlı Şelalesi, Hopa, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4658968a-1304-47d1-9921-04e13dda0305'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Artvin Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, Artvin''in simgelerindendir. Ziyaretçilerine eşsiz bir şehir ve Çoruh Nehri manzarası sunar.", "place_query": "Artvin Kalesi, Artvin Merkez"}, {"title": "Çoruh Nehri", "summary": "Türkiye''nin en hızlı akan nehirlerinden biri olan Çoruh, özellikle rafting ve doğa sporları için popülerdir. Nehir boyunca uzanan yemyeşil vadi manzaraları büyüleyicidir.", "place_query": "Çoruh Nehri, Artvin"}, {"title": "Atatürk Heykeli ve Atatürk Caddesi", "summary": "Şehir merkezindeki bu meydan ve cadde, Artvin''in sosyal hayatının kalbidir. Heykel çevresi ve caddedeki çay bahçeleri, ziyaretçilerin uğrak noktasıdır.", "place_query": "Atatürk Heykeli, Artvin Merkez"}, {"title": "Salih Paşa Camii", "summary": "19. yüzyıldan kalma bu tarihi cami, kesme taş işçiliği ve zarif mimarisiyle dikkat çeker. Şehrin en önemli dini yapılarından biridir.", "place_query": "Salih Paşa Camii, Artvin Merkez"}, {"title": "Artvin Müzesi", "summary": "Bölgenin arkeolojik ve etnografik zenginliklerini sergileyen müze, Artvin''in kültürel tarihine ışık tutar. Özellikle yöresel kıyafetler ve el sanatları ilgi çekicidir.", "place_query": "Artvin Müzesi, Artvin Merkez"}, {"title": "Seyitler Köyü ve Seyitler Kalesi", "summary": "Şehir merkezine yakın bu köy, doğal güzellikleri ve tarihi kale kalıntılarıyla huzurlu bir kaçış noktasıdır. Yürüyüş ve piknik için idealdir.", "place_query": "Seyitler Köyü, Artvin Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ddad39af-29f5-48c0-bee4-31107f0663be'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Murgul Çoruh Nehri Kenarı", "summary": "Çoruh Nehri''nin serin suları ve yeşil doğasıyla ünlü bu bölge, doğa yürüyüşleri ve piknik için idealdir. Nehir kenarında huzurlu bir gün geçirebilirsiniz.", "place_query": "Murgul Çoruh Nehri, Artvin"}, {"title": "Murgul Merkez Camii", "summary": "Murgul''un tarihi dokusunu yansıtan bu cami, yöre halkı için önemli bir ibadet ve buluşma noktasıdır. Ziyaretçilerine sakin bir atmosfer sunar.", "place_query": "Murgul Merkez Camii, Artvin"}, {"title": "Göktaş Yaylası", "summary": "Murgul''a bağlı Göktaş köyünde yer alan bu yayla, yemyeşil çayırları ve temiz havasıyla doğaseverlerin uğrak noktasıdır. Yaz aylarında yayla şenliklerine ev sahipliği yapar.", "place_query": "Göktaş Yaylası, Murgul, Artvin"}, {"title": "Murgul Şelalesi", "summary": "Orman içinde gizlenmiş bu şelale, doğal güzelliği ve serin sularıyla keşfedilmeyi bekleyen bir cennettir. Piknik ve fotoğrafçılık için popüler bir mekandır.", "place_query": "Murgul Şelalesi, Artvin"}, {"title": "Damar Köyü Tarihi Evleri", "summary": "Murgul''un Damar köyünde bulunan bu geleneksel Artvin evleri, taş ve ahşap mimarisiyle geçmişe yolculuk yapmanızı sağlar. Yöresel kültürü yakından tanıma fırsatı sunar.", "place_query": "Damar Köyü Tarihi Evler, Murgul, Artvin"}, {"title": "Murgul Karagöl", "summary": "Murgul sınırları içinde yer alan bu küçük göl, çevresindeki çam ormanlarıyla huzur verici bir manzaraya sahiptir. Doğa yürüyüşü ve kamp için uygundur.", "place_query": "Murgul Karagöl, Artvin"}, {"title": "Akarsu Köyü Yaylası", "summary": "Murgul''un Akarsu köyünde yer alan bu yayla, zengin bitki örtüsü ve manzarasıyla dikkat çeker. Özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak için tercih edilir.", "place_query": "Akarsu Köyü Yaylası, Murgul, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '54e61b43-5e2c-45cc-ba9f-b532020d5d0a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karçal Dağları", "summary": "Doğa yürüyüşü ve kamp için ideal olan bu dağlar, eşsiz manzaraları ve zengin bitki örtüsüyle doğa tutkunlarının gözde rotasıdır.", "place_query": "Karçal Dağları, Şavşat, Artvin"}, {"title": "Şavşat Karagöl", "summary": "Çam ormanlarıyla çevrili bu krater gölü, huzur veren atmosferi ve muhteşem doğal güzelliğiyle ziyaretçilerini büyüler.", "place_query": "Şavşat Karagöl, Şavşat, Artvin"}, {"title": "Şavşat Kalesi", "summary": "Tarihi bir Orta Çağ kalesi olan yapı, bölgeye hakim bir tepe üzerinde yer alır ve çevrenin panoramik manzarasını sunar.", "place_query": "Şavşat Kalesi, Şavşat, Artvin"}, {"title": "Papart Vadisi", "summary": "Yemyeşil doğası, şelaleleri ve yaylalarıyla ünlü bu vadi, doğa yürüyüşleri ve fotoğrafçılık için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Papart Vadisi, Şavşat, Artvin"}, {"title": "Tbiliski (Tibet) Yaylası", "summary": "Bakir doğası ve serin havasıyla yaz aylarında kaçış noktası olan bu yayla, geleneksel yayla yaşamını deneyimlemek için idealdir.", "place_query": "Tbiliski Yaylası, Şavşat, Artvin"}, {"title": "Şavşat Cevizli (Satlel) Köyü ve Mağaraları", "summary": "Tarihi kaya oyma mağaraları ve doğal güzellikleriyle dikkat çeken bu köy, hem tarih hem de doğa meraklıları için ilginç bir duraktır.", "place_query": "Cevizli Köyü Mağaraları, Şavşat, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'df79fd57-8203-485c-b880-bcdc6c813a07'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Barhal Yaylası", "summary": "Yemyeşil doğası, yayla evleri ve temiz havasıyla ünlü olan bu yayla, doğa yürüyüşleri ve kamp için idealdir. Özellikle yaz aylarında serinlemek ve muhteşem manzaralar eşliğinde vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Barhal Yaylası, Yusufeli, Artvin"}, {"title": "Şavşat Karagöl", "summary": "Çam ormanlarıyla çevrili bu krater gölü, turkuaz rengi suyu ve huzur veren atmosferiyle ziyaretçilerini büyüler. Piknik alanları ve yürüyüş parkurları sayesinde aileler için de popüler bir destinasyondur.", "place_query": "Şavşat Karagöl, Şavşat, Artvin"}, {"title": "Yusufeli Barajı ve HES", "summary": "Devasa boyutları ve etkileyici mühendislik yapısıyla dikkat çeken bu baraj, bölgenin enerji üretiminde önemli bir rol oynar. Baraj gölü çevresindeki manzaralar fotoğrafçılar için eşsiz kareler sunar.", "place_query": "Yusufeli Barajı, Yusufeli, Artvin"}, {"title": "Çoruh Nehri", "summary": "Türkiye''nin en hızlı akan nehirlerinden biri olan Çoruh, rafting ve kano gibi su sporları için dünyaca ünlüdür. Nehir boyunca uzanan vadiler ve kanyonlar, macera tutkunlarına unutulmaz bir deneyim vaat eder.", "place_query": "Çoruh Nehri, Yusufeli, Artvin"}, {"title": "Düzköy Yaylası", "summary": "Sakin ve bakir doğasıyla bilinen Düzköy Yaylası, geleneksel yayla yaşamını deneyimlemek isteyenler için harika bir seçenektir. Yayla şenlikleri ve doğal güzellikleriyle özellikle yerli turistlerin ilgisini çeker.", "place_query": "Düzköy Yaylası, Yusufeli, Artvin"}, {"title": "İşhan Kilisesi", "summary": "Orta Çağ Gürcü mimarisinin en önemli örneklerinden biri olan bu tarihi kilise, freskleri ve taş işçiliğiyle büyüleyicidir. Vadiye hakim konumuyla da etkileyici bir manzaraya sahiptir.", "place_query": "İşhan Kilisesi, Yusufeli, Artvin"}, {"title": "Tekkale Köyü ve Şelalesi", "summary": "Yemyeşil bir vadi içinde yer alan Tekkale Şelalesi, doğayla iç içe bir kaçış noktasıdır. Köyün tarihi taş evleri ve şelalenin serin suları, ziyaretçilere huzurlu bir atmosfer sunar.", "place_query": "Tekkale Şelalesi, Yusufeli, Artvin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '81a7ee1d-2103-43a7-bb55-2e383a032512'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bozdoğan Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin antik dönemlerine ışık tutuyor. Kaleye çıktığınızda Bozdoğan''ın panoramik manzarasını izleyebilirsiniz.", "place_query": "Bozdoğan Kalesi, Bozdoğan, Aydın"}, {"title": "Bozdoğan Barajı", "summary": "Doğal güzellikleriyle çevrili baraj gölü, piknik ve doğa yürüyüşü için ideal bir alandır. Sakin atmosferiyle hafta sonu kaçamaklarında tercih edilen bir noktadır.", "place_query": "Bozdoğan Barajı, Bozdoğan, Aydın"}, {"title": "Bozdoğan Çarşı Hamamı", "summary": "Osmanlı döneminden kalma tarihi hamam, ilçe merkezinde yer alır ve halen kullanılmaktadır. Geleneksel hamam kültürünü deneyimlemek isteyenler için özgün bir duraktır.", "place_query": "Bozdoğan Çarşı Hamamı, Bozdoğan, Aydın"}, {"title": "Yazıkent Kaplıcaları", "summary": "Bozdoğan''a bağlı Yazıkent Mahallesi''nde bulunan termal kaynaklar, şifalı sularıyla ünlüdür. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan kaplıcalar doğa içinde huzurlu bir ortam sunar.", "place_query": "Yazıkent Kaplıcaları, Bozdoğan, Aydın"}, {"title": "Kemer Barajı Mesire Alanı", "summary": "Kemer Barajı çevresinde yer alan mesire alanı, yeşil doğası ve temiz havasıyla piknikçilerin gözde mekanıdır. Baraj gölü manzarası eşliğinde dinlenmek mümkündür.", "place_query": "Kemer Barajı Mesire Alanı, Bozdoğan, Aydın"}, {"title": "Bozdoğan Yaylaları (Alangüllü Yaylası)", "summary": "İlçenin serin yaylalarından biri olan Alangüllü Yaylası, yaz aylarında sıcaktan kaçmak isteyenler için idealdir. Çam ormanları ve temiz havasıyla doğa yürüyüşü ve kamp için uygun bir ortam sunar.", "place_query": "Alangüllü Yaylası, Bozdoğan, Aydın"}, {"title": "Bozdoğan Etnografya Müzesi", "summary": "İlçe merkezinde bulunan müze, yöresel kıyafetler, el sanatları ve günlük yaşam eşyalarıyla Bozdoğan''ın kültürel mirasını sergiler. Bölgenin tarihine dair ilginç detaylar sunan küçük ama zengin bir koleksiyondur.", "place_query": "Bozdoğan Etnografya Müzesi, Bozdoğan, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd8fdb87f-114c-47e2-bfae-3a82ef8c6472'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Buharkent Belediyesi Kültür Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve keyifli vakit geçirmek için ideal bir mekandır. Yeşil alanları, yürüyüş yolları ve çocuk oyun alanları ile aileler için popüler bir buluşma noktasıdır.", "place_query": "Buharkent Belediyesi Kültür Parkı, Buharkent, Aydın"}, {"title": "Buharkent Şelalesi", "summary": "İlçe merkezine yaklaşık 5 km uzaklıkta bulunan bu şelale, doğal güzelliği ve serin sularıyla ziyaretçilerine huzurlu bir ortam sunar. Özellikle yaz aylarında piknik ve doğa yürüyüşü için tercih edilmektedir.", "place_query": "Buharkent Şelalesi, Buharkent, Aydın"}, {"title": "Buharkent Kalesi", "summary": "Tarihi bir kalıntı olan Buharkent Kalesi, bölgenin geçmişine ışık tutan önemli bir yapıdır. Kale kalıntıları, çevresindeki doğal manzara ile birlikte tarih meraklıları ve fotoğrafçılar için ilgi çekicidir.", "place_query": "Buharkent Kalesi, Buharkent, Aydın"}, {"title": "Buharkent Mesire Alanı", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için ideal olan bu mesire alanı, piknik masaları ve yeşil örtüsüyle aileler ve arkadaş grupları için popüler bir hafta sonu kaçamağıdır.", "place_query": "Buharkent Mesire Alanı, Buharkent, Aydın"}, {"title": "Buharkent Yaylası", "summary": "Serin havası ve eşsiz doğa manzarası ile bilinen Buharkent Yaylası, doğa yürüyüşü ve kamp yapmak isteyenler için harika bir rotadır. Yayla, özellikle yaz aylarında sıcaktan kaçan ziyaretçileri ağırlar.", "place_query": "Buharkent Yaylası, Buharkent, Aydın"}, {"title": "Buharkent Seyir Tepesi", "summary": "Buharkent ve çevresinin panoramik manzarasını sunan bu seyir tepesi, gün batımını izlemek ve fotoğraf çekmek için en popüler noktalardan biridir. Ulaşımı kolay olan tepe, kısa bir doğa yürüyüşüyle de ziyaret edilebilir.", "place_query": "Buharkent Seyir Tepesi, Buharkent, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '93472f7f-9282-479c-be0a-8b912a0b7de1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alabanda Antik Kenti", "summary": "Çine''nin en önemli tarihi kalıntılarından biri olan Alabanda, Karya dönemine ait etkileyici bir antik kenttir. Ziyaretçiler, tiyatro, agora ve tapınak kalıntıları arasında tarihe yolculuk yapabilir.", "place_query": "Alabanda Antik Kenti, Çine, Aydın"}, {"title": "Çine Çayı ve Mesire Alanı", "summary": "Çine ilçe merkezinden geçen Çine Çayı boyunca uzanan mesire alanları, piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir. Özellikle yaz aylarında serinlemek için tercih edilen bir noktadır.", "place_query": "Çine Çayı Mesire Alanı, Çine, Aydın"}, {"title": "Çine Kuvayı Milliye Müzesi", "summary": "Çine ilçe merkezinde bulunan bu müze, Milli Mücadele dönemine ait belge, fotoğraf ve eşyaları sergileyerek bölgenin tarihi hafızasını canlı tutar. Tarih meraklıları için önemli bir duraktır.", "place_query": "Çine Kuvayı Milliye Müzesi, Çine, Aydın"}, {"title": "Kırtık Şelalesi", "summary": "Çine''ye bağlı Kırtık köyünde yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla doğa yürüyüşü sevenler için popüler bir kaçış noktasıdır.", "place_query": "Kırtık Şelalesi, Çine, Aydın"}, {"title": "Eski Çine Evleri", "summary": "İlçe merkezinde ve çevre köylerde bulunan geleneksel taş ve ahşap mimarili eski Çine evleri, bölgenin kültürel dokusunu yansıtan fotoğraflık güzel manzaralar sunar.", "place_query": "Eski Çine Evleri, Çine, Aydın"}, {"title": "Çine Barajı ve Çevresi", "summary": "Çine Baraj Gölü çevresi, özellikle balık tutma ve doğa yürüyüşü için sakin bir ortam arayan ziyaretçiler tarafından tercih edilmektedir. Baraj manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Çine Barajı, Çine, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0bb2e993-9c91-441a-89e2-6e4bc14525f3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Apollon Tapınağı", "summary": "Didim''in simgesi olan bu görkemli antik tapınak, dünyanın en büyük üçüncü tapınağıdır. Miletos''un kutsal alanı olarak bilinen yapı, etkileyici sütunları ve tarihi atmosferiyle ziyaretçilerini büyüler.", "place_query": "Apollon Tapınağı, Didim, Aydın"}, {"title": "Altınkum Plajı", "summary": "Didim''in en ünlü plajı olan Altınkum, incecik altın sarısı kumu ve berrak deniziyle tatilcilerin gözdesidir. Mavi Bayraklı plaj, yüzme ve güneşlenmek için idealdir.", "place_query": "Altınkum Plajı, Didim, Aydın"}, {"title": "Milet Antik Kenti", "summary": "Didim''e oldukça yakın olan Milet, İyonya''nın en önemli antik kentlerinden biridir. Etkileyici tiyatrosu ve antik kalıntılarıyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "Milet Antik Kenti, Balat, Didim, Aydın"}, {"title": "Didim Marina", "summary": "Modern marinası, lüks yatları, kafeleri ve restoranlarıyla Didim Marina, hem deniz tutkunları hem de keyifli bir akşam yürüyüşü yapmak isteyenler için popüler bir noktadır.", "place_query": "Didim Marina, Didim, Aydın"}, {"title": "İlyas Bey Külliyesi", "summary": "Milet Antik Kenti yakınında bulunan bu 15. yüzyıl Osmanlı yapısı, cami, hamam ve medreseden oluşmaktadır. Restore edilmiş yapı, tarihi dokusuyla huzur verici bir atmosfere sahiptir.", "place_query": "İlyas Bey Külliyesi, Balat, Didim, Aydın"}, {"title": "Akbük Koyu", "summary": "Didim merkeze biraz uzak ama sakin ve doğal güzelliğiyle ünlü olan Akbük, tertemiz denizi ve çam ormanlarıyla çevrili koyuyla huzur arayanların kaçış noktasıdır.", "place_query": "Akbük Koyu, Didim, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6fe3b9c3-690f-4b85-9d74-3e8a214aa690'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tralleis Antik Kenti", "summary": "Aydın''ın kalbinde yer alan bu antik kent, Helenistik ve Roma dönemine ait kalıntılarıyla tarih meraklıları için eşsiz bir durak. Gymnasium, stadyum ve tiyatro kalıntıları hala görülebiliyor.", "place_query": "Tralleis Antik Kenti, Efeler, Aydın"}, {"title": "Aydın Arkeoloji Müzesi", "summary": "Bölgedeki kazılardan çıkarılan eserlerin sergilendiği müze, özellikle Afrodisias ve Tralleis''ten getirilen heykelleriyle ünlü. Tarihe ilgi duyanların mutlaka görmesi gereken bir yer.", "place_query": "Aydın Arkeoloji Müzesi, Efeler, Aydın"}, {"title": "Nasuh Paşa Külliyesi", "summary": "17. yüzyıldan kalma bu tarihi külliye, cami, medrese, hamam ve çarşıdan oluşuyor. Aydın''ın en önemli Osmanlı dönemi yapılarından biri olup şehir merkezinde yer alıyor.", "place_query": "Nasuh Paşa Külliyesi, Efeler, Aydın"}, {"title": "Aydın Saat Kulesi", "summary": "1890 yılında yapılan bu tarihi saat kulesi, şehrin simgelerinden biridir. Etrafındaki meydan, dinlenmek ve fotoğraf çekmek için ideal bir noktadır.", "place_query": "Aydın Saat Kulesi, Efeler, Aydın"}, {"title": "Çıplak Dağı ve Mesire Alanı", "summary": "Şehre yakın mesafedeki bu doğal alan, piknik ve doğa yürüyüşü için popülerdir. Yemyeşil ormanı ve temiz havasıyla hafta sonu kaçamakları için ideal bir rota.", "place_query": "Çıplak Dağı Mesire Alanı, Efeler, Aydın"}, {"title": "Aydın Büyük Menderes Köprüsü", "summary": "Tarihi taş köprü, Büyük Menderes Nehri üzerinde yer alır ve Osmanlı dönemi mimarisini yansıtır. Nehir manzarası eşliğinde yürüyüş yapmak için güzel bir yerdir.", "place_query": "Büyük Menderes Köprüsü, Efeler, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f95cea73-0a2c-45b9-a98d-edc2f037d9df'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Magnesia Antik Kenti", "summary": "Germencik''in en önemli tarihi zenginliği olan Magnesia, Artemis Tapınağı ve Zeus Tapınağı gibi etkileyici yapılarıyla ünlüdür. Antik kent, iyi korunmuş stadyumu ve agorasıyla ziyaretçilere antik dönemin ihtişamını yaşatır.", "place_query": "Magnesia Antik Kenti, Germencik, Aydın"}, {"title": "Germencik Şelalesi", "summary": "Doğa ile iç içe huzurlu bir kaçamak arayanlar için ideal olan şelale, çevresindeki piknik alanları ve yeşil doğasıyla hafta sonu ziyaretçilerinin gözde mekanlarından biridir.", "place_query": "Germencik Şelalesi, Germencik, Aydın"}, {"title": "Gümüşköy Kaplıcaları", "summary": "Termal turizm açısından önemli bir nokta olan Gümüşköy Kaplıcaları, romatizmal hastalıklara iyi gelen şifalı suları ve modern tesisleriyle sağlık turizmine hizmet vermektedir.", "place_query": "Gümüşköy Kaplıcaları, Germencik, Aydın"}, {"title": "Kızılcapınar Göleti", "summary": "Doğal güzelliği ve sakin atmosferiyle bilinen Kızılcapınar Göleti, özellikle balık tutma ve doğa yürüyüşü gibi aktiviteler için tercih edilmektedir. Çevresindeki yeşil alanlar piknik yapmak için de uygundur.", "place_query": "Kızılcapınar Göleti, Germencik, Aydın"}, {"title": "Ortaklar Köyü (Tarihi Evler)", "summary": "Germencik''e bağlı Ortaklar Köyü, geleneksel Türk mimarisini yansıtan tarihi evleri ve dar sokaklarıyla ziyaretçilere nostaljik bir atmosfer sunar. Köy, sakin ve otantik yapısıyla fotoğraf tutkunları için de ilgi çekicidir.", "place_query": "Ortaklar Köyü, Germencik, Aydın"}, {"title": "Hıdırbaba Türbesi", "summary": "Manevi bir atmosfere sahip olan Hıdırbaba Türbesi, bölge halkı tarafından kutsal kabul edilen ve ziyaret edilen önemli bir dini mekandır. Çevresindeki doğal doku türbeye ayrı bir huzur katmaktadır.", "place_query": "Hıdırbaba Türbesi, Germencik, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '066b434e-663b-4b0e-9d86-d1b87b57cb00'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İncirliova Belediyesi Kültür Parkı", "summary": "İlçe merkezinde yer alan bu park, yürüyüş yolları, yeşil alanları ve çocuk oyun alanlarıyla aileler için popüler bir dinlenme ve gezinti noktasıdır.", "place_query": "İncirliova Belediyesi Kültür Parkı, Aydın"}, {"title": "İncirliova Saat Kulesi", "summary": "İlçenin sembol yapılarından biri olan bu tarihi saat kulesi, merkezi bir konumda yer alır ve fotoğraf çekmek için sıkça ziyaret edilir.", "place_query": "İncirliova Saat Kulesi, Aydın"}, {"title": "İncirliova Halk Pazarı", "summary": "Yöresel ürünlerin, taze meyve ve sebzelerin satıldığı bu pazar, özellikle hafta sonları yerli halk ve ziyaretçilerin uğrak noktasıdır.", "place_query": "İncirliova Halk Pazarı, Aydın"}, {"title": "İncirliova Camii (Merkez Camii)", "summary": "İlçe merkezindeki bu tarihi cami, mimarisi ve manevi atmosferiyle dikkat çeker, ibadet ve ziyaret için önemli bir mekandır.", "place_query": "İncirliova Merkez Camii, Aydın"}, {"title": "İncirliova Mesire Alanı", "summary": "Şehir dışında kalan bu mesire alanı, piknik yapmak, doğayla iç içe vakit geçirmek isteyenler için sakin bir kaçış noktasıdır.", "place_query": "İncirliova Mesire Alanı, Aydın"}, {"title": "İncirliova Tren İstasyonu", "summary": "Tarihi bir demiryolu durağı olan bu istasyon, nostaljik atmosferi ve çevresindeki kafelerle gezginlerin ilgisini çeker.", "place_query": "İncirliova Tren İstasyonu, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '91d2a5dd-85b8-4e85-9695-490b396be1b0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aphrodisias Antik Kenti", "summary": "Afrodit''e adanmış bu etkileyici antik kent, muhteşem stadyumu ve mermer heykelleriyle ünlüdür. UNESCO Dünya Mirası Listesi''nde yer alan ören yeri, Karacasu''nun en önemli turistik cazibe merkezidir.", "place_query": "Aphrodisias Antik Kenti, Karacasu, Aydın"}, {"title": "Aphrodisias Müzesi", "summary": "Antik kentten çıkarılan birbirinden değerli heykel ve lahitlerin sergilendiği müze, ziyaretçilere bölgenin zengin tarihini yakından görme fırsatı sunar.", "place_query": "Aphrodisias Müzesi, Karacasu, Aydın"}, {"title": "Karacasu Barajı", "summary": "Doğal güzellikleri ve çevresindeki yeşil alanlarıyla piknik ve dinlenmek için ideal bir noktadır. Özellikle hafta sonları ailelerin uğrak yeridir.", "place_query": "Karacasu Barajı, Aydın"}, {"title": "Geyre Mahallesi (Eski Geyre)", "summary": "Aphrodisias antik kentinin üzerine kurulu olan eski Geyre köyü, taş evleri ve dar sokaklarıyla otantik bir atmosfere sahiptir. Köyün bir kısmı antik kent kazıları nedeniyle taşınmıştır.", "place_query": "Geyre Mahallesi, Karacasu, Aydın"}, {"title": "Karacasu Evleri", "summary": "Yöresel mimarinin güzel örneklerini oluşturan tarihi Karacasu evleri, cumbalı ve taş işçilikli yapılarıyla ilçe merkezinde gezilip görülebilecek kültürel değerlerdendir.", "place_query": "Karacasu Evleri, Aydın"}, {"title": "Dandalaz Çayı", "summary": "Karacasu''dan geçen ve doğal bir dinlenme alanı sunan Dandalaz Çayı kenarı, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Dandalaz Çayı, Karacasu, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7b19087e-ab5a-4ef2-8c49-cb12cd7ffe07'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alinda Antik Kenti", "summary": "Karpuzlu ilçe merkezinde bulunan bu antik kent, Helenistik döneme ait surları, agora ve tiyatrosuyla tarih severler için eşsiz bir durak. Yamaçtaki konumu sayesinde ziyaretçilere hem tarih hem de doğa manzarası sunuyor.", "place_query": "Alinda Antik Kenti, Karpuzlu, Aydın"}, {"title": "Karpuzlu Kalesi", "summary": "Alinda Antik Kenti''nin bir parçası olan bu kale, bölgeye hakim bir tepe üzerinde yer alır. Yürüyerek ulaşılabilen kale, etkileyici taş işçiliği ve panoramik Karpuzlu manzarasıyla fotoğrafçıların ilgisini çeker.", "place_query": "Karpuzlu Kalesi, Karpuzlu, Aydın"}, {"title": "Karpuzlu Barajı", "summary": "Doğal güzelliklerle çevrili bu baraj gölü, piknik ve olta balıkçılığı için idealdir. Sakin atmosferi ve yeşil çevresiyle hafta sonu kaçamaklarında tercih edilen bir noktadır.", "place_query": "Karpuzlu Barajı, Karpuzlu, Aydın"}, {"title": "Karpuzlu Şelalesi", "summary": "İlçe merkezine yakın mesafedeki bu küçük şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır. Çevresindeki yeşil alanlar piknik için uygundur.", "place_query": "Karpuzlu Şelalesi, Karpuzlu, Aydın"}, {"title": "Karpuzlu Köy Pazarı", "summary": "Yöresel ürünlerin ve el işi eşyaların satıldığı bu pazar, bölgenin kültürel dokusunu yansıtır. Ziyaretçiler, taze meyve-sebze ve zeytinyağı gibi yerel lezzetleri burada bulabilir.", "place_query": "Karpuzlu Köy Pazarı, Karpuzlu, Aydın"}, {"title": "Karpuzlu Kent Ormanı", "summary": "Yürüyüş parkurları ve piknik masalarıyla donatılmış bu ormanlık alan, doğa yürüyüşü sevenler için huzurlu bir rota sunar. Özellikle bahar aylarında yeşilin her tonunu görmek mümkündür.", "place_query": "Karpuzlu Kent Ormanı, Karpuzlu, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '179e1abf-8840-4d20-9228-2463eb7dd318'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cihanoğlu Konağı", "summary": "Koçarlı''nın en önemli tarihi yapılarından biri olan konak, Osmanlı dönemi sivil mimarisinin güzel bir örneğidir. Ziyaretçiler, restore edilmiş yapıda geçmişe yolculuk yapabilir.", "place_query": "Cihanoğlu Konağı, Koçarlı, Aydın"}, {"title": "Koçarlı Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, Koçarlı''nın simgelerinden biridir. Çevresindeki alan, dinlenmek ve fotoğraf çekmek için idealdir.", "place_query": "Koçarlı Saat Kulesi, Aydın"}, {"title": "Kemer Barajı ve Mesire Alanı", "summary": "Koçarlı sınırları içindeki Kemer Barajı, piknik ve doğa yürüyüşü için popüler bir noktadır. Baraj gölü manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Kemer Barajı, Koçarlı, Aydın"}, {"title": "Sarıçayır Tabiat Parkı", "summary": "Koçarlı''ya yakın konumda bulunan bu tabiat parkı, zengin bitki örtüsü ve temiz havasıyla doğaseverler için idealdir. Piknik alanları ve yürüyüş parkurları bulunur.", "place_query": "Sarıçayır Tabiat Parkı, Koçarlı, Aydın"}, {"title": "Koçarlı Merkez Camii", "summary": "İlçe merkezindeki tarihi cami, mimarisi ve huzur veren atmosferiyle dikkat çeker. Ziyaretçiler, hem ibadet edebilir hem de yapının detaylarını inceleyebilir.", "place_query": "Koçarlı Merkez Camii, Aydın"}, {"title": "Bıyıklı Köyü Kaya Mezarları", "summary": "Koçarlı''ya bağlı Bıyıklı Köyü''nde bulunan bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Tarih meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Bıyıklı Köyü Kaya Mezarları, Koçarlı, Aydın"}, {"title": "Çakırbeyli Köyü Çınaraltı Mesire Alanı", "summary": "Koçarlı''nın Çakırbeyli Köyü''nde yer alan bu mesire alanı, dev çınar ağaçlarının gölgesinde dinlenme imkanı sunar. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Çakırbeyli Köyü Çınaraltı, Koçarlı, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2d4bad4c-385a-4091-803d-931484da2023'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köşk Şelalesi", "summary": "İlçe merkezine yakın konumda yer alan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilerine huzurlu bir kaçış sunar. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Köşk Şelalesi, Köşk, Aydın"}, {"title": "Köşk Belediyesi Kent Ormanı", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla ailelerin uğrak noktasıdır. Şehirden uzaklaşmadan doğada vakit geçirmek isteyenler için mükemmel bir seçenektir.", "place_query": "Köşk Kent Ormanı, Köşk, Aydın"}, {"title": "Köşk Pazarı", "summary": "Her hafta kurulan bu pazar, bölgenin taze meyve, sebze ve yöresel ürünlerini bulabileceğiniz canlı bir alışveriş noktasıdır. Yerel halkla kaynaşmak ve Aydın''ın lezzetlerini tatmak için idealdir.", "place_query": "Köşk Pazarı, Köşk, Aydın"}, {"title": "Köşk Yaylası", "summary": "Şehir merkezine kısa bir mesafede bulunan bu yayla, serin havası ve çam ormanlarıyla ünlüdür. Doğa yürüyüşleri ve kampçılık için sıkça tercih edilen bir destinasyondur.", "place_query": "Köşk Yaylası, Köşk, Aydın"}, {"title": "Köşk Göleti", "summary": "Huzurlu bir su manzarası eşliğinde piknik yapmak veya olta balıkçılığıyla ilgilenmek için popüler bir mekandır. Çevresindeki dinlenme alanları sayesinde hafta sonu kaçamakları için sıkça ziyaret edilir.", "place_query": "Köşk Göleti, Köşk, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3b8325fc-fe77-4185-8279-cc9004420d64'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kadınlar Denizi", "summary": "Kuşadası''nın en popüler ve tarihi plajıdır. İnce kumlu sahili, berrak denizi ve sahil boyunca sıralanan kafe ve restoranlarıyla hem yerli hem de yabancı turistlerin uğrak noktasıdır.", "place_query": "Kadınlar Denizi Plajı, Kuşadası, Aydın"}, {"title": "Kuşadası Kalesi (Güvercinada)", "summary": "Kuşadası''nın simgesi haline gelmiş, anakaraya bir yolla bağlı küçük bir adadır. Tarihi Bizans ve Ceneviz kalesi, muhteşem gün batımı manzarası ve deniz içindeki konumuyla ziyaretçileri cezbeder.", "place_query": "Güvercinada Kalesi, Kuşadası, Aydın"}, {"title": "Dilek Yarımadası-Büyük Menderes Deltası Milli Parkı", "summary": "Kuşadası''na sadece birkaç kilometre uzaklıkta, eşsiz bir doğal yaşam alanıdır. Yürüyüş parkurları, sakin koyları (İçmeler, Aydınlık) ve zengin flora-faunası ile doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Dilek Yarımadası Milli Parkı, Kuşadası, Aydın"}, {"title": "Antik Efes Kenti", "summary": "Kuşadası''na yaklaşık 20 km mesafedeki bu antik kent, dünyanın en iyi korunmuş antik kentlerinden biridir. Celsus Kütüphanesi ve Büyük Tiyatro gibi yapılarıyla tarihe yolculuk yapmak isteyenler için mutlaka görülmesi gereken bir yerdir.", "place_query": "Efes Antik Kenti, Selçuk, İzmir"}, {"title": "Kuşadası Setur Marina", "summary": "Modern ve lüks bir marina olan Setur Marina, yüzlerce yatın bağlı olduğu, şık restoranlar, kafeler ve butik mağazalarıyla ünlüdür. Akşam yürüyüşleri ve deniz manzarası eşliğinde yemek yemek için popüler bir mekandır.", "place_query": "Setur Kuşadası Marina, Kuşadası, Aydın"}, {"title": "Kuşadası Özel Şehir Müzesi", "summary": "Kuşadası''nın tarihini, kültürünü ve geçmiş yaşamını yansıtan eserlerin sergilendiği bir müzedir. Ziyaretçilere kentin geçmişine dair keyifli bir bakış sunar.", "place_query": "Kuşadası Özel Şehir Müzesi, Kuşadası, Aydın"}, {"title": "Ladies Beach (Kadınlar Plajı)", "summary": "Kuşadası''nın en ünlü plajlarından biri olan bu plaj, canlı atmosferi ve plaj olanaklarıyla bilinir. Su sporları, şezlong ve şemsiye hizmetleriyle konforlu bir gün geçirmek isteyenler için idealdir.", "place_query": "Ladies Beach, Kuşadası, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ff4d9f06-d27e-46d7-a5a8-7cc2cddca390'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kuyucak Kaplıcaları", "summary": "Doğal termal sularıyla ünlü olan Kuyucak Kaplıcaları, romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan şifalı suları ve huzurlu atmosferiyle ziyaretçilerini ağırlar.", "place_query": "Kuyucak Kaplıcaları, Kuyucak, Aydın"}, {"title": "Gencelli Şelalesi", "summary": "Yemyeşil doğa içinde yer alan Gencelli Şelalesi, serin suları ve piknik alanlarıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Gencelli Şelalesi, Kuyucak, Aydın"}, {"title": "Kuyucak Merkez Camii", "summary": "Osmanlı dönemi mimarisini yansıtan tarihi cami, ilçenin merkezinde yer alır ve sade ama etkileyici yapısıyla dikkat çeker.", "place_query": "Kuyucak Merkez Camii, Kuyucak, Aydın"}, {"title": "Kuyucak Barajı", "summary": "Büyük Menderes Nehri üzerinde kurulu olan baraj, çevresindeki yeşil alanlar ve su sporları imkanlarıyla huzurlu bir gün geçirmek isteyenler için popüler bir duraktır.", "place_query": "Kuyucak Barajı, Kuyucak, Aydın"}, {"title": "Kuyucak Saat Kulesi", "summary": "İlçenin sembol yapılarından biri olan saat kulesi, Cumhuriyet dönemi mimarisini yansıtarak şehir merkezinde ziyaretçilerin ilgisini çeker.", "place_query": "Kuyucak Saat Kulesi, Kuyucak, Aydın"}, {"title": "Kuyucak Yaylası", "summary": "Serin havası ve doğal güzellikleriyle bilinen Kuyucak Yaylası, özellikle yaz aylarında şehir kalabalığından uzaklaşmak isteyenler için tercih edilen bir dinlenme alanıdır.", "place_query": "Kuyucak Yaylası, Kuyucak, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a5c7eb0c-655f-4577-a11f-e6ffedfc083c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nazilli Sümerbank Basma Fabrikası", "summary": "Cumhuriyet döneminin ilk sanayi yatırımlarından biri olan bu tarihi fabrika, endüstriyel mirasın önemli bir parçasıdır. Günümüzde kültür merkezi olarak hizmet veren yapı, sergi ve etkinliklere ev sahipliği yapmaktadır.", "place_query": "Nazilli Sümerbank Basma Fabrikası, Nazilli, Aydın"}, {"title": "Nazilli Atatürk Parkı", "summary": "Şehrin merkezinde yer alan bu geniş park, dinlenme ve yürüyüş alanlarıyla Nazillililerin ve ziyaretçilerin uğrak noktasıdır. İçerisindeki Atatürk Anıtı ve yeşil dokusuyla dikkat çeker.", "place_query": "Atatürk Parkı, Nazilli, Aydın"}, {"title": "Arpaz Kalesi", "summary": "Nazilli yakınlarındaki Arpaz Köyü''nde bulunan bu tarihi kale, Roma ve Bizans dönemlerine ait izler taşır. Yüksek bir tepe üzerine kurulu olan kale, çevreye hakim manzarasıyla görülmeye değerdir.", "place_query": "Arpaz Kalesi, Nazilli, Aydın"}, {"title": "Ortaköy Kaplıcası", "summary": "Nazilli ilçe sınırları içinde yer alan bu doğal termal kaynak, şifalı sularıyla bilinir. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan kaplıca, doğayla iç içe bir deneyim sunar.", "place_query": "Ortaköy Kaplıcası, Nazilli, Aydın"}, {"title": "Nazilli Kültür Merkezi", "summary": "Modern bir yapı olan kültür merkezi, tiyatro, konser ve sergi gibi çeşitli sanatsal etkinliklere ev sahipliği yapar. Şehrin kültürel hayatının kalbinin attığı bu mekan, ziyaretçilere keyifli anlar yaşatır.", "place_query": "Nazilli Kültür Merkezi, Nazilli, Aydın"}, {"title": "Nazilli Belediye Hamamı", "summary": "Tarihi bir Osmanlı hamamı olan bu yapı, geleneksel mimarisiyle dikkat çeker. Halen aktif olarak hizmet veren hamam, hem tarihi bir mekan gezisi hem de geleneksel hamam deneyimi için idealdir.", "place_query": "Nazilli Belediye Hamamı, Nazilli, Aydın"}, {"title": "Güzelköy Şelalesi", "summary": "Nazilli''ye bağlı Güzelköy sınırlarında bulunan bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü sevenler için popüler bir duraktır.", "place_query": "Güzelköy Şelalesi, Nazilli, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ff50fdfc-8e5d-4a40-adb5-fece0811459a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Priene Antik Kenti", "summary": "Milet ve Didim ile birlikte İyonya''nın en önemli şehirlerinden biri olan Priene, etkileyici tiyatrosu ve Athena Tapınağı ile tarih meraklıları için eşsiz bir duraktır.", "place_query": "Priene Antik Kenti, Söke, Aydın"}, {"title": "Milet Antik Kenti", "summary": "Antik dünyanın en büyük tiyatrolarından birine ev sahipliği yapan Milet, liman anıtları ve agora kalıntılarıyla görülmeye değer bir antik kenttir.", "place_query": "Milet Antik Kenti, Söke, Aydın"}, {"title": "Didim Antik Kenti (Apollon Tapınağı)", "summary": "Dünyanın en büyük tapınaklarından biri olan Apollon Tapınağı''nın bulunduğu Didim, görkemli sütunları ve mitolojik hikayeleriyle büyüler.", "place_query": "Apollon Tapınağı, Didim, Aydın"}, {"title": "Bafa Gölü Tabiat Parkı", "summary": "Latmos Dağları''nın eteklerinde yer alan Bafa Gölü, doğal güzelliği, kuş çeşitliliği ve çevresindeki antik yerleşimlerle huzurlu bir doğa kaçamağı sunar.", "place_query": "Bafa Gölü Tabiat Parkı, Söke, Aydın"}, {"title": "Dilek Yarımadası-Büyük Menderes Deltası Milli Parkı", "summary": "Benzersiz bitki örtüsü, yaban hayatı ve güzel koylarıyla ünlü bu milli park, doğa yürüyüşleri ve deniz keyfi için ideal bir yerdir.", "place_query": "Dilek Yarımadası Milli Parkı, Söke, Aydın"}, {"title": "Söke Pazarı", "summary": "Yöresel ürünlerin, taze sebze ve meyvelerin, el dokuması bezlerin bulunduğu renkli Söke Pazarı, otantik bir alışveriş deneyimi yaşatır.", "place_query": "Söke Pazarı, Söke, Aydın"}, {"title": "Myus Antik Kenti", "summary": "İyonya''nın küçük ama önemli şehirlerinden Myus, Bafa Gölü kıyısındaki kalıntıları ve huzurlu atmosferiyle tarih ve doğayı birleştirir.", "place_query": "Myus Antik Kenti, Söke, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3232fb88-84cc-4806-bedc-65731a4c5ae6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nysa Antik Kenti", "summary": "Sultanhisar''ın en önemli tarihi hazinesi olan Nysa, Roma dönemine ait görkemli bir kent. Özellikle devasa tiyatrosu, kütüphane kalıntıları ve agora yapılarıyla ziyaretçilerini büyüler.", "place_query": "Nysa Antik Kenti, Sultanhisar, Aydın"}, {"title": "Gerger Çayı ve Mesire Alanı", "summary": "Sultanhisar''ın doğal güzelliklerinden biri olan Gerger Çayı, piknik alanları ve serin sularıyla yerli halkın ve ziyaretçilerin uğrak noktasıdır. Doğa ile baş başa vakit geçirmek için idealdir.", "place_query": "Gerger Çayı Mesire Alanı, Sultanhisar, Aydın"}, {"title": "Sultanhisar Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale kalıntıları, bölgeye hakim manzarasıyla dikkat çeker. Geçmişte savunma amaçlı kullanılan bu yapı, günümüzde tarih ve manzara meraklıları için güzel bir rota sunar.", "place_query": "Sultanhisar Kalesi, Sultanhisar, Aydın"}, {"title": "Atça Tren İstasyonu ve Çevresi", "summary": "Sultanhisar''ın Atça Mahallesi''nde bulunan tarihi tren istasyonu, nostaljik bir atmosfere sahiptir. İstasyon çevresindeki eski yapılar ve demiryolu hattı, fotoğraf tutkunları için keyifli bir duraktır.", "place_query": "Atça Tren İstasyonu, Sultanhisar, Aydın"}, {"title": "Malgaç Köprüsü", "summary": "Tarihi taş köprülerden biri olan Malgaç Köprüsü, Sultanhisar''ın kırsal dokusunu yansıtan önemli bir yapıdır. Çevresindeki yeşil alanlarla birlikte huzurlu bir gezi noktasıdır.", "place_query": "Malgaç Köprüsü, Sultanhisar, Aydın"}, {"title": "Kavaklı Parkı", "summary": "Sultanhisar merkezde yer alan Kavaklı Parkı, geniş yeşil alanı ve yürüyüş yollarıyla dinlenmek için popüler bir mekandır. Aileler ve çocuklar için güvenli ve keyifli bir ortam sunar.", "place_query": "Kavaklı Parkı, Sultanhisar, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '61d736b5-8b48-4be5-a1c5-8ca0aa4442c9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yenipazar Kapalı Pazarı", "summary": "Yenipazar''ın en bilinen simgelerinden biri olan tarihi kapalı pazar, yöresel ürünlerin ve el sanatlarının satıldığı canlı bir alışveriş noktasıdır.", "place_query": "Yenipazar Kapalı Pazarı, Aydın"}, {"title": "Yenipazar Kervansarayı", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan kervansaray, bölgenin ticaret ve konaklama geçmişine tanıklık eden önemli bir kültürel mirastır.", "place_query": "Yenipazar Kervansarayı, Aydın"}, {"title": "Yenipazar Saat Kulesi", "summary": "İlçe merkezinde yer alan bu şık saat kulesi, Yenipazar''ın sembol yapılarından biri olup ziyaretçilerin uğrak noktasıdır.", "place_query": "Yenipazar Saat Kulesi, Aydın"}, {"title": "Yenipazar Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgenin tarihini ve kültürel dokusunu yansıtan eserleri sergilemektedir.", "place_query": "Yenipazar Müzesi, Aydın"}, {"title": "Bozdoğan Barajı (Yenipazar yakını)", "summary": "İlçeye yakın konumda bulunan bu baraj gölü, doğal manzarası ve piknik alanlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Bozdoğan Barajı, Aydın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3c962368-e325-428e-8659-f8b70bafd2cf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zağnos Paşa Külliyesi", "summary": "Altıeylül''ün sembol yapılarından biri olan tarihi külliye, cami, hamam ve medreseden oluşur. Osmanlı dönemi mimarisini yakından görmek ve huzurlu bir atmosferde vakit geçirmek için idealdir.", "place_query": "Zağnos Paşa Külliyesi, Altıeylül, Balıkesir"}, {"title": "Balıkesir Kuvayi Milliye Müzesi", "summary": "Milli Mücadele dönemine ışık tutan bu müze, Kurtuluş Savaşı''na ait belgeler, fotoğraflar ve eşyalarla zengin bir koleksiyona sahiptir. Tarih meraklıları için mutlaka görülmesi gereken bir noktadır.", "place_query": "Balıkesir Kuvayi Milliye Müzesi, Altıeylül, Balıkesir"}, {"title": "Balıkesir Saat Kulesi", "summary": "Şehrin merkezinde yer alan bu tarihi saat kulesi, 19. yüzyıldan kalma bir simge yapıdır. Çevresindeki kafe ve restoranlarla birlikte keyifli bir mola noktasıdır.", "place_query": "Balıkesir Saat Kulesi, Altıeylül, Balıkesir"}, {"title": "Değirmenboğazı Tabiat Parkı", "summary": "Şehir merkezine yakın konumuyla doğa ile iç içe bir kaçış noktasıdır. Yürüyüş parkurları, piknik alanları ve göletiyle aileler ve doğa severler için popüler bir mekandır.", "place_query": "Değirmenboğazı Tabiat Parkı, Altıeylül, Balıkesir"}, {"title": "Balıkesir Büyükşehir Belediyesi Hayvanat Bahçesi", "summary": "Özellikle çocuklu aileler için ideal bir gezi noktası olan hayvanat bahçesi, birçok farklı türde hayvana ev sahipliği yapar. Geniş yeşil alanlarıyla keyifli bir gün geçirmek için uygundur.", "place_query": "Balıkesir Büyükşehir Belediyesi Hayvanat Bahçesi, Altıeylül, Balıkesir"}, {"title": "Mollauslu Kanyonu", "summary": "Altıeylül sınırları içinde yer alan bu doğal kanyon, yürüyüş ve doğa sporları için harika bir rotadır. Sarp kayalıkları ve yeşil bitki örtüsüyle görsel bir şölen sunar.", "place_query": "Mollauslu Kanyonu, Altıeylül, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fb12346c-94f9-49d0-ae1a-5d1f11684df8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şeytan Sofrası", "summary": "Ayvalık''ın simgelerinden biri olan bu seyir tepesi, gün batımında sunduğu nefes kesici manzara ve ortasındaki efsanevi çukuruyla ünlüdür. Zirveden Takımadalar ve Ayvalık Körfezi''nin panoramik fotoğraflarını çekebilirsiniz.", "place_query": "Şeytan Sofrası, Ayvalık, Balıkesir"}, {"title": "Ayvalık Takımadaları (Cunda Adası dahil)", "summary": "22 adadan oluşan bu doğal güzellik, özellikle Cunda Adası (Ali Bey Adası) ile ünlüdür. Mavi yolculuklar, yüzme molaları ve adalar arası tekne turları için popüler bir destinasyondur.", "place_query": "Cunda Adası, Ayvalık, Balıkesir"}, {"title": "Saatli Camii (Ayvalık Merkez)", "summary": "Eskiden bir kilise olan ve Osmanlı döneminde camiye çevrilen bu yapı, şehrin en ikonik tarihi eserlerinden biridir. Kulesindeki saati ve etkileyici mimarisiyle merkezde mutlaka görülmelidir.", "place_query": "Saatli Camii, Ayvalık, Balıkesir"}, {"title": "Ayvalık Tarihi Taş Mektepler ve Taksiyarhis Kilisesi", "summary": "Rum mimarisinin en güzel örneklerinden biri olan Taksiyarhis Kilisesi, günümüzde müze olarak hizmet vermektedir. Yanındaki tarihi taş mektepler ise Ayvalık''ın kültürel dokusunu yansıtır.", "place_query": "Taksiyarhis Kilisesi Müzesi, Ayvalık, Balıkesir"}, {"title": "Sarımazı Plajı", "summary": "Ayvalık''ın en popüler ve uzun sahil şeritlerinden biri olan Sarımazı, ince kumu ve sığ deniziyle aileler için idealdir. Sahil boyunca kafeler ve restoranlar da bulunur.", "place_query": "Sarımazı Plajı, Ayvalık, Balıkesir"}, {"title": "Devil''s Table (Şeytan Sofrası) - Alternatif isimle Badavut Plajı", "summary": "Şeytan Sofrası''nın eteğinde yer alan Badavut Plajı, sakin ve temiz deniziyle bilinir. Özellikle rüzgar sörfü yapmak isteyenler için uygun dalga koşulları sunar.", "place_query": "Badavut Plajı, Ayvalık, Balıkesir"}, {"title": "Ayvalık Adaları Tabiat Parkı", "summary": "Korunan bir doğal alan olan bu park, zengin bitki örtüsü ve endemik türleriyle doğa yürüyüşleri ve kamp için idealdir. Adalar arasında yapılan tekne turlarıyla keşfedilebilir.", "place_query": "Ayvalık Adaları Tabiat Parkı, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd7d21078-edff-4e2b-93e8-bf64782ebc32'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Balya İlçe Merkezi ve Tarihi Çarşı", "summary": "Balya''nın eski çarşı bölgesi, tarihi dükkanları ve taş binalarıyla geçmişe yolculuk yapmanızı sağlar. Özellikle eski Rum evleri ve çarşıdaki samimi atmosfer, yöresel lezzetleri tatmak için idealdir.", "place_query": "Balya Merkez, Balıkesir"}, {"title": "Balya Madenleri (Eski Kurşun-Çinko Madeni)", "summary": "Osmanlı döneminden beri işletilen tarihi maden ocakları, bölgenin sanayi geçmişine ışık tutar. Terk edilmiş maden tesisleri ve tüneller, endüstriyel miras meraklıları için ilgi çekici bir keşif noktasıdır.", "place_query": "Balya Madenleri, Balya, Balıkesir"}, {"title": "Şifalı Su (Balya İçmeleri)", "summary": "Doğal kaynak suyu ve şifalı içme suyu olarak bilinen bu nokta, hem dinlenmek hem de doğayla baş başa kalmak için tercih edilir. Çevresindeki yeşil alanlar piknik yapmaya elverişlidir.", "place_query": "Balya İçmeleri, Balıkesir"}, {"title": "Kocaoluk Yaylası", "summary": "Yemyeşil çam ormanlarıyla çevrili bu yayla, temiz havası ve huzurlu ortamıyla doğa yürüyüşleri ve kamp için idealdir. Yaz aylarında serinlemek ve manzaranın tadını çıkarmak için güzel bir kaçış noktasıdır.", "place_query": "Kocaoluk Yaylası, Balya, Balıkesir"}, {"title": "Karaoğlan Şelalesi", "summary": "Balya''nın gizli kalmış doğal güzelliklerinden biri olan şelale, özellikle bahar ve yaz aylarında akan suyu ve çevresindeki yeşil örtüyle fotoğrafçılar ve doğaseverler için harika bir rotadır.", "place_query": "Karaoğlan Şelalesi, Balya, Balıkesir"}, {"title": "Gökköy Göleti", "summary": "Balya''ya yaklaşık 10 km mesafedeki bu küçük gölet, çevresindeki piknik alanları ve sakin ortamıyla hafta sonu kaçamakları için uygundur. Balık tutma imkanı da sunar.", "place_query": "Gökköy Göleti, Balya, Balıkesir"}, {"title": "Havran Barajı ve Çevresi", "summary": "Balya sınırlarına yakın olan Havran Barajı, geniş su yüzeyi ve çevresindeki yeşil alanlarla doğa yürüyüşü ve manzara seyri için tercih edilir. Özellikle gün batımında görsel bir şölen sunar.", "place_query": "Havran Barajı, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e1e8b440-c494-431b-98d7-b7f7ef121884'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kuş Cenneti Milli Parkı", "summary": "Bandırma''nın hemen yanı başındaki Manyas Kuş Cenneti, 266''dan fazla kuş türüne ev sahipliği yapan eşsiz bir sulak alan ve doğa harikasıdır. Kuş gözlem kuleleri ve müzesiyle doğaseverler için vazgeçilmez bir duraktır.", "place_query": "Kuş Cenneti Milli Parkı, Bandırma, Balıkesir"}, {"title": "Bandırma Arkeoloji Müzesi", "summary": "Kyzikos antik kenti ve çevresinden çıkarılan eserlerin sergilendiği bu modern müze, bölgenin zengin tarihine ışık tutar. Heykeller, lahitler ve sikke koleksiyonlarıyla tarih meraklılarını cezbeder.", "place_query": "Bandırma Arkeoloji Müzesi, Bandırma, Balıkesir"}, {"title": "Kyzikos Antik Kenti", "summary": "Bandırma''ya bağlı Erdek ilçesi sınırlarında bulunan bu antik kent, devasa Hadrian Tapınağı kalıntılarıyla ünlüdür. Roma döneminin en önemli liman kentlerinden biri olan Kyzikos, etkileyici sütunları ve tiyatrosuyla ziyaretçilerini büyüler.", "place_query": "Kyzikos Antik Kenti, Erdek, Balıkesir"}, {"title": "Erdek Plajları", "summary": "Bandırma''nın gözde tatil beldesi Erdek, ince kumlu ve mavi bayraklı plajlarıyla ünlüdür. Zeytinliada ve Çuğra gibi noktalarıyla deniz, kum ve güneş tatili için ideal bir kaçış noktasıdır.", "place_query": "Erdek Plajı, Erdek, Balıkesir"}, {"title": "Bandırma Sahil Yolu ve Cumhuriyet Meydanı", "summary": "Şehrin kalbindeki bu canlı alan, deniz manzaralı yürüyüş yolu, kafeleri ve Atatürk heykeliyle Bandırma''nın sosyal yaşamının merkezidir. Gün batımında yapılan bir yürüyüş, şehrin en keyifli anlarından biridir.", "place_query": "Cumhuriyet Meydanı, Bandırma, Balıkesir"}, {"title": "Manyas Gölü (Kuş Gölü)", "summary": "Kuş Cenneti''nin de bulunduğu bu büyük tatlı su gölü, doğal güzelliği ve biyolojik çeşitliliğiyle dikkat çeker. Göl çevresinde yapılan doğa yürüyüşleri ve piknik alanları, huzurlu bir gün geçirmek isteyenler için biçilmiş kaftandır.", "place_query": "Manyas Gölü, Bandırma, Balıkesir"}, {"title": "Bandırma Eski Gar Binası", "summary": "Tarihi 19. yüzyıla uzanan bu şık taş bina, Bandırma''nın demiryolu geçmişinin simgesidir. Günümüzde kültürel etkinliklere ev sahipliği yapan yapı, mimarisiyle fotoğraf tutkunlarının ilgisini çeker.", "place_query": "Bandırma Eski Gar Binası, Bandırma, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e797d479-6924-4fd8-b1f5-823a957c0033'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bigadiç Mağarası", "summary": "Burası, Türkiye''nin en büyük mağaralarından biridir ve etkileyici sarkıt, dikit ile sütun oluşumlarıyla ziyaretçilerini büyüler. Doğal güzelliği ve kolay ulaşılabilirliği sayesinde bölgenin en popüler turistik noktasıdır.", "place_query": "Bigadiç Mağarası, Bigadiç, Balıkesir"}, {"title": "Bigadiç Yaylaları (Çağış Yaylası)", "summary": "Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için ideal olan Çağış Yaylası, yemyeşil ormanları ve temiz havasıyla ünlüdür. Piknik ve doğa yürüyüşleri için harika bir seçenektir.", "place_query": "Çağış Yaylası, Bigadiç, Balıkesir"}, {"title": "Hisar Tepesi (Kale Kalıntıları)", "summary": "Bigadiç''in tarihi dokusunu yansıtan Hisar Tepesi, antik dönemlerden kalma kale kalıntılarına ev sahipliği yapar. Tepeye çıktığınızda ilçenin ve çevresinin muhteşem bir panoramik manzarasını izleyebilirsiniz.", "place_query": "Hisar Tepesi, Bigadiç, Balıkesir"}, {"title": "Kozpınar Şelalesi", "summary": "Doğal güzellikleriyle öne çıkan Kozpınar Şelalesi, özellikle bahar aylarında suyunun coşkun akışıyla görsel bir şölen sunar. Çevresindeki piknik alanları ile hafta sonu kaçamakları için popüler bir duraktır.", "place_query": "Kozpınar Şelalesi, Bigadiç, Balıkesir"}, {"title": "Bigadiç Kent Müzesi", "summary": "İlçenin tarihini, kültürünü ve geleneklerini yakından tanımak isteyenler için ideal bir durak olan müze, etnografik eserler ve yöresel objelerle zengin bir koleksiyona sahiptir. Bigadiç''in geçmişine dair keyifli bir yolculuk sunar.", "place_query": "Bigadiç Kent Müzesi, Bigadiç, Balıkesir"}, {"title": "Gölcük Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla bilinen Gölcük Göleti, çevresindeki mesire alanı ve yürüyüş parkurlarıyla doğaseverlerin uğrak noktasıdır. Gölet kenarında huzurlu bir gün geçirmek mümkündür.", "place_query": "Gölcük Göleti, Bigadiç, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '85e72273-5a26-4a49-948c-631cf734032b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ören Plajı", "summary": "Burhaniye''nin en popüler plajı olan Ören, ince kumlu sahili ve temiz deniziyle yaz aylarında yerli turistlerin akınına uğrar. Mavi Bayraklı plajda güneşlenip yüzebilir, sahil boyunca sıralanan kafe ve restoranlarda vakit geçirebilirsiniz.", "place_query": "Ören Plajı, Burhaniye, Balıkesir"}, {"title": "Burhaniye Kent Müzesi", "summary": "Eski bir taş binada hizmet veren müze, bölgenin tarihini, kültürünü ve zeytincilik geçmişini sergiler. Ziyaretçiler, yöresel kıyafetler ve tarım aletleriyle Burhaniye''nin geçmişine yolculuk yapar.", "place_query": "Burhaniye Kent Müzesi, Burhaniye, Balıkesir"}, {"title": "Taylıeli Koyu", "summary": "Sakin ve doğal güzelliğiyle bilinen Taylıeli Koyu, berrak denizi ve çam ormanlarıyla çevrili yapısıyla huzur arayanların tercihidir. Kamp yapmak veya doğayla baş başa kalmak için idealdir.", "place_query": "Taylıeli Koyu, Burhaniye, Balıkesir"}, {"title": "Pelitköy Sahili", "summary": "Uzun kumsalı ve sakin atmosferiyle bilinen Pelitköy, kalabalıktan uzak bir deniz keyfi sunar. Sahil boyunca yürüyüş yapabilir veya denize girip gün batımını izleyebilirsiniz.", "place_query": "Pelitköy Sahili, Burhaniye, Balıkesir"}, {"title": "Burhaniye Zeytin ve Zeytinyağı Müzesi", "summary": "Zeytinciliğin kalbi sayılan Burhaniye''de bu müze, zeytinyağı üretim sürecini ve yöresel kültürü tanıtır. Tarihi zeytinyağı işliklerini ve ekipmanları görme fırsatı bulursunuz.", "place_query": "Burhaniye Zeytin ve Zeytinyağı Müzesi, Burhaniye, Balıkesir"}, {"title": "Kemer Çamlığı Tabiat Parkı", "summary": "Çam ağaçlarıyla kaplı bu tabiat parkı, piknik ve doğa yürüyüşleri için popüler bir mekandır. Temiz havası ve kuş sesleri eşliğinde keyifli bir gün geçirebilirsiniz.", "place_query": "Kemer Çamlığı Tabiat Parkı, Burhaniye, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'df7863c0-ce8a-4428-b321-0ae3dd6f7813'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayvatlar Şelalesi", "summary": "Dursunbey''in en popüler doğal güzelliklerinden biri olan şelale, yemyeşil ormanlar içinde yer alır. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için ideal bir noktadır.", "place_query": "Ayvatlar Şelalesi, Dursunbey, Balıkesir"}, {"title": "Kocakaya Mağarası", "summary": "Bölgenin önemli doğal oluşumlarından olan mağara, sarkıt ve dikitleriyle dikkat çeker. Doğa severler ve mağara araştırmacıları için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Kocakaya Mağarası, Dursunbey, Balıkesir"}, {"title": "Dursunbey Milli Parkı", "summary": "Zengin bitki örtüsü ve çam ormanlarıyla kaplı milli park, kampçılık ve doğa yürüyüşleri için mükemmel bir ortam sunar. Temiz havası ve huzurlu atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Dursunbey Milli Parkı, Balıkesir"}, {"title": "Kumluca Yaylası", "summary": "Yemyeşil doğası ve serin havasıyla özellikle yaz aylarında şehir gürültüsünden kaçmak isteyenlerin uğrak noktasıdır. Yayla evleri ve doğal güzellikleriyle huzur verici bir kaçış noktasıdır.", "place_query": "Kumluca Yaylası, Dursunbey, Balıkesir"}, {"title": "Selimağa Çeşmesi", "summary": "Tarihi bir çeşme olan Selimağa Çeşmesi, Dursunbey''in kültürel miraslarından biridir. Çeşmenin bulunduğu alan, dinlenmek ve fotoğraf çekmek için sıkça ziyaret edilir.", "place_query": "Selimağa Çeşmesi, Dursunbey, Balıkesir"}, {"title": "Çanakçı Kanyonu", "summary": "Doğa yürüyüşçüleri ve macera arayanlar için ideal olan kanyon, etkileyici kaya oluşumları ve derin vadileriyle görülmeye değerdir. Kanyonda yürüyüş yaparken eşsiz manzaralar keşfedebilirsiniz.", "place_query": "Çanakçı Kanyonu, Dursunbey, Balıkesir"}, {"title": "Dursunbey Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi cami, Osmanlı dönemi mimarisinin güzel örneklerinden biridir. Hem ibadet hem de tarihi bir yapıyı görmek amacıyla ziyaret edilir.", "place_query": "Dursunbey Merkez Camii, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1b66923d-b014-4197-b383-1aff470e1990'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kazdağı Milli Parkı", "summary": "Muhteşem doğası, endemik bitki türleri ve yürüyüş parkurlarıyla ünlü milli park. Ziyaretçilerine eşsiz bir doğa deneyimi sunar.", "place_query": "Kazdağı Milli Parkı, Edremit, Balıkesir"}, {"title": "Akçay Sahili", "summary": "Edremit''in en popüler sahil şeridi olan Akçay, mavi bayraklı plajları ve canlı atmosferiyle tatilcilerin uğrak noktasıdır.", "place_query": "Akçay Sahili, Edremit, Balıkesir"}, {"title": "Şahin Deresi Kanyonu", "summary": "Doğa yürüyüşü ve kampçılık için ideal olan bu kanyon, derin vadileri ve şelaleleriyle dikkat çeker. Eşsiz manzaralar sunar.", "place_query": "Şahin Deresi Kanyonu, Edremit, Balıkesir"}, {"title": "Altınoluk Sahili", "summary": "Sakin ve huzurlu atmosferiyle bilinen Altınoluk, uzun kumsalı ve berrak deniziyle aileler için ideal bir plajdır.", "place_query": "Altınoluk Sahili, Edremit, Balıkesir"}, {"title": "Antandros Antik Kenti", "summary": "Edremit sınırları içinde yer alan antik kent, tarihi kalıntıları ve kazı çalışmalarıyla ziyaretçilere tarihle iç içe bir gezi imkanı sunar.", "place_query": "Antandros Antik Kenti, Edremit, Balıkesir"}, {"title": "Zeytinli Ada", "summary": "Edremit Körfezi''nde yer alan bu küçük ada, zeytin ağaçları ve doğal güzellikleriyle bilinir. Tekne turlarıyla ziyaret edilebilir.", "place_query": "Zeytinli Ada, Edremit, Balıkesir"}, {"title": "Edremit Körfezi Sahili", "summary": "Uzun kumsalı ve çeşitli plaj tesisleriyle ünlü olan körfez sahil şeridi, yaz aylarında yoğun ilgi görür ve su sporları için idealdir.", "place_query": "Edremit Körfezi Sahili, Edremit, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '829f38b1-af07-4ca9-a511-caa6abaf3b99'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zeytinli Ada (Manastır Adası)", "summary": "Erdek Körfezi''nde bulunan bu küçük ada, tarihi manastır kalıntıları ve muhteşem deniz manzarasıyla ünlüdür. Tekne turlarıyla ulaşılabilen ada, huzurlu atmosferi ve yüzme imkanı ile ziyaretçilerin favorisidir.", "place_query": "Zeytinli Ada, Erdek, Balıkesir"}, {"title": "Erdek Sahili ve İskele Meydanı", "summary": "Uzun kumsalı ve canlı sahil şeridiyle Erdek''in kalbi sayılan bu bölge, yürüyüş yapmak, denize girmek ve sahil kenarındaki kafe/restoranlarda vakit geçirmek için idealdir.", "place_query": "Erdek Sahili, Erdek, Balıkesir"}, {"title": "Kybele (Mater Magna) Anıtı", "summary": "Erdek yakınlarındaki antik Kyzikos kentine ait bu devasa ana tanrıça heykeli, bölgenin en önemli arkeolojik eserlerinden biridir. Tarih meraklıları için etkileyici bir duraktır.", "place_query": "Kybele Anıtı, Erdek, Balıkesir"}, {"title": "Kyzikos Antik Kenti", "summary": "Marmara Denizi kıyısında yer alan bu antik kent, görkemli kalıntıları ve özellikle Hadrian Tapınağı ile ünlüdür. Erdek''e birkaç kilometre uzaklıktaki bu ören yeri, tarihe yolculuk yapmak isteyenler için biçilmiş kaftandır.", "place_query": "Kyzikos Antik Kenti, Erdek, Balıkesir"}, {"title": "Belkıs Plajı", "summary": "Erdek''in en popüler ve temiz plajlarından biri olan Belkıs, ince kumu ve sakin deniziyle özellikle aileler tarafından tercih edilmektedir. Plajda güneşlenmek ve yüzmek için harika bir noktadır.", "place_query": "Belkıs Plajı, Erdek, Balıkesir"}, {"title": "Kapıdağ Yarımadası", "summary": "Doğal güzellikleri, zeytinlikleri ve pitoresk köyleriyle ünlü bu yarımada, doğa yürüyüşleri ve bisiklet turları için mükemmeldir. Aynı zamanda eşsiz manzaralar sunan seyir noktalarına ev sahipliği yapar.", "place_query": "Kapıdağ Yarımadası, Erdek, Balıkesir"}, {"title": "Peynirli Ada", "summary": "Erdek''in hemen açıklarında yer alan bu küçük ada, berrak denizi ve doğal güzelliğiyle tekne turlarının sık uğradığı bir noktadır. Adada yüzme ve şnorkelle dalış yapmak oldukça keyiflidir.", "place_query": "Peynirli Ada, Erdek, Balıkesir"}, {"title": "Erdek Çarşı ve Balıkçılar", "summary": "Şehir merkezindeki hareketli çarşı, yöresel ürünler ve taze balık almak için en doğru adrestir. Özellikle akşam saatlerinde balıkçı tezgahları ve restoranlar bölgeye ayrı bir canlılık katar.", "place_query": "Erdek Çarşısı, Erdek, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4dee0364-c2b5-4b84-97ed-e2f42055ec4c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gömeç Sahili", "summary": "Gömeç''in en popüler noktası olan bu sahil, uzun kumsalı ve sakin deniziyle aileler ve yüzme severler için idealdir. Çevresindeki kafe ve restoranlarla keyifli bir gün geçirebilirsiniz.", "place_query": "Gömeç Sahili, Gömeç, Balıkesir"}, {"title": "Karaağaç Plajı", "summary": "Berrak suları ve doğal kumsalıyla bilinen bu plaj, özellikle yaz aylarında yerli turistlerin uğrak noktasıdır. Sakin atmosferiyle dinlenmek isteyenler için harika bir seçenektir.", "place_query": "Karaağaç Plajı, Gömeç, Balıkesir"}, {"title": "Yel Değirmenleri Tepesi", "summary": "Gömeç''in simgelerinden olan bu tepe, tarihi yel değirmenleri ve muhteşem deniz manzarasıyla ünlüdür. Özellikle gün batımında fotoğrafçılar için eşsiz bir seyir noktasıdır.", "place_query": "Yel Değirmenleri Tepesi, Gömeç, Balıkesir"}, {"title": "Gömeç Kalesi", "summary": "Tarihi bir Bizans kalesi olan bu yapı, bölgenin geçmişine tanıklık eder. Kalıntıları arasında dolaşırken hem tarih hem de doğa iç içe bir deneyim yaşarsınız.", "place_query": "Gömeç Kalesi, Gömeç, Balıkesir"}, {"title": "Musalar Koyu", "summary": "Sakin ve huzurlu bir koy olan Musalar, doğal güzelliği ve temiz deniziyle bilinir. Çevredeki zeytinlikler arasında yürüyüş yapıp serin sularında yüzebilirsiniz.", "place_query": "Musalar Koyu, Gömeç, Balıkesir"}, {"title": "Gömeç Belediyesi Halk Plajı", "summary": "Ücretsiz ve düzenli bir plaj olan bu alan, şezlong ve şemsiye hizmetleriyle konforlu bir gün geçirmenizi sağlar. Özellikle çocuklu aileler için güvenli bir yüzme alanıdır.", "place_query": "Gömeç Belediyesi Halk Plajı, Gömeç, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '77eee113-d316-41d2-b9d3-e6d4a60ab8f1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gönen Kaplıcaları", "summary": "Bölgenin en ünlü şifa merkezi olan Gönen Kaplıcaları, romatizma ve cilt hastalıklarına iyi gelen termal sularıyla ünlüdür. Modern tesislerde konaklama ve tedavi imkanı sunar.", "place_query": "Gönen Kaplıcaları, Gönen, Balıkesir"}, {"title": "Sarıköy Kaplıcası", "summary": "Gönen''e bağlı Sarıköy''de yer alan bu kaplıca, doğal ortamı ve şifalı termal sularıyla huzurlu bir kaçış noktasıdır. Özellikle sindirim sistemi rahatsızlıklarına iyi geldiği bilinir.", "place_query": "Sarıköy Kaplıcası, Gönen, Balıkesir"}, {"title": "Gönen Şelalesi", "summary": "Yeşillikler içinde gizlenmiş bu şelale, piknik ve doğa yürüyüşü için ideal bir mekandır. Serin suları ve huzur veren atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Gönen Şelalesi, Gönen, Balıkesir"}, {"title": "Gönen Kent Müzesi", "summary": "Eski bir hükümet konağında hizmet veren müze, Gönen''in tarihini, kültürünü ve termal turizminin gelişimini sergileyen eserler barındırır. Şehir merkezinde kolayca ziyaret edilebilir.", "place_query": "Gönen Kent Müzesi, Balıkesir"}, {"title": "Kocaçay Mesire Alanı", "summary": "Gönen Çayı kenarında uzanan bu mesire alanı, aileler ve doğaseverler için popüler bir dinlenme noktasıdır. Yürüyüş parkurları ve piknik alanlarıyla hafta sonu kaçamağı yapmak isteyenleri ağırlar.", "place_query": "Kocaçay Mesire Alanı, Gönen, Balıkesir"}, {"title": "Gönen Kapalı Çarşısı", "summary": "Tarihi dokusuyla dikkat çeken bu kapalı çarşı, yöresel ürünler ve hediyelik eşyalar almak için uğranması gereken bir yerdir. Özellikle termal sabun ve doğal kozmetik ürünleri meşhurdur.", "place_query": "Gönen Kapalı Çarşısı, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a0ab1917-871a-40bf-aa5f-241264215a83'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Havran Barajı ve Çevresi", "summary": "Havran''a yaklaşık 5 km uzaklıktaki bu baraj, piknik alanları ve doğal güzelliğiyle hafta sonu kaçamakları için idealdir. Çam ormanlarıyla çevrili manzarası ve sakin atmosferi ziyaretçileri cezbeder.", "place_query": "Havran Barajı, Havran, Balıkesir"}, {"title": "Çamdibi Köyü ve Şelalesi", "summary": "Havran''a bağlı Çamdibi Köyü''nde yer alan bu şelale, özellikle bahar aylarında coşkun akan suları ve yeşil doğasıyla doğa yürüyüşçülerinin uğrak noktasıdır.", "place_query": "Çamdibi Köyü Şelalesi, Havran, Balıkesir"}, {"title": "Havran Saat Kulesi", "summary": "Cumhuriyet Meydanı''nda bulunan bu tarihi saat kulesi, ilçenin simgelerinden biridir. 20. yüzyıl başında yapılan kule, Havran''ın kent dokusuna karakter katar.", "place_query": "Havran Saat Kulesi, Havran, Balıkesir"}, {"title": "Havran Kentsel Sit Alanı ve Tarihi Evler", "summary": "Havran''ın merkezinde yer alan bu bölge, geleneksel Osmanlı dönemi ahşap ve taş evleriyle dikkat çeker. Arnavut kaldırımlı sokaklarda yürüyerek geçmişe yolculuk yapabilirsiniz.", "place_query": "Havran Tarihi Evler, Havran, Balıkesir"}, {"title": "Küçükdere Şelalesi", "summary": "Havran ilçe merkezine yaklaşık 15 km mesafedeki bu şelale, serin suları ve çevresindeki piknik alanlarıyla doğaseverler için popüler bir duraktır.", "place_query": "Küçükdere Şelalesi, Havran, Balıkesir"}, {"title": "Havran Zeytinyağı Müzesi", "summary": "Bölgenin zeytincilik kültürünü tanıtan bu özel müze, geleneksel zeytinyağı üretim yöntemlerini ve tarihi aletleri sergiler. Zeytin ve zeytinyağına ilgi duyanlar için keyifli bir duraktır.", "place_query": "Havran Zeytinyağı Müzesi, Havran, Balıkesir"}, {"title": "Kocasepet Tepesi Seyir Noktası", "summary": "Havran''ın yüksek noktalarından biri olan bu tepe, özellikle gün batımında ilçe ve çevresinin panoramik manzarasını sunar. Doğa yürüyüşü yapmak için de uygun rotalara sahiptir.", "place_query": "Kocasepet Tepesi, Havran, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2a3bc5ce-0507-43cf-ba3e-c11bda90fc75'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İvrindi Mağarası", "summary": "Bölgenin en önemli doğal güzelliklerinden biri olan bu mağara, etkileyici sarkıt ve dikitleriyle ziyaretçilerini büyüler. Doğa yürüyüşleri ve mağara keşfi için ideal bir noktadır.", "place_query": "İvrindi Mağarası, İvrindi, Balıkesir"}, {"title": "Gökçeyazı Göleti", "summary": "Huzurlu atmosferi ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popüler bir mekandır. Gölet kenarında dinlenip kuş sesleri eşliğinde vakit geçirebilirsiniz.", "place_query": "Gökçeyazı Göleti, İvrindi, Balıkesir"}, {"title": "Kocaoluk Şelalesi", "summary": "Yemyeşil ormanlar içinde gizlenmiş bu şelale, serin suları ve doğal güzelliği ile ziyaretçilerine huzur dolu bir kaçış sunar. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Kocaoluk Şelalesi, İvrindi, Balıkesir"}, {"title": "İvrindi Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale kalıntıları, bölgenin stratejik önemini gözler önüne serer. Tepeye konumlanmış yapısıyla çevreye hakim bir manzara sunar.", "place_query": "İvrindi Kalesi, İvrindi, Balıkesir"}, {"title": "Küçük Yayla Mesire Alanı", "summary": "Şehir hayatından uzaklaşmak isteyenler için ideal bir mesire alanıdır. Çam ağaçları arasında yürüyüş yapabilir, piknik yaparak doğanın tadını çıkarabilirsiniz.", "place_query": "Küçük Yayla Mesire Alanı, İvrindi, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '39249996-dbdb-4eb0-a155-a3ab62b79791'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kuvâ-yi Milliye Müzesi", "summary": "Balıkesir''in kurtuluş mücadelesindeki önemli rolünü anlatan bu müze, Milli Mücadele dönemine ait belge, fotoğraf ve eşyaları sergiliyor. Tarih meraklıları için etkileyici bir durak.", "place_query": "Kuvâ-yi Milliye Müzesi, Karesi, Balıkesir"}, {"title": "Balıkesir Saat Kulesi", "summary": "Karesi ilçesinin sembol yapılarından biri olan bu tarihi saat kulesi, 1827 yılında inşa edilmiş olup şehrin merkezinde yer alır. Çevresindeki meydan, buluşma noktası olarak popülerdir.", "place_query": "Balıkesir Saat Kulesi, Karesi, Balıkesir"}, {"title": "Zagor ve Macera Adası", "summary": "Özellikle çocuklu aileler için eğlenceli bir tema parkı olan Macera Adası, Zagor temalı oyun alanları ve doğal güzellikleriyle keyifli vakit geçirme imkanı sunar.", "place_query": "Zagor ve Macera Adası, Karesi, Balıkesir"}, {"title": "Değirmen Boğazı Tabiat Parkı", "summary": "Karesi''ye bağlı bu doğal alan, yürüyüş parkurları, piknik alanları ve göletiyle doğa severler için huzurlu bir kaçış noktasıdır. Hafta sonu kaçamakları için idealdir.", "place_query": "Değirmen Boğazı Tabiat Parkı, Karesi, Balıkesir"}, {"title": "Balıkesir Büyükşehir Belediyesi Atatürk Parkı", "summary": "Şehir merkezinde geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla dinlenmek ve spor yapmak için en çok tercih edilen parklardan biridir.", "place_query": "Atatürk Parkı, Karesi, Balıkesir"}, {"title": "Zağnos Paşa Camii", "summary": "Fatih Sultan Mehmet''in vezirlerinden Zağnos Paşa tarafından 1461 yılında yaptırılan bu tarihi cami, klasik Osmanlı mimarisinin güzel bir örneğidir. Şehrin en eski yapılarından biridir.", "place_query": "Zağnos Paşa Camii, Karesi, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dc9ab652-cb5b-4af1-94c6-0f052d8ee628'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kepsut Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale, ilçenin simgelerinden biridir. Ziyaretçilerine hem tarihi bir atmosfer hem de çevredeki doğal güzellikleri seyretme imkanı sunar.", "place_query": "Kepsut Kalesi, Kepsut, Balıkesir"}, {"title": "Kepsut Şelalesi", "summary": "Doğal güzelliğiyle dikkat çeken şelale, piknik ve doğa yürüyüşü için ideal bir mekandır. Sakin atmosferi ve yeşil doğasıyla ziyaretçilerine huzur verir.", "place_query": "Kepsut Şelalesi, Kepsut, Balıkesir"}, {"title": "Kepsut Göleti", "summary": "Balık tutma ve doğa ile iç içe vakit geçirme imkanı sunan gölet, özellikle hafta sonu kaçamakları için popülerdir. Çevresindeki yürüyüş yolları da ziyaretçilere keyifli anlar yaşatır.", "place_query": "Kepsut Göleti, Kepsut, Balıkesir"}, {"title": "Kepsut Merkez Camii", "summary": "Osmanlı dönemine ait tarihi bir yapı olan cami, mimarisi ve süslemeleriyle dikkat çeker. İlçenin merkezinde yer alması nedeniyle kolayca ziyaret edilebilir.", "place_query": "Kepsut Merkez Camii, Kepsut, Balıkesir"}, {"title": "Kepsut Pazarı", "summary": "Yöresel ürünlerin ve el işi eşyaların satıldığı pazar, ilçenin kültürel dokusunu yansıtır. Ziyaretçiler burada taze meyve-sebze ve hediyelik eşyalar bulabilir.", "place_query": "Kepsut Pazarı, Kepsut, Balıkesir"}, {"title": "Kepsut Yaylası", "summary": "Doğal güzellikleri ve temiz havasıyla bilinen yayla, doğa yürüyüşleri ve kampçılık için uygundur. Yaz aylarında serinlemek ve şehir hayatından kaçmak isteyenlerin tercih ettiği bir noktadır.", "place_query": "Kepsut Yaylası, Kepsut, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f61d0268-2515-4dab-a496-5337d36e1cd3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kuş Cenneti Milli Parkı", "summary": "Türkiye''nin en önemli kuş gözlem alanlarından biri olan Manyas Kuş Cenneti, yüzlerce kuş türüne ev sahipliği yapar. Ziyaretçiler, gözlem kulelerinden kuşları izleyebilir ve eşsiz doğal güzelliğin tadını çıkarabilir.", "place_query": "Kuş Cenneti Milli Parkı, Manyas, Balıkesir"}, {"title": "Manyas Gölü", "summary": "Bereketli suları ve çevresindeki yeşil alanlarla ünlü Manyas Gölü, doğa yürüyüşleri ve piknik için ideal bir noktadır. Gölde balık tutma imkanı da bulunur.", "place_query": "Manyas Gölü, Manyas, Balıkesir"}, {"title": "Saraylar Mahallesi (Tarihi Evler)", "summary": "Manyas''ın eski mahallelerinden biri olan Saraylar, geleneksel Osmanlı dönemi ahşap evleriyle dikkat çeker. Dar sokaklarında yürüyerek tarihi bir atmosfer yaşayabilirsiniz.", "place_query": "Saraylar Mahallesi, Manyas, Balıkesir"}, {"title": "Kızık Yaylası", "summary": "Manyas''ın yüksek kesimlerinde yer alan Kızık Yaylası, serin havası ve çam ormanlarıyla doğaseverlerin uğrak noktasıdır. Yayla evlerinde konaklama imkanı da mevcuttur.", "place_query": "Kızık Yaylası, Manyas, Balıkesir"}, {"title": "Dedeler Köyü Şelalesi", "summary": "Manyas''a bağlı Dedeler Köyü''nde bulunan bu şelale, özellikle bahar aylarında coşkulu akışıyla görsel bir şölen sunar. Çevresi piknik ve fotoğrafçılık için uygundur.", "place_query": "Dedeler Köyü Şelalesi, Manyas, Balıkesir"}, {"title": "Manyas Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan Manyas Müzesi, bölgenin arkeolojik ve etnografik eserlerini sergiler. Özellikle Roma dönemine ait buluntular ilgi çekicidir.", "place_query": "Manyas Müzesi, Manyas, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '85df231d-9351-457f-968e-d279fce52bc1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Marmara Adası", "summary": "Marmara ilçesinin ana karası olan ada, mermer ocakları ve doğal güzellikleriyle ünlüdür. Ziyaretçiler adanın tarihi köylerini keşfedebilir, tertemiz koylarında yüzebilir ve yöresel lezzetlerin tadını çıkarabilir.", "place_query": "Marmara Adası, Balıkesir"}, {"title": "Marmara Adası Mermer Ocakları", "summary": "Antik çağlardan beri işletilen bu ocaklar, beyaz mermerleriyle ünlüdür ve adanın ekonomisinin temelini oluşturur. Tarihi mermer çıkarma alanlarını görmek ve adanın kültürel mirasını yakından tanımak mümkündür.", "place_query": "Marmara Adası Mermer Ocakları, Balıkesir"}, {"title": "Saraylar Mahallesi (Mermer Köyü)", "summary": "Marmara Adası''nın en büyük yerleşimlerinden biri olan Saraylar, mermer işçiliğiyle ünlüdür. Köydeki tarihi mermer evler ve atölyeler, ziyaretçilere adanın kültürel dokusunu yansıtır.", "place_query": "Saraylar Mahallesi, Marmara, Balıkesir"}, {"title": "Asmalı Köyü", "summary": "Marmara Adası''nın şirin köylerinden biri olan Asmalı, sakin atmosferi ve zeytinlikleriyle bilinir. Köyde yürüyüş yapabilir, doğal güzelliklerin tadını çıkarabilir ve yöresel ürünler satın alabilirsiniz.", "place_query": "Asmalı Köyü, Marmara, Balıkesir"}, {"title": "Marmara Adası Koyları (Gündoğdu, Çınarlı, Aba)", "summary": "Marmara Adası''nın berrak denize sahip koyları, doğa ile iç içe bir yüzme deneyimi sunar. Gündoğdu, Çınarlı ve Aba koyları, sakinlik arayanlar için ideal noktalardır.", "place_query": "Marmara Adası Koyları, Balıkesir"}, {"title": "Marmara Adası Doğa Yürüyüşü Rotaları", "summary": "Ada, zeytinlikler ve çam ormanları arasında uzanan yürüyüş parkurlarıyla keşfedilmeye değerdir. Yürüyüş rotaları, adanın en yüksek noktası olan İlyas Dağı''na çıkarak eşsiz manzaralar sunar.", "place_query": "Marmara Adası Yürüyüş Rotaları, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '59859038-8c75-4c2a-935f-178c0651a262'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Savaştepe Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi cami, Osmanlı dönemi mimarisini yansıtan sade ve huzurlu bir yapıdır. Ziyaretçiler, caminin avlusunda dinlenip çevredeki yerel halkla sohbet edebilir.", "place_query": "Savaştepe Merkez Camii, Savaştepe, Balıkesir"}, {"title": "Savaştepe Pazarı", "summary": "Her hafta kurulan ilçe pazarı, yöresel ürünler, taze meyve-sebze ve el işi ürünlerle doludur. Yerel lezzetleri tatmak ve hediyelik eşya almak için ideal bir duraktır.", "place_query": "Savaştepe Pazarı, Savaştepe, Balıkesir"}, {"title": "Kocaçay Deresi", "summary": "İlçeden geçen bu dere, doğal güzelliği ve çevresindeki yeşil alanlarla piknik yapmak isteyenler için popüler bir mekandır. Sakin atmosferi sayesinde doğayla baş başa vakit geçirebilirsiniz.", "place_query": "Kocaçay Deresi, Savaştepe, Balıkesir"}, {"title": "Savaştepe Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu küçük şelale, özellikle bahar aylarında akan sularıyla serinletici bir manzara sunar. Çevresi yürüyüş ve fotoğraf çekimi için uygundur.", "place_query": "Savaştepe Şelalesi, Savaştepe, Balıkesir"}, {"title": "Sarıbeyler Köyü Tarihi Evleri", "summary": "Savaştepe''ye bağlı Sarıbeyler köyünde bulunan geleneksel Osmanlı evleri, taş ve ahşap işçiliğiyle dikkat çeker. Köy atmosferi, tarihi dokuya ilgi duyanlar için keşfedilmeye değerdir.", "place_query": "Saribeyler Köyü Tarihi Evleri, Savaştepe, Balıkesir"}, {"title": "Savaştepe Yaylası", "summary": "İlçenin yüksek kesimlerinde yer alan bu yayla, temiz havası ve geniş otlaklarıyla doğa severler için huzurlu bir kaçış noktasıdır. Yaz aylarında serinlemek ve kamp yapmak için tercih edilir.", "place_query": "Savaştepe Yaylası, Savaştepe, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '551aac4d-190d-4d4c-83ef-4c4c35047405'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sındırgı Yağcıbedir Halıları ve El Sanatları Merkezi", "summary": "Sındırgı denince akla ilk gelen, dünyaca ünlü Yağcıbedir halılarının dokunduğu bu merkezdir. Geleneksel el dokuması halıların üretim sürecini yerinde görebilir, yöresel kültürü yakından tanıyabilirsiniz.", "place_query": "Sındırgı Yağcıbedir Halıları El Sanatları Merkezi, Sındırgı, Balıkesir"}, {"title": "Hisaralan Kaplıcaları", "summary": "Termal turizmin önemli noktalarından biri olan Hisaralan Kaplıcaları, şifalı suları ve doğal güzelliğiyle ziyaretçilerine huzurlu bir kaçış sunar. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan sıcak su kaynaklarıyla ünlüdür.", "place_query": "Hisaralan Kaplıcaları, Sındırgı, Balıkesir"}, {"title": "Kocakaya Şelalesi", "summary": "Yemyeşil bir doğa içinde yer alan Kocakaya Şelalesi, serin suları ve piknik alanlarıyla hafta sonu kaçamaklarının favorisidir. Şelalenin çevresindeki yürüyüş parkurları doğaseverler için idealdir.", "place_query": "Kocakaya Şelalesi, Sındırgı, Balıkesir"}, {"title": "Sındırgı Ulu Camii", "summary": "Tarihi dokusuyla dikkat çeken Sındırgı Ulu Camii, Osmanlı dönemi mimarisinin güzel örneklerinden biridir. İlçe merkezinde yer alan cami, hem ibadet hem de tarihi keşif amaçlı ziyaret edilir.", "place_query": "Sındırgı Ulu Camii, Sındırgı, Balıkesir"}, {"title": "Küçükyenice Köyü Kaya Mezarları", "summary": "Antik dönemden kalma kaya mezarları, bölgenin tarihi geçmişine ışık tutan önemli kalıntılardır. Doğa ile iç içe bu arkeolojik alan, tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Küçükyenice Köyü Kaya Mezarları, Sındırgı, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '14f52119-042e-480b-9a8f-2c69e624a5c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Susurluk Şelalesi", "summary": "Susurluk ilçe merkezine yaklaşık 15 km uzaklıkta bulunan bu şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır. Çevresindeki piknik alanları ve yeşil doğasıyla huzurlu bir kaçış sunar.", "place_query": "Susurluk Şelalesi, Susurluk, Balıkesir"}, {"title": "Sultançayırı Tabiat Parkı", "summary": "Susurluk''un Göbel bölgesinde yer alan bu tabiat parkı, geniş çam ormanları ve temiz havasıyla kampçılar ve doğa yürüyüşçüleri için idealdir. Piknik masaları ve yürüyüş parkurları ile hafta sonu kaçamaklarının vazgeçilmezidir.", "place_query": "Sultançayırı Tabiat Parkı, Susurluk, Balıkesir"}, {"title": "Susurluk Merkez Camii", "summary": "İlçenin simge yapılarından biri olan bu camii, Osmanlı dönemi mimarisinin izlerini taşır. Tarihi dokusu ve merkezi konumuyla hem ibadet hem de kültürel ziyaret için önemli bir noktadır.", "place_query": "Susurluk Merkez Camii, Susurluk, Balıkesir"}, {"title": "Susurluk Çarşısı", "summary": "İlçenin kalbinde yer alan bu çarşı, özellikle meşhur Susurluk tostu ve ayranını tatmak için en doğru adrestir. Aynı zamanda yöresel ürünler ve hediyelik eşyalar bulabileceğiniz hareketli bir alışveriş noktasıdır.", "place_query": "Susurluk Çarşısı, Susurluk, Balıkesir"}, {"title": "Göbel Kaplıcaları", "summary": "Susurluk''un Göbel mahallesinde bulunan bu kaplıcalar, romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan termal sularıyla ünlüdür. Doğal ortamda şifa bulmak isteyenler için sakin bir kaçış noktasıdır.", "place_query": "Göbel Kaplıcaları, Susurluk, Balıkesir"}, {"title": "Susurluk Atatürk Evi Müzesi", "summary": "Atatürk''ün Susurluk ziyareti sırasında konakladığı bu tarihi ev, günümüzde müze olarak hizmet vermektedir. İçerisinde döneme ait eşyalar ve fotoğraflar sergilenerek ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Susurluk Atatürk Evi Müzesi, Susurluk, Balıkesir"}, {"title": "Kocasu Deresi", "summary": "Susurluk''tan geçen bu doğal dere, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için popülerdir. Çevresindeki yeşil alanlar ve kuş sesleri eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Kocasu Deresi, Susurluk, Balıkesir"}, {"title": "Susurluk Köprüsü", "summary": "Tarihi bir Osmanlı köprüsü olan bu yapı, ilçenin simgelerinden biridir. Taş işçiliği ve mimarisiyle fotoğrafçıların ilgisini çekerken, altından akan Kocasu Deresi manzaraya eşlik eder.", "place_query": "Susurluk Köprüsü, Susurluk, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '60ed565b-ee28-4cde-b818-f3a1090a2f10'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Amasra Kalesi", "summary": "Roma, Bizans ve Ceneviz dönemlerinden izler taşıyan bu tarihi kale, Amasra''nın simgesidir. İç avlusu ve surlarından eşsiz deniz manzarası sunar.", "place_query": "Amasra Kalesi, Amasra, Bartın"}, {"title": "Büyük Liman Plajı", "summary": "Amasra''nın en popüler plajı olan Büyük Liman, berrak denizi ve ince kumuyla yüzme ve güneşlenmek için idealdir. Çevresindeki kafelerde dinlenebilirsiniz.", "place_query": "Büyük Liman Plajı, Amasra, Bartın"}, {"title": "Küçük Liman Plajı", "summary": "Amasra''nın merkezinde yer alan bu küçük ve sakin plaj, tarihi dokuyla iç içe deniz keyfi sunar. Özellikle gün batımında manzarası büyüleyicidir.", "place_query": "Küçük Liman Plajı, Amasra, Bartın"}, {"title": "Amasra Müzesi", "summary": "Roma ve Bizans dönemine ait eserlerin sergilendiği küçük ama zengin bir müzedir. Amasra''nın tarihine dair önemli buluntuları yakından görebilirsiniz.", "place_query": "Amasra Müzesi, Amasra, Bartın"}, {"title": "Çekiciler Çarşısı", "summary": "Amasra''nın daracık sokaklarında yer alan bu tarihi çarşı, el yapımı ahşap hediyelik eşyaları ve yöresel ürünleriyle ünlüdür. Alışveriş için mutlaka uğranmalıdır.", "place_query": "Çekiciler Çarşısı, Amasra, Bartın"}, {"title": "Amasra Tarihi Evleri", "summary": "Osmanlı döneminden kalma, ahşap ve taşın iç içe geçtiği bu geleneksel evler, Amasra''nın dar sokaklarında sıralanır. Fotoğrafçılar için harika bir fon oluşturur.", "place_query": "Amasra Tarihi Evleri, Amasra, Bartın"}, {"title": "Boğaz Köprüsü", "summary": "Amasra''yı çevreleyen iki kara parçasını birbirine bağlayan bu tarihi köprü, şehrin sembol yapılarındandır. Üzerinden geçerken liman ve deniz manzarası izlenebilir.", "place_query": "Boğaz Köprüsü, Amasra, Bartın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '74aa66ff-1067-43b0-b0d3-c6da8a9f0ae5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kurucaşile Limanı ve Sahili", "summary": "Karadeniz''in hırçın dalgalarıyla buluşan bu liman, balıkçı tekneleri ve huzurlu atmosferiyle ünlüdür. Sahil şeridinde yürüyüş yapabilir, yöresel balık restoranlarında taze lezzetleri tadabilirsiniz.", "place_query": "Kurucaşile Limanı, Bartın"}, {"title": "Kurucaşile Kalesi", "summary": "Tarihi bir Ceneviz kalesi olan bu yapı, ilçeye tepeden bakar ve muhteşem bir Karadeniz manzarası sunar. Kale kalıntıları arasında dolaşırken bölgenin geçmişine tanıklık edebilirsiniz.", "place_query": "Kurucaşile Kalesi, Bartın"}, {"title": "Güzelcehisar Plajı ve Bazalt Sütunları", "summary": "Kurucaşile''ye yakın bu eşsiz plaj, volkanik oluşumlu bazalt sütunları ile dünyada nadir görülen doğal güzelliklerdendir. Deniz, kum ve jeolojik bir harikayı bir arada keşfedebilirsiniz.", "place_query": "Güzelcehisar Plajı, Bartın"}, {"title": "İnkumu Plajı", "summary": "Bartın''ın en popüler plajlarından biri olan İnkumu, ince kumlu sahili ve dalgasız deniziyle aileler için idealdir. Çevresindeki tesislerde konaklama ve yeme-içme imkanı bulabilirsiniz.", "place_query": "İnkumu Plajı, Bartın"}, {"title": "Bartın Çayı", "summary": "Kurucaşile''den geçerek Karadeniz''e dökülen bu çay, doğa yürüyüşleri ve piknik için huzurlu bir ortam sağlar. Çay kenarında yapacağınız bir gezinti, bölgenin yeşil dokusunu hissettirir.", "place_query": "Bartın Çayı, Kurucaşile, Bartın"}, {"title": "Amasra Antik Kenti ve Kemere Köprüsü", "summary": "Kurucaşile''ye yaklaşık 30 km uzaklıktaki Amasra, Roma ve Bizans döneminden kalma tarihi kalıntılarıyla ünlüdür. Kemere Köprüsü ve Amasra Kalesi, mutlaka görülmesi gereken yapılar arasındadır.", "place_query": "Amasra Antik Kenti, Bartın"}, {"title": "Kurucaşile Yaylaları (Örneğin: Kızılkaya Yaylası)", "summary": "Yeşilin her tonunu barındıran bu yaylalar, serin havası ve doğal güzellikleriyle şehir hayatından kaçış noktasıdır. Yayla evlerinde konaklayarak yöresel kültürü deneyimleyebilirsiniz.", "place_query": "Kızılkaya Yaylası, Kurucaşile, Bartın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '969ebd16-4032-4840-b0f2-022d5641fcc9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bartın Amasra", "summary": "Tarihi ve doğal güzellikleriyle ünlü bir sahil kasabası olan Amasra, Roma, Bizans ve Ceneviz dönemlerinden kalma yapıları, dar sokakları ve muhteşem deniz manzarasıyla ziyaretçilerini büyüler. Amasra Kalesi, Kemere Köprüsü ve Çekiciler Çarşısı en çok gezilen noktalardandır.", "place_query": "Amasra, Bartın"}, {"title": "Amasra Kalesi", "summary": "Roma döneminde inşa edilen ve Cenevizliler tarafından genişletilen bu tarihi kale, iki ayrı bölümden oluşur. Ziyaretçiler, surların üzerinden Amasra''nın eşsiz koy manzarasını izleyebilir ve tarihi atmosferi soluyabilir.", "place_query": "Amasra Kalesi, Bartın"}, {"title": "Güzelcehisar Bazalt Sütunları", "summary": "Bartın merkeze yaklaşık 15 km uzaklıkta bulunan bu doğal oluşum, volkanik lavların soğumasıyla oluşmuş altıgen bazalt sütunlarıyla ünlüdür. Sahil boyunca uzanan bu eşsiz jeolojik yapı, fotoğrafçılar ve doğa severler için harika bir duraktır.", "place_query": "Güzelcehisar Bazalt Sütunları, Bartın"}, {"title": "Bartın Çayı ve Irmağı", "summary": "Şehir merkezinden geçen Bartın Irmağı, doğa yürüyüşleri ve tekne turları için idealdir. Özellikle bahar aylarında yeşilin her tonunu barındıran çevresi, huzurlu bir gün geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Bartın Çayı, Bartın Merkez"}, {"title": "İnkumu Plajı", "summary": "Bartın merkeze 12 km uzaklıktaki bu uzun ve geniş kumsal, Karadeniz''in serin sularında yüzmek için popüler bir noktadır. Çevresindeki tesisler ve kamp alanlarıyla yaz aylarında yoğun ilgi görür.", "place_query": "İnkumu Plajı, Bartın"}, {"title": "Bartın Kent Müzesi", "summary": "Eski bir hükümet konağında hizmet veren bu müze, Bartın''ın tarihini, kültürünü ve el sanatlarını sergileyen zengin bir koleksiyona sahiptir. Şehir merkezinde kolayca ulaşılabilir ve ücretsiz gezilebilir.", "place_query": "Bartın Kent Müzesi, Bartın Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2076d028-448d-4c12-b8f1-6affa374ac27'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"id": 1, "title": "Küre Dağları Milli Parkı", "summary": "Bartın''ın Ulus ilçesi sınırları içinde yer alan bu milli park, eşsiz flora ve faunası, derin kanyonları ve zengin biyoçeşitliliği ile doğa turizminin gözdesidir. Ziyaretçiler, park içinde yürüyüş yapabilir, kamp kurabilir ve eşsiz manzaraların tadını çıkarabilir.", "place_query": "Küre Dağları Milli Parkı, Ulus, Bartın"}, {"id": 2, "title": "Uluyayla (Ulus Yaylası)", "summary": "Ulus ilçesine bağlı bu yayla, yemyeşil doğası, temiz havası ve geleneksel yayla evleriyle ünlüdür. Özellikle yaz aylarında serinlemek ve doğa yürüyüşleri yapmak isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Uluyayla, Ulus, Bartın"}, {"id": 3, "title": "Gezen Yaylası", "summary": "Ulus ilçesinde bulunan Gezen Yaylası, muhteşem manzarası ve huzurlu atmosferiyle dikkat çeker. Yaylada yapılan geleneksel şenlikler ve doğa yürüyüşleri, ziyaretçilere unutulmaz anlar yaşatır.", "place_query": "Gezen Yaylası, Ulus, Bartın"}, {"id": 4, "title": "Kozcağız Köyü Şelalesi", "summary": "Ulus ilçesi Kozcağız köyünde yer alan bu şelale, çevresindeki yeşil örtü ve serin sularıyla doğa severler için popüler bir durak noktasıdır. Özellikle yaz aylarında piknik ve yüzme için tercih edilir.", "place_query": "Kozcağız Köyü Şelalesi, Ulus, Bartın"}, {"id": 5, "title": "Kumluca Köyü Mağarası", "summary": "Ulus ilçesine bağlı Kumluca köyünde bulunan bu mağara, sarkıt ve dikitleriyle ilgi çekici bir doğal oluşumdur. Mağara, hem macera arayanlar hem de doğa fotoğrafçıları için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Kumluca Köyü Mağarası, Ulus, Bartın"}, {"id": 6, "title": "Ulus İlçe Merkezi Tarihi Evler", "summary": "Ulus ilçe merkezinde bulunan geleneksel ahşap ve taş yapılı tarihi evler, bölgenin kültürel mirasını yansıtır. Bu evler, mimari detayları ve geçmişe yolculuk hissiyle ziyaretçilerin ilgisini çeker.", "place_query": "Ulus Tarihi Evler, Ulus, Bartın"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cc630943-c996-4b18-a586-9c02d7f32966'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beşiri Kalesi", "summary": "Tarihi bir kale olup bölgenin hakim tepelerinden birinde yer alır. Çevresindeki doğal manzara ve tarihi dokusuyla ziyaretçilere keyifli bir gezi imkanı sunar.", "place_query": "Beşiri Kalesi, Beşiri, Batman"}, {"title": "Ilısu Barajı ve HES", "summary": "Büyük bir baraj gölü ve hidroelektrik santrali olup çevresindeki doğal güzelliklerle dikkat çeker. Bölgede piknik ve doğa yürüyüşü için popüler bir noktadır.", "place_query": "Ilısu Barajı, Beşiri, Batman"}, {"title": "Dicle Nehri Kıyıları", "summary": "Beşiri ilçesinden geçen Dicle Nehri''nin kıyıları, doğal yürüyüş ve dinlenme alanları sunar. Nehir kenarında huzurlu vakit geçirmek isteyenler için idealdir.", "place_query": "Dicle Nehri, Beşiri, Batman"}, {"title": "Beşiri Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi bir camidir. Mimari yapısı ve manevi atmosferiyle ziyaretçilerin ilgisini çeker.", "place_query": "Beşiri Merkez Camii, Beşiri, Batman"}, {"title": "Hasankeyf Antik Kenti (Yakın Çevre)", "summary": "Beşiri''ye yaklaşık 30 km uzaklıkta bulunan Hasankeyf, binlerce yıllık tarihi mağaraları, kalesi ve kültürel mirasıyla ünlüdür. Bölgeye gelenlerin mutlaka görmesi gereken bir yerdir.", "place_query": "Hasankeyf Antik Kenti, Hasankeyf, Batman"}, {"title": "Beşiri Yaylaları", "summary": "İlçe çevresindeki yaylalar, temiz havası ve yeşil doğasıyla özellikle yaz aylarında kaçış noktasıdır. Doğa severler için yürüyüş ve kamp imkanı sunar.", "place_query": "Beşiri Yaylaları, Beşiri, Batman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aa35f54b-e979-4367-900f-1695602150c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hasankeyf", "summary": "Tarihi ve doğal güzellikleriyle ünlü, Dicle Nehri kıyısında yer alan antik bir yerleşim. Mağaraları, kalesi ve El-Rızk Camii ile ziyaretçilere eşsiz bir tarih yolculuğu sunuyor.", "place_query": "Hasankeyf, Batman"}, {"title": "Gercüş Kalesi", "summary": "İlçe merkezine hakim bir tepede bulunan tarihi kale, bölgenin savunma yapılarından biri olarak biliniyor. Kaleye çıktığınızda Gercüş ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "Gercüş Kalesi, Gercüş, Batman"}, {"title": "Dicle Nehri Kenarı (Gercüş)", "summary": "Gercüş sınırları içinden geçen Dicle Nehri''nin kıyıları, piknik ve doğa yürüyüşü için ideal alanlar sunuyor. Özellikle bahar aylarında yeşilin ve suyun birleştiği huzurlu bir kaçış noktasıdır.", "place_query": "Dicle Nehri, Gercüş, Batman"}, {"title": "Zerzevan Kalesi", "summary": "Gercüş''e yaklaşık 30 km mesafedeki bu antik kale, Roma dönemine ait önemli bir askeri yerleşimdir. Mithras Tapınağı ve yer altı yapılarıyla tarih meraklıları için büyüleyici bir durak.", "place_query": "Zerzevan Kalesi, Çınar, Diyarbakır"}, {"title": "Gercüş Ulu Camii", "summary": "İlçe merkezinde bulunan tarihi cami, mimarisi ve manevi atmosferiyle dikkat çekiyor. Bölgenin dini ve kültürel mirasını yansıtan önemli bir yapıdır.", "place_query": "Gercüş Ulu Camii, Gercüş, Batman"}, {"title": "Kefr-i Züleyha Mağarası", "summary": "Hasankeyf yakınlarında bulunan bu mağara, efsanelere konu olmuş doğal bir oluşumdur. Tarih öncesi dönemlerden beri yerleşim gören mağara, gizemli atmosferiyle keşfedilmeyi bekliyor.", "place_query": "Kefr-i Züleyha Mağarası, Hasankeyf, Batman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '142c8c01-c4f1-44c9-b7b7-4b71c478e327'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hasankeyf Ören Yeri", "summary": "Dicle Nehri kıyısında binlerce yıllık tarihe ev sahipliği yapan bu antik yerleşim, mağaraları, kalıntıları ve eşsiz manzarasıyla ziyaretçilerini büyüler. Tarih öncesi dönemlerden günümüze kadar birçok medeniyete tanıklık etmiş bu açık hava müzesinde, kayalara oyulmuş yaşam alanlarını ve tarihi yapıları keşfedebilirsiniz.", "place_query": "Hasankeyf Ören Yeri, Hasankeyf, Batman"}, {"title": "Hasankeyf Kalesi", "summary": "Dicle Nehri''ne hâkim bir tepe üzerinde yer alan bu tarihi kale, bölgenin en önemli savunma yapılarından biridir. Kaleye çıktığınızda Hasankeyf''in ve nehrin panoramik manzarasını izleyebilir, Artuklu ve Eyyubi dönemlerinden kalma surlar ve burçlar arasında tarihe yolculuk yapabilirsiniz.", "place_query": "Hasankeyf Kalesi, Hasankeyf, Batman"}, {"title": "El-Rızk Camii (Ulu Cami)", "summary": "Hasankeyf''in en önemli İslami yapılarından biri olan bu cami, 15. yüzyılda inşa edilmiş olup zarif taş işçiliği ve mimarisiyle dikkat çeker. Minaresi ve kubbesiyle şehrin siluetinde öne çıkan cami, tarihi dokuyu hissetmek için mutlaka görülmelidir.", "place_query": "El-Rızk Camii, Hasankeyf, Batman"}, {"title": "Zeynel Bey Türbesi", "summary": "Akkoyunlu hükümdarı Uzun Hasan''ın oğlu Zeynel Bey adına yaptırılan bu türbe, turkuaz çinileri ve silindirik yapısıyla Anadolu''daki benzerlerinden ayrılır. Ilısu Barajı nedeniyle taşınan bu anıtsal yapı, yeni yerinde ziyaretçilerini beklemektedir.", "place_query": "Zeynel Bey Türbesi, Hasankeyf, Batman"}, {"title": "Hasankeyf Mağaraları", "summary": "Binlerce yıl önce kayalara oyulmuş bu mağaralar, insanlık tarihinin en eski yerleşim izlerini taşır. Mağaraların içindeki yaşam alanları, kiliseler ve su sarnıçları, bölgenin zengin geçmişine ışık tutar.", "place_query": "Hasankeyf Mağaraları, Hasankeyf, Batman"}, {"title": "Dicle Nehri Kıyısı ve Tekne Turları", "summary": "Dicle Nehri''nin serin sularında yapılan tekne turları, Hasankeyf''i farklı bir perspektiften görmenizi sağlar. Nehir kıyısında yürüyüş yapabilir, tarihi kalıntıları ve mağaraları suyun üzerinden izleyebilirsiniz.", "place_query": "Dicle Nehri, Hasankeyf, Batman"}, {"title": "Köprü Kalıntıları (Roma Köprüsü)", "summary": "Dicle Nehri üzerinde bulunan bu tarihi köprü kalıntıları, Roma döneminden günümüze ulaşan önemli bir yapıdır. Günümüzde sadece ayakları kalan köprü, Hasankeyf''in stratejik önemini ve geçmişteki ulaşım ağını gözler önüne serer.", "place_query": "Roma Köprüsü Kalıntıları, Hasankeyf, Batman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0cf7a461-af5c-4090-92f0-e780a45ea65a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Malabadi Köprüsü", "summary": "Ortaçağ''dan kalma bu görkemli taş köprü, dünyanın en geniş taş kemerli köprülerinden biridir. Batman Çayı üzerinde yükselen yapı, hem tarihi dokusu hem de eşsiz manzarasıyla ziyaretçileri büyüler.", "place_query": "Malabadi Köprüsü, Kozluk, Batman"}, {"title": "Hasankeyf Antik Kenti", "summary": "Tarih öncesi çağlardan günümüze kadar birçok medeniyete ev sahipliği yapmış bu antik kent, mağaraları, kalıntıları ve Dicle Nehri manzarasıyla büyüleyici bir açık hava müzesidir. Ilısu Barajı suları altında kalan bölümleriyle de dikkat çeker.", "place_query": "Hasankeyf Antik Kenti, Batman"}, {"title": "Kozluk Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Sade ve huzur veren atmosferiyle hem ibadet hem de ziyaret amaçlı uğranabilecek bir duraktır.", "place_query": "Kozluk Merkez Camii, Kozluk, Batman"}, {"title": "Kozluk Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale, ilçeye hakim bir manzara sunar. Çevresindeki doğal yapı ve kalıntılar, tarih meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Kozluk Kalesi, Kozluk, Batman"}, {"title": "Dicle Nehri Kenarı (Kozluk Bölgesi)", "summary": "Dicle Nehri''nin Kozluk sınırlarından geçen bölümü, doğa yürüyüşleri ve piknik için idealdir. Sakin akan suyu ve yeşil çevresi, şehir hayatından kaçış arayanlara huzurlu bir ortam vadediyor.", "place_query": "Dicle Nehri, Kozluk, Batman"}, {"title": "Kozluk Çayı Mesire Alanı", "summary": "İlçe merkezine yakın bu mesire alanı, aileler ve arkadaş grupları için popüler bir piknik ve dinlenme noktasıdır. Çay kenarında yürüyüş yapabilir, doğayla iç içe vakit geçirebilirsiniz.", "place_query": "Kozluk Çayı Mesire Alanı, Kozluk, Batman"}, {"title": "Kozluk Müzesi (Küçük Sergi Alanı)", "summary": "İlçenin kültürel mirasını yansıtan küçük bir müze veya sergi alanıdır. Yöresel eşyalar ve tarihi objelerle bölgenin geçmişine dair fikir edinebilirsiniz.", "place_query": "Kozluk Müzesi, Kozluk, Batman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dcfaf8fa-1c9a-4e4d-b425-70d140ebe546'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hasankeyf", "summary": "Binlerce yıllık tarihiyle ünlü bu antik yerleşim, mağaraları, kalıntıları ve Dicle Nehri manzarasıyla ziyaretçilerini büyüler. Tarih boyunca birçok medeniyete ev sahipliği yapmış eşsiz bir açık hava müzesidir.", "place_query": "Hasankeyf Ören Yeri, Hasankeyf, Batman"}, {"title": "İluh Deresi ve Mesire Alanı", "summary": "Şehir merkezine yakın bu yeşil alan, piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir. Dere kenarında yürüyüş yapabilir, huzurlu atmosferin tadını çıkarabilirsiniz.", "place_query": "İluh Deresi Mesire Alanı, Batman Merkez"}, {"title": "Batman Müzesi", "summary": "Bölgenin arkeolojik ve etnografik zenginliklerini sergileyen müze, Hasankeyf ve çevresinden çıkarılan eserlerle tarihe ışık tutar. Özellikle antik dönemlere ilgi duyanlar için kaçırılmaması gereken bir duraktır.", "place_query": "Batman Müzesi, Merkez, Batman"}, {"title": "Güneykent (Tilmerç) Tepesi", "summary": "Şehre hakim bir tepede yer alan bu nokta, Batman''ın panoramik manzarasını izlemek için en güzel yerlerden biridir. Gün batımında eşsiz bir seyir keyfi sunar.", "place_query": "Güneykent Tepesi, Batman Merkez"}, {"title": "Malabadi Köprüsü", "summary": "Dünyanın en büyük taş kemer köprülerinden biri olan bu yapı, 12. yüzyıldan kalma bir Artuklu mirasıdır. Batman Çayı üzerindeki görkemiyle hem tarih hem de fotoğraf tutkunlarını cezbeder.", "place_query": "Malabadi Köprüsü, Batman Merkez"}, {"title": "Petrolkent Parkı", "summary": "Şehir merkezinde geniş yeşil alanı, yürüyüş yolları ve çocuk oyun alanlarıyla ailelerin uğrak noktasıdır. Dinlenmek ve kısa bir doğa molası vermek için idealdir.", "place_query": "Petrolkent Parkı, Batman Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a74db1c8-5bdb-408f-95fc-490657a6f15b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sason Şelalesi", "summary": "Sason ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu şelale, bölgenin en popüler doğal güzelliklerinden biridir. Çevresi piknik alanları ve yürüyüş parkurlarıyla çevrili olup, özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Sason Şelalesi, Sason, Batman"}, {"title": "Eryemez Dağı", "summary": "Sason ilçesinin kuzeyinde yer alan Eryemez Dağı, doğa yürüyüşü ve kampçılık için ideal bir noktadır. Eşsiz manzaraları ve zengin bitki örtüsüyle doğaseverlerin ilgisini çeker.", "place_query": "Eryemez Dağı, Sason, Batman"}, {"title": "Sason Kalesi", "summary": "Tarihi bir kale olan Sason Kalesi, ilçe merkezine hakim bir tepe üzerinde yer alır. Bölgenin tarihine tanıklık eden kale, ziyaretçilere hem tarihi bir yolculuk hem de panoramik bir manzara sunar.", "place_query": "Sason Kalesi, Sason, Batman"}, {"title": "Abdalan Köyü Mağaraları", "summary": "Sason''a bağlı Abdalan Köyü''nde bulunan bu mağaralar, doğal oluşumları ve tarihi kalıntılarıyla dikkat çeker. Mağara turizmi ve keşif gezileri için uygun bir destinasyondur.", "place_query": "Abdalan Köyü Mağaraları, Sason, Batman"}, {"title": "Sason Yaylaları (Kaniya Şeyh Yaylası vb.)", "summary": "Sason çevresindeki yaylalar, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için idealdir. Kaniya Şeyh Yaylası, yeşil doğası ve temiz havasıyla öne çıkan popüler bir yayladır.", "place_query": "Kaniya Şeyh Yaylası, Sason, Batman"}, {"title": "Sason İlçe Merkezi Tarihi Camiler", "summary": "Sason ilçe merkezinde bulunan tarihi camiler, bölgenin kültürel ve dini mirasını yansıtır. Özellikle eski mimari yapılarıyla dikkat çeken bu camiler, tarih meraklıları için önemli bir duraktır.", "place_query": "Sason Merkez Camii, Sason, Batman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4cd19b6f-59fc-4801-bec0-6981999b4c47'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aydıntepe Yeraltı Şehri", "summary": "Tarihi ve mistik atmosferiyle ünlü bu yeraltı şehri, kayalar oyularak oluşturulmuş odaları ve galerileriyle ziyaretçilerini büyüler. Bölgenin en önemli arkeolojik miraslarından biridir.", "place_query": "Aydıntepe Yeraltı Şehri, Aydıntepe, Bayburt"}, {"title": "Çoruh Nehri Kenarı", "summary": "Doğal güzelliği ve serin sularıyla ünlü Çoruh Nehri, özellikle yaz aylarında piknik ve doğa yürüyüşleri için ideal bir mekandır. Nehir kenarındaki yemyeşil alanlar huzur verir.", "place_query": "Çoruh Nehri, Aydıntepe, Bayburt"}, {"title": "Sırakayalar Köprüsü", "summary": "Tarihi taş köprü, Osmanlı dönemi mimarisini yansıtan zarif yapısıyla dikkat çeker. Çevresindeki doğal manzara ile fotoğrafçılar için popüler bir duraktır.", "place_query": "Sırakayalar Köprüsü, Aydıntepe, Bayburt"}, {"title": "Aydıntepe Kalesi", "summary": "Tepede konumlanan bu tarihi kale, bölgeye hakim manzarasıyla göz doldurur. Kalıntıları arasında yürüyüş yaparken geçmişe yolculuk hissedersiniz.", "place_query": "Aydıntepe Kalesi, Aydıntepe, Bayburt"}, {"title": "Gümüşhane-Bayburt Yolu Üzerindeki Mesire Alanları", "summary": "Yol güzergahında yer alan bu mesire alanları, yeşil doğası ve temiz havasıyla dinlenmek isteyenler için idealdir. Özellikle hafta sonu kaçamaklarında tercih edilir.", "place_query": "Aydıntepe mesire alanları, Bayburt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fa00b896-74e4-42df-9907-05ed889b3a7a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çoruh Nehri Kenarı", "summary": "Doğal güzelliği ve serin sularıyla ünlü olan Çoruh Nehri kıyısı, piknik ve doğa yürüyüşleri için idealdir.", "place_query": "Çoruh Nehri, Demirözü, Bayburt"}, {"title": "Demirözü Barajı", "summary": "Bölgenin en önemli su kaynaklarından biri olan baraj, çevresindeki yeşil alanlar ve manzarasıyla ziyaretçilere huzurlu bir ortam sunar.", "place_query": "Demirözü Barajı, Bayburt"}, {"title": "Aydıntepe Yeraltı Şehri", "summary": "Demirözü''ne yakın konumdaki bu tarihi yeraltı şehri, erken Hristiyanlık dönemine ait kalıntıları ve gizemli atmosferiyle dikkat çeker.", "place_query": "Aydıntepe Yeraltı Şehri, Bayburt"}, {"title": "Sırakayalar Şelalesi", "summary": "Doğa tutkunlarının uğrak noktası olan bu şelale, yemyeşil doğası ve çağlayan sularıyla fotoğrafçılar için harika bir mekandır.", "place_query": "Sırakayalar Şelalesi, Bayburt"}, {"title": "Demirözü Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisini yansıtan sade ve etkileyici yapısıyla ziyaret edilebilir.", "place_query": "Demirözü Merkez Camii, Bayburt"}, {"title": "Kop Dağı Geçidi", "summary": "Doğal güzellikleri ve yüksek rakımlı manzarasıyla ünlü bu geçit, özellikle yaz aylarında doğa yürüyüşleri ve kamp için tercih edilir.", "place_query": "Kop Dağı Geçidi, Bayburt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b76150dd-6637-4236-bd26-5817a290e6b4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bayburt Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, Bayburt''un simgesidir. Roma dönemine kadar uzanan geçmişi ve muhteşem manzarası ile ziyaretçilerini büyüler.", "place_query": "Bayburt Kalesi, Bayburt Merkez"}, {"title": "Kenan Yavuz Etnografya Müzesi (Eski Bayburt Cezaevi)", "summary": "Restore edilmiş tarihi bir cezaevi binasında hizmet veren müze, yöresel kıyafetler, el sanatları ve günlük yaşam objeleriyle Bayburt kültürünü sergiliyor.", "place_query": "Kenan Yavuz Etnografya Müzesi, Bayburt"}, {"title": "Dede Korkut Türbesi", "summary": "Türk kültürünün önemli figürlerinden Dede Korkut''a ait olduğuna inanılan türbe, şehir merkezinde yer alır ve manevi bir atmosfere sahiptir.", "place_query": "Dede Korkut Türbesi, Bayburt"}, {"title": "Sırakayalar Şelalesi", "summary": "Bayburt''a yaklaşık 30 km uzaklıkta bulunan bu doğal güzellik, yemyeşil bir vadi içinde kademeli olarak akan şelaleleriyle doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Sırakayalar Şelalesi, Bayburt"}, {"title": "Bayburt Ulu Camii", "summary": "13. yüzyılda inşa edilen tarihi cami, sade mimarisi ve ahşap işçiliği ile dikkat çeker. Şehrin en eski ve önemli ibadet yapılarından biridir.", "place_query": "Bayburt Ulu Camii, Bayburt Merkez"}, {"title": "Çoruh Nehri Vadisi", "summary": "Bayburt''tan geçerek Artvin''e doğru akan Çoruh Nehri''nin oluşturduğu vadi, rafting ve kano gibi su sporları için elverişli parkurlar sunar. Aynı zamanda eşsiz bir doğa manzarasına sahiptir.", "place_query": "Çoruh Nehri, Bayburt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '140afcb2-f533-473f-b09f-9eef59a756c3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bozüyük Kent Müzesi", "summary": "Bozüyük''ün tarihini, kültürünü ve sanatını keşfedebileceğiniz modern bir müze. Osmanlı''dan Cumhuriyet''e uzanan süreçte ilçenin gelişimini anlatan eserler ve belgeler sergileniyor.", "place_query": "Bozüyük Kent Müzesi, Bozüyük, Bilecik"}, {"title": "Bozüyük Mesire Alanı (Bozüyük Orman Parkı)", "summary": "Şehir merkezine yakın, yeşillikler içinde piknik yapabileceğiniz, yürüyüş yolları bulunan geniş bir mesire alanı. Aile ve arkadaş grupları için huzurlu bir doğa kaçamağı sunuyor.", "place_query": "Bozüyük Mesire Alanı, Bozüyük, Bilecik"}, {"title": "Bozüyük Saat Kulesi", "summary": "Cumhuriyet dönemi mimarisinin güzel bir örneği olan bu tarihi saat kulesi, ilçe merkezinde simge yapılardan biridir. Çevresindeki alan, kısa bir mola vermek ve fotoğraf çekmek için idealdir.", "place_query": "Bozüyük Saat Kulesi, Bozüyük, Bilecik"}, {"title": "Metristepe Şehitliği ve Anıtı", "summary": "Kurtuluş Savaşı''nın önemli dönüm noktalarından biri olan Metristepe''de yer alan bu şehitlik, vatan savunmasında can veren kahramanları anmak için ziyaret ediliyor. Tepeden çevre manzarası da etkileyicidir.", "place_query": "Metristepe Şehitliği, Bozüyük, Bilecik"}, {"title": "Bozüyük Cam ve Kristal Müzesi", "summary": "Türkiye''deki ender tematik müzelerden biri olan bu müze, cam ve kristal işçiliğinin zarif örneklerini sergiliyor. Hem tarihi hem de modern eserlerin yer aldığı koleksiyon, sanatseverler için görülmeye değer.", "place_query": "Bozüyük Cam ve Kristal Müzesi, Bozüyük, Bilecik"}, {"title": "İnönü Mağarası", "summary": "Bozüyük sınırlarına yakın, doğal oluşumlu bu mağara, sarkıt ve dikitleriyle dikkat çekiyor. Mağara içindeki serin atmosfer ve ilginç kaya yapıları, doğa meraklıları için keşif rotası oluşturuyor.", "place_query": "İnönü Mağarası, Bozüyük, Bilecik"}, {"title": "Bozüyük Atatürk Parkı", "summary": "İlçe merkezinde yer alan bu büyük park, yürüyüş yolları, oturma alanları ve çocuk oyun gruplarıyla dinlenmek için popüler bir noktadır. Parkın ortasındaki Atatürk büstü ve çevre düzenlemesi dikkat çeker.", "place_query": "Atatürk Parkı, Bozüyük, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'da6a4faf-fda2-4238-bbf0-782f912264c2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölpazarı Kent Ormanı", "summary": "Şehrin gürültüsünden uzaklaşmak için ideal bir doğa kaçamağıdır. Yürüyüş parkurları ve piknik alanları ile aileler için huzurlu bir ortam sunar.", "place_query": "Gölpazarı Kent Ormanı, Gölpazarı, Bilecik"}, {"title": "Sarı Köşk (Gölpazarı Konağı)", "summary": "Tarihi bir Osmanlı konağı olan yapı, restore edilerek kültür evi haline getirilmiştir. Geleneksel mimariyi ve yöresel yaşamı yakından görmek için ziyaret edilebilir.", "place_query": "Sarı Köşk Gölpazarı, Bilecik"}, {"title": "Gölpazarı Şelalesi", "summary": "Doğal güzelliği ile dikkat çeken şelale, özellikle bahar ve yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için popüler bir noktadır.", "place_query": "Gölpazarı Şelalesi, Bilecik"}, {"title": "Sarıbeyler Göleti", "summary": "Mesire alanı olarak düzenlenmiş gölet, piknik yapmak ve olta balıkçılığı için sıkça tercih edilir. Çevresindeki yeşil alanlar huzurlu bir atmosfer sunar.", "place_query": "Sarıbeyler Göleti, Gölpazarı, Bilecik"}, {"title": "Gölpazarı Merkez Camii", "summary": "İlçe merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Dini ve kültürel bir ziyaret noktasıdır.", "place_query": "Gölpazarı Merkez Camii, Bilecik"}, {"title": "Söğüt Ertuğrul Gazi Türbesi (Gölpazarı yakını)", "summary": "Gölpazarı''na yaklaşık 20 km mesafedeki Söğüt ilçesinde bulunan türbe, Osmanlı Devleti''nin kurucusu Osman Gazi''nin babası Ertuğrul Gazi''ye aittir. Tarihi ve manevi önemi büyüktür.", "place_query": "Ertuğrul Gazi Türbesi, Söğüt, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '076c6903-60ca-48bc-b547-ff5936f32698'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İnhisar Kanyonu", "summary": "Sakarya Nehri kenarında uzanan bu etkileyici kanyon, doğa yürüyüşleri ve fotoğrafçılık için ideal bir noktadır. Dik kayalıkları ve yeşil doğasıyla huzurlu bir atmosfer sunar.", "place_query": "İnhisar Kanyonu, İnhisar, Bilecik"}, {"title": "Sakarya Nehri Kenarı", "summary": "İnhisar''dan geçen Sakarya Nehri boyunca yürüyüş yapabilir, piknik alanlarında vakit geçirebilir ve doğal güzelliğin tadını çıkarabilirsiniz.", "place_query": "Sakarya Nehri, İnhisar, Bilecik"}, {"title": "İnhisar Merkez Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olup, ilçenin merkezinde yer alır ve mimarisiyle dikkat çeker. Ziyaretçiler için manevi bir durak noktasıdır.", "place_query": "İnhisar Merkez Camii, İnhisar, Bilecik"}, {"title": "İnhisar Kalesi Kalıntıları", "summary": "Tarihi bir kaleden günümüze ulaşan kalıntılar, bölgenin geçmişine ışık tutar. Tepe üzerindeki konumu sayesinde çevreye hakim bir manzara sunar.", "place_query": "İnhisar Kalesi, İnhisar, Bilecik"}, {"title": "Küçükelmalı Köyü Şelalesi", "summary": "İnhisar''a bağlı Küçükelmalı Köyü''nde bulunan bu şelale, doğa severler için serinletici bir kaçış noktasıdır. Çevresindeki yeşil alanlar piknik için uygundur.", "place_query": "Küçükelmalı Köyü Şelalesi, İnhisar, Bilecik"}, {"title": "İnhisar Yaylası", "summary": "İlçenin yüksek kesimlerinde yer alan yayla, temiz havası ve geniş otlaklarıyla kampçılık ve doğa yürüyüşü için popüler bir destinasyondur.", "place_query": "İnhisar Yaylası, İnhisar, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5c564295-0db8-48bd-ac68-429953fcf43b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şeyh Edebali Türbesi", "summary": "Osmanlı Devleti''nin kuruluş felsefesine yön veren büyük alim Şeyh Edebali''nin türbesi, manevi atmosferi ve tarihi önemiyle Bilecik''in en çok ziyaret edilen noktasıdır. Türbe ve çevresindeki külliyeyi gezebilir, Osmanlı''nın temellerinin atıldığı bu kutsal topraklarda huzur bulabilirsiniz.", "place_query": "Şeyh Edebali Türbesi, Bilecik Merkez"}, {"title": "Bilecik Saat Kulesi", "summary": "1907 yılında II. Abdülhamid döneminde inşa edilen bu tarihi saat kulesi, şehrin simge yapılarından biridir. Şehrin merkezinde yer alan kule, çevresindeki tarihi evler ve çınar ağaçlarıyla güzel bir fotoğraf karesi sunar.", "place_query": "Bilecik Saat Kulesi, Merkez, Bilecik"}, {"title": "Pelitözü Göleti ve Mesire Alanı", "summary": "Şehir merkezine oldukça yakın olan bu yapay gölet, piknik yapmak, yürüyüş yapmak ve doğayla iç içe vakit geçirmek için idealdir. Gölet çevresindeki kafelerde dinlenebilir ve su sporları yapabilirsiniz.", "place_query": "Pelitözü Göleti, Bilecik Merkez"}, {"title": "Bilecik Müzesi", "summary": "Bilecik ve çevresindeki arkeolojik kazılarda ortaya çıkarılan eserlerin sergilendiği müze, bölgenin tarih öncesi dönemlerinden Osmanlı''ya uzanan zengin geçmişini gözler önüne seriyor. Hitit, Frig, Roma ve Bizans dönemlerine ait eserleri görebilirsiniz.", "place_query": "Bilecik Müzesi, Merkez, Bilecik"}, {"title": "Küçük Elmalı Tabiat Parkı", "summary": "Bilecik''e yaklaşık 15 km uzaklıkta bulunan bu tabiat parkı, zengin bitki örtüsü ve temiz havasıyla doğa severler için harika bir kaçış noktasıdır. İçerisinde yürüyüş parkurları, piknik alanları ve seyir terasları bulunur.", "place_query": "Küçük Elmalı Tabiat Parkı, Bilecik"}, {"title": "Söğüt Ertuğrul Gazi Türbesi", "summary": "Bilecik Merkez''e bağlı olmasa da hemen yanıbaşındaki Söğüt ilçesinde bulunan bu türbe, Osmanlı Devleti''nin kurucusu Osman Gazi''nin babası Ertuğrul Gazi''ye aittir. Tarihi önemi ve manevi atmosferiyle bölgenin en önemli ziyaret noktalarından biridir.", "place_query": "Ertuğrul Gazi Türbesi, Söğüt, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aa4fbdaa-f987-473c-a97b-0f9ef9c0706f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Osmaneli Evleri", "summary": "Tarihi Osmanlı ve Rum mimarisinin izlerini taşıyan bu restorasyon görmüş evler, ilçenin en karakteristik simgesidir. Arnavut kaldırımlı sokaklarında yürüyerek geçmişe yolculuk yapabilirsiniz.", "place_query": "Osmaneli Evleri, Bilecik"}, {"title": "Osmaneli Şelalesi", "summary": "Sakarya Nehri kıyısına yakın bu doğal şelale, piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle yaz aylarında serinlemek için sıkça ziyaret edilir.", "place_query": "Osmaneli Şelalesi, Bilecik"}, {"title": "Ayvaz Dede Türbesi", "summary": "Osmaneli''nin manevi değerlerinden biri olan bu türbe, hem yerli halk hem de ziyaretçiler tarafından saygıyla anılır. Tarihi ve mistik atmosferiyle dikkat çeker.", "place_query": "Ayvaz Dede Türbesi, Osmaneli, Bilecik"}, {"title": "Sakarya Nehri Kenarı", "summary": "İlçenin ortasından geçen Sakarya Nehri boyunca uzanan yürüyüş yolu, huzurlu bir gezinti ve kuş gözlemi yapmak için idealdir. Nehir kenarındaki kafelerde dinlenebilirsiniz.", "place_query": "Sakarya Nehri Osmaneli"}, {"title": "Osmaneli Çarşı Camii", "summary": "Tarihi bir Osmanlı eseri olan bu cami, ilçe merkezinde yer alır ve mimari detaylarıyla ilgi çeker. Çarşı merkezinde olduğu için ulaşımı kolaydır.", "place_query": "Osmaneli Çarşı Camii, Bilecik"}, {"title": "Günüören Göleti", "summary": "Osmaneli''ne bağlı Günüören köyünde bulunan bu gölet, doğal güzelliği ve sakin ortamıyla kampçılık ve piknik için tercih edilir. Çevresi yemyeşil ormanlarla kaplıdır.", "place_query": "Günüören Göleti, Osmaneli, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7e5ef824-0f1d-4d17-8fde-90a621d0c5c9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pazaryeri Saat Kulesi", "summary": "İlçe merkezinde yer alan bu tarihi saat kulesi, Pazaryeri''nin sembol yapılarından biridir. Çevresindeki kafe ve restoranlarla birlikte keyifli bir gezinti noktası sunar.", "place_query": "Pazaryeri Saat Kulesi, Bilecik"}, {"title": "Hamidiye Camii", "summary": "II. Abdülhamid döneminde yapılan bu tarihi cami, zarif mimarisi ve huzurlu atmosferiyle ziyaretçilerini etkiler. İlçenin en önemli dini yapılarından biridir.", "place_query": "Hamidiye Camii, Pazaryeri, Bilecik"}, {"title": "Pazaryeri Çarşı Merkezi", "summary": "İlçenin kalbi sayılan bu bölge, geleneksel dükkanları ve yöresel ürünleri ile ünlüdür. Özellikle Pazaryeri''nin meşhur pekmez ve tarhanasını buradan temin edebilirsiniz.", "place_query": "Pazaryeri Çarşısı, Bilecik"}, {"title": "Pazaryeri Mesire Alanı", "summary": "Doğayla iç içe vakit geçirmek isteyenler için ideal bir piknik ve dinlenme alanıdır. Yeşillikler arasında huzurlu bir gün geçirebilirsiniz.", "place_query": "Pazaryeri Mesire Alanı, Bilecik"}, {"title": "Kınık Köyü Kaya Mezarları", "summary": "Pazaryeri ilçe sınırlarındaki bu antik kaya mezarları, tarih meraklıları için ilgi çekici bir duraktır. Frig dönemine ait olduğu düşünülen yapılar, bölgenin tarihi zenginliğini gözler önüne serer.", "place_query": "Kınık Köyü Kaya Mezarları, Pazaryeri, Bilecik"}, {"title": "Sultanpınarı Tabiat Parkı", "summary": "Pazaryeri''ne yakın konumdaki bu tabiat parkı, zengin bitki örtüsü ve yürüyüş parkurlarıyla doğaseverlerin uğrak noktasıdır. Piknik alanları ve temiz havasıyla şehir stresinden uzaklaşmak için idealdir.", "place_query": "Sultanpınarı Tabiat Parkı, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '11e0b5ac-8f8d-4851-a419-5efcce8807cf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ertuğrul Gazi Türbesi", "summary": "Osmanlı Devleti''nin kurucusu Osman Gazi''nin babası Ertuğrul Gazi''nin türbesi olan bu kutsal mekan, Söğüt''ün en önemli tarihi ve manevi merkezidir. Her yıl Eylül ayında düzenlenen Ertuğrul Gazi''yi Anma ve Yörük Şenlikleri''ne ev sahipliği yapar.", "place_query": "Ertuğrul Gazi Türbesi, Söğüt, Bilecik"}, {"title": "Söğüt Ertuğrul Gazi Müzesi", "summary": "Ertuğrul Gazi Türbesi''nin hemen yanında yer alan bu müze, Osmanlı''nın kuruluş dönemine ait silahlar, kıyafetler, el yazmaları ve etnografik eserleri sergilemektedir. Tarihe ilgi duyan ziyaretçiler için kaçırılmaması gereken bir duraktır.", "place_query": "Söğüt Ertuğrul Gazi Müzesi, Söğüt, Bilecik"}, {"title": "Tarihi Söğüt Evleri", "summary": "Osmanlı dönemi sivil mimarisinin güzel örneklerini yansıtan bu tarihi ahşap ve kerpiç evler, Söğüt''ün dar sokaklarında gezinti yaparken görülmeye değerdir. Restore edilmiş bazı evler günümüzde kafe ve butik otel olarak hizmet vermektedir.", "place_query": "Tarihi Söğüt Evleri, Söğüt, Bilecik"}, {"title": "Çelebi Sultan Mehmet Camii", "summary": "Osmanlı Padişahı I. Mehmed (Çelebi Mehmet) tarafından 1414 yılında yaptırılan bu cami, Söğüt''ün en eski ve en önemli ibadet yapılarındandır. Kesme taş ve tuğladan inşa edilen yapı, sade ve etkileyici mimarisiyle dikkat çeker.", "place_query": "Çelebi Sultan Mehmet Camii, Söğüt, Bilecik"}, {"title": "Söğüt Şeyh Edebali Türbesi", "summary": "Osmanlı Devleti''nin kuruluşunda önemli rol oynayan manevi önderlerden Şeyh Edebali''nin türbesi, Söğüt''te ziyaret edilen kutsal mekanlar arasındadır. Tarihi atmosferi ve manevi huzuruyla ziyaretçilerini etkiler.", "place_query": "Şeyh Edebali Türbesi, Söğüt, Bilecik"}, {"title": "Söğüt Hamidiye Kışlası", "summary": "Sultan II. Abdülhamid döneminde inşa edilen bu tarihi kışla, günümüzde Söğüt''ün kültürel etkinliklerine ev sahipliği yapmaktadır. Yapının restore edilmiş hali, Osmanlı askeri mimarisinin güzel bir örneğini sunar.", "place_query": "Söğüt Hamidiye Kışlası, Söğüt, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '60e8418b-2cbf-4a7f-bbea-96efc2816448'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yenipazar Merkez Camii", "summary": "İlçenin merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin sade ve huzur verici bir örneğidir. Ziyaretçiler, ibadet sonrası cami avlusunda dinlenebilir ve çevresindeki çarşıyı keşfedebilir.", "place_query": "Yenipazar Merkez Camii, Bilecik"}, {"title": "Yenipazar Saat Kulesi", "summary": "Cumhuriyet döneminin simgelerinden biri olan bu kule, ilçe meydanında yükselir ve fotoğrafçılar için popüler bir noktadır. Etrafındaki kafelerde oturup kasabanın sakin atmosferini soluyabilirsiniz.", "place_query": "Yenipazar Saat Kulesi, Bilecik"}, {"title": "Bilecik Şeyh Edebali Türbesi", "summary": "Osmanlı Devleti''nin kuruluşunda manevi bir rehber olan Şeyh Edebali''nin türbesi, ilçeye yaklaşık 30 km mesafede bulunur. Tarihi ve manevi atmosferiyle ziyaretçilerin uğrak noktasıdır.", "place_query": "Şeyh Edebali Türbesi, Bilecik"}, {"title": "Küre Dağları Milli Parkı", "summary": "Yenipazar sınırları içinde kalan bu milli park, zengin bitki örtüsü ve yaban hayatıyla doğa yürüyüşü sevenler için idealdir. Kamp yapmak ve temiz hava almak için bölgenin en güzel alanlarından biridir.", "place_query": "Küre Dağları Milli Parkı, Yenipazar, Bilecik"}, {"title": "Yenipazar Kalesi", "summary": "Tarihi bir Bizans kalesi olan bu yapı, ilçeye hakim bir tepede konumlanmıştır. Kalıntılar arasında yürürken hem tarihe tanıklık eder hem de panoramik Yenipazar manzarası izleyebilirsiniz.", "place_query": "Yenipazar Kalesi, Bilecik"}, {"title": "Söğüt Ertuğrul Gazi Müzesi", "summary": "Yenipazar''a yaklaşık 25 km uzaklıktaki Söğüt ilçesinde bulunan bu müze, Osmanlı''nın kuruluş dönemine ait eserleri sergiler. Ertuğrul Gazi''nin hayatı ve Kayı Boyu''nun izleri burada canlanır.", "place_query": "Ertuğrul Gazi Müzesi, Söğüt, Bilecik"}, {"title": "Bilecik Pelitözü Göleti", "summary": "Yenipazar''a 40 km mesafedeki bu yapay gölet, piknik alanları ve yürüyüş yollarıyla aileler için popüler bir kaçış noktasıdır. Gölet çevresinde balık tutabilir veya sadece doğanın tadını çıkarabilirsiniz.", "place_query": "Pelitözü Göleti, Bilecik"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8aa0831a-d714-4f51-bfb4-b9f5f6a39f11'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Adaklı Merkez Camii ve Çevresi", "summary": "İlçe merkezinde yer alan bu cami, yöre halkı için önemli bir ibadet ve buluşma noktasıdır. Çevresindeki küçük dükkanlar ve çay bahçeleri, sakin bir atmosfer sunar.", "place_query": "Adaklı Merkez Camii, Adaklı, Bingöl"}, {"title": "Şeyh Abdullah Dağı", "summary": "Adaklı yakınlarında yükselen bu dağ, doğa yürüyüşleri ve kamp için idealdir. Zirveden ilçe ve çevresinin panoramik manzarası görülebilir.", "place_query": "Şeyh Abdullah Dağı, Adaklı, Bingöl"}, {"title": "Adaklı Yaylaları (Güney Yaylası vb.)", "summary": "İlçenin çevresindeki yaylalar, yemyeşil doğası ve serin havasıyla yaz aylarında ziyaretçileri cezbeder. Yöresel hayvancılık kültürünü yerinde gözlemleyebilirsiniz.", "place_query": "Adaklı Yaylaları, Bingöl"}, {"title": "Kargapazarı Dağı", "summary": "Bingöl''ün en yüksek dağlarından biri olan Kargapazarı, Adaklı sınırlarına yakındır. Dağcılık ve doğa sporları için popüler bir rotadır.", "place_query": "Kargapazarı Dağı, Bingöl"}, {"title": "Adaklı Eski Yerleşim Kalıntıları", "summary": "İlçe çevresinde tarihi dönemlere ait bazı eski yerleşim izleri ve taş yapı kalıntıları bulunur. Tarih meraklıları için keşfedilmeyi bekleyen alanlardır.", "place_query": "Adaklı tarihi kalıntılar, Bingöl"}, {"title": "Peri Suyu (Çayı)", "summary": "Adaklı''dan geçen bu akarsu, çevresindeki doğal bitki örtüsüyle huzurlu bir ortam sunar. Piknik ve olta balıkçılığı için tercih edilen bir noktadır.", "place_query": "Peri Suyu, Adaklı, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e52c94e6-dd39-4bd3-9faf-8cca8b4344c6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Genç Şelalesi", "summary": "İlçe merkezine yaklaşık 20 km uzaklıkta, doğal güzelliğiyle ünlü bir şelaledir. Çevresi piknik alanlarıyla donatılmış olup, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için ideal bir noktadır.", "place_query": "Genç Şelalesi, Genç, Bingöl"}, {"title": "Bingöl Üniversitesi Genç Meslek Yüksekokulu Kampüsü", "summary": "Modern mimarisi ve geniş yeşil alanlarıyla dikkat çeken kampüs, yürüyüş yapmak ve sakin bir ortamda vakit geçirmek isteyenler için popüler bir mekandır.", "place_query": "Bingöl Üniversitesi Genç Meslek Yüksekokulu, Genç, Bingöl"}, {"title": "Genç Kaymakamlığı ve Cumhuriyet Meydanı", "summary": "İlçenin merkezinde yer alan meydan, çevresindeki tarihi yapılar ve kafelerle sosyal hayatın kalbidir. Özellikle akşam saatlerinde yapılan yürüyüşler ve sohbetler için tercih edilir.", "place_query": "Cumhuriyet Meydanı, Genç, Bingöl"}, {"title": "Murat Nehri Kenarı", "summary": "Bingöl''ün önemli akarsularından biri olan Murat Nehri''nin Genç ilçesi sınırları içindeki kıyı şeridi, doğa yürüyüşleri ve balık tutma etkinlikleri için sıkça ziyaret edilmektedir.", "place_query": "Murat Nehri, Genç, Bingöl"}, {"title": "Genç Kalesi", "summary": "Tarihi bir kalıntı olan Genç Kalesi, ilçe merkezine yakın bir tepede yer alır. Bölgenin tarihine ışık tutan bu yapı, aynı zamanda çevresindeki manzarasıyla fotoğrafçılar için cazip bir noktadır.", "place_query": "Genç Kalesi, Genç, Bingöl"}, {"title": "Yedigöller Mevkii", "summary": "Genç ilçesine bağlı bu doğal alan, adını aldığı yedi küçük gölden oluşur. Yemyeşil doğası ve sakin atmosferiyle kampçılık ve doğa turizmi için uygundur.", "place_query": "Yedigöller Mevkii, Genç, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2e4f7e25-d9bc-48f9-a3b0-fb18b983d892'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göynük Çayı ve Mesire Alanı", "summary": "Karlıova''nın doğal güzelliklerinden olan Göynük Çayı çevresi, piknik ve doğa yürüyüşü için idealdir. Bölge, temiz havası ve yeşil doğasıyla ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Göynük Çayı, Karlıova, Bingöl"}, {"title": "Kösedağ", "summary": "Karlıova ilçe merkezine yakın konumdaki Kösedağ, özellikle doğa yürüyüşleri ve manzara seyri için popülerdir. Dağın zirvesinden çevredeki ovaları ve Bingöl Dağları''nı izlemek mümkündür.", "place_query": "Kösedağ, Karlıova, Bingöl"}, {"title": "Karlıova Ovası", "summary": "Geniş ve verimli bir ova olan Karlıova Ovası, özellikle yaz aylarında yeşilin her tonunu görebileceğiniz bir doğa harikasıdır. Bölge, fotoğrafçılar ve doğa severler için eşsiz kareler sunar.", "place_query": "Karlıova Ovası, Bingöl"}, {"title": "Kargapazarı Dağları", "summary": "Karlıova sınırları içinde yer alan Kargapazarı Dağları, dağcılık ve trekking için uygun rotalar barındırır. Bölge, zengin bitki örtüsü ve yaban hayatıyla dikkat çeker.", "place_query": "Kargapazarı Dağları, Karlıova, Bingöl"}, {"title": "Yayla ve Göletler (Yelesen Yaylası vb.)", "summary": "Karlıova çevresindeki yaylalar ve doğal göletler, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir. Yelesen Yaylası, bölgenin en bilinen yaylalarındandır.", "place_query": "Yelesen Yaylası, Karlıova, Bingöl"}, {"title": "Karlıova Şehitlik Anıtı", "summary": "İlçe merkezinde bulunan şehitlik anıtı, bölgenin tarihi ve manevi değerlerini yansıtan önemli bir noktadır. Ziyaretçiler burada saygı duruşunda bulunup çevredeki manzarayı izleyebilir.", "place_query": "Karlıova Şehitlik Anıtı, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '10916747-4759-41f3-a968-e548ca44ea3b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kiğı Kalesi", "summary": "Tarihi bir kaya kütlesi üzerine inşa edilmiş olan bu kale, bölgenin en önemli tarihi yapılarından biridir ve muhteşem bir vadi manzarası sunar.", "place_query": "Kiğı Kalesi, Kiğı, Bingöl"}, {"title": "Yelatan Köprüsü", "summary": "Tarihi bir taş köprü olan Yelatan Köprüsü, bölgenin geçmişine ışık tutan ve fotoğrafçılar için harika bir kare sunan etkileyici bir yapıdır.", "place_query": "Yelatan Köprüsü, Kiğı, Bingöl"}, {"title": "Sülbüs Dağı", "summary": "Bingöl''ün en yüksek zirvelerinden biri olan Sülbüs Dağı, doğa yürüyüşleri ve kampçılık için ideal bir noktadır; ayrıca eşsiz bir flora ve faunaya ev sahipliği yapar.", "place_query": "Sülbüs Dağı, Kiğı, Bingöl"}, {"title": "Kiğı Ulu Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Kiğı Ulu Camii, mimari detayları ve huzurlu atmosferiyle ziyaretçilerini etkileyen önemli bir dini yapıdır.", "place_query": "Kiğı Ulu Camii, Kiğı, Bingöl"}, {"title": "Göynük Çayı Vadisi", "summary": "Yemyeşil doğası ve tertemiz akan suyuyla Göynük Çayı Vadisi, piknik yapmak ve doğayla baş başa kalmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Göynük Çayı Vadisi, Kiğı, Bingöl"}, {"title": "Kırık Minare (Dik Minare)", "summary": "Bölgenin simgelerinden biri olan bu tarihi minare, geçmişte yaşanan depremlere rağmen ayakta kalmayı başarmış etkileyici bir yapıdır.", "place_query": "Kırık Minare, Kiğı, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '48b98924-c902-4170-a7c1-150e8be61867'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bingöl Çobantaşı Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard tutkunlarının uğrak noktası olan bu merkez, şehir merkezine yakınlığı ve doğal pistleriyle öne çıkar. Yazın da doğa yürüyüşleri için tercih edilir.", "place_query": "Bingöl Çobantaşı Kayak Merkezi, Bingöl Merkez"}, {"title": "Yüzen Ada (Aksakal Gölü)", "summary": "Bingöl''ün eşsiz doğal güzelliklerinden biri olan bu gölde, rüzgarla hareket eden küçük adacıklar bulunur. Kuş gözlemi ve doğa fotoğrafçılığı için popüler bir yerdir.", "place_query": "Yüzen Ada Aksakal Gölü, Bingöl"}, {"title": "Bingöl Kalesi", "summary": "Şehir merkezinde yer alan tarihi kale, Bingöl''ün geçmişine tanıklık eden önemli bir yapıdır. Tepeden şehir manzarasını izlemek için ideal bir noktadır.", "place_query": "Bingöl Kalesi, Bingöl Merkez"}, {"title": "Kargapazarı Dağı ve Mesire Alanı", "summary": "Doğal güzelliği ve temiz havasıyla bilinen bu alan, piknik ve kamp yapmak isteyenler için sıkça ziyaret edilir. Özellikle bahar ve yaz aylarında rengarenk çiçeklerle kaplıdır.", "place_query": "Kargapazarı Dağı Mesire Alanı, Bingöl"}, {"title": "Bingöl Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen müze, Bingöl''ün kültürel mirasını yakından tanımak isteyenler için önemli bir duraktır.", "place_query": "Bingöl Müzesi, Bingöl Merkez"}, {"title": "Sancak Köprüsü", "summary": "Tarihi bir Osmanlı dönemi köprüsü olan Sancak Köprüsü, taş işçiliği ve mimarisiyle dikkat çeker. Çevresindeki doğal dokuyla birlikte fotoğrafçılar için güzel bir mekandır.", "place_query": "Sancak Köprüsü, Bingöl"}, {"title": "Sarıçiçek Milli Parkı", "summary": "Bingöl''ün en önemli doğal alanlarından biri olan bu milli park, zengin bitki örtüsü ve yaban hayatıyla doğa severleri cezbeder. Yürüyüş rotaları ve mesire alanları mevcuttur.", "place_query": "Sarıçiçek Milli Parkı, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e07a8e13-c756-4d62-a059-a34994c78bf3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yüzen Ada (Bingöl Solhan Yüzen Adası)", "summary": "Solhan ilçesine bağlı Hazarşah köyünde bulunan bu doğa harikası, Türkiye''nin sayılı yüzen adalarından biridir. Gölet üzerinde rüzgar ve su akıntısıyla yer değiştiren ada, ziyaretçilere eşsiz bir manzara ve piknik imkanı sunar.", "place_query": "Yüzen Ada, Solhan, Bingöl"}, {"title": "Solhan Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle bahar ve yaz aylarında akan suları ve çevresindeki yeşil doğasıyla serinlemek ve doğa yürüyüşü yapmak için idealdir. Bölge halkının sıkça tercih ettiği bir mesire alanıdır.", "place_query": "Solhan Şelalesi, Bingöl"}, {"title": "Çendere Köprüsü (Solhan)", "summary": "Tarihi bir Roma dönemi köprüsü olan bu yapı, Solhan ilçesi sınırları içerisinde yer alır ve bölgenin önemli tarihi miraslarındandır. Taş işçiliği ve mimarisiyle fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Çendere Köprüsü, Solhan, Bingöl"}, {"title": "Kığı Kalesi", "summary": "Solhan''a bağlı Kığı köyünde bulunan bu tarihi kale, bölgeye hakim bir tepe üzerine inşa edilmiştir. Kaleye çıktığınızda çevredeki vadi ve dağ manzaraları nefes kesicidir; tarih ve doğa iç içedir.", "place_query": "Kığı Kalesi, Solhan, Bingöl"}, {"title": "Solhan Kayak Merkezi", "summary": "Bingöl''ün önemli kış turizmi noktalarından biri olan bu kayak merkezi, Solhan ilçesi yakınlarında yer alır. Kış aylarında kayak ve snowboard yapmak, yazın ise doğa yürüyüşleri için tercih edilir.", "place_query": "Solhan Kayak Merkezi, Bingöl"}, {"title": "Hazarşah Göleti", "summary": "Yüzen Ada''nın da bulunduğu bu gölet, piknik alanları ve sakin atmosferiyle hafta sonu kaçamakları için popüler bir duraktır. Gölet çevresinde yürüyüş yapabilir, kuş gözlemi yapabilirsiniz.", "place_query": "Hazarşah Göleti, Solhan, Bingöl"}, {"title": "Solhan Merkez Camii", "summary": "İlçe merkezinde bulunan bu cami, mimarisi ve çevre düzenlemesiyle dikkat çeker. Bölgenin dini ve kültürel yapısını yansıtan önemli bir yapıdır.", "place_query": "Solhan Merkez Camii, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '464be0ee-08ee-4408-ae46-f09e70ef6a1d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yayladere Merkez Camii ve Tarihi Evler", "summary": "Yayladere''nin merkezinde yer alan tarihi cami ve çevresindeki geleneksel taş evler, ilçenin kültürel dokusunu yansıtır. Ziyaretçiler, bu yapıları gezerek bölgenin tarihi atmosferini deneyimleyebilir.", "place_query": "Yayladere Merkez Camii, Yayladere, Bingöl"}, {"title": "Şenpazar Köprüsü", "summary": "Yayladere ilçesinde bulunan Şenpazar Köprüsü, tarihi bir taş köprüdür ve bölgenin önemli kültürel miraslarındandır. Doğal güzelliklerle çevrili bu yapı, fotoğrafçılık ve tarih meraklıları için idealdir.", "place_query": "Şenpazar Köprüsü, Yayladere, Bingöl"}, {"title": "Yayladere Yaylaları (Örneğin: Güney Yaylası)", "summary": "Yayladere, adını aldığı yaylalarıyla ünlüdür; özellikle Güney Yaylası, serin havası ve yeşil doğasıyla yaz aylarında kaçış noktasıdır. Doğa yürüyüşleri ve piknik için popüler bir yerdir.", "place_query": "Güney Yaylası, Yayladere, Bingöl"}, {"title": "Yayladere Göleti", "summary": "İlçe merkezine yakın konumdaki bu gölet, huzurlu bir doğa manzarası sunar. Çevresinde yürüyüş yapabilir, kuş gözlemi ve fotoğraf çekimi için uygun bir ortam bulabilirsiniz.", "place_query": "Yayladere Göleti, Yayladere, Bingöl"}, {"title": "Yayladere Şelalesi", "summary": "Yayladere ilçe sınırları içinde yer alan bu şelale, özellikle bahar ve yaz aylarında akan sularıyla görsel bir şölen sunar. Doğa severler için keşfedilmeyi bekleyen bir güzelliktir.", "place_query": "Yayladere Şelalesi, Yayladere, Bingöl"}, {"title": "Yayladere Kalesi (Harabe)", "summary": "Tarihi bir kale kalıntısı olan Yayladere Kalesi, bölgenin savunma yapılarına dair izler taşır. Tepe üzerinde yer alan kaleye çıkarak çevrenin panoramik manzarasını izleyebilirsiniz.", "place_query": "Yayladere Kalesi, Yayladere, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '01c967f2-0ef0-4cc3-9abd-01e011fa6dfb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yedisu Kaplıcaları", "summary": "Bingöl''ün Yedisu ilçesinde yer alan bu doğal kaplıcalar, şifalı termal sularıyla ziyaretçilerine sağlık ve dinlenme imkanı sunar. Doğal bir havuzda keyifli bir banyo deneyimi yaşayabilirsiniz.", "place_query": "Yedisu Kaplıcaları, Yedisu, Bingöl"}, {"title": "Yedisu Şelalesi", "summary": "Yemyeşil doğa içinde yer alan bu şelale, serin suları ve huzur veren atmosferiyle doğa severler için ideal bir kaçış noktasıdır. Piknik yapmak ve doğa yürüyüşleri için de uygundur.", "place_query": "Yedisu Şelalesi, Yedisu, Bingöl"}, {"title": "Çayırpınar Yaylası", "summary": "Yedisu''ya bağlı bu yayla, yemyeşil çayırları ve temiz havasıyla ünlüdür. Yaz aylarında yayla şenliklerine ev sahipliği yapar ve doğa ile baş başa kalmak isteyenler için harika bir rotadır.", "place_query": "Çayırpınar Yaylası, Yedisu, Bingöl"}, {"title": "Kurucaova Köyü ve Tarihi Evler", "summary": "Geleneksel mimariyi yansıtan tarihi taş evleriyle bilinen bu köy, Yedisu''nun kültürel dokusunu keşfetmek isteyenler için önemli bir duraktır. Köy halkının misafirperverliği de ziyaretçileri cezbeder.", "place_query": "Kurucaova Köyü, Yedisu, Bingöl"}, {"title": "Yedisu Göleti", "summary": "İlçe merkezine yakın konumdaki bu gölet, huzurlu bir piknik alanı ve doğa yürüyüşü imkanı sunar. Kuş gözlemi yapmak ve sakin bir gün geçirmek için idealdir.", "place_query": "Yedisu Göleti, Yedisu, Bingöl"}, {"title": "Yedisu Merkez Camii", "summary": "İlçenin tarihi ve dini yapılarından biri olan bu cami, mimarisiyle dikkat çeker. Hem ibadet hem de tarihi bir yapıyı ziyaret etmek isteyenler için uygun bir mekandır.", "place_query": "Yedisu Merkez Camii, Yedisu, Bingöl"}, {"title": "Yedisu Yaylaları (Genel Bölge)", "summary": "Yedisu, çevresindeki birçok yaylasıyla ünlüdür. Özellikle yaz aylarında serinlemek ve doğal güzellikleri keşfetmek için yayla turları düzenlenir. Bölge, zengin flora ve faunasıyla da dikkat çeker.", "place_query": "Yedisu Yaylaları, Bingöl"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2bb87447-4f56-48f4-91fd-8169f5e74604'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Adilcevaz Kalesi", "summary": "Van Gölü kıyısında yükselen bu tarihi Urartu kalesi, muhteşem göl ve dağ manzarası eşliğinde ziyaretçilere eşsiz bir tarih ve doğa deneyimi sunar.", "place_query": "Adilcevaz Kalesi, Adilcevaz, Bitlis"}, {"title": "Sahil Kalesi (Kef Kalesi)", "summary": "Van Gölü''nün hemen kıyısında yer alan bu Orta Çağ kalesi, etkileyici surları ve göl manzarasıyla fotoğrafçılar ve tarih meraklıları için ideal bir duraktır.", "place_query": "Sahil Kalesi Kef Kalesi, Adilcevaz, Bitlis"}, {"title": "Van Gölü Sahili ve Yüzme Alanları", "summary": "Adilcevaz''ın sakin ve temiz Van Gölü kıyıları, özellikle yaz aylarında serinlemek ve doğal güzelliklerin tadını çıkarmak için popüler bir noktadır.", "place_query": "Van Gölü Sahili, Adilcevaz, Bitlis"}, {"title": "Adilcevaz Müzesi", "summary": "Bölgedeki Urartu, Roma ve Osmanlı dönemlerine ait arkeolojik eserlerin sergilendiği bu küçük ama zengin müze, tarihe ilgi duyanlar için önemli bir duraktır.", "place_query": "Adilcevaz Müzesi, Adilcevaz, Bitlis"}, {"title": "Süphan Dağı Milli Parkı", "summary": "Türkiye''nin en yüksek dağlarından biri olan Süphan Dağı''nın eteklerindeki bu milli park, doğa yürüyüşleri ve kampçılık için eşsiz bir ortam sunar.", "place_query": "Süphan Dağı Milli Parkı, Adilcevaz, Bitlis"}, {"title": "Kazıkbeli Yaylası", "summary": "Süphan Dağı''nın eteklerinde yer alan bu yemyeşil yayla, temiz havası ve doğal güzellikleriyle piknik ve doğa yürüyüşü yapmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Kazıkbeli Yaylası, Adilcevaz, Bitlis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bdd8d1fe-d6c8-4b34-9ca0-438aaf707673'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ahlat Selçuklu Mezarlığı", "summary": "UNESCO Dünya Mirası Geçici Listesi''nde yer alan bu devasa açık hava müzesi, Selçuklu dönemine ait görkemli mezar taşları ve kümbetleriyle ünlüdür. Tarih meraklıları için eşsiz bir durak olup, bölgenin en önemli kültürel miraslarındandır.", "place_query": "Ahlat Selçuklu Mezarlığı, Ahlat, Bitlis"}, {"title": "Ahlat Müzesi", "summary": "Selçuklu Mezarlığı''ndan çıkarılan eserlerin sergilendiği müze, bölgenin zengin tarihine ışık tutar. Urartu''dan Osmanlı''ya uzanan geniş bir koleksiyona ev sahipliği yapar.", "place_query": "Ahlat Müzesi, Ahlat, Bitlis"}, {"title": "Harabeşehir (Eski Ahlat)", "summary": "Tarihi Ahlat şehrinin kalıntılarının bulunduğu bu alan, Selçuklu ve Osmanlı dönemlerine ait yapı temelleri ve sokak dokusuyla dikkat çeker. Açık hava müzesi niteliğindeki bölge, tarihi atmosferiyle ziyaretçilerini büyüler.", "place_query": "Harabeşehir, Ahlat, Bitlis"}, {"title": "Ahlat Sahili ve Van Gölü", "summary": "Van Gölü''nün kıyısında yer alan Ahlat Sahili, özellikle yaz aylarında serinlemek ve göl manzarasının tadını çıkarmak için idealdir. Sodalı suyu ve ince kumlu plajıyla bölge halkının ve turistlerin uğrak noktasıdır.", "place_query": "Ahlat Sahili, Ahlat, Bitlis"}, {"title": "Emir Bayındır Kümbeti", "summary": "Selçuklu dönemine ait bu zarif kümbet, taş işçiliğinin en güzel örneklerinden biridir. Geometrik desenleri ve kitabeleriyle dönemin sanat anlayışını yansıtır.", "place_query": "Emir Bayındır Kümbeti, Ahlat, Bitlis"}, {"title": "İkiz Kümbetler", "summary": "Ahlat''ın simgelerinden olan bu iki kümbet, yan yana konumlanmış olup Selçuklu mezar mimarisinin en özel örneklerindendir. Fotoğrafçılar için popüler bir çekim noktasıdır.", "place_query": "İkiz Kümbetler, Ahlat, Bitlis"}, {"title": "Ulu Kümbet", "summary": "Ahlat''taki en büyük kümbet olma özelliğini taşıyan bu yapı, ihtişamlı görüntüsüyle dikkat çeker. Selçuklu taş işçiliğinin ve mimari estetiğinin en görkemli örneklerindendir.", "place_query": "Ulu Kümbet, Ahlat, Bitlis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fafa7839-c8c6-4d1d-8745-f916f698ecb5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güroymak Merkez Camii", "summary": "İlçe merkezinde yer alan tarihi cami, mimarisi ve huzurlu atmosferiyle ziyaretçilerin ilgisini çeker. Bölgenin dini ve kültürel mirasını yansıtan önemli bir yapıdır.", "place_query": "Güroymak Merkez Camii, Güroymak, Bitlis"}, {"title": "Güroymak Şelalesi", "summary": "Doğal güzelliğiyle ünlü şelale, çevresindeki yeşil alanlarla piknik ve dinlenme için ideal bir noktadır. Özellikle yaz aylarında serinlemek isteyenlerin uğrak yeridir.", "place_query": "Güroymak Şelalesi, Güroymak, Bitlis"}, {"title": "Güroymak Kalesi", "summary": "Tarihi bir kale olan bu yapı, bölgenin geçmişine ışık tutar ve çevresine hakim manzarasıyla fotoğrafçılar için harika bir seyir noktası sunar.", "place_query": "Güroymak Kalesi, Güroymak, Bitlis"}, {"title": "Güroymak Mesire Alanı", "summary": "Aileler ve doğa severler için düzenlenmiş bu mesire alanı, yürüyüş yolları ve piknik masalarıyla huzurlu bir gün geçirme imkanı sağlar.", "place_query": "Güroymak Mesire Alanı, Güroymak, Bitlis"}, {"title": "Güroymak Yaylaları", "summary": "İlçe çevresindeki yaylalar, temiz havası ve muhteşem doğa manzaralarıyla trekking ve kamp yapmak isteyenler için popüler bir destinasyondur.", "place_query": "Güroymak Yaylaları, Bitlis"}, {"title": "Güroymak Göleti", "summary": "Balık tutma ve doğa yürüyüşü gibi aktiviteler için tercih edilen gölet, sakin atmosferiyle şehir stresinden uzaklaşmak isteyenlere hitap eder.", "place_query": "Güroymak Göleti, Güroymak, Bitlis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fcbf6d30-a396-419b-af93-61f8d602f92e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hizan Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde bulunan tarihi kale, Urartu dönemine ait izler taşır ve muhteşem bir vadi manzarası sunar.", "place_query": "Hizan Kalesi, Hizan, Bitlis"}, {"title": "Nazik Gölü", "summary": "Hizan sınırları içinde yer alan bu krater gölü, berrak suları ve çevresindeki yemyeşil doğasıyla piknik ve doğa yürüyüşleri için ideal bir noktadır.", "place_query": "Nazik Gölü, Hizan, Bitlis"}, {"title": "Hizan Şelalesi", "summary": "Sarp kayalıklardan dökülen bu şelale, özellikle bahar ve yaz aylarında coşkun akışıyla ziyaretçilerine serinletici bir atmosfer sunar.", "place_query": "Hizan Şelalesi, Hizan, Bitlis"}, {"title": "Karbastı Mağarası", "summary": "Doğal oluşumlu bu mağara, sarkıt ve dikitleriyle ilgi çeker; içerisindeki küçük göletiyle keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "Karbastı Mağarası, Hizan, Bitlis"}, {"title": "Sarıkaya Kaplıcaları", "summary": "Hizan ilçe merkezine yakın konumdaki bu kaplıcalar, romatizmal rahatsızlıklara iyi geldiğine inanılan termal sularıyla şifa arayanları ağırlar.", "place_query": "Sarıkaya Kaplıcaları, Hizan, Bitlis"}, {"title": "Akşar Köyü Tarihi Camii", "summary": "Yüzlerce yıllık geçmişe sahip bu taş cami, yöresel mimarinin güzel bir örneği olup hâlâ ibadete açıktır.", "place_query": "Akşar Köyü Tarihi Camii, Hizan, Bitlis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dd7550a7-6a1e-4ef1-951a-f838f7d73836'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"id": 1, "title": "Bitlis Kalesi", "summary": "Şehir merkezinde yükselen bu tarihi kale, Urartu dönemine kadar uzanan köklü geçmişiyle Bitlis''in simgesidir. Kaleye çıktığınızda şehri ve çevresini kuşbakışı izleyebilir, surlar ve burçlar arasında tarihi bir yolculuğa çıkabilirsiniz.", "place_query": "Bitlis Kalesi, Merkez, Bitlis"}, {"id": 2, "title": "Ahlat Selçuklu Mezarlığı", "summary": "Ahlat ilçesinde bulunan bu açık hava müzesi, devasa mezar taşları ve kümbetleriyle Selçuklu döneminin en önemli eserlerini barındırır. UNESCO Dünya Mirası Geçici Listesi''nde yer alan mezarlık, tarih ve sanat meraklıları için eşsiz bir duraktır.", "place_query": "Ahlat Selçuklu Mezarlığı, Ahlat, Bitlis"}, {"id": 3, "title": "Nemrut Krater Gölü", "summary": "Bitlis''in Tatvan ilçesinde yer alan Nemrut Dağı''nın tepesindeki krater gölü, eşsiz mavi suları ve çevresindeki volkanik oluşumlarla büyüler. Doğa yürüyüşü yapabilir, göl kenarında piknik yaparak huzur dolu anlar yaşayabilirsiniz.", "place_query": "Nemrut Krater Gölü, Tatvan, Bitlis"}, {"id": 4, "title": "Bitlis Ulu Camii", "summary": "12. yüzyılda inşa edilen bu tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Şehir merkezinde yer alan cami, hem ibadet hem de tarihi dokuya tanıklık etmek için ziyaret edilebilir.", "place_query": "Bitlis Ulu Camii, Merkez, Bitlis"}, {"id": 5, "title": "Tatvan Sahili ve Van Gölü", "summary": "Tatvan ilçesi, Van Gölü''nün masmavi sularına kıyısı olan uzun bir sahile sahiptir. Sahilde yürüyüş yapabilir, gün batımını izleyebilir ve gölün tadını çıkarabilirsiniz.", "place_query": "Tatvan Sahili, Tatvan, Bitlis"}, {"id": 6, "title": "Bitlis Etnografya Müzesi", "summary": "Tarihi bir konakta hizmet veren müze, Bitlis''in geleneksel yaşamını, kıyafetlerini ve el sanatlarını sergiler. Yöresel kültürü yakından tanımak için ideal bir duraktır.", "place_query": "Bitlis Etnografya Müzesi, Merkez, Bitlis"}, {"id": 7, "title": "Güroymak Kaplıcaları", "summary": "Bitlis''in Güroymak ilçesinde bulunan bu kaplıcalar, şifalı termal sularıyla ünlüdür. Romatizma ve cilt hastalıklarına iyi geldiğine inanılan sularında dinlenebilir, doğayla iç içe bir gün geçirebilirsiniz.", "place_query": "Güroymak Kaplıcaları, Güroymak, Bitlis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ca0b81be-eb59-45d4-9e27-7a3b3defbabb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mutki Kalesi", "summary": "Tarihi bir kalıntı olan Mutki Kalesi, ilçenin en önemli tarihi yapılarından biridir. Bölgenin stratejik geçmişine tanıklık eden kale, çevresindeki doğal manzarayla birlikte ziyaretçilere huzurlu bir atmosfer sunar.", "place_query": "Mutki Kalesi, Mutki, Bitlis"}, {"title": "Kavakbaşı Şelalesi", "summary": "Mutki ilçe merkezine yakın konumda bulunan bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle yaz aylarında yerli halkın uğrak yeridir.", "place_query": "Kavakbaşı Şelalesi, Mutki, Bitlis"}, {"title": "Mutki Göleti", "summary": "Çevresi yeşilliklerle kaplı olan yapay gölet, sakin bir gün geçirmek ve kuş gözlemi yapmak isteyenler için popüler bir duraktır. Gölet etrafında yürüyüş yapabilir ve doğanın tadını çıkarabilirsiniz.", "place_query": "Mutki Göleti, Mutki, Bitlis"}, {"title": "Geyikpınar Yaylası", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü Geyikpınar Yaylası, doğa severler için kaçış noktasıdır. Yaylada kamp kurup yöresel lezzetleri tatma imkanı da bulabilirsiniz.", "place_query": "Geyikpınar Yaylası, Mutki, Bitlis"}, {"title": "Koyunlu Köyü Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Koyunlu Köyü Camii, mimari detayları ve taş işçiliğiyle dikkat çeker. Bölgedeki dini ve kültürel mirası görmek isteyenler için önemli bir duraktır.", "place_query": "Koyunlu Köyü Camii, Mutki, Bitlis"}, {"title": "Mutki Merkez Çarşı", "summary": "İlçenin kalbi sayılan bu çarşı, yöresel el sanatları ve organik ürünleriyle ünlüdür. Burada Mutki''ye özgü hediyelik eşyalar alabilir ve yöresel tatları deneyimleyebilirsiniz.", "place_query": "Mutki Merkez Çarşı, Mutki, Bitlis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '67a83175-899a-4e9d-88ff-363598d591bb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dörtdivan Yaylaları (Örneğin: Göl Yaylası, Kızık Yaylası)", "summary": "Bolu''nun serin ve yeşil yaylalarından biri olan Dörtdivan yaylaları, doğa yürüyüşleri, piknik ve kamp için idealdir. Özellikle yaz aylarında şehir hayatından kaçmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Dörtdivan Yaylaları, Bolu"}, {"title": "Dörtdivan Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde bulunan tarihi cami ve Osmanlı döneminden kalma çeşmeler, Dörtdivan''ın kültürel mirasını yansıtır. Kısa bir şehir turu sırasında görülmeye değerdir.", "place_query": "Dörtdivan Merkez Camii, Bolu"}, {"title": "Sülüklü Göl (Dörtdivan)", "summary": "Doğal güzelliği ve sakin atmosferiyle bilinen Sülüklü Göl, çevresindeki yeşil alanlarla doğa severler için popüler bir mesire yeridir. Gölet çevresinde yürüyüş yapabilir ve piknik yapabilirsiniz.", "place_query": "Sülüklü Göl, Dörtdivan, Bolu"}, {"title": "Dörtdivan Kültür Evi", "summary": "Yöresel kültürü ve el sanatlarını tanımak isteyenler için ideal olan bu küçük müze, geleneksel yaşamı yansıtan objeler sergiler. Ziyaretçilere ilçenin tarihi hakkında bilgi verir.", "place_query": "Dörtdivan Kültür Evi, Bolu"}, {"title": "Kapaklı Şelalesi", "summary": "Dörtdivan sınırları içerisinde yer alan bu şelale, özellikle bahar aylarında suyun coşkun akışıyla etkileyici bir manzara sunar. Doğa fotoğrafçıları ve huzur arayanlar için güzel bir duraktır.", "place_query": "Kapaklı Şelalesi, Dörtdivan, Bolu"}, {"title": "Çavuşlar Kaya Mezarları", "summary": "İlçeye bağlı Çavuşlar köyü yakınlarında bulunan bu tarihi kaya mezarları, Roma veya daha eski dönemlere ait olduğu düşünülen arkeolojik kalıntılardır. Tarih meraklıları için ilgi çekicidir.", "place_query": "Çavuşlar Kaya Mezarları, Dörtdivan, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '963dd29d-f045-4ac0-8bdb-f5ec8f13a4a4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gerede Esentepe Mesire Yeri", "summary": "Şehir merkezine yakın, yemyeşil doğası ve piknik alanlarıyla bilinen bu mesire yeri, özellikle hafta sonları ailelerin uğrak noktasıdır. Temiz havası ve yürüyüş parkurları ile doğayla baş başa kalmak isteyenler için idealdir.", "place_query": "Esentepe Mesire Yeri, Gerede, Bolu"}, {"title": "Gerede Kaya Evleri", "summary": "Tarihi dokusuyla dikkat çeken bu kaya evler, bölgenin eski yerleşim kültürünü yansıtan eşsiz yapılardır. Doğal kaya oyuntularına inşa edilmiş olmalarıyla ziyaretçilere farklı bir keşif deneyimi sunar.", "place_query": "Gerede Kaya Evleri, Gerede, Bolu"}, {"title": "Gerede Kaplıcaları", "summary": "Termal sularıyla ünlü olan Gerede Kaplıcaları, romatizma ve cilt rahatsızlıklarına iyi geldiği düşünülen şifalı sularıyla ziyaretçilerini ağırlar. Doğal ortamında dinlenmek ve sağlık bulmak isteyenler için popüler bir duraktır.", "place_query": "Gerede Kaplıcaları, Gerede, Bolu"}, {"title": "Gerede Yaylaları (Örneğin: Kızık Yaylası)", "summary": "Gerede çevresindeki yaylalar, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler için harika rotalardır. Yemyeşil çayırları ve temiz havasıyla huzur veren bir atmosfere sahiptir.", "place_query": "Kızık Yaylası, Gerede, Bolu"}, {"title": "Gerede Tarihi Çarşı ve Camiler (Örn: Büyük Cami)", "summary": "Gerede''nin merkezinde yer alan tarihi çarşı ve Büyük Cami gibi yapılar, Osmanlı döneminden kalma mimari özellikler taşır. Dar sokakları ve tarihi atmosferi ile şehir kültürünü yakından tanımak isteyenler için idealdir.", "place_query": "Gerede Büyük Cami, Gerede, Bolu"}, {"title": "Gerede Ulusu (Gerede Çayı Kenarı)", "summary": "Şehrin içinden geçen Gerede Çayı çevresi, özellikle yaz akşamlarında yürüyüş yapmak ve dinlenmek için tercih edilen bir alandır. Çay kenarındaki mesire alanları ve kafeler, ziyaretçilere sakin bir ortam sunar.", "place_query": "Gerede Çayı, Gerede, Bolu"}, {"title": "Gerede Kültür ve Sanat Evi", "summary": "Gerede''nin yerel kültürünü ve el sanatlarını tanıtan bu merkez, yöresel ürünler ve tarihi objeler sergiler. Ziyaretçilere bölgenin gelenekleri hakkında bilgi edinme fırsatı sunan önemli bir duraktır.", "place_query": "Gerede Kültür ve Sanat Evi, Gerede, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f9bebda-2fe4-417d-9bac-4ae304cdead0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göynük Evleri (Tarihi Osmanlı Evleri)", "summary": "Göynük''ün simgesi haline gelmiş, Osmanlı döneminden kalma ahşap ve bağdadi sıvalı tarihi evler, dar sokakları ve huzurlu atmosferiyle ziyaretçilerini geçmişe götürüyor.", "place_query": "Göynük Evleri, Göynük, Bolu"}, {"title": "Akşemseddin Türbesi ve Külliyesi", "summary": "Fatih Sultan Mehmet''in hocası Akşemseddin''in türbesinin bulunduğu bu manevi mekan, Göynük''ün en önemli ziyaret noktalarından biridir ve çevresindeki tarihi yapılarla birlikte görülmeye değerdir.", "place_query": "Akşemseddin Türbesi, Göynük, Bolu"}, {"title": "Göynük Saat Kulesi", "summary": "1909 yılında yapılan ve ilçenin merkezinde yer alan bu tarihi saat kulesi, Göynük''ün sembol yapılarından biri olup çevresindeki çarşı ile keyifli bir gezinti sunar.", "place_query": "Göynük Saat Kulesi, Göynük, Bolu"}, {"title": "Göynük Cinci Hamamı", "summary": "Osmanlı döneminden kalma tarihi bir hamam olan Cinci Hamamı, özgün mimarisi ve restore edilmiş yapısıyla hem tarihi dokuyu hissetmek hem de geleneksel hamam deneyimi yaşamak için idealdir.", "place_query": "Cinci Hamamı, Göynük, Bolu"}, {"title": "Sülüklü Göl Tabiat Parkı", "summary": "Göynük''e yakın mesafede, doğayla iç içe bir tabiat parkı olan Sülüklü Göl, piknik alanları, yürüyüş yolları ve huzur veren göl manzarasıyla doğa severler için harika bir kaçış noktasıdır.", "place_query": "Sülüklü Göl Tabiat Parkı, Göynük, Bolu"}, {"title": "Çubuk Göleti Mesire Alanı", "summary": "Göynük merkeze yakın konumdaki Çubuk Göleti, yeşillikler içinde piknik yapmak, yürüyüş yapmak ve gölet kenarında dinlenmek isteyenler için popüler bir mesire alanıdır.", "place_query": "Çubuk Göleti, Göynük, Bolu"}, {"title": "Göynük Kaya Mezarları", "summary": "İlçe merkezine yakın kayalıklara oyulmuş antik döneme ait kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutan ilginç arkeolojik kalıntılardır.", "place_query": "Göynük Kaya Mezarları, Göynük, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '645dfb27-8b18-469d-93dd-1d538cc86152'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kıbrıscık Yaylaları (Büyükyayla, Düzyayla vb.)", "summary": "Bolu''nun en bakir doğal alanlarından olan Kıbrıscık yaylaları, yemyeşil çam ormanları ve temiz havasıyla doğa yürüyüşü ve piknik için idealdir. Özellikle yaz aylarında serinlemek ve manzaranın tadını çıkarmak için ziyaret edilir.", "place_query": "Kıbrıscık Yaylaları, Bolu"}, {"title": "Aladağlar Tabiat Parkı (Kıbrıscık Bölümü)", "summary": "Köroğlu Dağları''nın uzantısı olan bu tabiat parkı, zengin flora ve faunası, kamp alanları ve yürüyüş rotalarıyla doğaseverlerin uğrak noktasıdır. Bölgedeki en yüksek noktalardan biridir ve eşsiz bir seyir keyfi sunar.", "place_query": "Aladağlar Tabiat Parkı, Bolu"}, {"title": "Kıbrıscık Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde bulunan tarihi cami ve Osmanlı döneminden kalma taş çeşmeler, Kıbrıscık''ın kültürel dokusunu yansıtan önemli yapılardır. Kısa bir şehir turu sırasında görülmeye değerdir.", "place_query": "Kıbrıscık Merkez Camii, Bolu"}, {"title": "Gölcük Göleti (Kıbrıscık)", "summary": "İlçe merkezine yakın konumdaki bu küçük gölet, çevresindeki çam ağaçları ve sakin atmosferiyle huzurlu bir piknik ve yürüyüş alanıdır. Özellikle hafta sonu kaçamakları için tercih edilir.", "place_query": "Gölcük Göleti Kıbrıscık, Bolu"}, {"title": "Kıbrıscık Doğa Yürüyüşü Rotaları (Köroğlu Dağları)", "summary": "Köroğlu Dağları''nın eteklerinde yer alan Kıbrıscık, keşfedilmeyi bekleyen onlarca patika ve orman yoluna sahiptir. Doğa sporları meraklıları için zorluk derecesi farklı rotalar sunar.", "place_query": "Köroğlu Dağları Kıbrıscık yürüyüş rotaları, Bolu"}, {"title": "Kıbrıscık Köy Odaları ve Kültür Evleri", "summary": "İlçeye bağlı köylerde bulunan geleneksel köy odaları ve kültür evleri, yöresel yaşamı ve misafirperverliği yakından tanımak isteyenler için eşsiz bir deneyim sunar.", "place_query": "Kıbrıscık köy odaları, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9c31d354-6e08-4ab5-a312-aff6147419fc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mengen Karasu Şelalesi", "summary": "Bolu''nun Mengen ilçesinde yer alan bu şelale, doğal güzelliği ve çevresindeki yemyeşil ormanlık alanla ziyaretçilerine huzurlu bir kaçış sunar. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için idealdir.", "place_query": "Karasu Şelalesi, Mengen, Bolu"}, {"title": "Mengen Yaylaları", "summary": "Mengen, Bolu''nun en güzel yaylalarına ev sahipliği yapar; özellikle Gökçesu ve Çukurca yaylaları, muhteşem manzaraları ve temiz havasıyla doğaseverlerin uğrak noktasıdır. Yaylalarda geleneksel yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Mengen Yaylaları, Bolu"}, {"title": "Mengen Aşçılar Çeşmesi ve Anıtı", "summary": "Mengen, Türkiye''nin aşçılar başkenti olarak bilinir ve bu anıt, ilçenin bu ününü simgeler. Ziyaretçiler, burada hatıra fotoğrafı çektirip ilçenin meşhur aşçılık kültürü hakkında bilgi alabilir.", "place_query": "Aşçılar Çeşmesi, Mengen, Bolu"}, {"title": "Mengen Kapıkaya Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikitleriyle dikkat çeken bu mağara, macera arayanlar için keşfedilmeyi bekleyen bir yeraltı dünyasıdır. Mağara çevresi aynı zamanda piknik ve doğa yürüyüşü için de uygundur.", "place_query": "Kapıkaya Mağarası, Mengen, Bolu"}, {"title": "Mengen Merkez Camii", "summary": "Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, ilçe merkezinde yer alır ve hem ibadet hem de tarihi doku açısından önemli bir yapıdır. Caminin avlusu ve çevresi, sakin bir atmosfer sunar.", "place_query": "Mengen Merkez Camii, Bolu"}, {"title": "Mengen Gökçesu Göleti", "summary": "Şehir merkezine yaklaşık 20 km uzaklıktaki bu gölet, piknik alanları ve çevresindeki yürüyüş yollarıyla hafta sonu kaçamakları için popüler bir yerdir. Gölet kenarında olta balıkçılığı da yapılabilir.", "place_query": "Gökçesu Göleti, Mengen, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '17354276-19d4-4b67-a7df-b5611ee5147a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yedigöller Milli Parkı", "summary": "Bolu''nun en ünlü doğal harikası olan Yedigöller, yedi ayrı gölün bir arada bulunduğu eşsiz bir milli parktır. Özellikle sonbaharda büyüleyici renklere bürünen park, yürüyüş, piknik ve kamp için idealdir.", "place_query": "Yedigöller Milli Parkı, Bolu"}, {"title": "Gölcük Tabiat Parkı", "summary": "Bolu şehir merkezine sadece 13 km uzaklıktaki bu tabiat parkı, çam ormanlarıyla çevrili sakin gölüyle ünlüdür. Hafta sonu kaçamakları için popüler bir mesire ve yürüyüş alanıdır.", "place_query": "Gölcük Tabiat Parkı, Bolu"}, {"title": "Bolu Müzesi", "summary": "Bolu''nun tarihini ve kültürel mirasını sergileyen bu müze, Frig, Roma ve Bizans dönemlerine ait eserlerin yanı sıra yöresel etnografik objeleri de barındırır. Şehir merkezinde kolayca ziyaret edilebilir.", "place_query": "Bolu Müzesi, Bolu Merkez"}, {"title": "Büyüksu Şelalesi", "summary": "Bolu''nun doğal güzelliklerinden biri olan Büyüksu Şelalesi, yemyeşil bir vadi içinde akan serin sularıyla doğa severlerin uğrak noktasıdır. Piknik alanları ve yürüyüş parkurları da mevcuttur.", "place_query": "Büyüksu Şelalesi, Bolu"}, {"title": "Kaplıcalar (Bolu Merkez)", "summary": "Bolu, şifalı termal sularıyla da ünlüdür; merkezde ve çevresinde birçok kaplıca tesisi bulunur. Özellikle kış aylarında romatizma ve cilt rahatsızlıklarına iyi gelen bu sular, sağlık turizmi açısından önemlidir.", "place_query": "Bolu Kaplıcaları, Bolu Merkez"}, {"title": "Bolu Yaylaları (Sarıalan Yaylası)", "summary": "Bolu Merkez''e yakın Sarıalan Yaylası, temiz havası ve geniş çayırlarıyla doğa yürüyüşü ve kamp için popülerdir. Yaz aylarında serinlemek ve şehir gürültüsünden uzaklaşmak için idealdir.", "place_query": "Sarıalan Yaylası, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9fc98320-949a-4eab-b0f1-64f2a2a06ca3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mudurnu Tarihi Evleri", "summary": "Osmanlı döneminden kalma ahşap ve kagir yapılarıyla ünlü Mudurnu''nun dar sokaklarında yürüyerek tarihi atmosferi soluyabilirsiniz. Geleneksel mimarinin en güzel örneklerini görmek için idealdir.", "place_query": "Mudurnu Tarihi Evleri, Mudurnu, Bolu"}, {"title": "Yıldırım Bayezid Camii ve Külliyesi", "summary": "1382 yılında Yıldırım Bayezid tarafından yaptırılan cami ve külliye, Mudurnu''nun en önemli tarihi yapılarındandır. Caminin yanı sıra hamam, medrese ve çarşı da külliyenin bir parçasıdır.", "place_query": "Yıldırım Bayezid Camii, Mudurnu, Bolu"}, {"title": "Mudurnu Saat Kulesi", "summary": "1903 yılında II. Abdülhamid döneminde yapılan saat kulesi, ilçenin sembol yapılarındandır. Tarihi çarşı bölgesinde yer alır ve çevresindeki hanlarla birlikte görülmeye değerdir.", "place_query": "Mudurnu Saat Kulesi, Mudurnu, Bolu"}, {"title": "Sülüklü Göl Tabiat Parkı", "summary": "Mudurnu ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu doğal göl, piknik alanları ve yürüyüş parkurlarıyla doğa severler için ideal bir kaçış noktasıdır. Gölde yüzme de mümkündür.", "place_query": "Sülüklü Göl Tabiat Parkı, Mudurnu, Bolu"}, {"title": "Mudurnu Arkeoloji ve Ahşap Eserler Müzesi", "summary": "Tarihi bir konakta hizmet veren müze, bölgedeki arkeolojik buluntuların yanı sıra yöresel ahşap işçiliği örneklerini sergiler. Mudurnu''nun kültürel mirasını yakından tanımak için mutlaka ziyaret edilmelidir.", "place_query": "Mudurnu Arkeoloji ve Ahşap Eserler Müzesi, Mudurnu, Bolu"}, {"title": "Göynük Evleri (Mudurnu''ya yakın)", "summary": "Mudurnu''ya yaklaşık 30 km mesafedeki Göynük ilçesi, Mudurnu''ya benzer şekilde korunmuş Osmanlı evleriyle ünlüdür. Kısa bir yolculukla tarihi bir yolculuğa çıkabilirsiniz.", "place_query": "Göynük Evleri, Göynük, Bolu"}, {"title": "Abant Gölü Tabiat Parkı (Mudurnu sınırlarında)", "summary": "Bolu''nun en ünlü doğal güzelliklerinden biri olan Abant Gölü, Mudurnu ilçe sınırları içinde yer alır. Çam ormanlarıyla çevrili göl, yürüyüş, bisiklet ve piknik için harika bir ortam sunar.", "place_query": "Abant Gölü Tabiat Parkı, Mudurnu, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '175f4c68-5a63-4770-bfe5-a8de0c7ee0c1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Seben Gölü", "summary": "Doğal güzelliğiyle ünlü bu krater gölü, çam ormanlarıyla çevrili huzurlu atmosferi ve piknik alanlarıyla ziyaretçilerine eşsiz bir doğa deneyimi sunar.", "place_query": "Seben Gölü, Seben, Bolu"}, {"title": "Seben Kaya Evleri", "summary": "Tarihi dokuyu yansıtan bu kaya oyma evler, bölgenin geçmiş yaşam tarzını gözler önüne serer ve fotoğraf meraklıları için ilgi çekici bir duraktır.", "place_query": "Seben Kaya Evleri, Seben, Bolu"}, {"title": "Çeltikdere Şelalesi", "summary": "Yemyeşil orman içinde yer alan bu şelale, serin suları ve doğal çevresiyle doğa yürüyüşü yapmak ve piknik yapmak için idealdir.", "place_query": "Çeltikdere Şelalesi, Seben, Bolu"}, {"title": "Seben Yaylası", "summary": "Temiz havası, geniş çayırları ve muhteşem manzarasıyla ünlü bu yayla, kampçılar ve doğaseverler için vazgeçilmez bir rotadır.", "place_query": "Seben Yaylası, Seben, Bolu"}, {"title": "Kınık Mağarası", "summary": "Sarkıt ve dikitleriyle dikkat çeken bu doğal mağara, macera arayan ziyaretçiler için keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "Kınık Mağarası, Seben, Bolu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ceaf0dfd-2e09-4d15-a342-fe26c1cc5b5e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sagalassos Antik Kenti", "summary": "Burdur''un Ağlasun ilçesinde yer alan bu antik kent, Roma İmparatorluğu döneminde Pisidya''nın en önemli şehirlerinden biriydi. Etkileyici tiyatrosu, anıtsal çeşmeleri ve agora kalıntılarıyla tarih meraklıları için eşsiz bir açık hava müzesidir.", "place_query": "Sagalassos Antik Kenti, Ağlasun, Burdur"}, {"title": "Ağlasun Şelalesi", "summary": "İlçe merkezine yaklaşık 5 km uzaklıkta bulunan bu şelale, yemyeşil bir vadi içinde yer alır ve özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler tarafından tercih edilir.", "place_query": "Ağlasun Şelalesi, Ağlasun, Burdur"}, {"title": "Ağlasun Roma Hamamı", "summary": "Sagalassos Antik Kenti''nin girişine yakın konumda bulunan bu yapı, Roma dönemine ait iyi korunmuş hamam kalıntılarıyla dikkat çeker ve antik kent ziyaretçilerinin mutlaka görmesi gereken yerlerdendir.", "place_query": "Ağlasun Roma Hamamı, Sagalassos, Ağlasun, Burdur"}, {"title": "Yazır Köyü Kaya Mezarları", "summary": "Ağlasun''a bağlı Yazır köyünde bulunan bu kaya mezarları, Frig ve Roma dönemlerine ait olup bölgenin antik yerleşim tarihine ışık tutan önemli arkeolojik kalıntılardır.", "place_query": "Yazır Köyü Kaya Mezarları, Ağlasun, Burdur"}, {"title": "Çamlık Tepesi Seyir Noktası", "summary": "Ağlasun ilçe merkezine hakim bir tepede yer alan bu seyir noktası, hem Sagalassos''un hem de çevredeki dağların panoramik manzarasını sunarak fotoğrafçılar ve doğa severler için ideal bir duraktır.", "place_query": "Çamlık Tepesi, Ağlasun, Burdur"}, {"title": "Ağlasun Müzesi", "summary": "İlçe merkezinde bulunan küçük ama zengin bu müze, Sagalassos kazılarında ortaya çıkarılan heykeller, sikkeler ve günlük yaşam objelerini sergileyerek antik kent ziyaretini tamamlayıcı bir deneyim sunar.", "place_query": "Ağlasun Müzesi, Ağlasun, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0ee36d43-0903-46e1-8da9-83e6a52365ce'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Altınyayla Gölleri (Karagöl ve Gölcük)", "summary": "Burdur''un Altınyayla ilçesinde yer alan bu göller, doğal güzellikleri ve huzur veren atmosferiyle ziyaretçilerini büyüler. Özellikle Karagöl, çevresindeki ormanlık alanla birlikte piknik ve doğa yürüyüşü için idealdir.", "place_query": "Karagöl, Altınyayla, Burdur"}, {"title": "Burdur Gölü (Altınyayla Kıyıları)", "summary": "Burdur''un en büyük doğal gölü olan Burdur Gölü''nün Altınyayla kıyıları, kuş gözlemi ve doğa fotoğrafçılığı için popülerdir. Göl, flamingo gibi birçok kuş türüne ev sahipliği yapar.", "place_query": "Burdur Gölü, Altınyayla, Burdur"}, {"title": "Altınyayla Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, özellikle bahar aylarında coşkun akan suları ve yeşil doğasıyla serinlemek ve doğayla iç içe vakit geçirmek isteyenler için güzel bir duraktır.", "place_query": "Altınyayla Şelalesi, Burdur"}, {"title": "Ballık Mağarası", "summary": "Altınyayla sınırları içinde yer alan Ballık Mağarası, etkileyici sarkıt ve dikit oluşumlarıyla dikkat çeker. Mağara, doğa tutkunları ve macera arayanlar için keşfedilmeyi bekleyen bir yeraltı güzelliğidir.", "place_query": "Ballık Mağarası, Altınyayla, Burdur"}, {"title": "Kocapınar Yaylası", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü Kocapınar Yaylası, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Kocapınar Yaylası, Altınyayla, Burdur"}, {"title": "Çatak Köyü Kaya Mezarları", "summary": "Altınyayla''ya bağlı Çatak Köyü''nde bulunan bu tarihi kaya mezarları, bölgenin antik dönemlerine ışık tutar. Tarih ve arkeoloji meraklıları için ilginç bir duraktır.", "place_query": "Çatak Köyü Kaya Mezarları, Altınyayla, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd3590366-02d8-4a85-bf1b-db4e9f6052f6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İnsuyu Mağarası", "summary": "Bucak ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu mağara, Türkiye''nin en büyük mağaralarından biridir. İçerisindeki sarkıt, dikit ve sütun oluşumları ile ziyaretçilere doğa harikası bir yeraltı dünyası sunar.", "place_query": "İnsuyu Mağarası, Bucak, Burdur"}, {"title": "Kızılkaya Mağarası", "summary": "Bucak''ın Kızılkaya köyünde yer alan bu mağara, doğal güzelliği ve tarihi kalıntılarıyla dikkat çeker. Mağara içindeki kaya oluşumları ve çevresindeki doğa yürüyüş rotaları ziyaretçiler için popüler bir destinasyondur.", "place_query": "Kızılkaya Mağarası, Bucak, Burdur"}, {"title": "Bucak Yaylası", "summary": "Burdur''un serin ve yeşil yaylalarından biri olan Bucak Yaylası, özellikle yaz aylarında doğa ile baş başa kalmak isteyenler için idealdir. Yemyeşil çam ormanları ve temiz havasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Bucak Yaylası, Bucak, Burdur"}, {"title": "Kestel Kanyonu", "summary": "Bucak ilçe sınırları içinde yer alan Kestel Kanyonu, etkileyici kaya duvarları ve berrak akan suyu ile doğa yürüyüşçülerinin ve fotoğrafçıların uğrak noktasıdır. Kanyon boyunca yapılan yürüyüşler unutulmaz bir deneyim sunar.", "place_query": "Kestel Kanyonu, Bucak, Burdur"}, {"title": "Çamlık Mesire Alanı", "summary": "Bucak merkezine yakın konumdaki Çamlık Mesire Alanı, piknik yapmak ve doğada vakit geçirmek isteyen aileler için popüler bir mekandır. Çam ağaçları arasında kurulu masalar ve yürüyüş yolları ile huzurlu bir ortam sunar.", "place_query": "Çamlık Mesire Alanı, Bucak, Burdur"}, {"title": "Bucak Kent Ormanı", "summary": "Şehir merkezine yürüme mesafesinde bulunan Bucak Kent Ormanı, koşu ve yürüyüş parkurları, çocuk oyun alanları ve piknik alanlarıyla günübirlik ziyaretler için idealdir. Doğayla iç içe bir mola vermek isteyenler için harika bir seçenektir.", "place_query": "Bucak Kent Ormanı, Bucak, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f4a6a894-c392-4d62-988d-db25e5b33820'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çavdır Kaya Mezarları", "summary": "Bölgenin tarihi zenginliğini yansıtan, kayalara oyulmuş antik mezarlardır. Likya dönemine ait bu yapılar, tarih meraklıları için etkileyici bir durak sunar.", "place_query": "Çavdır Kaya Mezarları, Çavdır, Burdur"}, {"title": "Çavdır Yaylası", "summary": "Doğal güzelliği ve serin havasıyla özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır. Yemyeşil doğası ve temiz havasıyla doğa yürüyüşleri için idealdir.", "place_query": "Çavdır Yaylası, Çavdır, Burdur"}, {"title": "Çavdır Göleti", "summary": "Piknik ve dinlenme alanlarıyla çevrili bu gölet, huzurlu bir gün geçirmek isteyenler için popüler bir mekandır. Çevresindeki doğa yürüyüşü parkurları da keşfedilmeye değerdir.", "place_query": "Çavdır Göleti, Çavdır, Burdur"}, {"title": "Söğüt Dağı", "summary": "Bölgenin en yüksek noktalarından biri olan Söğüt Dağı, muhteşem manzarası ve zengin bitki örtüsüyle doğa sporları ve trekking için uygundur.", "place_query": "Söğüt Dağı, Çavdır, Burdur"}, {"title": "Çavdır Merkez Cami", "summary": "İlçe merkezinde yer alan tarihi cami, mimarisi ve huzur veren atmosferiyle dikkat çeker. Ziyaretçiler için kısa bir mola ve ibadet noktasıdır.", "place_query": "Çavdır Merkez Cami, Çavdır, Burdur"}, {"title": "Kibyra Antik Kenti (Gölhisar)", "summary": "Çavdır''a yaklaşık 30 km mesafedeki bu antik kent, etkileyici tiyatrosu ve Medusa mozaiğiyle ünlüdür. Bölge tarihine ilgi duyanlar için mutlaka görülmesi gereken bir yerdir.", "place_query": "Kibyra Antik Kenti, Gölhisar, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4a2385d3-6188-48f1-b0e0-2a0383064753'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çeltikçi Merkez Camii", "summary": "İlçenin tarihi dokusunu yansıtan bu cami, Osmanlı dönemi mimarisinin izlerini taşır ve bölge halkı için önemli bir ibadet ve kültür merkezidir.", "place_query": "Çeltikçi Merkez Camii, Burdur"}, {"title": "Yazır Köyü Kaya Mezarı", "summary": "Antik dönemden kalma bu kaya mezarı, bölgenin zengin tarihine ışık tutan etkileyici bir yapıdır ve doğa ile iç içe bir konumda yer alır.", "place_query": "Yazır Köyü Kaya Mezarı, Çeltikçi, Burdur"}, {"title": "Çeltikçi Göleti", "summary": "Doğal güzelliği ve çevresindeki piknik alanlarıyla bilinen bu gölet, doğa yürüyüşleri ve huzurlu vakit geçirmek isteyenler için ideal bir mekandır.", "place_query": "Çeltikçi Göleti, Burdur"}, {"title": "Karaköy Şelalesi", "summary": "Sarp kayalıklardan dökülen bu şelale, serin suları ve yeşil doğasıyla ziyaretçilerine görsel bir şölen sunar; özellikle yaz aylarında popülerdir.", "place_query": "Karaköy Şelalesi, Çeltikçi, Burdur"}, {"title": "Çeltikçi Eski Değirmen", "summary": "Tarihi bir su değirmeni olan bu yapı, geçmişte bölgenin tarım faaliyetlerine hizmet etmiş ve günümüzde nostaljik bir atmosfer sunmaktadır.", "place_query": "Çeltikçi Eski Değirmen, Burdur"}, {"title": "Burdur Gölü (Çeltikçi Kıyıları)", "summary": "Burdur Gölü''nün Çeltikçi sınırlarındaki kıyıları, kuş gözlemciliği ve sakin bir doğa deneyimi için keşfedilmeyi bekleyen güzel bir noktadır.", "place_query": "Burdur Gölü Çeltikçi Kıyıları, Burdur"}, {"title": "Çeltikçi Yaylası", "summary": "Temiz havası ve geniş otlaklarıyla ünlü bu yayla, doğa severler için kamp ve yürüyüş rotaları sunar; özellikle bahar aylarında canlanan bitki örtüsüyle büyüleyicidir.", "place_query": "Çeltikçi Yaylası, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7ca12450-1efb-4b1f-9fbf-a24538f4fc82'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kibyra Antik Kenti", "summary": "Gölhisar''ın en önemli tarihi hazinesi olan Kibyra, ''Gladyatörler Şehri'' olarak da bilinir. Etkileyici bir medusa mozaiğine ev sahipliği yapan antik kent, Roma dönemine ait stadyumu ve anıtsal yapılarıyla ziyaretçilerini büyüler.", "place_query": "Kibyra Antik Kenti, Gölhisar, Burdur"}, {"title": "Gölhisar Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumdaki bu gölet, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için ideal bir kaçış noktasıdır. Çevresindeki yeşil alanlar ve yürüyüş yollarıyla hafta sonu aile ziyaretlerinin vazgeçilmezidir.", "place_query": "Gölhisar Göleti, Gölhisar, Burdur"}, {"title": "Gölhisar Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, Kibyra Antik Kenti''nden çıkarılan eserleri ve bölgenin arkeolojik geçmişini sergiler. Ziyaretçiler, antik döneme ait heykeller, sikkeler ve günlük yaşam objelerini yakından görebilir.", "place_query": "Gölhisar Müzesi, Gölhisar, Burdur"}, {"title": "Çavdır Yaylası", "summary": "Gölhisar''a bağlı Çavdır köyü yakınlarındaki bu yayla, serin havası ve muhteşem doğa manzarasıyla bilinir. Özellikle yaz aylarında şehir gürültüsünden uzaklaşmak ve doğa yürüyüşü yapmak için tercih edilen bir rotadır.", "place_query": "Çavdır Yaylası, Gölhisar, Burdur"}, {"title": "Hisarardı Köyü Kaya Mezarları", "summary": "Gölhisar''ın tarihi dokusunu yansıtan bu kaya mezarları, Likya ve Roma dönemlerine ait izler taşır. Doğal kaya oluşumları içine oyulmuş bu yapılar, bölgenin antik yerleşim tarihine ışık tutar.", "place_query": "Hisarardı Köyü Kaya Mezarları, Gölhisar, Burdur"}, {"title": "Yusufça Köyü Mağarası", "summary": "Doğal oluşumlu bu mağara, sarkıt ve dikitleriyle dikkat çeker. Henüz tam olarak keşfedilmemiş olsa da macera arayan doğa severler için gizemli bir durak noktasıdır.", "place_query": "Yusufça Köyü Mağarası, Gölhisar, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c639b392-bb46-4b97-ae42-6befb70acf42'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karamanlı Kaya Mezarları", "summary": "İlçe merkezine yakın kayalık alanlarda bulunan ve Likya dönemine ait olduğu düşünülen bu antik mezarlar, tarih meraklıları için etkileyici bir duraktır.", "place_query": "Karamanlı Kaya Mezarları, Karamanlı, Burdur"}, {"title": "İnsuyu Mağarası", "summary": "Burdur merkeze yakın bu mağara, sarkıt ve dikitleriyle ünlü olup, ziyaretçilerine doğal bir yeraltı güzelliği sunar.", "place_query": "İnsuyu Mağarası, Burdur"}, {"title": "Sagalassos Antik Kenti", "summary": "Ağlasun ilçesinde yer alan bu görkemli antik kent, Roma dönemine ait tiyatrosu ve anıtsal çeşmeleriyle bölgenin en önemli tarihi alanlarındandır.", "place_query": "Sagalassos Antik Kenti, Ağlasun, Burdur"}, {"title": "Burdur Gölü", "summary": "Türkiye''nin önemli kuş cennetlerinden biri olan bu tektonik göl, özellikle flamingolar ve su kuşları için eşsiz bir yaşam alanıdır.", "place_query": "Burdur Gölü, Burdur"}, {"title": "Karamanlı Yaylaları", "summary": "İlçe çevresindeki yemyeşil yaylalar, temiz havası ve doğal güzellikleriyle doğa yürüyüşü ve piknik için idealdir.", "place_query": "Karamanlı Yaylaları, Karamanlı, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ee0d8539-6276-419f-bc7a-aef530970d64'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kemer Barajı ve Mesire Alanı", "summary": "Burdur Kemer ilçe merkezine yakın konumdaki bu baraj gölü, piknik alanları ve yürüyüş parkurlarıyla doğa severler için huzurlu bir kaçış noktasıdır. Özellikle bahar ve yaz aylarında kuş gözlemi ve fotoğrafçılık için idealdir.", "place_query": "Kemer Barajı, Kemer, Burdur"}, {"title": "Kemer Merkez Camii (Tarihi Cami)", "summary": "İlçenin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşıyan sade ve etkileyici bir yapıdır. Hem ibadet hem de kültürel miras açısından ziyaret edilmeye değerdir.", "place_query": "Kemer Merkez Camii, Kemer, Burdur"}, {"title": "Sultan Dağları Etekleri", "summary": "Kemer çevresini saran Sultan Dağları''nın etekleri, doğa yürüyüşleri ve kampçılık için elverişli rotalar sunar. Yemyeşil bitki örtüsü ve temiz havasıyla şehir gürültüsünden uzaklaşmak isteyenlerin tercihidir.", "place_query": "Sultan Dağları, Kemer, Burdur"}, {"title": "Kemer Çayı Kenarı Yürüyüş Yolu", "summary": "İlçe merkezinden geçen Kemer Çayı boyunca düzenlenmiş yürüyüş yolu, yerel halkın ve ziyaretçilerin keyifli vakit geçirdiği bir dinlenme alanıdır. Çayın serinletici sesi eşliğinde yapılan kısa bir yürüyüş, bölgenin sakin atmosferini hissettirir.", "place_query": "Kemer Çayı, Kemer, Burdur"}, {"title": "Elmacık Yaylası", "summary": "Kemer ilçesine bağlı Elmacık köyü yakınlarındaki bu yayla, özellikle yaz aylarında serinlemek ve doğayla iç içe olmak isteyenler için popüler bir duraktır. Yöresel lezzetlerin tadılabileceği küçük alabalık tesisleri de bulunur.", "place_query": "Elmacık Yaylası, Kemer, Burdur"}, {"title": "Belen Tepesi Seyir Noktası", "summary": "Kemer''e tepeden bakan Belen Tepesi, ilçe merkezinin ve çevresindeki dağların panoramik manzarasını sunar. Gün batımı saatlerinde özellikle fotoğraf tutkunları için eşsiz bir seyir noktasıdır.", "place_query": "Belen Tepesi Kemer Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c1719351-c927-4075-97cb-3e8311ff30ae'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Burdur Gölü", "summary": "Türkiye''nin önemli kuş cennetlerinden biri olan göl, doğal güzelliği ve zengin biyolojik çeşitliliğiyle ziyaretçilerini büyüler. Özellikle kuş gözlemciliği ve huzurlu bir doğa yürüyüşü için idealdir.", "place_query": "Burdur Gölü, Burdur Merkez"}, {"title": "Burdur Müzesi", "summary": "Bölgenin en zengin arkeoloji ve etnografya koleksiyonlarından birine ev sahipliği yapan müze, Pisidia ve Roma dönemine ait eserleriyle tarih meraklılarının ilgisini çeker. Sagalassos ve Kibyra antik kentlerinden getirilen heykeller müzenin en değerli parçaları arasındadır.", "place_query": "Burdur Müzesi, Burdur Merkez"}, {"title": "Sagalassos Antik Kenti", "summary": "Ağlasun ilçesinde bulunan ve ''Bin Bir Heykel Şehri'' olarak anılan bu antik kent, etkileyici Roma hamamı, tiyatrosu ve Antoninus Çeşmesi ile ünlüdür. UNESCO Dünya Mirası Geçici Listesi''nde yer alan Sagalassos, tarih ve doğa iç içe bir deneyim sunar.", "place_query": "Sagalassos Antik Kenti, Ağlasun, Burdur"}, {"title": "İnsuyu Mağarası", "summary": "Burdur''un 13 km kuzeyinde yer alan bu mağara, sarkıt ve dikitleriyle görülmeye değer doğal bir oluşumdur. İçinde yer alan gölcükler ve yürüyüş yolları sayesinde ziyaretçilere serin ve keyifli bir keşif imkanı tanır.", "place_query": "İnsuyu Mağarası, Burdur Merkez"}, {"title": "Kibyra Antik Kenti", "summary": "Gölhisar ilçesinde bulunan Kibyra, ''Gladyatörler Şehri'' olarak bilinir ve üzerinde Medusa başı kabartması bulunan anıtsal çeşmesiyle dikkat çeker. Antik tiyatrosu ve stadyumu da ziyaretçilerin ilgisini çeken diğer yapılardandır.", "place_query": "Kibyra Antik Kenti, Gölhisar, Burdur"}, {"title": "Burdur Ulu Camii", "summary": "Şehrin merkezinde yer alan bu tarihi cami, Selçuklu ve Osmanlı mimarisinin izlerini taşır. Ahşap işçiliği ve sade iç mekanıyla huzur veren bir atmosfere sahiptir.", "place_query": "Burdur Ulu Camii, Burdur Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4717f12d-3a27-4e1d-aa67-cda23087e6c3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tefenni Gölleri (Karataş Gölü ve diğerleri)", "summary": "Tefenni sınırları içinde yer alan doğal göller, özellikle Karataş Gölü, kuş gözlemciliği ve doğa yürüyüşleri için popülerdir. Sakin atmosferi ve zengin biyolojik çeşitliliği ile doğaseverler için huzurlu bir kaçış noktasıdır.", "place_query": "Karataş Gölü, Tefenni, Burdur"}, {"title": "Tefenni Saat Kulesi", "summary": "İlçe merkezindeki tarihi saat kulesi, Tefenni''nin simge yapılarından biridir. Cumhuriyet dönemi mimarisinin güzel bir örneği olan kule, çevresindeki meydanla birlikte ziyaretçilerin fotoğraf çekmek için uğradığı bir noktadır.", "place_query": "Tefenni Saat Kulesi, Tefenni, Burdur"}, {"title": "Tefenni Kent Ormanı", "summary": "Şehir merkezine yakın konumdaki bu yeşil alan, piknik yapmak ve doğada vakit geçirmek için idealdir. Yürüyüş yolları ve dinlenme alanlarıyla ailelerin sıkça tercih ettiği bir rekreasyon bölgesidir.", "place_query": "Tefenni Kent Ormanı, Tefenni, Burdur"}, {"title": "Hasanpaşa Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Hasanpaşa Camii, mimari detayları ve huzurlu atmosferiyle dikkat çeker. İlçenin kültürel mirasını yansıtan önemli dini yapılarından biridir.", "place_query": "Hasanpaşa Camii, Tefenni, Burdur"}, {"title": "Tefenni Yaylaları (ör. Sazak Yaylası)", "summary": "Tefenni çevresindeki yaylalar, özellikle yaz aylarında serinlemek ve doğal manzaraların tadını çıkarmak için tercih edilir. Yayla evleri ve temiz havasıyla geleneksel bir Anadolu deneyimi sunar.", "place_query": "Sazak Yaylası, Tefenni, Burdur"}, {"title": "Burdur Gölü (Tefenni kıyıları)", "summary": "Burdur Gölü''nün Tefenni ilçesine bakan kıyı şeridi, kuş türleri ve sakin göl manzarasıyla doğa fotoğrafçılığı için uygundur. Özellikle gün batımında eşsiz bir görüntü sunar.", "place_query": "Burdur Gölü, Tefenni, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ac2e0ddf-e531-4a69-92ef-c46748ce990f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Salda Gölü", "summary": "Beyaz kumsalı ve turkuaz rengiyle ''Türkiye''nin Maldivleri'' olarak anılan Salda Gölü, eşsiz doğal güzelliği ve berrak suyuyla ziyaretçilerine huzur dolu bir manzara sunar. Göl kenarında yürüyüş yapabilir, fotoğraf çekebilir ve doğanın tadını çıkarabilirsiniz.", "place_query": "Salda Gölü, Yeşilova, Burdur"}, {"title": "Kızılhisar Kanyonu", "summary": "Yeşilova ilçesinde yer alan bu etkileyici kanyon, yürüyüş ve doğa sporları için idealdir. Kanyonun içinden geçen dere ve yemyeşil bitki örtüsü, doğa tutkunlarına unutulmaz bir deneyim yaşatır.", "place_query": "Kızılhisar Kanyonu, Yeşilova, Burdur"}, {"title": "Yeşilova Merkez Camii", "summary": "Tarihi bir Osmanlı eseri olan bu cami, ilçenin merkezinde yer alır ve mimari detaylarıyla dikkat çeker. Hem ibadet hem de tarihi bir yapıyı görmek isteyenler için önemli bir duraktır.", "place_query": "Yeşilova Merkez Camii, Yeşilova, Burdur"}, {"title": "Karaçalı Şelalesi", "summary": "Yeşilova''ya bağlı Karaçalı köyü yakınlarında bulunan bu şelale, serin suları ve çevresindeki piknik alanlarıyla özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır. Doğa ile baş başa vakit geçirmek için harika bir yerdir.", "place_query": "Karaçalı Şelalesi, Yeşilova, Burdur"}, {"title": "Yakaören Göleti", "summary": "Yeşilova''nın Yakaören köyünde bulunan bu gölet, çevresindeki yeşil alanlar ve temiz havasıyla piknik ve doğa yürüyüşü için idealdir. Gölet manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Yakaören Göleti, Yeşilova, Burdur"}, {"title": "Harmandalı Etnografya Müzesi", "summary": "Yeşilova''nın Harmandalı köyünde yer alan bu küçük müze, yöresel kıyafetler, tarım aletleri ve günlük yaşam objeleriyle bölgenin kültürel mirasını sergiler. Geçmişe yolculuk yapmak isteyenler için keyifli bir duraktır.", "place_query": "Harmandalı Etnografya Müzesi, Yeşilova, Burdur"}, {"title": "Başpınar Tabiat Parkı", "summary": "Salda Gölü''nün hemen yanında bulunan bu tabiat parkı, zengin bitki örtüsü ve yürüyüş parkurlarıyla doğaseverler için ideal bir alandır. Piknik yapabilir, göl manzarası eşliğinde dinlenebilirsiniz.", "place_query": "Başpınar Tabiat Parkı, Yeşilova, Burdur"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '68aaaad7-e104-4051-90e2-69824022af7e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Büyükorhan Merkez Camii", "summary": "İlçe merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisini yansıtan sade ve huzurlu bir yapıdır. Ziyaretçiler için manevi bir durak ve ilçenin tarihi dokusunu görmek için ideal bir noktadır.", "place_query": "Büyükorhan Merkez Camii, Bursa"}, {"title": "Büyükorhan Şelalesi", "summary": "Doğa ile iç içe bir kaçamak arayanlar için popüler bir mesire alanıdır. Şelalenin serin suları ve çevresindeki yeşil alanlar, piknik ve yürüyüş için mükemmel bir ortam sunar.", "place_query": "Büyükorhan Şelalesi, Bursa"}, {"title": "Dereköy Yaylası", "summary": "Büyükorhan''ın en bilinen yaylalarından biri olan Dereköy, temiz havası ve muhteşem manzarasıyla ünlüdür. Özellikle yaz aylarında doğa yürüyüşleri ve kamp için sıkça tercih edilir.", "place_query": "Dereköy Yaylası, Büyükorhan, Bursa"}, {"title": "Karaağız Göleti", "summary": "Huzur veren bir doğa harikası olan gölet, balık tutma ve piknik yapma imkanı sunar. Çevresindeki zengin bitki örtüsü ve kuş sesleri eşliğinde sakin bir gün geçirmek için idealdir.", "place_query": "Karaağız Göleti, Büyükorhan, Bursa"}, {"title": "Büyükorhan Tarihi Çarşı", "summary": "İlçenin eski ticaret merkezi olan bu çarşı, yöresel ürünler ve el sanatlarını keşfetmek için harika bir yerdir. Dar sokakları ve tarihi dükkanlarıyla ziyaretçilere nostaljik bir alışveriş deneyimi yaşatır.", "place_query": "Büyükorhan Tarihi Çarşı, Bursa"}, {"title": "Süleymaniye Köyü Kaya Mezarları", "summary": "Bölgedeki tarihi kalıntılar arasında yer alan kaya mezarları, antik döneme ışık tutan önemli bir arkeolojik alandır. Tarih meraklıları için keşfedilmeyi bekleyen gizemli bir duraktır.", "place_query": "Süleymaniye Köyü Kaya Mezarları, Büyükorhan, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e6f48574-72b8-49b2-8f09-41ac805eb95a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gemlik Sahili ve İskele Meydanı", "summary": "Gemlik''in kalbi sayılan sahil şeridi, yürüyüş yolu, kafeleri ve deniz manzarasıyla hem yerli halkın hem de ziyaretçilerin uğrak noktasıdır. Özellikle gün batımında keyifli bir gezinti yapabilir, meşhur Gemlik zeytinini tadabilirsiniz.", "place_query": "Gemlik Sahili, Gemlik, Bursa"}, {"title": "Küçük Kumla Plajı", "summary": "Gemlik''e bağlı Küçük Kumla, tertemiz denizi ve ince kumlu plajıyla yaz aylarında en çok tercih edilen yerlerden biridir. Aileler için sakin ve güvenli bir yüzme alanı sunar.", "place_query": "Küçük Kumla Plajı, Gemlik, Bursa"}, {"title": "Gemlik Zeytin ve Zeytinyağı Müzesi", "summary": "Bölgenin zeytincilik kültürünü tanıtan bu müze, tarihi zeytinyağı işliklerini ve üretim araçlarını sergiler. Gemlik zeytininin hikayesini öğrenmek isteyenler için eşsiz bir duraktır.", "place_query": "Gemlik Zeytin ve Zeytinyağı Müzesi, Gemlik, Bursa"}, {"title": "Gemsaz Tabyası (Gemlik Askeri Tarih Müzesi)", "summary": "Osmanlı döneminden kalma bu tarihi tabya, restore edilerek askeri tarih müzesine dönüştürülmüştür. Deniz kenarındaki konumu ve sergilenen objelerle tarih meraklıları için ilgi çekicidir.", "place_query": "Gemsaz Tabyası, Gemlik, Bursa"}, {"title": "Kumsaz Plajı", "summary": "Gemlik''in popüler plajlarından biri olan Kumsaz, uzun kumsalı ve mavi bayraklı temiz deniziyle bilinir. Çevresindeki tesisler sayesinde günübirlik deniz keyfi için idealdir.", "place_query": "Kumsaz Plajı, Gemlik, Bursa"}, {"title": "Armutlu Kaplıcaları (Gemlik yakını)", "summary": "Gemlik sınırları içinde olmamakla birlikte çok yakındaki Armutlu, termal suları ve doğal güzellikleriyle ünlüdür. Şifalı suları ve huzurlu ortamıyla hafta sonu kaçamakları için tercih edilir.", "place_query": "Armutlu Kaplıcaları, Armutlu, Yalova"}, {"title": "Narlı Sahil", "summary": "Gemlik merkeze yakın, sakin bir sahil mahallesi olan Narlı, özellikle yaz aylarında denize girmek ve huzurlu bir ortamda vakit geçirmek isteyenler tarafından keşfedilir.", "place_query": "Narlı Sahil, Gemlik, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f35db9dd-e2b2-4664-99f1-74b1af43c49b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gürsu Merkez Camii", "summary": "Gürsu''nun merkezinde yer alan bu cami, ilçenin en bilinen dini yapılarından biridir. Ziyaretçiler, sade mimarisi ve huzurlu atmosferiyle ilçe merkezinde görebilecekleri önemli bir noktadır.", "place_query": "Gürsu Merkez Camii, Gürsu, Bursa"}, {"title": "Gürsu Belediyesi Kültür Parkı", "summary": "Aileler ve doğa severler için ideal olan bu park, yürüyüş yolları, yeşil alanları ve çocuk oyun alanlarıyla ilçede dinlenmek için en popüler noktalardan biridir.", "place_query": "Gürsu Belediyesi Kültür Parkı, Gürsu, Bursa"}, {"title": "İğdir Yaylası", "summary": "Gürsu''ya bağlı İğdir köyü yakınlarında bulunan bu yayla, doğal güzelliği ve temiz havasıyla piknik ve doğa yürüyüşü için sıkça tercih edilir. Bursa Ovası manzarası sunar.", "place_query": "İğdir Yaylası, Gürsu, Bursa"}, {"title": "Kazıklı Kaya (Kazıklı Kaya Tabiat Parkı)", "summary": "Gürsu sınırlarına yakın olan bu tabiat parkı, eşsiz kaya oluşumları ve zengin bitki örtüsüyle doğa tutkunlarının ilgisini çeker. Kamp ve tırmanış aktiviteleri için uygundur.", "place_query": "Kazıklı Kaya Tabiat Parkı, Gürsu, Bursa"}, {"title": "Gürsu Kent Meydanı", "summary": "İlçenin sosyal yaşamının kalbi olan meydan, çevresindeki kafe ve restoranlarla birlikte yerel halkın buluşma noktasıdır. Yakınındaki tarihi çarşı da gezilebilir.", "place_query": "Gürsu Kent Meydanı, Gürsu, Bursa"}, {"title": "Hasanağa Barajı Mesire Alanı", "summary": "Gürsu ilçe merkezine kısa bir mesafede bulunan bu mesire alanı, baraj gölü kenarında piknik yapma ve doğayla iç içe vakit geçirme imkanı sunar.", "place_query": "Hasanağa Barajı Mesire Alanı, Gürsu, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f26c3ab-0609-438c-938f-cf1c03947c92'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Harmancık Şelalesi", "summary": "İlçe merkezine yakın, doğa içinde huzurlu bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek ve piknik yapmak için idealdir.", "place_query": "Harmancık Şelalesi, Harmancık, Bursa"}, {"title": "Kocadere Göleti", "summary": "Doğal güzelliği ve çevresindeki yeşil alanlarla dikkat çeken bir mesire yeridir. Balık tutma ve doğa yürüyüşü için popülerdir.", "place_query": "Kocadere Göleti, Harmancık, Bursa"}, {"title": "Harmancık Merkez Camii", "summary": "İlçenin tarihi simgelerinden biri olan cami, Osmanlı mimarisinin sade ve etkileyici örneklerindendir. Hem ibadet hem de tarihi doku için ziyaret edilir.", "place_query": "Harmancık Merkez Camii, Harmancık, Bursa"}, {"title": "Çit Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü yayla, kamp ve doğa sporları tutkunları için harika bir rotadır. Manzarası fotoğrafçıları cezbeder.", "place_query": "Çit Yaylası, Harmancık, Bursa"}, {"title": "Keles Yolu Üzerindeki Tarihi Çeşmeler", "summary": "İlçe genelinde dağınık halde bulunan Osmanlı dönemi çeşmeleri, tarihi yolculuk yapmak isteyenler için keşfedilmeyi bekleyen duraklardır.", "place_query": "Harmancık tarihi çeşmeler, Bursa"}, {"title": "Melen Çayı Vadisi", "summary": "Doğa yürüyüşü ve kuş gözlemi için elverişli olan vadi, sakin atmosferiyle şehir gürültüsünden uzaklaşmak isteyenlerin tercihidir.", "place_query": "Melen Çayı Vadisi, Harmancık, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f00f7bf9-c70a-40d2-abc3-d22e89616e22'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Oylat Mağarası", "summary": "Bursa''nın İnegöl ilçesinde yer alan Oylat Mağarası, sarkıt ve dikitleriyle ünlü doğal bir oluşumdur. Astım hastalarına iyi geldiği düşünülen nemli havası ve etkileyici görüntüsüyle yerli turistlerin sıkça ziyaret ettiği bir noktadır.", "place_query": "Oylat Mağarası, İnegöl, Bursa"}, {"title": "Oylat Şelalesi", "summary": "Oylat Mağarası''nın hemen yakınında bulunan Oylat Şelalesi, yemyeşil doğası ve serin sularıyla piknik ve doğa yürüyüşü için idealdir. Özellikle yaz aylarında şehir kalabalığından kaçmak isteyenlerin uğrak noktasıdır.", "place_query": "Oylat Şelalesi, İnegöl, Bursa"}, {"title": "Babadağ (İnegöl)", "summary": "İnegöl''ün simgesi haline gelen Babadağ, kış aylarında kayak merkezi olarak hizmet verirken yazın da doğa yürüyüşleri ve kamp için tercih edilir. Zirvesinden İnegöl Ovası''nın panoramik manzarası izlenebilir.", "place_query": "Babadağ Kayak Merkezi, İnegöl, Bursa"}, {"title": "İnegöl Kent Müzesi", "summary": "İnegöl''ün tarihini, kültürünü ve ünlü mobilya sektörünün gelişimini anlatan Kent Müzesi, şehir merkezinde ziyaretçilerini bekliyor. Hem yetişkinler hem de çocuklar için ilgi çekici sergilere ev sahipliği yapmaktadır.", "place_query": "İnegöl Kent Müzesi, İnegöl, Bursa"}, {"title": "İshakpaşa Camii ve Külliyesi", "summary": "15. yüzyıldan kalma tarihi İshakpaşa Camii ve Külliyesi, İnegöl''ün en önemli Osmanlı dönemi yapılarındandır. Etkileyici mimarisi ve avlusundaki tarihi atmosferi ile şehir merkezinde mutlaka görülmesi gereken bir noktadır.", "place_query": "İshakpaşa Camii, İnegöl, Bursa"}, {"title": "Hilmiye Köyü (Karagöz ve Hacivat Evi)", "summary": "İnegöl''ün Hilmiye Köyü''nde bulunan bu müze-ev, geleneksel gölge oyunu kahramanları Karagöz ve Hacivat''ın anısına yapılmıştır. Köy yaşamını ve bu kültürel mirası yakından tanımak için güzel bir duraktır.", "place_query": "Hilmiye Köyü Karagöz Hacivat Evi, İnegöl, Bursa"}, {"title": "Cerrah Kaynak Suyu Mesire Alanı", "summary": "Doğal kaynak suyu ve geniş piknik alanlarıyla ünlü Cerrah Mesire Alanı, İnegöl''e bağlı Cerrah Mahallesi''nde yer alır. Şehre yakınlığı ve tertemiz havasıyla hafta sonu kaçamakları için popüler bir mekândır.", "place_query": "Cerrah Mesire Alanı, İnegöl, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8e00de2e-88d4-49ab-a9e8-86378a7b2c49'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İznik Gölü", "summary": "Türkiye''nin beşinci büyük gölü olan İznik Gölü, muhteşem manzarası ve kuş gözlemciliği için ideal doğal alanıyla ziyaretçileri büyüler. Göl çevresinde piknik yapabilir, bisiklet sürebilir veya gün batımında huzurlu bir yürüyüşün tadını çıkarabilirsiniz.", "place_query": "İznik Gölü, Bursa"}, {"title": "Ayasofya (İznik)", "summary": "Bizans döneminden kalma bu tarihi kilise, Osmanlı döneminde camiye çevrilmiş ve günümüzde müze olarak hizmet vermektedir. İznik''in en önemli sembollerinden biri olan yapı, etkileyici mozaikleri ve fresk kalıntılarıyla dikkat çeker.", "place_query": "Ayasofya Müzesi, İznik, Bursa"}, {"title": "Yeşil Cami (İznik)", "summary": "Osmanlı mimarisinin erken dönem örneklerinden olan Yeşil Cami, adını çinilerinden alır. Zarif işçiliği ve huzur veren avlusuyla şehrin en çok ziyaret edilen tarihi yapılarındandır.", "place_query": "Yeşil Cami, İznik, Bursa"}, {"title": "İznik Roma Tiyatrosu", "summary": "Antik çağdan günümüze ulaşan bu görkemli tiyatro, Helenistik ve Roma dönemlerine ışık tutar. Kazı çalışmaları devam eden alan, tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "İznik Roma Tiyatrosu, Bursa"}, {"title": "Süleyman Paşa Medresesi", "summary": "14. yüzyılda inşa edilen bu medrese, İznik''in en eski Osmanlı yapılarından biridir. Günümüzde İznik Müzesi olarak kullanılan yapı, bölgenin arkeolojik ve etnografik eserlerine ev sahipliği yapar.", "place_query": "Süleyman Paşa Medresesi, İznik, Bursa"}, {"title": "İznik Surları", "summary": "Antik çağlardan kalma bu surlar, şehri çevreleyen 4.5 kilometrelik uzunluğuyla etkileyicidir. Lefke Kapısı, İstanbul Kapısı ve Yenişehir Kapısı gibi tarihi girişleriyle ziyaretçilere geçmişte bir yolculuk sunar.", "place_query": "İznik Surları, Bursa"}, {"title": "Çini Atölyeleri (İznik Çinisi)", "summary": "İznik, dünyaca ünlü çini sanatının merkezidir. Şehirdeki çini atölyelerini ziyaret ederek geleneksel el işçiliğini yerinde görebilir, kendiniz de çini yapma deneyimi yaşayabilirsiniz.", "place_query": "İznik Çini Atölyeleri, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'de6382aa-29fc-4e1c-a9fa-e3dd39dd6893'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Longoz Ormanları (Karacabey Longozu)", "summary": "Bursa''nın en önemli doğal miraslarından biri olan Karacabey Longozu, su basar ormanları ve eşsiz ekosistemiyle doğa tutkunları için ideal bir yerdir. Yılın belirli dönemlerinde su altında kalan ağaçların oluşturduğu mistik manzara, ziyaretçilere adeta bir masal diyarında yürüyüş yapma hissi verir.", "place_query": "Karacabey Longozu, Karacabey, Bursa"}, {"title": "Ulubat Gölü", "summary": "Türkiye''nin önemli sulak alanlarından biri olan Ulubat Gölü, kuş gözlemciliği ve doğa fotoğrafçılığı için popüler bir duraktır. Göl çevresindeki balıkçı lokantaları ise yöresel lezzetleri tatmak için güzel bir fırsat sunar.", "place_query": "Ulubat Gölü, Karacabey, Bursa"}, {"title": "Karacabey Merkez Camii ve Külliyesi", "summary": "Osmanlı dönemine ait tarihi bir yapı olan Karacabey Merkez Camii, zarif mimarisi ve avlusundaki tarihi çınar ağacıyla dikkat çeker. İlçenin merkezinde yer alan bu külliye, tarih ve mimari meraklıları için önemli bir duraktır.", "place_query": "Karacabey Merkez Camii, Karacabey, Bursa"}, {"title": "Akköy Göleti ve Mesire Alanı", "summary": "Doğayla iç içe bir gün geçirmek isteyenler için ideal olan Akköy Göleti, piknik alanları ve yürüyüş parkurlarıyla ailelerin sıkça tercih ettiği bir mesire yeridir. Gölet çevresinde huzurlu bir atmosferde vakit geçirebilirsiniz.", "place_query": "Akköy Göleti, Karacabey, Bursa"}, {"title": "Malkara Kalesi", "summary": "Tarihi Bizans dönemine kadar uzanan Malkara Kalesi, Karacabey''in kırsalında keşfedilmeyi bekleyen bir yapıdır. Kalıntıları ve çevresindeki doğal manzara, tarih ve doğa yürüyüşü sevenler için keyifli bir rota oluşturur.", "place_query": "Malkara Kalesi, Karacabey, Bursa"}, {"title": "Karacabey Boğazı", "summary": "İlçenin en etkileyici doğal oluşumlarından biri olan Karacabey Boğazı, derin vadileri ve yemyeşil doğasıyla trekking ve doğa sporları için idealdir. Boğaz boyunca yapacağınız bir yürüyüş, size eşsiz manzaralar sunacaktır.", "place_query": "Karacabey Boğazı, Karacabey, Bursa"}, {"title": "Susurluk Şelalesi", "summary": "Karacabey sınırlarına yakın olan Susurluk Şelalesi, özellikle yaz aylarında serinlemek ve doğanın tadını çıkarmak için sıkça ziyaret edilir. Şelalenin çevresindeki piknik alanları, hafta sonu kaçamakları için popüler bir noktadır.", "place_query": "Susurluk Şelalesi, Susurluk, Balıkesir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c5926111-8031-4df1-8b48-a75d947b1ad7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölcük Tabiat Parkı", "summary": "Bursa''nın en popüler doğal alanlarından biri olan Gölcük, Keles sınırları içinde yer alır. Gölet çevresinde yürüyüş yapabilir, piknik alanlarında dinlenebilir ve eşsiz doğa manzarasının tadını çıkarabilirsiniz.", "place_query": "Gölcük Tabiat Parkı, Keles, Bursa"}, {"title": "Keles Yaylaları (Sorgun Yaylası, Gelemiç Yaylası)", "summary": "Keles, yemyeşil yaylalarıyla ünlüdür; özellikle Sorgun ve Gelemiç yaylaları, serin havası ve doğal güzellikleriyle ziyaretçileri cezbeder. Yayla evlerinde konaklayabilir, doğa yürüyüşleri yapabilirsiniz.", "place_query": "Sorgun Yaylası, Keles, Bursa"}, {"title": "Keles Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle bahar ve yaz aylarında coşkun akışıyla görsel bir şölen sunar. Çevresindeki mesire alanı, piknik ve doğa gezintisi için idealdir.", "place_query": "Keles Şelalesi, Keles, Bursa"}, {"title": "Keles Tarihi Evleri", "summary": "Keles''in eski mahallelerinde bulunan geleneksel Osmanlı dönemi ahşap evleri, sivil mimarinin güzel örneklerindendir. Dar sokaklarda yürüyerek tarihi atmosferi hissedebilirsiniz.", "place_query": "Keles Tarihi Evleri, Keles, Bursa"}, {"title": "Harmancık Göleti", "summary": "Keles ilçe sınırlarına yakın olan bu gölet, doğa ile iç içe huzurlu bir ortam arayanlar için idealdir. Çevresinde yürüyüş yapabilir ve manzaranın keyfini çıkarabilirsiniz.", "place_query": "Harmancık Göleti, Keles, Bursa"}, {"title": "Uludağ Milli Parkı (Keles Girişi)", "summary": "Uludağ''ın güney yamaçları Keles sınırları içinde yer alır ve buradan milli parka farklı bir rotadan ulaşabilirsiniz. Doğa yürüyüşleri, kamp ve yaban hayatı gözlemi için elverişlidir.", "place_query": "Uludağ Milli Parkı Keles girişi, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '75dedfc0-ef18-4cb9-a006-fd0c0784d86b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mudanya Sahili ve Mütareke Meydanı", "summary": "Mudanya''nın kalbi sayılan bu sahil şeridi, deniz manzarası, kafeleri ve yürüyüş yollarıyla huzurlu bir gezinti sunar. Meydanda bulunan Mütareke Evi, Mudanya Ateşkes Antlaşması''nın imzalandığı tarihi yapıdır.", "place_query": "Mudanya Mütareke Meydanı, Mudanya, Bursa"}, {"title": "Mudanya Mütareke Evi", "summary": "Milli Mücadele döneminin önemli bir simgesi olan bu tarihi bina, 11 Ekim 1922''de imzalanan Mudanya Ateşkes Antlaşması''na ev sahipliği yapmıştır. Müze olarak ziyarete açık olan ev, dönemin atmosferini yansıtan eşyalarıyla dikkat çeker.", "place_query": "Mudanya Mütareke Evi Müzesi, Mudanya, Bursa"}, {"title": "Tirilye (Zeytinbağı)", "summary": "Mudanya''ya bağlı bu tarihi Rum köyü, taş evleri, dar sokakları ve zeytinlikleriyle ünlüdür. Tarihi kiliseleri ve şirin restoranlarıyla huzurlu bir gün geçirmek için idealdir.", "place_query": "Tirilye, Mudanya, Bursa"}, {"title": "Kumyaka (Siglacık) Köyü", "summary": "Mudanya''nın en güzel sahil köylerinden biri olan Kumyaka, sakin plajı ve doğal güzellikleriyle öne çıkar. Ahşap yalıları ve tertemiz denizi sayesinde yaz aylarında yoğun ilgi görür.", "place_query": "Kumyaka Köyü, Mudanya, Bursa"}, {"title": "Mudanya Arkeoloji Müzesi", "summary": "Bölgedeki antik yerleşimlerden çıkarılan eserlerin sergilendiği müze, özellikle Myrleia antik kenti buluntularıyla tarih meraklılarının ilgisini çeker. Küçük ama etkileyici koleksiyonuyla görülmeye değerdir.", "place_query": "Mudanya Arkeoloji Müzesi, Mudanya, Bursa"}, {"title": "Güzelyalı Sahili", "summary": "Mudanya merkeze yakın bu sahil bandı, geniş yürüyüş yolları, bisiklet parkuru ve denize sıfır çay bahçeleriyle popülerdir. Özellikle gün batımında eşsiz bir manzara sunar.", "place_query": "Güzelyalı Sahili, Mudanya, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '206d1ab7-d997-4e1a-a512-eb98f6cda045'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mustafakemalpaşa Şelalesi", "summary": "İlçe merkezine yaklaşık 20 km uzaklıkta, doğa ile iç içe bir alanda yer alan bu şelale, özellikle yaz aylarında serinlemek ve piknik yapmak için popüler bir durak. Çevresindeki yeşil alanlar ve akan suyun sesi huzurlu bir atmosfer sunar.", "place_query": "Mustafakemalpaşa Şelalesi, Bursa"}, {"title": "Sırmaköy Mağarası", "summary": "Bölgenin önemli doğal oluşumlarından biri olan Sırmaköy Mağarası, sarkıt ve dikitleriyle ziyaretçileri büyüler. Mağara içindeki yürüyüş parkuru, doğa ve macera severler için keşfedilmeyi bekleyen bir rotadır.", "place_query": "Sırmaköy Mağarası, Mustafakemalpaşa, Bursa"}, {"title": "Tatkavaklı Göleti ve Mesire Alanı", "summary": "Tatkavaklı köyü yakınlarındaki bu gölet, çam ormanlarıyla çevrili sakin bir kaçış noktasıdır. Piknik masaları, yürüyüş yolları ve olta balıkçılığı imkanı ile aileler ve doğa tutkunları için idealdir.", "place_query": "Tatkavaklı Göleti, Mustafakemalpaşa, Bursa"}, {"title": "Mustafakemalpaşa Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, 19. yüzyıl sonlarında inşa edilmiş olup Mustafakemalpaşa''nın simge yapılarından biridir. Çevresindeki meydan, alışveriş ve dinlenme alanlarıyla şehir turu için iyi bir başlangıç noktasıdır.", "place_query": "Mustafakemalpaşa Saat Kulesi, Bursa"}, {"title": "Köybaşı (Değirmenci) Köprüsü", "summary": "Tarihi Osmanlı dönemine uzanan taş köprü, ilçenin kültürel mirasını yansıtır. Köprünün etrafındaki dere ve yeşil alanlar, fotoğrafçılar ve tarih meraklıları için güzel bir durak oluşturur.", "place_query": "Köybaşı Köprüsü, Mustafakemalpaşa, Bursa"}, {"title": "Yeşilyayla Yaylası", "summary": "Mustafakemalpaşa''ya bağlı Yeşilyayla köyü sınırlarındaki bu yayla, temiz havası ve geniş çayırlarıyla ünlüdür. Özellikle yaz aylarında doğa yürüyüşü yapmak ve kamp kurmak isteyenler için popüler bir kaçış noktasıdır.", "place_query": "Yeşilyayla Yaylası, Mustafakemalpaşa, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ee6abbf6-eca4-482d-81cf-a9f4317780c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Botanik Parkı", "summary": "Bursa''nın en büyük ve en popüler parklarından biri olan Botanik Parkı, yürüyüş yolları, göletleri, piknik alanları ve rengarenk çiçek bahçeleriyle doğayla iç içe huzurlu bir kaçış noktasıdır. Aileler ve doğa severler için ideal bir mekandır.", "place_query": "Bursa Botanik Parkı, Nilüfer, Bursa"}, {"title": "Balat Atatürk Ormanı", "summary": "Nilüfer''in Gölyazı bölgesine yakın bu geniş ormanlık alan, özellikle hafta sonları piknikçiler ve doğa yürüyüşçüleri tarafından tercih edilir. Temiz havası ve yeşil dokusuyla şehir gürültüsünden uzaklaşmak için harika bir yerdir.", "place_query": "Balat Atatürk Ormanı, Nilüfer, Bursa"}, {"title": "Gölyazı (Apolyont Gölü Kıyısı)", "summary": "Tarihi Rum evleri ve dar sokaklarıyla ünlü Gölyazı, Apolyont Gölü kıyısında yer alan şirin bir balıkçı kasabasıdır. Göl manzarası eşliğinde balık keyfi yapmak ve tarihi atmosferi hissetmek için sıkça ziyaret edilir.", "place_query": "Gölyazı, Nilüfer, Bursa"}, {"title": "Nilüfer Belediyesi Barış Manço Kültür Merkezi", "summary": "Sanat ve kültür etkinliklerinin kalbi olan bu merkez, tiyatro oyunları, konserler ve sergilere ev sahipliği yapar. Modern mimarisi ve geniş etkinlik takvimiyle bölgenin önemli bir kültür noktasıdır.", "place_query": "Barış Manço Kültür Merkezi, Nilüfer, Bursa"}, {"title": "Misi (Gümüştepe) Köyü", "summary": "Tarihi dokusunu koruyan Misi Köyü, taş evleri, şelalesi ve doğal güzellikleriyle ünlüdür. Özellikle Misi Şelalesi çevresinde yürüyüş yapabilir, köy kafelerinde organik ürünler tadabilirsiniz.", "place_query": "Misi Köyü (Gümüştepe), Nilüfer, Bursa"}, {"title": "Yörükköyü", "summary": "Bursa''nın en eski yerleşimlerinden biri olan Yörükköyü, tarihi ahşap evleri ve Arnavut kaldırımlı sokaklarıyla ziyaretçilerini geçmişe götürür. Köy meydanındaki çınar ağacı altında çay içmek keyiflidir.", "place_query": "Yörükköyü, Nilüfer, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ad74bb1d-5175-4aa1-9224-38ec41a93b97'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sultan Dağı", "summary": "Orhaneli''nin en yüksek noktalarından biri olan Sultan Dağı, doğa yürüyüşleri ve eşsiz manzarasıyla ziyaretçilerini cezbeder. Temiz havası ve zengin bitki örtüsüyle doğaseverler için ideal bir rotadır.", "place_query": "Sultan Dağı, Orhaneli, Bursa"}, {"title": "Orhaneli Barajı", "summary": "Bölgenin en önemli su kaynaklarından biri olan Orhaneli Barajı, çevresindeki piknik alanları ve huzurlu atmosferiyle aileler için popüler bir dinlenme noktasıdır. Balık tutma ve doğa fotoğrafçılığı için de sıkça tercih edilir.", "place_query": "Orhaneli Barajı, Orhaneli, Bursa"}, {"title": "Küreklidere Şelalesi", "summary": "Yemyeşil doğanın içinde gizlenmiş bu şelale, serinlemek ve doğanın sesini dinlemek isteyenler için harika bir kaçış noktasıdır. Özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Küreklidere Şelalesi, Orhaneli, Bursa"}, {"title": "Orhaneli Merkez Camii", "summary": "Tarihi dokusuyla dikkat çeken Orhaneli Merkez Camii, ilçenin simge yapılarından biridir. Osmanlı mimarisinin izlerini taşıyan cami, hem ibadet hem de tarihi bir ziyaret noktasıdır.", "place_query": "Orhaneli Merkez Camii, Orhaneli, Bursa"}, {"title": "Sorgun Yaylası", "summary": "Yüksek rakımı ve serin havasıyla yaz aylarında sıkça ziyaret edilen Sorgun Yaylası, kampçılık ve doğa yürüyüşü için idealdir. Yemyeşil çayırları ve temiz havasıyla şehir hayatından kaçış sunar.", "place_query": "Sorgun Yaylası, Orhaneli, Bursa"}, {"title": "Göynükbelen Köyü", "summary": "Geleneksel köy yaşamını deneyimlemek isteyenler için Göynükbelen Köyü, taş evleri ve doğal güzellikleriyle otantik bir atmosfer sunar. Köy kahvaltıları ve yerel lezzetler de ziyaretçileri cezbeder.", "place_query": "Göynükbelen Köyü, Orhaneli, Bursa"}, {"title": "Orhaneli Etnografya Müzesi", "summary": "İlçenin kültürel mirasını sergileyen bu küçük müze, yöresel kıyafetler, el sanatları ve tarihi objelerle ziyaretçilere geçmişe yolculuk yapma fırsatı verir.", "place_query": "Orhaneli Etnografya Müzesi, Orhaneli, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '508a4141-9cd3-4e11-adc8-ab3dc67875fb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İznik Gölü", "summary": "Bursa''nın en büyük doğal gölü olan İznik Gölü, Orhangazi sınırları içinde yer alır. Kuş gözlemi, piknik ve doğa yürüyüşleri için ideal bir alandır.", "place_query": "İznik Gölü, Orhangazi, Bursa"}, {"title": "Orhangazi Tarihi Çarşı", "summary": "Osmanlı döneminden kalma tarihi çarşı, yöresel ürünler ve el sanatları satan dükkanlarıyla ziyaretçilerine keyifli bir alışveriş deneyimi sunar.", "place_query": "Orhangazi Tarihi Çarşı, Bursa"}, {"title": "Keramet Kaplıcaları", "summary": "Şifalı termal sularıyla ünlü Keramet Kaplıcaları, romatizma ve cilt hastalıklarına iyi geldiği bilinen doğal bir şifa kaynağıdır.", "place_query": "Keramet Kaplıcaları, Orhangazi, Bursa"}, {"title": "Göl Orhangazi Parkı", "summary": "İznik Gölü kıyısında yer alan bu park, yürüyüş yolları, çocuk oyun alanları ve göl manzarasıyla aileler için huzurlu bir dinlenme noktasıdır.", "place_query": "Göl Orhangazi Parkı, Orhangazi, Bursa"}, {"title": "Sölöz Göleti", "summary": "Doğal güzelliği ve sakin atmosferiyle bilinen Sölöz Göleti, piknik ve balık tutma gibi aktiviteler için sıkça tercih edilir.", "place_query": "Sölöz Göleti, Orhangazi, Bursa"}, {"title": "Sarıalan Şelalesi", "summary": "Yemyeşil doğa içinde yer alan Sarıalan Şelalesi, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Sarıalan Şelalesi, Orhangazi, Bursa"}, {"title": "Orhangazi Kent Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını sergileyen bu müze, Osmanlı''dan günümüze uzanan hikayeyi ziyaretçilerine sunar.", "place_query": "Orhangazi Kent Müzesi, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1f2b09b6-95cd-4a63-aafd-2dd4c663ccce'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ulu Cami", "summary": "Bursa''nın simgesi olan bu görkemli cami, 20 kubbesi ve Selçuklu-Osmanlı mimarisinin en güzel örneklerinden biridir. İçerisindeki devasa şadırvan ve duvarlardaki hat sanatı eserleri ziyaretçileri büyüler.", "place_query": "Ulu Cami, Osmangazi, Bursa"}, {"title": "Bursa Kalesi ve Surları", "summary": "Şehrin tarihi çekirdeğini oluşturan kale, Osmangazi ilçesinde yer alır ve Bizans döneminden Osmanlı''ya uzanan bir geçmiş sunar. Surlar boyunca yürüyerek panoramik Bursa manzarası izlenebilir.", "place_query": "Bursa Kalesi, Osmangazi, Bursa"}, {"title": "Koza Han", "summary": "15. yüzyıldan kalma bu tarihi han, ipek ticaretinin kalbi olarak ünlüdür. Avlusundaki çay bahçesinde dinlenebilir ve han içindeki dükkanlardan gerçek Bursa ipeği satın alabilirsiniz.", "place_query": "Koza Han, Osmangazi, Bursa"}, {"title": "Tarihi Çarşılar (Kapalıçarşı ve Pirinç Hanı)", "summary": "Osmangazi''nin kalbindeki bu çarşılar, yüzyıllardır esnaf kültürünü yaşatır. Bursa bıçağı, şeftali şekeri ve ipek ürünleri gibi yerel lezzetleri ve hediyelikleri burada bulabilirsiniz.", "place_query": "Tarihi Çarşılar, Osmangazi, Bursa"}, {"title": "Yeşil Türbe ve Yeşil Cami", "summary": "Çelebi Mehmed''in türbesi olan Yeşil Türbe, çinileriyle ünlüdür ve Osmanlı erken dönem mimarisinin en zarif örneklerindendir. Hemen yanındaki Yeşil Cami ile birlikte ziyaret edilir.", "place_query": "Yeşil Türbe, Osmangazi, Bursa"}, {"title": "Bursa Teleferik (Telesiyej) ve Uludağ Milli Parkı", "summary": "Osmangazi''den başlayan teleferik hattı ile Uludağ''ın eteklerine ulaşabilirsiniz. Yazın doğa yürüyüşü, kışın ise kayak için popüler bir başlangıç noktasıdır.", "place_query": "Bursa Teleferik, Osmangazi, Bursa"}, {"title": "Emir Sultan Camii ve Türbesi", "summary": "Osmanlı döneminin önemli velilerinden Emir Sultan''a ait olan bu külliyenin bahçesi huzur vericidir. Cami ve türbe, özellikle cuma günleri yoğun ziyaretçi akınına uğrar.", "place_query": "Emir Sultan Camii, Osmangazi, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a0a5349e-520a-44fa-8a07-88196c28e98d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yenişehir Şehir Müzesi", "summary": "Bursa''nın tarih kokan ilçesi Yenişehir''in kültürel mirasını sergileyen bu müze, Osmanlı''dan günümüze uzanan zengin bir koleksiyona ev sahipliği yapıyor. Ziyaretçiler, yöresel kıyafetler, el sanatları ve arkeolojik eserlerle ilçenin geçmişine yolculuk yapabilir.", "place_query": "Yenişehir Şehir Müzesi, Yenişehir, Bursa"}, {"title": "Yenişehir Ulu Cami", "summary": "Osmanlı dönemi mimarisinin zarif bir örneği olan bu cami, geniş avlusu ve sade ama etkileyici yapısıyla dikkat çeker. İlçenin en önemli dini yapılarından biri olarak hem ibadet hem de tarihi keşif için ziyaret edilir.", "place_query": "Yenişehir Ulu Cami, Yenişehir, Bursa"}, {"title": "Süleymanpaşa Hamamı", "summary": "16. yüzyıldan kalma bu tarihi hamam, Osmanlı hamam kültürünü günümüze taşıyan nadide yapılardandır. Restore edilmiş haliyle hem mimari açıdan ilgi çeker hem de geleneksel bir yıkanma deneyimi sunar.", "place_query": "Süleymanpaşa Hamamı, Yenişehir, Bursa"}, {"title": "Karagöz Müzesi", "summary": "Geleneksel Türk gölge oyununun önemli ismi Karagöz''e adanan bu müze, renkli tasvirler ve canlandırmalarla ziyaretçilerini eğlenceli bir yolculuğa çıkarır. Özellikle çocuklu aileler için kültürel bir durak niteliğindedir.", "place_query": "Karagöz Müzesi, Yenişehir, Bursa"}, {"title": "Yenişehir Kent Ormanı", "summary": "Doğayla iç içe vakit geçirmek isteyenler için ideal olan bu ormanlık alan, yürüyüş parkurları ve piknik alanlarıyla huzurlu bir kaçış noktasıdır. Şehrin gürültüsünden uzaklaşıp temiz hava almak için sıkça tercih edilir.", "place_query": "Yenişehir Kent Ormanı, Yenişehir, Bursa"}, {"title": "Ayaz Köyü Şelalesi", "summary": "Yenişehir''e bağlı Ayaz Köyü''nde yer alan bu şelale, çevresindeki yeşil doğayla birlikte görsel bir şölen sunar. Özellikle bahar ve yaz aylarında serinlemek ve doğa fotoğrafları çekmek için popüler bir duraktır.", "place_query": "Ayaz Köyü Şelalesi, Yenişehir, Bursa"}, {"title": "Kozdere Göleti", "summary": "Sakin ve huzurlu atmosferiyle bilinen bu gölet, balık tutma ve doğa yürüyüşü gibi aktiviteler için idealdir. Çevresindeki yeşil alanlar, hafta sonu kaçamakları için Yenişehirlilerin uğrak noktalarından biridir.", "place_query": "Kozdere Göleti, Yenişehir, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e9186a06-eb0b-4966-8b2e-404db522160c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tarihi İpek Han", "summary": "Bursa''nın hanlar bölgesinde yer alan bu tarihi han, Osmanlı döneminde ipek ticaretinin merkeziydi. Günümüzde restore edilerek kafe ve dükkanlarla canlandırılmıştır.", "place_query": "İpek Han, Yıldırım, Bursa"}, {"title": "Yeşil Türbe", "summary": "Çelebi Sultan Mehmed adına yaptırılan bu türbe, yeşil çinileriyle ünlüdür ve Osmanlı mimarisinin en güzel örneklerinden biridir.", "place_query": "Yeşil Türbe, Yıldırım, Bursa"}, {"title": "Yeşil Camii", "summary": "Yeşil Türbe''nin hemen yanında yer alan bu cami, çini süslemeleri ve mimarisiyle Bursa''nın en önemli tarihi yapılarındandır.", "place_query": "Yeşil Camii, Yıldırım, Bursa"}, {"title": "Tarihi Cumalıkızık Köyü", "summary": "UNESCO Dünya Mirası listesinde yer alan bu Osmanlı köyü, dar sokakları ve tarihi evleriyle ziyaretçilere eşsiz bir atmosfer sunar.", "place_query": "Cumalıkızık Köyü, Yıldırım, Bursa"}, {"title": "Bursa Hayvanat Bahçesi", "summary": "Geniş bir alana kurulu olan bu hayvanat bahçesi, farklı türlerdeki hayvanları ve doğal yaşam alanlarıyla özellikle aileler için popüler bir gezi noktasıdır.", "place_query": "Bursa Hayvanat Bahçesi, Yıldırım, Bursa"}, {"title": "Emirsultan Camii ve Türbesi", "summary": "Osmanlı''nın kuruluş dönemine ait bu manevi mekan, Emir Sultan''ın türbesi ve camisiyle huzurlu bir atmosfere sahiptir.", "place_query": "Emirsultan Camii, Yıldırım, Bursa"}, {"title": "Yıldırım Beyazıt Camii", "summary": "Yıldırım ilçesine adını veren padişah tarafından yaptırılan bu cami, sade ve etkileyici mimarisiyle tarihi öneme sahiptir.", "place_query": "Yıldırım Beyazıt Camii, Yıldırım, Bursa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '457c91cc-5973-442d-9166-b87f99498a16'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Assos Antik Kenti (Behramkale)", "summary": "Tarihi M.Ö. 6. yüzyıla uzanan bu antik kent, Athena Tapınağı ve muhteşem Edremit Körfezi manzarasıyla ünlüdür. Aristoteles''in bir dönem burada yaşadığı bilinir ve ziyaretçilere hem tarih hem de eşsiz bir deniz manzarası sunar.", "place_query": "Assos Antik Kenti, Behramkale, Ayvacık, Çanakkale"}, {"title": "Behramkale Köyü", "summary": "Assos antik kentinin hemen yanındaki bu taş döşeli köy, Arnavut kaldırımlı sokakları ve restore edilmiş taş evleriyle ünlüdür. Butik otelleri ve deniz manzaralı restoranlarıyla huzurlu bir atmosfer sunar.", "place_query": "Behramkale Köyü, Ayvacık, Çanakkale"}, {"title": "Küçükkuyu Sahili ve Kordonu", "summary": "Ayvacık''ın en popüler sahil kasabası olan Küçükkuyu, uzun kordonu ve denize sıfır kafeleriyle bilinir. Özellikle gün batımında yürüyüş yapmak ve deniz ürünleri yemek için idealdir.", "place_query": "Küçükkuyu Sahili, Ayvacık, Çanakkale"}, {"title": "Adatepe Köyü", "summary": "Taş evleri, zeytinlikleri ve sakin atmosferiyle ünlü bu tarihi köy, doğal güzellikler ve geleneksel mimariyi bir arada sunar. Zeytinyağı müzeleri ve butik konaklama seçenekleriyle öne çıkar.", "place_query": "Adatepe Köyü, Ayvacık, Çanakkale"}, {"title": "Kazdağları Milli Parkı (Ayvacık Girişi)", "summary": "Benzersiz bitki örtüsü ve oksijen deposu olarak bilinen Kazdağları''nın Ayvacık sınırlarındaki bölümü, doğa yürüyüşleri ve kamp için idealdir. Şelaleleri ve endemik türleriyle doğaseverlerin gözde rotasıdır.", "place_query": "Kazdağları Milli Parkı, Ayvacık, Çanakkale"}, {"title": "Sokakağzı Koyu", "summary": "Assos''a yakın bu sakin koy, berrak denizi ve doğal güzelliğiyle yüzme ve dinlenme için popülerdir. Çevresindeki küçük pansiyonlar ve restoranlar sayesinde keyifli bir gün geçirilebilir.", "place_query": "Sokakağzı Koyu, Ayvacık, Çanakkale"}, {"title": "Gülpınar (Apollon Smintheus Tapınağı)", "summary": "Antik çağda Apollon''a adanmış bu tapınak, Gülpınar köyünde yer alır ve iyi korunmuş yapısıyla dikkat çeker. Mitoloji meraklıları ve tarih severler için önemli bir duraktır.", "place_query": "Apollon Smintheus Tapınağı, Gülpınar, Ayvacık, Çanakkale"}, {"title": "Babakale Köyü ve Kalesi", "summary": "Anadolu''nun en batı noktası olan Babakale, 18. yüzyıldan kalma Osmanlı kalesi ve rüzgarlı sahiliyle ünlüdür. Tarihi yapıyı gezebilir ve eşsiz gün batımını izleyebilirsiniz.", "place_query": "Babakale Kalesi, Ayvacık, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4e711c5a-5a46-4eb8-bcfd-a05cc2666d41'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kaz Dağları Milli Parkı", "summary": "Eşsiz doğası, zengin bitki örtüsü ve tertemiz havasıyla ünlü milli park, doğa yürüyüşleri ve kampçılık için ideal bir rotadır.", "place_query": "Kaz Dağları Milli Parkı, Bayramiç, Çanakkale"}, {"title": "Bayramiç Barajı ve Mesire Alanı", "summary": "Piknik ve dinlenme alanlarıyla çevrili baraj gölü, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için sıkça ziyaret edilir.", "place_query": "Bayramiç Barajı, Bayramiç, Çanakkale"}, {"title": "Hasanboğuldu Şelalesi", "summary": "Kaz Dağları''nın eteklerinde yer alan bu şelale, çevresindeki çam ormanları ve serin sularıyla doğa severlerin uğrak noktasıdır.", "place_query": "Hasanboğuldu Şelalesi, Bayramiç, Çanakkale"}, {"title": "Alexandria Troas Antik Kenti", "summary": "MÖ 4. yüzyılda kurulan ve Roma döneminde önemli bir liman kenti olan bu antik kent, büyük hamam ve agora kalıntılarıyla tarih meraklılarını cezbeder.", "place_query": "Alexandria Troas Antik Kenti, Bayramiç, Çanakkale"}, {"title": "Bayramiç Evleri (Tarihi Konaklar)", "summary": "İlçe merkezinde bulunan Osmanlı dönemine ait ahşap ve taş işçiliğiyle dikkat çeken tarihi konaklar, mimari dokuyu keşfetmek isteyenler için idealdir.", "place_query": "Bayramiç Tarihi Evleri, Bayramiç, Çanakkale"}, {"title": "Güvenlik Köyü ve Antik Kaya Mezarları", "summary": "Köy çevresindeki kayalara oyulmuş antik mezarlar ve doğal yapılar, bölgenin tarih öncesi dönemlerine ışık tutan önemli kalıntılardır.", "place_query": "Güvenlik Köyü Kaya Mezarları, Bayramiç, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '91831616-c53e-4719-83ec-e4a945999e33'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kocabağlar Tabiat Parkı", "summary": "Biga''nın en popüler doğal alanlarından biridir. İçerisinde yürüyüş parkurları, piknik alanları ve kamp yapma imkanı sunan bu park, özellikle hafta sonu doğa kaçamakları için idealdir.", "place_query": "Kocabağlar Tabiat Parkı, Biga, Çanakkale"}, {"title": "Biga Kalesi", "summary": "Tarihi bir yapı olan Biga Kalesi, bölgenin Osmanlı dönemindeki savunma yapılarından biridir. Günümüze kısmen ulaşan kale, tarih meraklıları için önemli bir durak noktasıdır.", "place_query": "Biga Kalesi, Biga, Çanakkale"}, {"title": "Çınaraltı Mesire Alanı", "summary": "Biga şehir merkezine yakın, dev çınar ağaçları altında huzur bulabileceğiniz bir mesire alanıdır. Aileler ve piknikçiler tarafından sıkça tercih edilir.", "place_query": "Çınaraltı Mesire Alanı, Biga, Çanakkale"}, {"title": "Biga Müzesi", "summary": "Biga ve çevresindeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği bu müze, bölgenin tarih öncesi dönemlerinden Osmanlı''ya uzanan zengin geçmişini gözler önüne serer.", "place_query": "Biga Müzesi, Biga, Çanakkale"}, {"title": "Karabiga (Priapos) Antik Kenti", "summary": "Biga ilçesine bağlı Karabiga beldesinde yer alan antik kent, Helenistik ve Roma dönemlerine ait kalıntılarıyla ünlüdür. Özellikle antik liman ve sur kalıntıları görülmeye değerdir.", "place_query": "Karabiga Antik Kenti, Biga, Çanakkale"}, {"title": "Gümüşçay Şelalesi", "summary": "Biga''nın kırsal kesiminde yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla doğa severler için popüler bir mekandır. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Gümüşçay Şelalesi, Biga, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a6ef7b80-11cc-4f66-82a0-87c5132f0831'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bozcaada Kalesi", "summary": "Ada merkezinde yer alan tarihi Venedik ve Osmanlı dönemi kalesi, muhteşem manzarası ve akşam ışıklandırmasıyla ziyaretçilerin ilk durağıdır.", "place_query": "Bozcaada Kalesi, Bozcaada, Çanakkale"}, {"title": "Ayazma Plajı", "summary": "Bozcaada''nın en popüler ve uzun plajı olup ince kumu, berrak denizi ve gün batımı manzarasıyla ünlüdür.", "place_query": "Ayazma Plajı, Bozcaada, Çanakkale"}, {"title": "Çayır Plajı", "summary": "Sakin ve huzurlu atmosferiyle bilinen bu plaj, rüzgar sörfü için ideal koşulları ve doğal güzelliğiyle dikkat çeker.", "place_query": "Çayır Plajı, Bozcaada, Çanakkale"}, {"title": "Bozcaada Müzesi", "summary": "Eski bir Rum evinde yer alan müze, adanın tarihini, kültürünü ve günlük yaşamını yansıtan etnografik eserler sunar.", "place_query": "Bozcaada Müzesi, Bozcaada, Çanakkale"}, {"title": "Polente Feneri", "summary": "Adanın en batı noktasındaki bu tarihi fener, özellikle gün batımında eşsiz bir seyir noktası ve fotoğrafçıların uğrak yeridir.", "place_query": "Polente Feneri, Bozcaada, Çanakkale"}, {"title": "Köy Meydanı ve Rum Evleri", "summary": "Bozcaada merkezindeki taş döşeli sokaklar, restore edilmiş Rum evleri ve şarap evleriyle ada kültürünü yansıtan keyifli bir gezi alanıdır.", "place_query": "Bozcaada Köy Meydanı, Bozcaada, Çanakkale"}, {"title": "Gökçeada Şarap Fabrikası", "summary": "Ada şaraplarının üretildiği bu tarihi fabrika, tadım etkinlikleri ve bağ eviyle şarap severler için popüler bir duraktır.", "place_query": "Gökçeada Şarap Fabrikası, Bozcaada, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd597f5fe-477a-4ec7-b6ac-f40704b63f6d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çan Termal Tesisleri", "summary": "Çan ilçe merkezine yakın konumda bulunan bu tesis, şifalı termal sularıyla ünlüdür. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan kaplıcaları, doğa içinde huzurlu bir dinlenme imkanı sunar.", "place_query": "Çan Termal Tesisleri, Çan, Çanakkale"}, {"title": "Kirazlı Manastırı", "summary": "Çan ilçesine bağlı Kirazlı köyünde bulunan bu tarihi manastır, Bizans döneminden kalma önemli bir dini yapıdır. Doğal güzellikler içinde yer alan manastır, sakin atmosferi ve tarihi dokusuyla ziyaretçilerini etkiler.", "place_query": "Kirazlı Manastırı, Çan, Çanakkale"}, {"title": "Çan Şehitliği ve Anıtı", "summary": "Çanakkale Savaşları''nda şehit düşen askerler anısına yapılmış bu anıt ve şehitlik, ilçenin manevi değeri yüksek noktalarındandır. Ziyaretçiler, burada tarihe tanıklık ederken saygı duruşunda bulunabilir.", "place_query": "Çan Şehitliği, Çan, Çanakkale"}, {"title": "Biga Çayı Kenarı", "summary": "Çan ilçesinden geçen Biga Çayı''nın çevresi, piknik ve doğa yürüyüşü için popüler bir alandır. Yeşil doğası ve akarsu sesi eşliğinde huzurlu vakit geçirmek isteyenlerin tercih ettiği bir mekandır.", "place_query": "Biga Çayı, Çan, Çanakkale"}, {"title": "Çan İlçe Merkezi ve Çarşısı", "summary": "İlçenin kalbi sayılan merkez çarşı, günlük ihtiyaçlar ve yöresel ürünler için canlı bir alışveriş noktasıdır. Burada Çan''ın meşhur seramik ürünlerini ve yöresel lezzetleri bulabilirsiniz.", "place_query": "Çan Merkez Çarşı, Çan, Çanakkale"}, {"title": "Hasanboğuldu Göleti", "summary": "Çan''a bağlı bölgede yer alan bu gölet, doğal güzelliği ve çevresindeki piknik alanlarıyla bilinir. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için ideal bir kaçış noktasıdır.", "place_query": "Hasanboğuldu Göleti, Çan, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '91849679-869c-4233-bb16-5c31322dec2a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gelibolu Yarımadası Tarihi Milli Parkı", "summary": "Çanakkale Savaşları''nın geçtiği bu milli park, şehitlikler, anıtlar ve siperlerle dolu. Tarihe tanıklık etmek ve duygusal bir yolculuk yapmak için en önemli durak.", "place_query": "Gelibolu Yarımadası Tarihi Milli Parkı, Eceabat, Çanakkale"}, {"title": "Şehitler Abidesi", "summary": "Çanakkale Savaşı''nda hayatını kaybeden askerler anısına yapılmış bu görkemli anıt, Morto Koyu''nda yer alır ve ziyaretçilere muhteşem bir manzara sunar.", "place_query": "Çanakkale Şehitler Abidesi, Eceabat, Çanakkale"}, {"title": "Conk Bayırı", "summary": "Çanakkale Savaşı''nın en kritik noktalarından biri olan Conk Bayırı, Mustafa Kemal Atatürk''ün ''Size ölmeyi emrediyorum'' sözünü söylediği yerdir. Tarihi siperler ve anıtlarla doludur.", "place_query": "Conk Bayırı, Eceabat, Çanakkale"}, {"title": "Anzak Koyu", "summary": "25 Nisan 1915''te Anzak askerlerinin çıkarma yaptığı bu koy, sakin plajı ve tarihi atmosferiyle hem yüzme hem de anma törenleri için popülerdir.", "place_query": "Anzak Koyu, Eceabat, Çanakkale"}, {"title": "Kilitbahir Kalesi", "summary": "Fatih Sultan Mehmet tarafından yaptırılan bu tarihi kale, yonca yaprağı planı ve Çanakkale Boğazı''na hakim konumuyla dikkat çeker. İçinde müze de bulunur.", "place_query": "Kilitbahir Kalesi, Eceabat, Çanakkale"}, {"title": "Çanakkale Destanı Tanıtım Merkezi", "summary": "Kabin içi simülasyonlar, dioramalar ve görsel şovlarla Çanakkale Savaşı''nı etkileyici bir şekilde anlatan modern bir müze. Tarihi canlı deneyimlemek için ideal.", "place_query": "Çanakkale Destanı Tanıtım Merkezi, Eceabat, Çanakkale"}, {"title": "Kabatepe Müzesi", "summary": "Gelibolu Yarımadası''ndaki savaş alanlarına girişte yer alan bu müze, savaştan kalma silahlar, üniformalar ve fotoğraflarla zengin bir koleksiyon sunar.", "place_query": "Kabatepe Müzesi, Eceabat, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4a889b26-0a1c-4927-be6a-c64d78ed3768'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alexandria Troas Antik Kenti", "summary": "Antik çağın önemli liman kentlerinden biri olan bu ören yeri, devasa surları, hamamı ve antik tiyatrosu ile tarih meraklıları için eşsiz bir durak.", "place_query": "Alexandria Troas Antik Kenti, Ezine, Çanakkale"}, {"title": "Geyikli Şarapçılık / Bağları", "summary": "Bozcaada''ya açılan kapı Geyikli''deki üzüm bağları ve şarap evleri, tadım turları ve doğal manzaralarıyla ünlüdür.", "place_query": "Geyikli Şarapçılık, Ezine, Çanakkale"}, {"title": "Ezine Peynir Müzesi", "summary": "Türkiye''nin ilk peynir müzesi olan bu yer, yöresel Ezine peynirinin yapım sürecini ve kültürel önemini sergiliyor.", "place_query": "Ezine Peynir Müzesi, Ezine, Çanakkale"}, {"title": "Baba Burnu (Baba Tepe) Feneri", "summary": "Anadolu''nun en batı noktasındaki tarihi deniz feneri, nefes kesici gün batımı manzarası ve rüzgarlı doğasıyla fotoğrafçıların uğrak noktası.", "place_query": "Baba Burnu Feneri, Ezine, Çanakkale"}, {"title": "Geyikli Plajı", "summary": "Sakin ve temiz denizi, ince kumlu sahili ile Bozcaada feribotu öncesi serinlemek için ideal bir halk plajıdır.", "place_query": "Geyikli Plajı, Ezine, Çanakkale"}, {"title": "Kestanbol Kaplıcaları", "summary": "Romatizmal hastalıklara iyi geldiğine inanılan termal suları ve doğal ortamıyla şifalı bir kaçış noktası sunar.", "place_query": "Kestanbol Kaplıcaları, Ezine, Çanakkale"}, {"title": "Çıplak Köyü Antik Kaya Mezarları", "summary": "Bölgedeki antik yerleşim izlerini gösteren kaya mezarları, doğa yürüyüşü sevenler için tarihi bir keşif rotasıdır.", "place_query": "Çıplak Köyü Kaya Mezarları, Ezine, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '57d9ba7b-0918-4b60-88c0-b6b73e4c1f28'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gelibolu Yarımadası Tarihi Milli Parkı", "summary": "Çanakkale Savaşları''nın yaşandığı bu tarihi alan, şehitlikler, anıtlar ve siperlerle dolu. Ziyaretçiler, 57. Alay Şehitliği ve Conkbayırı gibi noktalarda duygusal bir tarih yolculuğu yapar.", "place_query": "Gelibolu Yarımadası Tarihi Milli Parkı, Gelibolu, Çanakkale"}, {"title": "Şehitler Abidesi", "summary": "Çanakkale Savaşı''nda hayatını kaybeden askerler anısına yapılan bu görkemli anıt, Gelibolu''nun en önemli sembollerinden biridir. Deniz manzarası eşliğinde saygı duruşunda bulunabilirsiniz.", "place_query": "Şehitler Abidesi, Gelibolu, Çanakkale"}, {"title": "Kabatepe Müzesi", "summary": "Çanakkale Savaşı''na ait silah, kıyafet ve fotoğrafların sergilendiği bu müze, savaşın izlerini yakından görmek isteyenler için ideal. Gelibolu Yarımadası''na girişte mutlaka uğranmalı.", "place_query": "Kabatepe Müzesi, Gelibolu, Çanakkale"}, {"title": "Gelibolu Kalesi", "summary": "Bizans ve Osmanlı dönemlerinden kalma tarihi kale, Gelibolu merkezinde yer alır. Ege Denizi manzarası ve surlarıyla fotoğrafçıların ve tarih meraklılarının ilgisini çeker.", "place_query": "Gelibolu Kalesi, Gelibolu, Çanakkale"}, {"title": "Seddülbahir Köyü ve Kalesi", "summary": "Çanakkale Boğazı''nın girişinde stratejik bir noktada bulunan Seddülbahir, savaş alanlarına yakınlığı ve otantik köy atmosferiyle bilinir. Kalesi, bölgenin savunma tarihine ışık tutar.", "place_query": "Seddülbahir Köyü, Gelibolu, Çanakkale"}, {"title": "Kilitbahir Kalesi", "summary": "Fatih Sultan Mehmet tarafından yaptırılan bu kale, boğazın en dar noktasında eşsiz bir konuma sahiptir. Yonca yaprağı planı ve burçlarıyla dikkat çeker, Çanakkale''den feribotla ulaşılabilir.", "place_query": "Kilitbahir Kalesi, Gelibolu, Çanakkale"}, {"title": "Gelibolu Mevlevihanesi", "summary": "Osmanlı döneminde inşa edilen bu tarihi yapı, Gelibolu''nun kültürel mirasını yansıtır. Mevlevi kültürüne dair eserler ve sakin bir avlu sunar.", "place_query": "Gelibolu Mevlevihanesi, Gelibolu, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a3f83645-74dc-4634-a212-7215a27941d8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aydıncık Plajı", "summary": "Gökçeada''nın en popüler ve en uzun plajı olan Aydıncık, ince kumlu sahili ve masmavi deniziyle yüzme, güneşlenme ve su sporları için idealdir. Çevresindeki restoran ve kafelerle ziyaretçilere keyifli bir gün geçirme imkanı sunar.", "place_query": "Aydıncık Plajı, Gökçeada, Çanakkale"}, {"title": "Gökçeada Meryem Ana Kilisesi", "summary": "Tarihi bir Rum Ortodoks kilisesi olan bu yapı, etkileyici mimarisi ve huzurlu atmosferiyle adanın kültürel mirasını yansıtır. İç mekanındaki freskler ve ahşap işçiliği ziyaretçilerin ilgisini çeker.", "place_query": "Meryem Ana Kilisesi, Gökçeada, Çanakkale"}, {"title": "Kuzu Limanı", "summary": "Sakin ve berrak deniziyle ünlü Kuzu Limanı, özellikle yüzme ve şnorkelle dalış için tercih edilen bir koydur. Çevresindeki zeytin ağaçları ve doğal güzellikler, huzurlu bir kaçamak arayanlar için idealdir.", "place_query": "Kuzu Limanı, Gökçeada, Çanakkale"}, {"title": "Gökçeada Tuz Gölü", "summary": "Adanın kuzeybatısında yer alan bu doğal göl, özellikle kuş gözlemciliği için önemli bir noktadır. Flamingolar ve diğer su kuşlarını gözlemleyebileceğiniz göl, eşsiz manzarasıyla fotoğrafçıların da uğrak yeridir.", "place_query": "Tuz Gölü, Gökçeada, Çanakkale"}, {"title": "Gökçeada Zeytinli Köyü", "summary": "Adanın en eski Rum köylerinden biri olan Zeytinli, taş evleri, dar sokakları ve geleneksel mimarisiyle büyüleyici bir atmosfere sahiptir. Köy meydanında yerel ürünlerin tadına bakabilir ve tarihi dokuyu keşfedebilirsiniz.", "place_query": "Zeytinli Köyü, Gökçeada, Çanakkale"}, {"title": "Gökçeada Kalesi", "summary": "Cenevizliler tarafından inşa edilen tarihi kale, adanın en yüksek noktalarından birinde yer alır ve muhteşem bir manzara sunar. Kaleyi gezerken adanın tarihine dair izler bulabilir, çevredeki doğal güzellikleri seyredebilirsiniz.", "place_query": "Gökçeada Kalesi, Gökçeada, Çanakkale"}, {"title": "Yıldız Koyu", "summary": "Sakin ve el değmemiş doğasıyla ünlü Yıldız Koyu, berrak denizi ve yeşil doğasıyla huzur veren bir kaçış noktasıdır. Kamp yapmak veya doğayla baş başa kalmak isteyenler için idealdir.", "place_query": "Yıldız Koyu, Gökçeada, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f4aca45c-5345-43d8-b249-f878ce826558'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Lapseki Kalesi", "summary": "Tarihi bir Bizans kalesi olan Lapseki Kalesi, Çanakkale Boğazı''nın kıyısında yer alır ve muhteşem bir manzaraya sahiptir. Ziyaretçiler, kale kalıntılarını gezerken boğazın ve çevrenin güzelliğini izleyebilirler.", "place_query": "Lapseki Kalesi, Lapseki, Çanakkale"}, {"title": "Lapseki Sahili ve İskele Meydanı", "summary": "Lapseki''nin kalbi sayılan sahil şeridi ve iskele meydanı, yürüyüş yapmak, deniz havası almak ve çay bahçelerinde vakit geçirmek için idealdir. Özellikle gün batımında boğaz manzarası büyüleyicidir.", "place_query": "Lapseki Sahili, Lapseki, Çanakkale"}, {"title": "Dalyan Köyü ve Koyu", "summary": "Lapseki''ye bağlı Dalyan Köyü, sakin atmosferi ve doğal güzellikleriyle öne çıkar. Köyün kıyısındaki Dalyan Koyu, yüzme ve piknik için huzurlu bir kaçış noktasıdır.", "place_query": "Dalyan Köyü, Lapseki, Çanakkale"}, {"title": "Çardak Plajı", "summary": "Lapseki''nin popüler plajlarından biri olan Çardak Plajı, ince kumu ve temiz deniziyle aileler ve yüzücüler için tercih edilir. Plaj çevresinde kafe ve restoranlar da bulunur.", "place_query": "Çardak Plajı, Lapseki, Çanakkale"}, {"title": "Lapseki Şehitliği ve Anıtı", "summary": "Çanakkale Savaşları''nın önemli hatıralarından biri olan Lapseki Şehitliği, bölgede şehit düşen askerler anısına yapılmıştır. Tarihi bir saygı duruşu için ziyaret edilebilir ve etkileyici bir manzaraya sahiptir.", "place_query": "Lapseki Şehitliği, Lapseki, Çanakkale"}, {"title": "Umurbey Köyü ve Şehitlikleri", "summary": "Lapseki''ye bağlı Umurbey Köyü, Çanakkale Savaşları''nda önemli bir cephe hattıydı ve burada birçok şehitlik bulunur. Köy, savaş tarihine tanıklık etmek ve doğal güzelliklerini keşfetmek için ziyaret edilebilir.", "place_query": "Umurbey Köyü, Lapseki, Çanakkale"}, {"title": "Güpür Deresi Mesire Alanı", "summary": "Lapseki''nin yeşil alanlarından biri olan Güpür Deresi Mesire Alanı, piknik ve doğa yürüyüşü için popülerdir. Dere kenarında serinlemek ve huzurlu bir gün geçirmek mümkündür.", "place_query": "Güpür Deresi Mesire Alanı, Lapseki, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1e459c1d-65e4-4bee-b866-e95faf46c999'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çanakkale Şehitler Abidesi", "summary": "Gelibolu Yarımadası''nda yer alan bu anıt, Çanakkale Savaşı''nda hayatını kaybeden askerlerimizin anısına yapılmıştır. Ziyaretçiler, burada tarihi bir yolculuğa çıkar ve savaşın izlerini hissedebilir.", "place_query": "Çanakkale Şehitler Abidesi, Gelibolu, Çanakkale"}, {"title": "Kilitbahir Kalesi", "summary": "Çanakkale Boğazı''nın kıyısında, Fatih Sultan Mehmet tarafından yaptırılan bu tarihi kale, boğaz manzarası ve mimarisiyle dikkat çeker. Kaleyi gezerek bölgenin savunma tarihine tanıklık edebilirsiniz.", "place_query": "Kilitbahir Kalesi, Çanakkale Merkez"}, {"title": "Troya Antik Kenti", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu antik kent, Homeros''un İlyada destanına konu olmuştur. Kazı alanında Troya''nın katmanlarını ve ünlü tahta atı görebilirsiniz.", "place_query": "Troya Antik Kenti, Tevfikiye, Çanakkale"}, {"title": "Çanakkale Deniz Müzesi", "summary": "Çanakkale Boğazı''nın hemen kenarında bulunan bu müze, denizcilik tarihine ve savaş dönemine ait objeleri sergiler. Savaş gemileri ve mayınlar gibi ilginç eserler görebilirsiniz.", "place_query": "Çanakkale Deniz Müzesi, Çanakkale Merkez"}, {"title": "Aynalı Çarşı", "summary": "Çanakkale''nin kalbinde yer alan tarihi bir çarşı olan Aynalı Çarşı, hediyelik eşya ve yöresel ürünlerle doludur. Çarşıda dolaşırken şehrin kültürel dokusunu hissedebilirsiniz.", "place_query": "Aynalı Çarşı, Çanakkale Merkez"}, {"title": "Güzelce (Dardanos) Koyu", "summary": "Çanakkale merkeze yakın, sakin ve temiz bir plaj olan Dardanos Koyu, yüzme ve güneşlenmek için idealdir. Çevresindeki kafelerde dinlenebilir ve boğaz manzarasının tadını çıkarabilirsiniz.", "place_query": "Dardanos Koyu, Çanakkale Merkez"}, {"title": "Çimenlik Kalesi", "summary": "Fatih Sultan Mehmet tarafından yaptırılan bu kale, Çanakkale Boğazı''nın karşı kıyısında yer alır. İçinde askeri müzeler ve tarihi toplar bulunan kale, boğazın en güzel manzaralarından birini sunar.", "place_query": "Çimenlik Kalesi, Çanakkale Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6062e0f8-593b-4b48-9758-f12c6d83f341'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kaz Dağları Milli Parkı", "summary": "Eşsiz flora ve faunası, temiz havası ve yemyeşil doğasıyla ünlü Kaz Dağları, Yenice sınırları içinde kalan bölümüyle doğa yürüyüşleri ve kamp için ideal bir noktadır.", "place_query": "Kaz Dağları Milli Parkı, Yenice, Çanakkale"}, {"title": "Hasanboğuldu Şelalesi", "summary": "Yemyeşil bir vadi içinde yer alan bu şelale, serin suları ve piknik alanlarıyla özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır.", "place_query": "Hasanboğuldu Şelalesi, Yenice, Çanakkale"}, {"title": "Yenice Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla doğa ile iç içe vakit geçirmek isteyenler için ideal bir mesire alanıdır; yürüyüş yapabilir ve piknik yapabilirsiniz.", "place_query": "Yenice Göleti, Yenice, Çanakkale"}, {"title": "Kalkım Barajı", "summary": "Bölgenin önemli su kaynaklarından biri olan Kalkım Barajı, çevresindeki doğal manzarası ve huzurlu atmosferiyle fotoğrafçılar ve doğa severler için güzel bir duraktır.", "place_query": "Kalkım Barajı, Yenice, Çanakkale"}, {"title": "Yenice Tarihi Köprüleri", "summary": "Osmanlı döneminden kalma taş köprüler, ilçenin tarihi dokusunu yansıtan önemli yapılardır ve özellikle fotoğraf tutkunlarının ilgisini çeker.", "place_query": "Yenice Tarihi Köprüleri, Yenice, Çanakkale"}, {"title": "Kocadere Köyü ve Kocadere Şelalesi", "summary": "Sessiz ve sakin bir köy atmosferinde, doğa yürüyüşü yaparak ulaşabileceğiniz Kocadere Şelalesi, tertemiz havası ve serin sularıyla keşfedilmeyi bekliyor.", "place_query": "Kocadere Şelalesi, Yenice, Çanakkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bd68f021-597e-4a8b-a37b-b2abe94a7fd2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Atkaracalar Yeraltı Şehri", "summary": "Tarihi bir yeraltı şehri olan bu yapı, bölgenin en önemli turistik noktalarından biridir. Ziyaretçiler, galeriler ve odalar arasında gezinerek geçmişe yolculuk yapabilir.", "place_query": "Atkaracalar Yeraltı Şehri, Atkaracalar, Çankırı"}, {"title": "Ilısu Köyü Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikit yapılarıyla dikkat çeken bu mağara, doğa severler için eşsiz bir keşif noktasıdır.", "place_query": "Ilısu Köyü Mağarası, Atkaracalar, Çankırı"}, {"title": "Atkaracalar Kalesi", "summary": "Tarihi bir kale olan bu yapı, bölgenin savunma amaçlı kullanılan önemli bir noktasıdır. Çevresindeki doğal manzara, fotoğrafçılar için idealdir.", "place_query": "Atkaracalar Kalesi, Atkaracalar, Çankırı"}, {"title": "Bozkır Köyü Tarihi Camii", "summary": "Osmanlı dönemine ait bu tarihi cami, ahşap işçiliği ve mimari detaylarıyla dikkat çeker. Huzurlu atmosferiyle ziyaretçilere keyifli bir deneyim sunar.", "place_query": "Bozkır Köyü Tarihi Camii, Atkaracalar, Çankırı"}, {"title": "Atkaracalar Şelalesi", "summary": "Doğa ile iç içe bir kaçamak arayanlar için ideal olan bu şelale, serin suları ve yeşil çevresiyle piknik ve yürüyüş için popüler bir mekandır.", "place_query": "Atkaracalar Şelalesi, Atkaracalar, Çankırı"}, {"title": "Çankırı Tuz Mağarası (Atkaracalar yakını)", "summary": "Bölgedeki en büyük tuz mağaralarından biri olan bu yer, sağlık turizmi açısından da önemlidir. Ziyaretçiler, tuzun iyileştirici etkisini deneyimleyebilir.", "place_query": "Çankırı Tuz Mağarası, Atkaracalar, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e3471d68-d8d6-4e7b-8f42-57cf91248d04'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bayramören Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir. Bölgenin savunma amaçlı kullanılan yapılarından biri olup, çevresindeki doğal manzara ile dikkat çeker.", "place_query": "Bayramören Kalesi, Bayramören, Çankırı"}, {"title": "Ilgaz Dağı Milli Parkı", "summary": "Bayramören''e yakın konumda bulunan bu milli park, doğa yürüyüşleri, kamp ve kış sporları için popülerdir. Zengin flora ve faunasıyla doğaseverlerin ilgisini çeker.", "place_query": "Ilgaz Dağı Milli Parkı, Çankırı"}, {"title": "Bayramören Şelalesi", "summary": "İlçe sınırları içinde yer alan doğal bir şelaledir. Özellikle yaz aylarında serinlemek ve piknik yapmak için ziyaret edilir.", "place_query": "Bayramören Şelalesi, Bayramören, Çankırı"}, {"title": "Kavaklı Köyü Kaya Mezarları", "summary": "Bayramören''e bağlı Kavaklı Köyü''nde bulunan tarihi kaya mezarları, antik döneme ait izler taşır. Tarih meraklıları için ilginç bir duraktır.", "place_query": "Kavaklı Köyü Kaya Mezarları, Bayramören, Çankırı"}, {"title": "Yeniköy Yaylası", "summary": "Doğal güzelliği ve temiz havasıyla bilinen bu yayla, özellikle yaz aylarında doğa turizmi için idealdir. Yürüyüş ve piknik yapılabilir.", "place_query": "Yeniköy Yaylası, Bayramören, Çankırı"}, {"title": "Çankırı Tuz Mağarası", "summary": "Bayramören''e araçla ulaşılabilecek mesafedeki bu mağara, tuz oluşumları ve sağlık turizmi açısından ünlüdür. Astım ve solunum yolu rahatsızlıklarına iyi geldiğine inanılır.", "place_query": "Çankırı Tuz Mağarası, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5ab2ae38-b2ae-4d3b-8869-6791c5d4fec9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çerkeş Ulu Camii", "summary": "Tarihi Osmanlı dönemine uzanan bu cami, şehrin merkezinde yer alır ve mimarisiyle dikkat çeker. Ziyaretçiler, ahşap işçiliği ve sade atmosferiyle huzur bulabilir.", "place_query": "Çerkeş Ulu Camii, Çerkeş, Çankırı"}, {"title": "Ilısuluk Kaplıcası", "summary": "Doğal termal su kaynaklarıyla ünlü bu kaplıca, şifalı suları ve dinlendirici ortamıyla ziyaretçilerine rahatlama imkanı sunar. Özellikle kış aylarında tercih edilir.", "place_query": "Ilısuluk Kaplıcası, Çerkeş, Çankırı"}, {"title": "Çerkeş Kalesi", "summary": "Tarihi bir tepe üzerinde konumlanan kale kalıntıları, bölgenin geçmişine ışık tutar. Çevresindeki manzara, fotoğrafçılar ve doğa yürüyüşçüleri için idealdir.", "place_query": "Çerkeş Kalesi, Çerkeş, Çankırı"}, {"title": "Çerkeş Kent Ormanı", "summary": "Şehir merkezine yakın bu yeşil alan, piknik ve doğa yürüyüşleri için popülerdir. Temiz havası ve gölgelik alanlarıyla aileler için keyifli bir kaçış noktasıdır.", "place_query": "Çerkeş Kent Ormanı, Çerkeş, Çankırı"}, {"title": "Köprübaşı Mesire Alanı", "summary": "Akarsu kenarında kurulu bu mesire alanı, doğal güzelliği ve serin sularıyla yaz aylarında sıkça ziyaret edilir. Mangal ve piknik yapmak için uygun bir ortam sunar.", "place_query": "Köprübaşı Mesire Alanı, Çerkeş, Çankırı"}, {"title": "Çerkeş Müzesi", "summary": "Yöresel kültürü ve tarihi eserleri sergileyen bu küçük müze, bölgenin etnografik zenginliğini keşfetmek isteyenler için idealdir. Ziyaretçiler, geleneksel yaşamı yansıtan objeleri görebilir.", "place_query": "Çerkeş Müzesi, Çerkeş, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b5ec1a1c-5f8c-408b-8185-7fe36c67d3fb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eldivan Yaylası", "summary": "Şehir merkezine yaklaşık 20 km uzaklıkta bulunan bu yayla, doğal güzelliği, temiz havası ve yeşil örtüsüyle piknik ve doğa yürüyüşü için ideal bir kaçış noktasıdır.", "place_query": "Eldivan Yaylası, Eldivan, Çankırı"}, {"title": "Eldivan Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard yapmak isteyenler için popüler bir destinasyon olup, kısa pistleri ve doğal karıyla aileler ve amatör sporcular için uygundur.", "place_query": "Eldivan Kayak Merkezi, Eldivan, Çankırı"}, {"title": "Karaçayır Mesire Alanı", "summary": "Çam ormanlarıyla çevrili bu mesire alanı, mangal keyfi ve kamp yapmak isteyenler için huzurlu bir ortam sunar; yaz aylarında sıkça tercih edilir.", "place_query": "Karaçayır Mesire Alanı, Eldivan, Çankırı"}, {"title": "Eldivan Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale kalıntıları, bölgenin panoramik manzarasını izlemek ve kısa bir tarih yolculuğu yapmak için ziyaret edilebilir.", "place_query": "Eldivan Kalesi, Eldivan, Çankırı"}, {"title": "Seyfe Gölü (Eldivan)", "summary": "Kuş gözlemciliği ve doğa fotoğrafçılığı için önemli bir sulak alan olan göl, özellikle göç dönemlerinde çok sayıda kuş türüne ev sahipliği yapar.", "place_query": "Seyfe Gölü, Eldivan, Çankırı"}, {"title": "Eldivan Merkez Camii ve Çevresi", "summary": "İlçe merkezinde yer alan tarihi cami ve etrafındaki çarşı, yöresel alışveriş ve sakin bir atmosferde vakit geçirmek için idealdir.", "place_query": "Eldivan Merkez Camii, Eldivan, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1187e279-d405-4805-abf0-f79695d7e57a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ilgaz Dağı Milli Parkı", "summary": "Türkiye''nin önemli kış turizm merkezlerinden biri olan milli park, kış aylarında kayak ve snowboard, yaz aylarında ise kamp, trekking ve piknik gibi aktiviteler için idealdir. Yemyeşil ormanları ve temiz havasıyla doğa severlerin uğrak noktasıdır.", "place_query": "Ilgaz Dağı Milli Parkı, Ilgaz, Çankırı"}, {"title": "Ilgaz Kayak Merkezi", "summary": "Ilgaz Dağı''nın kuzey yamaçlarında yer alan kayak merkezi, uzun pistleri ve modern tesisleriyle özellikle hafta sonları yoğun ilgi görür. Kış sporları tutkunları için hem başlangıç hem de orta seviye pistler sunar.", "place_query": "Ilgaz Kayak Merkezi, Ilgaz, Çankırı"}, {"title": "Yıldıztepe", "summary": "Ilgaz Dağı''nın en yüksek noktalarından biri olan Yıldıztepe, muhteşem manzarası ve yürüyüş parkurlarıyla bilinir. Zirveye çıktığınızda Çankırı ve Kastamonu ovalarının panoramik görüntüsü sizi bekler.", "place_query": "Yıldıztepe, Ilgaz, Çankırı"}, {"title": "Ilgaz Kent Ormanı", "summary": "Ilgaz ilçe merkezine yakın konumdaki kent ormanı, piknik alanları, yürüyüş yolları ve çocuk oyun parkları ile aileler için huzurlu bir kaçış noktasıdır. Şehir gürültüsünden uzaklaşmak için idealdir.", "place_query": "Ilgaz Kent Ormanı, Ilgaz, Çankırı"}, {"title": "Ilgaz 15 Temmuz Şehitleri Anıtı ve Parkı", "summary": "Ilgaz ilçe merkezinde bulunan bu anıt ve park, hem tarihi bir hatıra hem de dinlenme alanı olarak ziyaret edilir. Çevresindeki yeşil alanlar ve oturma bankları ile kısa bir mola vermek için uygundur.", "place_query": "15 Temmuz Şehitleri Anıtı, Ilgaz, Çankırı"}, {"title": "Ilgaz Çarşı Camii ve Tarihi Çeşme", "summary": "Ilgaz''ın merkezinde yer alan tarihi cami ve yanındaki Osmanlı dönemi çeşmesi, ilçenin kültürel mirasını yansıtır. Mimari detayları ve tarihi dokusu ile fotoğrafçıların ilgisini çeker.", "place_query": "Ilgaz Çarşı Camii, Ilgaz, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9d801afc-c4d3-4cc8-95ca-1376c231e01e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızılırmak Köprüsü", "summary": "Tarihi ve mimari açıdan önemli bir yapı olan bu köprü, Kızılırmak Nehri üzerinde yer alır ve bölgenin simgelerindendir. Ziyaretçiler, nehir manzarası eşliğinde keyifli bir yürüyüş yapabilir.", "place_query": "Kızılırmak Köprüsü, Kızılırmak, Çankırı"}, {"title": "Kızılırmak Kalesi", "summary": "Tarihi bir kalıntı olan Kızılırmak Kalesi, bölgenin geçmişine ışık tutar ve çevresindeki doğal güzelliklerle dikkat çeker. Kale, fotoğrafçılar ve tarih meraklıları için ideal bir duraktır.", "place_query": "Kızılırmak Kalesi, Kızılırmak, Çankırı"}, {"title": "Kızılırmak Şelalesi", "summary": "Doğal bir güzellik olan bu şelale, özellikle bahar ve yaz aylarında ziyaretçilerine huzur veren bir atmosfer sunar. Çevresindeki piknik alanlarıyla aileler için popüler bir kaçış noktasıdır.", "place_query": "Kızılırmak Şelalesi, Kızılırmak, Çankırı"}, {"title": "Kızılırmak Müzesi", "summary": "İlçenin kültürel ve tarihi mirasını sergileyen bu müze, yöresel eserler ve etnografik objelerle zengin bir koleksiyona sahiptir. Kısa bir gezide bölgenin hikayesini keşfetmek için idealdir.", "place_query": "Kızılırmak Müzesi, Kızılırmak, Çankırı"}, {"title": "Kızılırmak Göleti ve Mesire Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için harika bir alan olan gölet, yürüyüş yolları ve piknik masalarıyla donatılmıştır. Kuş gözlemi ve sakin bir gün geçirmek için tercih edilir.", "place_query": "Kızılırmak Göleti Mesire Alanı, Kızılırmak, Çankırı"}, {"title": "Kızılırmak Cami (Tarihi Cami)", "summary": "Osmanlı döneminden kalma bu tarihi cami, mimari detayları ve huzurlu atmosferiyle ziyaretçileri cezbeder. İlçenin merkezinde yer alan cami, dini ve kültürel bir durak olarak öne çıkar.", "place_query": "Kızılırmak Merkez Cami, Kızılırmak, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '021d3148-2c2f-4062-9afc-7655cef51657'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Korgun Kalesi", "summary": "Korgun ilçe merkezine hakim bir tepe üzerinde yer alan tarihi kale kalıntıları, bölgenin stratejik önemini ve geçmişine dair izleri gözler önüne seriyor. Ziyaretçiler, kaleye tırmanarak hem tarihi dokuyu keşfedebilir hem de Çankırı Ovası''nın eşsiz manzarasını seyredebilir.", "place_query": "Korgun Kalesi, Korgun, Çankırı"}, {"title": "Korgun Ulu Camii", "summary": "İlçenin en önemli dini yapılarından biri olan cami, sade ve etkileyici mimarisiyle dikkat çekiyor. Özellikle Selçuklu ve Osmanlı dönemi izlerini taşıyan yapı, huzurlu atmosferiyle ziyaretçilerine manevi bir deneyim sunuyor.", "place_query": "Korgun Ulu Camii, Korgun, Çankırı"}, {"title": "Ilgaz Dağı Milli Parkı (Korgun Girişi)", "summary": "Korgun sınırları içerisinde yer alan bu eşsiz milli park, zengin bitki örtüsü ve yaban hayatıyla doğa severler için bir cennettir. Yürüyüş parkurları, piknik alanları ve temiz havasıyla şehir hayatından kaçış noktası olarak öne çıkar.", "place_query": "Ilgaz Dağı Milli Parkı Korgun girişi, Çankırı"}, {"title": "Korgun Karakaya Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikit yapılarıyla bilinen mağara, macera ve doğa tutkunları için keşfedilmeyi bekleyen bir hazinedir. Mağara içindeki serin hava ve sessizlik, ziyaretçilere farklı bir atmosfer sunar.", "place_query": "Karakaya Mağarası, Korgun, Çankırı"}, {"title": "Korgun Mesire Alanı (Şelale Piknik Alanı)", "summary": "İlçe merkezine yakın konumdaki bu mesire alanı, özellikle yaz aylarında ailelerin ve grupların uğrak noktasıdır. Küçük bir şelale ve dere kenarında kurulu piknik masaları, serinlemek ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Korgun Mesire Alanı, Korgun, Çankırı"}, {"title": "Korgun Eski Hamam (Tarihi Korgun Hamamı)", "summary": "Osmanlı döneminden kalma tarihi hamam, geleneksel hamam kültürünü yansıtan mimarisiyle dikkat çekiyor. Restore edilmiş yapısıyla hem tarihi bir mekanı gezmek hem de dinlenmek isteyenler için güzel bir durak.", "place_query": "Tarihi Korgun Hamamı, Korgun, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9322ae90-8a9c-432e-9f76-0dc4b5ae6517'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ilısu Köyü ve Şelalesi", "summary": "Kurşunlu’nun en popüler doğal güzelliklerinden biridir. Şelale çevresinde piknik yapabilir, doğa yürüyüşleri ile huzurlu bir gün geçirebilirsiniz.", "place_query": "Ilısu Şelalesi, Kurşunlu, Çankırı"}, {"title": "Kurşunlu Kaplıcaları", "summary": "Romatizmal hastalıklara iyi gelen şifalı suları ile ünlüdür. Termal otel ve tesislerde konaklayarak sağlık turizmi deneyimi yaşayabilirsiniz.", "place_query": "Kurşunlu Kaplıcaları, Çankırı"}, {"title": "Kurşunlu Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, ilçe merkezine hakim bir tepede yer alır. Çankırı’nın antik dönemlerine tanıklık eden önemli bir kültür varlığıdır.", "place_query": "Kurşunlu Kalesi, Kurşunlu, Çankırı"}, {"title": "Çavundur Köyü Mağarası", "summary": "Doğal oluşumlu mağara, sarkıt ve dikitleriyle dikkat çeker. Macera arayanlar için keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "Çavundur Mağarası, Kurşunlu, Çankırı"}, {"title": "Kurşunlu Yaylası", "summary": "Yeşilin her tonunu barındıran yayla, temiz havası ve manzarasıyla kampçıların ve doğaseverlerin uğrak noktasıdır. Özellikle yaz aylarında serinlemek için idealdir.", "place_query": "Kurşunlu Yaylası, Çankırı"}, {"title": "Kurşunlu Ulu Camii", "summary": "Osmanlı dönemine ait tarihi bir camidir. Ahşap işçiliği ve mimari detaylarıyla ilçenin dini ve kültürel mirasını yansıtır.", "place_query": "Kurşunlu Ulu Camii, Kurşunlu, Çankırı"}, {"title": "Sarıkaya Köyü Tarihi Çeşmesi", "summary": "Geçmişten günümüze ulaşan taş işçiliği örneği olan çeşme, köy meydanında yer alır. Fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Sarıkaya Köyü Tarihi Çeşmesi, Kurşunlu, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6d05416d-bfc5-4d30-9531-c35d32984e1d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çankırı Kalesi", "summary": "Şehir merkezine hakim bir tepede yer alan tarihi kale, Roma, Bizans, Selçuklu ve Osmanlı dönemlerine tanıklık etmiş olup, günümüzde restoran ve kafeleriyle ziyaretçilere keyifli bir seyir terası sunar.", "place_query": "Çankırı Kalesi, Merkez, Çankırı"}, {"title": "Tuz Mağarası", "summary": "Dünyanın en büyük ikinci tuz mağarası olan bu doğal oluşum, astım ve solunum yolu rahatsızlıklarına iyi geldiğine inanılan mikroklimasıyla hem sağlık turizmi hem de görsel şölen arayanları cezbeder.", "place_query": "Tuz Mağarası, Çankırı Merkez"}, {"title": "Çankırı Müzesi", "summary": "Kentin tarih öncesi dönemlerden Osmanlı''ya uzanan arkeolojik ve etnografik eserlerini sergileyen müze, özellikle Tuz Mağarası''ndan çıkarılan buluntularıyla dikkat çeker.", "place_query": "Çankırı Müzesi, Merkez, Çankırı"}, {"title": "Buğday Pazarı Medresesi (Taş Medrese)", "summary": "13. yüzyılda Selçuklu döneminde inşa edilen bu tarihi yapı, taş işçiliği ve kemerli avlusuyla fotoğrafçıların uğrak noktasıdır; günümüzde kültürel etkinliklere ev sahipliği yapar.", "place_query": "Buğday Pazarı Medresesi, Çankırı Merkez"}, {"title": "Ilgaz Dağı Milli Parkı", "summary": "Çankırı merkeze yaklaşık 30 km uzaklıktaki bu milli park, kış aylarında kayak merkezi, yaz aylarında ise yürüyüş ve piknik alanlarıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Ilgaz Dağı Milli Parkı, Çankırı"}, {"title": "Çankırı Saat Kulesi", "summary": "1905 yılında II. Abdülhamid döneminde yaptırılan bu tarihi kule, şehrin simgelerinden biri olup, merkezdeki meydanda konumlanmıştır ve özellikle akşam ışıklandırmasıyla güzel bir manzara sunar.", "place_query": "Çankırı Saat Kulesi, Merkez, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '00fbff19-03a7-42d4-974e-7e5a29e23bdd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ilısu Köyü ve Mağarası", "summary": "Orta ilçesine bağlı Ilısu Köyü''nde yer alan bu mağara, sarkıt ve dikitleriyle dikkat çeken doğal bir oluşumdur. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler için popüler bir destinasyondur.", "place_query": "Ilısu Mağarası, Orta, Çankırı"}, {"title": "Seydiler Köyü Kaya Mezarları", "summary": "Orta ilçesindeki Seydiler Köyü''nde bulunan bu tarihi kaya mezarları, Roma dönemine ait önemli bir arkeolojik alandır. Bölgenin antik geçmişini keşfetmek isteyen ziyaretçiler için eşsiz bir duraktır.", "place_query": "Seydiler Kaya Mezarları, Orta, Çankırı"}, {"title": "Çankırı Tuz Mağarası", "summary": "Orta ilçesine yaklaşık 20 km mesafede bulunan bu doğal tuz mağarası, astım ve solunum rahatsızlıklarına iyi geldiği bilinen şifalı havasıyla ünlüdür. Mağara içindeki tuz kristalleri ve geniş salonları ziyaretçileri büyüler.", "place_query": "Çankırı Tuz Mağarası, Çankırı Merkez"}, {"title": "Sakaeli Tabiat Parkı", "summary": "Orta ilçesi sınırları içinde yer alan bu tabiat parkı, zengin bitki örtüsü ve temiz havasıyla doğa severler için ideal bir kaçış noktasıdır. Piknik alanları ve yürüyüş parkurları ile hafta sonu gezilerinde sıkça tercih edilir.", "place_query": "Sakaeli Tabiat Parkı, Orta, Çankırı"}, {"title": "Orta Kalesi", "summary": "İlçe merkezinde yer alan bu tarihi kale, Orta''nın simgelerinden biridir. Kalenin tepesinden çevredeki vadi ve dağ manzarası izlenebilir; özellikle gün batımında fotoğrafçılar için harika bir karedir.", "place_query": "Orta Kalesi, Orta, Çankırı"}, {"title": "Kırkpınar Köyü Şelalesi", "summary": "Orta ilçesine bağlı Kırkpınar Köyü''nde bulunan bu şelale, doğal havuzları ve çevresindeki yeşil alanlarıyla piknik ve yüzme keyfi sunar. Özellikle yaz aylarında serinlemek için bölge halkının uğrak noktasıdır.", "place_query": "Kırkpınar Şelalesi, Orta, Çankırı"}, {"title": "Kavaklı Köyü Tarihi Çeşmesi", "summary": "Osmanlı döneminden kalma bu taş çeşme, Orta ilçesinin kültürel mirasını yansıtan önemli bir yapıdır. Köy meydanında yer alan çeşme, hem tarihi dokusu hem de soğuk suyuyla ziyaretçilerin ilgisini çeker.", "place_query": "Kavaklı Köyü Tarihi Çeşmesi, Orta, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '35e7339f-6be0-473d-b3ad-ea4feed6c376'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şabanözü Kapalı Pazarı", "summary": "İlçenin en canlı noktalarından biri olan bu pazar, özellikle haftalık kurulduğu günlerde yöresel ürünler, taze sebze-meyve ve el sanatlarıyla dolup taşar. Ziyaretçiler, Çankırı''nın otantik atmosferini burada birebir deneyimleyebilir.", "place_query": "Şabanözü Kapalı Pazarı, Şabanözü, Çankırı"}, {"title": "Çankırı Tuz Mağarası", "summary": "Çankırı''ya bağlı olan ve şifa kaynağı olarak bilinen bu doğal mağara, astım ve solunum rahatsızlıklarına iyi geldiği düşünülen tuz kristalleriyle ünlüdür. Şabanözü''ne yaklaşık 30 km mesafedeki bu eşsiz doğa harikası, hem sağlık turizmi hem de görsel şölen arayanlar için idealdir.", "place_query": "Çankırı Tuz Mağarası, Merkez, Çankırı"}, {"title": "Ilgaz Dağı Milli Parkı", "summary": "Şabanözü''ne bir saatlik mesafede yer alan bu milli park, dört mevsim doğa sporları ve kamp için popülerdir. Kışın kayak merkezi, yazın ise yürüyüş ve piknik alanlarıyla ziyaretçilerine huzurlu bir kaçış sunar.", "place_query": "Ilgaz Dağı Milli Parkı, Ilgaz, Kastamonu/Çankırı"}, {"title": "Çankırı Kalesi", "summary": "Şehir merkezinde yer alan bu tarihi kale, Roma ve Bizans dönemlerinden kalma kalıntılarıyla dikkat çeker. Kaleye tırmanan ziyaretçiler, Çankırı''nın panoramik manzarasını kuş bakışı izleme fırsatı bulur.", "place_query": "Çankırı Kalesi, Merkez, Çankırı"}, {"title": "Şabanözü Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumdaki bu gölet, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için sakin bir kaçış noktasıdır. Çevresindeki yeşil alanlar ve yürüyüş yollarıyla hafta sonu aile gezileri için idealdir.", "place_query": "Şabanözü Göleti, Şabanözü, Çankırı"}, {"title": "Çankırı Müzesi", "summary": "Şabanözü''ne 30 km uzaklıktaki bu müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Hitit, Frig ve Roma dönemlerine ait eserlerin yanı sıra yöresel kıyafet ve eşyalar da burada görülebilir.", "place_query": "Çankırı Müzesi, Merkez, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7af4219b-664c-439d-9d93-747cb8847c2d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yapraklı Kaplıcaları", "summary": "Çankırı''nın önemli termal turizm merkezlerinden biri olan Yapraklı Kaplıcaları, romatizma ve cilt hastalıklarına iyi gelen şifalı sularıyla ünlüdür. Doğal bir ortamda dinlenmek ve termal tedaviden faydalanmak isteyen ziyaretçiler için ideal bir duraktır.", "place_query": "Yapraklı Kaplıcaları, Yapraklı, Çankırı"}, {"title": "Ilgar Dağı", "summary": "Yapraklı ilçesi sınırlarında yer alan Ilgar Dağı, özellikle kış aylarında kayak ve kış sporları için popüler bir destinasyondur. Doğal güzellikleri ve temiz havasıyla doğa yürüyüşü sevenler için de harika bir rotadır.", "place_query": "Ilgar Dağı, Yapraklı, Çankırı"}, {"title": "Yapraklı Kalesi", "summary": "Tarihi bir geçmişe sahip olan Yapraklı Kalesi, ilçeye hakim bir tepe üzerinde yer alır ve çevresine muhteşem bir manzara sunar. Kalıntıları günümüze ulaşan kale, tarih meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Yapraklı Kalesi, Yapraklı, Çankırı"}, {"title": "Yapraklı Şelalesi", "summary": "Yemyeşil bir ormanın içinde gizlenmiş olan Yapraklı Şelalesi, serin suları ve huzur veren atmosferiyle doğaseverlerin uğrak noktasıdır. Piknik yapmak ve doğayla iç içe vakit geçirmek için mükemmel bir yerdir.", "place_query": "Yapraklı Şelalesi, Yapraklı, Çankırı"}, {"title": "Sarıkaya Köyü Mağaraları", "summary": "Yapraklı''ya bağlı Sarıkaya Köyü''nde bulunan bu mağaralar, doğal oluşumları ve tarihi sığınak olarak kullanılmış olmalarıyla dikkat çeker. Mağara keşfi ve doğa fotoğrafçılığı için ilgi çekici bir duraktır.", "place_query": "Sarıkaya Köyü Mağaraları, Yapraklı, Çankırı"}, {"title": "Yapraklı Yaylası", "summary": "Yaz aylarında serinlemek ve doğanın tadını çıkarmak isteyenler için ideal olan Yapraklı Yaylası, geniş çayırları ve zengin bitki örtüsüyle huzur verir. Yayla şenlikleri ve doğa yürüyüşleri için popüler bir mekandır.", "place_query": "Yapraklı Yaylası, Yapraklı, Çankırı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7a29929f-f8a4-4ae9-9dc9-a470d4daa628'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alacahöyük Ören Yeri", "summary": "Hitit döneminin en önemli merkezlerinden biri olan bu açık hava müzesinde kral mezarları, sfenksli kapı ve antik kalıntılar görülebilir. Türkiye''nin ilk kazı alanlarından biridir.", "place_query": "Alacahöyük Ören Yeri, Alaca, Çorum"}, {"title": "Alacahöyük Müzesi", "summary": "Alacahöyük kazılarında çıkarılan altın takılar, heykeller ve çivi yazılı tabletlerin sergilendiği müze, Hitit uygarlığına dair eşsiz eserler sunar.", "place_query": "Alacahöyük Müzesi, Alaca, Çorum"}, {"title": "Alaca Saat Kulesi", "summary": "İlçe merkezinde yer alan bu tarihi saat kulesi, Alaca''nın simge yapılarından biridir ve çevresi dinlenme alanlarıyla donatılmıştır.", "place_query": "Alaca Saat Kulesi, Alaca, Çorum"}, {"title": "İncesu Kanyonu", "summary": "Alaca ilçe sınırları içinde yer alan bu doğal kanyon, yürüyüş ve doğa fotoğrafçılığı için idealdir. Sarp kayalıklar ve yeşil doğasıyla dikkat çeker.", "place_query": "İncesu Kanyonu, Alaca, Çorum"}, {"title": "Hüseyin Gazi Türbesi", "summary": "Bölgede manevi bir öneme sahip olan bu türbe, özellikle yerli ziyaretçiler tarafından sıkça uğranan bir ziyaret noktasıdır.", "place_query": "Hüseyin Gazi Türbesi, Alaca, Çorum"}, {"title": "Alaca Karşıyaka Mesire Alanı", "summary": "Şehir merkezine yakın, piknik ve dinlenme imkanı sunan bu yeşil alan, özellikle hafta sonları aileler tarafından tercih edilir.", "place_query": "Alaca Karşıyaka Mesire Alanı, Alaca, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9061e98f-6e45-416a-b082-de3c9e5ca512'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İncesu Kanyonu Tabiat Parkı", "summary": "Bayat ilçe merkezine yaklaşık 15 km uzaklıkta bulunan bu kanyon, yürüyüş parkurları, şelaleleri ve eşsiz doğasıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "İncesu Kanyonu Tabiat Parkı, Bayat, Çorum"}, {"title": "Kunduzlu Mahallesi Kaya Mezarları", "summary": "Bayat''ın Kunduzlu köyünde yer alan bu antik kaya mezarları, Frig dönemine ait izler taşıyan ve bölgenin tarihine ışık tutan önemli bir arkeolojik alandır.", "place_query": "Kunduzlu Mahallesi Kaya Mezarları, Bayat, Çorum"}, {"title": "Çatak Kaya Mezarları", "summary": "İlçenin Çatak köyünde bulunan bu tarihi kaya mezarları, Helenistik ve Roma dönemlerine tarihlenen etkileyici yapılarıyla ziyaretçilerini geçmişe yolculuğa çıkarır.", "place_query": "Çatak Kaya Mezarları, Bayat, Çorum"}, {"title": "Bayat Kalesi", "summary": "İlçe merkezinde yer alan bu tarihi kale kalıntıları, Bayat''ın stratejik önemini gösteren ve çevreye hakim manzarasıyla dikkat çeken bir noktadır.", "place_query": "Bayat Kalesi, Bayat, Çorum"}, {"title": "Gökçeköy Mağarası", "summary": "Bayat''a bağlı Gökçeköy''de bulunan bu mağara, sarkıt ve dikitleriyle doğal bir güzellik sunarken, içerisindeki tarihi kalıntılarla da keşfedilmeyi bekleyen bir yeraltı dünyasıdır.", "place_query": "Gökçeköy Mağarası, Bayat, Çorum"}, {"title": "Ahmetler Yaylası", "summary": "Bayat''ın serin ve yeşil yaylalarından biri olan Ahmetler Yaylası, özellikle yaz aylarında şehir hayatından kaçmak isteyenler için huzurlu bir ortam ve doğa yürüyüşü imkanı sunar.", "place_query": "Ahmetler Yaylası, Bayat, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e096c4a7-8cbb-4ccb-b4f1-e58c988d5cf1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hattuşaş Antik Kenti", "summary": "Hitit İmparatorluğu''nun başkenti olan bu UNESCO Dünya Mirası alanı, devasa surları, Aslanlı Kapı ve Kral Kapısı gibi yapılarıyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "Hattuşaş Antik Kenti, Boğazkale, Çorum"}, {"title": "Yazılıkaya Açık Hava Tapınağı", "summary": "Hattuşaş''ın hemen yakınında yer alan bu kaya tapınağı, Hitit tanrı ve tanrıçalarının kabartmalarıyla süslü duvarlarıyla ünlüdür ve antik dönemin dini ritüellerine ışık tutar.", "place_query": "Yazılıkaya Açık Hava Tapınağı, Boğazkale, Çorum"}, {"title": "Boğazkale Müzesi", "summary": "Küçük ama etkileyici bu müze, Hattuşaş kazılarında ortaya çıkarılan çivi yazılı tabletler, seramikler ve heykeller gibi Hitit eserlerini sergileyerek bölgenin tarihine derinlemesine bir bakış sunar.", "place_query": "Boğazkale Müzesi, Boğazkale, Çorum"}, {"title": "Boğazkale (Boğazköy) Milli Parkı", "summary": "Hattuşaş antik kentini çevreleyen bu milli park, hem tarihi kalıntıları hem de doğal bitki örtüsüyle doğa yürüyüşü yapmak ve tarihle iç içe vakit geçirmek isteyenler için idealdir.", "place_query": "Boğazkale Milli Parkı, Boğazkale, Çorum"}, {"title": "Büyük Kale (Büyükkale)", "summary": "Hattuşaş''ın en yüksek noktasında yer alan bu yapı, Hitit krallarının saray kompleksi olup, surlar ve tapınak kalıntılarıyla birlikte bölgenin en etkileyici manzaralarından birini sunar.", "place_query": "Büyükkale, Boğazkale, Çorum"}, {"title": "Aslanlı Kapı", "summary": "Hattuşaş''ın batı surlarında bulunan bu kapı, iki büyük aslan heykeliyle süslenmiş olup, Hitit taş işçiliğinin en güzel örneklerinden biri olarak ziyaretçilerin ilgisini çeker.", "place_query": "Aslanlı Kapı, Boğazkale, Çorum"}, {"title": "Yer Kapı (Sfenksli Kapı)", "summary": "Hattuşaş''ın güneyinde yer alan bu kapı, sfenks heykelleri ve tünel yapısıyla dikkat çeker; antik kentin savunma sistemini ve mimari becerisini gözler önüne serer.", "place_query": "Yer Kapı, Boğazkale, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aff7ca76-ce4a-422c-a007-aea5356e3eec'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dodurga Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin savunma ve yerleşim tarihine ışık tutuyor. Ziyaretçiler, kaleye tırmanarak Dodurga ve çevresinin panoramik manzarasını izleyebilir.", "place_query": "Dodurga Kalesi, Dodurga, Çorum"}, {"title": "Kızılırmak Vadisi (Dodurga Kesimi)", "summary": "Kızılırmak''ın Dodurga sınırları içinden geçen bölümü, doğal güzelliği ve yeşil dokusuyla dikkat çeker. Vadi boyunca yürüyüş yapabilir, kuş gözlemi ve piknik için ideal bir ortam bulabilirsiniz.", "place_query": "Kızılırmak Vadisi, Dodurga, Çorum"}, {"title": "Dodurga Şelalesi", "summary": "İlçe merkezine yaklaşık 5 kilometre uzaklıkta bulunan bu şelale, özellikle bahar ve yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Dodurga Şelalesi, Dodurga, Çorum"}, {"title": "Dodurga Müzesi", "summary": "Küçük ama etkileyici bir koleksiyona sahip olan müze, ilçenin tarih öncesi dönemlerinden Osmanlı''ya kadar uzanan arkeolojik ve etnografik eserleri sergiliyor. Bölge kültürünü yakından tanımak için ziyaret edilmelidir.", "place_query": "Dodurga Müzesi, Dodurga, Çorum"}, {"title": "Dodurga Yaylası", "summary": "İlçeye bağlı yaylalardan biri olan bu alan, temiz havası ve doğal bitki örtüsüyle şehir hayatından kaçmak isteyenler için huzurlu bir kaçış noktasıdır. Özellikle yaz aylarında yayla şenliklerine ev sahipliği yapar.", "place_query": "Dodurga Yaylası, Dodurga, Çorum"}, {"title": "Dodurga Göleti", "summary": "Çevresi ağaçlandırılmış olan bu küçük gölet, piknik alanları ve yürüyüş yollarıyla ailelerin tercih ettiği bir mesire yeridir. Gölet çevresinde olta balıkçılığı da yapılabilmektedir.", "place_query": "Dodurga Göleti, Dodurga, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aafaf72a-2a95-4eb8-a425-640b5fbcbaf1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İskilip Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale, şehre hakim manzarası ve geçmişten gelen sur kalıntılarıyla ziyaretçilerine hem tarihi bir yolculuk hem de panoramik bir seyir imkanı sunar.", "place_query": "İskilip Kalesi, İskilip, Çorum"}, {"title": "İskilip Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, zarif ahşap işçiliği ve huzurlu atmosferiyle ilçenin en önemli dini yapılarından biridir.", "place_query": "İskilip Ulu Camii, İskilip, Çorum"}, {"title": "Kalehisar (Kızılkule) ve Çevresi", "summary": "Eski bir yerleşim alanı olan bölge, tarihi kule kalıntıları ve doğal yapısıyla özellikle doğa yürüyüşü ve fotoğrafçılık için idealdir.", "place_query": "Kalehisar Kızılkule, İskilip, Çorum"}, {"title": "İskilip Evleri (Tarihi Konaklar)", "summary": "Çorum''un geleneksel mimarisini yansıtan bu tarihi evler, cumbalı yapıları ve dar sokaklarıyla ziyaretçilere nostaljik bir atmosfer yaşatır.", "place_query": "Tarihi İskilip Evleri, İskilip, Çorum"}, {"title": "İskilip Şehitliği ve Anıtı", "summary": "Kurtuluş Savaşı ve Çorum yöresinde şehit düşen askerler anısına yapılan bu anıt ve şehitlik, tarihi bir saygı duruşu noktası olarak ziyaret edilmektedir.", "place_query": "İskilip Şehitliği, İskilip, Çorum"}, {"title": "İskilip Kaya Mezarları", "summary": "Helenistik ve Roma dönemine ait olduğu düşünülen bu kaya oyma mezarlar, bölgenin antik dönemdeki yerleşimine ışık tutan önemli arkeolojik kalıntılardır.", "place_query": "İskilip Kaya Mezarları, İskilip, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e70587a2-7216-4e70-8c71-b5bc9b78f4ae'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kargı Yaylaları (Göl Yaylası, Yedikır Yaylası vb.)", "summary": "Kargı''nın en önemli doğal zenginliklerinden olan yaylalar, özellikle yaz aylarında serin havası ve yeşil doğasıyla ziyaretçileri cezbeder. Göl Yaylası ve Yedikır Yaylası, kamp ve doğa yürüyüşü için popüler noktalardır.", "place_query": "Göl Yaylası, Kargı, Çorum"}, {"title": "Kargı Kanyonu", "summary": "Kızılırmak Nehri''nin oluşturduğu etkileyici kanyon, doğa tutkunları için eşsiz bir manzara sunar. Kanyon çevresinde yürüyüş yapabilir ve nehir kenarında piknik yapabilirsiniz.", "place_query": "Kargı Kanyonu, Kargı, Çorum"}, {"title": "Kargı Antik Kenti (Pimolisa)", "summary": "Kargı ilçe merkezinde yer alan antik kent, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklıları için önemli bir duraktır. Bölgede yapılan kazılarda çeşitli mimari parçalar ve sikkeler bulunmuştur.", "place_query": "Pimolisa Antik Kenti, Kargı, Çorum"}, {"title": "Kargı Müzesi", "summary": "İlçede bulunan küçük ama zengin müze, yöreye ait arkeolojik eserler ve etnografik objeleri sergilemektedir. Bölgenin tarihi ve kültürü hakkında bilgi edinmek için ideal bir yerdir.", "place_query": "Kargı Müzesi, Kargı, Çorum"}, {"title": "Kızılırmak Nehri Kenarı", "summary": "Kargı''dan geçen Kızılırmak''ın kenarı, doğa yürüyüşü ve fotoğrafçılık için güzel bir rotadır. Nehir boyunca uzanan yürüyüş parkuru, huzurlu bir gün geçirmek isteyenler için idealdir.", "place_query": "Kızılırmak Nehri, Kargı, Çorum"}, {"title": "Kargı Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, özellikle bahar aylarında suyunun bol olduğu dönemlerde görsel bir şölen sunar. Çevresindeki piknik alanlarıyla aileler için popüler bir kaçış noktasıdır.", "place_query": "Kargı Şelalesi, Kargı, Çorum"}, {"title": "Yediler Manastırı", "summary": "Kargı yakınlarındaki tarihi bir manastır olan Yediler Manastırı, Bizans dönemine ait kalıntıları ve mistik atmosferiyle dikkat çeker. Doğa içinde yer alan bu yapı, tarih ve doğayı bir arada arayanlar için keşfedilmeyi bekliyor.", "place_query": "Yediler Manastırı, Kargı, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '75cd74ad-22ba-46db-b444-c26fcef181ca'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Laçin Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilerine huzurlu bir kaçış sunar. Özellikle bahar ve yaz aylarında akan suyun sesi eşliğinde doğayla iç içe vakit geçirebilirsiniz.", "place_query": "Laçin Şelalesi, Çorum"}, {"title": "Laçin Kalesi", "summary": "Tarihi bir kalıntı olan Laçin Kalesi, ilçeye hakim bir tepe üzerinde yer alır ve çevrenin panoramik manzarasını izleme imkanı sunar. Bölgenin tarihine tanıklık etmek isteyenler için keşfedilmeye değer bir noktadır.", "place_query": "Laçin Kalesi, Çorum"}, {"title": "İncesu Kanyonu", "summary": "Laçin sınırları içinde bulunan bu kanyon, yürüyüş ve doğa fotoğrafçılığı için idealdir. Sarp kayalıklar ve yeşil bitki örtüsüyle çevrili patikaları, macera arayan ziyaretçileri beklemektedir.", "place_query": "İncesu Kanyonu, Laçin, Çorum"}, {"title": "Laçin Göleti", "summary": "İlçe merkezine kısa bir mesafedeki bu gölet, piknik ve olta balıkçılığı için popüler bir duraktır. Sakin atmosferi ve çevresindeki dinlenme alanlarıyla aileler için keyifli bir gün geçirme fırsatı sunar.", "place_query": "Laçin Göleti, Çorum"}, {"title": "Mihri Hatun Camii (Laçin Merkez Camii)", "summary": "Osmanlı dönemine ait bu tarihi cami, mimari detayları ve huzur veren atmosferiyle dikkat çeker. İlçenin kültürel mirasını yansıtan önemli bir yapı olarak ziyaret edilebilir.", "place_query": "Mihri Hatun Camii, Laçin, Çorum"}, {"title": "Laçin Yaylası", "summary": "Şehir hayatından uzaklaşmak isteyenler için ideal olan bu yayla, serin havası ve geniş yeşil alanlarıyla bilinir. Yaylada yürüyüş yapabilir, yöresel lezzetleri tadabilirsiniz.", "place_query": "Laçin Yaylası, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '44026e5f-350b-4597-9885-2e5a6b6b150d'::uuid;
