UPDATE location_pages SET travel_ideas_json = '[{"title": "Koyunbaba Köprüsü", "summary": "Osmancık''ın simgesi olan bu tarihi taş köprü, Koyunbaba Türbesi''nin hemen yanında yer alır ve Kızılırmak üzerinde muhteşem bir manzara sunar. Osmanlı döneminden kalma yapısıyla hem tarihi hem de fotoğrafçılık açısından büyüleyicidir.", "place_query": "Koyunbaba Köprüsü, Osmancık, Çorum"}, {"title": "Koyunbaba Türbesi", "summary": "Osmancık''ın en önemli manevi merkezlerinden biri olan türbe, Koyunbaba Köprüsü''nün hemen yanında bulunur. Ziyaretçiler hem huzur bulmak hem de tarihi atmosferi hissetmek için burayı sıkça ziyaret eder.", "place_query": "Koyunbaba Türbesi, Osmancık, Çorum"}, {"title": "Osmancık Kalesi", "summary": "Şehre hakim bir tepe üzerinde yer alan bu tarihi kale, Selçuklu ve Osmanlı dönemlerine ait izler taşır. Kaleye tırmanarak Osmancık''ın ve Kızılırmak''ın eşsiz panoramik manzarasını izleyebilirsiniz.", "place_query": "Osmancık Kalesi, Osmancık, Çorum"}, {"title": "Kızılırmak Nehri Kenarı ve Mesire Alanı", "summary": "Osmancık''tan geçen Kızılırmak''ın kenarında yer alan bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir. Nehir kenarında yürüyüş yapabilir, huzurlu bir gün geçirebilirsiniz.", "place_query": "Kızılırmak Kenarı Mesire Alanı, Osmancık, Çorum"}, {"title": "Çorum Osmancık Müzesi", "summary": "Osmancık''ta bulunan bu müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Hitit, Roma ve Osmanlı dönemlerine ait eserleri yakından görme fırsatı bulabilirsiniz.", "place_query": "Osmancık Müzesi, Osmancık, Çorum"}, {"title": "Karaören Göleti", "summary": "Osmancık''a bağlı Karaören köyünde bulunan bu gölet, doğal güzelliği ve sakin atmosferiyle bilinir. Balık tutma ve piknik gibi aktiviteler için sıkça tercih edilen bir mekandır.", "place_query": "Karaören Göleti, Osmancık, Çorum"}, {"title": "Osmancık Kaya Mezarları", "summary": "İlçe çevresindeki kayalıklara oyulmuş bu antik mezarlar, Roma dönemine ait önemli kalıntılardır. Tarih meraklıları için keşfedilmeyi bekleyen ilginç bir duraktır.", "place_query": "Osmancık Kaya Mezarları, Osmancık, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '80ddf76f-0a7f-4108-a216-4a367c91a88d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hattuşaş Antik Kenti", "summary": "Hitit İmparatorluğu''nun başkenti olan bu UNESCO Dünya Mirası alanı, devasa surları, Aslanlı Kapı ve Yer Kapı gibi yapılarıyla tarih meraklıları için eşsiz bir durak.", "place_query": "Hattuşaş Antik Kenti, Boğazkale, Çorum"}, {"title": "Yazılıkaya Açık Hava Tapınağı", "summary": "Hattuşaş''ın hemen yakınında yer alan bu kaya tapınağı, Hitit tanrı ve tanrıçalarının kabartmalarıyla ünlüdür ve antik dönemin dini ritüellerine ışık tutar.", "place_query": "Yazılıkaya Açık Hava Tapınağı, Boğazkale, Çorum"}, {"title": "Alacahöyük Ören Yeri", "summary": "Hitit dönemine ait önemli bir yerleşim olan Alacahöyük, Sfenksli Kapı ve kral mezarlarından çıkan altın eserleriyle ziyaretçilerini büyüler.", "place_query": "Alacahöyük Ören Yeri, Alacahöyük, Çorum"}, {"title": "Sungurlu Kalesi", "summary": "Sungurlu ilçe merkezinde bulunan bu tarihi kale, şehrin panoramik manzarasını sunar ve bölgenin savunma yapılarına dair izler taşır.", "place_query": "Sungurlu Kalesi, Sungurlu, Çorum"}, {"title": "Çorum Müzesi", "summary": "Hitit, Frig ve Roma dönemlerine ait zengin bir arkeolojik koleksiyona ev sahipliği yapan müze, bölgenin tarihini keşfetmek için ideal bir noktadır.", "place_query": "Çorum Müzesi, Çorum Merkez, Çorum"}, {"title": "İncesu Kanyonu", "summary": "Sungurlu yakınlarındaki bu doğal kanyon, yemyeşil doğası ve yürüyüş parkurlarıyla doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "İncesu Kanyonu, Sungurlu, Çorum"}, {"title": "Osmancık Kalesi", "summary": "Kızılırmak Nehri kıyısında yükselen bu tarihi kale, Selçuklu ve Osmanlı dönemlerine ait izler taşır ve nehir manzarasıyla fotoğraf tutkunlarını cezbeder.", "place_query": "Osmancık Kalesi, Osmancık, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b8625b13-9a57-4cc8-baf7-2848619e0b5d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Uğurludağ Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan bu tarihi kale, bölgenin en önemli simgelerindendir. Ziyaretçilerine hem tarihi bir atmosfer hem de çevrenin panoramik manzarasını sunar.", "place_query": "Uğurludağ Kalesi, Uğurludağ, Çorum"}, {"title": "İncesu Kanyonu", "summary": "Doğal güzelliği ve yürüyüş parkurlarıyla dikkat çeken bu kanyon, doğa severler için ideal bir kaçış noktasıdır. Kanyon içindeki derin vadiler ve kayalıklar etkileyici bir manzara oluşturur.", "place_query": "İncesu Kanyonu, Uğurludağ, Çorum"}, {"title": "Uğurludağ Şelalesi", "summary": "Özellikle bahar ve yaz aylarında akan bu şelale, çevresindeki yeşil alanlarla birlikte piknik ve doğa yürüyüşü için popüler bir mekandır. Sakin ve huzurlu atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Uğurludağ Şelalesi, Uğurludağ, Çorum"}, {"title": "Yazıcık Göleti", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal olan bu gölet, balık tutma ve kamp gibi aktivitelere olanak sağlar. Çevresi yemyeşil ağaçlarla kaplıdır ve huzurlu bir ortam sunar.", "place_query": "Yazıcık Göleti, Uğurludağ, Çorum"}, {"title": "Uğurludağ Kent Ormanı", "summary": "İlçe merkezine yakın konumda bulunan bu ormanlık alan, yürüyüş yolları ve dinlenme alanlarıyla donatılmıştır. Şehir gürültüsünden uzaklaşıp doğayla baş başa kalmak için sıkça tercih edilir.", "place_query": "Uğurludağ Kent Ormanı, Uğurludağ, Çorum"}, {"title": "Karabıyık Köyü Tarihi Evleri", "summary": "Geleneksel mimariyi yansıtan bu tarihi evler, köy yaşamının izlerini taşır. Ziyaretçiler, bu yapıları gezerek yöresel kültür hakkında bilgi edinebilir ve fotoğraf çekimi yapabilir.", "place_query": "Karabıyık Köyü Tarihi Evler, Uğurludağ, Çorum"}, {"title": "Dedeköy Mağarası", "summary": "Doğal oluşumlu bu mağara, ilçe sınırları içinde keşfedilmeyi bekleyen bir doğa harikasıdır. İçindeki sarkıt ve dikitler, mağara meraklıları için ilgi çekici bir deneyim sunar.", "place_query": "Dedeköy Mağarası, Uğurludağ, Çorum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8c589490-176b-4b3c-b405-24785577a322'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Acıpayam Gölü", "summary": "Doğal güzelliği ve kuş gözlemciliği için ideal bir sulak alan. Sakin atmosferiyle piknik ve doğa yürüyüşü yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Acıpayam Gölü, Acıpayam, Denizli"}, {"title": "Keloğlan Mağarası", "summary": "İlçe merkezine yakın konumdaki bu mağara, sarkıt ve dikitleriyle dikkat çeker. Doğa ve mağara meraklıları için keşfedilmeyi bekleyen bir doğal oluşumdur.", "place_query": "Keloğlan Mağarası, Acıpayam, Denizli"}, {"title": "Acıpayam Yaylaları (Gölcük Yaylası)", "summary": "Yemyeşil doğası, temiz havası ve muhteşem manzarasıyla yaz aylarında serinlemek isteyenlerin tercihidir. Kamp ve doğa yürüyüşleri için uygun bir ortam sunar.", "place_query": "Gölcük Yaylası, Acıpayam, Denizli"}, {"title": "Yatağan Köyü Tarihi Evleri", "summary": "Geleneksel Türk mimarisinin izlerini taşıyan tarihi taş evleriyle ünlüdür. Köy atmosferinde huzurlu bir gezinti yapmak isteyenler için idealdir.", "place_query": "Yatağan Köyü Tarihi Evleri, Acıpayam, Denizli"}, {"title": "Acıpayam Merkez Camii", "summary": "İlçenin simge yapılarından biri olan bu cami, Osmanlı ve Selçuklu mimari etkilerini taşır. Tarihi dokusu ve mimarisiyle ziyaretçilerin ilgisini çeker.", "place_query": "Acıpayam Merkez Camii, Acıpayam, Denizli"}, {"title": "Dedebağ Şelalesi", "summary": "Doğa ile iç içe, serin sularında yüzülebilen ve piknik yapılabilen bir şelaledir. Özellikle yaz aylarında bölge halkının ve ziyaretçilerin uğrak noktasıdır.", "place_query": "Dedebağ Şelalesi, Acıpayam, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '53c8f1f1-080c-42b4-bc15-3e00549f46d7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Babadağ Seyir Terası", "summary": "Denizli ve Babadağ manzarasını kuşbakışı izleyebileceğiniz bu teras, özellikle gün batımında büyüleyici bir atmosfer sunuyor.", "place_query": "Babadağ Seyir Terası, Babadağ, Denizli"}, {"title": "Babadağ Evleri (Tarihi Taş Evler)", "summary": "Yöreye özgü taş ve ahşap mimarinin en güzel örneklerini görebileceğiniz bu evler, dar sokaklarıyla size zamanda yolculuk yaptırıyor.", "place_query": "Babadağ Tarihi Taş Evler, Babadağ, Denizli"}, {"title": "Babadağ Şelalesi", "summary": "Yeşillikler içinde gizlenmiş bu şelale, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için ideal bir durak.", "place_query": "Babadağ Şelalesi, Babadağ, Denizli"}, {"title": "Babadağ Mesire Alanı", "summary": "Ailece piknik yapabileceğiniz, çam ağaçlarıyla çevrili geniş bir alan olup, temiz havası ve doğal güzelliğiyle huzur veriyor.", "place_query": "Babadağ Mesire Alanı, Babadağ, Denizli"}, {"title": "Kale Mahallesi (Tarihi Kale Kalıntıları)", "summary": "Bölgeye adını veren tarihi kale kalıntılarının bulunduğu bu mahalle, hem tarih meraklıları hem de manzara fotoğrafçıları için keşfedilmeyi bekliyor.", "place_query": "Kale Mahallesi Babadağ Denizli"}, {"title": "Babadağ Doğa Yürüyüşü Rotaları", "summary": "Zengin bitki örtüsü ve temiz havasıyla doğa sporları tutkunlarına hitap eden bu patikalar, eşsiz dağ manzaraları eşliğinde yürüyüş imkanı tanıyor.", "place_query": "Babadağ doğa yürüyüşü rotaları Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ce3b6aef-982f-4414-b544-eda9b43f3322'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Baklan Ovası", "summary": "Baklan ilçesinin en belirgin coğrafi özelliği olan geniş ova, tarım alanları ve doğal manzarasıyla dikkat çeker. Özellikle bahar aylarında yeşilin her tonunu görebileceğiniz huzurlu bir kırsal manzara sunar.", "place_query": "Baklan Ovası, Denizli"}, {"title": "Baklan Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, sade mimarisi ve yöresel dini yapı kültürünü yansıtması açısından ziyaret edilebilir. Cami çevresi, ilçenin günlük yaşamını gözlemlemek için de idealdir.", "place_query": "Baklan Merkez Camii, Denizli"}, {"title": "Baklan Şehitliği", "summary": "İlçe yakınlarında bulunan şehitlik, Kurtuluş Savaşı dönemine ait anıları yaşatır. Tarihi değeri ve manevi atmosferi ile ziyaretçilere saygı duruşunda bulunma fırsatı sunar.", "place_query": "Baklan Şehitliği, Denizli"}, {"title": "Baklan Höyüğü", "summary": "Baklan çevresinde yer alan bu arkeolojik höyük, bölgenin eski yerleşim tarihine ışık tutar. Tarih meraklıları için keşfedilmeyi bekleyen önemli bir duraktır.", "place_query": "Baklan Höyüğü, Denizli"}, {"title": "Baklan Yaylası", "summary": "İlçe sınırları içinde yer alan yayla, doğa yürüyüşleri ve piknik için tercih edilen bir alandır. Temiz havası ve sakin ortamı ile şehir gürültüsünden uzaklaşmak isteyenler için idealdir.", "place_query": "Baklan Yaylası, Denizli"}, {"title": "Baklan Göleti", "summary": "Baklan çevresindeki küçük gölet, doğa ile iç içe vakit geçirmek isteyenler için huzurlu bir noktadır. Çevresinde yürüyüş yapabilir ve kuş gözlemi yapabilirsiniz.", "place_query": "Baklan Göleti, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fc8e3902-2fbb-4987-b7b0-cb50dfc3f88b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bekilli Halı ve Kilimleri", "summary": "Bekilli, el dokuması halı ve kilimleriyle ünlüdür. İlçede halıcılık kültürünü yakından tanıyabilir, yöresel desenlerin işlendiği atölyeleri ziyaret edebilirsiniz.", "place_query": "Bekilli Halı ve Kilimleri, Denizli"}, {"title": "Kutlubey Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Kutlubey Camii, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. İlçe merkezinde yer alır ve hâlâ ibadete açıktır.", "place_query": "Kutlubey Camii, Bekilli, Denizli"}, {"title": "Bekilli Kaya Mezarları", "summary": "İlçe çevresindeki kayalık alanlarda bulunan antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Doğa yürüyüşüyle birleştirilebilecek tarihi bir duraktır.", "place_query": "Bekilli Kaya Mezarları, Denizli"}, {"title": "Bekilli Şelalesi", "summary": "İlçe merkezine yakın bir noktada bulunan bu küçük şelale, çevresindeki yeşil alanla piknik ve dinlenme için idealdir. Özellikle bahar aylarında su akışı artar.", "place_query": "Bekilli Şelalesi, Denizli"}, {"title": "Bekilli Yaylası", "summary": "Serin ve temiz havasıyla ünlü Bekilli Yaylası, doğa severler için huzurlu bir kaçış noktasıdır. Yaylada geleneksel yayla evleri ve geniş çayırlar bulunur.", "place_query": "Bekilli Yaylası, Denizli"}, {"title": "Bekilli Etnografya Müzesi", "summary": "Yöresel kıyafetler, dokuma tezgâhları ve gündelik eşyaların sergilendiği bu küçük müze, Bekilli''nin kültürel geçmişini keşfetmek için harika bir yerdir.", "place_query": "Bekilli Etnografya Müzesi, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4c884491-665b-4817-a255-cc8e7bb90ed2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kargı Şelalesi", "summary": "Beyağaç ilçe merkezine yaklaşık 10 km uzaklıkta, doğal güzelliği ile ünlü bir şelaledir. Çevresi piknik alanları ve yürüyüş parkurları ile ziyaretçilere huzurlu bir doğa deneyimi sunar.", "place_query": "Kargı Şelalesi, Beyağaç, Denizli"}, {"title": "Beyağaç Yaylası", "summary": "Beyağaç''ın serin ve yeşil yaylaları, özellikle yaz aylarında doğa severlerin uğrak noktasıdır. Temiz havası, çam ormanları ve manzarası ile kamp ve piknik için idealdir.", "place_query": "Beyağaç Yaylası, Denizli"}, {"title": "Akköy Şelalesi", "summary": "Beyağaç sınırlarında bulunan Akköy Şelalesi, doğal havuzları ve çevresindeki zengin bitki örtüsü ile dikkat çeker. Sessiz bir kaçamak ve fotoğrafçılık için popüler bir duraktır.", "place_query": "Akköy Şelalesi, Beyağaç, Denizli"}, {"title": "Eşen Çayı", "summary": "Beyağaç''tan geçen Eşen Çayı, rafting ve kano gibi su sporlarına elverişli akıntılarıyla bilinir. Çay kenarındaki mesire alanları ise aileler için keyifli bir dinlenme imkanı sunar.", "place_query": "Eşen Çayı, Beyağaç, Denizli"}, {"title": "Beyağaç Merkez Camii ve Tarihi Evler", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki geleneksel Denizli evleri, yöresel mimariyi yansıtır. Kısa bir şehir turu için ilgi çekici noktalardır.", "place_query": "Beyağaç Merkez Camii, Denizli"}, {"title": "Beyağaç Göleti (Sulama Göleti)", "summary": "İlçe yakınlarındaki bu gölet, çevresindeki yeşil alanlarla birlikte balık tutma ve doğa yürüyüşü için tercih edilir. Özellikle gün batımında manzarası görülmeye değerdir.", "place_query": "Beyağaç Göleti, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8d98dc60-c255-47a5-9026-0edd487ba531'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bozkurt İlçe Merkezi ve Çarşısı", "summary": "Denizli''nin şirin ilçelerinden Bozkurt''un merkezinde yerel hayatı gözlemleyebilir, küçük esnaf dükkanlarını gezebilir ve yöresel ürünler satın alabilirsiniz.", "place_query": "Bozkurt Merkez, Denizli"}, {"title": "Bozkurt Kalesi", "summary": "İlçeye hakim bir tepede bulunan tarihi kale kalıntıları, bölgenin antik dönemine ışık tutar ve çevreye karşı muhteşem bir manzara sunar.", "place_query": "Bozkurt Kalesi, Denizli"}, {"title": "Geyik Dağı", "summary": "Doğa yürüyüşleri ve kamp için ideal olan bu dağ, zengin bitki örtüsü ve temiz havasıyla doğaseverlerin ilgisini çeker.", "place_query": "Geyik Dağı, Bozkurt, Denizli"}, {"title": "Bozkurt Göleti", "summary": "Şehir merkezine yakın konumda bulunan bu yapay gölet, piknik alanları ve yürüyüş yolları ile hafta sonu kaçamakları için popüler bir noktadır.", "place_query": "Bozkurt Göleti, Denizli"}, {"title": "Baba Dağı", "summary": "Denizli''nin önemli yükseltilerinden biri olan Baba Dağı, özellikle yamaç paraşütü ve doğa sporları için bilinir; nefes kesici bir panoramaya sahiptir.", "place_query": "Baba Dağı, Bozkurt, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '35310b61-9d03-451f-a8c2-08172d70ae4f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Buldan Evleri", "summary": "Tarihi dokusuyla ünlü, dar sokakları ve restore edilmiş geleneksel evleriyle ziyaretçilere geçmişe yolculuk yaptıran bir yerleşim alanıdır.", "place_query": "Buldan Evleri, Buldan, Denizli"}, {"title": "Buldan Yaylası ve Gözlem Terası", "summary": "Doğal güzellikleri ve temiz havasıyla ünlü olan yayla, özellikle gün batımında muhteşem manzaralar sunan seyir terasıyla dikkat çeker.", "place_query": "Buldan Yaylası, Buldan, Denizli"}, {"title": "Kemer Barajı ve Mesire Alanı", "summary": "Baraj gölü çevresinde piknik yapma, yürüyüş ve doğayla iç içe vakit geçirme imkanı sunan popüler bir dinlenme noktasıdır.", "place_query": "Kemer Barajı, Buldan, Denizli"}, {"title": "Buldan El Dokuması Atölyeleri", "summary": "Yöreye özgü Buldan bezi ve el dokuması ürünlerin üretildiği atölyelerde hem üretim sürecini görebilir hem de hediyelik eşya satın alabilirsiniz.", "place_query": "Buldan El Dokuması Atölyeleri, Buldan, Denizli"}, {"title": "Tripolis Antik Kenti", "summary": "Buldan yakınlarında yer alan bu antik kent, Roma ve Bizans dönemine ait kalıntılarıyla tarih meraklıları için önemli bir duraktır.", "place_query": "Tripolis Antik Kenti, Buldan, Denizli"}, {"title": "Buldan Şelalesi", "summary": "Yeşillikler içinde gizlenmiş bu küçük şelale, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için ideal bir noktadır.", "place_query": "Buldan Şelalesi, Buldan, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2784e9fa-7bf0-4d87-aad6-d49087defea8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çal Bağları ve Şarap Evleri", "summary": "Çal, üzüm bağları ve şaraplarıyla ünlüdür. Bölgedeki şarap evlerini ziyaret ederek yerel üzüm çeşitlerini tadabilir ve bağlar arasında keyifli bir gün geçirebilirsiniz.", "place_query": "Çal Bağları, Denizli"}, {"title": "Küçük Menderes Irmağı Kenarı", "summary": "Çal ilçe merkezinden geçen Küçük Menderes Irmağı''nın kenarı, doğal güzelliği ve huzurlu atmosferiyle yürüyüş ve piknik için idealdir.", "place_query": "Küçük Menderes Irmağı, Çal, Denizli"}, {"title": "Çal Şehir Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenme ve çocuklar için oyun alanlarıyla ailelerin uğrak noktasıdır. Yeşil alanları ve oturma banklarıyla keyifli bir mola sunar.", "place_query": "Çal Şehir Parkı, Denizli"}, {"title": "Çal Tarihi Çarşı ve Camiler", "summary": "Çal''ın tarihi dokusunu yansıtan çarşısı ve Osmanlı döneminden kalma camileri, kültürel bir gezi için keşfedilmeye değerdir.", "place_query": "Çal Tarihi Çarşı, Denizli"}, {"title": "Akköy Kaplıcaları", "summary": "Çal ilçesine bağlı Akköy''de bulunan bu kaplıcalar, şifalı termal sularıyla sağlık turizmi için popüler bir duraktır.", "place_query": "Akköy Kaplıcaları, Çal, Denizli"}, {"title": "Çal Kalesi (Kale Mahallesi)", "summary": "Tarihi bir kale kalıntısı olan Çal Kalesi, bölgenin geçmişine ışık tutar ve çevresindeki manzara eşliğinde kısa bir yürüyüş rotası sunar.", "place_query": "Çal Kalesi, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd1a5b7ab-c342-41c3-a928-ff35d1f1bd8c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölcük Gölü", "summary": "Çameli ilçe merkezine yaklaşık 8 km uzaklıkta bulunan bu krater gölü, çam ormanlarıyla çevrili doğal güzelliği ve piknik alanlarıyla ziyaretçilerin uğrak noktasıdır. Gökyüzünün ve yeşilin birleştiği manzarasıyla fotoğrafçılar ve doğa severler için idealdir.", "place_query": "Gölcük Gölü, Çameli, Denizli"}, {"title": "Çameli Yaylaları (Örneğin: Gölemezli Yaylası)", "summary": "Çameli, serin ve yeşil yaylalarıyla ünlüdür; Gölemezli Yaylası bunların başında gelir. Temiz havası, geniş çayırları ve doğa yürüyüşü rotalarıyla özellikle yaz aylarında şehir hayatından kaçmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Gölemezli Yaylası, Çameli, Denizli"}, {"title": "Kızılyaka Şelalesi", "summary": "İlçe merkezine yaklaşık 15 km mesafedeki Kızılyaka Şelalesi, doğal havuzları ve çevresindeki sık ormanlık alanıyla serinlemek ve doğayla iç içe vakit geçirmek için popüler bir duraktır. Özellikle bahar aylarında suyun debisi artarak etkileyici bir görüntü oluşturur.", "place_query": "Kızılyaka Şelalesi, Çameli, Denizli"}, {"title": "Çameli Merkez Camii ve Tarihi Evler", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki geleneksel Türk evleri, Çameli''nin kültürel dokusunu yansıtır. Dar sokaklarda yapılacak kısa bir yürüyüş, bölgenin geçmişine dair ipuçları verir ve sakin bir atmosfer sunar.", "place_query": "Çameli Merkez Camii, Denizli"}, {"title": "Yaylacık Köyü Kaya Mezarları", "summary": "Çameli''nin Yaylacık Köyü''nde bulunan bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Kayalara oyulmuş bu mezarlar, hem tarih meraklıları hem de farklı bir kültürel deneyim arayanlar için ilgi çekicidir.", "place_query": "Yaylacık Köyü Kaya Mezarları, Çameli, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1fb6dfaf-07af-49ff-9395-9621ed622879'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çardak Gölü", "summary": "Denizli''nin önemli sulak alanlarından biri olan Çardak Gölü, kuş gözlemcileri ve doğa severler için huzurlu bir kaçış noktasıdır. Göçmen kuşlara ev sahipliği yapan göl, sakin atmosferiyle piknik ve yürüyüş için idealdir.", "place_query": "Çardak Gölü, Çardak, Denizli"}, {"title": "Çardak Kaplıcaları", "summary": "Termal sularıyla ünlü Çardak Kaplıcaları, şifalı sularında yıkanmak ve dinlenmek isteyen ziyaretçileri ağırlar. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan kaplıcalar, bölgenin en popüler sağlık turizmi noktalarındandır.", "place_query": "Çardak Kaplıcaları, Çardak, Denizli"}, {"title": "Çardak Hanı", "summary": "Tarihi İpek Yolu üzerinde yer alan Çardak Hanı, Selçuklu döneminden kalma önemli bir kervansaraydır. Kesme taştan yapılmış bu tarihi yapı, geçmişin ticaret ve konaklama kültürünü yansıtan etkileyici bir mimariye sahiptir.", "place_query": "Çardak Hanı, Çardak, Denizli"}, {"title": "Çardak Ulu Camii", "summary": "Osmanlı dönemine ait Çardak Ulu Camii, sade ama zarif mimarisiyle dikkat çeker. Tarihi dokusu ve huzur veren atmosferiyle ibadet ve ziyaret için önemli bir duraktır.", "place_query": "Çardak Ulu Camii, Çardak, Denizli"}, {"title": "Denizli Çardak Havalimanı", "summary": "Bölgenin hava ulaşımını sağlayan Denizli Çardak Havalimanı, modern terminal binası ve geniş otoparkı ile ziyaretçilere kolaylık sunar. Havalimanı çevresi, uçak izleme ve fotoğrafçılık için de popüler bir noktadır.", "place_query": "Denizli Çardak Havalimanı, Çardak, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '23dfb19b-8e19-4e01-b4f9-ad9871108534'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akdağ Tabiat Parkı", "summary": "Denizli''nin önemli doğal alanlarından biri olan Akdağ, zengin flora ve faunası, yürüyüş parkurları ve kamp alanlarıyla doğa severler için ideal bir kaçış noktasıdır. Özellikle bahar aylarında yeşilin her tonunu görebileceğiniz bu park, şehir gürültüsünden uzaklaşmak isteyenler için huzurlu bir ortam sunar.", "place_query": "Akdağ Tabiat Parkı, Çivril, Denizli"}, {"title": "Çivril Belediye Müzesi", "summary": "Çivril ve çevresinin tarihini, kültürünü ve arkeolojik zenginliklerini sergileyen bu müze, bölgenin geçmişine ışık tutan önemli bir duraktır. Hitit, Frig, Roma ve Bizans dönemlerine ait eserlerin yanı sıra yöresel etnografik objeler de ziyaretçilerin ilgisini çekmektedir.", "place_query": "Çivril Belediye Müzesi, Denizli"}, {"title": "Işıklı Gölü", "summary": "Çivril sınırları içinde yer alan Işıklı Gölü, kuş gözlemciliği ve doğa fotoğrafçılığı için popüler bir noktadır. Gölde yaşayan endemik balık türleri ve çevresindeki sazlıklar, bölgeye ayrı bir doğal güzellik katar; özellikle gün batımında manzarası büyüleyicidir.", "place_query": "Işıklı Gölü, Çivril, Denizli"}, {"title": "Beycesultan Höyüğü", "summary": "Tunç Çağı''ndan kalma önemli bir arkeolojik alan olan Beycesultan Höyüğü, Hitit ve öncesi dönemlere ait izler taşır. Bölgedeki kazılarda ortaya çıkarılan saray kalıntıları ve eserler, tarih meraklıları için eşsiz bir keşif fırsatı sunar.", "place_query": "Beycesultan Höyüğü, Çivril, Denizli"}, {"title": "Gümüşsu Şelalesi", "summary": "Çivril''in doğal güzelliklerinden biri olan Gümüşsu Şelalesi, serin suları ve çevresindeki yeşil alanlarla piknik ve dinlenme için tercih edilen bir mekandır. Özellikle yaz aylarında şelalenin sesi eşliğinde huzur bulmak mümkündür.", "place_query": "Gümüşsu Şelalesi, Çivril, Denizli"}, {"title": "Çivril Kalesi", "summary": "Tarihi bir geçmişe sahip olan Çivril Kalesi, ilçe merkezine hakim bir tepede yer alır ve çevreye panoramik bir manzara sunar. Kale kalıntıları arasında yapacağınız bir yürüyüş, hem tarihe tanıklık etmenizi hem de eşsiz bir fotoğraf karesi yakalamanızı sağlar.", "place_query": "Çivril Kalesi, Denizli"}, {"title": "Kızılhisar Yaylası", "summary": "Çivril''e bağlı Kızılhisar köyü yakınlarındaki bu yayla, özellikle yaz aylarında serin havası ve doğal güzellikleriyle kampçılar ve doğa yürüyüşçüleri için idealdir. Yaylada geleneksel yayla hayatını deneyimleyebilir, yöresel lezzetleri tadabilirsiniz.", "place_query": "Kızılhisar Yaylası, Çivril, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c1df81b4-95ba-4d5d-a1b6-c77acea69e1c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güney Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla bölge halkının ve ziyaretçilerin uğrak noktasıdır. Piknik alanları ve yürüyüş parkurlarıyla keyifli bir gün geçirebilirsiniz.", "place_query": "Güney Şelalesi, Güney, Denizli"}, {"title": "Güney Kalesi", "summary": "Tarihi bir kalıntı olan Güney Kalesi, ilçeye hakim bir tepede yer alır ve çevrenin panoramik manzarasını sunar. Tarih ve doğa severler için ideal bir duraktır.", "place_query": "Güney Kalesi, Güney, Denizli"}, {"title": "Güney İlçe Merkezi Tarihi Çarşı", "summary": "Geleneksel mimariyi yansıtan dükkanları ve samimi atmosferiyle ünlüdür. Yöresel ürünler satın alabilir ve yöre halkıyla sohbet edebilirsiniz.", "place_query": "Güney Çarşı, Güney, Denizli"}, {"title": "Güney Mesire Alanı", "summary": "Yeşillikler içinde huzurlu bir ortam arayanlar için biçilmiş kaftandır. Ailece piknik yapabileceğiniz ve doğayla iç içe vakit geçirebileceğiniz bir noktadır.", "place_query": "Güney Mesire Alanı, Güney, Denizli"}, {"title": "Güney Göleti", "summary": "Balık tutma ve doğa yürüyüşü gibi aktiviteler için popüler bir mekandır. Sakin suyu ve çevresindeki yeşil alanlarıyla fotoğrafçılar için de güzel kareler sunar.", "place_query": "Güney Göleti, Güney, Denizli"}, {"title": "Karahayıt Kaplıcaları", "summary": "Güney ilçesine yakın konumda bulunan bu kaplıcalar, şifalı termal sularıyla ünlüdür. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılır ve konaklama imkanı sunar.", "place_query": "Karahayıt Kaplıcaları, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9a2b9161-b3f4-48f4-b1bc-7aea8df5230c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Honaz Dağı Milli Parkı", "summary": "Denizli''nin en yüksek noktası olan Honaz Dağı, eşsiz doğası ve yürüyüş parkurlarıyla doğa severler için ideal bir kaçış noktasıdır. Zirveye tırmanırken göreceğiniz manzara ve temiz havasıyla ünlüdür.", "place_query": "Honaz Dağı Milli Parkı, Honaz, Denizli"}, {"title": "Kaklık Mağarası", "summary": "Sarkıt ve dikitleriyle ünlü bu mağara, traverten oluşumları ve içindeki gölüyle büyüleyici bir doğa harikasıdır. Ziyaretçilerine serin ve mistik bir atmosfer sunar.", "place_query": "Kaklık Mağarası, Honaz, Denizli"}, {"title": "Honaz Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan Honaz Kalesi, bölgeye hakim manzarası ve antik kalıntılarıyla tarih meraklılarının ilgisini çeker. Çevresindeki doğal güzelliklerle birlikte keyifli bir gezi rotası sunar.", "place_query": "Honaz Kalesi, Honaz, Denizli"}, {"title": "Kocabaş Kaplıcaları", "summary": "Şifalı termal sularıyla bilinen Kocabaş Kaplıcaları, dinlenmek ve sağlık bulmak isteyenler için popüler bir duraktır. Doğal ortamında termal banyo yapma imkanı sunar.", "place_query": "Kocabaş Kaplıcaları, Honaz, Denizli"}, {"title": "Honaz Şelalesi", "summary": "Yemyeşil bitki örtüsü arasında gizlenmiş bu şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için idealdir. Sakin atmosferiyle piknikçilerin de uğrak noktasıdır.", "place_query": "Honaz Şelalesi, Honaz, Denizli"}, {"title": "Honaz Kent Ormanı", "summary": "Geniş çam ağaçları ve yürüyüş yollarıyla donatılmış Kent Ormanı, aileler ve spor yapmak isteyenler için huzurlu bir ortam sağlar. Piknik alanları ve çocuk oyun parklarıyla da dikkat çeker.", "place_query": "Honaz Kent Ormanı, Honaz, Denizli"}, {"title": "Emirazizli Mahallesi Antik Kalıntılar", "summary": "Bölgedeki antik dönem izlerini taşıyan bu kalıntılar, Honaz''ın tarihi geçmişine ışık tutar. Tarih öncesi dönemlere ait yapı parçaları ve lahitler görmek mümkündür.", "place_query": "Emirazizli Mahallesi Antik Kalıntılar, Honaz, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6ff63263-31fb-4de1-a32f-be6e205594c5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kaleiçi Mahallesi ve Tarihi Evler", "summary": "Kale ilçe merkezindeki bu mahalle, geleneksel Denizli evlerinin en güzel örneklerini barındırır. Dar sokakları ve taş yapılarıyla ziyaretçilere geçmişe kısa bir yolculuk yapma fırsatı sunar.", "place_query": "Kaleiçi Mahallesi, Kale, Denizli"}, {"title": "Kale Kalesi (Tabae Antik Kenti)", "summary": "İlçeye adını veren bu tarihi kale, Tabae Antik Kenti''nin kalıntıları üzerinde yükselir. Bölgenin en eski yerleşimlerinden biri olan kale, hem tarihi dokusu hem de tepeden sunduğu manzara ile görülmeye değerdir.", "place_query": "Tabae Antik Kenti, Kale, Denizli"}, {"title": "Gökçeoren Şelalesi", "summary": "Kale ilçesine bağlı Gökçeören köyü yakınlarında bulunan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla hafta sonu kaçamaklarının favorisidir. Serin suları ve yeşil doğası fotoğrafçılar için de idealdir.", "place_query": "Gökçeören Şelalesi, Kale, Denizli"}, {"title": "Kale Barajı ve Mesire Alanı", "summary": "Kale Baraj Gölü çevresinde yer alan mesire alanı, doğa yürüyüşleri ve piknik için popüler bir duraktır. Su sporları ve olta balıkçılığı yapmak isteyenler için de sakin bir ortam sunar.", "place_query": "Kale Barajı, Kale, Denizli"}, {"title": "Çamlıca Yaylası", "summary": "Kale''nin serin yaylalarından biri olan Çamlıca, özellikle yaz aylarında sıcaktan kaçanlar için biçilmiş kaftandır. Çam ormanları arasında huzurlu bir doğa deneyimi arayanların uğrak noktasıdır.", "place_query": "Çamlıca Yaylası, Kale, Denizli"}, {"title": "Kale Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, Kale''nin simge yapılarından biridir. Cumhuriyet dönemi mimarisinin bir örneği olan kule, çevresindeki meydan ile birlikte şehir turunun başlangıç noktasıdır.", "place_query": "Kale Saat Kulesi, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '26400a57-d3d2-4910-ab5a-2a1bba0ed31a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pamukkale Travertenleri", "summary": "Beyaz kireç taşı travertenleri ve antik Hierapolis kenti ile ünlü bu doğal harika, UNESCO Dünya Mirası Listesi''ndedir. Ziyaretçiler travertenlerde yürüyebilir ve antik havuzda yüzebilir.", "place_query": "Pamukkale Travertenleri, Pamukkale, Denizli"}, {"title": "Hierapolis Antik Kenti", "summary": "Pamukkale''nin hemen yanında yer alan bu antik kent, Roma dönemine ait tiyatro, hamam ve tapınak kalıntılarıyla büyüleyicidir. Nekropolü ve antik havuzu da mutlaka görülmelidir.", "place_query": "Hierapolis Antik Kenti, Pamukkale, Denizli"}, {"title": "Laodikya Antik Kenti", "summary": "Denizli şehir merkezine yakın bu antik kent, iyi korunmuş stadyumu, çeşmeleri ve sütunlu caddeleriyle ünlüdür. Erken Hristiyanlık döneminin önemli merkezlerinden biridir.", "place_query": "Laodikya Antik Kenti, Denizli Merkez, Denizli"}, {"title": "Denizli Atatürk ve Etnografya Müzesi", "summary": "Şehir merkezinde bulunan bu müze, Atatürk''ün Denizli ziyaretinde kaldığı evde hizmet vermektedir. İçeride yöresel kıyafetler, el sanatları ve tarihi eserler sergilenir.", "place_query": "Denizli Atatürk ve Etnografya Müzesi, Merkezefendi, Denizli"}, {"title": "Çamlık Parkı", "summary": "Merkezefendi ilçesinde yer alan bu geniş park, yürüyüş yolları, göleti ve yeşil alanlarıyla şehir içinde dinlenmek için ideal bir noktadır. Aileler ve doğa severler için popülerdir.", "place_query": "Çamlık Parkı, Merkezefendi, Denizli"}, {"title": "Kaklık Mağarası", "summary": "Pamukkale''ye benzer traverten oluşumlarına sahip bu mağara, içindeki sarkıt ve dikitlerle dikkat çeker. Mağaranın içindeki sığ gölde yüzme imkanı da sunar.", "place_query": "Kaklık Mağarası, Kaklık, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4792830f-5acf-44bf-a96f-c0420f2035df'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pamukkale Travertenleri", "summary": "Bembeyaz kalker teraslarıyla dünyaca ünlü bu doğa harikası, sıcak termal suların oluşturduğu havuzları ve eşsiz manzarasıyla ziyaretçilerini büyüler.", "place_query": "Pamukkale Travertenleri, Pamukkale, Denizli"}, {"title": "Hierapolis Antik Kenti", "summary": "Pamukkale''nin hemen yanı başındaki bu antik kent, Roma dönemine ait tiyatrosu, nekropolü ve antik havuzuyla tarih meraklıları için kaçırılmaz bir duraktır.", "place_query": "Hierapolis Antik Kenti, Pamukkale, Denizli"}, {"title": "Kleopatra Antik Havuzu", "summary": "Sıcak termal suyun içinde antik sütunlar ve mermer parçaları arasında yüzme imkanı sunan bu havuz, hem tarihi hem de sağlık turizmi açısından popülerdir.", "place_query": "Kleopatra Antik Havuzu, Pamukkale, Denizli"}, {"title": "Pamukkale Doğal Parkı", "summary": "Travertenleri, antik kenti ve doğal yaşamı bir arada barındıran bu koruma alanı, yürüyüş parkurları ve piknik alanlarıyla doğaseverler için idealdir.", "place_query": "Pamukkale Doğal Parkı, Pamukkale, Denizli"}, {"title": "Laodikya Antik Kenti", "summary": "Pamukkale''ye yaklaşık 10 km uzaklıktaki bu antik kent, iyi korunmuş stadyumu, tiyatrosu ve mozaikleriyle önemli bir arkeolojik alan olarak öne çıkar.", "place_query": "Laodikya Antik Kenti, Denizli"}, {"title": "Karahayıt Kırmızı Suyu", "summary": "Demir oksit nedeniyle kırmızı renkli termal sularıyla ünlü bu bölge, şifalı kaplıcaları ve kendine özgü kırmızı travertenleriyle dikkat çeker.", "place_query": "Karahayıt Kırmızı Su, Pamukkale, Denizli"}, {"title": "Pamukkale Antik Tiyatro", "summary": "Hierapolis''in görkemli yapılarından biri olan bu tiyatro, 12.000 kişilik kapasitesi ve etkileyici akustiğiyle ziyaretçilere tarihi bir atmosfer sunar.", "place_query": "Hierapolis Antik Tiyatro, Pamukkale, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd63e078c-0b92-4b14-a73c-d2c8610a14d8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarayköy Kaplıcaları", "summary": "Denizli''nin önemli termal turizm merkezlerinden biridir. Romatizmal hastalıklar ve cilt rahatsızlıklarına iyi gelen şifalı sularıyla ünlüdür; dinlenme ve sağlık amaçlı ziyaret edilir.", "place_query": "Sarayköy Kaplıcaları, Sarayköy, Denizli"}, {"title": "Tekke Kaplıcası", "summary": "Sarayköy''ün en bilinen termal tesislerinden biridir. Doğal sıcak su kaynakları ve modern havuzlarıyla yıl boyunca ziyaretçi çeker.", "place_query": "Tekke Kaplıcası, Sarayköy, Denizli"}, {"title": "Sarayköy Saat Kulesi", "summary": "İlçe merkezinde yer alan tarihi bir yapıdır. Cumhuriyet dönemi mimarisinin izlerini taşıyan kule, şehrin simgelerinden biridir.", "place_query": "Sarayköy Saat Kulesi, Sarayköy, Denizli"}, {"title": "Kızıldere Travertenleri", "summary": "Pamukkale''ye benzer beyaz traverten oluşumlarına sahip doğal bir alandır. Termal suların oluşturduğu bu yapılar, doğa fotoğrafçıları için ilgi çekicidir.", "place_query": "Kızıldere Travertenleri, Sarayköy, Denizli"}, {"title": "Sarayköy Menderes Nehri Kenarı", "summary": "Büyük Menderes Nehri''nin kıyısında yer alan bu bölge, piknik ve doğa yürüyüşü için idealdir. Huzurlu atmosferiyle yerli halkın sıkça tercih ettiği bir mesire alanıdır.", "place_query": "Sarayköy Menderes Nehri kenarı, Sarayköy, Denizli"}, {"title": "Sığma Köyü Kaya Mezarları", "summary": "Antik döneme ait kaya mezarlarının bulunduğu tarihi bir alandır. Frig veya Roma dönemine ait olduğu düşünülen bu yapılar, tarih meraklıları için keşfedilmeyi bekler.", "place_query": "Sığma Köyü Kaya Mezarları, Sarayköy, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8ee5f3d5-6ecd-4df2-be22-ab34c23e8b1b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Serinhisar Yaylası", "summary": "Serinhisar''ın en bilinen doğal güzelliklerinden biridir. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir; yemyeşil alanları ve temiz havasıyla ünlüdür.", "place_query": "Serinhisar Yaylası, Denizli"}, {"title": "Karahisar Kalesi", "summary": "İlçeye adını veren tarihi bir kaledir. Afyonkarahisar''daki ünlü kaleyle karıştırılmamalıdır; Serinhisar''ın eski adı ''Karahisar''dan gelir ve kale kalıntıları bölgenin tarihine ışık tutar.", "place_query": "Karahisar Kalesi, Serinhisar, Denizli"}, {"title": "Yatağan Mesire Alanı", "summary": "Serinhisar''a yakın mesafede, piknik ve doğa yürüyüşleri için ideal bir alandır. Ağaçlarla çevrili ortamı ve şelalesiyle özellikle hafta sonları ziyaretçi akınına uğrar.", "place_query": "Yatağan Mesire Alanı, Serinhisar, Denizli"}, {"title": "Serinhisar Kapalı Pazar Yeri", "summary": "İlçenin en hareketli noktalarından biridir. Yöresel ürünlerin, özellikle Serinhisar''ın meşhur leblebisinin satıldığı bu pazar, hem alışveriş hem de yerel kültürü tanımak için idealdir.", "place_query": "Serinhisar Kapalı Pazar Yeri, Denizli"}, {"title": "Serinhisar Leblebiciler Çarşısı", "summary": "Denizli''nin leblebi diyarı olarak bilinen Serinhisar''da, bu çarşıda birbirinden farklı leblebi çeşitlerini tadabilir ve satın alabilirsiniz. Bölgeye özgü bir lezzet deneyimi sunar.", "place_query": "Serinhisar Leblebiciler Çarşısı, Denizli"}, {"title": "Kızılhisar Göleti", "summary": "Serinhisar''a birkaç kilometre uzaklıkta, doğal bir gölet ve çevresinde piknik alanları bulunur. Sakin atmosferi ve manzarasıyla doğaseverler için huzurlu bir kaçış noktasıdır.", "place_query": "Kızılhisar Göleti, Serinhisar, Denizli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'da472144-274f-4dd5-8b93-0e054008ef86'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karahayıt Köyü ve Kırmızı Su", "summary": "Pamukkale''ye 5 km uzaklıktaki bu köy, demir oksit nedeniyle kırmızı renkli termal suyuyla ünlüdür. Şifalı sularında yıkanabilir, çamur banyosu yapabilir ve bölgedeki otellerde konaklayabilirsiniz.", "place_query": "Karahayıt Köyü, Denizli, Türkiye"}, {"title": "Pamukkale Travertenleri", "summary": "UNESCO Dünya Mirası listesindeki Pamukkale, beyaz traverten terasları ve antik Hierapolis kentiyle dünyaca ünlüdür. Sıcak termal sularla oluşan bu doğa harikası, mutlaka görülmesi gereken bir yerdir.", "place_query": "Pamukkale Travertenleri, Denizli, Türkiye"}, {"title": "Hierapolis Antik Kenti", "summary": "Pamukkale''nin hemen üzerinde yer alan antik kent, Roma döneminden kalma tiyatro, agora, nekropol ve antik havuzuyla ziyaretçileri zamanda yolculuğa çıkarır. Antik havuzda tarihi sütunlar arasında yüzmek eşsiz bir deneyimdir.", "place_query": "Hierapolis Antik Kenti, Denizli, Türkiye"}, {"title": "Laodikeia Antik Kenti", "summary": "Denizli şehir merkezine yakın bu antik kent, Anadolu''nun en önemli arkeolojik alanlarından biridir. Stadyum, çeşmeler, anıtsal kapılar ve iyi korunmuş tiyatrosuyla tarih meraklılarını kendine çeker.", "place_query": "Laodikeia Antik Kenti, Denizli, Türkiye"}, {"title": "Çamlık Şelalesi", "summary": "Tavas ilçe merkezine 15 km uzaklıkta bulunan bu şelale, çam ormanlarıyla çevrili serinletici bir doğa kaçamağı sunar. Piknik alanları ve yürüyüş parkurlarıyla hafta sonu gezileri için idealdir.", "place_query": "Çamlık Şelalesi, Tavas, Denizli, Türkiye"}, {"title": "Tavas Ulu Camii", "summary": "Osmanlı döneminden kalma bu tarihi cami, Tavas''ın merkezinde yer alır ve ahşap işçiliğiyle dikkat çeker. Restore edilmiş yapısıyla hem ibadet hem de kültürel ziyaret noktasıdır.", "place_query": "Tavas Ulu Camii, Denizli, Türkiye"}, {"title": "Güney İlçesi (Kayaköy)", "summary": "Tavas''a bağlı Güney beldesindeki Kayaköy, doğal güzellikleri ve sakin atmosferiyle bilinir. Bölgede yürüyüş yapabilir, yöresel lezzetleri tadabilirsiniz.", "place_query": "Kayaköy, Güney, Denizli, Türkiye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'be9269e8-6e7d-48d7-9249-f9af113c094e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Diyarbakır Surları", "summary": "Dünyanın en uzun ve en sağlam surlarından biri olan Diyarbakır Surları, şehrin simgesidir. Burçları ve kapılarıyla tarihe tanıklık eden bu benzersiz yapıyı mutlaka görmelisiniz.", "place_query": "Diyarbakır Surları, Sur, Diyarbakır"}, {"title": "Hevsel Bahçeleri", "summary": "Dicle Nehri kıyısında, binlerce yıldır tarım yapılan bu verimli bahçeler, UNESCO Dünya Mirası Listesi''ndedir. Şehrin gürültüsünden kaçıp doğayla baş başa kalmak için ideal bir yerdir.", "place_query": "Hevsel Bahçeleri, Sur, Diyarbakır"}, {"title": "Ulu Cami", "summary": "Anadolu''nun en eski camilerinden biri olan Diyarbakır Ulu Cami, farklı medeniyetlerin izlerini taşıyan etkileyici bir yapıdır. Avlusu ve mimarisiyle ziyaretçilerini büyüler.", "place_query": "Diyarbakır Ulu Cami, Sur, Diyarbakır"}, {"title": "Hasan Paşa Hanı", "summary": "Tarihi bir Osmanlı kervansarayı olan Hasan Paşa Hanı, günümüzde kafeleri ve hediyelik eşya dükkanlarıyla canlı bir mekandır. Mardin taşından yapılmış avlusunda çay içmek keyiflidir.", "place_query": "Hasan Paşa Hanı, Sur, Diyarbakır"}, {"title": "Dicle Nehri Kenarı", "summary": "Diyarbakır''ın hayat kaynağı olan Dicle Nehri, özellikle On Gözlü Köprü çevresinde yürüyüş yapmak ve manzaranın tadını çıkarmak için harika bir noktadır.", "place_query": "Dicle Nehri, Sur, Diyarbakır"}, {"title": "Cahit Sıtkı Tarancı Müzesi", "summary": "Ünlü şair Cahit Sıtkı Tarancı''nın doğduğu ev, günümüzde müze olarak ziyarete açıktır. Şairin kişisel eşyaları ve eserlerinin sergilendiği bu samimi müze, edebiyatseverler için anlamlı bir duraktır.", "place_query": "Cahit Sıtkı Tarancı Müzesi, Sur, Diyarbakır"}, {"title": "Malabadi Köprüsü", "summary": "Diyarbakır''ın Silvan ilçesinde bulunan bu tarihi taş köprü, dünyanın en geniş taş kemerli köprülerinden biridir. Görkemli yapısı ve çevresindeki doğal güzelliklerle etkileyicidir.", "place_query": "Malabadi Köprüsü, Silvan, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '79ffc476-5730-48d0-b4a7-4d1f29e3948f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zerzevan Kalesi", "summary": "Roma İmparatorluğu döneminde askeri yerleşim olarak kullanılan bu etkileyici kale, Mithras Tapınağı ile de ünlüdür. Tarihi surlar, yer altı yapıları ve muhteşem manzarasıyla ziyaretçilerini büyüler.", "place_query": "Zerzevan Kalesi, Bismil, Diyarbakır"}, {"title": "Diyarbakır Surları (Bismil Kesimi)", "summary": "UNESCO Dünya Mirası Listesi''ndeki Diyarbakır Surları''nın Bismil sınırları içinde kalan bölümü, tarihi ihtişamı ve benzersiz mimarisiyle görülmeye değerdir. Özellikle burçlar ve kapılar dikkat çeker.", "place_query": "Diyarbakır Surları, Bismil, Diyarbakır"}, {"title": "Dicle Nehri Kıyıları", "summary": "Bismil''den geçen Dicle Nehri''nin kıyıları, doğal güzelliği ve piknik alanlarıyla huzurlu bir kaçamak sunar. Özellikle bahar aylarında yeşilin ve suyun tadını çıkarabilirsiniz.", "place_query": "Dicle Nehri, Bismil, Diyarbakır"}, {"title": "Bismil Ulu Camii", "summary": "Tarihi bir yapı olan Bismil Ulu Camii, bölgenin dini ve kültürel mirasını yansıtır. Sade ama etkileyici mimarisiyle ibadet ve ziyaret için önemli bir noktadır.", "place_query": "Bismil Ulu Camii, Bismil, Diyarbakır"}, {"title": "Yukarıdarlı Göleti", "summary": "Bismil''e bağlı Yukarıdarlı köyünde yer alan bu gölet, doğa ile iç içe sakin bir ortam arayanlar için idealdir. Çevresindeki yeşil alanlar ve kuş sesleri eşliğinde yürüyüş yapabilirsiniz.", "place_query": "Yukarıdarlı Göleti, Bismil, Diyarbakır"}, {"title": "Bismil Müzesi", "summary": "Bismil''deki arkeolojik kazılardan çıkarılan eserlerin sergilendiği bu müze, bölgenin binlerce yıllık tarihine ışık tutar. Özellikle Zerzevan Kalesi''nden getirilen buluntular dikkat çekicidir.", "place_query": "Bismil Müzesi, Bismil, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5321ce80-052a-4de4-98e9-1b24e6c7eb73'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çermik Kaplıcaları", "summary": "Çermik''in en bilinen şifa kaynağı olan termal suları, romatizma ve cilt hastalıklarına iyi gelmesiyle ünlüdür. Hem kapalı hem açık havuzlarıyla yıl boyunca ziyaretçi çeker.", "place_query": "Çermik Kaplıcaları, Çermik, Diyarbakır"}, {"title": "Çermik Kalesi", "summary": "İlçe merkezinde yüksek bir kaya üzerine inşa edilmiş tarihi kale, çevreye hakim manzarasıyla dikkat çeker. Roma ve Bizans dönemlerinden izler taşır.", "place_query": "Çermik Kalesi, Çermik, Diyarbakır"}, {"title": "Haburman Köprüsü", "summary": "Artuklu dönemine ait bu tarihi taş köprü, ilçe yakınlarındaki Haburman Çayı üzerinde yer alır. Mimari yapısı ve doğal çevresiyle fotoğrafçıların uğrak noktasıdır.", "place_query": "Haburman Köprüsü, Çermik, Diyarbakır"}, {"title": "Çermik Ulu Camii", "summary": "Selçuklu ve Artuklu mimarisinin izlerini taşıyan bu cami, kesme taş işçiliği ve sade iç mekanıyla tarihi atmosfer sunar. İlçenin en eski ibadet yapılarındandır.", "place_query": "Çermik Ulu Camii, Çermik, Diyarbakır"}, {"title": "Sinek Çayı ve Mesire Alanı", "summary": "Çermik merkeze yakın Sinek Çayı boyunca uzanan mesire alanı, piknik ve doğa yürüyüşü için idealdir. Özellikle bahar aylarında yeşil doğasıyla huzur verir.", "place_query": "Sinek Çayı, Çermik, Diyarbakır"}, {"title": "Yedi Kardeşler Tepesi", "summary": "İlçe manzarasını kuşbakışı görmek isteyenler için popüler bir seyir noktasıdır. Yürüyüş parkurları ve temiz havasıyla doğaseverlerin ilgisini çeker.", "place_query": "Yedi Kardeşler Tepesi, Çermik, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '20a3d40e-e4ed-4476-821a-a3c0f07755c3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çınar Ulu Camii", "summary": "Artuklu dönemine ait tarihi bir cami olup, taş işçiliği ve mimari detaylarıyla dikkat çeker. İlçe merkezinde yer alır ve bölgenin önemli dini yapılarındandır.", "place_query": "Çınar Ulu Camii, Diyarbakır"}, {"title": "Çınar Kalesi", "summary": "Tarihi bir gözetleme kalesi olup, çevresine hakim bir tepede konumlanmıştır. Bölgenin savunma yapıları arasında yer alır ve etkileyici manzarasıyla ziyaretçilerini cezbeder.", "place_query": "Çınar Kalesi, Diyarbakır"}, {"title": "Göksu Çayı", "summary": "Çınar ilçesinden geçen doğal bir akarsu olup, çevresi piknik ve doğa yürüyüşleri için idealdir. Özellikle bahar aylarında yeşil doğasıyla huzur verici bir atmosfer sunar.", "place_query": "Göksu Çayı, Çınar, Diyarbakır"}, {"title": "Çınar Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını yansıtan eserlerin sergilendiği küçük bir müzedir. Ziyaretçilere yöresel yaşam ve arkeolojik buluntular hakkında bilgi verir.", "place_query": "Çınar Müzesi, Diyarbakır"}, {"title": "Alatarla Höyüğü", "summary": "Çınar ilçesi sınırlarında yer alan arkeolojik bir höyüktür. Bölgenin antik yerleşim tarihine ışık tutan bu alan, tarih meraklıları için keşfedilmeye değerdir.", "place_query": "Alatarla Höyüğü, Çınar, Diyarbakır"}, {"title": "Çınar Mesire Alanı", "summary": "Şehir merkezine yakın, ağaçlık bir alanda kurulu piknik ve dinlenme tesisidir. Hafta sonu aile ziyaretleri için popüler bir kaçış noktasıdır.", "place_query": "Çınar Mesire Alanı, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '57ed7491-3e1f-44a2-a689-4b3c71737201'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çüngüş Kalesi", "summary": "İlçe merkezine hakim bir tepede yer alan tarihi kale, bölgenin savunma yapılarından biridir. Ziyaretçilerine hem tarihi bir atmosfer hem de çevrenin panoramik manzarasını sunar.", "place_query": "Çüngüş Kalesi, Çüngüş, Diyarbakır"}, {"title": "Hazreti Süleyman Türbesi", "summary": "Çüngüş ilçe merkezinde bulunan bu türbe, manevi atmosferi ve tarihi dokusuyla ziyaretçilerin ilgisini çeker. Bölge halkı tarafından kutsal kabul edilen önemli bir ziyaret noktasıdır.", "place_query": "Hazreti Süleyman Türbesi, Çüngüş, Diyarbakır"}, {"title": "Çüngüş Şelalesi", "summary": "Doğal güzelliğiyle öne çıkan bu şelale, özellikle bahar ve yaz aylarında piknik ve doğa yürüyüşü için idealdir. Serin suları ve yeşil çevresiyle huzurlu bir kaçış noktasıdır.", "place_query": "Çüngüş Şelalesi, Çüngüş, Diyarbakır"}, {"title": "Çüngüş Ulu Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan yapı, taş işçiliği ve mimari detaylarıyla dikkat çeker. İlçenin en eski ibadet yerlerinden biri olarak kültürel bir değer taşır.", "place_query": "Çüngüş Ulu Camii, Çüngüş, Diyarbakır"}, {"title": "Çüngüş Kanyonu", "summary": "Doğa sporları ve keşif tutkunları için etkileyici bir kanyondur. Yürüyüş parkurları ve eşsiz kaya oluşumlarıyla bölgede görülmeye değer bir doğal alandır.", "place_query": "Çüngüş Kanyonu, Çüngüş, Diyarbakır"}, {"title": "Çüngüş Köprüleri (Tarihi Taş Köprüler)", "summary": "Çevredeki dereler üzerinde yer alan tarihi taş köprüler, Osmanlı dönemi mühendisliğini yansıtır. Fotoğrafçılar ve tarih meraklıları için ilgi çekici duraklardır.", "place_query": "Tarihi Taş Köprüler, Çüngüş, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '71744d13-28d0-404c-82a4-2488f056e1c1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dicle Barajı ve Mesire Alanı", "summary": "Dicle ilçesi sınırlarında yer alan bu baraj gölü, çevresindeki mesire alanlarıyla piknik ve doğa yürüyüşü için popüler bir noktadır. Özellikle bahar aylarında yeşilin ve mavinin buluştuğu manzarası ziyaretçileri cezbeder.", "place_query": "Dicle Barajı, Dicle, Diyarbakır"}, {"title": "Dicle Köprüsü (On Gözlü Köprü)", "summary": "Diyarbakır''ın simge yapılarından olan tarihi On Gözlü Köprü, Dicle Nehri üzerinde yer alır ve ilçeye yakın konumuyla sık ziyaret edilir. 11. yüzyıldan kalma bu köprü, muhteşem nehir manzarası eşliğinde fotoğrafçılar için ideal bir duraktır.", "place_query": "On Gözlü Köprü, Dicle, Diyarbakır"}, {"title": "Kırklar Dağı", "summary": "Dicle ilçesi yakınlarındaki bu dağ, doğa yürüyüşleri ve şehir manzarası izlemek isteyenler için popüler bir rota. Özellikle gün batımında zirveden izlenen Dicle Nehri ve çevre köylerin panoramik görüntüsü etkileyicidir.", "place_query": "Kırklar Dağı, Dicle, Diyarbakır"}, {"title": "Dicle Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisini yansıtan sade ve zarif yapısıyla dikkat çeker. Hem ibadet hem de tarihi dokuya tanıklık etmek için uğranabilecek önemli bir noktadır.", "place_query": "Dicle Merkez Camii, Dicle, Diyarbakır"}, {"title": "Dicle Nehri Kıyısı Yürüyüş Yolu", "summary": "Dicle Nehri boyunca uzanan bu doğal yürüyüş parkuru, ilçe sakinlerinin ve ziyaretçilerin en çok tercih ettiği dinlenme alanlarından biridir. Kuş sesleri eşliğinde yapılan yürüyüş, stres atmak için birebirdir.", "place_query": "Dicle Nehri Kıyısı, Dicle, Diyarbakır"}, {"title": "Dicle Kalesi", "summary": "İlçe merkezine kısa bir mesafede bulunan bu tarihi kale kalıntıları, bölgenin savunma amaçlı kullanılan eski yapılarından biridir. Harabe halinde de olsa tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Dicle Kalesi, Dicle, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e1c69179-acea-4b43-b8d2-b4d9f2ee49df'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eğil Kral Kızı Mağarası", "summary": "Dicle Nehri kıyısında yer alan efsanevi bir mağara. Doğal güzelliği ve tarihi hikayeleriyle ziyaretçileri büyüler.", "place_query": "Eğil Kral Kızı Mağarası, Diyarbakır"}, {"title": "Eğil Kalesi", "summary": "Dicle Nehri''ne hakim bir tepe üzerinde bulunan tarihi kale. Bölgenin stratejik önemini yansıtan kalıntıları ve nefis manzarasıyla ünlüdür.", "place_query": "Eğil Kalesi, Diyarbakır"}, {"title": "Eğil Roma Kalesi (Kalesi Harabesi)", "summary": "Roma döneminden kalma bu kale kalıntıları, tarih meraklıları için önemli bir duraktır. Eğil''in tarihi dokusunu gözler önüne serer.", "place_query": "Eğil Roma Kalesi, Diyarbakır"}, {"title": "Dicle Nehri (Eğil Bölümü)", "summary": "Eğil''den geçen Dicle Nehri, doğa yürüyüşleri ve piknik için ideal bir alandır. Nehir kenarında huzur veren bir atmosfer sunar.", "place_query": "Dicle Nehri Eğil, Diyarbakır"}, {"title": "Eğil Müzesi", "summary": "Bölgede yapılan arkeolojik kazılarda bulunan eserlerin sergilendiği müze. Eğil ve çevresinin zengin tarihine ışık tutar.", "place_query": "Eğil Müzesi, Diyarbakır"}, {"title": "Eğil Şelalesi", "summary": "Doğal bir güzellik olan bu şelale, özellikle bahar aylarında coşkun akışıyla görsel bir şölen sunar. Çevresi piknik ve dinlenme alanı olarak kullanılır.", "place_query": "Eğil Şelalesi, Diyarbakır"}, {"title": "Eğil Kaya Mezarları", "summary": "Kayalara oyulmuş antik mezarlar, bölgenin binlerce yıllık geçmişine tanıklık eder. Tarih ve arkeoloji tutkunları için etkileyici bir duraktır.", "place_query": "Eğil Kaya Mezarları, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6b9a9380-f2d5-4ced-b8bf-421b69e48438'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ergani Çayı ve Mesire Alanı", "summary": "Ergani ilçe merkezine yakın, piknik ve doğa yürüyüşü için ideal bir mesire alanıdır. Çay boyunca uzanan yeşil alanlar ve temiz havasıyla hafta sonu ziyaretçilerini ağırlar.", "place_query": "Ergani Çayı Mesire Alanı, Ergani, Diyarbakır"}, {"title": "Hilar Mağaraları (Hilâr Mağaraları)", "summary": "Ergani sınırlarında yer alan tarih öncesi döneme ait bu mağaralar, arkeolojik önemi ve etkileyici doğal yapısıyla dikkat çeker. Bölgedeki en eski yerleşim izlerini görmek mümkündür.", "place_query": "Hilar Mağaraları, Ergani, Diyarbakır"}, {"title": "Sesverenpınar Köyü", "summary": "Ergani''nin doğal güzellikleriyle ünlü köylerinden biridir. Özellikle bahar aylarında yeşilin her tonunu görebileceğiniz, huzurlu bir kırsal kaçış noktasıdır.", "place_query": "Sesverenpınar Köyü, Ergani, Diyarbakır"}, {"title": "Ergani Ulu Camii", "summary": "İlçe merkezinde bulunan tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de tarihi dokuya tanıklık etmek için ziyaret edilir.", "place_query": "Ergani Ulu Camii, Ergani, Diyarbakır"}, {"title": "Zülküf Dağı", "summary": "Ergani yakınlarında yükselen bu dağ, doğa yürüyüşleri ve manzara seyri için popülerdir. Özellikle gün doğumu ve gün batımında eşsiz bir panoramik görüntü sunar.", "place_query": "Zülküf Dağı, Ergani, Diyarbakır"}, {"title": "Ergani Kalesi", "summary": "Tarihi bir kalıntı olan Ergani Kalesi, ilçenin geçmişine ışık tutar. Kale kalıntıları arasında dolaşırken bölgenin stratejik önemini hissedebilirsiniz.", "place_query": "Ergani Kalesi, Ergani, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5cde3d83-f1cb-4b90-9667-7e10c2a318a1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hani Kalesi", "summary": "Tarihi bir kaledir. Bölgenin geçmişine ışık tutar ve etkileyici manzarasıyla ziyaretçilerini büyüler.", "place_query": "Hani Kalesi, Hani, Diyarbakır"}, {"title": "Hani Çayı", "summary": "Doğal güzelliğiyle ünlü bir akarsudur. Çevresindeki yeşil alanlar piknik ve dinlenme için idealdir.", "place_query": "Hani Çayı, Hani, Diyarbakır"}, {"title": "Hani Ulu Camii", "summary": "Tarihi bir camidir. Mimari yapısı ve dini önemiyle dikkat çeker, huzurlu bir atmosfer sunar.", "place_query": "Hani Ulu Camii, Hani, Diyarbakır"}, {"title": "Hani Müzesi", "summary": "Yöresel kültür ve tarihi eserlerin sergilendiği bir müzedir. Bölgenin zengin geçmişini keşfetmek için idealdir.", "place_query": "Hani Müzesi, Hani, Diyarbakır"}, {"title": "Hani Yaylaları", "summary": "Doğa yürüyüşleri ve kamp için popülerdir. Temiz havası ve muhteşem manzaralarıyla huzur verir.", "place_query": "Hani Yaylaları, Hani, Diyarbakır"}, {"title": "Hani Taş Köprü", "summary": "Tarihi bir taş köprüdür. Mimari güzelliği ve çevresindeki doğal ortamıyla fotoğrafçılar için cazip bir noktadır.", "place_query": "Hani Taş Köprü, Hani, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '17e38738-1a04-4f22-82d0-5c5a6202e6fb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hazro Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir. Bölgenin savunma yapılarına güzel bir örnek teşkil eder ve çevresindeki manzarasıyla ziyaretçilerine hoş bir seyir imkanı sunar.", "place_query": "Hazro Kalesi, Hazro, Diyarbakır"}, {"title": "Sarıyaprak Göleti", "summary": "Doğal güzellikleri ve huzurlu atmosferiyle piknik ve doğa yürüyüşü için ideal bir mekandır. Gölet çevresi yeşil alanlarla kaplıdır ve özellikle bahar aylarında canlı bir manzaraya sahiptir.", "place_query": "Sarıyaprak Göleti, Hazro, Diyarbakır"}, {"title": "Hazro Ulu Camii", "summary": "İlçenin en eski ve önemli ibadet yapılarından biridir. Tarihi mimarisi ve taş işçiliğiyle dikkat çeker, bölgenin kültürel mirasını yansıtır.", "place_query": "Hazro Ulu Camii, Hazro, Diyarbakır"}, {"title": "Kırık Minare (Hazro)", "summary": "Adını yıkık minaresinden alan bu tarihi yapı, ilçenin simgelerindendir. Geçmişte cami olarak kullanılan yapı, günümüzde tarihi bir kalıntı olarak ziyaret edilmektedir.", "place_query": "Kırık Minare, Hazro, Diyarbakır"}, {"title": "Hazro Mağaraları", "summary": "İlçe çevresinde bulunan doğal kaya oluşumları ve mağaralardır. Tarih öncesi dönemlerden beri yerleşim izleri taşıyan bu mağaralar, doğa ve tarih meraklıları için keşfedilmeyi bekleyen alanlardır.", "place_query": "Hazro Mağaraları, Hazro, Diyarbakır"}, {"title": "Çayönü Höyüğü", "summary": "Hazro ilçesi sınırları içinde yer alan önemli bir Neolitik dönem arkeolojik alanıdır. Dünyanın en eski yerleşimlerinden biri olarak kabul edilir ve bölgenin tarih öncesi kültürüne ışık tutar.", "place_query": "Çayönü Höyüğü, Hazro, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c7f98e4b-b69f-450c-acc6-9ef61b878859'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Diyarbakır Surları", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu devasa surlar, Çin Seddi''nden sonra dünyanın en uzun savunma duvarıdır. Şehrin tarihi dokusunu görmek için eşsiz bir fırsat sunar.", "place_query": "Diyarbakır Surları, Sur, Diyarbakır"}, {"title": "Hasan Paşa Hanı", "summary": "16. yüzyıldan kalma bu tarihi han, geleneksel Diyarbakır mimarisini yansıtır. Günümüzde kafeleri ve hediyelik eşya dükkanlarıyla canlı bir kültür merkezidir.", "place_query": "Hasan Paşa Hanı, Sur, Diyarbakır"}, {"title": "Ulu Cami (Diyarbakır)", "summary": "Anadolu''nun en eski camilerinden biri olan Ulu Cami, farklı medeniyetlerin izlerini taşıyan mimarisiyle dikkat çeker. Geniş avlusu ve tarihi atmosferi mutlaka görülmelidir.", "place_query": "Diyarbakır Ulu Cami, Sur, Diyarbakır"}, {"title": "Diyarbakır Arkeoloji Müzesi", "summary": "Bölgenin zengin tarihini gözler önüne seren müze, Paleolitik çağdan Osmanlı dönemine kadar uzanan geniş bir koleksiyona sahiptir. Özellikle Çayönü buluntuları etkileyicidir.", "place_query": "Diyarbakır Arkeoloji Müzesi, Sur, Diyarbakır"}, {"title": "On Gözlü Köprü (Silan Köprüsü)", "summary": "Dicle Nehri üzerindeki bu tarihi köprü, 11 gözünden 10''u su üzerinde olduğu için halk arasında On Gözlü olarak bilinir. Özellikle gün batımında muhteşem bir manzara sunar.", "place_query": "On Gözlü Köprü, Sur, Diyarbakır"}, {"title": "Dört Ayaklı Minare", "summary": "Diyarbakır''ın sembollerinden biri olan bu minare, dört sütun üzerine oturtulmuş nadir yapılardandır. Şehrin en çok fotoğraflanan tarihi eserlerindendir.", "place_query": "Dört Ayaklı Minare, Sur, Diyarbakır"}, {"title": "Cahit Sıtkı Tarancı Müzesi", "summary": "Ünlü şair Cahit Sıtkı Tarancı''nın doğduğu ev, günümüzde müze olarak ziyarete açıktır. Evin içindeki eşyalar ve şairin kişisel belgeleri duygusal bir atmosfer yaratır.", "place_query": "Cahit Sıtkı Tarancı Müzesi, Sur, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6e8f62c6-e2b4-4463-9793-0a20b9a2b0f7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kocaköy Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi cami, geleneksel mimarisiyle dikkat çeker ve yöre halkı tarafından sıkça ziyaret edilir.", "place_query": "Kocaköy Merkez Camii, Kocaköy, Diyarbakır"}, {"title": "Kocaköy Kalesi", "summary": "İlçenin simgelerinden olan tarihi kale, bölgenin geçmişine ışık tutan kalıntıları ve panoramik manzarasıyla ziyaretçileri cezbeder.", "place_query": "Kocaköy Kalesi, Kocaköy, Diyarbakır"}, {"title": "Dicle Nehri Kıyısı (Kocaköy Bölümü)", "summary": "Dicle Nehri''nin ilçe sınırlarından geçen bölümü, doğal güzelliği ve piknik alanlarıyla dinlendirici bir kaçış noktası sunar.", "place_query": "Dicle Nehri Kocaköy, Diyarbakır"}, {"title": "Kocaköy Eski Hamamı", "summary": "Geçmişten günümüze ulaşan tarihi hamam, geleneksel mimarisi ve kültürel değeriyle keşfedilmeyi bekleyen bir yapıdır.", "place_query": "Kocaköy Eski Hamamı, Kocaköy, Diyarbakır"}, {"title": "Kocaköy Yaylaları", "summary": "İlçe çevresindeki yemyeşil yaylalar, temiz havası ve doğal manzarasıyla doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Kocaköy Yaylaları, Kocaköy, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '03a79f0f-d226-4358-a3c9-7ef71c4788fa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kulp Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin stratejik önemini gözler önüne serer ve ziyaretçilere eşsiz bir manzara sunar.", "place_query": "Kulp Kalesi, Kulp, Diyarbakır"}, {"title": "Kulp Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla özellikle yaz aylarında piknik ve doğa yürüyüşü için ideal bir mekandır.", "place_query": "Kulp Şelalesi, Kulp, Diyarbakır"}, {"title": "Kulp Ulu Camii", "summary": "Tarihi dokusu ve mimarisiyle dikkat çeken cami, ilçenin en eski yapılarından biri olup manevi bir atmosfere sahiptir.", "place_query": "Kulp Ulu Camii, Kulp, Diyarbakır"}, {"title": "Kulp Mağaraları", "summary": "Bölgedeki doğal mağaralar, tarih öncesi dönemlerden beri yerleşim izleri taşır ve mağara turizmi açısından keşfedilmeyi bekler.", "place_query": "Kulp Mağaraları, Kulp, Diyarbakır"}, {"title": "Kulp Yaylaları", "summary": "Yeşilin her tonunu barındıran yaylalar, temiz havası ve doğal güzellikleriyle kampçılar ve doğaseverler için huzurlu bir kaçış noktasıdır.", "place_query": "Kulp Yaylaları, Kulp, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b4d2a1e4-cef8-4a1f-ad10-f6ea7936863b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Lice Kalesi", "summary": "Tarihi bir kalıntı olan Lice Kalesi, ilçe merkezine hakim bir tepede yer alır ve bölgenin stratejik geçmişine tanıklık eder. Ziyaretçiler, kalıntılar arasında dolaşırken çevrenin panoramik manzarasını izleyebilir.", "place_query": "Lice Kalesi, Lice, Diyarbakır"}, {"title": "Lice Kaplıcaları", "summary": "Termal sularıyla bilinen Lice Kaplıcaları, romatizmal rahatsızlıklara iyi geldiğine inanılan doğal bir şifa kaynağıdır. Doğa içinde huzurlu bir ortamda termal banyo yapma imkanı sunar.", "place_query": "Lice Kaplıcaları, Lice, Diyarbakır"}, {"title": "Kulp Çayı", "summary": "Lice ilçesinden geçen Kulp Çayı, çevresindeki yemyeşil doğayla piknik ve doğa yürüyüşü için ideal bir alandır. Serin suları ve doğal güzelliğiyle yerli halkın uğrak noktalarından biridir.", "place_query": "Kulp Çayı, Lice, Diyarbakır"}, {"title": "Lice Ulu Camii", "summary": "Tarihi bir yapı olan Lice Ulu Camii, yöresel mimari özellikler taşıyan ve geçmişi yüzyıllara dayanan bir ibadethanedir. İlçenin kültürel mirasını yansıtan önemli bir duraktır.", "place_query": "Lice Ulu Camii, Lice, Diyarbakır"}, {"title": "Abalı Mağarası", "summary": "Lice yakınlarında bulunan Abalı Mağarası, doğal oluşumu ve sarkıtlarıyla dikkat çeken bir mağaradır. Macera arayan doğa severler için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Abalı Mağarası, Lice, Diyarbakır"}, {"title": "Lice Yaylaları (Güneşli Yaylası vb.)", "summary": "Lice çevresindeki yaylalar, özellikle yaz aylarında serin havası ve bol oksijeniyle doğa tutkunlarını cezbeder. Yemyeşil alanlarda kamp yapmak veya doğa yürüyüşü yapmak mümkündür.", "place_query": "Güneşli Yaylası, Lice, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '226e7284-f0f2-45ec-87b2-247f7771cc18'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Malabadi Köprüsü", "summary": "Dünyanın en geniş taş kemerli köprülerinden biri olan bu yapı, Artuklu dönemine ait muhteşem bir sanat eseridir. Batman Çayı üzerinde yükselen köprü, fotoğrafçılar ve tarih meraklıları için eşsiz bir duraktır.", "place_query": "Malabadi Köprüsü, Silvan, Diyarbakır"}, {"title": "Silvan Kalesi", "summary": "Şehrin en önemli tarihi simgelerinden biri olan kale, Roma ve Artuklu dönemlerine tanıklık etmiştir. Surları ve burçlarıyla etkileyici bir manzara sunar.", "place_query": "Silvan Kalesi, Silvan, Diyarbakır"}, {"title": "Hasuni Mağaraları", "summary": "Doğal kaya oluşumları ve içindeki tarihi kiliseleriyle ünlü bu mağaralar, hem doğa yürüyüşü hem de tarih keşfi için idealdir. Bölgedeki en eski yerleşim izlerinden birini barındırır.", "place_query": "Hasuni Mağaraları, Silvan, Diyarbakır"}, {"title": "Silvan Ulu Camii", "summary": "Artuklu mimarisinin güzel örneklerinden biri olan cami, taş işçiliği ve sade ama etkileyici iç mekanıyla dikkat çeker. Tarihi dokuyu hissetmek için mutlaka görülmeli.", "place_query": "Silvan Ulu Camii, Silvan, Diyarbakır"}, {"title": "Selahaddin Eyyubi Türbesi", "summary": "İslam dünyasının önemli komutanlarından Selahaddin Eyyubi''nin aile üyelerine ait olduğuna inanılan türbe, tarihi ve manevi atmosferiyle ziyaretçileri ağırlar.", "place_query": "Selahaddin Eyyubi Türbesi, Silvan, Diyarbakır"}, {"title": "Silvan Çayı ve Mesire Alanı", "summary": "Şehir merkezine yakın bu doğal alan, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için popülerdir. Çay kenarında huzurlu bir gün geçirebilirsiniz.", "place_query": "Silvan Çayı Mesire Alanı, Silvan, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1781d66a-e1d6-43ff-a40e-7ee05e64507a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Diyarbakır Kalesi", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu devasa sur, dünyanın en uzun ve en sağlam savunma duvarlarından biridir. Burçları ve kapılarıyla tarihe tanıklık eden eşsiz bir yapıdır.", "place_query": "Diyarbakır Kalesi, Sur, Diyarbakır"}, {"title": "Hevsel Bahçeleri", "summary": "Diyarbakır Kalesi ile Dicle Nehri arasında uzanan, binlerce yıllık tarım geleneğini yansıtan verimli bir vahadır. UNESCO Dünya Mirası alanı olup, doğa ve tarihin iç içe geçtiği huzurlu bir yürüyüş rotasıdır.", "place_query": "Hevsel Bahçeleri, Sur, Diyarbakır"}, {"title": "Ulu Cami", "summary": "Anadolu''nun en eski camilerinden biri olan Ulu Cami, farklı medeniyetlerin izlerini taşıyan mimarisiyle dikkat çeker. İslam dünyasının beşinci Harem-i Şerifi olarak kabul edilir.", "place_query": "Diyarbakır Ulu Cami, Sur, Diyarbakır"}, {"title": "Hasan Paşa Hanı", "summary": "Osmanlı döneminden kalma bu tarihi han, restore edilerek günümüzde kafe, restoran ve hediyelik eşya dükkanlarıyla canlı bir kültür merkezine dönüşmüştür. Şehrin tarihi atmosferini soluyabileceğiniz ideal bir mekandır.", "place_query": "Hasan Paşa Hanı, Sur, Diyarbakır"}, {"title": "Dört Ayaklı Minare", "summary": "Diyarbakır''ın simgelerinden biri olan bu eşsiz minare, dört sütun üzerine oturtulmuş nadir yapılardandır. Şehrin tarihi siluetinde önemli bir yere sahiptir.", "place_query": "Dört Ayaklı Minare, Sur, Diyarbakır"}, {"title": "Sülüklü Han", "summary": "Kentin en eski hanlarından biri olan Sülüklü Han, avlusundaki tarihi atmosferi ve çay bahçeleriyle ziyaretçilere keyifli bir mola imkanı sunar. Özellikle akşam saatlerinde canlı bir buluşma noktasıdır.", "place_query": "Sülüklü Han, Sur, Diyarbakır"}, {"title": "Dicle Nehri Kıyısı", "summary": "Diyarbakır''ın güneyinden geçen Dicle Nehri, özellikle Hevsel Bahçeleri kenarında yürüyüş yapmak ve doğanın tadını çıkarmak için ideal bir mekandır. Nehir kenarındaki mesire alanları piknik ve dinlenme için popülerdir.", "place_query": "Dicle Nehri kıyısı, Sur, Diyarbakır"}, {"title": "Zinciriye Medresesi", "summary": "Artuklu döneminden kalma bu tarihi medrese, taş işçiliğinin zarif örneklerini sergiler. Günümüzde kültürel etkinliklere ev sahipliği yapan medrese, tarihi dokuyu yakından görmek için önemli bir duraktır.", "place_query": "Zinciriye Medresesi, Sur, Diyarbakır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cdcf3013-8658-41cd-8400-01c3a84d7714'::uuid;
