[]'::jsonb WHERE id = '65d66cf7-f873-4651-9933-bdb62ca56c1c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akçakoca Merkez Plajı", "summary": "Karadeniz''in mavi sularıyla buluşan uzun kumsalı, yaz aylarında yerli ve yabancı turistlerin uğrak noktasıdır. Şezlong, şemsiye ve çevredeki kafe-restoranlar sayesinde konforlu bir deniz keyfi sunar.", "place_query": "Akçakoca Merkez Plajı, Akçakoca, Düzce"}, {"title": "Akçakoca Ceneviz Kalesi", "summary": "Tarihi Cenevizliler dönemine uzanan bu kale, şehir merkezinde yüksek bir tepe üzerinde yer alır. Kaleyi gezerken Karadeniz''in eşsiz manzarasını izleyebilir, bölgenin geçmişine tanıklık edebilirsiniz.", "place_query": "Akçakoca Ceneviz Kalesi, Akçakoca, Düzce"}, {"title": "Fakıllı Mağarası", "summary": "Düzce''nin en önemli doğal oluşumlarından biri olan mağara, sarkıt ve dikitleriyle büyüleyici bir atmosfere sahiptir. İçerideki yürüyüş yolları ve aydınlatma sistemi sayesinde her yaştan ziyaretçi rahatça gezebilir.", "place_query": "Fakıllı Mağarası, Akçakoca, Düzce"}, {"title": "Aktaş Şelalesi", "summary": "Yemyeşil ormanlar içinde gizlenmiş bu şelale, doğa yürüyüşü ve piknik yapmak isteyenler için ideal bir noktadır. Şelalenin serin suları ve çevresindeki doğal havuz, yaz sıcağında ferahlatıcı bir kaçış sunar.", "place_query": "Aktaş Şelalesi, Akçakoca, Düzce"}, {"title": "Gençlik Parkı ve Akçakoca Sahil Yolu", "summary": "Sahil boyunca uzanan yürüyüş ve bisiklet yolu, deniz manzarası eşliğinde keyifli bir gezinti imkânı sağlar. Park içinde çocuk oyun alanları, banklar ve kafeler bulunur; özellikle gün batımında romantik bir atmosfere bürünür.", "place_query": "Gençlik Parkı, Akçakoca, Düzce"}, {"title": "Kurugöl Kanyonu", "summary": "Akçakoca''ya yaklaşık 20 km mesafedeki bu kanyon, yürüyüş parkurları ve ahşap seyir teraslarıyla doğaseverlerin ilgisini çeker. Kanyonun derinliklerinde akan dere ve zengin bitki örtüsü, huzurlu bir doğa deneyimi vadediyor.", "place_query": "Kurugöl Kanyonu, Akçakoca, Düzce"}, {"title": "Melenağzı Plajı", "summary": "Akçakoca''nın en popüler plajlarından biri olan Melenağzı, ince kumu ve dalgasız deniziyle aileler için idealdir. Çevredeki tesisler sayesinde günübirlik ihtiyaçlarınızı karşılayabilir, deniz keyfini doyasıya yaşayabilirsiniz.", "place_query": "Melenağzı Plajı, Akçakoca, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1d8edb44-eb19-4c44-b85c-05bbf6cab978'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çilimli Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla hafta sonu kaçamaklarının favorisidir. Özellikle bahar ve yaz aylarında akan suyun sesi eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Çilimli Şelalesi, Düzce"}, {"title": "Çilimli Merkez Camii", "summary": "İlçenin simge yapılarından biri olan bu cami, Osmanlı mimarisinin izlerini taşıyan zarif bir yapıdır. Hem ibadet hem de tarihi dokuya tanıklık etmek için ziyaret edilebilir.", "place_query": "Çilimli Merkez Camii, Düzce"}, {"title": "Çilimli Yaylası", "summary": "Şehir hayatından uzaklaşmak isteyenler için ideal olan bu yayla, yemyeşil doğası ve temiz havasıyla ünlüdür. Yürüyüş yapabilir, yöresel lezzetlerin tadına bakabilirsiniz.", "place_query": "Çilimli Yaylası, Düzce"}, {"title": "Çilimli Göleti", "summary": "Doğa ile iç içe bir piknik ve balık tutma noktası olan gölet, sakin atmosferiyle bilinir. Çevresindeki yeşil alanlar ailece vakit geçirmek için idealdir.", "place_query": "Çilimli Göleti, Düzce"}, {"title": "Çilimli Kalesi", "summary": "Tarihi kalıntılarıyla dikkat çeken bu kale, bölgenin geçmişine ışık tutar. Tepeye konumlanmış olması sayesinde Çilimli ve çevresinin panoramik manzarasını sunar.", "place_query": "Çilimli Kalesi, Düzce"}, {"title": "Düzce Konuralp Müzesi", "summary": "Çilimli''ye kısa bir mesafedeki bu müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Antik dönem eserlerinden geleneksel kıyafetlere kadar geniş bir koleksiyon görebilirsiniz.", "place_query": "Konuralp Müzesi, Düzce"}, {"title": "Güzeldere Şelalesi Tabiat Parkı", "summary": "Çilimli sınırlarına yakın bu tabiat parkı, şelalesi ve yürüyüş yollarıyla doğa severlerin uğrak noktasıdır. Piknik alanları ve kamp imkanı da mevcuttur.", "place_query": "Güzeldere Şelalesi Tabiat Parkı, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6506684b-7f4c-4785-a94f-3869ab5858a3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cumayeri Merkez Camii", "summary": "Cumayeri''nin merkezinde yer alan tarihi cami, bölgenin dini ve kültürel mirasını yansıtır. Ziyaretçiler, sade mimarisi ve huzurlu atmosferiyle ilçenin manevi merkezini keşfedebilir.", "place_query": "Cumayeri Merkez Camii, Cumayeri, Düzce"}, {"title": "Cumayeri Göleti", "summary": "Doğayla iç içe bir piknik ve dinlenme alanı olan Cumayeri Göleti, özellikle hafta sonları ailelerin uğrak noktasıdır. Çevresindeki yürüyüş yolları ve yeşil alanlar, sakin bir gün geçirmek isteyenler için idealdir.", "place_query": "Cumayeri Göleti, Cumayeri, Düzce"}, {"title": "Çilimli Yaylası", "summary": "Cumayeri''ne yaklaşık 15 km uzaklıktaki bu yayla, muhteşem manzarası ve temiz havasıyla doğa severlerin ilgisini çeker. Yayla evlerinde konaklama imkanı sunan bölge, özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Çilimli Yaylası, Düzce"}, {"title": "Düzce Konuralp Antik Kenti", "summary": "Cumayeri''ne yaklaşık 25 km mesafedeki bu antik kent, Roma ve Bizans dönemine ait kalıntılarıyla tarih meraklılarına hitap eder. Tiyatro, su kemerleri ve mozaikler, bölgenin zengin geçmişine ışık tutar.", "place_query": "Konuralp Antik Kenti, Düzce"}, {"title": "Düzce Akçakoca Plajları", "summary": "Cumayeri''ne yaklaşık 30 km uzaklıktaki Akçakoca ilçesi, Karadeniz kıyısındaki plajlarıyla ünlüdür. Özellikle Ceneviz Kalesi Plajı ve Yalı Plajı, deniz keyfi yapmak isteyenler için popüler seçeneklerdir.", "place_query": "Akçakoca Plajları, Düzce"}, {"title": "Düzce Güzeldere Şelalesi", "summary": "Cumayeri''ne yaklaşık 35 km mesafedeki bu şelale, yemyeşil ormanlar arasında gizlenmiş doğal bir güzelliktir. Piknik alanları ve yürüyüş parkurlarıyla doğa turizmi için ideal bir duraktır.", "place_query": "Güzeldere Şelalesi, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd195f3a3-5a9d-4381-a40a-6a4d547300b3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölyaka Yaylaları (Samandere ve Çoğa Yaylası)", "summary": "Doğal güzellikleriyle ünlü bu yaylalar, yeşilin her tonunu görebileceğiniz, temiz havası ve yürüyüş rotalarıyla huzurlu bir kaçış noktasıdır. Özellikle Samandere Şelalesi, bölgenin en popüler doğa harikalarından biridir.", "place_query": "Samandere Şelalesi, Gölyaka, Düzce"}, {"title": "Samandere Şelalesi Tabiat Parkı", "summary": "Samandere Şelalesi, iki kademeli dökülen suları ve çevresindeki zengin bitki örtüsüyle fotoğrafçıların ve doğa severlerin uğrak noktasıdır. Tabiat parkı içinde piknik alanları ve yürüyüş parkurları bulunur.", "place_query": "Samandere Şelalesi Tabiat Parkı, Gölyaka, Düzce"}, {"title": "Gölyaka İlçe Merkezi ve Göleti", "summary": "İlçe merkezindeki yapay gölet, çevresindeki kafeler ve yürüyüş yollarıyla sakin bir atmosfer sunar. Hafta sonu ailelerin ve grupların piknik yapmak için tercih ettiği dinlendirici bir alandır.", "place_query": "Gölyaka Göleti, Gölyaka, Düzce"}, {"title": "Efteni Gölü Yaban Hayatı Geliştirme Sahası", "summary": "Gölyaka sınırları içinde yer alan Efteni Gölü, kuş gözlemciliği için önemli bir sulak alandır. Göçmen kuşlara ev sahipliği yapan göl, doğa fotoğrafçıları ve yürüyüşçüler için sakin bir rotadır.", "place_query": "Efteni Gölü, Gölyaka, Düzce"}, {"title": "Çoğa Yaylası", "summary": "Yoğun ormanlık alanlar ve yayla evleriyle bilinen Çoğa Yaylası, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için idealdir. Yaylada geleneksel köy kahvaltısı yapabileceğiniz küçük işletmeler bulunur.", "place_query": "Çoğa Yaylası, Gölyaka, Düzce"}, {"title": "Gölyaka Kervan Yolu (Tarihi Kervan Yolu)", "summary": "Tarihi İpek Yolu''nun bir parçası olan bu patika, doğa yürüyüşü ve tarih meraklıları için keşfedilmeyi bekleyen bir rotadır. Orman içinden geçen yol, eski dönemlerin izlerini taşır.", "place_query": "Gölyaka Tarihi Kervan Yolu, Gölyaka, Düzce"}, {"title": "Düzce Gölyaka Köy Pazarı", "summary": "Haftalık kurulan köy pazarı, yöresel organik ürünler, el yapımı peynirler ve doğal sebzelerle dolu renkli bir alışveriş deneyimi sunar. Yerel halkla sohbet edip bölgenin kültürünü yakından tanıyabilirsiniz.", "place_query": "Gölyaka Köy Pazarı, Gölyaka, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '84dde92f-f0b2-41fa-b32e-4dc21475481d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gümüşova Şelalesi", "summary": "Doğal güzelliği ve çevresindeki yeşil alanlarla ünlü bir mesire yeridir. Şelalenin serin sularında yüzebilir ve piknik yapabilirsiniz.", "place_query": "Gümüşova Şelalesi, Gümüşova, Düzce"}, {"title": "Gümüşova Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü bir yayladır. Doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Gümüşova Yaylası, Gümüşova, Düzce"}, {"title": "Kadıoğlu Konağı", "summary": "Tarihi bir Osmanlı konağı olup, geleneksel mimariyi yansıtmaktadır. Ziyaretçilere geçmişe yolculuk yapma imkanı sunar.", "place_query": "Kadıoğlu Konağı, Gümüşova, Düzce"}, {"title": "Gümüşova Merkez Camii", "summary": "İlçenin merkezinde bulunan tarihi bir camidir. Osmanlı dönemi mimarisinin güzel bir örneğidir.", "place_query": "Gümüşova Merkez Camii, Gümüşova, Düzce"}, {"title": "Gümüşova Göleti", "summary": "Doğa ile iç içe huzurlu bir ortam sunan bir gölettir. Balık tutma ve piknik gibi aktiviteler için popülerdir.", "place_query": "Gümüşova Göleti, Gümüşova, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6c66597c-f898-40c1-9c38-531a0558e269'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölyaka Şelalesi", "summary": "Kaynaşlı ilçe merkezine yaklaşık 20 km mesafede, doğa içinde yer alan bu şelale, özellikle yaz aylarında serinlemek ve piknik yapmak isteyen ziyaretçilerin uğrak noktasıdır.", "place_query": "Gölyaka Şelalesi, Düzce"}, {"title": "Sultanpınar Yaylası", "summary": "Kaynaşlı''nın en yüksek yaylalarından biri olan Sultanpınar, muhteşem manzarası, temiz havası ve doğa yürüyüşü rotalarıyla doğaseverler için ideal bir kaçış noktasıdır.", "place_query": "Sultanpınar Yaylası, Kaynaşlı, Düzce"}, {"title": "Kaynaşlı Merkez Camii ve Tarihi Çarşı", "summary": "İlçe merkezinde bulunan tarihi cami ve çevresindeki geleneksel çarşı, yöresel ürünler almak ve Kaynaşlı''nın kültürel dokusunu hissetmek için ziyaret edilir.", "place_query": "Kaynaşlı Merkez Camii, Düzce"}, {"title": "Düzce Belediyesi Kent Ormanı", "summary": "Kaynaşlı''ya yaklaşık 10 km uzaklıkta bulunan bu geniş ormanlık alan, yürüyüş parkurları, piknik alanları ve bisiklet yollarıyla aileler ve doğa sporcuları için popüler bir dinlenme yeridir.", "place_query": "Düzce Belediyesi Kent Ormanı, Düzce"}, {"title": "Hacıosmanoğlu Köyü Kaya Mezarları", "summary": "Kaynaşlı''nın Hacıosmanoğlu köyünde yer alan bu tarihi kaya mezarları, bölgenin antik dönemlerine ışık tutan önemli bir arkeolojik alandır.", "place_query": "Hacıosmanoğlu Köyü Kaya Mezarları, Kaynaşlı, Düzce"}, {"title": "Çamlıca Yaylası", "summary": "Kaynaşlı sınırları içinde yer alan Çamlıca Yaylası, çam ormanlarıyla kaplı doğası ve yayla evleriyle huzurlu bir gün geçirmek isteyenlerin sıkça tercih ettiği bir noktadır.", "place_query": "Çamlıca Yaylası, Kaynaşlı, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f890a45e-9776-48ff-be3d-2f0345f0a5ba'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Düzce Konuralp Antik Kenti", "summary": "Prusias ad Hypium olarak da bilinen bu antik kent, Roma dönemine ait tiyatro, su kemerleri ve mozaikleriyle tarih meraklıları için eşsiz bir durak. Kentteki kazı çalışmaları hala devam etmektedir.", "place_query": "Konuralp Antik Kenti, Düzce Merkez"}, {"title": "Düzce Konuralp Müzesi", "summary": "Antik kentten çıkarılan eserlerin sergilendiği müze, bölgenin zengin tarihini gözler önüne seriyor. Heykeller, sikkeler ve günlük yaşam objeleri ilgi çekicidir.", "place_query": "Konuralp Müzesi, Düzce"}, {"title": "Hediyelik Eşya ve Yöresel Pazar (Perşembe Pazarı)", "summary": "Düzce Merkez''de her Perşembe kurulan büyük pazar, taze meyve-sebzeden el yapımı ürünlere kadar her şeyi bulabileceğiniz renkli bir alışveriş noktasıdır. Yöresel tatları denemek için idealdir.", "place_query": "Düzce Perşembe Pazarı, Düzce Merkez"}, {"title": "Düzce Belediyesi Kent Ormanı", "summary": "Şehir merkezine yakın bu geniş ormanlık alan, yürüyüş parkurları, piknik alanları ve göletiyle doğayla iç içe huzurlu bir kaçış sunar. Hafta sonu ailelerin uğrak noktasıdır.", "place_query": "Düzce Kent Ormanı, Düzce Merkez"}, {"title": "Sarıkaya Kaplıcaları", "summary": "Düzce Merkez''e bağlı Sarıkaya köyünde bulunan bu termal kaynak, romatizma ve cilt hastalıklarına iyi geldiği bilinen şifalı sularıyla ünlüdür. Doğal havuzları ve dinlendirici atmosferiyle öne çıkar.", "place_query": "Sarıkaya Kaplıcaları, Düzce Merkez"}, {"title": "Atatürk Heykeli ve Cumhuriyet Meydanı", "summary": "Düzce''nin kalbi sayılan bu meydan, şehrin sembolü Atatürk heykeli ve çevresindeki kafelerle sosyal yaşamın merkezidir. Gece ışıklandırmasıyla da güzel bir atmosfere sahiptir.", "place_query": "Cumhuriyet Meydanı, Düzce Merkez"}, {"title": "Düzce Çamlıpınar Göleti", "summary": "Merkeze kısa bir mesafedeki bu yapay gölet, çam ormanlarıyla çevrili yürüyüş yolları ve piknik alanlarıyla doğaseverler için popüler bir hafta sonu rotasıdır. Olta balıkçılığı da yapılabilir.", "place_query": "Çamlıpınar Göleti, Düzce Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '29f11ef0-6824-4076-bb07-4aa403cb2e81'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yığılca Şelalesi", "summary": "Yemyeşil ormanların içinde gizlenmiş bu şelale, doğa yürüyüşleri ve serinlemek için ideal bir noktadır. Özellikle yaz aylarında ziyaretçilerin uğrak yeridir.", "place_query": "Yığılca Şelalesi, Yığılca, Düzce"}, {"title": "Göktepe Yaylası", "summary": "Yüksek rakımı ve temiz havasıyla ünlü bu yayla, doğa ile baş başa kalmak isteyenler için mükemmel bir kaçış noktasıdır. Manzarası ve yayla evleriyle dikkat çeker.", "place_query": "Göktepe Yaylası, Yığılca, Düzce"}, {"title": "Çiçekli Yaylası", "summary": "Adını rengarenk kır çiçeklerinden alan bu yayla, özellikle ilkbahar ve yaz aylarında görsel bir şölen sunar. Doğa fotoğrafçıları için harika bir mekandır.", "place_query": "Çiçekli Yaylası, Yığılca, Düzce"}, {"title": "Kızılca Yaylası", "summary": "Sessiz ve sakin atmosferiyle bilinen Kızılca Yaylası, kampçılar ve doğa severler için popüler bir duraktır. Çevresindeki zengin bitki örtüsü keşfedilmeye değerdir.", "place_query": "Kızılca Yaylası, Yığılca, Düzce"}, {"title": "Yığılca Merkez Camii", "summary": "Tarihi dokusuyla öne çıkan bu cami, ilçenin merkezinde yer alır ve Osmanlı mimarisinin izlerini taşır. Hem ibadet hem de kültürel ziyaret için önemli bir noktadır.", "place_query": "Yığılca Merkez Camii, Yığılca, Düzce"}, {"title": "Aydınpınar Yaylası", "summary": "Doğal güzellikleri ve bol oksijeniyle ünlü bu yayla, trekking ve piknik yapmak için idealdir. Yığılca''nın en popüler yaylalarından biridir.", "place_query": "Aydınpınar Yaylası, Yığılca, Düzce"}, {"title": "Hacılar Yaylası", "summary": "Yemyeşil çam ormanlarıyla çevrili bu yayla, huzurlu bir doğa deneyimi sunar. Özellikle hafta sonu kaçamakları için tercih edilen bir mekandır.", "place_query": "Hacılar Yaylası, Yığılca, Düzce"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fecbae9d-c25a-4454-b37b-0190373922eb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Enez Kalesi", "summary": "Tarihi MÖ 7. yüzyıla kadar uzanan, Bizans ve Osmanlı dönemlerinde kullanılmış görkemli bir kaledir. Meriç Nehri deltasına hakim tepede yer alır ve bölgenin en önemli tarihi yapısıdır.", "place_query": "Enez Kalesi, Enez, Edirne"}, {"title": "Enez Sahili (Enez Plajı)", "summary": "Meriç Nehri''nin Ege Denizi''ne döküldüğü noktada yer alan uzun ve ince kumlu bir plajdır. Doğal güzelliği ve sakin atmosferiyle yaz aylarında yerli turistlerin uğrak noktasıdır.", "place_query": "Enez Plajı, Enez, Edirne"}, {"title": "Dalyan Koyu", "summary": "Enez merkeze yaklaşık 10 km uzaklıkta, doğal bir kanal ve lagün sistemiyle çevrili sakin bir koydur. Tekne turları ve doğa yürüyüşleri için idealdir.", "place_query": "Dalyan Koyu, Enez, Edirne"}, {"title": "Meriç Nehri Deltası", "summary": "Kuş gözlemciliği açısından Türkiye''nin en önemli sulak alanlarından biridir. Delta, yüzlerce kuş türüne ev sahipliği yapar ve doğa fotoğrafçıları için eşsiz fırsatlar sunar.", "place_query": "Meriç Nehri Deltası, Enez, Edirne"}, {"title": "Gala Gölü Milli Parkı", "summary": "Enez sınırları içinde kalan bu milli park, zengin bitki örtüsü ve kuş çeşitliliğiyle ünlüdür. Gölet çevresinde yürüyüş yapabilir, piknik alanlarında vakit geçirebilirsiniz.", "place_query": "Gala Gölü Milli Parkı, Enez, Edirne"}, {"title": "Enez Arkeoloji Müzesi", "summary": "Küçük ama etkileyici bir müze olup, Enez Kalesi ve çevresinde yapılan kazılarda çıkarılan eserleri sergiler. Bölgenin antik çağlardaki yaşamına dair önemli ipuçları sunar.", "place_query": "Enez Arkeoloji Müzesi, Enez, Edirne"}, {"title": "Taşaltı Köyü Plajı", "summary": "Enez merkeze yaklaşık 5 km mesafede, doğal bir koyda yer alan sakin bir plajdır. Berrak denizi ve çam ormanıyla çevrili olmasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Taşaltı Köyü Plajı, Enez, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bee9459e-ea21-4f39-8c50-499778e955f5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Havsa Merkez Camii", "summary": "Havsa''nın en önemli tarihi yapılarından biri olan cami, Osmanlı dönemi mimarisini yansıtır ve ilçenin merkezinde yer alır.", "place_query": "Havsa Merkez Camii, Havsa, Edirne"}, {"title": "Havsa Atatürk Anıtı", "summary": "İlçe merkezinde bulunan anıt, Cumhuriyet''in simgelerinden olup çevresindeki parkla birlikte ziyaretçilerin uğrak noktasıdır.", "place_query": "Atatürk Anıtı, Havsa, Edirne"}, {"title": "Havsa Mesire Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal olan bu mesire alanı, piknik ve yürüyüş imkanı sunar.", "place_query": "Havsa Mesire Alanı, Havsa, Edirne"}, {"title": "Havsa Tarihi Çeşmeleri", "summary": "İlçe genelinde dağınık halde bulunan Osmanlı dönemi çeşmeleri, tarihi dokuyu yansıtan küçük ama önemli yapılardır.", "place_query": "Havsa Tarihi Çeşmeleri, Havsa, Edirne"}, {"title": "Havsa Köy Pazarı", "summary": "Haftanın belirli günlerinde kurulan pazar, yöresel ürünler ve el işi eşyalar bulmak için ziyaret edilebilir.", "place_query": "Havsa Köy Pazarı, Havsa, Edirne"}, {"title": "Havsa Ovası", "summary": "Geniş tarım arazileriyle çevrili ova, doğa fotoğrafçılığı ve sakin kırsal manzaralar için güzel bir durak noktasıdır.", "place_query": "Havsa Ovası, Havsa, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f5bd2ea8-4ea2-4c2c-97cd-c838344a9bdf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İpsala Kalesi", "summary": "Tarihi Bizans dönemine uzanan bu kale, İpsala''nın simge yapılarından biridir. Merkezde yer alan kalıntılar, bölgenin antik geçmişine tanıklık etmek isteyenler için ilgi çekicidir.", "place_query": "İpsala Kalesi, İpsala, Edirne"}, {"title": "Meriç Nehri ve Kıyı Şeridi", "summary": "İpsala sınırları içinden geçen Meriç Nehri, doğal güzelliği ve huzurlu atmosferiyle bilinir. Nehir kıyısında yürüyüş yapabilir, kuş gözlemi yapabilir veya piknik yaparak vakit geçirebilirsiniz.", "place_query": "Meriç Nehri, İpsala, Edirne"}, {"title": "İpsala Peyniri ve Köy Pazarı", "summary": "İpsala, özellikle manda yoğurdu ve İpsala peyniri ile ünlüdür. İlçe merkezinde kurulan köy pazarında yöresel lezzetleri tadabilir ve taze peynir, yoğurt gibi ürünleri satın alabilirsiniz.", "place_query": "İpsala Köy Pazarı, İpsala, Edirne"}, {"title": "Yenikarpuzlu Köyü Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Yenikarpuzlu Köyü Camii, mimarisi ve ahşap işçiliği ile dikkat çeker. Köy ortamında sakin bir kültür gezisi yapmak isteyenler için uygun bir duraktır.", "place_query": "Yenikarpuzlu Köyü Camii, İpsala, Edirne"}, {"title": "Sarıcaali Köyü Şelalesi", "summary": "Doğa ile iç içe bir kaçamak arayanlar için Sarıcaali Köyü yakınlarındaki küçük şelale, yeşillikler arasında serinleme imkanı sunar. Özellikle bahar ve yaz aylarında ziyaret edilebilir.", "place_query": "Sarıcaali Köyü Şelalesi, İpsala, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd455fcc2-55e3-4d04-8ce5-c00556bf37ef'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Erikli Plajı", "summary": "Mavi bayraklı, ince kumlu ve uzun sahiliyle Keşan''ın en popüler plajıdır. Özellikle sığ denizi sayesinde aileler için idealdir.", "place_query": "Erikli Plajı, Keşan, Edirne"}, {"title": "Yayla Plajı", "summary": "Keşan''ın bir diğer ünlü mavi bayraklı plajı olup, doğal güzelliği ve temiz deniziyle dikkat çeker. Kamp ve karavan turizmi için de uygundur.", "place_query": "Yayla Plajı, Keşan, Edirne"}, {"title": "Mecidiye Köyü ve Plajı", "summary": "Sakin atmosferi ve berrak deniziyle bilinen bu köy, özellikle huzurlu bir tatil arayanların tercihidir. Köy kahvaltıları da meşhurdur.", "place_query": "Mecidiye Köyü, Keşan, Edirne"}, {"title": "Keşan Kent Müzesi", "summary": "Keşan''ın tarihini, kültürünü ve etnografik yapısını yansıtan eserlerin sergilendiği modern bir müzedir. Şehir merkezinde kolayca ziyaret edilebilir.", "place_query": "Keşan Kent Müzesi, Keşan, Edirne"}, {"title": "Hersekzade Ahmet Paşa Camii (Keşan Merkez Camii)", "summary": "16. yüzyıldan kalma tarihi bir cami olup, Mimar Sinan''ın eserleri arasında sayılır. Kesme taş işçiliği ve zarif minaresiyle dikkat çeker.", "place_query": "Hersekzade Ahmet Paşa Camii, Keşan, Edirne"}, {"title": "Keşan Pazarı (Salı Pazarı)", "summary": "Yöresel ürünlerin, taze sebze-meyve ve el yapımı ürünlerin satıldığı büyük bir pazardır. Keşan''ın kültürel dokusunu görmek için idealdir.", "place_query": "Keşan Salı Pazarı, Keşan, Edirne"}, {"title": "Gökçetepe Tabiat Parkı", "summary": "Doğa yürüyüşleri ve piknik için popüler bir alandır. Zengin bitki örtüsü ve deniz manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Gökçetepe Tabiat Parkı, Keşan, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2c4915c1-3a13-42e0-aea8-204e25c1b4d7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Lalapaşa Kalesi", "summary": "Tarihi bir Bizans kalesi olan Lalapaşa Kalesi, bölgenin en önemli tarihi yapılarından biridir. Ziyaretçiler, kalenin surları arasında dolaşarak hem tarihi atmosferi soluyabilir hem de çevredeki manzarayı izleyebilir.", "place_query": "Lalapaşa Kalesi, Lalapaşa, Edirne"}, {"title": "Süleymaniye Köyü Camii", "summary": "Osmanlı döneminden kalma bu tarihi camii, mimarisi ve huzurlu atmosferiyle dikkat çeker. Köy meydanında yer alan cami, bölgenin kültürel mirasını yansıtan önemli bir duraktır.", "place_query": "Süleymaniye Köyü Camii, Lalapaşa, Edirne"}, {"title": "Hacıdanişment Köyü Taş Köprüsü", "summary": "Tarihi bir taş köprü olan bu yapı, Osmanlı dönemi mühendisliğinin güzel bir örneğidir. Çevresindeki doğal güzelliklerle birleşen köprü, fotoğrafçılar ve tarih meraklıları için ideal bir noktadır.", "place_query": "Hacıdanişment Köyü Taş Köprüsü, Lalapaşa, Edirne"}, {"title": "Doğanca Köyü Şelalesi", "summary": "Doğal güzelliğiyle öne çıkan Doğanca Köyü Şelalesi, özellikle bahar ve yaz aylarında ziyaretçilerine serinletici bir kaçış sunar. Şelalenin etrafındaki yeşil alanlar piknik yapmak için de uygundur.", "place_query": "Doğanca Köyü Şelalesi, Lalapaşa, Edirne"}, {"title": "Lalapaşa Merkez Camii", "summary": "İlçe merkezinde bulunan bu camii, sade ve etkileyici mimarisiyle dikkat çeker. Bölge halkı için önemli bir ibadet ve buluşma noktası olan cami, aynı zamanda tarihi bir değere sahiptir.", "place_query": "Lalapaşa Merkez Camii, Lalapaşa, Edirne"}, {"title": "Sinanköy Göleti", "summary": "Doğa ile iç içe bir ortam arayanlar için ideal olan Sinanköy Göleti, yürüyüş ve piknik yapmak için popüler bir yerdir. Gölet çevresindeki yeşil alanlar ve kuş sesleri huzurlu bir atmosfer sunar.", "place_query": "Sinanköy Göleti, Lalapaşa, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5bd7bdd6-42af-4bca-a50f-dfe5c7647cdf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Meriç Nehri Kıyısı", "summary": "Meriç ilçesine adını veren nehir, özellikle bahar ve yaz aylarında piknik ve doğa yürüyüşü için tercih edilen huzurlu bir alandır. Nehir kıyısında yürüyüş yapabilir, kuş gözlemi yapabilir ve sakin bir gün geçirebilirsiniz.", "place_query": "Meriç Nehri, Meriç, Edirne"}, {"title": "Meriç Merkez Camii", "summary": "İlçe merkezinde bulunan ve Osmanlı dönemi mimarisini yansıtan tarihi bir yapıdır. Cami, hem ibadet hem de fotoğrafçılık açısından ilgi çekicidir.", "place_query": "Meriç Merkez Camii, Meriç, Edirne"}, {"title": "Küplü Köyü ve Doğal Gölet", "summary": "Meriç''e bağlı Küplü köyü, doğal güzellikleri ve küçük göletiyle bilinir. Özellikle hafta sonu kaçamakları için sakin bir ortam sunar.", "place_query": "Küplü Köyü, Meriç, Edirne"}, {"title": "Subaşı Köyü Tarihi Çeşmeleri", "summary": "Meriç''in Subaşı köyünde bulunan tarihi çeşmeler, bölgenin su kültürünü ve geçmişini yansıtan önemli yapılardır. Köy atmosferini keşfetmek için güzel bir duraktır.", "place_query": "Subaşı Köyü, Meriç, Edirne"}, {"title": "Meriç Ovası Tarım Alanları", "summary": "Bölgenin verimli tarım arazileri olan Meriç Ovası, özellikle ayçiçeği ve buğday tarlalarıyla meşhurdur. Mevsimine göre sarı ve yeşilin tonlarını görebileceğiniz geniş bir manzara sunar.", "place_query": "Meriç Ovası, Meriç, Edirne"}, {"title": "Kavaklı Köyü ve Çevresi", "summary": "Meriç''in Kavaklı köyü, doğal yapısı ve sakin köy hayatını deneyimlemek isteyenler için idealdir. Köy çevresinde kısa doğa yürüyüşleri yapabilirsiniz.", "place_query": "Kavaklı Köyü, Meriç, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'acf87f11-d4db-4667-918d-f2780a6f0899'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Selimiye Camii", "summary": "Mimar Sinan''ın ustalık eseri olan bu cami, UNESCO Dünya Mirası listesinde yer alır ve dev kubbesiyle Edirne''nin siluetini belirler. İçindeki çini süslemeler ve zarif hat sanatıyla ziyaretçileri büyüler.", "place_query": "Selimiye Camii, Edirne Merkez, Edirne"}, {"title": "Edirne Büyük Sinagogu", "summary": "Avrupa''nın üçüncü büyük sinagogu olan bu yapı, 2015''te restore edilerek ziyarete açılmıştır. Dönemin Yahudi cemaatinin izlerini taşıyan etkileyici bir dini ve kültürel mirastır.", "place_query": "Edirne Büyük Sinagogu, Edirne Merkez, Edirne"}, {"title": "Eski Cami", "summary": "Edirne''nin en eski camilerinden biri olan Eski Cami, 15. yüzyılda inşa edilmiştir. Kesme taş duvarları ve sade mimarisiyle dikkat çekerken, içindeki büyük yazıtlarıyla ünlüdür.", "place_query": "Eski Cami, Edirne Merkez, Edirne"}, {"title": "Edirne Arkeoloji ve Etnoğrafya Müzesi", "summary": "Selimiye Camii Külliyesi içinde yer alan müze, bölgenin antik dönemlerinden Osmanlı''ya uzanan zengin bir koleksiyon sunar. Roma, Bizans ve Osmanlı eserleriyle tarihe yolculuk yapabilirsiniz.", "place_query": "Edirne Arkeoloji ve Etnoğrafya Müzesi, Edirne Merkez, Edirne"}, {"title": "Meriç Köprüsü", "summary": "Osmanlı döneminde Mimar Sinan tarafından inşa edilen bu taş köprü, Meriç Nehri üzerinde uzanır. Özellikle gün batımında nehir manzarasıyla fotoğrafçıların ve yürüyüşçülerin uğrak noktasıdır.", "place_query": "Meriç Köprüsü, Edirne Merkez, Edirne"}, {"title": "Saraçlar Caddesi", "summary": "Edirne''nin en hareketli ve tarihi caddesi olan Saraçlar, dükkanları, kafeleri ve tarihi yapılarıyla ünlüdür. Yürüyüş yapıp alışveriş edebileceğiniz, şehrin nabzının attığı bir yerdir.", "place_query": "Saraçlar Caddesi, Edirne Merkez, Edirne"}, {"title": "Kaleiçi", "summary": "Edirne''nin tarihi çekirdeği olan Kaleiçi, dar sokakları, eski evleri ve butik otelleriyle otantik bir atmosfer sunar. Yürüyerek keşfetmek, şehrin geçmişine tanıklık etmek için idealdir.", "place_query": "Kaleiçi, Edirne Merkez, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c8376dc0-b6fa-46b0-862a-450317937de5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Süloğlu Merkez Camii", "summary": "İlçenin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin sade ve huzurlu bir örneğidir. Bölge halkı için önemli bir ibadet ve buluşma noktasıdır.", "place_query": "Süloğlu Merkez Camii, Edirne"}, {"title": "Süloğlu Barajı ve Mesire Alanı", "summary": "Şehir merkezine yakın konumdaki bu baraj, piknik ve doğa yürüyüşü için idealdir. Özellikle hafta sonları ailelerin uğrak noktası olup, huzurlu bir doğa kaçamağı sunar.", "place_query": "Süloğlu Barajı, Edirne"}, {"title": "Süloğlu İlçe Ormanı", "summary": "İlçe sınırları içinde kalan bu ormanlık alan, temiz havası ve yürüyüş parkurlarıyla doğaseverler için idealdir. Piknik yapmak ve şehir gürültüsünden uzaklaşmak için tercih edilir.", "place_query": "Süloğlu Ormanı, Edirne"}, {"title": "Süloğlu Köy Pazarı", "summary": "Yöresel ürünlerin ve taze sebze-meyvenin satıldığı bu pazar, ilçenin sosyal ve ticari hayatının kalbinde yer alır. Ziyaretçilere otantik bir alışveriş deneyimi sunar.", "place_query": "Süloğlu Pazarı, Edirne"}, {"title": "Süloğlu Şehitlikleri ve Anıtları", "summary": "Balkan Savaşları ve Kurtuluş Savaşı dönemine ait şehitlikler, ilçenin tarihi dokusunu yansıtır. Ziyaretçiler, burada vatan için can veren kahramanları anma fırsatı bulur.", "place_query": "Süloğlu Şehitliği, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7acd3e51-733d-442a-85e2-9594e47d6d0e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Uzunköprü (Tarihi Taş Köprü)", "summary": "II. Murat tarafından 15. yüzyılda yaptırılan bu tarihi köprü, dünyanın en uzun taş köprülerinden biridir. Ergene Nehri üzerinde yer alan köprü, hem mimarisi hem de tarihi dokusuyla kentin simgesi konumundadır.", "place_query": "Uzunköprü, Edirne"}, {"title": "Uzunköprü Müzesi", "summary": "Kent merkezinde bulunan bu müze, bölgenin arkeolojik ve etnografik zenginliklerini sergilemektedir. Trakya''nın geçmişine dair önemli eserleri barındırmasıyla ziyaretçilerin ilgisini çeker.", "place_query": "Uzunköprü Müzesi, Edirne"}, {"title": "Kadıköy Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın bu doğal alan, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için idealdir. Gölet çevresinde yürüyüş yapabilir, huzurlu bir gün geçirebilirsiniz.", "place_query": "Kadıköy Göleti, Uzunköprü, Edirne"}, {"title": "Kavaklı Plajı (Meriç Nehri Kenarı)", "summary": "Meriç Nehri kıyısında yer alan bu plaj, yaz aylarında serinlemek ve doğal güzelliklerin tadını çıkarmak için popüler bir noktadır. Nehir kenarında dinlenmek ve yüzmek mümkündür.", "place_query": "Kavaklı Plajı, Uzunköprü, Edirne"}, {"title": "Sultan II. Murat Camii", "summary": "Uzunköprü''nün en önemli tarihi yapılarından biri olan bu cami, 15. yüzyılda inşa edilmiştir. Osmanlı mimarisinin güzel bir örneği olan cami, hâlâ ibadete açıktır ve tarih meraklılarının ilgisini çeker.", "place_query": "Sultan II. Murat Camii, Uzunköprü, Edirne"}, {"title": "Yeniköy Mağarası", "summary": "Uzunköprü yakınlarındaki bu doğal mağara, keşfedilmeyi bekleyen bir doğa harikasıdır. Mağara içindeki sarkıt ve dikitler, doğa tutkunları için etkileyici bir görüntü sunar.", "place_query": "Yeniköy Mağarası, Uzunköprü, Edirne"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '55398cb4-fdbe-426b-9379-e981ca37becc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ağın Kalesi", "summary": "Keban Baraj Gölü kıyısında, yarımada üzerinde yer alan tarihi bir kaledir. Frig, Roma ve Bizans dönemlerine ait izler taşıyan kale, muhteşem göl ve doğa manzarası sunar.", "place_query": "Ağın Kalesi, Ağın, Elazığ"}, {"title": "Keban Baraj Gölü (Ağın Kıyıları)", "summary": "Elazığ''ın en büyük baraj göllerinden biri olan Keban Baraj Gölü''nün Ağın kıyıları, huzurlu doğası ve serin sularıyla piknik, kamp ve tekne turları için idealdir.", "place_query": "Keban Baraj Gölü, Ağın, Elazığ"}, {"title": "Ağın Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını yansıtan küçük ama etkileyici bir müzedir. Yöresel kıyafetler, arkeolojik buluntular ve etnografik eserler sergilenmektedir.", "place_query": "Ağın Müzesi, Ağın, Elazığ"}, {"title": "Taş Evler ve Tarihi Ağın Sokakları", "summary": "Ağın''ın daracık sokaklarında sıralanan taş evler, Osmanlı dönemi mimarisinin güzel örneklerindendir. Fotoğraf tutkunları ve tarih meraklıları için görülmeye değerdir.", "place_query": "Tarihi Ağın Evleri, Ağın, Elazığ"}, {"title": "Ağın Köprüsü", "summary": "Keban Baraj Gölü üzerinde yer alan bu tarihi köprü, ilçeyi çevre yerleşimlere bağlar. Çevresindeki göl manzarası eşliğinde yürüyüş yapabilirsiniz.", "place_query": "Ağın Köprüsü, Ağın, Elazığ"}, {"title": "Yelmaniye Köyü ve Yaylaları", "summary": "Ağın''a bağlı Yelmaniye Köyü, yemyeşil yaylaları ve temiz havasıyla doğa yürüyüşleri için popüler bir noktadır. Köyde geleneksel yaşamı gözlemleyebilirsiniz.", "place_query": "Yelmaniye Köyü, Ağın, Elazığ"}, {"title": "Ağın Şelalesi", "summary": "İlçe merkezine yakın bir konumda bulunan bu küçük şelale, çevresindeki ağaçlık alanla serinlemek ve doğayla baş başa kalmak için güzel bir duraktır.", "place_query": "Ağın Şelalesi, Ağın, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b04f504f-a6a7-4dd9-b39f-8158d8f22a4e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alacakaya Mağarası", "summary": "Bölgenin en önemli doğal güzelliklerinden biri olan bu mağara, etkileyici sarkıt ve dikitleriyle ziyaretçilerini büyüler. Doğa sporları ve mağara turizmi için ideal bir noktadır.", "place_query": "Alacakaya Mağarası, Alacakaya, Elazığ"}, {"title": "Hazar Gölü", "summary": "Elazığ''ın incisi olarak bilinen bu büyük göl, Alacakaya ilçesine de yakın mesafededir. Muhteşem manzarası, yüzme alanları ve piknik olanaklarıyla hafta sonu kaçamakları için popüler bir destinasyondur.", "place_query": "Hazar Gölü, Elazığ"}, {"title": "Alacakaya Kalesi", "summary": "Tarihi bir kalıntı olan bu kale, ilçenin yüksek bir noktasında yer alır ve çevreye hakim bir manzara sunar. Tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Alacakaya Kalesi, Alacakaya, Elazığ"}, {"title": "Maden Deresi (Alacakaya)", "summary": "Doğal yapısı ve çevresindeki yeşil alanlarla dikkat çeken bu dere, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için tercih edilir. Bölge halkının uğrak noktalarındandır.", "place_query": "Maden Deresi, Alacakaya, Elazığ"}, {"title": "Alacakaya Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, özellikle bahar aylarında suyunun bol olduğu dönemlerde görsel bir şölen sunar. Doğa fotoğrafçıları ve piknikçiler için idealdir.", "place_query": "Alacakaya Şelalesi, Alacakaya, Elazığ"}, {"title": "Sivrice Kayak Merkezi (Hazar Baba)", "summary": "Alacakaya''ya da yakın mesafedeki bu kayak merkezi, kış aylarında kayak ve snowboard yapmak isteyenler için popüler bir destinasyondur. Hazar Gölü manzarası eşliğinde kış sporları yapma imkanı sunar.", "place_query": "Hazar Baba Kayak Merkezi, Sivrice, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2b59d2d3-5455-4a75-b704-f688210276d1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Arıcak Merkez Camii", "summary": "İlçenin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve bölge halkı için önemli bir ibadet ve kültür merkezidir.", "place_query": "Arıcak Merkez Camii, Arıcak, Elazığ"}, {"title": "Keban Barajı (Arıcak Kıyıları)", "summary": "Elazığ''ın en büyük baraj göllerinden biri olan Keban Barajı''nın Arıcak kıyıları, doğal manzarası ve balıkçılık aktiviteleriyle ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Keban Barajı Arıcak Kıyıları, Arıcak, Elazığ"}, {"title": "Arıcak Yaylaları (Örneğin: Baskil Yaylası)", "summary": "İlçe çevresindeki yeşil yaylalar, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Baskil Yaylası, Arıcak, Elazığ"}, {"title": "Arıcak Kalesi", "summary": "Tarihi bir kalıntı olan Arıcak Kalesi, bölgenin geçmişine ışık tutan ve çevresine hakim bir tepede yer alan etkileyici bir yapıdır.", "place_query": "Arıcak Kalesi, Arıcak, Elazığ"}, {"title": "Maden Deresi (Arıcak Çayı)", "summary": "İlçeden geçen bu doğal dere, çevresindeki piknik alanları ve yeşil doğasıyla özellikle hafta sonu aile gezileri için popüler bir mekandır.", "place_query": "Maden Deresi Arıcak, Elazığ"}, {"title": "Arıcak Şehitliği ve Anıtı", "summary": "İlçenin manevi değerlerinden biri olan şehitlik, ziyaretçilere saygı duruşunda bulunma ve bölgenin tarihine tanıklık etme fırsatı sunar.", "place_query": "Arıcak Şehitliği, Arıcak, Elazığ"}, {"title": "Arıcak Piknik Alanları (Örneğin: Gölpınar Mesire Yeri)", "summary": "İlçe çevresindeki ağaçlık alanlarda kurulu piknik alanları, mangal keyfi ve doğayla iç içe vakit geçirmek isteyenler için idealdir.", "place_query": "Gölpınar Mesire Yeri, Arıcak, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '54c39560-2b47-4cf4-a66d-a4e8e403140a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Baskil Kalesi", "summary": "Tarihi bir kale olup bölgenin hakim tepelerinden birinde yer alır. Hem tarihi dokuyu görmek hem de çevredeki doğal manzarayı izlemek için ziyaret edilir.", "place_query": "Baskil Kalesi, Baskil, Elazığ"}, {"title": "Keban Baraj Gölü (Baskil Kıyıları)", "summary": "Keban Barajı''nın Baskil ilçesi sınırları içinde kalan kıyı şeridi, piknik ve doğa yürüyüşü için popülerdir. Gölet manzarası ve temiz havasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Keban Baraj Gölü Baskil kıyıları, Baskil, Elazığ"}, {"title": "Baskil Şelalesi", "summary": "İlçe merkezine yakın doğal bir şelale olup, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir. Çevresi piknik alanlarıyla donatılmıştır.", "place_query": "Baskil Şelalesi, Baskil, Elazığ"}, {"title": "Baskil Kaya Mezarları", "summary": "Tarihi dönemlere ait kaya mezarları, bölgenin antik geçmişine ışık tutar. Tarih meraklıları için ilgi çekici bir duraktır.", "place_query": "Baskil Kaya Mezarları, Baskil, Elazığ"}, {"title": "Baskil Yaylaları (Örneğin: Sarıyayla)", "summary": "Baskil çevresindeki yaylalar, yeşil doğası ve yayla kültürünü deneyimlemek isteyenler için idealdir. Özellikle yaz aylarında serin hava ve doğa yürüyüşleri için uğrak noktasıdır.", "place_query": "Baskil yaylaları, Baskil, Elazığ"}, {"title": "Baskil Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi cami, mimarisi ve manevi atmosferiyle ziyaretçileri cezbeder. Baskil''in kültürel dokusunu yansıtan önemli bir yapıdır.", "place_query": "Baskil Merkez Camii, Baskil, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1171ee9f-1260-4053-af19-4b823480383b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karakoçan Kalesi", "summary": "İlçe merkezinde bulunan tarihi bir kaledir. Bölgenin savunma amaçlı kullanılan yapılarından biri olup, çevresindeki doğal manzara ile ziyaretçilerine tarihi bir atmosfer sunar.", "place_query": "Karakoçan Kalesi, Karakoçan, Elazığ"}, {"title": "Keban Barajı Karakoçan Kıyıları", "summary": "Keban Baraj Gölü''nün Karakoçan sınırları içinde kalan kıyı şeridi, piknik ve doğa yürüyüşü için idealdir. Sakin suları ve yeşil çevresiyle huzurlu bir kaçış noktasıdır.", "place_query": "Keban Barajı Karakoçan Kıyıları, Karakoçan, Elazığ"}, {"title": "Karakoçan Mesire Alanı", "summary": "İlçe merkezine yakın, ağaçlık bir alanda kurulu mesire yeridir. Aileler için mangal ve piknik yapma imkanı sunar, hafta sonları yoğun ilgi görür.", "place_query": "Karakoçan Mesire Alanı, Karakoçan, Elazığ"}, {"title": "Sarıcan Köyü Tarihi Camii", "summary": "Sarıcan Köyü''nde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Ahşap işçiliği ve sade yapısıyla dikkat çeker.", "place_query": "Sarıcan Köyü Tarihi Camii, Karakoçan, Elazığ"}, {"title": "Güneybağlar Köyü Şelalesi", "summary": "Güneybağlar Köyü yakınlarında yer alan bu küçük şelale, doğal güzelliği ve serin sularıyla özellikle yaz aylarında ziyaretçi çeker. Çevresi yürüyüş ve fotoğrafçılık için uygundur.", "place_query": "Güneybağlar Köyü Şelalesi, Karakoçan, Elazığ"}, {"title": "Karakoçan Yaylaları (Örn: Kırmızı Yayla)", "summary": "İlçenin yüksek kesimlerinde yer alan yaylalar, temiz havası ve geniş otlaklarıyla bilinir. Kırmızı Yayla gibi noktalar, doğa severler için kamp ve trekking rotaları sunar.", "place_query": "Kırmızı Yayla, Karakoçan, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '70034b72-39e5-428b-bd2f-a8407e4b98d6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Keban Baraj Gölü", "summary": "Türkiye''nin en büyük baraj göllerinden biri olan Keban Baraj Gölü, muhteşem manzarası ve su sporları olanaklarıyla ziyaretçileri cezbeder. Özellikle gün batımında eşsiz bir doğa deneyimi sunar.", "place_query": "Keban Baraj Gölü, Keban, Elazığ"}, {"title": "Keban Kalesi", "summary": "Tarihi bir geçmişe sahip olan Keban Kalesi, Fırat Nehri kıyısında yükselerek bölgeye hakim bir konumda yer alır. Kaleye çıktığınızda hem tarihi dokuyu hem de nehir manzarasını bir arada görebilirsiniz.", "place_query": "Keban Kalesi, Keban, Elazığ"}, {"title": "Keban İlçe Merkezi ve Çarşısı", "summary": "Keban''ın samimi ilçe merkezi, küçük dükkanları ve yöresel ürünleriyle keşfedilmeyi bekler. Burada yöresel lezzetlerden alışveriş yapabilir ve ilçenin günlük yaşamına tanıklık edebilirsiniz.", "place_query": "Keban Merkez, Elazığ"}, {"title": "Fırat Nehri Kıyısı ve Mesire Alanları", "summary": "Fırat Nehri''nin serin suları boyunca uzanan mesire alanları, piknik ve doğa yürüyüşü için idealdir. Nehir kenarında huzur dolu bir gün geçirebilirsiniz.", "place_query": "Fırat Nehri, Keban, Elazığ"}, {"title": "Keban Höyüğü", "summary": "Keban Baraj Gölü''nün suları altında kalmadan önce kurtarma kazıları yapılan Keban Höyüğü, bölgenin antik tarihine ışık tutar. Arkeoloji meraklıları için önemli bir duraktır.", "place_query": "Keban Höyüğü, Keban, Elazığ"}, {"title": "Ağın-Keban Yolu Manzaraları", "summary": "Keban ile Ağın arasındaki yol, Fırat Nehri ve baraj gölünün eşsiz manzaraları eşliğinde keyifli bir sürüş deneyimi sunar. Fotoğrafçılar için vazgeçilmez bir rotadır.", "place_query": "Keban Ağın yolu, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fdf51fc9-197a-4420-b45a-44a0d45988f5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kovancılar Şelalesi", "summary": "Kovancılar''ın doğal güzelliklerinden biri olan bu şelale, piknik ve doğa yürüyüşü için ideal bir ortam sunar. Serin suları ve yeşil çevresiyle özellikle yaz aylarında ziyaretçi çeker.", "place_query": "Kovancılar Şelalesi, Kovancılar, Elazığ"}, {"title": "Kovancılar Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale, bölgenin savunma yapılarından biridir. Tepe üzerinde yer alan kaleyi ziyaret ederek hem tarihi keşfedebilir hem de çevre manzarasını izleyebilirsiniz.", "place_query": "Kovancılar Kalesi, Kovancılar, Elazığ"}, {"title": "Poyraz Barajı ve Mesire Alanı", "summary": "Poyraz Barajı çevresinde oluşturulan mesire alanı, piknik ve kamp yapmak isteyenler için huzurlu bir ortam sağlar. Baraj manzarası eşliğinde doğayla baş başa vakit geçirebilirsiniz.", "place_query": "Poyraz Barajı, Kovancılar, Elazığ"}, {"title": "Kovancılar Müzesi", "summary": "Kovancılar''ın kültürel ve tarihi mirasını yansıtan bu müze, yöresel eserler ve etnografik objelerle zengin bir koleksiyona sahiptir. Bölgenin geçmişine dair keyifli bir yolculuk sunar.", "place_query": "Kovancılar Müzesi, Kovancılar, Elazığ"}, {"title": "Çakırkaş Yaylası", "summary": "Kovancılar sınırlarındaki bu yayla, yemyeşil doğası ve temiz havasıyla doğaseverler için kaçış noktasıdır. Yayla şenliklerine ev sahipliği yapmasıyla da bilinir.", "place_query": "Çakırkaş Yaylası, Kovancılar, Elazığ"}, {"title": "Kovancılar Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, mimari detayları ve manevi atmosferiyle dikkat çeker. Ziyaretçiler hem ibadet edebilir hem de yapının estetiğini gözlemleyebilir.", "place_query": "Kovancılar Merkez Camii, Kovancılar, Elazığ"}, {"title": "Sarıbahçe Köyü Kaya Mezarları", "summary": "Kovancılar''a bağlı Sarıbahçe Köyü''nde bulunan bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Tarih meraklıları için ilgi çekici bir duraktır.", "place_query": "Sarıbahçe Köyü Kaya Mezarları, Kovancılar, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bc03e2a1-42cf-463e-91de-cb177558d5a5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hazar Gölü", "summary": "Elazığ''ın en popüler doğal güzelliklerinden biri olan Hazar Gölü, yüzme, piknik ve kamp gibi aktiviteler için idealdir. Göl çevresindeki tesislerde konaklama ve yeme-içme imkanı da bulunur.", "place_query": "Hazar Gölü, Elazığ"}, {"title": "Harput Kalesi", "summary": "Elazığ merkeze bağlı Harput''ta yer alan tarihi kale, şehre hakim muhteşem bir manzaraya sahiptir. Urartu döneminden kalma bu yapı, bölgenin en önemli tarihi simgelerindendir.", "place_query": "Harput Kalesi, Elazığ"}, {"title": "Keban Barajı ve Göleti", "summary": "Maden ilçesine yakın konumdaki Keban Barajı, Türkiye''nin en büyük barajlarından biridir. Baraj gölü çevresinde doğa yürüyüşleri yapabilir ve etkileyici manzaraları fotoğraflayabilirsiniz.", "place_query": "Keban Barajı, Elazığ"}, {"title": "Maden Müzesi", "summary": "Maden ilçesinde bulunan bu müze, bölgenin zengin maden tarihini ve jeolojik yapısını sergiler. Bakır çıkarma süreci ve yöresel maden örnekleri hakkında bilgi edinebilirsiniz.", "place_query": "Maden Müzesi, Elazığ"}, {"title": "Hazar Baba Tepesi", "summary": "Hazar Gölü kıyısında yer alan bu tepe, kuşbakışı göl ve çevre manzarasıyla ünlüdür. Özellikle gün batımında eşsiz fotoğraflar çekmek için popüler bir noktadır.", "place_query": "Hazar Baba Tepesi, Elazığ"}, {"title": "Sivrice Kayak Merkezi", "summary": "Elazığ''ın Sivrice ilçesinde bulunan bu kayak merkezi, kış aylarında kayak ve snowboard yapmak isteyenler için idealdir. Telesiyej ve konaklama tesisleri mevcuttur.", "place_query": "Sivrice Kayak Merkezi, Elazığ"}, {"title": "Buzluk Mağarası", "summary": "Elazığ merkeze bağlı Buzluk köyünde yer alan bu mağara, yaz kış sıcaklığını koruyan buzullarıyla dikkat çeker. Doğal bir soğutma sistemi gibi çalışan mağara, ilginç bir gezi noktasıdır.", "place_query": "Buzluk Mağarası, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b9569d7a-f7e9-4ce1-b334-179f10c1da0f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Harput Kalesi", "summary": "Elazığ''ın simgesi haline gelmiş tarihi bir kaledir. Şehre hakim bir tepede yer alan kale, Urartu döneminden günümüze ulaşmış etkileyici surları ve manzarasıyla ziyaretçilerini büyüler.", "place_query": "Harput Kalesi, Elazığ Merkez"}, {"title": "Hazar Gölü", "summary": "Elazığ''ın en popüler doğal güzelliklerinden biridir. Çevresindeki mesire alanları, plajları ve yürüyüş yollarıyla özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Hazar Gölü, Elazığ"}, {"title": "Harput Ulu Camii", "summary": "Anadolu''nun en eski camilerinden biri olup, 11. yüzyılda Artuklular tarafından inşa edilmiştir. Tarihi dokusu ve kesme taştan yapılmış görkemli mimarisiyle dikkat çeker.", "place_query": "Harput Ulu Camii, Elazığ"}, {"title": "Elazığ Arkeoloji ve Etnoğrafya Müzesi", "summary": "Bölgenin zengin tarihini gözler önüne seren müze, Urartu, Roma ve Bizans dönemlerine ait eserlerin yanı sıra yöresel kıyafet ve eşyaları da sergiler.", "place_query": "Elazığ Arkeoloji ve Etnoğrafya Müzesi, Elazığ Merkez"}, {"title": "Buzluk Mağarası", "summary": "Yaz kış sıcaklığını koruyan ve içinde doğal buz oluşumları bulunan ilginç bir mağaradır. Özellikle sıcak yaz günlerinde serinlemek için uğranan popüler bir duraktır.", "place_query": "Buzluk Mağarası, Elazığ Merkez"}, {"title": "Keban Baraj Gölü", "summary": "Türkiye''nin en büyük baraj göllerinden biridir. Çevresindeki piknik alanları, su sporları imkanları ve muhteşem manzarasıyla doğaseverler için harika bir kaçış noktasıdır.", "place_query": "Keban Baraj Gölü, Elazığ"}, {"title": "Sivrice Kayak Merkezi", "summary": "Hazar Gölü kıyısında yer alan bu kayak merkezi, kış aylarında kayak ve snowboard yapmak isteyenler için idealdir. Aynı zamanda göl manzaralı pistleriyle de benzersiz bir deneyim sunar.", "place_query": "Sivrice Kayak Merkezi, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f2731ecc-0bf3-4903-80f0-07822ea7f947'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Palu Kalesi", "summary": "Murat Nehri kıyısında yükselen tarihi kale, Urartu döneminden kalma izler taşır ve bölgenin en önemli simgelerindendir. Zirveye çıktığınızda Palu Ovası ve nehrin muhteşem manzarası sizi bekler.", "place_query": "Palu Kalesi, Palu, Elazığ"}, {"title": "Cimşit Kalesi", "summary": "Palu''nun yaklaşık 10 km kuzeyinde, sarp bir kaya üzerine inşa edilmiş bu kale, Orta Çağ''dan günümüze ulaşan etkileyici bir yapıdır. Doğa yürüyüşü sevenler için keşfedilmeyi bekleyen tarihi bir hazinedir.", "place_query": "Cimşit Kalesi, Palu, Elazığ"}, {"title": "Palu Ulu Camii", "summary": "Selçuklu döneminde inşa edilen bu tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Şehir merkezinde yer alan cami, hala ibadete açık olup ziyaretçilerine huzurlu bir atmosfer sunar.", "place_query": "Palu Ulu Camii, Palu, Elazığ"}, {"title": "Hazarbaba Kayak Merkezi", "summary": "Elazığ merkeze yaklaşık 30 km mesafede bulunan bu kayak merkezi, kış aylarında kayak ve snowboard tutkunlarını ağırlar. Yazın ise doğa yürüyüşleri ve piknik için ideal bir kaçış noktasıdır.", "place_query": "Hazarbaba Kayak Merkezi, Elazığ"}, {"title": "Murat Nehri Kenarı", "summary": "Palu''dan geçen Murat Nehri, özellikle bahar aylarında yeşilin ve mavinin buluştuğu huzur verici bir manzara sunar. Nehir kenarında yürüyüş yapabilir, piknik alanlarında vakit geçirebilirsiniz.", "place_query": "Murat Nehri, Palu, Elazığ"}, {"title": "Gökçedere Şelalesi", "summary": "Palu ilçe merkezine yaklaşık 20 km uzaklıkta bulunan bu şelale, çevresindeki yeşil alanlarla birlikte doğaseverler için popüler bir duraktır. Özellikle yaz aylarında serinlemek ve doğayla iç içe olmak için tercih edilir.", "place_query": "Gökçedere Şelalesi, Palu, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'be47f1d5-0547-497a-96d0-29c4f83c28d5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hazar Gölü", "summary": "Elazığ''ın incisi olarak bilinen bu tektonik göl, doğal güzelliği ve çevresindeki mesire alanlarıyla yüzme, piknik ve kamp için ideal bir noktadır.", "place_query": "Hazar Gölü, Sivrice, Elazığ"}, {"title": "Sivrice Kayak Merkezi", "summary": "Hazar Gölü kıyısında yer alan bu kayak merkezi, kış aylarında kayak ve snowboard yapmak isteyenler için şehre yakın bir alternatif sunar.", "place_query": "Sivrice Kayak Merkezi, Elazığ"}, {"title": "Keban Baraj Gölü (Sivrice Kıyıları)", "summary": "Devasa baraj gölünün Sivrice sınırları içindeki kıyı şeridi, balıkçılık ve tekne turları için popülerdir ve muhteşem manzaralar sunar.", "place_query": "Keban Baraj Gölü, Sivrice, Elazığ"}, {"title": "Sivrice Kalesi", "summary": "Tarihi bir Urartu kalesi olan bu yapı, ilçe merkezine hakim bir tepede yer alır ve çevrenin panoramik manzarasını izleme imkanı verir.", "place_query": "Sivrice Kalesi, Sivrice, Elazığ"}, {"title": "Cip Barajı ve Mesire Alanı", "summary": "Elazığ merkeze yakın olan bu baraj ve çevresi, yeşil alanları ve yürüyüş parkurlarıyla hafta sonu kaçamakları için sık tercih edilen bir dinlenme noktasıdır.", "place_query": "Cip Barajı, Elazığ"}, {"title": "Sivrice İlçe Merkezi ve Çarşısı", "summary": "Küçük ve samimi bir ilçe merkezi olan Sivrice, yöresel ürünlerin satıldığı pazarları ve sakin atmosferiyle ziyaretçilere farklı bir deneyim sunar.", "place_query": "Sivrice Merkez, Elazığ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a0226c52-7658-419a-9d72-cf35638eb91f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çayırlı Merkez Camii ve Çevresi", "summary": "İlçe merkezinde yer alan tarihi cami, yöresel mimarinin güzel bir örneğidir. Çevresindeki çarşı ve kahvehaneler, ilçenin günlük yaşamına tanıklık etmek için idealdir.", "place_query": "Çayırlı Merkez Camii, Erzincan"}, {"title": "Esence Dağları (Keşiş Dağı)", "summary": "İlçenin güneyinde yükselen bu görkemli dağ silsilesi, doğa yürüyüşleri ve dağcılık için popülerdir. Zirveleri karla kaplı manzarasıyla fotoğrafçılar için eşsiz bir duraktır.", "place_query": "Esence Dağları, Çayırlı, Erzincan"}, {"title": "Çayırlı Yaylaları (Özellikle Kırkbulak Yaylası)", "summary": "Serin havası, yeşil çayırları ve temiz havasıyla yaz aylarında kaçış noktasıdır. Yaylacılık kültürünü yakından görmek ve doğayla baş başa kalmak için idealdir.", "place_query": "Kırkbulak Yaylası, Çayırlı, Erzincan"}, {"title": "Çayırlı Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumda bulunan gölet, piknik ve olta balıkçılığı için tercih edilen bir alandır. Çevresindeki yeşil alanlar aileler için huzurlu bir ortam sunar.", "place_query": "Çayırlı Göleti, Erzincan"}, {"title": "Karasu Nehri Kenarı", "summary": "İlçe sınırlarından geçen Karasu Nehri''nin berrak suları ve çevresindeki doğal doku, doğa yürüyüşleri ve fotoğraf çekimleri için güzel bir rotadır. Özellikle ilkbahar ve yaz aylarında canlı bir manzaraya sahiptir.", "place_query": "Karasu Nehri, Çayırlı, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'be5ab8ce-91a7-47d1-a88e-1ea9ff6e3a24'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İliç Kalesi", "summary": "Tarihi bir kaya kütlesi üzerine inşa edilmiş olan bu kale, İliç''in sembol yapılarındandır. Çevresindeki vadi manzarası ile ziyaretçilere eşsiz bir seyir imkanı sunar.", "place_query": "İliç Kalesi, İliç, Erzincan"}, {"title": "Karasu Nehri (İliç Bölümü)", "summary": "Erzincan''ın önemli akarsularından biri olan Karasu Nehri, İliç sınırları içerisinde doğal güzellikler sunar. Özellikle piknik ve doğa yürüyüşleri için tercih edilen bir noktadır.", "place_query": "Karasu Nehri, İliç, Erzincan"}, {"title": "İliç Yöresel Pazarı", "summary": "Yöre halkının el emeği ürünlerini ve organik tarım ürünlerini bulabileceğiniz bu pazar, İliç''in kültürel dokusunu yansıtır. Ziyaretçilere otantik bir alışveriş deneyimi sunar.", "place_query": "İliç Pazarı, İliç, Erzincan"}, {"title": "Mihrap Yaylası", "summary": "İliç''e bağlı yaylalardan biri olan Mihrap Yaylası, yemyeşil doğası ve temiz havasıyla yaz aylarında kamp ve doğa tatili yapmak isteyenler için idealdir.", "place_query": "Mihrap Yaylası, İliç, Erzincan"}, {"title": "İliç Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Sade ve huzurlu atmosferi ile dini ve kültürel bir ziyaret noktasıdır.", "place_query": "İliç Merkez Camii, İliç, Erzincan"}, {"title": "Kuruçay Şelalesi", "summary": "İliç yakınlarında bulunan bu şelale, doğa severler için serinletici bir kaçış noktasıdır. Çevresindeki yeşil alanlar piknik ve fotoğrafçılık için elverişlidir.", "place_query": "Kuruçay Şelalesi, İliç, Erzincan"}, {"title": "İliç Köprüsü", "summary": "Tarihi bir taş köprü olan İliç Köprüsü, bölgenin geçmişteki ulaşım ağının önemli bir parçasıdır. Günümüzde fotoğraf tutkunları ve tarih meraklıları tarafından ziyaret edilmektedir.", "place_query": "İliç Köprüsü, İliç, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a77567f7-4c80-4afd-932e-84e94697f2eb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kemah Kalesi", "summary": "Karasu Nehri kıyısında yüksek bir kaya üzerine kurulu tarihi bir kaledir. Selçuklu ve Osmanlı dönemlerine ait izler taşır ve muhteşem bir vadi manzarası sunar.", "place_query": "Kemah Kalesi, Kemah, Erzincan"}, {"title": "Kemah Tarihi Köprüsü", "summary": "Karasu Nehri üzerinde yer alan bu tarihi taş köprü, Roma döneminden günümüze ulaşan nadir yapılardandır. Köprünün çevresi piknik ve fotoğrafçılık için idealdir.", "place_query": "Kemah Tarihi Köprüsü, Kemah, Erzincan"}, {"title": "Kemah Ulu Camii", "summary": "Selçuklu dönemine ait olan bu cami, ahşap işçiliği ve sade mimarisiyle dikkat çeker. Tarihi doku içinde huzurlu bir ziyaret noktasıdır.", "place_query": "Kemah Ulu Camii, Kemah, Erzincan"}, {"title": "Kemah Çayı ve Mesire Alanı", "summary": "Karasu Çayı kıyısında yer alan bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek için bölge halkının uğrak noktasıdır. Yürüyüş parkurları ve kır kahveleri bulunur.", "place_query": "Kemah Çayı Mesire Alanı, Kemah, Erzincan"}, {"title": "Kemah Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgedeki arkeolojik ve etnografik eserleri sergiler. Kemah''ın tarihine dair kapsamlı bilgi edinmek isteyenler için idealdir.", "place_query": "Kemah Müzesi, Kemah, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '07bf610f-8a3b-43cf-afb7-4333853b46fe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karanlık Kanyon", "summary": "Dünyanın en derin ikinci kanyonu olan bu etkileyici doğa harikası, dik kayalıkları ve Fırat Nehri''nin turkuaz sularıyla nefes kesici bir manzara sunar. Tekne turları ve doğa yürüyüşleri için popüler bir destinasyondur.", "place_query": "Karanlık Kanyon, Kemaliye, Erzincan"}, {"title": "Kemaliye Evleri", "summary": "Kemaliye''nin dar sokaklarında sıralanan tarihi taş ve ahşap evler, Osmanlı dönemi mimarisinin güzel örneklerini oluşturur. Şehir merkezinde yürüyerek keşfedilebilecek bu yapılar, fotoğrafçılar için de ideal bir mekandır.", "place_query": "Kemaliye Evleri, Erzincan"}, {"title": "Kemaliye (Eğin) Müzesi", "summary": "Eski bir konakta hizmet veren bu müze, yöresel kıyafetler, el sanatları ve etnografik eserlerle bölgenin kültürel zenginliğini sergiler. Ziyaretçilere Kemaliye''nin tarihi ve gelenekleri hakkında keyifli bir yolculuk sunar.", "place_query": "Kemaliye Müzesi, Erzincan"}, {"title": "Karasu Çayı ve Bağlar", "summary": "Kemaliye''nin verimli bağları arasından akan Karasu Çayı, serin suları ve yeşil doğasıyla huzurlu bir kaçış noktasıdır. Özellikle yaz aylarında piknik ve doğa yürüyüşü için tercih edilir.", "place_query": "Karasu Çayı, Kemaliye, Erzincan"}, {"title": "Kemaliye Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale kalıntıları, şehre ve Fırat Nehri vadisine hakim panoramik bir seyir imkanı sunar. Bölgenin stratejik önemini anlamak için görülmeye değer bir noktadır.", "place_query": "Kemaliye Kalesi, Erzincan"}, {"title": "Taş Köprü (Kemaliye Köprüsü)", "summary": "Kemaliye''nin simgelerinden biri olan bu tarihi taş köprü, Fırat Nehri üzerinde yükselir ve Osmanlı dönemi mühendisliğinin zarif bir örneğidir. Köprüden geçerken nehir manzarası ve çevredeki doğa keyifli bir deneyim sunar.", "place_query": "Taş Köprü, Kemaliye, Erzincan"}, {"title": "Kemaliye Kanyonu ve Yürüyüş Parkurları", "summary": "Karanlık Kanyon''a komşu olan bu bölge, dik yamaçlar ve derin vadilerle çevrili etkileyici yürüyüş rotalarına ev sahipliği yapar. Doğa sporları meraklıları için macera dolu bir keşif alanıdır.", "place_query": "Kemaliye Kanyonu, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '75406dcc-38b9-49d7-a8ad-65b9892bc301'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Erzincan Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, Erzincan''ın simgelerinden biridir. Roma döneminden kalma yapı, şehrin panoramik manzarasını sunar.", "place_query": "Erzincan Kalesi, Erzincan Merkez"}, {"title": "Kemaliye (Eğin) Evleri", "summary": "Kemaliye ilçesinde bulunan bu tarihi evler, Osmanlı dönemi mimarisinin en güzel örneklerindendir. Taş ve ahşap işçiliğiyle dikkat çeken evler, dar sokaklarıyla büyüleyici bir atmosfer sunar.", "place_query": "Kemaliye Evleri, Erzincan"}, {"title": "Girlevik Şelalesi", "summary": "Erzincan''ın Çağlayan beldesinde yer alan bu şelale, yıl boyunca akan suları ve çevresindeki piknik alanlarıyla popüler bir doğa harikasıdır. Özellikle bahar aylarında ziyaretçi akınına uğrar.", "place_query": "Girlevik Şelalesi, Erzincan"}, {"title": "Eksisu Mesire Alanı", "summary": "Şehir merkezine yakın bu mesire alanı, doğal göleti ve yeşil alanlarıyla aileler için ideal bir kaçış noktasıdır. Yürüyüş yolları ve piknik masalarıyla donatılmıştır.", "place_query": "Eksisu Mesire Alanı, Erzincan"}, {"title": "Erzincan Müzesi", "summary": "Şehir merkezinde bulunan müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Urartu, Roma ve Osmanlı dönemlerine ait eserler görülebilir.", "place_query": "Erzincan Müzesi, Erzincan Merkez"}, {"title": "Keşiş Dağı (Esence Dağları)", "summary": "Erzincan''ın doğusunda yükselen bu dağ silsilesi, doğa yürüyüşleri ve dağcılık için popülerdir. Kış aylarında kayak turizmi de yapılabilir.", "place_query": "Keşiş Dağı, Erzincan"}, {"title": "Terzi Baba Türbesi", "summary": "Erzincan''ın manevi değerlerinden biri olan bu türbe, halk arasında saygı gören bir ziyaret noktasıdır. Şehir merkezine yakın konumuyla kolayca ulaşılabilir.", "place_query": "Terzi Baba Türbesi, Erzincan Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9c3eabea-934a-463f-ac43-66e90e59a275'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Otlukbeli Gölü", "summary": "Erzincan''ın Otlukbeli ilçesinde yer alan bu krater gölü, doğal güzelliği ve huzur veren atmosferiyle ziyaretçilerini büyüler. Çevresindeki yemyeşil ormanlık alan ve temiz havası, doğa yürüyüşleri ve piknik için ideal bir ortam sunar.", "place_query": "Otlukbeli Gölü, Otlukbeli, Erzincan"}, {"title": "Otlukbeli Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard tutkunlarının uğrak noktası olan bu merkez, bakir pistleri ve doğal karıyla dikkat çeker. Özellikle hafta sonu kaçamakları için popüler bir destinasyondur.", "place_query": "Otlukbeli Kayak Merkezi, Otlukbeli, Erzincan"}, {"title": "Otlukbeli Yaylası", "summary": "Yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için birebir olan bu yayla, geniş çayırları ve eşsiz manzarasıyla ünlüdür. Yöresel lezzetleri tatma ve kamp yapma imkanı da sunar.", "place_query": "Otlukbeli Yaylası, Otlukbeli, Erzincan"}, {"title": "Otlukbeli Taş Köprü", "summary": "Tarihi bir yapı olan bu taş köprü, ilçenin geçmişine ışık tutan önemli bir kültürel mirastır. Çevresindeki doğal dokuyla bütünleşen köprü, fotoğrafçılar için güzel bir kare yakalama fırsatı sunar.", "place_query": "Otlukbeli Taş Köprü, Otlukbeli, Erzincan"}, {"title": "Otlukbeli Mesire Alanı", "summary": "Aileler ve arkadaş grupları için piknik ve dinlenme amacıyla tercih edilen bu alan, ağaçlar arasında huzurlu bir ortam sağlar. Çocuk oyun alanları ve oturma banklarıyla donatılmıştır.", "place_query": "Otlukbeli Mesire Alanı, Otlukbeli, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '405d4257-e999-4d55-bad4-4cbf650694a3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Refahiye Kalesi", "summary": "Tarihi bir kaya kütlesi üzerine kurulu olan kale, Refahiye''nin en önemli tarihi yapılarından biridir. Çevresindeki doğal güzelliklerle birlikte ziyaretçilere eşsiz bir manzara sunar.", "place_query": "Refahiye Kalesi, Refahiye, Erzincan"}, {"title": "Kızıldağ Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard tutkunlarının uğrak noktası olan merkez, doğal karla kaplı pistleriyle bilinir. Yazın ise doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Kızıldağ Kayak Merkezi, Refahiye, Erzincan"}, {"title": "Göynük Göleti", "summary": "Refahiye''nin huzur veren doğal alanlarından biri olan gölet, piknik ve olta balıkçılığı için popülerdir. Çevresi çam ormanlarıyla kaplıdır ve dinlenmek için mükemmel bir ortam sunar.", "place_query": "Göynük Göleti, Refahiye, Erzincan"}, {"title": "Cengerli Kaplıcası", "summary": "Şifalı termal sularıyla ünlü olan kaplıca, romatizma ve cilt hastalıklarına iyi geldiği düşünülen doğal bir kaynaktır. Doğa içinde konumlanmış olup termal turizm için önemli bir duraktır.", "place_query": "Cengerli Kaplıcası, Refahiye, Erzincan"}, {"title": "Kemah Kalesi", "summary": "Refahiye''ye yaklaşık 30 km uzaklıktaki bu tarihi kale, Fırat Nehri kıyısında yükselen etkileyici bir yapıdır. Urartu döneminden kalma olduğu tahmin edilen kale, bölgenin tarihine ışık tutar.", "place_query": "Kemah Kalesi, Kemah, Erzincan"}, {"title": "Karasu Çayı Vadisi", "summary": "Doğa yürüyüşü ve fotoğrafçılık için ideal olan vadi, yemyeşil bitki örtüsü ve şelaleleriyle ünlüdür. Özellikle ilkbahar aylarında canlanan doğasıyla ziyaretçilerine huzur verir.", "place_query": "Karasu Çayı Vadisi, Refahiye, Erzincan"}, {"title": "Sarıçiçek Yaylası", "summary": "Refahiye''nin en güzel yaylalarından biri olan Sarıçiçek, yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için idealdir. Yöresel lezzetlerin tadılabileceği yayla şenlikleri de düzenlenmektedir.", "place_query": "Sarıçiçek Yaylası, Refahiye, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9bbbf914-ea26-4622-a496-c328a0a3e2ed'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mama Hatun Türbesi ve Külliyesi", "summary": "Saltuklu dönemine ait bu tarihi külliye, Tercan''ın en önemli simgesidir. Etkileyici taş işçiliği ve mimarisiyle ziyaretçilerini büyüler.", "place_query": "Mama Hatun Türbesi, Tercan, Erzincan"}, {"title": "Tercan Şelalesi", "summary": "Doğal güzelliği ile ünlü bu şelale, özellikle yaz aylarında serinlemek ve piknik yapmak için idealdir. Çevresi yeşilliklerle kaplıdır.", "place_query": "Tercan Şelalesi, Tercan, Erzincan"}, {"title": "Tercan Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale, bölgeye hakim manzarasıyla dikkat çeker. Geçmişe yolculuk yapmak isteyenler için güzel bir duraktır.", "place_query": "Tercan Kalesi, Tercan, Erzincan"}, {"title": "Pekeriç Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü bu yayla, doğa yürüyüşleri ve kampçılık için popüler bir noktadır. Özellikle yaz aylarında canlanır.", "place_query": "Pekeriç Yaylası, Tercan, Erzincan"}, {"title": "Tercan Ulu Camii", "summary": "Tarihi bir Osmanlı camisi olan bu yapı, mimari detayları ve huzur veren atmosferiyle ziyaretçilerini ağırlar. Şehir merkezinde kolayca bulunabilir.", "place_query": "Tercan Ulu Camii, Tercan, Erzincan"}, {"title": "Karasu Nehri (Tercan Kesimi)", "summary": "Doğal güzellikler eşliğinde akışı izlenebilen nehir, özellikle balık tutma ve piknik alanlarıyla bilinir. Huzurlu bir doğa kaçamağı sunar.", "place_query": "Karasu Nehri, Tercan, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bb30f227-7838-4144-afd0-32c4953b6857'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Üzümlü Kalesi", "summary": "Tarihi bir kale olan Üzümlü Kalesi, bölgenin stratejik noktalarından biridir ve ziyaretçilere eşsiz bir manzara sunar. Kalenin çevresindeki doğal yapı ve tarihi doku, fotoğrafçılar ve tarih meraklıları için idealdir.", "place_query": "Üzümlü Kalesi, Üzümlü, Erzincan"}, {"title": "Altıntepe Kalesi", "summary": "Urartu dönemine ait önemli bir arkeolojik alan olan Altıntepe Kalesi, bölgenin en eski yerleşimlerinden biridir. Kazılarda ortaya çıkarılan tapınak ve saray kalıntıları, tarih severler için büyüleyici bir deneyim sunar.", "place_query": "Altıntepe Kalesi, Üzümlü, Erzincan"}, {"title": "Karasu Nehri", "summary": "Erzincan''ın en önemli akarsularından biri olan Karasu Nehri, doğa yürüyüşleri ve piknik alanlarıyla ünlüdür. Nehir kenarında huzurlu bir gün geçirebilir, bölgenin serin sularında balık tutabilirsiniz.", "place_query": "Karasu Nehri, Üzümlü, Erzincan"}, {"title": "Üzümlü Şelalesi", "summary": "Doğal güzelliğiyle göz kamaştıran Üzümlü Şelalesi, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir duraktır. Çevresindeki yemyeşil alanlar, piknik ve kamp için idealdir.", "place_query": "Üzümlü Şelalesi, Üzümlü, Erzincan"}, {"title": "Eksik Köyü Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikit yapılarıyla dikkat çeken Eksik Köyü Mağarası, macera arayanlar için keşfedilmeyi bekleyen bir yeraltı dünyasıdır. Mağara içi yürüyüşleri, doğa severlere eşsiz anlar yaşatır.", "place_query": "Eksik Köyü Mağarası, Üzümlü, Erzincan"}, {"title": "Üzümlü Merkez Camii", "summary": "Osmanlı dönemi mimarisinin izlerini taşıyan Üzümlü Merkez Camii, hem ibadet hem de tarihi bir yapı olarak ziyaret edilebilir. Caminin sade ve etkileyici mimarisi, bölgenin kültürel dokusunu yansıtır.", "place_query": "Üzümlü Merkez Camii, Üzümlü, Erzincan"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '16cfad7b-5b20-4ee3-9046-38a5901121ed'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aşkale Şehir Merkezi ve Tarihi Evler", "summary": "İlçe merkezinde yer alan tarihi taş ve ahşap evler, geçmişin izlerini taşıyan sivil mimari örnekleriyle ziyaretçilere nostaljik bir atmosfer sunar.", "place_query": "Aşkale Merkez, Erzurum"}, {"title": "Çiftlik Köyü ve Peri Bacaları", "summary": "Aşkale''nin Çiftlik köyünde bulunan peri bacaları, volkanik tüflerin aşınmasıyla oluşan ilginç kaya oluşumlarıyla doğa fotoğrafçıları ve gezginler için eşsiz bir manzara sunar.", "place_query": "Çiftlik Köyü Peri Bacaları, Aşkale, Erzurum"}, {"title": "Aşkale Kayak Merkezi", "summary": "Kış aylarında hizmet veren bu kayak merkezi, doğal pistleri ve beyaz örtüsüyle bölge halkının ve ziyaretçilerin kış sporları keyfi yaşamasına olanak tanır.", "place_query": "Aşkale Kayak Merkezi, Erzurum"}, {"title": "Kandilli Köyü ve Şelalesi", "summary": "Kandilli köyü yakınlarında yer alan şelale, çevresindeki yeşil alanlar ve serin sularıyla doğa yürüyüşü yapmak ve piknik için ideal bir kaçış noktasıdır.", "place_query": "Kandilli Köyü Şelalesi, Aşkale, Erzurum"}, {"title": "Aşkale Kalesi", "summary": "Tarihi bir savunma yapısı olan Aşkale Kalesi, bölgenin stratejik önemini gözler önüne serer ve kalıntılarıyla tarih meraklılarına hitap eder.", "place_query": "Aşkale Kalesi, Erzurum"}, {"title": "Yaylalar (Örnek: Güzelyayla veya Yaylabaşı)", "summary": "Aşkale çevresindeki yaylalar, temiz havası, geniş otlakları ve geleneksel yayla kültürüyle doğayla iç içe bir gün geçirmek isteyenler için huzurlu bir ortam sağlar.", "place_query": "Aşkale yaylaları, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cd0bfd69-bd82-4795-8c14-78db2a0fbefe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çifte Minareli Medrese", "summary": "Erzurum''un simgesi haline gelmiş bu Selçuklu eseri, taş işçiliğinin en güzel örneklerinden biridir. İki minaresi ve süslü taç kapısıyla ziyaretçileri büyüler.", "place_query": "Çifte Minareli Medrese, Erzurum Merkez, Erzurum"}, {"title": "Erzurum Kalesi", "summary": "Tarihi Urartulara kadar uzanan kale, şehre hakim bir tepede yer alır. İçinde gezilebilen burçlar ve surlar, Erzurum''un panoramik manzarasını sunar.", "place_query": "Erzurum Kalesi, Erzurum Merkez, Erzurum"}, {"title": "Palandöken Kayak Merkezi", "summary": "Türkiye''nin en önemli kayak merkezlerinden biri olan Palandöken, uzun pistleri ve kaliteli karıyla kış sporları tutkunlarının uğrak noktasıdır. Aziziye ilçesi sınırları içinde yer alır.", "place_query": "Palandöken Kayak Merkezi, Aziziye, Erzurum"}, {"title": "Üç Kümbetler", "summary": "Erzurum''un sembol yapılarından olan bu kümbetler, Selçuklu dönemine ait anıt mezarlardır. Özellikle Emir Saltuk Kümbeti, mimarisiyle dikkat çeker.", "place_query": "Üç Kümbetler, Erzurum Merkez, Erzurum"}, {"title": "Abdurrahman Gazi Türbesi", "summary": "Erzurum''un manevi değerlerinden biri olan bu türbe, şehir merkezine yakın bir tepede yer alır. Ziyaretçiler hem manevi bir atmosfer yaşar hem de şehir manzarasını izler.", "place_query": "Abdurrahman Gazi Türbesi, Erzurum Merkez, Erzurum"}, {"title": "Aziziye Tabyaları", "summary": "93 Harbi olarak bilinen Osmanlı-Rus Savaşı''nda büyük kahramanlık destanının yazıldığı tabyalardır. Tarihi önemi ve milli mücadeledeki yeriyle mutlaka görülmesi gereken bir noktadır.", "place_query": "Aziziye Tabyaları, Aziziye, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '51b95d27-c522-45a1-89da-9eee2f0a38f9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çat Mesire Alanı", "summary": "Erzurum''un Çat ilçesinde yer alan bu mesire alanı, özellikle yaz aylarında piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için popüler bir duraktır. Bol oksijenli havası ve yeşil alanlarıyla aileler için ideal bir kaçış noktasıdır.", "place_query": "Çat Mesire Alanı, Çat, Erzurum"}, {"title": "Palandöken Kayak Merkezi (Çat sınırına yakın)", "summary": "Her ne kadar merkez ilçeye bağlı olsa da, Çat ilçesine de oldukça yakın olan Palandöken, Türkiye''nin en önemli kayak merkezlerinden biridir. Uzun pistleri ve kış turizmi ile bölgeye gelen ziyaretçilerin ilk duraklarındandır.", "place_query": "Palandöken Kayak Merkezi, Erzurum"}, {"title": "Çat Yaylaları (Örnek: Gölyurt Yaylası)", "summary": "Çat ilçesi, yemyeşil yaylalarıyla ünlüdür. Gölyurt Yaylası gibi noktalar, doğa yürüyüşleri, kamp ve yayla turizmi için harika fırsatlar sunar. Yaz aylarında serinlemek ve eşsiz manzaraları izlemek için idealdir.", "place_query": "Gölyurt Yaylası, Çat, Erzurum"}, {"title": "Çat Kaplıcaları", "summary": "Şifalı termal sularıyla bilinen Çat Kaplıcaları, romatizma ve cilt hastalıklarına iyi geldiğine inanılan doğal bir şifa kaynağıdır. Hem yerli halk hem de çevre illerden gelen ziyaretçiler tarafından tercih edilmektedir.", "place_query": "Çat Kaplıcaları, Çat, Erzurum"}, {"title": "Tuzla Gölü (Çat sınırları içinde kalan kısım)", "summary": "Erzurum''un önemli sulak alanlarından biri olan Tuzla Gölü, kuş gözlemciliği ve doğa fotoğrafçılığı için eşsiz bir ortam sunar. Göl çevresindeki bozkır manzarası, sakin bir gün geçirmek isteyenler için idealdir.", "place_query": "Tuzla Gölü, Çat, Erzurum"}, {"title": "Çat Merkez Cami ve Tarihi Evler", "summary": "Çat ilçe merkezinde bulunan tarihi cami ve geleneksel Erzurum evleri, bölgenin kültürel dokusunu yansıtır. Kısa bir şehir turu yaparak yöresel mimariyi yakından görebilir ve tarihi atmosferi hissedebilirsiniz.", "place_query": "Çat Merkez Cami, Çat, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c766f4e3-ce3f-48ed-a6dc-a918b8372a1f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hınıs Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale, Hınıs''ın simgesi konumundadır ve bölgenin stratejik önemini gözler önüne serer. Kalenin surları ve kalıntıları, ziyaretçilere eşsiz bir manzara ve tarihi bir atmosfer sunar.", "place_query": "Hınıs Kalesi, Hınıs, Erzurum"}, {"title": "Hınıs Ulu Camii", "summary": "Selçuklu dönemine ait olduğu düşünülen bu tarihi cami, mimari detayları ve taş işçiliğiyle dikkat çekmektedir. Hınıs''ın en önemli dini yapılarından biri olarak ziyaretçilerin ilgisini çeker.", "place_query": "Hınıs Ulu Camii, Hınıs, Erzurum"}, {"title": "Karaçoban Köprüsü", "summary": "Hınıs ilçe merkezine yakın konumda bulunan bu tarihi köprü, bölgenin geçmiş dönemlerdeki ulaşım ağına ışık tutar. Doğal güzellikler içindeki köprü, fotoğrafçılar için güzel bir durak noktasıdır.", "place_query": "Karaçoban Köprüsü, Hınıs, Erzurum"}, {"title": "Hınıs Şelalesi", "summary": "İlçe merkezine kısa bir mesafede yer alan bu şelale, özellikle bahar ve yaz aylarında akan sularıyla serinletici bir doğa kaçamağı sunar. Çevresindeki yeşil alanlar piknik ve dinlenme için idealdir.", "place_query": "Hınıs Şelalesi, Hınıs, Erzurum"}, {"title": "Hınıs Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, yöreye ait arkeolojik buluntular, etnografik eserler ve el sanatlarını sergilemektedir. Hınıs''ın kültürel geçmişini keşfetmek isteyenler için önemli bir duraktır.", "place_query": "Hınıs Müzesi, Hınıs, Erzurum"}, {"title": "Parmakpınarı Mesire Alanı", "summary": "Hınıs''a bağlı bir bölgede bulunan bu mesire alanı, doğal güzellikleri ve temiz havasıyla aileler için popüler bir piknik ve dinlenme noktasıdır. Yürüyüş yapmak ve doğayla iç içe vakit geçirmek için uygundur.", "place_query": "Parmakpınarı Mesire Alanı, Hınıs, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '97e4ef6b-db3f-45c1-96a9-f6761a95c1b9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Horasan Kalesi", "summary": "Tarihi bir kaledir ve bölgenin en önemli tarihi yapılarından biridir. Horasan''ın merkezinde yer alır ve ziyaretçilere tarihi bir atmosfer sunar.", "place_query": "Horasan Kalesi, Horasan, Erzurum"}, {"title": "Çermik Kaplıcaları", "summary": "Doğal termal suları ile ünlü olan bu kaplıcalar, şifalı suları ve doğal güzellikleriyle ziyaretçilerine huzurlu bir deneyim sunar.", "place_query": "Çermik Kaplıcaları, Horasan, Erzurum"}, {"title": "Aras Nehri Kenarı", "summary": "Doğal bir güzellik olan Aras Nehri kıyısı, piknik yapmak ve doğa yürüyüşleri için idealdir. Kuş gözlemciliği için de popüler bir noktadır.", "place_query": "Aras Nehri, Horasan, Erzurum"}, {"title": "Horasan Müzesi", "summary": "Bölgenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bir müzedir. Arkeolojik ve etnografik koleksiyonları ile ziyaretçilere zengin bir geçmiş sunar.", "place_query": "Horasan Müzesi, Horasan, Erzurum"}, {"title": "Kırkgöz Köprüsü", "summary": "Tarihi bir taş köprüdür ve Horasan''ın simgelerinden biridir. Mimari yapısı ve tarihi dokusu ile fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Kırkgöz Köprüsü, Horasan, Erzurum"}, {"title": "Horasan Yaylaları", "summary": "Yeşil doğası ve temiz havası ile ünlü olan yaylalar, doğa yürüyüşleri ve kampçılık için popüler bir destinasyondur. Özellikle yaz aylarında serinlemek için idealdir.", "place_query": "Horasan Yaylaları, Horasan, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8adbe96c-e14b-48a0-89df-7a4cd2f93586'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İspir Kalesi", "summary": "İlçe merkezinde, Çoruh Nehri kıyısında yükselen tarihi bir kaledir. Urartu dönemine kadar uzandığı tahmin edilen kale, bölgeye hakim manzarası ve tarihi dokusuyla ziyaretçilerini etkiler.", "place_query": "İspir Kalesi, İspir, Erzurum"}, {"title": "Çoruh Nehri", "summary": "Türkiye''nin en hızlı akan nehirlerinden biri olan Çoruh, İspir sınırları içinde muhteşem bir vadi manzarası sunar. Özellikle rafting ve doğa sporları için popüler bir destinasyondur.", "place_query": "Çoruh Nehri, İspir, Erzurum"}, {"title": "İspir Evleri", "summary": "Yöresel mimarinin en güzel örneklerinden olan tarihi İspir Evleri, taş ve ahşap işçiliğiyle dikkat çeker. Dar sokaklarda yürürken geçmişe yolculuk yaparsınız.", "place_query": "İspir Evleri, İspir, Erzurum"}, {"title": "Kırık Köprü (Taş Köprü)", "summary": "Çoruh Nehri üzerinde yer alan tarihi bir Osmanlı dönemi köprüsüdür. Mimarisi ve nehir manzarasıyla fotoğrafçılar için vazgeçilmez bir duraktır.", "place_query": "Kırık Köprü, İspir, Erzurum"}, {"title": "Yedigöller Yaylası", "summary": "İspir''e bağlı yüksek rakımlı bir yayla olup, doğal gölleri ve zengin bitki örtüsüyle ünlüdür. Doğa yürüyüşü ve kamp için ideal bir noktadır.", "place_query": "Yedigöller Yaylası, İspir, Erzurum"}, {"title": "Mescidli Köyü (Tarihi Camiler)", "summary": "İspir''deki tarihi camilerin en bilinenlerinden biri olan Mescidli Köyü Camii, ahşap işçiliği ve süslemeleriyle dikkat çeker. Köyün kendisi de doğal güzellikler sunar.", "place_query": "Mescidli Köyü Camii, İspir, Erzurum"}, {"title": "İspir Çamlığı Mesire Alanı", "summary": "İlçe merkezine yakın, çam ağaçlarıyla kaplı bir mesire alanıdır. Piknik, yürüyüş ve temiz hava almak için aileler tarafından sıkça tercih edilir.", "place_query": "İspir Çamlığı, İspir, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '243ae0d6-0858-480f-b8f3-283e4f1e3d7b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köse Dağı", "summary": "Karayazı ilçe merkezine yakın, yüksek rakımlı bu dağ, doğal güzelliği ve geniş yaylalarıyla ünlüdür. Özellikle yaz aylarında yeşilin her tonunu görebileceğiniz, doğa yürüyüşleri ve piknik için ideal bir noktadır.", "place_query": "Köse Dağı, Karayazı, Erzurum"}, {"title": "Karayazı Yaylaları", "summary": "İlçe çevresinde yer alan geniş ve bakir yaylalar, doğa tutkunları için huzurlu bir kaçış noktasıdır. Yöresel hayvancılık kültürünü yakından gözlemleyebilir ve temiz havanın tadını çıkarabilirsiniz.", "place_query": "Karayazı Yaylaları, Erzurum"}, {"title": "Karayazı Merkez Camii", "summary": "İlçenin tarihi dokusunu yansıtan bu cami, mimarisi ve manevi atmosferiyle ziyaretçilerini ağırlar. Bölgenin dini ve kültürel geçmişine dair önemli bir duraktır.", "place_query": "Karayazı Merkez Camii, Erzurum"}, {"title": "Karayazı Şelalesi", "summary": "İlçe sınırları içinde yer alan bu şelale, özellikle bahar aylarında eriyen karlarla birlikte coşkun akan sularıyla görsel bir şölen sunar. Çevresi doğal yürüyüş ve fotoğrafçılık için elverişlidir.", "place_query": "Karayazı Şelalesi, Erzurum"}, {"title": "Karayazı Göleti", "summary": "Yöre halkının mesire alanı olarak kullandığı bu gölet, sakin atmosferi ve çevresindeki yeşil alanlarla piknik ve dinlenme imkanı sunar. Özellikle yaz akşamlarında serinlemek için idealdir.", "place_query": "Karayazı Göleti, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '72346533-943a-4374-8ed0-cb3ab9c8bfba'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köprüköy Şehitliği ve Anıtı", "summary": "Bölgenin önemli tarihi ve manevi değerlerinden biri olan şehitlik, özellikle Kurtuluş Savaşı döneminde bu topraklarda can veren askerler anısına yapılmıştır. Ziyaretçiler burada hem tarihi bir atmosfer solur hem de saygı duruşunda bulunur.", "place_query": "Köprüköy Şehitliği, Köprüköy, Erzurum"}, {"title": "Köprüköy Köprüsü (Tarihi Taş Köprü)", "summary": "İlçeye adını veren tarihi taş köprü, bölgenin en bilinen simgelerinden biridir. Osmanlı döneminden kalan bu köprü, Aras Nehri üzerinde yer almakta olup mimarisi ve konumuyla fotoğrafçılar için de ilgi çekicidir.", "place_query": "Tarihi Taş Köprü, Köprüköy, Erzurum"}, {"title": "Köprüköy Merkez Camii", "summary": "İlçe merkezinde bulunan bu cami, hem ibadet hem de mimari açıdan dikkat çeker. Cami, yöre halkının yoğun olarak uğradığı ve çevresinde küçük çarşılarıyla da bilinen bir noktadır.", "place_query": "Köprüköy Merkez Camii, Köprüköy, Erzurum"}, {"title": "Aras Nehri Kenarı", "summary": "Köprüköy sınırları içerisinden geçen Aras Nehri, doğal güzellikleri ve sakin atmosferiyle piknik ve yürüyüş için idealdir. Özellikle bahar ve yaz aylarında nehir kenarında vakit geçirmek bölge halkı için popüler bir etkinliktir.", "place_query": "Aras Nehri, Köprüköy, Erzurum"}, {"title": "Köprüköy Çarşı Merkezi", "summary": "İlçenin günlük yaşamını ve yerel kültürü gözlemlemek isteyenler için ideal bir noktadır. Küçük dükkanları, yöresel ürünleri ve samimi atmosferiyle kısa bir gezi ve alışveriş imkanı sunar.", "place_query": "Köprüköy Çarşısı, Köprüköy, Erzurum"}, {"title": "Köprüköy Yaylaları (Karadağ Yaylası)", "summary": "İlçeye bağlı yaylalar, özellikle yaz aylarında serinlemek ve doğayla iç içe olmak isteyenler için kaçış noktasıdır. Karadağ Yaylası, yeşil doğası ve temiz havasıyla öne çıkar.", "place_query": "Karadağ Yaylası, Köprüköy, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6e1521c6-3449-424c-9d45-b54e5cd89606'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Narman Peribacaları", "summary": "Narman ilçesinin simgesi haline gelmiş, volkanik tüflerden oluşan ve rüzgar ile suyun aşındırması sonucu oluşan peri bacaları, eşsiz manzaraları ve fotoğrafçılık için ideal ortamıyla ziyaretçileri büyüler.", "place_query": "Narman Peribacaları, Narman, Erzurum"}, {"title": "Narman Kalesi", "summary": "Tarihi bir geçmişe sahip olan Narman Kalesi, ilçe merkezine hakim bir tepe üzerinde yer alır ve çevresindeki vadi manzarasıyla tarih ve doğayı bir arada sunar.", "place_query": "Narman Kalesi, Narman, Erzurum"}, {"title": "Kireçli Mağarası", "summary": "Doğal oluşumlu bu mağara, sarkıt ve dikitleriyle dikkat çeker; mağara içindeki serin hava ve ilginç kaya yapıları doğa severler için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Kireçli Mağarası, Narman, Erzurum"}, {"title": "Narman Şelalesi", "summary": "Yeşillikler arasında gizlenmiş bu şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir piknik ve gezinti alanıdır.", "place_query": "Narman Şelalesi, Narman, Erzurum"}, {"title": "Pamuk Dağı (Kırmızı Peribacaları)", "summary": "Narman''a bağlı bu bölge, kırmızımsı renk tonlarındaki peri bacaları ve ilginç kaya formasyonlarıyla ''Kırmızı Peribacaları'' olarak da anılır ve görsel bir şölen sunar.", "place_query": "Pamuk Dağı Peribacaları, Narman, Erzurum"}, {"title": "Narman İlçe Merkezi Tarihi Evler", "summary": "İlçe merkezinde bulunan geleneksel Osmanlı ve Erzurum mimarisini yansıtan tarihi taş evler, dar sokakları ve otantik atmosferiyle kısa bir şehir turu için idealdir.", "place_query": "Narman Tarihi Evler, Narman, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ceba39cf-eda4-49f1-829a-3a4575ed21d3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Oltu Kalesi", "summary": "İlçe merkezinde yüksek bir tepe üzerinde yer alan tarihi kale, Oltu''nun simgesi olup muhteşem bir şehir manzarası sunar. Ziyaretçiler hem tarihi dokuyu hissedebilir hem de çevredeki doğal güzellikleri izleyebilir.", "place_query": "Oltu Kalesi, Oltu, Erzurum"}, {"title": "Oltu Taşı İşleme Atölyeleri", "summary": "Dünyaca ünlü Oltu taşından yapılan takı ve süs eşyalarının üretildiği atölyeler, bölgeye özgü bu değerli taşın işlenişine tanıklık etmek isteyenler için ideal bir duraktır. Burada hediyelik eşya satın alabilir ve taşın hikayesini öğrenebilirsiniz.", "place_query": "Oltu Taşı Atölyeleri, Oltu, Erzurum"}, {"title": "Oltu Çayı Vadisi", "summary": "Şehrin içinden geçen Oltu Çayı''nın oluşturduğu yeşil vadi, doğa yürüyüşleri ve piknik için popüler bir mekandır. Özellikle bahar ve yaz aylarında huzurlu atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Oltu Çayı, Oltu, Erzurum"}, {"title": "Penek (Penek Köyü) Mağaraları", "summary": "Oltu''ya bağlı Penek köyünde bulunan tarihi mağaralar, doğal kaya oluşumları ve geçmişte barınak olarak kullanılmış yapılarıyla dikkat çeker. Macera arayanlar için keşfedilmeyi bekleyen gizemli bir noktadır.", "place_query": "Penek Mağaraları, Oltu, Erzurum"}, {"title": "Ayazma (Kutsal Su) ve Şelalesi", "summary": "Oltu ilçe merkezine yakın konumda bulunan bu doğal kaynak ve şelale, soğuk ve berrak sularıyla ünlüdür. Çevresi mesire alanı olarak düzenlenmiş olup yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Ayazma Şelalesi, Oltu, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f7ba3c9-9e3c-4569-95ec-1131e4b7d8f1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Olur Kalesi", "summary": "Tarihi bir kalıntı olan Olur Kalesi, ilçenin en önemli tarihi yapılarından biridir ve bölgenin geçmişine ışık tutar.", "place_query": "Olur Kalesi, Olur, Erzurum"}, {"title": "Olur Yaylaları (Mesela: Çamlıyamaç Yaylası)", "summary": "Olur ve çevresindeki yaylalar, yemyeşil doğası ve serin havasıyla doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Olur Yaylaları, Olur, Erzurum"}, {"title": "Süngütaşı Mağarası", "summary": "Bölgedeki doğal oluşumlardan biri olan mağara, keşfedilmeyi bekleyen gizemli bir doğa harikasıdır.", "place_query": "Süngütaşı Mağarası, Olur, Erzurum"}, {"title": "Olur Merkez Camii ve Tarihi Yapılar", "summary": "İlçe merkezindeki tarihi cami ve çevresindeki yapılar, yöresel mimariyi yansıtan önemli kültürel duraklardır.", "place_query": "Olur Merkez Camii, Olur, Erzurum"}, {"title": "Oltu Çayı Kenarı", "summary": "Oltu Çayı''nın ilçeden geçen kısmı, piknik ve dinlenme alanlarıyla sakin bir gün geçirmek için tercih edilir.", "place_query": "Oltu Çayı, Olur, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e2d9c1be-81bd-410e-8e4d-f399e9bc7a14'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Palandöken Kayak Merkezi", "summary": "Türkiye''nin en önemli kış turizmi merkezlerinden biri olan Palandöken, uzun kayak pistleri ve kaliteli kar yapısıyla yerli ve yabancı sporcuların gözde mekanıdır. Kış aylarında kayak ve snowboard yapmak, yazın ise doğa yürüyüşleri ve dağ bisikleti için idealdir.", "place_query": "Palandöken Kayak Merkezi, Palandöken, Erzurum"}, {"title": "Erzurum Kalesi", "summary": "Tarihi Urartu dönemine kadar uzanan ve Selçuklu ile Osmanlı izlerini taşıyan Erzurum Kalesi, şehir merkezine hakim bir tepede yer alır. İçindeki saat kulesi ve surlar, ziyaretçilere hem tarihi bir yolculuk hem de panoramik şehir manzarası sunar.", "place_query": "Erzurum Kalesi, Erzurum Merkez"}, {"title": "Çifte Minareli Medrese", "summary": "Selçuklu döneminin en görkemli yapılarından biri olan Çifte Minareli Medrese, taş işçiliğinin zarif örneklerini sergiler. Günümüzde müze olarak hizmet veren medrese, tarihi atmosferi ve süslemeleriyle fotoğraf tutkunları için vazgeçilmez bir duraktır.", "place_query": "Çifte Minareli Medrese, Erzurum Merkez"}, {"title": "Tortum Şelalesi", "summary": "Erzurum''un Uzundere ilçesi sınırlarında bulunan Tortum Şelalesi, 48 metre yüksekliğiyle Türkiye''nin en büyük şelalelerinden biridir. Çevresindeki piknik alanları ve doğal havuzlarıyla yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için ideal bir noktadır.", "place_query": "Tortum Şelalesi, Uzundere, Erzurum"}, {"title": "Abdurrahman Gazi Türbesi", "summary": "Erzurum''un manevi simgelerinden biri olan Abdurrahman Gazi Türbesi, şehre hakim bir tepede yer alır. Ziyaretçiler, buradan Erzurum Ovası''nın ve Palandöken Dağları''nın nefes kesen manzarasını izleyebilir, aynı zamanda tarihi bir atmosferde huzur bulabilir.", "place_query": "Abdurrahman Gazi Türbesi, Erzurum Merkez"}, {"title": "Üç Kümbetler", "summary": "Erzurum''un simge yapılarından olan Üç Kümbetler, Selçuklu dönemine ait üç adet türbeden oluşur. Anıtsal mimarileri ve geometrik süslemeleriyle dikkat çeken bu yapılar, bölgenin Orta Çağ''daki mezar geleneğini yansıtır.", "place_query": "Üç Kümbetler, Erzurum Merkez"}, {"title": "Erzurum Kongre Binası (Müze)", "summary": "Milli Mücadele döneminde 1919''da Erzurum Kongresi''ne ev sahipliği yapan bu tarihi bina, günümüzde müze olarak hizmet vermektedir. Kurtuluş Savaşı''nın önemli kararlarının alındığı bu yapı, tarih meraklıları için duygusal ve öğretici bir duraktır.", "place_query": "Erzurum Kongre Binası Müzesi, Erzurum Merkez"}, {"title": "Aydınpınar (Köşk) Mesire Alanı", "summary": "Palandöken ilçesi sınırlarındaki bu mesire alanı, yeşil doğası ve piknik olanaklarıyla şehir merkezine yakın bir kaçış noktasıdır. Özellikle yaz aylarında aileler tarafından tercih edilen alan, temiz havası ve doğal güzellikleriyle huzur verir.", "place_query": "Aydınpınar Mesire Alanı, Palandöken, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7ceec4c2-128b-4b5b-a92f-4e943b6767de'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pazaryolu Merkez Camii", "summary": "İlçenin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve bölge halkı için önemli bir ibadet ve buluşma noktasıdır.", "place_query": "Pazaryolu Merkez Camii, Pazaryolu, Erzurum"}, {"title": "Çoruh Nehri", "summary": "Pazaryolu sınırları içinden geçen Çoruh Nehri, doğal güzelliği ve rafting gibi su sporlarına uygun yapısıyla ziyaretçilere eşsiz manzaralar ve aktivite imkanı sunar.", "place_query": "Çoruh Nehri, Pazaryolu, Erzurum"}, {"title": "Pazaryolu Yaylaları (Örnek: Kırkgöz Yaylası)", "summary": "İlçenin yüksek kesimlerinde yer alan yaylalar, yemyeşil doğası, temiz havası ve geleneksel yayla kültürünü deneyimlemek isteyenler için ideal kaçış noktalarıdır.", "place_query": "Kırkgöz Yaylası, Pazaryolu, Erzurum"}, {"title": "Pazaryolu Kalesi", "summary": "İlçe merkezine yakın bir tepe üzerinde bulunan bu tarihi kale kalıntıları, bölgenin savunma tarihine ışık tutar ve çevreye hakim bir seyir terası sunar.", "place_query": "Pazaryolu Kalesi, Pazaryolu, Erzurum"}, {"title": "Süngütaşı Mağarası", "summary": "Pazaryolu sınırlarındaki bu doğal mağara, sarkıt ve dikit oluşumlarıyla dikkat çeker ve doğa yürüyüşü ile mağara keşfi yapmak isteyenler için popüler bir duraktır.", "place_query": "Süngütaşı Mağarası, Pazaryolu, Erzurum"}, {"title": "Pazaryolu Köprüleri (Tarihi Taş Köprüler)", "summary": "İlçe çevresindeki dereler üzerinde yer alan Osmanlı dönemi taş köprüler, mimari zarafetleri ve tarihi dokularıyla fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Tarihi taş köprüler, Pazaryolu, Erzurum"}, {"title": "Pazaryolu Mesire Alanı", "summary": "İlçe merkezine yakın bu mesire alanı, piknik yapmak, doğada vakit geçirmek ve ailece keyifli bir gün yaşamak için tercih edilen huzurlu bir noktadır.", "place_query": "Pazaryolu Mesire Alanı, Pazaryolu, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '285fd290-7764-41b5-b365-d062027e51e5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Narman Peri Bacaları", "summary": "Doğal kaya oluşumları ve peri bacaları ile ünlü bu alan, eşsiz manzaralar sunar. Fotoğrafçılar ve doğa yürüyüşçüleri için ideal bir noktadır.", "place_query": "Narman Peri Bacaları, Narman, Erzurum"}, {"title": "Şenkaya Kayak Merkezi", "summary": "Kış turizmi için popüler bir merkezdir. Kayak pistleri ve doğal kar örtüsüyle kış sporları tutkunlarını cezbeder.", "place_query": "Şenkaya Kayak Merkezi, Şenkaya, Erzurum"}, {"title": "Oltu Taşı İşleme Atölyeleri", "summary": "Bölgeye özgü Oltu taşından yapılan takı ve süs eşyalarının işlendiği atölyeler, hediyelik eşya almak için ziyaret edilebilir.", "place_query": "Oltu Taşı İşleme Atölyeleri, Şenkaya, Erzurum"}, {"title": "Şenkaya Kalesi", "summary": "Tarihi bir kale olup, bölgenin geçmişine ışık tutar. Kaleye çıkarak çevredeki manzarayı izlemek mümkündür.", "place_query": "Şenkaya Kalesi, Şenkaya, Erzurum"}, {"title": "Göksu Deresi", "summary": "Doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için tercih edilen bir alandır. Yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Göksu Deresi, Şenkaya, Erzurum"}, {"title": "Çatak Göleti", "summary": "Sakin bir doğa kaçamağı sunan gölet, balık tutma ve kamp yapma imkanı sağlar. Kuş gözlemi için de uygundur.", "place_query": "Çatak Göleti, Şenkaya, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f5423266-31bd-4b8b-8c81-249cc794706d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tekman Kalesi", "summary": "İlçe merkezine yakın bir tepede yer alan tarihi bir kaledir. Bölgenin savunma yapılarından biri olarak bilinir ve çevresindeki doğal manzara ziyaretçilere keyifli bir seyir imkanı sunar.", "place_query": "Tekman Kalesi, Tekman, Erzurum"}, {"title": "Tekman Yaylaları (Örneğin: Kırık Yaylası)", "summary": "Erzurum''un serin ve yeşil yaylaları arasında yer alan Tekman yaylaları, doğal güzellikleri ve temiz havasıyla özellikle yaz aylarında doğa yürüyüşü ve kamp için idealdir.", "place_query": "Tekman Yaylaları, Tekman, Erzurum"}, {"title": "Tekman Göleti", "summary": "İlçe sınırları içinde bulunan yapay gölet, piknik ve olta balıkçılığı için popüler bir duraktır. Çevresi ağaçlık alanlarla kaplı olup sakin bir doğa kaçamağı sunar.", "place_query": "Tekman Göleti, Tekman, Erzurum"}, {"title": "Hınıs Çayı Vadisi (Tekman Bölümü)", "summary": "Tekman''dan geçen Hınıs Çayı''nın oluşturduğu vadi, ilginç kaya oluşumları ve yeşil doğasıyla dikkat çeker. Doğa fotoğrafçıları ve yürüyüşçüler için güzel bir rotadır.", "place_query": "Hınıs Çayı, Tekman, Erzurum"}, {"title": "Tekman Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde bulunan tarihi cami ve Osmanlı dönemine ait çeşmeler, Tekman''ın kültürel mirasını yansıtan önemli yapılardır. Kısa bir şehir turu için idealdir.", "place_query": "Tekman Merkez Camii, Tekman, Erzurum"}, {"title": "Başköy Mağarası", "summary": "Tekman''a bağlı Başköy yakınlarında bulunan bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Keşfedilmeyi bekleyen doğal bir oluşumdur ve macera arayanlar için uygundur.", "place_query": "Başköy Mağarası, Tekman, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0a802f96-c7ac-4789-86b0-2359edf4f613'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tortum Şelalesi", "summary": "Türkiye''nin en büyük ve en yüksek şelalelerinden biri olan Tortum Şelalesi, 48 metre yükseklikten dökülen görkemli suyuyla büyüleyici bir doğa harikasıdır. Özellikle ilkbahar ve yaz aylarında suyun debisinin artmasıyla ortaya çıkan muhteşem manzara, ziyaretçilere unutulmaz bir deneyim sunar.", "place_query": "Tortum Şelalesi, Tortum, Erzurum"}, {"title": "Tortum Gölü", "summary": "Heyelan sonucu oluşan bu doğal set gölü, çevresindeki yemyeşil doğası ve sakin atmosferiyle huzurlu bir kaçış noktasıdır. Tortum Şelalesi''nin de kaynağı olan gölde tekne turları yapabilir ve eşsiz fotoğraflar çekebilirsiniz.", "place_query": "Tortum Gölü, Tortum, Erzurum"}, {"title": "Uzundere Tortum Şelalesi Tabiat Parkı", "summary": "Tortum Şelalesi''ni de içine alan bu tabiat parkı, piknik alanları, yürüyüş parkurları ve seyir teraslarıyla doğayla iç içe vakit geçirmek için idealdir. Şelalenin ihtişamını en yakından görebileceğiniz noktalardan biridir.", "place_query": "Uzundere Tortum Şelalesi Tabiat Parkı, Erzurum"}, {"title": "Tortum Kalesi", "summary": "Tarihi bir geçmişe sahip olan Tortum Kalesi, bölgeye hakim bir tepe üzerinde yer alır ve çevrenin panoramik manzarasını sunar. Urartu dönemine kadar uzanan tarihiyle, bölgenin zengin kültürel mirasını keşfetmek isteyenler için önemli bir duraktır.", "place_query": "Tortum Kalesi, Tortum, Erzurum"}, {"title": "Tortum Çayı", "summary": "Tortum Gölü''nden doğan ve şelaleyi oluşturduktan sonra yoluna devam eden bu akarsu, çevresindeki doğal güzelliklerle birlikte keyifli bir gezi rotası sunar. Özellikle kanyonda yürüyüş yapmak ve serin sularında zaman geçirmek mümkündür.", "place_query": "Tortum Çayı, Tortum, Erzurum"}, {"title": "Tortum İlçe Merkezi ve Tarihi Evler", "summary": "Tortum''un şirin ilçe merkezinde, geleneksel Erzurum mimarisini yansıtan tarihi evler ve sokaklar arasında keyifli bir yürüyüş yapabilirsiniz. Yöresel lezzetleri tatmak ve bölgenin günlük yaşamına tanıklık etmek için ideal bir noktadır.", "place_query": "Tortum Merkez, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7f7162eb-fbe6-48cb-96d7-5b72b1730f2b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tortum Şelalesi", "summary": "Türkiye''nin en büyük şelalelerinden biri olan Tortum Şelalesi, 48 metre yüksekten dökülen suları ve çevresindeki yemyeşil doğasıyla büyüleyici bir manzara sunar. Özellikle ilkbahar ve yaz aylarında suyun debisinin arttığı dönemlerde ziyaretçilerine görsel bir şölen yaşatır.", "place_query": "Tortum Şelalesi, Uzundere, Erzurum"}, {"title": "Uzundere Yedigöller", "summary": "Birbirine bağlı yedi küçük gölden oluşan bu doğal harika, yemyeşil ormanlar ve dağlarla çevrilidir. Doğa yürüyüşü, kamp ve fotoğrafçılık için ideal olan bu alan, huzur dolu atmosferiyle ziyaretçilerini kendine hayran bırakır.", "place_query": "Yedigöller, Uzundere, Erzurum"}, {"title": "Öşvank Manastırı", "summary": "10. yüzyıldan kalma bu tarihi Gürcü manastırı, etkileyici taş işçiliği ve fresk kalıntılarıyla dikkat çeker. Uzundere''nin en önemli kültürel miraslarından biri olan yapı, tarih ve mimari meraklıları için eşsiz bir duraktır.", "place_query": "Öşvank Manastırı, Uzundere, Erzurum"}, {"title": "Tortum Gölü", "summary": "Heyelan sonucu oluşan bu doğal set gölü, çevresindeki sarp kayalıklar ve zümrüt yeşili suyuyla kartpostallık bir güzelliğe sahiptir. Göl çevresinde yürüyüş yapabilir, piknik alanlarında dinlenebilirsiniz.", "place_query": "Tortum Gölü, Uzundere, Erzurum"}, {"title": "Uzundere Kalesi", "summary": "Tarihi bir Orta Çağ kalesi olan Uzundere Kalesi, ilçeye hakim bir tepe üzerinde konumlanmıştır. Kaleye tırmanarak hem bölgenin tarihine tanıklık edebilir hem de muhteşem bir vadi manzarası izleyebilirsiniz.", "place_query": "Uzundere Kalesi, Uzundere, Erzurum"}, {"title": "Sapaca Şelalesi", "summary": "Daha az bilinen ancak keşfedilmeyi bekleyen bu şelale, doğal havuzları ve sessiz ortamıyla doğa severler için saklı bir cennettir. Şelalenin serin sularında yüzebilir veya çevresinde kamp kurabilirsiniz.", "place_query": "Sapaca Şelalesi, Uzundere, Erzurum"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e12e5e4c-6b1e-4940-b83d-fa226a894db2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çifte Minareli Medrese", "summary": "Selçuklu döneminin en görkemli eserlerinden biri olan bu medrese, taş işçiliği ve çini süslemeleriyle büyüleyici bir atmosfere sahiptir.", "place_query": "Çifte Minareli Medrese, Yakutiye, Erzurum"}, {"title": "Yakutiye Medresesi", "summary": "İlhanlılar döneminde yapılan bu tarihi medrese, taç kapısı ve geometrik desenleriyle dikkat çeker; günümüzde müze olarak hizmet vermektedir.", "place_query": "Yakutiye Medresesi, Erzurum"}, {"title": "Erzurum Kalesi", "summary": "Tarihi binlerce yıl öncesine dayanan kale, şehir merkezinde yükselerek ziyaretçilere eşsiz bir panorama sunar ve surlarıyla büyüler.", "place_query": "Erzurum Kalesi, Yakutiye, Erzurum"}, {"title": "Üç Kümbetler", "summary": "Selçuklu mezar anıtları olan bu üç kümbet, mimari zarafeti ve tarihi dokusuyla Erzurum''un simge yapıları arasında yer alır.", "place_query": "Üç Kümbetler, Erzurum"}, {"title": "Erzurum Saat Kulesi", "summary": "Tepedeki tarihi saat kulesi, şehri kuşbakışı görmek isteyenler için harika bir seyir noktasıdır ve özellikle gün batımında etkileyicidir.", "place_query": "Erzurum Saat Kulesi, Yakutiye, Erzurum"}, {"title": "Lala Mustafa Paşa Camii", "summary": "Osmanlı dönemi mimarisinin güzel bir örneği olan cami, sade ve huzurlu iç mekanıyla ibadet ve ziyaret için idealdir.", "place_query": "Lala Mustafa Paşa Camii, Yakutiye, Erzurum"}, {"title": "Erzurum Arkeoloji Müzesi", "summary": "Bölgenin zengin tarihini gözler önüne seren müze, Urartu''dan Osmanlı''ya uzanan geniş bir eser koleksiyonuna ev sahipliği yapar.", "place_query": "Erzurum Arkeoloji Müzesi, Yakutiye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '26284fed-3eaa-4bbf-a0e3-055496210ff1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alpu İlçe Merkezi ve Tarihi Çarşı", "summary": "Alpu''nun merkezinde yer alan tarihi çarşı, yöresel ürünler ve samimi atmosferi ile dikkat çeker. Ziyaretçiler, burada geleneksel el sanatlarını ve bölgeye özgü lezzetleri keşfedebilir.", "place_query": "Alpu Merkez, Eskişehir"}, {"title": "Alpu Göleti ve Mesire Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal bir noktadır. Gölet çevresinde yürüyüş yapabilir, piknik alanlarında dinlenebilir ve kuş gözlemi yapabilirsiniz.", "place_query": "Alpu Göleti, Eskişehir"}, {"title": "Bozan Köyü Kaya Mezarları", "summary": "Alpu ilçesine bağlı Bozan Köyü''nde bulunan bu tarihi kaya mezarları, Frig dönemine ait önemli kalıntılardır. Tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Bozan Köyü Kaya Mezarları, Alpu, Eskişehir"}, {"title": "Gökdere Köyü Şelalesi", "summary": "Alpu''nun doğal güzelliklerinden biri olan Gökdere Köyü Şelalesi, özellikle bahar aylarında coşkun akan sularıyla görsel bir şölen sunar. Doğa yürüyüşleri için de uygun bir rotadır.", "place_query": "Gökdere Köyü Şelalesi, Alpu, Eskişehir"}, {"title": "Alpu Halk Eğitim Merkezi ve El Sanatları Atölyeleri", "summary": "Yöresel el sanatlarının yaşatıldığı bu merkezde, seramik, dokuma ve ahşap oyma gibi geleneksel ürünleri yakından görebilirsiniz. Ayrıca atölyelere katılarak deneyim kazanma şansınız da var.", "place_query": "Alpu Halk Eğitim Merkezi, Eskişehir"}, {"title": "Alpu Ovası ve Tarım Alanları", "summary": "Geniş ve verimli Alpu Ovası, bölgenin tarımsal zenginliğini gözler önüne serer. Özellikle buğday ve şeker pancarı tarlaları arasında yapacağınız bir gezinti, kırsal yaşamın tadını çıkarmanızı sağlar.", "place_query": "Alpu Ovası, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ac42a355-5fdc-4527-94cb-4dbe16068561'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beylikova Göleti", "summary": "İlçe merkezine yakın konumda bulunan bu gölet, piknik ve doğa yürüyüşleri için popüler bir mekandır. Sakin atmosferi ve yeşil çevresiyle hafta sonu kaçamakları için idealdir.", "place_query": "Beylikova Göleti, Eskişehir"}, {"title": "Beylikova Merkez Camii", "summary": "İlçenin en büyük ve tarihi camilerinden biri olup, Osmanlı dönemi mimarisini yansıtan özgün detaylarıyla dikkat çeker. Ziyaretçiler hem ibadet hem de tarihi dokuya tanıklık edebilir.", "place_query": "Beylikova Merkez Camii, Eskişehir"}, {"title": "Beylikova Etnografya Müzesi", "summary": "Yöresel kültürü ve geçmiş yaşamı yansıtan eşyaların sergilendiği bu müze, ilçenin tarihine ışık tutar. Küçük ama samimi atmosferiyle ziyaretçilere keyifli bir deneyim sunar.", "place_query": "Beylikova Etnografya Müzesi, Eskişehir"}, {"title": "Seyitgazi Külliyesi (Beylikova yakını)", "summary": "Beylikova''ya yaklaşık 30 km mesafedeki Seyitgazi ilçesinde yer alan bu külliye, Selçuklu ve Osmanlı dönemine ait önemli bir dini ve tarihi yapıdır. Özellikle Seyyid Battal Gazi Türbesi ile ünlüdür.", "place_query": "Seyitgazi Külliyesi, Eskişehir"}, {"title": "Porsuk Çayı Kenarı (Beylikova bölümü)", "summary": "Porsuk Çayı''nın ilçeden geçen kısmı, doğal güzellikleri ve yürüyüş yollarıyla huzurlu bir ortam sunar. Özellikle ilkbahar ve yaz aylarında çevredeki yeşil alanlar piknik için tercih edilir.", "place_query": "Porsuk Çayı Beylikova, Eskişehir"}, {"title": "Beylikova Yaylaları", "summary": "İlçe çevresindeki yaylalar, temiz havası ve doğal manzaralarıyla doğa severler için ideal rotalardır. Kamp ve doğa yürüyüşü yapmak isteyenler tarafından sıkça ziyaret edilir.", "place_query": "Beylikova yaylaları, Eskişehir"}, {"title": "Beylikova Pazarı", "summary": "Haftalık kurulan bu pazar, yöresel ürünler, taze sebze-meyve ve el işi ürünler bulmak için en canlı noktalardan biridir. Yerel halkla kaynaşmak ve alışveriş yapmak için idealdir.", "place_query": "Beylikova pazar yeri, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3b673564-3ba8-4880-8069-b05bd2624393'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sakaryabaşı Mesire Alanı", "summary": "Sakarya Nehri''nin doğduğu kaynaklardan oluşan bu mesire alanı, piknik ve doğa yürüyüşleri için ideal bir yerdir. Berrak suları ve yemyeşil çevresiyle huzurlu bir atmosfer sunar.", "place_query": "Sakaryabaşı Mesire Alanı, Çifteler, Eskişehir"}, {"title": "Çifteler Şefkat Parkı", "summary": "İlçe merkezinde yer alan bu park, geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla aileler için popüler bir dinlenme noktasıdır.", "place_query": "Şefkat Parkı, Çifteler, Eskişehir"}, {"title": "Beyaz Altın Müzesi (Yunus Emre Müzesi)", "summary": "Çifteler''e bağlı Yunus Emre beldesinde bulunan bu müze, bölgenin lületaşı (beyaz altın) kültürünü tanıtır. Heykeller ve işleme örnekleriyle ziyaretçilere ilginç bir deneyim sunar.", "place_query": "Beyaz Altın Müzesi, Yunus Emre, Çifteler, Eskişehir"}, {"title": "Yunus Emre Türbesi ve Külliyesi", "summary": "Büyük Türk şairi Yunus Emre''nin türbesine ev sahipliği yapan bu külliyede, manevi bir atmosfer eşliğinde tarihi yapıları gezebilirsiniz.", "place_query": "Yunus Emre Türbesi, Yunus Emre, Çifteler, Eskişehir"}, {"title": "Çifteler Barajı ve Çevresi", "summary": "Sakarya Nehri üzerinde kurulu bu baraj, kuş gözlemi ve doğa fotoğrafçılığı için ideal bir noktadır. Çevresindeki yeşil alanlar huzurlu bir kaçış sağlar.", "place_query": "Çifteler Barajı, Eskişehir"}, {"title": "Kırka Bor İşletme Müessesesi", "summary": "Dünyanın en büyük bor yataklarına ev sahipliği yapan Kırka beldesinde, bor madeni çıkarma ve işleme sürecini gözlemleyebileceğiniz bir sanayi tesisidir.", "place_query": "Kırka Bor İşletmesi, Çifteler, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f9079f4-7c9c-44d6-bd51-486de4679323'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Midas Antik Kenti (Yazılıkaya)", "summary": "Frigya uygarlığının önemli merkezlerinden olan bu antik kent, kayalara oyulmuş anıtsal cepheleri ve Zeus için yapıldığı düşünülen sunağıyla ünlüdür. Tarih ve doğanın iç içe geçtiği bu alan, bölgenin en etkileyici arkeolojik duraklarındandır.", "place_query": "Midas Antik Kenti Yazılıkaya, Günyüzü, Eskişehir"}, {"title": "Günyüzü Kızılcaören Yeraltı Şehri", "summary": "Tarihi Frig dönemine kadar uzanan bu yeraltı şehri, kayalar oyularak oluşturulmuş odaları, tünelleri ve yaşam alanlarıyla dikkat çeker. Ziyaretçilere gizemli bir keşif ve serin bir atmosfer sunar.", "place_query": "Kızılcaören Yeraltı Şehri, Günyüzü, Eskişehir"}, {"title": "Günyüzü Göleti", "summary": "Çevresi piknik ve dinlenme alanlarıyla donatılmış bu yapay gölet, doğayla baş başa kalmak isteyenler için huzurlu bir ortam sağlar. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için idealdir.", "place_query": "Günyüzü Göleti, Eskişehir"}, {"title": "Günyüzü Kanyonu", "summary": "Eşsiz kaya oluşumları ve yemyeşil bitki örtüsüyle çevrili bu kanyon, doğa yürüyüşü ve fotoğrafçılık için harika bir rotadır. Sessiz ve sakin atmosferiyle ziyaretçilerine görsel bir şölen sunar.", "place_query": "Günyüzü Kanyonu, Eskişehir"}, {"title": "Günyüzü Merkez Camii ve Tarihi Evler", "summary": "Osmanlı dönemi mimarisini yansıtan tarihi cami ve çevresindeki geleneksel Türk evleri, ilçenin kültürel dokusunu gözler önüne serer. Dar sokaklarda yapılacak bir yürüyüş, geçmişe kısa bir yolculuk gibidir.", "place_query": "Günyüzü Merkez Camii, Eskişehir"}, {"title": "Frig Vadisi (Günyüzü Bölümü)", "summary": "Bölgenin en önemli tarihi ve doğal zenginliklerinden biri olan Frig Vadisi''nin Günyüzü sınırları içinde kalan kısmı, kayalara oyulmuş anıtlar ve kaya mezarlarıyla doludur. Tarih öncesi dönemlere tanıklık etmek isteyenler için benzersiz bir açık hava müzesidir.", "place_query": "Frig Vadisi Günyüzü, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ba1d7cfb-e4a0-49b3-ac72-ea764af95583'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Han İlçe Merkezi ve Tarihi Evler", "summary": "Han ilçe merkezinde yer alan geleneksel Osmanlı dönemi sivil mimari örnekleri, ilçenin tarihi dokusunu yansıtır. Özellikle restore edilmiş ahşap ve kerpiç evler, fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Han İlçe Merkezi, Eskişehir"}, {"title": "Çatacık Tabiat Parkı", "summary": "Han ilçesi sınırları içinde bulunan Çatacık Tabiat Parkı, zengin bitki örtüsü ve temiz havasıyla doğa yürüyüşleri ve piknik için idealdir. Bölgedeki endemik türler ve huzurlu atmosfer ziyaretçileri cezbeder.", "place_query": "Çatacık Tabiat Parkı, Han, Eskişehir"}, {"title": "Mihalıççık - Han Yolu Üzerindeki Tarihi Köprüler", "summary": "Han ilçesi çevresinde, özellikle Mihalıççık yolu üzerinde bulunan Osmanlı dönemi taş köprüler, tarihi ve mimari açıdan değer taşır. Bu köprüler, bölgenin geçmişteki ulaşım ağının önemli parçalarıdır.", "place_query": "Han Mihalıççık yolu tarihi köprüler, Eskişehir"}, {"title": "Sündiken Dağları Milli Parkı", "summary": "Han ilçesinin güneyinde yer alan Sündiken Dağları, milli park statüsünde olup zengin flora ve faunasıyla dikkat çeker. Kamp, trekking ve doğa fotoğrafçılığı için popüler bir destinasyondur.", "place_query": "Sündiken Dağları Milli Parkı, Han, Eskişehir"}, {"title": "Han İlçesi Yaylaları (Özellikle Ağapınar Yaylası)", "summary": "Han ilçesine bağlı yaylalar, özellikle Ağapınar Yaylası, serin havası ve doğal güzellikleriyle yaz aylarında kaçış noktasıdır. Yöresel şenlikler ve doğa yürüyüşleri için uygun bir ortam sunar.", "place_query": "Ağapınar Yaylası, Han, Eskişehir"}, {"title": "Han Kalesi Kalıntıları", "summary": "İlçeye adını veren tarihi Han Kalesi''nden günümüze sadece kalıntılar ulaşmıştır. Tepe üzerinde yer alan kalıntılar, bölgenin stratejik önemini ve tarihini gözler önüne serer.", "place_query": "Han Kalesi kalıntıları, Han, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ab16bca2-8a99-465c-ab47-1df696a41e3e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İnönü Mağarası", "summary": "Tarih öncesi döneme ait kalıntıların bulunduğu bu mağara, bölgenin en önemli arkeolojik alanlarından biridir. Ziyaretçiler, mağaranın içindeki doğal oluşumları ve tarihi atmosferi keşfedebilir.", "place_query": "İnönü Mağarası, İnönü, Eskişehir"}, {"title": "İnönü Şehitliği ve Anıtı", "summary": "İnönü Savaşları''nda hayatını kaybeden askerler anısına yapılan bu anıt ve şehitlik, tarihi bir öneme sahiptir. Ziyaretçiler, burada saygı duruşunda bulunabilir ve çevredeki manzarayı izleyebilir.", "place_query": "İnönü Şehitliği, İnönü, Eskişehir"}, {"title": "İnönü Belediye Parkı", "summary": "Şehir merkezinde yer alan bu park, dinlenmek ve doğayla iç içe vakit geçirmek için idealdir. Yürüyüş yolları, oturma alanları ve yeşil alanlarıyla aileler için popüler bir mekandır.", "place_query": "İnönü Belediye Parkı, İnönü, Eskişehir"}, {"title": "İnönü Evleri", "summary": "Geleneksel Osmanlı mimarisini yansıtan bu tarihi evler, ilçenin kültürel dokusunu gözler önüne serer. Dar sokaklarda yürüyerek bu yapıların estetiğini yakından görebilirsiniz.", "place_query": "İnönü Evleri, İnönü, Eskişehir"}, {"title": "İnönü Mesire Alanı", "summary": "Piknik ve doğa yürüyüşü için uygun olan bu mesire alanı, şehir gürültüsünden uzaklaşmak isteyenler için huzurlu bir kaçış noktasıdır. Ağaçlar arasında serinleyebilir ve mangal keyfi yapabilirsiniz.", "place_query": "İnönü Mesire Alanı, İnönü, Eskişehir"}, {"title": "İnönü Tren İstasyonu", "summary": "Tarihi bir yapı olan bu istasyon, Kurtuluş Savaşı döneminde önemli bir lojistik merkez olarak kullanılmıştır. Günümüzde hala aktif olan istasyon, nostaljik bir atmosfer sunar.", "place_query": "İnönü Tren İstasyonu, İnönü, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '37fb776d-f036-415d-b8be-745ce2411ec3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mahmudiye At Çiftlikleri", "summary": "Mahmudiye, at yetiştiriciliği ile ünlüdür ve bölgede birçok at çiftliği bulunur. Ziyaretçiler bu çiftliklerde atları yakından görebilir, binicilik yapabilir ve at sevgisini deneyimleyebilir.", "place_query": "Mahmudiye At Çiftlikleri, Mahmudiye, Eskişehir"}, {"title": "Mahmudiye Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve doğayla iç içe vakit geçirmek isteyenler için ideal bir mekandır. Yürüyüş yolları ve oturma alanları ile huzurlu bir atmosfer sunar.", "place_query": "Mahmudiye Belediye Parkı, Mahmudiye, Eskişehir"}, {"title": "Mahmudiye Camii", "summary": "Tarihi bir yapı olan Mahmudiye Camii, ilçenin en önemli dini ve mimari eserlerinden biridir. Osmanlı dönemi izlerini taşıyan cami, ziyaretçilerin ilgisini çeker.", "place_query": "Mahmudiye Camii, Mahmudiye, Eskişehir"}, {"title": "Seyitgazi Köyü ve Türbesi", "summary": "Mahmudiye''ye yakın konumdaki Seyitgazi Köyü, Seyyid Battal Gazi Türbesi ve külliyesi ile ünlüdür. Tarihi ve manevi atmosferiyle ziyaretçilere farklı bir deneyim sunar.", "place_query": "Seyitgazi Türbesi, Seyitgazi, Eskişehir"}, {"title": "Mahmudiye Yaylası", "summary": "Doğa severler için kaçırılmayacak bir rota olan Mahmudiye Yaylası, temiz havası ve yeşil manzaralarıyla piknik ve yürüyüş için idealdir.", "place_query": "Mahmudiye Yaylası, Mahmudiye, Eskişehir"}, {"title": "Eskişehir Büyükşehir Belediyesi Hayvanat Bahçesi", "summary": "Mahmudiye ilçe sınırları içinde olmasa da yakın mesafedeki bu hayvanat bahçesi, özellikle aileler için popüler bir gezi noktasıdır. Birçok hayvan türüne ev sahipliği yapar.", "place_query": "Eskişehir Hayvanat Bahçesi, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '28282f99-2729-4606-9a91-53e26ad749b0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mihalgazi Kalesi", "summary": "Tarihi bir Bizans kalesi olup, bölgenin en önemli kültürel miraslarından biridir. Tepe üzerindeki konumu sayesinde Sakarya Nehri ve çevresinin panoramik manzarasını sunar.", "place_query": "Mihalgazi Kalesi, Mihalgazi, Eskişehir"}, {"title": "Sakarya Nehri Kenarı", "summary": "Mihalgazi''den geçen Sakarya Nehri kıyısı, doğa yürüyüşleri ve piknik için ideal bir alandır. Özellikle bahar aylarında yeşilin ve suyun huzur verici atmosferi ziyaretçileri cezbeder.", "place_query": "Sakarya Nehri, Mihalgazi, Eskişehir"}, {"title": "Mihalgazi Köprüsü", "summary": "Tarihi taş köprü, Osmanlı döneminden kalma önemli bir yapıdır. Sakarya Nehri üzerinde yer alan köprü, fotoğrafçılar ve tarih meraklıları için popüler bir duraktır.", "place_query": "Mihalgazi Köprüsü, Mihalgazi, Eskişehir"}, {"title": "Alpagut Mağarası", "summary": "Mihalgazi sınırları içinde yer alan bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Doğa sporları ve mağara keşfi sevenler için benzersiz bir deneyim sunar.", "place_query": "Alpagut Mağarası, Mihalgazi, Eskişehir"}, {"title": "Mihalgazi Yaylaları", "summary": "Bölgenin serin ve yeşil yaylaları, özellikle yaz aylarında şehir kalabalığından kaçmak isteyenler için huzurlu bir kaçış noktasıdır. Doğa yürüyüşleri ve kamp için uygun alanlar barındırır.", "place_query": "Mihalgazi Yaylaları, Eskişehir"}, {"title": "Sakarya Vadisi Tabiat Parkı", "summary": "Mihalgazi yakınlarındaki bu tabiat parkı, zengin bitki örtüsü ve kuş gözlemi fırsatlarıyla doğaseverlerin uğrak noktasıdır. Piknik alanları ve yürüyüş parkurları mevcuttur.", "place_query": "Sakarya Vadisi Tabiat Parkı, Mihalgazi, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7ef427b9-76f7-4a39-994c-2ba896332898'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mihalıççık Kalesi", "summary": "Tarihi bir kaledir. Bölgenin en önemli tarihi yapılarından biridir ve muhteşem bir manzaraya sahiptir. Ziyaretçilerine hem tarihi bir yolculuk hem de doğa ile iç içe bir deneyim sunar.", "place_query": "Mihalıççık Kalesi, Eskişehir"}, {"title": "Sorkun Göleti", "summary": "Doğal güzelliği ile ünlü bir gölettir. Piknik alanları ve yürüyüş parkurları ile aileler için ideal bir kaçış noktasıdır. Kuş gözlemciliği için de popüler bir yerdir.", "place_query": "Sorkun Göleti, Mihalıççık, Eskişehir"}, {"title": "Dinek Şelalesi", "summary": "Doğa severler için popüler bir şelaledir. Serin suları ve çevresindeki yeşil alanlar, özellikle yaz aylarında ziyaretçilere huzurlu bir ortam sunar.", "place_query": "Dinek Şelalesi, Mihalıççık, Eskişehir"}, {"title": "Mihalıççık Müzesi", "summary": "Yöresel tarih ve kültürü yansıtan bir müzedir. Bölgeden çıkarılan arkeolojik eserler ve etnografik objeler sergilenir. Tarihe ilgi duyanlar için mutlaka görülmesi gereken bir yerdir.", "place_query": "Mihalıççık Müzesi, Eskişehir"}, {"title": "Karaağaç Yaylası", "summary": "Yemyeşil doğası ve temiz havası ile ünlü bir yayladır. Doğa yürüyüşleri, kamp ve piknik için idealdir. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Karaağaç Yaylası, Mihalıççık, Eskişehir"}, {"title": "Sivrihisar Dağı", "summary": "Bölgenin en yüksek noktalarından biridir. Dağcılık ve doğa sporları için popüler bir destinasyondur. Zirvesinden Eskişehir''in muhteşem manzarası izlenebilir.", "place_query": "Sivrihisar Dağı, Mihalıççık, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b41965df-aace-4ef8-a708-b3dd38a20689'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Odunpazarı Evleri", "summary": "Osmanlı döneminden kalma renkli ve restore edilmiş ahşap evlerin bulunduğu tarihi bir semttir. Dar sokaklarında yürüyüş yapabilir, el sanatları dükkanlarını ziyaret edebilirsiniz.", "place_query": "Odunpazarı Evleri, Eskişehir"}, {"title": "Odunpazarı Modern Müze (OMM)", "summary": "Çağdaş sanat eserlerinin sergilendiği, mimarisiyle de dikkat çeken etkileyici bir müzedir. Hem sanatseverler hem de fotoğraf tutkunları için harika bir duraktır.", "place_query": "Odunpazarı Modern Müze, Eskişehir"}, {"title": "Kurutuluş Anıtı ve Şehr-i Aşk Parkı", "summary": "Odunpazarı''nın yüksek bir noktasında bulunan bu park, Kurtuluş Savaşı anıtı ve şehrin panoramik manzarasıyla ünlüdür. Özellikle gün batımında ziyaret edilmesi önerilir.", "place_query": "Kurtuluş Anıtı Odunpazarı, Eskişehir"}, {"title": "Eskişehir Balmumu Heykeller Müzesi", "summary": "Türkiye''nin önemli isimlerinin ve dünya liderlerinin gerçekçi balmumu heykellerinin sergilendiği sıra dışı bir müzedir. Odunpazarı''nda gezilecek eğlenceli yerlerden biridir.", "place_query": "Balmumu Heykeller Müzesi, Odunpazarı, Eskişehir"}, {"title": "Atlantis Su Parkı ve Macera Ormanı", "summary": "Özellikle yaz aylarında aileler için popüler bir eğlence merkezidir. Su kaydırakları ve macera parkurlarıyla hem serinlemek hem de eğlenmek için idealdir.", "place_query": "Atlantis Su Parkı, Odunpazarı, Eskişehir"}, {"title": "Eskişehir Büyükşehir Belediyesi Masal Şatosu", "summary": "Çocukların hayal dünyasını canlandıran, masal karakterlerinin ve canlandırmalarının olduğu renkli bir yapıdır. Aileler için keyifli bir ziyaret noktasıdır.", "place_query": "Masal Şatosu, Odunpazarı, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2d93c935-e255-43e1-807a-b701747a744c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıcakaya Kaplıcaları", "summary": "Sarıcakaya''nın en bilinen doğal zenginliği olan termal sular, romatizma ve cilt hastalıklarına iyi gelmesiyle ünlüdür. Bölgedeki otel ve tesislerde şifalı sulardan faydalanabilir, doğal güzellikler içinde dinlenebilirsiniz.", "place_query": "Sarıcakaya Kaplıcaları, Sarıcakaya, Eskişehir"}, {"title": "Seyitgazi Kalesi", "summary": "Sarıcakaya sınırları içinde olmasa da yakın mesafedeki bu tarihi kale, bölgede mutlaka görülmesi gereken bir yapıdır. Frig, Roma ve Osmanlı dönemlerine ait izler taşıyan kale, muhteşem bir vadi manzarası sunar.", "place_query": "Seyitgazi Kalesi, Seyitgazi, Eskişehir"}, {"title": "Sarıcakaya Göleti", "summary": "Doğal bir güzellik olan bu gölet, piknik ve doğa yürüyüşü için idealdir. Çevresindeki yeşil alanlar ve sakin atmosferiyle hafta sonu kaçamakları için popüler bir noktadır.", "place_query": "Sarıcakaya Göleti, Sarıcakaya, Eskişehir"}, {"title": "Mihalgazi Kalesi", "summary": "Sarıcakaya''ya komşu Mihalgazi ilçesinde yer alan bu tarihi kale, Sakarya Nehri kıyısında yükselir. Bizans döneminden kalma yapı, nehir manzarası eşliğinde tarihi bir yolculuk yapma fırsatı sunar.", "place_query": "Mihalgazi Kalesi, Mihalgazi, Eskişehir"}, {"title": "Sakarya Nehri Kenarı", "summary": "Sarıcakaya''dan geçen Sakarya Nehri''nin kıyıları, doğa ile iç içe vakit geçirmek için harika bir yerdir. Nehir kenarında yürüyüş yapabilir, balık tutabilir veya sadece huzurlu manzaranın tadını çıkarabilirsiniz.", "place_query": "Sakarya Nehri, Sarıcakaya, Eskişehir"}, {"title": "Sarıcakaya Tarihi Çarşı", "summary": "İlçe merkezinde bulunan bu geleneksel çarşı, yöresel ürünler ve el sanatları satın almak için idealdir. Özellikle termal sabunlar ve doğal ürünleriyle dikkat çeker.", "place_query": "Sarıcakaya Çarşı, Sarıcakaya, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'af418b0b-c60d-46d7-8551-3082848dfe0c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Seyitgazi Külliyesi", "summary": "13. yüzyıldan kalma bu tarihi külliye, Seyit Battal Gazi''nin türbesini ve camiyi barındırır. Bölgenin en önemli inanç ve kültür merkezlerinden biridir.", "place_query": "Seyitgazi Külliyesi, Seyitgazi, Eskişehir"}, {"title": "Seyitgazi Müzesi", "summary": "Külliye içinde yer alan müze, bölgedeki arkeolojik ve etnografik eserleri sergiler. Frig, Roma ve Osmanlı dönemine ait buluntular görülebilir.", "place_query": "Seyitgazi Müzesi, Seyitgazi, Eskişehir"}, {"title": "Yazılıkaya (Midas Şehri)", "summary": "Frig dönemine ait bu antik kent, kayalara oyulmuş anıtsal cephesiyle ünlüdür. ''Midas Anıtı'' olarak da bilinen yapı, tarih meraklıları için eşsiz bir duraktır.", "place_query": "Yazılıkaya Midas Şehri, Seyitgazi, Eskişehir"}, {"title": "Kümbet Asarönü Antik Kenti", "summary": "Frig ve Roma kalıntılarını bir arada sunan bu ören yeri, kayalara oyulmuş mezarları ve kalıntılarıyla dikkat çeker. Doğa ile tarihin iç içe olduğu bir noktadır.", "place_query": "Kümbet Asarönü Antik Kenti, Seyitgazi, Eskişehir"}, {"title": "Seyitgazi Kalesi", "summary": "Tepenin üzerinde yer alan bu tarihi kale, çevreye hakim bir manzara sunar. Kalıntıları arasında gezerken bölgenin savunma tarihine dair izler görebilirsiniz.", "place_query": "Seyitgazi Kalesi, Seyitgazi, Eskişehir"}, {"title": "Kırka Bor Madenleri ve Göleti", "summary": "Eti Maden''e ait bor işletmelerinin oluşturduğu bu doğal gölet, turkuaz rengiyle ilgi çeker. Fotoğrafçılar ve doğa severler için popüler bir duraktır.", "place_query": "Kırka Bor Madenleri Göleti, Seyitgazi, Eskişehir"}, {"title": "Doğray Köyü (Doğray Camii ve Tarihi Evler)", "summary": "Osmanlı döneminden kalma ahşap ve taş yapılarıyla sakin bir köy atmosferi sunar. Köy camisi ve geleneksel evler, kültürel bir gezinti için idealdir.", "place_query": "Doğray Köyü, Seyitgazi, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '383dc685-5a7a-4249-8f7e-98dcc480b11e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sivrihisar Ulu Camii", "summary": "Selçuklu döneminin en önemli ahşap direkli camilerinden biri olan bu yapı, 40 ahşap sütunu ve işlemeli tavanıyla dikkat çeker. Tarihi dokusu ve mimari zarafetiyle ziyaretçilerini büyüler.", "place_query": "Sivrihisar Ulu Camii, Sivrihisar, Eskişehir"}, {"title": "Sivrihisar Saat Kulesi", "summary": "Şehrin simgesi haline gelmiş bu tarihi saat kulesi, 19. yüzyıldan kalma olup kare planlı ve taş yapısıyla öne çıkar. Tepeden şehri seyretmek için harika bir noktadır.", "place_query": "Sivrihisar Saat Kulesi, Sivrihisar, Eskişehir"}, {"title": "Zaimağa Konağı", "summary": "Osmanlı dönemi sivil mimarisinin güzel bir örneği olan bu konak, restore edilerek kültür merkezine dönüştürülmüştür. İçindeki etnografik eşyalar ve tarihi atmosferiyle görülmeye değerdir.", "place_query": "Zaimağa Konağı, Sivrihisar, Eskişehir"}, {"title": "Sivrihisar Balıkdamı Kuş Cenneti", "summary": "Sakarya Nehri kıyısında yer alan bu doğal sulak alan, yüzlerce kuş türüne ev sahipliği yapar. Doğa fotoğrafçıları ve kuş gözlemcileri için eşsiz bir duraktır.", "place_query": "Balıkdamı Kuş Cenneti, Sivrihisar, Eskişehir"}, {"title": "Sivrihisar Kalesi", "summary": "Antik çağlardan kalma bu kale, şehrin en yüksek noktasında yer alır ve panoramik manzarasıyla ünlüdür. Tarih boyunca birçok medeniyete ev sahipliği yapmıştır.", "place_query": "Sivrihisar Kalesi, Sivrihisar, Eskişehir"}, {"title": "Nasreddin Hoca Arkeoloji ve Etnoğrafya Müzesi", "summary": "Nasreddin Hoca''nın doğum yeri olan Sivrihisar''da bulunan bu müze, hem arkeolojik eserleri hem de yöresel kıyafet ve eşyaları sergiler. Hoca''nın hayatına dair ilginç bilgiler sunar.", "place_query": "Nasreddin Hoca Arkeoloji ve Etnoğrafya Müzesi, Sivrihisar, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '48ba3c2c-ab0f-4f6d-bc6d-6f9b26df8a29'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eskişehir Büyükşehir Belediyesi Bilim Deney Merkezi ve Sabancı Uzay Evi", "summary": "Çocuklar ve yetişkinler için interaktif bilim deneyleri ve planetaryum gösterimleri sunan popüler bir merkez. Eğitici ve eğlenceli bir gün geçirmek için ideal bir durak.", "place_query": "Bilim Deney Merkezi, Tepebaşı, Eskişehir"}, {"title": "Kentpark", "summary": "Şehrin merkezinde yapay plajı, yürüyüş yolları ve kafeleriyle ünlü dev bir park. Özellikle yaz aylarında serinlemek ve dinlenmek için en popüler noktalardan biridir.", "place_query": "Kentpark, Tepebaşı, Eskişehir"}, {"title": "Odunpazarı Evleri", "summary": "Tepebaşı''na bağlı Odunpazarı bölgesinde bulunan, restore edilmiş geleneksel Osmanlı evleri. Sanat galerileri, butik kafeler ve hediyelik eşya dükkanlarıyla dolu tarihi bir semttir.", "place_query": "Odunpazarı Evleri, Eskişehir"}, {"title": "Eskişehir Hayvanat Bahçesi", "summary": "Türkiye''nin en büyük ve en modern hayvanat bahçelerinden biri olup, yüzlerce hayvan türüne ev sahipliği yapar. Doğal yaşam alanları ve geniş yeşil alanlarıyla aileler için harika bir gezi noktasıdır.", "place_query": "Eskişehir Hayvanat Bahçesi, Tepebaşı, Eskişehir"}, {"title": "Sazova Bilim Kültür ve Sanat Parkı", "summary": "Masal Şatosu, korsan gemisi ve dev akvaryumuyla çocukların hayal dünyasını harekete geçiren büyük bir tema parkı. Aynı zamanda içindeki Bilim Deney Merkezi ile de ünlüdür.", "place_query": "Sazova Parkı, Tepebaşı, Eskişehir"}, {"title": "Eskişehir Büyükşehir Belediyesi Su Altı Dünyası", "summary": "Sazova Parkı içinde yer alan ve tünel akvaryumuyla ünlü bu merkez, köpekbalıkları ve vatozlar gibi deniz canlılarını yakından görme fırsatı sunar. Eğitici ve etkileyici bir deneyimdir.", "place_query": "Su Altı Dünyası, Sazova, Tepebaşı, Eskişehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4187ffa2-5126-4870-bb01-632907efd37d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Araban Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu kale, bölgenin stratejik önemini yansıtan kalıntılarıyla ziyaretçilere tarih ve manzara sunuyor.", "place_query": "Araban Kalesi, Araban, Gaziantep"}, {"title": "Araban Ovası", "summary": "Geniş ve verimli tarım arazileriyle ünlü bu ova, özellikle ilkbaharda yeşilin her tonunu görmek isteyenler için huzurlu bir doğa kaçamağıdır.", "place_query": "Araban Ovası, Araban, Gaziantep"}, {"title": "Araban Barajı", "summary": "Çevresindeki piknik alanları ve sakin suyuyla hafta sonu dinlenmek isteyen aileler için popüler bir mesire yeridir.", "place_query": "Araban Barajı, Araban, Gaziantep"}, {"title": "Araban İlçe Merkezi Tarihi Camileri", "summary": "İlçe merkezinde bulunan Osmanlı döneminden kalma tarihi camiler, sade mimarileri ve huzur veren atmosferleriyle dikkat çeker.", "place_query": "Araban merkez camileri, Araban, Gaziantep"}, {"title": "Elif Harabeleri", "summary": "Araban sınırları içinde yer alan bu antik yerleşim kalıntıları, bölgenin Roma ve Bizans dönemlerine ışık tutan önemli bir arkeolojik alandır.", "place_query": "Elif Harabeleri, Araban, Gaziantep"}, {"title": "Araban Yaylaları", "summary": "Yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için ideal olan yaylalar, zengin bitki örtüsü ve temiz havasıyla bilinir.", "place_query": "Araban yaylaları, Araban, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '021d15c5-8a34-45b9-a54a-ae8f7ba20e1b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yesemek Taş Ocağı ve Heykel Atölyesi", "summary": "Hitit dönemine ait devasa bir açık hava heykel atölyesi ve taş ocağıdır. Yarı işlenmiş bazalt aslan ve sfenks heykelleriyle tarihe tanıklık edebilirsiniz.", "place_query": "Yesemek Taş Ocağı ve Heykel Atölyesi, İslahiye, Gaziantep"}, {"title": "İslahiye Kalesi", "summary": "Tarihi bir kaledir ve bölgenin en eski yerleşim alanlarından biridir. Kale kalıntıları ve çevresindeki manzara ziyaretçilere keyifli bir atmosfer sunar.", "place_query": "İslahiye Kalesi, İslahiye, Gaziantep"}, {"title": "Tahtaköprü Barajı ve Mesire Alanı", "summary": "Doğal güzellikleriyle ünlü bir baraj ve piknik alanıdır. Özellikle hafta sonları doğa yürüyüşü ve kuş gözlemi için idealdir.", "place_query": "Tahtaköprü Barajı, İslahiye, Gaziantep"}, {"title": "İslahiye Müzesi", "summary": "Bölgedeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği modern bir müzedir. Hitit, Roma ve Bizans dönemine ait buluntuları yakından görebilirsiniz.", "place_query": "İslahiye Müzesi, İslahiye, Gaziantep"}, {"title": "Fevzipaşa Tabiat Parkı", "summary": "Yeşillikler içinde huzurlu bir doğa parkıdır. Piknik alanları, yürüyüş yolları ve temiz havasıyla şehir stresinden uzaklaşmak için birebirdir.", "place_query": "Fevzipaşa Tabiat Parkı, İslahiye, Gaziantep"}, {"title": "İslahiye Yaylaları", "summary": "Yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilen yaylalardır. Özellikle Boğaziçi ve Güllüce yaylaları meşhurdur.", "place_query": "İslahiye Yaylaları, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '61bac365-d3ec-421e-a9fc-cd4d93d27605'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karkamış Antik Kenti", "summary": "Hitit İmparatorluğu''nun önemli merkezlerinden biri olan bu antik kent, etkileyici surları ve kabartmalarıyla tarih meraklıları için eşsiz bir duraktır. Sınır hattında yer alması ona ayrı bir atmosfer katar.", "place_query": "Karkamış Antik Kenti, Karkamış, Gaziantep"}, {"title": "Fırat Nehri Kenarı", "summary": "Karkamış''tan geçen Fırat Nehri''nin kıyıları, huzurlu yürüyüşler ve doğayla iç içe vakit geçirmek için idealdir. Özellikle gün batımında nehir manzarası büyüleyicidir.", "place_query": "Fırat Nehri, Karkamış, Gaziantep"}, {"title": "Karkamış Barajı ve Çevresi", "summary": "Bölgedeki en büyük su kütlelerinden biri olan baraj, piknik alanları ve kuş gözlemi yapma imkanı sunar. Sakin atmosferiyle doğa severler için kaçırılmaması gereken bir noktadır.", "place_query": "Karkamış Barajı, Gaziantep"}, {"title": "Karkamış Müzesi", "summary": "Karkamış Antik Kenti''nden çıkarılan eserlerin sergilendiği bu müze, bölgenin zengin tarihine ışık tutar. Hitit dönemine ait heykeller ve çivi yazılı tabletler en dikkat çekici parçalar arasındadır.", "place_query": "Karkamış Müzesi, Karkamış, Gaziantep"}, {"title": "Karkamış Kalesi", "summary": "Antik kentin surları üzerinde yükselen bu kale, bölgeye hakim bir tepede yer alır. Hem tarihi dokusu hem de çevredeki Fırat manzarasıyla fotoğrafçılar için harika bir noktadır.", "place_query": "Karkamış Kalesi, Karkamış, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bddf3d72-7c0f-4b32-aec4-f8ff622485f0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zeugma Antik Kenti", "summary": "Dünyaca ünlü Çingene Kızı mozaiğine ev sahipliği yapan bu antik kent, Fırat Nehri kıyısındaki eşsiz konumu ve etkileyici mozaikleriyle tarih meraklıları için mutlaka görülmesi gereken bir yerdir.", "place_query": "Zeugma Antik Kenti, Nizip, Gaziantep"}, {"title": "Zeugma Mozaik Müzesi", "summary": "Zeugma''dan çıkarılan olağanüstü mozaiklerin sergilendiği bu müze, dünyanın en büyük mozaik müzelerinden biri olup, ziyaretçilere antik dönemin sanatsal zenginliğini sunar.", "place_query": "Zeugma Mozaik Müzesi, Şehitkamil, Gaziantep"}, {"title": "Rumkale", "summary": "Fırat Nehri''nin kıyısında yükselen bu tarihi kale, eşsiz manzarası ve Hristiyanlık tarihi açısından önemiyle hem doğa hem de tarih tutkunlarını cezbeder.", "place_query": "Rumkale, Nizip, Gaziantep"}, {"title": "Birecik Kelaynak Üretme İstasyonu", "summary": "Nesli tükenme tehlikesi altındaki kelaynak kuşlarının korunduğu bu istasyon, hem doğa severler için eşsiz bir gözlem noktası hem de önemli bir koruma projesidir.", "place_query": "Birecik Kelaynak Üretme İstasyonu, Birecik, Şanlıurfa"}, {"title": "Nizip Kalesi", "summary": "Şehrin merkezinde yükselen bu tarihi kale, Nizip''in geçmişine tanıklık eden bir yapı olup, çevresindeki panoramik manzarasıyla ziyaretçilerine keyifli bir gezi imkanı sunar.", "place_query": "Nizip Kalesi, Nizip, Gaziantep"}, {"title": "Nizip Belediye Parkı", "summary": "Şehrin ortasında yer alan bu geniş park, yürüyüş yolları, göleti ve yeşil alanlarıyla aileler ve doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Nizip Belediye Parkı, Nizip, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ba54e825-8813-418b-a76e-e587a02d8ce0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nurdağı Gezbeli Yaylası", "summary": "Yemyeşil doğası ve serin havasıyla özellikle yaz aylarında piknik ve kamp için ideal bir yayladır. Ziyaretçilerine huzurlu bir doğa kaçamağı sunar.", "place_query": "Gezbeli Yaylası, Nurdağı, Gaziantep"}, {"title": "Nurdağı Kalesi", "summary": "Tarihi İpek Yolu üzerinde yer alan bu kale, bölgenin stratejik önemini gözler önüne serer. Kalıntıları ve çevresindeki manzarasıyla tarih meraklıları için ilgi çekicidir.", "place_query": "Nurdağı Kalesi, Nurdağı, Gaziantep"}, {"title": "Sakçagözü Höyüğü", "summary": "Neolitik döneme kadar uzanan tarihiyle önemli bir arkeolojik alandır. Bölgedeki kazılarda ortaya çıkarılan buluntular, ilk yerleşimler hakkında bilgi verir.", "place_query": "Sakçagözü Höyüğü, Nurdağı, Gaziantep"}, {"title": "Nurdağı Şelalesi", "summary": "Doğa yürüyüşü sevenler için popüler bir durak olan şelale, özellikle bahar aylarında coşkun akan sularıyla görsel bir şölen sunar. Çevresi piknik alanı olarak da kullanılmaktadır.", "place_query": "Nurdağı Şelalesi, Nurdağı, Gaziantep"}, {"title": "Kartal Kayası Seyir Terası", "summary": "Nurdağı''nın yüksek noktalarından biri olan bu seyir terası, ziyaretçilere muhteşem bir vadi ve dağ manzarası izleme fırsatı verir. Özellikle gün batımında etkileyici bir deneyim sunar.", "place_query": "Kartal Kayası, Nurdağı, Gaziantep"}, {"title": "Nurdağı Atatürk Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve çocuklarla vakit geçirmek için uygun bir alandır. Yeşil alanları ve yürüyüş yollarıyla halkın uğrak noktasıdır.", "place_query": "Atatürk Parkı, Nurdağı, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '79fbbe16-3fd2-451b-a9ef-62c5cec7a716'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gaziantep Kalesi", "summary": "Şehir merkezinde yer alan ve tarihi binlerce yıl öncesine dayanan bu kale, Gaziantep''in simgelerinden biridir. Ziyaretçiler, kaleyi çevreleyen surlar ve içindeki yapılarla geçmişe yolculuk yapabilir.", "place_query": "Gaziantep Kalesi, Şahinbey, Gaziantep"}, {"title": "Zeugma Mozaik Müzesi", "summary": "Dünyanın en büyük mozaik müzelerinden biri olan bu müze, Zeugma Antik Kenti''nden çıkarılan eşsiz mozaikleri sergiler. Çingene Kızı mozaiği en ünlü eserlerindendir.", "place_query": "Zeugma Mozaik Müzesi, Şehitkamil, Gaziantep"}, {"title": "Bakırcılar Çarşısı", "summary": "Gaziantep''in tarihi çarşılarından biri olan Bakırcılar Çarşısı, el yapımı bakır ürünleri ve geleneksel el sanatlarıyla ünlüdür. Ziyaretçiler burada hediyelik eşya alışverişi yapabilir.", "place_query": "Bakırcılar Çarşısı, Şahinbey, Gaziantep"}, {"title": "Gaziantep Hayvanat Bahçesi", "summary": "Türkiye''nin en büyük hayvanat bahçelerinden biri olan bu alan, yüzlerce hayvan türüne ev sahipliği yapar. Aileler için ideal bir gezi noktasıdır.", "place_query": "Gaziantep Hayvanat Bahçesi, Şehitkamil, Gaziantep"}, {"title": "Yesemek Açık Hava Müzesi", "summary": "Oğuzeli ilçesine bağlı Yesemek köyünde yer alan bu açık hava müzesi, Hitit dönemine ait taş ocakları ve heykel atölyeleriyle ünlüdür. Tarih meraklıları için eşsiz bir duraktır.", "place_query": "Yesemek Açık Hava Müzesi, Oğuzeli, Gaziantep"}, {"title": "Dülük Antik Kenti", "summary": "Gaziantep''e yakın bir konumda bulunan bu antik kent, Roma ve Bizans dönemlerine ait kalıntılarıyla dikkat çeker. Mağaralar ve yer altı yapıları keşfedilmeyi bekler.", "place_query": "Dülük Antik Kenti, Şehitkamil, Gaziantep"}, {"title": "Gaziantep Mutfak Müzesi", "summary": "Gaziantep''in ünlü mutfak kültürünü tanıtan bu müze, yöresel yemeklerin ve mutfak eşyalarının sergilendiği interaktif bir alandır. Şehrin gastronomi mirasını yakından görmek için idealdir.", "place_query": "Gaziantep Mutfak Müzesi, Şahinbey, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7f51e36c-e566-449c-b939-777592aba501'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gaziantep Kalesi", "summary": "Şehrin simgesi olan bu tarihi kale, Hititlerden Osmanlıya kadar pek çok medeniyete ev sahipliği yapmıştır. İçerisinde Gaziantep Savunması ve Kent Müzesi bulunur.", "place_query": "Gaziantep Kalesi, Şahinbey, Gaziantep"}, {"title": "Zeugma Mozaik Müzesi", "summary": "Dünyanın en büyük mozaik müzelerinden biri olan Zeugma, ünlü Çingene Kızı mozaiğine ev sahipliği yapar. Antik Zeugma kentinden çıkarılan eserler sergilenmektedir.", "place_query": "Zeugma Mozaik Müzesi, Şahinbey, Gaziantep"}, {"title": "Emine Göğüş Mutfak Müzesi", "summary": "Gaziantep''in UNESCO gastronomi şehri unvanını taçlandıran bu müze, yöresel mutfak kültürünü ve tarihi mutfak eşyalarını sergiler. Şehrin lezzet yolculuğuna dair eşsiz bir durak.", "place_query": "Emine Göğüş Mutfak Müzesi, Şahinbey, Gaziantep"}, {"title": "Tarihi Gümrük Hanı", "summary": "17. yüzyıldan kalma bu tarihi han, restore edilerek kültür ve sanat merkezine dönüştürülmüştür. Avlusunda çay keyfi yapabilir, el sanatları dükkanlarını gezebilirsiniz.", "place_query": "Tarihi Gümrük Hanı, Şahinbey, Gaziantep"}, {"title": "Gaziantep Hayvanat Bahçesi", "summary": "Türkiye''nin en büyük ve Avrupa''nın sayılı hayvanat bahçelerinden biridir. Yüzlerce türden binlerce hayvana ev sahipliği yapar, özellikle aileler için ideal bir gezi noktasıdır.", "place_query": "Gaziantep Hayvanat Bahçesi, Şahinbey, Gaziantep"}, {"title": "Şahinbey Parkı ve Millet Kıraathanesi", "summary": "Şehir merkezinde geniş yeşil alanları, yürüyüş yolları ve göletiyle dinlenme imkanı sunar. İçerisindeki tarihi Millet Kıraathanesi, Osmanlı dönemi atmosferini yaşatır.", "place_query": "Şahinbey Parkı, Gaziantep"}, {"title": "Copper (Bakırcılar) Çarşısı", "summary": "Gaziantep''in en eski çarşılarından biri olan Bakırcılar Çarşısı, bakır işlemeciliğinin canlı olarak sürdüğü bir açık hava atölyesidir. Hediyelik eşya alışverişi için uğranması gereken bir yerdir.", "place_query": "Bakırcılar Çarşısı, Şahinbey, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '45e5d338-0b83-479f-8802-1f055b2586c9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gaziantep Kalesi", "summary": "Şehir merkezinde yükselen tarihi kale, Gaziantep''in simgelerinden biridir. İçerisinde Panorama Müzesi ve savunma tarihine dair sergiler bulunur, şehir manzarası eşliğinde tarihe tanıklık edebilirsiniz.", "place_query": "Gaziantep Kalesi, Şehitkamil, Gaziantep"}, {"title": "Zeugma Mozaik Müzesi", "summary": "Dünyanın en büyük mozaik müzelerinden biri olan bu müze, Zeugma Antik Kenti''nden çıkarılan eşsiz mozaiklere ev sahipliği yapar. Çingene Kızı mozaiği başta olmak üzere binlerce yıllık sanat eserlerini yakından görebilirsiniz.", "place_query": "Zeugma Mozaik Müzesi, Şehitkamil, Gaziantep"}, {"title": "Gaziantep Hayvanat Bahçesi", "summary": "Türkiye''nin en büyük hayvanat bahçelerinden biri olup, yüzlerce türde hayvana ev sahipliği yapar. Geniş alanı ve doğal yaşam ortamlarıyla özellikle aileler için keyifli bir gezi noktasıdır.", "place_query": "Gaziantep Hayvanat Bahçesi, Şehitkamil, Gaziantep"}, {"title": "Emine Göğüş Mutfak Müzesi", "summary": "Gaziantep''in ünlü mutfak kültürünü tanıtan bu müze, yöresel yemeklerin yapım aşamalarını ve tarihini sergiler. Geleneksel mutfak eşyaları ve lezzetlerin hikâyeleriyle dolu bir deneyim sunar.", "place_query": "Emine Göğüş Mutfak Müzesi, Şehitkamil, Gaziantep"}, {"title": "Şehitkamil Bilim Merkezi", "summary": "Çocuklar ve yetişkinler için interaktif deneyler, atölyeler ve bilimsel gösteriler sunan modern bir merkezdir. Eğlenceli ve öğretici aktivitelerle bilime ilgi duyan herkes için ideal bir duraktır.", "place_query": "Şehitkamil Bilim Merkezi, Gaziantep"}, {"title": "Dülük Antik Kenti", "summary": "Şehitkamil sınırlarında yer alan bu antik kent, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklılarını cezbeder. Özellikle mağara kiliseleri ve yer altı yapılarıyla dikkat çeker.", "place_query": "Dülük Antik Kenti, Şehitkamil, Gaziantep"}, {"title": "Hamam Müzesi", "summary": "Tarihi bir hamam binasında hizmet veren bu müze, Osmanlı dönemi hamam kültürünü ve Gaziantep''in sosyal yaşamını gözler önüne serer. Orijinal mimarisi ve sergilenen objelerle zamanda yolculuk yaparsınız.", "place_query": "Hamam Müzesi, Şehitkamil, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0c0c51fd-1518-4699-8081-78131b81ad2e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yavuzeli Kalesi", "summary": "Tarihi bir kale olup, bölgenin stratejik önemini yansıtır. Ziyaretçiler, kalenin surlarından çevredeki geniş ovayı ve Fırat Nehri''nin manzarasını izleyebilir.", "place_query": "Yavuzeli Kalesi, Yavuzeli, Gaziantep"}, {"title": "Fırat Nehri Kenarı (Yavuzeli Bölümü)", "summary": "Fırat Nehri''nin Yavuzeli sınırları içinden geçen bölümü, doğal güzelliği ve huzurlu atmosferiyle piknik ve yürüyüş için idealdir. Nehir kenarında yerel balıkçıları da gözlemleyebilirsiniz.", "place_query": "Fırat Nehri, Yavuzeli, Gaziantep"}, {"title": "Yavuzeli Merkez Camii", "summary": "İlçenin merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Hem ibadet hem de kültürel ziyaret için önemli bir noktadır.", "place_query": "Yavuzeli Merkez Camii, Yavuzeli, Gaziantep"}, {"title": "Yavuzeli Antik Kenti (Doliche)", "summary": "Yavuzeli sınırları içinde yer alan antik Doliche kenti, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklıları için eşsiz bir keşif alanı sunar. Zeus Dolichenus kültüyle de bilinir.", "place_query": "Doliche Antik Kenti, Yavuzeli, Gaziantep"}, {"title": "Yavuzeli Yaylaları (Örnek: Sof Dağı)", "summary": "Bölgenin serin yaylaları, özellikle yaz aylarında doğa yürüyüşleri ve kamp için popülerdir. Sof Dağı eteklerindeki yeşil alanlar, şehir gürültüsünden uzaklaşmak isteyenler için idealdir.", "place_query": "Sof Dağı, Yavuzeli, Gaziantep"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd100b48f-3252-4d50-b235-caf8fb3137c3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alucra Yaylaları (Karaköy Yaylası, Karadağ Yaylası)", "summary": "Alucra''nın en önemli doğal zenginliklerinden olan yaylalar, yemyeşil ormanlar ve temiz havasıyla ünlüdür. Karaköy ve Karadağ yaylaları özellikle yaz aylarında doğa yürüyüşleri ve kamp için ideal, huzur dolu kaçış noktalarıdır.", "place_query": "Alucra Yaylaları, Giresun"}, {"title": "Şebinkarahisar Kalesi", "summary": "Alucra''ya yaklaşık 30 km uzaklıktaki bu tarihi kale, bölgeye hakim bir tepe üzerinde yer alır. Roma ve Bizans dönemlerinden kalma kaleyi ziyaret ederek hem tarihe tanıklık edebilir hem de muhteşem bir manzara izleyebilirsiniz.", "place_query": "Şebinkarahisar Kalesi, Giresun"}, {"title": "Alucra Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Sade ve etkileyici yapısıyla ziyaretçilerin ilgisini çeker ve manevi bir atmosfer sunar.", "place_query": "Alucra Merkez Camii, Giresun"}, {"title": "Alucra Kaya Mezarları", "summary": "İlçe çevresinde bulunan antik döneme ait kaya mezarları, bölgenin tarih öncesi yerleşimine ışık tutar. Doğal kaya oluşumları içine oyulmuş bu mezarlar, tarih meraklıları için keşfedilmeyi bekleyen birer hazinedir.", "place_query": "Alucra Kaya Mezarları, Giresun"}, {"title": "Alucra Gölleri (Karagöl, Akgöl)", "summary": "Yüksek rakımlı bölgelerde yer alan bu buzul gölleri, doğa tutkunları için eşsiz bir manzara sunar. Berrak suları ve çevresindeki zengin bitki örtüsüyle trekking ve fotoğrafçılık için popüler duraklardır.", "place_query": "Alucra Gölleri, Giresun"}, {"title": "Kümbet Yaylası", "summary": "Alucra''ya yaklaşık 40 km uzaklıkta bulunan Kümbet Yaylası, Giresun''un en bilinen yaylalarındandır. Geniş düzlükleri, ahşap evleri ve geleneksel yayla şenlikleriyle ünlüdür; doğa yürüyüşü ve yöresel lezzetler için idealdir.", "place_query": "Kümbet Yaylası, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '762f3767-a436-4632-82e4-3513878cd5df'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bulancak Sahili ve Yürüyüş Yolu", "summary": "Uzun sahil şeridi ve modern yürüyüş yoluyla Bulancak''ın en popüler dinlenme ve gezinti alanıdır. Deniz manzarası eşliğinde yürüyüş yapabilir, kafelerde vakit geçirebilirsiniz.", "place_query": "Bulancak Sahili, Bulancak, Giresun"}, {"title": "Kovuk Dağı", "summary": "Doğa yürüyüşleri ve kamp için ideal olan bu dağ, eşsiz Karadeniz manzaraları sunar. Özellikle yaz aylarında doğaseverlerin uğrak noktasıdır.", "place_query": "Kovuk Dağı, Bulancak, Giresun"}, {"title": "Bulancak Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin satıldığı bu kapalı pazar, hem alışveriş hem de kültürel deneyim için önemli bir duraktır. Taze fındık, mısır ekmeği ve yöresel peynirler bulabilirsiniz.", "place_query": "Bulancak Kapalı Pazar Yeri, Bulancak, Giresun"}, {"title": "Giresun Adası (Aretias Adası)", "summary": "Bulancak''a yaklaşık 30 km mesafedeki bu tarihi ada, Karadeniz''in tek yerleşime açık adasıdır. Antik kalıntıları, doğal güzelliği ve piknik alanlarıyla ünlüdür.", "place_query": "Giresun Adası, Giresun Merkez"}, {"title": "Kümbet Yaylası", "summary": "Bulancak sınırları içinde yer alan bu yayla, yemyeşil doğası ve geleneksel yayla evleriyle huzurlu bir kaçış noktasıdır. Yaz aylarında düzenlenen şenlikleriyle de bilinir.", "place_query": "Kümbet Yaylası, Bulancak, Giresun"}, {"title": "Hacı Abdullah Dağı ve Seyir Terası", "summary": "Bölgenin en yüksek noktalarından biri olan bu dağ, Bulancak ve Giresun Körfezi''nin panoramik manzarasını sunar. Gün doğumu ve gün batımı fotoğrafları için idealdir.", "place_query": "Hacı Abdullah Dağı, Bulancak, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9d3ff53c-072d-4490-8c43-8f152b03662d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamoluk Şelalesi", "summary": "İlçenin en bilinen doğal güzelliği olan bu şelale, yeşil örtüyle çevrili yemyeşil bir vadide yer alır ve özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyen ziyaretçilerin uğrak noktasıdır.", "place_query": "Çamoluk Şelalesi, Çamoluk, Giresun"}, {"title": "Çamoluk Kalesi", "summary": "Tarihi bir kale olup ilçe merkezine hakim bir tepede konumlanmıştır; bölgenin stratejik önemini yansıtan bu yapı, aynı zamanda çevreye karşı muhteşem bir manzara sunar.", "place_query": "Çamoluk Kalesi, Çamoluk, Giresun"}, {"title": "Çamoluk Yaylası", "summary": "Doğu Karadeniz''in tipik yaylalarından biri olan bu bölge, zengin bitki örtüsü, temiz havası ve geleneksel yayla kültürüyle doğa yürüyüşü ve kamp için idealdir.", "place_query": "Çamoluk Yaylası, Çamoluk, Giresun"}, {"title": "Çamoluk Göleti", "summary": "Sakin ve huzurlu bir ortam arayanlar için biçilmiş kaftan olan bu gölet, piknik alanları ve çevresindeki yürüyüş yollarıyla ailelerin ve doğa severlerin tercih ettiği bir dinlenme noktasıdır.", "place_query": "Çamoluk Göleti, Çamoluk, Giresun"}, {"title": "Kale Tepesi Seyir Noktası", "summary": "Çamoluk Kalesi''nin bulunduğu tepe, ilçe merkezini ve çevredeki vadileri kuşbakışı görmek için en iyi noktalardan biridir; özellikle gün batımında eşsiz fotoğraf kareleri yakalanabilir.", "place_query": "Kale Tepesi, Çamoluk, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3e0b186d-b092-4086-98d1-080e914e88e4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çanakçı Yaylaları (Kümbet, Bektaş, Kulakkaya)", "summary": "Karadeniz''in en yeşil yaylalarına ev sahipliği yapan Çanakçı, özellikle Kümbet, Bektaş ve Kulakkaya yaylalarıyla ünlüdür. Doğa yürüyüşleri, yayla şenlikleri ve muhteşem manzaralar eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Kümbet Yaylası, Çanakçı, Giresun"}, {"title": "Çanakçı Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, yemyeşil doğa içinde serinletici bir kaçış noktasıdır. Özellikle yaz aylarında piknik ve fotoğrafçılık için idealdir.", "place_query": "Çanakçı Şelalesi, Giresun"}, {"title": "Kale (Çanakçı Kalesi)", "summary": "Tarihi bir kalıntı olan Çanakçı Kalesi, ilçeye hakim bir tepede yer alır. Çevresindeki doğal dokuyla birlikte hem tarih hem de manzara meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Çanakçı Kalesi, Giresun"}, {"title": "Sis Dağı Yaylası", "summary": "Çanakçı sınırları içinde yer alan Sis Dağı Yaylası, yüksek rakımı ve bakir doğasıyla dikkat çeker. Yayla turizmi ve kamp yapmak isteyenler için sakin bir alternatiftir.", "place_query": "Sis Dağı Yaylası, Çanakçı, Giresun"}, {"title": "Kümbet Yaylası", "summary": "Giresun''un en popüler yaylalarından biri olan Kümbet Yaylası, Çanakçı ilçesi sınırlarındadır. Her yıl düzenlenen Kümbet Yayla Şenlikleri ve doğal güzellikleriyle ziyaretçilerini cezbeder.", "place_query": "Kümbet Yaylası, Çanakçı, Giresun"}, {"title": "Bektaş Yaylası", "summary": "Çanakçı''ya bağlı Bektaş Yaylası, zengin flora ve faunası ile doğa severlerin uğrak noktasıdır. Yayla evleri ve temiz havasıyla dinlenmek isteyenler için harika bir seçenektir.", "place_query": "Bektaş Yaylası, Çanakçı, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9e9e51c1-e411-4ff6-bdc0-9a873a860731'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kümbet Yaylası", "summary": "Giresun''un en ünlü yaylalarından biri olan Kümbet, yemyeşil doğası, geleneksel yayla evleri ve her yıl düzenlenen Kümbet Yayla Şenlikleri ile ziyaretçilerine eşsiz bir kültürel ve doğal deneyim sunar.", "place_query": "Kümbet Yaylası, Dereli, Giresun"}, {"title": "Kulakkaya Yaylası", "summary": "Dereli sınırları içinde yer alan Kulakkaya Yaylası, yüksek rakımı ve çam ormanlarıyla çevrili huzur veren atmosferiyle doğa yürüyüşü ve kamp için ideal bir noktadır.", "place_query": "Kulakkaya Yaylası, Dereli, Giresun"}, {"title": "Giresun Adası", "summary": "Karadeniz''in tek yerleşime açık adası olan Giresun Adası, antik kalıntıları ve doğal güzelliğiyle tekne turlarının vazgeçilmez durağıdır; özellikle bahar aylarında adayı süsleyen gelincik çiçekleriyle ünlüdür.", "place_query": "Giresun Adası, Giresun Merkez"}, {"title": "Mavigöl (Karagöl)", "summary": "Dereli ilçesine bağlı Bektaş Yaylası yakınlarında bulunan Mavigöl, berrak turkuaz suları ve çevresindeki sık ormanlarla görenleri büyüleyen doğal bir krater gölüdür.", "place_query": "Mavigöl Karagöl, Dereli, Giresun"}, {"title": "Bektaş Yaylası", "summary": "Dereli''nin en popüler yaylalarından Bektaş, yıl boyunca düzenlenen festivalleri, yöresel ürün pazarları ve nefis manzarasıyla hem yerli hem yabancı turistlerin uğrak noktasıdır.", "place_query": "Bektaş Yaylası, Dereli, Giresun"}, {"title": "Tamzara Şelalesi", "summary": "Dereli ilçe merkezine birkaç kilometre uzaklıktaki Tamzara Şelalesi, 30 metre yüksekten dökülen suları ve çevresindeki piknik alanlarıyla serinlemek ve doğayla baş başa kalmak için harika bir yerdir.", "place_query": "Tamzara Şelalesi, Dereli, Giresun"}, {"title": "Giresun Kalesi", "summary": "Şehir merkezine hakim bir tepede bulunan Giresun Kalesi, Roma ve Bizans dönemlerinden kalma surları ve kalıntılarıyla tarihe tanıklık ederken, aynı zamanda eşsiz bir şehir ve deniz manzarası sunar.", "place_query": "Giresun Kalesi, Giresun Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dc1d9d17-a1ce-425e-a51f-5b5c5116c85e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Doğankent Yaylası", "summary": "Doğankent''in en popüler doğal alanlarından biri olan yayla, yeşilin her tonunu görebileceğiniz, temiz havası ve muhteşem manzarasıyla huzur verici bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için idealdir.", "place_query": "Doğankent Yaylası, Doğankent, Giresun"}, {"title": "Karahasan Şelalesi", "summary": "Doğankent sınırları içerisinde yer alan bu şelale, etkileyici su sesi ve çevresindeki sık ormanlık alanla doğa severler için görülmeye değer bir duraktır. Piknik ve fotoğrafçılık için de uygun bir ortam sunar.", "place_query": "Karahasan Şelalesi, Doğankent, Giresun"}, {"title": "Doğankent Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, mimarisi ve manevi atmosferiyle dikkat çeker. Bölge halkı için önemli bir ibadet ve buluşma noktasıdır.", "place_query": "Doğankent Merkez Camii, Doğankent, Giresun"}, {"title": "Giresun Doğankent Göleti", "summary": "Doğankent''in yakınlarında bulunan bu yapay gölet, çevresindeki yeşil alanlarla birlikte piknik ve yürüyüş için sakin bir ortam sağlar. Su manzarası eşliğinde dinlenmek isteyenler için idealdir.", "place_query": "Doğankent Göleti, Doğankent, Giresun"}, {"title": "Doğankent Çarşı ve Pazar Yeri", "summary": "İlçenin kalbi sayılabilecek bu bölge, yerel halkın alışveriş yaptığı ve yöresel ürünlerin satıldığı canlı bir noktadır. Özellikle pazar günleri kurulan pazarda yöresel lezzetleri ve el sanatlarını bulabilirsiniz.", "place_query": "Doğankent Pazar Yeri, Doğankent, Giresun"}, {"title": "Çambaşı Yaylası (Doğankent yolu üzeri)", "summary": "Doğankent''e yakın mesafedeki bu yayla, yemyeşil doğası ve geleneksel yayla evleriyle ünlüdür. Doğa yürüyüşleri ve kamp için popüler bir destinasyondur.", "place_query": "Çambaşı Yaylası, Doğankent, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9dbaa651-c4ea-41e7-bccc-9d05558a0b14'::uuid;
