UPDATE location_pages SET travel_ideas_json = '[{"title": "Eynesil Kalesi", "summary": "Denize nazır bir tepede yer alan tarihi kale, bölgenin en önemli simgelerindendir. Ziyaretçilerine hem tarihi bir yolculuk hem de muhteşem Karadeniz manzarası sunar.", "place_query": "Eynesil Kalesi, Eynesil, Giresun"}, {"title": "Eynesil Plajı", "summary": "Uzun ve geniş kumsalıyla ilçenin en popüler serinleme ve dinlenme noktasıdır. Özellikle yaz aylarında yerli halk ve turistler tarafından yoğun ilgi görür.", "place_query": "Eynesil Plajı, Eynesil, Giresun"}, {"title": "Görele-Eynesil Sahil Yolu", "summary": "Karadeniz''in eşsiz yeşili ile mavisini bir arada sunan bu sahil yolu, manzara fotoğrafçılığı ve keyifli sürüşler için idealdir. Yol boyunca birçok seyir noktası bulunur.", "place_query": "Görele Eynesil Sahil Yolu, Giresun"}, {"title": "Eynesil Merkez Cami", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Hem ibadet hem de kültürel ziyaretler için önemli bir duraktır.", "place_query": "Eynesil Merkez Cami, Eynesil, Giresun"}, {"title": "Eynesil Çay Bahçeleri", "summary": "Karadeniz''e özgü yeşil çay bahçeleri arasında huzur dolu bir mola vermek isteyenler için ideal mekanlardır. Yöresel çayın tadına bakmak ve doğayla iç içe vakit geçirmek mümkündür.", "place_query": "Eynesil Çay Bahçeleri, Eynesil, Giresun"}, {"title": "Eynesil Yaylaları", "summary": "İlçenin yüksek kesimlerinde yer alan yaylalar, serin havası ve doğal güzellikleriyle özellikle yaz aylarında kaçış noktasıdır. Yürüyüş ve piknik için idealdir.", "place_query": "Eynesil Yaylaları, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e1116388-0e85-41f8-84d7-cd7246ab3410'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Görele Kalesi", "summary": "Tarihi bir Bizans kalesi olan yapı, şehir merkezine hakim bir tepede yer alır. Görele ve deniz manzarası eşliğinde tarihi bir atmosfer sunar.", "place_query": "Görele Kalesi, Görele, Giresun"}, {"title": "Kale Meydanı ve Atatürk Anıtı", "summary": "İlçenin merkezi noktası olan meydan, çevresindeki kafeler ve Atatürk Anıtı ile hem yerel halkın hem de ziyaretçilerin buluşma noktasıdır.", "place_query": "Kale Meydanı, Görele, Giresun"}, {"title": "Görele Sahili ve Yürüyüş Yolu", "summary": "Karadeniz''in serin sularına paralel uzanan sahil şeridi, yürüyüş yolu ve banklarıyla dinlenmek ve deniz havası almak için ideal bir yerdir.", "place_query": "Görele Sahili, Görele, Giresun"}, {"title": "Görele Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgenin tarihi eserlerini ve etnografik objelerini sergileyerek kültürel bir durak sunar.", "place_query": "Görele Müzesi, Görele, Giresun"}, {"title": "Çavuşlu Köyü Yaylası", "summary": "Görele''ye bağlı yaylalardan biri olan Çavuşlu, yeşil doğası ve temiz havasıyla doğa yürüyüşleri ve piknik için popüler bir kaçış noktasıdır.", "place_query": "Çavuşlu Köyü Yaylası, Görele, Giresun"}, {"title": "Görele Fındık Bahçeleri", "summary": "Giresun''un meşhur fındığının yetiştiği bahçeler, ilçe genelinde yaygındır ve ziyaretçilere fındık hasadı ve kırsal yaşamı deneyimleme fırsatı verir.", "place_query": "Görele Fındık Bahçeleri, Görele, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '92de3e47-73aa-4a8a-8718-eb1829ca7107'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güce Yaylası", "summary": "Doğal güzelliği ve temiz havasıyla ünlü olan Güce Yaylası, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyen ziyaretçilerin uğrak noktasıdır. Yemyeşil çayırları ve manzarasıyla huzur verici bir atmosfer sunar.", "place_query": "Güce Yaylası, Güce, Giresun"}, {"title": "Kümbet Yaylası", "summary": "Giresun''un en meşhur yaylalarından biri olan Kümbet Yaylası, Güce ilçesine yakın konumuyla da bilinir. Geleneksel yayla şenliklerine ev sahipliği yapan bu yer, zengin bitki örtüsü ve muhteşem doğasıyla fotoğrafçıların ve doğaseverlerin ilgisini çeker.", "place_query": "Kümbet Yaylası, Giresun"}, {"title": "Güce Şelalesi", "summary": "İlçe merkezine yakın bir konumda yer alan Güce Şelalesi, doğal yapısı ve çevresindeki yeşil alanlarla piknik ve doğa gezileri için idealdir. Şelalenin serin suları ve sesi, ziyaretçilere huzurlu bir kaçamak sunar.", "place_query": "Güce Şelalesi, Güce, Giresun"}, {"title": "Güce Merkez Camii ve Tarihi Çeşme", "summary": "İlçenin tarihi dokusunu yansıtan Güce Merkez Camii ve yanındaki tarihi çeşme, mimarisiyle dikkat çeker. Bölgenin kültürel mirasını yakından görmek isteyen ziyaretçiler için önemli bir duraktır.", "place_query": "Güce Merkez Camii, Güce, Giresun"}, {"title": "Karasu Deresi", "summary": "Güce''den geçen Karasu Deresi, çevresindeki yürüyüş parkurları ve doğal güzellikleriyle öne çıkar. Özellikle ilkbahar ve yaz aylarında dere kenarında yapılan doğa yürüyüşleri, ziyaretçilere keyifli anlar yaşatır.", "place_query": "Karasu Deresi, Güce, Giresun"}, {"title": "Güce Yöresel Pazarı", "summary": "Haftanın belirli günlerinde kurulan Güce Yöresel Pazarı, yöresel ürünlerin ve el sanatlarının satıldığı canlı bir alışveriş noktasıdır. Ziyaretçiler burada taze meyve, sebze ve yöresel lezzetleri bulabilir, bölgenin kültürünü yakından tanıyabilir.", "place_query": "Güce Pazarı, Güce, Giresun"}, {"title": "Güce Kalesi", "summary": "Tarihi bir kalıntı olan Güce Kalesi, ilçenin yüksek bir noktasında yer alır ve çevreye hakim bir manzara sunar. Kalıntılar arasında yapılacak bir gezi, bölgenin tarihine dair ipuçları verir ve fotoğrafçılık için idealdir.", "place_query": "Güce Kalesi, Güce, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c197257e-cd57-447c-9a2b-5026e8af5c8a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Keşap Kalesi", "summary": "Tarihi bir kalenin bulunduğu bu tepe, Keşap manzarasının en güzel izlendiği noktalardan biridir. Ziyaretçiler hem tarihi dokuyu keşfeder hem de doğa ile iç içe bir gün geçirebilir.", "place_query": "Keşap Kalesi, Keşap, Giresun"}, {"title": "Yolağzı Plajı", "summary": "Keşap''ın en popüler plajlarından biri olan Yolağzı, ince kumlu sahili ve temiz deniziyle yaz aylarında yerli halkın ve turistlerin uğrak noktasıdır.", "place_query": "Yolağzı Plajı, Keşap, Giresun"}, {"title": "Keşap Sahili ve Yürüyüş Yolu", "summary": "Keşap merkezde yer alan sahil şeridi, deniz kenarında yürüyüş yapmak ve gün batımını izlemek için idealdir. Çevresindeki kafe ve parklarla dinlendirici bir atmosfer sunar.", "place_query": "Keşap Sahili, Keşap, Giresun"}, {"title": "Duroğlu Yaylası", "summary": "Keşap sınırları içinde yer alan bu yayla, yeşilin her tonunu barındıran doğası ve serin havasıyla doğa yürüyüşü ve piknik için tercih edilen bir mekandır.", "place_query": "Duroğlu Yaylası, Keşap, Giresun"}, {"title": "Keşap Merkez Camii", "summary": "Osmanlı dönemi mimarisini yansıtan tarihi cami, ilçenin merkezinde yer alır ve hem ibadet hem de tarihi yapı meraklıları için önemli bir duraktır.", "place_query": "Keşap Merkez Camii, Keşap, Giresun"}, {"title": "Çamlıca Şelalesi", "summary": "Keşap''a bağlı köylerde bulunan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla huzur verici bir kaçış noktasıdır. Özellikle bahar aylarında su akışı artar.", "place_query": "Çamlıca Şelalesi, Keşap, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8f26784f-d604-4e57-a4fb-efd731827a24'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Giresun Kalesi", "summary": "Şehre hakim bir tepe üzerinde yer alan tarihi kale, muhteşem manzarası ve Bizans döneminden kalma yapısıyla ziyaretçilerin ilk durağıdır. İçinde seyir terasları, kafeterya ve piknik alanları bulunur.", "place_query": "Giresun Kalesi, Giresun Merkez"}, {"title": "Giresun Adası", "summary": "Karadeniz''in tek yerleşime açık adası olan bu doğal güzellik, tekne turlarıyla ulaşılan sakin koyları ve endemik bitki örtüsüyle ünlüdür. Antik çağ kalıntıları ve piknik alanları da bulunur.", "place_query": "Giresun Adası, Giresun Merkez"}, {"title": "Göksu Travertenleri", "summary": "Şehir merkezine yaklaşık 20 km uzaklıktaki bu beyaz travertenler, doğal havuzları ve şelaleleriyle serinlemek ve fotoğraf çekmek için ideal bir noktadır. Özellikle yaz aylarında yoğun ilgi görür.", "place_query": "Göksu Travertenleri, Giresun"}, {"title": "Giresun Müzesi (Gogora Kilisesi)", "summary": "Eski bir Rum kilisesi olan yapı, günümüzde arkeolojik ve etnografik eserlerin sergilendiği bir müze olarak hizmet verir. Taş işçiliği ve tarihi atmosferiyle dikkat çeker.", "place_query": "Giresun Müzesi, Giresun Merkez"}, {"title": "Kümbet Yaylası", "summary": "Giresun''un en popüler yaylalarından biri olan Kümbet, yeşil doğası, yayla evleri ve her yıl düzenlenen festivalleriyle ünlüdür. Doğa yürüyüşleri ve yöresel lezzetler için ideal bir duraktır.", "place_query": "Kümbet Yaylası, Giresun"}, {"title": "Espiye Şehitler Çay Bahçesi ve Sahil Yolu", "summary": "Merkeze bağlı olmasa da yakın çevredeki bu sahil bandı, yürüyüş yolu, çay bahçeleri ve deniz manzarasıyla yerel halkın uğrak noktasıdır. Özellikle gün batımında keyifli bir atmosfer sunar.", "place_query": "Espiye Sahil Yolu, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1ad9533e-8cf0-481f-8d4f-61b9bd1f74ad'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Piraziz Sahili", "summary": "Giresun''un en güzel sahil şeritlerinden biri olan Piraziz Sahili, yürüyüş yapmak ve deniz manzarası eşliğinde dinlenmek için idealdir. Özellikle yaz akşamlarında halkın uğrak noktasıdır.", "place_query": "Piraziz Sahili, Piraziz, Giresun"}, {"title": "Piraziz Kalesi", "summary": "Tarihi bir kalıntı olan Piraziz Kalesi, bölgenin geçmişine ışık tutar ve tepeden muhteşem bir Karadeniz manzarası sunar. Tarih ve doğayı bir arada görmek isteyenler için güzel bir duraktır.", "place_query": "Piraziz Kalesi, Piraziz, Giresun"}, {"title": "Görele-Piraziz Yolu Sahil Şeridi", "summary": "Piraziz ile Görele arasındaki bu sahil yolu, yeşil ve mavinin buluştuğu manzaralarıyla ünlüdür. Araçla veya yürüyerek keyifli bir gezi rotası sunar.", "place_query": "Görele Piraziz yolu sahil şeridi, Giresun"}, {"title": "Piraziz Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de kültürel geziler için ziyaret edilebilir.", "place_query": "Piraziz Merkez Camii, Piraziz, Giresun"}, {"title": "Piraziz Yaylaları (Bozat Yaylası)", "summary": "Piraziz''e bağlı yaylalar arasında yer alan Bozat Yaylası, serin havası ve doğal güzellikleriyle öne çıkar. Doğa yürüyüşleri ve piknik için tercih edilen bir mekandır.", "place_query": "Bozat Yaylası, Piraziz, Giresun"}, {"title": "Piraziz Fındık Bahçeleri", "summary": "Giresun''un meşhur fındık üretiminin kalbinde yer alan Piraziz''deki fındık bahçeleri, yeşilin her tonunu görmek isteyenler için eşsiz bir doğa deneyimi sunar. Hasat döneminde bölgeyi ziyaret etmek ayrı bir keyiftir.", "place_query": "Piraziz fındık bahçeleri, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1cc5e033-0bae-4c3e-9da3-14b2a4b9279a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şebinkarahisar Kalesi", "summary": "Şehrin simgesi olan bu tarihi kale, muhteşem manzarası ve surlarıyla ziyaretçilerini büyüler. Kale içinde gezerken hem tarihe tanıklık eder hem de Giresun''un eşsiz doğasını kuşbakışı izleyebilirsiniz.", "place_query": "Şebinkarahisar Kalesi, Şebinkarahisar, Giresun"}, {"title": "Tamzara (Avutmuş) Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla ünlü bu şelale, piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle yaz aylarında şelalenin çevresindeki yeşillikler huzur verici bir atmosfer sunar.", "place_query": "Tamzara Şelalesi, Şebinkarahisar, Giresun"}, {"title": "Büyük Cami (Kurşunlu Cami)", "summary": "Osmanlı döneminden kalma bu tarihi cami, mimarisi ve taş işçiliğiyle dikkat çeker. Şebinkarahisar''ın en eski yapılarından biri olup, ibadet ve ziyaret için önemli bir duraktır.", "place_query": "Büyük Cami Şebinkarahisar, Giresun"}, {"title": "Şebinkarahisar Kapalı Çarşısı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu tarihi çarşı, alışveriş ve kültürel deneyim için idealdir. Burada yöresel lezzetleri tadabilir, şehrin dokusunu yakından hissedebilirsiniz.", "place_query": "Şebinkarahisar Kapalı Çarşı, Giresun"}, {"title": "Kale Mahallesi Tarihi Evleri", "summary": "Osmanlı ve geleneksel Karadeniz mimarisinin güzel örneklerini sergileyen bu evler, dar sokakları ve ahşap yapılarıyla fotoğrafçılar için harika bir mekandır. Tarihi atmosferde keyifli bir yürüyüş yapabilirsiniz.", "place_query": "Kale Mahallesi Tarihi Evler, Şebinkarahisar, Giresun"}, {"title": "Karagöl Tabiat Parkı", "summary": "Şebinkarahisar''a yaklaşık 30 km uzaklıktaki bu krater gölü, çam ormanları ve temiz havasıyla doğa severlerin uğrak noktasıdır. Göl çevresinde kamp yapabilir, yürüyüş rotalarını keşfedebilirsiniz.", "place_query": "Karagöl Tabiat Parkı, Şebinkarahisar, Giresun"}, {"title": "İstiklal Çeşmesi", "summary": "Şebinkarahisar''ın merkezinde yer alan bu tarihi çeşme, Kurtuluş Savaşı dönemine ait önemli bir anıttır. Şehrin kültürel mirasını yansıtan bu yapı, kısa bir mola vermek için uygun bir duraktır.", "place_query": "İstiklal Çeşmesi, Şebinkarahisar, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b39cbf57-d013-411e-b423-41216cdf8f7f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tirebolu Kalesi", "summary": "Deniz kenarında yükselen tarihi bir kaledir. Karadeniz''in eşsiz manzarasını seyredip bölgenin savunma tarihine tanıklık edebilirsiniz.", "place_query": "Tirebolu Kalesi, Tirebolu, Giresun"}, {"title": "Hacı Hüseyin Camii", "summary": "Tirebolu''nun en önemli tarihi camilerinden biridir. Osmanlı dönemi mimarisinin güzel bir örneği olarak ziyaretçilerini bekliyor.", "place_query": "Hacı Hüseyin Camii, Tirebolu, Giresun"}, {"title": "Çamlıbel Plajı", "summary": "Tirebolu''nun en popüler plajıdır. Temiz denizi ve ince kumlu sahiliyle yaz aylarında yerli ve yabancı turistlerin uğrak noktasıdır.", "place_query": "Çamlıbel Plajı, Tirebolu, Giresun"}, {"title": "Giresun Adası", "summary": "Tirebolu''ya yaklaşık 20 km mesafede bulunan bu ada, Karadeniz''in tek adası olma özelliğini taşır. Antik kalıntıları ve doğal güzelliğiyle keşfedilmeyi bekliyor.", "place_query": "Giresun Adası, Giresun"}, {"title": "Sis Dağı Yaylası", "summary": "Tirebolu''nun yüksek kesimlerinde yer alan bu yayla, yemyeşil doğası ve temiz havasıyla doğa yürüyüşü ve kamp için idealdir.", "place_query": "Sis Dağı Yaylası, Tirebolu, Giresun"}, {"title": "Tirebolu Müzesi", "summary": "Bölgenin tarihini ve kültürünü yansıtan eserlerin sergilendiği küçük ama zengin bir müzedir. Arkeolojik ve etnografik koleksiyonlarıyla dikkat çeker.", "place_query": "Tirebolu Müzesi, Tirebolu, Giresun"}, {"title": "Küçük Manastır (Panagia Theotokos Manastırı)", "summary": "Tirebolu sınırları içinde yer alan tarihi bir Rum manastırıdır. Doğayla iç içe konumu ve mistik atmosferiyle fotoğrafçılar ve tarih meraklıları için özel bir duraktır.", "place_query": "Küçük Manastır, Tirebolu, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f88313de-89fe-40b7-9bec-573af70f72d4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yağlıdere Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için ideal bir noktadır.", "place_query": "Yağlıdere Şelalesi, Yağlıdere, Giresun"}, {"title": "Kümbet Yaylası", "summary": "Giresun''un en popüler yaylalarından biri olan Kümbet, muhteşem manzarası, serin havası ve geleneksel yayla evleriyle ünlüdür; özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Kümbet Yaylası, Dereli, Giresun"}, {"title": "Yağlıdere Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneği olup, dini ve kültürel bir ziyaret noktasıdır.", "place_query": "Yağlıdere Merkez Camii, Yağlıdere, Giresun"}, {"title": "Kale (Yağlıdere Kalesi)", "summary": "İlçe sınırları içinde bulunan bu tarihi kale kalıntısı, bölgenin savunma tarihine ışık tutar ve çevresindeki doğal manzara ile dikkat çeker.", "place_query": "Yağlıdere Kalesi, Yağlıdere, Giresun"}, {"title": "Giresun Adası", "summary": "Giresun merkeze yakın olan bu küçük ada, tarihi kalıntıları ve eşsiz deniz manzarasıyla tekne turlarının vazgeçilmez duraklarından biridir.", "place_query": "Giresun Adası, Giresun Merkez, Giresun"}, {"title": "Sis Dağı Yaylası", "summary": "Yağlıdere''ye bağlı yaylalardan biri olan Sis Dağı, zengin bitki örtüsü ve temiz havasıyla doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Sis Dağı Yaylası, Yağlıdere, Giresun"}, {"title": "Yağlıdere Göleti", "summary": "İlçe merkezine yakın bu yapay gölet, piknik alanları ve yürüyüş yollarıyla aileler için sakin bir dinlenme ortamı sunar.", "place_query": "Yağlıdere Göleti, Yağlıdere, Giresun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9259ed7a-c17c-428f-aab1-441e81b48b10'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kaledibi Kanyonu", "summary": "Doğa yürüyüşleri ve kamp için ideal olan bu kanyon, yemyeşil bitki örtüsü ve berrak suyuyla huzurlu bir kaçış noktasıdır. Kanyon boyunca yürüyüş yapabilir, serin sularında yüzebilirsiniz.", "place_query": "Kaledibi Kanyonu, Kelkit, Gümüşhane"}, {"title": "Satala Antik Kenti", "summary": "Roma İmparatorluğu dönemine ait önemli bir lejyoner yerleşimi olan Satala, tarihi kalıntıları ve etkileyici mozaikleriyle ziyaretçilerini geçmişe yolculuğa çıkarıyor. Antik kent, bölgenin en önemli arkeolojik alanlarından biridir.", "place_query": "Satala Antik Kenti, Kelkit, Gümüşhane"}, {"title": "Kelkit Çayı", "summary": "Bölgenin can damarı olan Kelkit Çayı, rafting ve kano gibi su sporları için elverişli parkurlarıyla macera arayanların uğrak noktasıdır. Çayın etrafındaki yeşil alanlar piknik yapmak için de idealdir.", "place_query": "Kelkit Çayı, Kelkit, Gümüşhane"}, {"title": "Kirazlı Yaylası", "summary": "Yemyeşil çayırları, serin havası ve muhteşem doğa manzarasıyla ünlü Kirazlı Yaylası, özellikle yaz aylarında şehir hayatından kaçmak isteyenler için huzurlu bir sığınaktır. Yayla şenlikleri de bölgenin kültürel zenginliğini yansıtır.", "place_query": "Kirazlı Yaylası, Kelkit, Gümüşhane"}, {"title": "Kelkit Taş Köprü", "summary": "Tarihi bir yapı olan Kelkit Taş Köprü, Osmanlı dönemi mimarisini yansıtan zarif yapısıyla fotoğrafçılar ve tarih meraklıları için görülmeye değer bir duraktır. Köprü, Kelkit Çayı üzerinde yer alır.", "place_query": "Kelkit Taş Köprü, Kelkit, Gümüşhane"}, {"title": "Deredolu Mağarası", "summary": "Sarkıt ve dikit oluşumlarıyla dikkat çeken Deredolu Mağarası, doğal güzellikleri ve gizemli atmosferiyle mağara keşfine ilgi duyanlar için etkileyici bir rotadır. Mağara içindeki yürüyüş yolları ziyareti kolaylaştırmaktadır.", "place_query": "Deredolu Mağarası, Kelkit, Gümüşhane"}, {"title": "Gümüşhane Kelkit Müzesi", "summary": "Bölgenin tarihini ve kültürünü yansıtan eserlerin sergilendiği müze, arkeolojik buluntular ve etnografik objelerle zengin bir koleksiyona sahiptir. Ziyaretçilere Kelkit ve çevresinin geçmişi hakkında kapsamlı bilgi sunar.", "place_query": "Gümüşhane Kelkit Müzesi, Kelkit, Gümüşhane"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '337307a0-83c7-4844-8059-b520840b8290'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köse İsmail Bey Camii", "summary": "Köse ilçe merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Ziyaretçiler, huzurlu atmosferi ve taş işçiliğindeki detaylarıyla ilgi çeker.", "place_query": "Köse İsmail Bey Camii, Köse, Gümüşhane"}, {"title": "Köse Kalesi", "summary": "İlçe merkezine hakim bir tepede bulunan tarihi kale kalıntıları, bölgenin stratejik önemini gözler önüne serer. Kaleye tırmananlar, Gümüşhane vadisinin eşsiz manzarasını izleyebilir.", "place_query": "Köse Kalesi, Köse, Gümüşhane"}, {"title": "Tomara Şelalesi", "summary": "Köse ilçe sınırları içinde yer alan Tomara Şelalesi, doğal güzelliği ve serin sularıyla ziyaretçilerine huzurlu bir kaçış sunar. Özellikle yaz aylarında piknik ve doğa yürüyüşü için popüler bir noktadır.", "place_query": "Tomara Şelalesi, Köse, Gümüşhane"}, {"title": "Köse Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü Köse Yaylası, doğa severler için ideal bir kamp ve trekking rotasıdır. Yayla evlerinde konaklayarak yöresel lezzetleri deneyimleyebilirsiniz.", "place_query": "Köse Yaylası, Köse, Gümüşhane"}, {"title": "Köse Taş Köprüsü", "summary": "Tarihi bir Osmanlı köprüsü olan bu yapı, ilçenin simgelerinden biridir. Taş işçiliğinin zarif örneklerinden biri olan köprü, fotoğrafçılar için harika bir karedir.", "place_query": "Köse Taş Köprüsü, Köse, Gümüşhane"}, {"title": "Sarıçiçek Yaylası", "summary": "Köse''ye bağlı Sarıçiçek Yaylası, rengarenk kır çiçekleri ve berrak dereleriyle ünlüdür. Doğa yürüyüşleri ve kamp için sakin bir ortam arayanların uğrak noktasıdır.", "place_query": "Sarıçiçek Yaylası, Köse, Gümüşhane"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4dbb1e28-bd86-4bd0-a8a4-fda58e2b89f6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kürtün Kalesi", "summary": "Tarihi bir Bizans kalesi olan bu yapı, Kürtün ilçe merkezine hakim bir tepede yer alır ve bölgenin tarihi dokusunu yansıtan önemli bir simgedir.", "place_query": "Kürtün Kalesi, Kürtün, Gümüşhane"}, {"title": "Örümcek Ormanı", "summary": "Doğal güzelliği ve zengin bitki örtüsüyle ünlü bu orman, yürüyüş ve doğa fotoğrafçılığı için ideal bir mekandır.", "place_query": "Örümcek Ormanı, Kürtün, Gümüşhane"}, {"title": "Süleymaniye Mahallesi Tarihi Evleri", "summary": "Kürtün''ün eski mahallelerinden birinde bulunan bu geleneksel ahşap evler, yöresel mimarinin güzel örneklerini sunar.", "place_query": "Süleymaniye Mahallesi Tarihi Evleri, Kürtün, Gümüşhane"}, {"title": "Kürtün Yaylaları (Örümcek Yaylası, Erikbeli Yaylası vb.)", "summary": "Yemyeşil doğası ve serin havasıyla özellikle yaz aylarında ziyaretçilerin uğrak noktası olan yaylalar, doğa turizmi için biçilmiş kaftandır.", "place_query": "Örümcek Yaylası, Kürtün, Gümüşhane"}, {"title": "Kürtün Çayı ve Mesire Alanları", "summary": "İlçeden geçen bu akarsu çevresindeki piknik ve mesire alanları, aileler için huzurlu bir kaçış noktasıdır.", "place_query": "Kürtün Çayı Mesire Alanı, Kürtün, Gümüşhane"}, {"title": "Taşköprü Yaylası", "summary": "Yüksek rakımı ve eşsiz manzarasıyla bilinen bu yayla, kampçılar ve doğa severler için popüler bir duraktır.", "place_query": "Taşköprü Yaylası, Kürtün, Gümüşhane"}, {"title": "Kürtün Şelalesi", "summary": "Doğal bir güzellik olan bu şelale, çevresindeki yeşil alanla birlikte ziyaretçilere serinletici bir deneyim sunar.", "place_query": "Kürtün Şelalesi, Kürtün, Gümüşhane"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7fe7b18f-1542-4c75-97a7-f2785eefd564'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Süleymaniye Mahallesi ve Tarihi Evler", "summary": "Gümüşhane''nin en eski yerleşimlerinden biri olan bu mahalle, restore edilmiş tarihi ahşap ve taş evleriyle ünlüdür. Dar sokaklarında yürürken Osmanlı dönemi mimarisini yakından görebilir, yöresel el sanatları ürünleri satın alabilirsiniz.", "place_query": "Süleymaniye Mahallesi, Gümüşhane Merkez"}, {"title": "Gümüşhane Kalesi", "summary": "Şehir merkezine hakim bir tepede yer alan bu tarihi kale, muhteşem bir şehir manzarası sunar. Bizans döneminden kalma yapı, özellikle gün batımında fotoğraf tutkunları için ideal bir noktadır.", "place_query": "Gümüşhane Kalesi, Gümüşhane Merkez"}, {"title": "Tomara Şelalesi Tabiat Parkı", "summary": "Gümüşhane''ye yaklaşık 20 km uzaklıktaki bu şelale, 40 metre yüksekten dökülen suları ve çevresindeki yeşil alanlarıyla doğa severler için popüler bir kaçış noktasıdır. Piknik alanları ve yürüyüş yolları bulunur.", "place_query": "Tomara Şelalesi Tabiat Parkı, Gümüşhane"}, {"title": "Karaca Mağarası", "summary": "Gümüşhane''ye 17 km mesafedeki bu mağara, sarkıt ve dikitleriyle ülkemizin en etkileyici oluşumlarından biridir. İçerisindeki aydınlatma sistemi sayesinde rahatça gezilebilen mağara, yıl boyunca ziyaretçi akınına uğrar.", "place_query": "Karaca Mağarası, Torul, Gümüşhane"}, {"title": "Santa Harabeleri (Yukarı Karasu Vadisi)", "summary": "Gümüşhane merkeze bağlı Dumanlı köyü yakınlarında bulunan bu antik yerleşim, Bizans ve Osmanlı dönemlerine ait kilise, şapel ve konut kalıntılarıyla tarihi bir atmosfer sunar. Doğa yürüyüşü ve tarih meraklıları için eşsiz bir rotadır.", "place_query": "Santa Harabeleri, Dumanlı Köyü, Gümüşhane"}, {"title": "Gümüşhane Müzesi", "summary": "Şehir merkezinde bulunan bu müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Roma, Bizans ve Osmanlı dönemlerine ait eserler ile yöresel kıyafet ve eşyalar burada görülebilir.", "place_query": "Gümüşhane Müzesi, Merkez, Gümüşhane"}, {"title": "Çamlıca Yaylası", "summary": "Gümüşhane merkeze bağlı bu yayla, yemyeşil çayırları ve temiz havasıyla yaz aylarında kampçılar ve doğa yürüyüşçüleri için popüler bir duraktır. Yöresel lezzetlerin tadılabileceği küçük işletmeler de bulunur.", "place_query": "Çamlıca Yaylası, Gümüşhane Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7afd4769-e605-4feb-bc71-a8613bf9fa6a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şiran Karaca Mağarası", "summary": "Bölgenin en önemli turistik noktalarından biri olan Karaca Mağarası, etkileyici sarkıt ve dikitleriyle ünlüdür. Ziyaretçiler, yürüyüş yolları eşliğinde mağaranın büyüleyici doğal oluşumlarını keşfedebilir.", "place_query": "Karaca Mağarası, Şiran, Gümüşhane"}, {"title": "Şiran Erikbaşı Yaylası", "summary": "Yeşilin her tonunu barındıran Erikbaşı Yaylası, doğa yürüyüşleri ve kamp için ideal bir noktadır. Temiz havası ve manzarasıyla ziyaretçilerine huzurlu bir kaçamak sunar.", "place_query": "Erikbaşı Yaylası, Şiran, Gümüşhane"}, {"title": "Tomara Şelalesi", "summary": "Şiran sınırları içinde yer alan Tomara Şelalesi, yemyeşil doğa içinde akan sularıyla görsel bir şölen sunar. Özellikle bahar ve yaz aylarında piknik ve fotoğrafçılık için popüler bir duraktır.", "place_query": "Tomara Şelalesi, Şiran, Gümüşhane"}, {"title": "Şiran Tarihi Taş Köprü", "summary": "Osmanlı döneminden kalma bu tarihi taş köprü, ilçenin simgelerinden biridir. Çevresindeki doğal dokuyla bütünleşen köprü, tarih ve fotoğraf meraklıları için görülmeye değerdir.", "place_query": "Tarihi Taş Köprü, Şiran, Gümüşhane"}, {"title": "Sarıçiçek Yaylası", "summary": "Yüksek rakımı ve çiçeklerle kaplı düzlükleriyle Sarıçiçek Yaylası, doğaseverler için keşfedilmeyi bekleyen bir cennettir. Yayla, geleneksel yaşamı deneyimlemek isteyenlere de eşsiz bir atmosfer sunar.", "place_query": "Sarıçiçek Yaylası, Şiran, Gümüşhane"}, {"title": "Şiran Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, mimari detayları ve huzur veren atmosferiyle dikkat çeker. Ziyaretçiler, caminin iç süslemelerini ve çevresindeki tarihi dokuya tanıklık edebilir.", "place_query": "Merkez Camii, Şiran, Gümüşhane"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c4297874-7fe3-41de-97df-e9d714c2c71f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Torul Kalesi", "summary": "Tarihi İpek Yolu üzerinde yer alan bu ortaçağ kalesi, bölgeye hakim bir tepe üzerinde kurulmuştur. Ziyaretçilerini etkileyici manzarası ve tarihi dokusuyla karşılar.", "place_query": "Torul Kalesi, Torul, Gümüşhane"}, {"title": "Torul Barajı ve Hidroelektrik Santrali", "summary": "Harşit Çayı üzerinde kurulu bu büyük baraj, hem enerji üretimi hem de çevresindeki piknik alanlarıyla ziyaretçilere huzurlu bir doğa kaçamağı sunar. Özellikle baraj gölü manzarası fotoğrafçılar için idealdir.", "place_query": "Torul Barajı, Torul, Gümüşhane"}, {"title": "Kürtün - Torul Karayolu Manzaraları", "summary": "Özellikle sonbaharda sararan yapraklar ve sisle kaplı dağlar eşliğinde yapılan bu yolculuk, Karadeniz''in en güzel manzaralı yollarından birini sunar. Yol üzerinde birçok seyir noktası bulunur.", "place_query": "Kürtün Torul yolu manzara, Gümüşhane"}, {"title": "Satala Antik Kenti", "summary": "Torul ilçe merkezine yaklaşık 30 km uzaklıktaki Sadak Köyü''nde bulunan bu antik kent, Roma İmparatorluğu''nun önemli askeri garnizonlarından biriydi. Kalıntılar arasında surlar, hamam ve tapınak temelleri görülebilir.", "place_query": "Satala Antik Kenti, Sadak Köyü, Gümüşhane"}, {"title": "Torul Yaylaları (Örnek: Kazıkbeli Yaylası)", "summary": "Yemyeşil çayırları, soğuk su kaynakları ve geleneksel yayla evleriyle ünlü bu yaylalar, doğa yürüyüşü ve kamp için idealdir. Özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenlerin uğrak noktasıdır.", "place_query": "Kazıkbeli Yaylası, Torul, Gümüşhane"}, {"title": "Harşit Çayı Vadisi", "summary": "Torul''dan geçen Harşit Çayı''nın oluşturduğu derin vadi, kanyon görünümü ve rafting olanaklarıyla dikkat çeker. Çevresindeki yürüyüş parkurları ve piknik alanlarıyla doğa severler için popüler bir rotadır.", "place_query": "Harşit Çayı Vadisi, Torul, Gümüşhane"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '45e9cfe1-5285-4516-a14e-1aca3231439d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çukurca Merkez Camii ve Tarihi Çarşı", "summary": "İlçe merkezinde yer alan bu cami ve çevresindeki tarihi çarşı, bölgenin kültürel dokusunu yansıtan önemli bir noktadır. Ziyaretçiler hem ibadet edebilir hem de yöresel ürünlerin satıldığı dükkanları gezebilir.", "place_query": "Çukurca Merkez Camii, Hakkari"}, {"title": "Zap Suyu Vadisi", "summary": "Çukurca''dan geçen Zap Suyu''nun oluşturduğu vadi, doğal güzelliği ve yemyeşil manzaralarıyla dikkat çeker. Doğa yürüyüşü ve piknik için ideal bir alandır.", "place_query": "Zap Suyu Vadisi, Çukurca, Hakkari"}, {"title": "Çukurca Kalesi", "summary": "Tarihi bir kale olan Çukurca Kalesi, ilçeye hakim bir tepede yer alır ve bölgenin savunma tarihine ışık tutar. Kaleye çıktığınızda Çukurca''nın panoramik manzarasını izleyebilirsiniz.", "place_query": "Çukurca Kalesi, Hakkari"}, {"title": "Güven Dağı ve Yaylaları", "summary": "Çukurca sınırları içinde bulunan Güven Dağı, özellikle yaz aylarında yaylaları ve serin havasıyla ünlüdür. Doğa sporları ve kampçılık için tercih edilen bir rotadır.", "place_query": "Güven Dağı, Çukurca, Hakkari"}, {"title": "Çukurca Şelalesi", "summary": "İlçe merkezine yakın bir konumda bulunan bu şelale, çevresindeki yeşil alanlarla birlikte doğa severler için huzurlu bir kaçış noktasıdır. Özellikle bahar aylarında suyun debisi artar ve görsel şölen sunar.", "place_query": "Çukurca Şelalesi, Hakkari"}, {"title": "Köprülü Köyü ve Tarihi Taş Köprü", "summary": "Çukurca''ya bağlı Köprülü Köyü''nde bulunan tarihi taş köprü, Osmanlı döneminden kalma bir yapıdır. Köyün doğal atmosferi ve köprünün mimarisi fotoğrafçılar için ilgi çekicidir.", "place_query": "Köprülü Köyü Tarihi Taş Köprü, Çukurca, Hakkari"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '68e3368d-c48d-44a8-9d92-063d701a973d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hakkari Kalesi", "summary": "Şehir merkezinde yüksek bir kayalık üzerinde yer alan tarihi kale, bölgenin en önemli simgelerindendir. Urartu dönemine kadar uzanan geçmişi ve şehre hakim manzarasıyla ziyaretçileri cezbeder.", "place_query": "Hakkari Kalesi, Hakkari Merkez"}, {"title": "Cilo Dağı ve Sat Gölleri", "summary": "Hakkari''nin doğal güzelliklerinin başında gelen Cilo Dağı ve eteklerindeki Sat Gölleri, eşsiz buzul gölleri ve dağ manzaralarıyla doğa tutkunları için adeta bir cennettir. Trekking ve kamp için ideal bir bölgedir.", "place_query": "Sat Gölleri, Hakkari"}, {"title": "Meydan Medresesi", "summary": "Hakkari Merkez''de bulunan tarihi Meydan Medresesi, bölgenin önemli eğitim ve kültür merkezlerinden biri olmuştur. Taş işçiliği ve mimarisiyle dikkat çeken yapı, tarihi atmosferiyle ziyaretçilerini etkiler.", "place_query": "Meydan Medresesi, Hakkari Merkez"}, {"title": "Hakkari Müzesi", "summary": "Şehir merkezinde yer alan müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Urartu, Pers ve Osmanlı dönemlerine ait eserler ile yöresel kıyafet ve eşyalar görülebilir.", "place_query": "Hakkari Müzesi, Merkez, Hakkari"}, {"title": "Zap Vadisi", "summary": "Hakkari Merkez''den geçen Zap Suyu''nun oluşturduğu derin vadi, etkileyici kanyon görüntüsü ve doğal yapısıyla dikkat çeker. Bölgede doğa yürüyüşü yapmak ve fotoğraf çekmek için popüler bir noktadır.", "place_query": "Zap Vadisi, Hakkari"}, {"title": "Durankaya Yaylası", "summary": "Hakkari Merkez''e bağlı Durankaya köyü yakınlarındaki bu yayla, yeşil doğası ve temiz havasıyla yaz aylarında kaçış noktasıdır. Yöresel yaşamı gözlemlemek ve doğa ile baş başa kalmak için idealdir.", "place_query": "Durankaya Yaylası, Hakkari"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b1ba1fbe-b195-4964-ba1d-ee7031759a60'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kelat (Kale) Mağarası", "summary": "Şemdinli''ye bağlı Derecik yakınlarında bulunan bu büyük mağara, tarih öncesi dönemlerden beri yerleşim görmüş olup etkileyici sarkıt ve dikitleriyle doğa ve macera tutkunlarının ilgisini çeker.", "place_query": "Kelat Mağarası, Şemdinli, Hakkari"}, {"title": "Şemdinli Yüksekova Yaylaları (Örneğin: Merga Bütan Yaylası)", "summary": "Bölgenin en yeşil ve serin yaylalarından biri olan Merga Bütan, doğal güzelliği, berrak havası ve göçer kültürünü yakından gözlemleme fırsatı sunar.", "place_query": "Merga Bütan Yaylası, Şemdinli, Hakkari"}, {"title": "Zap Suyu Kenarı ve Mesire Alanları", "summary": "Şemdinli ilçe merkezinden geçen Zap Suyu boyunca uzanan mesire alanları, piknik yapmak ve doğa yürüyüşü için idealdir; özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Zap Suyu, Şemdinli, Hakkari"}, {"title": "Şemdinli Ulu Camii", "summary": "Tarihi bir yapı olan bu cami, yöresel mimari özellikleri ve taş işçiliğiyle dikkat çeker; ilçenin en eski ibadethanelerinden biridir.", "place_query": "Ulu Camii, Şemdinli, Hakkari"}, {"title": "Güzelkonak (Nernek) Köyü ve Tarihi Taş Evler", "summary": "Geleneksel Hakkari taş mimarisinin en güzel örneklerini barındıran bu köy, dar sokakları ve tarihi atmosferiyle fotoğrafçılar ve kültür turizmi sevenler için keşfedilmeyi bekler.", "place_query": "Güzelkonak Köyü, Şemdinli, Hakkari"}, {"title": "Altunsaç (Tiyar) Vadisi", "summary": "Sarp kayalıklar ve yemyeşil bitki örtüsüyle çevrili bu vadi, doğa yürüyüşleri ve kamp için elverişli olup bölgenin en etkileyici doğal manzaralarından birini sunar.", "place_query": "Altunsaç Vadisi, Şemdinli, Hakkari"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'db714960-f13d-4cf0-8e92-dc9d0770bb10'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cilo-Sat Gölleri", "summary": "Türkiye''nin en yüksek dağ göllerinden oluşan bu eşsiz doğa harikası, buzul gölleri ve muhteşem manzaralarıyla trekking ve doğa fotoğrafçılığı için idealdir.", "place_query": "Cilo-Sat Gölleri, Yüksekova, Hakkari"}, {"title": "Reşko Tepesi (Uludoruk Tepesi)", "summary": "Hakkari''nin en yüksek zirvesi olan Reşko Tepesi, zorlu doğa koşulları ve nefes kesen panoramik manzarasıyla dağcılar için popüler bir rotadır.", "place_query": "Reşko Tepesi, Yüksekova, Hakkari"}, {"title": "Yüksekova Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, mimarisi ve huzurlu atmosferiyle ziyaretçilerin ilgisini çeken önemli bir dini yapıdır.", "place_query": "Yüksekova Merkez Camii, Hakkari"}, {"title": "Zap Suyu Vadisi", "summary": "Yüksekova''dan geçen Zap Suyu''nun oluşturduğu bu derin vadi, yemyeşil doğası ve sarp kayalıklarıyla doğa yürüyüşleri ve piknik için tercih edilir.", "place_query": "Zap Suyu Vadisi, Yüksekova, Hakkari"}, {"title": "Berçelan Yaylası", "summary": "Yüksekova''ya yakın bu yayla, serin havası, çiçeklerle kaplı düzlükleri ve geleneksel yayla kültürünü deneyimlemek isteyenler için popüler bir kaçış noktasıdır.", "place_query": "Berçelan Yaylası, Yüksekova, Hakkari"}, {"title": "Köprülü Mağaraları", "summary": "Bölgedeki doğal mağara oluşumları arasında yer alan Köprülü Mağaraları, jeolojik yapısı ve gizemli atmosferiyle macera arayanları cezbeder.", "place_query": "Köprülü Mağaraları, Yüksekova, Hakkari"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '80f30e07-4004-47db-9b75-e43b512cf6aa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "St. Pierre Kilisesi (Aziz Petrus Kilisesi)", "summary": "Hristiyanlık tarihinin en önemli ibadet yerlerinden biri olan bu mağara kilise, Vatikan tarafından kutsal hac yeri ilan edilmiştir. İçindeki mozaikler ve kaya yapısıyla ziyaretçileri etkiler.", "place_query": "St. Pierre Kilisesi, Antakya, Hatay"}, {"title": "Hatay Arkeoloji Müzesi", "summary": "Dünyanın en büyük mozaik koleksiyonuna ev sahipliği yapan müze, özellikle Antik Çağ mozaikleri ve lahitleriyle ünlüdür. Roma ve Bizans dönemine ait eserler görülmeye değerdir.", "place_query": "Hatay Arkeoloji Müzesi, Antakya, Hatay"}, {"title": "Antakya Uzun Çarşı", "summary": "Tarihi İpek Yolu üzerinde yer alan bu kapalı çarşı, baharat, künefe, zeytinyağı sabunu ve el yapımı bakır eşyalarıyla meşhurdur. Yöresel lezzetleri tatmak için ideal bir noktadır.", "place_query": "Antakya Uzun Çarşı, Antakya, Hatay"}, {"title": "Habib-i Neccar Camii", "summary": "Anadolu''nun en eski camilerinden biri olan bu yapı, İslam ve Hristiyanlık açısından kutsal kabul edilen Habib-i Neccar''ın türbesini barındırır. Mimari detayları ve avlusu huzur vericidir.", "place_query": "Habib-i Neccar Camii, Antakya, Hatay"}, {"title": "Antakya Mozaik Hanı", "summary": "Eski bir handan restore edilen bu mekan, mozaik atölyeleri ve hediyelik eşya dükkanlarıyla kültürel bir durak sunar. Ziyaretçiler mozaik yapımını izleyebilir ve satın alabilir.", "place_query": "Antakya Mozaik Hanı, Antakya, Hatay"}, {"title": "Gündüz Kışlası ve Antakya Savunma Şehitliği", "summary": "Hatay''ın anavatana katılışı sırasında önemli rol oynayan bu kışla, tarihi belgeler ve fotoğraflarla dolu bir müze olarak ziyaret edilebilir. Şehitlik bölgesi duygusal bir atmosfer sunar.", "place_query": "Gündüz Kışlası, Antakya, Hatay"}, {"title": "Asi Nehri Kenarı ve Köprüler", "summary": "Antakya''nın simgesi Asi Nehri boyunca yürüyüş yapabilir, tarihi köprüleri (örneğin Roma Köprüsü) görebilirsiniz. Nehir kenarındaki kafelerde dinlenmek keyiflidir.", "place_query": "Asi Nehri, Antakya, Hatay"}, {"title": "Antakya Etnografya Müzesi", "summary": "Hatay''ın zengin kültürel mozaiğini yansıtan bu müze, yöresel kıyafetler, el sanatları ve günlük yaşam objeleriyle ziyaretçilere geçmişe yolculuk yaptırır.", "place_query": "Antakya Etnografya Müzesi, Antakya, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'acd73aef-faa2-459a-966a-8600d2c1e71a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Arsuz Halk Plajı", "summary": "Hatay''ın en popüler sahil şeridi olan Arsuz''da denize girmek için en ideal noktalardan biridir. Uzun kumsalı ve berrak deniziyle yaz aylarında yoğun ilgi görür.", "place_query": "Arsuz Halk Plajı, Arsuz, Hatay"}, {"title": "Uluçınar Sahili", "summary": "Arsuz''un merkezinde yer alan bu sahil, yürüyüş yolu, kafeler ve deniz manzarasıyla hem yerli halkın hem de turistlerin uğrak noktasıdır.", "place_query": "Uluçınar Sahili, Arsuz, Hatay"}, {"title": "Arsuz Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, bölgenin stratejik önemini yansıtır. Ziyaretçilerine hem tarih hem de eşsiz bir deniz manzarası sunar.", "place_query": "Arsuz Kalesi, Arsuz, Hatay"}, {"title": "Piyale Paşa Camii", "summary": "Arsuz''un önemli tarihi yapılarından biri olan cami, Osmanlı dönemi mimarisini yansıtır ve dini turizm açısından ilgi çeker.", "place_query": "Piyale Paşa Camii, Arsuz, Hatay"}, {"title": "Karaali Yaylası", "summary": "Doğa severler için ideal bir kaçış noktası olan yayla, yemyeşil ormanları ve serin havasıyla özellikle yaz aylarında tercih edilir.", "place_query": "Karaali Yaylası, Arsuz, Hatay"}, {"title": "Arsuz Sahil Yürüyüş Yolu", "summary": "Deniz kenarında uzanan bu yürüyüş yolu, gün batımında muhteşem manzaralar sunar ve bisiklet sürmek için de idealdir.", "place_query": "Arsuz Sahil Yürüyüş Yolu, Arsuz, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c7a6d92e-6407-44fe-8289-d6915c8951c3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Belen Geçidi", "summary": "Tarihi İpek Yolu üzerinde bulunan bu geçit, muhteşem manzarası ve serin havasıyla ziyaretçilerine eşsiz bir doğa deneyimi sunar. Özellikle yaz aylarında Hatay''ın sıcağından kaçmak için ideal bir noktadır.", "place_query": "Belen Geçidi, Belen, Hatay"}, {"title": "Sokullu Mehmet Paşa Külliyesi", "summary": "Mimar Sinan''ın eserlerinden biri olan bu külliye, cami, han, hamam ve çarşıdan oluşan tarihi bir komplekstir. Belen''in merkezinde yer alan yapı, Osmanlı mimarisinin güzel bir örneğidir.", "place_query": "Sokullu Mehmet Paşa Külliyesi, Belen, Hatay"}, {"title": "Belen Atik Camii", "summary": "16. yüzyılda inşa edilen bu tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Belen''in en eski yapılarından biri olup hala ibadete açıktır.", "place_query": "Belen Atik Camii, Belen, Hatay"}, {"title": "Güzelyayla Mesire Alanı", "summary": "Belen''in yüksek kesimlerinde yer alan bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için popüler bir duraktır. Çam ormanları ve temiz havasıyla ünlüdür.", "place_query": "Güzelyayla Mesire Alanı, Belen, Hatay"}, {"title": "Belen Şelalesi", "summary": "Nur Dağları''nın eteklerinde gizlenmiş bu şelale, özellikle bahar aylarında coşkun akan suları ve çevresindeki yeşilliklerle huzur verici bir atmosfer sunar. Doğa yürüyüşü sevenler için idealdir.", "place_query": "Belen Şelalesi, Belen, Hatay"}, {"title": "Belen Tarihi Çarşısı", "summary": "Sokullu Mehmet Paşa Külliyesi''nin hemen yanında yer alan bu tarihi çarşı, yöresel ürünler ve el sanatları satan dükkanlarıyla ünlüdür. Ziyaretçiler burada Hatay''a özgü lezzetleri tadabilir ve hediyelik eşyalar alabilir.", "place_query": "Belen Tarihi Çarşısı, Belen, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bbebf64e-0a1d-4712-9d23-5c012154a5d0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Harbiye Şelalesi", "summary": "Antakya''nın serinletici doğal harikası olan Harbiye Şelalesi, çağlayan sesi eşliğinde yemyeşil bitki örtüsü içinde huzur verici bir atmosfer sunar. Şelale çevresindeki kafe ve restoranlarda yöresel lezzetlerin tadını çıkarabilirsiniz.", "place_query": "Harbiye Şelalesi, Defne, Hatay"}, {"title": "Necmi Asfuroğlu Arkeoloji Müzesi", "summary": "Hatay''ın zengin tarihini gözler önüne seren bu modern müze, mozaiklerden heykellere kadar binlerce yıllık esere ev sahipliği yapıyor. Antik dönemlere yolculuk yapmak isteyenler için eşsiz bir durak.", "place_query": "Hatay Arkeoloji Müzesi, Antakya, Hatay"}, {"title": "St. Pierre Kilisesi (Aziz Petrus Kilisesi)", "summary": "Hristiyanlık tarihinin en eski kiliselerinden biri olarak kabul edilen bu mağara kilise, Antakya''nın manevi atmosferini hissettirir. UNESCO Dünya Mirası Geçici Listesi''nde yer alan yapı, hem tarihi hem de dini önemiyle dikkat çeker.", "place_query": "St. Pierre Kilisesi, Antakya, Hatay"}, {"title": "Habib-i Neccar Camii", "summary": "Anadolu''nun en eski camilerinden biri olan Habib-i Neccar, hem Müslümanlar hem de Hristiyanlar için kutsal kabul edilen bir mekandır. Tarihi dokusu ve huzur veren avlusuyla Defne''de mutlaka görülmesi gereken yerlerdendir.", "place_query": "Habib-i Neccar Camii, Antakya, Hatay"}, {"title": "Antakya Mozaik Koleksiyonu (Hatay Arkeoloji Müzesi)", "summary": "Dünyanın en büyük mozaik koleksiyonlarından birine sahip olan müze, özellikle Geç Antik Çağ''dan kalma dev mozaiklerle büyüleyici bir deneyim sunar. Defne''ye sadece birkaç kilometre uzaklıktadır.", "place_query": "Hatay Arkeoloji Müzesi mozaik, Antakya"}, {"title": "İplik Pazarı (Antakya Uzun Çarşı)", "summary": "Antakya''nın tarihi çarşılarından biri olan İplik Pazarı, dar sokakları ve renkli dükkanlarıyla yöresel ürünlerden baharatlara kadar her şeyi bulabileceğiniz bir alışveriş noktasıdır. Defne''ye yakın konumuyla şehir kültürünü keşfetmek için idealdir.", "place_query": "İplik Pazarı, Antakya, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd390cc96-f67a-4871-8d9d-31a483100cb2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çınarlı Caddesi", "summary": "Dörtyol''un kalbi sayılan bu cadde, tarihi çınar ağaçlarıyla kaplıdır ve yöresel lezzetlerin tadılabileceği kafeler, restoranlar ile çarşı alışverişi için idealdir.", "place_query": "Çınarlı Caddesi, Dörtyol, Hatay"}, {"title": "Dörtyol Sahili", "summary": "Akdeniz''in serin sularına kıyısı olan bu sahil, yürüyüş yapmak, denize girmek ve gün batımını izlemek için popüler bir dinlenme noktasıdır.", "place_query": "Dörtyol Sahili, Dörtyol, Hatay"}, {"title": "Payas Kalesi (Sokullu Mehmet Paşa Külliyesi)", "summary": "16. yüzyılda Mimar Sinan tarafından inşa edilen bu tarihi külliye, cami, han, hamam ve kaleden oluşur; Osmanlı dönemi mimarisini yakından görmek isteyenler için önemli bir duraktır.", "place_query": "Payas Kalesi, Dörtyol, Hatay"}, {"title": "Dörtyol Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgenin arkeolojik ve etnografik eserlerini sergileyerek Hatay''ın kültürel geçmişine ışık tutar.", "place_query": "Dörtyol Müzesi, Dörtyol, Hatay"}, {"title": "Kuzuculu Yaylası", "summary": "Şehir merkezine yaklaşık 20 km uzaklıkta bulunan bu yayla, yemyeşil doğası, temiz havası ve piknik alanlarıyla doğaseverler için huzurlu bir kaçış noktasıdır.", "place_query": "Kuzuculu Yaylası, Dörtyol, Hatay"}, {"title": "Dörtyol Tarihi Hamamı", "summary": "Osmanlı döneminden kalma bu tarihi hamam, geleneksel mimarisi ve sıcak suyuyla hem yerli halkın hem de ziyaretçilerin uğrak noktasıdır.", "place_query": "Dörtyol Tarihi Hamamı, Dörtyol, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c07ea73f-8fbd-4b62-a217-e50882e9333d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Erzin Plajı", "summary": "İskenderun Körfezi kıyısında uzanan bu plaj, ince kumu ve sakin deniziyle dinlenmek isteyenler için idealdir. Özellikle yaz aylarında yerli halkın uğrak noktasıdır.", "place_query": "Erzin Plajı, Erzin, Hatay"}, {"title": "Delibekirli Şelalesi", "summary": "Nur Dağları''nın eteklerinde yer alan bu şelale, doğal havuzları ve yeşil çevresiyle piknik ve doğa yürüyüşü için popüler bir yerdir.", "place_query": "Delibekirli Şelalesi, Erzin, Hatay"}, {"title": "Erzin Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, bölgeye hakim bir tepede yer alır ve çevresindeki manzarasıyla dikkat çeker. Kalıntılar arasında gezinti yapmak mümkündür.", "place_query": "Erzin Kalesi, Erzin, Hatay"}, {"title": "Güzeloluk Yaylası", "summary": "Serin havası ve çam ormanlarıyla ünlü bu yayla, özellikle yaz sıcağından kaçmak isteyenler için huzurlu bir kaçış noktasıdır. Yürüyüş parkurları ve mesire alanları bulunur.", "place_query": "Güzeloluk Yaylası, Erzin, Hatay"}, {"title": "Karamanlı Köyü Tarihi Evleri", "summary": "Taş ve ahşap mimarisiyle dikkat çeken bu köy evleri, geleneksel Hatay kültürünü yansıtır. Köy içinde yapılacak bir gezinti, fotoğraf tutkunları için eşsiz kareler sunar.", "place_query": "Karamanlı Köyü, Erzin, Hatay"}, {"title": "Ağırtaş Kanyonu", "summary": "Doğal oluşumu ve etkileyici kaya yapılarıyla bilinen bu kanyon, macera arayanlar için trekking ve keşif rotası olarak öne çıkar. Bölge, zengin bitki örtüsüyle de dikkat çeker.", "place_query": "Ağırtaş Kanyonu, Erzin, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd21fc328-196b-4c37-a736-512dcdac68dd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dörtyol Şelalesi", "summary": "Hassa sınırlarına yakın doğal güzelliğiyle ünlü bir şelaledir. Çevresi piknik alanlarıyla donatılmış olup, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Dörtyol Şelalesi, Hassa, Hatay"}, {"title": "Akbez Yaylası", "summary": "Hassa''nın en bilinen yaylalarından biri olan Akbez, yemyeşil ormanları ve temiz havasıyla doğa yürüyüşleri ve kamp için idealdir. Bölge halkı tarafından yaz aylarında sıkça tercih edilen bir dinlenme alanıdır.", "place_query": "Akbez Yaylası, Hassa, Hatay"}, {"title": "Hassa Kalesi", "summary": "Tarihi bir kalıntı olan Hassa Kalesi, bölgenin geçmişine ışık tutan önemli bir yapıdır. Kalıntıları günümüze ulaşan kale, çevresindeki manzarasıyla da fotoğraf tutkunlarının ilgisini çeker.", "place_query": "Hassa Kalesi, Hassa, Hatay"}, {"title": "Küreci Yaylası", "summary": "Hassa''nın sakin ve huzurlu yaylalarından biri olan Küreci, zengin bitki örtüsü ve serin havasıyla doğaseverler için kaçış noktasıdır. Yaylada geleneksel yayla evleri ve doğal göletler bulunur.", "place_query": "Küreci Yaylası, Hassa, Hatay"}, {"title": "Hassa Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, çevresindeki doğal havuzlar ve yeşil alanlarla piknik ve yüzme imkanı sunar. Özellikle hafta sonları ailelerin uğrak noktasıdır.", "place_query": "Hassa Şelalesi, Hassa, Hatay"}, {"title": "Tepehan Yaylası", "summary": "Hassa''nın yüksek kesimlerinde yer alan Tepehan Yaylası, muhteşem manzarası ve temiz havasıyla ünlüdür. Doğa yürüyüşleri ve kampçılık için elverişli olan yayla, gökyüzü gözlemi için de idealdir.", "place_query": "Tepehan Yaylası, Hassa, Hatay"}, {"title": "Karaağaç Göleti", "summary": "Hassa''da bulunan bu yapay gölet, çevresindeki piknik alanları ve yürüyüş yollarıyla huzurlu bir gün geçirmek için uygundur. Gölet çevresinde balık tutma imkanı da bulunur.", "place_query": "Karaağaç Göleti, Hassa, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e5ef5065-5a16-4d28-bed4-f35934837a42'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Arsuz Plajları", "summary": "İskenderun''un sahil ilçesi Arsuz''da yer alan bu uzun kumsal, berrak denizi ve çam ormanlarıyla çevrili doğal güzelliğiyle ünlüdür. Özellikle yaz aylarında deniz ve kum keyfi yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Arsuz Plajları, Arsuz, Hatay"}, {"title": "İskenderun Sahil Bandı", "summary": "Şehrin kalbinde uzanan bu geniş sahil yolu, yürüyüş ve bisiklet parkurları, kafeleri ve deniz manzarasıyla hem yerel halkın hem de ziyaretçilerin en çok tercih ettiği alanlardandır. Gün batımında eşsiz bir atmosfere sahiptir.", "place_query": "İskenderun Sahil Bandı, İskenderun, Hatay"}, {"title": "Hatay Arkeoloji Müzesi", "summary": "Dünyanın en büyük mozaik koleksiyonuna ev sahipliği yapan bu müze, Antakya ve çevresindeki antik kentlerden çıkarılan eserleri sergiler. Özellikle Geç Antik Çağ''a ait mozaikler, ziyaretçileri büyülemektedir.", "place_query": "Hatay Arkeoloji Müzesi, Antakya, Hatay"}, {"title": "St. Pierre Kilisesi (Mağara Kilisesi)", "summary": "Antakya''da bulunan ve Hristiyanlık tarihi açısından büyük öneme sahip bu mağara kilisesi, Aziz Petrus''un ilk cemaatlerden birine vaaz verdiği yer olarak kabul edilir. UNESCO Dünya Mirası Geçici Listesi''nde yer almaktadır.", "place_query": "St. Pierre Kilisesi, Antakya, Hatay"}, {"title": "Titus Tüneli ve Beşikli Mağara", "summary": "Roma İmparatoru Vespasianus ve oğlu Titus döneminde sel sularını kontrol altına almak için kayalar oyularak yapılan bu anıtsal tünel, antik mühendisliğin etkileyici bir örneğidir. Yanındaki Beşikli Mağara ise kaya mezarlarıyla dikkat çeker.", "place_query": "Titus Tüneli, Samandağ, Hatay"}, {"title": "Harbiye Şelaleleri", "summary": "Antakya''nın hemen güneyinde, yeşillikler içinde kalan Harbiye, çağlayanları ve serin sularıyla ünlü bir mesire alanıdır. Mitolojiye göre Daphne''nin hikayesine ev sahipliği yapan bu yer, doğa yürüyüşleri ve piknik için idealdir.", "place_query": "Harbiye Şelaleleri, Defne, Hatay"}, {"title": "İskenderun Kalesi", "summary": "Şehir merkezinde yer alan ve tarihi M.Ö. 4. yüzyıla kadar uzanan bu kale, Büyük İskender tarafından yaptırılmıştır. Günümüzde kalıntılarıyla ziyaretçilere tarihi bir atmosfer sunar ve şehir manzarasına hakim bir konumdadır.", "place_query": "İskenderun Kalesi, İskenderun, Hatay"}, {"title": "Sokullu Mehmet Paşa Külliyesi (Payas Kalesi)", "summary": "Payas''ta bulunan bu Osmanlı dönemi külliyesi, kervansaray, cami, hamam ve çarşıdan oluşan büyük bir yapı kompleksidir. Tarihi İpek Yolu üzerinde önemli bir durak olan yapı, restorasyonuyla dikkat çekmektedir.", "place_query": "Sokullu Mehmet Paşa Külliyesi, Payas, Dörtyol, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6972a2cc-af5b-458e-83f5-4733bf824f99'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kırıkhan Ulu Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olup, şehrin merkezinde yer alır. Mimari detayları ve huzurlu atmosferi ile ziyaretçilerin ilgisini çeker.", "place_query": "Kırıkhan Ulu Camii, Kırıkhan, Hatay"}, {"title": "Kırıkhan Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen küçük ama zengin bir müzedir. Geçmişe yolculuk yapmak isteyenler için idealdir.", "place_query": "Kırıkhan Müzesi, Kırıkhan, Hatay"}, {"title": "Kırıkhan Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin, taze meyve-sebze ve el sanatlarının satıldığı canlı bir pazardır. Hatay mutfağının lezzetlerini bulmak için de uğranabilir.", "place_query": "Kırıkhan Kapalı Pazar Yeri, Kırıkhan, Hatay"}, {"title": "Kırıkhan Kalesi", "summary": "Tarihi bir kale olup şehre hakim bir tepede konumlanmıştır. Günümüze kısmen ulaşan kalıntıları ve manzarası ile dikkat çeker.", "place_query": "Kırıkhan Kalesi, Kırıkhan, Hatay"}, {"title": "Kırıkhan Mesire Alanı", "summary": "Doğayla iç içe piknik yapmak ve dinlenmek için popüler bir noktadır. Yeşil alanları ve temiz havası ile aileler için idealdir.", "place_query": "Kırıkhan Mesire Alanı, Kırıkhan, Hatay"}, {"title": "Kırıkhan Eski Hamam", "summary": "Tarihi bir hamam olup geleneksel hamam kültürünü yaşamak isteyenler için önemli bir duraktır. Restore edilmiş haliyle ziyaretçilere hizmet vermektedir.", "place_query": "Kırıkhan Eski Hamam, Kırıkhan, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '86a0d8f6-7af0-42b3-bf9d-92cb9ba050b9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kumlu Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve kısa bir yürüyüş yapmak için idealdir. Özellikle hafta sonları ailelerin uğrak noktasıdır.", "place_query": "Kumlu Belediye Parkı, Kumlu, Hatay"}, {"title": "Kumlu Tarihi Çarşı", "summary": "Küçük ama otantik bir çarşı olup yöresel el sanatları ve Hatay''a özgü ürünleri bulabilirsiniz. Tarihi dokusuyla dikkat çeker.", "place_query": "Kumlu Tarihi Çarşı, Kumlu, Hatay"}, {"title": "Kumlu Ulu Camii", "summary": "İlçenin en eski ve en büyük camilerinden biridir. Osmanlı dönemi mimarisini yansıtan sade ve huzurlu bir yapıdır.", "place_query": "Kumlu Ulu Camii, Kumlu, Hatay"}, {"title": "Kumlu Göleti", "summary": "Şehir merkezine yakın bu küçük gölet, piknik ve doğa yürüyüşü için popüler bir yerdir. Kuş gözlemi yapmak isteyenler için de uygundur.", "place_query": "Kumlu Göleti, Kumlu, Hatay"}, {"title": "Kumlu Köy Pazarı", "summary": "Her hafta kurulan bu pazarda taze meyve, sebze ve yöresel lezzetler satılır. Hatay mutfağının taze malzemelerini bulmak için idealdir.", "place_query": "Kumlu Köy Pazarı, Kumlu, Hatay"}, {"title": "Kumlu Tepesi Seyir Noktası", "summary": "İlçeye hakim bir tepede yer alan bu noktadan, Kumlu ve çevresindeki tarım arazilerinin panoramik manzarası izlenebilir. Gün batımında özellikle güzeldir.", "place_query": "Kumlu Tepesi Seyir Noktası, Kumlu, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b4a207b3-ebb1-461b-855b-e9a873b1ea9f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Payas Kalesi (Sokollu Mehmet Paşa Külliyesi)", "summary": "Tarihi İpek Yolu üzerinde yer alan bu görkemli kale ve külliye, 16. yüzyılda Mimar Sinan tarafından yapılmıştır. İçerisinde cami, han, hamam ve dükkanlarıyla bir Osmanlı yaşam kompleksi sunar.", "place_query": "Payas Kalesi, Payas, Hatay"}, {"title": "Payas Sahili ve Halk Plajı", "summary": "Geniş ve temiz kumsalıyla Payas''ın en popüler serinleme noktasıdır. Özellikle yaz aylarında denize girmek ve gün batımında yürüyüş yapmak için idealdir.", "place_query": "Payas Halk Plajı, Payas, Hatay"}, {"title": "Payas Tarihi Çarşısı", "summary": "Kale çevresinde kurulmuş olan bu tarihi çarşı, yöresel el sanatları ve Hatay''a özgü ürünlerle doludur. Dar sokaklarında dolaşırken Osmanlı dönemi ticaret hayatını hissedebilirsiniz.", "place_query": "Payas Tarihi Çarşı, Payas, Hatay"}, {"title": "Payas Kervansarayı", "summary": "Sokollu Mehmet Paşa Külliyesi''nin bir parçası olan bu büyük kervansaray, geçmişte tüccarların konaklama ve ticaret merkeziydi. Günümüzde restorasyonu yapılarak kültürel etkinliklere ev sahipliği yapmaktadır.", "place_query": "Payas Kervansarayı, Payas, Hatay"}, {"title": "Payas Ulu Camii", "summary": "Külliye içinde yer alan bu cami, Mimar Sinan''ın eserleri arasında sayılır. Kesme taş işçiliği ve sade mimarisiyle dikkat çeker; ibadete açık olup ziyaret edilebilir.", "place_query": "Payas Ulu Camii, Payas, Hatay"}, {"title": "Payas Şelalesi (Çağlayan)", "summary": "İlçe merkezine yakın bir konumda bulunan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla hafta sonu kaçamakları için popülerdir. Sesi ve serinliğiyle huzur verir.", "place_query": "Payas Şelalesi, Payas, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9c0f8a6f-fb80-4447-a7d3-76cd8faf5c0a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Demirköprü Barajı ve Mesire Alanı", "summary": "Reyhanlı''ya yaklaşık 15 km mesafede bulunan bu baraj gölü, piknik alanları ve doğal güzelliğiyle hafta sonu kaçamaklarının vazgeçilmezidir. Kuş gözlemi ve doğa yürüyüşü için de idealdir.", "place_query": "Demirköprü Barajı, Reyhanlı, Hatay"}, {"title": "Reyhanlı Belediye Parkı", "summary": "İlçe merkezinde yer alan bu büyük park, yürüyüş yolları, göleti ve çocuk oyun alanlarıyla aileler için popüler bir dinlenme noktasıdır. Özellikle akşam saatlerinde canlı bir atmosfere sahiptir.", "place_query": "Reyhanlı Belediye Parkı, Reyhanlı, Hatay"}, {"title": "Reyhanlı Kapalı Çarşısı", "summary": "Yöresel ürünler, baharatlar ve hediyelik eşyaların satıldığı bu tarihi çarşı, ilçenin ticaret ve kültür merkezidir. Alışveriş yaparken Suriye mutfağının lezzetlerini de bulabilirsiniz.", "place_query": "Reyhanlı Kapalı Çarşısı, Reyhanlı, Hatay"}, {"title": "Reyhanlı Surp Asdvadzadzin Kilisesi", "summary": "Ermeni cemaatine ait bu tarihi kilise, 19. yüzyıldan kalma mimarisi ve dini önemiyle dikkat çeker. Restore edilmiş yapı, bölgenin çok kültürlü geçmişine tanıklık eder.", "place_query": "Surp Asdvadzadzin Kilisesi, Reyhanlı, Hatay"}, {"title": "Reyhanlı Şehitler Anıtı", "summary": "İlçe meydanında yer alan bu anıt, bölgenin yakın tarihine ışık tutar ve özellikle milli bayramlarda ziyaretçi akınına uğrar. Çevresi düzenlenmiş alan, kısa bir mola için uygundur.", "place_query": "Reyhanlı Şehitler Anıtı, Reyhanlı, Hatay"}, {"title": "Cilvegözü Sınır Kapısı ve Çevresi", "summary": "Türkiye-Suriye sınırında yer alan bu kapı, ticari hareketliliği ve stratejik konumuyla bilinir. Sınırın hemen yanındaki küçük tezgahlarda Suriye''ye özgü ürünler bulabilirsiniz.", "place_query": "Cilvegözü Sınır Kapısı, Reyhanlı, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f57bbba9-3629-4b98-8fea-c58e9eeed1b4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çevlik Plajı", "summary": "Hatay''ın en uzun ve popüler plajlarından biri olan Çevlik, ince kumlu sahili ve berrak deniziyle yüzme ve güneşlenme için idealdir. Samandağ ilçe merkezine yakın konumuyla yaz aylarında yoğun ilgi görür.", "place_query": "Çevlik Plajı, Samandağ, Hatay"}, {"title": "Vespasianus Titus Tüneli", "summary": "Roma döneminde sel sularını denize yönlendirmek için dağa oyulan bu görkemli tünel, antik mühendislik harikası olarak kabul edilir. Tünelin içinde yürüyerek tarihi bir yolculuk yapabilirsiniz.", "place_query": "Vespasianus Titus Tüneli, Samandağ, Hatay"}, {"title": "Beşikli Mağara", "summary": "Tarih öncesi dönemlerden kalma bu mağara, içindeki lahitler ve kaya mezarlarıyla dikkat çeker. Arkeolojik önemi ve mistik atmosferiyle ziyaretçilerini etkiler.", "place_query": "Beşikli Mağara, Samandağ, Hatay"}, {"title": "St. Simon Manastırı", "summary": "Samandağ''ın Seyh Ömer Köyü yakınlarında bulunan bu tarihi manastır, 6. yüzyılda inşa edilmiş olup muhteşem deniz manzarası sunar. Sütunlu yapısı ve huzurlu çevresiyle öne çıkar.", "place_query": "St. Simon Manastırı, Samandağ, Hatay"}, {"title": "Samandağ Sahili", "summary": "Akdeniz''in en uzun kumsallarından biri olan bu sahil, yeşil deniz kaplumbağalarının (Caretta caretta) yuvalama alanı olarak da ünlüdür. Doğal güzelliği ve sakin atmosferiyle huzur verir.", "place_query": "Samandağ Sahili, Hatay"}, {"title": "Karaçay Deresi ve Mesire Alanı", "summary": "Samandağ''ın serin sularıyla ünlü Karaçay Deresi çevresindeki mesire alanı, piknik ve doğa yürüyüşleri için popüler bir noktadır. Özellikle yaz aylarında yerli halkın uğrak yeridir.", "place_query": "Karaçay Deresi, Samandağ, Hatay"}, {"title": "Hıdırbey Köyü ve Yaylası", "summary": "Samandağ''a bağlı bu şirin köy, yemyeşil yaylası ve temiz havasıyla doğa severler için kaçış noktasıdır. Köy kahvaltıları ve doğal yaşamıyla bilinir.", "place_query": "Hıdırbey Köyü, Samandağ, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '479552a0-9da3-415b-b8b4-63a4192c54c6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karaçay Şelalesi", "summary": "Yayladağı''nın serin ve yeşil doğasında yer alan bu şelale, özellikle yaz aylarında piknik ve doğa yürüyüşü için en popüler noktalardan biridir.", "place_query": "Karaçay Şelalesi, Yayladağı, Hatay"}, {"title": "Yayladağı Göz Evi (Gözleme Evi)", "summary": "Bölgeye özgü gözlemeleri ve doğal ortamıyla ünlü bu mekan, yol üzerinde mola verip yöresel lezzetleri tatmak için ideal bir durak noktasıdır.", "place_query": "Yayladağı Gözleme Evi, Hatay"}, {"title": "Kısık Vadisi", "summary": "Yemyeşil bitki örtüsü ve içinden geçen deresiyle doğa tutkunlarının uğrak noktası olan vadi, kamp ve yürüyüş için sakin bir ortam sunar.", "place_query": "Kısık Vadisi, Yayladağı, Hatay"}, {"title": "Yayladağı Sınır Kapısı ve Çevresi", "summary": "Suriye sınırında yer alan bu kapı, stratejik konumuyla dikkat çekerken çevresindeki geniş düzlükler ve manzara fotoğrafçılar için ilgi çekicidir.", "place_query": "Yayladağı Sınır Kapısı, Hatay"}, {"title": "Küçük Dalyan (Yayladağı Sahili)", "summary": "Akdeniz''in berrak sularına kıyısı olan bu sakin plaj, kalabalıktan uzak deniz keyfi yapmak isteyenler için huzurlu bir seçenektir.", "place_query": "Yayladağı Sahili, Hatay"}, {"title": "Belen Geçidi (Yayladağı Yolu Üzeri)", "summary": "Tarihi İpek Yolu güzergahında yer alan bu geçit, hem tarihi dokusu hem de zirveden Hatay ovasını gören panoramik manzarasıyla uğrak bir seyir noktasıdır.", "place_query": "Belen Geçidi, Yayladağı, Hatay"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '67a0beca-b8cc-446d-bbd5-862beddb6f44'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aralık Gökkuşağı Tepeleri (Renkli Tepeler)", "summary": "İlçe merkezine yakın konumda bulunan bu eşsiz doğal oluşum, farklı mineral katmanlarının oluşturduğu renk cümbüşüyle görenleri büyüler. Özellikle gün batımında ortaya çıkan manzarası fotoğrafçılar için kaçırılmaz bir fırsattır.", "place_query": "Aralık Gökkuşağı Tepeleri, Iğdır"}, {"title": "Aralık Ovası ve Kuş Gözlem Alanı", "summary": "Verimli Aralık Ovası, göçmen kuşlar için önemli bir durak noktasıdır. Özellikle ilkbahar ve sonbaharda turna, leylek ve yırtıcı kuş türlerini gözlemlemek için ideal bir doğa harikasıdır.", "place_query": "Aralık Ovası, Iğdır"}, {"title": "Sürmeli Kalesi", "summary": "İlçe sınırları içinde yer alan tarihi bir kaledir. Bölgenin stratejik noktalarından biri olan kale, geçmişte önemli savunma yapısı olarak kullanılmış olup çevresine hakim manzarasıyla dikkat çeker.", "place_query": "Sürmeli Kalesi, Aralık, Iğdır"}, {"title": "Aralık Karasu Bataklığı (Karasu Sulak Alanı)", "summary": "Bölgenin önemli sulak alanlarından biri olan Karasu, zengin bitki örtüsü ve su kuşlarına ev sahipliği yapar. Doğa yürüyüşü ve kuş gözlemciliği için huzurlu bir ortam sunar.", "place_query": "Karasu Sulak Alanı, Aralık, Iğdır"}, {"title": "Aralık Kervansarayı (Harabe)", "summary": "Tarihi İpek Yolu üzerinde yer alan bu eski kervansaray kalıntıları, bölgenin ticaret geçmişine ışık tutar. Günümüze ulaşan duvarları ve mimari izleriyle tarih meraklıları için ilgi çekici bir duraktır.", "place_query": "Aralık Kervansarayı, Iğdır"}, {"title": "Aralık Şehitlik Anıtı", "summary": "Bölgede yaşanan tarihi olayları anmak amacıyla yapılmış olan anıt, çevre düzenlemesi ve manevi atmosferiyle ziyaretçilerini ağırlar. Yakın tarihe tanıklık etmek isteyenler için anlamlı bir duraktır.", "place_query": "Aralık Şehitlik Anıtı, Iğdır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b9898ea7-fb19-4473-b777-9f1b78f7edf2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karakoyunlu Kalesi", "summary": "İlçe merkezinde yer alan bu tarihi kale, bölgenin en önemli kültürel miraslarından biridir. Ziyaretçiler kalenin surlarından çevreyi seyrederken tarihi atmosferi hissedebilirler.", "place_query": "Karakoyunlu Kalesi, Karakoyunlu, Iğdır"}, {"title": "Sürmeli Kalesi", "summary": "Karakoyunlu ilçesine bağlı Koçkıran köyü yakınlarında bulunan bu tarihi kale, Urartu dönemine ait izler taşır. Bölgenin en eski yerleşim alanlarından biri olarak tarih meraklılarının ilgisini çeker.", "place_query": "Sürmeli Kalesi, Koçkıran, Karakoyunlu, Iğdır"}, {"title": "Karakoyunlu Şehitlik Anıtı", "summary": "İlçedeki önemli anıtlardan biri olan bu yapı, bölge tarihine ışık tutar. Ziyaretçiler burada hem anıtı görebilir hem de çevredeki yeşil alanlarda dinlenebilir.", "place_query": "Karakoyunlu Şehitlik Anıtı, Karakoyunlu, Iğdır"}, {"title": "Iğdır Ovası Seyir Noktaları", "summary": "Karakoyunlu çevresindeki yüksek noktalardan Iğdır Ovası''nın muhteşem manzarası izlenebilir. Özellikle Ağrı Dağı''nın net görülebildiği bu noktalar, doğa fotoğrafçıları için idealdir.", "place_query": "Iğdır Ovası seyir noktası, Karakoyunlu, Iğdır"}, {"title": "Koçkıran Köyü Tarihi Mezarlığı", "summary": "Karakoyunlu''ya bağlı Koçkıran köyünde bulunan bu tarihi mezarlık, eski mezar taşları ve kitabeleriyle dikkat çeker. Bölgenin geçmişine dair ipuçları sunan önemli bir kültürel alandır.", "place_query": "Koçkıran Köyü Tarihi Mezarlığı, Karakoyunlu, Iğdır"}, {"title": "Karakoyunlu Parkı ve Mesire Alanı", "summary": "İlçe merkezinde yer alan bu park, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için popüler bir mekandır. Aileler ve gruplar için ideal bir dinlenme alanıdır.", "place_query": "Karakoyunlu Parkı, Karakoyunlu, Iğdır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7ee4194d-e701-48b8-aa11-cf37b7e0a201'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Iğdır Soykırım Anıtı ve Müzesi", "summary": "Iğdır''ın en önemli simgelerinden biri olan bu anıt ve müze, 1918 yılında yaşanan olayları anmak için inşa edilmiştir. Ziyaretçilerine hem tarihi bir yolculuk hem de etkileyici bir manzara sunar.", "place_query": "Iğdır Soykırım Anıtı ve Müzesi, Iğdır Merkez"}, {"title": "Ağrı Dağı (Büyük Ağrı) Manzara Seyir Noktaları", "summary": "Türkiye''nin en yüksek dağı olan Ağrı Dağı''nın eşsiz manzarasını izlemek için Iğdır Ovası''ndan yapılan seyirler popülerdir. Özellikle gün doğumu ve gün batımında muhteşem fotoğraflar çekilebilir.", "place_query": "Ağrı Dağı manzara seyir noktası, Iğdır"}, {"title": "Iğdır Kalesi", "summary": "Şehir merkezinde yer alan tarihi bir kaledir. Geçmişi Urartulara kadar uzanan kale, Iğdır''ın tarihine tanıklık etmek ve çevreyi kuşbakışı görmek için ideal bir noktadır.", "place_query": "Iğdır Kalesi, Iğdır Merkez"}, {"title": "Yukarı Çarıkçı Köyü ve Tuz Mağarası", "summary": "Doğal bir oluşum olan tuz mağarası, astım ve solunum yolu rahatsızlıklarına iyi geldiğine inanılan mikroklimasıyla ziyaretçi çeker. Mağara ve köy çevresi doğa yürüyüşleri için de uygundur.", "place_query": "Yukarı Çarıkçı Tuz Mağarası, Iğdır"}, {"title": "Karakoyunlu Koç Başlı Mezar Taşları", "summary": "Iğdır''ın tarihi mezarlıklarında bulunan ve Karakoyunlu dönemine ait koç başlı mezar taşları, bölgenin zengin kültürel mirasını yansıtan önemli eserlerdir.", "place_query": "Karakoyunlu koç başlı mezar taşları, Iğdır"}, {"title": "Iğdır Ovası ve Kuş Cenneti", "summary": "Verimli Iğdır Ovası, göçmen kuşlar için önemli bir durak noktasıdır. Özellikle ilkbahar ve sonbaharda çok sayıda kuş türünü gözlemlemek mümkündür.", "place_query": "Iğdır Ovası kuş gözlem, Iğdır"}, {"title": "Melekli Beldesi Eski Yerleşim Alanı", "summary": "Iğdır''ın en eski yerleşim yerlerinden biri olan Melekli, höyüğü ve tarihi kalıntılarıyla arkeoloji meraklıları için ilgi çekici bir duraktır.", "place_query": "Melekli Höyüğü, Iğdır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f5d3f177-a8f8-4d15-a9a0-dcd23c070795'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tuzluca Tuz Mağaraları", "summary": "Tuzluca''nın simgesi haline gelmiş bu doğal tuz mağaraları, astım ve solunum yolu rahatsızlıklarına iyi geldiğine inanılan mikroklimasıyla ünlüdür. Ziyaretçiler hem şifalı havayı soluyabilir hem de mağaranın etkileyici jeolojik oluşumlarını keşfedebilir.", "place_query": "Tuzluca Tuz Mağaraları, Tuzluca, Iğdır"}, {"title": "Tuzluca Kalesi", "summary": "Tarihi bir kaya kalesi olan Tuzluca Kalesi, bölgeye hakim bir tepe üzerinde yer alır ve çevresine muhteşem bir manzara sunar. Özellikle fotoğrafçılar ve tarih meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Tuzluca Kalesi, Tuzluca, Iğdır"}, {"title": "Aşağı Çıyrıklı Köyü Tarihi Yerleşimi", "summary": "Tuzluca''ya bağlı bu köy, eski dönemlere ait kayalara oyulmuş yaşam alanları ve mağaralarıyla dikkat çeker. Bölgenin zengin tarihine tanıklık etmek ve doğayla iç içe bir atmosferde vakit geçirmek için idealdir.", "place_query": "Aşağı Çıyrıklı Köyü, Tuzluca, Iğdır"}, {"title": "Gaziler Mahallesi Tarihi Evleri", "summary": "Tuzluca''nın eski dokusunu yansıtan bu mahallede, geleneksel taş ve kerpiç mimariye sahip tarihi evler bulunur. Dar sokaklarında yürüyüş yaparak yöresel yaşamın izlerini sürebilirsiniz.", "place_query": "Gaziler Mahallesi, Tuzluca, Iğdır"}, {"title": "Iğdır Dağı (Tuzluca Yamaçları)", "summary": "Bölgenin en yüksek noktalarından biri olan Iğdır Dağı''nın Tuzluca''ya bakan yamaçları, doğa yürüyüşleri ve kamp için popülerdir. Eşsiz bir panoramik manzara eşliğinde huzurlu bir doğa deneyimi sunar.", "place_query": "Iğdır Dağı, Tuzluca, Iğdır"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '313761fe-622a-41b4-9925-79d3e65bb2cb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yazılı Kanyon Tabiat Parkı", "summary": "Isparta''nın Aksu ilçesi sınırları içinde yer alan bu etkileyici kanyon, 600 metre derinliği ve yemyeşil doğası ile doğa yürüyüşü ve fotoğrafçılık için ideal bir yerdir. Kanyonun içinden akan dere ve şelaleler ziyaretçilere huzurlu bir atmosfer sunar.", "place_query": "Yazılı Kanyon Tabiat Parkı, Aksu, Isparta"}, {"title": "Aksu Çayı ve Mesire Alanı", "summary": "İlçe merkezinden geçen Aksu Çayı çevresindeki mesire alanları, piknik yapmak ve doğada vakit geçirmek isteyenler için popüler bir duraktır. Özellikle yaz aylarında serinlemek için tercih edilen doğal bir güzelliktir.", "place_query": "Aksu Çayı Mesire Alanı, Aksu, Isparta"}, {"title": "Zindan Mağarası", "summary": "Aksu ilçesi yakınlarında bulunan bu büyüleyici mağara, sarkıt ve dikitleriyle dikkat çeker. İçerisindeki göl ve doğal oluşumlar, mağara turizmine ilgi duyan ziyaretçiler için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Zindan Mağarası, Aksu, Isparta"}, {"title": "Kovada Gölü Milli Parkı", "summary": "Aksu sınırlarına yakın konumdaki bu milli park, göl çevresindeki yürüyüş parkurları ve zengin kuş gözlem fırsatlarıyla doğaseverlerin uğrak noktasıdır. Göldeki kano ve olta balıkçılığı da popüler aktiviteler arasındadır.", "place_query": "Kovada Gölü Milli Parkı, Aksu, Isparta"}, {"title": "Aksu Şelalesi", "summary": "İlçe merkezine kısa bir mesafede yer alan bu şelale, özellikle bahar aylarında karların erimesiyle coşkun akan sularıyla görsel bir şölen sunar. Çevresindeki doğal havuzlar, serinlemek için idealdir.", "place_query": "Aksu Şelalesi, Aksu, Isparta"}, {"title": "Tota Yaylası", "summary": "Aksu''nun yüksek kesimlerinde bulunan bu yayla, yemyeşil çayırları ve temiz havasıyla yayla turizmi için mükemmel bir seçenektir. Özellikle yaz aylarında kampçılar ve doğa yürüyüşçüleri tarafından sıkça ziyaret edilir.", "place_query": "Tota Yaylası, Aksu, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5943ba6f-0236-4211-8b08-548e7671f8e5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Atabey Kızıldağ Milli Parkı", "summary": "Doğal güzellikleri ve yürüyüş parkurlarıyla ünlü olan bu milli park, ziyaretçilere eşsiz bir doğa deneyimi sunar. Zengin bitki örtüsü ve manzaralarıyla fotoğrafçıların da ilgisini çeker.", "place_query": "Kızıldağ Milli Parkı, Atabey, Isparta"}, {"title": "Atabey Camii (Hacı İlyas Camii)", "summary": "Tarihi bir yapı olan bu cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Atabey''in merkezinde yer alan cami, hem ibadet hem de tarihi doku açısından önemlidir.", "place_query": "Atabey Camii, Atabey, Isparta"}, {"title": "Atabey Çarşı Hamamı", "summary": "Osmanlı döneminden kalma bu tarihi hamam, günümüze kadar iyi korunmuş nadir yapılardandır. Ziyaretçilere geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Atabey Çarşı Hamamı, Atabey, Isparta"}, {"title": "Atabey Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla piknik ve dinlenme için ideal bir noktadır. Gölet çevresinde yürüyüş yapabilir, doğayla iç içe vakit geçirebilirsiniz.", "place_query": "Atabey Göleti, Atabey, Isparta"}, {"title": "Harmancık Köyü Yaylası", "summary": "Atabey''e bağlı Harmancık Köyü sınırlarında bulunan bu yayla, serin havası ve yeşil doğasıyla özellikle yaz aylarında ziyaretçi akınına uğrar. Doğa yürüyüşleri ve kamp için uygundur.", "place_query": "Harmancık Köyü Yaylası, Atabey, Isparta"}, {"title": "Atabey Eski Evleri", "summary": "İlçe merkezinde dağınık halde bulunan tarihi evler, geleneksel Türk mimarisini yansıtır. Sokak aralarında yapacağınız bir yürüyüşle bu yapıları keşfedebilirsiniz.", "place_query": "Atabey Eski Evleri, Atabey, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8635b34c-dbf9-4190-a258-acbbd76432d7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eğirdir Gölü", "summary": "Isparta''nın incisi olarak bilinen Eğirdir Gölü, muhteşem manzarası ve berrak sularıyla ziyaretçilerine huzur dolu anlar yaşatır. Göl çevresinde yürüyüş yapabilir, bisiklet sürebilir veya tekne turlarına katılabilirsiniz.", "place_query": "Eğirdir Gölü, Eğirdir, Isparta"}, {"title": "Eğirdir Kalesi", "summary": "Tarihi bir yarımada üzerinde yer alan Eğirdir Kalesi, kente hakim bir tepede konumlanmıştır. Kaleyi gezerken hem tarihi dokuyu hissedebilir hem de gölün eşsiz panoramik manzarasını izleyebilirsiniz.", "place_query": "Eğirdir Kalesi, Eğirdir, Isparta"}, {"title": "Yeşil Ada (Can Ada)", "summary": "Eğirdir Gölü''nün ortasında yer alan bu küçük ada, yürüyüş yolları, piknik alanları ve dinlenme noktalarıyla popüler bir gezi durağıdır. Adada ayrıca tarihi bir kilise kalıntısı da bulunur.", "place_query": "Yeşil Ada, Eğirdir, Isparta"}, {"title": "Eğirdir Evleri", "summary": "Osmanlı ve Türk mimarisinin güzel örneklerini barındıran Eğirdir Evleri, dar sokakları ve ahşap detaylarıyla büyüleyici bir atmosfere sahiptir. Bu tarihi evleri gezerek yöresel kültürü yakından tanıyabilirsiniz.", "place_query": "Eğirdir Evleri, Eğirdir, Isparta"}, {"title": "Kovada Gölü Milli Parkı", "summary": "Eğirdir''e yaklaşık 30 km uzaklıktaki bu milli park, yemyeşil ormanlar ve sakin gölüyle doğa severler için ideal bir kaçış noktasıdır. Yürüyüş parkurları ve kamp alanlarıyla keşfedilmeyi bekler.", "place_query": "Kovada Gölü Milli Parkı, Eğirdir, Isparta"}, {"title": "Eğirdir Müzesi", "summary": "Eski bir medrese binasında hizmet veren Eğirdir Müzesi, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Müzede Pisidia, Roma ve Bizans dönemlerine ait eserler görebilirsiniz.", "place_query": "Eğirdir Müzesi, Eğirdir, Isparta"}, {"title": "Barla Dağı", "summary": "Eğirdir Gölü''nün batı kıyısında yükselen Barla Dağı, doğa yürüyüşleri ve dağcılık için popüler bir destinasyondur. Zirveden göl ve çevresinin nefes kesen manzarasını izleyebilirsiniz.", "place_query": "Barla Dağı, Eğirdir, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a50c3d9b-1c93-43f0-9789-b54a9da67155'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gelendost Gölü", "summary": "Isparta''nın doğal güzelliklerinden biri olan Gelendost Gölü, kuş gözlemciliği ve doğa yürüyüşleri için idealdir. Sakin atmosferi ve çevresindeki yeşil alanlar, ziyaretçilere huzurlu bir kaçamak sunar.", "place_query": "Gelendost Gölü, Gelendost, Isparta"}, {"title": "Gelendost Kalesi", "summary": "Tarihi bir yapı olan Gelendost Kalesi, bölgenin geçmişine ışık tutar ve çevresindeki manzara ile ziyaretçilerine eşsiz bir seyir keyfi yaşatır. Kalıntılar arasında yapacağınız keşif, tarihe yolculuk hissi verir.", "place_query": "Gelendost Kalesi, Gelendost, Isparta"}, {"title": "Gelendost Yaylası", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal bir durak olan Gelendost Yaylası, temiz havası ve geniş yeşil alanlarıyla piknik ve kamp yapmaya uygundur. Yayla, özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Gelendost Yaylası, Gelendost, Isparta"}, {"title": "Gelendost Şelalesi", "summary": "Doğal güzelliğiyle dikkat çeken Gelendost Şelalesi, çevresindeki yürüyüş parkurları ve serin sularıyla ziyaretçilerine huzurlu bir ortam sunar. Şelale, özellikle fotoğrafçılar için popüler bir noktadır.", "place_query": "Gelendost Şelalesi, Gelendost, Isparta"}, {"title": "Gelendost Ulu Camii", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan Gelendost Ulu Camii, mimarisi ve atmosferiyle dikkat çeker. Cami, hem ibadet hem de tarihi bir mekan olarak ziyaret edilebilir.", "place_query": "Gelendost Ulu Camii, Gelendost, Isparta"}, {"title": "Gelendost Çarşı Pazarı", "summary": "Yöresel ürünlerin satıldığı Gelendost Çarşı Pazarı, ziyaretçilere bölgenin kültürünü ve lezzetlerini tanıma fırsatı sunar. Pazar, özellikle el yapımı ürünler ve taze meyve-sebze alışverişi için idealdir.", "place_query": "Gelendost Çarşı Pazarı, Gelendost, Isparta"}, {"title": "Gelendost Parkı", "summary": "Şehir merkezinde yer alan Gelendost Parkı, dinlenmek ve doğayla iç içe vakit geçirmek için ideal bir mekandır. Park, çocuk oyun alanları ve oturma alanları ile aileler için uygun bir ortam sunar.", "place_query": "Gelendost Parkı, Gelendost, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1da29291-e88e-4f80-bb7b-c2f8b8a09af2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gönen Barajı ve Mesire Alanı", "summary": "Doğal güzelliği ve huzurlu atmosferiyle piknik, yürüyüş ve olta balıkçılığı için ideal bir noktadır. Gönen çayı üzerinde yer alan baraj, özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Gönen Barajı, Isparta"}, {"title": "Gönen Kaya Mezarları", "summary": "Antik dönemden kalma bu kaya mezarları, ilçenin tarihi dokusunu gözler önüne serer. Doğal kaya oluşumları içine oyulmuş bu yapılar, tarih meraklıları için keşfedilmeyi bekleyen önemli bir duraktır.", "place_query": "Gönen Kaya Mezarları, Isparta"}, {"title": "Gönen Kaplıcaları", "summary": "Termal sularıyla ünlü bu kaplıcalar, romatizma ve cilt rahatsızlıklarına iyi geldiği bilinen şifalı sulara sahiptir. Modern tesisleri ve doğal ortamıyla şehir stresinden uzaklaşmak isteyenler için popüler bir dinlenme noktasıdır.", "place_query": "Gönen Kaplıcaları, Isparta"}, {"title": "Gönen Şelalesi", "summary": "Yemyeşil doğa içinde gizlenmiş bu şelale, serinlemek ve doğayla baş başa kalmak isteyenler için harika bir seçenektir. Çevresindeki piknik alanları ve yürüyüş yollarıyla hafta sonu kaçamaklarının vazgeçilmez adresidir.", "place_query": "Gönen Şelalesi, Isparta"}, {"title": "Gönen Yaylaları (Sorkun Yaylası vb.)", "summary": "İlçe sınırları içinde yer alan yaylalar, temiz havası ve muhteşem manzaralarıyla doğa tutkunlarını cezbeder. Özellikle yaz aylarında serinlemek ve geleneksel yayla hayatını deneyimlemek için idealdir.", "place_query": "Sorkun Yaylası, Gönen, Isparta"}, {"title": "Gönen Merkez Camii ve Tarihi Çarşı", "summary": "İlçe merkezinde bulunan tarihi cami ve çevresindeki geleneksel çarşı, yöresel ürünler almak ve kısa bir şehir turu yapmak için uygun bir duraktır. Isparta halısı ve gül ürünleri gibi yöresel lezzetleri burada bulabilirsiniz.", "place_query": "Gönen Merkez Camii, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2c60e624-4472-4338-80d1-5ee3163e81de'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Keçiborlu Gölü (Yarışlı Gölü)", "summary": "Kuş gözlemciliği ve doğa fotoğrafçılığı için ideal olan bu göl, özellikle flamingolar başta olmak üzere birçok su kuşuna ev sahipliği yapar. Sessiz ve huzurlu atmosferiyle doğaseverler için kaçırılmayacak bir duraktır.", "place_query": "Yarışlı Gölü, Keçiborlu, Isparta"}, {"title": "Kızıldağ Milli Parkı", "summary": "Isparta sınırları içinde yer alan bu milli park, zengin bitki örtüsü ve yürüyüş parkurlarıyla doğa tutkunlarını cezbeder. Parkın zirvesinden çevredeki göl ve dağ manzaraları eşsiz bir seyir keyfi sunar.", "place_query": "Kızıldağ Milli Parkı, Isparta"}, {"title": "Keçiborlu Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle yaz aylarında serinlemek ve piknik yapmak isteyen yerli halkın uğrak noktasıdır. Çevresindeki doğal havuz ve yeşil alanlar aileler için keyifli bir ortam oluşturur.", "place_query": "Keçiborlu Şelalesi, Isparta"}, {"title": "Eğirdir Gölü (Keçiborlu Kıyıları)", "summary": "Türkiye''nin önemli tatlı su göllerinden Eğirdir Gölü''nün Keçiborlu''ya bakan kıyıları, sakin atmosferi ve gün batımı manzaralarıyla bilinir. Göl kenarında yürüyüş yapabilir veya balık tutmanın tadını çıkarabilirsiniz.", "place_query": "Eğirdir Gölü, Keçiborlu, Isparta"}, {"title": "Senirce Köyü Tarihi Evleri", "summary": "Keçiborlu''ya bağlı Senirce Köyü, geleneksel mimariyi yansıtan tarihi taş evleriyle dikkat çeker. Köyün dar sokaklarında yürürken geçmişe yolculuk yapabilir ve yöresel yaşama tanıklık edebilirsiniz.", "place_query": "Senirce Köyü, Keçiborlu, Isparta"}, {"title": "Keçiborlu Kent Ormanı", "summary": "İlçe merkezine yakın mesafede bulunan bu ormanlık alan, yürüyüş ve bisiklet parkurlarıyla spor yapmak isteyenler için idealdir. Piknik alanları ve temiz havasıyla hafta sonu kaçamakları için popüler bir mekandır.", "place_query": "Keçiborlu Kent Ormanı, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '291be304-3f36-4aff-b181-6c46fcd6c759'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Isparta Çarşısı (Tarihi Isparta Çarşısı)", "summary": "Isparta''nın en eski ticaret merkezi olan çarşı, yöresel gül ürünleri, halı ve kilimleriyle ünlüdür. Ziyaretçiler, tarihi dükkanlar arasında dolaşarak şehrin kültürel dokusunu yakından hissedebilirler.", "place_query": "Tarihi Isparta Çarşısı, Merkez, Isparta"}, {"title": "Isparta Müzesi", "summary": "Pisidia bölgesinden çıkarılan arkeolojik eserlerin sergilendiği müze, bölgenin zengin tarihine ışık tutar. Heykeller, lahitler ve etnografik objelerle dolu koleksiyonu, tarih meraklıları için kaçırılmaz bir duraktır.", "place_query": "Isparta Müzesi, Merkez, Isparta"}, {"title": "Gülkent (Gül Bahçeleri ve Gül Fabrikaları)", "summary": "Isparta''nın dünyaca ünlü gül bahçeleri, özellikle mayıs-haziran aylarında ziyaretçileri büyüler. Gül fabrikalarında gül suyu, gül yağı ve diğer gül ürünlerinin üretimini yerinde görebilirsiniz.", "place_query": "Isparta Gül Bahçeleri, Merkez, Isparta"}, {"title": "Aya Stefanos (Stefanos) Kilisesi", "summary": "Isparta merkezinde bulunan bu tarihi kilise, Bizans döneminden kalma önemli bir yapıdır. Günümüzde kültür merkezi olarak kullanılan yapı, mimarisi ve fresk kalıntılarıyla dikkat çeker.", "place_query": "Aya Stefanos Kilisesi, Merkez, Isparta"}, {"title": "Isparta Belediye Parkı ve Atatürk Anıtı", "summary": "Şehrin merkezinde yer alan bu park, dinlenmek ve kısa bir yürüyüş yapmak için idealdir. Parktaki Atatürk Anıtı ve çevresindeki yeşil alanlar, yerli halkın ve turistlerin uğrak noktasıdır.", "place_query": "Isparta Belediye Parkı, Merkez, Isparta"}, {"title": "Isparta Kalesi (Kaleiçi)", "summary": "Şehre hakim bir tepe üzerinde bulunan tarihi kale kalıntıları, Isparta''nın geçmişine tanıklık eder. Kaleiçi bölgesi, dar sokakları ve geleneksel evleriyle keşfedilmeyi bekleyen bir açık hava müzesidir.", "place_query": "Isparta Kalesi, Merkez, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '70094e4f-b362-4a6e-9094-344327fad735'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eğirdir Gölü", "summary": "Türkiye''nin en büyük dördüncü gölü olan Eğirdir Gölü, Şarkikaraağaç ilçesinin güney sınırında yer alır ve muhteşem manzaraları, yüzme ve su sporları imkanı sunar. Gölde bulunan iki küçük ada, Can Ada ve Yeşil Ada, özellikle yürüyüş ve fotoğrafçılık için popüler noktalardır.", "place_query": "Eğirdir Gölü, Isparta"}, {"title": "Kovada Gölü Milli Parkı", "summary": "Şarkikaraağaç''a yaklaşık 30 km uzaklıkta bulunan bu milli park, endemik bitki türleri ve zengin kuş popülasyonuyla doğa severler için ideal bir yerdir. Göletin etrafındaki yürüyüş parkurları, piknik alanları ve kamp imkanlarıyla huzurlu bir kaçamak sunar.", "place_query": "Kovada Gölü Milli Parkı, Isparta"}, {"title": "Şarkikaraağaç Kalesi", "summary": "İlçe merkezinde bulunan tarihi bir yapı olan Şarkikaraağaç Kalesi, bölgenin Bizans ve Selçuklu dönemlerine tanıklık etmiştir. Kalenin tepesinden ilçe ve çevresindeki tarım arazilerinin panoramik manzarası izlenebilir.", "place_query": "Şarkikaraağaç Kalesi, Isparta"}, {"title": "Yalvaç Antik Kenti (Antiocheia)", "summary": "Şarkikaraağaç''a yaklaşık 40 km mesafedeki Yalvaç ilçesinde yer alan Antiocheia Antik Kenti, Roma dönemine ait kalıntıları ve mozaikleriyle ünlüdür. Bölgenin en önemli arkeolojik alanlarından biri olan bu kent, tarih meraklıları için eşsiz bir deneyim sunar.", "place_query": "Antiocheia Antik Kenti, Yalvaç, Isparta"}, {"title": "Sütçüler Yaylası", "summary": "Şarkikaraağaç''ın kuzeyindeki Sütçüler ilçesi sınırlarında bulunan bu yayla, yemyeşil doğası ve serin havasıyla yaz aylarında popüler bir kaçış noktasıdır. Yaylada doğa yürüyüşleri yapabilir, yöresel ürünler satın alabilirsiniz.", "place_query": "Sütçüler Yaylası, Isparta"}, {"title": "Gölcük Krater Gölü", "summary": "Isparta merkeze yaklaşık 15 km uzaklıkta olan Gölcük Krater Gölü, volkanik bir kraterin içinde oluşmuş doğal bir göldür. Çevresindeki çam ormanları ve piknik alanlarıyla hafta sonu gezileri için ideal bir yerdir.", "place_query": "Gölcük Krater Gölü, Isparta"}, {"title": "Çandır Köyü ve Tarihi Evleri", "summary": "Şarkikaraağaç ilçesine bağlı Çandır Köyü, geleneksel taş ve ahşap mimarisiyle dikkat çeken tarihi evleriyle ünlüdür. Köyde yürüyüş yapabilir, yöresel lezzetleri tadabilir ve fotoğrafçılık için güzel kareler yakalayabilirsiniz.", "place_query": "Çandır Köyü, Şarkikaraağaç, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '78ea2009-3438-4997-9f9e-3836bcc1f322'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Senirkent Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu doğal şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyen ziyaretçilerin uğrak noktasıdır. Çevresindeki piknik alanları ve yürüyüş parkurları ile hafta sonu kaçamakları için idealdir.", "place_query": "Senirkent Şelalesi, Senirkent, Isparta"}, {"title": "Yalvaç Antik Kenti (Pisidia Antiokheia)", "summary": "Senirkent''e komşu Yalvaç ilçesinde yer alan bu önemli antik kent, Roma ve Bizans dönemine ait kalıntılarıyla ünlüdür. Tiyatro, su kemerleri ve mozaikleri görmek için bölgedeki en popüler tarihi duraklardan biridir.", "place_query": "Pisidia Antiokheia Antik Kenti, Yalvaç, Isparta"}, {"title": "Eğirdir Gölü", "summary": "Senirkent''e yaklaşık 40 km mesafedeki Eğirdir Gölü, doğal güzelliği ve turkuaz sularıyla ünlüdür. Göl kenarında yürüyüş yapabilir, tekne turlarına katılabilir veya çevredeki tesislerde konaklayarak huzurlu bir gün geçirebilirsiniz.", "place_query": "Eğirdir Gölü, Eğirdir, Isparta"}, {"title": "Kovada Gölü Milli Parkı", "summary": "Senirkent ilçe sınırları içinde kalan bu milli park, eşsiz bitki örtüsü ve kuş gözlemciliği için ideal bir doğa harikasıdır. Göl çevresindeki yürüyüş yolları ve kamp alanları doğaseverler için popüler bir destinasyondur.", "place_query": "Kovada Gölü Milli Parkı, Senirkent, Isparta"}, {"title": "Senirkent Ulu Camii", "summary": "İlçe merkezinde bulunan tarihi Ulu Camii, Osmanlı dönemi mimarisinin güzel örneklerinden biridir. Restore edilmiş yapısı ve sade atmosferiyle hem ibadet hem de kültürel ziyaret için önemli bir mekandır.", "place_query": "Senirkent Ulu Camii, Senirkent, Isparta"}, {"title": "Barla Dağı", "summary": "Senirkent yakınlarındaki Barla Dağı, doğa yürüyüşleri ve manzara seyri için popüler bir rotadır. Zirveye çıkan patikalarda yürüyerek Eğirdir Gölü ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "Barla Dağı, Senirkent, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8c0d1f85-6633-4b19-99b5-a97c8eedfa08'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yazılı Kanyon Tabiat Parkı", "summary": "Isparta''nın Sütçüler ilçesinde yer alan bu eşsiz kanyon, 800 metre derinliği ve 1 km uzunluğundaki yürüyüş parkuruyla doğa severler için harika bir rotadır. Kanyonun içinde antik kaya yazıtlarını ve şelaleleri görebilirsiniz.", "place_query": "Yazılı Kanyon Tabiat Parkı, Sütçüler, Isparta"}, {"title": "Sütçüler Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, yeşillikler içinde serinlemek ve piknik yapmak için ideal bir noktadır. Özellikle yaz aylarında ziyaretçilerin uğrak yeridir.", "place_query": "Sütçüler Şelalesi, Sütçüler, Isparta"}, {"title": "Kovada Gölü Milli Parkı", "summary": "Sütçüler sınırları içinde yer alan bu milli park, kızılçam ormanları ve krater gölüyle ünlüdür. Yürüyüş, kamp ve kuş gözlemi yapmak isteyenler için mükemmel bir doğa cennetidir.", "place_query": "Kovada Gölü Milli Parkı, Sütçüler, Isparta"}, {"title": "Adada Antik Kenti", "summary": "Sütçüler''e bağlı Sağrak köyü yakınlarında bulunan bu antik kent, Pisidya dönemine ait kalıntılarıyla tarih meraklılarını cezbeder. Bölgede hala ayakta duran yapılar ve lahitler görmek mümkündür.", "place_query": "Adada Antik Kenti, Sütçüler, Isparta"}, {"title": "Çandır Köyü Kaya Mezarları", "summary": "Sütçüler''in Çandır köyünde yer alan bu kaya mezarları, Roma dönemine ait etkileyici bir arkeolojik alandır. Kayaların oyulmasıyla yapılmış mezarlar ve çevredeki doğal manzara görülmeye değerdir.", "place_query": "Çandır Köyü Kaya Mezarları, Sütçüler, Isparta"}, {"title": "Sarp Dağı ve Yaylaları", "summary": "Sütçüler''in yüksek kesimlerinde yer alan Sarp Dağı, zengin bitki örtüsü ve yaylalarıyla doğa yürüyüşleri için popülerdir. Özellikle yaz aylarında yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Sarp Dağı, Sütçüler, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '165fb90b-cdf1-4cb0-b266-7b8bb7e8aa9e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Uluborlu Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu kale, bölgeye hakim manzarası ve Bizans/Selçuklu dönemlerine ait kalıntıları ile ziyaretçileri etkiler. Özellikle gün batımında eşsiz bir seyir noktasıdır.", "place_query": "Uluborlu Kalesi, Uluborlu, Isparta"}, {"title": "Uluborlu Saat Kulesi", "summary": "1900''lü yılların başında yapılan bu tarihi saat kulesi, ilçe merkezinde simge yapılardan biridir. Çevresindeki tarihi çeşme ve meydan ile birlikte hoş bir atmosfer sunar.", "place_query": "Uluborlu Saat Kulesi, Uluborlu, Isparta"}, {"title": "Kızıldağ Milli Parkı", "summary": "Uluborlu sınırları içinde yer alan bu milli park, zengin bitki örtüsü, temiz havası ve yürüyüş rotaları ile doğaseverler için idealdir. Piknik alanları ve kamp imkanı da bulunur.", "place_query": "Kızıldağ Milli Parkı, Uluborlu, Isparta"}, {"title": "Uluborlu Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan bu müze, bölgenin arkeolojik ve etnografik eserlerini sergiler. Özellikle Roma ve Bizans dönemine ait buluntular dikkat çeker.", "place_query": "Uluborlu Müzesi, Uluborlu, Isparta"}, {"title": "Uluborlu Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumdaki bu gölet, çevresindeki yeşil alanlar ve yürüyüş yolları ile hafta sonu kaçamakları için popülerdir. Balık tutma ve piknik yapma imkanı sunar.", "place_query": "Uluborlu Göleti, Uluborlu, Isparta"}, {"title": "Tarihi Uluborlu Evleri", "summary": "İlçenin dar sokaklarında yer alan geleneksel taş ve ahşap yapılı evler, Osmanlı dönemi mimarisini yansıtır. Fotoğraf tutkunları için güzel kareler yakalama fırsatı verir.", "place_query": "Tarihi Uluborlu Evleri, Uluborlu, Isparta"}, {"title": "Uluborlu Kiraz Festivali (Mevsimlik)", "summary": "Her yıl haziran ayında düzenlenen bu festival, yöreye özgü kiraz çeşitlerinin tanıtıldığı, konser ve etkinliklerle renklenen bir şenliktir. Ziyaretçilere keyifli anlar yaşatır.", "place_query": "Uluborlu Kiraz Festivali, Uluborlu, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8115e16e-1782-40eb-9ece-2507576012d5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Antik Kent Antiocheia", "summary": "Pisidia Antiocheia''sı olarak da bilinen bu antik kent, Yalvaç''ın en önemli tarihi hazinesidir. Augustus Tapınağı, antik tiyatro ve mozaikli yapılarıyla ziyaretçilerine büyüleyici bir tarih yolculuğu sunar.", "place_query": "Pisidia Antiocheia Antik Kenti, Yalvaç, Isparta"}, {"title": "Yalvaç Müzesi", "summary": "Pisidia Antiocheia kazılarında çıkarılan eserlerin sergilendiği bu müze, bölgenin zengin tarihini gözler önüne seriyor. Heykeller, sikkeler ve lahitler müzenin en dikkat çekici koleksiyonları arasındadır.", "place_query": "Yalvaç Müzesi, Yalvaç, Isparta"}, {"title": "Hoyran Gölü (Eğirdir Gölü''nün Kuzeyi)", "summary": "Eğirdir Gölü''nün kuzey kısmını oluşturan Hoyran Gölü, Yalvaç sınırları içinde yer alır. Kuş gözlemciliği ve doğa yürüyüşleri için ideal olan bu göl, huzurlu manzarasıyla ziyaretçilerini cezbeder.", "place_query": "Hoyran Gölü, Yalvaç, Isparta"}, {"title": "Men Kutsal Alanı", "summary": "Antik dönemde ay tanrısı Men''e adanmış bu kutsal alan, Pisidia Antiocheia''nın hemen yanında yer alır. Tapınak kalıntıları ve çevresindeki kaya mezarları, bölgenin dini tarihine ışık tutar.", "place_query": "Men Tapınağı, Yalvaç, Isparta"}, {"title": "Yalvaç Evleri (Tarihi Yalvaç Evleri)", "summary": "Yalvaç''ın dar sokaklarında sıralanan bu geleneksel evler, taş ve ahşap işçiliğinin güzel örnekleridir. Özellikle cumbalı ve geniş saçaklı yapılarıyla fotoğraf tutkunları için eşsiz kareler sunar.", "place_query": "Tarihi Yalvaç Evleri, Yalvaç, Isparta"}, {"title": "Sücüllü Şelalesi", "summary": "Yalvaç ilçe merkezine yaklaşık 20 km uzaklıkta bulunan bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa gezileri için popüler bir duraktır.", "place_query": "Sücüllü Şelalesi, Yalvaç, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '50e6f69c-bc93-421a-9d21-c07f097bb479'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızıldağ Milli Parkı", "summary": "Beyşehir Gölü''nün doğu kıyısında yer alan bu milli park, zengin flora ve faunası, yürüyüş parkurları ve muhteşem göl manzaralarıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Kızıldağ Milli Parkı, Yenişarbademli, Isparta"}, {"title": "Eflatun Pınarı", "summary": "Hitit dönemine ait bu kutsal anıt, su kaynağının etrafına örülmüş taş bloklar ve hiyerogliflerle süslü duvarlarıyla tarih ve doğanın iç içe geçtiği eşsiz bir açık hava müzesidir.", "place_query": "Eflatun Pınarı, Yenişarbademli, Isparta"}, {"title": "Beyşehir Gölü", "summary": "Türkiye''nin en büyük tatlı su göllerinden biri olan Beyşehir Gölü, Yenişarbademli kıyılarında huzurlu piknik alanları, kuş gözlemi ve tekne turları için popüler bir destinasyondur.", "place_query": "Beyşehir Gölü, Yenişarbademli, Isparta"}, {"title": "Yenişarbademli Kalesi", "summary": "Tarihi bir kalıntı olan bu kale, ilçe merkezine hakim bir tepede yer alır ve çevredeki eşsiz manzarayı izlemek için güzel bir seyir noktası sunar.", "place_query": "Yenişarbademli Kalesi, Yenişarbademli, Isparta"}, {"title": "Dedegül Dağı", "summary": "Bölgenin en yüksek noktalarından biri olan Dedegül Dağı, özellikle doğa yürüyüşü ve kampçılık için tercih edilen, zirvesinden muhteşem bir göl ve dağ manzarası vaat eden bir rotadır.", "place_query": "Dedegül Dağı, Yenişarbademli, Isparta"}, {"title": "Kubadabad Sarayı", "summary": "Selçuklu dönemine ait bu tarihi saray kompleksi, Beyşehir Gölü kıyısındaki kalıntıları ve çini süslemeleriyle Anadolu Selçuklu sanatının önemli bir örneğini oluşturur.", "place_query": "Kubadabad Sarayı, Yenişarbademli, Isparta"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b8ceb808-5d68-4d5e-a6be-ea80f64f2945'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Büyükada", "summary": "Adalar''ın en büyük ve en popüler adasıdır. Tarihi ahşap köşkleri, faytonları ve Aya Yorgi Tepesi''ne yapılan yürüyüşlerle ünlüdür.", "place_query": "Büyükada, Adalar, İstanbul"}, {"title": "Aya Yorgi Kilisesi ve Tepesi", "summary": "Büyükada''nın en yüksek noktasında yer alan bu tarihi kiliseye çıkan yokuş, muhteşem manzarası ve dilek dileme geleneğiyle ziyaretçi çeker.", "place_query": "Aya Yorgi Kilisesi, Büyükada, Adalar, İstanbul"}, {"title": "Heybeliada", "summary": "Büyükada''dan sonra en çok ziyaret edilen ada olup, sessiz sokakları, çam ormanları ve Deniz Lisesi gibi tarihi yapılarıyla bilinir.", "place_query": "Heybeliada, Adalar, İstanbul"}, {"title": "Heybeliada Ruhban Okulu", "summary": "Heybeliada''da bulunan bu tarihi bina, Ortodoks dünyası için önemli bir merkezdir ve mimarisiyle dikkat çeker.", "place_query": "Heybeliada Ruhban Okulu, Adalar, İstanbul"}, {"title": "Kınalıada", "summary": "Adalar''ın en küçük ve İstanbul''a en yakın adasıdır. Sakin atmosferi ve plajlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Kınalıada, Adalar, İstanbul"}, {"title": "Burgazada", "summary": "Sakin ve yeşil bir ada olan Burgazada, özellikle yürüyüş parkurları ve deniz manzaralı kafeleriyle bilinir.", "place_query": "Burgazada, Adalar, İstanbul"}, {"title": "Sedef Adası", "summary": "Adalar''ın en sakin ve lüks yerleşimlerinden biri olan Sedef Adası, doğal güzellikleri ve plajlarıyla öne çıkar.", "place_query": "Sedef Adası, Adalar, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '21bea446-aef8-4169-b4a2-2b62c410df00'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İstanbul Havalimanı", "summary": "Dünyanın en büyük havalimanlarından biri olan İstanbul Havalimanı, modern mimarisi, devasa yolcu kapasitesi ve içindeki alışveriş merkezi, restoranlar ile dinlenme alanları sayesinde sadece bir ulaşım noktası değil, aynı zamanda keşfedilecek bir destinasyondur.", "place_query": "İstanbul Havalimanı, Arnavutköy, İstanbul"}, {"title": "Arnavutköy Merkez Camii", "summary": "İlçenin simge yapılarından biri olan bu cami, Osmanlı ve Selçuklu mimarisinin izlerini taşıyan zarif yapısı ve geniş avlusuyla hem ibadet hem de ziyaret amaçlı uğranılabilecek huzurlu bir mekandır.", "place_query": "Arnavutköy Merkez Camii, Arnavutköy, İstanbul"}, {"title": "Boyalık Sahili", "summary": "İstanbul''un Karadeniz kıyısında yer alan Boyalık Sahili, uzun kumsalı, doğal plajı ve özellikle yaz aylarında denize girmek ve piknik yapmak isteyenler için şehir kalabalığından uzak, sakin bir kaçış noktasıdır.", "place_query": "Boyalık Sahili, Arnavutköy, İstanbul"}, {"title": "Durusu (Terkos) Gölü", "summary": "İstanbul''un önemli içme suyu kaynaklarından biri olan Durusu Gölü, çevresindeki yemyeşil ormanlık alanlar, kuş gözlem noktaları ve mesire yerleriyle doğa yürüyüşü, bisiklet turları ve hafta sonu piknikleri için ideal bir doğal cennettir.", "place_query": "Durusu Gölü, Arnavutköy, İstanbul"}, {"title": "Hacımaşlı Korusu", "summary": "Arnavutköy''ün en büyük yeşil alanlarından biri olan Hacımaşlı Korusu, içerisindeki yürüyüş parkurları, göleti ve çocuk oyun alanlarıyla ailelerin ve doğaseverlerin sıkça tercih ettiği huzurlu bir mesire yeridir.", "place_query": "Hacımaşlı Korusu, Arnavutköy, İstanbul"}, {"title": "Arnavutköy Belediyesi Kent Ormanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için düzenlenmiş bu kent ormanı, yürüyüş ve koşu parkurları, ahşap oturma alanları ve manzarasıyla doğayla iç içe vakit geçirmek için harika bir seçenektir.", "place_query": "Arnavutköy Kent Ormanı, Arnavutköy, İstanbul"}, {"title": "İstanbul Akvaryum", "summary": "Arnavutköy sınırları içinde bulunan ve dünyanın en büyük tematik akvaryumlarından biri olan bu merkez, farklı kıtalardan binlerce deniz canlısını barındıran dev tünelleri ve eğlenceli etkinlikleriyle çocuklu aileler için vazgeçilmez bir duraktır.", "place_query": "İstanbul Akvaryum, Arnavutköy, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '94ee72a9-47b8-4447-9dc9-be8edb87082f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ataşehir Mustafa Saffet Kültür Merkezi", "summary": "Ataşehir''in önemli kültür ve sanat merkezlerinden biridir. Tiyatro, konser ve sergi gibi birçok etkinliğe ev sahipliği yapar.", "place_query": "Ataşehir Mustafa Saffet Kültür Merkezi, İstanbul"}, {"title": "İstanbul Ataşehir Belediyesi 15 Temmuz Şehitler Parkı", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve göletiyle ilçenin en büyük ve popüler parkıdır. Aileler ve sporcular için ideal bir dinlenme noktasıdır.", "place_query": "15 Temmuz Şehitler Parkı, Ataşehir, İstanbul"}, {"title": "Büyükşehir Belediyesi Ataşehir Spor Kompleksi (Branda Spor Tesisleri)", "summary": "Modern spor salonları, yüzme havuzu ve futbol sahalarıyla dikkat çeker. Spor yapmak veya maç izlemek için sıkça tercih edilir.", "place_query": "Branda Spor Tesisleri, Ataşehir, İstanbul"}, {"title": "Ataşehir Nato Yolu Parkı", "summary": "Özellikle hafta sonları ailelerin uğrak noktası olan bu park, çocuk oyun alanları ve oturma gruplarıyla huzurlu bir ortam sunar.", "place_query": "Nato Yolu Parkı, Ataşehir, İstanbul"}, {"title": "Özdilek Ataşehir Alışveriş Merkezi", "summary": "Geniş mağaza yelpazesi, yeme-içme alanları ve sinema salonlarıyla ilçenin en büyük alışveriş merkezlerinden biridir.", "place_query": "Özdilek Ataşehir, İstanbul"}, {"title": "Ataşehir İçerenköy Merkez Camii", "summary": "Modern mimarisi ve geniş avlusuyla dikkat çeken bu cami, ilçenin önemli ibadet ve buluşma noktalarındandır.", "place_query": "İçerenköy Merkez Camii, Ataşehir, İstanbul"}, {"title": "Ataşehir Metro Korusu", "summary": "Yoğun şehir hayatından kaçış noktası olan bu koru, yürüyüş yapmak ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Ataşehir Metro Korusu, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'afc51787-ae2f-4e94-9ba8-2b50d17fee83'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Avcılar Sahil Bandı", "summary": "Marmara Denizi kıyısında uzanan yürüyüş ve bisiklet yolu, piknik alanları ve kafeleriyle hafta sonu ailelerin ve spor yapanların uğrak noktasıdır. Gün batımında deniz manzarası eşliğinde yürüyüş yapabilirsiniz.", "place_query": "Avcılar Sahil Bandı, İstanbul"}, {"title": "Avcılar Merkez Camii", "summary": "Modern Osmanlı mimarisiyle dikkat çeken bu büyük cami, geniş avlusu ve çevresindeki çarşıyla ilçenin simgelerindendir. İbadet ve ziyaret için huzurlu bir ortam sunar.", "place_query": "Avcılar Merkez Camii, İstanbul"}, {"title": "Avcılar Belediyesi Barış Manço Kültür Merkezi", "summary": "Tiyatro, konser ve sergi gibi kültürel etkinliklere ev sahipliği yapan merkez, sanatseverler için önemli bir buluşma noktasıdır. Ziyaretinizi etkinlik takvimine göre planlayabilirsiniz.", "place_query": "Barış Manço Kültür Merkezi, Avcılar, İstanbul"}, {"title": "Avcılar Kent Ormanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için ideal olan bu ormanlık alan, yürüyüş parkurları ve piknik masalarıyla doğayla iç içe vakit geçirme imkanı sunar.", "place_query": "Avcılar Kent Ormanı, İstanbul"}, {"title": "Ambarlı Limanı ve Çevresi", "summary": "İstanbul''un önemli yük limanlarından biri olan Ambarlı, büyük gemileri ve deniz ticaretini yakından görmek isteyenler için ilginç bir rota olabilir. Çevredeki balıkçı lokantaları da deniz ürünleri sevenleri cezbeder.", "place_query": "Ambarlı Limanı, Avcılar, İstanbul"}, {"title": "Avcılar Pazarı (Salı Pazarı)", "summary": "Her hafta Salı günü kurulan büyük halk pazarı, taze meyve-sebze, giyim ve ev eşyalarının uygun fiyatlarla satıldığı renkli bir alışveriş deneyimi sunar.", "place_query": "Avcılar Salı Pazarı, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '59bddd63-f75d-401b-a131-142feeebf013'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bağcılar Meydanı", "summary": "İlçenin merkezi ve en hareketli noktası olan meydan, çevresindeki alışveriş merkezleri, kafeler ve restoranlarla günlük yaşamın kalbini oluşturur. Ziyaretçiler burada ilçenin sosyal dokusunu yakından gözlemleyebilir.", "place_query": "Bağcılar Meydanı, Bağcılar, İstanbul"}, {"title": "Mahmutbey Metro İstasyonu ve Çevresi", "summary": "Modern metro hattının ilçedeki önemli duraklarından biri olan Mahmutbey, çevresindeki yeni yapılaşma ve yeşil alanlarla dikkat çeker. Ulaşımın kolay olduğu bu bölge, kentsel dönüşümün simgesi haline gelmiştir.", "place_query": "Mahmutbey Metro İstasyonu, Bağcılar, İstanbul"}, {"title": "Bağcılar Belediyesi Kültür Merkezi", "summary": "Tiyatro oyunları, konserler ve sergilere ev sahipliği yapan bu merkez, ilçenin kültürel hayatına canlılık katar. Sanatseverler için uygun fiyatlı ve kaliteli etkinlikler sunar.", "place_query": "Bağcılar Belediyesi Kültür Merkezi, Bağcılar, İstanbul"}, {"title": "Bağcılar Fatih Sultan Mehmet Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla ailelerin tercih ettiği büyük bir parktır. Şehrin gürültüsünden uzaklaşmak için ideal bir dinlenme noktasıdır.", "place_query": "Fatih Sultan Mehmet Parkı, Bağcılar, İstanbul"}, {"title": "Bağcılar Kapalı Spor Salonu", "summary": "Çeşitli spor müsabakalarına ve etkinliklere ev sahipliği yapan modern bir tesistir. Spor severlerin ilgisini çeken bu salon, ilçenin dinamik yapısını yansıtır.", "place_query": "Bağcılar Kapalı Spor Salonu, Bağcılar, İstanbul"}, {"title": "Bağcılar Yavuz Selim Camii", "summary": "Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, ilçenin en eski ibadethanelerinden biridir. Sade ve huzurlu atmosferiyle ziyaretçilerine manevi bir deneyim sunar.", "place_query": "Yavuz Selim Camii, Bağcılar, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '19768c84-0f6a-43b5-a78f-d9cb33dc3c92'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İstanbul Akvaryum (Turkuazoo)", "summary": "Avrupa''nın en büyük akvaryumlarından biri olan bu merkez, birbirinden farklı temalı bölümleri ve tünel akvaryumuyla ziyaretçilere deniz canlılarını yakından görme fırsatı sunar. Özellikle aileler ve çocuklar için eğlenceli bir gezi rotasıdır.", "place_query": "İstanbul Akvaryum, Bahçelievler, İstanbul"}, {"title": "CNR Expo Fuar Merkezi", "summary": "Bahçelievler''de yer alan bu büyük fuar merkezi, yıl boyunca kitap, gıda, mobilya ve teknoloji gibi birçok alanda ulusal ve uluslararası fuarlara ev sahipliği yapar. Alışveriş ve etkinlik tutkunları için ideal bir noktadır.", "place_query": "CNR Expo, Bahçelievler, İstanbul"}, {"title": "Yenibosna Merkez Camii", "summary": "Modern Osmanlı mimarisiyle dikkat çeken bu cami, geniş avlusu ve yüksek minareleriyle bölgenin en önemli ibadet ve simge yapılarından biridir. Ziyaretçiler hem huzurlu bir atmosfer bulur hem de mimari detayları keşfeder.", "place_query": "Yenibosna Merkez Camii, Bahçelievler, İstanbul"}, {"title": "Bahçelievler Belediyesi Kültür Merkezi", "summary": "Tiyatro oyunları, konserler ve sergilere ev sahipliği yapan bu merkez, ilçenin kültür-sanat hayatının kalbinde yer alır. Sanatseverler için keyifli bir akşam geçirme imkanı tanır.", "place_query": "Bahçelievler Belediyesi Kültür Merkezi, İstanbul"}, {"title": "Atatürk Havalimanı Anıtı ve Parkı", "summary": "Eski Atatürk Havalimanı sahasında yer alan bu anıt ve park alanı, tarihi bir uçağın sergilendiği geniş yeşil bir alandır. Havacılık tarihine ilgi duyanlar ve yürüyüş yapmak isteyenler için sakin bir kaçış noktasıdır.", "place_query": "Atatürk Havalimanı Anıtı, Bahçelievler, İstanbul"}, {"title": "World Atlantis Alışveriş Merkezi", "summary": "Mağazaları, yemek alanı ve sinema salonlarıyla Bahçelievler''de popüler bir alışveriş ve eğlence merkezidir. Hafta sonu ailece vakit geçirmek için rahat bir seçenek sunar.", "place_query": "World Atlantis AVM, Bahçelievler, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '94db0694-e440-44de-a8d4-ecc057953acd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İstanbul Akvaryum (Florya Akvaryumu)", "summary": "Bakırköy''ün en popüler aile eğlence merkezlerinden biri olan İstanbul Akvaryum, devasa su altı tüneli ve binlerce deniz canlısıyla ziyaretçilere eşsiz bir keşif deneyimi sunar.", "place_query": "İstanbul Akvaryum, Florya, Bakırköy, İstanbul"}, {"title": "Galleria Ataköy", "summary": "Bakırköy''ün en büyük ve ilk alışveriş merkezlerinden biri olan Galleria, geniş mağaza yelpazesi, restoranları ve deniz manzaralı kafeleriyle alışveriş ve yeme-içme için ideal bir duraktır.", "place_query": "Galleria Ataköy, Bakırköy, İstanbul"}, {"title": "Bakırköy Sahil Yolu ve Lunapark", "summary": "Bakırköy''ün en uzun sahil şeridinde yürüyüş yapabilir, bisiklete binebilir ve çocuklar için eğlenceli bir lunaparkta vakit geçirebilirsiniz; özellikle gün batımında manzarası büyüleyicidir.", "place_query": "Bakırköy Sahil Yolu, Bakırköy, İstanbul"}, {"title": "Atatürk Havalimanı Eski Pist Alanı (Millet Bahçesi)", "summary": "Eski Atatürk Havalimanı pistinin bir bölümüne kurulan bu dev millet bahçesi, geniş yeşil alanları, yürüyüş yolları ve açık hava etkinlikleriyle Bakırköy''de nefes alınacak yeni bir merkezdir.", "place_query": "Atatürk Havalimanı Millet Bahçesi, Bakırköy, İstanbul"}, {"title": "Bakırköy Özgürlük Meydanı ve Çarşı", "summary": "Bakırköy''ün kalbi sayılan Özgürlük Meydanı çevresindeki tarihi çarşılar, butik dükkanlar ve lezzetli sokak yemekleriyle ünlüdür; alışveriş ve keşif için canlı bir noktadır.", "place_query": "Bakırköy Özgürlük Meydanı, Bakırköy, İstanbul"}, {"title": "İstanbul Cevahir Hotel & Kongre Merkezi (Eski İstanbul Cevahir Oteli)", "summary": "Bakırköy''de deniz kenarında yer alan bu tarihi yapı, günümüzde lüks bir otel ve kongre merkezi olarak hizmet verse de, mimarisi ve manzarasıyla fotoğrafçılar için popüler bir mekandır.", "place_query": "İstanbul Cevahir Hotel, Bakırköy, İstanbul"}, {"title": "Yeşilköy Sahili ve Marina", "summary": "Bakırköy''ün komşusu Yeşilköy''de bulunan bu sahil şeridi, lüks yatların bulunduğu marinası, balık restoranları ve huzurlu yürüyüş yollarıyla sakin bir kaçış noktasıdır.", "place_query": "Yeşilköy Sahili, Bakırköy, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7393540f-0cc4-4d73-9166-b3bea5c991db'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Başakşehir Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve göletiyle aileler için ideal bir dinlenme ve piknik alanıdır. Şehrin gürültüsünden kaçmak için popüler bir nefes noktasıdır.", "place_query": "Başakşehir Millet Bahçesi, Başakşehir, İstanbul"}, {"title": "Şahintepe Mesire Alanı", "summary": "Doğal bitki örtüsü ve manzarasıyla hafta sonu kaçamakları için tercih edilen bir mesire yeridir. Mangal yapmak ve doğayla iç içe vakit geçirmek için uygundur.", "place_query": "Şahintepe Mesire Alanı, Başakşehir, İstanbul"}, {"title": "Başakşehir Göleti ve Çevresi", "summary": "Yürüyüş ve bisiklet yollarıyla çevrili yapay gölet, özellikle akşam yürüyüşleri ve sakin bir ortam arayanlar için popülerdir.", "place_query": "Başakşehir Göleti, Başakşehir, İstanbul"}, {"title": "Fatih Terim Stadı (Başakşehir Stadyumu)", "summary": "Modern mimarisiyle dikkat çeken bu stadyum, Medipol Başakşehir takımının maçlarına ev sahipliği yapar. Spor tutkunları için önemli bir ziyaret noktasıdır.", "place_query": "Fatih Terim Stadı, Başakşehir, İstanbul"}, {"title": "Başakşehir Millet Kütüphanesi", "summary": "Geniş kitap koleksiyonu ve sessiz çalışma alanlarıyla öğrenciler ve kitapseverler için modern bir kültür merkezidir. Mimari yapısı da ilgi çeker.", "place_query": "Başakşehir Millet Kütüphanesi, Başakşehir, İstanbul"}, {"title": "Başakşehir Botanik Parkı", "summary": "Farklı bitki türlerinin sergilendiği bu park, doğa severler için huzurlu bir kaçış noktasıdır. Yürüyüş yolları ve dinlenme alanları mevcuttur.", "place_query": "Başakşehir Botanik Parkı, Başakşehir, İstanbul"}, {"title": "Sular Vadisi Parkı", "summary": "Şelaleleri, yapay göletleri ve yeşil dokusuyla dikkat çeken bu park, özellikle aileler ve fotoğrafçılar için güzel bir manzara sunar.", "place_query": "Sular Vadisi Parkı, Başakşehir, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2ce5b69f-7886-4ed6-8813-2191a44aa3b7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bayrampaşa Cezaevi (İstanbul Cezaevi)", "summary": "Tarihi bir cezaevi binası olan bu yapı, mimarisi ve geçmişiyle dikkat çeker. Günümüzde aktif bir cezaevi olarak kullanıldığı için iç ziyaret mümkün değildir, ancak dışarıdan görülmeye değer tarihi bir simgedir.", "place_query": "Bayrampaşa Cezaevi, Bayrampaşa, İstanbul"}, {"title": "İstanbul Üniversitesi Cerrahpaşa Tıp Fakültesi (Tarihi Binalar)", "summary": "Kampüs içindeki tarihi binalar, Osmanlı dönemi mimarisini yansıtır. Sağlık müzesi ve yeşil alanlarıyla keyifli bir gezinti rotası sunar.", "place_query": "Cerrahpaşa Tıp Fakültesi, İstanbul Üniversitesi, Bayrampaşa, İstanbul"}, {"title": "Bayrampaşa Belediyesi Kültür Merkezi", "summary": "Modern bir kültür merkezi olan bu mekan, tiyatro, konser ve sergi gibi etkinliklere ev sahipliği yapar. Bölgedeki kültürel aktivitelerin kalbidir.", "place_query": "Bayrampaşa Belediyesi Kültür Merkezi, Bayrampaşa, İstanbul"}, {"title": "Olimpiyat Parkı (Bayrampaşa)", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme noktasıdır. Spor sahaları da mevcuttur.", "place_query": "Olimpiyat Parkı, Bayrampaşa, İstanbul"}, {"title": "Bayrampaşa Kapalı Spor Salonu", "summary": "Çeşitli spor müsabakalarına ve etkinliklere ev sahipliği yapan bu salon, spor severler için önemli bir merkezdir. Basketbol ve voleybol maçları sıkça düzenlenir.", "place_query": "Bayrampaşa Kapalı Spor Salonu, Bayrampaşa, İstanbul"}, {"title": "Sağmalcılar Çarşısı", "summary": "Yöresel ürünlerden tekstile kadar geniş bir ürün yelpazesi sunan bu çarşı, alışveriş için canlı bir noktadır. Uygun fiyatlarıyla bilinir.", "place_query": "Sağmalcılar Çarşısı, Bayrampaşa, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3b4a1aaf-582f-4888-9de5-c0a2251e4257'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dolmabahçe Sarayı", "summary": "Osmanlı İmparatorluğu''nun son dönemine tanıklık eden bu görkemli saray, Boğaz kıyısındaki konumu ve Avrupa tarzı mimarisiyle İstanbul''un en çok ziyaret edilen tarihi yapılarından biridir. İçerisindeki kristal avizeler, muhteşem merdivenler ve Mustafa Kemal Atatürk''ün hayata gözlerini yumduğu oda en dikkat çekici bölümlerdir.", "place_query": "Dolmabahçe Sarayı, Beşiktaş, İstanbul"}, {"title": "Ortaköy Camii (Büyük Mecidiye Camii)", "summary": "Boğaz''ın incisi olarak bilinen bu neo-barok tarzdaki cami, Ortaköy Meydanı''nda Boğaziçi Köprüsü''nün hemen yanında yer alır. Eşsiz deniz manzarası ve zarif siluetiyle hem ibadet hem de fotoğrafçılık için popüler bir noktadır.", "place_query": "Ortaköy Camii, Beşiktaş, İstanbul"}, {"title": "Yıldız Parkı", "summary": "Yıldız Sarayı''nın bahçesi olarak bilinen bu geniş yeşil alan, İstanbul''un ortasında huzurlu bir kaçış noktasıdır. İçerisindeki göletler, köşkler ve yürüyüş yollarıyla doğaseverler için ideal bir mekandır.", "place_query": "Yıldız Parkı, Beşiktaş, İstanbul"}, {"title": "Rahmi M. Koç Müzesi", "summary": "Haliç kıyısındaki bu endüstri müzesi, tarihi araçlardan denizaltılara, uçaklardan buharlı lokomotiflere kadar geniş bir koleksiyona ev sahipliği yapar. Hem çocuklar hem de yetişkinler için interaktif ve eğlenceli bir deneyim sunar.", "place_query": "Rahmi M. Koç Müzesi, Hasköy, Beyoğlu, İstanbul"}, {"title": "Beşiktaş İskelesi ve Çarşısı", "summary": "Beşiktaş''ın kalbi sayılan bu bölge, vapur iskelesi çevresinde yoğunlaşan kafeler, balıkçılar ve hareketli çarşısıyla ünlüdür. Özellikle hafta sonları kurulan Balık Pazarı ve nostaljik sokakları keşfedilmeye değerdir.", "place_query": "Beşiktaş İskelesi, Beşiktaş, İstanbul"}, {"title": "Akaretler Sıra Evleri", "summary": "19. yüzyılda inşa edilen bu tarihi sıra evler, İstanbul''un en güzel mimari örneklerinden biridir. Günümüzde butik mağazalar, kafeler ve restoranlara ev sahipliği yapan bu sokak, nostaljik bir atmosferde alışveriş yapmak için idealdir.", "place_query": "Akaretler Sıra Evleri, Beşiktaş, İstanbul"}, {"title": "Deniz Müzesi", "summary": "Türkiye''nin en büyük denizcilik müzesi olan bu yapı, Osmanlı ve Cumhuriyet dönemine ait saltanat kayıkları, gemiler ve denizcilik objelerini sergiler. Özellikle tarihi kayıkların bulunduğu bölüm oldukça etkileyicidir.", "place_query": "Deniz Müzesi, Beşiktaş, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8fdf22af-e604-4ea8-a87a-042815fcb9f9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Polonezköy Tabiat Parkı", "summary": "İstanbul''un yeşil örtüsü içinde huzurlu bir kaçış noktası olan Polonezköy, yürüyüş parkurları, piknik alanları ve doğal güzelliğiyle ünlüdür. Tarihi Polonez köyü kültürünü de yakından görebilirsiniz.", "place_query": "Polonezköy Tabiat Parkı, Beykoz, İstanbul"}, {"title": "Anadolu Hisarı", "summary": "Fatih Sultan Mehmet tarafından İstanbul''un fethi öncesinde inşa edilen bu tarihi hisar, Boğaz''ın en dar noktasında muhteşem bir manzaraya sahiptir. Hisar çevresindeki kafelerde boğaz keyfi yapabilirsiniz.", "place_query": "Anadolu Hisarı, Beykoz, İstanbul"}, {"title": "Beykoz Korusu (Abraham Paşa Korusu)", "summary": "Boğaz manzaralı bu geniş koru, yürüyüş yolları, tarihi köşkü ve göletiyle doğa severlerin favori mekanlarındandır. Özellikle hafta sonu kaçamakları için idealdir.", "place_query": "Beykoz Korusu, Beykoz, İstanbul"}, {"title": "Yoros Kalesi", "summary": "Anadolu Kavağı''nda Boğaz''ın Karadeniz''e açıldığı noktada yer alan bu tarihi Bizans kalesi, nefes kesen bir boğaz ve deniz manzarası sunar. Tarih ve doğa iç içe bir deneyim yaşatır.", "place_query": "Yoros Kalesi, Anadolu Kavağı, Beykoz, İstanbul"}, {"title": "Beykoz Cam ve Billur Müzesi", "summary": "Tarihi Beykoz Dereseki Köşkü''nde hizmet veren bu müze, Osmanlı''dan günümüze cam ve billur eserlerden oluşan zengin bir koleksiyona ev sahipliği yapar. Hem tarihi yapı hem de sergilenen eserler büyüleyicidir.", "place_query": "Beykoz Cam ve Billur Müzesi, Beykoz, İstanbul"}, {"title": "Riva (Çayağzı) Plajı", "summary": "Beykoz''un Karadeniz kıyısındaki bu uzun plajı, doğal kumsalı ve dalgalı deniziyle yaz aylarında popüler bir serinleme noktasıdır. Çevresindeki tesislerle günübirlik keyifli bir kaçış sunar.", "place_query": "Riva Plajı, Beykoz, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '43db4da4-3267-4d36-9ad3-03872fa947df'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beylikdüzü Yaşam Vadisi", "summary": "İstanbul''un en büyük ve en popüler parklarından biri olan Yaşam Vadisi, yürüyüş ve bisiklet yolları, göletleri, spor alanları ve kafeleriyle aileler ve doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Beylikdüzü Yaşam Vadisi, Beylikdüzü, İstanbul"}, {"title": "Beylikdüzü Sahil Bandı ve Plajları", "summary": "Marmara Denizi kıyısında uzanan bu sahil şeridi, yürüyüş yapmak, bisiklete binmek veya deniz manzarası eşliğinde dinlenmek için harika bir alandır; yaz aylarında halk plajları da aktiftir.", "place_query": "Beylikdüzü Sahil, Beylikdüzü, İstanbul"}, {"title": "Beylikdüzü Atatürk Kent Parkı", "summary": "Geniş yeşil alanları, çocuk oyun parkları ve spor tesisleri ile bilinen bu park, özellikle hafta sonu piknik yapmak ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Beylikdüzü Atatürk Kent Parkı, Beylikdüzü, İstanbul"}, {"title": "Beylikdüzü Migros AVM", "summary": "Bölgenin en büyük alışveriş merkezlerinden biri olan Migros AVM, çok sayıda mağaza, restoran, sinema ve eğlence seçenekleriyle alışveriş ve sosyalleşme için popüler bir merkezdir.", "place_query": "Migros AVM Beylikdüzü, İstanbul"}, {"title": "Beylikdüzü Kıyı Parkı", "summary": "Sahil boyunca uzanan bu park, özellikle gün batımı manzarası ve deniz kenarında huzurlu yürüyüşleriyle bilinir; ayrıca balık tutma iskelesi de bulunur.", "place_query": "Beylikdüzü Kıyı Parkı, Beylikdüzü, İstanbul"}, {"title": "Beylikdüzü Spor ve Etkinlik Merkezi", "summary": "Modern spor salonları, yüzme havuzu ve çeşitli etkinlik alanları ile spor yapmak veya bir etkinliğe katılmak isteyenler için kapsamlı bir tesistir.", "place_query": "Beylikdüzü Spor ve Etkinlik Merkezi, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2a24a9c3-ce22-4940-8809-1144bf6726f2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İstiklal Caddesi", "summary": "Beyoğlu''nun kalbi olan bu ünlü cadde, tarihi binaları, sanat galerileri, butik mağazaları ve canlı sokak atmosferiyle hem yerli hem yabancı turistlerin en çok ziyaret ettiği noktalardan biridir. Nostaljik tramvayı ve sürekli hareketli yapısıyla unutulmaz bir deneyim sunar.", "place_query": "İstiklal Caddesi, Beyoğlu, İstanbul"}, {"title": "Galata Kulesi", "summary": "Beyoğlu silüetinin simgesi olan bu tarihi kule, 14. yüzyıldan beri İstanbul''a tepeden bakar. Ziyaretçiler, kulenin seyir terasından Haliç ve Boğaz''ın eşsiz manzarasını izleyebilir, ayrıca içindeki restoran ve kafelerde vakit geçirebilir.", "place_query": "Galata Kulesi, Beyoğlu, İstanbul"}, {"title": "Pera Müzesi", "summary": "Kurucusu Suna ve İnan Kıraç''ın adını taşıyan bu müze, Osmanlı dönemi resim sanatı, ağırlık ve ölçü aletleri ile Kütahya çini ve seramik koleksiyonlarına ev sahipliği yapar. Özellikle Kaplumbağa Terbiyecisi tablosuyla ünlüdür ve Beyoğlu''nun kültür sanat hayatının önemli bir durağıdır.", "place_query": "Pera Müzesi, Meşrutiyet Caddesi, Beyoğlu, İstanbul"}, {"title": "Taksim Meydanı", "summary": "İstanbul''un en merkezi ve sembolik meydanlarından biri olan Taksim, Cumhuriyet Anıtı, Taksim Camii ve çevresindeki AVM''lerle hem buluşma noktası hem de tarihi bir alandır. Gece gündüz canlılığını koruyan meydan, şehrin nabzını tutar.", "place_query": "Taksim Meydanı, Beyoğlu, İstanbul"}, {"title": "Çiçek Pasajı", "summary": "İstiklal Caddesi üzerindeki tarihi bir geçit olan Çiçek Pasajı, 19. yüzyıldan kalma zarif mimarisiyle ünlüdür. İçindeki meyhaneler ve restoranlar, özellikle akşam saatlerinde canlı bir atmosfer sunar ve rakı-balık kültürünün en bilinen adreslerinden biridir.", "place_query": "Çiçek Pasajı, İstiklal Caddesi, Beyoğlu, İstanbul"}, {"title": "Madame Tussauds İstanbul", "summary": "Dünyaca ünlü balmumu heykel müzesinin İstanbul''daki şubesi, yerli ve yabancı ünlülerin gerçekçi heykellerini sergiler. Ziyaretçiler, Atatürk''ten Messi''ye, Mustafa Kemal Atatürk''ten Hollywood yıldızlarına kadar birçok figürle fotoğraf çektirme fırsatı bulur.", "place_query": "Madame Tussauds İstanbul, İstiklal Caddesi, Beyoğlu"}, {"title": "SALT Galata", "summary": "Eski bir banka binasında yer alan bu kültür merkezi, modern sanat sergileri, kütüphanesi ve arşiviyle dikkat çeker. Özellikle mimarisi ve sunduğu sergilerle sanatseverler için Beyoğlu''nda önemli bir duraktır.", "place_query": "SALT Galata, Bankalar Caddesi, Beyoğlu, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3f443698-3ba8-4741-a22b-3ba5d0e65091'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Büyükçekmece Kordon Boyu", "summary": "Marmara Denizi kıyısında uzanan bu geniş yürüyüş yolu, gün batımı manzarası, kafeleri ve bisiklet yoluyla İstanbulluların en popüler buluşma noktalarından biridir.", "place_query": "Büyükçekmece Kordon, Büyükçekmece, İstanbul"}, {"title": "Kanuni Sultan Süleyman Köprüsü", "summary": "Mimar Sinan tarafından 16. yüzyılda inşa edilen bu tarihi taş köprü, Büyükçekmece Gölü ile denizi birbirine bağlayan eşsiz bir yapıdır ve hâlâ yürüyerek geçilebilmektedir.", "place_query": "Kanuni Sultan Süleyman Köprüsü, Büyükçekmece, İstanbul"}, {"title": "Büyükçekmece Plajı", "summary": "Mavi Bayraklı halk plajı, temiz kumsalı ve denize girmek için ayrılmış bölümleriyle yaz aylarında ailelerin ve gençlerin uğrak noktasıdır.", "place_query": "Büyükçekmece Plajı, Büyükçekmece, İstanbul"}, {"title": "Büyükçekmece Atatürk Kültür Merkezi ve Amfi Tiyatro", "summary": "Deniz kenarında konumlanmış açık hava tiyatrosu ve kültür merkezi, yıl boyunca konser, festival ve tiyatro gösterilerine ev sahipliği yapar.", "place_query": "Büyükçekmece Amfi Tiyatro, Büyükçekmece, İstanbul"}, {"title": "Mimaroba Sahil Parkı", "summary": "Geniş yeşil alanları, çocuk oyun parkları, yürüyüş ve koşu parkurları ile deniz manzaralı huzurlu bir dinlenme ve piknik alanıdır.", "place_query": "Mimaroba Sahil Parkı, Büyükçekmece, İstanbul"}, {"title": "Büyükçekmece Gölü Çevresi", "summary": "Kuş gözlemi, doğa yürüyüşü ve bisiklet turları için ideal olan göl çevresi, özellikle hafta sonları doğaseverlerin tercih ettiği sakin bir kaçış noktasıdır.", "place_query": "Büyükçekmece Gölü, Büyükçekmece, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1c9ac26e-e352-4842-ad4b-213e4be55c99'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çatalca Mübadele Müzesi", "summary": "Türkiye''nin ilk ve tek mübadele müzesi olan bu yapı, 1923 nüfus mübadelesiyle Yunanistan''dan gelen göçmenlerin hikayesini anlatır. Müzede döneme ait eşyalar, fotoğraflar ve belgeler sergilenir.", "place_query": "Çatalca Mübadele Müzesi, Çatalca, İstanbul"}, {"title": "Çatalca Yaylaları (Binkılıç ve Çilingoz Tabiat Parkı)", "summary": "İstanbul''un yeşil nefes alma noktalarından biri olan bu bölge, geniş ormanlık alanları, yürüyüş parkurları ve piknik alanlarıyla doğa severlerin uğrak yeridir. Özellikle Çilingoz Tabiat Parkı, kamp ve doğa sporları için idealdir.", "place_query": "Çilingoz Tabiat Parkı, Çatalca, İstanbul"}, {"title": "Çatalca Ferhatpaşa Göleti", "summary": "Huzurlu bir doğa kaçamağı arayanlar için ideal olan bu gölet, çevresindeki yeşil alanlar ve yürüyüş yollarıyla piknik ve olta balıkçılığı için popülerdir.", "place_query": "Ferhatpaşa Göleti, Çatalca, İstanbul"}, {"title": "Çatalca Elbasan Köyü ve Tarihi Ahşap Evler", "summary": "Tarihi Rum ve Türk mimarisinin izlerini taşıyan bu köy, restore edilmiş ahşap evleri ve dar sokaklarıyla nostaljik bir atmosfer sunar.", "place_query": "Elbasan Köyü, Çatalca, İstanbul"}, {"title": "Çatalca Kalesi", "summary": "Bizans döneminden kalma bu tarihi kale, Çatalca''nın en önemli simgelerinden biridir. Tepeye konumlanmış olan kale, çevreye hakim bir manzara sunar.", "place_query": "Çatalca Kalesi, Çatalca, İstanbul"}, {"title": "Çatalca Subaşı Köyü ve Mağaraları", "summary": "Doğal güzellikleri ve tarihi mağaralarıyla bilinen Subaşı Köyü, trekking ve doğa yürüyüşü için sıkça tercih edilir. Bölgedeki mağaralar keşfedilmeyi bekleyen doğal oluşumlardır.", "place_query": "Subaşı Köyü Mağaraları, Çatalca, İstanbul"}, {"title": "Çatalca Gökçeali Köyü ve Şelalesi", "summary": "İstanbul''a yakınlığıyla bilinen bu şelale, özellikle bahar ve yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler tarafından ziyaret edilir.", "place_query": "Gökçeali Şelalesi, Çatalca, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '582b3ed6-55f4-4271-a246-2fc8e81a5688'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çekmeköy Kent Ormanı", "summary": "İstanbul''un en büyük kent ormanlarından biri olan bu alan, yürüyüş parkurları, bisiklet yolları ve piknik alanlarıyla doğayla iç içe vakit geçirmek isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Çekmeköy Kent Ormanı, Çekmeköy, İstanbul"}, {"title": "Çekmeköy Belediyesi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş yolları, çocuk oyun parkları ve göletiyle ailelerin ve spor yapmak isteyenlerin sıkça tercih ettiği modern bir rekreasyon alanıdır.", "place_query": "Çekmeköy Millet Bahçesi, Çekmeköy, İstanbul"}, {"title": "Reşadiye Cami ve Külliyesi", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan bu cami, mimari detayları ve huzurlu avlusuyla bölgenin önemli dini ve kültürel miraslarından biridir.", "place_query": "Reşadiye Cami, Çekmeköy, İstanbul"}, {"title": "Çekmeköy Yayla Parkı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için manzaralı bir seyir noktası sunan bu park, özellikle gün batımında İstanbul Boğazı ve köprüler manzarasıyla ünlüdür.", "place_query": "Çekmeköy Yayla Parkı, Çekmeköy, İstanbul"}, {"title": "Çekmeköy Merkez Camii", "summary": "Modern mimarisiyle dikkat çeken bu cami, geniş ibadet alanı ve avlusuyla bölge sakinlerinin uğrak noktalarından biridir.", "place_query": "Çekmeköy Merkez Camii, Çekmeköy, İstanbul"}, {"title": "Alemdağ Tabiat Parkı", "summary": "Çekmeköy sınırlarına yakın konumdaki bu tabiat parkı, zengin bitki örtüsü, yürüyüş rotaları ve kamp alanlarıyla doğa severler için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Alemdağ Tabiat Parkı, Çekmeköy, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '48d880a5-f237-48cc-a734-f88747243fb6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Esenler Merkez Camii", "summary": "Modern mimarisi ve geniş avlusuyla dikkat çeken cami, ilçenin önemli dini ve kültürel merkezlerinden biridir.", "place_query": "Esenler Merkez Camii, Esenler, İstanbul"}, {"title": "Esenler Şehir Parkı", "summary": "Koşu yolları, oyun alanları ve yeşil alanlarıyla aileler için popüler bir dinlenme ve piknik noktasıdır.", "place_query": "Esenler Şehir Parkı, Esenler, İstanbul"}, {"title": "Atışalanı Meydanı", "summary": "Çevresindeki kafeler ve mağazalarla ilçenin sosyal yaşam merkezi olan meydan, buluşma noktası olarak sıkça tercih edilir.", "place_query": "Atışalanı Meydanı, Esenler, İstanbul"}, {"title": "Esenler Kapalı Çarşı", "summary": "Uygun fiyatlı tekstil ürünleri ve hediyelik eşyalarıyla bilinen bu çarşı, alışveriş için ideal bir duraktır.", "place_query": "Esenler Kapalı Çarşı, Esenler, İstanbul"}, {"title": "Menderes Parkı", "summary": "Spor alanları ve yürüyüş patikalarıyla özellikle sabah sporcuları ve aileler tarafından tercih edilen bir yeşil alandır.", "place_query": "Menderes Parkı, Esenler, İstanbul"}, {"title": "Esenler Kültür Merkezi", "summary": "Tiyatro oyunları, sergiler ve konserler gibi kültürel etkinliklere ev sahipliği yapan merkez, ilçenin sanat hayatına katkı sağlar.", "place_query": "Esenler Kültür Merkezi, Esenler, İstanbul"}, {"title": "Dörtyol Meydanı", "summary": "Ana arterlerin kesiştiği noktada bulunan meydan, çevresindeki iş yerleri ve yemek mekanlarıyla canlı bir merkezdir.", "place_query": "Dörtyol Meydanı, Esenler, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c93b5b12-38dc-4521-b452-b0df018001f3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Esenyurt Belediyesi Kültür ve Sanat Merkezi", "summary": "İlçenin en önemli kültürel etkinlik mekanıdır; tiyatro, konser ve sergilere ev sahipliği yapar.", "place_query": "Esenyurt Belediyesi Kültür ve Sanat Merkezi, İstanbul"}, {"title": "Esenyurt Kent Meydanı", "summary": "İlçenin kalbi sayılan bu meydan, sosyal yaşamın merkezi olup çevresinde kafeler ve alışveriş noktaları bulunur.", "place_query": "Esenyurt Kent Meydanı, İstanbul"}, {"title": "Esenyurt Sahil Bandı", "summary": "Marmara Denizi kıyısında uzanan yürüyüş yolu ve yeşil alanlarıyla dinlenmek ve manzara izlemek için idealdir.", "place_query": "Esenyurt Sahil Bandı, İstanbul"}, {"title": "Beylikdüzü Yaşam Vadisi", "summary": "Esenyurt sınırına yakın bu büyük park, bisiklet yolları, göletleri ve spor alanlarıyla popüler bir rekreasyon alanıdır.", "place_query": "Beylikdüzü Yaşam Vadisi, İstanbul"}, {"title": "Esenyurt Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla ailelerin sıkça tercih ettiği bir parktır.", "place_query": "Esenyurt Millet Bahçesi, İstanbul"}, {"title": "Esenyurt Stadyumu", "summary": "Spor etkinlikleri ve konserler için kullanılan bu stadyum, ilçenin önemli toplanma noktalarından biridir.", "place_query": "Esenyurt Stadyumu, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f085c108-910f-4278-809f-7182ac422d9f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pierre Loti Tepesi", "summary": "Haliç''in eşsiz manzarası eşliğinde çay keyfi yapmak için ideal bir seyir noktasıdır. Fransız yazar Pierre Loti''nin adını taşıyan tepeye teleferikle de ulaşabilirsiniz.", "place_query": "Pierre Loti Tepesi, Eyüpsultan, İstanbul"}, {"title": "Eyüp Sultan Camii ve Türbesi", "summary": "İstanbul''un en kutsal ziyaret noktalarından biri olan cami, Hz. Ebu Eyyub el-Ensari''nin türbesini barındırır. Özellikle cuma ve kandil günlerinde yoğun ziyaretçi akınına uğrar.", "place_query": "Eyüp Sultan Camii, Eyüpsultan, İstanbul"}, {"title": "Minyatürk", "summary": "Türkiye ve Osmanlı coğrafyasındaki önemli yapıların 1/25 ölçekli minyatürlerinin sergilendiği açık hava müzesidir. Çocuklu aileler için eğlenceli ve öğretici bir duraktır.", "place_query": "Minyatürk, Eyüpsultan, İstanbul"}, {"title": "Santralistanbul", "summary": "Eski bir elektrik santralinden dönüştürülen bu kültür merkezi, çağdaş sanat sergileri ve etkinliklere ev sahipliği yapar. Endüstriyel mimarisi ve Haliç manzarasıyla dikkat çeker.", "place_query": "Santralistanbul, Eyüpsultan, İstanbul"}, {"title": "Eyüpsultan Mezarlığı", "summary": "Tarihi ve manevi atmosferiyle ünlü bu mezarlık, Osmanlı döneminden kalma birçok devlet adamının ve sanatçının kabrine ev sahipliği yapar. Huzurlu bir yürüyüş için idealdir.", "place_query": "Eyüpsultan Mezarlığı, Eyüpsultan, İstanbul"}, {"title": "Feshane", "summary": "Osmanlı döneminde fes üretimi için kurulan, günümüzde ise fuar, sergi ve etkinlik alanı olarak kullanılan tarihi bir yapıdır. Haliç kıyısındaki konumuyla keyifli bir gezinti sunar.", "place_query": "Feshane, Eyüpsultan, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6a7542fb-0b46-4e27-a37b-c94651df16c1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayasofya Camii", "summary": "Bizans İmparatorluğu''ndan günümüze ulaşan muhteşem bir mimari şaheser olan Ayasofya, hem müze hem de cami olarak hizmet vermiş, İstanbul''un sembol yapılarından biridir. İçindeki devasa kubbesi, mozaikleri ve tarihi atmosferi ile ziyaretçileri büyüler.", "place_query": "Ayasofya Camii, Fatih, İstanbul"}, {"title": "Sultanahmet Camii (Mavi Camii)", "summary": "Altı minaresi ve içini süsleyen mavi İznik çinileriyle ünlü olan Sultanahmet Camii, İstanbul''un en önemli ibadet ve turizm merkezlerindendir. Avlusundaki geniş alan ve etkileyici mimarisiyle görenleri hayran bırakır.", "place_query": "Sultanahmet Camii, Fatih, İstanbul"}, {"title": "Kapalıçarşı", "summary": "Dünyanın en büyük ve en eski kapalı çarşılarından biri olan Kapalıçarşı, 60''tan fazla sokağı ve binlerce dükkanıyla alışveriş tutkunları için bir cennettir. Altın, halı, baharat, hediyelik eşya gibi her şeyi bulabileceğiniz tarihi bir çarşıdır.", "place_query": "Kapalıçarşı, Fatih, İstanbul"}, {"title": "Topkapı Sarayı", "summary": "Osmanlı İmparatorluğu''nun kalbi olan Topkapı Sarayı, padişahların yaşadığı ve devleti yönettiği görkemli bir saraydır. Harem dairesi, kutsal emanetler ve muhteşem Boğaz manzarasıyla ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Topkapı Sarayı, Fatih, İstanbul"}, {"title": "Yerebatan Sarnıcı", "summary": "Bizans döneminden kalma devasa bir yeraltı su deposu olan Yerebatan Sarnıcı, sütun ormanı ve loş ışıklarıyla mistik bir atmosfere sahiptir. Medusa başlı sütunları ve büyüleyici akustiğiyle İstanbul''un en popüler turistik noktalarındandır.", "place_query": "Yerebatan Sarnıcı, Fatih, İstanbul"}, {"title": "Süleymaniye Camii", "summary": "Mimar Sinan''ın ustalık eserlerinden biri olan Süleymaniye Camii, İstanbul''un silüetine hakim bir tepede yer alır. Geniş avlusu, zarif minareleri ve Haliç manzarasıyla hem ibadet hem de seyir için ideal bir mekandır.", "place_query": "Süleymaniye Camii, Fatih, İstanbul"}, {"title": "Gülhane Parkı", "summary": "Topkapı Sarayı''nın hemen yanında yer alan Gülhane Parkı, İstanbul''un en eski ve en büyük parklarından biridir. Tarihi ağaçları, yürüyüş yolları ve deniz manzarasıyla şehrin karmaşasından kaçmak için huzurlu bir ortam sunar.", "place_query": "Gülhane Parkı, Fatih, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f78e0354-27d8-4a89-8627-f03f7fc14a41'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gaziosmanpaşa Meydanı ve Anıtı", "summary": "İlçenin merkezi ve sembolü olan bu meydan, Gaziosmanpaşa Anıtı ile dikkat çeker. Çevresindeki kafeler ve alışveriş noktalarıyla hem yerel halkın hem de ziyaretçilerin buluşma noktasıdır.", "place_query": "Gaziosmanpaşa Meydanı, Gaziosmanpaşa, İstanbul"}, {"title": "Vialand Tema Parkı (Eurasia Theme Park)", "summary": "İstanbul''un en büyük eğlence parklarından biri olan Vialand, lunaparkı, alışveriş merkezi ve çeşitli etkinlik alanlarıyla aileler ve çocuklar için popüler bir destinasyondur.", "place_query": "Vialand Tema Parkı, Gaziosmanpaşa, İstanbul"}, {"title": "Olimpiyat Parkı (İstanbul Olimpiyat Parkı)", "summary": "Geniş yeşil alanları, yürüyüş ve bisiklet yolları ile doğayla iç içe vakit geçirmek isteyenler için ideal bir rekreasyon alanıdır. Spor tesisleri ve göletiyle dikkat çeker.", "place_query": "İstanbul Olimpiyat Parkı, Gaziosmanpaşa, İstanbul"}, {"title": "Gaziosmanpaşa Belediyesi Kültür ve Sanat Merkezi", "summary": "Tiyatro, sergi ve konser gibi kültürel etkinliklere ev sahipliği yapan bu merkez, ilçenin sanat hayatına canlılık katar. Ziyaretçiler için ücretsiz ve ücretli birçok etkinlik sunar.", "place_query": "Gaziosmanpaşa Belediyesi Kültür ve Sanat Merkezi, Gaziosmanpaşa, İstanbul"}, {"title": "Küçükköy Merkez Camii", "summary": "Tarihi bir Osmanlı camisi olan Küçükköy Merkez Camii, mimarisi ve manevi atmosferiyle ilçenin önemli dini yapılarından biridir. Çevresindeki tarihi çarşı da gezilmeye değerdir.", "place_query": "Küçükköy Merkez Camii, Gaziosmanpaşa, İstanbul"}, {"title": "Gaziosmanpaşa Ormanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için küçük bir doğa kaçamağı sunan bu ormanlık alan, piknik ve doğa yürüyüşü için idealdir.", "place_query": "Gaziosmanpaşa Ormanı, Gaziosmanpaşa, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '24fb526f-e822-4d1f-a181-687f12bc4250'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güngören Merkez Camii", "summary": "İlçenin simgesi haline gelmiş büyük ve modern bir camidir. Geniş avlusu ve etkileyici mimarisiyle hem ibadet hem de ziyaret amaçlı uğranan önemli bir noktadır.", "place_query": "Güngören Merkez Camii, Güngören, İstanbul"}, {"title": "Güngören Belediyesi Parkı ve Mesire Alanı", "summary": "Şehrin kalabalığından kaçmak isteyenler için ideal bir yeşil alandır. Yürüyüş yolları, göleti ve piknik alanlarıyla ailelerin sıkça tercih ettiği bir dinlenme noktasıdır.", "place_query": "Güngören Belediyesi Parkı, Güngören, İstanbul"}, {"title": "Topkapı Kültür Parkı", "summary": "Güngören sınırlarına yakın olan bu büyük park, tarihi surların hemen yanında yer alır. Geniş yeşil alanları, yürüyüş parkurları ve açık hava etkinlikleriyle popülerdir.", "place_query": "Topkapı Kültür Parkı, Topkapı, İstanbul"}, {"title": "Güngören Kapalı Pazar Yeri", "summary": "Yöresel ürünler ve taze meyve-sebze alışverişi için canlı bir merkezdir. Haftanın belirli günlerinde kurulan pazar, ilçenin sosyal ve ticari hayatının kalbinde yer alır.", "place_query": "Güngören Kapalı Pazar Yeri, Güngören, İstanbul"}, {"title": "Haznedar Çarşısı", "summary": "Güngören''in en işlek alışveriş noktalarından biridir. Giyimden hediyelik eşyaya kadar birçok ürünü bulabileceğiniz bu çarşı, yerel halkın uğrak yeridir.", "place_query": "Haznedar Çarşısı, Güngören, İstanbul"}, {"title": "İstanbul Surları (Güngören Kesimi)", "summary": "Tarihi Bizans surlarının ilçe sınırları içinde kalan bölümü, tarihe ilgi duyanlar için önemli bir duraktır. Surlar boyunca yürüyüş yaparak İstanbul''un savunma geçmişine tanıklık edebilirsiniz.", "place_query": "İstanbul Surları, Güngören, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '60e08af1-4c8d-4531-adec-636de9bbc49f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Moda Sahili", "summary": "Kadıköy''ün en popüler sahil şeridi olan Moda Sahili, yürüyüş yolu, yeşil alanları ve deniz manzarasıyla hem yerli halkın hem de turistlerin uğrak noktasıdır. Özellikle gün batımında eşsiz bir manzara sunar.", "place_query": "Moda Sahili, Kadıköy, İstanbul"}, {"title": "Kadıköy Çarşı", "summary": "İstanbul''un en hareketli ve renkli semt pazarlarından biri olan Kadıköy Çarşı, balıkçıları, baharatçıları, butik kafeleri ve sokak lezzetleriyle ünlüdür. Alışveriş ve gastronomi için ideal bir yerdir.", "place_query": "Kadıköy Çarşı, Kadıköy, İstanbul"}, {"title": "Haydarpaşa Garı", "summary": "Tarihi 1908 yılına dayanan ve Alman mimarisiyle inşa edilen Haydarpaşa Garı, İstanbul''un simge yapılarından biridir. Deniz kıyısındaki konumu ve görkemli cephesiyle fotoğrafçıların favorisidir.", "place_query": "Haydarpaşa Garı, Kadıköy, İstanbul"}, {"title": "Yoğurtçu Parkı", "summary": "Deniz kenarında geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla bilinen Yoğurtçu Parkı, aileler ve spor yapmak isteyenler için popüler bir dinlenme noktasıdır.", "place_query": "Yoğurtçu Parkı, Kadıköy, İstanbul"}, {"title": "Kadıköy Boğa Heykeli", "summary": "Kadıköy''ün en bilinen sembollerinden biri olan Boğa Heykeli, Altıyol meydanında yer alır. Buluşma noktası olarak kullanılan bu heykel, çevresindeki kafe ve restoranlarla canlı bir atmosfere sahiptir.", "place_query": "Kadıköy Boğa Heykeli, Kadıköy, İstanbul"}, {"title": "Fenerbahçe Parkı", "summary": "Deniz manzaralı geniş bir park olan Fenerbahçe Parkı, yürüyüş yolları, piknik alanları ve çocuk oyun alanlarıyla huzurlu bir kaçış noktasıdır. Aynı zamanda Fenerbahçe Spor Kulübü''nün tarihi tesislerine ev sahipliği yapar.", "place_query": "Fenerbahçe Parkı, Kadıköy, İstanbul"}, {"title": "Kadıköy Antikacılar Çarşısı", "summary": "Eski eşya ve antika meraklıları için bir cennet olan bu çarşı, nostaljik objeler, vintage mobilyalar ve koleksiyon ürünleriyle doludur. Keşfetmek için saatler harcanabilir.", "place_query": "Kadıköy Antikacılar Çarşısı, Kadıköy, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4ecd716b-88d2-446a-bd7a-bb83fc2daba1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sadberk Hanım Müzesi", "summary": "Osmanlı ve Anadolu medeniyetlerine ait zengin bir arkeoloji ve etnografya koleksiyonuna ev sahipliği yapan bu müze, tarihi bir yalıda yer alır ve kültür meraklıları için eşsiz bir duraktır.", "place_query": "Sadberk Hanım Müzesi, Kağıthane, İstanbul"}, {"title": "Kağıthane Hasbahçe Mesire Alanı", "summary": "Tarihi bir mesire yeri olan bu yeşil alan, göleti ve yürüyüş yollarıyla şehrin ortasında huzurlu bir kaçış noktası sunar.", "place_query": "Kağıthane Hasbahçe Mesire Alanı, Kağıthane, İstanbul"}, {"title": "Kağıthane Deresi ve Çevresi", "summary": "Restore edilmiş dere kenarı yürüyüş yolu, kafeleri ve yeşil alanlarıyla ilçenin en popüler sosyalleşme ve dinlenme noktalarından biridir.", "place_query": "Kağıthane Deresi, Kağıthane, İstanbul"}, {"title": "İstanbul Cevahir AVM", "summary": "Avrupa''nın en büyük alışveriş merkezlerinden biri olan Cevahir, yüzlerce mağazası, yeme-içme alanları ve eğlence seçenekleriyle ziyaretçileri cezbeder.", "place_query": "İstanbul Cevahir AVM, Kağıthane, İstanbul"}, {"title": "Emirgan Korusu (Kağıthane sınırına yakın)", "summary": "Boğaz manzaralı bu tarihi koru, rengârenk çiçekleri, köşkleri ve yürüyüş parkurlarıyla doğaseverler için ideal bir mekandır.", "place_query": "Emirgan Korusu, Sarıyer, İstanbul"}, {"title": "Kağıthane Belediyesi Sanat Galerisi ve Kültür Merkezi", "summary": "Sergiler, tiyatro oyunları ve atölyelerle ilçenin kültür sanat hayatına canlılık katan bu merkez, sanatseverler için önemli bir duraktır.", "place_query": "Kağıthane Belediyesi Kültür Merkezi, Kağıthane, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6b534dd0-23c7-4bf0-97d2-e8cccbe281ce'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kartal Sahil Parkı", "summary": "Marmara Denizi kıyısında uzanan bu park, yürüyüş ve bisiklet yolları, yeşil alanları ve deniz manzarasıyla Kartal''ın en popüler dinlenme ve gezinti noktasıdır.", "place_query": "Kartal Sahil Parkı, Kartal, İstanbul"}, {"title": "Kartal Meydanı ve Atatürk Anıtı", "summary": "İlçenin merkezi sayılan meydan, çevresindeki kafeler ve alışveriş olanaklarıyla hem yerel halkın hem de ziyaretçilerin buluşma noktasıdır; ortasındaki Atatürk Anıtı ise simgesel değer taşır.", "place_query": "Kartal Meydanı, Kartal, İstanbul"}, {"title": "Yakacık Çınar Mesire Yeri", "summary": "Kartal''ın Yakacık semtinde yer alan bu geniş mesire alanı, büyük çınar ağaçları altında piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Yakacık Çınar Mesire Yeri, Kartal, İstanbul"}, {"title": "Aydos Kalesi", "summary": "Kartal sınırları içinde kalan tarihi bir Bizans kalesidir; ormanlık alan içindeki kaleye tırmanarak İstanbul manzarasını seyretmek mümkündür.", "place_query": "Aydos Kalesi, Kartal, İstanbul"}, {"title": "Kartal Belediyesi Kültür Merkezi", "summary": "Tiyatro oyunları, konserler ve sergilere ev sahipliği yapan bu merkez, ilçedeki kültürel etkinliklerin kalbi konumundadır.", "place_query": "Kartal Belediyesi Kültür Merkezi, Kartal, İstanbul"}, {"title": "Soğanlık Sahili", "summary": "Kartal''ın Soğanlık semtinde yer alan bu sahil şeridi, balık tutma noktaları ve deniz kenarında yürüyüş yapma imkanı sunar; özellikle gün batımında manzarası etkileyicidir.", "place_query": "Soğanlık Sahili, Kartal, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7a54919b-42f2-4b11-ae6b-efe554c79651'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Küçükçekmece Gölü", "summary": "İstanbul''un önemli doğal sulak alanlarından biri olan göl, kuş gözlemciliği ve doğa yürüyüşleri için idealdir. Özellikle gün batımında sunduğu manzara ile fotoğrafçıların da uğrak noktasıdır.", "place_query": "Küçükçekmece Gölü, Küçükçekmece, İstanbul"}, {"title": "Menekşe Plajı", "summary": "Küçükçekmece sahilinde yer alan bu plaj, yaz aylarında serinlemek ve deniz keyfi yapmak isteyenler için popüler bir mekandır. Sahil boyunca yürüyüş yapabilir, kafe ve restoranlarda vakit geçirebilirsiniz.", "place_query": "Menekşe Plajı, Küçükçekmece, İstanbul"}, {"title": "Küçükçekmece Sahil Parkı", "summary": "Marmara Denizi kıyısında uzanan bu park, yürüyüş ve bisiklet yolları, yeşil alanları ve dinlenme banklarıyla aileler için huzurlu bir kaçış noktasıdır. Hafta sonları piknik yapmak için de sıkça tercih edilir.", "place_query": "Küçükçekmece Sahil Parkı, Küçükçekmece, İstanbul"}, {"title": "Küçükçekmece Belediyesi Bilim ve Sanat Merkezi", "summary": "Çocuklar ve gençler için bilim, teknoloji ve sanat atölyelerinin düzenlendiği bu merkez, eğitici ve eğlenceli aktiviteler arayan ailelerin ilgisini çeker. Planetaryumu ve interaktif sergileriyle öne çıkar.", "place_query": "Küçükçekmece Belediyesi Bilim ve Sanat Merkezi, Küçükçekmece, İstanbul"}, {"title": "Cennet Mahallesi Halk Plajı", "summary": "Küçükçekmece''de denize girmek için bir diğer seçenek olan bu plaj, temiz suyu ve geniş kumsalıyla bilinir. Çevresindeki kafe ve büfeler sayesinde gün boyu konforlu bir deniz keyfi sunar.", "place_query": "Cennet Mahallesi Halk Plajı, Küçükçekmece, İstanbul"}, {"title": "Kanarya Sahil Parkı", "summary": "Sahil şeridinde yer alan bu park, özellikle akşam yürüyüşleri ve deniz manzarası eşliğinde dinlenmek isteyenler için idealdir. Çocuk oyun alanları ve spor aletleriyle de aktiftir.", "place_query": "Kanarya Sahil Parkı, Küçükçekmece, İstanbul"}, {"title": "Küçükçekmece Atatürk Parkı", "summary": "İlçenin merkezinde bulunan bu büyük park, anıtı, göleti ve geniş yeşil alanlarıyla hem dinlenme hem de sosyalleşme alanıdır. Hafta sonu aile piknikleri ve çocuk oyunları için uygundur.", "place_query": "Küçükçekmece Atatürk Parkı, Küçükçekmece, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '551e81cc-4e4f-438a-81c4-04e09026e95b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Maltepe Sahil Parkı", "summary": "İstanbul''un en uzun sahil şeritlerinden birine sahip olan bu park, yürüyüş ve bisiklet yolları, yeşil alanları ve deniz manzarasıyla hafta sonu kaçamakları için ideal bir noktadır.", "place_query": "Maltepe Sahil Parkı, Maltepe, İstanbul"}, {"title": "Maltepe Pazarı", "summary": "Her hafta kurulan ve bölgenin en büyük açık hava pazarlarından biri olan Maltepe Pazarı, taze meyve-sebze, giyim ve ev eşyalarıyla renkli bir alışveriş deneyimi sunar.", "place_query": "Maltepe Pazarı, Maltepe, İstanbul"}, {"title": "Başıbüyük Parkı ve Mesire Alanı", "summary": "Doğal güzellikleri ve geniş piknik alanlarıyla bilinen bu mesire yeri, özellikle aileler için huzurlu bir doğa kaçışı ve mangal keyfi imkanı sağlar.", "place_query": "Başıbüyük Parkı, Maltepe, İstanbul"}, {"title": "Orhangazi Şehir Parkı", "summary": "İçerisinde yapay göleti, yürüyüş parkurları ve çocuk oyun alanları bulunan bu park, Maltepe''nin en popüler sosyalleşme ve dinlenme alanlarından biridir.", "place_query": "Orhangazi Şehir Parkı, Maltepe, İstanbul"}, {"title": "Maltepe Dragos Tepesi", "summary": "Adalar ve Marmara Denizi manzarasına hakim olan bu seyir noktası, özellikle gün batımında muhteşem bir fotoğraf karesi yakalamak isteyenlerin uğrak noktasıdır.", "place_query": "Dragos Tepesi, Maltepe, İstanbul"}, {"title": "Maltepe Belediyesi Prof. Dr. Türkan Saylan Kültür Merkezi", "summary": "Tiyatro, konser ve sergi gibi birçok kültürel etkinliğe ev sahipliği yapan bu merkez, ilçenin sanat ve kültür hayatının kalbi konumundadır.", "place_query": "Prof. Dr. Türkan Saylan Kültür Merkezi, Maltepe, İstanbul"}, {"title": "Altayçeşme Tabiat Parkı", "summary": "Şehir merkezine yakın olmasına rağmen sessiz bir doğa ortamı sunan bu tabiat parkı, yürüyüş yapmak ve temiz hava almak için sık tercih edilen bir alandır.", "place_query": "Altayçeşme Tabiat Parkı, Maltepe, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '52a8310c-edf6-4179-9a87-03eae1713a48'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pendik Sahil ve Millet Bahçesi", "summary": "Marmara Denizi kıyısında uzanan geniş yürüyüş yolları, bisiklet parkuru ve yeşil alanlarıyla hafta sonu aile gezileri için ideal bir rekreasyon alanıdır. Deniz manzaralı kafelerde oturup vapurların geçişini izleyebilirsiniz.", "place_query": "Pendik Sahil ve Millet Bahçesi, Pendik, İstanbul"}, {"title": "Pendik Marina", "summary": "Modern yat limanı, restoranları ve kafeleriyle ünlü olan marina, özellikle akşam saatlerinde romantik bir atmosfer sunar. Deniz kenarında yürüyüş yapabilir, balık restoranlarında taze deniz ürünleri tadabilirsiniz.", "place_query": "Pendik Marina, Pendik, İstanbul"}, {"title": "Göksu Parkı", "summary": "İçerisinde yapay göleti, piknik alanları ve çocuk oyun parkları bulunan büyük bir şehir parkıdır. Özellikle yaz aylarında ailelerin uğrak noktası olup, sandal kiralayarak gölette gezinti yapabilirsiniz.", "place_query": "Göksu Parkı, Pendik, İstanbul"}, {"title": "Tarihi Pendik Çarşısı", "summary": "Osmanlı döneminden kalma dar sokakları ve tarihi dükkanlarıyla ünlü bu çarşı, yöresel ürünler ve hediyelik eşyalar almak için idealdir. Ayrıca çarşı içindeki tarihi hamam ve camileri de ziyaret edebilirsiniz.", "place_query": "Tarihi Pendik Çarşısı, Pendik, İstanbul"}, {"title": "Pendik Kaynarca Tabiat Parkı", "summary": "Şehir merkezine yakın olmasına rağmen doğal güzellikleriyle dikkat çeken bu park, yürüyüş parkurları ve piknik masalarıyla doğaseverler için kaçış noktasıdır. İçerisindeki küçük gölet ve çam ağaçları huzur verici bir ortam sunar.", "place_query": "Pendik Kaynarca Tabiat Parkı, Pendik, İstanbul"}, {"title": "Viaport Marina Outlet Center", "summary": "Alışveriş ve eğlenceyi bir arada sunan bu büyük alışveriş merkezi, marka mağazaları, sinema salonları ve yemek alanlarıyla ünlüdür. Ayrıca marinası ve açık hava etkinlik alanlarıyla tüm gün vakit geçirebileceğiniz bir destinasyondur.", "place_query": "Viaport Marina Outlet Center, Pendik, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4145aa52-6218-412b-bffd-94db297eee2a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sancaktepe Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla aileler için huzurlu bir kaçış noktasıdır. Piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Sancaktepe Millet Bahçesi, Sancaktepe, İstanbul"}, {"title": "Sarıgazi Göleti ve Mesire Alanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için popüler bir mesire alanıdır. Gölet çevresinde yürüyüş yapabilir, balık tutabilir veya mangal keyfi yapabilirsiniz.", "place_query": "Sarıgazi Göleti Mesire Alanı, Sancaktepe, İstanbul"}, {"title": "Abdurrahmangazi Cami", "summary": "Modern Osmanlı mimarisiyle dikkat çeken bu büyük cami, ilçenin önemli dini ve kültürel sembollerinden biridir. Geniş avlusu ve etkileyici kubbesiyle ziyaretçilerini cezbeder.", "place_query": "Abdurrahmangazi Cami, Sancaktepe, İstanbul"}, {"title": "Sancaktepe Belediyesi Prof. Dr. Necmettin Erbakan Kültür Merkezi", "summary": "Tiyatro, konser ve sergi gibi çeşitli kültürel etkinliklere ev sahipliği yapan modern bir merkezdir. İlçenin sanat ve kültür hayatının kalbidir.", "place_query": "Prof. Dr. Necmettin Erbakan Kültür Merkezi, Sancaktepe, İstanbul"}, {"title": "Samandıra Hipodromu", "summary": "Türkiye''nin önemli at yarışı pistlerinden biri olan hipodrom, hafta sonları düzenlenen yarışlarla spor ve eğlence tutkunlarını ağırlar. Geniş alanı ve sosyal tesisleriyle dikkat çeker.", "place_query": "Samandıra Hipodromu, Sancaktepe, İstanbul"}, {"title": "Merve Mahallesi Pazar Yeri ve Parkı", "summary": "Haftalık kurulan semt pazarı ve çevresindeki park, yöresel ürünleri keşfetmek ve keyifli bir gün geçirmek için canlı bir noktadır. Özellikle pazar günleri oldukça hareketlidir.", "place_query": "Merve Mahallesi Pazar Yeri, Sancaktepe, İstanbul"}, {"title": "Sancaktepe Kent Ormanı", "summary": "Koşu ve yürüyüş parkurları, bisiklet yolları ve temiz havasıyla spor yapmak ve doğada vakit geçirmek için harika bir alandır. Şehir hayatına kısa bir mola vermek için idealdir.", "place_query": "Sancaktepe Kent Ormanı, Sancaktepe, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '57de898b-122a-42a4-a0ec-d57a4f7fbeac'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Belgrad Ormanı", "summary": "İstanbul''un en büyük ve en popüler doğal alanlarından biri olan Belgrad Ormanı, yürüyüş parkurları, piknik alanları ve Atatürk Arboretumu ile doğaseverler için ideal bir kaçış noktasıdır.", "place_query": "Belgrad Ormanı, Sarıyer, İstanbul"}, {"title": "Rumeli Feneri", "summary": "Karadeniz''in Boğaz''la buluştuğu noktada yer alan Rumeli Feneri, muhteşem deniz manzarası, tarihi deniz feneri ve yürüyüş rotalarıyla ziyaretçilerine huzurlu bir atmosfer sunar.", "place_query": "Rumeli Feneri, Sarıyer, İstanbul"}, {"title": "Sarıyer Merkez ve Pazarı", "summary": "Sarıyer''in hareketli merkezi, meşhur boğaz manzaralı balıkçıları ve haftalık pazarıyla ünlüdür; özellikle taze balık ve deniz ürünleri yemek için uğranması gereken bir noktadır.", "place_query": "Sarıyer Merkez, İstanbul"}, {"title": "Kilyos Plajı", "summary": "Karadeniz kıyısında yer alan Kilyos, geniş plajı, sörf olanakları ve yaz aylarında canlı atmosferiyle İstanbul''un en popüler sahil bölgelerinden biridir.", "place_query": "Kilyos Plajı, Sarıyer, İstanbul"}, {"title": "Atatürk Arboretumu", "summary": "Belgrad Ormanı içinde yer alan bu botanik bahçesi, yüzlerce ağaç ve bitki türüne ev sahipliği yapar; doğa fotoğrafçıları ve huzur arayanlar için eşsiz bir sakinlik sunar.", "place_query": "Atatürk Arboretumu, Sarıyer, İstanbul"}, {"title": "Maden Deresi", "summary": "Belgrad Ormanı''nın içinden geçen Maden Deresi, yürüyüş yolları ve piknik alanlarıyla doğayla iç içe vakit geçirmek isteyenlerin uğrak noktalarından biridir.", "place_query": "Maden Deresi, Sarıyer, İstanbul"}, {"title": "Sarıyer Boğaz Kıyısı ve İskele", "summary": "Sarıyer iskelesi çevresi, boğaz manzaralı kafeleri, balık ekmek tezgahları ve yürüyüş yoluyla hem yerli halkın hem de turistlerin keyifle vakit geçirdiği bir alandır.", "place_query": "Sarıyer İskelesi, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '053438f3-4e3d-4c3b-b928-c95f5fc0cfdd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şile Feneri", "summary": "Tarihi deniz feneri ve çevresindeki kayalıklar, gün batımında eşsiz manzaralar sunar. Karadeniz''in dalgalarına karşı yürüyüş yapabilir, fenerin tarihi dokusunu keşfedebilirsiniz.", "place_query": "Şile Feneri, Şile, İstanbul"}, {"title": "Şile Plajı", "summary": "İstanbul''un en popüler halk plajlarından biri olan Şile Plajı, geniş kumsalı ve dalgalı deniziyle yaz aylarında yoğun ilgi görür. Çevresinde kafe ve restoranlar bulunur.", "place_query": "Şile Plajı, Şile, İstanbul"}, {"title": "Ağlayan Kaya", "summary": "Doğal bir kaya oluşumu olan Ağlayan Kaya, suyun kayadan süzülerek akmasıyla ilginç bir görüntü oluşturur. Etrafındaki yeşil alan piknik ve dinlenme için idealdir.", "place_query": "Ağlayan Kaya, Şile, İstanbul"}, {"title": "Şile Kalesi", "summary": "Tarihi bir Ceneviz kalesi olan Şile Kalesi, deniz kenarında yükselir ve bölgenin simgelerindendir. Kaleyi çevreleyen surlar ve manzara fotoğrafçılar için harika bir noktadır.", "place_query": "Şile Kalesi, Şile, İstanbul"}, {"title": "Sofular Köyü Plajı", "summary": "Sakin ve temiz deniziyle bilinen Sofular Köyü Plajı, kalabalıktan uzaklaşmak isteyenler için idealdir. Doğal kumsalı ve çam ormanları arasında huzurlu bir gün geçirebilirsiniz.", "place_query": "Sofular Köyü Plajı, Şile, İstanbul"}, {"title": "Şile Kumbaba Plajı", "summary": "Kumsalı ve dalgalı deniziyle bilinen Kumbaba Plajı, özellikle aileler tarafından tercih edilir. Çevresindeki tesisler sayesinde konforlu bir plaj deneyimi sunar.", "place_query": "Kumbaba Plajı, Şile, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0551f5c8-831a-404f-9f84-3f3d3a257706'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Silivri Sahili ve Yürüyüş Yolu", "summary": "Marmara Denizi kıyısında uzanan bu sahil şeridi, yürüyüş yolu, bisiklet parkuru ve dinlenme alanlarıyla hem yerli halkın hem de ziyaretçilerin uğrak noktasıdır. Özellikle gün batımında eşsiz bir manzara sunar.", "place_query": "Silivri Sahili, Silivri, İstanbul"}, {"title": "Silivri Cezaevi Müzesi", "summary": "Türkiye''nin en büyük cezaevi komplekslerinden biri olan Silivri Cezaevi''nin bir bölümü müzeye dönüştürülmüştür. Cezaevi yaşamına dair objeler ve tarihi belgelerin sergilendiği bu müze, ilginç bir deneyim sunar.", "place_query": "Silivri Cezaevi Müzesi, Silivri, İstanbul"}, {"title": "Piri Mehmet Paşa Camii ve Külliyesi", "summary": "16. yüzyılda Mimar Sinan tarafından inşa edilen bu tarihi cami ve külliye, Silivri''nin en önemli Osmanlı dönemi yapılarındandır. Cami, medrese, hamam ve çarşıdan oluşan külliye, tarihi dokusuyla dikkat çeker.", "place_query": "Piri Mehmet Paşa Camii, Silivri, İstanbul"}, {"title": "Kumburgaz Plajı", "summary": "Silivri''nin en popüler sahil bölgelerinden biri olan Kumburgaz, ince kumlu plajı ve denize sıfır kafe-restoranlarıyla yaz aylarında yoğun ilgi görür. Aileler ve genç gruplar için ideal bir günlük kaçamak noktasıdır.", "place_query": "Kumburgaz Plajı, Silivri, İstanbul"}, {"title": "Silivri Atatürk Kent Parkı", "summary": "Geniş yeşil alanları, göleti, yürüyüş yolları ve çocuk oyun alanlarıyla şehrin ortasında bir nefes alma noktasıdır. Piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Silivri Atatürk Kent Parkı, Silivri, İstanbul"}, {"title": "Değirmenköy Sahili", "summary": "Silivri''nin daha sakin ve doğal kalmış sahil bölgelerinden biridir. Denize girmek, balık tutmak ve huzurlu bir atmosferde vakit geçirmek isteyenler için tercih edilir.", "place_query": "Değirmenköy Sahili, Silivri, İstanbul"}, {"title": "Gümüşyaka Sahili", "summary": "Uzun sahil şeridi ve yaz aylarında canlanan sosyal tesisleriyle bilinen Gümüşyaka, Silivri''nin deniz turizmi açısından önemli noktalarındandır. Özellikle hafta sonu kaçamakları için popülerdir.", "place_query": "Gümüşyaka Sahili, Silivri, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c51ab1e0-59fc-4adf-8634-3a6fa05f79f3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İstanbul Cevahir Alışveriş Merkezi", "summary": "Avrupa''nın en büyük alışveriş merkezlerinden biri olan Cevahir, Şişli''de yer alır ve yüzlerce mağazası, yemek katı ve eğlence alanlarıyla ziyaretçilere keyifli bir alışveriş ve vakit geçirme deneyimi sunar.", "place_query": "İstanbul Cevahir Alışveriş Merkezi, Şişli, İstanbul"}, {"title": "İstanbul Lütfi Kırdar Kongre ve Sergi Sarayı", "summary": "Harbiye semtinde bulunan bu tarihi kongre merkezi, uluslararası etkinliklere, konserlere ve fuarlara ev sahipliği yapar; mimarisi ve konumuyla dikkat çeker.", "place_query": "Lütfi Kırdar Kongre Merkezi, Harbiye, Şişli, İstanbul"}, {"title": "Maçka Demokrasi Parkı", "summary": "Şişli ile Beşiktaş arasında uzanan bu yeşil vadi, yürüyüş yolları, spor alanları ve boğaz manzarasıyla şehrin ortasında doğayla iç içe bir kaçış noktasıdır.", "place_query": "Maçka Demokrasi Parkı, Şişli, İstanbul"}, {"title": "Nişantaşı", "summary": "Şişli''nin en lüks ve popüler semti olan Nişantaşı, butik mağazaları, kafeleri, sanat galerileri ve tarihi binalarıyla ünlüdür; şehir hayatının kalbinde yer alır.", "place_query": "Nişantaşı, Şişli, İstanbul"}, {"title": "Askeri Müze (Harbiye)", "summary": "Harbiye semtinde bulunan bu müze, Osmanlı ve Türk askeri tarihine ait geniş bir koleksiyon sunar; özellikle Mehteran Bölüğü gösterileriyle ünlüdür.", "place_query": "Askeri Müze, Harbiye, Şişli, İstanbul"}, {"title": "Bomonti Ada", "summary": "Eski Bomonti Bira Fabrikası''nın restore edilmesiyle oluşan bu modern yaşam merkezi, restoranları, barları, sineması ve açık hava etkinlikleriyle popüler bir buluşma noktasıdır.", "place_query": "Bomonti Ada, Şişli, İstanbul"}, {"title": "Şişli Camii", "summary": "1940''lı yıllarda inşa edilen bu modern mimarili cami, Şişli''nin simge yapılarından biridir ve geniş avlusuyla dikkat çeker.", "place_query": "Şişli Camii, Şişli, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7f36c10f-6d8a-40b9-8da9-a910ff59debe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sultanbeyli Millet Bahçesi", "summary": "İlçenin en büyük yeşil alanlarından biri olan bu park, yürüyüş yolları, göleti ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme ve piknik noktasıdır.", "place_query": "Sultanbeyli Millet Bahçesi, Sultanbeyli, İstanbul"}, {"title": "Sultanbeyli Belediyesi Kültür Merkezi", "summary": "Tiyatro, konser ve sergi gibi kültürel etkinliklere ev sahipliği yapan bu merkez, ilçedeki sanat ve kültür hayatının kalbidir.", "place_query": "Sultanbeyli Kültür Merkezi, Sultanbeyli, İstanbul"}, {"title": "Sultanbeyli Göleti ve Mesire Alanı", "summary": "Doğayla iç içe vakit geçirmek isteyenler için huzurlu bir ortam sunan gölet, çevresindeki yürüyüş parkuru ve oturma alanlarıyla hafta sonu kaçamakları için popülerdir.", "place_query": "Sultanbeyli Göleti, Sultanbeyli, İstanbul"}, {"title": "Abdurrahmangazi Cami", "summary": "Modern mimarisi ve geniş avlusuyla dikkat çeken bu cami, ilçenin önemli dini ve sosyal buluşma noktalarından biridir.", "place_query": "Abdurrahmangazi Cami, Sultanbeyli, İstanbul"}, {"title": "Sultanbeyli Kent Ormanı", "summary": "Koşu ve yürüyüş parkurları, piknik alanları ve zengin bitki örtüsüyle doğa sporları ve temiz hava arayanlar için ideal bir kaçış noktasıdır.", "place_query": "Sultanbeyli Kent Ormanı, Sultanbeyli, İstanbul"}, {"title": "Sultanbeyli Kapalı Spor Salonu", "summary": "Basketbol, voleybol ve diğer salon sporlarına ev sahipliği yapan tesis, spor etkinlikleri ve maçları izlemek için ilçedeki en önemli mekandır.", "place_query": "Sultanbeyli Spor Salonu, Sultanbeyli, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2dd1479b-56ec-4c4b-ac2f-f1b07b7ea8c2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sultangazi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla ilçenin en büyük ve en popüler rekreasyon alanıdır. Aileler ve doğa severler için huzurlu bir kaçış noktası sunar.", "place_query": "Sultangazi Millet Bahçesi, Sultangazi, İstanbul"}, {"title": "Cebeci Mahallesi Mesire Alanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için ideal bir piknik ve dinlenme alanıdır. Doğal güzelliği ve temiz havasıyla hafta sonu ziyaretçilerini ağırlar.", "place_query": "Cebeci Mesire Alanı, Sultangazi, İstanbul"}, {"title": "Sultangazi Belediyesi Kültür Merkezi", "summary": "İlçenin kültürel ve sanatsal etkinliklerine ev sahipliği yapan modern bir merkezdir. Tiyatro, sergi ve konser gibi birçok etkinliğe katılma imkanı sunar.", "place_query": "Sultangazi Belediyesi Kültür Merkezi, Sultangazi, İstanbul"}, {"title": "50. Yıl Parkı", "summary": "Sultangazi''nin merkezi noktalarından birinde yer alan bu park, spor alanları ve dinlenme banklarıyla günlük yaşamın bir parçasıdır. Özellikle akşam yürüyüşleri için tercih edilir.", "place_query": "50. Yıl Parkı, Sultangazi, İstanbul"}, {"title": "Habibler Mahallesi Seyir Tepesi", "summary": "İlçeye hakim bir tepede yer alan bu nokta, İstanbul''un geniş bir panoramik manzarasını sunar. Özellikle gün batımında fotoğrafçılar ve doğa yürüyüşçüleri için popüler bir duraktır.", "place_query": "Habibler Seyir Tepesi, Sultangazi, İstanbul"}, {"title": "Sultangazi Gençlik Merkezi", "summary": "Gençlerin sosyal ve kültürel gelişimine katkıda bulunan bu merkez, çeşitli atölye çalışmaları ve etkinlikler düzenler. Spor salonları ve kütüphanesiyle de dikkat çeker.", "place_query": "Sultangazi Gençlik Merkezi, Sultangazi, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '118db304-9478-48b7-9f99-99de99734b97'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tuzla Sahil Parkı", "summary": "İstanbul''un Anadolu Yakası''nda geniş yeşil alanları ve yürüyüş yollarıyla ünlü olan bu sahil parkı, deniz manzarası eşliğinde bisiklet sürmek veya piknik yapmak için idealdir.", "place_query": "Tuzla Sahil Parkı, Tuzla, İstanbul"}, {"title": "Tuzla Marina", "summary": "Modern yat limanı ve çevresindeki kafe-restoranlarıyla bilinen Tuzla Marina, deniz kenarında keyifli vakit geçirmek ve gün batımını izlemek için popüler bir noktadır.", "place_query": "Tuzla Marina, Tuzla, İstanbul"}, {"title": "Aydınlı Sahili", "summary": "Tuzla''nın en bilinen plajlarından biri olan Aydınlı Sahili, yaz aylarında denize girmek ve güneşlenmek için sıkça tercih edilir.", "place_query": "Aydınlı Sahili, Tuzla, İstanbul"}, {"title": "Tuzla Belediyesi Kültür Merkezi", "summary": "Tuzla''nın kültürel kalbi sayılan bu merkez, tiyatro oyunları, konserler ve sergilere ev sahipliği yaparak ziyaretçilere sanat dolu bir deneyim sunar.", "place_query": "Tuzla Belediyesi Kültür Merkezi, Tuzla, İstanbul"}, {"title": "İçmeler Mahallesi Sahil Yolu", "summary": "Deniz kenarında uzanan bu yürüyüş ve koşu parkuru, sakin atmosferi ve deniz kokusuyla Tuzla''da huzurlu bir gezinti yapmak isteyenlerin favorisidir.", "place_query": "İçmeler Sahil Yolu, Tuzla, İstanbul"}, {"title": "Tuzla Atatürk Parkı", "summary": "Şehir merkezinde yer alan bu büyük park, oyun alanları, spor aletleri ve gölgelik banklarıyla aileler için dinlendirici bir kaçış noktasıdır.", "place_query": "Tuzla Atatürk Parkı, Tuzla, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c582fdec-d089-4431-8a4b-f741f4f8b3c9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aydos Ormanı", "summary": "İstanbul''un en büyük ormanlarından biri olan Aydos Ormanı, doğa yürüyüşleri, piknik alanları ve bisiklet parkurları ile Ümraniye''de doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır. Tarihi Aydos Kalesi''ni de bünyesinde barındırır.", "place_query": "Aydos Ormanı, Ümraniye, İstanbul"}, {"title": "Aydos Kalesi", "summary": "Aydos Ormanı içinde yer alan bu tarihi Bizans kalesi, İstanbul''un fethinde önemli rol oynamış ve muhteşem bir İstanbul manzarası sunar. Tarih ve doğayı birleştiren bir keşif noktasıdır.", "place_query": "Aydos Kalesi, Ümraniye, İstanbul"}, {"title": "Ümraniye Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş yolları, göleti ve çocuk oyun alanlarıyla şehrin ortasında nefes alabileceğiniz büyük bir parktır. Ailece vakit geçirmek ve dinlenmek için idealdir.", "place_query": "Ümraniye Millet Bahçesi, İstanbul"}, {"title": "Maden Deresi Tabiat Parkı", "summary": "Ümraniye sınırları içinde kalan bu tabiat parkı, şelalesi, piknik masaları ve yürüyüş parkurları ile hafta sonu kaçamakları için popüler bir doğal alandır. Şehir gürültüsünden uzaklaşmak isteyenler için biçilmiş kaftandır.", "place_query": "Maden Deresi Tabiat Parkı, Ümraniye, İstanbul"}, {"title": "Çamlık Mesire Alanı", "summary": "Yemyeşil çam ağaçları arasında yer alan bu mesire alanı, mangal keyfi ve doğa yürüyüşü yapmak isteyenler için Ümraniye''nin en bilinen piknik noktalarındandır. Temiz havası ve sakin atmosferiyle öne çıkar.", "place_query": "Çamlık Mesire Alanı, Ümraniye, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '08c27c01-91fc-4438-9008-d2398d031f3c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kız Kulesi", "summary": "İstanbul Boğazı''nın incisi, eşsiz manzarası ve tarihi hikayeleriyle ünlü. Hem kafeteryasında Boğaz keyfi yapabilir hem de küçük müzesini gezebilirsiniz.", "place_query": "Kız Kulesi, Üsküdar, İstanbul"}, {"title": "Büyük Çamlıca Tepesi", "summary": "İstanbul''un en yüksek noktalarından biri olup Boğaz, Adalar ve şehir manzarasını panoramik olarak izleyebileceğiniz dev bir seyir terasına sahiptir.", "place_query": "Büyük Çamlıca Tepesi, Üsküdar, İstanbul"}, {"title": "Mihrimah Sultan Camii (İskele Camii)", "summary": "Mimar Sinan''ın Üsküdar''daki en önemli eserlerinden biri olan bu cami, iskeleye yakın konumu ve zarif mimarisiyle hem ibadet hem de fotoğrafçılık için popülerdir.", "place_query": "Mihrimah Sultan Camii, Üsküdar, İstanbul"}, {"title": "Maiden''s Tower (Kız Kulesi) Açıklaması ile Karıştırılmamalıdır - Şemsi Paşa Camii", "summary": "Mimar Sinan''ın kıyıya inşa ettiği küçük ama etkileyici bir cami ve külliyedir. Deniz kenarındaki konumu ve sade güzelliğiyle huzurlu bir duraktır.", "place_query": "Şemsi Paşa Camii, Üsküdar, İstanbul"}, {"title": "Beylerbeyi Sarayı", "summary": "Boğaz kıyısındaki bu görkemli Osmanlı sarayı, yazlık saray olarak kullanılmış olup ihtişamlı odaları ve bahçesiyle geziye değerdir.", "place_query": "Beylerbeyi Sarayı, Üsküdar, İstanbul"}, {"title": "Üsküdar Sahili ve Salacak", "summary": "Uzun sahil yürüyüş yolu, çay bahçeleri ve Kız Kulesi''ne en yakın nokta olmasıyla bilinir. Özellikle gün batımında romantik bir atmosfere sahiptir.", "place_query": "Salacak Sahili, Üsküdar, İstanbul"}, {"title": "Nakkaştepe Millet Bahçesi", "summary": "Boğaz manzaralı geniş yeşil alanları, yürüyüş parkurları ve piknik alanlarıyla aileler ve doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Nakkaştepe Millet Bahçesi, Üsküdar, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ca38c24c-9f5e-4cd9-ad37-d90e95104b31'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yedikule Hisarı", "summary": "Bizans ve Osmanlı dönemine tanıklık eden bu tarihi kale, İstanbul''un kara surlarının en görkemli bölümüdür. Ziyaretçiler burçlara çıkarak hem tarihi atmosferi soluyabilir hem de şehrin panoramik manzarasını izleyebilir.", "place_query": "Yedikule Hisarı, Zeytinburnu, İstanbul"}, {"title": "Zeytinburnu Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş yolları ve göletiyle aileler için huzurlu bir kaçış noktasıdır. Piknik yapmak, spor yapmak veya sadece doğanın tadını çıkarmak için idealdir.", "place_query": "Zeytinburnu Millet Bahçesi, Zeytinburnu, İstanbul"}, {"title": "Kazlıçeşme Sanat Galerisi", "summary": "Eski bir fabrika binasının restore edilmesiyle oluşturulan bu kültür merkezi, çağdaş sanat sergileri ve etkinliklere ev sahipliği yapar. Sanatseverler için ilçenin en önemli buluşma noktalarından biridir.", "place_query": "Kazlıçeşme Sanat Galerisi, Zeytinburnu, İstanbul"}, {"title": "Zeytinburnu Tarihi Su Kemeri", "summary": "Roma döneminden kalma bu etkileyici su kemeri, ilçenin en eski yapılarından biridir. Tarih meraklıları için fotoğraf çekmek ve geçmişe yolculuk yapmak için harika bir duraktır.", "place_query": "Zeytinburnu Tarihi Su Kemeri, Zeytinburnu, İstanbul"}, {"title": "Merkezefendi Camii ve Türbesi", "summary": "Osmanlı dönemine ait bu manevi mekân, Merkezefendi hazretlerinin türbesi ve çevresindeki tarihi yapılarla huzur verici bir atmosfere sahiptir. Ziyaretçiler hem ibadet edebilir hem de tarihi dokuyu hissedebilir.", "place_query": "Merkezefendi Camii ve Türbesi, Zeytinburnu, İstanbul"}, {"title": "Zeytinburnu Sahil Yolu", "summary": "Marmara Denizi kıyısında uzanan bu yürüyüş ve bisiklet yolu, gün batımında eşsiz bir manzara sunar. Spor yapmak veya deniz havası almak isteyenler için popüler bir güzergâhtır.", "place_query": "Zeytinburnu Sahil Yolu, Zeytinburnu, İstanbul"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f1a2fe1e-6b73-4833-a478-f67a515a5e89'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aliağa Sahili ve Halk Plajı", "summary": "İlçe merkezine yakın, temiz denizi ve düzenli plajı ile yaz aylarında yerli halkın ve ziyaretçilerin uğrak noktasıdır. Denize girmek ve güneşlenmek için ideal bir kıyı şeridi sunar.", "place_query": "Aliağa Halk Plajı, İzmir"}, {"title": "Kyme Antik Kenti", "summary": "Aiolis bölgesinin önemli liman kentlerinden biri olan Kyme, Aliağa sınırları içinde yer alır. Antik tiyatro, agora ve sur kalıntılarıyla tarih meraklıları için etkileyici bir açık hava müzesidir.", "place_query": "Kyme Antik Kenti, Aliağa, İzmir"}, {"title": "Myrina Antik Kenti", "summary": "Aliağa''nın Kalabaklı mevkiinde bulunan Myrina, antik döneme ait nekropol alanı ve lahitleriyle ünlüdür. Bölgedeki arkeolojik kazılar, ziyaretçilere tarih öncesine yolculuk yapma fırsatı verir.", "place_query": "Myrina Antik Kenti, Aliağa, İzmir"}, {"title": "Güzelhisar Barajı ve Mesire Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için piknik alanları, yürüyüş parkurları ve baraj manzarası sunar. Hafta sonu kaçamaklarında sık tercih edilen huzurlu bir noktadır.", "place_query": "Güzelhisar Barajı, Aliağa, İzmir"}, {"title": "Aliağa Tersaneler Bölgesi", "summary": "Türkiye''nin önemli gemi inşa ve bakım merkezlerinden biri olan bu bölge, endüstriyel turizm açısından ilgi çekicidir. Dev gemileri yakından görmek ve denizcilik faaliyetlerini izlemek mümkündür.", "place_query": "Aliağa Tersaneler Bölgesi, İzmir"}, {"title": "Helios Aliağa Alışveriş Merkezi", "summary": "Aliağa''nın modern yüzünü yansıtan alışveriş merkezi, çeşitli mağazalar, yeme-içme alanları ve sinema salonlarıyla ziyaretçilere keyifli vakit geçirme imkanı tanır.", "place_query": "Helios Aliağa AVM, İzmir"}, {"title": "Aliağa Atatürk Parkı", "summary": "Şehir merkezinde yer alan geniş ve yeşil bir park olup, yürüyüş yolları, çocuk oyun alanları ve dinlenme banklarıyla aileler için ideal bir mekandır.", "place_query": "Aliağa Atatürk Parkı, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'da48d4bb-caeb-4808-ae4b-da4eeda35493'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İnciraltı Kent Ormanı", "summary": "İzmir Körfezi''nin güzel bir manzarasına sahip geniş bir yeşil alan. Yürüyüş ve bisiklet parkurları, piknik alanları ve sahil şeridiyle özellikle hafta sonları ailelerin ve doğaseverlerin uğrak noktasıdır.", "place_query": "İnciraltı Kent Ormanı, Balçova, İzmir"}, {"title": "Balçova Teleferiği", "summary": "Şehir merkezine yakın konumuyla kolay ulaşılabilen bu teleferik, zirveye çıkarken İzmir Körfezi ve çevresinin panoramik manzarasını sunar. Tepe noktasında kafe ve seyir terası bulunur.", "place_query": "Balçova Teleferik Tesisleri, Balçova, İzmir"}, {"title": "Agamemnon Kaplıcaları", "summary": "Tarihi antik döneme kadar uzanan bu termal kaynaklar, şifalı sularıyla ünlüdür. Modern tesislerde termal havuz ve hamam hizmeti sunan kaplıca, sağlık turizmi için popüler bir duraktır.", "place_query": "Agamemnon Kaplıcaları, Balçova, İzmir"}, {"title": "Sakarya Parkı", "summary": "Balçova''nın merkezinde yer alan bu büyük park, göleti, yürüyüş yolları ve çocuk oyun alanlarıyla bilinir. Özellikle akşam saatlerinde ışıklandırmasıyla romantik bir atmosfer sunar.", "place_query": "Sakarya Parkı, Balçova, İzmir"}, {"title": "Balçova Belediyesi Sevgi Yolu", "summary": "Sahil boyunca uzanan bu yürüyüş ve bisiklet yolu, deniz kenarında keyifli bir gezinti imkanı sağlar. Çevresindeki kafe ve restoranlarla birlikte gün batımını izlemek için ideal bir noktadır.", "place_query": "Sevgi Yolu, Balçova, İzmir"}, {"title": "Balçova Barajı Mesire Alanı", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için sakin bir doğa kaçamağıdır. Baraj gölü çevresindeki yeşil alanlarda piknik yapabilir ve huzurlu bir gün geçirebilirsiniz.", "place_query": "Balçova Barajı Mesire Alanı, Balçova, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '363c24bb-4208-43f1-89ee-130630957cd7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bayındır Çarşı Hamamı", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan hamam, restore edilerek günümüze kazandırılmıştır. İlçe merkezinde yer alan bu yapı, hem mimarisi hem de kültürel değeriyle ziyaretçilerin ilgisini çekmektedir.", "place_query": "Bayındır Çarşı Hamamı, Bayındır, İzmir"}, {"title": "Bayındır Saat Kulesi", "summary": "Cumhuriyet döneminin simgelerinden biri olan saat kulesi, ilçe meydanında yer alır. Çevresindeki tarihi yapılarla birlikte Bayındır''ın en bilinen fotoğraf karelerinden birini oluşturur.", "place_query": "Bayındır Saat Kulesi, Bayındır, İzmir"}, {"title": "Bayındır Arasta Çarşısı", "summary": "Tarihi dokusunu koruyan bu çarşı, el sanatları ve yöresel ürünlerin satıldığı dükkanlarıyla ünlüdür. Ziyaretçiler burada hem alışveriş yapabilir hem de ilçenin geçmişine tanıklık edebilir.", "place_query": "Bayındır Arasta Çarşısı, Bayındır, İzmir"}, {"title": "Bayındır Müzesi", "summary": "İlçenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bu müze, ziyaretçilere Bayındır''ın geçmişine dair kapsamlı bir bakış sunar. Arkeolojik ve etnografik koleksiyonlarıyla dikkat çeker.", "place_query": "Bayındır Müzesi, Bayındır, İzmir"}, {"title": "Erikli Şelalesi", "summary": "Bayındır''a bağlı Erikli köyünde yer alan bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Erikli Şelalesi, Bayındır, İzmir"}, {"title": "Küçükdağyenice Köyü Kaya Mezarları", "summary": "Antik dönemden kalma bu kaya mezarları, bölgenin tarihi zenginliğini gözler önüne serer. Doğa ile iç içe bir ortamda yer alan bu yapılar, tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Küçükdağyenice Köyü Kaya Mezarları, Bayındır, İzmir"}, {"title": "Bayındır Zeytinlikleri ve Doğa Yürüyüş Rotaları", "summary": "İlçenin geniş zeytinlik alanları, doğa yürüyüşü ve fotoğrafçılık için eşsiz fırsatlar sunar. Rota boyunca zeytin ağaçları arasında huzurlu bir yürüyüş yapabilir, kırsal yaşamın tadını çıkarabilirsiniz.", "place_query": "Bayındır Zeytinlikleri, Bayındır, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '61834079-8c0f-4a2c-99d1-8a3ab4bf03cc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bayraklı Sahili ve Mavişehir Sahil Bandı", "summary": "İzmir Körfezi manzarasına karşı yürüyüş yapabileceğiniz, bisiklet sürebileceğiniz ve dinlenebileceğiniz geniş bir sahil şerididir. Özellikle gün batımında eşsiz bir atmosfere sahiptir.", "place_query": "Mavişehir Sahil Bandı, Bayraklı, İzmir"}, {"title": "Bayraklı Höyüğü (Bornova Höyüğü)", "summary": "İzmir''in en eski yerleşim alanlarından biri olan bu höyük, Neolitik dönemden günümüze uzanan tarihi katmanlarıyla arkeoloji meraklıları için önemli bir noktadır.", "place_query": "Bayraklı Höyüğü, Bayraklı, İzmir"}, {"title": "Egekent Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun parklarıyla aileler için ideal bir dinlenme ve piknik alanıdır. Havuzu ve kafeteryasıyla da dikkat çeker.", "place_query": "Egekent Parkı, Bayraklı, İzmir"}, {"title": "İzmir Optimum Outlet", "summary": "Bayraklı''da bulunan bu büyük alışveriş merkezi, marka mağazaları, yeme-içme alanları ve sinema salonlarıyla alışveriş ve eğlence için popüler bir duraktır.", "place_query": "İzmir Optimum Outlet, Bayraklı, İzmir"}, {"title": "Bayraklı Spor ve Etkinlik Merkezi", "summary": "Spor salonları, yüzme havuzu ve çeşitli etkinlik alanlarıyla spor yapmak veya vakit geçirmek isteyenler için modern bir tesistir.", "place_query": "Bayraklı Spor ve Etkinlik Merkezi, Bayraklı, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5f212dc7-f392-4965-987c-13ac916541dd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bergama Akropolü (Pergamon Antik Kenti)", "summary": "UNESCO Dünya Mirası listesindeki bu antik kent, Helenistik dönemin en önemli merkezlerinden biriydi. Trajan Tapınağı, dev tiyatro ve kütüphane kalıntılarıyla ziyaretçilerine büyüleyici bir tarih yolculuğu sunar.", "place_query": "Bergama Akropolü, Bergama, İzmir"}, {"title": "Bergama Asklepionu", "summary": "Antik çağın en ünlü sağlık merkezi olan Asklepion, tıp tanrısı Asklepios''a adanmıştır. Tedavi yöntemleri, kutsal kaynak suları ve etkileyici sütunlu yollarıyla tarihe tanıklık etmek isteyenler için eşsiz bir duraktır.", "place_query": "Bergama Asklepionu, Bergama, İzmir"}, {"title": "Kızılavlu (Serapis Tapınağı)", "summary": "Mısır tanrıları Serapis, İsis ve Harpokrates''e adanan bu görkemli tapınak, kırmızı tuğlalarıyla dikkat çeker. Bergama''nın en etkileyici yapılarından biri olup, Bizans döneminde kiliseye dönüştürülmüştür.", "place_query": "Kızılavlu, Bergama, İzmir"}, {"title": "Bergama Arkeoloji Müzesi", "summary": "Pergamon kazılarında çıkarılan eserlerin sergilendiği müze, antik kentten getirilen heykeller, lahitler ve günlük yaşam objeleriyle zengin bir koleksiyona sahiptir. Bergama tarihini derinlemesine keşfetmek için idealdir.", "place_query": "Bergama Arkeoloji Müzesi, Bergama, İzmir"}, {"title": "Bergama Çarşı Camii ve Külliyesi", "summary": "14. yüzyılda inşa edilen bu tarihi cami, Bergama''nın en önemli Osmanlı yapılarından biridir. Kesme taş işçiliği ve sade mimarisiyle huzurlu bir atmosfer sunar.", "place_query": "Bergama Çarşı Camii, Bergama, İzmir"}, {"title": "Bergama Kozak Yaylası", "summary": "Çam ormanları ve zengin bitki örtüsüyle çevrili bu yayla, doğa yürüyüşleri ve piknik için popüler bir kaçış noktasıdır. Özellikle sonbaharda muhteşem manzaralar sunar.", "place_query": "Kozak Yaylası, Bergama, İzmir"}, {"title": "Allianoi Antik Kenti", "summary": "Antik dönemde termal kaynaklarıyla ünlü olan Allianoi, günümüzde su altında kalmış olsa da kalıntıları hala görülebilmektedir. Tarihi ve doğal güzellikleri bir arada sunan bu alan, Bergama''nın gizli hazinelerindendir.", "place_query": "Allianoi Antik Kenti, Bergama, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9e328acb-9c75-44fa-bec4-5ddc3f54389f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beydağ Göleti", "summary": "Beydağ''ın merkezine yakın, piknik ve dinlenme alanlarıyla çevrili bu gölet, doğa yürüyüşleri ve kuş gözlemi için huzurlu bir ortam sunar. Özellikle hafta sonları ailelerin uğrak noktasıdır.", "place_query": "Beydağ Göleti, Beydağ, İzmir"}, {"title": "Beydağ Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale kalıntıları, bölgenin antik geçmişine ışık tutar ve zirveden Beydağ manzarasını izleme fırsatı verir.", "place_query": "Beydağ Kalesi, Beydağ, İzmir"}, {"title": "Küçük Menderes Nehri Kenarı", "summary": "Beydağ sınırları içinden geçen Küçük Menderes Nehri''nin kenarı, doğal yürüyüş parkurları ve fotoğrafçılık için sakin bir atmosfer sunar.", "place_query": "Küçük Menderes Nehri, Beydağ, İzmir"}, {"title": "Beydağ Ormanları", "summary": "Çam ağaçlarıyla kaplı geniş ormanlık alanlar, kampçılık ve doğa yürüyüşü yapmak isteyenler için keşfedilmeyi bekleyen bir doğa cennetidir.", "place_query": "Beydağ Ormanları, Beydağ, İzmir"}, {"title": "Beydağ Merkez Camii ve Çarşı", "summary": "Beydağ''ın tarihi merkezinde yer alan cami ve çevresindeki küçük çarşı, yöresel ürünler almak ve kasaba atmosferini hissetmek için idealdir.", "place_query": "Beydağ Merkez Camii, Beydağ, İzmir"}, {"title": "Çamlık Mahallesi Mesire Alanı", "summary": "Beydağ''a bağlı Çamlık Mahallesi''nde bulunan bu mesire alanı, piknik masaları ve yeşil örtüsüyle şehir gürültüsünden uzaklaşmak için güzel bir seçenektir.", "place_query": "Çamlık Mesire Alanı, Beydağ, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e876cecb-ca78-4602-8ea1-5608b15dfb77'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yeşilova Höyüğü", "summary": "İzmir''in bilinen en eski yerleşim yeri olan bu höyük, 8 bin yıllık tarihiyle kentin ilk köyü olarak kabul edilir. Açık hava müzesi ve ziyaretçi merkeziyle tarihe ilgi duyanlar için eşsiz bir durak.", "place_query": "Yeşilova Höyüğü, Bornova, İzmir"}, {"title": "Bornova Büyük Park", "summary": "Şehrin en büyük ve en popüler parklarından biri olan Büyük Park, yürüyüş yolları, göleti ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme noktasıdır.", "place_query": "Bornova Büyük Park, İzmir"}, {"title": "Homero Vadisi", "summary": "Doğa yürüyüşleri ve piknik için sıkça tercih edilen bu vadi, zengin bitki örtüsü ve deresiyle şehir merkezine yakın bir doğa kaçamağı sunar. Özellikle bahar aylarında rengarenk bir manzaraya bürünür.", "place_query": "Homero Vadisi, Bornova, İzmir"}, {"title": "Bornova Kent Arşivi ve Müzesi", "summary": "Bornova''nın tarihi konaklarını ve kültürel geçmişini yansıtan bu müze, eski fotoğraflar ve objelerle ilçenin hikayesini anlatır. Tarihi bir konakta yer alması da ayrı bir cazibe katar.", "place_query": "Bornova Kent Arşivi ve Müzesi, İzmir"}, {"title": "Evangelistria Rum Kilisesi", "summary": "19. yüzyıldan kalma bu tarihi Rum kilisesi, etkileyici mimarisi ve restorasyonuyla dikkat çeker. Günümüzde kültür merkezi olarak kullanılan yapı, Bornova''nın çok kültürlü geçmişine tanıklık eder.", "place_query": "Evangelistria Rum Kilisesi, Bornova, İzmir"}, {"title": "Kavaklıdere Mahallesi Tarihi Konakları", "summary": "Bornova''nın en eski yerleşimlerinden biri olan bu mahalle, Rum ve Levanten mimarisinin izlerini taşıyan zarif konaklarıyla ünlüdür. Sokaklarında yürümek adeta zamanda yolculuk gibidir.", "place_query": "Kavaklıdere Mahallesi Tarihi Konaklar, Bornova, İzmir"}, {"title": "Ege Üniversitesi Kampüsü", "summary": "Geniş yeşil alanları ve botanik bahçesiyle şehir içinde bir nefes alma noktası olan kampüs, özellikle Ege Üniversitesi Botanik Bahçesi''ni gezmek isteyenler için keyifli bir rotadır.", "place_query": "Ege Üniversitesi Botanik Bahçesi, Bornova, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9e6e2b04-e992-41a6-bbb4-7e91551c7f5a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Buca Göleti ve Mesire Alanı", "summary": "Buca''nın en popüler doğal kaçış noktalarından biri olan gölet, yürüyüş parkurları, piknik alanları ve gölet manzarasıyla aileler ve doğa severler için ideal bir dinlenme alanı sunuyor.", "place_query": "Buca Göleti, Buca, İzmir"}, {"title": "Büyük Park (Buca Belediyesi Büyük Parkı)", "summary": "Şehrin ortasında geniş yeşil alanları, yürüyüş yolları ve göletiyle bilinen Büyük Park, Buca''nın en eski ve en sevilen parklarından biridir.", "place_query": "Büyük Park, Buca, İzmir"}, {"title": "Buca Kasaplar Meydanı", "summary": "Tarihi Buca''nın kalbi sayılan bu meydan, çevresindeki tarihi binalar, kafeler ve restoranlarla hem yerli halkın hem de ziyaretçilerin uğrak noktasıdır.", "place_query": "Kasaplar Meydanı, Buca, İzmir"}, {"title": "Bucalı Levanten Köşkleri (Buca Evleri)", "summary": "19. yüzyıldan kalma bu zarif Levanten köşkleri, Buca''nın kozmopolit geçmişine tanıklık eden, fotoğrafçılar ve tarih meraklıları için görülmeye değer mimari yapılardır.", "place_query": "Buca Levanten Köşkleri, Buca, İzmir"}, {"title": "Buca Şirinyer Hipodromu", "summary": "İzmir''in önemli at yarışı merkezlerinden biri olan hipodrom, yarış günlerinde heyecanlı bir atmosfer sunar ve sosyal bir etkinlik alanı olarak da ziyaret edilebilir.", "place_query": "Şirinyer Hipodromu, Buca, İzmir"}, {"title": "Buca Barış Manço Kültür Merkezi", "summary": "Ünlü sanatçı Barış Manço''nun adını taşıyan bu merkez, tiyatro, konser ve sergi gibi çeşitli kültürel etkinliklere ev sahipliği yaparak Buca''nın sanat hayatına katkıda bulunuyor.", "place_query": "Barış Manço Kültür Merkezi, Buca, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c9792b0a-c887-4423-a02a-1f51ff64f0e3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alaçatı Çarşısı", "summary": "Taş sokakları, butik otelleri ve ünlü rüzgar sörfü plajlarıyla Alaçatı, Ege''nin en popüler tatil merkezlerinden biridir. Çarşıda alışveriş yapabilir, kafelerde vakit geçirebilirsiniz.", "place_query": "Alaçatı Çarşısı, Çeşme, İzmir"}, {"title": "Ilıca Plajı", "summary": "Sığ ve ılık denizi, altın sarısı kumsalıyla aileler için ideal bir plajdır. Ilıca''daki doğal kumullar ve termal su kaynakları da ziyaretçileri cezbeder.", "place_query": "Ilıca Plajı, Çeşme, İzmir"}, {"title": "Çeşme Kalesi", "summary": "Cenevizliler döneminde inşa edilen bu tarihi kale, günümüzde Çeşme Arkeoloji Müzesi''ne ev sahipliği yapmaktadır. Kaleden Çeşme limanı ve Ege Denizi manzarası izlenebilir.", "place_query": "Çeşme Kalesi, Çeşme, İzmir"}, {"title": "Dalyan Koyu", "summary": "Sakin ve berrak denizi, doğal güzelliğiyle Dalyan, kalabalıktan uzaklaşmak isteyenler için ideal bir koydur. Çevresindeki zeytinlikler ve yeşil doğa huzur verir.", "place_query": "Dalyan Koyu, Çeşme, İzmir"}, {"title": "Alaçatı Değirmenleri", "summary": "Alaçatı''nın simgesi haline gelen tarihi taş değirmenler, özellikle gün batımında muhteşem bir manzara sunar. Bölge, fotoğraf tutkunları için popüler bir duraktır.", "place_query": "Alaçatı Değirmenleri, Çeşme, İzmir"}, {"title": "Sığacık Kalesi", "summary": "Çeşme merkeze yakın Teos Antik Kenti yakınındaki Sığacık Kalesi, tarihi dokusu ve çevresindeki restoranlarla keyifli bir gezi noktasıdır. Kale içinde yürüyüş yapabilirsiniz.", "place_query": "Sığacık Kalesi, Seferihisar, İzmir"}, {"title": "Ovacık Plajı", "summary": "Doğal kum ve çakıl karışımı plajı, temiz denizi ve çam ağaçlarıyla çevrili yapısıyla Ovacık, Çeşme''nin en popüler plajlarından biridir. Su sporları da yapılabilir.", "place_query": "Ovacık Plajı, Çeşme, İzmir"}, {"title": "Erythrai Antik Kenti", "summary": "Ildırı köyü sınırlarındaki bu antik kent, İyonya''nın önemli şehirlerinden biridir. Tiyatro, agora ve sur kalıntıları tarih meraklıları için keşfedilmeyi bekler.", "place_query": "Erythrai Antik Kenti, Ildırı, Çeşme, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1f1df25e-7f9d-421e-80c8-e7a2e19d3d60'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İzmir Kuş Cenneti (Çiğli Kuş Cenneti)", "summary": "Çiğli sınırları içinde yer alan bu önemli doğal yaşam alanı, yüzlerce kuş türüne ev sahipliği yapar. Doğa fotoğrafçıları ve kuş gözlemcileri için eşsiz bir duraktır.", "place_query": "İzmir Kuş Cenneti, Çiğli, İzmir"}, {"title": "Çiğli Mezarlıkbaşı Sahili", "summary": "İzmir Körfezi''nin kuzey kıyısında yer alan bu sahil şeridi, yürüyüş yapmak ve deniz manzarası eşliğinde vakit geçirmek için idealdir. Özellikle gün batımında huzurlu bir atmosfere sahiptir.", "place_query": "Mezarlıkbaşı Sahili, Çiğli, İzmir"}, {"title": "Çiğli Belediyesi Atatürk Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun parkları ile ailelerin uğrak noktasıdır. Hafta sonları piknik yapmak ve dinlenmek için idealdir.", "place_query": "Atatürk Parkı, Çiğli, İzmir"}, {"title": "Mavişehir Sahil Parkı", "summary": "Çiğli''nin modern yüzünü temsil eden Mavişehir bölgesinde yer alan bu park, uzun sahil yürüyüş yolu ve bisiklet parkuru ile popülerdir. Deniz kenarında kafe ve restoranlar da bulunur.", "place_query": "Mavişehir Sahil Parkı, Çiğli, İzmir"}, {"title": "Çiğli Araştırma Ormanı", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için biyolojik çeşitlilik açısından zengin bir doğa alanıdır. Ağaçlarla kaplı patikaları, doğa yürüyüşleri için uygundur.", "place_query": "Çiğli Araştırma Ormanı, Çiğli, İzmir"}, {"title": "Eski İzmir (Smyrna) Antik Kenti - Tepekule Höyüğü", "summary": "Çiğli sınırlarındaki Bayraklı''ya komşu bu antik yerleşim, İzmir''in ilk kurulduğu bölgedir. Homeros''un yaşadığına inanılan bu höyük, tarih meraklıları için önemli bir duraktır.", "place_query": "Tepekule Höyüğü, Bayraklı, İzmir"}, {"title": "İzmir Doğal Yaşam Parkı", "summary": "Çiğli ilçesinde bulunan bu büyük hayvanat bahçesi, yüzlerce hayvan türünü doğal ortamında gözlemleme fırsatı sunar. Aileler ve çocuklar için eğlenceli bir gün geçirme imkanı sağlar.", "place_query": "İzmir Doğal Yaşam Parkı, Çiğli, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0a756269-6195-4ad8-9ef3-41689a58b31c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dikili Sahili ve İskele Meydanı", "summary": "Dikili''nin kalbi sayılan bu sahil şeridi, yürüyüş yolu, kafeleri ve deniz manzarasıyla hem yerli halkın hem de turistlerin uğrak noktasıdır. Özellikle gün batımında keyifli bir yürüyüş yapabilir, sahil boyunca sıralanan balık restoranlarında taze deniz ürünlerinin tadını çıkarabilirsiniz.", "place_query": "Dikili Sahili, İzmir"}, {"title": "Bademli Köyü", "summary": "Dikili''nin en popüler ve şirin köylerinden biri olan Bademli, taş evleri, dar sokakları ve tertemiz koylarıyla ünlüdür. Sakin bir tatil arayanlar için ideal olan bu köyde denize girebilir, zeytinlikler arasında huzur dolu bir gün geçirebilirsiniz.", "place_query": "Bademli Köyü, Dikili, İzmir"}, {"title": "Çandarlı Kalesi", "summary": "14. yüzyılda Cenevizliler tarafından inşa edilen ve günümüze kadar büyük ölçüde sağlam kalmış olan Çandarlı Kalesi, tarihi dokusu ve deniz kenarındaki konumuyla dikkat çeker. Kaleyi gezdikten sonra çevresindeki restoranlarda deniz manzarası eşliğinde yemek yiyebilirsiniz.", "place_query": "Çandarlı Kalesi, Dikili, İzmir"}, {"title": "Nebiler Şelalesi", "summary": "Dikili''ye yaklaşık 20 km uzaklıkta, doğa ile iç içe bir kaçamak yapmak isteyenler için harika bir nokta olan Nebiler Şelalesi, yeşillikler arasında akan serin sularıyla piknik ve doğa yürüyüşü için idealdir.", "place_query": "Nebiler Şelalesi, Dikili, İzmir"}, {"title": "Kite Beach (Uçurtma Plajı)", "summary": "Rüzgar sörfü ve uçurtma sörfü meraklılarının uğrak noktası olan bu plaj, geniş kumsalı ve sürekli esen rüzgarıyla sporculara ideal koşullar sunar. Aynı zamanda sakin denizi sayesinde yüzmek ve güneşlenmek için de tercih edilen bir yerdir.", "place_query": "Kite Beach, Dikili, İzmir"}, {"title": "Pitane Antik Kenti (Çandarlı)", "summary": "Çandarlı''nın antik adı olan Pitane, M.Ö. 7. yüzyıla kadar uzanan tarihiyle Aiol bölgesinin önemli liman kentlerindendir. Günümüzde kalıntıları Çandarlı''nın içinde yer alan antik kent, tarih meraklıları için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Pitane Antik Kenti, Çandarlı, Dikili, İzmir"}, {"title": "Maden Adası", "summary": "Dikili''nin hemen karşısında yer alan bu küçük ada, eski bir maden ocağı olmasının yanı sıra doğal güzellikleriyle de dikkat çeker. Tekne turlarıyla ulaşılabilen adada yürüyüş yapabilir ve eşsiz deniz manzarasının keyfini çıkarabilirsiniz.", "place_query": "Maden Adası, Dikili, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '469d3710-e51f-4aac-9c37-c05f5545c086'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Foça Antik Kenti (Phokaia)", "summary": "İzmir''in Foça ilçesinde yer alan bu antik kent, İyon uygarlığının önemli şehirlerinden biridir. Ziyaretçiler, Athena Tapınağı kalıntıları, antik tiyatro ve sur duvarlarını görebilir, tarihin izlerini sürebilir.", "place_query": "Foça Antik Kenti, Foça, İzmir"}, {"title": "Foça Sahili ve Kordon", "summary": "Foça''nın kalbinde yer alan bu sahil şeridi, yürüyüş yapmak, deniz manzarası eşliğinde çay içmek ve gün batımını izlemek için idealdir. Çevresindeki kafeler ve restoranlar sayesinde canlı bir atmosfer sunar.", "place_query": "Foça Sahili, Foça, İzmir"}, {"title": "Siren Kayalıkları", "summary": "Foça açıklarında bulunan bu kayalıklar, mitolojideki Siren hikayesiyle ünlüdür. Tekne turlarıyla ulaşılabilen kayalıklar, berrak denizi ve eşsiz doğal güzelliğiyle fotoğrafçılar ve doğa severler için popüler bir duraktır.", "place_query": "Siren Kayalıkları, Foça, İzmir"}, {"title": "Foça Fok Evleri ve Akdeniz Fokları", "summary": "Foça, nesli tükenme tehlikesi altındaki Akdeniz foklarının (Monachus monachus) yaşam alanıdır. Fok Evleri, bu sevimli canlıları doğal ortamlarında gözlemlemek ve koruma çalışmaları hakkında bilgi almak için ziyaret edilebilir.", "place_query": "Foça Fok Evleri, Foça, İzmir"}, {"title": "Beş Kapılar (Taşhan)", "summary": "Foça''nın tarihi çarşısında yer alan bu Osmanlı dönemi yapısı, günümüzde hediyelik eşya dükkanları ve kafelerle canlı bir merkezdir. Taş duvarları ve kemerli kapılarıyla tarihi bir atmosfer sunar.", "place_query": "Beş Kapılar Taşhan, Foça, İzmir"}, {"title": "Foça Şehir Müzesi", "summary": "Foça''nın tarihini ve kültürünü yansıtan bu müze, arkeolojik eserler, etnografik objeler ve bölgeye özgü el sanatları sergiler. Ziyaretçiler, Foça''nın zengin geçmişine dair kapsamlı bir bilgi edinebilir.", "place_query": "Foça Şehir Müzesi, Foça, İzmir"}, {"title": "Küçük Deniz (Küçük Koy)", "summary": "Foça''nın sakin ve huzurlu koylarından biri olan Küçük Deniz, yüzmek ve güneşlenmek için idealdir. Çevresindeki doğal güzellikler ve sakin denizi, kalabalıktan uzaklaşmak isteyenler için mükemmel bir kaçış noktasıdır.", "place_query": "Küçük Deniz, Foça, İzmir"}, {"title": "Foça Kalesi", "summary": "Cenevizliler döneminden kalma bu tarihi kale, Foça''nın en yüksek noktalarından birinde yer alır. Kaleye çıktığınızda, Foça Körfezi ve çevresinin nefes kesen manzarasını izleyebilir, tarihi dokuyu hissedebilirsiniz.", "place_query": "Foça Kalesi, Foça, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cc89bbd7-10b2-44dd-9e42-e4f977f13df7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gaziemir Göleti ve Piknik Alanı", "summary": "Şehir merkezine yakın, yeşil alanları ve göletiyle aileler için ideal bir piknik ve yürüyüş noktasıdır. Hafta sonları sıkça tercih edilen bu alan, doğayla iç içe vakit geçirmek isteyenler için huzurlu bir kaçış sunar.", "place_query": "Gaziemir Göleti, Gaziemir, İzmir"}, {"title": "Gaziemir Belediyesi Atatürk Parkı", "summary": "İlçenin en büyük ve en bilinen parklarından biri olan Atatürk Parkı, yürüyüş yolları, oyun alanları ve açık hava spor aletleriyle her yaştan ziyaretçiye hitap eder. Dinlenmek ve çocuklarla keyifli zaman geçirmek için popüler bir duraktır.", "place_query": "Atatürk Parkı, Gaziemir, İzmir"}, {"title": "Gaziemir Kent Müzesi", "summary": "Gaziemir''in tarihini, kültürünü ve gelişimini sergileyen bu müze, ilçenin geçmişine ışık tutan önemli bir kültürel duraktır. Ücretsiz ziyaret edilebilen müze, özellikle tarih meraklıları için ilgi çekicidir.", "place_query": "Gaziemir Kent Müzesi, Gaziemir, İzmir"}, {"title": "Fatih Parkı", "summary": "Geniş yeşil alanı ve oturma gruplarıyla mahalle sakinlerinin buluşma noktası olan Fatih Parkı, özellikle akşam yürüyüşleri ve çocuk oyunları için tercih edilir. Sakin atmosferiyle bilinir.", "place_query": "Fatih Parkı, Gaziemir, İzmir"}, {"title": "Gaziemir Pazarı (Semt Pazarı)", "summary": "Her hafta kurulan ve taze meyve, sebze, giyim ile ev eşyalarının satıldığı Gaziemir Semt Pazarı, yerel halkın alışveriş ihtiyacını karşılayan renkli bir noktadır. Yöresel ürünleri ve uygun fiyatlarıyla ziyaretçi çeker.", "place_query": "Gaziemir Semt Pazarı, Gaziemir, İzmir"}, {"title": "Sarnıç Mahallesi Seyir Tepesi", "summary": "Gaziemir''e tepeden bakan bu doğal seyir noktası, özellikle gün batımında İzmir Körfezi ve kent manzarası izlemek için idealdir. Doğa yürüyüşü yapmak ve fotoğraf çekmek isteyenler tarafından sıkça ziyaret edilir.", "place_query": "Sarnıç Seyir Tepesi, Gaziemir, İzmir"}, {"title": "Gaziemir Kapalı Spor Salonu ve Spor Kompleksi", "summary": "Modern spor tesisleriyle donatılmış bu kompleks, basketbol, voleybol ve diğer salon sporlarına ev sahipliği yapar. Spor yapmak veya maç izlemek için ilçenin önemli bir merkezidir.", "place_query": "Gaziemir Spor Salonu, Gaziemir, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1a7e9d38-972c-446d-a871-a98e7687ac8b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güzelbahçe Sahili ve Plajları", "summary": "İzmir Körfezi''nin en güzel manzaralarından birine sahip olan sahil şeridi, yürüyüş ve bisiklet yolları, kafeleri ve restoranlarıyla hafta sonu kaçamaklarının vazgeçilmezidir. Özellikle gün batımında eşsiz bir atmosfer sunar.", "place_query": "Güzelbahçe Sahili, İzmir"}, {"title": "Yelki Plajı", "summary": "Güzelbahçe''nin en popüler plajlarından biri olan Yelki, temiz denizi ve ince kumuyla bilinir. Çevresindeki balık restoranları ve kafeler sayesinde yaz aylarında yoğun ilgi görür.", "place_query": "Yelki Plajı, Güzelbahçe, İzmir"}, {"title": "Köstem Zeytinyağı Müzesi", "summary": "Türkiye''nin ilk özel zeytinyağı müzelerinden biri olan bu yer, zeytinyağı üretim tarihini ve geleneksel yöntemleri sergiler. Zeytin ağaçları arasında huzurlu bir atmosferde zeytinyağı tadımı da yapabilirsiniz.", "place_query": "Köstem Zeytinyağı Müzesi, Güzelbahçe, İzmir"}, {"title": "Güzelbahçe Belediyesi Atatürk Kültür Merkezi ve Parkı", "summary": "Deniz kenarındaki bu geniş park alanı, çocuk oyun grupları, yürüyüş yolları ve açık hava etkinlikleriyle aileler için ideal bir dinlenme noktasıdır. Kültür merkezinde zaman zaman sergi ve konserler düzenlenir.", "place_query": "Atatürk Kültür Merkezi, Güzelbahçe, İzmir"}, {"title": "Çamlı Köyü ve Yaylası", "summary": "Güzelbahçe''nin yüksek kesimlerinde yer alan Çamlı Köyü, doğal güzellikleri, çam ormanları ve temiz havasıyla şehirden kaçış noktasıdır. Köy kahvaltıları ve doğa yürüyüşleri için popülerdir.", "place_query": "Çamlı Köyü, Güzelbahçe, İzmir"}, {"title": "Yassıca Ada", "summary": "Güzelbahçe açıklarında yer alan küçük bir ada olan Yassıca, tekne turlarıyla ulaşılabilen, doğal güzelliği ve berrak deniziyle yüzme ve şnorkelle dalış için idealdir. Özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Yassıca Ada, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7c3f39da-d8bd-47f5-87c4-2cf58d207443'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Küçük Yalı Spor Parkı", "summary": "Karabağlar''ın en büyük ve en popüler parklarından biridir. Geniş yürüyüş yolları, spor alanları ve çocuk oyun gruplarıyla ailelerin ve spor severlerin uğrak noktasıdır.", "place_query": "Küçük Yalı Spor Parkı, Karabağlar, İzmir"}, {"title": "İzmir Oyuncak Müzesi", "summary": "Karabağlar sınırları içinde yer alan bu özel müze, geçmişten günümüze birçok oyuncağı sergileyerek hem çocuklar hem de yetişkinler için nostaljik bir yolculuk sunar.", "place_query": "İzmir Oyuncak Müzesi, Karabağlar, İzmir"}, {"title": "Uzundere Rekreasyon Alanı (Kültürpark Uzundere)", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için ideal bir yeşil alandır. Göleti, piknik masaları ve yürüyüş parkurlarıyla hafta sonu kaçamakları için sıkça tercih edilir.", "place_query": "Uzundere Rekreasyon Alanı, Karabağlar, İzmir"}, {"title": "Karabağlar Belediyesi Merkez Parkı", "summary": "İlçenin merkezinde yer alan bu park, sosyal donatıları ve düzenli etkinlikleriyle bilinir. Çevresindeki kafeler ve dinlenme alanlarıyla keyifli vakit geçirme imkanı tanır.", "place_query": "Karabağlar Belediyesi Merkez Parkı, İzmir"}, {"title": "Eski İzmir Evleri (Bozyaka Bölgesi)", "summary": "Karabağlar''ın Bozyaka semtinde bulunan tarihi İzmir evleri, kentin eski mimari dokusunu yansıtan nadide yapılardır. Dar sokaklarda yürüyerek geçmişe kısa bir yolculuk yapabilirsiniz.", "place_query": "Bozyaka Tarihi Evler, Karabağlar, İzmir"}, {"title": "Küçük Yalı Sahili", "summary": "İzmir Körfezi''ne kıyısı olan bu sahil şeridi, özellikle gün batımında eşsiz manzaralar sunar. Yürüyüş yapmak ve deniz havası almak için popüler bir duraktır.", "place_query": "Küçük Yalı Sahili, Karabağlar, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bb735737-1567-47cb-907d-b4f0600170cd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarpıncık Koyu", "summary": "Karaburun''un en popüler koylarından biri olan Sarpıncık, berrak denizi ve doğal güzelliği ile ünlüdür. Çam ormanlarıyla çevrili bu koy, sakin denizi sayesinde yüzme ve şnorkelle dalış için idealdir.", "place_query": "Sarpıncık Koyu, Karaburun, İzmir"}, {"title": "Karaburun Mavi Bayraklı Halk Plajı", "summary": "Karaburun merkezde yer alan bu plaj, mavi bayraklı temiz denizi ve ince kumlu sahili ile aileler için popüler bir yüzme noktasıdır. Plajda gün batımını izlemek de ayrı bir keyiftir.", "place_query": "Karaburun Merkez Halk Plajı, İzmir"}, {"title": "Küçükbahşiş Köyü ve Koyları", "summary": "Doğal dokusunu koruyan Küçükbahşiş, dar sokakları ve taş evleriyle dikkat çeker. Köyün kıyısındaki koylar, sakin ve huzurlu bir deniz tatili arayanların uğrak noktasıdır.", "place_query": "Küçükbahşiş Köyü, Karaburun, İzmir"}, {"title": "Bademler Köyü", "summary": "Zeytinlikler ve badem ağaçlarıyla çevrili bu şirin köy, kırsal yaşamı deneyimlemek isteyenler için idealdir. Köy meydanında yöresel ürünler bulabilir ve doğa yürüyüşleri yapabilirsiniz.", "place_query": "Bademler Köyü, Karaburun, İzmir"}, {"title": "Körmen Deresi ve Şelalesi", "summary": "Karaburun''un yeşil örtüsü içinde gizlenmiş bu dere ve küçük şelale, doğa yürüyüşleri ve piknik için popüler bir noktadır. Serin sularında ayaklarınızı dinlendirebilir, çevredeki bitki örtüsünü keşfedebilirsiniz.", "place_query": "Körmen Deresi, Karaburun, İzmir"}, {"title": "Mordoğan Sahili ve Koyları", "summary": "Karaburun''un en canlı mahallelerinden biri olan Mordoğan, uzun sahili ve çevresindeki küçük koylarla bilinir. Denize girmek, balık restoranlarında yemek yemek ve gün batımını izlemek için tercih edilir.", "place_query": "Mordoğan Sahili, Karaburun, İzmir"}, {"title": "Eğlenhoca Koyu", "summary": "Sakin ve el değmemiş bir doğa harikası olan Eğlenhoca Koyu, özellikle hafta sonu kaçamaklarında tercih edilir. Çam ağaçları arasından denize uzanan patikaları ve berrak suyuyla ünlüdür.", "place_query": "Eğlenhoca Koyu, Karaburun, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cac6c914-2193-48e4-8b32-d4f0ee6896c9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bostanlı Sahili ve Yürüyüş Yolu", "summary": "Karşıyaka''nın en popüler noktası olan Bostanlı Sahili, uzun yürüyüş ve bisiklet yolu, deniz manzarası ve karşı kıyıdaki İzmir manzarasıyla ünlüdür. Özellikle gün batımında seyir keyfi yapmak için idealdir.", "place_query": "Bostanlı Sahili, Karşıyaka, İzmir"}, {"title": "Karşıyaka Çarşı", "summary": "Karşıyaka''nın kalbi sayılan çarşı bölgesi, tarihi yapıları, butik kafeleri, restoranları ve alışveriş olanaklarıyla hem yerli hem de yabancı ziyaretçilerin uğrak noktasıdır.", "place_query": "Karşıyaka Çarşı, İzmir"}, {"title": "İzmir Kuş Cenneti (Gediz Deltası)", "summary": "Karşıyaka sınırları içinde yer alan bu doğal sulak alan, 200''den fazla kuş türüne ev sahipliği yapar. Doğa fotoğrafçıları ve kuş gözlemcileri için eşsiz bir duraktır.", "place_query": "İzmir Kuş Cenneti, Gediz Deltası, Karşıyaka"}, {"title": "Karşıyaka Spor Kulübü ve Mustafa Kemal Atatürk Karşıyaka Spor Müzesi", "summary": "Karşıyaka''nın köklü spor kulübüne ait bu müze, kulübün tarihini, kupalarını ve Atatürk''ün Karşıyaka sevgisini anlatan özel bir koleksiyona sahiptir.", "place_query": "Karşıyaka Spor Müzesi, İzmir"}, {"title": "Mavişehir Sahil Parkı", "summary": "Modern düzenlemesi, geniş yeşil alanları, çocuk oyun parkları ve sahil boyunca uzanan yürüyüş yoluyla ailelerin ve spor yapanların favori mekanlarından biridir.", "place_query": "Mavişehir Sahil Parkı, Karşıyaka, İzmir"}, {"title": "Yamanlar Dağı ve Kartal Tepe Seyir Noktası", "summary": "Karşıyaka''nın yüksek kesimlerinde yer alan Yamanlar Dağı, İzmir Körfezi''nin panoramik manzarasını sunar. Doğa yürüyüşleri ve piknik için de tercih edilir.", "place_query": "Yamanlar Dağı, Karşıyaka, İzmir"}, {"title": "Latife Hanım Anı Evi", "summary": "Atatürk''ün eşi Latife Hanım''ın Karşıyaka''daki aile evi olan bu yapı, müze olarak ziyarete açıktır. Dönemin yaşamına dair eşyalar ve fotoğraflar sergilenir.", "place_query": "Latife Hanım Anı Evi, Karşıyaka, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2d5fe76c-77e8-4e7f-8e26-fcb18e4e1705'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kemalpaşa Kanyonu", "summary": "Doğa yürüyüşü ve piknik için ideal olan bu kanyon, yemyeşil bitki örtüsü ve şelaleleriyle huzurlu bir kaçış noktası sunar.", "place_query": "Kemalpaşa Kanyonu, İzmir"}, {"title": "Ulucak Höyüğü", "summary": "İzmir''in en eski yerleşimlerinden biri olan bu arkeolojik alan, Neolitik döneme ait buluntularıyla tarih meraklıları için büyüleyici bir duraktır.", "place_query": "Ulucak Höyüğü, Kemalpaşa, İzmir"}, {"title": "Kemalpaşa İzmir Saat Kulesi", "summary": "İlçe merkezinde yer alan bu tarihi saat kulesi, Kemalpaşa''nın simgelerinden biri olup çevresindeki meydanıyla buluşma noktasıdır.", "place_query": "Kemalpaşa Saat Kulesi, İzmir"}, {"title": "Kemalpaşa Kiraz Festivali Alanı", "summary": "Her yıl düzenlenen ünlü Kiraz Festivali''ne ev sahipliği yapan bu alan, festival zamanı renkli etkinlikler ve yerel lezzetlerle canlanır.", "place_query": "Kemalpaşa Kiraz Festivali, İzmir"}, {"title": "Nif Dağı", "summary": "Doğa sporları ve trekking için popüler olan Nif Dağı, zirvesinden İzmir Körfezi ve çevresinin muhteşem manzarasını sunar.", "place_query": "Nif Dağı, Kemalpaşa, İzmir"}, {"title": "Kemalpaşa Kent Ormanı", "summary": "Geniş yürüyüş yolları, piknik alanları ve göletiyle aileler için sakin bir doğa kaçamağı sunan bu ormanlık alan, hafta sonu gezileri için idealdir.", "place_query": "Kemalpaşa Kent Ormanı, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '939d2ba9-1931-4c67-9457-fdfe73f801de'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kınık Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşımakta olup, ibadet ve ziyaret için önemli bir duraktır.", "place_query": "Kınık Merkez Camii, Kınık, İzmir"}, {"title": "Kınık Pazarı", "summary": "Haftalık kurulan büyük pazar, yöresel ürünler, taze sebze-meyve ve el işi ürünleriyle ünlüdür; yerel kültürü yakından tanımak için idealdir.", "place_query": "Kınık Pazarı, Kınık, İzmir"}, {"title": "Kınık Atatürk Anıtı", "summary": "İlçe meydanında bulunan anıt, Cumhuriyet tarihine tanıklık eden sembolik bir yapı olup, çevresi dinlenme alanlarıyla donatılmıştır.", "place_query": "Atatürk Anıtı, Kınık, İzmir"}, {"title": "Kınık Göleti ve Mesire Alanı", "summary": "Doğal güzelliğiyle piknik ve yürüyüş için popüler bir mekandır; gölet çevresinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Kınık Göleti, Kınık, İzmir"}, {"title": "Kınık Arkeolojik Sit Alanı", "summary": "Bölgedeki antik kalıntılar ve höyükler, tarih öncesi dönemlere ışık tutan önemli bir arkeolojik alandır; kazı çalışmaları devam etmektedir.", "place_query": "Kınık Arkeolojik Sit Alanı, İzmir"}, {"title": "Kınık Yaylası", "summary": "Serin havası ve yeşil doğasıyla yaz aylarında kaçış noktası olan yayla, doğa yürüyüşleri ve kamp için elverişlidir.", "place_query": "Kınık Yaylası, Kınık, İzmir"}, {"title": "Kınık Tarihi Çeşmeleri", "summary": "İlçe genelinde dağınık halde bulunan Osmanlı dönemi çeşmeleri, mimari detayları ve tarihi dokusuyla dikkat çeker.", "place_query": "Kınık Tarihi Çeşmeleri, Kınık, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '018e0a3d-9d9a-4a11-b45a-cc9786bcdd1a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kiraz İlçe Merkezi ve Tarihi Çarşı", "summary": "Kiraz''ın merkezinde yer alan tarihi çarşı, yöresel ürünlerin satıldığı dükkanları ve samimi atmosferiyle ziyaretçilere ilçenin günlük yaşamını deneyimleme fırsatı sunar.", "place_query": "Kiraz Merkez, İzmir"}, {"title": "Gölcük Göleti", "summary": "Kiraz''a bağlı Gölcük köyünde bulunan bu gölet, çevresindeki yeşil alanlar ve piknik imkanlarıyla doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Gölcük Göleti, Kiraz, İzmir"}, {"title": "Kiraz Kalesi (Kız Kalesi)", "summary": "İlçe merkezine yakın bir tepede yer alan bu tarihi kale kalıntısı, bölgenin antik dönemlerine ışık tutar ve çevresine hakim manzarasıyla fotoğrafçılar için idealdir.", "place_query": "Kiraz Kalesi, Kiraz, İzmir"}, {"title": "Kiraz Barajı", "summary": "Kiraz ilçe sınırları içinde yer alan bu baraj, sakin su yüzeyi ve çevresindeki doğal yürüyüş parkurlarıyla huzurlu bir gün geçirmek isteyenler için popüler bir duraktır.", "place_query": "Kiraz Barajı, İzmir"}, {"title": "Karaağaç Mahallesi Tarihi Evleri", "summary": "Kiraz''ın kırsal mahallelerinden Karaağaç''ta bulunan geleneksel taş ve ahşap evler, yöresel mimariyi yansıtarak ziyaretçilere nostaljik bir atmosfer sunar.", "place_query": "Karaağaç Mahallesi, Kiraz, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '14164d4c-eccc-4391-8e47-ed0963b97864'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kemeraltı Çarşısı", "summary": "İzmir''in kalbi sayılan tarihi çarşı, dar sokakları, dükkanları, camileri ve hanlarıyla alışveriş ve kültür turu için ideal bir yerdir.", "place_query": "Kemeraltı Çarşısı, Konak, İzmir"}, {"title": "İzmir Saat Kulesi", "summary": "Konak Meydanı''ndaki bu sembol yapı, İzmir''in simgesi olup çevresindeki tarihi binalar ve deniz manzarasıyla fotoğrafçıların uğrak noktasıdır.", "place_query": "İzmir Saat Kulesi, Konak, İzmir"}, {"title": "Kordon Boyu", "summary": "Deniz kenarında uzanan yürüyüş yolu, bisiklet parkuru ve kafeleriyle İzmirlilerin ve turistlerin vazgeçilmez buluşma noktasıdır.", "place_query": "Kordon Boyu, Konak, İzmir"}, {"title": "Asansör (Tarihi Asansör)", "summary": "1907 yılında inşa edilen bu tarihi asansör, Karataş semtinden denize inip çıkmayı sağlarken tepesinde muhteşem İzmir Körfezi manzarası sunar.", "place_query": "Tarihi Asansör, Konak, İzmir"}, {"title": "İzmir Arkeoloji Müzesi", "summary": "Ege Bölgesi''nin en zengin arkeolojik koleksiyonlarından birine ev sahipliği yapan müze, antik dönem eserleriyle tarih meraklılarını cezbeder.", "place_query": "İzmir Arkeoloji Müzesi, Konak, İzmir"}, {"title": "Kadifekale", "summary": "İzmir''in en yüksek tepelerinden birinde yer alan antik kale, şehrin ve körfezin panoramik manzarasını izlemek için en iyi noktalardan biridir.", "place_query": "Kadifekale, Konak, İzmir"}, {"title": "İzmir Tarihi Askeri Havagazı Fabrikası (Kültür Parkı)", "summary": "Restore edilerek kültür merkezine dönüştürülen bu tarihi yapı, sergi alanları ve etkinlikleriyle sanatseverler için popüler bir mekandır.", "place_query": "Tarihi Havagazı Fabrikası, Konak, İzmir"}, {"title": "Kızlarağası Hanı", "summary": "Kemeraltı''nın içinde yer alan 18. yüzyıl Osmanlı hanı, avlusundaki çay bahçeleri ve hediyelik eşya dükkanlarıyla huzurlu bir mola noktasıdır.", "place_query": "Kızlarağası Hanı, Konak, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6b186f55-3862-409e-bf0c-00ced943bce8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Özdere Plajı", "summary": "Menderes''in en popüler yaz destinasyonlarından olan Özdere Plajı, uzun kumsalı ve temiz deniziyle aileler ve gençler için ideal bir yüzme ve güneşlenme alanı sunar.", "place_query": "Özdere Plajı, Menderes, İzmir"}, {"title": "Cumaovası (Menderes) Tren İstasyonu", "summary": "Tarihi bir durak olan bu istasyon, nostaljik tren yolculukları ve çevresindeki eski yapılarla fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Cumaovası Tren İstasyonu, Menderes, İzmir"}, {"title": "Gümüldür Plajı", "summary": "Sakin atmosferi ve berrak sularıyla bilinen Gümüldür Plajı, özellikle yaz aylarında deniz keyfi yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Gümüldür Plajı, Menderes, İzmir"}, {"title": "Tekke Dağı", "summary": "Doğa yürüyüşleri ve kampçılık için popüler bir rota olan Tekke Dağı, ziyaretçilerine eşsiz İzmir Körfezi manzarası ve huzurlu bir doğa deneyimi sunar.", "place_query": "Tekke Dağı, Menderes, İzmir"}, {"title": "Menderes Şelalesi", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için serinletici bir kaçış noktası olan Menderes Şelalesi, piknik alanları ve doğal havuzlarıyla öne çıkar.", "place_query": "Menderes Şelalesi, Menderes, İzmir"}, {"title": "Değirmendere Barajı", "summary": "Balık tutma ve doğa gezintisi gibi aktiviteler için tercih edilen Değirmendere Barajı, çevresindeki yeşil alanlarla huzurlu bir gün geçirmek isteyenleri ağırlar.", "place_query": "Değirmendere Barajı, Menderes, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a6977676-efb4-4b70-9ade-46e978eb694e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Menemen Kalesi", "summary": "Tarihi bir kalenin kalıntıları arasında dolaşarak bölgenin geçmişine tanıklık edebilir, çevredeki manzarayı seyredebilirsiniz.", "place_query": "Menemen Kalesi, Menemen, İzmir"}, {"title": "Yamanlar Dağı ve Karagöl", "summary": "Doğa yürüyüşleri ve piknik için ideal olan bu alan, zirvedeki krater gölü Karagöl ile huzurlu bir kaçış noktası sunar.", "place_query": "Karagöl, Yamanlar Dağı, Menemen, İzmir"}, {"title": "Menemen Tarihi Çarşı ve Arasta", "summary": "Yöresel ürünler, el sanatları ve tarihi dükkanlarıyla ünlü bu çarşıda alışveriş yapabilir, eski Menemen dokusunu hissedebilirsiniz.", "place_query": "Menemen Tarihi Çarşı, Menemen, İzmir"}, {"title": "Seyrek Köyü ve Gediz Deltası", "summary": "Kuş gözlemciliği ve doğa fotoğrafçılığı için önemli bir alan olan Gediz Deltası''na yakın bu köy, sakin atmosferiyle keşfedilmeyi bekliyor.", "place_query": "Seyrek Köyü, Menemen, İzmir"}, {"title": "Menemen Müzesi", "summary": "Arkeolojik ve etnografik eserlerin sergilendiği müze, bölgenin tarih öncesinden günümüze kültürel mirasını gözler önüne seriyor.", "place_query": "Menemen Müzesi, Menemen, İzmir"}, {"title": "Gediz Nehri Kenarı ve Mesire Alanları", "summary": "Nehir kenarında yürüyüş yapabilir, piknik alanlarında dinlenebilir ve doğayla iç içe vakit geçirebilirsiniz.", "place_query": "Gediz Nehri, Menemen, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8edc5a49-9c7f-4bd9-833e-6ef73c1278b2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Narlıdere Sahil Bandı", "summary": "İzmir Körfezi manzaralı yürüyüş ve bisiklet yolu, dinlenme alanları ve kafeleriyle Narlıdere''nin en popüler sosyal alanıdır. Özellikle gün batımında huzurlu bir atmosfer sunar.", "place_query": "Narlıdere Sahil Bandı, Narlıdere, İzmir"}, {"title": "İnciraltı Kent Ormanı", "summary": "Geniş yeşil alanları, yürüyüş parkurları, göleti ve piknik alanlarıyla doğayla iç içe vakit geçirmek isteyenler için ideal bir rekreasyon bölgesidir. İzmir''in en büyük kent ormanlarından biridir.", "place_query": "İnciraltı Kent Ormanı, Narlıdere, İzmir"}, {"title": "Narlıdere Atatürk Kültür Merkezi", "summary": "Tiyatro, konser ve sergi gibi kültürel etkinliklere ev sahipliği yapan modern bir yapıdır. Bölgenin sanat ve kültür hayatına önemli katkı sağlar.", "place_query": "Narlıdere Atatürk Kültür Merkezi, Narlıdere, İzmir"}, {"title": "Güzelbahçe Plajları (Narlıdere sınırına yakın)", "summary": "Narlıdere''ye komşu Güzelbahçe''de yer alan bu plajlar, temiz denizi ve doğal kumsalıyla yaz aylarında yüzme ve güneşlenme için tercih edilir. Özellikle Yalı ve Kocakum plajları popülerdir.", "place_query": "Güzelbahçe Plajları, İzmir"}, {"title": "Sakarya Parkı", "summary": "Narlıdere''nin merkezinde bulunan bu park, çocuk oyun alanları, spor aletleri ve oturma gruplarıyla ailelerin uğrak noktasıdır. Çevresindeki kafe ve restoranlarla da hareketlidir.", "place_query": "Sakarya Parkı, Narlıdere, İzmir"}, {"title": "Narlıdere Pazar Alanı (Halk Pazarı)", "summary": "Her hafta kurulan bu semt pazarı, taze meyve-sebze, yöresel ürünler ve el işi eşyalarıyla hem alışveriş hem de yerel kültürü deneyimlemek için canlı bir ortam sunar.", "place_query": "Narlıdere Halk Pazarı, Narlıdere, İzmir"}, {"title": "Yamanlar Dağı (Narlıdere etekleri)", "summary": "Narlıdere''nin kuzeyindeki bu dağlık alan, doğa yürüyüşleri ve manzara seyri için idealdir. Zirveden İzmir Körfezi ve şehir manzarası etkileyicidir.", "place_query": "Yamanlar Dağı, Narlıdere, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c120c7b1-9818-4af0-823f-7fc38d22d99c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Birgi Tarihi Kent", "summary": "UNESCO Dünya Mirası Geçici Listesi''nde yer alan Birgi, Osmanlı ve Selçuklu döneminden kalma tarihi evleri, dar sokakları ve Çakırağa Konağı ile ünlüdür. Ziyaretçilerine adeta bir açık hava müzesi deneyimi sunar.", "place_query": "Birgi, Ödemiş, İzmir"}, {"title": "Çakırağa Konağı", "summary": "19. yüzyıldan kalma bu görkemli konak, geleneksel Türk mimarisinin en güzel örneklerinden biridir. İçindeki el yapımı süslemeler ve havuzlu avlusuyla ziyaretçileri büyüler.", "place_query": "Çakırağa Konağı, Birgi, Ödemiş, İzmir"}, {"title": "Gölcük Gölü ve Mesire Alanı", "summary": "Ödemiş''in en popüler doğal alanlarından biri olan Gölcük Gölü, çam ormanlarıyla çevrili huzurlu bir göldür. Piknik yapmak, yürüyüş yapmak ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Gölcük Gölü, Ödemiş, İzmir"}, {"title": "Bozdağ Kayak Merkezi", "summary": "Ege Bölgesi''nin sayılı kayak merkezlerinden biri olan Bozdağ, kış aylarında kayak ve snowboard yapmak isteyenler için popüler bir destinasyondur. Yazın ise doğa yürüyüşleri ve kamp için tercih edilir.", "place_query": "Bozdağ Kayak Merkezi, Ödemiş, İzmir"}, {"title": "Ödemiş Yıldız Kent Arşivi ve Müzesi", "summary": "Eski bir hükümet konağında hizmet veren bu müze, Ödemiş''in tarihini, kültürünü ve geçmiş yaşamını yansıtan eserlerle doludur. Bölgenin etnografik zenginliğini keşfetmek için harika bir noktadır.", "place_query": "Ödemiş Yıldız Kent Arşivi ve Müzesi, Ödemiş, İzmir"}, {"title": "Lübbey Yaylası", "summary": "Ödemiş''in serin yaylalarından biri olan Lübbey, özellikle yaz aylarında şehrin gürültüsünden kaçmak isteyenler için popüler bir kaçış noktasıdır. Doğal güzelliği ve temiz havasıyla ünlüdür.", "place_query": "Lübbey Yaylası, Ödemiş, İzmir"}, {"title": "Aydınoğlu Mehmet Bey Camii", "summary": "Birgi''de bulunan bu tarihi cami, 1312 yılında Aydınoğulları Beyliği döneminde inşa edilmiştir. Selçuklu ve Osmanlı mimarisinin izlerini taşıyan yapı, özellikle ahşap işçiliği ve süslemeleriyle dikkat çeker.", "place_query": "Aydınoğlu Mehmet Bey Camii, Birgi, Ödemiş, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7ceee635-760a-4d9a-a720-4ce06b18b793'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sığacık Kaleiçi", "summary": "Tarihi Sığacık Kalesi''nin içinde yer alan bu bölge, dar sokakları, taş evleri ve butik otelleriyle huzurlu bir atmosfer sunar. Özellikle hafta sonu kurulan Sığacık Pazarı, yöresel ürünler ve el sanatları ile ünlüdür.", "place_query": "Sığacık Kaleiçi, Seferihisar, İzmir"}, {"title": "Teos Antik Kenti", "summary": "İyon uygarlığının önemli liman kentlerinden biri olan Teos, Dionysos Tapınağı ve antik tiyatrosuyla tarih meraklılarını cezbeder. Kazı çalışmaları halen devam eden bu açık hava müzesi, Seferihisar''ın en değerli arkeolojik alanıdır.", "place_query": "Teos Antik Kenti, Seferihisar, İzmir"}, {"title": "Akarca Plajı", "summary": "Sakin ve temiz deniziyle bilinen Akarca Plajı, mavi bayraklı kumsalı ve çam ormanına yakın konumuyla aileler için ideal bir yüzme noktasıdır. Çevresindeki tesisler sayesinde günübirlik ziyaretler için oldukça popülerdir.", "place_query": "Akarca Plajı, Seferihisar, İzmir"}, {"title": "Seferihisar Çamlığı", "summary": "Geniş çam ormanlarıyla kaplı bu mesire alanı, piknik yapmak, doğa yürüyüşleri gerçekleştirmek ve temiz hava almak için birebirdir. İçerisinde bulunan yürüyüş parkurları ve çocuk oyun alanları ile hafta sonu kaçamaklarının vazgeçilmezidir.", "place_query": "Seferihisar Çamlığı, Seferihisar, İzmir"}, {"title": "Sığacık Pazarı", "summary": "Her hafta sonu Sığacık Kalesi çevresinde kurulan bu pazar, Ege Bölgesi''nin en büyük ve en renkli organik pazarlarından biridir. Yöresel zeytinyağları, otlar, el dokuması ürünler ve hediyelik eşyalar bulabileceğiniz bu pazar, Seferihisar''ın simgelerindendir.", "place_query": "Sığacık Pazarı, Seferihisar, İzmir"}, {"title": "Sığacık Kalesi", "summary": "Kanuni Sultan Süleyman döneminde inşa edilen bu tarihi kale, Osmanlı dönemi askeri mimarisinin güzel bir örneğidir. Kale içindeki dar sokaklar ve tarihi doku, ziyaretçilere eşsiz bir gezi deneyimi sunar.", "place_query": "Sığacık Kalesi, Seferihisar, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'da86be65-e225-4543-ba9b-d3c5922ebdb2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Efes Antik Kenti", "summary": "Antik dünyanın en önemli kentlerinden biri olan Efes, Celsus Kütüphanesi ve Büyük Tiyatrosu ile büyüleyici bir tarih yolculuğu sunar.", "place_query": "Efes Antik Kenti, Selçuk, İzmir"}, {"title": "Meryem Ana Evi", "summary": "Hristiyanlık için kutsal kabul edilen ve Meryem Ana''nın son yıllarını geçirdiğine inanılan bu şapel, Bülbül Dağı''nda huzurlu bir ziyaret noktasıdır.", "place_query": "Meryem Ana Evi, Selçuk, İzmir"}, {"title": "Şirince Köyü", "summary": "Dar sokakları, taş evleri ve ünlü meyve şaraplarıyla ünlü bu tarihi Rum köyü, doğal güzelliği ve otantik atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Şirince Köyü, Selçuk, İzmir"}, {"title": "St. Jean Bazilikası", "summary": "Bizans İmparatoru Justinianus tarafından yaptırılan bu görkemli bazilika, Aziz Yuhanna''nın mezarının üzerine inşa edilmiştir ve Selçuk''un siluetine hakimdir.", "place_query": "St. Jean Bazilikası, Selçuk, İzmir"}, {"title": "Selçuk Ayasuluk Kalesi", "summary": "Tepedeki konumuyla Selçuk''a hakim bir manzara sunan bu tarihi kale, içerisindeki cami ve yapılarla geçmişe ışık tutar.", "place_query": "Ayasuluk Kalesi, Selçuk, İzmir"}, {"title": "İsa Bey Camii", "summary": "14. yüzyılda Aydınoğulları Beyliği tarafından yaptırılan bu tarihi cami, Anadolu Selçuklu ve Osmanlı mimarisinin izlerini taşıyan etkileyici bir yapıdır.", "place_query": "İsa Bey Camii, Selçuk, İzmir"}, {"title": "Efes Müzesi", "summary": "Efes Antik Kenti''nden çıkarılan Artemis heykelleri ve diğer önemli eserlerin sergilendiği bu müze, antik döneme dair kapsamlı bir koleksiyon sunar.", "place_query": "Efes Müzesi, Selçuk, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3f6d451b-c1d5-4450-b8c0-1d79e3bb4f4e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tire Müzesi", "summary": "Tarihi bir medresede hizmet veren müze, bölgenin zengin arkeolojik ve etnografik eserlerini sergiliyor; antik dönemden Osmanlı''ya uzanan geniş bir koleksiyon sunuyor.", "place_query": "Tire Müzesi, İzmir"}, {"title": "Birgi Çakırağa Konağı", "summary": "18. yüzyıldan kalma bu görkemli konak, geleneksel Osmanlı sivil mimarisinin en güzel örneklerinden biri olarak ziyaretçileri büyülüyor.", "place_query": "Çakırağa Konağı, Birgi, İzmir"}, {"title": "Aydınoğulları Bedesteni", "summary": "Tire çarşısının kalbinde yer alan tarihi bedesten, yöresel ürünler ve el sanatları alışverişi için ideal bir noktadır.", "place_query": "Aydınoğulları Bedesteni, Tire, İzmir"}, {"title": "Tire Yuvarlak Çeşme", "summary": "İlçenin simge yapılarından olan bu tarihi çeşme, Osmanlı dönemi taş işçiliğini yansıtan zarif bir yapıdır.", "place_query": "Yuvarlak Çeşme, Tire, İzmir"}, {"title": "Küçük Menderes Nehri Kenarı", "summary": "Nehir boyunca uzanan yürüyüş yolları ve piknik alanları, doğayla iç içe sakin bir gün geçirmek isteyenler için huzurlu bir ortam sunar.", "place_query": "Küçük Menderes Nehri, Tire, İzmir"}, {"title": "Tire İpek Yolu Kervansarayı", "summary": "Tarihi İpek Yolu üzerinde bulunan bu kervansaray, geçmişte tüccarlara konaklama imkânı sağlamış, günümüzde ise kültürel etkinliklere ev sahipliği yapmaktadır.", "place_query": "Tire Kervansarayı, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '85376dd2-6a52-46e4-8c4c-c13094593bae'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Metropolis Antik Kenti", "summary": "Torbalı sınırlarındaki bu antik kent, Helenistik, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklıları için eşsiz bir durak. ''Analar Tanrıçası''nın Kenti'' olarak da bilinen Metropolis, etkileyici tiyatrosu ve mozaikleriyle ziyaretçilerini büyüler.", "place_query": "Metropolis Antik Kenti, Torbalı, İzmir"}, {"title": "Torbalı Şehir Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve göletiyle aileler için huzurlu bir kaçış noktasıdır. Piknik yapmak, spor yapmak veya sadece doğanın tadını çıkarmak için idealdir.", "place_query": "Torbalı Şehir Parkı, Torbalı, İzmir"}, {"title": "Torbalı Hal ve Pazar Yeri", "summary": "Yöresel ürünlerin ve taze sebze-meyvenin satıldığı bu hareketli pazar, Torbalı''nın yerel lezzetlerini ve canlı kültürünü deneyimlemek için harika bir yerdir.", "place_query": "Torbalı Kapalı Pazar Yeri, İzmir"}, {"title": "Küçük Menderes Havzası Sulak Alanları", "summary": "Torbalı''nın verimli ovalarını besleyen bu sulak alanlar, kuş gözlemcileri ve doğa fotoğrafçıları için önemli bir noktadır. Bölgenin doğal güzelliğini ve biyolojik çeşitliliğini keşfetmek mümkündür.", "place_query": "Küçük Menderes Deltası, Torbalı, İzmir"}, {"title": "Torbalı Belediyesi Atatürk Kültür Merkezi", "summary": "Modern mimarisi ve çok amaçlı salonlarıyla şehrin kültür-sanat merkezi konumundadır. Tiyatro oyunları, konserler ve sergiler burada düzenlenmektedir.", "place_query": "Torbalı Atatürk Kültür Merkezi, İzmir"}, {"title": "Ayrancılar Göleti ve Mesire Alanı", "summary": "Torbalı''nın Ayrancılar mahallesinde bulunan bu gölet, piknik alanları ve doğal çevresiyle hafta sonu kaçamakları için popüler bir yerdir. Sessizlik ve doğa ile baş başa kalmak isteyenler için biçilmiş kaftandır.", "place_query": "Ayrancılar Göleti, Torbalı, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7cf7e8ca-3da8-4bce-9b84-6653b66bc283'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Urla Bağ Yolu", "summary": "Urla''nın ünlü bağ evlerini ve butik şaraplarını keşfedebileceğiniz, tadım ve lezzet duraklarıyla dolu bir rota.", "place_query": "Urla Bağ Yolu, İzmir"}, {"title": "Klazomenai Antik Kenti", "summary": "İlk zeytinyağı atölyelerinin bulunduğu antik İyon kenti; tarihe tanıklık eden kalıntıları ve arkeolojik alanıyla ziyaretçilerini bekliyor.", "place_query": "Klazomenai Antik Kenti, Urla, İzmir"}, {"title": "Urla Sahil Şeridi ve İskele Meydanı", "summary": "Deniz kenarında yürüyüş yapabileceğiniz, kafe ve restoranların sıralandığı canlı bir sahil bandı; özellikle gün batımı manzarasıyla ünlüdür.", "place_query": "Urla İskele Meydanı, İzmir"}, {"title": "Özbek Köyü", "summary": "Taş evleri, dar sokakları ve huzurlu atmosferiyle Urla''nın en otantik köylerinden biri; doğa yürüyüşleri ve fotoğrafçılık için ideal.", "place_query": "Özbek Köyü, Urla, İzmir"}, {"title": "Urla Zeytinyağı Müzesi", "summary": "Zeytinyağı üretiminin tarihini ve bölgenin zeytincilik kültürünü anlatan, ödüllü bir müze; tadım ve satış imkanı da sunuyor.", "place_query": "Urla Zeytinyağı Müzesi, İzmir"}, {"title": "Gülbahçe Koyu", "summary": "Sakin ve temiz denizi, çam ormanlarıyla çevrili doğal yapısıyla Urla''nın en popüler yüzme ve piknik noktalarından biri.", "place_query": "Gülbahçe Koyu, Urla, İzmir"}, {"title": "Urla Antik Tiyatro", "summary": "Klazomenai antik kenti sınırları içinde yer alan, Helenistik döneme ait kalıntıları görebileceğiniz tarihi bir tiyatro alanı.", "place_query": "Urla Antik Tiyatro, İzmir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ba9bcdae-a704-4fe9-86a6-49de2381b8ea'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Afşin Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan Afşin Kalesi, bölgenin stratejik önemini yansıtan kalıntıları ve çevresine hakim manzarasıyla ziyaretçilerine eşsiz bir tarih ve doğa deneyimi sunar.", "place_query": "Afşin Kalesi, Afşin, Kahramanmaraş"}, {"title": "Hurman Kalesi", "summary": "Hurman Çayı kenarında yükselen bu tarihi kale, Orta Çağ''dan kalma etkileyici surları ve bölgenin doğal güzellikleriyle iç içe geçmiş yapısıyla fotoğraf severler için ideal bir duraktır.", "place_query": "Hurman Kalesi, Afşin, Kahramanmaraş"}, {"title": "Eshab-ı Kehf (Yedi Uyurlar) Mağarası", "summary": "İslam ve Hristiyan inancında önemli bir yere sahip olan bu mağara, efsanevi Yedi Uyurlar kıssasına ev sahipliği yapmasıyla bilinir ve çevresindeki mescit ile ziyaretçilere manevi bir atmosfer sunar.", "place_query": "Eshab-ı Kehf Mağarası, Afşin, Kahramanmaraş"}, {"title": "Afşin Arıtma Tesisi Mesire Alanı", "summary": "Şehir merkezine yakın, yeşil alanları ve piknik masalarıyla aileler için huzurlu bir kaçış noktası olan bu mesire alanı, doğayla iç içe vakit geçirmek isteyenler için idealdir.", "place_query": "Afşin Arıtma Tesisi Mesire Alanı, Afşin, Kahramanmaraş"}, {"title": "Göksun Barajı", "summary": "Afşin sınırlarına yakın konumdaki Göksun Barajı, geniş su yüzeyi ve çevresindeki yemyeşil tepelerle huzur verici bir manzara sunar; özellikle gün batımında fotoğrafçılar için büyüleyici bir ortam yaratır.", "place_query": "Göksun Barajı, Afşin, Kahramanmaraş"}, {"title": "Tanır Yaylası", "summary": "Yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenlerin uğrak noktası olan Tanır Yaylası, çam ormanları, temiz havası ve yayla evleriyle geleneksel bir deneyim sunar.", "place_query": "Tanır Yaylası, Afşin, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f1f19795-95f5-4a64-824c-20c7d019d838'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çokak Yaylası", "summary": "Andırın''ın en popüler yaylalarından biri olan Çokak Yaylası, yemyeşil doğası, temiz havası ve serinletici şelaleleriyle ünlüdür. Özellikle yaz aylarında yerli turistlerin akınına uğrayan bu yayla, doğa yürüyüşleri ve piknik için ideal bir noktadır.", "place_query": "Çokak Yaylası, Andırın, Kahramanmaraş"}, {"title": "Andırın Yedikuyular Kayak Merkezi", "summary": "Kahramanmaraş''ın önemli kış turizmi merkezlerinden biri olan Yedikuyular Kayak Merkezi, Andırın sınırları içinde yer alır. Kış aylarında kayak ve snowboard yapmak isteyenler için uygun pistleri ve eşsiz manzarasıyla ziyaretçilerini ağırlar.", "place_query": "Yedikuyular Kayak Merkezi, Andırın, Kahramanmaraş"}, {"title": "Geben Yaylası", "summary": "Andırın''ın en yüksek yaylalarından biri olan Geben Yaylası, zengin bitki örtüsü ve serin iklimiyle bilinir. Yayla evleri ve doğal güzellikleriyle huzurlu bir kaçamak arayanlar için mükemmel bir duraktır.", "place_query": "Geben Yaylası, Andırın, Kahramanmaraş"}, {"title": "Andırın Şelalesi", "summary": "Andırın ilçe merkezine yakın konumda bulunan bu şelale, çevresindeki yeşil alanlar ve serin sularıyla piknik ve dinlenme için popüler bir noktadır. Özellikle yaz aylarında doğa severlerin uğrak yeridir.", "place_query": "Andırın Şelalesi, Andırın, Kahramanmaraş"}, {"title": "Kaleboynu Yaylası", "summary": "Andırın''ın doğal güzelliklerinden biri olan Kaleboynu Yaylası, yemyeşil ormanları ve geniş yayla alanlarıyla dikkat çeker. Doğa yürüyüşleri ve kampçılık için elverişli bir ortam sunar.", "place_query": "Kaleboynu Yaylası, Andırın, Kahramanmaraş"}, {"title": "Andırın Kalesi", "summary": "Tarihi bir yapı olan Andırın Kalesi, ilçenin geçmişine ışık tutan önemli bir eserdir. Kale, çevresindeki doğal manzara ile birleşerek ziyaretçilere hem tarihi hem de görsel bir deneyim sunar.", "place_query": "Andırın Kalesi, Andırın, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '51acb2be-689d-402d-9f15-b4e2039e81f1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çağlayancerit Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin savunma amaçlı kullanılan önemli yapılarından biridir. Kaleye çıktığınızda Çağlayancerit ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "Çağlayancerit Kalesi, Çağlayancerit, Kahramanmaraş"}, {"title": "Aksu Çayı ve Mesire Alanı", "summary": "İlçeden geçen Aksu Çayı çevresinde bulunan mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek için idealdir. Özellikle yaz aylarında serin suları ve yeşil doğasıyla ziyaretçilerini cezbeder.", "place_query": "Aksu Çayı Mesire Alanı, Çağlayancerit, Kahramanmaraş"}, {"title": "Uludaz Yaylası", "summary": "Çağlayancerit''in yüksek kesimlerinde yer alan Uludaz Yaylası, yemyeşil doğası ve temiz havasıyla ünlüdür. Yayla evlerinde konaklayabilir, yöresel lezzetleri tadabilir ve doğa yürüyüşleri yapabilirsiniz.", "place_query": "Uludaz Yaylası, Çağlayancerit, Kahramanmaraş"}, {"title": "Bozlar Şelalesi", "summary": "İlçe sınırları içinde bulunan Bozlar Şelalesi, etkileyici doğal güzelliği ve serin sularıyla ziyaretçilerine huzurlu bir ortam sunar. Şelale çevresinde piknik yapabilir ve fotoğraf çekebilirsiniz.", "place_query": "Bozlar Şelalesi, Çağlayancerit, Kahramanmaraş"}, {"title": "Çağlayancerit Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de tarihi dokuya tanıklık etmek için ziyaret edilebilecek önemli bir yapıdır.", "place_query": "Çağlayancerit Merkez Camii, Çağlayancerit, Kahramanmaraş"}, {"title": "Küçükcerit Köyü Tarihi Evleri", "summary": "Küçükcerit Köyü''nde bulunan geleneksel taş ve ahşap evler, yöresel mimarinin güzel örneklerini sergiler. Köyde yürüyüş yaparak geçmişe yolculuk yapabilir ve yöre halkının misafirperverliğini deneyimleyebilirsiniz.", "place_query": "Küçükcerit Köyü Tarihi Evleri, Çağlayancerit, Kahramanmaraş"}, {"title": "Döngele Yaylası", "summary": "Yüksek rakımı ve zengin bitki örtüsüyle dikkat çeken Döngele Yaylası, doğa severler için keşfedilmeyi bekleyen bir cennettir. Yaylada kamp yapabilir ve eşsiz yıldız manzarasının tadını çıkarabilirsiniz.", "place_query": "Döngele Yaylası, Çağlayancerit, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd6c2aac8-97c7-4fe0-88e4-23dd1c35c7c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kahramanmaraş Kalesi", "summary": "Şehir merkezinde yüksek bir tepe üzerinde yer alan tarihi kale, muhteşem şehir manzarası sunar ve bölgenin en önemli simge yapılarından biridir.", "place_query": "Kahramanmaraş Kalesi, Dulkadiroğlu, Kahramanmaraş"}, {"title": "Tarihi Kapalı Çarşı", "summary": "Osmanlı döneminden kalma bu tarihi çarşı, yöresel bakır işlemeciliği, baharatlar ve hediyelik eşyalarla dolu dar sokaklarıyla ziyaretçileri büyüler.", "place_query": "Tarihi Kapalı Çarşı, Dulkadiroğlu, Kahramanmaraş"}, {"title": "Abdülhamid Han Camii", "summary": "Şehrin en büyük ve en görkemli camilerinden biri olan bu yapı, Osmanlı mimarisinin güzel bir örneği olup geniş avlusu ve zarif minareleriyle dikkat çeker.", "place_query": "Abdülhamid Han Camii, Dulkadiroğlu, Kahramanmaraş"}, {"title": "Maraş Biberi ve Dondurma Müzesi", "summary": "Kahramanmaraş''ın dünyaca ünlü dondurması ve biberinin üretim sürecini, tarihini ve kültürünü etkileşimli bir şekilde keşfedebileceğiniz eşsiz bir müzedir.", "place_query": "Maraş Biberi ve Dondurma Müzesi, Dulkadiroğlu, Kahramanmaraş"}, {"title": "Ulu Cami", "summary": "Dulkadiroğlu Beyliği döneminden kalma bu tarihi cami, sade ve etkileyici mimarisi ile şehrin en eski ibadethanelerinden biridir.", "place_query": "Ulu Cami, Dulkadiroğlu, Kahramanmaraş"}, {"title": "Taş Medrese", "summary": "Geçmişte medrese olarak kullanılan bu tarihi taş yapı, günümüzde kültürel etkinliklere ev sahipliği yapmakta ve Maraş''ın tarihi dokusunu yansıtmaktadır.", "place_query": "Taş Medrese, Dulkadiroğlu, Kahramanmaraş"}, {"title": "100. Yıl Parkı", "summary": "Şehrin en büyük ve en popüler yeşil alanlarından biri olan bu park, yürüyüş yolları, göleti ve dinlenme alanlarıyla aileler için ideal bir kaçış noktasıdır.", "place_query": "100. Yıl Parkı, Dulkadiroğlu, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '20f631e0-d77d-4891-9b34-0242878a9696'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ekinözü Merkez Camii", "summary": "İlçenin merkezinde yer alan tarihi cami, yöresel mimarinin güzel bir örneğidir ve ibadet ziyaretleri için önemli bir noktadır.", "place_query": "Ekinözü Merkez Camii, Ekinözü, Kahramanmaraş"}, {"title": "Ceyhan Nehri Kenarı", "summary": "İlçenin yakınından geçen Ceyhan Nehri, doğal yürüyüşler ve piknik yapmak için huzurlu bir ortam sunar.", "place_query": "Ceyhan Nehri, Ekinözü, Kahramanmaraş"}, {"title": "Ekinözü Yaylaları", "summary": "Çevredeki yaylalar, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyen ziyaretçiler için popülerdir.", "place_query": "Ekinözü yaylaları, Kahramanmaraş"}, {"title": "Kaleboyu Tepesi", "summary": "İlçeye hakim bir tepede bulunan Kaleboyu, tarihi kalıntıları ve panoramik manzarası ile dikkat çeker.", "place_query": "Kaleboyu Tepesi, Ekinözü, Kahramanmaraş"}, {"title": "Ekinözü Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, bölgenin geçmişine ışık tutar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Ekinözü Kalesi, Kahramanmaraş"}, {"title": "Gözpınarı Mesire Alanı", "summary": "Doğa ile iç içe bir piknik ve dinlenme alanı olan Gözpınarı, özellikle hafta sonu kaçamaklarında tercih edilir.", "place_query": "Gözpınarı Mesire Alanı, Ekinözü, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c2eb6760-7f1d-4055-8ec7-e889fa401605'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Elbistan Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan tarihi cami, şehrin merkezinde yer alır ve bölgenin en önemli dini yapılarından biridir.", "place_query": "Elbistan Ulu Camii, Elbistan, Kahramanmaraş"}, {"title": "Elbistan Müzesi", "summary": "Hitit, Roma ve Bizans dönemlerine ait eserlerin sergilendiği müze, bölgenin zengin tarihini keşfetmek isteyenler için ideal bir duraktır.", "place_query": "Elbistan Müzesi, Elbistan, Kahramanmaraş"}, {"title": "Elbistan Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale kalıntıları, şehre hakim bir manzara sunar ve geçmişe yolculuk yapma fırsatı verir.", "place_query": "Elbistan Kalesi, Elbistan, Kahramanmaraş"}, {"title": "Kapıçam Tabiat Parkı", "summary": "Elbistan''a yaklaşık 20 km uzaklıktaki bu doğal park, piknik alanları, yürüyüş yolları ve göletiyle doğa severler için popüler bir kaçış noktasıdır.", "place_query": "Kapıçam Tabiat Parkı, Kahramanmaraş"}, {"title": "Elbistan Çarşı Hamamı", "summary": "Osmanlı döneminden kalma bu tarihi hamam, geleneksel mimarisi ve hala aktif kullanımıyla ziyaretçilere otantik bir deneyim sunar.", "place_query": "Elbistan Çarşı Hamamı, Elbistan, Kahramanmaraş"}, {"title": "Kızılin Köprüsü", "summary": "Tarihi taş köprü, Ceyhan Nehri üzerinde yer alır ve bölgenin eski ulaşım yapılarına dair güzel bir örnektir.", "place_query": "Kızılin Köprüsü, Elbistan, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a9531504-e89b-4f24-ba3e-71850918683f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göksun Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla piknik ve dinlenme için ideal bir noktadır. Özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Göksun Şelalesi, Göksun, Kahramanmaraş"}, {"title": "Kaleboyu Kalesi", "summary": "Tarihi bir kale olup bölgenin stratejik önemini yansıtır. Kaleye çıktığınızda Göksun Ovası''nın muhteşem manzarasını izleyebilirsiniz.", "place_query": "Kaleboyu Kalesi, Göksun, Kahramanmaraş"}, {"title": "Göksun Müzesi", "summary": "Hitit, Roma ve Bizans dönemlerine ait eserlerin sergilendiği küçük ama zengin bir müzedir. İlçe merkezinde kolayca ziyaret edilebilir.", "place_query": "Göksun Müzesi, Göksun, Kahramanmaraş"}, {"title": "Cihan Paşa Camii", "summary": "Osmanlı döneminden kalma tarihi bir camidir. Mimari detayları ve taş işçiliğiyle dikkat çeker, ilçenin en önemli dini yapılarındandır.", "place_query": "Cihan Paşa Camii, Göksun, Kahramanmaraş"}, {"title": "Göksun Yaylaları (Kazmaca Yaylası)", "summary": "Doğa yürüyüşleri ve kampçılık için popüler olan yaylalar, temiz havası ve yeşil doğasıyla huzur verir. Özellikle Kazmaca Yaylası sık tercih edilir.", "place_query": "Kazmaca Yaylası, Göksun, Kahramanmaraş"}, {"title": "Köşk Höyük", "summary": "Hitit dönemine ait önemli bir arkeolojik alandır. Bölgedeki kazılarda ortaya çıkarılan kalıntılar tarih meraklıları için büyük önem taşır.", "place_query": "Köşk Höyük, Göksun, Kahramanmaraş"}, {"title": "Sarıkız Tepesi", "summary": "Göksun''un en yüksek noktalarından biri olup eşsiz bir panoramik manzara sunar. Gün doğumu ve gün batımı fotoğrafları için idealdir.", "place_query": "Sarıkız Tepesi, Göksun, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '669b55ca-84be-46ac-bed4-e35641d130dc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Nurhak Dağı", "summary": "Bölgenin en yüksek noktalarından biri olan Nurhak Dağı, doğa yürüyüşleri ve kampçılık için idealdir. Zirvesinden çevre ilçelerin muhteşem manzarası izlenebilir.", "place_query": "Nurhak Dağı, Nurhak, Kahramanmaraş"}, {"title": "Ilıca Şelalesi", "summary": "Nurhak ilçe merkezine yakın konumdaki bu şelale, serin suları ve yeşil doğasıyla piknik ve mesire için popüler bir noktadır.", "place_query": "Ilıca Şelalesi, Nurhak, Kahramanmaraş"}, {"title": "Nurhak Barajı ve Mesire Alanı", "summary": "Baraj gölü çevresinde düzenlenen mesire alanı, olta balıkçılığı ve doğa ile baş başa vakit geçirmek isteyenler için huzurlu bir ortam sunar.", "place_query": "Nurhak Barajı, Nurhak, Kahramanmaraş"}, {"title": "Kale (Nurhak Kalesi)", "summary": "Tarihi bir kalıntı olan Nurhak Kalesi, bölgenin geçmişine ışık tutar ve tepe üzerindeki konumuyla etkileyici bir panoramik görüntü sağlar.", "place_query": "Nurhak Kalesi, Nurhak, Kahramanmaraş"}, {"title": "Yeşil Yayla (Yayla Evleri)", "summary": "Yaz aylarında yaylacıların uğrak noktası olan bu bölge, temiz havası ve doğal güzellikleriyle şehir stresinden uzaklaşmak için idealdir.", "place_query": "Yeşil Yayla, Nurhak, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c90378c0-f7d3-43f8-b135-5a872325f3a5'::uuid;
