'663e544c-4046-4067-b487-35f003cba791'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızkapanlı Höyüğü", "summary": "Pazarcık ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu höyük, bölgenin en önemli arkeolojik alanlarından biridir. Hitit dönemine ait izler taşıyan höyük, özellikle tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Kızkapanlı Höyüğü, Pazarcık, Kahramanmaraş"}, {"title": "Pazarcık Kalesi", "summary": "İlçe merkezinde yer alan tarihi kale, Pazarcık''ın simgelerinden biridir. Bölgeye hakim bir tepe üzerine kurulu olan kale, çevresindeki manzarasıyla ziyaretçilerine güzel bir seyir imkanı sunar.", "place_query": "Pazarcık Kalesi, Pazarcık, Kahramanmaraş"}, {"title": "Narlı Göleti ve Mesire Alanı", "summary": "Pazarcık''a bağlı Narlı Mahallesi''nde bulunan gölet, piknik ve doğa yürüyüşleri için ideal bir mekandır. Sakin atmosferi ve yeşil çevresiyle hafta sonu kaçamakları için sıkça tercih edilir.", "place_query": "Narlı Göleti, Pazarcık, Kahramanmaraş"}, {"title": "Pazarcık Ulu Camii", "summary": "İlçe merkezindeki tarihi cami, Osmanlı dönemi mimarisinin güzel örneklerinden biridir. Restore edilmiş yapısı ve iç süslemeleriyle dikkat çeken cami, hem ibadet hem de kültürel ziyaretler için önemli bir noktadır.", "place_query": "Pazarcık Ulu Camii, Pazarcık, Kahramanmaraş"}, {"title": "Cevizlidere Şelalesi", "summary": "Pazarcık ilçe sınırlarında yer alan bu doğal şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir duraktır. Çevresindeki yeşil alanlar piknik için de uygundur.", "place_query": "Cevizlidere Şelalesi, Pazarcık, Kahramanmaraş"}, {"title": "Yumaklı (Yumaklıcık) Köyü Tarihi Evleri", "summary": "Pazarcık''ın Yumaklıcık köyünde bulunan geleneksel taş ve ahşap evler, bölgenin kırsal mimarisini yansıtır. Tarihi dokuyu görmek ve köy hayatını deneyimlemek isteyenler için güzel bir rota oluşturur.", "place_query": "Yumaklıcık Köyü, Pazarcık, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b722ee58-5646-4711-ad28-99f02673e919'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Türkoğlu Şelalesi", "summary": "İlçe merkezine yakın, doğal güzelliğiyle piknik ve mesire alanı olarak kullanılan popüler bir şelaledir. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler tarafından tercih edilir.", "place_query": "Türkoğlu Şelalesi, Kahramanmaraş"}, {"title": "Türkoğlu Kapalı Pazar Yeri", "summary": "İlçenin en hareketli noktalarından biri olan bu kapalı pazar, yöresel ürünlerin ve taze meyve-sebzenin satıldığı renkli bir alışveriş deneyimi sunar. Yerel halkın günlük yaşamını gözlemlemek için idealdir.", "place_query": "Türkoğlu Kapalı Pazar Yeri, Kahramanmaraş"}, {"title": "Türkoğlu Merkez Camii", "summary": "Modern mimarisi ve geniş avlusuyla ilçenin simge yapılarından biridir. Hem ibadet hem de mimari açıdan ziyaret edilmeye değerdir.", "place_query": "Türkoğlu Merkez Camii, Kahramanmaraş"}, {"title": "Ceyhan Nehri Kenarı Mesire Alanı", "summary": "Ceyhan Nehri''nin kıyısında yer alan bu mesire alanı, doğa yürüyüşü ve piknik için sakin bir ortam sunar. Nehir manzarası eşliğinde huzurlu vakit geçirmek mümkündür.", "place_query": "Ceyhan Nehri Mesire Alanı, Türkoğlu, Kahramanmaraş"}, {"title": "Beyoğlu Mahallesi Tarihi Çeşmeler", "summary": "İlçede Osmanlı döneminden kalma birkaç tarihi çeşme, özellikle Beyoğlu Mahallesi''nde bulunur. Bu çeşmeler, bölgenin geçmişine dair izler taşıyan küçük ama anlamlı durak noktalarıdır.", "place_query": "Beyoğlu Mahallesi Tarihi Çeşmeler, Türkoğlu, Kahramanmaraş"}, {"title": "Türkoğlu Kalesi (Kalıntıları)", "summary": "İlçe sınırları içinde yer alan bu tarihi kale kalıntısı, bölgenin savunma amaçlı kullanılan eski yerleşimlerinden biridir. Tepe üzerindeki konumu sayesinde çevreye hakim bir manzara sunar.", "place_query": "Türkoğlu Kalesi Kalıntıları, Kahramanmaraş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0e299a2e-e054-4579-a2b3-78ad8db3bc00'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eflani Kaya Mezarları", "summary": "Tarihi Frig dönemine kadar uzanan bu kaya mezarları, ilçe merkezine yakın bir konumda yer alır ve bölgenin antik geçmişine ışık tutar.", "place_query": "Eflani Kaya Mezarları, Karabük"}, {"title": "Eflani Kalesi", "summary": "Tarihi bir kale olan bu yapı, ilçeye hakim bir tepe üzerinde yer alır ve çevresine muhteşem bir manzara sunar.", "place_query": "Eflani Kalesi, Karabük"}, {"title": "Eflani Yaylaları (Sarıçiçek Yaylası vb.)", "summary": "Yeşilin her tonunu barındıran yaylalar, doğa yürüyüşleri ve piknik için ideal olup serinletici bir kaçış noktasıdır.", "place_query": "Sarıçiçek Yaylası, Eflani, Karabük"}, {"title": "Eflani Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, Osmanlı dönemi mimarisinin güzel bir örneğidir ve şehrin simgelerindendir.", "place_query": "Eflani Saat Kulesi, Karabük"}, {"title": "Sarıçiçek Göleti", "summary": "Yaylalar bölgesinde yer alan bu gölet, çevresiyle birlikte huzurlu bir doğa gezisi ve fotoğrafçılık için popüler bir duraktır.", "place_query": "Sarıçiçek Göleti, Eflani, Karabük"}, {"title": "Eflani Taş Köprü", "summary": "Tarihi bir Osmanlı köprüsü olan bu yapı, taş işçiliğinin güzel bir örneğini sergiler ve fotoğraf çekmek için idealdir.", "place_query": "Eflani Taş Köprü, Karabük"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c3bcd484-745d-4791-a510-48b160428d88'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hadrianapolis Antik Kenti", "summary": "Eskipazar sınırları içinde yer alan bu antik kent, Roma dönemine ait mozaikleri, hamamı ve şehir kalıntılarıyla tarih meraklıları için eşsiz bir durak.", "place_query": "Hadrianapolis Antik Kenti, Eskipazar, Karabük"}, {"title": "Eskipazar Kaya Mezarları", "summary": "Bölgedeki kayalara oyulmuş bu tarihi mezarlar, antik dönem mezar mimarisini yakından görmek isteyenler için etkileyici bir açık hava müzesi niteliğindedir.", "place_query": "Eskipazar Kaya Mezarları, Karabük"}, {"title": "Karabük Şehir Ormanı", "summary": "Eskipazar''a yakın konumuyla doğa yürüyüşleri ve piknik için ideal olan bu ormanlık alan, temiz havası ve yeşil doğasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Karabük Şehir Ormanı, Karabük"}, {"title": "Eskipazar Merkez Camii ve Külliyesi", "summary": "Osmanlı dönemi mimarisini yansıtan bu tarihi cami ve külliye, ilçenin merkezinde yer alarak hem ibadet hem de kültürel ziyaretler için önemli bir noktadır.", "place_query": "Eskipazar Merkez Camii, Karabük"}, {"title": "Sarıkaya Kaplıcaları", "summary": "Eskipazar''da bulunan bu doğal kaplıcalar, şifalı suları ve termal tesisleriyle dinlenmek ve sağlık turizmi için popüler bir destinasyondur.", "place_query": "Sarıkaya Kaplıcaları, Eskipazar, Karabük"}, {"title": "Büyükdüz Göleti", "summary": "Doğal güzelliği ve çevresindeki yürüyüş parkurlarıyla bilinen bu gölet, özellikle hafta sonu doğa severlerin uğrak noktasıdır.", "place_query": "Büyükdüz Göleti, Eskipazar, Karabük"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1acf1170-7cb5-493d-8427-9a2721dd8227'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Safranbolu Tarihi Çarşı", "summary": "Osmanlı döneminden kalma dükkanlar, hanlar ve çeşmelerle dolu bu tarihi çarşı, Safranbolu’nun kültürel kalbidir. Ziyaretçiler burada el yapımı bakır ürünleri, lokum ve safran gibi yöresel lezzetleri bulabilir.", "place_query": "Safranbolu Tarihi Çarşı, Karabük Merkez"}, {"title": "Hıdırlık Tepesi", "summary": "Safranbolu’nun en güzel manzarasını sunan bu seyir noktası, özellikle gün batımında büyüleyici bir atmosfere sahiptir. Tepede tarihi bir yapı ve çay bahçesi de bulunur.", "place_query": "Hıdırlık Tepesi, Safranbolu, Karabük"}, {"title": "Safranbolu Evleri", "summary": "UNESCO Dünya Mirası Listesi’nde yer alan bu geleneksel Osmanlı evleri, dar sokaklar ve ahşap işçiliğiyle ünlüdür. Birçoğu butik otel veya müze olarak hizmet verir.", "place_query": "Safranbolu Evleri, Karabük Merkez"}, {"title": "Karabük Demir ve Çelik Müzesi", "summary": "Türkiye’nin ilk demir-çelik fabrikasının tarihini anlatan bu müze, endüstriyel mirası gözler önüne serer. Eski makineler, fotoğraflar ve belgelerle dolu etkileyici bir sergi sunar.", "place_query": "Karabük Demir ve Çelik Müzesi, Karabük Merkez"}, {"title": "İncekaya Su Kemeri", "summary": "Roma döneminden kalma bu tarihi su kemeri, Tokatlı Kanyonu üzerinde yükselir ve etkileyici bir görüntü oluşturur. Kanyon manzarası eşliğinde fotoğraf çekmek için ideal bir noktadır.", "place_query": "İncekaya Su Kemeri, Safranbolu, Karabük"}, {"title": "Tokatlı Kanyonu", "summary": "Doğal güzelliği ve yürüyüş parkurlarıyla ünlü bu kanyon, cam seyir terası ve şelaleleriyle ziyaretçileri büyüler. Kanyon boyunca yapılan doğa yürüyüşü unutulmaz bir deneyim sunar.", "place_query": "Tokatlı Kanyonu, Safranbolu, Karabük"}, {"title": "Cinci Hanı", "summary": "17. yüzyılda inşa edilen bu tarihi han, Safranbolu’nun en önemli yapılarından biridir. Günümüzde otel ve restoran olarak hizmet veren han, Osmanlı mimarisinin zarif bir örneğidir.", "place_query": "Cinci Hanı, Safranbolu, Karabük"}, {"title": "Safranbolu Kent Tarihi Müzesi", "summary": "Eski bir hükümet konağında yer alan müze, Safranbolu’nun tarihini ve kültürünü sergiler. Arkeolojik buluntular, etnografik eserler ve yöresel kıyafetler müzenin öne çıkan koleksiyonlarındandır.", "place_query": "Safranbolu Kent Tarihi Müzesi, Karabük Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '77134154-faca-4ac4-8963-8ce359c8a323'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karabük Ovacık Yaylası", "summary": "Doğal güzellikleri ve temiz havasıyla ünlü olan bu yayla, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyen ziyaretçilerin uğrak noktasıdır.", "place_query": "Ovacık Yaylası, Karabük"}, {"title": "Bulak Mağarası", "summary": "Sarkıt ve dikitleriyle etkileyici bir doğa harikası olan mağara, ziyaretçilerine eşsiz bir yeraltı keşfi sunar.", "place_query": "Bulak Mağarası, Ovacık, Karabük"}, {"title": "Safranbolu Evleri (Ovacık''a yakın bir tarihi alan)", "summary": "Osmanlı dönemi mimarisinin en güzel örneklerini barındıran bu evler, dar sokakları ve tarihi dokusuyla büyüler.", "place_query": "Safranbolu Evleri, Karabük"}, {"title": "Karabük Ovacık Kanyonu", "summary": "Doğa yürüyüşleri ve fotoğrafçılık için ideal olan kanyon, yemyeşil bitki örtüsü ve akan deresiyle huzur verir.", "place_query": "Ovacık Kanyonu, Karabük"}, {"title": "Ovacık Şehitler Anıtı ve Çevresi", "summary": "Bölgenin tarihi önemini yansıtan anıt, çevresindeki piknik alanlarıyla birlikte ziyaretçilere hem manevi bir atmosfer hem de dinlenme imkanı sunar.", "place_query": "Ovacık Şehitler Anıtı, Karabük"}, {"title": "Eskipazar Antik Kenti (Hadrianopolis)", "summary": "Ovacık''a yakın konumdaki bu antik kent, Roma ve Bizans dönemine ait mozaikler ve kalıntılarla tarih meraklılarını cezbeder.", "place_query": "Hadrianopolis Antik Kenti, Eskipazar, Karabük"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ceeccea1-381d-499d-8ad2-08fc592049c2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Safranbolu Evleri", "summary": "Osmanlı döneminden kalma, dar sokakları ve ahşap taş mimarisiyle ünlü tarihi evler. Ziyaretçiler burada geleneksel Türk yaşamını keşfedebilir ve eşsiz fotoğraflar çekebilir.", "place_query": "Safranbolu Evleri, Safranbolu, Karabük"}, {"title": "Safranbolu Tarihi Çarşısı", "summary": "Arnavut kaldırımlı sokakları ve el yapımı ürünler satan dükkanlarıyla ünlü tarihi çarşı. Bakırcılar, yemeniciler ve safran satıcılarıyla kültürel bir alışveriş deneyimi sunar.", "place_query": "Safranbolu Tarihi Çarşısı, Safranbolu, Karabük"}, {"title": "Kristal Teras", "summary": "Tokatlı Kanyonu üzerinde yer alan, 80 metre yüksekliğindeki cam seyir terası. Ziyaretçilere nefes kesen kanyon manzarası eşliğinde adrenalin dolu bir deneyim yaşatır.", "place_query": "Kristal Teras, Safranbolu, Karabük"}, {"title": "Tokatlı Kanyonu", "summary": "Safranbolu''nun doğal güzelliklerinden biri olan, yürüyüş parkurları ve ahşap köprüleriyle keşfedilmeyi bekleyen derin bir kanyon. Doğa yürüyüşü ve fotoğrafçılık için idealdir.", "place_query": "Tokatlı Kanyonu, Safranbolu, Karabük"}, {"title": "Hıdırlık Tepesi", "summary": "Safranbolu''nun panoramik manzarasını izlemek için en popüler nokta. Özellikle gün batımında tarihi evlerin ve şehrin kuşbakışı görüntüsü büyüleyicidir.", "place_query": "Hıdırlık Tepesi, Safranbolu, Karabük"}, {"title": "Cinci Hanı", "summary": "17. yüzyıldan kalma tarihi bir kervansaray olan Cinci Hanı, Osmanlı ticaret hayatının izlerini taşır. Günümüzde restoran ve hediyelik eşya dükkanlarıyla ziyaretçileri ağırlar.", "place_query": "Cinci Hanı, Safranbolu, Karabük"}, {"title": "İncekaya Su Kemeri", "summary": "Tokatlı Kanyonu girişinde bulunan, Roma döneminden kalma tarihi su kemeri. Doğa ile tarihin iç içe geçtiği bu yapı, fotoğrafçılar için popüler bir duraktır.", "place_query": "İncekaya Su Kemeri, Safranbolu, Karabük"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ac0b670d-86b8-4434-8302-43ad45ffa142'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yenice Ormanları", "summary": "Türkiye''nin en büyük ve en zengin biyolojik çeşitliliğine sahip ormanlarından biri olan Yenice Ormanları, doğa yürüyüşleri ve kamp için ideal bir noktadır. Bakir doğası, şelaleleri ve endemik bitki türleriyle doğa severler için eşsiz bir deneyim sunar.", "place_query": "Yenice Ormanları, Karabük"}, {"title": "Kadıncık Ana Mağarası", "summary": "Yenice ilçe merkezine yaklaşık 20 km uzaklıkta bulunan bu mağara, sarkıt ve dikitleriyle görülmeye değerdir. Efsanelere konu olan mağara, doğal güzelliği ve mistik atmosferiyle ziyaretçilerini etkiler.", "place_query": "Kadıncık Ana Mağarası, Yenice, Karabük"}, {"title": "Ödül Ormanı Tabiat Parkı", "summary": "Yenice sınırları içinde yer alan bu tabiat parkı, zengin bitki örtüsü ve temiz havasıyla piknik ve doğa yürüyüşü için popüler bir destinasyondur. Park içindeki yürüyüş parkurları ve seyir terasları ziyaretçilere huzurlu anlar yaşatır.", "place_query": "Ödül Ormanı Tabiat Parkı, Yenice, Karabük"}, {"title": "Yenice Şelalesi", "summary": "Yemyeşil ormanların içinde gizlenmiş bu şelale, serin suları ve doğal havuzuyla özellikle yaz aylarında ziyaretçi akınına uğrar. Şelaleye ulaşmak için kısa bir doğa yürüyüşü yapmak gerekir.", "place_query": "Yenice Şelalesi, Karabük"}, {"title": "Sarıkaya Tabiat Parkı", "summary": "Yenice ilçesine bağlı Sarıkaya mevkiinde bulunan bu tabiat parkı, kamp ve günübirlik dinlenme alanlarıyla bilinir. Çam ormanlarıyla çevrili park, şehir gürültüsünden uzaklaşmak isteyenler için idealdir.", "place_query": "Sarıkaya Tabiat Parkı, Yenice, Karabük"}, {"title": "Küre Dağları Milli Parkı (Yenice Girişi)", "summary": "Küre Dağları Milli Parkı''nın Yenice sınırları içinde kalan bölümü, derin vadiler ve zengin yaban hayatıyla keşfedilmeyi bekler. Bölgedeki yürüyüş rotaları, doğa fotoğrafçıları ve macera arayanlar için benzersiz fırsatlar sunar.", "place_query": "Küre Dağları Milli Parkı Yenice girişi, Karabük"}, {"title": "Yenice Eski Camii", "summary": "Tarihi dokusuyla dikkat çeken bu cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Yenice merkezde yer alan cami, hem ibadet hem de tarihi bir yapı olarak ziyaret edilebilir.", "place_query": "Yenice Eski Camii, Karabük"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4e7db4c1-6ba3-4c47-a4f2-60bb4c0f39ff'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayrancı Barajı", "summary": "Bölgenin en önemli su kaynaklarından biri olan baraj, çevresindeki yeşil alanlar ve sakin atmosferiyle piknik ve doğa yürüyüşü için idealdir. Özellikle kuş gözlemcileri için huzurlu bir ortam sunar.", "place_query": "Ayrancı Barajı, Karaman"}, {"title": "Ayrancı İlçe Merkezi Tarihi Camiler", "summary": "İlçe merkezinde bulunan ve Osmanlı döneminden kalma tarihi camiler, sade mimarileri ve manevi atmosferleriyle ziyaretçilerin ilgisini çeker. Yöresel taş işçiliğini görmek mümkündür.", "place_query": "Ayrancı Merkez Camii, Karaman"}, {"title": "Çatalkaya Mağarası", "summary": "Ayrancı sınırları içinde yer alan bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Macera arayan doğa tutkunları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Çatalkaya Mağarası, Ayrancı, Karaman"}, {"title": "Dikilitaş (Menfeç) Anıtı", "summary": "İlçe yakınlarında bulunan bu tarihi anıt, Roma dönemine ait olduğu düşünülen bir mezar yapısıdır. Bölgenin antik geçmişine ışık tutan önemli bir kültür varlığıdır.", "place_query": "Dikilitaş Anıtı, Ayrancı, Karaman"}, {"title": "Kızılkaya Yaylası", "summary": "Yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için ideal bir yayladır. Çam ormanları ve temiz havasıyla kampçıların da uğrak noktalarındandır.", "place_query": "Kızılkaya Yaylası, Ayrancı, Karaman"}, {"title": "Ayrancı Höyükleri (Tümülüsler)", "summary": "İlçe geneline yayılmış antik höyükler, bölgenin Neolitik dönemden beri yerleşim gördüğünü kanıtlar. Arkeoloji meraklıları için ilgi çekici bir keşif rotasıdır.", "place_query": "Ayrancı Höyükleri, Karaman"}, {"title": "Berendi Köyü Tarihi Evleri", "summary": "Ayrancı''ya bağlı Berendi Köyü''nde bulunan geleneksel taş evler, yöresel mimariyi yansıtır. Köy, sakin atmosferiyle kırsal turizm için uygun bir duraktır.", "place_query": "Berendi Köyü, Ayrancı, Karaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4dd009a2-0d99-410e-8c9a-5133dc8edc76'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Başyayla Yaylası", "summary": "Başyayla ilçesinin en bilinen doğal alanı olan yayla, yemyeşil ormanları ve temiz havasıyla özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Başyayla Yaylası, Başyayla, Karaman"}, {"title": "Bolluk Mağarası", "summary": "İlçe merkezine yakın konumdaki bu mağara, etkileyici sarkıt ve dikit oluşumlarıyla doğa ve mağara tutkunlarının ilgisini çeker; çevresindeki piknik alanları da ziyaretçilere keyifli vakit geçirme imkanı sunar.", "place_query": "Bolluk Mağarası, Başyayla, Karaman"}, {"title": "Göksu Nehri Kenarı", "summary": "Başyayla sınırlarından geçen Göksu Nehri''nin berrak suları ve yeşil çevresi, doğa yürüyüşleri, piknik ve fotoğrafçılık için huzurlu bir ortam oluşturur.", "place_query": "Göksu Nehri, Başyayla, Karaman"}, {"title": "Çamlıca Tepesi Seyir Noktası", "summary": "İlçeye hakim bir tepede yer alan bu seyir noktasından Başyayla''nın panoramik manzarasını izleyebilir, özellikle gün batımında eşsiz kareler yakalayabilirsiniz.", "place_query": "Çamlıca Tepesi, Başyayla, Karaman"}, {"title": "Başyayla Merkez Camii ve Çevresi", "summary": "İlçenin tarihi dokusunu yansıtan merkez camii ve etrafındaki eski çarşı, yöresel hayatı gözlemlemek ve geleneksel mimariyi görmek için kısa bir şehir turu rotasıdır.", "place_query": "Başyayla Merkez Camii, Başyayla, Karaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7e632caf-7107-4fba-ac85-c8c32b4a5e0c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ermenek Kalesi", "summary": "Ermenek ilçe merkezinde yüksek bir kaya kütlesi üzerine kurulu olan bu tarihi kale, bölgenin en önemli simgelerindendir. Karamanoğulları döneminden kalma yapı, şehre hakim manzarası ve sur kalıntılarıyla ziyaretçilerine tarihi bir atmosfer sunar.", "place_query": "Ermenek Kalesi, Ermenek, Karaman"}, {"title": "Görmeli (Gökçe) Plajı", "summary": "Ermenek''in Görmeli Mahallesi''nde bulunan bu plaj, Göksu Nehri kıyısında doğal bir yüzme alanıdır. Berrak ve serin suyu, yeşil doğayla çevrili ortamıyla özellikle yaz aylarında yerli halkın ve ziyaretçilerin uğrak noktasıdır.", "place_query": "Görmeli Plajı, Görmeli, Ermenek, Karaman"}, {"title": "Meydan Köprüsü", "summary": "Ermenek ilçe merkezinde yer alan bu tarihi taş köprü, Roma veya Bizans döneminden kalma olduğu düşünülen önemli bir mimari eserdir. Göksu Nehri üzerinde bulunan köprü, zarif kemer yapısıyla dikkat çeker ve fotoğrafçılar için popüler bir mekandır.", "place_query": "Meydan Köprüsü, Ermenek, Karaman"}, {"title": "Ermenek Barajı ve Hidroelektrik Santrali", "summary": "Göksu Nehri üzerinde kurulu olan bu baraj, hem enerji üretimi hem de çevresindeki doğal güzelliklerle bilinir. Baraj gölü çevresi piknik ve dinlenme alanları ile ziyaretçilere huzurlu bir ortam sunar.", "place_query": "Ermenek Barajı, Ermenek, Karaman"}, {"title": "Taşkale (Kızılkaya) Mağarası", "summary": "Ermenek''e bağlı Taşkale köyünde bulunan bu doğal mağara, etkileyici sarkıt ve dikit oluşumlarıyla dikkat çeker. Mağara, doğa yürüyüşü ve keşif yapmak isteyenler için ilgi çekici bir duraktır.", "place_query": "Taşkale Mağarası, Ermenek, Karaman"}, {"title": "Ermenek Müzesi", "summary": "İlçe merkezinde yer alan bu müze, Ermenek ve çevresindeki antik yerleşimlerden çıkarılan arkeolojik eserleri sergiler. Hitit, Roma ve Bizans dönemlerine ait buluntular, bölgenin zengin tarihine ışık tutar.", "place_query": "Ermenek Müzesi, Ermenek, Karaman"}, {"title": "Balkusan Yaylası", "summary": "Ermenek''e bağlı Balkusan köyü yakınlarındaki bu yayla, yemyeşil çam ormanları ve serin havasıyla doğa severler için ideal bir kaçış noktasıdır. Yaylada kamp yapabilir, doğa yürüyüşleri gerçekleştirebilirsiniz.", "place_query": "Balkusan Yaylası, Ermenek, Karaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0825bd59-973b-4f0c-9fd9-33399bc658fd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kazımkarabekir İlçe Merkezi ve Cumhuriyet Meydanı", "summary": "İlçenin kalbi sayılan bu meydan, çevresindeki tarihi yapılar ve anıtlarla birlikte yörenin sosyal ve kültürel hayatını yansıtır. Ziyaretçiler, burada ilçenin günlük yaşamına tanıklık edebilir ve çevredeki küçük esnaf dükkanlarını gezebilir.", "place_query": "Kazımkarabekir Merkez, Karaman"}, {"title": "Kazımkarabekir Atatürk Evi", "summary": "Atatürk''ün ilçeyi ziyareti sırasında kullandığı bu tarihi ev, günümüzde küçük bir müze olarak hizmet vermektedir. Milli mücadele ruhunu yansıtan eşyalar ve fotoğraflar, ziyaretçilere duygusal bir atmosfer sunar.", "place_query": "Atatürk Evi, Kazımkarabekir, Karaman"}, {"title": "Kazımkarabekir Şehitliği", "summary": "İlçenin simgelerinden biri olan bu şehitlik, Kurtuluş Savaşı ve sonrasında vatan için can veren kahramanların anısını yaşatır. Sessiz ve huzurlu ortamı, saygı ve minnet duygularıyla ziyaret edilmektedir.", "place_query": "Kazımkarabekir Şehitliği, Karaman"}, {"title": "Kazımkarabekir Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumdaki bu gölet, piknik ve doğa yürüyüşü için ideal bir kaçış noktasıdır. Çevresindeki yeşil alanlar ve temiz havasıyla ailelerin ve doğaseverlerin uğrak yeridir.", "place_query": "Kazımkarabekir Göleti, Karaman"}, {"title": "Kazımkarabekir Yeraltı Şehri (Süleymanhacı Yeraltı Şehri)", "summary": "Bölgede keşfedilen bu yeraltı şehri, Bizans dönemine ait olduğu düşünülen tarihi bir yapıdır. Dar koridorları ve odalarıyla ziyaretçilere geçmişin gizemli atmosferini yaşatır.", "place_query": "Süleymanhacı Yeraltı Şehri, Kazımkarabekir, Karaman"}, {"title": "Karaman Müzesi (Kazımkarabekir''e yakın)", "summary": "İlçeye yaklaşık 30 km uzaklıktaki Karaman Müzesi, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Hitit, Roma ve Osmanlı dönemlerine ait eserler, tarih meraklıları için önemli bir duraktır.", "place_query": "Karaman Müzesi, Karaman Merkez"}, {"title": "Manazan Mağaraları (Kazımkarabekir sınırlarında)", "summary": "İlçe sınırları içinde yer alan bu doğal mağaralar, tarih öncesi dönemlerden beri yerleşim görmüş etkileyici kaya oluşumlarıdır. Mağaraların içindeki odalar ve galeriler, doğa ve macera tutkunlarını cezbeder.", "place_query": "Manazan Mağaraları, Kazımkarabekir, Karaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8a632dcc-7f53-42a8-87ff-8f80c053bec9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karaman Kalesi", "summary": "Şehir merkezinde yer alan tarihi bir kaledir. Hititlerden Osmanlı''ya kadar birçok medeniyete ev sahipliği yapmış olup, Karaman''ın simge yapılarından biridir.", "place_query": "Karaman Kalesi, Karaman Merkez, Karaman"}, {"title": "Maden Şehri Örenyeri", "summary": "Karaman''a yaklaşık 20 km uzaklıkta bulunan antik bir kenttir. Roma ve Bizans dönemine ait kalıntıları ve doğal güzellikleriyle ziyaretçileri cezbeder.", "place_query": "Maden Şehri Örenyeri, Karaman Merkez, Karaman"}, {"title": "Binbir Kilise (Madenşehri)", "summary": "Tarihi bir yerleşim alanı olan Binbir Kilise, çok sayıda kilise kalıntısı ve şapeliyle ünlüdür. Özellikle Hristiyanlık tarihi açısından önemli bir duraktır.", "place_query": "Binbir Kilise, Karaman Merkez, Karaman"}, {"title": "Karaman Müzesi", "summary": "Şehir merkezinde bulunan müze, bölgenin arkeolojik ve etnografik eserlerini sergiler. Hitit, Frig, Roma ve Bizans dönemlerine ait objeler görülebilir.", "place_query": "Karaman Müzesi, Karaman Merkez, Karaman"}, {"title": "Aktekke Camii", "summary": "Karaman''ın en önemli tarihi camilerinden biridir. 13. yüzyılda yapılmış olup, Selçuklu ve Osmanlı mimarisinin izlerini taşır.", "place_query": "Aktekke Camii, Karaman Merkez, Karaman"}, {"title": "Tarlaşık Köprüsü", "summary": "Tarihi bir taş köprüdür. Karaman çevresinde doğa yürüyüşü ve fotoğrafçılık için popüler bir noktadır.", "place_query": "Tarlaşık Köprüsü, Karaman Merkez, Karaman"}, {"title": "Gödet Barajı ve Mesire Alanı", "summary": "Şehre yakın bir konumda bulunan baraj ve çevresindeki mesire alanı, piknik ve doğa yürüyüşü için idealdir. Kuş gözlemciliği de yapılabilir.", "place_query": "Gödet Barajı, Karaman Merkez, Karaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e6594bae-96c6-40a5-8e12-b6bb0e744a92'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıveliler Mağarası", "summary": "Bölgenin en önemli doğal oluşumlarından biri olan bu mağara, sarkıt ve dikitleriyle ziyaretçileri büyüler. Doğa sporları ve mağara turizmi için idealdir.", "place_query": "Sarıveliler Mağarası, Sarıveliler, Karaman"}, {"title": "Göktepe Yaylası", "summary": "Yemyeşil doğası, temiz havası ve muhteşem manzarasıyla özellikle yaz aylarında piknik ve kamp yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Göktepe Yaylası, Sarıveliler, Karaman"}, {"title": "Sarıveliler Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla çevredeki en popüler mesire alanlarından biridir. Şelale çevresinde yürüyüş yapabilir ve doğayla iç içe vakit geçirebilirsiniz.", "place_query": "Sarıveliler Şelalesi, Sarıveliler, Karaman"}, {"title": "Yenice Köyü Kaya Mezarları", "summary": "Tarihi Lidya ve Roma dönemlerine ait bu kaya mezarları, bölgenin zengin geçmişine ışık tutar. Tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "Yenice Köyü Kaya Mezarları, Sarıveliler, Karaman"}, {"title": "Çavuşlu Göleti", "summary": "Sakin atmosferi ve çevresindeki yeşil alanlarla huzurlu bir kaçamak sunar. Balık tutma ve doğa yürüyüşü gibi aktiviteler için idealdir.", "place_query": "Çavuşlu Göleti, Sarıveliler, Karaman"}, {"title": "Sarıveliler Merkez Camii", "summary": "Yöresel mimari özellikler taşıyan tarihi cami, hem ibadet hem de kültürel ziyaretler için önemli bir duraktır. Çevresindeki eski çarşı da gezilebilir.", "place_query": "Sarıveliler Merkez Camii, Sarıveliler, Karaman"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '146af9cf-d803-4f00-90ed-c5e551d39d0e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akyaka Kars", "summary": "Kars''ın Akyaka ilçesi, sınır kapısı ve tarihi yapılarıyla dikkat çeker. Ziyaretçiler, burada Kars''a özgü mimariyi ve sakin taşra atmosferini deneyimleyebilir.", "place_query": "Akyaka, Kars"}, {"title": "Akyaka Tren İstasyonu", "summary": "Tarihi bir durak olan Akyaka Tren İstasyonu, bölgenin ulaşım ve kültür tarihine tanıklık eder. Doğu Ekspresi yolcularının uğrak noktalarından biridir.", "place_query": "Akyaka Tren İstasyonu, Kars"}, {"title": "Akyaka Sınır Kapısı", "summary": "Türkiye-Ermenistan sınırında yer alan bu kapı, bölgenin jeopolitik önemini gözler önüne serer. Çevresindeki geniş düzlükler ve sınır manzarası fotoğrafçılar için eşsiz bir fırsat sunar.", "place_query": "Akyaka Sınır Kapısı, Kars"}, {"title": "Çıldır Gölü (Akyaka kesimi)", "summary": "Akyaka''ya yakın mesafedeki Çıldır Gölü, kışın donarak buz üstünde yürüyüş ve atlı kızak keyfi sunar. Yazın ise kuş gözlemi ve doğa yürüyüşleri için idealdir.", "place_query": "Çıldır Gölü, Kars"}, {"title": "Akyaka Köyü Tarihi Evleri", "summary": "Taş ve ahşap mimarinin izlerini taşıyan bu köy evleri, bölgenin geleneksel yaşamını yansıtır. Dar sokakları ve samimi atmosferiyle ziyaretçileri geçmişe götürür.", "place_query": "Akyaka Köyü, Kars"}, {"title": "Arpaçay Vadisi", "summary": "Akyaka sınırları içinden geçen Arpaçay Vadisi, yemyeşil doğası ve sakin akışıyla huzur verir. Piknik ve doğa yürüyüşü için tercih edilen bir noktadır.", "place_query": "Arpaçay Vadisi, Akyaka, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c96b4cc5-5512-4a83-826e-ba3fc2835b54'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çıldır Gölü", "summary": "Arpaçay sınırları içinde yer alan bu büyük göl, kış aylarında donarak atlı kızak ve buz balıkçılığı gibi eşsiz deneyimler sunar. Yazın ise kuş gözlemciliği ve doğa yürüyüşleri için popülerdir.", "place_query": "Çıldır Gölü, Arpaçay, Kars"}, {"title": "Arpaçay Barajı", "summary": "Bölgenin önemli su kaynaklarından biri olan baraj, çevresindeki yeşil alanlar ve sakin atmosferiyle piknik ve doğa yürüyüşü için idealdir. Ayrıca kuş türlerini gözlemlemek için de uygun bir noktadır.", "place_query": "Arpaçay Barajı, Arpaçay, Kars"}, {"title": "Küçük Çıldır Köyü ve Tarihi Evler", "summary": "Geleneksel Kars mimarisini yansıtan taş evleriyle ünlü bu köy, sakin bir kırsal atmosferde yürüyüş yapmak ve yerel yaşamı gözlemlemek için güzel bir duraktır.", "place_query": "Küçük Çıldır Köyü, Arpaçay, Kars"}, {"title": "Arpaçay Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, sade mimarisi ve huzur veren ortamıyla dikkat çeker. Çevresindeki çarşı ile birlikte kısa bir gezi rotası oluşturur.", "place_query": "Arpaçay Merkez Camii, Arpaçay, Kars"}, {"title": "Arpaçay Ovası Yürüyüş Rotaları", "summary": "Geniş ve verimli ova, doğa yürüyüşleri ve bisiklet turları için elverişli patikalara sahiptir. Özellikle ilkbahar ve yaz aylarında yeşilin her tonunu görmek mümkündür.", "place_query": "Arpaçay Ovası, Arpaçay, Kars"}, {"title": "Bozkurt Köyü Kaya Mezarları", "summary": "Arpaçay''a bağlı Bozkurt Köyü''nde bulunan bu tarih öncesi kaya mezarları, bölgenin eski yerleşim izlerini keşfetmek isteyenler için ilginç bir arkeolojik duraktır.", "place_query": "Bozkurt Köyü Kaya Mezarları, Arpaçay, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '76861bf1-c603-43d7-8a62-f3c83cc09f2a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ani Antik Kenti", "summary": "Dünyaca ünlü bu antik kent, birçok medeniyete ev sahipliği yapmış olup ''Dünyanın İlk Şehri'' olarak anılır. Göz alıcı katedralleri, camileri ve surlarıyla ziyaretçilere eşsiz bir tarihi atmosfer sunar.", "place_query": "Ani Antik Kenti, Digor, Kars"}, {"title": "Ani Katedrali (Fethiye Camii)", "summary": "Ani Antik Kenti''nin en önemli yapılarından biri olan bu katedral, hem Ermeni mimarisinin hem de Selçuklu döneminin izlerini taşır. Şehrin silüetine hâkim konumuyla büyüleyici bir manzara sunar.", "place_query": "Ani Katedrali, Digor, Kars"}, {"title": "Ani Surları ve Aslanlı Kapı", "summary": "Antik kenti çevreleyen görkemli surlar ve ihtişamlı Aslanlı Kapı, şehrin savunma mimarisinin en güzel örneklerindendir. Kapıdaki aslan kabartmaları, ziyaretçilerin ilk karşılaştığı etkileyici detaylardandır.", "place_query": "Ani Surları, Digor, Kars"}, {"title": "Tigran Honents Kilisesi", "summary": "Ani''deki en iyi korunmuş yapılardan biri olan bu kilise, içindeki etkileyici freskleriyle ünlüdür. Dini ve tarihi önemi, onu bölgedeki en popüler ziyaret noktalarından biri yapar.", "place_query": "Tigran Honents Kilisesi, Digor, Kars"}, {"title": "Abamor (Ebul Mübarek) Kalesi", "summary": "Ani Antik Kenti yakınlarındaki bu tarihi kale, Arpaçay Nehri''nin oluşturduğu derin vadiye hâkim bir tepede yer alır. Bölgenin stratejik önemini gözler önüne seren bu yapı, muhteşem bir manzaraya sahiptir.", "place_query": "Abamor Kalesi, Digor, Kars"}, {"title": "Digor Kaya Mezarları", "summary": "İlçe merkezine yakın kayalıklara oyulmuş bu antik mezarlar, bölgenin Urartu dönemine ait olduğu düşünülen önemli arkeolojik kalıntılarındandır. Tarih öncesi döneme ışık tutan bu yapılar, keşfedilmeyi bekleyen gizemli bir duraktır.", "place_query": "Digor Kaya Mezarları, Digor, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c621de72-739f-4750-895f-8d5f35cd7af5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kağızman Kalesi", "summary": "Tarihi bir kaledir ve ilçeye hakim bir tepede yer alır. Ziyaretçilere eşsiz bir manzara sunar ve bölgenin tarihine dair önemli ipuçları verir.", "place_query": "Kağızman Kalesi, Kağızman, Kars"}, {"title": "Çengilli Köyü", "summary": "Tarihi taş evleri ve doğal güzellikleriyle ünlü bir köydür. Özellikle fotoğrafçılar ve doğa yürüyüşü sevenler için popüler bir duraktır.", "place_query": "Çengilli Köyü, Kağızman, Kars"}, {"title": "Kağızman Arkeoloji ve Etnoğrafya Müzesi", "summary": "İlçenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bir müzedir. Bölgenin geçmişine dair kapsamlı bilgi edinmek için ideal bir yerdir.", "place_query": "Kağızman Arkeoloji ve Etnoğrafya Müzesi, Kağızman, Kars"}, {"title": "Keçi Kalesi", "summary": "Doğal bir kaya oluşumu üzerine inşa edilmiş tarihi bir kaledir. Zorlu doğası ve etkileyici manzarasıyla macera arayanlar için cazip bir noktadır.", "place_query": "Keçi Kalesi, Kağızman, Kars"}, {"title": "Kağızman Çayı ve Mesire Alanı", "summary": "İlçe merkezinden geçen çay boyunca uzanan mesire alanı, piknik ve dinlenme için popüler bir yerdir. Doğal güzelliği ve huzurlu atmosferiyle bilinir.", "place_query": "Kağızman Çayı, Kağızman, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a2446bde-d18e-46d2-932c-9a62141ebc3d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ani Harabeleri", "summary": "Kars''ın en önemli tarihi mirası olan Ani Örenyeri, 11. yüzyılda Ermeni Krallığı''na başkentlik yapmış, ''Dünyanın En Eski Kenti'' olarak da bilinir. Katedral, Selçuklu ve Gürcü yapılarıyla dolu bu açık hava müzesi, UNESCO Dünya Mirası Listesi''nde yer alır.", "place_query": "Ani Harabeleri, Ocaklı, Kars Merkez, Kars"}, {"title": "Kars Kalesi", "summary": "Şehre hakim bir tepede bulunan Kars Kalesi, 12. yüzyılda Saltuklular döneminde inşa edilmiş olup, Osmanlı ve Rus dönemlerinde de kullanılmıştır. Kaleden Kars Ovası ve şehir manzarası izlenebilir.", "place_query": "Kars Kalesi, Kars Merkez, Kars"}, {"title": "Kümbet Camii (On İki Havariler Kilisesi)", "summary": "10. yüzyılda Bagratlı Krallığı tarafından yaptırılan bu yapı, 12 Havari''yi simgeleyen kubbeleriyle dikkat çeker. Osmanlı döneminde camiye çevrilen yapı, günümüzde müze olarak hizmet vermektedir.", "place_query": "Kümbet Camii, Kars Merkez, Kars"}, {"title": "Çıldır Gölü", "summary": "Kars ve Ardahan sınırında yer alan Çıldır Gölü, Türkiye''nin en büyük tatlı su göllerinden biridir. Kış aylarında donan göl yüzeyinde atlı kızak ve buz balıkçılığı yapılır; yazın ise doğa yürüyüşleri ve piknik için idealdir.", "place_query": "Çıldır Gölü, Kars Merkez, Kars"}, {"title": "Sarıkamış Kayak Merkezi", "summary": "Kars''ın Sarıkamış ilçesindeki bu kayak merkezi, kristal kar kalitesi ve uzun pistleriyle ünlüdür. Cıbıltepe mevkiinde yer alan tesis, kış sporları tutkunları için popüler bir destinasyondur.", "place_query": "Sarıkamış Kayak Merkezi, Sarıkamış, Kars"}, {"title": "Kars Müzesi", "summary": "Kars şehir merkezinde bulunan bu müze, bölgedeki arkeolojik kazılardan çıkarılan Urartu, Pers, Roma, Selçuklu ve Osmanlı dönemlerine ait eserleri sergiler. Ani Harabeleri''nden getirilen taş eserler ve etnografik objeler önemli koleksiyonlar arasındadır.", "place_query": "Kars Müzesi, Kars Merkez, Kars"}, {"title": "Mazlum Ağa Hamamı", "summary": "18. yüzyıl Osmanlı döneminden kalma bu tarihi hamam, Kars''ın en eski yapılarından biridir. Geleneksel hamam kültürünü yaşatmak isteyen ziyaretçiler için restore edilmiş ve hizmete açılmıştır.", "place_query": "Mazlum Ağa Hamamı, Kars Merkez, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'eaf6e5eb-6155-413b-a34a-b8684862e0a2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıkamış Kayak Merkezi", "summary": "Türkiye''nin önemli kış turizm merkezlerinden biri olan kayak merkezi, kristal karı ve uzun pistleriyle ünlüdür. Kış aylarında kayak ve snowboard tutkunlarını ağırlar.", "place_query": "Sarıkamış Kayak Merkezi, Sarıkamış, Kars"}, {"title": "Sarıkamış Şehitliği", "summary": "1914-1915 Sarıkamış Harekatı''nda şehit düşen askerler anısına yapılan bu anıt ve şehitlik, bölgenin en önemli tarihi ve manevi noktalarından biridir.", "place_query": "Sarıkamış Şehitliği, Sarıkamış, Kars"}, {"title": "Cıbıltepe Kayak Merkezi", "summary": "Sarıkamış Kayak Merkezi''nin bir parçası olan Cıbıltepe, doğal karlı yapısı ve nefes kesen manzaralarıyla kış sporları için ideal bir destinasyondur.", "place_query": "Cıbıltepe Kayak Merkezi, Sarıkamış, Kars"}, {"title": "Sarıkamış Kış Müzesi", "summary": "Sarıkamış Harekatı''nın tarihini ve bölgenin kış savaşlarındaki rolünü anlatan bu müze, ziyaretçilere duygusal ve tarihi bir deneyim sunar.", "place_query": "Sarıkamış Kış Müzesi, Sarıkamış, Kars"}, {"title": "Köroğlu Vadisi", "summary": "Doğal güzellikleri ve yemyeşil ormanlarıyla ünlü bu vadi, yürüyüş ve piknik yapmak isteyenler için popüler bir doğa kaçış noktasıdır.", "place_query": "Köroğlu Vadisi, Sarıkamış, Kars"}, {"title": "Sarıkamış Ormanları", "summary": "Sarıçam ağaçlarıyla kaplı bu geniş ormanlık alan, temiz havası ve huzurlu atmosferiyle doğa severlerin uğrak noktasıdır.", "place_query": "Sarıkamış Ormanları, Sarıkamış, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c66d8959-f23a-4d04-ad8d-4faaeae7284f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Selim Kalesi", "summary": "Tarihi bir yapı olan Selim Kalesi, bölgenin stratejik önemini yansıtan etkileyici bir kaledir. Ziyaretçiler, kalenin surları arasında tarihi bir yolculuğa çıkarken çevredeki bozkır manzarasını da izleyebilir.", "place_query": "Selim Kalesi, Selim, Kars"}, {"title": "Köroğlu Kayası", "summary": "Doğal bir oluşum olan Köroğlu Kayası, efsanelere konu olmuş etkileyici bir kaya kütlesidir. Bölgeye gelenler, bu doğa harikasını fotoğraflamak ve çevrede yürüyüş yapmak için sıkça uğrar.", "place_query": "Köroğlu Kayası, Selim, Kars"}, {"title": "Selim Çayı Mesire Alanı", "summary": "Selim Çayı kenarında yer alan bu mesire alanı, piknik ve doğa yürüyüşleri için ideal bir yerdir. Özellikle yaz aylarında serinlemek ve dinlenmek isteyen yerli halkın uğrak noktasıdır.", "place_query": "Selim Çayı Mesire Alanı, Selim, Kars"}, {"title": "Büyükdere Göleti", "summary": "Sakin ve huzurlu atmosferiyle Büyükdere Göleti, doğa severler için kaçış noktasıdır. Gölet çevresinde yürüyüş yapabilir, kuş gözlemi yapabilir veya sadece manzaranın tadını çıkarabilirsiniz.", "place_query": "Büyükdere Göleti, Selim, Kars"}, {"title": "Selim Merkez Camii", "summary": "Mimari yapısıyla dikkat çeken Selim Merkez Camii, ilçenin en önemli tarihi ve dini yapılarından biridir. Cami, hem ibadet hem de tarihi bir yapı olarak ziyaretçilerini ağırlamaktadır.", "place_query": "Selim Merkez Camii, Selim, Kars"}, {"title": "Çıplaklı Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü Çıplaklı Yaylası, yayla turizmi için harika bir seçenektir. Özellikle yaz aylarında düzenlenen etkinlikler ve doğal güzellikleriyle ziyaretçilerini cezbeder.", "place_query": "Çıplaklı Yaylası, Selim, Kars"}, {"title": "Kars Boztepe Selim Şehitliği", "summary": "Tarihi öneme sahip olan Kars Boztepe Selim Şehitliği, vatan savunmasında can veren askerlerimizin anısını yaşatmaktadır. Ziyaretçiler, burada saygı duruşunda bulunabilir ve tarihi atmosferi hissedebilir.", "place_query": "Kars Boztepe Selim Şehitliği, Selim, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '16825320-59ee-415e-910b-d49134c37d4e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Susuz Şelalesi", "summary": "Susuz ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu şelale, bölgenin en popüler doğal güzelliklerinden biridir. Özellikle ilkbahar ve yaz aylarında akan suyu ve çevresindeki yeşil doğasıyla piknik ve fotoğrafçılık için ideal bir noktadır.", "place_query": "Susuz Şelalesi, Susuz, Kars"}, {"title": "Susuz Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir. Orta Çağ''dan kalma bu yapı, bölgedeki hakim tepeden Kars Ovası''nı kuşbakışı görmenizi sağlar ve tarih meraklıları için önemli bir duraktır.", "place_query": "Susuz Kalesi, Susuz, Kars"}, {"title": "Çıplaklı Göleti", "summary": "Susuz ilçesine bağlı Çıplaklı köyü yakınlarında bulunan bu gölet, doğal güzelliği ve huzurlu atmosferiyle bilinir. Balık tutma ve doğa yürüyüşü gibi aktiviteler için sıkça ziyaret edilir.", "place_query": "Çıplaklı Göleti, Susuz, Kars"}, {"title": "Susuz Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Sade ve etkileyici yapısıyla hem ibadet hem de kültürel ziyaretler için önemli bir mekandır.", "place_query": "Susuz Merkez Camii, Susuz, Kars"}, {"title": "Kars Çayı Vadisi (Susuz Kesimi)", "summary": "Susuz ilçesinden geçen Kars Çayı''nın oluşturduğu vadi, doğa yürüyüşleri ve kuş gözlemi için idealdir. Bölgenin tipik bozkır ve yeşil alan karışımı manzaraları sunar.", "place_query": "Kars Çayı, Susuz, Kars"}, {"title": "Susuz Eski Taş Köprü", "summary": "İlçe çıkışında yer alan tarihi taş köprü, geçmiş dönemlerde önemli bir geçiş noktası olmuştur. Günümüzde fotoğrafçılar ve tarih severler için ilgi çekici bir duraktır.", "place_query": "Susuz Taş Köprü, Susuz, Kars"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e05eb7ce-ebf5-4b49-a6d1-b42724d038b0'::uuid;
