UPDATE location_pages SET travel_ideas_json = '[{"title": "Ağlı Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin savunma yapılarından biridir. Ziyaretçilerine eşsiz bir panoramik manzara sunar.", "place_query": "Ağlı Kalesi, Ağlı, Kastamonu"}, {"title": "Ilıca Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır. Çevresi piknik ve dinlenme için idealdir.", "place_query": "Ilıca Şelalesi, Ağlı, Kastamonu"}, {"title": "Ağlı Yaylaları (örneğin Göynük Yaylası)", "summary": "Yeşilin her tonunu barındıran yaylalar, temiz havası ve doğal yürüyüş parkurları ile doğa severler için harika bir kaçış noktasıdır.", "place_query": "Göynük Yaylası, Ağlı, Kastamonu"}, {"title": "Tarihi Ağlı Evleri", "summary": "Kastamonu''nun karakteristik mimarisini yansıtan ahşap ve taş yapılı tarihi evler, ilçenin kültürel dokusunu gözler önüne serer.", "place_query": "Tarihi Ağlı Evleri, Ağlı, Kastamonu"}, {"title": "Ağlı Merkez Camii", "summary": "Osmanlı dönemi mimarisinin izlerini taşıyan cami, sade ve huzurlu atmosferiyle ibadet ve ziyaret amaçlı uğranabilecek önemli bir yapıdır.", "place_query": "Ağlı Merkez Camii, Ağlı, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '439b2ffd-8773-435c-b825-2feab128a156'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Araç Kanyonu", "summary": "Doğal güzelliği ve yürüyüş parkurlarıyla ünlü olan bu kanyon, ziyaretçilere eşsiz bir doğa deneyimi sunar. Kanyon içerisinde yer alan şelaleler ve bitki örtüsü, fotoğrafçılar için de ideal bir ortam oluşturur.", "place_query": "Araç Kanyonu, Kastamonu"}, {"title": "Araç Tarihi Evleri", "summary": "Osmanlı döneminden kalma ahşap ve taş yapıların bulunduğu bu evler, ilçenin tarihi dokusunu yansıtır. Dar sokakları ve geleneksel mimarisiyle ziyaretçileri geçmişe götüren bir atmosfere sahiptir.", "place_query": "Araç Tarihi Evleri, Kastamonu"}, {"title": "Araç Kalesi", "summary": "Tarihi bir tepe üzerine inşa edilmiş olan bu kale, Araç''ın panoramik manzarasını izlemek için en güzel noktalardan biridir. Kalenin çevresindeki doğal yapı ve tarihi kalıntılar, keşfedilmeyi bekleyen bir hazine gibidir.", "place_query": "Araç Kalesi, Kastamonu"}, {"title": "Ilıca Şelalesi", "summary": "Araç ilçe merkezine yakın konumda bulunan bu şelale, serin suları ve çevresindeki piknik alanlarıyla özellikle yaz aylarında yoğun ilgi görür. Doğa ile baş başa vakit geçirmek isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Ilıca Şelalesi, Araç, Kastamonu"}, {"title": "Araç Müzesi", "summary": "İlçenin kültürel ve tarihi mirasını sergileyen bu müze, yöreye ait etnografik eserler, giysiler ve günlük yaşam objeleriyle zengin bir koleksiyona sahiptir. Araç''ın geçmişine dair detaylı bilgi edinmek isteyenler için ideal bir duraktır.", "place_query": "Araç Müzesi, Kastamonu"}, {"title": "Güzelcehisar Köyü ve Mağaraları", "summary": "Araç''a bağlı bu köy, doğal kaya oluşumları ve mağaralarıyla dikkat çeker. Mağaraların içindeki sarkıt ve dikitler, doğa tutkunları ve macera arayanlar için keşfedilmeyi bekleyen benzersiz bir alan sunar.", "place_query": "Güzelcehisar Köyü Mağaraları, Araç, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '540826df-23ad-4c81-8e60-ea6221c35ec0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Azdavay Ev Şelalesi", "summary": "Yemyeşil bir vadi içinde yer alan bu şelale, doğal güzelliği ve serin sularıyla ziyaretçilerine huzurlu bir kaçış sunar. Piknik alanları ve yürüyüş parkurları ile hafta sonu doğa severlerin uğrak noktasıdır.", "place_query": "Ev Şelalesi, Azdavay, Kastamonu"}, {"title": "Azdavay Kaya Mezarları", "summary": "Antik dönemden kalma bu kaya mezarları, bölgenin tarihi dokusunu gözler önüne seren önemli bir arkeolojik alandır. Kayalara oyulmuş bu yapılar, fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Azdavay Kaya Mezarları, Azdavay, Kastamonu"}, {"title": "Kastamonu Azdavay Yaylaları", "summary": "Bölgenin serin ve temiz havasını soluyabileceğiniz yaylalar, doğa yürüyüşleri ve kamp için idealdir. Özellikle yaz aylarında şehir hayatından kaçmak isteyenlerin tercih ettiği huzur dolu alanlardır.", "place_query": "Azdavay Yaylaları, Kastamonu"}, {"title": "Azdavay Merkez Camii", "summary": "Tarihi bir Osmanlı yapısı olan bu cami, mimarisi ve süslemeleriyle dikkat çeker. İlçenin merkezinde yer alan cami, hem ibadet hem de tarihi bir yapıyı görmek isteyenler için önemli bir duraktır.", "place_query": "Azdavay Merkez Camii, Kastamonu"}, {"title": "Azdavay Kanyonu", "summary": "Doğal bir oluşum olan bu kanyon, etkileyici kaya yapıları ve yürüyüş rotaları ile macera arayanlar için biçilmiş kaftandır. Bölgedeki zengin bitki örtüsü ve kuş sesleri eşliğinde unutulmaz bir deneyim sunar.", "place_query": "Azdavay Kanyonu, Kastamonu"}, {"title": "Azdavay Taş Köprü", "summary": "Tarihi bir Osmanlı köprüsü olan bu yapı, ilçenin simgelerinden biridir. Taş işçiliğinin güzel bir örneği olan köprü, fotoğraf çekmek ve tarihi atmosferi hissetmek için idealdir.", "place_query": "Azdavay Taş Köprü, Kastamonu"}, {"title": "Azdavay Kalesi", "summary": "Tarihi bir kale olan bu yapı, ilçeye hakim bir tepe üzerinde yer alır. Kaleye çıktığınızda Azdavay''ın panoramik manzarasını izley