UPDATE location_pages SET travel_ideas_json = '[{"title": "Cide Plajı", "summary": "Uzun ve geniş kumsalı ile Karadeniz''in en güzel plajlarından biridir. Özellikle yaz aylarında yerli turistlerin akınına uğrar, deniz ve güneş keyfi için idealdir.", "place_query": "Cide Plajı, Cide, Kastamonu"}, {"title": "Gideros Koyu", "summary": "Doğal güzelliği ve sakin atmosferiyle ünlü olan bu koy, çam ormanlarıyla çevrilidir. Berrak denizi ve huzurlu ortamı sayesinde kampçılar ve doğa severler için popüler bir duraktır.", "place_query": "Gideros Koyu, Cide, Kastamonu"}, {"title": "Cide Kalesi", "summary": "Tarihi bir Ceneviz kalesi olan bu yapı, ilçeye hakim bir tepe üzerinde yer alır. Kaleye çıktığınızda Cide''nin ve Karadeniz''in eşsiz manzarasını seyredebilirsiniz.", "place_query": "Cide Kalesi, Cide, Kastamonu"}, {"title": "Ilıca Şelalesi ve Mesire Alanı", "summary": "Cide''nin doğal güzelliklerinden biri olan şelale, piknik alanları ve yürüyüş parkurları ile çevrilidir. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için sıkça tercih edilir.", "place_query": "Ilıca Şelalesi, Cide, Kastamonu"}, {"title": "Kuşaklı Şelalesi", "summary": "Yemyeşil bir orman içinde gizlenmiş bu şelale, doğa yürüyüşleri için harika bir rotadır. Sessiz ve huzurlu ortamı, fotoğraf tutkunları için de benzersiz kareler sunar.", "place_query": "Kuşaklı Şelalesi, Cide, Kastamonu"}, {"title": "Cide Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını sergileyen küçük ama etkileyici bir müzedir. Arkeolojik eserler, etnografik objeler ve yöresel kıyafetler gibi birçok farklı koleksiyonu barındırır.", "place_query": "Cide Müzesi, Cide, Kastamonu"}, {"title": "Aydos Kalesi", "summary": "Cide sınırları içinde bulunan bu tarihi kale, muhteşem bir Karadeniz manzarasına sahiptir. Tarihi dokusu ve doğal güzelliği ile keşfedilmeyi bekleyen önemli bir noktadır.", "place_query": "Aydos Kalesi, Cide, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd42d8ded-864a-4715-81