UPDATE location_pages SET travel_ideas_json = '[{"title": "Daday Şelalesi", "summary": "Daday ilçe merkezine yaklaşık 5 km uzaklıkta, yemyeşil bir vadi içinde yer alan doğal bir şelaledir. Özellikle yaz aylarında serinlemek ve piknik yapmak için bölge halkının ve ziyaretçilerin uğrak noktasıdır.", "place_query": "Daday Şelalesi, Daday, Kastamonu"}, {"title": "Daday Kalesi", "summary": "İlçe merkezinde, tarihi bir tepe üzerinde yer alan ve Roma dönemine kadar uzanan geçmişe sahip bir kaledir. Günümüze kısmen sağlam ulaşan surları ve burçlarıyla tarih meraklıları için ilgi çekicidir.", "place_query": "Daday Kalesi, Daday, Kastamonu"}, {"title": "Sazlıgöl Göleti", "summary": "Daday''ın doğal güzelliklerinden biri olan Sazlıgöl, huzurlu atmosferi ve çevresindeki yürüyüş yollarıyla doğaseverler için idealdir. Gölet çevresinde kuş gözlemi yapmak ve fotoğraf çekmek mümkündür.", "place_query": "Sazlıgöl Göleti, Daday, Kastamonu"}, {"title": "Daday Müzesi", "summary": "İlçe merkezinde bulunan bu müze, Daday ve çevresine ait etnografik eserler ile arkeolojik buluntuları sergilemektedir. Yöresel kıyafetler, mutfak eşyaları ve geçmişe ışık tutan objeler ziyaretçilerin ilgisini çeker.", "place_query": "Daday Müzesi, Kastamonu"}, {"title": "Ilgaz Dağı Milli Parkı (Daday Girişi)", "summary": "Daday ilçesi sınırlarından da girişi bulunan bu milli park, zengin flora ve faunasıyla ünlüdür. Doğa yürüyüşleri, kamp ve fotoğrafçılık gibi aktiviteler için uygun bir ortam sunar.", "place_query": "Ilgaz Dağı Milli Parkı, Daday, Kastamonu"}, {"title": "Eski Daday Evleri", "summary": "İlçe merkezinde ve çevre köylerde bulunan, geleneksel Kastamonu mimarisini yansıtan ahşap ve taş yapılardır. Sokak aralarında yürüyerek bu tarihi evlerin atmosferini hissetmek mümkündür.", "place_query": "Daday Evleri, Daday, Kastamonu"}, {"title": "Ballıdağ Yaylası", "summary": "Daday''a bağlı Ballıdağ köyü sınırlarında yer alan bu yayla, yemyeşil çayırları ve temiz havasıyla bilinir. Yaz aylarında yaylacılık geleneğini görmek ve doğayla baş başa vakit geçirmek için idealdir.", "place_query": "Ballıdağ Yaylası, Daday, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6f381d20-4579-480c-831b-316c8e405dd3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Devrekani Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, ilçe merkezine hakim bir tepede yer alır. Ziyaretçilerine hem tarihi bir atmosfer hem de çevrenin panoramik manzarasını sunar.", "place_query": "Devrekani Kalesi, Devrekani, Kastamonu"}, {"title": "Ilıca Şelalesi", "summary": "Doğal güzelliği ile ünlü bu şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir durak noktasıdır. Çevresindeki yeşil alanlar piknik için idealdir.", "place_query": "Ilıca Şelalesi, Devrekani, Kastamonu"}, {"title": "Devrekani Yaylaları (Çatak Yaylası)", "summary": "Bölgenin en bilinen yaylalarından biri olan Çatak Yaylası, yemyeşil doğası, temiz havası ve geleneksel yayla kültürünü deneyimleme fırsatı sunar. Doğa yürüyüşleri ve kamp için uygundur.", "place_query": "Çatak Yaylası, Devrekani, Kastamonu"}, {"title": "Horma Kanyonu", "summary": "Devrekani sınırları içinde yer alan etkileyici bir kanyondur. Doğa yürüyüşü ve fotoğrafçılık için ideal olan kanyon, sarp kayalıkları ve derin vadisiyle dikkat çeker.", "place_query": "Horma Kanyonu, Devrekani, Kastamonu"}, {"title": "Yusufoğlu Konağı", "summary": "Tarihi bir sivil mimari örneği olan bu konak, Osmanlı dönemi yaşam tarzını yansıtan detaylarıyla ziyaretçileri geçmişe götürüyor. Restore edilmiş yapısıyla ilçenin kültürel mirasını gözler önüne seriyor.", "place_query": "Yusufoğlu Konağı, Devrekani, Kastamonu"}, {"title": "Devrekani Merkez Camii", "summary": "İlçenin en önemli tarihi yapılarından biri olan cami, mimarisi ve manevi atmosferi ile dikkat çeker. Ziyaretçiler hem ibadet edebilir hem de tarihi dokuyu yakından görebilir.", "place_query": "Devrekani Merkez Camii, Devrekani, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9bc75c48-e3ad-44d9-b1e3-69a4c0a6f8b5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Doğanyurt Sahili", "summary": "Karadeniz''in hırçın dalgalarına karşı uzanan geniş bir kumsal. Doğal güzelliği ve sakin atmosferiyle yaz aylarında serinlemek ve deniz keyfi yapmak için idealdir.", "place_query": "Doğanyurt Plajı, Doğanyurt, Kastamonu"}, {"title": "Gökçeağaç Şelalesi", "summary": "Yemyeşil bir ormanın içinde saklı kalmış bu şelale, doğa yürüyüşleri ve piknik için popüler bir noktadır. Serin suları ve huzur veren sesiyle ziyaretçilerini büyüler.", "place_query": "Gökçeağaç Şelalesi, Doğanyurt, Kastamonu"}, {"title": "Çatak Kanyonu", "summary": "Doğanyurt''a bağlı Çatak köyü yakınlarında bulunan bu kanyon, etkileyici kaya oluşumları ve doğal yapısıyla dikkat çeker. Doğa fotoğrafçıları ve macera arayanlar için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Çatak Kanyonu, Doğanyurt, Kastamonu"}, {"title": "Doğanyurt Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, ilçeye hakim bir tepe üzerinde yer alır. Kalıntıları günümüze ulaşan yapı, bölgenin stratejik önemini gözler önüne serer ve muhteşem bir manzara sunar.", "place_query": "Doğanyurt Kalesi, Doğanyurt, Kastamonu"}, {"title": "Güzelcehisar Köyü ve Plajı", "summary": "Sakin ve huzurlu bir atmosfere sahip olan bu köy plajı, berrak denizi ve doğal kumsalıyla öne çıkar. Kalabalıktan uzak, sessiz bir deniz tatili arayanların tercih ettiği bir yerdir.", "place_query": "Güzelcehisar Plajı, Doğanyurt, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3c7b25bb-0013-4463-b931-7f5e813cbd32'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hanönü Yaylaları (Sarıaşık Yaylası vb.)", "summary": "Hanönü''nün yüksek kesimlerinde yer alan yaylalar, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için idealdir. Sarıaşık Yaylası başta olmak üzere bölge, zengin flora ve muhteşem manzaralar sunar.", "place_query": "Sarıaşık Yaylası, Hanönü, Kastamonu"}, {"title": "Gökçeağaç Şelalesi", "summary": "Hanönü''ne bağlı Gökçeağaç köyü yakınlarında bulunan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popüler bir duraktır.", "place_query": "Gökçeağaç Şelalesi, Hanönü, Kastamonu"}, {"title": "Çakırçalı Göleti", "summary": "Hanönü ilçe merkezine yakın konumda bulunan bu gölet, çevresindeki mesire alanıyla hafta sonu kaçamakları için tercih edilmektedir. Balık tutma ve piknik gibi aktivitelere olanak sağlar.", "place_query": "Çakırçalı Göleti, Hanönü, Kastamonu"}, {"title": "Hanönü Kalesi", "summary": "İlçe merkezinde yer alan tarihi kale kalıntıları, bölgenin geçmişine ışık tutar. Tepeden Hanönü ve çevresini panoramik olarak izleme imkanı sunar.", "place_query": "Hanönü Kalesi, Hanönü, Kastamonu"}, {"title": "Söğütlüçeşme Mesire Alanı", "summary": "Hanönü ilçe merkezine yakın, ağaçlarla çevrili bu mesire alanı, piknik yapmak ve doğada vakit geçirmek için sıkça ziyaret edilir. Özellikle yaz aylarında serin ve huzurlu bir ortam sunar.", "place_query": "Söğütlüçeşme Mesire Alanı, Hanönü, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ef5d593e-c29a-4ea0-9069-1a7745b8bc65'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İhsangazi Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir. Bölgenin savunma yapılarından biri olarak bilinir ve çevresindeki doğal manzara ile ziyaretçilerine tarihi bir atmosfer sunar.", "place_query": "İhsangazi Kalesi, İhsangazi, Kastamonu"}, {"title": "İhsangazi Şelalesi", "summary": "İlçeye bağlı köylerden birinde bulunan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için ideal bir noktadır.", "place_query": "İhsangazi Şelalesi, İhsangazi, Kastamonu"}, {"title": "Hıdırlık Tepesi", "summary": "İlçe merkezine yakın bir konumda yer alan bu tepe, İhsangazi ve çevresinin panoramik manzarasını izlemek için en güzel seyir noktalarından biridir.", "place_query": "Hıdırlık Tepesi, İhsangazi, Kastamonu"}, {"title": "İhsangazi Merkez Camii", "summary": "İlçenin tarihi camilerinden biri olan bu yapı, Osmanlı dönemi mimarisinin izlerini taşır ve dini turizm açısından önemli bir duraktır.", "place_query": "İhsangazi Merkez Camii, İhsangazi, Kastamonu"}, {"title": "Sipahiler Köyü Kaya Mezarları", "summary": "İlçeye bağlı Sipahiler Köyü''nde bulunan bu kaya mezarları, antik döneme ait kalıntılar olup tarih meraklıları için keşfedilmeyi bekleyen bir alandır.", "place_query": "Sipahiler Köyü Kaya Mezarları, İhsangazi, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '45ba69bb-16ee-4d55-acfa-5589d968a7e4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İnebolu Evleri", "summary": "Kastamonu''nun en güzel sivil mimari örneklerinden olan bu tarihi ahşap evler, dar sokakları ve eşsiz Karadeniz manzarasıyla ziyaretçileri büyüler.", "place_query": "İnebolu Evleri, İnebolu, Kastamonu"}, {"title": "İnebolu Çarşısı", "summary": "Tarihi dokusunu koruyan çarşı, yöresel el sanatları, bakır işlemeciliği ve İnebolu''ya özgü lezzetleri deneyimlemek için ideal bir noktadır.", "place_query": "İnebolu Çarşısı, İnebolu, Kastamonu"}, {"title": "İnebolu Kalesi", "summary": "Cenevizliler döneminden kalma bu kale, şehre tepeden bakan konumuyla hem tarihi bir yapı hem de mükemmel bir seyir terasıdır.", "place_query": "İnebolu Kalesi, İnebolu, Kastamonu"}, {"title": "İnebolu Sahili ve Plajları", "summary": "Karadeniz''in serin sularına girmek ve sahil şeridinde yürüyüş yapmak isteyenler için İnebolu''nun halk plajları ve doğal koyları popüler duraklardandır.", "place_query": "İnebolu Plajı, İnebolu, Kastamonu"}, {"title": "İstiklal Yolu Müzesi", "summary": "Kurtuluş Savaşı''nda cepheye silah ve mühimmat taşınan tarihi yolun anısına kurulan müze, milli mücadele ruhunu yansıtan eşsiz bir durak noktasıdır.", "place_query": "İstiklal Yolu Müzesi, İnebolu, Kastamonu"}, {"title": "Yukarıköy Kaya Mezarları", "summary": "İnebolu''ya bağlı Yukarıköy''de bulunan Helenistik döneme ait kaya mezarları, bölgenin antik geçmişine ışık tutan etkileyici kalıntılardandır.", "place_query": "Yukarıköy Kaya Mezarları, İnebolu, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e83312b5-e89e-4f72-afc4-abfba4cddb3e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Küre Dağları Milli Parkı", "summary": "Türkiye''nin önemli oksijen depolarından biri olan bu milli park, eşsiz flora ve faunası, derin kanyonları ve şelaleleriyle doğa yürüyüşü ve kamp için ideal bir destinasyondur.", "place_query": "Küre Dağları Milli Parkı, Kastamonu"}, {"title": "Ilıca Şelalesi", "summary": "Küre Dağları''nın serin sularıyla beslenen bu şelale, çevresindeki piknik alanları ve doğal havuzlarıyla ziyaretçilere huzurlu bir doğa kaçamağı sunar.", "place_query": "Ilıca Şelalesi, Küre, Kastamonu"}, {"title": "Küre Kaymakamlığı Kanyonu (Valla Kanyonu)", "summary": "Derinliği ve ihtişamıyla ünlü Valla Kanyonu, Küre sınırları içinde yer alır ve doğa sporları meraklıları için nefes kesici manzaralar ve zorlu parkurlar barındırır.", "place_query": "Valla Kanyonu, Küre, Kastamonu"}, {"title": "Küre Eski Hamam", "summary": "Tarihi dokusuyla dikkat çeken bu Osmanlı dönemi hamamı, ilçe merkezinde yer alır ve geleneksel mimariyi yakından görmek isteyenler için önemli bir duraktır.", "place_query": "Küre Eski Hamam, Kastamonu"}, {"title": "Küre Evleri", "summary": "Kastamonu''nun geleneksel ahşap mimarisini yansıtan bu tarihi evler, dar sokaklar boyunca sıralanarak ziyaretçilere zamanda yolculuk hissi yaşatır.", "place_query": "Küre Evleri, Kastamonu"}, {"title": "Ağlı Kaya Mezarları", "summary": "Küre ilçesine bağlı Ağlı köyünde bulunan bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutan önemli arkeolojik kalıntılardır.", "place_query": "Ağlı Kaya Mezarları, Küre, Kastamonu"}, {"title": "Ersizlerdere Şelalesi", "summary": "Küre Dağları''nın derinliklerinde gizlenmiş bu şelale, yemyeşil doğası ve huzur veren sesiyle trekking rotalarının popüler bir molasıdır.", "place_query": "Ersizlerdere Şelalesi, Küre, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '59fe711e-534e-4289-9d62-31843e032c14'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kastamonu Kalesi", "summary": "Şehre hakim bir tepede yer alan tarihi kale, muhteşem manzarası ve Bizans dönemine uzanan geçmişiyle mutlaka görülmeli.", "place_query": "Kastamonu Kalesi, Kastamonu Merkez"}, {"title": "Nasrullah Meydanı ve Köprüsü", "summary": "Tarihi konakları, camisi ve 16. yüzyıldan kalma taş köprüsüyle şehrin sosyal ve kültürel kalbi sayılan bu meydan, yürüyüş ve fotoğraf için idealdir.", "place_query": "Nasrullah Meydanı, Kastamonu Merkez"}, {"title": "Kastamonu Saat Kulesi", "summary": "1885 yılında yapılan bu sekizgen saat kulesi, şehrin simgelerinden biri olup çevresindeki tarihi dokuyla birlikte ziyaret edilir.", "place_query": "Kastamonu Saat Kulesi, Kastamonu Merkez"}, {"title": "Şeyh Şaban-ı Veli Külliyesi", "summary": "Kastamonu''nun manevi merkezlerinden olan bu külliye, türbesi ve huzur veren avlusuyla hem inanç turizmi hem de tarih meraklıları için önemlidir.", "place_query": "Şeyh Şaban-ı Veli Külliyesi, Kastamonu Merkez"}, {"title": "Kastamonu Arkeoloji Müzesi", "summary": "Bölgeden çıkarılan Helenistik, Roma ve Bizans dönemi eserlerinin sergilendiği müze, tarihe ilgi duyanlar için zengin bir koleksiyon sunar.", "place_query": "Kastamonu Arkeoloji Müzesi, Kastamonu Merkez"}, {"title": "Atabey Camii ve Medresesi", "summary": "13. yüzyılda yapılan bu Selçuklu eseri, taş işçiliği ve tarihi atmosferiyle şehrin en eski yapılarından biridir.", "place_query": "Atabey Camii, Kastamonu Merkez"}, {"title": "Kastamonu Evleri", "summary": "Osmanlı döneminden kalma ahşap süslemeli ve cumbalı tarihi evler, özellikle Hepkebirler ve İsmailbey Mahallesi''nde görülmeye değerdir.", "place_query": "Kastamonu Tarihi Evleri, Kastamonu Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '82b78383-aa75-49d2-b7dc-c290e95ae9d1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ilgarini Mağarası", "summary": "Türkiye''nin en büyük mağaralarından biri olan Ilgarini, etkileyici sarkıt ve dikitleriyle doğa tutkunlarının vazgeçilmez rotasıdır. Mağara içindeki tarihi kilise kalıntıları da ziyaretçilere eşsiz bir atmosfer sunar.", "place_query": "Ilgarini Mağarası, Pınarbaşı, Kastamonu"}, {"title": "Horma Kanyonu", "summary": "Küre Dağları Milli Parkı sınırları içinde yer alan Horma Kanyonu, yemyeşil doğası ve içinden akan deresiyle doğa yürüyüşü sevenler için idealdir. Kanyon boyunca uzanan ahşap yürüyüş yolları ve seyir terasları ziyaretçilere muhteşem manzaralar sunar.", "place_query": "Horma Kanyonu, Pınarbaşı, Kastamonu"}, {"title": "Küre Dağları Milli Parkı", "summary": "Benzersiz biyoçeşitliliği ve etkileyici kanyonlarıyla ünlü bu milli park, trekking, kamp ve fotoğrafçılık için popüler bir destinasyondur. Pınarbaşı ilçesi, parkın en güzel noktalarına açılan bir kapı konumundadır.", "place_query": "Küre Dağları Milli Parkı, Pınarbaşı, Kastamonu"}, {"title": "Çatak Kanyonu", "summary": "Derin vadisi ve yemyeşil bitki örtüsüyle dikkat çeken Çatak Kanyonu, doğa yürüyüşleri için huzurlu bir rotadır. Kanyonun içinden geçen dere ve kayalıklar, ziyaretçilere serinletici bir deneyim vadediyor.", "place_query": "Çatak Kanyonu, Pınarbaşı, Kastamonu"}, {"title": "Pınarbaşı Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenlerin uğrak noktasıdır. Çevresindeki piknik alanları aileler için keyifli bir gün geçirme imkânı sunar.", "place_query": "Pınarbaşı Şelalesi, Pınarbaşı, Kastamonu"}, {"title": "Muratbaşı Köyü (Tarihi Evler)", "summary": "Geleneksel Kastamonu mimarisini yansıtan tarihi ahşap evleriyle ünlü Muratbaşı Köyü, sakin atmosferi ve doğal güzellikleriyle fotoğraf tutkunlarını cezbeder. Köydeki taş sokaklar ve çeşmeler geçmişe kısa bir yolculuk yapma fırsatı verir.", "place_query": "Muratbaşı Köyü, Pınarbaşı, Kastamonu"}, {"title": "Valla Kanyonu", "summary": "Derinliği ve ihtişamıyla Türkiye''nin en etkileyici kanyonlarından biri olan Valla, macera arayan doğa sporcuları için zorlu bir rota sunar. Kanyonun görkemli manzarası, bölgeye gelen herkesi büyüler.", "place_query": "Valla Kanyonu, Pınarbaşı, Kastamonu"}, {"title": "Samanlık Kanyonu", "summary": "Pınarbaşı''nın saklı kalmış güzelliklerinden biri olan Samanlık Kanyonu, yemyeşil doğası ve sakin ortamıyla huzur arayanlar için idealdir. Kanyon içindeki yürüyüş parkuru, ziyaretçilere eşsiz bir doğa deneyimi yaşatır.", "place_query": "Samanlık Kanyonu, Pınarbaşı, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f2097d91-b5a2-4f9e-bc06-f172134097a8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şenpazar Kanyonu", "summary": "Bölgenin en önemli doğal güzelliklerinden biri olan kanyon, yemyeşil doğası ve yürüyüş parkurlarıyla ziyaretçilerine huzurlu bir deneyim sunar.", "place_query": "Şenpazar Kanyonu, Kastamonu"}, {"title": "Çatak Kanyonu", "summary": "Etkileyici kaya oluşumları ve berrak suyuyla ünlü bu kanyon, doğa yürüyüşü ve fotoğrafçılık için ideal bir noktadır.", "place_query": "Çatak Kanyonu, Şenpazar, Kastamonu"}, {"title": "Şenpazar Tarihi Evleri", "summary": "Geleneksel Kastamonu mimarisini yansıtan ahşap ve taş yapılar, ilçenin tarihi dokusunu keşfetmek isteyenler için görülmeye değerdir.", "place_query": "Şenpazar Tarihi Evleri, Kastamonu"}, {"title": "Güzelcehisar Köyü ve Şelalesi", "summary": "Doğal güzelliğiyle öne çıkan köy, şelalesi ve çevresindeki piknik alanlarıyla hafta sonu kaçamakları için popüler bir duraktır.", "place_query": "Güzelcehisar Şelalesi, Şenpazar, Kastamonu"}, {"title": "Küre Dağları Milli Parkı (Şenpazar Girişi)", "summary": "Zengin flora ve faunasıyla ünlü milli parkın Şenpazar sınırları içindeki bölümü, trekking ve kamp severler için eşsiz rotalar barındırır.", "place_query": "Küre Dağları Milli Parkı, Şenpazar, Kastamonu"}, {"title": "Şenpazar Merkez Camii", "summary": "Tarihi bir geçmişe sahip olan cami, ilçenin merkezinde yer alır ve mimari detaylarıyla dikkat çeker.", "place_query": "Şenpazar Merkez Camii, Kastamonu"}, {"title": "Yenice Şelalesi", "summary": "Sessiz ve sakin bir doğa alanında yer alan şelale, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler tarafından tercih edilir.", "place_query": "Yenice Şelalesi, Şenpazar, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dc2f99bc-525a-4c3e-8394-45f46d89a43c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Seydiler İlçe Merkezi ve Tarihi Evler", "summary": "Seydiler''in karakteristik ahşap ve taş mimarili tarihi evleri, ilçenin otantik atmosferini yansıtır. Dar sokaklarında yürüyerek yöresel yaşama tanıklık edebilirsiniz.", "place_query": "Seydiler Merkez, Kastamonu"}, {"title": "Kastamonu Kalesi", "summary": "Şehre hakim bir tepede yer alan ve tarihi 12. yüzyıla uzanan bu kale, Kastamonu''nun simge yapılarındandır. Kaleyi çevreleyen surlar ve manzarası ziyaretçileri etkiler.", "place_query": "Kastamonu Kalesi, Kastamonu Merkez"}, {"title": "Ilıca Şelalesi ve Mesire Alanı", "summary": "Seydiler''e yaklaşık 15 km uzaklıktaki bu doğal alan, şelalesi ve piknik imkanlarıyla hafta sonu kaçamakları için idealdir. Serin sularında yüzebilir, yeşillikler arasında dinlenebilirsiniz.", "place_query": "Ilıca Şelalesi, Kastamonu"}, {"title": "Kastamonu Saat Kulesi", "summary": "1885 yılında yapılan ve şehrin en önemli sembollerinden biri olan bu tarihi saat kulesi, kare planlı ve ahşap çatılı yapısıyla dikkat çeker. Çevresindeki tarihi çarşıyla birlikte gezilebilir.", "place_query": "Kastamonu Saat Kulesi, Kastamonu Merkez"}, {"title": "Valla Kanyonu (Pınarbaşı)", "summary": "Seydiler''in güneyindeki Pınarbaşı ilçesinde yer alan bu etkileyici kanyon, dik duvarları ve doğal güzelliğiyle ünlüdür. Doğa yürüyüşleri ve fotoğrafçılık için popüler bir noktadır.", "place_query": "Valla Kanyonu, Pınarbaşı, Kastamonu"}, {"title": "Kastamonu Arkeoloji Müzesi", "summary": "Kastamonu ve çevresindeki kazılardan çıkarılan eserlerin sergilendiği müze, bölgenin antik dönemlerine ışık tutar. Heykeller, lahitler ve günlük yaşam objeleri görülebilir.", "place_query": "Kastamonu Arkeoloji Müzesi, Kastamonu Merkez"}, {"title": "Nasrullah Köprüsü", "summary": "Kastamonu şehir merkezinde Gökırmak üzerinde bulunan bu tarihi taş köprü, 16. yüzyılda inşa edilmiştir. Köprünün kemerli yapısı ve çevresindeki tarihi doku fotoğrafçılar için caziptir.", "place_query": "Nasrullah Köprüsü, Kastamonu Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0d350728-1db6-4c48-b593-3a383c717f7a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pompeiopolis Antik Kenti", "summary": "Taşköprü''nün en önemli tarihi mirası olan bu antik kent, Roma dönemine ait mozaikler, hamam kalıntıları ve sütunlu yollarla ziyaretçilerini büyüler. Bölgenin Paflagonya''daki en parlak şehirlerinden biri olarak bilinir.", "place_query": "Pompeiopolis Antik Kenti, Taşköprü, Kastamonu"}, {"title": "Taşköprü Barajı ve Mesire Alanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için ideal bir piknik ve doğa yürüyüşü noktasıdır. Baraj gölü manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Taşköprü Barajı, Taşköprü, Kastamonu"}, {"title": "Ilıca Şelalesi", "summary": "Taşköprü''ye bağlı Ilıca köyünde yer alan bu şelale, serin suları ve çevresindeki yemyeşil doğasıyla özellikle yaz aylarında serinlemek için popüler bir duraktır.", "place_query": "Ilıca Şelalesi, Taşköprü, Kastamonu"}, {"title": "Taşköprü Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale, ilçeye hakim bir manzara sunar. Kalenin surları ve burçları arasında dolaşırken geçmişin izlerini hissedebilirsiniz.", "place_query": "Taşköprü Kalesi, Taşköprü, Kastamonu"}, {"title": "Harman Çayı ve Kanyonu", "summary": "Doğa sporları ve trekking için ideal olan bu kanyon, berrak akan Harman Çayı ve sarp kayalıklarıyla macera arayanları cezbeder. Bölge, eşsiz kaya oluşumlarına ev sahipliği yapar.", "place_query": "Harman Çayı Kanyonu, Taşköprü, Kastamonu"}, {"title": "Taşköprü Sarımsak Müzesi", "summary": "Taşköprü''nün dünyaca ünlü sarımsağının tanıtıldığı bu müze, hem geleneksel üretim yöntemlerini hem de yöresel kültürü sergiler. Ziyaretçiler, sarımsağın hikayesini burada keşfedebilir.", "place_query": "Taşköprü Sarımsak Müzesi, Taşköprü, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aef36c1c-0ddb-415e-9df6-b035d0f1cad9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tosya Kalesi", "summary": "Tosya''nın sembolü olan tarihi kale, şehre hakim bir tepe üzerinde yer alır ve muhteşem bir manzara sunar. Roma döneminden kalma kalıntılarıyla tarih meraklıları için görülmeye değer bir noktadır.", "place_query": "Tosya Kalesi, Tosya, Kastamonu"}, {"title": "Tosya Evleri (Tarihi Tosya Evleri)", "summary": "Kastamonu''ya özgü ahşap ve kerpiç mimarinin güzel örneklerini sergileyen tarihi evler, dar sokaklarında yürüyüş yaparak geçmişe yolculuk yapma imkanı sunar.", "place_query": "Tarihi Tosya Evleri, Tosya, Kastamonu"}, {"title": "Ilgaz Dağı Milli Parkı (Tosya Girişi)", "summary": "Tosya sınırları içinde kalan bölümleriyle ünlü milli park, doğa yürüyüşleri, kamp ve piknik için idealdir. Zengin bitki örtüsü ve temiz havasıyla doğaseverlerin uğrak noktasıdır.", "place_query": "Ilgaz Dağı Milli Parkı Tosya girişi, Kastamonu"}, {"title": "Tosya Müzesi", "summary": "Şehir merkezinde bulunan müze, bölgenin arkeolojik ve etnografik eserlerini sergileyerek Tosya''nın zengin tarihini gözler önüne serer. Özellikle yöresel kıyafet ve eşyalar dikkat çekicidir.", "place_query": "Tosya Müzesi, Tosya, Kastamonu"}, {"title": "Piruze (Pirüze) Mağarası", "summary": "Tosya yakınlarında bulunan bu doğal mağara, etkileyici sarkıt ve dikitleriyle ziyaretçilerini büyüler. Doğa turizmi için keşfedilmeyi bekleyen gizli bir cennettir.", "place_query": "Piruze Mağarası, Tosya, Kastamonu"}, {"title": "Kızılcık Şelalesi", "summary": "Tosya ilçe merkezine yakın konumdaki bu şelale, çevresindeki yeşil doğayla birlikte huzurlu bir kaçış noktasıdır. Özellikle bahar ve yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Kızılcık Şelalesi, Tosya, Kastamonu"}, {"title": "Tosya Ulu Camii", "summary": "Selçuklu dönemi mimarisinin güzel bir örneği olan cami, kesme taş işçiliği ve sade iç tasarımıyla dikkat çeker. Tarihi atmosferiyle ibadet ve ziyaret için önemli bir duraktır.", "place_query": "Tosya Ulu Camii, Tosya, Kastamonu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4388dba7-3a23-4e55-881b-a070fdcb946a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akkışla Kalesi", "summary": "Tarihi bir kale olup bölgenin en önemli kültürel miraslarındandır. Ziyaretçilerine tarihi bir atmosfer ve çevreye hakim manzaralar sunar.", "place_query": "Akkışla Kalesi, Akkışla, Kayseri"}, {"title": "Gömürgen Yaylası", "summary": "Doğal güzelliği ve serin havasıyla bilinen bir yayladır. Doğa yürüyüşleri ve piknik için ideal bir mekandır.", "place_query": "Gömürgen Yaylası, Akkışla, Kayseri"}, {"title": "Kululu Ören Yeri", "summary": "Hitit dönemine ait kalıntıların bulunduğu arkeolojik bir alandır. Tarih meraklıları için önemli bir ziyaret noktasıdır.", "place_query": "Kululu Ören Yeri, Akkışla, Kayseri"}, {"title": "Akkışla Şelalesi", "summary": "Doğa ile iç içe, serinletici bir suya sahip şelaledir. Özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır.", "place_query": "Akkışla Şelalesi, Akkışla, Kayseri"}, {"title": "Karakaya Barajı", "summary": "Bölgenin su kaynaklarından biri olan baraj, çevresindeki yeşil alanlarla piknik ve doğa aktiviteleri için uygundur.", "place_query": "Karakaya Barajı, Akkışla, Kayseri"}, {"title": "Akkışla Merkez Cami", "summary": "İlçenin tarihi camilerinden biri olup mimarisi ve huzur veren atmosferiyle dikkat çeker.", "place_query": "Akkışla Merkez Cami, Akkışla, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4fff4fbc-799f-4852-b6e7-8ad9a26b02bd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bünyan Halı ve Kilim Müzesi", "summary": "Bünyan''ın ünlü el dokuması halı ve kilimlerinin sergilendiği bu müze, ilçenin kültürel mirasını yakından tanımak için ideal bir durak. Ziyaretçiler, yüzyıllık geleneklerle dokunan renkli ve desenli halıları görme fırsatı buluyor.", "place_query": "Bünyan Halı ve Kilim Müzesi, Bünyan, Kayseri"}, {"title": "Koramaz Vadisi", "summary": "Bünyan sınırları içinde de uzanan bu eşsiz vadi, kaya oyma kiliseleri, mağaraları ve doğal yürüyüş parkurlarıyla ünlüdür. Tarih ve doğayı bir arada deneyimlemek isteyenler için harika bir açık hava müzesidir.", "place_query": "Koramaz Vadisi, Bünyan, Kayseri"}, {"title": "Bünyan Kalesi", "summary": "İlçe merkezinde yer alan bu tarihi kale, Selçuklu döneminden kalma olup bölgenin savunma yapılarına ışık tutar. Kalenin tepesinden Bünyan manzarasını izlemek mümkündür.", "place_query": "Bünyan Kalesi, Bünyan, Kayseri"}, {"title": "Samağır Barajı ve Mesire Alanı", "summary": "Bünyan''a yaklaşık 10 km uzaklıktaki bu baraj, piknik alanları ve yeşil çevresiyle hafta sonu kaçamakları için popüler bir noktadır. Gölet kenarında yürüyüş yapabilir ve huzurlu bir gün geçirebilirsiniz.", "place_query": "Samağır Barajı, Bünyan, Kayseri"}, {"title": "Bünyan Ulu Camii", "summary": "Selçuklu mimarisinin izlerini taşıyan bu tarihi cami, taş işçiliği ve sade iç mekanıyla dikkat çeker. İlçenin en eski ibadet yapılarından biri olarak ziyaretçilerini ağırlamaktadır.", "place_query": "Bünyan Ulu Camii, Bünyan, Kayseri"}, {"title": "Karakaya Mağarası", "summary": "Bünyan ilçesine bağlı Karakaya köyünde bulunan bu doğal mağara, sarkıt ve dikitleriyle ilgi çeker. Mağara içindeki serin hava ve ilginç kaya oluşumları doğa severler için keşfedilmeyi bekliyor.", "place_query": "Karakaya Mağarası, Bünyan, Kayseri"}, {"title": "Elbaşı Şelalesi", "summary": "Bünyan''ın Elbaşı köyü yakınlarındaki bu şelale, özellikle bahar aylarında coşkun akan sularıyla görsel bir şölen sunar. Çevresindeki doğal havuzlar ve yeşil alanlar, serinlemek ve doğayla baş başa kalmak için idealdir.", "place_query": "Elbaşı Şelalesi, Bünyan, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aff1830e-aef4-4be3-9d62-15e639868ac0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sultan Sazlığı Milli Parkı", "summary": "Büyük ve Küçük Göl''den oluşan bu sulak alan, yüzlerce kuş türüne ev sahipliği yapar. Doğa fotoğrafçıları ve kuş gözlemcileri için eşsiz bir rotadır.", "place_query": "Sultan Sazlığı Milli Parkı, Develi, Kayseri"}, {"title": "Erciyes Dağı", "summary": "Kayseri''nin simgesi olan bu heybetli dağ, kış sporları ve doğa yürüyüşleri için popülerdir. Develi ilçesinden de görülebilen muhteşem manzaralar sunar.", "place_query": "Erciyes Dağı, Kayseri"}, {"title": "Zamantı Irmağı", "summary": "Develi''den geçen bu akarsu, rafting ve doğa sporları için idealdir. Çevresindeki yemyeşil alanlar piknik ve kamp için de tercih edilir.", "place_query": "Zamantı Irmağı, Develi, Kayseri"}, {"title": "Develi Kapalı Çarşısı", "summary": "Tarihi dokusuyla dikkat çeken bu çarşı, yöresel el sanatları ve hediyelik eşyalar için uğrak noktasıdır. Alışveriş yaparken ilçenin kültürünü yakından tanıyabilirsiniz.", "place_query": "Develi Kapalı Çarşısı, Develi, Kayseri"}, {"title": "Koç Dağı", "summary": "Doğa yürüyüşleri ve kampçılık için tercih edilen bu dağ, yemyeşil yaylaları ve temiz havasıyla ünlüdür. Zirveden Develi Ovası''nı seyretmek mümkündür.", "place_query": "Koç Dağı, Develi, Kayseri"}, {"title": "Develi Ulu Camii", "summary": "Selçuklu dönemine ait bu tarihi cami, taş işçiliği ve mimari detaylarıyla dikkat çeker. İlçenin en önemli dini yapılarından biridir.", "place_query": "Develi Ulu Camii, Develi, Kayseri"}, {"title": "Yayla Göleti (Develi)", "summary": "Şehir merkezine yakın bu gölet, huzurlu bir doğa kaçamağı arayanlar için idealdir. Çevresinde yürüyüş parkurları ve piknik alanları bulunur.", "place_query": "Yayla Göleti, Develi, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '52caaad4-7bdb-405e-adf4-7eeab9ee7801'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Felahiye Kalesi", "summary": "İlçe merkezinde bulunan tarihi bir kaledir. Selçuklu dönemine ait olduğu düşünülen yapı, bölgenin tarihine tanıklık etmek isteyenler için önemli bir duraktır.", "place_query": "Felahiye Kalesi, Felahiye, Kayseri"}, {"title": "Yenimahalle Göleti", "summary": "Doğal güzelliği ve huzurlu atmosferiyle piknik ve dinlenmek için ideal bir yerdir. Gölet çevresinde yürüyüş yapabilir ve kuş sesleri eşliğinde vakit geçirebilirsiniz.", "place_query": "Yenimahalle Göleti, Felahiye, Kayseri"}, {"title": "Korualan Şelalesi", "summary": "İlçeye bağlı Korualan köyünde yer alan bu şelale, doğa severler için keşfedilmeyi bekleyen bir cennettir. Serin suları ve yeşil doğasıyla fotoğrafçıların da ilgisini çeker.", "place_query": "Korualan Şelalesi, Felahiye, Kayseri"}, {"title": "Felahiye Taş Köprü", "summary": "Tarihi bir Osmanlı dönemi köprüsü olan bu yapı, ilçenin simgelerindendir. Taş işçiliği ve mimarisiyle dikkat çeker, çevresindeki dere ile güzel bir manzara sunar.", "place_query": "Felahiye Taş Köprü, Felahiye, Kayseri"}, {"title": "Süleymanlı Yaylası", "summary": "Yaz aylarında serinlemek ve doğayla iç içe olmak isteyenler için popüler bir yayladır. Yemyeşil çayırları ve temiz havasıyla kamp ve doğa yürüyüşü için uygundur.", "place_query": "Süleymanlı Yaylası, Felahiye, Kayseri"}, {"title": "Felahiye Merkez Camii", "summary": "İlçenin en büyük ve tarihi camilerinden biridir. Osmanlı ve Selçuklu mimari izlerini taşıyan cami, özellikle ibadet ve tarihi doku görmek isteyenler tarafından ziyaret edilir.", "place_query": "Felahiye Merkez Camii, Felahiye, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0def3caa-fafc-418a-a44f-8c4718aadfe7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hacılar Şelalesi", "summary": "İlçe merkezine yakın, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle yaz aylarında ziyaretçilerin uğrak yeridir.", "place_query": "Hacılar Şelalesi, Hacılar, Kayseri"}, {"title": "Erciyes Dağı", "summary": "Kayseri''nin simgesi olan bu görkemli dağ, kış sporları ve doğa turizmi için Türkiye''nin önde gelen merkezlerindendir. Hacılar ilçesi, Erciyes''in eteklerinde yer alır ve muhteşem manzaralar sunar.", "place_query": "Erciyes Dağı, Kayseri"}, {"title": "Hacılar Kent Müzesi", "summary": "İlçenin tarihini, kültürünü ve geleneksel yaşamını yansıtan eserlerin sergilendiği küçük ama etkileyici bir müzedir. Ziyaretçilere yöresel mirası yakından tanıma fırsatı sunar.", "place_query": "Hacılar Kent Müzesi, Hacılar, Kayseri"}, {"title": "Yamaç Paraşütü Atış Alanı (Hacılar)", "summary": "Erciyes''in eteklerinde yer alan bu alan, yamaç paraşütü yapmak isteyenler için popüler bir kalkış noktasıdır. Nefes kesen bir manzara eşliğinde adrenalin dolu bir deneyim sunar.", "place_query": "Yamaç Paraşütü Atış Alanı, Hacılar, Kayseri"}, {"title": "Hacılar Yaylası", "summary": "Şehir hayatından uzaklaşmak isteyenler için huzurlu bir kaçış noktasıdır. Yemyeşil doğası, temiz havası ve yayla kültürünü deneyimlemek için idealdir.", "place_query": "Hacılar Yaylası, Hacılar, Kayseri"}, {"title": "Soğanlı Vadisi", "summary": "Hacılar ilçe sınırları içinde olmasa da yakın çevredeki en etkileyici doğal ve tarihi alanlardan biridir. Peri bacaları ve kaya oyma kiliseleriyle ünlüdür.", "place_query": "Soğanlı Vadisi, Yeşilhisar, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '891e6015-ff87-443c-a4e1-14333c62c002'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İncesu Mağarası", "summary": "İlçe merkezine yakın konumdaki bu doğal mağara, etkileyici sarkıt ve dikitleriyle ziyaretçilerini büyüler. Doğa yürüyüşü ve mağara keşfi için ideal bir noktadır.", "place_query": "İncesu Mağarası, İncesu, Kayseri"}, {"title": "İncesu Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, ilçenin sembol yapılarından biridir. Kaleye çıktığınızda İncesu ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "İncesu Kalesi, İncesu, Kayseri"}, {"title": "İncesu Ulu Camii", "summary": "Osmanlı döneminden kalma bu tarihi cami, taş işçiliği ve mimari detaylarıyla dikkat çeker. İlçenin en önemli dini yapılarından biridir.", "place_query": "İncesu Ulu Camii, İncesu, Kayseri"}, {"title": "İncesu Kaya Mezarları", "summary": "Bölgedeki antik yerleşim izlerini taşıyan bu kaya mezarları, tarih meraklıları için ilgi çekici bir duraktır. Kayalara oyulmuş bu yapılar, geçmişe yolculuk yapma fırsatı sunar.", "place_query": "İncesu Kaya Mezarları, İncesu, Kayseri"}, {"title": "İncesu Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın bu gölet, piknik ve dinlenme için popüler bir mekandır. Çevresindeki yeşil alanlar ve yürüyüş yollarıyla doğayla iç içe vakit geçirebilirsiniz.", "place_query": "İncesu Göleti, İncesu, Kayseri"}, {"title": "İncesu Geleneksel Evleri", "summary": "İlçede dağınık halde bulunan tarihi taş ve ahşap evler, yöresel mimariyi yansıtır. Dar sokaklarda yapacağınız bir yürüyüşle bu evlerin nostaljik atmosferini hissedebilirsiniz.", "place_query": "İncesu Geleneksel Evleri, İncesu, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '30e17390-17e5-4cdd-a97a-4eb8911bad6e'::uuid;
