place_query": "Kocasinan Çarşıları, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0cb2f2b8-c172-411a-ae08-e44b481b1e84'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kayseri Kalesi", "summary": "Şehrin merkezinde yer alan tarihi kale, Roma, Bizans, Selçuklu ve Osmanlı dönemlerine tanıklık etmiş olup, günümüzde restore edilerek kültür sanat etkinliklerine ev sahipliği yapmaktadır.", "place_query": "Kayseri Kalesi, Melikgazi, Kayseri"}, {"title": "Büyük Saat Kulesi", "summary": "1906 yılında yapılan ve Kayseri''nin simgesi haline gelen bu saat kulesi, şehrin en işlek noktalarından birinde yer alır ve çevresindeki tarihi yapılarla birlikte görülmeye değerdir.", "place_query": "Büyük Saat Kulesi, Melikgazi, Kayseri"}, {"title": "Talas Amerikan Koleji", "summary": "1871 yılında kurulan ve günümüzde müze olarak hizmet veren bu tarihi kampüs, etkileyici mimarisi ve bahçesiyle ziyaretçilere geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Talas Amerikan Koleji, Melikgazi, Kayseri"}, {"title": "Kayseri Arkeoloji Müzesi", "summary": "Kültepe Kaniş-Karum başta olmak üzere bölgedeki kazılardan çıkarılan eserlerin sergilendiği müze, Hitit ve Asur dönemlerine ait tabletler ve heykellerle tarih meraklılarını cezbeder.", "place_query": "Kayseri Arkeoloji Müzesi, Melikgazi, Kayseri"}, {"title": "Erciyes Dağı", "summary": "Kış sporları ve doğa turizmi için Türkiye''nin en önemli merkezlerinden biri olan Erciyes Dağı, kayak pistleri, teleferik ve eşsiz manzarasıyla yıl boyunca ziyaretçi ağırlar.", "place_query": "Erciyes Dağı, Melikgazi, Kayseri"}, {"title": "Gevher Nesibe Şifaiyesi (Tıp Tarihi Müzesi)", "summary": "1206 yılında Selçuklu döneminde yapılan bu tarihi hastane ve tıp medresesi, günümüzde Tıp Tarihi Müzesi olarak kullanılmakta ve dönemin sağlık anlayışını gözler önüne sermektedir.", "place_query": "Gevher Nesibe Şifaiyesi, Melikgazi, Kayseri"}, {"title": "Döner Kümbet", "summary": "Selçuklu dönemine ait bu anıt mezar, döner gibi görünen dış cephesiyle dikkat çeker ve Kayseri''nin en özel yapılarından biridir.", "place_query": "Döner Kümbet, Melikgazi, Kayseri"}]'::jsonb,