UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızılırmak Nehri Kenarı", "summary": "Özvatan''dan geçen Kızılırmak''ın kıyıları, doğal güzelliği ve huzurlu atmosferiyle piknik ve yürüyüş için idealdir. Nehir boyunca uzanan yeşil alanlar, bölge sakinlerinin ve ziyaretçilerin en çok tercih ettiği dinlenme noktalarından biridir.", "place_query": "Kızılırmak Nehri, Özvatan, Kayseri"}, {"title": "Özvatan Kalesi", "summary": "Tarihi bir kalıntı olan Özvatan Kalesi, ilçenin geçmişine ışık tutar ve çevresine hakim bir tepede yer alır. Kaleyi ziyaret edenler, hem tarihi dokuyu hissedebilir hem de bölgenin panoramik manzarasını izleyebilir.", "place_query": "Özvatan Kalesi, Özvatan, Kayseri"}, {"title": "Küçük Özvatan Göleti", "summary": "Doğa ile iç içe bir ortam sunan Küçük Özvatan Göleti, balık tutma ve piknik gibi aktiviteler için popüler bir mekandır. Çevresindeki ağaçlık alan, özellikle yaz aylarında serinlemek ve huzur bulmak isteyenler için idealdir.", "place_query": "Küçük Özvatan Göleti, Özvatan, Kayseri"}, {"title": "Hırka Dağı Yaylası", "summary": "Özvatan sınırları içinde yer alan Hırka Dağı Yaylası, yemyeşil doğası ve temiz havasıyla ünlüdür. Özellikle yaz aylarında yaylacılar ve doğa yürüyüşçüleri tarafından sıkça ziyaret edilir.", "place_query": "Hırka Dağı Yaylası, Özvatan, Kayseri"}, {"title": "Özvatan Eski Camii", "summary": "İlçedeki tarihi yapılardan biri olan Özvatan Eski Camii, mimarisi ve manevi atmosferiyle dikkat çeker. Ziyaretçiler, caminin huzur veren ortamında vakit geçirebilir ve bölgenin kültürel mirasını yakından görebilir.", "place_query": "Özvatan Eski Camii, Özvatan, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6b4bc1e6-ba10-4200-bbe4-f2e22b36e415'::uuid;
