UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıoğlan Kapuzbaşı Şelaleleri", "summary": "Kayseri''nin en etkileyici doğal güzelliklerinden biri olan Kapuzbaşı Şelaleleri, Sarıoğlan ilçesi sınırları içinde yer alır. 7 ayrı koldan dökülen şelaleler, yemyeşil doğası ve serin sularıyla ziyaretçilerine görsel bir şölen sunar.", "place_query": "Kapuzbaşı Şelaleleri, Sarıoğlan, Kayseri"}, {"title": "Yahyalı Kapuzbaşı Şelalesi", "summary": "Sarıoğlan''a yaklaşık 30 km mesafedeki bu şelale, Türkiye''nin en yüksek debili şelalelerinden biridir. Çevresindeki piknik alanları ve yürüyüş parkurları ile doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Yahyalı Kapuzbaşı Şelalesi, Yahyalı, Kayseri"}, {"title": "Sarıoğlan Kalesi", "summary": "Tarihi bir yapı olan Sarıoğlan Kalesi, ilçe merkezine yakın bir konumda yer alır. Bölgenin geçmişine ışık tutan kale, özellikle fotoğraf tutkunları için güzel bir manzara sunar.", "place_query": "Sarıoğlan Kalesi, Sarıoğlan, Kayseri"}, {"title": "Sarıoğlan Yeraltı Şehri", "summary": "Sarıoğlan''da keşfedilen yeraltı şehri, bölgenin tarihi zenginliğini gözler önüne serer. Dar koridorları ve odalarıyla ziyaretçilere eşsiz bir keşif deneyimi yaşatır.", "place_query": "Sarıoğlan Yeraltı Şehri, Sarıoğlan, Kayseri"}, {"title": "Sarıoğlan Göleti", "summary": "Doğal güzellikleriyle bilinen Sarıoğlan Göleti, piknik ve olta balıkçılığı için popüler bir mekandır. Çevresindeki yeşil alanlar ve temiz havasıyla huzurlu bir gün geçirmek isteyenler için idealdir.", "place_query": "Sarıoğlan Göleti, Sarıoğlan, Kayseri"}, {"title": "Sarıoğlan Termal Kaynakları", "summary": "Sarıoğlan ilçesinde bulunan termal kaynaklar, şifalı sularıyla dikkat çeker. Özellikle romatizma ve cilt rahatsızlıklarına iyi geldiği bilinen bu kaynaklar, sağlık turizmi açısından önemli bir potansiyele sahiptir.", "place_query": "Sarıoğlan Termal Kaynakları, Sarıoğlan, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2974008b-377b-44de-9e94-a0dad20c6e5d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarız Gölü", "summary": "Doğal güzelliği ve huzur veren atmosferiyle ünlü olan bu göl, piknik ve doğa yürüyüşleri için ideal bir noktadır. Çevresindeki yeşil alanlar ve temiz havası ziyaretçileri kendine çeker.", "place_query": "Sarız Gölü, Sarız, Kayseri"}, {"title": "Sarız Kalesi", "summary": "Tarihi bir yapı olan bu kale, bölgenin geçmişine ışık tutar ve etkileyici manzarasıyla fotoğrafçılar için harika bir fırsat sunar. Kalıntıları arasında dolaşırken tarihi hissedebilirsiniz.", "place_query": "Sarız Kalesi, Sarız, Kayseri"}, {"title": "Binboğa Dağları", "summary": "Doğa sporları ve trekking tutkunları için eşsiz bir rota olan bu dağlar, zengin bitki örtüsü ve vahşi yaşamıyla keşfedilmeyi bekler. Zirvelerinden Sarız''ın panoramik manzarası izlenebilir.", "place_query": "Binboğa Dağları, Sarız, Kayseri"}, {"title": "Sarız Yaylası", "summary": "Serin havası ve yemyeşil çayırlarıyla yaz aylarında kaçış noktası olan bu yayla, geleneksel yayla kültürünü deneyimlemek isteyenler için idealdir. Doğa yürüyüşleri ve kamp için uygundur.", "place_query": "Sarız Yaylası, Sarız, Kayseri"}, {"title": "Kızılkaya Mağarası", "summary": "Doğal oluşumu ve ilginç kaya yapılarıyla dikkat çeken bu mağara, macera arayan ziyaretçiler için gizemli bir keşif alanıdır. Mağara içindeki sarkıt ve dikitler görülmeye değerdir.", "place_query": "Kızılkaya Mağarası, Sarız, Kayseri"}, {"title": "Sarız Çayı Kenarı", "summary": "Şehir hayatından uzaklaşmak isteyenler için huzurlu bir dinlenme alanı sunan bu bölge, piknik yapmak ve doğa sesleri eşliğinde vakit geçirmek için popülerdir. Çayın serin suları yaz aylarında ferahlatıcıdır.", "place_query": "Sarız Çayı, Sarız, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '137ee99e-854b-403b-a486-ee1ac898f91a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ali Dağı", "summary": "Talas''ın simgesi haline gelmiş bu dağ, doğa yürüyüşleri ve şehir manzarası eşliğinde piknik yapmak için ideal bir noktadır. Zirveye çıktığınızda Kayseri Ovası''nın nefes kesen panoramik görüntüsü sizi bekler.", "place_query": "Ali Dağı, Talas, Kayseri"}, {"title": "Talas Amerikan Koleji Binaları", "summary": "19. yüzyılda misyonerler tarafından inşa edilen bu tarihi yapılar, günümüzde restore edilerek kültür merkezine dönüştürülmüştür. Taş işçiliği ve mimarisiyle geçmişe yolculuk yapmak isteyenler için eşsiz bir duraktır.", "place_query": "Talas Amerikan Koleji, Talas, Kayseri"}, {"title": "Talas Tarihi Evleri", "summary": "Dar sokakları süsleyen geleneksel Kayseri mimarisindeki bu taş evler, fotoğraf tutkunları için vazgeçilmez bir rotadır. Özellikle restore edilmiş bölümleriyle geçmişin izlerini günümüze taşır.", "place_query": "Talas Tarihi Evleri, Kayseri"}, {"title": "Kurşunlu Camii ve Külliyesi", "summary": "Mimar Sinan''ın ustalık eserlerinden biri olan bu cami, 16. yüzyıldan kalma zarif yapısıyla dikkat çeker. Külliyesiyle birlikte Talas''ın en önemli tarihi ibadet ve kültür merkezlerinden biridir.", "place_query": "Kurşunlu Camii, Talas, Kayseri"}, {"title": "Reşadiye Cami", "summary": "II. Abdülhamid döneminde yaptırılan bu cami, kesme taş işçiliği ve tek minaresiyle sade ama etkileyici bir görünüme sahiptir. Talas''ın merkezinde yer alan bu yapı, huzurlu bir ziyaret için idealdir.", "place_query": "Reşadiye Cami, Talas, Kayseri"}, {"title": "Talas Şelalesi", "summary": "Şehir merkezine yakın konumuyla doğa ile iç içe vakit geçirmek isteyenlerin uğrak noktasıdır. Özellikle bahar aylarında coşan şelale, çevresindeki mesire alanıyla piknikçileri ağırlar.", "place_query": "Talas Şelalesi, Kayseri"}, {"title": "Zamantı Irmağı Vadisi", "summary": "Talas sınırlarından geçen bu vadi, yürüyüş ve bisiklet parkurlarıyla doğa sporlarına olanak tanır. Sarp kayalıkları ve yeşil örtüsüyle huzur dolu bir kaçamak sunar.", "place_query": "Zamantı Irmağı, Talas, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ee99de86-5698-4e05-b1fe-0b79589c6f9e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tomarza Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin savunma yapılarından biridir. Kalıntıları ve manzarasıyla ziyaretçilere tarihi bir atmosfer sunar.", "place_query": "Tomarza Kalesi, Tomarza, Kayseri"}, {"title": "Tomarza Şelalesi", "summary": "Doğal güzelliği ile öne çıkan şelale, piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle bahar ve yaz aylarında serinlemek için tercih edilir.", "place_query": "Tomarza Şelalesi, Tomarza, Kayseri"}, {"title": "Karakaya Barajı", "summary": "İlçe sınırları içinde bulunan baraj gölü, çevresindeki yeşil alanlarla doğa severler için huzurlu bir kaçış noktasıdır. Balık tutma ve manzara izleme imkanı sunar.", "place_query": "Karakaya Barajı, Tomarza, Kayseri"}, {"title": "Tarihi Tomarza Evleri", "summary": "İlçe merkezinde ve köylerinde dağınık halde bulunan geleneksel taş ve ahşap evler, yöresel mimariyi yansıtır. Fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Tarihi Tomarza Evleri, Tomarza, Kayseri"}, {"title": "Ali Dağı (Tomarza)", "summary": "Bölgenin yüksek dağlarından biri olan Ali Dağı, doğa yürüyüşü ve kampçılık için uygun rotalar barındırır. Zirvesinden çevre ilçelerin panoramik manzarası izlenebilir.", "place_query": "Ali Dağı, Tomarza, Kayseri"}, {"title": "Tomarza Ulu Camii", "summary": "İlçe merkezinde bulunan tarihi cami, sade mimarisi ve manevi atmosferiyle dikkat çeker. Yöre halkı için önemli bir ibadet ve buluşma noktasıdır.", "place_query": "Tomarza Ulu Camii, Tomarza, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '89093030-fa59-45e4-a190-1a3007383d0c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aladağlar Milli Parkı", "summary": "Türkiye''nin en önemli dağcılık ve doğa yürüyüşü merkezlerinden biridir. Demirkazık, Kaldı ve Emler gibi zirveleriyle ünlü olan park, eşsiz bitki örtüsü ve vahşi yaşamıyla doğa severler için eşsiz bir deneyim sunar.", "place_query": "Aladağlar Milli Parkı, Yahyalı, Kayseri"}, {"title": "Kapuzbaşı Şelaleleri", "summary": "Yedi ayrı koldan yüksek kayalıklardan dökülen bu şelaleler, Türkiye''nin en yüksek ve en etkileyici şelaleleri arasında yer alır. Çevresindeki piknik alanları ve yürüyüş parkurlarıyla ziyaretçilere huzurlu bir doğa kaçamağı sunar.", "place_query": "Kapuzbaşı Şelaleleri, Yahyalı, Kayseri"}, {"title": "Yahyalı Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, Yahyalı ilçe merkezine hakim bir tepe üzerinde yer alır. Kaleye çıktığınızda ilçenin ve çevre dağların panoramik manzarasını izleyebilirsiniz.", "place_query": "Yahyalı Kalesi, Yahyalı, Kayseri"}, {"title": "Sultansazlığı Milli Parkı", "summary": "Zengin kuş türlerine ev sahipliği yapan bu sulak alan, özellikle flamingolar ve turnalar için önemli bir yaşam alanıdır. Kuş gözlemciliği yapmak ve doğa fotoğrafçılığı için ideal bir noktadır.", "place_query": "Sultansazlığı Milli Parkı, Yahyalı, Kayseri"}, {"title": "Çamlıca Şelalesi ve Mesire Alanı", "summary": "Yemyeşil bir ormanın içinde yer alan bu şelale ve mesire alanı, özellikle yaz aylarında serinlemek ve piknik yapmak isteyenlerin uğrak noktasıdır. Doğal güzelliği ve temiz havasıyla huzur verir.", "place_query": "Çamlıca Şelalesi Mesire Alanı, Yahyalı, Kayseri"}, {"title": "Süleymanlı Camii", "summary": "Yahyalı''nın tarihi camilerinden biri olan Süleymanlı Camii, Osmanlı dönemi mimarisinin güzel bir örneğidir. Cami, sade ve etkileyici atmosferiyle ziyaretçilerini tarihi bir yolculuğa çıkarır.", "place_query": "Süleymanlı Camii, Yahyalı, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '26bfddae-5e25-49d6-b390-23c898321301'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Soğanlı Vadisi", "summary": "Peribacaları ve kayaya oyulmuş kiliseleriyle ünlü bu vadi, Kapadokya''nın en etkileyici doğal ve tarihi alanlarından biridir. Güvercinlikler ve yürüyüş parkurları ziyaretçilere eşsiz bir deneyim sunar.", "place_query": "Soğanlı Vadisi, Yeşilhisar, Kayseri"}, {"title": "Erdemli Vadisi", "summary": "Soğanlı Vadisi''ne yakın konumdaki bu vadi, kayalara oyulmuş şapelleri ve manastır kalıntılarıyla Bizans dönemi dini mimarisini gözler önüne serer. Sessiz ve huzurlu atmosferiyle doğa yürüyüşü için idealdir.", "place_query": "Erdemli Vadisi, Yeşilhisar, Kayseri"}, {"title": "Yeşilhisar Kalesi", "summary": "İlçe merkezinde yer alan tarihi kale, bölgenin stratejik önemini yansıtan bir yapıdır. Kaleyi çevreleyen dar sokaklar ve geleneksel evler, ziyaretçilere nostaljik bir gezi imkanı sunar.", "place_query": "Yeşilhisar Kalesi, Yeşilhisar, Kayseri"}, {"title": "Yamaçlı Şelalesi", "summary": "Yeşilhisar''ın doğal güzelliklerinden biri olan şelale, özellikle bahar ve yaz aylarında piknik ve doğa ile iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Yamaçlı Şelalesi, Yeşilhisar, Kayseri"}, {"title": "Aşıklı Höyük", "summary": "İlçe sınırları içinde yer alan bu önemli arkeolojik alan, Anadolu''nun en eski yerleşimlerinden biri olarak kabul edilir. Akeramik Neolitik döneme ait buluntular, bölgenin tarih öncesine ışık tutar.", "place_query": "Aşıklı Höyük, Yeşilhisar, Kayseri"}, {"title": "Yeşilhisar Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu pazar, ilçenin kültürel dokusunu yansıtan renkli bir alışveriş deneyimi sunar. Özellikle haftalık kurulan pazar günleri hareketlidir.", "place_query": "Yeşilhisar Kapalı Pazar Yeri, Yeşilhisar, Kayseri"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '14e8b0cd-7b0e-469b-88e8-b4a79b2e97e0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Elbeyli İlçe Merkezi ve Çevresi", "summary": "Kilis''in sakin ilçelerinden biri olan Elbeyli, tipik Güneydoğu Anadolu kırsal yaşamını deneyimlemek isteyenler için idealdir. Ziyaretçiler, ilçe merkezinde günlük hayatı gözlemleyebilir ve çevredeki tarım arazilerinde yürüyüş yapabilir.", "place_query": "Elbeyli, Kilis"}, {"title": "Kilis Evleri (Elbeyli''deki Tarihi Yapılar)", "summary": "İlçede bulunan bazı eski Kilis evleri, yöresel taş işçiliği ve mimari özellikleriyle dikkat çeker. Bu yapılar, bölgenin kültürel geçmişine dair ipuçları sunar.", "place_query": "Kilis Evleri, Elbeyli, Kilis"}, {"title": "Elbeyli Ovası", "summary": "Geniş ve verimli tarım arazileriyle kaplı Elbeyli Ovası, özellikle ilkbahar aylarında yeşilin her tonunu görebileceğiniz huzurlu bir doğa yürüyüşü rotasıdır.", "place_query": "Elbeyli Ovası, Kilis"}, {"title": "Cumhuriyet Meydanı ve Çarşı", "summary": "İlçenin sosyal merkezi olan Cumhuriyet Meydanı ve çevresindeki küçük çarşı, yöresel ürünleri satın alabileceğiniz ve halkla sohbet edebileceğiniz bir noktadır.", "place_query": "Cumhuriyet Meydanı, Elbeyli, Kilis"}, {"title": "Elbeyli Şehitliği", "summary": "Bölgenin yakın tarihine tanıklık eden şehitlik, saygıyla ziyaret edilmesi gereken bir anıt alanıdır. Sade atmosferiyle duygusal bir ziyaret sunar.", "place_query": "Elbeyli Şehitliği, Kilis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c44a0a4b-8c07-4b7a-8a5d-03e956a58274'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ravanda Kalesi", "summary": "Kilis''in simgelerinden olan bu tarihi kale, şehir merkezine hakim bir tepede yer alır. Haçlı Seferleri ve Osmanlı dönemine tanıklık eden yapı, muhteşem bir manzara sunar.", "place_query": "Ravanda Kalesi, Kilis Merkez"}, {"title": "Kilis Müzesi", "summary": "Şehir merkezinde bulunan müze, arkeolojik eserler ve yöresel etnografik objelerle Kilis''in zengin tarihini gözler önüne serer. Özellikle mozaik koleksiyonu dikkat çekicidir.", "place_query": "Kilis Müzesi, Kilis Merkez"}, {"title": "Ulu Cami (Kilis)", "summary": "17. yüzyılda inşa edilen bu tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Şehrin en eski ve en önemli ibadet yapılarından biridir.", "place_query": "Ulu Cami, Kilis Merkez"}, {"title": "Aktepe (Kilis''in Seyir Tepesi)", "summary": "Şehir merkezine yakın bu yüksek tepe, Kilis ve çevresinin panoramik manzarasını izlemek için en ideal noktalardan biridir. Özellikle gün batımında ziyaretçilerine huzurlu bir atmosfer sunar.", "place_query": "Aktepe, Kilis Merkez"}, {"title": "Kilis Evleri (Tarihi Kilis Evleri)", "summary": "Kilis''in dar sokaklarında bulunan bu geleneksel taş evler, özgün mimarileri ve avlularıyla geçmişe yolculuk yaptırır. Birçoğu hala özenle korunmaktadır.", "place_query": "Tarihi Kilis Evleri, Kilis Merkez"}, {"title": "Oylum Höyük", "summary": "Kilis''in 5 km kuzeydoğusunda yer alan bu büyük höyük, Neolitik Çağ''dan günümüze kadar kesintisiz yerleşime sahne olmuştur. Bölgenin en önemli arkeolojik alanlarından biridir.", "place_query": "Oylum Höyük, Kilis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f86aba4f-29c8-4ad4-922f-8777d1060013'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kilis Müzesi", "summary": "Kilis''in tarihini ve kültürel mirasını yansıtan önemli bir müzedir. Arkeolojik eserler, etnografik objeler ve yöresel kıyafetler sergilenmektedir.", "place_query": "Kilis Müzesi, Kilis Merkez"}, {"title": "Ravanda Kalesi", "summary": "Musabeyli ilçesi sınırlarında yer alan tarihi bir kaledir. Haçlı Seferleri döneminden kalma kalıntıları ve etkileyici manzarası ile ziyaretçilerini cezbeder.", "place_query": "Ravanda Kalesi, Musabeyli, Kilis"}, {"title": "Oylum Höyük", "summary": "Kilis''in en önemli arkeolojik alanlarından biridir. Tunç Çağı''ndan günümüze kadar kesintisiz yerleşim görmüş olup, bölgenin tarihine ışık tutmaktadır.", "place_query": "Oylum Höyük, Kilis Merkez"}, {"title": "Musabeyli Göleti", "summary": "Musabeyli ilçesinde bulunan bu gölet, doğal güzelliği ve huzur veren atmosferi ile piknik ve doğa yürüyüşü için ideal bir mekandır.", "place_query": "Musabeyli Göleti, Musabeyli, Kilis"}, {"title": "Kilis Evleri", "summary": "Kilis''in eski mahallelerinde bulunan tarihi taş evler, yöresel mimarinin güzel örnekleridir. Dar sokaklarda yürüyerek geçmişe yolculuk yapabilirsiniz.", "place_query": "Tarihi Kilis Evleri, Kilis Merkez"}, {"title": "Akpınar Mesire Alanı", "summary": "Kilis şehir merkezine yakın, yeşillikler içinde bir mesire alanıdır. Piknik yapmak, dinlenmek ve doğayla iç içe vakit geçirmek için sıkça tercih edilir.", "place_query": "Akpınar Mesire Alanı, Kilis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd7334953-40d3-464c-9a54-855ed4339825'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Polateli Kalesi", "summary": "İlçe merkezine hakim bir tepede yer alan tarihi kale, bölgenin savunma yapılarından biridir. Ziyaretçilerine hem tarihi bir atmosfer hem de çevrenin panoramik manzarasını sunar.", "place_query": "Polateli Kalesi, Polateli, Kilis"}, {"title": "Ravanda Kalesi", "summary": "Polateli sınırları içinde yer alan bu görkemli ortaçağ kalesi, Haçlı ve Memlük dönemlerinden izler taşır. Tarih meraklıları için etkileyici bir keşif noktasıdır.", "place_query": "Ravanda Kalesi, Polateli, Kilis"}, {"title": "Polateli Ulu Camii", "summary": "İlçenin tarihi camilerinden biri olan yapı, sade mimarisi ve huzurlu atmosferiyle dikkat çeker. Bölgenin dini ve kültürel mirasını yansıtan önemli bir duraktır.", "place_query": "Polateli Ulu Camii, Polateli, Kilis"}, {"title": "Polateli Çarşı Camii", "summary": "İlçe merkezinde bulunan ve Osmanlı dönemi izlerini taşıyan bu cami, bölge halkı için önemli bir ibadet ve buluşma noktasıdır. Tarihi dokusuyla ziyaretçilerini cezbeder.", "place_query": "Polateli Çarşı Camii, Polateli, Kilis"}, {"title": "Polateli Yaylası", "summary": "Şehir hayatından uzaklaşmak isteyenler için ideal olan bu yayla, temiz havası ve yeşil doğasıyla huzur verir. Özellikle yaz aylarında piknik ve doğa yürüyüşleri için tercih edilir.", "place_query": "Polateli Yaylası, Polateli, Kilis"}, {"title": "Söğütlü Göleti", "summary": "Polateli yakınlarındaki bu küçük gölet, doğa ile baş başa kalmak isteyenler için sakin bir kaçış noktasıdır. Çevresindeki ağaçlık alan ve su manzarasıyla huzur verir.", "place_query": "Söğütlü Göleti, Polateli, Kilis"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'df7ed8f5-7d2f-41b2-84b0-a2fec51b1397'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bahşılı Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale, Kırıkkale ve çevresine hakim manzarasıyla ziyaretçilerine eşsiz bir seyir keyfi sunar. Bölgenin tarihi dokusunu yansıtan önemli bir yapıdır.", "place_query": "Bahşılı Kalesi, Bahşılı, Kırıkkale"}, {"title": "Kırıkkale Müzesi", "summary": "Bahşılı''ya kısa bir mesafede bulunan müze, bölgede yapılan arkeolojik kazılardan çıkarılan eserleri ve yöresel etnografik objeleri sergileyerek geçmişe ışık tutar.", "place_query": "Kırıkkale Müzesi, Kırıkkale"}, {"title": "Çeşnigir Köprüsü", "summary": "Keskin ilçesi sınırlarında yer alan bu tarihi Roma köprüsü, Kızılırmak üzerindeki görkemli kemerleriyle fotoğrafçılar ve doğa severler için popüler bir durak noktasıdır.", "place_query": "Çeşnigir Köprüsü, Keskin, Kırıkkale"}, {"title": "Kırıkkale Tabiat Parkı", "summary": "Şehir merkezine yakın bu yeşil alan, piknik alanları ve yürüyüş parkurlarıyla aileler ve doğa tutkunları için huzurlu bir kaçış noktasıdır.", "place_query": "Kırıkkale Tabiat Parkı, Kırıkkale"}, {"title": "Kapulukaya Barajı ve Mesire Alanı", "summary": "Kızılırmak üzerinde kurulu baraj gölü çevresindeki mesire alanı, balık tutma, kamp yapma ve doğa yürüyüşü gibi aktiviteler için idealdir.", "place_query": "Kapulukaya Barajı, Kırıkkale"}, {"title": "Noktel Tepesi", "summary": "Bahşılı''ya yakın konumuyla bilinen bu tepe, özellikle gün batımında sunduğu panoramik Kırıkkale manzarasıyla ziyaretçilerin uğrak noktasıdır.", "place_query": "Noktel Tepesi, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0733e3b2-c301-46ec-8a6c-037319b3f69d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Balışeyh Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla bölge halkının uğrak noktasıdır. Piknik alanları ve yürüyüş parkurları ile doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Balışeyh Şelalesi, Balışeyh, Kırıkkale"}, {"title": "Keskin Dağı Tabiat Parkı", "summary": "Zengin bitki örtüsü ve temiz havasıyla doğa yürüyüşleri ve kamp için popülerdir. Yüksek noktalarından Kırıkkale manzarası izlenebilir.", "place_query": "Keskin Dağı Tabiat Parkı, Kırıkkale"}, {"title": "Balışeyh Merkez Camii", "summary": "İlçenin tarihi ve mimari açıdan önemli yapılarından biridir. Osmanlı dönemi izlerini taşıyan cami, ibadet ve ziyaret amacıyla sıkça uğranır.", "place_query": "Balışeyh Merkez Camii, Balışeyh, Kırıkkale"}, {"title": "Kırıkkale Müzesi", "summary": "İlçe merkezine kısa mesafede bulunan müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Hitit, Roma ve Osmanlı dönemine ait eserler görülebilir.", "place_query": "Kırıkkale Müzesi, Kırıkkale Merkez, Kırıkkale"}, {"title": "Karacabey Barajı", "summary": "Balışeyh sınırlarında yer alan baraj, çevresindeki yeşil alanlar ve yürüyüş yollarıyla sakin bir doğa deneyimi sunar. Balık tutma ve piknik için uygundur.", "place_query": "Karacabey Barajı, Balışeyh, Kırıkkale"}, {"title": "Kırıkkale Silah Müzesi", "summary": "Türkiye''nin önemli silah sanayi merkezlerinden birinde yer alan müze, askeri tarih meraklıları için eşsiz bir koleksiyon sunar. Savunma sanayiinin geçmişine tanıklık edin.", "place_query": "Kırıkkale Silah Müzesi, Kırıkkale Merkez, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '08147909-e1f3-444c-a3c3-9fb5722cec2a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çelebi Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir. Bölgenin savunma yapılarından biri olarak bilinir ve çevresindeki doğal manzara ile ziyaretçilere hoş bir seyir imkanı sunar.", "place_query": "Çelebi Kalesi, Çelebi, Kırıkkale"}, {"title": "Çelebi Şelalesi", "summary": "Doğal güzelliği ile öne çıkan bu şelale, piknik ve doğa yürüyüşü için ideal bir noktadır. Çevresindeki yeşil alanlar ve serin suları ile huzurlu bir kaçış sunar.", "place_query": "Çelebi Şelalesi, Çelebi, Kırıkkale"}, {"title": "Hacılar Köyü Camii", "summary": "Tarihi bir Osmanlı dönemi camisidir. Mimari detayları ve köyün sakin atmosferi ile kültürel bir durak olarak ilgi çeker.", "place_query": "Hacılar Köyü Camii, Çelebi, Kırıkkale"}, {"title": "Çelebi Yaylası", "summary": "Yüksek rakımı ve temiz havası ile yaz aylarında serinlemek için tercih edilen bir yayladır. Doğa yürüyüşleri ve kamp için uygun alanlar barındırır.", "place_query": "Çelebi Yaylası, Çelebi, Kırıkkale"}, {"title": "Karaçayır Tabiat Parkı", "summary": "Çelebi sınırlarına yakın bu tabiat parkı, zengin bitki örtüsü ve piknik alanları ile doğaseverler için popüler bir destinasyondur.", "place_query": "Karaçayır Tabiat Parkı, Kırıkkale"}, {"title": "Çelebi Göleti", "summary": "Balık tutma ve doğa ile baş başa vakit geçirme imkanı sunan bir gölettir. Çevresindeki yeşil alanlar aile piknikleri için elverişlidir.", "place_query": "Çelebi Göleti, Çelebi, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd5f84b43-f5f0-4cc5-88a0-d1f4141bc0f4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Delice İlçe Merkezi ve Çarşısı", "summary": "Delice''nin merkezindeki çarşı, ilçenin günlük yaşamını ve yerel kültürünü yansıtan, ziyaretçilere otantik bir Anadolu kasabası deneyimi sunan canlı bir noktadır.", "place_query": "Delice Merkez, Kırıkkale"}, {"title": "Delice Kalesi", "summary": "Tarihi bir geçmişe sahip olan Delice Kalesi, bölgenin savunma yapılarından biri olarak bilinir ve çevresindeki kırsal manzaraya hakim bir tepede yer alır, fotoğrafçılar için idealdir.", "place_query": "Delice Kalesi, Kırıkkale"}, {"title": "Çerikli Kasabası", "summary": "Delice''ye bağlı bir belde olan Çerikli, sakin atmosferi ve tipik İç Anadolu köy yaşamını gözlemlemek isteyenler için huzurlu bir durak noktasıdır.", "place_query": "Çerikli, Delice, Kırıkkale"}, {"title": "Sulakyurt Yaylası", "summary": "Delice yakınlarındaki Sulakyurt Yaylası, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için yeşil alanları ve temiz havasıyla popüler bir piknik ve mesire yeridir.", "place_query": "Sulakyurt Yaylası, Kırıkkale"}, {"title": "Delice Çayı ve Çevresi", "summary": "Delice ilçesine adını veren Delice Çayı, çevresindeki doğal yürüyüş alanları ve kırsal manzaraları ile doğa severler için sakin bir kaçış noktası sunar.", "place_query": "Delice Çayı, Kırıkkale"}, {"title": "Büyükavşar Köyü Tarihi Eserleri", "summary": "Delice''ye bağlı Büyükavşar Köyü, çevresinde bulunan tarihi kalıntılar ve geleneksel köy mimarisi ile tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Büyükavşar Köyü, Delice, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '61d8129c-f677-4865-bb7d-c0c7769b0a21'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karakeçili Şelalesi", "summary": "İlçe merkezine yakın, doğal güzelliğiyle piknik ve doğa yürüyüşü için popüler bir noktadır. Özellikle bahar aylarında akan suyu ve çevresindeki yeşil alanlarıyla ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Karakeçili Şelalesi, Karakeçili, Kırıkkale"}, {"title": "Karakeçili İlçe Merkezi ve Çarşı", "summary": "Küçük ama samimi bir ilçe merkezi olan Karakeçili''de, yöresel ürünlerin satıldığı dükkanlar ve sakin bir atmosfer bulunur. İlçenin günlük yaşamını deneyimlemek ve kısa bir yürüyüş yapmak için idealdir.", "place_query": "Karakeçili Merkez, Kırıkkale"}, {"title": "Sulakyurt Yaylası", "summary": "Karakeçili sınırları içinde yer alan bu yayla, temiz havası ve geniş otlak alanlarıyla doğa severler için keşfedilmeyi bekleyen bir noktadır. Yürüyüş ve kamp yapmak isteyenler için sakin bir kaçış noktasıdır.", "place_query": "Sulakyurt Yaylası, Karakeçili, Kırıkkale"}, {"title": "Köprüköy Göleti", "summary": "İlçeye bağlı Köprüköy yakınlarındaki bu gölet, balık tutma ve piknik yapma imkanı sunan huzurlu bir doğa alanıdır. Çevresi ağaçlarla kaplı olup, özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Köprüköy Göleti, Karakeçili, Kırıkkale"}, {"title": "Karakeçili Kalesi Kalıntıları", "summary": "Tarihi bir geçmişe sahip olan bu kale kalıntıları, ilçenin kültürel mirasını yansıtan önemli bir noktadır. Tepe üzerinde yer alan kalıntılar, çevreye hakim bir manzara sunar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Karakeçili Kalesi, Karakeçili, Kırıkkale"}, {"title": "Kızılırmak Nehri Kenarı", "summary": "Karakeçili''den geçen Kızılırmak''ın kıyıları, doğa yürüyüşü ve dinlenmek için sakin bir ortam sağlar. Nehir boyunca uzanan patikalar, kuş gözlemi ve fotoğrafçılık için idealdir.", "place_query": "Kızılırmak Nehri, Karakeçili, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b0891f36-e8d7-4b7b-a856-e71f1e22785c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Keskin Kalesi", "summary": "Tarihi bir kalıntı olan Keskin Kalesi, ilçeye hakim bir tepede yer alır ve bölgenin geçmişine tanıklık eden önemli bir kültürel mirastır. Ziyaretçiler buradan çevrenin panoramik manzarasını izleyebilir.", "place_query": "Keskin Kalesi, Keskin, Kırıkkale"}, {"title": "Keskin Müzesi", "summary": "İlçe merkezinde bulunan bu müze, yöresel etnografik eserler ve arkeolojik buluntular sergileyerek Keskin''in tarihini ve kültürünü tanıtır. Küçük ama zengin koleksiyonuyla ziyaretçilere keyifli bir gezi imkanı sunar.", "place_query": "Keskin Müzesi, Keskin, Kırıkkale"}, {"title": "Konur Köyü ve Tarihi Evleri", "summary": "Keskin''e bağlı Konur Köyü, geleneksel mimariyi yansıtan tarihi taş evleri ve doğal güzellikleriyle bilinir. Köy, sakin atmosferi ve otantik yapısıyla fotoğraf tutkunları için ideal bir duraktır.", "place_query": "Konur Köyü, Keskin, Kırıkkale"}, {"title": "Keskin Barajı ve Mesire Alanı", "summary": "Şehir merkezine yakın konumdaki Keskin Barajı, çevresindeki yeşil alanlar ve piknik masalarıyla aileler için popüler bir mesire yeridir. Doğa yürüyüşü ve balık tutma gibi aktiviteler için de uygundur.", "place_query": "Keskin Barajı, Keskin, Kırıkkale"}, {"title": "Keskin Taşhan (Tarihi Taşhan)", "summary": "Geçmişte konaklama ve ticaret amaçlı kullanılan tarihi bir yapı olan Taşhan, Keskin''in kültürel miraslarındandır. Günümüzde restore edilerek kültürel etkinliklere ev sahipliği yapmaktadır.", "place_query": "Keskin Taşhan, Keskin, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd99cafe2-d9b2-45d8-a1cc-4af96ef0d4f5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kırıkkale MKE Silah Fabrikası Müzesi", "summary": "Türkiye''nin ilk silah fabrikası olan bu müze, savunma sanayii tarihine ilgi duyanlar için eşsiz bir duraktır. Osmanlı''dan günümüze uzanan geniş silah koleksiyonu ve tarihi üretim atölyeleri görülmeye değerdir.", "place_query": "MKE Silah Fabrikası Müzesi, Kırıkkale Merkez, Kırıkkale"}, {"title": "Kırıkkale Nata Vega Alışveriş Merkezi", "summary": "Şehrin en büyük ve modern alışveriş merkezi olan Nata Vega, sinema salonları, yeme-içme alanları ve çeşitli mağazalarıyla aileler için ideal bir günübirlik gezi noktasıdır.", "place_query": "Nata Vega Alışveriş Merkezi, Kırıkkale Merkez"}, {"title": "Kırıkkale Şehir Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve yapay göletiyle şehrin nefes alma noktasıdır. Özellikle hafta sonları aile piknikleri ve çocuk oyun alanlarıyla popülerdir.", "place_query": "Kırıkkale Şehir Parkı, Merkez, Kırıkkale"}, {"title": "Kırıkkale Kapalı Spor Salonu ve Çevresi", "summary": "Şehrin spor merkezi olan bu alan, basketbol ve voleybol maçlarının yanı sıra konser ve etkinliklere de ev sahipliği yapar. Çevresindeki kafelerle spor ve sosyalleşme bir aradadır.", "place_query": "Kırıkkale Kapalı Spor Salonu, Merkez, Kırıkkale"}, {"title": "Kırıkkale Atatürk Anıtı ve Cumhuriyet Meydanı", "summary": "Şehir merkezindeki bu meydan, Atatürk anıtı ve çevresindeki tarihi binalarla kentin simgesidir. Resmi törenlerin yanı sıra günlük buluşma noktası olarak da kullanılır.", "place_query": "Atatürk Anıtı, Cumhuriyet Meydanı, Kırıkkale Merkez"}, {"title": "Kırıkkale Koşu Yolu ve Mesire Alanı", "summary": "Şehrin girişinde yer alan bu uzun yürüyüş parkuru, doğayla iç içe spor yapma imkanı sunar. Piknik masaları ve dinlenme banklarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Kırıkkale Koşu Yolu Mesire Alanı, Merkez, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b8e5e463-e841-42db-bf35-a183a7b0993b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sulakyurt Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi bir kaledir. Çevresindeki doğal manzara ve tarihi dokusuyla ziyaretçilere huzurlu bir atmosfer sunar.", "place_query": "Sulakyurt Kalesi, Sulakyurt, Kırıkkale"}, {"title": "Sulakyurt Kapalı Pazar Yeri", "summary": "İlçenin en hareketli noktalarından biri olan bu pazar yeri, yöresel ürünler ve canlı atmosferiyle alışveriş yapmak isteyenler için idealdir.", "place_query": "Sulakyurt Kapalı Pazar Yeri, Sulakyurt, Kırıkkale"}, {"title": "Kırıkkale Sulakyurt Şelalesi", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için popüler bir mesire alanıdır. Şelalenin serin suları ve yeşil çevresi piknik ve yürüyüş için uygundur.", "place_query": "Sulakyurt Şelalesi, Sulakyurt, Kırıkkale"}, {"title": "Sulakyurt Merkez Camii", "summary": "İlçenin tarihi camilerinden biri olup, mimarisi ve manevi atmosferiyle dikkat çeker. Ziyaretçiler için sakin bir ibadet ve dinlenme noktasıdır.", "place_query": "Sulakyurt Merkez Camii, Sulakyurt, Kırıkkale"}, {"title": "Sulakyurt Göleti", "summary": "Doğal güzelliği ve çevresindeki piknik alanlarıyla bilinen bu gölet, balık tutma ve doğa yürüyüşü gibi aktiviteler için tercih edilir.", "place_query": "Sulakyurt Göleti, Sulakyurt, Kırıkkale"}, {"title": "Sulakyurt Eski Hamam", "summary": "Tarihi bir Osmanlı hamamı olan bu yapı, ilçenin geçmişine tanıklık eden önemli bir kültürel mirastır. Restore edilmiş haliyle ziyaretçilere açıktır.", "place_query": "Sulakyurt Eski Hamam, Sulakyurt, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ccdddc55-2f1a-4c8c-954f-9bf921cffb1b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yahşihan Köprüsü (Tarihi Taş Köprü)", "summary": "Kızılırmak üzerinde bulunan bu tarihi taş köprü, Yahşihan''ın simgesi haline gelmiştir. Osmanlı döneminden kalma yapı, özellikle fotoğrafçılar ve tarih meraklıları için görülmeye değer bir duraktır.", "place_query": "Tarihi Yahşihan Köprüsü, Kırıkkale"}, {"title": "Kırıkkale Müzesi", "summary": "Yahşihan''a çok yakın konumdaki bu müze, bölgenin arkeolojik ve etnografik zenginliklerini sergiler. Hitit, Roma ve Osmanlı dönemlerine ait eserlerin yanı sıra silah koleksiyonu da dikkat çeker.", "place_query": "Kırıkkale Müzesi, Kırıkkale"}, {"title": "Kızılırmak Kenarı Yürüyüş Parkuru", "summary": "Yahşihan''dan geçen Kızılırmak boyunca uzanan bu yürüyüş parkuru, doğa severler için huzurlu bir kaçış noktasıdır. Nehir manzarası eşliğinde yürüyüş yapabilir veya piknik alanlarında vakit geçirebilirsiniz.", "place_query": "Kızılırmak kenarı yürüyüş yolu, Yahşihan, Kırıkkale"}, {"title": "Yahşihan Mesire Alanı", "summary": "Aileler ve arkadaş grupları için ideal olan bu mesire alanı, yeşil alanları ve piknik masalarıyla hafta sonu kaçamakları için popülerdir. Çocuk oyun alanları da mevcuttur.", "place_query": "Yahşihan Mesire Alanı, Kırıkkale"}, {"title": "Kırıkkale Nükleer Araştırma ve Eğitim Merkezi (Anıt ve Sergi Alanı)", "summary": "Türkiye''nin ilk nükleer reaktörünün bulunduğu bu merkez, bilim ve teknoloji meraklıları için ilginç bir duraktır. Ziyaretçiler, reaktörün tarihçesi ve çalışma prensipleri hakkında bilgi alabilir.", "place_query": "Kırıkkale Nükleer Araştırma Merkezi, Kırıkkale"}, {"title": "Yahşihan Belediyesi Millet Bahçesi", "summary": "Modern peyzajı ve geniş yeşil alanlarıyla şehir merkezinde nefes alabileceğiniz bir noktadır. Yürüyüş yolları, oturma alanları ve kafe ile donatılmıştır.", "place_query": "Yahşihan Millet Bahçesi, Kırıkkale"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fbd83b15-6986-44b8-942e-521c50535995'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Babaeski Kalesi", "summary": "Tarihi Bizans dönemine kadar uzanan bu kale, ilçenin simge yapılarından biridir. Günümüze sadece sur duvarlarının bir kısmı ulaşmış olsa da, tarihi atmosferi ve şehir manzarasıyla ziyaretçileri cezbeder.", "place_query": "Babaeski Kalesi, Babaeski, Kırklareli"}, {"title": "Babaeski Bedesteni", "summary": "Osmanlı döneminden kalma tarihi bir çarşı olan bedesten, restore edilerek günümüzde küçük dükkanlarıyla hizmet vermektedir. Mimarisi ve tarihi dokusuyla ilçenin önemli kültürel miraslarındandır.", "place_query": "Babaeski Bedesteni, Babaeski, Kırklareli"}, {"title": "Babaeski Merkez Camii (Sokollu Mehmet Paşa Camii)", "summary": "Mimar Sinan''ın eseri olan bu tarihi cami, 16. yüzyılda Sokollu Mehmet Paşa tarafından yaptırılmıştır. Kesme taş işçiliği ve sadık mimarisiyle dikkat çeker, halen ibadete açıktır.", "place_query": "Sokollu Mehmet Paşa Camii, Babaeski, Kırklareli"}, {"title": "Babaeski Atatürk Evi", "summary": "Mustafa Kemal Atatürk''ün Balkan gezisi sırasında konakladığı bu tarihi ev, günümüzde müze olarak ziyaret edilebilir. İçerisinde Atatürk''e ait fotoğraflar ve o döneme ait eşyalar sergilenmektedir.", "place_query": "Atatürk Evi Müzesi, Babaeski, Kırklareli"}, {"title": "Babaeski Taş Köprü", "summary": "Osmanlı döneminde inşa edilen bu tarihi taş köprü, ilçenin önemli simgelerindendir. Günümüzde hala kullanılan köprü, özellikle fotoğrafçıların ilgisini çeker.", "place_query": "Babaeski Taş Köprü, Babaeski, Kırklareli"}, {"title": "Babaeski Şehir Parkı", "summary": "İlçe merkezinde yer alan bu geniş park, yürüyüş yolları, göleti ve yeşil alanlarıyla dinlenmek için ideal bir mekandır. Aileler ve doğa severler tarafından sıkça tercih edilir.", "place_query": "Babaeski Şehir Parkı, Babaeski, Kırklareli"}, {"title": "Babaeski Panorama Müzesi", "summary": "Balkan Savaşları''na ait sahnelerin canlandırıldığı bu modern müze, ziyaretçilere tarihi bir yolculuk sunar. Etkileyici panoramik resimleri ve ses efektleriyle dikkat çeker.", "place_query": "Babaeski Panorama Müzesi, Babaeski, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c66255a1-b019-4282-911f-8f978ad0f214'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dupnisa Mağarası", "summary": "Türkiye''nin en önemli mağaralarından biri olan Dupnisa, etkileyici sarkıt ve dikitleriyle ziyaretçilerini büyüler. İçinde akan dere ve yarasa kolonileriyle doğa tutkunları için eşsiz bir keşif noktasıdır.", "place_query": "Dupnisa Mağarası, Demirköy, Kırklareli"}, {"title": "İğneada Longoz Ormanları", "summary": "Avrupa''nın sayılı su basar ormanlarından biri olan İğneada Longozu, eşsiz ekosistemi ve yürüyüş parkurlarıyla doğaseverlerin gözdesidir. Kuş gözlemi ve doğa fotoğrafçılığı için ideal bir alandır.", "place_query": "İğneada Longoz Ormanları, Demirköy, Kırklareli"}, {"title": "Mert Gölü", "summary": "İğneada Longoz Ormanları içinde yer alan Mert Gölü, sakin suları ve çevresindeki yemyeşil doğasıyla huzur verici bir manzaraya sahiptir. Gölet çevresinde yürüyüş yapabilir ve piknik yapabilirsiniz.", "place_query": "Mert Gölü, İğneada, Demirköy, Kırklareli"}, {"title": "Demirköy Fatih Dökümhanesi", "summary": "Fatih Sultan Mehmet döneminde top dökümü için kullanılan bu tarihi tesis, Osmanlı sanayi mirasının nadide örneklerindendir. Günümüzde müze olarak ziyarete açık olan dökümhane, tarih meraklıları için önemli bir duraktır.", "place_query": "Demirköy Fatih Dökümhanesi, Demirköy, Kırklareli"}, {"title": "İğneada Sahili ve Plajı", "summary": "Karadeniz''in serin sularına kucak açan İğneada Sahili, uzun kumsalı ve doğal güzelliğiyle yaz aylarının popüler plajlarındandır. Kamp yapmak ve deniz keyfi yapmak için idealdir.", "place_query": "İğneada Plajı, Demirköy, Kırklareli"}, {"title": "Sivriler Tabyası", "summary": "19. yüzyılda Osmanlı-Rus savaşları sırasında inşa edilen Sivriler Tabyası, tarihi bir savunma yapısı olarak günümüze ulaşmıştır. Tabyadan Karadeniz ve çevre ormanların panoramik manzarası izlenebilir.", "place_query": "Sivriler Tabyası, Demirköy, Kırklareli"}, {"title": "Sultançayırı Yaylası", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü Sultançayırı Yaylası, doğa yürüyüşleri ve kamp için harika bir seçenektir. Yaylada geleneksel yayla şenlikleri de düzenlenmektedir.", "place_query": "Sultançayırı Yaylası, Demirköy, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fa02de64-ffdd-436a-8d0f-91459bcbd104'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kofçaz Merkez Camii", "summary": "Kofçaz ilçe merkezinde bulunan tarihi cami, yöre halkı için önemli bir ibadet ve kültür merkezidir. Ziyaretçiler, sade mimarisi ve huzurlu atmosferi ile dikkat çeker.", "place_query": "Kofçaz Merkez Camii, Kırklareli"}, {"title": "Dupnisa Mağarası", "summary": "Kofçaz sınırları içinde yer alan ve Türkiye''nin en önemli mağaralarından biri olan Dupnisa, etkileyici sarkıt ve dikitleriyle doğa ve macera severlerin uğrak noktasıdır. Mağara içindeki yürüyüş parkuru ve eşsiz jeolojik yapılar ziyaretçileri büyüler.", "place_query": "Dupnisa Mağarası, Kofçaz, Kırklareli"}, {"title": "Kofçaz Yaylaları", "summary": "İlçenin serin ve yeşil yaylaları, özellikle yaz aylarında doğa yürüyüşleri ve piknik için ideal alanlar sunar. Temiz havası ve manzarası ile huzur arayanların tercihidir.", "place_query": "Kofçaz Yaylaları, Kırklareli"}, {"title": "Ahlatlı Köyü Kaya Mezarları", "summary": "Kofçaz''a bağlı Ahlatlı köyünde bulunan tarihi kaya mezarları, bölgenin antik dönemlerine ışık tutan önemli arkeolojik kalıntılardır. Tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Ahlatlı Köyü Kaya Mezarları, Kofçaz, Kırklareli"}, {"title": "Kofçaz Barajı", "summary": "İlçe merkezine yakın konumdaki Kofçaz Barajı, çevresindeki yeşil alanlar ve su manzarasıyla doğa ile iç içe vakit geçirmek isteyenler için popüler bir yerdir. Balık tutma ve piknik etkinlikleri için sıkça ziyaret edilir.", "place_query": "Kofçaz Barajı, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ca9be58f-3f31-4d95-82cd-1bfb832f4e57'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Lüleburgaz Sokullu Mehmet Paşa Külliyesi", "summary": "Mimar Sinan''ın eseri olan bu külliye, cami, medrese, hamam ve kervansaraydan oluşur. Lüleburgaz''ın en önemli tarihi yapısıdır ve Osmanlı mimarisinin güzel bir örneğidir.", "place_query": "Sokullu Mehmet Paşa Külliyesi, Lüleburgaz, Kırklareli"}, {"title": "Lüleburgaz Kent Ormanı", "summary": "Şehir merkezine yakın, geniş yeşil alanları ve yürüyüş parkurlarıyla doğayla iç içe vakit geçirmek isteyenler için ideal bir dinlenme ve piknik alanıdır.", "place_query": "Lüleburgaz Kent Ormanı, Lüleburgaz, Kırklareli"}, {"title": "Lüleburgaz Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen müze, Trakya''nın tarihine ışık tutar. Ziyaretçilerine keyifli bir kültür gezisi sunar.", "place_query": "Lüleburgaz Müzesi, Lüleburgaz, Kırklareli"}, {"title": "Lüleburgaz Yıldızları Parkı", "summary": "Özellikle akşam saatlerinde aydınlatmasıyla dikkat çeken bu park, çocuk oyun alanları ve oturma gruplarıyla aileler için popüler bir buluşma noktasıdır.", "place_query": "Lüleburgaz Yıldızları Parkı, Lüleburgaz, Kırklareli"}, {"title": "Kırklareli Atatürk Evi (Lüleburgaz)", "summary": "Atatürk''ün Lüleburgaz ziyaretlerinde konakladığı tarihi ev, günümüzde müze olarak hizmet vermektedir. Kurtuluş Savaşı''na ait anılara ev sahipliği yapar.", "place_query": "Atatürk Evi, Lüleburgaz, Kırklareli"}, {"title": "Lüleburgaz Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin ve taze meyve-sebzenin satıldığı renkli bir pazar yeridir. Trakya kültürünü yakından tanımak için ideal bir duraktır.", "place_query": "Lüleburgaz Kapalı Pazar Yeri, Lüleburgaz, Kırklareli"}, {"title": "Lüleburgaz Şehir Stadı ve Çevresi", "summary": "Spor etkinlikleri ve açık hava yürüyüşleri için kullanılan bu alan, şehrin dinamik noktalarından biridir. Çevresindeki kafelerle sosyalleşme imkanı sunar.", "place_query": "Lüleburgaz Şehir Stadı, Lüleburgaz, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7d6efe80-8a29-4a50-a80a-fe08725c6f34'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kırklareli Müzesi", "summary": "Bölgenin zengin tarihini ve kültürel mirasını sergileyen bu müze, arkeolojik eserler ve etnografik objelerle ziyaretçilerine keyifli bir geçmiş yolculuğu sunuyor.", "place_query": "Kırklareli Müzesi, Merkez, Kırklareli"}, {"title": "Dupnisa Mağarası", "summary": "Türkiye''nin en önemli mağaralarından biri olan Dupnisa, etkileyici sarkıt ve dikitleriyle doğa severler için benzersiz bir yer altı keşif imkanı sağlıyor.", "place_query": "Dupnisa Mağarası, Kırklareli"}, {"title": "Kırklareli Tarihi Saat Kulesi", "summary": "Şehrin simgesi haline gelmiş bu zarif saat kulesi, 19. yüzyıl Osmanlı mimarisini yansıtarak meydana karakteristik bir hava katmaktadır.", "place_query": "Kırklareli Saat Kulesi, Merkez, Kırklareli"}, {"title": "Kırklareli Atatürk Evi", "summary": "Mustafa Kemal Atatürk''ün ziyaretleri sırasında kullandığı bu tarihi ev, günümüzde müze olarak hizmet veriyor ve dönemin atmosferini yansıtan eşyalarla doludur.", "place_query": "Kırklareli Atatürk Evi, Merkez, Kırklareli"}, {"title": "Kıyıköy (Kıyıköy Plajı ve Manastırı)", "summary": "Karadeniz kıyısındaki bu şirin kasaba, hem doğal plajlarıyla deniz keyfi sunar hem de kayalara oyulmuş tarihi Aya Nikola Manastırı ile kültür turizmine hitap eder.", "place_query": "Kıyıköy, Vize, Kırklareli"}, {"title": "İğneada Longoz Ormanları", "summary": "Avrupa''nın en büyük longoz (subasar) ormanlarından biri olan bu eşsiz ekosistem, yürüyüş parkurları ve kuş gözlemi için doğa tutkunlarının uğrak noktasıdır.", "place_query": "İğneada Longoz Ormanları, Demirköy, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bc5295a9-d975-4321-9cb4-4cba40f2e2d0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pehlivanköy Tren İstasyonu", "summary": "Tarihi bir tren istasyonu olan bu yapı, Pehlivanköy''ün simgesi haline gelmiştir. Özellikle demiryolu meraklıları ve nostalji sevenler için keyifli bir durak noktasıdır.", "place_query": "Pehlivanköy Tren İstasyonu, Pehlivanköy, Kırklareli"}, {"title": "Pehlivanköy Köprüsü", "summary": "Tarihi bir taş köprü olup, ilçenin önemli kültürel miraslarından biridir. Çevresindeki doğal alan, fotoğrafçılık ve kısa yürüyüşler için idealdir.", "place_query": "Pehlivanköy Köprüsü, Pehlivanköy, Kırklareli"}, {"title": "Pehlivanköy Merkez Camii", "summary": "İlçe merkezinde bulunan bu cami, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de tarihi bir yapı olarak ziyaretçilerin ilgisini çeker.", "place_query": "Pehlivanköy Merkez Camii, Pehlivanköy, Kırklareli"}, {"title": "Pehlivanköy Atatürk Anıtı", "summary": "İlçe meydanında yer alan bu anıt, Atatürk''ün bölgeye verdiği önemi simgeler. Çevresi, dinlenmek ve şehir turu yapmak için uygun bir alandır.", "place_query": "Pehlivanköy Atatürk Anıtı, Pehlivanköy, Kırklareli"}, {"title": "Pehlivanköy Doğa Yürüyüşü Rotaları", "summary": "İlçe çevresindeki kırsal alanlar, doğa yürüyüşü ve bisiklet turları için idealdir. Özellikle Ergene Nehri kıyısındaki patikalar, huzurlu bir doğa deneyimi sunar.", "place_query": "Pehlivanköy doğa yürüyüşü rotaları, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '612dddb1-e91f-4df5-948b-1224a7a84cd3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pınarhisar Kalesi", "summary": "Tarihi bir Bizans kalesi olan yapı, şehrin simgesi konumundadır. Tepeden çevreyi kuşbakışı görmek ve tarihi dokuyu hissetmek için en ideal noktadır.", "place_query": "Pınarhisar Kalesi, Pınarhisar, Kırklareli"}, {"title": "Pınarhisar Mağarası", "summary": "Doğal oluşumu ve içindeki sarkıt-dikitleriyle dikkat çeken bu mağara, doğa severler ve mağara araştırmacıları için popüler bir duraktır.", "place_query": "Pınarhisar Mağarası, Pınarhisar, Kırklareli"}, {"title": "Kaynarca Göleti", "summary": "Piknik ve doğa yürüyüşleri için tercih edilen bu gölet, huzurlu atmosferi ve yeşil çevresiyle hafta sonu kaçamaklarının vazgeçilmezidir.", "place_query": "Kaynarca Göleti, Pınarhisar, Kırklareli"}, {"title": "Pınarhisar Kent Ormanı", "summary": "Şehir merkezine yakın konumuyla kolay ulaşılabilen bu ormanlık alan, yürüyüş parkurları ve temiz havasıyla doğayla iç içe vakit geçirmek isteyenler için idealdir.", "place_query": "Pınarhisar Kent Ormanı, Pınarhisar, Kırklareli"}, {"title": "Pınarhisar Atatürk Evi", "summary": "Mustafa Kemal Atatürk''ün bir dönem konakladığı bu tarihi ev, günümüzde müze olarak ziyaretçilere açıktır ve milli tarihe tanıklık eden önemli bir yapıdır.", "place_query": "Pınarhisar Atatürk Evi, Pınarhisar, Kırklareli"}, {"title": "Erenler Tabiat Parkı", "summary": "Pınarhisar sınırları içinde yer alan bu tabiat parkı, zengin bitki örtüsü ve kamp alanlarıyla doğa tutkunlarının uğrak noktasıdır.", "place_query": "Erenler Tabiat Parkı, Pınarhisar, Kırklareli"}, {"title": "Pınarhisar Merkez Camii", "summary": "Osmanlı dönemi mimarisini yansıtan bu tarihi cami, ilçenin en eski ve en bilinen ibadethanelerinden biridir.", "place_query": "Pınarhisar Merkez Camii, Pınarhisar, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c9ff6d41-7a13-4728-9066-b82601d5a4cb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Vize Kalesi ve Tarihi Surlar", "summary": "Bizans ve Osmanlı dönemlerinden izler taşıyan bu etkileyici kale, Vize''nin simgesi konumundadır. Şehrin tepesine kurulu surlar ve burçlar, ziyaretçilere hem tarihi bir yolculuk hem de panoramik manzaralar sunar.", "place_query": "Vize Kalesi, Vize, Kırklareli"}, {"title": "Vize Antik Tiyatrosu", "summary": "Trakya''nın en önemli antik kalıntılarından biri olan bu tiyatro, Roma dönemine ait ender yapılardandır. Hâlâ ayakta duran oturma sıraları ve sahne binası, tarih meraklıları için büyüleyici bir duraktır.", "place_query": "Vize Antik Tiyatro, Vize, Kırklareli"}, {"title": "Vize Müzesi", "summary": "Küçük ama zengin koleksiyonuyla dikkat çeken müze, bölgedeki arkeolojik kazılardan çıkarılan eserleri ve etnografik objeleri sergiler. Trakya uygarlıklarının izlerini yakından görmek için ideal bir noktadır.", "place_query": "Vize Müzesi, Vize, Kırklareli"}, {"title": "Kıyıköy (Midye) Kasabası", "summary": "Vize ilçesine bağlı bu tarihi balıkçı kasabası, Karadeniz kıyısındaki doğal güzellikleri ve eski Rum evleriyle ünlüdür. Ayrıca Kıyıköy Kalesi ve Aya Nikola Manastırı''nı da keşfedebilirsiniz.", "place_query": "Kıyıköy, Vize, Kırklareli"}, {"title": "Kıyıköy Mağarası", "summary": "Kıyıköy yakınlarındaki bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. İçerideki küçük göl ve serin atmosfer, doğa yürüyüşü sevenler için keyifli bir keşif sunar.", "place_query": "Kıyıköy Mağarası, Vize, Kırklareli"}, {"title": "Büyük Mandıra Şelalesi", "summary": "Vize ormanları içinde gizlenmiş bu şelale, yeşillikler arasında huzurlu bir kaçış noktasıdır. Özellikle bahar aylarında coşan suyu ve çevresindeki piknik alanlarıyla doğaseverlerin uğrak yeridir.", "place_query": "Büyük Mandıra Şelalesi, Vize, Kırklareli"}, {"title": "Dupnisa Mağarası", "summary": "Türkiye''nin en önemli mağaralarından biri olan Dupnisa, ziyaretçilere açık üç katlı yapısıyla büyüleyicidir. İçindeki göller, sarkıt ve dikitler, doğa harikası bir yer altı dünyası sunar.", "place_query": "Dupnisa Mağarası, Vize, Kırklareli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '12087e9d-a1d8-43c8-8632-e888d7250e6c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akçakent Merkez Camii", "summary": "İlçenin merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin sade ve huzurlu bir örneğidir. Ziyaretçiler hem ibadet edebilir hem de yapının tarihi dokusunu gözlemleyebilir.", "place_query": "Akçakent Merkez Camii, Kırşehir"}, {"title": "Akçakent Kalesi", "summary": "İlçe merkezine yakın bir tepede bulunan bu tarihi kale kalıntıları, bölgenin stratejik önemini gözler önüne serer. Tepeden çevreyi seyretmek için güzel bir noktadır.", "place_query": "Akçakent Kalesi, Kırşehir"}, {"title": "Seyfe Gölü", "summary": "Kırşehir''in önemli sulak alanlarından biri olan Seyfe Gölü, kuş gözlemciliği için idealdir. Özellikle ilkbahar ve sonbaharda göçmen kuşlara ev sahipliği yapar.", "place_query": "Seyfe Gölü, Kırşehir"}, {"title": "Akçakent Yaylası", "summary": "Doğal güzellikleri ve temiz havasıyla bilinen yayla, piknik ve doğa yürüyüşü için tercih edilir. Yaz aylarında serinlemek ve şehir gürültüsünden uzaklaşmak için idealdir.", "place_query": "Akçakent Yaylası, Kırşehir"}, {"title": "Kalealtı Mağarası", "summary": "Akçakent sınırları içinde yer alan bu doğal mağara, ilginç kaya oluşumları ve serin atmosferiyle dikkat çeker. Doğa sporları ve keşif meraklıları için uygun bir duraktır.", "place_query": "Kalealtı Mağarası, Akçakent, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b90f2c72-f3cc-4b72-8bb6-a551e265bd67'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Seyfe Gölü Tabiatı Koruma Alanı", "summary": "Kırşehir''in en önemli sulak alanlarından biri olan Seyfe Gölü, kuş gözlemcileri ve doğa severler için harika bir duraktır. Birçok kuş türüne ev sahipliği yapan bu alan, huzurlu atmosferi ve eşsiz manzarasıyla ziyaretçilerini büyüler.", "place_query": "Seyfe Gölü Tabiatı Koruma Alanı, Akpınar, Kırşehir"}, {"title": "Kırşehir Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan Kırşehir Kalesi, tarihi dokusu ve panoramik şehir manzarasıyla görülmeye değerdir. Kalenin çevresinde yürüyüş yapabilir ve Kırşehir''in tarihine tanıklık edebilirsiniz.", "place_query": "Kırşehir Kalesi, Kırşehir Merkez"}, {"title": "Cacabey Medresesi (Gök Medrese)", "summary": "Anadolu Selçuklu dönemine ait bu eşsiz yapı, astronomi ve fen bilimleri medresesi olarak inşa edilmiştir. Gök Medrese olarak da bilinen yapı, döneminin ileri mimari ve bilim anlayışını yansıtan önemli bir tarihi eserdir.", "place_query": "Cacabey Medresesi, Kırşehir Merkez"}, {"title": "Aşıkpaşa Türbesi ve Anıt Mezarı", "summary": "Ünlü Türk şairi ve mutasavvıfı Aşıkpaşa''nın anısına yapılan bu türbe, Kırşehir''in manevi ve kültürel mirasının önemli bir parçasıdır. Ziyaretçiler, burada hem tarihi bir atmosfer soluyabilir hem de Aşıkpaşa''nın eserleri hakkında bilgi alabilir.", "place_query": "Aşıkpaşa Türbesi, Kırşehir Merkez"}, {"title": "Kaman Kalehöyük Arkeoloji Müzesi", "summary": "Kaman ilçesinde bulunan bu müze, bölgenin zengin tarihini gözler önüne seren önemli bir arkeoloji merkezidir. Müzede, höyük kazılarında çıkarılan eserler sergilenmekte olup, tarih meraklıları için kaçırılmaması gereken bir duraktır.", "place_query": "Kaman Kalehöyük Arkeoloji Müzesi, Kaman, Kırşehir"}, {"title": "Kırşehir Müzesi", "summary": "Şehir merkezinde bulunan Kırşehir Müzesi, Hitit, Frig, Roma ve Bizans dönemlerine ait arkeolojik eserlerin yanı sıra etnografik objeleri de sergilemektedir. Bölgenin kültürel birikimini yakından tanımak için ideal bir noktadır.", "place_query": "Kırşehir Müzesi, Kırşehir Merkez"}, {"title": "Kesikköprü Barajı ve Çevresi", "summary": "Kırşehir''in doğal güzelliklerinden biri olan Kesikköprü Barajı, piknik alanları ve yeşil doğasıyla hafta sonu kaçamakları için popüler bir yerdir. Baraj çevresinde yürüyüş yapabilir, kuş sesleri eşliğinde huzurlu vakit geçirebilirsiniz.", "place_query": "Kesikköprü Barajı, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ab47c2b1-b616-4ca9-a664-eaff9af1a93e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kırşehir Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, Kırşehir manzarasını izlemek için en güzel noktalardan biridir. Hititlerden Osmanlı''ya kadar birçok medeniyete ev sahipliği yapmış olup, özellikle gün batımında eşsiz bir atmosfere sahiptir.", "place_query": "Kırşehir Kalesi, Kırşehir Merkez"}, {"title": "Cacabey Medresesi (Gök Medrese)", "summary": "13. yüzyılda Selçuklu döneminde astronomi ve fen bilimleri okulu olarak inşa edilen bu medrese, dönemin en önemli eğitim kurumlarındandır. Gök rengi çinileri ve mimarisiyle dikkat çeker, günümüzde müze olarak hizmet vermektedir.", "place_query": "Cacabey Medresesi, Kırşehir Merkez"}, {"title": "Aşıkpaşa Türbesi", "summary": "Ünlü Türk halk şairi ve mutasavvıf Aşıkpaşa''nın anıt mezarı, Kırşehir''in manevi simgelerinden biridir. Türbe, şairin Garibnâme adlı eserine ithafen ziyaretçilere açık olup, çevresi huzurlu bir dinlenme alanıdır.", "place_query": "Aşıkpaşa Türbesi, Kırşehir Merkez"}, {"title": "Kaman Kalehöyük Arkeoloji Müzesi", "summary": "Boztepe ilçesine bağlı Kaman''da bulunan bu müze, bölgedeki kazılardan çıkarılan Hitit, Frig ve Roma dönemine ait eserleri sergiler. Açık hava müzesi konseptiyle ziyaretçilere tarih öncesi dönemleri keşfetme fırsatı sunar.", "place_query": "Kaman Kalehöyük Arkeoloji Müzesi, Kaman, Kırşehir"}, {"title": "Hirfanlı Baraj Gölü", "summary": "Kırşehir sınırları içinde yer alan bu büyük baraj gölü, doğal güzelliği ve kuş gözlemciliği için ideal bir noktadır. Özellikle ilkbahar ve yaz aylarında piknik, balıkçılık ve tekne turları için popüler bir destinasyondur.", "place_query": "Hirfanlı Baraj Gölü, Kırşehir"}, {"title": "Kırşehir Müzesi", "summary": "Şehir merkezinde bulunan bu müze, Neolitik dönemden Osmanlı''ya kadar uzanan geniş bir eser koleksiyonuna sahiptir. Arkeoloji ve etnografya bölümleriyle Kırşehir''in kültürel mirasını yakından tanıma imkanı sunar.", "place_query": "Kırşehir Müzesi, Kırşehir Merkez"}, {"title": "Kesikköprü Köprüsü", "summary": "Kırşehir''in Mucur ilçesi yakınlarında bulunan bu tarihi köprü, Roma döneminden günümüze ulaşmış önemli bir yapıdır. Kızılırmak üzerinde yer alan köprü, özellikle fotoğrafçılar için etkileyici bir manzara sunar.", "place_query": "Kesikköprü Köprüsü, Mucur, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '022d7dfc-f44f-43a9-818a-9a52ce6dc126'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çiçekdağı Kalesi", "summary": "Tarihi bir kaledir ve ilçeye hakim bir tepede yer alır. Çevresindeki manzarasıyla ziyaretçilerine güzel bir seyir imkanı sunar.", "place_query": "Çiçekdağı Kalesi, Çiçekdağı, Kırşehir"}, {"title": "Çiçekdağı Kaplıcaları", "summary": "Termal sularıyla ünlü olan bu kaplıcalar, şifalı suları ve dinlendirici atmosferiyle sağlık turizmi için popüler bir duraktır.", "place_query": "Çiçekdağı Kaplıcaları, Çiçekdağı, Kırşehir"}, {"title": "Kalealtı Mağarası", "summary": "Doğal oluşumuyla dikkat çeken bu mağara, ilçe merkezine yakın konumuyla doğa severlerin keşfetmekten keyif aldığı bir noktadır.", "place_query": "Kalealtı Mağarası, Çiçekdağı, Kırşehir"}, {"title": "Seyfe Gölü (Yakın Çevre)", "summary": "Çiçekdağı''na yakın mesafede bulunan Seyfe Gölü, kuş gözlemciliği ve doğal güzellikleriyle öne çıkan bir sulak alandır.", "place_query": "Seyfe Gölü, Kırşehir"}, {"title": "Çiçekdağı Yaylası", "summary": "Yeşil doğası ve temiz havasıyla yayla, özellikle yaz aylarında piknik ve doğa yürüyüşü için tercih edilen bir mekandır.", "place_query": "Çiçekdağı Yaylası, Çiçekdağı, Kırşehir"}, {"title": "Çiçekdağı Merkez Camii", "summary": "Mimari yapısıyla dikkat çeken tarihi cami, ilçenin merkezinde yer alır ve hem ibadet hem de kültürel ziyaretler için önemli bir noktadır.", "place_query": "Çiçekdağı Merkez Camii, Çiçekdağı, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4a321723-2bf9-4703-8e9f-d902e7f4d0d6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kalehöyük Arkeoloji Müzesi", "summary": "Kaman''ın en önemli tarihi merkezi olan Kalehöyük''te yer alan bu müze, bölgedeki kazılarda çıkarılan Hitit, Frig ve Roma dönemine ait eserleri sergiliyor. Açık hava müzesi konseptiyle ziyaretçilere eşsiz bir tarih yolculuğu sunuyor.", "place_query": "Kalehöyük Arkeoloji Müzesi, Kaman, Kırşehir"}, {"title": "Kaman Çağırkan Kalesi", "summary": "Doğal kaya oluşumları üzerine inşa edilmiş bu tarihi kale, muhteşem manzarası ve stratejik konumuyla dikkat çekiyor. Çevresindeki yeşil alanlar piknik ve doğa yürüyüşleri için idealdir.", "place_query": "Çağırkan Kalesi, Kaman, Kırşehir"}, {"title": "Seyfe Gölü Tabiat Parkı", "summary": "Kaman yakınlarındaki bu kuş cenneti, özellikle flamingo ve yaban ördeği gibi su kuşlarına ev sahipliği yapıyor. Doğa fotoğrafçıları ve kuş gözlemcileri için harika bir durak.", "place_query": "Seyfe Gölü Tabiat Parkı, Kaman, Kırşehir"}, {"title": "Kaman İçma Suyu (Maden Suyu) Tesisleri", "summary": "Doğal maden suyu kaynaklarıyla ünlü Kaman''da, bu tesislerde şifalı suları tadabilir ve dinlenme alanlarında vakit geçirebilirsiniz. Bölge halkı tarafından sağlık amaçlı sıkça ziyaret edilir.", "place_query": "Kaman İçma Suyu, Kaman, Kırşehir"}, {"title": "Kaman Yeraltı Şehri", "summary": "Hitit dönemine ait olduğu düşünülen bu yeraltı şehri, dar koridorları ve odalarıyla keşfedilmeyi bekliyor. Tarih meraklıları için gizemli bir atmosfer sunuyor.", "place_query": "Kaman Yeraltı Şehri, Kaman, Kırşehir"}, {"title": "Kaman Cevizli Köyü Göleti", "summary": "Doğayla iç içe huzurlu bir gün geçirmek isteyenler için ideal olan bu gölet, çevresindeki piknik alanları ve yürüyüş yollarıyla popülerdir. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Cevizli Köyü Göleti, Kaman, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f47ded4-4d72-422e-aca8-cdd84bf1734c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kırşehir Kalesi", "summary": "Şehir merkezinde yüksek bir tepe üzerinde yer alan tarihi kale, Kırşehir''in simgelerinden biridir. Kaleye çıktığınızda şehri kuşbakışı izleyebilir, tarihi dokuyu hissedebilirsiniz.", "place_query": "Kırşehir Kalesi, Merkez, Kırşehir"}, {"title": "Ahi Evran Camii ve Türbesi", "summary": "Ahilik teşkilatının kurucusu Ahi Evran-ı Veli''nin türbesini barındıran bu külliyede, hem manevi bir atmosfer yaşayabilir hem de tarihi camiyi ziyaret edebilirsiniz.", "place_query": "Ahi Evran Camii ve Türbesi, Merkez, Kırşehir"}, {"title": "Cacabey Medresesi (Gökbilim Medresesi)", "summary": "Anadolu''daki ilk astronomi medreselerinden biri olan bu yapı, Selçuklu dönemine ait eşsiz bir eserdir. Gök bilimleri eğitimi için inşa edilen medrese, mimarisiyle de dikkat çeker.", "place_query": "Cacabey Medresesi, Merkez, Kırşehir"}, {"title": "Kırşehir Müzesi", "summary": "Hitit, Frig, Roma ve Bizans dönemlerine ait arkeolojik eserlerin yanı sıra etnografik objelerin sergilendiği müze, bölgenin zengin tarihine ışık tutar.", "place_query": "Kırşehir Müzesi, Merkez, Kırşehir"}, {"title": "Kaman Kalehöyük ve Arkeoloji Müzesi", "summary": "Kaman ilçesinde bulunan bu höyük, bölgenin en önemli arkeolojik kazı alanlarından biridir. Yanındaki Japon Anadolu Arkeoloji Müzesi''nde ise kazılarda çıkan eserler sergilenmektedir.", "place_query": "Kaman Kalehöyük Arkeoloji Müzesi, Kaman, Kırşehir"}, {"title": "Seyfe Gölü Kuş Cenneti", "summary": "Kırşehir''in Mucur ilçesi yakınlarında bulunan bu doğal göl, birçok kuş türüne ev sahipliği yapar. Doğa fotoğrafçıları ve kuş gözlemcileri için ideal bir noktadır.", "place_query": "Seyfe Gölü Kuş Cenneti, Mucur, Kırşehir"}, {"title": "Aşıkpaşa Türbesi", "summary": "Ünlü Türk şairi ve mutasavvıfı Aşık Paşa''nın türbesi, Kırşehir''deki önemli kültürel ziyaret noktalarından biridir. Türbe, sade bir mimariye sahip olup manevi bir atmosfer sunar.", "place_query": "Aşıkpaşa Türbesi, Merkez, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b52a1796-e738-42b3-b1e2-720a790952ad'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Obruk Hanı", "summary": "Selçuklu döneminden kalma tarihi bir kervansaray olan Obruk Hanı, taş işçiliği ve görkemli mimarisiyle dikkat çeker. Mucur''un en önemli tarihi yapılarından biridir.", "place_query": "Obruk Hanı, Mucur, Kırşehir"}, {"title": "Mucur Yeraltı Şehri", "summary": "Kayalar oyularak yapılmış bu yeraltı şehri, erken Hristiyanlık döneminde sığınak olarak kullanılmıştır. Dar koridorları ve odalarıyla keşfedilmeyi bekleyen gizemli bir yapıdır.", "place_query": "Mucur Yeraltı Şehri, Mucur, Kırşehir"}, {"title": "Kesikköprü Barajı ve Mesire Alanı", "summary": "Kesikköprü Barajı çevresindeki yeşil alanlar ve piknik masaları, doğayla iç içe huzurlu bir gün geçirmek isteyenler için idealdir. Baraj manzarası eşliğinde yürüyüş yapabilir veya balık tutabilirsiniz.", "place_query": "Kesikköprü Barajı Mesire Alanı, Mucur, Kırşehir"}, {"title": "Mucur Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan Mucur Kalesi, bölgeye hakim bir manzara sunar. Kalıntıları günümüze ulaşan kale, hem tarih meraklıları hem de fotoğrafçılar için güzel bir duraktır.", "place_query": "Mucur Kalesi, Mucur, Kırşehir"}, {"title": "Seyfe Gölü", "summary": "Mucur sınırları içinde yer alan Seyfe Gölü, kuş gözlemciliği için önemli bir sulak alandır. Özellikle ilkbahar ve sonbaharda göçmen kuşlara ev sahipliği yapar, doğaseverler için eşsiz bir rotadır.", "place_query": "Seyfe Gölü, Mucur, Kırşehir"}, {"title": "Mucur Kapalı Çarşısı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu tarihi çarşı, Mucur''un kültürel dokusunu yansıtır. Özellikle el dokuması halı ve kilimleriyle ünlüdür.", "place_query": "Mucur Kapalı Çarşısı, Mucur, Kırşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'af3be348-174f-4a1e-9ab5-0cdf6c7df6b7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Maşukiye Yaylası", "summary": "Yeşilin her tonunu barındıran bu yayla, şelaleleri ve yürüyüş parkurlarıyla doğa severler için ideal bir kaçış noktasıdır. Özellikle hafta sonları piknik ve dinlenmek için sıkça tercih edilir.", "place_query": "Maşukiye Yaylası, Başiskele, Kocaeli"}, {"title": "Kartepe Kayak Merkezi", "summary": "Kocaeli''nin en yüksek noktalarından biri olan Kartepe, kış aylarında kayak ve snowboard yapmak isteyenlerin uğrak yeridir. Yazın ise doğa yürüyüşü ve yamaç paraşütü gibi aktiviteler sunar.", "place_query": "Kartepe Kayak Merkezi, Kocaeli"}, {"title": "Başiskele Sahil Parkı ve Yürüyüş Yolu", "summary": "İzmit Körfezi manzaralı bu sahil şeridi, yürüyüş ve bisiklet yolları ile dinlenme alanları sunar. Gün batımında eşsiz bir manzaraya sahip olup, aileler için huzurlu bir ortamdır.", "place_query": "Başiskele Sahil Parkı, Kocaeli"}, {"title": "Sapanca Gölü (Kocaeli Kıyıları)", "summary": "Başiskele sınırlarına yakın olan Sapanca Gölü''nün kuzey kıyıları, piknik alanları ve göl manzaralı kafeleriyle ünlüdür. Su sporları ve doğa fotoğrafçılığı için popüler bir destinasyondur.", "place_query": "Sapanca Gölü, Kocaeli kıyıları"}, {"title": "Servetiye Cami ve Tarihi Çınar Ağacı", "summary": "Osmanlı döneminden kalma bu tarihi cami, yanındaki dev çınar ağacıyla birlikte huzurlu bir atmosfer sunar. Bölgenin kültürel mirasını yansıtan önemli bir durak noktasıdır.", "place_query": "Servetiye Cami, Başiskele, Kocaeli"}, {"title": "Kiraz Dağları Tabiat Parkı", "summary": "Yoğun ormanlık alanı ve temiz havasıyla doğa yürüyüşçülerinin favori rotalarındandır. Kamp yapmak ve şehir gürültüsünden uzaklaşmak için idealdir.", "place_query": "Kiraz Dağları Tabiat Parkı, Başiskele, Kocaeli"}, {"title": "Ballıkaya Tabiat Parkı", "summary": "Şelaleleri ve zengin bitki örtüsüyle dikkat çeken bu tabiat parkı, piknik alanları ve yürüyüş parkurları ile doğa tutkunlarını ağırlar. Özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Ballıkaya Tabiat Parkı, Başiskele, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'eac77fce-2793-46aa-bac5-6cf581b4d94a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çayırova Belediyesi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme ve piknik noktasıdır.", "place_query": "Çayırova Millet Bahçesi, Çayırova, Kocaeli"}, {"title": "Çayırova Cumhuriyet Parkı", "summary": "İlçenin merkezinde yer alan bu park, spor alanları ve sosyal tesisleriyle günlük geziler için popüler bir mekandır.", "place_query": "Cumhuriyet Parkı, Çayırova, Kocaeli"}, {"title": "Gebze Eskihisar Kalesi", "summary": "Çayırova''ya kısa mesafedeki bu tarihi Bizans kalesi, muhteşem deniz manzarası ve Osman Hamdi Bey Müzesi ile kültürel bir duraktır.", "place_query": "Eskihisar Kalesi, Gebze, Kocaeli"}, {"title": "Osman Hamdi Bey Müzesi (Eskihisar)", "summary": "Ünlü ressam ve arkeolog Osman Hamdi Bey''in restore edilmiş evi olan müze, kişisel eşyaları ve tarihi atmosferiyle ziyaretçileri cezbeder.", "place_query": "Osman Hamdi Bey Müzesi, Eskihisar, Gebze, Kocaeli"}, {"title": "Ballıkayalar Tabiat Parkı", "summary": "Tavşanlı vadisinde bulunan bu doğal park, kanyon yürüyüşleri, şelaleler ve kaya tırmanışı imkanıyla doğa severler için harika bir kaçış noktasıdır.", "place_query": "Ballıkayalar Tabiat Parkı, Gebze, Kocaeli"}, {"title": "Hünkar Çayırı Tabiat Parkı", "summary": "Gebze sınırlarındaki bu geniş mesire alanı, piknik alanları ve yürüyüş yollarıyla hafta sonu kaçamakları için sık tercih edilir.", "place_query": "Hünkar Çayırı Tabiat Parkı, Gebze, Kocaeli"}, {"title": "Darıca Hayvanat Bahçesi ve Botanik Parkı", "summary": "Çayırova''ya yakın bu büyük hayvanat bahçesi, yüzlerce hayvan türü ve bitki çeşitliliğiyle özellikle çocuklu aileler için popüler bir gezi rotasıdır.", "place_query": "Darıca Hayvanat Bahçesi, Darıca, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4a4ed60a-b8c6-497a-b583-e07db30a25ff'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Darıca Hayvanat Bahçesi (Darıca Faruk Yalçın Hayvanat Bahçesi ve Botanik Parkı)", "summary": "Türkiye''nin en eski ve en büyük özel hayvanat bahçelerinden biridir. 200''den fazla türde binlerce hayvanı barındıran park, aynı zamanda geniş botanik bahçesi ve çocuk oyun alanlarıyla aileler için ideal bir günübirlik gezi noktasıdır.", "place_query": "Darıca Faruk Yalçın Hayvanat Bahçesi ve Botanik Parkı, Darıca, Kocaeli"}, {"title": "Darıca Sahili ve Sahil Bandı", "summary": "Marmara Denizi kıyısında uzanan düzenlenmiş sahil yürüyüş yolu, bisiklet parkuru ve yeşil alanlarıyla bilinir. Özellikle gün batımında keyifli bir yürüyüş yapabilir, deniz manzarası eşliğinde dinlenebilirsiniz.", "place_query": "Darıca Sahili, Darıca, Kocaeli"}, {"title": "Darıca Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları, göleti ve çocuk oyun alanlarıyla şehrin ortasında bir nefes alma noktasıdır. Ailece piknik yapmak veya doğayla iç içe vakit geçirmek için sıkça tercih edilir.", "place_query": "Darıca Millet Bahçesi, Darıca, Kocaeli"}, {"title": "Darıca Merkez Camii ve Külliyesi", "summary": "Modern Osmanlı mimarisiyle inşa edilmiş bu büyük cami, Darıca''nın simge yapılarından biridir. Geniş avlusu ve çevresindeki külliyesiyle hem ibadet hem de ziyaret amaçlı uğranabilecek huzurlu bir mekandır.", "place_query": "Darıca Merkez Camii, Darıca, Kocaeli"}, {"title": "Eskihisar Kalesi (Darıca Eskihisar)", "summary": "Darıca sınırları içinde yer alan tarihi bir Bizans kalesidir. Deniz kıyısındaki konumu ve surlarıyla fotoğrafçılar için güzel kareler sunar; ayrıca çevredeki balıkçı barınağı ve sahiliyle de gezilebilir.", "place_query": "Eskihisar Kalesi, Darıca, Kocaeli"}, {"title": "Darıca Piri Reis Parkı", "summary": "Ünlü Osmanlı denizcisi Piri Reis''in adını taşıyan bu park, deniz temalı oyun alanları ve yeşil dokusuyla çocuklu aileler için keyifli bir duraktır. Park içinde Piri Reis''e ait bir büst ve bilgilendirici panolar da bulunur.", "place_query": "Piri Reis Parkı, Darıca, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bdbdc00f-10c8-4b0d-8b24-6182762338e1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Derince Sahil Parkı", "summary": "Derince''nin en popüler dinlenme ve yürüyüş alanıdır. Uzun sahil şeridinde yürüyüş yapabilir, deniz manzarası eşliğinde çayınızı yudumlayabilirsiniz.", "place_query": "Derince Sahil Parkı, Derince, Kocaeli"}, {"title": "Derince Belediyesi Kültür Merkezi", "summary": "İlçenin önemli kültür ve sanat merkezlerinden biridir. Tiyatro oyunları, konserler ve çeşitli etkinliklere ev sahipliği yapmaktadır.", "place_query": "Derince Belediyesi Kültür Merkezi, Derince, Kocaeli"}, {"title": "Derince Harikalar Sahili", "summary": "Aileler için keyifli bir gezi noktasıdır. Çocuk oyun alanları, kafeleri ve yeşil alanlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Harikalar Sahili, Derince, Kocaeli"}, {"title": "Çenedağ Tabiat Parkı", "summary": "Derince sınırları içinde yer alan bu tabiat parkı, doğa yürüyüşleri ve piknik için popüler bir destinasyondur. Şehir gürültüsünden uzaklaşmak isteyenler için biçilmiş kaftandır.", "place_query": "Çenedağ Tabiat Parkı, Derince, Kocaeli"}, {"title": "Derince Yelken Kulübü", "summary": "Deniz sporlarına ilgi duyanlar için önemli bir merkezdir. Yelken ve kürek gibi aktivitelerin yanı sıra, kulüp bünyesindeki restoranıyla da sosyal bir ortam sunar.", "place_query": "Derince Yelken Kulübü, Derince, Kocaeli"}, {"title": "Derince Merkez Camii", "summary": "Modern Osmanlı mimarisiyle dikkat çeken bu cami, ilçenin simge yapılarından biridir. Geniş avlusu ve etkileyici kubbesiyle ziyaretçilerini büyüler.", "place_query": "Derince Merkez Camii, Derince, Kocaeli"}, {"title": "Derince Pazar Yeri", "summary": "Yöresel ürünler ve taze meyve-sebze almak isteyenler için canlı bir alışveriş noktasıdır. Pazar günleri kurulan bu büyük pazarda, yöresel lezzetleri de bulabilirsiniz.", "place_query": "Derince Pazarı, Derince, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '71b1c416-c30f-4a32-ae12-5e40c8499a78'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dilovası Sahili ve Yürüyüş Yolu", "summary": "İzmit Körfezi manzarası eşliğinde yürüyüş yapabileceğiniz, dinlenme alanları ve kafeleriyle halkın uğrak noktasıdır. Özellikle gün batımında manzarası keyiflidir.", "place_query": "Dilovası Sahil Yolu, Kocaeli"}, {"title": "Eskihisar Kalesi", "summary": "Dilovası sınırları içinde yer alan tarihi bir Bizans kalesidir. Deniz kıyısındaki konumu ve restore edilmiş yapısıyla ziyaretçilere tarih ve doğa iç içe bir deneyim sunar.", "place_query": "Eskihisar Kalesi, Gebze, Kocaeli"}, {"title": "Ballıkayalar Tabiat Parkı", "summary": "Dilovası''na yakın konumdaki bu tabiat parkı, derin vadileri, şelaleleri ve kaya tırmanışı rotalarıyla doğa sporları ve piknik için idealdir. Özellikle hafta sonu doğa kaçamaklarında tercih edilir.", "place_query": "Ballıkayalar Tabiat Parkı, Kocaeli"}, {"title": "Dilovası Belediyesi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla aileler için huzurlu bir dinlenme noktasıdır. Şehir merkezine yakınlığıyla kolay ulaşılabilir.", "place_query": "Dilovası Millet Bahçesi, Kocaeli"}, {"title": "Hereke Kalesi", "summary": "Dilovası''na bağlı Hereke Mahallesi''nde bulunan tarihi bir kaledir. Körfez manzarasına hakim tepede yer alır ve bölgenin tarihi dokusunu yansıtır.", "place_query": "Hereke Kalesi, Kocaeli"}, {"title": "Dilovası Merkez Camii ve Külliyesi", "summary": "Modern Osmanlı mimarisiyle dikkat çeken bu külliye, geniş avlusu ve ibadet alanıyla bölgenin önemli dini yapılarındandır. Çevresindeki çarşıyla da ziyaretçi çeker.", "place_query": "Dilovası Merkez Camii, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '02172fc6-c9eb-4fd9-9faf-35fb0a5d445c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eskihisar Kalesi", "summary": "Bizans döneminden kalma tarihi bir kale olup, Gebze''nin simgelerindendir. Marmara Denizi kıyısında yer alır ve özellikle gün batımında muhteşem manzaralar sunar.", "place_query": "Eskihisar Kalesi, Gebze, Kocaeli"}, {"title": "Osman Hamdi Bey Müzesi (Eskihisar Köşkü)", "summary": "Ünlü ressam ve arkeolog Osman Hamdi Bey''in Gebze Eskihisar''daki yazlık evi olan bu köşk, günümüzde müze olarak ziyaretçilere açıktır. Sanatçının kişisel eşyaları ve eserleri sergilenmektedir.", "place_query": "Osman Hamdi Bey Müzesi, Gebze, Kocaeli"}, {"title": "Çoban Mustafa Paşa Külliyesi", "summary": "Kanuni Sultan Süleyman döneminde Mimar Sinan''a yaptırılan bu külliye, cami, medrese, hamam ve türbeden oluşur. Gebze''nin en önemli tarihi ve dini yapılarındandır.", "place_query": "Çoban Mustafa Paşa Külliyesi, Gebze, Kocaeli"}, {"title": "Ballıkayalar Tabiat Parkı", "summary": "Gebze''ye bağlı Tavşanlı köyü yakınlarında bulunan bu tabiat parkı, derin vadileri, kayalıkları ve şelalesiyle doğa yürüyüşü ve tırmanış için idealdir. Muhteşem bir doğal güzelliğe sahiptir.", "place_query": "Ballıkayalar Tabiat Parkı, Gebze, Kocaeli"}, {"title": "Hünkar Çayırı Tabiat Parkı", "summary": "Gebze sınırları içinde yer alan bu geniş mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek için popüler bir yerdir. İçinde tarihi bir kasır da bulunmaktadır.", "place_query": "Hünkar Çayırı Tabiat Parkı, Gebze, Kocaeli"}, {"title": "Gebze Sahil Bandı ve Marina", "summary": "Eskihisar ve Hereke arasında uzanan sahil şeridi, yürüyüş yolları, kafeleri ve marinasıyla keyifli bir gezinti alanıdır. Marmara Denizi manzarası eşliğinde dinlenme imkanı sunar.", "place_query": "Gebze Sahil Bandı, Kocaeli"}, {"title": "Hereke Kalesi", "summary": "Gebze''nin Hereke mahallesinde yer alan tarihi bir kaledir. Deniz kenarında konumlanmış olup, çevresindeki doğal güzelliklerle birlikte ziyaret edilebilir.", "place_query": "Hereke Kalesi, Gebze, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e5ac4aca-12c3-42bc-98c6-28ab808c3ab3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölcük Tabiat Parkı", "summary": "İlçeye adını veren doğal güzellik, yürüyüş yolları ve piknik alanlarıyla hafta sonu kaçamaklarının vazgeçilmezidir.", "place_query": "Gölcük Tabiat Parkı, Gölcük, Kocaeli"}, {"title": "Kavaklı Sahili", "summary": "Sahil şeridi boyunca uzanan yürüyüş yolu, kafeleri ve deniz manzarasıyla Gölcük''ün en popüler gezinti alanıdır.", "place_query": "Kavaklı Sahili, Gölcük, Kocaeli"}, {"title": "Değirmendere Sahil Parkı", "summary": "Deniz kenarında geniş yeşil alanları, çocuk oyun parkları ve balık restoranlarıyla aileler için ideal bir dinlenme noktasıdır.", "place_query": "Değirmendere Sahil Parkı, Gölcük, Kocaeli"}, {"title": "Gölcük Deniz Müzesi (Donanma Komutanlığı)", "summary": "Türk Deniz Kuvvetleri''ne ait tarihi araç ve gereçlerin sergilendiği müze, denizcilik tarihine ilgi duyanlar için eşsiz bir duraktır.", "place_query": "Gölcük Deniz Müzesi, Gölcük, Kocaeli"}, {"title": "Eski Hamam (Gölcük Merkez)", "summary": "Osmanlı döneminden kalma tarihi yapı, günümüzde restore edilerek kültürel etkinliklere ev sahipliği yapmaktadır.", "place_query": "Eski Hamam, Gölcük, Kocaeli"}, {"title": "Gölcük Belediyesi Kültür Merkezi", "summary": "Tiyatro, konser ve sergi gibi etkinliklerin düzenlendiği modern bir kültür merkezi olup ilçenin sanat hayatına canlılık katar.", "place_query": "Gölcük Belediyesi Kültür Merkezi, Gölcük, Kocaeli"}, {"title": "Kirazlı Yaylası", "summary": "Doğa yürüyüşleri ve kamp için ideal olan yayla, temiz havası ve yeşil örtüsüyle şehir gürültüsünden kaçmak isteyenler için biçilmiş kaftandır.", "place_query": "Kirazlı Yaylası, Gölcük, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '41d7965e-8e9c-4642-b183-7eeeefcdc867'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saat Kulesi", "summary": "İzmit''in simgesi haline gelmiş tarihi bir yapıdır. II. Abdülhamid döneminde yapılan kule, kent meydanında yer alır ve özellikle akşam ışıklandırmasıyla güzel bir atmosfer sunar.", "place_query": "İzmit Saat Kulesi, İzmit, Kocaeli"}, {"title": "Seka Kağıt Müzesi", "summary": "Türkiye''nin ilk kağıt fabrikasının dönüştürülmesiyle oluşturulmuş endüstriyel bir müzedir. Ziyaretçiler, kağıt üretim sürecini ve eski makineleri yakından görme fırsatı bulur.", "place_query": "Seka Kağıt Müzesi, İzmit, Kocaeli"}, {"title": "İzmit Marina ve Sahil Yolu", "summary": "Marmara Denizi kıyısında uzanan modern bir yürüyüş ve dinlenme alanıdır. Kafeleri, bisiklet yolları ve deniz manzarasıyla hem yerli halkın hem de turistlerin uğrak noktasıdır.", "place_query": "İzmit Marina, Kocaeli"}, {"title": "Kocaeli Arkeoloji ve Etnoğrafya Müzesi", "summary": "Tarihi bir tren garı binasında hizmet veren müze, bölgedeki antik kentlerden çıkarılan eserleri sergiler. Roma, Bizans ve Osmanlı dönemlerine ait objeler görülmeye değerdir.", "place_query": "Kocaeli Arkeoloji ve Etnoğrafya Müzesi, İzmit"}, {"title": "Ballıkayalar Tabiat Parkı", "summary": "İzmit merkeze yaklaşık 20 km uzaklıkta bulunan bu vadi, kanyon görünümü ve şelaleleriyle doğa yürüyüşü sevenler için idealdir. Kamp ve tırmanış aktiviteleri de yapılabilir.", "place_query": "Ballıkayalar Tabiat Parkı, Kocaeli"}, {"title": "Orhan Camii (Pertev Paşa Camii)", "summary": "Mimar Sinan''ın eseri olan 16. yüzyıl Osmanlı camisidir. Kesme taş işçiliği ve geniş avlusuyla dikkat çeker; şehrin en önemli tarihi ibadet yapılarından biridir.", "place_query": "Orhan Camii, İzmit, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1d8e4c64-5418-4ad3-af0d-1d43db8f7247'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kandıra Cebeci Plajı", "summary": "Karadeniz''in mavi sularına uzanan geniş kumsalı ve dalgasız deniziyle aileler için ideal bir plaj. Çevresindeki tesisler ve doğal güzelliğiyle yaz aylarının en popüler noktalarından biridir.", "place_query": "Cebeci Plajı, Kandıra, Kocaeli"}, {"title": "Kandıra Uçurum Seyir Terası", "summary": "Karadeniz''in eşsiz manzarasını kuşbakışı izleyebileceğiniz, özellikle gün batımında büyüleyici bir atmosfere sahip seyir noktasıdır. Fotoğraf tutkunları için vazgeçilmez bir duraktır.", "place_query": "Kandıra Uçurum Seyir Terası, Kocaeli"}, {"title": "Kefken Adası", "summary": "Tarihi deniz feneri ve sarp kayalıklarıyla dikkat çeken küçük bir ada. Doğa yürüyüşleri ve piknik için uygun alanlarıyla hafta sonu kaçamakları için popülerdir.", "place_query": "Kefken Adası, Kandıra, Kocaeli"}, {"title": "Kandıra Mağaraları (Karasu Mağarası)", "summary": "Bölgenin önemli doğal oluşumlarından biri olan mağara, sarkıt ve dikitleriyle ilgi çeker. Mağara içindeki serin hava ve mistik atmosfer ziyaretçilere farklı bir deneyim sunar.", "place_query": "Kandıra Mağaraları, Kocaeli"}, {"title": "Kandıra Merkez Camii ve Tarihi Çarşı", "summary": "Osmanlı dönemi mimarisini yansıtan tarihi cami ve etrafındaki dar sokaklarda sıralanmış çarşı, yöresel ürünler ve el sanatları alışverişi için idealdir. Bölgenin kültürel dokusunu hissetmek için görülmeli.", "place_query": "Kandıra Merkez Camii, Kocaeli"}, {"title": "Babalı Sahili", "summary": "Sakin ve temiz denizi, çam ağaçlarıyla çevrili kumsalı ile huzurlu bir plaj deneyimi arayanların tercihidir. Kampçılar için de uygun alanlar barındırır.", "place_query": "Babalı Sahili, Kandıra, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b3853a70-ae78-48d9-8c4d-a05aef59ab3c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karamürsel Sahil Parkı", "summary": "İlçenin en popüler mesire alanı olan sahil parkı, yürüyüş yolları, çocuk oyun alanları ve deniz manzarasıyla aileler ve dinlenmek isteyenler için ideal bir noktadır.", "place_query": "Karamürsel Sahil Parkı, Karamürsel, Kocaeli"}, {"title": "Ereğli Kalesi", "summary": "Tarihi bir Bizans kalesi olan Ereğli Kalesi, Karamürsel''e hakim bir tepede yer alır ve muhteşem İzmit Körfezi manzarası sunar.", "place_query": "Ereğli Kalesi, Karamürsel, Kocaeli"}, {"title": "Karamürsel Merkez Camii", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan bu cami, zarif mimarisi ve şehir merkezindeki konumuyla ziyaretçilerin ilgisini çeker.", "place_query": "Karamürsel Merkez Camii, Karamürsel, Kocaeli"}, {"title": "Altınkaya Şelalesi", "summary": "Karamürsel sınırları içinde yer alan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla doğaseverler için huzurlu bir kaçış noktasıdır.", "place_query": "Altınkaya Şelalesi, Karamürsel, Kocaeli"}, {"title": "Karamürsel Deniz Müzesi", "summary": "Denizcilik tarihine ilgi duyanlar için özel bir müze olan bu yer, bölgenin deniz kültürünü ve tarihi gemilerini sergiler.", "place_query": "Karamürsel Deniz Müzesi, Karamürsel, Kocaeli"}, {"title": "Akçat Sahili", "summary": "Sakin ve temiz plajıyla bilinen Akçat Sahili, yüzme ve güneşlenmek isteyenler için Karamürsel''in en güzel kıyılarından biridir.", "place_query": "Akçat Sahili, Karamürsel, Kocaeli"}, {"title": "Kaymakçı Göleti Mesire Alanı", "summary": "Doğa içinde piknik yapmak, yürüyüş yapmak veya balık tutmak isteyenler için düzenlenmiş bu gölet, huzurlu bir gün geçirmek için idealdir.", "place_query": "Kaymakçı Göleti Mesire Alanı, Karamürsel, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0a0a5f72-b7d5-42c3-a228-51c1cb115787'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kartepe Kayak Merkezi", "summary": "Kocaeli''nin en popüler kış turizmi noktası olan Kartepe Kayak Merkezi, İstanbul''a yakınlığı ve doğal güzellikleriyle kış aylarında kayak ve snowboard yapmak isteyenlerin uğrak noktasıdır. Yazın da doğa yürüyüşleri ve piknik için idealdir.", "place_query": "Kartepe Kayak Merkezi, Kartepe, Kocaeli"}, {"title": "Sapanca Gölü (Kartepe Kıyıları)", "summary": "Kartepe sınırları içinde kalan Sapanca Gölü kıyıları, muhteşem manzarası ve temiz havasıyla huzur dolu bir kaçış noktasıdır. Göl kenarında yürüyüş yapabilir, bisiklet sürebilir veya piknik yapabilirsiniz.", "place_query": "Sapanca Gölü Kartepe kıyıları, Kartepe, Kocaeli"}, {"title": "Kartepe Doğal Yaşam Parkı", "summary": "Özellikle aileler için ideal olan bu park, çeşitli hayvan türlerini doğal ortamında gözlemleme fırsatı sunar. Çocuklar için eğitici ve eğlenceli bir deneyim sunan park, yeşil alanlarıyla da dikkat çeker.", "place_query": "Kartepe Doğal Yaşam Parkı, Kartepe, Kocaeli"}, {"title": "Maşukiye", "summary": "Kartepe''nin en ünlü turistik beldelerinden biri olan Maşukiye, şelaleleri, yemyeşil doğası ve restoranlarıyla ünlüdür. Özellikle hafta sonları İstanbul ve çevre illerden gelen ziyaretçilerle dolup taşar.", "place_query": "Maşukiye, Kartepe, Kocaeli"}, {"title": "Kartepe Yürüyüş Parkurları", "summary": "Kartepe ormanları boyunca uzanan birçok işaretli yürüyüş parkuru, doğaseverler için keşfedilmeyi bekleyen rotalar sunar. Farklı zorluk seviyelerindeki parkurlar, her seviyeden yürüyüşçüye hitap eder.", "place_query": "Kartepe yürüyüş parkurları, Kartepe, Kocaeli"}, {"title": "Kartepe Teleferik ve Seyir Terası", "summary": "Kartepe''nin zirvesine çıkan teleferik, eşsiz bir manzara deneyimi sunar. Zirvedeki seyir terasından Sapanca Gölü, İzmit Körfezi ve çevredeki dağların panoramik görüntüsünü izleyebilirsiniz.", "place_query": "Kartepe Teleferik, Kartepe, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1ce2a9b9-f323-4638-be7a-be32f11556fd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hereke Kalesi", "summary": "Körfez ilçesinin simgelerinden biri olan tarihi kale, Hereke Körfezi''ne hakim bir tepede yer alır. Muhteşem manzarası ve tarihi dokusuyla ziyaretçilere keyifli bir gezi imkanı sunar.", "place_query": "Hereke Kalesi, Körfez, Kocaeli"}, {"title": "Hereke Sahili ve İskelesi", "summary": "Körfez''in en popüler sahil şeridi olan Hereke Sahili, yürüyüş yolu, parkları ve deniz manzarasıyla dinlenmek için ideal bir noktadır. Tarihi Hereke İskelesi de burada bulunur.", "place_query": "Hereke Sahili, Körfez, Kocaeli"}, {"title": "Darıca Hayvanat Bahçesi ve Botanik Parkı", "summary": "Körfez sınırlarına çok yakın olan bu geniş alan, yüzlerce hayvan türü ve zengin bitki örtüsüyle aileler için harika bir günübirlik gezi rotasıdır.", "place_query": "Darıca Hayvanat Bahçesi ve Botanik Parkı, Kocaeli"}, {"title": "Körfez Sahil Parkı", "summary": "İlçe merkezinde yer alan bu modern park, yürüyüş ve bisiklet yolları, çocuk oyun alanları ve deniz kenarındaki kafeleriyle popüler bir buluşma noktasıdır.", "place_query": "Körfez Sahil Parkı, Kocaeli"}, {"title": "Yarımca Sahili", "summary": "Körfez''in bir diğer güzel sahil şeridi olan Yarımca, özellikle gün batımında sunduğu eşsiz manzara ve sakin atmosferiyle bilinir. Sahil boyunca yürüyüş yapabilirsiniz.", "place_query": "Yarımca Sahili, Körfez, Kocaeli"}, {"title": "Eskihisar Kalesi ve Kocaeli Müzesi", "summary": "Körfez''e komşu Gebze ilçesinde bulunan bu tarihi kale ve içindeki müze, bölgenin tarihine ışık tutar. Osmanlı döneminden kalma yapı, Gebze Körfezi''nin güzel bir manzarasına sahiptir.", "place_query": "Eskihisar Kalesi, Gebze, Kocaeli"}, {"title": "Tütünçiftlik Sahili", "summary": "Körfez''in hareketli mahallelerinden Tütünçiftlik''teki sahil, yerel halkın sıkça tercih ettiği, banklar ve yürüyüş yollarıyla donatılmış bir dinlenme alanıdır.", "place_query": "Tütünçiftlik Sahili, Körfez, Kocaeli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '74b0d02c-362c-4d49-bb01-2b625be54364'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ahırlı Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisini yansıtan sade ve huzurlu bir atmosfere sahiptir. Ziyaretçiler hem ibadet edebilir hem de çevredeki günlük hayatı gözlemleyebilir.", "place_query": "Ahırlı Merkez Camii, Ahırlı, Konya"}, {"title": "Seyir Tepesi (Ahırlı)", "summary": "İlçeye hakim bir noktada yer alan bu tepe, özellikle gün batımında muhteşem manzaralar sunar. Doğa yürüyüşü ve fotoğrafçılık için idealdir.", "place_query": "Seyir Tepesi, Ahırlı, Konya"}, {"title": "Ahırlı Göleti", "summary": "İlçe merkezine yakın konumdaki bu yapay gölet, piknik alanları ve yeşil çevresiyle aileler için popüler bir dinlenme noktasıdır. Balık tutma imkanı da bulunur.", "place_query": "Ahırlı Göleti, Ahırlı, Konya"}, {"title": "Karadiken Yaylası", "summary": "Ahırlı''nın yüksek kesimlerinde yer alan bu yayla, temiz havası ve doğal güzellikleriyle yaz aylarında serinlemek isteyenlerin uğrak noktasıdır. Yürüyüş ve kamp için elverişlidir.", "place_query": "Karadiken Yaylası, Ahırlı, Konya"}, {"title": "Ahırlı Kalesi (Kalıntıları)", "summary": "İlçe sınırları içinde yer alan bu tarihi kale kalıntıları, bölgenin antik dönemlerine ışık tutar. Tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Ahırlı Kalesi, Ahırlı, Konya"}, {"title": "Bozkır-Ahırlı Yolu Üzerindeki Tarihi Köprüler", "summary": "Bozkır ile Ahırlı arasındaki yol güzergahında bulunan taş köprüler, Osmanlı dönemi mühendisliğini yansıtan yapılardır. Doğa ile iç içe bir yolculukta görülmeye değerdir.", "place_query": "Tarihi Köprüler, Ahırlı-Bozkır Yolu, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd18ffbf7-a93a-479f-9600-305920e131f4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akören Göleti", "summary": "İlçe merkezine yakın konumda bulunan bu gölet, piknik ve doğa yürüyüşü için ideal bir alandır. Çevresindeki yeşil alanlar ve sakin atmosferiyle hafta sonu kaçamaklarında tercih edilir.", "place_query": "Akören Göleti, Akören, Konya"}, {"title": "Akören Hz. Ali Camii", "summary": "Tarihi bir yapı olan bu cami, ilçenin en eski ibadet yerlerinden biridir. Mimari detayları ve manevi atmosferiyle ziyaretçilerin ilgisini çeker.", "place_query": "Hz. Ali Camii, Akören, Konya"}, {"title": "Akören Kent Ormanı", "summary": "Şehir merkezine yakın, ağaçlarla kaplı bu ormanlık alan yürüyüş ve bisiklet parkurları sunar. Doğayla iç içe vakit geçirmek isteyenler için huzurlu bir ortamdır.", "place_query": "Akören Kent Ormanı, Akören, Konya"}, {"title": "Akören Yaylası", "summary": "Yaz aylarında serinlemek ve doğal manzaranın tadını çıkarmak için ideal bir yayladır. Yöre halkının uğrak noktalarından biri olup, temiz havasıyla dikkat çeker.", "place_query": "Akören Yaylası, Akören, Konya"}, {"title": "Akören Pazarı", "summary": "Haftalık kurulan halk pazarı, yöresel ürünler ve el sanatlarını bulabileceğiniz renkli bir alışveriş noktasıdır. Taze meyve, sebze ve organik ürünler burada satılır.", "place_query": "Akören Pazarı, Akören, Konya"}, {"title": "Akören Taşköprü", "summary": "Tarihi bir köprü olan bu yapı, ilçenin kültürel mirasları arasında yer alır. Taş işçiliği ve mimarisiyle fotoğrafçıların ilgisini çeker.", "place_query": "Taşköprü, Akören, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '64b86146-0d45-45b3-9c23-fae205920105'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akşehir Nasreddin Hoca Türbesi ve Parkı", "summary": "Nasreddin Hoca''nın türbesinin bulunduğu bu park, mizahın başkenti Akşehir''in en simgesel noktasıdır. Türbe ve çevresindeki heykeller, ziyaretçilere Hoca''nın fıkralarını hatırlatan keyifli bir atmosfer sunar.", "place_query": "Nasreddin Hoca Türbesi, Akşehir, Konya"}, {"title": "Akşehir Gölü", "summary": "Büyük bir kısmı kurumuş olsa da hâlâ önemli bir sulak alan olan göl, kuş gözlemciliği ve doğa yürüyüşleri için idealdir. Özellikle gün batımında eşsiz manzaralar sunar.", "place_query": "Akşehir Gölü, Akşehir, Konya"}, {"title": "Akşehir Müzesi", "summary": "Arkeoloji ve etnografya bölümleriyle Akşehir''in tarihini gözler önüne seren müze, bölgedeki antik kentlerden çıkarılan eserleri barındırır. Nasreddin Hoca''ya ait balmumu heykeli de burada sergilenir.", "place_query": "Akşehir Müzesi, Akşehir, Konya"}, {"title": "Akşehir Kalesi (İç Kale)", "summary": "Selçuklu ve Osmanlı dönemlerinde kullanılan tarihi kale, şehir merkezinde yer alır. Kale kalıntıları arasında gezerken Akşehir''in panoramik manzarasını izleyebilirsiniz.", "place_query": "Akşehir Kalesi, Akşehir, Konya"}, {"title": "Taş Medrese", "summary": "Selçuklu dönemine ait bu tarihi medrese, taş işçiliğinin güzel örneklerini sergiler. Günümüzde kültürel etkinliklere ev sahipliği yapan yapı, fotoğrafçılar için de ilgi çekicidir.", "place_query": "Taş Medrese, Akşehir, Konya"}, {"title": "Akşehir Seyir Tepesi", "summary": "Şehri kuşbakışı görmek isteyenler için ideal bir noktadır. Özellikle akşam saatlerinde şehir ışıklarının yarattığı manzara, romantik bir atmosfer sunar.", "place_query": "Akşehir Seyir Tepesi, Akşehir, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '31c9602f-ac5b-4d89-ae9f-6396cc9f71e8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Altınekin Merkez Camii", "summary": "İlçenin merkezinde yer alan ve Osmanlı mimarisinin izlerini taşıyan tarihi bir camidir. Sade ve huzur veren atmosferiyle ziyaretçilerine manevi bir deneyim sunar.", "place_query": "Altınekin Merkez Camii, Altınekin, Konya"}, {"title": "Altınekin Göleti", "summary": "İlçe merkezine yakın konumda bulunan bu gölet, piknik ve doğa yürüyüşü için ideal bir mekandır. Kuş sesleri eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Altınekin Göleti, Altınekin, Konya"}, {"title": "Zincirli Höyük", "summary": "Altınekin sınırları içinde yer alan bu antik höyük, bölgenin tarih öncesi dönemlerine ışık tutmaktadır. Arkeoloji meraklıları için keşfedilmeyi bekleyen önemli bir noktadır.", "place_query": "Zincirli Höyük, Altınekin, Konya"}, {"title": "Altınekin Kent Ormanı", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için biçilmiş kaftan olan bu ormanlık alan, yürüyüş parkurları ve piknik alanlarıyla doğayla iç içe vakit geçirme imkanı sunar.", "place_query": "Altınekin Kent Ormanı, Altınekin, Konya"}, {"title": "Zengen Yaylası", "summary": "Altınekin''e bağlı Zengen Mahallesi''nde bulunan bu yayla, serin havası ve yeşil manzaralarıyla yaz aylarında kaçış noktasıdır. Doğal güzelliğiyle fotoğrafçıların da ilgisini çeker.", "place_query": "Zengen Yaylası, Altınekin, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f3456a62-4621-4939-bf2f-e77ef6905c71'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beyşehir Gölü Milli Parkı", "summary": "Türkiye''nin en büyük tatlı su göllerinden biri olan Beyşehir Gölü, eşsiz doğal güzelliği ve kuş çeşitliliğiyle doğa severler için ideal bir kaçış noktasıdır. Gölde tekne turları yapabilir, çevresindeki piknik alanlarında vakit geçirebilirsiniz.", "place_query": "Beyşehir Gölü Milli Parkı, Beyşehir, Konya"}, {"title": "Eflatun Pınarı Hitit Anıtı", "summary": "Hitit İmparatorluğu dönemine ait bu etkileyici anıt, su kaynağının başında yer alan kabartmaları ve gizemli atmosferiyle tarih meraklılarını büyüler. UNESCO Dünya Mirası Geçici Listesi''nde yer alan bu yapı, bölgenin en önemli arkeolojik hazinelerindendir.", "place_query": "Eflatun Pınarı Hitit Anıtı, Beyşehir, Konya"}, {"title": "Beyşehir Kalesi", "summary": "Şehir merkezinde yer alan ve Selçuklu döneminden kalma bu tarihi kale, Beyşehir Gölü manzarasına hakim bir tepede konumlanmıştır. Kaleyi gezerken hem tarihe tanıklık edebilir hem de muhteşem bir göl manzarası izleyebilirsiniz.", "place_query": "Beyşehir Kalesi, Beyşehir, Konya"}, {"title": "Kubadabad Sarayları", "summary": "Selçuklu Sultanı Alaeddin Keykubad tarafından yaptırılan bu saray kompleksi, göl kıyısındaki benzersiz konumu ve döneminin ihtişamını yansıtan çini süslemeleriyle ünlüdür. Kazı çalışmaları devam eden bu açık hava müzesi, tarihe ilgi duyanlar için mutlaka görülmelidir.", "place_query": "Kubadabad Sarayları, Beyşehir, Konya"}, {"title": "Beyşehir Eşrefoğlu Camii", "summary": "13. yüzyılda Eşrefoğulları Beyliği tarafından inşa edilen bu cami, ahşap direkleri ve işlemeli tavanıyla Anadolu''nun en güzel ahşap camilerinden biri olarak kabul edilir. İçerisindeki tarihi atmosfer ve kalem işi süslemeler ziyaretçileri büyüler.", "place_query": "Eşrefoğlu Camii, Beyşehir, Konya"}, {"title": "Beyşehir Gölü Adaları", "summary": "Beyşehir Gölü içerisinde irili ufaklı birçok ada bulunur; bunlar arasında en popüler olanları Mada Adası ve İğdeli Ada''dır. Tekneyle ulaşılabilen bu adalar, doğa yürüyüşleri ve kamp için sakin ve huzurlu bir ortam sunar.", "place_query": "Beyşehir Gölü Adaları, Beyşehir, Konya"}, {"title": "Derebucak Mağaraları", "summary": "Beyşehir''e bağlı Derebucak beldesinde bulunan bu mağaralar, sarkıt ve dikitleriyle doğa harikası bir oluşumdur. Mağara içindeki yürüyüş parkurları ve eşsiz jeolojik yapıları, macera arayan ziyaretçiler için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Derebucak Mağaraları, Beyşehir, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9f08e5a0-eba4-4fcc-b0b0-48a8226abfa2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çarşamba Suyu (Bozkır Çayı)", "summary": "Bozkır''ın simgesi haline gelmiş, ilçenin içinden geçen ve çevresinde mesire alanları bulunan doğal bir akarsudur. Özellikle yaz aylarında serinlemek ve piknik yapmak için ziyaret edilir.", "place_query": "Çarşamba Suyu, Bozkır, Konya"}, {"title": "Bozkır Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi bir kaledir. Hititler dönemine kadar uzandığı düşünülen kale, bölgenin tarihi dokusunu yansıtır ve muhteşem bir şehir manzarası sunar.", "place_query": "Bozkır Kalesi, Bozkır, Konya"}, {"title": "Sorkun Yaylası", "summary": "Bozkır''a bağlı Sorkun Mahallesi''nde bulunan, yemyeşil doğası ve serin havasıyla ünlü bir yayladır. Doğa yürüyüşleri ve kampçılık için ideal bir ortam sunar.", "place_query": "Sorkun Yaylası, Bozkır, Konya"}, {"title": "Akçapınar Mağarası", "summary": "Bozkır ilçe merkezine yaklaşık 20 km uzaklıkta bulunan, sarkıt ve dikitleriyle dikkat çeken doğal bir mağaradır. Mağara içindeki gölü ve oluşumlarıyla ziyaretçilere görsel bir şölen sunar.", "place_query": "Akçapınar Mağarası, Bozkır, Konya"}, {"title": "Bozkır Müzesi", "summary": "İlçe merkezinde yer alan bu müze, bölgede yapılan arkeolojik kazılarda ortaya çıkarılan eserlerin sergilendiği önemli bir kültür durağıdır. Hitit, Frig ve Roma dönemlerine ait buluntular görülebilir.", "place_query": "Bozkır Müzesi, Bozkır, Konya"}, {"title": "Yalıhöyük (Türbe Höyük)", "summary": "Bozkır''ın Yalıhöyük Mahallesi''nde bulunan ve Neolitik döneme kadar uzanan geçmişiyle önemli bir arkeolojik sit alanıdır. Bölgedeki en eski yerleşim izlerine ev sahipliği yapar.", "place_query": "Yalıhöyük, Bozkır, Konya"}, {"title": "Kırmızıpınar Mesire Alanı", "summary": "Bozkır''a yaklaşık 10 km mesafede, bol oksijenli havası ve yeşil alanlarıyla piknik ve dinlenme için tercih edilen bir mesire yeridir. Özellikle hafta sonları aileler tarafından yoğun ilgi görür.", "place_query": "Kırmızıpınar Mesire Alanı, Bozkır, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '58167472-8458-472c-810b-357cabfaf7e1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çeltik Kalesi", "summary": "Tarihi bir kalıntı olan Çeltik Kalesi, ilçenin simge yapılarından biridir. Ziyaretçilerine bölgenin tarihine dair izler sunar ve çevresindeki manzara ile dikkat çeker.", "place_query": "Çeltik Kalesi, Çeltik, Konya"}, {"title": "Gökpınar Göleti", "summary": "Doğal güzelliği ile bilinen Gökpınar Göleti, piknik ve dinlenme alanlarıyla ziyaretçilerine huzurlu bir ortam sağlar. Özellikle yaz aylarında serinlemek için tercih edilen bir noktadır.", "place_query": "Gökpınar Göleti, Çeltik, Konya"}, {"title": "Çeltik Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, mimarisi ve manevi atmosferi ile dikkat çeker. Yöre halkı için önemli bir ibadet ve ziyaret noktasıdır.", "place_query": "Çeltik Merkez Camii, Çeltik, Konya"}, {"title": "Kırkpınar Yaylası", "summary": "Çeltik''e bağlı bu yayla, doğa yürüyüşleri ve kamp aktiviteleri için idealdir. Temiz havası ve yeşil alanlarıyla doğaseverlerin uğrak noktalarındandır.", "place_query": "Kırkpınar Yaylası, Çeltik, Konya"}, {"title": "Çeltik Höyüğü", "summary": "Arkeolojik bir alan olan Çeltik Höyüğü, bölgenin eski yerleşim tarihine ışık tutar. Tarih meraklıları için keşfedilmeye değer bir noktadır.", "place_query": "Çeltik Höyüğü, Çeltik, Konya"}, {"title": "Yukarı Çeltik Göleti", "summary": "Sakin ve doğal bir ortam arayanlar için ideal olan bu gölet, çevresindeki yürüyüş yolları ve piknik alanlarıyla bilinir. Kuş gözlemi yapmak isteyenler için de uygun bir yerdir.", "place_query": "Yukarı Çeltik Göleti, Çeltik, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9840381d-ee27-4ead-88c0-a4b014458e8e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tuz Gölü", "summary": "Türkiye''nin en büyük ikinci gölü olan Tuz Gölü, Cihanbeyli sınırları içinde yer alan eşsiz bir doğa harikasıdır. Özellikle yaz aylarında bembeyaz tuz tabakaları ve suyun pembe tonlara büründüğü manzarasıyla fotoğrafçıların ve doğa severlerin uğrak noktasıdır.", "place_query": "Tuz Gölü, Cihanbeyli, Konya"}, {"title": "Gölyazı Kuş Cenneti", "summary": "Tuz Gölü''nün hemen kıyısında yer alan bu alan, onlarca kuş türüne ev sahipliği yapmasıyla bilinir. Doğa gözlemcileri ve kuş fotoğrafçıları için ideal bir durak olup, sakin atmosferiyle huzur verir.", "place_query": "Gölyazı Kuş Cenneti, Cihanbeyli, Konya"}, {"title": "Cihanbeyli İlçe Merkezi ve Tarihi Çarşı", "summary": "İlçenin kalbinde yer alan tarihi çarşı, yöresel el sanatları ve gıda ürünlerini bulabileceğiniz otantik bir alışveriş noktasıdır. Özellikle yöresel lezzetler ve hediyelik eşyalar için ziyaret edilir.", "place_query": "Cihanbeyli Merkez Çarşı, Konya"}, {"title": "Kırkışla Göleti ve Mesire Alanı", "summary": "Cihanbeyli''ye bağlı Kırkışla Mahallesi''nde bulunan bu gölet, piknik ve doğa yürüyüşü için popüler bir kaçış noktasıdır. Yeşil alanları ve sakin suyuyla aileler için ideal bir dinlenme yeridir.", "place_query": "Kırkışla Göleti, Cihanbeyli, Konya"}, {"title": "Büyükbeşkavak Yeraltı Şehri", "summary": "Cihanbeyli''nin Büyükbeşkavak Mahallesi''nde bulunan bu tarihi yeraltı şehri, bölgenin eski yerleşim izlerini taşır. Mağara odaları ve tünelleriyle keşfetmeye değer bir kültürel mirastır.", "place_query": "Büyükbeşkavak Yeraltı Şehri, Cihanbeyli, Konya"}, {"title": "Cihanbeyli Saat Kulesi", "summary": "İlçe merkezinde yer alan bu tarihi saat kulesi, Cihanbeyli''nin simge yapılarından biridir. Çevresindeki park ve kafelerle birlikte keyifli bir mola noktası sunar.", "place_query": "Cihanbeyli Saat Kulesi, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b3a2a522-dd0a-4778-aad9-e37222fc8db3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çatalhöyük Neolitik Kenti", "summary": "UNESCO Dünya Mirası listesindeki bu antik yerleşim, insanlık tarihinin en eski şehirlerinden biridir. M.Ö. 7400''lere tarihlenen kerpiç evleri ve duvar resimleriyle ünlüdür.", "place_query": "Çatalhöyük, Çumra, Konya"}, {"title": "Çumra Belediye Parkı", "summary": "İlçe merkezinde yer alan bu geniş park, yürüyüş yolları, göleti ve yeşil alanlarıyla aileler için popüler bir dinlenme noktasıdır.", "place_query": "Çumra Belediye Parkı, Konya"}, {"title": "Boncuklu Höyük", "summary": "Çatalhöyük''ten daha eski olduğu düşünülen bu arkeolojik alan, Neolitik döneme ait önemli buluntulara ev sahipliği yapmaktadır.", "place_query": "Boncuklu Höyük, Çumra, Konya"}, {"title": "Çumra Müzesi", "summary": "İlçe merkezindeki küçük ama etkileyici müzede, Çatalhöyük ve Boncuklu Höyük kazılarından çıkan eserler sergilenmektedir.", "place_query": "Çumra Müzesi, Konya"}, {"title": "Alibeyhüyüğü Cami", "summary": "Çumra''nın tarihi köylerinden Alibeyhüyüğü''nde bulunan bu cami, geleneksel Osmanlı mimarisinin güzel bir örneğidir.", "place_query": "Alibeyhüyüğü Cami, Çumra, Konya"}, {"title": "Karkın Şelalesi", "summary": "Çumra''ya bağlı Karkın köyü yakınlarındaki bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Karkın Şelalesi, Çumra, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'abbeca6f-6c71-4883-9ea1-033e905d78a0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Derbent Şelalesi", "summary": "İlçe merkezine yaklaşık 10 km uzaklıkta bulunan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilerine huzurlu bir kaçış sunar. Özellikle bahar aylarında akan suyun sesi eşliğinde doğayla baş başa vakit geçirebilirsiniz.", "place_query": "Derbent Şelalesi, Derbent, Konya"}, {"title": "Aladağ (Derbent Aladağları)", "summary": "Derbent''in kuzeyinde yükselen Aladağlar, doğa yürüyüşleri ve kampçılık için ideal bir rotadır. Bölge, zengin bitki örtüsü ve temiz havasıyla doğaseverlerin ilgisini çeker.", "place_query": "Aladağ, Derbent, Konya"}, {"title": "Derbent Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Sade ve etkileyici yapısıyla hem ibadet hem de kültürel ziyaretler için önemli bir duraktır.", "place_query": "Derbent Merkez Camii, Derbent, Konya"}, {"title": "Meyil Dağı", "summary": "Derbent sınırları içinde bulunan Meyil Dağı, özellikle yamaç paraşütü ve doğa sporları için tercih edilen bir noktadır. Tepeden ilçe ve çevresinin panoramik manzarası izlenebilir.", "place_query": "Meyil Dağı, Derbent, Konya"}, {"title": "Derbent Göleti", "summary": "İlçe merkezine yakın konumdaki bu yapay gölet, piknik ve olta balıkçılığı için popüler bir alandır. Çevresindeki yeşil alanlar aileler için sakin bir gün geçirme imkanı sağlar.", "place_query": "Derbent Göleti, Derbent, Konya"}, {"title": "Çiftliközü Yaylası", "summary": "Derbent''in yüksek kesimlerinde yer alan bu yayla, yaz aylarında serinlemek ve doğal yaşamı deneyimlemek isteyenler için idealdir. Yayla evleri ve geniş çayırlarıyla dikkat çeker.", "place_query": "Çiftliközü Yaylası, Derbent, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '06f3537b-5751-42de-8a73-7a7d91f71923'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Balatini Mağarası", "summary": "Türkiye''nin en büyük mağaralarından biri olan Balatini, devasa sarkıt ve dikitleri ile görülmeye değer bir doğa harikasıdır. Mağara içindeki yürüyüş parkurları ve aydınlatma sistemi sayesinde ziyaretçiler bu eşsiz oluşumu rahatça keşfedebilir.", "place_query": "Balatini Mağarası, Derebucak, Konya"}, {"title": "İnönü Mağarası", "summary": "Derebucak''ta bulunan İnönü Mağarası, tarih öncesi dönemlerden kalma kalıntıları ve etkileyici mağara oluşumlarıyla dikkat çeker. Mağara, bölgenin jeolojik geçmişine ışık tutan önemli bir doğal anıttır.", "place_query": "İnönü Mağarası, Derebucak, Konya"}, {"title": "Derebucak Göleti", "summary": "Doğal güzelliği ve sakin atmosferiyle bilinen Derebucak Göleti, piknik ve doğa yürüyüşü için ideal bir yerdir. Gölet çevresi, özellikle bahar aylarında yeşilin her tonunu gözler önüne serer.", "place_query": "Derebucak Göleti, Derebucak, Konya"}, {"title": "Çamlık Tepesi Seyir Noktası", "summary": "Derebucak''ın en yüksek noktalarından biri olan Çamlık Tepesi, ziyaretçilerine muhteşem bir vadi ve orman manzarası sunar. Özellikle gün batımında buradan izlenecek manzara unutulmaz bir deneyim yaşatır.", "place_query": "Çamlık Tepesi, Derebucak, Konya"}, {"title": "Gencek Yaylası", "summary": "Derebucak sınırları içinde yer alan Gencek Yaylası, yemyeşil çayırları ve serin havasıyla yaz aylarında kaçış noktasıdır. Yayla, doğa yürüyüşleri ve kampçılık için de oldukça popülerdir.", "place_query": "Gencek Yaylası, Derebucak, Konya"}, {"title": "Derebucak Kaya Mezarları", "summary": "Bölgedeki antik yerleşim izlerini taşıyan kaya mezarları, tarih meraklıları için önemli bir duraktır. Kayalara oyulmuş bu mezarlar, bölgenin binlerce yıllık geçmişine tanıklık eder.", "place_query": "Derebucak Kaya Mezarları, Derebucak, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3afc694f-c172-484d-b247-d01f4a19d608'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Doğanhisar Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin savunma yapılarından biridir. Ziyaretçilerine hem tarihi bir atmosfer hem de eşsiz bir Doğanhisar manzarası sunar.", "place_query": "Doğanhisar Kalesi, Doğanhisar, Konya"}, {"title": "Çatalhöyük Neolitik Kenti", "summary": "Doğanhisar sınırları içinde olmasa da yakın çevredeki en önemli tarihi alan olan Çatalhöyük, UNESCO Dünya Mirası Listesi''ndedir. Neolitik döneme ait benzersiz buluntuları ve yerleşim planıyla tarih meraklıları için görülmeye değerdir.", "place_query": "Çatalhöyük Neolitik Kenti, Çumra, Konya"}, {"title": "Beyşehir Gölü Milli Parkı", "summary": "Doğanhisar''a komşu olan Beyşehir Gölü, Türkiye''nin en büyük tatlı su göllerinden biridir. Milli park statüsündeki bu doğal güzellik, kuş gözlemi, piknik ve doğa yürüyüşleri için idealdir.", "place_query": "Beyşehir Gölü Milli Parkı, Beyşehir, Konya"}, {"title": "Eflatun Pınarı Hitit Anıtı", "summary": "Beyşehir Gölü kıyısında yer alan bu Hitit dönemi anıtı, Doğanhisar''a yakın bir mesafededir. Anıtsal taş işçiliği ve su kültüyle ilgili kabartmalarıyla dikkat çeken arkeolojik bir sit alanıdır.", "place_query": "Eflatun Pınarı Hitit Anıtı, Beyşehir, Konya"}, {"title": "Doğanhisar Yaylaları", "summary": "İlçenin yüksek kesimlerinde bulunan yaylalar, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popülerdir. Bol oksijenli havası ve yeşil doğasıyla huzur verir.", "place_query": "Doğanhisar Yaylaları, Doğanhisar, Konya"}, {"title": "Kubadabad Sarayı", "summary": "Beyşehir Gölü kıyısında, Selçuklu dönemine ait bu yazlık saray kompleksi, Doğanhisar''a yakın konumdadır. Çini süslemeleri ve tarihi yapısıyla Selçuklu sanatının önemli bir örneğidir.", "place_query": "Kubadabad Sarayı, Beyşehir, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd4186025-1502-45b7-ba59-a919346ddb43'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Emirgazi İlçe Merkezi ve Çarşısı", "summary": "İlçenin kalbi sayılan merkez, küçük esnafı ve yerel atmosferiyle ziyaretçilere otantik bir Anadolu kasabası deneyimi sunar.", "place_query": "Emirgazi Merkez, Konya"}, {"title": "Emirgazi Göleti ve Mesire Alanı", "summary": "Doğal güzelliği ve piknik alanlarıyla bilinen bu gölet, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir duraktır.", "place_query": "Emirgazi Göleti, Konya"}, {"title": "Demiryolu Müzesi (Emirgazi Garı)", "summary": "Tarihi tren istasyonu binasında yer alan bu küçük müze, bölgenin demiryolu geçmişine ışık tutan fotoğraf ve objeleri sergiler.", "place_query": "Emirgazi Garı Demiryolu Müzesi"}, {"title": "Karahöyük (Emirgazi Höyüğü)", "summary": "Arkeolojik öneme sahip bu höyük, bölgede yapılan kazılarda ortaya çıkan kalıntılarla tarih meraklıları için ilgi çekici bir noktadır.", "place_query": "Karahöyük Emirgazi"}, {"title": "Emirgazi Yaylası", "summary": "Şehir gürültüsünden uzak, temiz havası ve yeşil doğasıyla yayla, doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Emirgazi Yaylası"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '63ee71fb-3420-489b-a903-b72616c66376'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ereğli Müzesi", "summary": "Bölgenin zengin tarihini yansıtan arkeolojik ve etnografik eserlerin sergilendiği bir müzedir. Hitit, Roma ve Bizans dönemlerine ait kalıntılar görülebilir.", "place_query": "Ereğli Müzesi, Konya"}, {"title": "İvriz Kaya Anıtı", "summary": "Geç Hitit dönemine ait, kral Warpalawas''ı ve bereket tanrısını betimleyen etkileyici bir kaya kabartmasıdır. Tarih meraklıları için eşsiz bir durak.", "place_query": "İvriz Kaya Anıtı, Ereğli, Konya"}, {"title": "Aktopraklık Höyüğü", "summary": "Neolitik ve Kalkolitik dönemlere ait buluntuların ortaya çıkarıldığı önemli bir arkeolojik alandır. Bölgenin ilk yerleşim izlerini görmek mümkün.", "place_query": "Aktopraklık Höyüğü, Ereğli, Konya"}, {"title": "Ereğli Kapalı Çarşısı", "summary": "Yöresel ürünler ve el sanatlarının satıldığı tarihi bir çarşıdır. Geleneksel Konya lezzetlerini tatmak ve hediyelik eşya almak için idealdir.", "place_query": "Ereğli Kapalı Çarşısı, Konya"}, {"title": "Ayrancı Barajı ve Mesire Alanı", "summary": "Şehir merkezine yakın, piknik ve doğa yürüyüşü için popüler bir alandır. Baraj manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Ayrancı Barajı, Ereğli, Konya"}, {"title": "Zengibar Kalesi", "summary": "Antik dönemlerden kalma bir kale kalıntısı olup, stratejik konumuyla dikkat çeker. Kaleye tırmanarak çevrenin panoramik manzarasını izleyebilirsiniz.", "place_query": "Zengibar Kalesi, Ereğli, Konya"}, {"title": "Ereğli Ulu Camii", "summary": "Selçuklu ve Osmanlı mimari özelliklerini taşıyan tarihi bir camidir. İç süslemeleri ve taş işçiliği görmeye değerdir.", "place_query": "Ereğli Ulu Camii, Konya"}, {"title": "Kızılören Mağarası", "summary": "İlçe sınırları içinde bulunan doğal bir mağaradır. Sarkıt ve dikitleriyle doğa severler için ilgi çekici bir keşif noktasıdır.", "place_query": "Kızılören Mağarası, Ereğli, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '55a53357-22d3-460e-9b23-dce05bb895c1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güneysınır Kervansarayı", "summary": "Tarihi İpek Yolu üzerinde yer alan bu Selçuklu dönemi kervansarayı, bölgenin en önemli tarihi yapılarından biridir. Taş işçiliği ve mimari detaylarıyla ziyaretçilerine geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Güneysınır Kervansarayı, Güneysınır, Konya"}, {"title": "Güneysınır Ulu Camii", "summary": "Bölgenin en eski ve en büyük camilerinden biri olan bu yapı, Osmanlı dönemi mimarisinin güzel bir örneğidir. Sade ve etkileyici atmosferiyle ibadet ve ziyaret için huzurlu bir ortam sağlar.", "place_query": "Güneysınır Ulu Camii, Güneysınır, Konya"}, {"title": "Güneysınır Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale kalıntıları, çevreye hakim bir manzara sunar. Bölgenin savunma tarihine ışık tutan bu yapı, doğa yürüyüşleri ve fotoğrafçılık için idealdir.", "place_query": "Güneysınır Kalesi, Güneysınır, Konya"}, {"title": "Güneysınır Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla piknik ve dinlenme için popüler bir noktadır. Gölet çevresinde yürüyüş yapabilir, doğayla iç içe keyifli vakit geçirebilirsiniz.", "place_query": "Güneysınır Göleti, Güneysınır, Konya"}, {"title": "Bostandere Vadisi", "summary": "Yemyeşil doğası ve sakin atmosferiyle doğa tutkunları için keşfedilmeyi bekleyen bir vadidir. Yürüyüş rotaları ve piknik alanlarıyla hafta sonu kaçamakları için uygundur.", "place_query": "Bostandere Vadisi, Güneysınır, Konya"}, {"title": "Güneysınır Taş Köprü", "summary": "Tarihi bir taş köprü olan bu yapı, geçmişte bölgenin önemli geçiş noktalarından biriydi. Günümüzde ise nostaljik bir fotoğraf karesi ve kısa bir mola vermek için ziyaret edilmektedir.", "place_query": "Güneysınır Taş Köprü, Güneysınır, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f0ce1caa-c84d-43e4-ba51-f961244229d6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göksu Nehri ve Göksu Vadisi", "summary": "Hadim''in en önemli doğal güzelliklerinden biri olan Göksu Nehri, berrak suları ve çevresindeki yemyeşil vadi manzarasıyla huzur verici bir ortam sunar. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için idealdir.", "place_query": "Göksu Nehri, Hadim, Konya"}, {"title": "Hadim Yerköprü Şelalesi", "summary": "Bölgenin en etkileyici doğal oluşumlarından biri olan Yerköprü Şelalesi, Göksu Nehri üzerinde yer alır ve traverten yapısıyla dikkat çeker. Şelalenin çevresindeki mesire alanı piknik ve doğa ile iç içe vakit geçirmek için popülerdir.", "place_query": "Yerköprü Şelalesi, Hadim, Konya"}, {"title": "Hadim Tarihi Taş Köprü", "summary": "Tarihi geçmişiyle Hadim''in simgelerinden biri olan bu taş köprü, Osmanlı dönemi mimarisini yansıtır. Göksu Nehri üzerinde yer alan köprü, hem tarihi bir yapı olarak hem de fotoğrafçılık açısından ilgi çekicidir.", "place_query": "Tarihi Taş Köprü, Hadim, Konya"}, {"title": "Hadim Aladağlar Milli Parkı (Sınır Bölgesi)", "summary": "Hadim ilçesi sınırlarına yakın olan Aladağlar Milli Parkı, zengin bitki örtüsü ve yaban hayatıyla doğa tutkunları için keşfedilmeyi bekleyen bir cennettir. Kampçılık, trekking ve dağcılık gibi aktiviteler için uygun parkurlar sunar.", "place_query": "Aladağlar Milli Parkı, Hadim, Konya"}, {"title": "Hadim Merkez Camii ve Tarihi Çarşı", "summary": "Hadim''in merkezinde yer alan tarihi cami ve çevresindeki çarşı, ilçenin kültürel dokusunu yansıtır. Özellikle yöresel ürünlerin satıldığı dükkanlar ve sakin atmosferiyle ziyaretçilere farklı bir deneyim sunar.", "place_query": "Hadim Merkez Camii, Hadim, Konya"}, {"title": "Bademli Yaylası", "summary": "Hadim''in yüksek kesimlerinde bulunan Bademli Yaylası, serin havası ve muhteşem doğa manzarasıyla yayla turizmi için ideal bir noktadır. Yayla evlerinde konaklama imkanı ve yöresel lezzetleri tatma fırsatı sunar.", "place_query": "Bademli Yaylası, Hadim, Konya"}, {"title": "Korualan Mağarası", "summary": "Henüz tam anlamıyla turizme açılmamış olsa da Korualan Mağarası, doğal oluşumu ve sarkıt-dikitleriyle mağara meraklıları için ilgi çekici bir duraktır. Bölgedeki diğer doğal güzelliklerle birlikte keşfedilebilir.", "place_query": "Korualan Mağarası, Hadim, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '53b8a1ba-4829-4ada-a3c5-bc966701e13a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Halkapınar Mağarası", "summary": "Bölgenin en bilinen doğal oluşumlarından biri olan bu mağara, etkileyici sarkıt ve dikitleriyle ziyaretçilerini büyüler. Doğa yürüyüşü ve mağara keşfi için idealdir.", "place_query": "Halkapınar Mağarası, Halkapınar, Konya"}, {"title": "İvriz Anıtı", "summary": "Halkapınar sınırları içinde yer alan bu Geç Hitit dönemi kaya anıtı, Kral Warpalawas''ı ve bereket tanrısını betimleyen kabartmalarıyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "İvriz Anıtı, Halkapınar, Konya"}, {"title": "İvriz Barajı ve Mesire Alanı", "summary": "Doğal güzellikleriyle ünlü İvriz Barajı çevresindeki mesire alanı, piknik ve doğa yürüyüşü yapmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "İvriz Barajı, Halkapınar, Konya"}, {"title": "Güneysınır Göleti", "summary": "Halkapınar''a yakın konumdaki bu gölet, çevresindeki yeşil alanlar ve sakin atmosferiyle balık tutma ve piknik gibi aktiviteler için popülerdir.", "place_query": "Güneysınır Göleti, Halkapınar, Konya"}, {"title": "Çamlık Yaylası", "summary": "Yemyeşil çam ormanlarıyla kaplı bu yayla, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Çamlık Yaylası, Halkapınar, Konya"}, {"title": "Halkapınar Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin sade ama zarif bir örneği olup manevi atmosferiyle dikkat çeker.", "place_query": "Halkapınar Merkez Camii, Halkapınar, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5166855a-447b-4247-98b8-0d8600ec5019'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hüyük Höyüğü", "summary": "Bölgenin en önemli arkeolojik alanlarından biri olan höyük, Hitit ve Frig dönemlerine ait izler taşır. Tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "Hüyük Höyüğü, Hüyük, Konya"}, {"title": "Çukurkent Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikit yapılarıyla dikkat çeken mağara, doğa tutkunları için görülmeye değer bir duraktır.", "place_query": "Çukurkent Mağarası, Hüyük, Konya"}, {"title": "Hüyük Şelalesi", "summary": "Yeşil alanlarla çevrili, serin sularıyla piknik ve dinlenme için ideal bir doğal güzelliktir. Özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Hüyük Şelalesi, Hüyük, Konya"}, {"title": "İmrenler Tepesi Seyir Noktası", "summary": "Hüyük ve çevresinin panoramik manzarasını sunan bu tepe, gün batımında eşsiz fotoğraf kareleri yakalamak için popüler bir noktadır.", "place_query": "İmrenler Tepesi, Hüyük, Konya"}, {"title": "Büyükşehir Belediyesi Hüyük Mesire Alanı", "summary": "Aileler için düzenlenmiş yürüyüş parkurları, piknik alanları ve çocuk oyun alanlarıyla huzurlu bir doğa kaçamağı sunar.", "place_query": "Hüyük Mesire Alanı, Hüyük, Konya"}, {"title": "Kıreli Göleti", "summary": "Sakin ve huzurlu atmosferiyle balık tutma ve doğa yürüyüşü sevenlerin uğrak noktasıdır. Gölet çevresi yeşil alanlarla kaplıdır.", "place_query": "Kıreli Göleti, Hüyük, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a355bec8-6f2a-4241-ac42-b277cffef639'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ilgın Kaplıcaları", "summary": "Ilgın''ın en bilinen şifa kaynağı olan termal tesisler, romatizma ve cilt hastalıklarına iyi gelen sıcak sularıyla ünlüdür. Hem konaklama hem de günübirlik termal havuz keyfi sunar.", "place_query": "Ilgın Kaplıcaları, Ilgın, Konya"}, {"title": "Çekirdeksiz Ilgın Çileği Tarlaları", "summary": "Ilgın''a özgü aroması ve lezzetiyle ünlü çekirdeksiz çilek, yaz aylarında tarlalardan taze olarak toplanabilir. Bölgede çilek festivalleri de düzenlenir.", "place_query": "Ilgın Çilek Tarlaları, Ilgın, Konya"}, {"title": "Ilgın Lala Mustafa Paşa Camii", "summary": "16. yüzyılda Mimar Sinan tarafından yapılan bu tarihi cami, kesme taş işçiliği ve zarif minaresiyle dikkat çeker. Ilgın''ın simge yapılarından biridir.", "place_query": "Lala Mustafa Paşa Camii, Ilgın, Konya"}, {"title": "Ilgın Müzesi", "summary": "Küçük ama zengin bir arkeoloji ve etnografya müzesi olan Ilgın Müzesi, bölgede bulunan Roma ve Bizans dönemi eserlerini sergiler. Tarihe ilgi duyanlar için idealdir.", "place_query": "Ilgın Müzesi, Ilgın, Konya"}, {"title": "Ilgın Gölü (Ilgın Çayırbağı Göleti)", "summary": "Şehir merkezine yakın bu doğal gölet, piknik alanları ve yürüyüş yollarıyla huzurlu bir kaçış noktasıdır. Kuş gözlemi ve doğa fotoğrafçılığı için de uygundur.", "place_query": "Ilgın Gölü, Ilgın, Konya"}, {"title": "Ilgın Kapalı Çarşı ve Tarihi Çarşı", "summary": "Ilgın''ın eski çarşı bölgesinde yer alan bu tarihi pazar yeri, yöresel ürünler ve el sanatlarıyla doludur. Özellikle çilek reçeli ve termal sabunları meşhurdur.", "place_query": "Ilgın Kapalı Çarşı, Ilgın, Konya"}, {"title": "Ilgın Yaylası (Yukarı Çiğil Yaylası)", "summary": "Şehir gürültüsünden uzak, yemyeşil doğası ve temiz havasıyla ünlü yayla, yaz aylarında serinlemek ve doğa yürüyüşü yapmak için tercih edilir.", "place_query": "Yukarı Çiğil Yaylası, Ilgın, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c6d722fb-cbce-4039-bdbd-0e683deb72f8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kadınhanı Kervansarayı", "summary": "Selçuklu döneminden kalma bu tarihi kervansaray, bölgenin en önemli kültürel mirasıdır. İhtişamlı taş işçiliği ve avlusuyla ziyaretçilerine tarihi bir yolculuk sunar.", "place_query": "Kadınhanı Kervansarayı, Konya"}, {"title": "Kadınhanı Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve doğayla iç içe vakit geçirmek için idealdir. Yürüyüş yolları ve yeşil alanlarıyla aileler için popüler bir mekandır.", "place_query": "Kadınhanı Belediye Parkı, Konya"}, {"title": "Kadınhanı Atatürk Anıtı", "summary": "İlçe meydanında bulunan bu anıt, Cumhuriyet''in simgelerinden biridir. Çevresiyle birlikte şehrin sosyal yaşamının merkezi konumundadır.", "place_query": "Kadınhanı Atatürk Anıtı, Konya"}, {"title": "Kadınhanı Yeraltı Şehri", "summary": "Yakın zamanda keşfedilen bu yeraltı şehri, tarih öncesi dönemlere ait izler taşır. Dar koridorları ve odalarıyla macera arayan ziyaretçileri cezbeder.", "place_query": "Kadınhanı Yeraltı Şehri, Konya"}, {"title": "Kadınhanı Cami (Merkez Cami)", "summary": "Osmanlı ve Selçuklu mimarisinin izlerini taşıyan bu tarihi cami, ilçenin manevi merkezidir. Sade ama etkileyici yapısıyla dikkat çeker.", "place_query": "Kadınhanı Merkez Cami, Konya"}, {"title": "Kadınhanı Mesire Alanı", "summary": "Şehir merkezine yakın bu mesire alanı, piknik ve doğa yürüyüşü için tercih edilir. Ağaçlık alanları ve temiz havasıyla hafta sonu kaçamakları için uygundur.", "place_query": "Kadınhanı Mesire Alanı, Konya"}, {"title": "Kadınhanı Höyüğü", "summary": "Arkeolojik öneme sahip bu höyük, bölgenin antik yerleşim tarihine ışık tutar. Tarih meraklıları için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Kadınhanı Höyüğü, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0e58ecc5-e284-488e-80ba-f221dc704c1f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Meke Krater Gölü", "summary": "Dünyanın en ilginç oluşumlarından biri olan Meke, volkanik bir kraterin suyla dolması ve ortasında ikinci bir koni oluşmasıyla meydana gelmiş eşsiz bir doğa harikasıdır. Ziyaretçiler, bu benzersiz manzarayı fotoğraflamak ve kraterin çevresinde yürüyüş yapmak için gelir.", "place_query": "Meke Krater Gölü, Karapınar, Konya"}, {"title": "Acıgöl (Karapınar Gölü)", "summary": "Meke Krateri''nin hemen yanında yer alan Acıgöl, sodalı ve tuzlu suyuyla dikkat çeken bir diğer volkanik krater gölüdür. Kuş gözlemcileri ve doğa fotoğrafçıları için huzurlu bir durak noktasıdır.", "place_query": "Acıgöl, Karapınar, Konya"}, {"title": "Karapınar Obrukları", "summary": "Bölgenin kendine özgü karstik yapısının bir sonucu olarak oluşan derin ve etkileyici obruklar, doğa tutkunları için keşfedilmeyi bekleyen gizemli alanlardır. En bilinenleri Meyil Obruğu ve Kızören Obruğu''dur.", "place_query": "Kızören Obruğu, Karapınar, Konya"}, {"title": "Çatalhöyük (Neolitik Kent)", "summary": "Karapınar ilçe merkezine biraz uzak olsa da, UNESCO Dünya Mirası Listesi''ndeki bu antik kent, bölgenin en önemli tarihi zenginliklerinden biridir. 9 bin yıllık geçmişiyle insanlık tarihine ışık tutan bu alan, mutlaka görülmeye değerdir.", "place_query": "Çatalhöyük, Çumra, Konya"}, {"title": "Karapınar İlçe Merkezi ve Tarihi Camiler", "summary": "İlçe merkezinde yer alan tarihi yapılar arasında başta Ulu Cami olmak üzere, Osmanlı döneminden kalma birkaç cami ve çeşme bulunur. Şehir merkezinde kısa bir gezinti, bölgenin kültürel dokusunu hissetmek için idealdir.", "place_query": "Karapınar Merkez, Konya"}, {"title": "Karapınar Rüzgar Enerjisi Santrali Çevresi", "summary": "Bölgenin rüzgarlı ovalarında yükselen modern rüzgar türbinleri, doğa ve teknolojiyi bir arada görmek isteyenler için ilginç bir manzara sunar. Özellikle gün batımında türbinlerin siluetleri fotoğrafçılar için güzel kareler oluşturur.", "place_query": "Karapınar Rüzgar Enerjisi Santrali, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9bc8281a-0c88-4e04-985d-7ce64fc8c3d6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mevlana Müzesi", "summary": "Konya''nın en önemli simgesi olan Mevlana Celaleddin Rumi''nin türbesi ve dergahıdır. Tarihi atmosferi, eşsiz çinileri ve manevi havasıyla her yıl milyonlarca ziyaretçiyi ağırlar.", "place_query": "Mevlana Müzesi, Karatay, Konya"}, {"title": "Alaeddin Tepesi ve Alaeddin Camii", "summary": "Şehir merkezinde yükselen tarihi bir tepe üzerinde yer alan Alaeddin Camii, Selçuklu döneminin en önemli eserlerindendir. Tepe, Konya manzarasını izlemek ve dinlenmek için ideal bir noktadır.", "place_query": "Alaeddin Tepesi, Karatay, Konya"}, {"title": "İnce Minareli Medrese", "summary": "Selçuklu taş işçiliğinin en güzel örneklerinden biri olan bu medrese, ince minaresi ve geometrik süslemeleriyle dikkat çeker. Günümüzde Taş ve Ahşap Eserler Müzesi olarak hizmet vermektedir.", "place_query": "İnce Minareli Medrese, Karatay, Konya"}, {"title": "Karatay Medresesi", "summary": "Selçuklu Veziri Celaleddin Karatay tarafından yaptırılan bu medrese, çini süslemeleriyle ünlüdür. Müze olarak kullanılan yapı, Selçuklu çini sanatının en nadide örneklerini sergiler.", "place_query": "Karatay Medresesi, Karatay, Konya"}, {"title": "Konya Tropikal Kelebek Bahçesi", "summary": "Avrupa''nın en büyük tropikal kelebek bahçelerinden biri olan bu merkez, yüzlerce kelebek türüne ve tropikal bitkilere ev sahipliği yapar. Özellikle çocuklu aileler için büyüleyici bir deneyim sunar.", "place_query": "Konya Tropikal Kelebek Bahçesi, Karatay, Konya"}, {"title": "Sille Köyü", "summary": "Konya''ya 8 km uzaklıkta bulunan bu tarihi köy, Rum ve Türk kültürlerinin izlerini taşır. Taş evleri, tarihi kiliseleri (özellikle Aya Elena Kilisesi) ve doğal güzellikleriyle huzurlu bir kaçış noktasıdır.", "place_query": "Sille Köyü, Karatay, Konya"}, {"title": "Aziziye Camii", "summary": "19. yüzyılda inşa edilen bu cami, barok ve ampir üsluplarını birleştiren dikkat çekici bir mimariye sahiptir. Konya''nın en fotojenik yapılarından biri olarak öne çıkar.", "place_query": "Aziziye Camii, Karatay, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c0ea3f00-8ff9-447e-870e-74b392769c53'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kulu Gölü", "summary": "Kulu''nun en önemli doğal zenginliklerinden biri olan bu göl, özellikle kuş gözlemcileri için bir cennettir. Her yıl binlerce flamingo ve diğer su kuşlarına ev sahipliği yapar, huzurlu bir doğa kaçamağı sunar.", "place_query": "Kulu Gölü, Kulu, Konya"}, {"title": "Kulu Camii (Merkez Camii)", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve yöre halkı için önemli bir ibadet ve kültür merkezidir.", "place_query": "Kulu Merkez Camii, Kulu, Konya"}, {"title": "Kulu Kent Müzesi", "summary": "İlçenin tarihini, kültürünü ve geleneklerini yansıtan eserlerin sergilendiği bu müze, Kulu''yu daha yakından tanımak isteyen ziyaretçiler için ideal bir duraktır.", "place_query": "Kulu Kent Müzesi, Kulu, Konya"}, {"title": "Kozanlı Göleti", "summary": "Kulu''ya bağlı Kozanlı Mahallesi''nde bulunan bu gölet, piknik ve doğa yürüyüşleri için popüler bir mekandır. Sakin atmosferi ve yeşil çevresiyle hafta sonu kaçamakları için tercih edilir.", "place_query": "Kozanlı Göleti, Kulu, Konya"}, {"title": "Kulu Yeraltı Şehri", "summary": "Bölgede keşfedilen ve henüz tam olarak gün yüzüne çıkarılmamış olan bu yeraltı şehri, tarih meraklıları için büyüleyici bir keşif alanıdır. Erken Hristiyanlık dönemine ait olduğu düşünülmektedir.", "place_query": "Kulu Yeraltı Şehri, Kulu, Konya"}, {"title": "Kulu Kalesi", "summary": "Tarihi bir höyük üzerinde yer alan ve günümüze sadece kalıntıları ulaşan bu kale, ilçeye hakim bir tepeden Kulu Ovası''nın muhteşem manzarasını sunar.", "place_query": "Kulu Kalesi, Kulu, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9c3ee35f-4e2b-4659-955d-00ece237a4d6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mevlana Müzesi", "summary": "Konya''nın en önemli simgesi olan bu müze, Mevlana Celaleddin Rumi''nin türbesini barındırır ve her yıl milyonlarca ziyaretçiyi mistik atmosferiyle kendine çeker.", "place_query": "Mevlana Müzesi, Karatay, Konya"}, {"title": "Meram Bağları", "summary": "Meram ilçesinde yer alan bu tarihi mesire alanı, şelaleleri, yeşil dokusu ve yürüyüş yollarıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Meram Bağları, Meram, Konya"}, {"title": "Tavus Baba Türbesi ve Parkı", "summary": "Meram''da huzurlu bir ortamda bulunan bu türbe ve çevresindeki park, hem manevi bir ziyaret hem de piknik yapmak için popüler bir duraktır.", "place_query": "Tavus Baba Türbesi, Meram, Konya"}, {"title": "Sille Barajı ve Mesire Alanı", "summary": "Meram sınırlarına yakın bu baraj çevresi, doğa yürüyüşleri ve piknik alanlarıyla hafta sonu keyfi yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Sille Barajı, Selçuklu, Konya"}, {"title": "Meram Dere ve Çevresi", "summary": "Meram''ın ortasından geçen bu dere boyunca uzanan yürüyüş yolları, kafeler ve yeşil alanlar, ilçenin en canlı sosyal mekanlarından biridir.", "place_query": "Meram Dere, Meram, Konya"}, {"title": "Konya Tropikal Kelebek Bahçesi", "summary": "Meram ilçesinde bulunan bu bahçe, yüzlerce kelebek türü ve tropikal bitkileriyle aileler ve doğa meraklıları için eşsiz bir deneyim sunar.", "place_query": "Konya Tropikal Kelebek Bahçesi, Meram, Konya"}, {"title": "Kozağaç Kent Ormanı", "summary": "Meram''ın yemyeşil bir noktasındaki bu kent ormanı, bisiklet yolları ve piknik alanlarıyla doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Kozağaç Kent Ormanı, Meram, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f69ec73e-782e-40d0-bdb1-2728cdfc886b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarayönü Belediye Parkı", "summary": "İlçe merkezinde dinlenmek ve vakit geçirmek için ideal olan bu park, yeşil alanları ve yürüyüş yollarıyla ziyaretçilere huzurlu bir ortam sunar.", "place_query": "Sarayönü Belediye Parkı, Sarayönü, Konya"}, {"title": "Çeşmelisebil Göleti", "summary": "Doğa ile iç içe bir piknik ve mesire alanı olan gölet, özellikle hafta sonları ailelerin ve doğa severlerin uğrak noktasıdır.", "place_query": "Çeşmelisebil Göleti, Sarayönü, Konya"}, {"title": "Ladik Gölü", "summary": "Sarayönü sınırları içinde yer alan bu doğal göl, kuş gözlemi ve doğa yürüyüşleri için popüler bir duraktır.", "place_query": "Ladik Gölü, Sarayönü, Konya"}, {"title": "Sarayönü Tarihi Evleri", "summary": "İlçede dağınık halde bulunan geleneksel Konya evleri, geçmişe yolculuk yapmak isteyenler için ilgi çekici bir kültürel rotadır.", "place_query": "Sarayönü Tarihi Evleri, Sarayönü, Konya"}, {"title": "Gözlü Yaylası", "summary": "Yaz aylarında serinlemek ve doğal manzaranın tadını çıkarmak için tercih edilen yayla, yürüyüş ve kamp aktiviteleri için uygundur.", "place_query": "Gözlü Yaylası, Sarayönü, Konya"}, {"title": "Sarayönü Merkez Camii", "summary": "İlçenin simge yapılarından biri olan cami, mimarisi ve manevi atmosferiyle ziyaretçilerini ağırlar.", "place_query": "Sarayönü Merkez Camii, Sarayönü, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6f23e12f-0ff5-4ced-b0e4-a5bf6b6a0762'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mevlana Müzesi", "summary": "Konya denince akla gelen ilk yer olan Mevlana Müzesi, Mevlana Celaleddin Rumi''nin türbesini ve dervişlere ait eşyaları barındıran kutsal bir mekandır. Yeşil kubbe ve mistik atmosferiyle her yıl milyonlarca ziyaretçiyi ağırlar.", "place_query": "Mevlana Müzesi, Selçuklu, Konya"}, {"title": "Konya Tropikal Kelebek Bahçesi", "summary": "Avrupa''nın en büyük tropikal kelebek bahçelerinden biri olan bu merkez, yüzlerce kelebek türüne ev sahipliği yapar. Aileler ve doğa severler için eşsiz bir deneyim sunan tropik bitkilerle dolu dev bir seradır.", "place_query": "Konya Tropikal Kelebek Bahçesi, Selçuklu, Konya"}, {"title": "İnce Minareli Medrese", "summary": "13. yüzyılda Selçuklu döneminde yapılan bu medrese, muhteşem taş işçiliği ve zarif minaresiyle ünlüdür. Günümüzde Taş ve Ahşap Eserler Müzesi olarak hizmet veren yapı, Selçuklu sanatının en güzel örneklerini sergiler.", "place_query": "İnce Minareli Medrese, Selçuklu, Konya"}, {"title": "Konya Bilim Merkezi", "summary": "Türkiye''nin TÜBİTAK destekli ilk bilim merkezlerinden olan bu modern tesis, interaktif sergiler, atölyeler ve planetaryumuyla çocuklar ve yetişkinler için eğlenceli bir öğrenme ortamı sunar.", "place_query": "Konya Bilim Merkezi, Selçuklu, Konya"}, {"title": "Alaeddin Tepesi", "summary": "Konya''nın tam merkezinde yer alan bu tarihi tepe, üzerinde bulunan Alaeddin Camii ve Selçuklu saray kalıntılarıyla şehrin simgelerindendir. Şehrin panoramik manzarasını izlemek ve dinlenmek için ideal bir noktadır.", "place_query": "Alaeddin Tepesi, Selçuklu, Konya"}, {"title": "Selçuklu Kongre Merkezi", "summary": "Modern mimarisi ve geniş yeşil alanlarıyla dikkat çeken bu merkez, uluslararası kongrelere, konserlere ve kültürel etkinliklere ev sahipliği yapar. Çevresindeki yürüyüş yolları ve havuzlarıyla da ziyaretçilere huzurlu bir ortam sunar.", "place_query": "Selçuklu Kongre Merkezi, Selçuklu, Konya"}, {"title": "Sille Köyü", "summary": "Selçuklu ilçesine bağlı tarihi bir mahalle olan Sille, antik çağlardan kalma kaya kiliseleri ve taş evleriyle ünlüdür. Özellikle Aya Elena Kilisesi ve Sille Barajı çevresi, tarih ve doğayı bir arada arayanlar için keşfedilmeyi bekler.", "place_query": "Sille Köyü, Selçuklu, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '045f5d28-767f-44fe-8f9e-47d9bc989489'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Seydişehir Yerköprü Şelalesi", "summary": "Beyşehir-Seydişehir yolu üzerinde bulunan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilerine huzurlu bir atmosfer sunar. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için popüler bir durak noktasıdır.", "place_query": "Yerköprü Şelalesi, Seydişehir, Konya"}, {"title": "Seydişehir İlçe Merkezi ve Çarşısı", "summary": "Şehrin kalbi sayılabilecek bu bölge, tarihi yapıları ve hareketli çarşısıyla yerel yaşamı yakından tanımak isteyenler için idealdir. Alışveriş yapabilir, yöresel lezzetleri tadabilirsiniz.", "place_query": "Seydişehir Merkez, Konya"}, {"title": "Seydişehir Kültür Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla aileler için keyifli bir dinlenme noktasıdır. Park içindeki gölet ve kafeler, şehir merkezinde kısa bir kaçamak yapmak isteyenler için idealdir.", "place_query": "Seydişehir Kültür Parkı, Konya"}, {"title": "Seydişehir Tarihi Evleri", "summary": "Osmanlı döneminden kalma ahşap ve taş işçiliğinin güzel örneklerini barındıran bu evler, ilçenin kültürel mirasını yansıtır. Dar sokaklarda yürüyerek geçmişe kısa bir yolculuk yapabilirsiniz.", "place_query": "Seydişehir Tarihi Evler, Konya"}, {"title": "Seydişehir Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerinin sergilendiği bu müze, Seydişehir ve çevresinin tarihine ışık tutar. Ziyaretçiler, antik dönemlerden günümüze uzanan zengin bir koleksiyonu keşfedebilir.", "place_query": "Seydişehir Müzesi, Konya"}, {"title": "Seydişehir Göleti ve Mesire Alanı", "summary": "Şehir merkezine yakın konumda bulunan bu gölet, doğa yürüyüşleri ve piknik yapmak için popüler bir mekandır. Çevresindeki yeşil alanlar, hafta sonu kaçamakları için huzurlu bir ortam sağlar.", "place_query": "Seydişehir Göleti, Konya"}, {"title": "Seydişehir Süleyman Şah Türbesi", "summary": "Tarihi öneme sahip bu türbe, bölgenin manevi atmosferini hissetmek isteyenler tarafından ziyaret edilir. Yapı, Selçuklu dönemi mimarisinin izlerini taşır ve çevresiyle birlikte sakin bir ziyaret noktasıdır.", "place_query": "Süleyman Şah Türbesi, Seydişehir, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9fa913c7-f4f1-425a-9bb5-1360be0d3b2c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Taşkent Kalesi", "summary": "Taşkent ilçe merkezinde yer alan tarihi kale kalıntıları, bölgenin antik dönemlerine ışık tutuyor. Ziyaretçiler, kalenin surlarından çevredeki dağ manzarasını izleyebilir.", "place_query": "Taşkent Kalesi, Taşkent, Konya"}, {"title": "Balcılar Mağarası", "summary": "Taşkent''e bağlı Balcılar Mahallesi''nde bulunan bu mağara, doğal oluşumu ve sarkıtlarıyla dikkat çekiyor. Mağara içi serin havası ve ilginç kaya yapılarıyla doğa severler için ideal bir durak.", "place_query": "Balcılar Mağarası, Taşkent, Konya"}, {"title": "Sazak Yaylası", "summary": "Taşkent''in yüksek kesimlerinde yer alan Sazak Yaylası, yemyeşil çayırları ve temiz havasıyla piknik ve kamp için popülerdir. Yaz aylarında yerel halkın dinlenme alanı olarak da kullanılır.", "place_query": "Sazak Yaylası, Taşkent, Konya"}, {"title": "Taşkent Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle bahar aylarında coşkun akan sularıyla görsel bir şölen sunar. Çevresindeki doğal havuzlar ve yeşil alanlar, ziyaretçilere huzurlu bir ortam sağlar.", "place_query": "Taşkent Şelalesi, Taşkent, Konya"}, {"title": "Çetmi Köyü Tarihi Evleri", "summary": "Taşkent''e bağlı Çetmi Köyü''ndeki geleneksel taş ve ahşap evler, yöresel mimariyi yansıtır. Köy, sakin atmosferi ve tarihi dokusuyla fotoğrafçılar ve kültür turizmi meraklıları için keşfedilmeyi bekliyor.", "place_query": "Çetmi Köyü, Taşkent, Konya"}, {"title": "Taşkent Yaylası", "summary": "İlçe merkezine birkaç kilometre uzaklıktaki bu yayla, geniş otlakları ve çam ormanlarıyla ünlüdür. Doğa yürüyüşleri ve kamp aktiviteleri için sıkça tercih edilir.", "place_query": "Taşkent Yaylası, Taşkent, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3357554e-be8d-4383-a58a-0b2cf1505208'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tuzlukçu Konya Evleri", "summary": "Tuzlukçu ilçe merkezinde yer alan geleneksel Konya evleri, yöresel mimariyi yansıtan tarihi yapılarıyla dikkat çeker. Sokak aralarında yürüyerek geçmişe yolculuk yapabilirsiniz.", "place_query": "Tuzlukçu Konya Evleri, Tuzlukçu, Konya"}, {"title": "Tuzlukçu Çarşı Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve ibadet ile ziyaret için önemli bir duraktır.", "place_query": "Tuzlukçu Çarşı Camii, Tuzlukçu, Konya"}, {"title": "Tuzlukçu Göleti", "summary": "İlçe yakınlarında yer alan bu gölet, doğal güzelliği ve piknik alanlarıyla hafta sonu kaçamakları için idealdir. Kuş gözlemi ve doğa yürüyüşü yapabilirsiniz.", "place_query": "Tuzlukçu Göleti, Tuzlukçu, Konya"}, {"title": "Tuzlukçu İlçe Merkezi Pazar Yeri", "summary": "Haftalık kurulan pazar, yöresel ürünler ve el sanatlarını bulabileceğiniz renkli bir alışveriş noktasıdır. Yöre halkıyla kaynaşmak için güzel bir fırsattır.", "place_query": "Tuzlukçu Pazar Yeri, Tuzlukçu, Konya"}, {"title": "Tuzlukçu Yaylaları", "summary": "İlçe çevresindeki yaylalar, serin havası ve yeşil doğasıyla doğa severler için huzurlu bir kaçış noktasıdır. Kamp ve trekking için uygundur.", "place_query": "Tuzlukçu Yaylaları, Tuzlukçu, Konya"}, {"title": "Tuzlukçu Mesire Alanı", "summary": "Şehir merkezine yakın bu mesire alanı, aileler için piknik ve dinlenme imkanı sunar. Çocuk oyun alanları ve yeşil alanlarıyla keyifli vakit geçirebilirsiniz.", "place_query": "Tuzlukçu Mesire Alanı, Tuzlukçu, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6be09a13-e0de-45e3-808a-44b247d638aa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yalıhüyük Şelalesi", "summary": "Yalıhüyük ilçe merkezine yakın konumda yer alan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilerin ilgisini çeker. Özellikle bahar ve yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için ideal bir noktadır.", "place_query": "Yalıhüyük Şelalesi, Yalıhüyük, Konya"}, {"title": "Yalıhüyük Göleti", "summary": "İlçe sınırları içinde bulunan bu gölet, huzurlu atmosferi ve çevresindeki yeşil alanlarla doğa yürüyüşü ve piknik yapmak isteyenler için popüler bir duraktır. Gölet çevresinde balık tutma imkanı da bulunur.", "place_query": "Yalıhüyük Göleti, Yalıhüyük, Konya"}, {"title": "Yalıhüyük Merkez Camii", "summary": "İlçenin merkezinde yer alan bu tarihi camii, Osmanlı dönemi mimarisinin izlerini taşıyan sade ve etkileyici yapısıyla dikkat çeker. Hem ibadet hem de tarihi dokuya tanıklık etmek için ziyaret edilebilir.", "place_query": "Yalıhüyük Merkez Camii, Yalıhüyük, Konya"}, {"title": "Yalıhüyük Kent Ormanı", "summary": "Şehir merkezine yakın bu ormanlık alan, yürüyüş parkurları ve dinlenme banklarıyla doğaseverler için kaçış noktasıdır. Temiz havası ve sessiz ortamıyla günübirlik ziyaretler için uygundur.", "place_query": "Yalıhüyük Kent Ormanı, Yalıhüyük, Konya"}, {"title": "Yalıhüyük Kalesi (Hisar)", "summary": "İlçe yakınlarındaki tarihi kale kalıntıları, bölgenin geçmişine ışık tutan önemli bir arkeolojik alandır. Kalıntılar arasında yürüyerek hem tarihi keşfedebilir hem de çevredeki manzarayı izleyebilirsiniz.", "place_query": "Yalıhüyük Kalesi, Yalıhüyük, Konya"}, {"title": "Sille Mahallesi (Yakın Çevre)", "summary": "Yalıhüyük''e yaklaşık 1 saat mesafedeki bu tarihi mahalle, taş evleri, kiliseleri ve kültürel dokusuyla ünlüdür. Özellikle Aya Eleni Kilisesi ve tarihi çarşısıyla ziyaretçilere farklı bir deneyim sunar.", "place_query": "Sille Mahallesi, Selçuklu, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1ac89905-0ebb-44f2-a8d4-d70f250ff903'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yunak Kalesi", "summary": "Tarihi bir kaledir ve bölgenin en önemli simgelerinden biridir. Ziyaretçilere hem tarihi bir atmosfer sunar hem de çevredeki doğal güzellikleri izleme imkanı verir.", "place_query": "Yunak Kalesi, Yunak, Konya"}, {"title": "Yunak Göleti", "summary": "Doğal bir gölet olup piknik ve dinlenme alanlarıyla çevrilidir. Huzurlu atmosferi ve yeşil doğasıyla hafta sonu kaçamakları için idealdir.", "place_query": "Yunak Göleti, Yunak, Konya"}, {"title": "Yunak İlçe Merkezi ve Tarihi Çarşı", "summary": "İlçe merkezindeki tarihi çarşı, yöresel ürünler ve el sanatlarıyla ünlüdür. Geleneksel mimari dokusuyla ziyaretçilere otantik bir alışveriş deneyimi sunar.", "place_query": "Yunak Tarihi Çarşı, Yunak, Konya"}, {"title": "Yunak Kültür Evi", "summary": "Yöresel kültürü yansıtan eserlerin sergilendiği bir müze evidir. Bölgenin tarihini ve geleneklerini yakından tanımak isteyenler için önemli bir duraktır.", "place_query": "Yunak Kültür Evi, Yunak, Konya"}, {"title": "Yunak Şelalesi", "summary": "Doğal bir şelale olup çevresi yürüyüş parkurları ve piknik alanlarıyla donatılmıştır. Serin suları ve yeşil doğasıyla doğa severler için popüler bir mekandır.", "place_query": "Yunak Şelalesi, Yunak, Konya"}, {"title": "Yunak Orman İçi Dinlenme Alanı", "summary": "Geniş çam ormanları içinde yer alan bu dinlenme alanı, kamp ve doğa yürüyüşleri için uygundur. Temiz havası ve sessiz ortamıyla şehir stresinden uzaklaşmak isteyenler için idealdir.", "place_query": "Yunak Orman İçi Dinlenme Alanı, Yunak, Konya"}, {"title": "Yunak Yaylası", "summary": "Yüksek rakımlı bir yayla olup yaz aylarında serinlemek için tercih edilir. Yemyeşil doğası, yayla evleri ve geleneksel yaşam tarzıyla ziyaretçilere huzurlu bir deneyim sunar.", "place_query": "Yunak Yaylası, Yunak, Konya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '56ee0213-737f-459c-8989-d301a6fc9ae3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Altıntaş Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve yürüyüş yapmak için idealdir. Çocuk oyun alanları ve yeşil alanlarıyla aileler için popüler bir buluşma noktasıdır.", "place_query": "Altıntaş Belediye Parkı, Altıntaş, Kütahya"}, {"title": "Altıntaş İlçe Camii", "summary": "İlçenin en büyük ve tarihi camilerinden biri olup, Osmanlı dönemi mimarisinin izlerini taşır. Dini ve kültürel bir ziyaret noktasıdır.", "place_query": "Altıntaş İlçe Camii, Altıntaş, Kütahya"}, {"title": "Seyitömer Höyüğü", "summary": "Altıntaş sınırları içinde yer alan bu antik höyük, Frig ve Roma dönemlerine ait kalıntılar barındırır. Tarih meraklıları için önemli bir arkeolojik alandır.", "place_query": "Seyitömer Höyüğü, Altıntaş, Kütahya"}, {"title": "Altıntaş Göleti", "summary": "Doğal güzelliği ve çevresindeki piknik alanlarıyla hafta sonu kaçamakları için tercih edilir. Gölet kenarında yürüyüş yapabilir ve kuş gözlemi gerçekleştirebilirsiniz.", "place_query": "Altıntaş Göleti, Altıntaş, Kütahya"}, {"title": "Kütahya Altıntaş Yaylası", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için huzurlu bir doğa kaçışı sunar. Yaylada kamp yapabilir ve yöresel bitki örtüsünü keşfedebilirsiniz.", "place_query": "Altıntaş Yaylası, Altıntaş, Kütahya"}, {"title": "Altıntaş Çinicilik Atölyeleri", "summary": "Kütahya''nın ünlü çini sanatını yakından görmek için ilçedeki küçük atölyeleri ziyaret edebilirsiniz. El yapımı çini ürünler satın alma imkanı da bulunur.", "place_query": "Altıntaş çini atölyeleri, Altıntaş, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fe9585c3-1934-4906-aa2b-40642c2f2dab'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aslanapa Merkez Camii ve Külliyesi", "summary": "İlçe merkezinde yer alan tarihi cami ve külliye, Osmanlı dönemi mimarisini yansıtan önemli bir yapıdır. Ziyaretçiler, hem ibadet edebilir hem de tarihi atmosferi yakından deneyimleyebilir.", "place_query": "Aslanapa Merkez Camii, Aslanapa, Kütahya"}, {"title": "Sorkun Köyü Tarihi Evleri", "summary": "Sorkun Köyü''ndeki geleneksel Osmanlı evleri, taş ve ahşap işçiliğiyle dikkat çeker. Köy, sakin atmosferi ve otantik dokusuyla doğa ve tarih severler için ideal bir durak noktasıdır.", "place_query": "Sorkun Köyü, Aslanapa, Kütahya"}, {"title": "Aslanapa Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumdaki gölet, piknik ve yürüyüş yapmak isteyenler için popüler bir dinlenme alanıdır. Çevresindeki yeşil alanlar ve su manzarası huzurlu bir gün geçirmek için idealdir.", "place_query": "Aslanapa Göleti, Aslanapa, Kütahya"}, {"title": "Karaağaç Şelalesi", "summary": "İlçeye bağlı Karaağaç Köyü yakınlarında bulunan şelale, doğal güzelliği ve serin sularıyla özellikle yaz aylarında ziyaretçi akınına uğrar. Çevredeki yürüyüş parkurları doğa tutkunlarını cezbeder.", "place_query": "Karaağaç Şelalesi, Aslanapa, Kütahya"}, {"title": "Yukarıkaraağaç Köyü Kaya Mezarları", "summary": "Yukarıkaraağaç Köyü''nde bulunan antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Arkeoloji meraklıları için keşfedilmeyi bekleyen ilginç bir duraktır.", "place_query": "Yukarıkaraağaç Köyü Kaya Mezarları, Aslanapa, Kütahya"}, {"title": "Aslanapa Yaylası", "summary": "İlçenin yüksek kesimlerinde yer alan yayla, temiz havası ve geniş otlaklarıyla doğa yürüyüşleri ve kamp için uygundur. Yayla şenlikleri döneminde yerel kültürü yakından tanıma fırsatı sunar.", "place_query": "Aslanapa Yaylası, Aslanapa, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fdc8ae70-f298-4696-bbf2-13bfdfd9064f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aizanoi Antik Kenti", "summary": "Çavdarhisar''ın en önemli tarihi hazinesi olan Aizanoi, muhteşem Zeus Tapınağı, antik tiyatrosu ve stadyumuyla Roma döneminin en iyi korunmuş kentlerinden biridir. Ziyaretçiler, 2. yüzyıldan kalma dünyanın ilk borsa binası ve antik baraj kalıntılarını da görebilir.", "place_query": "Aizanoi Antik Kenti, Çavdarhisar, Kütahya"}, {"title": "Zeus Tapınağı", "summary": "Aizanoi Antik Kenti''nin kalbinde yer alan bu devasa tapınak, Anadolu''nun en iyi korunmuş Roma dönemi Zeus tapınaklarından biridir. Yüksek sütunları ve etkileyici kabartmalarıyla ziyaretçilerini büyüler.", "place_query": "Zeus Tapınağı, Çavdarhisar, Kütahya"}, {"title": "Çavdarhisar Kalesi", "summary": "Küçük bir tepe üzerinde yer alan bu tarihi kale kalıntıları, bölgeye adını vermiş olup çevrenin panoramik manzarasını sunar. Özellikle gün batımında fotoğrafçılar için harika bir noktadır.", "place_query": "Çavdarhisar Kalesi, Çavdarhisar, Kütahya"}, {"title": "Aizanoi Antik Tiyatro ve Stadyum", "summary": "Birbirine bitişik inşa edilmiş bu eşsiz yapı kompleksi, antik dünyada nadir görülen bir mimari çözümdür. Tiyatro ve stadyumun birleştiği bu alan, hem gladyatör dövüşlerine hem de sanat gösterilerine ev sahipliği yapmıştır.", "place_query": "Aizanoi Antik Tiyatro, Çavdarhisar, Kütahya"}, {"title": "Pencerli Köprü", "summary": "Antik kent içinde yer alan ve hala kullanılan bu tarihi taş köprü, Roma döneminden günümüze ulaşmış nadir yapılardandır. Köprünün altından akan Kocaçay, özellikle yaz aylarında serin bir atmosfer sunar.", "place_query": "Pencerli Köprü, Çavdarhisar, Kütahya"}, {"title": "Meteor Krateri", "summary": "Çavdarhisar ilçe merkezine yaklaşık 7 km uzaklıkta bulunan bu doğal oluşum, 2 milyon yıl önce bir göktaşının düşmesiyle oluşmuştur. Krater çevresi, doğa yürüyüşleri ve piknik için ideal bir alandır.", "place_query": "Meteor Krateri, Çavdarhisar, Kütahya"}, {"title": "Çavdarhisar Müzesi", "summary": "Aizanoi kazılarında çıkarılan eserlerin sergilendiği bu küçük ama zengin müze, bölgenin tarihine ışık tutmaktadır. Heykeller, sikkeler, seramikler ve lahitler gibi birçok arkeolojik buluntuyu yakından görebilirsiniz.", "place_query": "Çavdarhisar Müzesi, Çavdarhisar, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9d36682a-6194-424b-a975-410679a5e3f0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Domaniç Şehitliği ve Anıtı", "summary": "Kurtuluş Savaşı''nın önemli duraklarından olan bu anıt, bölgenin tarihi önemini vurgular ve ziyaretçilere duygusal bir atmosfer sunar.", "place_query": "Domaniç Şehitliği, Domaniç, Kütahya"}, {"title": "Domaniç Yaylaları (Örneğin: Çukurca Yaylası)", "summary": "Yemyeşil doğası, temiz havası ve muhteşem manzaralarıyla ünlü yaylalar, doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Domaniç Yaylaları, Domaniç, Kütahya"}, {"title": "Domaniç Göleti", "summary": "Piknik alanları ve çevresindeki doğal güzelliklerle huzurlu bir gün geçirmek isteyenler için popüler bir mesire yeridir.", "place_query": "Domaniç Göleti, Domaniç, Kütahya"}, {"title": "Domaniç Müzesi", "summary": "İlçenin tarihini, kültürünü ve Kurtuluş Savaşı''ndaki rolünü yansıtan eserlerin sergilendiği küçük ama etkileyici bir müzedir.", "place_query": "Domaniç Müzesi, Domaniç, Kütahya"}, {"title": "Hisar (Domaniç Kalesi) Kalıntıları", "summary": "Tarihi bir tepe üzerinde yer alan kale kalıntıları, hem tarihi bir keşif hem de çevreye hakim bir seyir noktası sunar.", "place_query": "Domaniç Kalesi, Domaniç, Kütahya"}, {"title": "Kütahya-Domaniç Ormanları", "summary": "Geniş çam ve köknar ormanlarıyla kaplı bu bölge, doğa tutkunları için yürüyüş rotaları ve eşsiz bir bitki örtüsü barındırır.", "place_query": "Domaniç Ormanları, Domaniç, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a7bc74eb-ddd2-429f-bb88-843feb5edbef'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dumlupınar Şehitliği ve Zafer Anıtı", "summary": "Kurtuluş Savaşı''nın dönüm noktası olan Büyük Taarruz''un sona erdiği yerde bulunan bu anıt ve şehitlik, zaferin sembolüdür. Ziyaretçiler burada hem tarihi atmosferi soluyabilir hem de etkileyici anıtı görebilir.", "place_query": "Dumlupınar Şehitliği ve Zafer Anıtı, Kütahya"}, {"title": "Zafertepe Anıtı", "summary": "Büyük Taarruz''un son safhasında Başkomutan Mustafa Kemal Atatürk''ün ''Ordular, ilk hedefiniz Akdeniz''dir, ileri!'' emrini verdiği noktadır. Tepeden çevreyi seyrederken tarihe tanıklık edebilirsiniz.", "place_query": "Zafertepe Anıtı, Dumlupınar, Kütahya"}, {"title": "Dumlupınar Müzesi", "summary": "Kurtuluş Savaşı''na ait silah, mühimmat, fotoğraf ve belgelerin sergilendiği bu müze, savaşın izlerini yakından görmek isteyenler için önemli bir duraktır.", "place_query": "Dumlupınar Müzesi, Kütahya"}, {"title": "Çal Köyü Şehitliği", "summary": "Büyük Taarruz sırasında şehit düşen askerlerin anısına yapılmış bu şehitlik, sakin ve huzurlu ortamıyla ziyaretçilere duygusal bir deneyim sunar.", "place_query": "Çal Köyü Şehitliği, Dumlupınar, Kütahya"}, {"title": "Dumlupınar Kalesi", "summary": "Tarihi geçmişiyle bilinen bu küçük kale, çevreye hakim bir tepe üzerinde yer alır. Bölgenin stratejik önemini gözler önüne seren bir yapıdır.", "place_query": "Dumlupınar Kalesi, Kütahya"}, {"title": "Dumlupınar Yaylası", "summary": "Doğal güzellikleri ve temiz havasıyla bilinen yayla, özellikle yaz aylarında piknik ve doğa yürüyüşü için idealdir. Sakin bir kaçış noktası arayanlar için uygundur.", "place_query": "Dumlupınar Yaylası, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0670588b-ca0f-4df3-a89d-b304bce3f180'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Emet Termal Kaplıcaları", "summary": "Emet''in en bilinen şifa kaynağı olan termal suları, romatizma ve cilt hastalıklarına iyi gelmesiyle ünlüdür. Bölgede birçok otel ve kaplıca tesisi bulunur, özellikle kış aylarında yoğun ilgi görür.", "place_query": "Emet Termal Kaplıcaları, Emet, Kütahya"}, {"title": "Emet Şelalesi", "summary": "Yeşillikler içinde gizlenmiş bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Emet Şelalesi, Emet, Kütahya"}, {"title": "Ağaçköy Göleti ve Mesire Alanı", "summary": "Huzurlu bir doğa kaçamağı arayanlar için biçilmiş kaftan olan bu gölet, çevresindeki piknik alanları ve yürüyüş yollarıyla ailelerin favori mekanlarındandır. Manzarası fotoğrafçılar için de idealdir.", "place_query": "Ağaçköy Göleti, Emet, Kütahya"}, {"title": "Emet Müzesi", "summary": "İlçe merkezinde yer alan bu küçük müze, Emet ve çevresindeki antik yerleşimlerden çıkarılan arkeolojik eserleri sergiler. Bölgenin tarihine dair kısa ama etkileyici bir yolculuk sunar.", "place_query": "Emet Müzesi, Emet, Kütahya"}, {"title": "Çarşı Camii (Kurşunlu Camii)", "summary": "Emet''in tarihi dokusunu yansıtan bu cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Merkezi konumu sayesinde ilçe gezilerinde mutlaka uğranan bir duraktır.", "place_query": "Çarşı Camii, Emet, Kütahya"}, {"title": "Emet Kalesi Kalıntıları", "summary": "Tarihi bir tepe üzerinde yer alan kale kalıntıları, ilçeye hakim bir manzara sunar. Günümüze sadece temel ve sur parçaları ulaşsa da, bölgenin antik çağdaki savunma yapısını gösterir.", "place_query": "Emet Kalesi, Emet, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f45d787-5f07-4203-8808-2a44f4cac85c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gediz Ulu Camii", "summary": "Tarihi bir Osmanlı camisi olup, şehrin merkezinde yer alır. Mimari detayları ve manevi atmosferiyle ziyaretçilerin ilgisini çeker.", "place_query": "Gediz Ulu Camii, Gediz, Kütahya"}, {"title": "Murat Dağı", "summary": "Doğa yürüyüşleri ve kamp için ideal bir dağdır. Zengin flora ve fauna çeşitliliği ile doğaseverlerin uğrak noktasıdır.", "place_query": "Murat Dağı, Gediz, Kütahya"}, {"title": "Gediz Şehitler Çeşmesi", "summary": "Tarihi bir anıt çeşme olup, Kurtuluş Savaşı dönemine tanıklık eder. Bölgenin tarihi dokusunu yansıtan önemli bir noktadır.", "place_query": "Gediz Şehitler Çeşmesi, Gediz, Kütahya"}, {"title": "Akdağ Tabiat Parkı", "summary": "Piknik ve doğa ile iç içe vakit geçirmek için tercih edilen bir parktır. Yemyeşil ormanları ve temiz havasıyla huzur verir.", "place_query": "Akdağ Tabiat Parkı, Gediz, Kütahya"}, {"title": "Gediz Kalesi", "summary": "Tarihi bir kale kalıntısı olup, şehre hakim bir tepede yer alır. Gediz''in tarihi geçmişine ışık tutar ve panoramik manzara sunar.", "place_query": "Gediz Kalesi, Gediz, Kütahya"}, {"title": "Gediz Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen bir müzedir. Gediz ve çevresinin kültürel mirasını keşfetmek için idealdir.", "place_query": "Gediz Müzesi, Gediz, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a59b6b6f-fc43-46d8-a247-760d3dcf73a2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hisarcık Merkez Camii ve Külliyesi", "summary": "İlçe merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Ziyaretçiler, hem ibadet edebilir hem de tarihi atmosferi yakından hissedebilirler.", "place_query": "Hisarcık Merkez Camii, Hisarcık, Kütahya"}, {"title": "Hisarcık Kalesi", "summary": "İlçeye hakim bir tepe üzerinde bulunan kale kalıntıları, bölgenin tarihine ışık tutar. Kaleye tırmanarak hem tarihi keşfedebilir hem de muhteşem bir manzara izleyebilirsiniz.", "place_query": "Hisarcık Kalesi, Hisarcık, Kütahya"}, {"title": "Şaphane Dağı Milli Parkı", "summary": "Hisarcık sınırları içinde yer alan bu milli park, zengin bitki örtüsü ve temiz havasıyla doğa yürüyüşleri için idealdir. Piknik alanları ve seyir noktalarıyla hafta sonu kaçamakları için popüler bir destinasyondur.", "place_query": "Şaphane Dağı Milli Parkı, Hisarcık, Kütahya"}, {"title": "Çukurören Köyü Mağarası", "summary": "Doğal oluşumlu bu mağara, sarkıt ve dikitleriyle dikkat çeker. Mağara keşfi ve doğa fotoğrafçılığı için ilgi çekici bir noktadır.", "place_query": "Çukurören Köyü Mağarası, Hisarcık, Kütahya"}, {"title": "Karbasan Göleti", "summary": "Hisarcık''a bağlı Karbasan köyünde yer alan bu gölet, çevresindeki yeşil alanlarla birlikte piknik ve olta balıkçılığı için sakin bir ortam sunar. Doğayla iç içe vakit geçirmek isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Karbasan Göleti, Hisarcık, Kütahya"}, {"title": "Kütahya - Hisarcık Arası Tarihi Köprüler", "summary": "İlçe genelinde, özellikle kırsal kesimde Osmanlı döneminden kalma taş köprüler bulunur. Bu köprüler, tarihi doku ve mühendislik harikalarını görmek isteyenler için keşfedilmeyi bekleyen güzelliklerdir.", "place_query": "Hisarcık tarihi köprüler, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f6ea4ac8-306d-4cfc-9f03-a8f43b0b3e2f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kütahya Kalesi", "summary": "Şehre hakim bir tepe üzerinde yer alan tarihi kale, Friglerden Osmanlı''ya kadar birçok medeniyete ev sahipliği yapmıştır. Surları ve kuleleriyle etkileyici bir manzara sunar.", "place_query": "Kütahya Kalesi, Merkez, Kütahya"}, {"title": "Çini Müzesi", "summary": "Kütahya''nın dünyaca ünlü çini sanatını en iyi şekilde sergileyen müze, tarihi bir medrese binasında yer alır. Osmanlı ve Selçuklu dönemine ait nadide çini eserlerini görebilirsiniz.", "place_query": "Kütahya Çini Müzesi, Merkez, Kütahya"}, {"title": "Zafertepe Şehitliği ve Anıtı", "summary": "Büyük Taarruz''un kazanıldığı tepede yer alan bu anıt, Kurtuluş Savaşı''nın sembol mekanlarındandır. Şehitlik ve müze ile birlikte milli mücadele ruhunu hissettirir.", "place_query": "Zafertepe Şehitliği ve Anıtı, Merkez, Kütahya"}, {"title": "Germiyan Sokağı", "summary": "Restore edilmiş tarihi Osmanlı evleri, taş döşeli yolları ve çini atölyeleriyle ünlü bu sokak, Kütahya''nın kültürel dokusunu yansıtır. Hediyelik eşya alışverişi için de idealdir.", "place_query": "Germiyan Sokağı, Merkez, Kütahya"}, {"title": "Ulu Cami", "summary": "Kütahya''nın en büyük ve en eski camilerinden biri olan Ulu Cami, 14. yüzyılda Germiyanoğulları döneminde inşa edilmiştir. Ahşap işçiliği ve sade mimarisiyle dikkat çeker.", "place_query": "Ulu Cami, Merkez, Kütahya"}, {"title": "Kütahya Arkeoloji Müzesi", "summary": "Bölgedeki kazılardan çıkarılan Frig, Roma ve Bizans dönemine ait eserlerin sergilendiği müze, tarih meraklıları için önemli bir duraktır. Lahitler ve heykeller öne çıkar.", "place_query": "Kütahya Arkeoloji Müzesi, Merkez, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dfaac84f-2e88-426b-88d6-741291fd7d74'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pazarlar Merkez Camii ve Çevresi", "summary": "İlçe merkezinde yer alan tarihi cami, Pazarlar''ın kültürel ve dini hayatının kalbidir. Ziyaretçiler, caminin sade mimarisini ve çevresindeki geleneksel dükkanları görebilir.", "place_query": "Pazarlar Merkez Camii, Kütahya"}, {"title": "Pazarlar Kalesi", "summary": "İlçenin yüksek bir noktasında bulunan tarihi kale kalıntıları, bölgenin stratejik önemini gözler önüne serer. Kaleye çıktığınızda Pazarlar ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "Pazarlar Kalesi, Kütahya"}, {"title": "Sofça Köyü Tarihi Evleri", "summary": "Pazarlar''a bağlı Sofça Köyü, geleneksel Osmanlı dönemi mimarisini yansıtan taş ve ahşap evleriyle ünlüdür. Köyde dolaşırken geçmişe yolculuk yapmış gibi hissedersiniz.", "place_query": "Sofça Köyü, Pazarlar, Kütahya"}, {"title": "Yüreğil Göleti ve Mesire Alanı", "summary": "Doğayla iç içe vakit geçirmek isteyenler için ideal olan bu gölet, piknik alanları ve yürüyüş parkurları sunar. Özellikle bahar ve yaz aylarında huzurlu bir kaçış noktasıdır.", "place_query": "Yüreğil Göleti, Pazarlar, Kütahya"}, {"title": "Pazarlar İlçe Müzesi (Kültür Evi)", "summary": "İlçenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bu küçük müze, yöresel kıyafetler, tarım aletleri ve el sanatları ürünlerini barındırır. Pazarlar''ın geçmişine dair keyifli bir keşif sunar.", "place_query": "Pazarlar Kültür Evi, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dee26080-6cc2-4cb4-b486-48062fa39949'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şaphane Evleri", "summary": "Tarihi Osmanlı dönemine uzanan, yöresel mimariyi yansıtan ahşap ve taş yapılardan oluşan bu evler, ilçenin kültürel dokusunu keşfetmek isteyenler için ideal bir duraktır.", "place_query": "Şaphane Evleri, Şaphane, Kütahya"}, {"title": "Çamlıca Tepesi Seyir Noktası", "summary": "Şaphane ve çevresinin panoramik manzarasını sunan bu tepe, özellikle gün batımında ziyaretçilere huzur veren bir doğa deneyimi yaşatır.", "place_query": "Çamlıca Tepesi, Şaphane, Kütahya"}, {"title": "Karamık Göleti", "summary": "Şaphane yakınlarında yer alan bu gölet, piknik alanları ve doğal çevresiyle hafta sonu kaçamakları için popüler bir noktadır; ayrıca olta balıkçılığı da yapılabilir.", "place_query": "Karamık Göleti, Şaphane, Kütahya"}, {"title": "Şaphane Merkez Camii", "summary": "İlçenin tarihi camilerinden biri olan bu yapı, sade mimarisi ve manevi atmosferiyle dikkat çeker; çevresindeki çarşı da gezilebilir.", "place_query": "Merkez Camii, Şaphane, Kütahya"}, {"title": "Şaphane Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü bu yayla, doğa yürüyüşleri ve kamp yapmak isteyenler için sakin bir kaçış noktasıdır.", "place_query": "Şaphane Yaylası, Kütahya"}, {"title": "Kızık Yaylası", "summary": "Şaphane ilçe sınırları içinde bulunan bu yayla, zengin bitki örtüsü ve serin iklimiyle yaz aylarında sıkça ziyaret edilir.", "place_query": "Kızık Yaylası, Şaphane, Kütahya"}, {"title": "Şaphane Kalesi Kalıntıları", "summary": "Tarihi kalıntılar arasında yer alan bu kale, ilçenin savunma amaçlı geçmişine ışık tutar ve çevresindeki doğal güzelliklerle birleşir.", "place_query": "Şaphane Kalesi, Şaphane, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '468d2459-9e11-41ab-a593-de92adb87584'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Simav Kaplıcaları", "summary": "Simav''ın termal sularıyla ünlü kaplıcaları, şifalı suları ve modern tesisleriyle yıl boyunca ziyaretçi çeker. Romatizma ve cilt hastalıklarına iyi geldiğine inanılan sıcak sular, doğal güzellikler içinde huzurlu bir deneyim sunar.", "place_query": "Simav Kaplıcaları, Simav, Kütahya"}, {"title": "Simav Gölü (Çitgöl)", "summary": "Doğal bir krater gölü olan Simav Gölü, çevresindeki yemyeşil ormanlar ve piknik alanlarıyla doğa severler için ideal bir kaçış noktasıdır. Kuş gözlemi yapmak ve huzurlu bir yürüyüş için popülerdir.", "place_query": "Simav Gölü, Simav, Kütahya"}, {"title": "Hisar Bey Dağı ve Seyir Terası", "summary": "Simav''a hakim bir tepede yer alan Hisar Bey Dağı, muhteşem manzarası ve temiz havasıyla ünlüdür. Zirveye çıkanlar tüm ilçeyi ve çevredeki dağları kuşbakışı görebilir.", "place_query": "Hisar Bey Dağı, Simav, Kütahya"}, {"title": "Simav Kalesi", "summary": "Tarihi bir Bizans yapısı olan Simav Kalesi, ilçenin en eski yapılarından biridir. Kalıntıları günümüze ulaşan kale, tarih meraklıları için ilgi çekici bir durak ve çevresinden şehir manzarası sunar.", "place_query": "Simav Kalesi, Simav, Kütahya"}, {"title": "Ağaçköy (Eynal Kaplıcaları)", "summary": "Simav''ın Eynal bölgesinde yer alan Ağaçköy, termal suları ve doğal güzellikleriyle dikkat çeker. Özellikle Eynal Kaplıcaları, şifalı suları ve konaklama imkanlarıyla sağlık turizmi için önemli bir merkezdir.", "place_query": "Eynal Kaplıcaları, Simav, Kütahya"}, {"title": "Simav Müzesi", "summary": "İlçe merkezinde bulunan Simav Müzesi, bölgenin arkeolojik ve etnografik eserlerini sergiler. Antik dönemden Osmanlı''ya uzanan geniş bir koleksiyon, ziyaretçilere Simav''ın zengin tarihini keşfetme fırsatı sunar.", "place_query": "Simav Müzesi, Simav, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '647a8e72-934a-4093-91ea-a8d887e270a1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tavşanlı Belediye Müzesi", "summary": "Kentin tarihini ve kültürel mirasını sergileyen bu müze, arkeolojik eserler ve etnografik objelerle ziyaretçilere Tavşanlı''nın geçmişine dair keyifli bir yolculuk sunuyor.", "place_query": "Tavşanlı Belediye Müzesi, Tavşanlı, Kütahya"}, {"title": "Tavşanlı Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale, çevresine hakim manzarası ve antik kalıntılarıyla bölgenin savunma yapılarına dair önemli izler taşıyor.", "place_query": "Tavşanlı Kalesi, Tavşanlı, Kütahya"}, {"title": "Tavşanlı Kaplıcaları", "summary": "Termal sularıyla ünlü bu kaplıcalar, şifalı suları ve dinlendirici atmosferiyle sağlık turizmi açısından popüler bir durak noktasıdır.", "place_query": "Tavşanlı Kaplıcaları, Tavşanlı, Kütahya"}, {"title": "Köşk Hamamı", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan Köşk Hamamı, mimarisi ve geleneksel hamam kültürünü deneyimlemek isteyenler için ideal bir mekandır.", "place_query": "Köşk Hamamı, Tavşanlı, Kütahya"}, {"title": "Tavşanlı Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, sade ve etkileyici yapısıyla şehrin en önemli dini yapılarından biridir.", "place_query": "Tavşanlı Ulu Camii, Tavşanlı, Kütahya"}, {"title": "Çamlıca Mesire Alanı", "summary": "Yeşil doğası ve piknik alanlarıyla Tavşanlı''nın en popüler mesire yerlerinden biri olan Çamlıca, aileler ve doğa severler için huzurlu bir kaçış noktası sunuyor.", "place_query": "Çamlıca Mesire Alanı, Tavşanlı, Kütahya"}, {"title": "Tavşanlı Kent Ormanı", "summary": "Şehir merkezine yakın konumuyla yürüyüş ve doğa sporları için tercih edilen bu ormanlık alan, temiz havası ve yürüyüş parkurlarıyla dikkat çekiyor.", "place_query": "Tavşanlı Kent Ormanı, Tavşanlı, Kütahya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8c8dd7ec-e610-476e-9113-06f23b71d700'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akçadağ Pınarbaşı Mesire Alanı", "summary": "Akçadağ ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu mesire alanı, doğal güzellikleri ve piknik alanlarıyla bilinir. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için ideal bir yerdir.", "place_query": "Pınarbaşı Mesire Alanı, Akçadağ, Malatya"}, {"title": "Akçadağ Kalesi", "summary": "İlçenin tarihi simgelerinden biri olan Akçadağ Kalesi, stratejik bir tepe üzerine kurulmuştur. Kalıntıları günümüze ulaşan kale, bölgenin tarihine tanıklık etmek isteyen ziyaretçiler için önemli bir duraktır.", "place_query": "Akçadağ Kalesi, Akçadağ, Malatya"}, {"title": "Levent Vadisi", "summary": "Akçadağ sınırları içinde yer alan Levent Vadisi, eşsiz kaya oluşumları ve doğal yapısıyla dikkat çeker. Vadide yürüyüş yapabilir, fotoğrafçılıkla ilgilenenler için benzersiz manzaralar keşfedebilirsiniz.", "place_query": "Levent Vadisi, Akçadağ, Malatya"}, {"title": "Akçadağ Şelalesi", "summary": "Doğa severler için popüler bir rota olan Akçadağ Şelalesi, yeşillikler arasında akan sularıyla huzur verici bir atmosfer sunar. Özellikle bahar aylarında suyun debisi artar ve görsel bir şölen oluşur.", "place_query": "Akçadağ Şelalesi, Akçadağ, Malatya"}, {"title": "Karakaya Baraj Gölü (Akçadağ Kıyıları)", "summary": "Malatya''nın önemli su kaynaklarından Karakaya Baraj Gölü''nün Akçadağ kıyıları, doğal güzellikleri ve sakin atmosferiyle bilinir. Balık tutma, piknik yapma ve manzara izleme gibi aktiviteler için uygundur.", "place_query": "Karakaya Baraj Gölü, Akçadağ, Malatya"}, {"title": "Akçadağ Yaylaları (Örnek: Kürecik Yaylası)", "summary": "Akçadağ çevresindeki yaylalar, özellikle yaz aylarında serin havası ve doğal bitki örtüsüyle ziyaretçileri cezbeder. Kürecik Yaylası gibi noktalar, doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Kürecik Yaylası, Akçadağ, Malatya"}, {"title": "Akçadağ Tarihi Köprüleri", "summary": "İlçede bulunan Osmanlı dönemine ait tarihi taş köprüler, mimari yapıları ve bölgenin geçmişine ışık tutmasıyla önemlidir. Bu köprüler, özellikle tarih meraklıları için görülmeye değer noktalardır.", "place_query": "Akçadağ Tarihi Köprüleri, Akçadağ, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '02f77e5b-1503-49aa-a189-115fd4cd342f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Arapgir Eski Evleri", "summary": "Tarihi dokusuyla ünlü Arapgir''in restore edilmiş taş ve ahşap evleri, dar sokakları ve geleneksel mimarisiyle ziyaretçilere geçmişe yolculuk yaptırıyor.", "place_query": "Arapgir Eski Evleri, Arapgir, Malatya"}, {"title": "Arapgir Ulu Camii", "summary": "Selçuklu döneminden kalma bu tarihi cami, kesme taş işçiliği ve zarif mimarisiyle Arapgir''in en önemli dini yapılarından biridir.", "place_query": "Arapgir Ulu Camii, Arapgir, Malatya"}, {"title": "Kozluk Çayı ve Mesire Alanı", "summary": "Doğal güzelliği ve serin sularıyla ünlü Kozluk Çayı, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için ideal bir mekandır.", "place_query": "Kozluk Çayı, Arapgir, Malatya"}, {"title": "Arapgir Kalesi", "summary": "Tarihi kalıntıları ve şehre hakim konumuyla Arapgir Kalesi, bölgenin stratejik önemini gözler önüne seren bir seyir noktasıdır.", "place_query": "Arapgir Kalesi, Arapgir, Malatya"}, {"title": "Taşdelen Köprüsü", "summary": "Tarihi bir Osmanlı köprüsü olan Taşdelen Köprüsü, mimari yapısı ve çevresindeki doğal manzarasıyla fotoğrafçıların ve tarih meraklılarının uğrak noktasıdır.", "place_query": "Taşdelen Köprüsü, Arapgir, Malatya"}, {"title": "Arapgir Müzesi", "summary": "Yöresel etnografik eserlerin ve arkeolojik buluntuların sergilendiği Arapgir Müzesi, ilçenin kültürel mirasını yakından tanıma fırsatı sunar.", "place_query": "Arapgir Müzesi, Arapgir, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '565d138d-2cb8-46dc-8488-049c570c75cd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Arguvan Kalesi", "summary": "Tarihi bir kaledir; bölgenin savunma yapılarından biri olarak bilinir. Ziyaretçiler, kalenin kalıntıları arasında dolaşırken tarihi atmosferi hissedebilir ve çevredeki doğal manzarayı izleyebilir.", "place_query": "Arguvan Kalesi, Arguvan, Malatya"}, {"title": "Arguvan Barajı", "summary": "Bölgenin önemli su kaynaklarından biridir; çevresindeki yeşil alanlar ve sakin ortamıyla piknik ve doğa yürüyüşü için idealdir. Baraj gölü manzarası fotoğrafçılık için de popülerdir.", "place_query": "Arguvan Barajı, Arguvan, Malatya"}, {"title": "Sultansuyu Tabiat Parkı", "summary": "Malatya merkeze yakın olan bu tabiat parkı, zengin bitki örtüsü ve piknik alanlarıyla bilinir. Doğa yürüyüşleri, kamp ve kuş gözlemi gibi aktiviteler için uygundur.", "place_query": "Sultansuyu Tabiat Parkı, Malatya"}, {"title": "Arguvan Höyükleri", "summary": "Bölgede birçok höyük bulunur; bunlar, eski yerleşim izlerini taşıyan arkeolojik alanlardır. Tarih meraklıları için keşfedilmeyi bekleyen önemli noktalardır.", "place_query": "Arguvan Höyükleri, Arguvan, Malatya"}, {"title": "Karakaya Barajı (Arguvan çevresi)", "summary": "Fırat Nehri üzerinde kurulu büyük bir barajdır; Arguvan sınırlarına yakın kıyıları doğal güzellik sunar. Tekne turları ve balıkçılık için popüler bir destinasyondur.", "place_query": "Karakaya Barajı, Arguvan, Malatya"}, {"title": "Arguvan Yaylaları", "summary": "Bölgenin serin yaylaları, özellikle yaz aylarında doğa ile baş başa kalmak isteyenler için idealdir. Yaylalarda geleneksel yaşamı gözlemleyebilir ve temiz havanın tadını çıkarabilirsiniz.", "place_query": "Arguvan Yaylaları, Arguvan, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a3cc4372-71c1-462f-bab6-d9f13c085530'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Battalgazi Ulu Camii", "summary": "Selçuklu döneminin en önemli eserlerinden biri olan bu cami, 1224 yılında inşa edilmiştir. Devasa taç kapısı, geniş avlusu ve tarihi dokusuyla ziyaretçilerini büyüler.", "place_query": "Battalgazi Ulu Camii, Battalgazi, Malatya"}, {"title": "Malatya Arkeoloji Müzesi", "summary": "Hitit, Roma, Bizans ve Osmanlı dönemlerine ait binlerce eserin sergilendiği müze, özellikle Aslantepe Höyüğü''nden çıkarılan buluntularıyla ünlüdür.", "place_query": "Malatya Arkeoloji Müzesi, Battalgazi, Malatya"}, {"title": "Aslantepe Höyüğü", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu antik kent, M.Ö. 5000 yılına kadar uzanan geçmişiyle dünyanın bilinen en eski şehir devletlerinden biridir.", "place_query": "Aslantepe Höyüğü, Battalgazi, Malatya"}, {"title": "Malatya Kent Müzesi", "summary": "Şehrin tarihini, kültürünü ve günlük yaşamını interaktif sergilerle anlatan müze, Malatya''nın geçmişine dair kapsamlı bir bakış sunar.", "place_query": "Malatya Kent Müzesi, Battalgazi, Malatya"}, {"title": "Taşhoron Kilisesi (Surp Kevork Ermeni Kilisesi)", "summary": "19. yüzyıldan kalma bu tarihi Ermeni kilisesi, restore edilerek kültürel etkinliklere ev sahipliği yapmaktadır. Mimari detayları ve huzurlu atmosferiyle dikkat çeker.", "place_query": "Taşhoron Kilisesi, Battalgazi, Malatya"}, {"title": "Battalgazi Eski Şehir (Meliha) ve Surları", "summary": "Eski Malatya olarak da bilinen Battalgazi merkezinde, Selçuklu ve Osmanlı döneminden kalma sur kalıntıları, tarihi evler ve dar sokaklar gezilebilir.", "place_query": "Battalgazi Eski Şehir Surları, Battalgazi, Malatya"}, {"title": "Günpınar Şelalesi", "summary": "Battalgazi''ye yaklaşık 40 km uzaklıkta, Darende ilçesi sınırlarında yer alan bu şelale, doğal güzelliği ve piknik alanlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Günpınar Şelalesi, Darende, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2b3e9060-095d-450a-a9c7-a1ab45afd96a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Somuncu Baba Türbesi ve Külliyesi", "summary": "Darende''nin manevi merkezi olan bu külliye, ünlü mutasavvıf Somuncu Baba''nın türbesini barındırır. Osmanlı ve Selçuklu mimarisinin izlerini taşıyan yapı, her yıl binlerce ziyaretçiyi ağırlar.", "place_query": "Somuncu Baba Türbesi, Darende, Malatya"}, {"title": "Günpınar Şelalesi", "summary": "Türkiye''nin en yüksek debili şelalelerinden biri olan Günpınar, yemyeşil doğası ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Şelalenin çevresindeki mesire alanı özellikle yaz aylarında yoğun ilgi görür.", "place_query": "Günpınar Şelalesi, Darende, Malatya"}, {"title": "Darende Balaban Vadisi", "summary": "Balaban Vadisi, doğal kaya oluşumları ve mağaralarıyla dikkat çeken, trekking ve fotoğrafçılık için popüler bir doğa harikasıdır. Vadi boyunca uzanan yürüyüş parkuru, ziyaretçilere eşsiz manzaralar sunar.", "place_query": "Balaban Vadisi, Darende, Malatya"}, {"title": "Zinciriye Medresesi", "summary": "Selçuklu dönemine ait tarihi bir yapı olan Zinciriye Medresesi, taş işçiliği ve mimarisiyle göz kamaştırır. Medrese, geçmişte önemli bir eğitim kurumu olarak hizmet vermiştir.", "place_query": "Zinciriye Medresesi, Darende, Malatya"}, {"title": "Arapgir Kapısı (Darende Kalesi)", "summary": "Tarihi Darende Kalesi''nin günümüze ulaşan en belirgin yapısı olan Arapgir Kapısı, bölgenin savunma tarihine ışık tutar. Kale kalıntıları ve kapı, şehre hakim bir tepede yer alır.", "place_query": "Arapgir Kapısı, Darende, Malatya"}, {"title": "Hacılar Kalesi", "summary": "Darende''ye bağlı Hacılar Mahallesi''nde yer alan bu tarihi kale, etkileyici surları ve dar sokaklarıyla ziyaretçilerini geçmişe yolculuğa çıkarır. Kalenin tepesinden çevrenin panoramik manzarası izlenebilir.", "place_query": "Hacılar Kalesi, Darende, Malatya"}, {"title": "Darende Müzesi", "summary": "Darende Müzesi, bölgenin arkeolojik ve etnografik zenginliklerini sergileyen küçük ama kapsamlı bir müzedir. Hitit, Roma, Bizans ve Osmanlı dönemlerine ait eserler burada görülebilir.", "place_query": "Darende Müzesi, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bf1dce25-5065-433e-95a7-4daef3ef2c67'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eskiköy Şelalesi", "summary": "Doğanşehir''in doğal güzelliklerinden biri olan şelale, yeşillikler içinde huzurlu bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek ve piknik yapmak için ziyaret edilir.", "place_query": "Eskiköy Şelalesi, Doğanşehir, Malatya"}, {"title": "Polat Şelalesi", "summary": "Doğanşehir ilçe merkezine yakın konumuyla bilinen Polat Şelalesi, doğa yürüyüşleri ve fotoğrafçılık için popüler bir duraktır. Çevresi mesire alanı olarak düzenlenmiştir.", "place_query": "Polat Şelalesi, Doğanşehir, Malatya"}, {"title": "Doğanşehir Kalesi", "summary": "Tarihi bir kalıntı olan Doğanşehir Kalesi, bölgenin geçmişine ışık tutar. Tepe üzerindeki konumu sayesinde çevreye hakim bir manzara sunar.", "place_query": "Doğanşehir Kalesi, Doğanşehir, Malatya"}, {"title": "Sürgü Göleti", "summary": "Doğanşehir''in Sürgü Mahallesi''nde bulunan bu gölet, doğal güzelliği ve huzurlu atmosferiyle bilinir. Balık tutma ve piknik için ideal bir yerdir.", "place_query": "Sürgü Göleti, Doğanşehir, Malatya"}, {"title": "Kurucaova Yaylası", "summary": "Doğanşehir''e bağlı Kurucaova''da yer alan yayla, serin havası ve geniş yeşil alanlarıyla yaz aylarında kaçış noktasıdır. Doğa yürüyüşleri ve kamp için uygundur.", "place_query": "Kurucaova Yaylası, Doğanşehir, Malatya"}, {"title": "Gündeğdi Yaylası", "summary": "Yüksek rakımı ve temiz havasıyla bilinen Gündeğdi Yaylası, Doğanşehir''de doğayla iç içe vakit geçirmek isteyenlerin tercihidir. Yayla şenliklerine de ev sahipliği yapar.", "place_query": "Gündeğdi Yaylası, Doğanşehir, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bed9c267-9fb1-489a-af80-bf4251991bd7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Doğanyol Kalesi", "summary": "Tarihi bir kaledir ve bölgenin en önemli simgelerinden biridir. Ziyaretçilerine hem tarihi bir atmosfer hem de çevredeki doğal güzellikleri izleme fırsatı sunar.", "place_query": "Doğanyol Kalesi, Doğanyol, Malatya"}, {"title": "Keban Baraj Gölü (Doğanyol Kıyıları)", "summary": "Keban Barajı''nın Doğanyol sınırları içinde kalan kıyı şeridi, huzurlu bir doğa kaçamağı arayanlar için idealdir. Göl manzarası eşliğinde piknik yapabilir ve doğa yürüyüşleri gerçekleştirebilirsiniz.", "place_query": "Keban Baraj Gölü Doğanyol Kıyısı, Malatya"}, {"title": "Sürgü Çayı", "summary": "Doğanyol''dan geçen bu akarsu, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için popüler bir noktadır. Çevresindeki yeşil alanlar piknik için elverişlidir.", "place_query": "Sürgü Çayı, Doğanyol, Malatya"}, {"title": "Gökçe Köyü Mağaraları", "summary": "Doğanyol yakınlarındaki Gökçe Köyü''nde bulunan doğal mağaralar, keşfedilmeyi bekleyen gizli güzelliklerdendir. Mağaralar, bölgenin jeolojik yapısını gözlemlemek isteyenler için ilgi çekicidir.", "place_query": "Gökçe Köyü Mağaraları, Doğanyol, Malatya"}, {"title": "Doğanyol Yaylaları", "summary": "Bölgenin serin ve temiz havasını soluyabileceğiniz yaylaları, doğa yürüyüşleri ve kamp için uygundur. Özellikle yaz aylarında şehir hayatından kaçmak isteyenler için huzurlu bir ortam sunar.", "place_query": "Doğanyol Yaylaları, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'efb626d0-08e2-495e-817f-12fb63c67e5e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hekimhan Kalesi", "summary": "Tarihi bir kaya kütlesi üzerine inşa edilmiş olan bu kale, Hekimhan''ın simgesi konumundadır. Bölgenin stratejik önemini yansıtan kaleyi ziyaret ederek çevrenin panoramik manzarasını izleyebilirsiniz.", "place_query": "Hekimhan Kalesi, Hekimhan, Malatya"}, {"title": "Taşhan (Hekimhan Taşhanı)", "summary": "Selçuklu dönemine ait tarihi bir kervansaray olan Taşhan, restore edilerek günümüze kazandırılmıştır. İçerisinde yöresel ürünlerin satıldığı dükkanlar ve kafeler bulunur.", "place_query": "Taşhan, Hekimhan, Malatya"}, {"title": "Hasançelebi Kalesi", "summary": "Hekimhan''a bağlı Hasançelebi Mahallesi''nde yer alan bu tarihi kale, doğal kaya oluşumları üzerine kuruludur. Bölgenin en etkileyici yapılarından biri olup ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Hasançelebi Kalesi, Hekimhan, Malatya"}, {"title": "Güzelyurt Mağarası", "summary": "Doğal oluşumlu bu mağara, sarkıt ve dikitleriyle dikkat çeker. Doğa severler için keşfedilmeyi bekleyen bir durak olup, çevresindeki piknik alanlarıyla da tercih edilir.", "place_query": "Güzelyurt Mağarası, Hekimhan, Malatya"}, {"title": "Hekimhan Müzesi", "summary": "İlçe merkezinde bulunan bu küçük müze, yöreye ait arkeolojik ve etnografik eserleri sergilemektedir. Hekimhan''ın kültürel tarihine dair önemli ipuçları sunar.", "place_query": "Hekimhan Müzesi, Hekimhan, Malatya"}, {"title": "Yamaç Paraşütü ve Doğa Sporları Alanı", "summary": "Hekimhan''ın yüksek tepeleri, özellikle yamaç paraşütü gibi doğa sporları için elverişli bir ortam sunar. Bölge, adrenalin tutkunları ve doğa yürüyüşçüleri için idealdir.", "place_query": "Hekimhan yamaç paraşütü alanı, Malatya"}, {"title": "Kurşunlu Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olan Kurşunlu Camii, kesme taş işçiliği ve mimarisiyle dikkat çeker. İlçenin dini ve kültürel mirasının önemli bir parçasıdır.", "place_query": "Kurşunlu Camii, Hekimhan, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'be7d3791-6a3c-4ed1-ada4-36debe69bb46'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kale İçi Kalesi", "summary": "İlçeye adını veren tarihi kale, Malatya Ovası''na hakim bir tepe üzerinde kuruludur. Hitit, Roma ve Bizans dönemlerinde kullanılmış olup, bölgenin stratejik önemini yansıtan etkileyici bir yapıdır.", "place_query": "Kale İçi Kalesi, Kale, Malatya"}, {"title": "Kale Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu doğal şelale, özellikle bahar ve yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir piknik ve mesire alanıdır.", "place_query": "Kale Şelalesi, Kale, Malatya"}, {"title": "İzollu Köprüsü", "summary": "Tarihi bir taş köprü olan İzollu Köprüsü, Osmanlı dönemi mimarisinin güzel örneklerindendir. Çevresindeki doğal doku ile birlikte fotoğrafçılar ve tarih meraklıları için ideal bir durak noktasıdır.", "place_query": "İzollu Köprüsü, Kale, Malatya"}, {"title": "Kale Kapalı Çarşı", "summary": "İlçe merkezinde yer alan bu kapalı çarşı, yöresel ürünlerin ve el sanatlarının satıldığı küçük dükkanlarıyla bilinir. Özellikle Malatya kayısısı ve yöresel lezzetleri satın almak için uğranabilecek canlı bir noktadır.", "place_query": "Kale Kapalı Çarşı, Kale, Malatya"}, {"title": "Kale Atatürk Parkı", "summary": "İlçenin merkezinde bulunan bu park, dinlenmek ve yürüyüş yapmak için en çok tercih edilen yeşil alanlardan biridir. Anıtı ve oturma alanlarıyla aileler için sakin bir ortam sunar.", "place_query": "Kale Atatürk Parkı, Kale, Malatya"}, {"title": "Yukarı Düvenci Mağarası", "summary": "Kale ilçesi sınırları içinde yer alan bu doğal mağara, sarkıt ve dikit oluşumlarıyla dikkat çeker. Mağara meraklıları ve doğa yürüyüşü sevenler için keşfedilmeyi bekleyen ilginç bir noktadır.", "place_query": "Yukarı Düvenci Mağarası, Kale, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '41b443f6-507d-4b31-876c-bc6771e584fb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kuluncak Kalesi", "summary": "İlçe merkezine hakim bir tepede yer alan tarihi bir kaledir. Bölgenin savunma tarihine ışık tutar ve çevresindeki vadi manzarasıyla dikkat çeker.", "place_query": "Kuluncak Kalesi, Kuluncak, Malatya"}, {"title": "Sürgü Çayı Mesire Alanı", "summary": "Sürgü Çayı boyunca uzanan bu mesire alanı, piknik ve doğa yürüyüşü için idealdir. Özellikle yaz aylarında serinlemek için bölge halkı tarafından sıkça tercih edilir.", "place_query": "Sürgü Çayı Mesire Alanı, Kuluncak, Malatya"}, {"title": "Kuluncak Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla bilinen bu yayla, şehir hayatından kaçmak isteyenler için huzurlu bir kaçış noktasıdır. Yayla şenliklerine de ev sahipliği yapar.", "place_query": "Kuluncak Yaylası, Kuluncak, Malatya"}, {"title": "Boztepe Mesire Alanı", "summary": "Çam ormanlarıyla kaplı bu mesire alanı, kamp ve doğa sporları için uygun bir ortam sunar. Manzarasıyla fotoğraf tutkunlarının da ilgisini çeker.", "place_query": "Boztepe Mesire Alanı, Kuluncak, Malatya"}, {"title": "Kuluncak Etnografya Müzesi", "summary": "Yöresel kıyafetler, tarım aletleri ve günlük yaşam objelerinin sergilendiği bu küçük müze, Kuluncak''ın kültürel geçmişine dair önemli ipuçları sunar.", "place_query": "Kuluncak Etnografya Müzesi, Kuluncak, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c195b0ef-2dfb-4c4f-80df-ce202ce68090'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pütürge Şelalesi", "summary": "Pütürge ilçe merkezine yakın bir konumda yer alan bu doğal şelale, çevresindeki yeşil alanlarla birlikte piknik ve doğa yürüyüşü için ideal bir noktadır.", "place_query": "Pütürge Şelalesi, Pütürge, Malatya"}, {"title": "Kale Köyü Kalesi", "summary": "Tarihi bir kalıntı olan Kale Köyü Kalesi, bölgenin antik dönemlerine ışık tutan önemli bir arkeolojik alandır ve çevresindeki manzarasıyla dikkat çeker.", "place_query": "Kale Köyü Kalesi, Pütürge, Malatya"}, {"title": "Pütürge Ulu Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, geleneksel mimarisi ve huzurlu atmosferiyle ziyaretçilerin ilgisini çeken bir dini yapıdır.", "place_query": "Pütürge Ulu Camii, Pütürge, Malatya"}, {"title": "Kömürhan Köprüsü", "summary": "Pütürge sınırları içinde yer alan bu tarihi köprü, Fırat Nehri üzerinde uzanır ve bölgenin önemli bir ulaşım ve seyir noktasıdır.", "place_query": "Kömürhan Köprüsü, Pütürge, Malatya"}, {"title": "Pütürge Yaylaları", "summary": "Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için tercih edilen yaylalar, zengin bitki örtüsü ve temiz havasıyla ünlüdür.", "place_query": "Pütürge Yaylaları, Pütürge, Malatya"}, {"title": "Tepehan Göleti", "summary": "Pütürge''ye bağlı Tepehan köyü yakınlarında bulunan bu gölet, çevresindeki mesire alanıyla piknik ve olta balıkçılığı için popüler bir yerdir.", "place_query": "Tepehan Göleti, Pütürge, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '773d5bad-96a4-49ec-b204-e70d8b23789e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yazıhan Kalesi", "summary": "Tarihi bir kale olup bölgenin stratejik noktalarından biridir. Ziyaretçiler burada tarihi dokuyu ve çevredeki doğal manzarayı keşfedebilir.", "place_query": "Yazıhan Kalesi, Yazıhan, Malatya"}, {"title": "Karakaya Barajı ve Çevresi", "summary": "Fırat Nehri üzerinde yer alan büyük bir baraj olup doğal güzellikleri ve su sporları olanaklarıyla dikkat çeker. Piknik ve manzara izleme için idealdir.", "place_query": "Karakaya Barajı, Yazıhan, Malatya"}, {"title": "Yazıhan Ulu Camii", "summary": "Tarihi bir cami olup mimarisiyle ve manevi atmosferiyle ziyaretçileri cezbeder. Bölgenin kültürel mirasını yansıtan önemli bir yapıdır.", "place_query": "Yazıhan Ulu Camii, Yazıhan, Malatya"}, {"title": "Fırat Nehri Kenarı", "summary": "Doğal bir alan olup yürüyüş, balık tutma ve dinlenme için popülerdir. Nehir manzarası eşliğinde huzurlu bir deneyim sunar.", "place_query": "Fırat Nehri, Yazıhan, Malatya"}, {"title": "Yazıhan Eski Köprüsü", "summary": "Tarihi bir taş köprü olup bölgenin geçmişine tanıklık eder. Fotoğrafçılık ve tarihi keşif için ideal bir noktadır.", "place_query": "Yazıhan Eski Köprüsü, Yazıhan, Malatya"}, {"title": "Yazıhan Yaylası", "summary": "Doğal bir yayla olup serin havası ve yeşil alanlarıyla doğa severler için kaçış noktasıdır. Kamp ve doğa yürüyüşü için uygundur.", "place_query": "Yazıhan Yaylası, Yazıhan, Malatya"}, {"title": "Yazıhan Müzesi (varsayılan)", "summary": "Bölgenin tarihini ve kültürünü sergileyen bir müzedir. Arkeolojik eserler ve etnografik objelerle ziyaretçilere bilgi sunar.", "place_query": "Yazıhan Müzesi, Yazıhan, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a9cc2eea-07c7-4d70-82dc-05579eb2d7c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Malatya Müzesi", "summary": "Bölgenin zengin tarihini yansıtan eserlerin sergilendiği modern bir müze. Hitit, Roma, Bizans ve Osmanlı dönemlerine ait arkeolojik buluntuları ve yöresel etnografik objeleri keşfedebilirsiniz.", "place_query": "Malatya Müzesi, Yeşilyurt, Malatya"}, {"title": "Battalgazi Ulu Camii", "summary": "Anadolu Selçuklu mimarisinin en güzel örneklerinden biri olan bu tarihi cami, 13. yüzyıldan günümüze ulaşmıştır. Etkileyici taş işçiliği ve huzurlu atmosferiyle ziyaretçilerini büyüler.", "place_query": "Battalgazi Ulu Camii, Malatya"}, {"title": "Aslantepe Höyüğü", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu antik kent, Geç Hitit dönemine ait önemli bir yerleşimdir. Kazılarda ortaya çıkarılan saray, tapınak ve anıtsal heykeller tarihe ışık tutuyor.", "place_query": "Aslantepe Höyüğü, Malatya"}, {"title": "Karakaya Barajı ve Çevresi", "summary": "Fırat Nehri üzerinde kurulu devasa baraj gölü, etkileyici manzarası ve doğal güzelliğiyle dikkat çeker. Piknik, balık tutma ve tekne turları için popüler bir kaçış noktasıdır.", "place_query": "Karakaya Barajı, Malatya"}, {"title": "Taşhoron Kalesi", "summary": "Yeşilyurt ilçe merkezine yakın, kayalık bir tepe üzerine kurulu tarihi bir kaledir. Roma ve Bizans dönemlerinden izler taşıyan kale, Malatya Ovası''nın panoramik manzarasını sunar.", "place_query": "Taşhoron Kalesi, Yeşilyurt, Malatya"}, {"title": "Kurşunlu Camii ve Külliyesi", "summary": "Osmanlı döneminden kalma bu tarihi külliye, cami, medrese ve türbeden oluşur. İnce işçiliği ve sade mimarisiyle huzur veren bir atmosfere sahiptir.", "place_query": "Kurşunlu Camii, Yeşilyurt, Malatya"}, {"title": "Orduzu Pınarbaşı Mesire Alanı", "summary": "Yeşilyurt sınırlarında yer alan bu mesire alanı, doğal kaynak suları ve piknik alanlarıyla ünlüdür. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Orduzu Pınarbaşı, Yeşilyurt, Malatya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2638f4aa-3ac8-4349-b4f6-27979e57e58d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ahmetli Göleti ve Mesire Alanı", "summary": "Doğa ile iç içe piknik yapmak ve yürüyüş yapmak isteyenler için ideal bir alandır. Gölet çevresinde dinlenme imkanı sunar.", "place_query": "Ahmetli Göleti, Ahmetli, Manisa"}, {"title": "Ahmetli Şelalesi", "summary": "Bölgenin serinletici doğal güzelliklerinden biridir. Özellikle bahar ve yaz aylarında şelale çevresi doğa severlerin uğrak noktasıdır.", "place_query": "Ahmetli Şelalesi, Ahmetli, Manisa"}, {"title": "Tarihi Ahmetli Köprüsü", "summary": "Osmanlı döneminden kalma taş köprü, ilçenin tarihi dokusunu yansıtan önemli bir yapıdır. Fotoğrafçılar için güzel bir kare sunar.", "place_query": "Tarihi Ahmetli Köprüsü, Ahmetli, Manisa"}, {"title": "Gölcük Yaylası", "summary": "Ahmetli yakınlarındaki bu yayla, yeşil doğası ve temiz havasıyla kamp ve doğa yürüyüşleri için popülerdir. Manzarası ziyaretçileri büyüler.", "place_query": "Gölcük Yaylası, Ahmetli, Manisa"}, {"title": "Ahmetli Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, mimarisi ve huzur veren atmosferi ile dikkat çeker. Ziyaretçiler için manevi bir duraktır.", "place_query": "Ahmetli Merkez Camii, Ahmetli, Manisa"}, {"title": "Deliktaş Mağarası", "summary": "Ahmetli sınırları içinde yer alan bu doğal mağara, ilginç kaya oluşumları ve gizemli atmosferiyle macera arayanları cezbeder.", "place_query": "Deliktaş Mağarası, Ahmetli, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd9132612-7007-4f10-9ef4-0c6166d9d322'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akhisar Arkeoloji Müzesi", "summary": "Antik Thyateira kentinden çıkarılan eserlerin sergilendiği müze, bölgenin zengin tarihine ışık tutuyor. Özellikle Roma ve Bizans dönemine ait heykel, sikke ve seramik koleksiyonları dikkat çekiyor.", "place_query": "Akhisar Arkeoloji Müzesi, Akhisar, Manisa"}, {"title": "Thyateira Antik Kenti", "summary": "Binlerce yıllık geçmişe sahip bu antik kent, Anadolu''nun önemli yerleşimlerinden biriydi. Günümüzde kazı çalışmaları devam eden alanda, sütunlu cadde ve hamam kalıntıları görülebiliyor.", "place_query": "Thyateira Antik Kenti, Akhisar, Manisa"}, {"title": "Akhisar Kalesi", "summary": "Şehir merkezine hakim bir tepede bulunan tarihi kale, Bizans ve Osmanlı dönemlerinden izler taşıyor. Kaleye çıktığınızda Akhisar''ın panoramik manzarasını izleyebilirsiniz.", "place_query": "Akhisar Kalesi, Akhisar, Manisa"}, {"title": "Akhisar Zeytin ve Zeytinyağı Müzesi", "summary": "Bölgenin zeytincilik kültürünü tanıtan bu müze, geleneksel üretim aletlerinden modern tesislere kadar geniş bir koleksiyon sunuyor. Zeytinyağının tarihine dair keyifli bir yolculuk vaat ediyor.", "place_query": "Akhisar Zeytin ve Zeytinyağı Müzesi, Akhisar, Manisa"}, {"title": "Karaosmanoğlu Camii", "summary": "Osmanlı döneminden kalma bu tarihi cami, zarif mimarisi ve iç süslemeleriyle dikkat çekiyor. Şehrin en eski ibadethanelerinden biri olarak huzurlu bir atmosfere sahiptir.", "place_query": "Karaosmanoğlu Camii, Akhisar, Manisa"}, {"title": "Akhisar Kervansarayı", "summary": "Tarihi İpek Yolu üzerinde yer alan bu yapı, ticaret kervanlarının konaklaması için inşa edilmiş. Günümüzde restore edilerek kültürel etkinliklere ev sahipliği yapmaktadır.", "place_query": "Akhisar Kervansarayı, Akhisar, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4cf9116e-553a-474d-a941-2e6607c004aa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alaşehir Antik Kenti (Philadelphia)", "summary": "Tarihi Lidya bölgesinin önemli kentlerinden biri olan Philadelphia, özellikle erken Hristiyanlık dönemindeki yedi kiliseden birine ev sahipliği yapmasıyla ünlüdür. Antik tiyatro, stadyum ve Bizans dönemi yapılarının kalıntılarını görebilirsiniz.", "place_query": "Alaşehir Antik Kenti Philadelphia, Manisa"}, {"title": "Alaşehir St. Jean Kilisesi", "summary": "Hristiyanlık tarihinde önemli bir yere sahip olan ve İncil''de adı geçen yedi kiliseden biri olan St. Jean Kilisesi, Bizans dönemine ait mozaik ve fresk kalıntılarıyla dikkat çeker. Tarihi atmosferiyle ziyaretçilerini etkiler.", "place_query": "St. Jean Kilisesi Alaşehir Manisa"}, {"title": "Alaşehir Çarşı Hamamı", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan Çarşı Hamamı, geleneksel Türk hamam kültürünü deneyimlemek isteyenler için ideal bir noktadır. Restore edilmiş yapısıyla şehrin merkezinde kolayca ziyaret edilebilir.", "place_query": "Alaşehir Çarşı Hamamı Manisa"}, {"title": "Kurudere Şelalesi", "summary": "Alaşehir''e yaklaşık 20 km uzaklıkta bulunan Kurudere Şelalesi, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için popüler bir mekandır. Özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Kurudere Şelalesi Alaşehir Manisa"}, {"title": "Alaşehir Atatürk Evi Müzesi", "summary": "Mustafa Kemal Atatürk''ün 1925 yılında Alaşehir''i ziyareti sırasında kaldığı ev, günümüzde müze olarak hizmet vermektedir. Kurtuluş Savaşı dönemine ait fotoğraflar ve belgeler sergilenmektedir.", "place_query": "Alaşehir Atatürk Evi Müzesi Manisa"}, {"title": "Alaşehir Kalesi", "summary": "Şehir merkezine hakim bir tepede yer alan Alaşehir Kalesi, Bizans ve Osmanlı dönemlerinde kullanılmış tarihi bir savunma yapısıdır. Kaleye çıktığınızda Alaşehir manzarasını kuşbakışı izleyebilirsiniz.", "place_query": "Alaşehir Kalesi Manisa"}, {"title": "Sardes Antik Kenti (Sart)", "summary": "Alaşehir''e yaklaşık 30 km mesafedeki Sardes, Lidya Krallığı''nın başkenti ve tarihte ilk paranın basıldığı yer olarak bilinir. Artemis Tapınağı ve antik sinagogu ile ünlüdür.", "place_query": "Sardes Antik Kenti Sart Salihli Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7dad9add-5d5b-4b39-a8f6-f3f71e79cdaf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Demirci Şelalesi", "summary": "Demirci ilçe merkezine yaklaşık 20 km uzaklıkta, doğal güzelliğiyle ünlü bir şelaledir. Çevresi piknik alanları ve yürüyüş parkurlarıyla ziyaretçilere huzurlu bir doğa deneyimi sunar.", "place_query": "Demirci Şelalesi, Demirci, Manisa"}, {"title": "Ağaçhisar Kalesi", "summary": "Demirci ilçesinin Ağaçhisar köyünde yer alan tarihi bir kaledir. Bizans döneminden kalma yapı, bölgenin stratejik önemini ve tarihini yansıtan etkileyici kalıntılara sahiptir.", "place_query": "Ağaçhisar Kalesi, Demirci, Manisa"}, {"title": "Demirci Kanyonu", "summary": "İlçenin kuzeyinde yer alan bu kanyon, sarp kayalıkları ve yemyeşil bitki örtüsüyle doğa tutkunları için ideal bir rotadır. Kanyon içinde yürüyüş yapabilir ve eşsiz manzaraları fotoğraflayabilirsiniz.", "place_query": "Demirci Kanyonu, Demirci, Manisa"}, {"title": "Kula-Demirci Jeoparkı", "summary": "UNESCO tarafından tescillenmiş bu jeopark, volkanik oluşumlar ve peri bacalarıyla ünlüdür. Demirci sınırları içinde kalan bölümleriyle ziyaretçilere eşsiz bir jeolojik miras sunar.", "place_query": "Kula-Demirci Jeoparkı, Demirci, Manisa"}, {"title": "Demirci Müzesi", "summary": "İlçe merkezinde bulunan bu müze, bölgenin tarihini ve kültürel mirasını sergiler. Arkeolojik eserler, etnografik objeler ve yöresel el sanatları koleksiyonuyla dikkat çeker.", "place_query": "Demirci Müzesi, Demirci, Manisa"}, {"title": "Sarıçam Tabiat Parkı", "summary": "Demirci''ye bağlı Sarıçam köyü yakınlarındaki bu tabiat parkı, sık çam ormanları ve temiz havasıyla kampçılar ve doğa yürüyüşçüleri için popüler bir duraktır.", "place_query": "Sarıçam Tabiat Parkı, Demirci, Manisa"}, {"title": "Demirci Yaylası", "summary": "İlçenin yüksek kesimlerinde yer alan bu yayla, serin yaz aylarında kaçış noktasıdır. Yemyeşil çayırları ve geleneksel yayla evleriyle huzurlu bir atmosfer sunar.", "place_query": "Demirci Yaylası, Demirci, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd2c50312-5d05-4689-862e-f44bc65edf6b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölmarmara Gölü", "summary": "İlçeye adını veren doğal göl, kuş gözlemciliği ve piknik için popülerdir. Özellikle bahar aylarında çevresi yeşillenir ve huzurlu bir doğa kaçamağı sunar.", "place_query": "Gölmarmara Gölü, Gölmarmara, Manisa"}, {"title": "Gölmarmara Mesire Alanı", "summary": "Göl kenarında yer alan bu mesire alanı, aileler için mangal ve piknik yapma imkanı sağlar. Çocuk oyun alanları ve yürüyüş yolları ile hafta sonu ziyaretçilerinin uğrak noktasıdır.", "place_query": "Gölmarmara Mesire Alanı, Gölmarmara, Manisa"}, {"title": "Kocaçay Mesire Alanı", "summary": "Kocaçay deresi boyunca uzanan bu mesire alanı, serin suları ve gölge ağaçlarıyla yaz aylarında serinlemek için idealdir. Doğal bir ortamda piknik yapmak isteyenler tarafından tercih edilir.", "place_query": "Kocaçay Mesire Alanı, Gölmarmara, Manisa"}, {"title": "Gölmarmara Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, ilçenin geçmişine ışık tutar. Tepe üzerinde yer aldığından çevreye hakim bir manzara sunar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Gölmarmara Kalesi, Gölmarmara, Manisa"}, {"title": "Gölmarmara Atatürk Parkı", "summary": "İlçe merkezinde bulunan bu park, dinlenmek ve kısa bir yürüyüş yapmak için uygundur. Atatürk büstü ve yeşil alanlarıyla yerel halkın buluşma noktalarından biridir.", "place_query": "Atatürk Parkı, Gölmarmara, Manisa"}, {"title": "Sarıçam Yaylası", "summary": "Gölmarmara''ya bağlı köylerde yer alan bu yayla, temiz havası ve doğal güzellikleri ile bilinir. Özellikle yaz aylarında doğa yürüyüşü ve kamp için tercih edilen bir rotadır.", "place_query": "Sarıçam Yaylası, Gölmarmara, Manisa"}, {"title": "Gölmarmara Etnografya Evi", "summary": "Yöresel kültürü yansıtan bu küçük müze, geçmişe ait eşyalar ve geleneksel yaşam hakkında bilgi verir. İlçenin tarihini ve kültürünü yakından tanımak isteyenler için önerilir.", "place_query": "Gölmarmara Etnografya Evi, Gölmarmara, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1c2765f2-4a0f-4f41-ac05-99fed0fdaced'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gördes Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan kale, Gördes''in en eski yapılarından biridir ve çevresine hakim manzarasıyla ziyaretçilerine eşsiz bir seyir imkanı sunar.", "place_query": "Gördes Kalesi, Gördes, Manisa"}, {"title": "Gördes Halı ve Kilim Atölyeleri", "summary": "Dünyaca ünlü Gördes halılarının dokunduğu atölyeler, el emeği göz nuru eserleri yakından görmek ve geleneksel dokuma sanatını yerinde keşfetmek için ideal bir durak noktasıdır.", "place_query": "Gördes Halı Atölyeleri, Gördes, Manisa"}, {"title": "Güneşli Köyü Şelalesi", "summary": "Doğal güzelliğiyle öne çıkan bu şelale, çevresindeki yeşil alanlar ve serin sularıyla piknik ve doğa yürüyüşü yapmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Güneşli Köyü Şelalesi, Gördes, Manisa"}, {"title": "Durasıllı Mahallesi Kaya Mezarları", "summary": "Antik döneme ait kaya oyma mezarlar, bölgenin tarih öncesi yerleşimine ışık tutan önemli arkeolojik kalıntılar arasında yer alır ve tarih meraklıları için keşfedilmeyi bekler.", "place_query": "Durasıllı Kaya Mezarları, Gördes, Manisa"}, {"title": "Gördes Barajı ve Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla bilinen baraj çevresi, özellikle hafta sonlarında ailelerin piknik yapıp doğayla iç içe vakit geçirebileceği sakin bir rekreasyon alanıdır.", "place_query": "Gördes Barajı, Gördes, Manisa"}, {"title": "Yeldeğirmeni Tepe Seyir Noktası", "summary": "Gördes''in panoramik manzarasını kuşbakışı izleyebileceğiniz bu tepe, gün batımında eşsiz fotoğraf kareleri yakalamak isteyen ziyaretçilerin uğrak noktalarından biridir.", "place_query": "Yeldeğirmeni Tepe, Gördes, Manisa"}, {"title": "Kurşunlu Mahallesi Tarihi Çeşmeler", "summary": "Osmanlı döneminden kalma taş işçiliğiyle dikkat çeken tarihi çeşmeler, ilçenin kültürel mirasını yansıtan ve fotoğraflamak için ideal olan duraklardandır.", "place_query": "Kurşunlu Mahallesi Tarihi Çeşmeler, Gördes, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd609df29-8553-4dab-9ff8-37a8c53f661c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kırkağaç Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu kale, bölgeye hakim manzarası ve geçmiş dönemlere ait izleriyle ziyaretçilere hem tarihi bir yolculuk hem de doğa yürüyüşü imkanı sunar.", "place_query": "Kırkağaç Kalesi, Kırkağaç, Manisa"}, {"title": "Bakırçay Mesire Alanı", "summary": "Bakırçay Nehri kenarında yer alan bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Bakırçay Mesire Alanı, Kırkağaç, Manisa"}, {"title": "Kırkağaç Kent Müzesi", "summary": "İlçenin kültürel mirasını ve tarihini yansıtan eserlerin sergilendiği bu müze, Kırkağaç''ın geçmişine dair keyifli bir keşif sunar.", "place_query": "Kırkağaç Kent Müzesi, Kırkağaç, Manisa"}, {"title": "Kırkağaç Çınar Ağacı", "summary": "Tarihi ve anıtsal boyutlarıyla dikkat çeken bu dev çınar ağacı, ilçe merkezinde doğal bir simge olarak ziyaretçilerin ilgisini çeker.", "place_query": "Kırkağaç Çınar Ağacı, Kırkağaç, Manisa"}, {"title": "Kırkağaç Hamidiye Camii", "summary": "Osmanlı dönemine ait bu tarihi cami, mimari özellikleri ve sade güzelliğiyle ilçenin önemli dini yapılarından biridir.", "place_query": "Kırkağaç Hamidiye Camii, Kırkağaç, Manisa"}, {"title": "Kırkağaç Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, Kırkağaç''ın sembol yapılarından biri olup çevresindeki alan buluşma noktası olarak kullanılır.", "place_query": "Kırkağaç Saat Kulesi, Kırkağaç, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '213bf1aa-0f98-4b9d-89a5-48126eab1205'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köprübaşı Barajı ve Mesire Alanı", "summary": "Doğal güzelliği ve huzurlu atmosferiyle piknik yapmak, yürüyüş yapmak ve manzaranın tadını çıkarmak için ideal bir noktadır. Baraj gölü çevresinde dinlenme alanları bulunur.", "place_query": "Köprübaşı Barajı, Köprübaşı, Manisa"}, {"title": "Güneşli Şelalesi", "summary": "Köprübaşı''nın doğal güzelliklerinden biri olan şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler tarafından ziyaret edilir.", "place_query": "Güneşli Şelalesi, Köprübaşı, Manisa"}, {"title": "Köprübaşı Merkez Camii ve Tarihi Çarşı", "summary": "İlçenin merkezinde yer alan tarihi cami ve çevresindeki çarşı, yöresel ürünleri görmek ve kısa bir kültür turu yapmak için uğranabilecek bir duraktır.", "place_query": "Köprübaşı Merkez Camii, Manisa"}, {"title": "Boruçukuru Göleti", "summary": "Doğa yürüyüşleri ve olta balıkçılığı için popüler bir durak olan gölet, sakin atmosferiyle hafta sonu kaçamakları için tercih edilir.", "place_query": "Boruçukuru Göleti, Köprübaşı, Manisa"}, {"title": "Köprübaşı Yaylaları (Örneğin: Gölcük Yaylası)", "summary": "İlçenin yüksek kesimlerinde bulunan yaylalar, temiz havası ve yeşil doğasıyla doğaseverler için keşfedilmeyi bekleyen güzellikler sunar.", "place_query": "Gölcük Yaylası, Köprübaşı, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c16c19db-98e8-4bbf-ab0e-04d11513d896'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kula Volkanik Jeoparkı", "summary": "Dünyanın en genç volkanik alanlarından biri olan bu jeopark, peri bacaları, kraterler ve lav akıntılarıyla eşsiz bir doğal manzara sunar. UNESCO Küresel Jeopark ağında yer alan bölge, doğa yürüyüşleri ve fotoğrafçılık için idealdir.", "place_query": "Kula Volkanik Jeoparkı, Kula, Manisa"}, {"title": "Kula Evleri (Tarihi Kula Evleri)", "summary": "Osmanlı döneminden kalma, taş ve ahşap işçiliğinin zarif örnekleri olan tarihi evler, dar sokakları ve geleneksel mimarisiyle ziyaretçileri geçmişe götürür. Birçoğu butik otel ve restoran olarak hizmet vermektedir.", "place_query": "Tarihi Kula Evleri, Kula, Manisa"}, {"title": "Kula Peribacaları", "summary": "Jeoparkın en dikkat çekici noktalarından biri olan peribacaları, volkanik tüflerin aşınmasıyla oluşmuş ilginç kaya oluşumlarıdır. Özellikle gün batımında muhteşem bir fotoğraf karesi sunar.", "place_query": "Kula Peribacaları, Kula, Manisa"}, {"title": "Divlit Yanardağı Krateri", "summary": "Kula Volkanik Jeoparkı''nın en belirgin kraterlerinden biri olan Divlit, yaklaşık 10 bin yıl önce patlamış genç bir volkandır. Krater çevresindeki yürüyüş parkuru ve manzarası görülmeye değerdir.", "place_query": "Divlit Yanardağı Krateri, Kula, Manisa"}, {"title": "Kula Şelalesi", "summary": "Şehrin gürültüsünden uzak, yeşillikler içinde gizlenmiş bu şelale, serinlemek ve doğayla baş başa kalmak isteyenler için popüler bir piknik ve mesire alanıdır.", "place_query": "Kula Şelalesi, Kula, Manisa"}, {"title": "Kula Kent Müzesi", "summary": "Eski bir hükümet konağında hizmet veren müze, Kula''nın tarihini, kültürünü ve volkanik jeolojisini sergileyen zengin koleksiyonlara ev sahipliği yapar. Bölgeyi tanımak için iyi bir başlangıç noktasıdır.", "place_query": "Kula Kent Müzesi, Kula, Manisa"}, {"title": "Kula Kalesi", "summary": "Roma ve Bizans dönemlerinde kullanılmış olan tarihi kale, şehre tepeden bakan bir konumda yer alır. Kalıntıları günümüze ulaşan kaleden Kula Ovası''nın panoramik manzarası izlenebilir.", "place_query": "Kula Kalesi, Kula, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7b40bb9f-a41e-4cd2-852e-592e47d5f66c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sardes Antik Kenti", "summary": "Lidya Krallığı''nın başkenti olan bu antik kent, tarihte ilk parayı basan uygarlığa ev sahipliği yapmıştır. Artemis Tapınağı ve devasa Gymnasium yapısı en dikkat çekici kalıntıları arasındadır.", "place_query": "Sardes Antik Kenti, Salihli, Manisa"}, {"title": "Salihli Çayı ve Mesire Alanı", "summary": "Şehir merkezinden geçen Salihli Çayı boyunca uzanan yürüyüş yolları ve yeşil alanlar, piknik ve dinlenme için ideal bir ortam sunar. Özellikle hafta sonları ailelerin uğrak noktasıdır.", "place_query": "Salihli Çayı Mesire Alanı, Salihli, Manisa"}, {"title": "Kurşunlu Kaplıcaları", "summary": "Termal turizmin önemli merkezlerinden biri olan Kurşunlu Kaplıcaları, romatizmal ve cilt rahatsızlıklarına iyi gelen şifalı sularıyla ünlüdür. Modern tesisleri sayesinde konforlu bir termal tatil imkanı sunar.", "place_query": "Kurşunlu Kaplıcaları, Salihli, Manisa"}, {"title": "Gölmarmara Kuş Cenneti", "summary": "Marmara Gölü kıyısında yer alan bu doğal alan, yüzlerce kuş türüne ev sahipliği yapar ve kuş gözlemciliği için mükemmel bir noktadır. Sazlıklar ve su kuşları eşliğinde huzurlu bir doğa deneyimi yaşatır.", "place_query": "Gölmarmara Kuş Cenneti, Salihli, Manisa"}, {"title": "Salihli Kent Müzesi", "summary": "Bölgenin tarihini, kültürünü ve etnografik zenginliklerini sergileyen bu müze, Salihli''nin geçmişine ışık tutar. Lidya, Roma ve Osmanlı dönemlerine ait eserler ziyaretçileri beklemektedir.", "place_query": "Salihli Kent Müzesi, Salihli, Manisa"}, {"title": "Karaoğlanlı Göleti ve Piknik Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal olan bu gölet, çam ormanlarıyla çevrilidir. Yürüyüş parkurları ve piknik masalarıyla sakin bir gün geçirmek mümkündür.", "place_query": "Karaoğlanlı Göleti, Salihli, Manisa"}, {"title": "Adala Kanyonu", "summary": "Salihli''ye bağlı Adala beldesinde yer alan bu kanyon, dik kayalıkları ve berrak akan Gediz Nehri ile doğa yürüyüşçüleri için eşsiz bir rotadır. Kanyon boyunca uzanan patikalar keşfedilmeyi bekler.", "place_query": "Adala Kanyonu, Salihli, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4c984351-e888-4f62-b824-196f2081c694'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıgöl Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla ziyaretçilerine huzurlu bir ortam sunan şelale, piknik ve doğa yürüyüşü için idealdir.", "place_query": "Sarıgöl Şelalesi, Sarıgöl, Manisa"}, {"title": "Kemer Köyü Kaya Evleri", "summary": "Tarihi taş yapıları ve otantik atmosferiyle dikkat çeken kaya evler, bölgenin kültürel mirasını yansıtmaktadır.", "place_query": "Kemer Köyü Kaya Evleri, Sarıgöl, Manisa"}, {"title": "Sarıgöl Ulu Camii", "summary": "Osmanlı dönemine ait tarihi cami, mimari detayları ve manevi atmosferiyle ziyaretçilerini etkilemektedir.", "place_query": "Sarıgöl Ulu Camii, Sarıgöl, Manisa"}, {"title": "Alaşehir Çayı Vadisi", "summary": "Yemyeşil doğası ve yürüyüş parkurlarıyla doğa severler için ideal bir rota olan vadi, kuş gözlemi için de uygundur.", "place_query": "Alaşehir Çayı Vadisi, Sarıgöl, Manisa"}, {"title": "Sarıgöl Kent Ormanı", "summary": "Şehir merkezine yakın konumuyla kolay ulaşılabilen ormanlık alan, piknik ve doğa yürüyüşü için popüler bir mekandır.", "place_query": "Sarıgöl Kent Ormanı, Sarıgöl, Manisa"}, {"title": "Yıldırım Köyü Tarihi Çeşmesi", "summary": "Geçmişten günümüze uzanan tarihi çeşme, köy meydanında yer alarak bölgenin kültürel dokusunu yansıtmaktadır.", "place_query": "Yıldırım Köyü Tarihi Çeşmesi, Sarıgöl, Manisa"}, {"title": "Sarıgöl Pazarı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı renkli pazar, hem alışveriş hem de yerel kültürü tanımak için idealdir.", "place_query": "Sarıgöl Pazarı, Sarıgöl, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '95a5577b-9dfc-4369-aa06-a394e5497d3a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saruhanlı Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, yürüyüş yolları ve oturma alanlarıyla aileler için huzurlu bir dinlenme noktasıdır. Hafta sonları piknik yapmak ve çocuklarla vakit geçirmek için idealdir.", "place_query": "Saruhanlı Belediye Parkı, Saruhanlı, Manisa"}, {"title": "Saruhanlı Halı Pazarı", "summary": "Yöresel el dokuması halı ve kilimlerin satıldığı bu pazar, kültürel mirası yakından görmek isteyen ziyaretçiler için popüler bir alışveriş durağıdır. Geleneksel motiflerle süslü ürünler hediyelik olarak da tercih edilir.", "place_query": "Saruhanlı Halı Pazarı, Saruhanlı, Manisa"}, {"title": "Koldere Köyü Kaya Mezarları", "summary": "Saruhanlı''ya bağlı Koldere Köyü''nde bulunan bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Doğa ve tarih iç içe geçmiş bu alan, keşif severler için sakin bir rotadır.", "place_query": "Koldere Köyü Kaya Mezarları, Saruhanlı, Manisa"}, {"title": "Saruhanlı Atatürk Evi", "summary": "Mustafa Kemal Atatürk''ün Manisa ziyaretleri sırasında konakladığı bu tarihi ev, günümüzde müze olarak hizmet vermektedir. İçerideki eşyalar ve fotoğraflar, Cumhuriyet tarihine tanıklık etme fırsatı sunar.", "place_query": "Saruhanlı Atatürk Evi, Saruhanlı, Manisa"}, {"title": "Saruhanlı Mesire Alanı", "summary": "İlçe çıkışında yeşillikler içinde yer alan bu mesire alanı, mangal ve piknik yapmak isteyenler için popüler bir kaçış noktasıdır. Temiz havası ve doğal gölgesiyle yaz aylarında sık tercih edilir.", "place_query": "Saruhanlı Mesire Alanı, Saruhanlı, Manisa"}, {"title": "Kumkuyucak Göleti", "summary": "Saruhanlı sınırlarındaki bu küçük gölet, çevresindeki ağaçlık alanla doğa yürüyüşü ve olta balıkçılığı için sakin bir ortam sunar. Kuş gözlemi yapmak isteyenler için de elverişlidir.", "place_query": "Kumkuyucak Göleti, Saruhanlı, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fef9cd73-d417-45c4-9c75-a55902735211'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Manisa Kalesi", "summary": "Antik dönemden günümüze ulaşan bu tarihi kale, Spil Dağı''nın eteklerinde şehre hakim bir noktada yer alır. Ziyaretçiler hem surların arasında tarihi hissedebilir hem de Manisa manzarasının keyfini çıkarabilir.", "place_query": "Manisa Kalesi, Şehzadeler, Manisa"}, {"title": "Sultan Camii ve Külliyesi", "summary": "15. yüzyılda II. Bayezid tarafından yaptırılan bu külliye, Osmanlı mimarisinin en güzel örneklerinden biridir. Cami, medrese, imaret ve şifahaneden oluşan yapı topluluğu, özellikle tarih ve kültür meraklıları için önemli bir duraktır.", "place_query": "Sultan Camii, Manisa, Şehzadeler"}, {"title": "Spil Dağı Milli Parkı", "summary": "Doğa yürüyüşleri, piknik alanları ve zengin bitki örtüsüyle ünlü olan milli park, aynı zamanda tarihi Sardes Antik Kenti''ne de ev sahipliği yapar. Ziyaretçiler hem doğayla iç içe vakit geçirebilir hem de antik kalıntıları keşfedebilir.", "place_query": "Spil Dağı Milli Parkı, Manisa"}, {"title": "Atatürk Evi Müzesi", "summary": "Manisa''nın kurtuluşu anısına Atatürk''ün kaldığı ev, bugün müze olarak hizmet vermektedir. O döneme ait eşyalar ve belgelerle dolu bu ev, Kurtuluş Savaşı tarihine ilgi duyanlar için etkileyici bir deneyim sunar.", "place_query": "Atatürk Evi Müzesi, Şehzadeler, Manisa"}, {"title": "Manisa Arkeoloji Müzesi", "summary": "Lidya, Roma ve Bizans dönemlerine ait zengin bir eser koleksiyonuna sahip olan müze, bölgenin tarihine ışık tutar. Heykeller, sikkeler ve günlük kullanım eşyaları, antik dünyaya dair merak uyandırıcı bir yolculuk vaat eder.", "place_query": "Manisa Arkeoloji Müzesi, Şehzadeler, Manisa"}, {"title": "Muradiye Camii", "summary": "16. yüzyılda Mimar Sinan tarafından inşa edilen bu cami, zarif minaresi ve geniş avlusuyla dikkat çeker. Osmanlı döneminin klasik mimari üslubunu yansıtan yapı, şehrin en önemli ibadet ve kültür mekanlarından biridir.", "place_query": "Muradiye Camii, Şehzadeler, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '74cb71ec-ae7c-4e9b-9668-3ecfbebb1977'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Selendi Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Selendi Şelalesi, Selendi, Manisa"}, {"title": "Selendi Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, bölgenin antik dönemine ışık tutar ve tepeden Selendi manzarasını izleme imkanı sunar.", "place_query": "Selendi Kalesi, Selendi, Manisa"}, {"title": "Çukuroba Köyü Kaya Mezarları", "summary": "Frig dönemine ait kaya mezarları, tarih meraklıları için etkileyici bir duraktır. Doğal kaya oluşumları içinde yer alan bu mezarlar bölgenin en önemli arkeolojik miraslarındandır.", "place_query": "Çukuroba Köyü Kaya Mezarları, Selendi, Manisa"}, {"title": "Gölbaşı Göleti ve Mesire Alanı", "summary": "Yeşillikler içinde huzurlu bir piknik alanı ve yürüyüş parkuru sunar. Gölet manzarası eşliğinde doğayla baş başa vakit geçirmek isteyenler için idealdir.", "place_query": "Gölbaşı Göleti, Selendi, Manisa"}, {"title": "Selendi Ulu Camii", "summary": "Osmanlı dönemi mimarisini yansıtan tarihi cami, ilçe merkezinde yer alır. Restore edilmiş yapısıyla hem ibadet hem de kültürel ziyaret noktasıdır.", "place_query": "Selendi Ulu Camii, Selendi, Manisa"}, {"title": "Karaburun Mağarası", "summary": "Doğal oluşumlu bu mağara, sarkıt ve dikitleriyle dikkat çeker. Macera arayan doğa severler için keşfedilmeyi bekleyen bir yeraltı güzelliğidir.", "place_query": "Karaburun Mağarası, Selendi, Manisa"}, {"title": "Selendi Yaylaları (Örneğin: Çamlıca Yaylası)", "summary": "Serin havası ve çam ormanlarıyla ünlü yaylalar, yaz aylarında kaçış noktasıdır. Doğa yürüyüşleri ve kamp için elverişlidir.", "place_query": "Çamlıca Yaylası, Selendi, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '13601f08-5ecd-4ca2-bb0e-36f2dcb1042a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Soma Antik Kenti (Soma Höyüğü)", "summary": "Soma''nın merkezinde yer alan bu antik höyük, bölgenin tarih öncesi dönemlerine ışık tutar. Ziyaretçiler, höyüğün çevresinde yürüyüş yaparak geçmişin izlerini keşfedebilir.", "place_query": "Soma Höyüğü, Soma, Manisa"}, {"title": "Soma Barajı ve Mesire Alanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için ideal bir doğa kaçamağıdır. Baraj çevresinde piknik yapabilir, yürüyüş yollarında vakit geçirebilirsiniz.", "place_query": "Soma Barajı, Soma, Manisa"}, {"title": "Kırkağaç Ovası ve Zeytinlikler", "summary": "Soma sınırları içinde yer alan bu geniş ova, zeytin ağaçlarıyla kaplıdır ve huzurlu bir kırsal manzara sunar. Doğa fotoğrafçılığı ve sakin bir gün geçirmek için biçilmiş kaftandır.", "place_query": "Kırkağaç Ovası, Soma, Manisa"}, {"title": "Soma Şehitliği", "summary": "2014 yılındaki maden faciasında hayatını kaybeden işçiler anısına yapılmış bu anıt ve şehitlik, ziyaretçilere duygusal bir deneyim sunar. Bölgenin yakın tarihine tanıklık etmek için önemli bir duraktır.", "place_query": "Soma Şehitliği, Soma, Manisa"}, {"title": "Darkale Köyü", "summary": "Soma''ya bağlı bu tarihi köy, taş evleri ve dar sokaklarıyla dikkat çeker. Doğal güzellikleri ve geleneksel mimarisiyle huzurlu bir kırsal atmosfer sunar.", "place_query": "Darkale Köyü, Soma, Manisa"}, {"title": "Soma Maden Müzesi", "summary": "Bölgenin madencilik tarihini ve kültürünü yansıtan bu müze, maden işçilerinin yaşamına dair belgeler ve objeler sergiler. Soma''nın kimliğini anlamak için mutlaka görülmelidir.", "place_query": "Soma Maden Müzesi, Soma, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fc58d52b-65fe-4779-9f37-0d4651eb8bf1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Turgutlu Şelalesi", "summary": "Manisa''nın Turgutlu ilçesinde yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popüler bir kaçış noktasıdır.", "place_query": "Turgutlu Şelalesi, Turgutlu, Manisa"}, {"title": "Urganlı Kaplıcaları", "summary": "Turgutlu''ya bağlı Urganlı Mahallesi''nde bulunan bu kaplıcalar, termal suları ve sağlık turizmiyle ünlüdür; romatizma ve cilt hastalıklarına iyi geldiğine inanılır.", "place_query": "Urganlı Kaplıcaları, Turgutlu, Manisa"}, {"title": "Karaçam Tabiat Parkı", "summary": "Turgutlu''nun yakınında, çam ormanlarıyla kaplı bu tabiat parkı, kampçılık, doğa yürüyüşü ve temiz hava arayan ziyaretçiler için ideal bir dinlenme alanıdır.", "place_query": "Karaçam Tabiat Parkı, Turgutlu, Manisa"}, {"title": "Turgutlu Kalesi (Kaleiçi)", "summary": "Tarihi bir geçmişe sahip olan Turgutlu Kalesi, günümüze kısmen ulaşabilmiş surları ve bölgenin geçmişine dair izler sunan önemli bir kültürel miras alanıdır.", "place_query": "Turgutlu Kalesi, Turgutlu, Manisa"}, {"title": "Derbent Göleti ve Mesire Alanı", "summary": "Turgutlu''ya bağlı Derbent köyünde yer alan bu gölet, doğal güzellikleri ve piknik alanlarıyla hafta sonu kaçamakları için sıkça tercih edilen bir yerdir.", "place_query": "Derbent Göleti, Turgutlu, Manisa"}, {"title": "Turgutlu Müzesi", "summary": "İlçenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bu müze, arkeolojik buluntular ve etnografik objelerle ziyaretçilere zengin bir geçmiş sunar.", "place_query": "Turgutlu Müzesi, Turgutlu, Manisa"}, {"title": "Yıldırım Camii", "summary": "Osmanlı dönemi mimarisinin güzel bir örneği olan bu cami, Turgutlu''nun merkezinde yer alır ve tarihi dokusuyla dikkat çeker.", "place_query": "Yıldırım Camii, Turgutlu, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '15adbc49-a19a-4f99-a726-6f37c26f53bf'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Manisa Kalesi", "summary": "Antik dönemden günümüze ulaşan bu tarihi kale, şehir merkezine hakim bir tepede yer alır ve Manisa''nın simgelerinden biridir. Ziyaretçiler, surlar arasında yürürken hem tarihi atmosferi hissedebilir hem de şehri kuşbakışı izleyebilir.", "place_query": "Manisa Kalesi, Yunusemre, Manisa"}, {"title": "Sultan Camii ve Külliyesi", "summary": "15. yüzyılda II. Murat tarafından yaptırılan bu cami, zarif mimarisi ve huzurlu avlusuyla dikkat çeker. Külliyesiyle birlikte Osmanlı dönemi eserlerini yakından görmek isteyenler için önemli bir duraktır.", "place_query": "Sultan Camii, Yunusemre, Manisa"}, {"title": "Niobe Kayalıkları", "summary": "Mitolojiye konu olmuş bu kayalıklar, Manisa''nın sembolik doğal oluşumlarındandır. Yunan mitolojisindeki Niobe hikayesiyle bağlantılı olan bu alan, hem tarih hem de doğa meraklıları için ilgi çekicidir.", "place_query": "Niobe Kayalıkları, Yunusemre, Manisa"}, {"title": "Muradiye Camii", "summary": "Kanuni Sultan Süleyman''ın oğlu Şehzade Mustafa adına yaptırılan bu cami, zarif çinileri ve etkileyici kubbesiyle öne çıkar. Şehzade Mustafa''nın türbesi de burada bulunduğu için tarihi ve manevi bir öneme sahiptir.", "place_query": "Muradiye Camii, Yunusemre, Manisa"}, {"title": "Manisa Arkeoloji Müzesi", "summary": "Bölgedeki kazılardan çıkarılan eserlerin sergilendiği bu müze, Lidya ve Roma dönemlerine ait önemli koleksiyonlara ev sahipliği yapar. Tarih meraklıları için zengin bir keşif sunar.", "place_query": "Manisa Arkeoloji Müzesi, Yunusemre, Manisa"}, {"title": "Spil Dağı Milli Parkı", "summary": "Şehre yakın konumuyla doğa severler için vazgeçilmez bir kaçış noktasıdır. Yürüyüş parkurları, piknik alanları ve zengin bitki örtüsüyle hem spor hem de dinlenme imkanı sunar.", "place_query": "Spil Dağı Milli Parkı, Yunusemre, Manisa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd8482751-43cc-467e-b938-9d92fc9cd109'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mardin Kalesi", "summary": "Mardin''in simgesi olan bu görkemli kale, şehre tepeden bakan muhteşem bir manzaraya sahiptir. Tarihi binlerce yıl öncesine uzanan kale, özellikle gün batımında eşsiz bir fotoğraf karesi sunar.", "place_query": "Mardin Kalesi, Artuklu, Mardin"}, {"title": "Deyrulzafaran Manastırı", "summary": "Mardin''in 5 km doğusunda bulunan bu tarihi Süryani manastırı, 5. yüzyıldan beri ayakta durmaktadır. Mimari yapısı ve dini önemiyle ziyaretçilerin ilgisini çeken manastır, hâlâ aktif olarak kullanılmaktadır.", "place_query": "Deyrulzafaran Manastırı, Artuklu, Mardin"}, {"title": "Mardin Müzesi", "summary": "Eski bir Süryani patriklik binasında hizmet veren müze, bölgenin zengin tarihini yansıtan arkeolojik eserler ve etnografik objeler sergiler. Mezopotamya medeniyetlerine ait buluntuları görmek için ideal bir duraktır.", "place_query": "Mardin Müzesi, Artuklu, Mardin"}, {"title": "Kasımiye Medresesi", "summary": "Artuklu dönemine ait bu etkileyici medrese, taş işçiliği ve avlusundaki havuzuyla dikkat çeker. Tarihi atmosferi ve sakin ortamıyla ziyaretçilere huzurlu bir gezi imkanı sunar.", "place_query": "Kasımiye Medresesi, Artuklu, Mardin"}, {"title": "Mardin Evleri ve Dar Sokaklar", "summary": "Beyaz kireç taşından yapılmış, kemerli ve dar sokaklarıyla ünlü Mardin evleri, şehrin en otantik bölgesini oluşturur. Yürüyerek keşfedilen bu sokaklar, tarihi dokuyu yakından hissettirir.", "place_query": "Mardin Evleri, Artuklu, Mardin"}, {"title": "Ulu Cami (Mardin)", "summary": "12. yüzyılda inşa edilen bu cami, Artuklu mimarisinin en güzel örneklerinden biridir. Minberi ve taş süslemeleriyle dikkat çeken cami, şehrin merkezinde kolayca ziyaret edilebilir.", "place_query": "Mardin Ulu Cami, Artuklu, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '53e5b1e9-eaae-4ead-963c-3f56ca241d65'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dargeçit Kalesi", "summary": "İlçe merkezinde bulunan tarihi kale, bölgenin stratejik önemini gösteren etkileyici bir yapıdır ve çevresindeki vadi manzarasıyla ziyaretçilerine eşsiz bir seyir keyfi sunar.", "place_query": "Dargeçit Kalesi, Dargeçit, Mardin"}, {"title": "Dargeçit Ulu Camii", "summary": "Artuklu dönemine ait olan bu tarihi cami, taş işçiliği ve mimari detaylarıyla dikkat çeker; hala ibadete açık olup ziyaretçilerini geçmişe yolculuğa çıkarır.", "place_query": "Dargeçit Ulu Camii, Dargeçit, Mardin"}, {"title": "Dargeçit Köprüsü", "summary": "Tarihi taş köprü, Dicle Nehri üzerinde yer alır ve bölgenin önemli kültürel miraslarından biridir; özellikle fotoğrafçılar için güzel bir manzara sunar.", "place_query": "Dargeçit Köprüsü, Dargeçit, Mardin"}, {"title": "Dargeçit Kanyonu", "summary": "Doğal güzellikleriyle ünlü bu kanyon, yürüyüş ve doğa sporları sevenler için ideal bir rotadır; derin vadileri ve yemyeşil bitki örtüsüyle büyüler.", "place_query": "Dargeçit Kanyonu, Dargeçit, Mardin"}, {"title": "Sümer Kalesi", "summary": "Dargeçit sınırları içinde yer alan bu antik kale, bölgenin en eski yerleşim izlerini taşır ve tarih meraklıları için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Sümer Kalesi, Dargeçit, Mardin"}, {"title": "Dargeçit Yaylası", "summary": "Yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için mükemmel bir kaçış noktasıdır; geniş çayırları ve temiz havasıyla ünlüdür.", "place_query": "Dargeçit Yaylası, Dargeçit, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '00a10474-4edf-4f60-9c55-e87309491793'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Derik Merkez Camii (Ulu Camii)", "summary": "Derik''in en eski ve en büyük camilerinden biri olup, tarihi dokusu ve mimari özellikleriyle dikkat çeker. Şehrin merkezinde yer alan bu cami, hem ibadet hem de ziyaret için önemli bir noktadır.", "place_query": "Derik Merkez Camii, Mardin"}, {"title": "Derik Kalesi", "summary": "İlçe merkezine hakim bir tepede bulunan tarihi bir kaledir. Bölgenin savunma yapılarından biri olan kale, ziyaretçilere panoramik Derik manzarası sunar.", "place_query": "Derik Kalesi, Mardin"}, {"title": "Şeyh Abdurrahman Türbesi", "summary": "Derik''te bulunan ve bölge halkı tarafından kutsal kabul edilen bu türbe, manevi bir atmosfer arayan ziyaretçilerin uğrak noktasıdır. Tarihi ve dini önemiyle bilinir.", "place_query": "Şeyh Abdurrahman Türbesi Derik"}, {"title": "Derik Kapalı Çarşısı", "summary": "Yöresel ürünlerin, el sanatlarının ve günlük ihtiyaçların satıldığı tarihi bir çarşıdır. Derik''in ticaret hayatının kalbi olan çarşı, ziyaretçilere otantik bir alışveriş deneyimi sunar.", "place_query": "Derik Kapalı Çarşısı Mardin"}, {"title": "Kıllıt Köprüsü", "summary": "Derik yakınlarında bulunan tarihi bir taş köprüdür. Çevresindeki doğal güzelliklerle bütünleşen köprü, fotoğrafçılık ve doğa yürüyüşleri için idealdir.", "place_query": "Kıllıt Köprüsü Derik"}, {"title": "Zerzevan Kalesi", "summary": "Derik ilçe sınırları içerisinde yer alan Zerzevan Kalesi, Roma dönemine ait önemli bir askeri yerleşimdir. Son yıllarda yapılan kazılarla ortaya çıkarılan Mithras Tapınağı ile uluslararası üne kavuşmuştur.", "place_query": "Zerzevan Kalesi Derik Mardin"}, {"title": "Derik Şelalesi", "summary": "Derik''in doğal güzelliklerinden biri olan şelale, özellikle bahar ve yaz aylarında piknik ve doğa gezileri için popüler bir mekandır. Serin suları ve yeşil çevresiyle huzur verici bir atmosfere sahiptir.", "place_query": "Derik Şelalesi Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd8a4966e-ee1a-483c-8660-5877cbfee113'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Koçhisar Kalesi", "summary": "Kızıltepe''nin simgelerinden biri olan bu tarihi kale, bölgenin stratejik önemini yansıtan kalıntıları ve etkileyici manzarasıyla ziyaretçileri cezbeder.", "place_query": "Koçhisar Kalesi, Kızıltepe, Mardin"}, {"title": "Mardin Kapalı Çarşısı (Kızıltepe Çarşısı)", "summary": "Geleneksel el sanatları, baharatlar ve yöresel ürünlerin satıldığı bu hareketli çarşı, otantik bir alışveriş deneyimi sunar.", "place_query": "Kızıltepe Kapalı Çarşı, Mardin"}, {"title": "Kızıltepe Ulu Camii", "summary": "Artuklu dönemine ait bu tarihi cami, mimari detayları ve huzurlu atmosferiyle hem ibadet hem de kültürel ziyaret için önemli bir noktadır.", "place_query": "Kızıltepe Ulu Camii, Mardin"}, {"title": "Dara Antik Kenti", "summary": "Kızıltepe''ye yaklaşık 30 km mesafedeki bu antik kent, Roma İmparatorluğu''nun doğu sınırında yer alan etkileyici kalıntıları ve yer altı yapılarıyla ünlüdür.", "place_query": "Dara Antik Kenti, Mardin"}, {"title": "Kızıltepe Arkeoloji Müzesi", "summary": "Bölgede yapılan kazılarda ortaya çıkarılan eserlerin sergilendiği müze, Mezopotamya''nın zengin tarihine ışık tutar.", "place_query": "Kızıltepe Arkeoloji Müzesi, Mardin"}, {"title": "Zinciriye Medresesi", "summary": "Kızıltepe merkezine yakın bu tarihi medrese, Artuklu mimarisinin zarif örneklerinden biri olup taş işçiliğiyle büyüler.", "place_query": "Zinciriye Medresesi, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '401db5ef-c914-4d72-8bbd-063e249a9b34'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mazıdağı Şelalesi", "summary": "Mazıdağı''nın doğal güzelliklerinden biri olan şelale, özellikle bahar aylarında akan suları ve çevresindeki yeşil alanlarıyla piknik ve doğa yürüyüşü için idealdir.", "place_query": "Mazıdağı Şelalesi, Mardin"}, {"title": "Dara Antik Kenti", "summary": "Mazıdağı ilçe merkezine yaklaşık 30 km uzaklıkta bulunan bu antik kent, Geç Roma dönemine ait kalıntıları, zindanları ve su sarnıçlarıyla tarih meraklıları için önemli bir duraktır.", "place_query": "Dara Antik Kenti, Mardin"}, {"title": "Mardin Taş Evleri (Mazıdağı Mahalleleri)", "summary": "Mazıdağı''nın geleneksel taş yapıları, bölgenin tarihi dokusunu yansıtır. Özellikle eski mahallelerde yürüyüş yaparak yerel mimariyi yakından görebilirsiniz.", "place_query": "Mazıdağı eski mahalleler, Mardin"}, {"title": "Mardin Müzesi", "summary": "Mazıdağı''na yaklaşık 40 km uzaklıktaki Mardin Müzesi, bölgedeki arkeolojik kazılardan çıkarılan eserler, etnografik objeler ve mozaiklerle zengin bir koleksiyona sahiptir.", "place_query": "Mardin Müzesi, Mardin"}, {"title": "Kasımiye Medresesi", "summary": "Mardin şehir merkezinde bulunan bu tarihi medrese, Selçuklu ve Artuklu mimarisinin izlerini taşır. Büyük avlusu, havuzu ve taş işçiliğiyle görülmeye değerdir.", "place_query": "Kasımiye Medresesi, Mardin"}, {"title": "Mazıdağı Doğa Yürüyüşü Rotaları", "summary": "Mazıdağı çevresindeki tepeler ve kırsal alanlar, doğa yürüyüşü sevenler için keşfedilmemiş patikalar ve eşsiz manzaralar sunar.", "place_query": "Mazıdağı doğa yürüyüşü rotaları, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6793df25-9744-466f-8f81-e4fa9e3c2d67'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Midyat Mor Gabriel Manastırı", "summary": "Dünyanın en eski Süryani Ortodoks manastırlarından biri olan bu yapı, 4. yüzyıldan beri ayakta duruyor. Taş işçiliği, mozaikleri ve huzur veren atmosferiyle ziyaretçilerini büyülüyor.", "place_query": "Mor Gabriel Manastırı, Midyat, Mardin"}, {"title": "Midyat Kasımiye Medresesi", "summary": "13. yüzyılda Artuklular tarafından inşa edilen bu medrese, etkileyici taş oymaları ve geniş avlusuyla dikkat çekiyor. Tarihi atmosferi ve mimari detayları fotoğrafçılar için ideal.", "place_query": "Kasımiye Medresesi, Midyat, Mardin"}, {"title": "Midyat Eski Çarşı (Midyat Çarşısı)", "summary": "Dar sokakları, taş dükkanları ve el işi gümüş, bakır ile deri ürünleriyle ünlü bu çarşı, alışveriş ve keşif için harika bir durak. Yöresel tatları da tadabilirsiniz.", "place_query": "Midyat Çarşısı, Midyat, Mardin"}, {"title": "Midyat Mor Şarbel Kilisesi", "summary": "Süryani Katoliklerine ait bu kilise, 19. yüzyılda inşa edilmiş olup iç mekanındaki süslemeler ve dini atmosferiyle öne çıkıyor. Midyat''ın çok kültürlü yapısını yansıtıyor.", "place_query": "Mor Şarbel Kilisesi, Midyat, Mardin"}, {"title": "Midyat Mardin Taş Evleri (Midyat Sokakları)", "summary": "Tarihi Midyat evlerinin sıralandığı bu sokaklar, bembeyaz kireç taşından yapılmış kemerli geçitleri ve avlularıyla büyüleyici. Şehrin otantik dokusunu hissetmek için mutlaka gezilmeli.", "place_query": "Midyat Tarihi Taş Evler, Midyat, Mardin"}, {"title": "Midyat Dara Antik Kenti", "summary": "Midyat''a yaklaşık 30 km uzaklıktaki bu antik kent, Roma İmparatorluğu''nun doğu sınırındaki önemli bir askeri yerleşimdi. Zindanları, su sarnıçları ve kalıntılarıyla tarihe tanıklık ediyor.", "place_query": "Dara Antik Kenti, Mardin"}, {"title": "Midyat Mardin Mor Hananyo Manastırı (Deyrulzafaran)", "summary": "Midyat''a yakın bu manastır, 5. yüzyıldan kalma ve safran rengi taşlarıyla ünlü. Süryani kültürünün önemli merkezlerinden biri olarak ziyaretçilere mistik bir deneyim sunuyor.", "place_query": "Mor Hananyo Manastırı, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'eac0ed9c-74ca-432c-859b-76610f396f5d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mor Yakup (Aziz Yakup) Kilisesi", "summary": "Nusaybin''in en önemli tarihi yapılarından biri olan bu Süryani kilisesi, 4. yüzyıla kadar uzanan geçmişi ve etkileyici mimarisiyle ziyaretçilerini büyüler. İçerisindeki tarihi mozaikler ve dini atmosfer, huzurlu bir deneyim sunar.", "place_query": "Mor Yakup Kilisesi, Nusaybin, Mardin"}, {"title": "Nusaybin Pazarı (Kapalı Çarşı)", "summary": "Yöresel ürünlerden baharatlara, tekstilden hediyelik eşyalara kadar her şeyi bulabileceğiniz renkli ve hareketli bir alışveriş noktasıdır. Özellikle canlı atmosferi ve farklı kültürlerin izlerini taşıyan tezgahlarıyla ünlüdür.", "place_query": "Nusaybin Kapalı Çarşı, Mardin"}, {"title": "Zeynel Abidin Camii ve Türbesi", "summary": "Nusaybin''in simgelerinden olan bu tarihi cami ve türbe, hem dini hem de mimari açıdan büyük öneme sahiptir. Zeynel Abidin Hazretleri''nin türbesine ev sahipliği yapan yapı, manevi bir atmosfer sunar.", "place_query": "Zeynel Abidin Camii, Nusaybin, Mardin"}, {"title": "Nusaybin Müzesi", "summary": "Bölgenin zengin tarihini ve arkeolojik mirasını sergileyen müze, Nusaybin ve çevresinde bulunan eserleri yakından görme fırsatı sunar. Hitit, Roma, Bizans ve İslam dönemlerine ait objeler dikkat çekicidir.", "place_query": "Nusaybin Müzesi, Mardin"}, {"title": "Gırnavaz Höyüğü", "summary": "Nusaybin''in hemen yanı başında, Mezopotamya''nın en eski yerleşimlerinden biri olan bu höyük, binlerce yıllık tarihe tanıklık eder. Arkeoloji meraklıları için eşsiz bir keşif alanıdır.", "place_query": "Gırnavaz Höyüğü, Nusaybin, Mardin"}, {"title": "Dara Antik Kenti", "summary": "Nusaybin''e yaklaşık 30 km uzaklıktaki bu antik kent, Roma İmparatorluğu''nun doğudaki önemli garnizonlarından biriydi. Etkileyici su sarnıçları, zindanlar ve mağaralarıyla görülmeye değer bir tarih hazinesidir.", "place_query": "Dara Antik Kenti, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e0a6d9f0-fb54-4099-a672-4648b84acf2d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zerzevan Kalesi", "summary": "Roma dönemine ait bu etkileyici kale, Mardin''in Ömerli ilçesinde yer alır ve bölgenin en önemli tarihi yapılarından biridir. Ziyaretçiler, surların ve antik kalıntıların arasında dolaşarak eşsiz bir manzara eşliğinde tarihe yolculuk yapabilir.", "place_query": "Zerzevan Kalesi, Ömerli, Mardin"}, {"title": "Mardin Kalesi", "summary": "Mardin''in simgesi haline gelmiş bu devasa kale, şehre tepeden bakan muhteşem bir konuma sahiptir. Tarihi boyunca birçok medeniyete ev sahipliği yapmış olan kale, ziyaretçilere hem tarihi bir deneyim hem de panoramik bir şehir manzarası sunar.", "place_query": "Mardin Kalesi, Mardin Merkez"}, {"title": "Deyrulzafaran Manastırı", "summary": "Mardin''in Ömerli ilçesine yakın konumda bulunan bu tarihi Süryani manastırı, binlerce yıllık geçmişiyle dini ve kültürel bir mirastır. Ziyaretçiler, etkileyici taş işçiliğini ve huzurlu atmosferini keşfedebilir.", "place_query": "Deyrulzafaran Manastırı, Mardin"}, {"title": "Mardin Müzesi", "summary": "Mardin''in zengin tarihini ve kültürünü yansıtan önemli bir müze olup, Arkeoloji ve Etnoğrafya bölümleriyle dikkat çeker. Hitit, Asur, Roma ve Osmanlı dönemlerine ait eserler, ziyaretçilere bölgenin geçmişine dair kapsamlı bir bakış sunar.", "place_query": "Mardin Müzesi, Mardin Merkez"}, {"title": "Kasımiye Medresesi", "summary": "Artuklu dönemine ait bu tarihi medrese, taş işçiliğinin en güzel örneklerinden biridir ve Mardin''in en çok ziyaret edilen yapıları arasında yer alır. Avlusundaki havuzu ve etkileyici mimarisiyle ziyaretçilere huzurlu bir atmosfer sunar.", "place_query": "Kasımiye Medresesi, Mardin"}, {"title": "Mardin Taş Evleri ve Dar Sokakları", "summary": "Mardin''in tarihi dokusunu oluşturan bembeyaz taş evler ve daracık sokaklar, şehrin en karakteristik özelliklerindendir. Ziyaretçiler, bu sokaklarda dolaşarak geleneksel Mardin yaşamına tanıklık edebilir ve eşsiz fotoğraflar çekebilir.", "place_query": "Mardin Taş Evleri, Mardin Merkez"}, {"title": "Mor Gabriel Manastırı", "summary": "Dünyanın ayakta kalan en eski Süryani manastırlarından biri olan Mor Gabriel, Midyat yakınlarında bulunur. Tarihi ve dini önemi kadar, büyüleyici mimarisi ve huzur veren bahçeleriyle de ziyaretçileri kendine çeker.", "place_query": "Mor Gabriel Manastırı, Midyat, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4a744ce7-03db-4a8d-9948-cff7bcd942d8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Savur Evleri", "summary": "Tarihi taş mimariyi yansıtan bu evler, dar sokakları ve cumbalı yapılarıyla Savur''un simgesidir. Fotoğrafçılar ve kültür turizmi meraklıları için eşsiz bir atmosfer sunar.", "place_query": "Savur Evleri, Savur, Mardin"}, {"title": "Savur Kalesi", "summary": "Şehre hakim bir tepe üzerinde yer alan kale, tarihi boyunca birçok medeniyete ev sahipliği yapmıştır. Ziyaretçilerine hem tarihi dokuyu hem de panoramik manzarayı bir arada sunar.", "place_query": "Savur Kalesi, Savur, Mardin"}, {"title": "Savur Çarşıları", "summary": "Yöresel el sanatları, bakırcılar ve gümüş işlemeciliğiyle ünlü tarihi çarşılar, alışveriş ve kültürel keşif için idealdir. Özellikle Savur bıçağı ve telkari ürünleri meşhurdur.", "place_query": "Savur Çarşıları, Savur, Mardin"}, {"title": "Savur Şelalesi", "summary": "İlçe merkezine yakın mesafede doğal bir güzellik olan şelale, özellikle bahar ve yaz aylarında piknik ve doğa yürüyüşü için popülerdir. Serin suları ve yeşil çevresiyle huzur verir.", "place_query": "Savur Şelalesi, Savur, Mardin"}, {"title": "Mardin Savur Mor Meryem Kilisesi", "summary": "Süryani mirasının önemli bir parçası olan bu tarihi kilise, taş işçiliği ve dini atmosferiyle dikkat çeker. Ziyaretçiler hem ibadet hem de kültürel gezi amacıyla uğrar.", "place_query": "Mor Meryem Kilisesi, Savur, Mardin"}, {"title": "Savur Kaymakamlığı Konağı", "summary": "Osmanlı döneminden kalma bu tarihi konak, restore edilerek müze ve kültür evi olarak hizmet vermektedir. İçinde Savur''a dair etnografik eserler sergilenir.", "place_query": "Savur Kaymakamlığı Konağı, Savur, Mardin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '08106fa2-a322-4264-a313-4f67f78c34a8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mersin Marina", "summary": "Modern bir yaşam merkezi olan Mersin Marina, yürüyüş yolları, kafeleri ve restoranlarıyla şehrin en popüler buluşma noktalarından biridir. Deniz manzarası eşliğinde keyifli vakit geçirebilir, çeşitli etkinliklere katılabilirsiniz.", "place_query": "Mersin Marina, Akdeniz, Mersin"}, {"title": "Mersin Atatürk Evi Müzesi", "summary": "Tarihi bir konakta yer alan bu müze, Atatürk''ün Mersin ziyaretlerinde kaldığı ev olarak bilinir. Kurtuluş Savaşı dönemine ait eşyalar ve fotoğraflarla dolu olan müze, şehrin tarihine ışık tutar.", "place_query": "Atatürk Evi Müzesi, Akdeniz, Mersin"}, {"title": "Mersin Arkeoloji Müzesi", "summary": "Zengin bir koleksiyona sahip olan müze, bölgedeki antik kentlerden çıkarılan eserleri sergiler. Heykeller, mozaikler ve lahitlerle dolu bu müze, tarih meraklıları için kaçırılmaması gereken bir duraktır.", "place_query": "Mersin Arkeoloji Müzesi, Akdeniz, Mersin"}, {"title": "Kızkalesi (Deniz Kalesi)", "summary": "Mersin''in simgelerinden biri olan bu tarihi kale, denizin ortasında yükselen eşsiz bir yapıdır. Tekne turlarıyla ulaşılabilen kale, hem tarihi dokusu hem de fotoğrafçılık açısından büyük ilgi çeker.", "place_query": "Kızkalesi, Erdemli, Mersin"}, {"title": "Yumuktepe Höyüğü", "summary": "Neolitik dönemden günümüze kadar kesintisiz yerleşime sahne olmuş önemli bir arkeolojik alandır. Mersin''in en eski yerleşim yerlerinden biri olan höyük, tarih öncesi çağlara ışık tutar.", "place_query": "Yumuktepe Höyüğü, Akdeniz, Mersin"}, {"title": "Mersin Cumhuriyet Meydanı", "summary": "Şehrin merkezinde yer alan bu meydan, çevresindeki tarihi binalar ve heykeliyle dikkat çeker. Hem yerel halkın hem de turistlerin uğrak noktası olan meydan, şehir turu için ideal bir başlangıç noktasıdır.", "place_query": "Cumhuriyet Meydanı, Akdeniz, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1f5e7f79-1810-4e0b-ad59-fce96ea915cd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Anamur Kalesi", "summary": "Deniz kıyısında, Selçuklu ve Roma dönemlerine ait etkileyici bir kale. Ziyaretçiler hem tarihi dokuyu keşfedebilir hem de kale surlarından Akdeniz''in muhteşem manzarasını izleyebilir.", "place_query": "Anamur Kalesi, Anamur, Mersin"}, {"title": "Mamure Kalesi", "summary": "Türkiye''nin en iyi korunmuş kalelerinden biri olup, 23 kulesi ve geniş avlusuyla büyüleyicidir. Antik çağlardan Osmanlı''ya kadar birçok medeniyete ev sahipliği yapmıştır.", "place_query": "Mamure Kalesi, Anamur, Mersin"}, {"title": "Anemurium Antik Kenti", "summary": "Roma ve Bizans dönemine ait kalıntılarıyla ünlü bu antik kent, deniz kenarında yer alır. Tiyatro, hamam ve mozaikli yapılarıyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "Anemurium Antik Kenti, Anamur, Mersin"}, {"title": "İskele Plajı", "summary": "Anamur''un en popüler plajı olan İskele, ince kumu ve berrak deniziyle yüzme ve güneşlenmek için idealdir. Çevresindeki kafe ve restoranlarla keyifli bir gün geçirebilirsiniz.", "place_query": "İskele Plajı, Anamur, Mersin"}, {"title": "Anamur Müzesi", "summary": "Bölgedeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği modern bir müze. Heykeller, seramikler ve antik dönem günlük yaşamına dair objeler ilgi çekicidir.", "place_query": "Anamur Müzesi, Anamur, Mersin"}, {"title": "Çamlıpınar Alabalık Tesisleri", "summary": "Doğayla iç içe, şelale sesi eşliğinde alabalık yiyebileceğiniz bir mesire alanı. Özellikle hafta sonları aileler ve doğa severler tarafından sıkça tercih edilir.", "place_query": "Çamlıpınar Alabalık Tesisleri, Anamur, Mersin"}, {"title": "Puledre Şelalesi", "summary": "Yemyeşil bir vadi içinde yer alan bu şelale, serin suları ve doğal havuzlarıyla piknik ve doğa yürüyüşü için harikadır. Sessizliği ve temiz havasıyla şehirden kaçış sunar.", "place_query": "Puledre Şelalesi, Anamur, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3616c3bf-dc37-4686-9188-e31d2c152fbe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aydıncık Mağaraları", "summary": "Mersin''in Aydıncık ilçesinde yer alan bu mağaralar, etkileyici sarkıt ve dikitleriyle ünlüdür. Ziyaretçiler, doğal oluşumların büyüleyici güzelliğini keşfedebilir ve serin mağara atmosferinde keyifli bir gezi yapabilir.", "place_query": "Aydıncık Mağaraları, Aydıncık, Mersin"}, {"title": "Aydıncık Sahili", "summary": "Temiz denizi ve uzun kumsalıyla bilinen Aydıncık Sahili, yüzme ve güneşlenme için ideal bir noktadır. Özellikle yaz aylarında yerli ve yabancı turistlerin uğrak yeridir.", "place_query": "Aydıncık Sahili, Aydıncık, Mersin"}, {"title": "Sofular Kalesi", "summary": "Aydıncık''a bağlı Sofular Mahallesi''nde bulunan bu tarihi kale, bölgenin zengin geçmişine tanıklık eder. Deniz manzaralı konumu ve antik kalıntılarıyla tarih meraklıları için keşfedilmeyi bekleyen bir mekandır.", "place_query": "Sofular Kalesi, Aydıncık, Mersin"}, {"title": "Aydıncık Limanı", "summary": "Balıkçı tekneleri ve küçük yatların demirlediği Aydıncık Limanı, huzurlu bir atmosfere sahiptir. Çevresindeki kafe ve restoranlarda taze deniz ürünlerini tadabilir, gün batımında keyifli bir yürüyüş yapabilirsiniz.", "place_query": "Aydıncık Limanı, Aydıncık, Mersin"}, {"title": "Aydıncık Plajı", "summary": "İlçe merkezine yakın konumdaki bu plaj, ince kumu ve sakin deniziyle aileler için güvenli bir yüzme alanı sunar. Çevredeki olanaklar sayesinde rahat bir gün geçirebilirsiniz.", "place_query": "Aydıncık Plajı, Aydıncık, Mersin"}, {"title": "Aydıncık Yaylası", "summary": "Şehir merkezine kısa bir mesafede bulunan Aydıncık Yaylası, yemyeşil doğası ve temiz havasıyla doğa severler için kaçış noktasıdır. Piknik alanları ve yürüyüş rotalarıyla huzurlu bir gün geçirebilirsiniz.", "place_query": "Aydıncık Yaylası, Aydıncık, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5c639b47-0909-44d3-9fa8-6730a887e789'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bozyazı Sahili ve Plajları", "summary": "Mersin''in en güzel uzun kumsallarından birine sahip olan Bozyazı Sahili, berrak denizi ve ince kumuyla yüzme ve güneşlenmek için idealdir. Sahil boyunca yürüyüş yapabilir, denizin tadını çıkarabilirsiniz.", "place_query": "Bozyazı Sahili, Mersin"}, {"title": "Bozyazı Kalesi", "summary": "Deniz kenarında yükselen bu tarihi kale, bölgeye hakim bir tepe üzerinde yer alır ve muhteşem bir manzara sunar. Kalenin çevresi ve iç yapısı, ziyaretçilere tarihi bir atmosfer ve fotoğraf fırsatı sağlar.", "place_query": "Bozyazı Kalesi, Mersin"}, {"title": "Narlıkuyu Plajı ve Cennet-Cehennem Obrukları", "summary": "Bozyazı''ya yaklaşık 30 km mesafedeki Narlıkuyu, berrak denizi ve ünlü Cennet-Cehennem obruklarına yakınlığıyla popülerdir. Obrukların etkileyici doğal yapısını keşfedebilir, ardından plajda serinleyebilirsiniz.", "place_query": "Narlıkuyu Plajı, Mersin"}, {"title": "Kızkalesi (Deniz Kalesi)", "summary": "Mersin''in simgelerinden biri olan Kızkalesi, denizin ortasında yükselen tarihi bir kaledir. Tekne turlarıyla kaleye ulaşabilir, çevresindeki plajlarda yüzebilir ve eşsiz fotoğraflar çekebilirsiniz.", "place_query": "Kızkalesi, Mersin"}, {"title": "Adamkayalar (Adamkayalar Kabartmaları)", "summary": "Bozyazı yakınlarındaki Adamkayalar, kayalara oyulmuş antik figürleriyle ünlü bir açık hava müzesidir. Tarihi kabartmaları görmek ve doğa içinde yürüyüş yapmak için ideal bir noktadır.", "place_query": "Adamkayalar, Mersin"}, {"title": "Bozyazı Yaylaları (Sorgun Yaylası vb.)", "summary": "Şehir hayatından kaçmak isteyenler için Bozyazı''nın yemyeşil yaylaları serin bir kaçış noktasıdır. Yayla evlerinde konaklayabilir, doğa yürüyüşleri yapabilir ve yöresel lezzetleri tadabilirsiniz.", "place_query": "Sorgun Yaylası, Bozyazı, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '60b8cd9d-ff5d-46cc-94f9-cd407bf85f2c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamlıyayla Şelalesi", "summary": "İlçe merkezine yakın, doğal güzelliği ve serin sularıyla özellikle yaz aylarında piknik ve doğa yürüyüşü için popüler bir duraktır.", "place_query": "Çamlıyayla Şelalesi, Çamlıyayla, Mersin"}, {"title": "Kadıncık Çayı ve Kanyonu", "summary": "Bölgenin en önemli doğal oluşumlarından olan kanyon, berrak akan Kadıncık Çayı ve yemyeşil vadisiyle kano, trekking ve kamp gibi aktiviteler için idealdir.", "place_query": "Kadıncık Çayı, Çamlıyayla, Mersin"}, {"title": "Çamlıyayla Yaylası", "summary": "Toroslar''ın eteklerinde yer alan bu yayla, yemyeşil çam ormanları ve temiz havasıyla özellikle yaz aylarında Mersinlilerin kaçış noktasıdır.", "place_query": "Çamlıyayla Yaylası, Mersin"}, {"title": "Namrun Kalesi (Çamlıyayla Kalesi)", "summary": "Tarihi bir Roma kalesi olan yapı, ilçeye hakim bir tepe üzerinde yer alır ve ziyaretçilere hem tarihi bir atmosfer hem de muhteşem bir manzara sunar.", "place_query": "Namrun Kalesi, Çamlıyayla, Mersin"}, {"title": "Cehennemdere Vadisi", "summary": "Derin ve sarp kayalıkları, şelaleleri ve zengin bitki örtüsüyle doğa sporları ve keşif tutkunları için eşsiz bir rotadır.", "place_query": "Cehennemdere Vadisi, Çamlıyayla, Mersin"}, {"title": "Sultan Pınarı Mesire Alanı", "summary": "Bol oksijenli çam ormanları içinde yer alan bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için huzurlu bir ortam sağlar.", "place_query": "Sultan Pınarı, Çamlıyayla, Mersin"}, {"title": "Kızılkaya Tepesi", "summary": "Yüksek rakımı ve panoramik Toros manzarası ile özellikle gün doğumu ve gün batımı fotoğrafları çekmek isteyen doğa severlerin uğrak noktasıdır.", "place_query": "Kızılkaya Tepesi, Çamlıyayla, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3409055f-21f5-4e76-b6e7-55c11518b024'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızkalesi (Deniz Kalesi)", "summary": "Mersin''in simgesi haline gelmiş, kıyıdan 200 metre açıkta bir adacık üzerinde yer alan tarihi bir kaledir. Tekneyle ulaşılabilen kale, hem tarihi dokusu hem de eşsiz deniz manzarasıyla ziyaretçilerin ilgisini çeker.", "place_query": "Kızkalesi, Erdemli, Mersin"}, {"title": "Adamkayalar", "summary": "Deniz seviyesinden yaklaşık 100 metre yükseklikteki kaya yüzeyine oyulmuş antik kabartmalar ve mezarlardan oluşan etkileyici bir arkeolojik alandır. Roma dönemine ait bu figürler, bölgenin tarihi zenginliğini gözler önüne serer.", "place_query": "Adamkayalar, Erdemli, Mersin"}, {"title": "Cennet-Cehennem Obrukları", "summary": "Doğal kireçtaşı oluşumları sonucu meydana gelmiş iki büyük obruktur. Cennet Obruğu''nun içinde bir mağara ve kilise kalıntısı bulunurken, Cehennem Obruğu''nun derinliği ve efsaneleri ziyaretçileri büyüler.", "place_query": "Cennet Cehennem Obrukları, Erdemli, Mersin"}, {"title": "Kanlıdivane Antik Kenti", "summary": "Büyük bir obruğun etrafına kurulmuş, Helenistik ve Roma dönemine ait kalıntılarıyla dikkat çeken bir antik kenttir. Sütunlu yolları, kiliseleri ve zeytinyağı işlikleri ile tarihe yolculuk yapmak isteyenler için ideal bir duraktır.", "place_query": "Kanlıdivane Antik Kenti, Erdemli, Mersin"}, {"title": "Korykos Antik Kenti", "summary": "Kızkalesi''nin hemen yanında yer alan, surları, sarnıçları ve mozaikleriyle ünlü bir antik kenttir. Özellikle sahildeki büyük hamam kalıntısı ve liman yapıları dikkat çekicidir.", "place_query": "Korykos Antik Kenti, Erdemli, Mersin"}, {"title": "Mersin Erdemli Sahili", "summary": "Uzun ve bakir plajlarıyla ünlü olan sahil şeridi, özellikle yaz aylarında deniz ve güneş tatili yapmak isteyenler için popüler bir destinasyondur. Berrak denizi ve çevresindeki tesislerle huzurlu bir tatil imkanı sunar.", "place_query": "Erdemli Sahili, Mersin"}, {"title": "Tisan Yarımadası", "summary": "Bakir doğası ve sakin koylarıyla bilinen Tisan, doğa yürüyüşleri ve kampçılık için ideal bir bölgedir. Aynı zamanda antik döneme ait kalıntılar da barındıran yarımada, huzur arayanların gözde mekanlarındandır.", "place_query": "Tisan Yarımadası, Erdemli, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6432635e-5323-4637-907b-aeb792ca49eb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gülnar Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale, bölgenin antik çağlardan kalma önemli bir savunma yapısıdır. Gülnar ve çevresinin panoramik manzarasını sunar.", "place_query": "Gülnar Kalesi, Gülnar, Mersin"}, {"title": "Aydıncık (Kelenderis) Antik Kenti", "summary": "Gülnar ilçe sınırlarına yakın Aydıncık''ta bulunan antik kent, Roma ve Bizans dönemine ait kalıntılarıyla tarih meraklıları için ideal bir duraktır.", "place_query": "Kelenderis Antik Kenti, Aydıncık, Mersin"}, {"title": "Gülnar Şelalesi", "summary": "Doğal bitki örtüsüyle çevrili bu şelale, serinlemek ve doğayla iç içe vakit geçirmek için popüler bir piknik alanıdır.", "place_query": "Gülnar Şelalesi, Gülnar, Mersin"}, {"title": "Büyükeceli Plajı", "summary": "Gülnar''ın sahil kesiminde yer alan bu plaj, temiz denizi ve sakin atmosferiyle yaz aylarında yerli halkın uğrak noktasıdır.", "place_query": "Büyükeceli Plajı, Gülnar, Mersin"}, {"title": "Meydancık Kalesi", "summary": "Helenistik dönemden kalma bu kale kalıntısı, bölgenin stratejik önemini gözler önüne serer ve çevredeki doğa yürüyüşleriyle birleştirilebilir.", "place_query": "Meydancık Kalesi, Gülnar, Mersin"}, {"title": "Pınarbaşı Mesire Alanı", "summary": "Bol oksijenli çam ormanları ve dereden gelen su sesi eşliğinde piknik yapabileceğiniz, Gülnar''a yakın huzurlu bir doğa alanıdır.", "place_query": "Pınarbaşı Mesire Alanı, Gülnar, Mersin"}, {"title": "Gülnar Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip müze, çevredeki antik kentlerden çıkarılan arkeolojik eserleri ve yöresel etnografik objeleri sergiler.", "place_query": "Gülnar Müzesi, Gülnar, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '763e286f-21a7-460e-ad41-b02404716a17'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızkalesi (Deniz Kalesi)", "summary": "Mersin''in simgelerinden biri olan bu küçük ada kalesi, denizin ortasında yükselir. Tekne turlarıyla ulaşılabilen kale, hem tarihi dokusu hem de eşsiz fotoğraf kareleriyle ziyaretçilerini büyüler.", "place_query": "Kızkalesi, Mezitli, Mersin"}, {"title": "Mersin Marina", "summary": "Modern yat limanı ve çevresindeki kafe, restoran ve mağazalarıyla şehrin en popüler sosyal yaşam merkezlerinden biridir. Akşam yürüyüşleri ve deniz manzarası eşliğinde vakit geçirmek için idealdir.", "place_query": "Mersin Marina, Mezitli, Mersin"}, {"title": "Virşehir Kalesi", "summary": "Mezitli ilçe sınırlarında yer alan bu tarihi kale, Roma ve Bizans dönemlerine ait kalıntılarıyla dikkat çeker. Tepeden Mezitli Ovası ve deniz manzarasına hakim bir konumda yer alır.", "place_query": "Virşehir Kalesi, Mezitli, Mersin"}, {"title": "Mezitli Sahil Yolu ve Plajları", "summary": "Uzun sahil şeridi boyunca uzanan yürüyüş ve bisiklet yolları, halk plajları ve dinlenme alanlarıyla Mezitli''nin en çok tercih edilen rekreasyon bölgesidir. Özellikle gün batımında keyifli bir atmosfer sunar.", "place_query": "Mezitli Sahil Yolu, Mezitli, Mersin"}, {"title": "Soloi-Pompeiopolis Antik Kenti", "summary": "Mezitli sınırları içinde yer alan bu antik kent, M.Ö. 7. yüzyıla kadar uzanan tarihiyle önemli bir arkeolojik alandır. Sütunlu yolu ve antik liman kalıntıları en dikkat çekici yapıları arasındadır.", "place_query": "Soloi-Pompeiopolis Antik Kenti, Mezitli, Mersin"}, {"title": "Mezitli Merkez Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla aileler için popüler bir dinlenme noktasıdır. Park içinde bulunan gölet ve kafeteryalar da ziyaretçilere hizmet verir.", "place_query": "Mezitli Merkez Parkı, Mezitli, Mersin"}, {"title": "Tarsus Şelalesi (Mezitli''ye yakın)", "summary": "Mezitli''ye yaklaşık 30 km mesafedeki Tarsus Şelalesi, Berdan Çayı üzerinde yer alan doğal bir güzelliktir. Çevresindeki mesire alanı ve restoranlar sayesinde hafta sonu kaçamakları için sıkça tercih edilir.", "place_query": "Tarsus Şelalesi, Tarsus, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5b29033b-1882-4207-9b20-9cc37da199a4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mut Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan bu kale, Roma ve Bizans dönemlerinden izler taşır. Ziyaretçiler, kalenin surlarından Mersin''in en yeşil ilçelerinden biri olan Mut''un panoramik manzarasını izleyebilir.", "place_query": "Mut Kalesi, Mut, Mersin"}, {"title": "Lamas (Limonlu) Çayı ve Kanyonu", "summary": "Mut''un doğal güzelliklerinden biri olan bu kanyon, yürüyüş ve doğa fotoğrafçılığı için idealdir. Çay boyunca uzanan patikalar, ziyaretçilere huzurlu bir doğa deneyimi sunar.", "place_query": "Limonlu Çayı Kanyonu, Mut, Mersin"}, {"title": "Karacaoğlan Evi ve Müzesi", "summary": "Ünlü halk ozanı Karacaoğlan''ın anısına düzenlenmiş bu müze, onun yaşamına ve eserlerine dair objeler sergiler. Müze, Mut''un kültürel mirasını keşfetmek isteyenler için önemli bir duraktır.", "place_query": "Karacaoğlan Evi Müzesi, Mut, Mersin"}, {"title": "Mut Barajı ve Mesire Alanı", "summary": "Göksu Nehri üzerinde kurulu bu baraj, piknik ve dinlenme alanlarıyla çevrilidir. Su sporları ve balıkçılık gibi aktivitelerin yanı sıra, barajın çevresindeki yeşil alanlar aileler için popüler bir kaçış noktasıdır.", "place_query": "Mut Barajı, Mut, Mersin"}, {"title": "Dağpazarı (Koropissos) Antik Kenti", "summary": "Mut ilçe merkezine yaklaşık 40 km uzaklıkta bulunan bu antik kent, Roma dönemine ait kalıntılarıyla dikkat çeker. Tarih meraklıları, bölgedeki tapınak ve sarnıç gibi yapıları keşfedebilir.", "place_query": "Dağpazarı Antik Kenti, Mut, Mersin"}, {"title": "Mut Yörük Müzesi", "summary": "Yörük kültürünü yansıtan çadır, giysi ve günlük eşyaların sergilendiği bu müze, bölgenin göçebe geçmişine ışık tutar. Açık hava müzesi konseptiyle ziyaretçilere farklı bir deneyim sunar.", "place_query": "Mut Yörük Müzesi, Mut, Mersin"}, {"title": "Göksu Nehri Kenarı ve Doğa Yürüyüşleri", "summary": "Mut''tan geçen Göksu Nehri, özellikle ilkbahar ve sonbaharda yürüyüşçüler için eşsiz bir rota oluşturur. Nehir boyunca uzanan yemyeşil vadiler, kuş sesleri eşliğinde huzurlu bir gezinti imkanı tanır.", "place_query": "Göksu Nehri, Mut, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3bb0ad37-ec9e-42d7-b524-e76db8045624'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kız Kalesi", "summary": "Denizin içinde yer alan bu tarihi kale, eşsiz manzarası ve hikayesiyle Silifke''nin en ikonik yapılarından biridir. Tekneyle ulaşılabilen kaleyi ziyaret edebilir, çevresindeki plajlarda denize girebilirsiniz.", "place_query": "Kız Kalesi, Silifke, Mersin"}, {"title": "Silifke Kalesi", "summary": "Şehre hakim bir tepede bulunan bu ortaçağ kalesi, Silifke''nin tarihi dokusunu ve panoramik manzarasını gözler önüne serer. Kalenin surları arasında yürüyüş yapabilir ve bölgenin tarihine tanıklık edebilirsiniz.", "place_query": "Silifke Kalesi, Silifke, Mersin"}, {"title": "Göksu Nehri Deltası", "summary": "Kuş gözlemciliği ve doğa yürüyüşleri için ideal olan bu delta, zengin bitki örtüsü ve göçmen kuşlara ev sahipliği yapar. Nehir kenarında piknik yapabilir veya tekne turlarına katılabilirsiniz.", "place_query": "Göksu Deltası, Silifke, Mersin"}, {"title": "Cennet ve Cehennem Obrukları", "summary": "Doğal oluşumları ve mitolojik hikayeleriyle ünlü bu obruklar, etkileyici manzaralar sunar. Cennet Obruğu''ndaki tarihi kalıntıları gezebilir, Cehennem Obruğu''nun derinliklerine bakarak doğanın gücünü hissedebilirsiniz.", "place_query": "Cennet Cehennem Obrukları, Silifke, Mersin"}, {"title": "Narlıkuyu", "summary": "Mas mavi denizi ve doğal güzellikleriyle ünlü bu sahil beldesi, yüzme ve dinlenme için popüler bir noktadır. Ayrıca burada bulunan Narlıkuyu Mozaik Müzesi''ni de ziyaret edebilirsiniz.", "place_query": "Narlıkuyu, Silifke, Mersin"}, {"title": "Uzuncaburç (Diocaesarea)", "summary": "Antik dönemin önemli kentlerinden biri olan Uzuncaburç, etkileyici sütunlu caddesi ve tapınak kalıntılarıyla tarih meraklılarını cezbeder. Bölgedeki en iyi korunmuş antik kentlerden biridir.", "place_query": "Uzuncaburç Antik Kenti, Silifke, Mersin"}, {"title": "Taşucu", "summary": "Silifke''nin hareketli sahil kasabası olan Taşucu, plajları, balık restoranları ve marina atmosferiyle ünlüdür. Ayrıca buradan Kıbrıs''a feribot seferleri düzenlenir.", "place_query": "Taşucu, Silifke, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '534f647a-6058-4891-8a85-9f9ccf5e62b0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tarsus Şelalesi", "summary": "Berdan Çayı üzerinde yer alan bu şelale, Tarsus''un simgesi haline gelmiştir. Çevresindeki kafelerde dinlenebilir, doğal havuzda yüzebilir ve şelalenin serinletici atmosferinin tadını çıkarabilirsiniz.", "place_query": "Tarsus Şelalesi, Tarsus, Mersin"}, {"title": "St. Paul Kuyusu ve Anıt Müzesi", "summary": "Hristiyanlık tarihi açısından büyük önem taşıyan bu kutsal kuyu, St. Paul''un vaftiz edildiği yer olarak bilinir. Müzede bölgenin erken Hristiyanlık dönemine ait eserler sergilenmektedir.", "place_query": "St. Paul Kuyusu ve Anıt Müzesi, Tarsus, Mersin"}, {"title": "Tarsus Müzesi", "summary": "Eski bir medrese binasında hizmet veren müze, bölgenin zengin tarihini gözler önüne seren eserlere ev sahipliği yapar. Neolitik dönemden Osmanlı''ya uzanan geniş bir koleksiyonu keşfedebilirsiniz.", "place_query": "Tarsus Müzesi, Tarsus, Mersin"}, {"title": "Kleopatra Kapısı", "summary": "Antik Tarsus''un giriş kapılarından biri olan bu yapı, Mısır Kraliçesi Kleopatra''nın kente gelişiyle anılır. Roma dönemine ait bu tarihi kapı, şehrin en önemli simgelerindendir.", "place_query": "Kleopatra Kapısı, Tarsus, Mersin"}, {"title": "Tarsus Ulu Cami", "summary": "Selçuklu döneminden kalma bu tarihi cami, kesme taş işçiliği ve zarif mimarisiyle dikkat çeker. İç avlusu ve çeşmesiyle huzurlu bir atmosfer sunar.", "place_query": "Tarsus Ulu Cami, Tarsus, Mersin"}, {"title": "Eshab-ı Kehf Mağarası", "summary": "Yedi Uyurlar efsanesine ev sahipliği yapan bu kutsal mağara, hem İslam hem de Hristiyanlık açısından önemli bir ziyaret noktasıdır. Doğal kaya oluşumları ve tarihi dokusuyla mistik bir deneyim sunar.", "place_query": "Eshab-ı Kehf Mağarası, Tarsus, Mersin"}, {"title": "Gözlükule Höyüğü", "summary": "Tarsus''un en eski yerleşim alanlarından biri olan bu höyük, Neolitik Çağ''dan Roma dönemine kadar kesintisiz yerleşim görmüştür. Arkeoloji meraklıları için önemli bir açık hava müzesi niteliğindedir.", "place_query": "Gözlükule Höyüğü, Tarsus, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '79ac9eb9-e0c8-41d7-b775-f34f1e698685'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cennet Cehennem Obruğu", "summary": "Mersin''in Narlıkuyu bölgesinde bulunan bu devasa obruklar, şelaleler ve tarihi kalıntılarla çevrili etkileyici bir doğa harikasıdır. Cennet Obruğu''nun içine inen merdivenlerle antik bir kiliseyi ziyaret edebilir, doğanın büyüleyici gücünü hissedebilirsiniz.", "place_query": "Cennet Cehennem Obruğu, Narlıkuyu, Mersin"}, {"title": "Kız Kalesi", "summary": "Deniz kıyısındaki küçük bir adacık üzerine kurulu bu tarihi kale, Mersin''in simge yapılarından biridir. Tekneyle ulaşılan kaleden Akdeniz''in muhteşem manzarasını izleyebilir ve bölgenin zengin tarihine tanıklık edebilirsiniz.", "place_query": "Kız Kalesi, Kızkalesi, Mersin"}, {"title": "Mersin Marina", "summary": "Modern yat limanı ve çevresindeki kafe, restoran ve mağazalarıyla şehrin en popüler buluşma noktalarından biridir. Akşam yürüyüşleri, deniz manzarası eşliğinde yemek yemek ve keyifli vakit geçirmek için idealdir.", "place_query": "Mersin Marina, Mersin"}, {"title": "Yerköprü Şelalesi", "summary": "Mut ilçesi sınırlarında yer alan bu doğal güzellik, yer altından çıkan suların oluşturduğu travertenler ve şelaleleriyle büyüler. Çevresindeki piknik alanları ve yürüyüş parkurlarıyla doğa severler için kaçırılmayacak bir duraktır.", "place_query": "Yerköprü Şelalesi, Mut, Mersin"}, {"title": "Mersin Atatürk Evi Müzesi", "summary": "Atatürk''ün Mersin ziyaretlerinde kaldığı tarihi ev, günümüzde müze olarak hizmet vermektedir. O döneme ait eşyalar ve fotoğraflarla dolu bu müze, Cumhuriyet tarihine ilgi duyanlar için önemli bir duraktır.", "place_query": "Atatürk Evi Müzesi, Mersin"}, {"title": "Göksu Nehri Deltası", "summary": "Kuş gözlemciliği ve doğa yürüyüşleri için eşsiz bir alan olan delta, zengin bitki örtüsü ve nadir kuş türlerine ev sahipliği yapar. Özellikle ilkbahar ve sonbahar aylarında doğa tutkunlarının uğrak noktasıdır.", "place_query": "Göksu Deltası, Silifke, Mersin"}, {"title": "Mersin Arkeoloji Müzesi", "summary": "Bölgenin zengin tarihini gözler önüne seren bu modern müze, Neolitik dönemden Osmanlı''ya kadar uzanan geniş bir eser koleksiyonuna sahiptir. Mozaikler, heykeller ve günlük yaşam objeleriyle tarihe yolculuk yapabilirsiniz.", "place_query": "Mersin Arkeoloji Müzesi, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '821fef18-fd82-4135-ba3e-b61cd33999a3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mersin Marina", "summary": "Modern bir yaşam merkezi olan marina, yürüyüş yolları, kafeler, restoranlar ve mağazalarıyla hem yerel halkın hem de turistlerin uğrak noktasıdır. Deniz kenarında keyifli vakit geçirmek için idealdir.", "place_query": "Mersin Marina, Yenişehir, Mersin"}, {"title": "Mersin Atatürk Evi Müzesi", "summary": "Atatürk''ün Mersin ziyaretlerinde kaldığı tarihi ev, günümüzde müze olarak hizmet vermektedir. Kurtuluş Savaşı dönemine ait eşyalar ve fotoğraflar sergilenmektedir.", "place_query": "Atatürk Evi Müzesi, Yenişehir, Mersin"}, {"title": "Mersin Arkeoloji Müzesi", "summary": "Bölgenin zengin tarihini yansıtan eserlerin sergilendiği modern bir müzedir. Özellikle mozaik koleksiyonu ve lahitler büyük ilgi çekmektedir.", "place_query": "Mersin Arkeoloji Müzesi, Yenişehir, Mersin"}, {"title": "Mersin Devlet Opera ve Balesi", "summary": "Mimari açıdan dikkat çeken bu kültür merkezi, yıl boyunca opera, bale ve tiyatro gösterilerine ev sahipliği yapmaktadır. Sanatseverler için önemli bir duraktır.", "place_query": "Mersin Devlet Opera ve Balesi, Yenişehir, Mersin"}, {"title": "Cumhuriyet Meydanı", "summary": "Şehrin merkezinde yer alan bu meydan, Atatürk anıtı ve çevresindeki tarihi binalarla dikkat çeker. Buluşma noktası olarak bilinir ve çevresi kafelerle doludur.", "place_query": "Cumhuriyet Meydanı, Yenişehir, Mersin"}, {"title": "Mersin Sahil Bandı", "summary": "Uzun sahil şeridi boyunca uzanan yürüyüş ve bisiklet yolu, deniz manzarası eşliğinde spor yapma veya dinlenme imkanı sunar. Özellikle gün batımında keyifli bir atmosfere sahiptir.", "place_query": "Mersin Sahil Bandı, Yenişehir, Mersin"}, {"title": "Mersin Üniversitesi Kampüsü", "summary": "Geniş ve yeşil bir alana kurulu olan kampüs, içerisindeki gölet ve yürüyüş parkurlarıyla doğayla iç içe bir ortam sunar. Özellikle hafta sonları piknik ve gezinti için tercih edilir.", "place_query": "Mersin Üniversitesi Kampüsü, Yenişehir, Mersin"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5e91d164-d8cc-477f-84c3-1e8b8a833d3b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bodrum Kalesi (Sualtı Arkeoloji Müzesi)", "summary": "Bodrum''un simgesi haline gelmiş bu tarihi kale, Haçlılar tarafından inşa edilmiş olup içinde dünyaca ünlü Sualtı Arkeoloji Müzesi''ni barındırır. Cam batıkları ve eserleriyle tarihe tanıklık edebileceğiniz eşsiz bir durak.", "place_query": "Bodrum Kalesi, Bodrum, Muğla"}, {"title": "Gümbet Plajı", "summary": "Canlı gece hayatı ve hareketli plaj atmosferiyle ünlü Gümbet, su sporları ve eğlence arayanların uğrak noktasıdır. Gün boyu güneşlenip denizin tadını çıkarabilir, akşam barlar sokağında keyifli vakit geçirebilirsiniz.", "place_query": "Gümbet Plajı, Bodrum, Muğla"}, {"title": "Yalıkavak Marina", "summary": "Lüks yatlar, şık kafeler ve butik mağazalarıyla ünlü Yalıkavak Marina, Bodrum''un en prestijli bölgelerinden biridir. Özellikle gün batımında sunduğu manzara ve kaliteli restoranlarıyla ziyaretçilerini ağırlar.", "place_query": "Yalıkavak Marina, Bodrum, Muğla"}, {"title": "Antik Tiyatro (Bodrum)", "summary": "MÖ 4. yüzyıla tarihlenen bu açık hava tiyatrosu, 13.000 kişilik kapasitesiyle günümüzde hâlâ konser ve etkinliklere ev sahipliği yapmaktadır. Tepeden Bodrum manzarasını izlemek için harika bir noktadır.", "place_query": "Antik Tiyatro, Bodrum, Muğla"}, {"title": "Ortakent Plajı", "summary": "Sakin ve temiz deniziyle aileler için ideal olan Ortakent Plajı, mavi bayraklı kumu ve çevresindeki restoranlarıyla bilinir. Kalabalıktan uzak, huzurlu bir deniz keyfi sunar.", "place_query": "Ortakent Plajı, Bodrum, Muğla"}, {"title": "Pedasa Antik Kenti", "summary": "Bodrum''un en eski Leleg yerleşimlerinden biri olan Pedasa, zeytinlikler arasında gizlenmiş etkileyici surları ve kral mezarlarıyla tarih meraklılarına hitap eder. Az bilinen bu antik kent, sessiz bir keşif rotasıdır.", "place_query": "Pedasa Antik Kenti, Bodrum, Muğla"}, {"title": "Bitez Plajı", "summary": "Sakin atmosferi ve uzun sahil şeridiyle Bitez, yürüyüş yapmak ve denize girmek için popüler bir noktadır. Sahil boyunca sıralanan kafe ve barlarıyla hem gündüz hem akşam keyifli vakit geçirebilirsiniz.", "place_query": "Bitez Plajı, Bodrum, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '53a6b948-a338-4b79-900a-6976a470ad7e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarısu Plajı", "summary": "Dalaman''ın en popüler plajı olan Sarısu, ince kumlu sahili ve berrak deniziyle yüzme ve güneşlenmek için idealdir. Çevresindeki tesisler sayesinde rahat bir gün geçirebilirsiniz.", "place_query": "Sarısu Plajı, Dalaman, Muğla"}, {"title": "Dalaman Çayı", "summary": "Doğal güzelliğiyle ünlü Dalaman Çayı, özellikle rafting ve kano gibi su sporları için tercih edilir. Çevresi piknik ve doğa yürüyüşleri için de uygundur.", "place_query": "Dalaman Çayı, Dalaman, Muğla"}, {"title": "Kocagöl", "summary": "Sakin ve huzurlu atmosferiyle bilinen Kocagöl, kuş gözlemi yapmak ve doğayla iç içe vakit geçirmek isteyenler için harika bir noktadır. Göl çevresinde yürüyüş parkurları bulunur.", "place_query": "Kocagöl, Dalaman, Muğla"}, {"title": "Dalaman Müzesi", "summary": "Bölgenin tarihini ve kültürünü yansıtan Dalaman Müzesi, arkeolojik eserler ve etnografik objelerle ziyaretçilere keyifli bir geçmiş yolculuğu sunar.", "place_query": "Dalaman Müzesi, Dalaman, Muğla"}, {"title": "Kızılkum Plajı", "summary": "Altın sarısı kumsalı ve temiz deniziyle bilinen Kızılkum Plajı, Dalaman''da deniz keyfi yapmak için bir diğer popüler seçenektir. Özellikle yaz aylarında yoğun ilgi görür.", "place_query": "Kızılkum Plajı, Dalaman, Muğla"}, {"title": "Dalaman Şehitlik Anıtı", "summary": "Tarihi bir öneme sahip olan Dalaman Şehitlik Anıtı, bölgenin geçmişine tanıklık eden ve saygıyla ziyaret edilen bir noktadır. Çevresi yeşil alanlarla çevrilidir.", "place_query": "Dalaman Şehitlik Anıtı, Dalaman, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f61c7302-6a74-4a4f-bee7-502a7758b6bb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Datça Limanı ve Koyları", "summary": "Datça''nın kalbi sayılan bu liman, rengarenk tekneleri, sahil şeridindeki kafeleri ve restoranlarıyla canlı bir atmosfer sunar. Özellikle gün batımında eşsiz bir manzaraya sahiptir.", "place_query": "Datça Limanı, Datça, Muğla"}, {"title": "Knidos Antik Kenti", "summary": "Datça Yarımadası''nın en ucunda yer alan bu antik kent, iki limanı ve tarihi kalıntılarıyla ünlüdür. Afrodisyas ve yuvarlak tapınak gibi yapıları görmek mümkündür.", "place_query": "Knidos Antik Kenti, Datça, Muğla"}, {"title": "Palamutbükü Plajı", "summary": "Datça''nın en popüler plajlarından biri olan Palamutbükü, berrak denizi ve ince kumlu sahiliyle yüzme ve güneşlenme için idealdir. Çevresindeki balık restoranlarıyla da meşhurdur.", "place_query": "Palamutbükü Plajı, Datça, Muğla"}, {"title": "Kızlan Köyü ve Eski Datça Evleri", "summary": "Beyaz badanalı, taş döşeli dar sokakları ve tarihi taş evleriyle ünlü Kızlan Köyü, Datça''nın otantik atmosferini yansıtır. Zeytin ağaçları arasında huzurlu bir yürüyüş yapılabilir.", "place_query": "Kızlan Köyü, Datça, Muğla"}, {"title": "Datça Değirmenleri", "summary": "Yarımadanın çeşitli noktalarında bulunan tarihi yel değirmenleri, özellikle gün batımında harika fotoğraf kareleri sunar. En bilinenleri Reşadiye ve Hızırşah bölgesindedir.", "place_query": "Datça Değirmenleri, Datça, Muğla"}, {"title": "Hayıtbükü Plajı", "summary": "Sakin ve huzurlu atmosferiyle bilinen Hayıtbükü, mavi bayraklı plajı ve çam ormanlarıyla çevrili doğal güzelliğiyle öne çıkar. Denizi oldukça berrak ve sakindir.", "place_query": "Hayıtbükü Plajı, Datça, Muğla"}, {"title": "Datça Yarımadası Özel Çevre Koruma Bölgesi", "summary": "Doğal güzellikleri ve biyolojik çeşitliliği koruma altına alınan bu bölge, bakir koyları, zengin bitki örtüsü ve yürüyüş parkurlarıyla doğa severler için idealdir.", "place_query": "Datça Yarımadası Özel Çevre Koruma Bölgesi, Datça, Muğla"}, {"title": "Reşadiye Mahallesi (Eski Datça)", "summary": "Restore edilmiş tarihi taş evleri, butik otelleri ve sanat galerileriyle ünlü Eski Datça, dar sokaklarında kaybolmak için harika bir yerdir. Zeytinyağlı yemekleriyle de meşhurdur.", "place_query": "Reşadiye Mahallesi, Datça, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '52246f12-5903-4f54-bede-1aa25575bf40'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"lat": 36.5452403, "lng": 29.1232412, "title": "Ölüdeniz Plajı", "summary": "Turkuaz rengi denizi ve Belceğiz Plajı ile dünyaca ünlü, yamaç paraşütü için de ideal bir nokta.", "category": "sightseeing", "place_id": "osm:relation:17968848", "distance_km": 7.5, "place_query": "Ölüdeniz Plajı, Fethiye, Muğla", "distance_km_from_district": 7.5}, {"lat": 36.4734959, "lng": 29.4040786, "title": "Saklıkent Kanyonu", "summary": "18 km uzunluğundaki görkemli kanyon, doğa yürüyüşü ve serin sularında yürüyüş deneyimi sunar.", "category": "sightseeing", "place_id": "osm:node:310786309", "distance_km": 29.8, "place_query": "Saklıkent Kanyonu, Seydikemer, Muğla", "distance_km_from_district": 29.8}, {"lat": 36.5750, "lng": 29.0910, "title": "Kayaköy (Karmylassos)", "summary": "Terk edilmiş Rum köyü, tarihi taş evleri ve hüzünlü atmosferiyle açık hava müzesi gibidir.", "category": "sightseeing", "place_id": "manual:kayakoy", "distance_km": 4.8, "google_type": "historical_landmark", "place_query": "Kayaköy Örenyeri, Fethiye, Muğla", "distance_km_from_district": 4.8}, {"lat": 36.6225, "lng": 29.1168, "title": "Fethiye Kaya Mezarları", "summary": "Antik Telmessos kentinden kalma, kayalara oyulmuş etkileyici Likya mezarları şehre tepeden bakar.", "category": "sightseeing", "place_id": "manual:amyntas", "distance_km": 1.1, "google_type": "historical_landmark", "place_query": "Fethiye Kaya Mezarları, Fethiye, Muğla", "distance_km_from_district": 1.1}, {"lat": 36.4974686, "lng": 29.1271717, "title": "Butterfly Valley (Kelebekler Vadisi)", "summary": "Sadece deniz veya yamaç paraşütüyle ulaşılabilen, ender kelebek türlerine ev sahipliği yapan doğal vadi.", "category": "sightseeing", "place_id": "osm:node:676515551", "distance_km": 12.8, "place_query": "Kelebekler Vadisi, Fethiye, Muğla", "distance_km_from_district": 12.8}, {"lat": 36.6670051, "lng": 29.1054533, "title": "Çalış Plajı", "summary": "Gün batımı manzarası ve uzun kumsalıyla ünlü, Fethiye merkeze yakın popüler bir plaj.", "category": "sightseeing", "place_id": "osm:way:187029014", "distance_km": 6.2, "place_query": "Çalış Plajı, Fethiye, Muğla", "distance_km_from_district": 6.2}, {"lat": 36.5430, "lng": 29.0520, "title": "Af Kule (Kızılada)", "summary": "Ölüdeniz açıklarında bulunan, yüzme ve şnorkelle dalış için ideal küçük ada.", "category": "sightseeing", "place_id": "manual:afkule", "distance_km": 9.7, "google_type": "tourist_attraction", "place_query": "Af Kule, Ölüdeniz, Fethiye, Muğla", "distance_km_from_district": 9.7}]'::jsonb, service_pois_json = '[{"lat": 36.6137255, "lng": 29.0760009, "type": "restaurant", "label": "Main Restaurant", "source": "nominatim_vitrin", "category": "amenity", "place_id": "osm:way:277385226", "googleType": "restaurant", "distance_km": 3.8}, {"lat": 36.7493095, "lng": 28.9448495, "type": "restaurant", "label": "Günaydin Restaurant", "source": "nominatim_vitrin", "category": "amenity", "place_id": "osm:way:241505928", "googleType": "restaurant", "distance_km": 21.7}, {"lat": 36.5768779, "lng": 29.087677, "type": "restaurant", "label": "Nara Restaurant", "source": "nominatim_vitrin", "category": "amenity", "place_id": "osm:node:2476440116", "googleType": "restaurant", "distance_km": 4.8}, {"lat": 36.5498464, "lng": 29.1251439, "type": "supermarket", "label": "ÖDS Discount Supermarket", "source": "nominatim_vitrin", "category": "amenity", "place_id": "osm:node:9116556523", "googleType": "supermarket", "distance_km": 7}, {"lat": 36.5503338, "lng": 29.1254483, "type": "supermarket", "label": "Unicorn Supermarket", "source": "nominatim_vitrin", "category": "amenity", "place_id": "osm:node:9116555126", "googleType": "supermarket", "distance_km": 6.9}, {"lat": 37.0499997, "lng": 28.3584581, "type": "supermarket", "label": "Has Supermarket", "source": "nominatim_vitrin", "category": "amenity", "place_id": "osm:node:5239394922", "googleType": "supermarket", "distance_km": 83.3}, {"lat": 36.7387178, "lng": 29.218329