UPDATE location_pages SET travel_ideas_json = '[{"title": "Kavaklıdere Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle yaz aylarında yerli halkın ve çevre ilçelerden gelen ziyaretçilerin uğrak yeridir.", "place_query": "Kavaklıdere Şelalesi, Kavaklıdere, Muğla"}, {"title": "Menteşe Tarihi Evleri (Kavaklıdere Merkez)", "summary": "Kavaklıdere merkezinde yer alan geleneksel Menteşe mimarisini yansıtan tarihi evler, bölgenin kültürel dokusunu keşfetmek isteyenler için görülmeye değerdir.", "place_query": "Kavaklıdere Merkez, Muğla"}, {"title": "Çamlıca Yaylası", "summary": "Yemyeşil ormanlar ve temiz havasıyla ünlü olan Çamlıca Yaylası, kamp ve doğa yürüyüşü için sakin bir kaçış noktasıdır. Manzarası fotoğrafçılar için idealdir.", "place_query": "Çamlıca Yaylası, Kavaklıdere, Muğla"}, {"title": "Sarnıç Yaylası", "summary": "Kavaklıdere''nin en popüler yaylalarından biri olan Sarnıç, yayla şenliklerine ev sahipliği yapar. Doğal güzellikleri ve serin havasıyla ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Sarnıç Yaylası, Kavaklıdere, Muğla"}, {"title": "Kavaklıdere Barajı", "summary": "Bölgenin önemli su kaynaklarından biri olan baraj, çevresindeki yeşil alanlarla piknik ve olta balıkçılığı için tercih edilen bir yerdir. Sakin manzarasıyla dinlendiricidir.", "place_query": "Kavaklıdere Barajı, Kavaklıdere, Muğla"}, {"title": "Kızılyaka Köyü (Doğa Yürüyüşü Rotası)", "summary": "Kavaklıdere''ye bağlı bu köy, zeytinlikleri ve doğal patikalarıyla doğa yürüyüşçüleri için güzel bir rotadır. Köy yaşamını yakından görmek isteyenler için idealdir.", "place_query": "Kızılyaka Köyü, Kavaklıdere, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ebf22132-ebfc-42c9-95f6-7f8b5ad28435'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köyceğiz Gölü", "summary": "Doğal güzelliği ve sakin atmosferiyle ünlü olan bu göl, tekne turları, yüzme ve kuş gözlemi için idealdir. Çevresindeki sazlıklar ve ormanlık alanlar huzurlu bir kaçamak sunar.", "place_query": "Köyceğiz Gölü, Köyceğiz, Muğla"}, {"title": "Kaunos Antik Kenti", "summary": "Köyceğiz Gölü kıyısındaki bu antik kent, Likya ve Karya dönemlerine ait kalıntılarıyla tarih meraklılarını cezbeder. Kaya mezarları ve antik tiyatrosu en dikkat çekici yapılarındandır.", "place_query": "Kaunos Antik Kenti, Köyceğiz, Muğla"}, {"title": "İztuzu Plajı", "summary": "Caretta caretta kaplumbağalarının yuvalama alanı olan bu plaj, altın kumları ve berrak deniziyle ünlüdür. Doğal yaşamı koruma çalışmaları sayesinde eşsiz bir ekosisteme ev sahipliği yapar.", "place_query": "İztuzu Plajı, Ortaca, Muğla"}, {"title": "Köyceğiz Dalyan Kanalları", "summary": "Tekne turlarıyla keşfedilen bu kanallar, göl ile deniz arasında uzanır ve yemyeşil doğasıyla büyüler. Yüzme molaları ve kuş gözlemi için popüler bir rotadır.", "place_query": "Köyceğiz Dalyan Kanalları, Köyceğiz, Muğla"}, {"title": "Sultaniye Kaplıcaları", "summary": "Köyceğiz Gölü kıyısındaki bu doğal kaplıcalar, şifalı termal suları ve çamur banyolarıyla sağlık turizmi için idealdir. Muhteşem göl manzarası eşliğinde dinlenme imkanı sunar.", "place_query": "Sultaniye Kaplıcaları, Köyceğiz, Muğla"}, {"title": "Köyceğiz Doğal Parkı", "summary": "Göl çevresindeki bu korunan alan, yürüyüş parkurları ve piknik alanlarıyla doğaseverler için biçilmiş kaftandır. Zengin bitki örtüsü ve kuş türleri gözlemlenebilir.", "place_query": "Köyceğiz Doğal Parkı, Köyceğiz, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'df127e98-9e51-431e-9d56-2b21d4e2ca2e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Marmaris Kalesi ve Arkeoloji Müzesi", "summary": "Şehrin tam merkezinde, limana hakim bir tepede yer alan tarihi kale, içindeki arkeoloji müzesiyle hem tarihe tanıklık ediyor hem de muhteşem bir manzara sunuyor.", "place_query": "Marmaris Kalesi, Marmaris, Muğla"}, {"title": "İçmeler Plajı", "summary": "Marmaris''e sadece 8 km uzaklıktaki bu uzun ve ince kumlu plaj, sakin denizi ve çevresindeki restoran ve kafelerle aileler ve yüzme severler için ideal bir kaçış noktasıdır.", "place_query": "İçmeler Plajı, Marmaris, Muğla"}, {"title": "Turunç Plajı ve Koyu", "summary": "Çam ormanlarıyla çevrili, berrak sulara sahip bu huzurlu koy, doğal güzelliği ve sakin atmosferiyle Marmaris''in en popüler günübirlik gezi destinasyonlarından biridir.", "place_query": "Turunç, Marmaris, Muğla"}, {"title": "Bozburun Yarımadası", "summary": "Sakin köyleri, gizli koyları ve geleneksel tekne yapım atölyeleriyle ünlü bu yarımada, doğa ve huzur arayanlar için eşsiz bir keşif rotası sunar.", "place_query": "Bozburun, Marmaris, Muğla"}, {"title": "Sedir Adası (Kedrai Antik Kenti)", "summary": "Eşsiz Kleopatra Plajı''na ev sahipliği yapan bu ada, antik kent kalıntıları ve efsanevi kumsalıyla tarih ve doğayı bir arada deneyimlemek isteyenler için görülmeye değerdir.", "place_query": "Sedir Adası, Marmaris, Muğla"}, {"title": "Marmaris Milli Parkı", "summary": "Kızılçam ormanları, yürüyüş parkurları ve koylarıyla kaplı bu geniş milli park, doğa yürüyüşü, kamp ve piknik için şehir hayatından kaçış noktasıdır.", "place_query": "Marmaris Milli Parkı, Marmaris, Muğla"}, {"title": "Netsel Marina", "summary": "Lüks yatları, şık restoranları, kafeleri ve mağazalarıyla modern bir yaşam merkezi olan marina, özellikle akşam saatlerinde keyifli bir gezinti ve yemek deneyimi sunar.", "place_query": "Netsel Marina, Marmaris, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fd0d527d-63c6-4b5d-aa81-bb60404dad85'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Muğla Müzesi", "summary": "Bölgenin arkeolojik ve etnografik zenginliğini sergileyen bu müze, Likya, Karya ve Roma dönemine ait eserler ile yöresel kıyafet ve eşyaları görmek için ideal bir duraktır.", "place_query": "Muğla Müzesi, Menteşe, Muğla"}, {"title": "Menteşe Konakları (Saburhane Bölgesi)", "summary": "Tarihi Muğla evlerinin en güzel örneklerini barındıran bu bölge, dar sokakları, restore edilmiş konakları ve geleneksel mimarisiyle fotoğrafçıların ve tarih meraklılarının uğrak noktasıdır.", "place_query": "Saburhane Evleri, Menteşe, Muğla"}, {"title": "Muğla Ulu Camii", "summary": "Şehir merkezinde yer alan ve 14. yüzyılda inşa edilen bu tarihi cami, sade ama etkileyici mimarisi ve geniş avlusuyla dikkat çeker, aynı zamanda şehrin simge yapılarındandır.", "place_query": "Muğla Ulu Camii, Menteşe, Muğla"}, {"title": "Arasta Çarşısı", "summary": "Muğla’nın kalbinde yer alan bu tarihi çarşı, yöresel ürünler, el sanatları ve hediyelik eşya dükkanlarıyla hem alışveriş hem de şehrin dokusunu hissetmek için keyifli bir rotadır.", "place_query": "Arasta Çarşısı, Menteşe, Muğla"}, {"title": "Muğla Atatürk Evi ve Kültür Merkezi", "summary": "Atatürk''ün 1930 yılında Muğla ziyaretinde kaldığı bu tarihi konak, günümüzde müze olarak hizmet verir ve Kurtuluş Savaşı ile Atatürk''e ait fotoğraf ve eşyaları sergiler.", "place_query": "Atatürk Evi Müzesi, Menteşe, Muğla"}, {"title": "Gazi Mustafa Kemal Atatürk Bulvarı (Kordon)", "summary": "Şehrin en canlı caddelerinden biri olan bu bulvar, kafe ve restoranları, çınar ağaçlarıyla kaplı yürüyüş yolu ve şehir manzarasıyla yerli halkın ve ziyaretçilerin buluşma noktasıdır.", "place_query": "Muğla Kordon, Menteşe, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '102e2b20-190b-4eb3-b4b6-cb44fdc624f9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Labranda Antik Kenti", "summary": "Milas’a 14 km uzaklıkta, yemyeşil bir tepe üzerinde yer alan bu antik kent, Hekatomnos Hanedanı’na başkentlik yapmış olup Zeus Labraundos Tapınağı ile ünlüdür. Sessiz ortamı ve etkileyici manzarasıyla tarih ve doğayı bir arada sunar.", "place_query": "Labranda Antik Kenti, Milas, Muğla"}, {"title": "Milas Müzesi", "summary": "Şehir merkezinde bulunan müze, bölgedeki kazılardan çıkarılan eserlerin sergilendiği önemli bir kültür durağıdır. Heykeller, lahitler ve takılar gibi birçok arkeolojik buluntuya ev sahipliği yapar.", "place_query": "Milas Müzesi, Milas, Muğla"}, {"title": "Beçin Antik Kenti", "summary": "Milas’a 5 km mesafedeki bu antik kent, Karia dönemine ait surları, kalesi ve yapı kalıntılarıyla dikkat çeker. Tepeden Milas Ovası’nı izleme fırsatı sunar ve özellikle gün batımında büyüleyicidir.", "place_query": "Beçin Antik Kenti, Milas, Muğla"}, {"title": "İasos Antik Kenti", "summary": "Milas’ın Kıyıkışlacık Mahallesi’nde bulunan İasos, deniz kıyısındaki konumu ve agorası, tiyatrosu ile ünlüdür. Antik dönemin önemli balıkçılık merkezi olan kent, huzurlu bir gezi ve yüzme imkanı sunar.", "place_query": "İasos Antik Kenti, Kıyıkışlacık, Milas, Muğla"}, {"title": "Gökçeler Kanyonu ve İncirliin Mağarası", "summary": "Milas’a yaklaşık 30 km uzaklıkta bulunan bu doğa harikası kanyon, yürüyüş parkurları ve şelaleleriyle ünlüdür. İçindeki İncirliin Mağarası, tarih öncesi döneme ait kalıntıları ve sarkıtlarıyla keşfedilmeyi bekler.", "place_query": "Gökçeler Kanyonu, Milas, Muğla"}, {"title": "Milas Ulu Camii", "summary": "14. yüzyılda inşa edilen bu tarihi cami, Menteşeoğulları dönemine ait nadide bir yapıdır. Kesme taş işçiliği ve sade mimarisiyle şehrin en önemli dini yapılarından biridir.", "place_query": "Milas Ulu Camii, Milas, Muğla"}, {"title": "Bafa Gölü (Milas Kıyıları)", "summary": "Milas sınırları içinde kalan Bafa Gölü kıyıları, zeytin ağaçları ve antik kalıntılarla çevrili huzurlu bir doğa alanıdır. Kuş gözlemi ve doğa yürüyüşü için ideal olup, özellikle Herakleia Antik Kenti’ne yakınlığıyla bilinir.", "place_query": "Bafa Gölü, Milas, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bc77d8ec-1d5a-44ef-b372-f65c9206500a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dalyan Nehri ve Kaya Mezarları", "summary": "Dalyan Nehri boyunca tekne turlarıyla keşfedilen antik Kaya Mezarları, bölgenin en etkileyici tarihi kalıntılarındandır. Nehir kenarındaki restoranlarda yemek yerken manzaranın tadını çıkarabilirsiniz.", "place_query": "Dalyan Nehri Kaya Mezarları, Ortaca, Muğla"}, {"title": "İztuzu Plajı", "summary": "Caretta caretta kaplumbağalarının yumurtlama alanı olarak ünlü bu uzun kumsal, doğal güzelliği ve temiz deniziyle yüzme ve güneşlenme için idealdir. Çevresindeki tatil köyleri ve kafelerle huzurlu bir gün geçirebilirsiniz.", "place_query": "İztuzu Plajı, Ortaca, Muğla"}, {"title": "Kaunos Antik Kenti", "summary": "Dalyan''a hakim tepede yer alan Kaunos, Likya ve Karya dönemlerine ait kalıntılarıyla tarih meraklıları için eşsiz bir açık hava müzesidir. Antik tiyatro, agora ve surları görmek mümkündür.", "place_query": "Kaunos Antik Kenti, Ortaca, Muğla"}, {"title": "Köyceğiz Gölü", "summary": "Ortaca sınırlarındaki bu büyük doğal göl, çevresindeki sazlıklar ve kuş türleriyle doğa yürüyüşleri ve tekne turları için popülerdir. Göl kıyısında piknik yapabilir veya balık restoranlarında vakit geçirebilirsiniz.", "place_query": "Köyceğiz Gölü, Ortaca, Muğla"}, {"title": "Sultaniye Kaplıcaları", "summary": "Köyceğiz Gölü kıyısında yer alan bu doğal kaplıcalar, şifalı suları ve çamur banyolarıyla ünlüdür. Romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılır; ayrıca göl manzarası eşliğinde termal keyfi sunar.", "place_query": "Sultaniye Kaplıcaları, Ortaca, Muğla"}, {"title": "Dalyan Çamur Banyoları", "summary": "Dalyan''daki bu doğal çamur havuzları, ziyaretçilere eğlenceli bir cilt bakımı deneyimi sunar. Çamura bulanıp güneşte kuruduktan sonra temizlenmek için nehre girebilirsiniz.", "place_query": "Dalyan Çamur Banyoları, Ortaca, Muğla"}, {"title": "Ortaca Pazarı", "summary": "Her hafta kurulan bu renkli pazar, yöresel ürünler, taze meyve-sebze ve el işi hediyelikler için uğrak noktasıdır. Yerel halkla kaynaşmak ve Muğla mutfağının lezzetlerini tatmak için idealdir.", "place_query": "Ortaca Pazarı, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0a12221e-e745-44f0-b870-224efeaa44db'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saklıkent Milli Parkı", "summary": "Türkiye''nin en uzun kanyonlarından biri olan Saklıkent, doğa yürüyüşü ve serin sularıyla ünlüdür. Yaz aylarında kanyon içinde yürüyüp şelalelerin altında vakit geçirebilirsiniz.", "place_query": "Saklıkent Milli Parkı, Seydikemer, Muğla"}, {"title": "Patara Antik Kenti", "summary": "Likya Birliği''nin başkenti olan Patara, 12 km''lik kumsalı ve antik tiyatrosuyla tarih ve doğayı birleştirir. Noel Baba''nın doğduğu yer olarak da bilinir.", "place_query": "Patara Antik Kenti, Seydikemer, Muğla"}, {"title": "Patara Plajı", "summary": "Türkiye''nin en uzun plajlarından biri olan Patara, caretta caretta kaplumbağalarının yuvalama alanıdır. Altın kumları ve dalgasız deniziyle aileler için idealdir.", "place_query": "Patara Plajı, Seydikemer, Muğla"}, {"title": "Letoon Antik Kenti", "summary": "UNESCO Dünya Mirası listesindeki Letoon, Likya''nın dini merkezi olarak üç tapınağıyla dikkat çeker. Sessiz ve huzurlu atmosferiyle tarih meraklılarına hitap eder.", "place_query": "Letoon Antik Kenti, Seydikemer, Muğla"}, {"title": "Xanthos Antik Kenti", "summary": "UNESCO listesindeki Xanthos, Likya uygarlığının başkenti olup Harpy Anıtı ve Roma tiyatrosuyla ünlüdür. Tarihi kalıntılar arasında dolaşmak eşsiz bir deneyim sunar.", "place_query": "Xanthos Antik Kenti, Seydikemer, Muğla"}, {"title": "Girmeler Mağarası", "summary": "Seydikemer merkeze yakın Girmeler Mağarası, doğal oluşumu ve serin havasıyla keşfedilmeyi bekler. Mağara içindeki sarkıt ve dikitler görülmeye değerdir.", "place_query": "Girmeler Mağarası, Seydikemer, Muğla"}, {"title": "Eşen Çayı", "summary": "Saklıkent''ten doğan Eşen Çayı, rafting ve doğa sporları için popülerdir. Çay kenarında piknik yapıp serin suların keyfini çıkarabilirsiniz.", "place_query": "Eşen Çayı, Seydikemer, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c0e0aeff-03f7-4fdb-a313-73eec446fd81'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akyaka Plajı", "summary": "Ula''nın en popüler plajı olan Akyaka Plajı, ince kumları ve berrak deniziyle ünlüdür. Özellikle yaz aylarında yerli ve yabancı turistlerin akınına uğrar.", "place_query": "Akyaka Plajı, Ula, Muğla"}, {"title": "Azmak Deresi", "summary": "Akyaka''dan geçen ve doğal güzelliğiyle büyüleyen Azmak Deresi, tekne turlarıyla keşfedilebilir. Soğuk ve berrak suları, yeşil doğayla birleşerek eşsiz bir manzara sunar.", "place_query": "Azmak Deresi, Akyaka, Ula, Muğla"}, {"title": "Ula Kentsel Sit Alanı ve Tarihi Evler", "summary": "Ula ilçe merkezinde yer alan tarihi evler ve dar sokaklar, geleneksel Muğla mimarisini yansıtır. Yürüyüş yaparak bu tarihi dokuyu yakından görebilirsiniz.", "place_query": "Ula Kentsel Sit Alanı, Ula, Muğla"}, {"title": "Çiçekli Köyü ve Çiçekli Şelalesi", "summary": "Ula''ya bağlı Çiçekli Köyü''nde bulunan şelale, doğa yürüyüşleri ve piknik için ideal bir noktadır. Serin suları ve çevresindeki yeşillikler huzur verir.", "place_query": "Çiçekli Şelalesi, Ula, Muğla"}, {"title": "Gökova Körfezi", "summary": "Ula kıyılarında yer alan Gökova Körfezi, masmavi denizi ve çam ormanlarıyla çevrili koylarıyla ünlüdür. Tekne turları ve yüzme için popüler bir destinasyondur.", "place_query": "Gökova Körfezi, Ula, Muğla"}, {"title": "Köyceğiz Gölü (Ula sınırı)", "summary": "Ula ile Köyceğiz arasında yer alan bu doğal göl, kuş gözlemi ve doğa yürüyüşleri için harika bir alandır. Göl çevresindeki plajlar da ziyaretçiler için cazip noktalardır.", "place_query": "Köyceğiz Gölü, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '93d12c61-42b9-4009-bf55-ac98a81b4120'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Stratonikeia Antik Kenti", "summary": "Gladyatörler şehri olarak bilinen, dünyanın en büyük mermer kentlerinden biri. Helenistik, Roma, Bizans, Beylikler ve Osmanlı dönemlerine ait katmanları bir arada görebilirsiniz.", "place_query": "Stratonikeia Antik Kenti, Yatağan, Muğla"}, {"title": "Lagina Antik Kenti", "summary": "Hekate kutsal alanı ile ünlü bu antik kent, etkileyici kabartmaları ve tapınak kalıntılarıyla tarih meraklıları için eşsiz bir duraktır.", "place_query": "Lagina Antik Kenti, Yatağan, Muğla"}, {"title": "Yatağan Şehir Müzesi", "summary": "Bölgenin arkeolojik zenginliklerini sergileyen müze, özellikle Stratonikeia ve Lagina kazılarından çıkan eserlerle ziyaretçileri büyüler.", "place_query": "Yatağan Şehir Müzesi, Muğla"}, {"title": "Köyceğiz Gölü", "summary": "Yatağan sınırlarına yakın bu doğal göl, kuş cenneti ve doğa yürüyüşleriyle huzur verici bir kaçış noktasıdır. Göl kenarında piknik yapabilir veya tekne turuna çıkabilirsiniz.", "place_query": "Köyceğiz Gölü, Muğla"}, {"title": "Yatağan Termik Santrali ve Çevresi", "summary": "Bölgenin enerji üretim merkezi olan santralin çevresindeki tepelerden Muğla ovasının manzarası izlenebilir. Ayrıca yakındaki eski köy yaşamını yansıtan kırsal alanlar keşfedilebilir.", "place_query": "Yatağan Termik Santrali, Muğla"}, {"title": "Kavaklıdere Şelalesi", "summary": "Yatağan''a bağlı Kavaklıdere ilçesinde yer alan bu şelale, serin suları ve yeşil doğasıyla piknik ve doğa yürüyüşü için idealdir.", "place_query": "Kavaklıdere Şelalesi, Muğla"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5eca2009-7d56-4cdc-a317-7a83683e452d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bulanık Ulu Camii", "summary": "Bulanık''ın en önemli tarihi yapılarından biri olan cami, Selçuklu ve Osmanlı mimarisinin izlerini taşır. Şehir merkezinde yer alan cami, özellikle mimari detayları ve huzurlu atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Bulanık Ulu Camii, Bulanık, Muş"}, {"title": "Muş Bulanık Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde bulunan tarihi kale, bölgenin savunma amaçlı kullanılan önemli yapılarındandır. Kaleye çıktığınızda Bulanık Ovası''nın muhteşem manzarasını izleyebilirsiniz.", "place_query": "Bulanık Kalesi, Bulanık, Muş"}, {"title": "Bulanık Ovası", "summary": "Muş Ovası''nın bir parçası olan geniş ve verimli Bulanık Ovası, özellikle bahar aylarında yemyeşil görüntüsüyle doğa tutkunlarına huzur dolu bir seyir imkanı sunar. Bölgede tarım ve hayvancılık faaliyetlerini gözlemleyebilirsiniz.", "place_query": "Bulanık Ovası, Bulanık, Muş"}, {"title": "Bulanık Çayı", "summary": "Bulanık ilçesinden geçen ve bölgenin can damarı olan bu akarsu, çevresindeki piknik alanları ve doğal güzellikleriyle hafta sonu kaçamakları için idealdir. Su kenarında yürüyüş yapabilir veya balık tutabilirsiniz.", "place_query": "Bulanık Çayı, Bulanık, Muş"}, {"title": "Yoncalı Göleti", "summary": "Bulanık''a bağlı Yoncalı köyü yakınlarında bulunan bu gölet, mesire alanı olarak düzenlenmiştir. Piknik yapmak, doğa yürüyüşü yapmak ve kuş gözlemi için sakin bir ortam arayanların tercih ettiği bir noktadır.", "place_query": "Yoncalı Göleti, Bulanık, Muş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c1566e77-1054-46be-94a6-b61d71fd750f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hasköy Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi cami, Osmanlı dönemi mimarisinin izlerini taşıması ve bölge halkı için önemli bir ibadet ve buluşma noktası olmasıyla bilinir.", "place_query": "Hasköy Merkez Camii, Hasköy, Muş"}, {"title": "Hasköy Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin, el işi halı ve kilimlerin satıldığı pazar, ilçe ekonomisinin can damarı olup ziyaretçilere otantik bir alışveriş deneyimi sunar.", "place_query": "Hasköy Kapalı Pazar Yeri, Hasköy, Muş"}, {"title": "Murat Nehri Kenarı", "summary": "Hasköy''den geçen Murat Nehri''nin kıyıları, piknik ve doğa yürüyüşü için ideal alanlar sunar; özellikle bahar aylarında yeşilin ve suyun birleştiği huzurlu bir manzaraya sahiptir.", "place_query": "Murat Nehri, Hasköy, Muş"}, {"title": "Hasköy Kalesi", "summary": "İlçe sınırları içinde yer alan tarihi kale kalıntıları, bölgenin stratejik önemini gösterir ve tepeden çevrenin panoramik manzarasını izleme fırsatı verir.", "place_query": "Hasköy Kalesi, Hasköy, Muş"}, {"title": "Karaçoban Yaylası", "summary": "Hasköy''e bağlı köylerde bulunan bu yayla, yaz aylarında serin havası ve doğal güzellikleriyle kampçılar ve doğa severler için popüler bir kaçış noktasıdır.", "place_query": "Karaçoban Yaylası, Hasköy, Muş"}, {"title": "Korkut Köprüsü", "summary": "Tarihi taş köprü, Murat Nehri üzerinde yer alır ve Osmanlı dönemi mühendisliğini yansıtan yapısıyla fotoğraf tutkunları için ilgi çekici bir duraktır.", "place_query": "Korkut Köprüsü, Hasköy, Muş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a0a4d299-afd1-47a7-bf8d-f9941ef599e1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Korkut Ulu Camii", "summary": "Tarihi bir yapı olan bu cami, bölgenin en eski ibadet yerlerinden biridir ve mimarisiyle dikkat çeker.", "place_query": "Korkut Ulu Camii, Korkut, Muş"}, {"title": "Korkut Kalesi", "summary": "Tarihi kalıntılarıyla ünlü bu kale, bölgenin geçmişine tanıklık eden önemli bir noktadır ve ziyaretçilere eşsiz bir manzara sunar.", "place_query": "Korkut Kalesi, Korkut, Muş"}, {"title": "Murat Nehri", "summary": "Bölgenin en önemli akarsularından biri olan Murat Nehri, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçiler için huzurlu bir kaçış noktasıdır.", "place_query": "Murat Nehri, Korkut, Muş"}, {"title": "Korkut Mesire Alanı", "summary": "Yeşil alanları ve temiz havasıyla aileler için ideal bir dinlenme ve piknik yeridir; şehir gürültüsünden uzaklaşmak isteyenler için biçilmiş kaftandır.", "place_query": "Korkut Mesire Alanı, Korkut, Muş"}, {"title": "Korkut Köprüsü", "summary": "Tarihi taş köprü, yörenin kültürel mirasını yansıtan ve fotoğrafçıların ilgisini çeken bir yapıdır.", "place_query": "Korkut Köprüsü, Korkut, Muş"}, {"title": "Korkut Yaylası", "summary": "Doğa yürüyüşleri ve kampçılık için popüler bir destinasyon olan yayla, yemyeşil manzaraları ve serin havasıyla yaz aylarında sıkça tercih edilir.", "place_query": "Korkut Yaylası, Korkut, Muş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b71134eb-734e-4f44-9e62-cd1224bc9c5f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Malazgirt Meydan Muharebesi Tarihî Alanı", "summary": "1071''deki büyük zaferin yaşandığı bu tarihî alan, Selçuklu tarihine tanıklık eden en önemli noktalardan biridir. Ziyaretçiler, savaşın geçtiği ovayı görebilir ve anıtları gezebilirler.", "place_query": "Malazgirt Meydan Muharebesi Tarihî Alanı, Malazgirt, Muş"}, {"title": "Malazgirt Kalesi", "summary": "Tarih boyunca birçok medeniyete ev sahipliği yapmış olan bu kale, şehre hâkim bir tepede yer alır. Kaleyi gezerken hem tarihî atmosferi hissedebilir hem de çevrenin panoramik manzarasını izleyebilirsiniz.", "place_query": "Malazgirt Kalesi, Malazgirt, Muş"}, {"title": "Malazgirt Ulu Camii", "summary": "Selçuklu dönemine ait bu tarihî cami, taş işçiliği ve mimarisiyle dikkat çeker. İlçenin en eski yapılarından biri olarak ziyaretçilere geçmişe yolculuk imkânı sunar.", "place_query": "Malazgirt Ulu Camii, Malazgirt, Muş"}, {"title": "Adilcevaz Kalesi", "summary": "Malazgirt''e yaklaşık 30 km mesafedeki bu Urartu kalesi, Van Gölü kıyısında etkileyici bir konuma sahiptir. Tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "Adilcevaz Kalesi, Adilcevaz, Bitlis"}, {"title": "Malazgirt Şehitlik Anıtı", "summary": "1071 zaferinde hayatını kaybeden askerler anısına yapılan bu anıt, bölgenin en sembolik yapılarındandır. Çevresi düzenlenmiş alanıyla huzurlu bir ziyaret noktasıdır.", "place_query": "Malazgirt Şehitlik Anıtı, Malazgirt, Muş"}, {"title": "Bulanık Ovası", "summary": "Malazgirt yakınlarındaki bu geniş ova, doğal güzelliği ve verimli topraklarıyla ünlüdür. Özellikle bahar aylarında yeşilin her tonunu görebileceğiniz huzur verici bir manzaraya sahiptir.", "place_query": "Bulanık Ovası, Bulanık, Muş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f66017a-3532-4bbb-960c-b64cd3e6884e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Muş Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, Muş''un sembol yapılarından biridir. Urartu dönemine kadar uzanan geçmişi ve muhteşem şehir manzarasıyla ziyaretçilerini büyüler.", "place_query": "Muş Kalesi, Merkez, Muş"}, {"title": "Murat Köprüsü", "summary": "Tarihi taş köprü, Murat Nehri üzerinde yer almakta olup Selçuklu dönemi mimarisinin güzel bir örneğidir. Özellikle fotoğrafçılar için eşsiz bir manzara sunar.", "place_query": "Murat Köprüsü, Merkez, Muş"}, {"title": "Muş Lalesi Doğal Yaşam Alanı", "summary": "Her yıl Nisan-Mayıs aylarında açan endemik Muş laleleri, bölgenin en önemli doğal güzelliklerindendir. Bu alan, rengarenk lalelerle kaplı manzarasıyla doğa severler için görülmeye değerdir.", "place_query": "Muş Lalesi Doğal Yaşam Alanı, Merkez, Muş"}, {"title": "Çarşı Camii (Ulu Camii)", "summary": "Şehir merkezinde bulunan tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Yüzyıllara meydan okuyan yapı, ibadet ve ziyaret için önemli bir duraktır.", "place_query": "Çarşı Camii, Merkez, Muş"}, {"title": "Muş Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen müze, Urartu, Roma ve Osmanlı dönemlerine ait buluntulara ev sahipliği yapmaktadır. Muş''un kültürel tarihini yakından tanımak için ideal bir yerdir.", "place_query": "Muş Müzesi, Merkez, Muş"}, {"title": "Kızıl Ziyaret Tepesi", "summary": "Şehre yakın bir konumda bulunan bu tepe, doğa yürüyüşleri ve piknik için popüler bir mekandır. Tepeden Muş Ovası''nın panoramik manzarasını izlemek mümkündür.", "place_query": "Kızıl Ziyaret Tepesi, Merkez, Muş"}, {"title": "Havuzbaşı Mesire Alanı", "summary": "Şehir merkezine yakın, yeşil alanları ve yapay göletiyle aileler için ideal bir dinlenme noktasıdır. Huzurlu atmosferi ve temiz havasıyla hafta sonu kaçamakları için tercih edilir.", "place_query": "Havuzbaşı Mesire Alanı, Merkez, Muş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e8fb536d-e628-463e-85c3-f8247ebbf126'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bingöl Dağı Milli Parkı", "summary": "Muş''un Varto ilçesi sınırları içinde yer alan bu milli park, eşsiz doğal güzellikleri, zengin flora ve faunası ile doğa yürüyüşü ve kampçılık için ideal bir noktadır. Özellikle yaz aylarında yemyeşil yaylaları ve buzul gölleriyle ziyaretçilerine huzur dolu bir deneyim sunar.", "place_query": "Bingöl Dağı Milli Parkı, Varto, Muş"}, {"title": "Varto Kayak Merkezi", "summary": "Kış turizmi için önemli bir merkez olan Varto Kayak Merkezi, doğal kar kalitesi ve uzun pistleriyle kayak tutkunlarının uğrak noktasıdır. Modern tesisleri ve eşsiz manzarasıyla hem acemi hem de profesyonel kayakçılara hitap eder.", "place_query": "Varto Kayak Merkezi, Varto, Muş"}, {"title": "Zernek Kalesi", "summary": "Varto ilçe merkezine yakın bir konumda bulunan Zernek Kalesi, tarihi dokusu ve etkileyici mimarisiyle dikkat çeker. Bölgenin stratejik noktalarından biri olan kale, ziyaretçilerine geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Zernek Kalesi, Varto, Muş"}, {"title": "Varto Şelalesi", "summary": "Doğal güzellikleriyle ünlü Varto Şelalesi, çevresindeki yeşil alanlar ve serin sularıyla piknik ve dinlenme için popüler bir mekandır. Özellikle yaz aylarında doğa severlerin uğrak noktası olan şelale, huzur verici atmosferiyle büyüler.", "place_query": "Varto Şelalesi, Varto, Muş"}, {"title": "Çöğürlü Yaylası", "summary": "Muş''un Varto ilçesinde yer alan Çöğürlü Yaylası, bakir doğası, temiz havası ve geniş otlaklarıyla ünlüdür. Yayla, geleneksel göçer kültürünü deneyimlemek ve doğayla baş başa kalmak isteyenler için mükemmel bir kaçış noktasıdır.", "place_query": "Çöğürlü Yaylası, Varto, Muş"}, {"title": "Karakaya Tepesi Seyir Noktası", "summary": "Varto''nun en yüksek noktalarından biri olan Karakaya Tepesi, muhteşem bir panoramik manzara sunar. Buradan ilçenin ve çevresindeki dağların kuşbakışı görüntüsünü izleyebilir, unutulmaz fotoğraflar çekebilirsiniz.", "place_query": "Karakaya Tepesi, Varto, Muş"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '82ee8754-5695-4a64-8d7e-6c12041a9237'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Acıgöl Krater Gölü", "summary": "Nevşehir''in Acıgöl ilçesinde bulunan bu krater gölü, volkanik bir patlama sonucu oluşmuştur. Doğal güzelliği ve sakin atmosferiyle doğa severler için ideal bir fotoğrafçılık ve piknik noktasıdır.", "place_query": "Acıgöl Krater Gölü, Acıgöl, Nevşehir"}, {"title": "Karadağ (Kara Dağ)", "summary": "Acıgöl sınırları içinde yer alan sönmüş bir volkan olan Karadağ, eşsiz manzaralar sunar. Tepesine çıkıldığında Kapadokya''nın geniş bir panoramasını görebilir, doğa yürüyüşleri yapabilirsiniz.", "place_query": "Karadağ, Acıgöl, Nevşehir"}, {"title": "Tatlarin Yeraltı Şehri", "summary": "Acıgöl ilçesine bağlı Tatlarin köyünde bulunan bu yeraltı şehri, Kapadokya''nın en büyük ve en etkileyici yer altı yerleşimlerinden biridir. Geniş odaları, şapeli ve havalandırma sistemleriyle tarihe tanıklık etmek isteyenler için harika bir duraktır.", "place_query": "Tatlarin Yeraltı Şehri, Acıgöl, Nevşehir"}, {"title": "Topada Yeraltı Şehri", "summary": "Acıgöl''ün Topada köyünde yer alan bu yeraltı şehri, daha az bilinen ama oldukça iyi korunmuş bir yapıdır. Ziyaretçilere Kapadokya''nın yer altı yaşamına dair otantik bir deneyim sunar.", "place_query": "Topada Yeraltı Şehri, Acıgöl, Nevşehir"}, {"title": "Acıgöl Müzesi", "summary": "Acıgöl ilçe merkezinde bulunan bu küçük ama zengin müze, bölgedeki arkeolojik kazılardan çıkarılan eserleri sergiler. Hitit, Roma ve Bizans dönemlerine ait buluntular, ziyaretçilere bölgenin derin tarihini keşfetme fırsatı verir.", "place_query": "Acıgöl Müzesi, Acıgöl, Nevşehir"}, {"title": "Kurugöl Mağarası", "summary": "Acıgöl yakınlarında bulunan bu doğal mağara, etkileyici sarkıt ve dikitleriyle dikkat çeker. Doğa sporları ve mağara keşfi meraklıları için gizli bir cennettir.", "place_query": "Kurugöl Mağarası, Acıgöl, Nevşehir"}, {"title": "Aşıklı Höyük", "summary": "Acıgöl ilçesi sınırları içinde yer alan bu höyük, Kapadokya''nın en eski yerleşimlerinden biridir. Neolitik döneme ait buluntuları ve açık hava müzesi atmosferiyle tarih öncesi yaşamı gözler önüne serer.", "place_query": "Aşıklı Höyük, Kızılkaya, Acıgöl, Nevşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '30452550-b6b7-4fb6-a8eb-2c579a50881c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Avanos Ören Yeri (Sarıhan Kervansarayı)", "summary": "13. yüzyıldan kalma bu tarihi Selçuklu kervansarayı, taş işçiliği ve avlusuyla büyüleyicidir. Günümüzde el sanatları atölyeleri ve sergilerine ev sahipliği yapmaktadır.", "place_query": "Sarıhan Kervansarayı, Avanos, Nevşehir"}, {"title": "Avanos Çömlek Atölyeleri", "summary": "Kızılırmak''ın kırmızı kilinden yapılan çömlekler, Avanos''un simgesidir. Yüzyıllardır süren bu gelenek, atölyelerde uygulamalı olarak izlenebilir.", "place_query": "Avanos çömlek atölyeleri, Nevşehir"}, {"title": "Güray Müze (Yeraltı Seramik Müzesi)", "summary": "Yer altına oyulmuş bu modern müze, seramik sanatının tarihini ve güncel örneklerini sergiler. Kapadokya''nın eşsiz atmosferinde bir kültür yolculuğu sunar.", "place_query": "Güray Müze, Avanos, Nevşehir"}, {"title": "Kızılırmak Nehri ve Kenar Yürüyüşü", "summary": "Kapadokya''nın can damarı olan Kızılırmak, Avanos''tan geçerken huzurlu bir yürüyüş ve piknik alanı sunar. Nehir kenarındaki kafelerde dinlenmek de mümkündür.", "place_query": "Kızılırmak Nehri, Avanos, Nevşehir"}, {"title": "Avanos Asma Köprü", "summary": "Kızılırmak üzerindeki bu tarihi asma köprü, hem ulaşım hem de fotoğrafçılık için popüler bir noktadır. Nehrin iki yakasını birbirine bağlayan köprüden manzara muhteşemdir.", "place_query": "Avanos Asma Köprü, Nevşehir"}, {"title": "Zelve Açık Hava Müzesi", "summary": "Avanos''a 10 km mesafedeki bu antik yerleşim, kayalara oyulmuş kiliseleri ve yaşam alanlarıyla ünlüdür. Kapadokya''nın en etkileyici açık hava müzelerinden biridir.", "place_query": "Zelve Açık Hava Müzesi, Avanos, Nevşehir"}, {"title": "Paşabağları (Rahipler Vadisi)", "summary": "Peri bacalarının en ilginç örneklerini barındıran bu vadi, üç başlı mantar şeklindeki kaya oluşumlarıyla tanınır. Kısa bir yürüyüşle doğa harikasını keşfedebilirsiniz.", "place_query": "Paşabağları, Avanos, Nevşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9148432b-a11b-4910-b887-7449cbfdce15'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Derinkuyu Yeraltı Şehri", "summary": "Kapadokya''nın en büyük ve en derin yeraltı şehirlerinden biri olup, 8 kata kadar inen labirent gibi tünelleri, kiliseleri ve havalandırma bacalarıyla ziyaretçileri büyüler.", "place_query": "Derinkuyu Yeraltı Şehri, Derinkuyu, Nevşehir"}, {"title": "Saint Jean Kilisesi", "summary": "Rum Ortodoks cemaatinden kalma bu tarihi kilise, taş işçiliği ve fresk kalıntılarıyla Derinkuyu''nun kültürel mirasını yansıtır.", "place_query": "Saint Jean Kilisesi, Derinkuyu, Nevşehir"}, {"title": "Derinkuyu Yeraltı Şehri Müzesi", "summary": "Yeraltı şehri girişinde yer alan bu küçük müze, bölgenin jeolojik yapısı ve yer altı yaşamına dair eserler sergiler.", "place_query": "Derinkuyu Yeraltı Şehri Müzesi, Nevşehir"}, {"title": "Derinkuyu Göleti Mesire Alanı", "summary": "İlçe merkezine yakın bu gölet, piknik alanları ve yürüyüş yollarıyla doğayla iç içe sakin bir gün geçirmek isteyenler için idealdir.", "place_query": "Derinkuyu Göleti Mesire Alanı, Derinkuyu, Nevşehir"}, {"title": "Yazıhöyük (Antik Nora Şehri)", "summary": "Derinkuyu''ya bağlı Yazıhöyük köyünde yer alan antik Nora kenti, Roma ve Bizans dönemine ait kalıntıları ve mağara kiliseleriyle tarih meraklılarını cezbeder.", "place_query": "Yazıhöyük Antik Nora Şehri, Derinkuyu, Nevşehir"}, {"title": "Derinkuyu Evleri ve Taş Döşeli Sokaklar", "summary": "İlçe merkezinde bulunan geleneksel taş evler ve dar sokaklar, Kapadokya''nın otantik mimarisini yakından görmek için keyifli bir yürüyüş rotası sunar.", "place_query": "Derinkuyu Taş Evler, Derinkuyu, Nevşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bacd7ff8-5b7a-4138-8425-7eed3a3c79a8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gülşehir Açık Hava Müzesi", "summary": "Gülşehir ilçe merkezinde bulunan bu tarihi alan, kayalara oyulmuş kiliseleri ve freskleriyle ünlüdür. Bölgenin en önemli erken Hristiyanlık dönemi kalıntılarından birini görebilirsiniz.", "place_query": "Gülşehir Açık Hava Müzesi, Nevşehir"}, {"title": "Aziz Jean (St. Jean) Kilisesi", "summary": "Gülşehir ilçesindeki en bilinen kaya kiliselerinden biridir. İçerisindeki renkli freskler ve tarihi atmosferiyle ziyaretçileri etkiler.", "place_query": "Aziz Jean Kilisesi Gülşehir"}, {"title": "Gülşehir Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi bir kaledir. Çevredeki peribacaları ve şehir manzarasını izlemek için ideal bir noktadır.", "place_query": "Gülşehir Kalesi, Nevşehir"}, {"title": "Gülşehir Yeraltı Şehri", "summary": "Kapadokya''nın diğer yeraltı şehirlerine göre daha az bilinen ancak oldukça etkileyici olan bu yapı, geniş odaları ve tünelleriyle keşfedilmeyi bekliyor.", "place_query": "Gülşehir Yeraltı Şehri"}, {"title": "Açıksaray (Açık Saray)", "summary": "Gülşehir''in yakınında, kayaların oyulmasıyla oluşmuş geniş bir yerleşim alanıdır. Manastır, kilise ve yaşam alanlarının bir arada bulunduğu bu bölge, doğa yürüyüşleri için de uygundur.", "place_query": "Açıksaray Gülşehir"}, {"title": "Gülşehir Seyir Tepesi", "summary": "İlçe merkezine yakın bir konumda bulunan bu tepe, özellikle gün batımında muhteşem bir manzara sunar. Peribacaları ve vadilerin panoramik görüntüsü için uğranması gereken bir noktadır.", "place_query": "Gülşehir Seyir Tepesi"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ec4070e8-dd8e-471e-a531-30f88e471408'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hacıbektaş Veli Müzesi", "summary": "Hacı Bektaş Veli''nin türbesini ve dergahını barındıran bu müze, Alevi-Bektaşi kültürünün en önemli merkezlerinden biridir. Tarihi yapıları, bahçesi ve manevi atmosferiyle her yıl binlerce ziyaretçi çeker.", "place_query": "Hacıbektaş Veli Müzesi, Hacıbektaş, Nevşehir"}, {"title": "Hacıbektaş Atatürk Evi Müzesi", "summary": "Atatürk''ün 1919''da ziyaret ettiği ve bir gece konakladığı tarihi ev, bugün müze olarak hizmet vermektedir. O döneme ait eşyalar ve fotoğraflarla zenginleştirilmiş nostaljik bir mekandır.", "place_query": "Atatürk Evi Müzesi, Hacıbektaş, Nevşehir"}, {"title": "Hacıbektaş Kapalı Çarşısı", "summary": "Yöresel el sanatları, hediyelik eşyalar ve özellikle Hacıbektaş taşından yapılmış ürünlerin satıldığı bu çarşı, alışveriş yapmak için ideal bir yerdir. Ziyaretçiler burada yöreye özgü ürünleri bulabilir.", "place_query": "Hacıbektaş Kapalı Çarşısı, Hacıbektaş, Nevşehir"}, {"title": "Hacıbektaş Etnografya Müzesi", "summary": "Bektaşi kültürüne ait giysiler, mutfak eşyaları, el yazmaları ve dini objelerin sergilendiği bu müze, bölgenin somut olmayan kültürel mirasını yakından tanıma fırsatı sunar.", "place_query": "Hacıbektaş Etnografya Müzesi, Hacıbektaş, Nevşehir"}, {"title": "Cemevi ve Kültür Merkezi", "summary": "Modern mimarisiyle dikkat çeken bu yapı, hem ibadet hem de kültürel etkinliklere ev sahipliği yapar. Hacıbektaş''ın manevi atmosferini hissetmek isteyenler için önemli bir duraktır.", "place_query": "Hacıbektaş Cemevi, Hacıbektaş, Nevşehir"}, {"title": "Hacıbektaş Şehir Parkı ve Mesire Alanı", "summary": "Şehir merkezine yakın, yeşil alanları ve yürüyüş yollarıyla dinlenmek ve piknik yapmak için uygun bir mekandır. Özellikle bahar aylarında aileler tarafından tercih edilir.", "place_query": "Hacıbektaş Şehir Parkı, Hacıbektaş, Nevşehir"}, {"title": "Kızılırmak Vadisi (Hacıbektaş Bölümü)", "summary": "Hacıbektaş sınırları içinden geçen Kızılırmak''ın oluşturduğu vadi, doğal güzellikleri ve yürüyüş rotalarıyla doğaseverler için keşfedilmeyi bekleyen bir alandır. Kuş gözlemi için de elverişlidir.", "place_query": "Kızılırmak Vadisi Hacıbektaş, Nevşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fca93758-c5e0-44f4-9059-a5d3bf79e517'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kozaklı Kaplıcaları", "summary": "Nevşehir''in önemli termal turizm merkezlerinden biri olan Kozaklı Kaplıcaları, romatizma ve cilt hastalıklarına iyi gelen şifalı sularıyla ünlüdür. Bölgedeki birçok otel ve termal tesis, ziyaretçilere konforlu bir sağlık ve dinlenme imkanı sunar.", "place_query": "Kozaklı Kaplıcaları, Kozaklı, Nevşehir"}, {"title": "Kozaklı Termal Turizm Merkezi", "summary": "Kozaklı ilçe merkezinde bulunan bu merkez, modern termal otelleri ve havuzlarıyla dikkat çeker. Kış aylarında bile sıcak sularında yüzebileceğiniz bu tesisler, termal turizmin kalbinin attığı yerdir.", "place_query": "Kozaklı Termal Turizm Merkezi, Kozaklı, Nevşehir"}, {"title": "Kozaklı Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, özellikle yaz akşamlarında ailelerin ve çocukların uğrak noktasıdır. Yeşil alanları, yürüyüş yolları ve dinlenme banklarıyla huzurlu bir mola vermek için idealdir.", "place_query": "Kozaklı Belediye Parkı, Kozaklı, Nevşehir"}, {"title": "Kozaklı Şelalesi", "summary": "İlçe merkezine yaklaşık 10 kilometre uzaklıkta bulunan bu doğal şelale, piknik ve doğa yürüyüşü sevenler için popüler bir duraktır. Çevresindeki yeşil alanlar ve serin suları, özellikle bahar aylarında görülmeye değerdir.", "place_query": "Kozaklı Şelalesi, Kozaklı, Nevşehir"}, {"title": "Kozaklı Taşköprü", "summary": "Tarihi bir Roma dönemi köprüsü olan Taşköprü, ilçenin simge yapılarından biridir. Günümüzde hala ayakta olan bu yapı, fotoğrafçılar ve tarih meraklıları için ilgi çekici bir duraktır.", "place_query": "Kozaklı Taşköprü, Kozaklı, Nevşehir"}, {"title": "Kozaklı Etnografya Müzesi", "summary": "İlçe merkezinde bulunan bu küçük müze, Kozaklı ve çevresinin geleneksel yaşamını yansıtan etnografik eserleri sergiler. Ziyaretçiler, yöresel kıyafetler, mutfak eşyaları ve el sanatları ürünlerini yakından görebilir.", "place_query": "Kozaklı Etnografya Müzesi, Kozaklı, Nevşehir"}, {"title": "Kozaklı Yeraltı Şehri", "summary": "Kapadokya bölgesinin karakteristik yapılarından biri olan bu yeraltı şehri, ilçe merkezine birkaç kilometre uzaklıktadır. Tarih boyunca sığınak olarak kullanılan bu labirent benzeri yapı, keşfedilmeyi bekleyen bir tarih hazinesidir.", "place_query": "Kozaklı Yeraltı Şehri, Kozaklı, Nevşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ba386b73-a5bd-4a2b-a6e8-2520d816ba9f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göreme Açık Hava Müzesi", "summary": "Kapadokya''nın en önemli kaya kiliseleri ve şapellerini barındıran bu UNESCO Dünya Mirası alanı, benzersiz freskleri ve tarihi dokusuyla ziyaretçilerini büyüler.", "place_query": "Göreme Açık Hava Müzesi, Nevşehir Merkez"}, {"title": "Uçhisar Kalesi", "summary": "Bölgenin en yüksek noktasındaki bu doğal kaya kalesi, tepeden Kapadokya''nın eşsiz manzarasını sunar ve içindeki tünellerle keşfedilmeyi bekler.", "place_query": "Uçhisar Kalesi, Nevşehir Merkez"}, {"title": "Paşabağları (Rahipler Vadisi)", "summary": "Peri bacalarının en yoğun ve etkileyici örneklerinin bulunduğu bu vadi, üç başlı mantar formundaki kaya oluşumlarıyla ünlüdür.", "place_query": "Paşabağları, Nevşehir Merkez"}, {"title": "Avanos Çömlek Atölyeleri", "summary": "Kızılırmak''ın kıyısındaki bu tarihi ilçede, yüzyıllardır süregelen çömlekçilik geleneğini yerinde izleyebilir ve kendi seramiğinizi yapmayı deneyebilirsiniz.", "place_query": "Avanos Çömlek Atölyeleri, Nevşehir Merkez"}, {"title": "Derinkuyu Yeraltı Şehri", "summary": "Sekiz katlı bu devasa yeraltı şehri, binlerce insanı barındıracak şekilde oyulmuş odaları, kiliseleri ve havalandırma sistemleriyle hayranlık uyandırır.", "place_query": "Derinkuyu Yeraltı Şehri, Nevşehir"}, {"title": "Zelve Açık Hava Müzesi", "summary": "Terk edilmiş bir yerleşim olan Zelve, kayalara oyulmuş evleri, kiliseleri ve vadileriyle Kapadokya''nın en otantik ve etkileyici açık hava müzelerinden biridir.", "place_query": "Zelve Açık Hava Müzesi, Nevşehir Merkez"}, {"title": "Güvercinlik Vadisi", "summary": "Adını kayalara oyulmuş yüzlerce güvercin yuvasından alan bu vadi, doğa yürüyüşleri için ideal olup özellikle gün batımında büyüleyici bir manzara sunar.", "place_query": "Güvercinlik Vadisi, Nevşehir Merkez"}, {"title": "Nevşehir Kalesi", "summary": "Şehir merkezinde yükselen bu tarihi kale, içindeki mağaralar ve dar sokaklarıyla keşfedilmeyi beklerken tepeden Nevşehir''in panoramik manzarasını izleme fırsatı verir.", "place_query": "Nevşehir Kalesi, Nevşehir Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1e60eaaa-f823-47ed-aee1-e849e4fec42b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Göreme Açık Hava Müzesi", "summary": "Kapadokya''nın en önemli manastır yaşamı merkezlerinden biri olan bu UNESCO Dünya Mirası alanında, 10. ve 12. yüzyıllara ait kaya kiliselerini ve eşsiz freskleri görebilirsiniz.", "place_query": "Göreme Açık Hava Müzesi, Göreme, Nevşehir"}, {"title": "Ürgüp Üç Güzeller Tepesi", "summary": "Kapadokya''nın simgesi haline gelmiş üç peribacasını seyretmek için en ideal noktalardan biridir. Özellikle gün batımında muhteşem bir manzara sunar.", "place_query": "Üç Güzeller, Ürgüp, Nevşehir"}, {"title": "Temenni Tepesi", "summary": "Ürgüp''ün panoramik manzarasını izleyebileceğiniz bu tepede, dilek ağacına bez bağlayarak dilek dileyebilir ve şehri kuşbakışı görebilirsiniz.", "place_query": "Temenni Tepesi, Ürgüp, Nevşehir"}, {"title": "Mazı Yeraltı Şehri", "summary": "Ürgüp''e bağlı Kayakapı Mahallesi''nde yer alan bu yeraltı şehri, 4 katlı olup erken Hristiyanlık döneminde sığınak olarak kullanılmıştır. Dar tünelleri ve yaşam alanlarıyla etkileyicidir.", "place_query": "Mazı Yeraltı Şehri, Ürgüp, Nevşehir"}, {"title": "Taşkın Paşa Camii ve Külliyesi", "summary": "Dulkadiroğulları döneminden kalma bu tarihi cami ve medrese, Ürgüp''ün en önemli Selçuklu ve Osmanlı eserlerindendir. Taş işçiliği ve avlusu dikkat çekicidir.", "place_query": "Taşkınpaşa Camii, Ürgüp, Nevşehir"}, {"title": "Cemil Köyü", "summary": "Ürgüp''e bağlı bu geleneksel Kapadokya köyü, taş evleri, dar sokakları ve şarap evleriyle bilinir. Doğal yapısını korumuş olan köy, huzurlu bir atmosfer sunar.", "place_query": "Cemil Köyü, Ürgüp, Nevşehir"}, {"title": "Mustafapaşa (Sinasos)", "summary": "Rum mimarisinin en güzel örneklerini barındıran bu tarihi mahalle, taş işlemeli konakları ve kiliseleriyle ünlüdür. Özellikle Afet Küçük Kilisesi görülmeye değerdir.", "place_query": "Mustafapaşa, Ürgüp, Nevşehir"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5ed99519-4632-4ec1-9b2b-359887d2f9f6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Altunhisar Kalesi", "summary": "Tarihi bir kaya kütlesi üzerine inşa edilmiş olan bu kale, bölgeye hakim bir tepede yer alır ve çevresine eşsiz bir manzara sunar. Özellikle gün batımında fotoğrafçılar için vazgeçilmez bir noktadır.", "place_query": "Altunhisar Kalesi, Altunhisar, Niğde"}, {"title": "Gümüşler Manastırı", "summary": "Altunhisar sınırları içinde yer alan bu tarihi manastır, kayaya oyulmuş yapısı ve etkileyici freskleriyle dikkat çeker. Bölgenin en önemli kültürel miraslarından biridir.", "place_query": "Gümüşler Manastırı, Altunhisar, Niğde"}, {"title": "Altunhisar Göleti", "summary": "Doğa ile iç içe bir piknik ve dinlenme alanı olan bu gölet, özellikle yaz aylarında serinlemek ve huzurlu bir gün geçirmek isteyenler tarafından sıkça tercih edilir. Çevresindeki yeşil alanlar yürüyüş için idealdir.", "place_query": "Altunhisar Göleti, Altunhisar, Niğde"}, {"title": "Ulukışla-Altunhisar Karayolu Seyir Terası", "summary": "Yol üzerinde bulunan bu seyir noktası, Melendiz Dağları ve çevresindeki vadilerin panoramik manzarasını sunar. Özellikle doğa fotoğrafçıları ve yolculuk yapanlar için mola vermeye değer bir yerdir.", "place_query": "Ulukışla Altunhisar yolu seyir terası, Niğde"}, {"title": "Kızıltepe Yaylası", "summary": "Yüksek rakımı ve temiz havasıyla ünlü olan bu yayla, doğa yürüyüşleri ve kampçılık için uygun bir ortam sağlar. Yaz aylarında serin bir kaçış noktası arayanların uğrak yeridir.", "place_query": "Kızıltepe Yaylası, Altunhisar, Niğde"}, {"title": "Altunhisar Eski Camii", "summary": "Osmanlı döneminden kalma bu tarihi cami, sade mimarisi ve taş işçiliğiyle ilçenin kültürel dokusunu yansıtır. İlçe merkezinde kolayca ziyaret edilebilir.", "place_query": "Altunhisar Eski Camii, Altunhisar, Niğde"}, {"title": "Hasandere Şelalesi", "summary": "Altunhisar''a bağlı bir bölgede yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla ziyaretçilerine huzurlu bir ortam sunar. Özellikle ilkbahar ve yaz aylarında su akışı artar.", "place_query": "Hasandere Şelalesi, Altunhisar, Niğde"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4f0850ef-6a1b-4af0-8631-c604a5699aed'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aladağlar Milli Parkı", "summary": "Türkiye''nin en önemli dağcılık ve trekking rotalarından biridir. Eşsiz doğal güzellikleri, derin vadileri ve yüksek zirveleriyle doğa tutkunlarının vazgeçilmez adresidir.", "place_query": "Aladağlar Milli Parkı, Niğde"}, {"title": "Gümüşler Manastırı", "summary": "Niğde''ye bağlı Gümüşler beldesinde yer alan bu tarihi manastır, kayaya oyulmuş yapısı ve etkileyici freskleriyle ünlüdür. Özellikle ''Gülen Meryem Ana'' freski dikkat çeker.", "place_query": "Gümüşler Manastırı, Niğde"}, {"title": "Niğde Kalesi", "summary": "Şehir merkezinde yer alan bu tarihi kale, Roma ve Selçuklu dönemlerinden izler taşır. Tepeye konumlanmış olması sayesinde Niğde manzarasını kuşbakışı izleme imkanı sunar.", "place_query": "Niğde Kalesi, Niğde Merkez"}, {"title": "Köşk Höyük (Köşk Müzesi)", "summary": "Bor ilçesi yakınlarında bulunan bu açık hava müzesi, Neolitik döneme ait kalıntıları ve canlandırmalarıyla tarih öncesi yaşama ışık tutar. Bölgenin en önemli arkeolojik alanlarındandır.", "place_query": "Köşk Höyük, Bor, Niğde"}, {"title": "Eski Gümüşler (Gümüşler Kasabası)", "summary": "Tarihi taş evleri ve dar sokaklarıyla ünlü bu şirin kasaba, özellikle Gümüşler Manastırı''nın hemen yanında yer alır. Geleneksel Niğde mimarisini görmek için idealdir.", "place_query": "Gümüşler Kasabası, Niğde"}, {"title": "Niğde Müzesi", "summary": "Hitit, Roma, Bizans ve Selçuklu dönemlerine ait zengin bir eser koleksiyonuna sahiptir. Bölgenin tarihini ve kültürel mirasını yakından tanımak isteyenler için mutlaka görülmesi gereken bir noktadır.", "place_query": "Niğde Müzesi, Niğde Merkez"}, {"title": "Andaval (Akkilise) Ören Yeri", "summary": "Bor ilçesi yakınlarındaki bu antik yerleşim, özellikle erken Hristiyanlık dönemine ait bir bazilika kalıntısıyla bilinir. Tarihi dokusu ve sakin atmosferiyle keşfedilmeyi bekleyen bir ören yeridir.", "place_query": "Andaval Ören Yeri, Bor, Niğde"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd5542a9b-72c4-4963-9916-f7e1c7f33650'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aladağlar Milli Parkı", "summary": "Türkiye''nin en önemli dağcılık ve doğa yürüyüşü merkezlerinden biridir. Binlerce metre yüksekliğindeki zirveler, buzul gölleri ve eşsiz vadileriyle doğa tutkunlarını kendine çeker.", "place_query": "Aladağlar Milli Parkı, Çamardı, Niğde"}, {"title": "Demirkazık Zirvesi", "summary": "Aladağlar''ın en yüksek ve en sembolik zirvesidir. Profesyonel dağcılar için popüler bir tırmanış rotası olup, muhteşem manzarasıyla ünlüdür.", "place_query": "Demirkazık Zirvesi, Çamardı, Niğde"}, {"title": "Çamardı Yedi Göller", "summary": "Aladağlar''ın içinde, buzul sularıyla beslenen yedi ayrı gölden oluşan doğal bir güzelliktir. Doğa yürüyüşü ve kamp için ideal bir bölgedir.", "place_query": "Yedi Göller, Çamardı, Niğde"}, {"title": "Emli Vadisi", "summary": "Aladağlar''ın en popüler yürüyüş rotalarından biridir. Vadideki şelaleler, doğal havuzlar ve yemyeşil bitki örtüsü ziyaretçilere huzur verir.", "place_query": "Emli Vadisi, Çamardı, Niğde"}, {"title": "Çamardı İlçe Merkezi ve Tarihi Evler", "summary": "İlçe merkezinde, geleneksel Niğde mimarisini yansıtan tarihi taş evler ve sokaklar bulunur. Yöresel lezzetleri tatmak ve kültürel bir gezi yapmak için uğranabilir.", "place_query": "Çamardı Merkez, Niğde"}, {"title": "Küçükgöl (Sekli Gölü)", "summary": "Aladağlar''ın yüksek kesimlerinde yer alan, sakin ve berrak sularıyla bilinen bir buzul gölüdür. Trekking rotalarının önemli bir durağıdır.", "place_query": "Küçükgöl, Çamardı, Niğde"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e5c4d036-600f-4dba-b95a-bd2641e4f5b0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çiftehan Kaplıcaları", "summary": "Niğde Çiftlik ilçesinde yer alan bu doğal kaplıca, şifalı termal suları ve tarihi Roma dönemine uzanan geçmişiyle ünlüdür. Ziyaretçiler hem doğal güzellikler içinde dinlenebilir hem de termal suyun sağlık veren etkilerinden faydalanabilir.", "place_query": "Çiftehan Kaplıcaları, Çiftlik, Niğde"}, {"title": "Karanlıkdere Şelalesi", "summary": "Çiftlik ilçesi sınırları içinde yer alan Karanlıkdere Şelalesi, yemyeşil doğası ve serin sularıyla doğa yürüyüşü ve piknik için ideal bir noktadır. Özellikle bahar ve yaz aylarında ziyaretçilerine huzurlu bir atmosfer sunar.", "place_query": "Karanlıkdere Şelalesi, Çiftlik, Niğde"}, {"title": "Andaval (Aktaş) Antik Kenti", "summary": "Çiftlik ilçesine bağlı Aktaş köyünde bulunan Andaval Antik Kenti, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklılarının ilgisini çeker. Bölgedeki en önemli arkeolojik alanlardan biridir.", "place_query": "Andaval Antik Kenti, Aktaş, Çiftlik, Niğde"}, {"title": "Melendiz Dağı", "summary": "Çiftlik ilçesinin doğusunda yükselen Melendiz Dağı, doğa yürüyüşleri, kamp ve dağcılık için popüler bir rotadır. Zirvesinden Niğde Ovası ve çevre dağların muhteşem manzarası izlenebilir.", "place_query": "Melendiz Dağı, Çiftlik, Niğde"}, {"title": "Gümüşler Manastırı (Gümüşler Köyü)", "summary": "Çiftlik ilçesine bağlı Gümüşler köyünde yer alan bu tarihi manastır, kayaya oyulmuş yapısı ve freskleriyle dikkat çeker. Bölgenin önemli kültürel miraslarından biridir ve huzurlu bir ziyaret sunar.", "place_query": "Gümüşler Manastırı, Gümüşler, Çiftlik, Niğde"}, {"title": "Çiftlik İlçe Merkezi ve Yöresel Pazarlar", "summary": "Çiftlik ilçe merkezi, yöresel ürünlerin satıldığı pazarları ve samimi atmosferiyle ziyaretçilere otantik bir deneyim sunar. Özellikle el yapımı halı, kilim ve yöresel yiyecekler ilgi çekicidir.", "place_query": "Çiftlik Merkez, Niğde"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '89c8e94c-fc5d-4641-ba0c-efcba9781e98'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Niğde Kalesi", "summary": "Şehir merkezinde yüksek bir tepe üzerinde yer alan tarihi kale, Roma, Bizans ve Selçuklu dönemlerine ait izler taşır. Kaleyi çevreleyen surlar ve iç kısımdaki yapılar, ziyaretçilere eşsiz bir şehir manzarası sunar.", "place_query": "Niğde Kalesi, Niğde Merkez"}, {"title": "Alaeddin Camii", "summary": "Anadolu Selçuklu döneminin en önemli eserlerinden biri olan bu cami, 1223 yılında I. Alaeddin Keykubad tarafından yaptırılmıştır. Taş işçiliği ve mimari detaylarıyla dikkat çeken yapı, Niğde''nin simgelerindendir.", "place_query": "Alaeddin Camii, Niğde Merkez"}, {"title": "Niğde Müzesi", "summary": "Bölgedeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği müze, Hitit, Roma, Bizans ve Osmanlı dönemlerine ait zengin bir koleksiyona sahiptir. Tarih meraklıları için kaçırılmayacak bir duraktır.", "place_query": "Niğde Müzesi, Niğde Merkez"}, {"title": "Gümüşler Manastırı", "summary": "Niğde''ye 9 km uzaklıktaki Gümüşler beldesinde yer alan bu kaya manastırı, Bizans dönemine ait freskleri ve mimarisiyle ünlüdür. Kapadokya benzeri yeraltı şehri ve kiliseleriyle ziyaretçileri büyüler.", "place_query": "Gümüşler Manastırı, Niğde"}, {"title": "Hüdavend Hatun Türbesi", "summary": "Selçuklu dönemine ait bu türbe, 1312 yılında inşa edilmiş olup taş oymacılığının en güzel örneklerindendir. İnce işçilik ve geometrik desenleriyle dikkat çeker.", "place_query": "Hüdavend Hatun Türbesi, Niğde Merkez"}, {"title": "Aktaş Gölü (Çöl Gölü)", "summary": "Niğde merkeze yaklaşık 15 km uzaklıkta bulunan bu doğal göl, özellikle kuş gözlemciliği ve doğa yürüyüşleri için idealdir. Çevresi yeşil alanlarla kaplı olup huzurlu bir kaçış noktasıdır.", "place_query": "Aktaş Gölü, Niğde"}, {"title": "Sungurbey Camii ve Külliyesi", "summary": "14. yüzyılda inşa edilen bu külliye, cami, medrese ve türbeden oluşmaktadır. Selçuklu taş işçiliğinin izlerini taşıyan yapı, tarihi atmosferiyle ziyaretçileri etkiler.", "place_query": "Sungurbey Camii, Niğde Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '36d23d33-4c08-4680-8bb6-ec58e6898995'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çiftehan Kaplıcaları", "summary": "Tarihi İpek Yolu üzerinde yer alan bu doğal kaplıcalar, romatizma ve cilt hastalıklarına iyi gelen termal sularıyla ünlüdür. Doğa içinde şifa bulmak isteyenler için ideal bir duraktır.", "place_query": "Çiftehan Kaplıcaları, Ulukışla, Niğde"}, {"title": "Ulukışla İlçe Merkezi ve Tarihi Evler", "summary": "İlçe merkezinde Osmanlı döneminden kalma tarihi taş evler ve dar sokaklar, ziyaretçilere geçmişe yolculuk yapma fırsatı sunar. Özellikle fotoğraf tutkunları için güzel kareler vaat eder.", "place_query": "Ulukışla Merkez, Niğde"}, {"title": "Aladağlar Milli Parkı (Ulukışla Girişi)", "summary": "Türkiye''nin en önemli dağcılık ve trekking rotalarından biri olan Aladağlar, Ulukışla sınırlarından da ulaşılabilir. Eşsiz kaya oluşumları, buzul gölleri ve zengin bitki örtüsüyle doğaseverleri büyüler.", "place_query": "Aladağlar Milli Parkı Ulukışla Girişi, Niğde"}, {"title": "Gümüşköy Kaplıcaları", "summary": "Çiftehan''a yakın konumdaki bu şifalı su kaynağı, sakin ve huzurlu atmosferiyle bilinir. Termal turizm açısından bölgenin önemli duraklarından biridir.", "place_query": "Gümüşköy Kaplıcaları, Ulukışla, Niğde"}, {"title": "Pozantı-Ulukışla Tarihi Kervan Yolu", "summary": "Tarihi İpek Yolu''nun bir parçası olan bu antik yol, bölgenin ticaret ve kültür tarihine ışık tutar. Doğa yürüyüşü yaparken tarihi izleri keşfetmek mümkündür.", "place_query": "Tarihi Kervan Yolu Ulukışla, Niğde"}, {"title": "Bolkar Dağları", "summary": "Ulukışla sınırlarında yükselen Bolkar Dağları, zengin flora ve faunası, yaylaları ve trekking rotalarıyla doğa sporcuları için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Bolkar Dağları Ulukışla, Niğde"}, {"title": "Ulukışla Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu pazar, bölgenin kültürel dokusunu yakından tanımak isteyenler için canlı bir durak noktasıdır.", "place_query": "Ulukışla Kapalı Pazar Yeri, Niğde"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9b54fd60-651e-4387-8ad8-65f01d0826e0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akkuş Yaylaları (Topçam Yaylası)", "summary": "Ordu''nun en yüksek ve serin yaylalarından biri olan Topçam Yaylası, muhteşem doğa manzarası, temiz havası ve geleneksel yayla evleriyle ünlüdür. Ziyaretçiler burada yürüyüş yapabilir, yöresel lezzetler tadabilir ve doğayla baş başa vakit geçirebilir.", "place_query": "Topçam Yaylası, Akkuş, Ordu"}, {"title": "Akkuş Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, yeşillikler arasından dökülen suları ve çevresindeki piknik alanıyla doğaseverler için ideal bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek ve doğal güzellikleri izlemek için sıkça ziyaret edilir.", "place_query": "Akkuş Şelalesi, Akkuş, Ordu"}, {"title": "Kalebaşı Tepesi", "summary": "Akkuş''un en yüksek noktalarından biri olan Kalebaşı Tepesi, kuşbakışı ilçe manzarası ve çevredeki dağların eşsiz görüntüsünü sunar. Gün doğumu ve gün batımı fotoğrafları çekmek isteyenler için popüler bir seyir noktasıdır.", "place_query": "Kalebaşı Tepesi, Akkuş, Ordu"}, {"title": "Akkuş Merkez Camii ve Tarihi Çevresi", "summary": "İlçe merkezinde yer alan bu cami, Osmanlı dönemi mimarisinin izlerini taşıyan sade ve huzurlu bir yapıdır. Çevresindeki tarihi çeşme ve eski taş evlerle birlikte kısa bir kültür turu yapılabilir.", "place_query": "Akkuş Merkez Camii, Akkuş, Ordu"}, {"title": "Gölköy Yaylası (Akkuş sınırı)", "summary": "Akkuş sınırlarına yakın olan bu yayla, geniş çayırları ve çam ormanlarıyla ünlüdür. Doğa yürüyüşleri ve kampçılık için elverişli olan bölge, özellikle yaz aylarında yerli turistlerin uğrak noktasıdır.", "place_query": "Gölköy Yaylası, Akkuş, Ordu"}, {"title": "Akkuş Göleti", "summary": "İlçe merkezine kısa bir mesafede bulunan bu yapay gölet, piknik alanları ve yürüyüş yollarıyla aileler için sakin bir gün geçirme imkanı sunar. Gölet çevresinde balık tutma ve doğa fotoğrafçılığı da yapılabilir.", "place_query": "Akkuş Göleti, Akkuş, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9890ede4-339b-4e0c-b276-da6e42188004'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Boztepe", "summary": "Ordu''nun simgesi haline gelmiş bu tepeden şehir ve deniz manzarası izlenir. Teleferikle ulaşım sağlanır, kafelerde çay içip gün batımını seyretmek popülerdir.", "place_query": "Boztepe, Altınordu, Ordu"}, {"title": "Yason Burnu", "summary": "Karadeniz''in en güzel burunlarından biri olan Yason''da tarihi deniz feneri ve eşsiz doğa manzarası bulunur. Özellikle gün doğumu ve batımında fotoğrafçıların uğrak noktasıdır.", "place_query": "Yason Burnu, Ordu"}, {"title": "Ordu Saat Kulesi", "summary": "Şehir merkezinde yer alan bu tarihi kule, Ordu''nun sembol yapılarından biridir. Çevresindeki park ve kafelerle birlikte keyifli bir gezinti alanı sunar.", "place_query": "Ordu Saat Kulesi, Altınordu"}, {"title": "Paşaoğlu Konağı ve Etnografya Müzesi", "summary": "19. yüzyıldan kalma bu geleneksel Karadeniz konağı, günümüzde etnografya müzesi olarak hizmet vermektedir. Yöresel kıyafetler, mutfak eşyaları ve tarihi objeler sergilenir.", "place_query": "Paşaoğlu Konağı Etnografya Müzesi, Altınordu, Ordu"}, {"title": "Cumhuriyet Meydanı", "summary": "Altınordu''nun en işlek noktalarından biri olan meydan, çevresindeki mağazalar, kafeler ve tarihi binalarla şehir hayatının kalbini oluşturur.", "place_query": "Cumhuriyet Meydanı, Altınordu, Ordu"}, {"title": "Ulugöl Tabiat Parkı", "summary": "Ordu''ya yaklaşık 20 km mesafedeki bu doğal göl ve çevresi, piknik ve yürüyüş için ideal bir alandır. Çam ormanları arasında huzurlu bir kaçamak sunar.", "place_query": "Ulugöl Tabiat Parkı, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '286825e7-d91e-42ab-a275-8b95a91917c5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aybastı Perşembe Yaylası", "summary": "Doğal güzelliği ve serin havasıyla ünlü bu yayla, özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır. Geniş çayırları, yürüyüş rotaları ve geleneksel yayla evleriyle huzurlu bir kaçamak sunar.", "place_query": "Perşembe Yaylası, Aybastı, Ordu"}, {"title": "Kurul Kalesi (Ordu)", "summary": "Aybastı ilçe merkezine yaklaşık 30 km uzaklıkta bulunan bu antik kale, eşsiz manzarası ve tarihi kalıntılarıyla dikkat çeker. Bölgenin en önemli arkeolojik alanlarından biridir.", "place_query": "Kurul Kalesi, Ordu"}, {"title": "Aybastı Şelalesi", "summary": "İlçe merkezine kısa bir mesafede yer alan bu şelale, doğa yürüyüşü ve piknik için idealdir. Çevresindeki yeşil örtü ve serin sularıyla doğaseverlerin favori mekanlarındandır.", "place_query": "Aybastı Şelalesi, Ordu"}, {"title": "Gölköy-Ulubey Kanyonu", "summary": "Aybastı''ya yaklaşık 40 km uzaklıkta bulunan bu etkileyici kanyon, doğa yürüyüşleri ve fotoğrafçılık için popülerdir. Kanyon boyunca uzanan patikalar ve eşsiz kaya oluşumları ziyaretçileri büyüler.", "place_query": "Ulubey Kanyonu, Ordu"}, {"title": "Aybastı Yayla Evleri ve Kültürü", "summary": "Aybastı''nın geleneksel yayla kültürünü yansıtan bu evler, özellikle yaz aylarında yöresel yaşamı deneyimlemek isteyenler için idealdir. Yayla şenlikleri ve doğal ortamıyla unutulmaz bir deneyim sunar.", "place_query": "Aybastı Yayla Evleri, Ordu"}, {"title": "Aybastı Göleti", "summary": "İlçe merkezine yakın konumdaki bu yapay gölet, piknik alanları ve yürüyüş yollarıyla aileler için popüler bir dinlenme noktasıdır. Gölet çevresinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Aybastı Göleti, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c9065ace-d8f3-44f0-9312-eaef1232b2c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamaş Yaylası", "summary": "Ordu''nun yayla turizminin en güzel örneklerinden biri olan Çamaş Yaylası, yeşilin her tonunu barındıran doğası, temiz havası ve muhteşem manzarasıyla ziyaretçilerine huzur dolu bir deneyim sunar.", "place_query": "Çamaş Yaylası, Çamaş, Ordu"}, {"title": "Çamaş Şelalesi", "summary": "Sarp kayalıklardan dökülen serin suları ve çevresindeki yemyeşil bitki örtüsüyle doğa severler için ideal bir kaçış noktası olan Çamaş Şelalesi, bölgenin en popüler doğal güzelliklerindendir.", "place_query": "Çamaş Şelalesi, Çamaş, Ordu"}, {"title": "Çamaş Kalesi", "summary": "Tarihi geçmişiyle dikkat çeken Çamaş Kalesi, bölgeye hakim bir tepe üzerinde yer alır ve çevresindeki vadi manzarasıyla fotoğraf tutkunları için eşsiz kareler sunar.", "place_query": "Çamaş Kalesi, Çamaş, Ordu"}, {"title": "Karabük Yaylası", "summary": "Çamaş ilçe merkezine yakın konumuyla bilinen Karabük Yaylası, geniş çayırları ve doğal yürüyüş parkurlarıyla kampçılar ve doğa yürüyüşçüleri için popüler bir duraktır.", "place_query": "Karabük Yaylası, Çamaş, Ordu"}, {"title": "Çamaş Göleti", "summary": "Piknik alanları ve çevre düzenlemesiyle ailelerin uğrak noktası olan Çamaş Göleti, sakin atmosferi ve doğayla iç içe vakit geçirme imkanı sunar.", "place_query": "Çamaş Göleti, Çamaş, Ordu"}, {"title": "Çamaş Merkez Camii", "summary": "Osmanlı mimarisinin izlerini taşıyan tarihi Çamaş Merkez Camii, ilçenin en eski yapılarından biri olarak hem ibadet hem de kültürel ziyaret amaçlı ilgi görmektedir.", "place_query": "Çamaş Merkez Camii, Çamaş, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dee18609-e2eb-4a24-8ea0-01d6ab59089f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çatalpınar Yaylası", "summary": "Ordu''nun en güzel yaylalarından biri olan Çatalpınar Yaylası, yeşilin her tonunu barındıran doğası, temiz havası ve muhteşem manzarasıyla doğa yürüyüşü ve piknik için ideal bir noktadır.", "place_query": "Çatalpınar Yaylası, Çatalpınar, Ordu"}, {"title": "Gaga Gölü", "summary": "Çatalpınar sınırları içinde yer alan Gaga Gölü, etrafı yemyeşil ormanlarla çevrili sakin bir doğa harikasıdır. Kuş gözlemi ve huzurlu bir kaçamak için popülerdir.", "place_query": "Gaga Gölü, Çatalpınar, Ordu"}, {"title": "Çatalpınar Merkez Camii", "summary": "İlçenin merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğini sergiler ve bölgenin kültürel mirasını yansıtır.", "place_query": "Çatalpınar Merkez Camii, Çatalpınar, Ordu"}, {"title": "Kestane Ormanları ve Piknik Alanları", "summary": "Çatalpınar, zengin kestane ormanlarıyla ünlüdür. Bu ormanlar içinde yer alan piknik alanları, özellikle sonbaharda doğayla iç içe vakit geçirmek isteyenler için harika bir seçenektir.", "place_query": "Çatalpınar kestane ormanı piknik alanı, Ordu"}, {"title": "Elma Çiçeği Vadisi", "summary": "İlkbaharda elma ağaçlarının çiçek açmasıyla beyaza bürünen bu vadi, eşsiz bir doğal manzara sunar ve fotoğrafçılar için popüler bir duraktır.", "place_query": "Elma Çiçeği Vadisi, Çatalpınar, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8c4a500d-404a-4677-a4c7-06c4449c6c5c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çaybaşı Yaylası", "summary": "Doğal güzellikleri ve temiz havasıyla ünlü olan yayla, özellikle yaz aylarında doğa yürüyüşleri ve piknik için ideal bir kaçış noktasıdır. Ziyaretçiler, yeşilin her tonunu görebilecekleri bu yaylada huzur dolu vakit geçirebilir.", "place_query": "Çaybaşı Yaylası, Çaybaşı, Ordu"}, {"title": "Çaybaşı Şelalesi", "summary": "Bölgenin gizli cennetlerinden biri olan şelale, etkileyici manzarası ve serin sularıyla doğaseverlerin uğrak noktasıdır. Şelalenin çevresinde yürüyüş yapabilir ve fotoğraf çekebilirsiniz.", "place_query": "Çaybaşı Şelalesi, Çaybaşı, Ordu"}, {"title": "Çaybaşı Merkez Camii", "summary": "İlçenin tarihi ve mimari açıdan önemli yapılarından biri olan cami, hem ibadet hem de kültürel bir ziyaret noktasıdır. Osmanlı dönemi izlerini taşıyan cami, sakin atmosferiyle dikkat çeker.", "place_query": "Çaybaşı Merkez Camii, Çaybaşı, Ordu"}, {"title": "Çaybaşı Göleti", "summary": "Yemyeşil doğa ile çevrili bu gölet, balık tutma ve piknik yapma imkanı sunar. Özellikle hafta sonları ailelerin tercih ettiği gölet, huzurlu bir gün geçirmek için idealdir.", "place_query": "Çaybaşı Göleti, Çaybaşı, Ordu"}, {"title": "Çaybaşı Kalesi", "summary": "Tarihi kalıntılarıyla dikkat çeken kale, ilçenin geçmişine ışık tutan önemli bir yapıdır. Tepe üzerinde yer alan kale, aynı zamanda çevreye hakim bir seyir noktası sunar.", "place_query": "Çaybaşı Kalesi, Çaybaşı, Ordu"}, {"title": "Çaybaşı Yayla Şenlikleri Alanı", "summary": "Her yıl düzenlenen yayla şenliklerine ev sahipliği yapan bu alan, yöresel kültürü ve eğlenceyi bir arada sunar. Ziyaretçiler, burada geleneksel etkinliklere katılabilir ve yöresel lezzetleri tadabilir.", "place_query": "Çaybaşı Yayla Şenlikleri, Çaybaşı, Ordu"}, {"title": "Çaybaşı Doğa Yürüyüşü Parkurları", "summary": "İlçenin zengin bitki örtüsü ve engebeli arazisi, doğa yürüyüşü meraklıları için çeşitli parkurlar sunar. Bu parkurlar, keşfedilmeyi bekleyen eşsiz manzaralar ve sessiz bir doğa deneyimi vaat eder.", "place_query": "Çaybaşı Doğa Yürüyüşü Parkurları, Çaybaşı, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '37d36cf3-1aeb-44b3-b172-0b87167844e5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yalıköy Plajı", "summary": "Fatsa''nın en popüler plajlarından biri olan Yalıköy, ince kumlu sahili ve berrak deniziyle yaz aylarında yüzme ve güneşlenmek için idealdir. Çevresindeki kafe ve restoranlar sayesinde ziyaretçilere keyifli bir gün geçirme imkanı sunar.", "place_query": "Yalıköy Plajı, Fatsa, Ordu"}, {"title": "Fatsa Kalesi", "summary": "Şehir merkezine hakim bir tepede yer alan tarihi Fatsa Kalesi, Pontus döneminden kalma kalıntıları ve muhteşem Karadeniz manzarasıyla görülmeye değerdir. Kaleye çıkarken çevredeki doğal güzellikleri de keşfedebilirsiniz.", "place_query": "Fatsa Kalesi, Fatsa, Ordu"}, {"title": "Bolaman Kalesi", "summary": "Fatsa''nın Bolaman Mahallesi''nde bulunan bu tarihi kale, deniz kıyısındaki konumu ve etkileyici mimarisiyle dikkat çeker. Özellikle gün batımında eşsiz bir manzara sunan kale, fotoğraf tutkunları için harika bir noktadır.", "place_query": "Bolaman Kalesi, Fatsa, Ordu"}, {"title": "Fatsa Sahil Bandı ve Yürüyüş Yolu", "summary": "Uzun sahil şeridi boyunca uzanan yürüyüş ve bisiklet yolu, deniz kenarında keyifli bir gezinti yapmak isteyenler için idealdir. Çevredeki parklar, kafeler ve dinlenme alanlarıyla aileler için popüler bir buluşma noktasıdır.", "place_query": "Fatsa Sahil Bandı, Fatsa, Ordu"}, {"title": "Fatsa Müzesi", "summary": "Bölgenin tarihine ışık tutan Fatsa Müzesi, arkeolojik eserler ve etnografik objelerle zengin bir koleksiyona sahiptir. Ziyaretçiler, Karadeniz''in kültürel mirasını yakından tanıma fırsatı bulur.", "place_query": "Fatsa Müzesi, Fatsa, Ordu"}, {"title": "Çağlayan Şelalesi", "summary": "Fatsa ilçe merkezine yaklaşık 20 kilometre uzaklıkta bulunan Çağlayan Şelalesi, yemyeşil doğanın içinde huzur verici bir kaçış noktasıdır. Özellikle bahar aylarında suyun debisinin artmasıyla görsel bir şölen sunar.", "place_query": "Çağlayan Şelalesi, Fatsa, Ordu"}, {"title": "Gaga Gölü", "summary": "Fatsa sınırları içinde yer alan Gaga Gölü, doğal güzelliği ve çevresindeki piknik alanlarıyla doğaseverlerin uğrak noktasıdır. Gölde kano yapabilir veya çevresinde yürüyüş yaparak stres atabilirsiniz.", "place_query": "Gaga Gölü, Fatsa, Ordu"}, {"title": "Evkaf Mahallesi Tarihi Evleri", "summary": "Fatsa''nın eski mahallelerinden Evkaf''ta bulunan tarihi ahşap evler, Karadeniz mimarisinin güzel örneklerini sergiler. Dar sokaklarda yapacağınız bir yürüyüş, sizi geçmişe götürecek nostaljik bir deneyim sunar.", "place_query": "Evkaf Mahallesi Tarihi Evler, Fatsa, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c38effc2-af9a-4a48-950b-a508350a540f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölköy Ulu Camii", "summary": "Tarihi bir Osmanlı eseri olan bu cami, ilçenin merkezinde yer alır ve mimarisiyle dikkat çeker.", "place_query": "Gölköy Ulu Camii, Gölköy, Ordu"}, {"title": "Harami Yaylası", "summary": "Doğal güzellikleri ve temiz havasıyla ünlü bu yayla, özellikle yaz aylarında doğa yürüyüşleri ve piknik için ideal bir kaçış noktasıdır.", "place_query": "Harami Yaylası, Gölköy, Ordu"}, {"title": "Gölköy Şelalesi", "summary": "Yeşillikler arasında gizlenmiş bu şelale, serinlemek ve doğayla iç içe vakit geçirmek isteyen ziyaretçiler için popüler bir duraktır.", "place_query": "Gölköy Şelalesi, Gölköy, Ordu"}, {"title": "Kale Mahallesi Kaya Mezarları", "summary": "Antik döneme ait bu kaya mezarları, bölgenin tarihine ışık tutan önemli arkeolojik kalıntılardandır.", "place_query": "Kale Mahallesi Kaya Mezarları, Gölköy, Ordu"}, {"title": "Gölköy Kalesi", "summary": "Tarihi bir kalenin kalıntıları olan bu alan, ilçeye hakim bir tepede yer alır ve çevresine muhteşem bir manzara sunar.", "place_query": "Gölköy Kalesi, Gölköy, Ordu"}, {"title": "Aybastı-Gölköy Yayla Yolu", "summary": "Bu güzergah, yemyeşil manzaralar eşliğinde yaylalar arasında keyifli bir sürüş deneyimi sunar ve fotoğrafçılar için eşsiz kareler vaat eder.", "place_query": "Aybastı-Gölköy Yayla Yolu, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2059624c-3b0c-49f5-a340-0fa29ec528b7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gülyalı Plajı", "summary": "Ordu''nun en popüler plajlarından biri olan Gülyalı Plajı, ince kumlu sahili ve temiz deniziyle yaz aylarında yoğun ilgi görür. Çevresindeki kafe ve restoranlarla keyifli bir gün geçirmek için idealdir.", "place_query": "Gülyalı Plajı, Ordu"}, {"title": "Gülyalı Sahil Parkı", "summary": "Deniz kenarında yürüyüş yapabileceğiniz, çocuk oyun alanları ve dinlenme banklarıyla donatılmış bu park, aileler için huzurlu bir kaçış noktasıdır. Özellikle gün batımında manzarası büyüleyicidir.", "place_query": "Gülyalı Sahil Parkı, Ordu"}, {"title": "Gülyalı Kalesi", "summary": "Tarihi bir Bizans kalesi olan Gülyalı Kalesi, denize hakim bir tepede konumlanmıştır. Kalıntıları ve çevresindeki doğal güzellik, tarih ve manzara meraklıları için keşfedilmeye değerdir.", "place_query": "Gülyalı Kalesi, Ordu"}, {"title": "Turnasuyu Şelalesi", "summary": "Gülyalı ilçe merkezine yaklaşık 10 km uzaklıkta bulunan Turnasuyu Şelalesi, yeşillikler içinde akan soğuk sularıyla piknik ve doğa yürüyüşü için popüler bir noktadır.", "place_query": "Turnasuyu Şelalesi, Gülyalı, Ordu"}, {"title": "Gülyalı Yaylası", "summary": "Ordu''nun serin yaylalarından biri olan Gülyalı Yaylası, yemyeşil çayırları ve temiz havasıyla doğaseverlerin uğrak yeridir. Yayla evlerinde konaklama imkanı da mevcuttur.", "place_query": "Gülyalı Yaylası, Ordu"}, {"title": "Gülyalı Sahil Yolu", "summary": "Karadeniz sahil şeridi boyunca uzanan bu yol, araçla veya yürüyerek keyifli bir gezi rotası sunar. Deniz manzarası eşliğinde bisiklet sürmek de oldukça popülerdir.", "place_query": "Gülyalı Sahil Yolu, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a90a9a04-8264-4ec7-95bd-33cb0dcff042'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gürgentepe Yaylası", "summary": "Ordu''nun en güzel yaylalarından biri olan Gürgentepe Yaylası, doğal güzellikleri, temiz havası ve yeşil örtüsüyle ziyaretçilerine huzurlu bir kaçış sunar. Yayla evleri ve piknik alanlarıyla özellikle yaz aylarında popülerdir.", "place_query": "Gürgentepe Yaylası, Gürgentepe, Ordu"}, {"title": "Karaağaç Şelalesi", "summary": "Gürgentepe sınırları içinde yer alan Karaağaç Şelalesi, etkileyici doğası ve serin sularıyla doğa severlerin uğrak noktasıdır. Çevresindeki yürüyüş parkurları ve piknik alanlarıyla keyifli bir gün geçirebilirsiniz.", "place_query": "Karaağaç Şelalesi, Gürgentepe, Ordu"}, {"title": "Gürgentepe Mağarası", "summary": "Bölgenin önemli doğal oluşumlarından biri olan Gürgentepe Mağarası, sarkıt ve dikitleriyle ilgi çeker. Mağara içindeki serin atmosfer ve doğal yapı, macera arayan ziyaretçiler için idealdir.", "place_query": "Gürgentepe Mağarası, Gürgentepe, Ordu"}, {"title": "Gürgentepe Kalesi", "summary": "Tarihi bir kalıntı olan Gürgentepe Kalesi, bölgenin geçmişine ışık tutar ve çevresindeki manzarasıyla fotoğrafçılar için güzel bir noktadır. Kale kalıntıları arasında yapacağınız gezinti, size farklı bir deneyim sunar.", "place_query": "Gürgentepe Kalesi, Gürgentepe, Ordu"}, {"title": "Gürgentepe Göleti", "summary": "Yapay bir gölet olan Gürgentepe Göleti, çevresindeki yeşil alanlar ve yürüyüş yollarıyla aileler için sakin bir kaçış noktasıdır. Gölet kenarında balık tutabilir veya piknik yapabilirsiniz.", "place_query": "Gürgentepe Göleti, Gürgentepe, Ordu"}, {"title": "Gürgentepe Merkez Camii", "summary": "Gürgentepe''nin merkezinde yer alan bu tarihi cami, mimarisi ve huzur veren atmosferiyle dikkat çeker. Bölge halkı için önemli bir ibadet ve buluşma noktasıdır.", "place_query": "Gürgentepe Merkez Camii, Gürgentepe, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '163c0fb9-d7c1-4634-8cff-6d69a3971f8a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İkizce Yaylaları (Kayabaşı Yaylası)", "summary": "Doğal güzelliği ve temiz havasıyla ünlü olan yayla, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler için popüler bir kaçış noktasıdır. Ziyaretçiler burada yemyeşil ormanlar ve geniş çayırlar arasında huzur bulabilir.", "place_query": "Kayabaşı Yaylası, İkizce, Ordu"}, {"title": "İkizce Şelalesi", "summary": "İlçe merkezine yakın konumda yer alan bu şelale, doğal bir havuz oluşturarak yaz aylarında serinlemek ve piknik yapmak için ideal bir ortam sunar. Çevresindeki yeşil alanlar fotoğrafçılar için de güzel kareler vaat eder.", "place_query": "İkizce Şelalesi, Ordu"}, {"title": "Çamaş Yaylası", "summary": "İkizce sınırları içinde bulunan bu yayla, zengin bitki örtüsü ve muhteşem manzarasıyla doğa severlerin uğrak noktasıdır. Yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Çamaş Yaylası, İkizce, Ordu"}, {"title": "İkizce Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde yer alan tarihi cami ve Osmanlı döneminden kalma çeşmeler, İkizce''nin kültürel mirasını yansıtan önemli yapılardır. Kısa bir şehir turunda görülmeye değerdir.", "place_query": "İkizce Merkez Camii, Ordu"}, {"title": "Kurtuluş Mahallesi Mesire Alanı", "summary": "Aileler için ideal olan bu mesire alanı, piknik masaları ve yeşil alanlarıyla hafta sonu kaçamakları için popüler bir mekandır. Çocuklar için oyun alanları da mevcuttur.", "place_query": "Kurtuluş Mahallesi Mesire Alanı, İkizce, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5761ba23-cd2c-4fcd-b68e-97e5b673a0d0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çambaşı Yaylası", "summary": "Ordu''nun en popüler yaylalarından biri olan Çambaşı, doğal güzelliği, temiz havası ve kış aylarında kayak merkezi olarak hizmet vermesiyle ünlüdür. Ziyaretçiler burada yayla evlerinde konaklayabilir, doğa yürüyüşleri yapabilir ve eşsiz manzaraların tadını çıkarabilir.", "place_query": "Çambaşı Yaylası, Kabadüz, Ordu"}, {"title": "Ohtamış Şelalesi", "summary": "Kabadüz ilçesinde yer alan Ohtamış Şelalesi, 30 metre yüksekliğinden dökülen suları ve çevresindeki yeşil doğasıyla görenleri büyüler. Şelale çevresinde piknik alanları ve yürüyüş parkurları bulunur.", "place_query": "Ohtamış Şelalesi, Kabadüz, Ordu"}, {"title": "Kabadüz Yaylası", "summary": "Kabadüz ilçe merkezine yakın konumdaki bu yayla, zengin bitki örtüsü ve serin havasıyla özellikle yaz aylarında yoğun ilgi görür. Yöresel ürünlerin satıldığı pazarı ve geleneksel yayla evleri ile dikkat çeker.", "place_query": "Kabadüz Yaylası, Kabadüz, Ordu"}, {"title": "Gaga Gölü", "summary": "Kabadüz sınırları içinde bulunan Gaga Gölü, doğal bir krater gölü olup etrafı çam ormanlarıyla çevrilidir. Sakin atmosferi ve kuş gözlemi için uygun ortamıyla doğa severlerin tercih ettiği bir noktadır.", "place_query": "Gaga Gölü, Kabadüz, Ordu"}, {"title": "Kabadüz Kayak Merkezi", "summary": "Çambaşı Yaylası''nda yer alan bu kayak merkezi, Karadeniz Bölgesi''nin önemli kış turizmi destinasyonlarından biridir. Kayak pistleri, telesiyej hattı ve konaklama tesisleri ile kış sporları tutkunlarına hizmet verir.", "place_query": "Çambaşı Kayak Merkezi, Kabadüz, Ordu"}, {"title": "Kabadüz Yürüyüş Parkurları", "summary": "Kabadüz ilçesi, doğa yürüyüşü için ideal birçok patikaya ev sahipliği yapar. Özellikle yaylalar arasındaki rotalar, ziyaretçilere yemyeşil ormanlar ve dereler eşliğinde unutulmaz bir deneyim sunar.", "place_query": "Kabadüz Doğa Yürüyüşü Parkurları, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8f951ddb-7c1b-40a4-ac9a-cb9d1eb1db9d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kabataş Yaylası", "summary": "Ordu''nun en güzel yaylalarından biri olan Kabataş Yaylası, yeşilin her tonunu görebileceğiniz, doğa yürüyüşleri ve piknik için ideal bir noktadır. Özellikle yaz aylarında serinlemek ve eşsiz manzaraların tadını çıkarmak için sıkça ziyaret edilir.", "place_query": "Kabataş Yaylası, Kabataş, Ordu"}, {"title": "Kabataş Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla ziyaretçilerine huzurlu bir ortam sunar. Şelalenin serin suları ve sesi, doğayla baş başa kalmak isteyenler için büyüleyici bir deneyim sağlar.", "place_query": "Kabataş Şelalesi, Kabataş, Ordu"}, {"title": "Yukarı Kızılen Yaylası", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü Yukarı Kızılen Yaylası, geleneksel yayla kültürünü deneyimlemek isteyenler için harika bir duraktır. Yöresel lezzetlerin tadılabileceği yayla evleri ve doğa yürüyüşü rotalarıyla dikkat çeker.", "place_query": "Yukarı Kızılen Yaylası, Kabataş, Ordu"}, {"title": "Kabataş Kalesi", "summary": "Tarihi bir kalıntı olan Kabataş Kalesi, bölgenin geçmişine ışık tutan önemli bir noktadır. Kale kalıntılarından çevredeki dağların ve vadilerin panoramik manzarasını izlemek mümkündür.", "place_query": "Kabataş Kalesi, Kabataş, Ordu"}, {"title": "Karşıyaka Mahallesi Mesire Alanı", "summary": "Aileler ve arkadaş grupları için piknik yapma imkanı sunan bu mesire alanı, ağaçlar altında dinlenmek ve doğayla iç içe vakit geçirmek için popüler bir yerdir. Çocuk oyun alanları ve yürüyüş yollarıyla donatılmıştır.", "place_query": "Karşıyaka Mahallesi Mesire Alanı, Kabataş, Ordu"}, {"title": "Kabataş Merkez Camii ve Çevresi", "summary": "İlçenin merkezinde yer alan bu tarihi cami, mimarisiyle dikkat çekerken çevresindeki küçük dükkanlar ve kafeler de ziyaretçilere keyifli anlar sunar. Bölgenin sosyal ve kültürel hayatını gözlemlemek için iyi bir noktadır.", "place_query": "Kabataş Merkez Camii, Kabataş, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '499eea4c-2701-44ea-8e03-1d6a240f0091'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Korgan Yaylaları (Çayırkent ve Çatalkaya Yaylası)", "summary": "Ordu''nun yayla turizminin önemli duraklarından olan Korgan yaylaları, yeşilin her tonunu barındıran doğası, temiz havası ve geleneksel yayla kültürüyle ziyaretçilerine huzurlu bir kaçış sunar. Özellikle yaz aylarında düzenlenen yayla şenlikleri ile ünlüdür.", "place_query": "Korgan Yaylaları, Korgan, Ordu"}, {"title": "Gölalan Yaylası", "summary": "Korgan''ın en bilinen ve en yüksek yaylalarından biri olan Gölalan, muhteşem manzarası, soğuk pınarları ve zengin bitki örtüsüyle doğa severlerin uğrak noktasıdır. Yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Gölalan Yaylası, Korgan, Ordu"}, {"title": "Korgan Şelaleleri", "summary": "İlçe sınırları içerisinde yer alan ve özellikle bahar aylarında coşan Korgan Şelaleleri, doğa yürüyüşleri ve piknik için ideal bir ortam oluşturur. Bölgenin saklı güzelliklerinden biridir.", "place_query": "Korgan Şelaleleri, Korgan, Ordu"}, {"title": "Korgan Kalesi", "summary": "Tarihi kalıntılarıyla dikkat çeken Korgan Kalesi, ilçe merkezine hakim bir tepede yer alır ve çevresine eşsiz bir panoramik manzara sunar. Tarih ve doğanın iç içe geçtiği bir noktadır.", "place_query": "Korgan Kalesi, Korgan, Ordu"}, {"title": "Dibekli Yaylası", "summary": "Korgan''ın doğal güzelliklerinden bir diğeri olan Dibekli Yaylası, yemyeşil çayırları, sakin atmosferi ve yöresel lezzetleri tatma fırsatı sunan yayla evleriyle bilinir.", "place_query": "Dibekli Yaylası, Korgan, Ordu"}, {"title": "Korgan İlçe Merkezi ve Tarihi Çarşı", "summary": "İlçe merkezindeki tarihi çarşı, yöresel el sanatları ürünleri ve organik köy ürünlerini bulabileceğiniz küçük dükkanlarıyla ziyaretçilere otantik bir alışveriş deneyimi sunar.", "place_query": "Korgan Merkez, Korgan, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e7f086a0-cddc-4ff2-ac46-71c85ed58aca'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kumru Kalesi", "summary": "Tarihi bir kalıntı olan Kumru Kalesi, ilçeye hakim bir tepede yer alır. Bölgenin tarihine tanıklık etmek ve çevreyi kuşbakışı izlemek için ideal bir noktadır.", "place_query": "Kumru Kalesi, Kumru, Ordu"}, {"title": "Kumru Şelalesi", "summary": "Doğal güzelliği ve huzur veren atmosferiyle ziyaretçilerini büyüleyen bu şelale, piknik ve doğa yürüyüşleri için popüler bir duraktır.", "place_query": "Kumru Şelalesi, Kumru, Ordu"}, {"title": "Kumru Yaylası", "summary": "Yeşilin her tonunu barındıran yayla, serin havası ve muhteşem manzaralarıyla doğaseverlerin gözde mekanlarındandır. Özellikle yaz aylarında kaçamak yapmak için idealdir.", "place_query": "Kumru Yaylası, Kumru, Ordu"}, {"title": "Kumru Merkez Camii", "summary": "İlçenin en önemli dini yapılarından biri olan cami, mimarisi ve huzurlu ortamıyla dikkat çeker. Ziyaretçiler için manevi bir durak noktasıdır.", "place_query": "Kumru Merkez Camii, Kumru, Ordu"}, {"title": "Kumru Göleti", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal bir alan olan gölet, çevresindeki yürüyüş yolları ve piknik alanlarıyla hafta sonu kaçamaklarına ev sahipliği yapar.", "place_query": "Kumru Göleti, Kumru, Ordu"}, {"title": "Kumru Pazarı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı renkli pazar, ilçenin kültürel dokusunu yansıtır. Alışveriş yapmak ve yerel lezzetleri tatmak için uğranması gereken bir yerdir.", "place_query": "Kumru Pazarı, Kumru, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7abd46c5-9700-4fe5-bb0f-22e7c9b914a5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çiçekli Yaylası", "summary": "Muhteşem doğal güzelliği ve yemyeşil çayırlarıyla ünlü olan yayla, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenlerin uğrak noktasıdır. Ziyaretçiler, yayla evlerinde konaklayarak yöresel lezzetleri tadabilir ve eşsiz manzaraların keyfini çıkarabilir.", "place_query": "Çiçekli Yaylası, Mesudiye, Ordu"}, {"title": "Keyfalan Yaylası", "summary": "Ordu''nun en güzel yaylalarından biri olarak kabul edilen Keyfalan, zengin bitki örtüsü ve tertemiz havasıyla dikkat çeker. Yayla şenliklerine ev sahipliği yapan bu bölge, kamp ve doğa sporları için de idealdir.", "place_query": "Keyfalan Yaylası, Mesudiye, Ordu"}, {"title": "Ulugöl Tabiat Parkı", "summary": "Heyelan set gölü olarak oluşan Ulugöl, çevresindeki sık ormanlarla kaplı doğa harikası bir parktır. Piknik alanları, yürüyüş parkurları ve kuş gözlemi yapma imkanı sunan bu sakin ortam, doğaseverler için kaçırılmaz bir duraktır.", "place_query": "Ulugöl Tabiat Parkı, Mesudiye, Ordu"}, {"title": "Mesudiye Şelaleleri", "summary": "Bölgedeki birçok farklı noktada bulunan şelaleler, özellikle bahar aylarında karların erimesiyle coşkun akışlarıyla görsel bir şölen sunar. Doğa yürüyüşleri sırasında keşfedilebilecek bu şelaleler, fotoğrafçılar için de harika kareler vaat eder.", "place_query": "Mesudiye Şelaleleri, Mesudiye, Ordu"}, {"title": "Gökçeada (Gökçe Yaylası)", "summary": "Yüksek rakımı ve geniş düzlükleriyle bilinen Gökçe Yaylası, yaz aylarında serin bir kaçış noktasıdır. Yöre halkının hayvancılık faaliyetlerine tanıklık edebileceğiniz yaylada, doğal yaşamın içinde huzurlu vakit geçirebilirsiniz.", "place_query": "Gökçe Yaylası, Mesudiye, Ordu"}, {"title": "Kale Mahallesi (Mesudiye Kalesi)", "summary": "Tarihi bir geçmişe sahip olan Mesudiye Kalesi kalıntıları, ilçe merkezine hakim bir tepede yer alır. Bölgenin tarihine tanıklık etmek ve çevrenin panoramik manzarasını izlemek için burayı ziyaret edebilirsiniz.", "place_query": "Mesudiye Kalesi, Mesudiye, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '275cfcc5-8527-4e24-bbab-0016e65c2583'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Perşembe Yaylası", "summary": "Doğal güzelliği ve serin havasıyla ünlü olan bu yayla, yeşil doğası, yürüyüş parkurları ve muhteşem manzarasıyla ziyaretçilerine huzur dolu bir kaçamak sunar.", "place_query": "Perşembe Yaylası, Perşembe, Ordu"}, {"title": "Çaka Kalesi", "summary": "Tarihi bir Bizans kalesi olan Çaka Kalesi, deniz manzaralı konumu ve etkileyici kalıntılarıyla hem tarih meraklılarına hem de doğa severlere hitap eder.", "place_query": "Çaka Kalesi, Perşembe, Ordu"}, {"title": "Perşembe Sahili ve Plajları", "summary": "Uzun kumsalı ve temiz deniziyle Perşembe Sahili, yaz aylarında yüzme, güneşlenme ve deniz keyfi yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Perşembe Sahili, Perşembe, Ordu"}, {"title": "Hoynat Adası", "summary": "Perşembe ilçesine bağlı bu küçük ada, doğal güzelliği, kuş gözlemciliği imkanı ve huzurlu atmosferiyle dikkat çeker; özellikle doğa fotoğrafçıları için idealdir.", "place_query": "Hoynat Adası, Perşembe, Ordu"}, {"title": "Perşembe Kalesi", "summary": "Tarihi bir yapı olan Perşembe Kalesi, ilçe merkezinde yer alır ve çevresindeki yeşil alanlarla birlikte keyifli bir gezi rotası sunar.", "place_query": "Perşembe Kalesi, Perşembe, Ordu"}, {"title": "Belen Tepesi Seyir Noktası", "summary": "Perşembe''nin yüksek noktalarından biri olan Belen Tepesi, ilçe ve deniz manzarasını kuşbakışı izlemek isteyenler için mükemmel bir seyir terasıdır.", "place_query": "Belen Tepesi, Perşembe, Ordu"}, {"title": "Perşembe Müzesi", "summary": "Küçük ama zengin koleksiyonuyla Perşembe Müzesi, yörenin tarihini, kültürünü ve etnografik değerlerini tanımak isteyenler için ideal bir duraktır.", "place_query": "Perşembe Müzesi, Perşembe, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '642f3bf4-9385-4844-8f7e-cd6f1a3f6a76'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ulubey Kanyonu", "summary": "Türkiye''nin en uzun ikinci kanyonu olan bu doğa harikası, yürüyüş parkurları ve cam seyir terası ile ziyaretçilere nefes kesici manzaralar sunar. Kanyon boyunca uzanan vadi ve şelaleler, doğa fotoğrafçıları ve trekking severler için ideal bir rotadır.", "place_query": "Ulubey Kanyonu, Ulubey, Ordu"}, {"title": "Ulubey Cam Teras", "summary": "Kanyonun en etkileyici noktalarından birinde yer alan bu cam seyir terası, 135 metre yükseklikten vadiye kuşbakışı bakma imkanı verir. Heyecan arayanlar ve eşsiz fotoğraf kareleri yakalamak isteyenler için popüler bir duraktır.", "place_query": "Ulubey Cam Teras, Ulubey, Ordu"}, {"title": "Ulubey Tarihi Evleri", "summary": "Osmanlı döneminden kalma ahşap ve taş mimarili geleneksel Karadeniz evleri, ilçe merkezinde dar sokaklarda sıralanır. Tarihi dokuyu ve yöresel yaşamı yakından görmek isteyenler için huzurlu bir gezi rotasıdır.", "place_query": "Ulubey Tarihi Evleri, Ulubey, Ordu"}, {"title": "Ulubey Şelalesi", "summary": "Kanyon içinde gizlenmiş bu şelale, özellikle bahar ve yaz aylarında coşkun akan suları ve çevresindeki yeşil doğasıyla serinlemek ve piknik yapmak için idealdir. Doğa yürüyüşü severlerin sıkça uğradığı bir noktadır.", "place_query": "Ulubey Şelalesi, Ulubey, Ordu"}, {"title": "Ohtamış Şelalesi", "summary": "Ulubey ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu şelale, yemyeşil ormanlar arasında yer alır ve yaz aylarında serinlemek için popülerdir. Çevresindeki mesire alanı, aileler için keyifli bir kaçamak noktasıdır.", "place_query": "Ohtamış Şelalesi, Ulubey, Ordu"}, {"title": "Ulubey Kanyonu Yürüyüş Parkuru", "summary": "Kanyon boyunca uzanan işaretli yürüyüş parkuru, farklı zorluk seviyelerinde etaplar sunar ve doğa sporları meraklıları için benzersiz bir deneyim sağlar. Parkur boyunca kaya oluşumları, mağaralar ve yerel bitki örtüsü keşfedilebilir.", "place_query": "Ulubey Kanyonu Yürüyüş Parkuru, Ulubey, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fd23f470-2e67-4c53-93b2-9c05810ece62'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ünye Kalesi", "summary": "Denizden 250 metre yükseklikte, eşsiz bir manzaraya sahip olan tarihi kale, Pontus döneminden kalma kalıntıları ve Ordu şehir merkezini kuşbakışı gören konumuyla ziyaretçilerin ilk durağı oluyor.", "place_query": "Ünye Kalesi, Ünye, Ordu"}, {"title": "Çamlık Mesire Alanı", "summary": "Yemyeşil çam ağaçları arasında piknik yapabileceğiniz, yürüyüş parkurlarında doğayla iç içe vakit geçirebileceğiniz bu mesire alanı, özellikle hafta sonu ailelerin uğrak noktasıdır.", "place_query": "Çamlık Mesire Alanı, Ünye, Ordu"}, {"title": "Ünye Sahili ve Yürüyüş Yolu", "summary": "Uzun sahil şeridi, tertemiz denizi ve modern yürüyüş yoluyla Ünye''nin en popüler dinlenme noktasıdır; gün batımında yapılan yürüyüşler ise ayrı bir keyif verir.", "place_query": "Ünye Sahili, Ünye, Ordu"}, {"title": "Uzunkum Plajı", "summary": "İnce kumu ve dalgasız deniziyle aileler için ideal olan bu plaj, mavi bayrak ödülü sayesinde temizliğiyle de ön plana çıkar ve yaz aylarında yoğun ilgi görür.", "place_query": "Uzunkum Plajı, Ünye, Ordu"}, {"title": "Ocaklı Yaylası", "summary": "Şehir merkezine yaklaşık 30 kilometre uzaklıkta, serin havası, çiçeklerle kaplı yayla evleri ve doğa yürüyüşü rotalarıyla doğaseverlerin kaçış noktasıdır.", "place_query": "Ocaklı Yaylası, Ünye, Ordu"}, {"title": "Ünye Müzesi", "summary": "Eski bir kilise binasında hizmet veren müze, bölgedeki arkeolojik kazılardan çıkarılan eserler, etnografik objeler ve yöresel kıyafetlerle Ünye''nin tarihine ışık tutar.", "place_query": "Ünye Müzesi, Ünye, Ordu"}, {"title": "Kale Camii (Cami-i Kebir)", "summary": "Osmanlı dönemi mimarisinin güzel örneklerinden biri olan bu tarihi cami, şehir merkezinde yer alır ve özellikle ahşap işçiliğiyle dikkat çeker.", "place_query": "Kale Camii, Ünye, Ordu"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c9f650f4-8693-41ea-9b4c-42e8634e68c8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Haruniye Kaplıcaları", "summary": "Bahçe ilçesinin en bilinen termal turizm merkezidir. Romatizmal hastalıklar ve cilt problemlerine iyi gelen şifalı suları ve doğal güzellikleriyle ziyaretçilerini ağırlar.", "place_query": "Haruniye Kaplıcaları, Bahçe, Osmaniye"}, {"title": "Düziçi Yaylası", "summary": "Bahçe ilçesi sınırları içinde yer alan bu yayla, yemyeşil doğası ve serin havasıyla özellikle yaz aylarında piknik ve kamp için popüler bir kaçış noktasıdır.", "place_query": "Düziçi Yaylası, Bahçe, Osmaniye"}, {"title": "Kaledere Kanyonu", "summary": "Doğa yürüyüşü sevenler için etkileyici bir kanyondur. Derin vadileri ve kayalık oluşumlarıyla bölgenin saklı doğal güzelliklerinden biridir.", "place_query": "Kaledere Kanyonu, Bahçe, Osmaniye"}, {"title": "Bahçe Kalesi", "summary": "Tarihi bir kalıntı olan Bahçe Kalesi, ilçeye tepeden bakan konumuyla hem tarihi bir atmosfer sunar hem de çevrenin panoramik manzarasını izleme imkanı verir.", "place_query": "Bahçe Kalesi, Bahçe, Osmaniye"}, {"title": "Çamlık Mesire Alanı", "summary": "Çam ağaçlarıyla çevrili bu mesire alanı, aileler için ideal bir piknik ve dinlenme noktasıdır. Temiz havası ve doğal gölgesiyle huzurlu bir ortam sunar.", "place_query": "Çamlık Mesire Alanı, Bahçe, Osmaniye"}, {"title": "Kurtkulağı Kervansarayı", "summary": "Tarihi İpek Yolu üzerinde bulunan bu 17. yüzyıl kervansarayı, Osmanlı dönemi mimarisini yansıtan önemli bir yapıdır ve Bahçe''ye yakın konumuyla gezilebilir.", "place_query": "Kurtkulağı Kervansarayı, Ceyhan, Adana"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3cfee0a4-1723-49e4-a1db-395dd7ab5c10'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Haruniye Kaplıcaları", "summary": "Doğal termal suları ve şifalı içmecesiyle ünlü bu kaplıca, romatizma ve cilt rahatsızlıklarına iyi geldiğine inanılan şifalı sularıyla ziyaretçilerini ağırlıyor. Bölgenin en popüler sağlık turizmi noktalarından biridir.", "place_query": "Haruniye Kaplıcaları, Düziçi, Osmaniye"}, {"title": "Düziçi Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale, bölgeye hakim manzarası ve Hitit dönemine uzanan geçmişiyle dikkat çekiyor. Özellikle gün batımında eşsiz bir seyir noktası sunuyor.", "place_query": "Düziçi Kalesi, Düziçi, Osmaniye"}, {"title": "Akyar Şelalesi", "summary": "Yeşillikler içinde gizlenmiş bu şelale, serin suları ve doğal havuzlarıyla piknik ve doğa yürüyüşü sevenler için ideal bir kaçış noktasıdır. Özellikle bahar aylarında suyun debisi artarak görsel bir şölen sunar.", "place_query": "Akyar Şelalesi, Düziçi, Osmaniye"}, {"title": "Bozalan Yaylası", "summary": "Yemyeşil çam ormanları ve temiz havasıyla ünlü bu yayla, yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenlerin uğrak noktasıdır. Yayla şenlikleri de yöresel kültürü tanımak için güzel bir fırsattır.", "place_query": "Bozalan Yaylası, Düziçi, Osmaniye"}, {"title": "Düziçi İçmecesi", "summary": "Demir ve kükürt açısından zengin olan bu doğal içme suyu kaynağı, mide ve bağırsak rahatsızlıklarına iyi geldiğine inanılarak yıllardır ziyaret ediliyor. Çevresindeki mesire alanıyla da keyifli bir gün geçirme imkanı sunuyor.", "place_query": "Düziçi İçmecesi, Düziçi, Osmaniye"}, {"title": "Gavur Dağı (Düldül Dağı) Etekleri", "summary": "Toroslar''ın uzantısı olan bu dağlık alan, doğa yürüyüşleri ve kampçılık için elverişli parkurlara sahiptir. Zirveye doğru yapılan tırmanışlarda zengin bitki örtüsü ve kuş gözlemciliği yapmak mümkündür.", "place_query": "Gavur Dağı, Düziçi, Osmaniye"}, {"title": "Yarbaşı Mesire Alanı", "summary": "Çam ağaçları arasında yer alan bu mesire alanı, piknik masaları ve yürüyüş yollarıyla aileler için huzurlu bir ortam sağlar. Hafta sonları şehir gürültüsünden uzaklaşmak isteyenlerin sıkça tercih ettiği bir dinlenme noktasıdır.", "place_query": "Yarbaşı Mesire Alanı, Düziçi, Osmaniye"}, {"title": "Düziçi Merkez Camii", "summary": "Osmanlı mimarisinden izler taşıyan bu tarihi cami, ilçenin sembol yapılarından biridir. Kesme taş işçiliği ve zarif minaresiyle hem ibadet hem de fotoğrafçılık açısından ilgi çekmektedir.", "place_query": "Düziçi Merkez Camii, Düziçi, Osmaniye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8120928c-3c7b-437a-9630-a83fa4ef4f7d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zorkun Yaylası", "summary": "Osmaniye''nin en popüler yaylalarından biri olan Zorkun, yemyeşil doğası, temiz havası ve özellikle yaz aylarında serinlemek isteyen ziyaretçiler için ideal bir kaçış noktasıdır. Yaylada piknik alanları, yürüyüş parkurları ve yöresel lezzetler sunan tesisler bulunur.", "place_query": "Zorkun Yaylası, Osmaniye"}, {"title": "Karaçay Şelalesi", "summary": "Hasanbeyli ilçe merkezine yakın konumda bulunan Karaçay Şelalesi, doğal güzelliği ve çevresindeki yeşil alanlarla doğa severlerin uğrak noktasıdır. Şelalenin serin suları ve huzur verici atmosferi özellikle hafta sonu kaçamakları için tercih edilir.", "place_query": "Karaçay Şelalesi, Hasanbeyli, Osmaniye"}, {"title": "Hasanbeyli Yaylası", "summary": "İlçenin adını taşıyan bu yayla, şehir merkezine yakınlığı ve kolay ulaşımı ile dikkat çeker. Çam ormanlarıyla çevrili yayla, doğa yürüyüşleri ve kamp aktiviteleri için sakin bir ortam sunar.", "place_query": "Hasanbeyli Yaylası, Osmaniye"}, {"title": "Kalekayası Tepesi", "summary": "Hasanbeyli sınırları içinde yer alan Kalekayası Tepesi, hem tarihi kalıntıları hem de muhteşem manzarasıyla bilinir. Tepeden çevredeki yaylaları ve Ovacık Ovası''nı kuşbakışı izlemek mümkündür.", "place_query": "Kalekayası Tepesi, Hasanbeyli, Osmaniye"}, {"title": "Yarpuz Yaylası", "summary": "Osmaniye''nin en yüksek yaylalarından biri olan Yarpuz, zengin bitki örtüsü ve serin iklimiyle öne çıkar. Özellikle yaz aylarında yoğun ilgi gören yaylada, doğa yürüyüşleri ve fotoğrafçılık için eşsiz fırsatlar vardır.", "place_query": "Yarpuz Yaylası, Osmaniye"}, {"title": "Hasanbeyli Merkez Camii ve Çevresi", "summary": "İlçe merkezinde bulunan tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Caminin çevresindeki eski çarşı ve sokaklar, yöresel el sanatları ve kahve kültürünü keşfetmek için idealdir.", "place_query": "Hasanbeyli Merkez Camii, Osmaniye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '09a5583b-b04f-464c-a5e8-4c8a29ae87ac'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karatepe-Aslantaş Açık Hava Müzesi", "summary": "Hitit dönemine ait etkileyici kabartmaları ve surlarıyla ünlü bu açık hava müzesi, Kadirli''ye 20 km mesafede yer alır. Tarih meraklıları için eşsiz bir durak olup, aynı zamanda Aslantaş Barajı''nın manzarasına karşı huzurlu bir gezinti sunar.", "place_query": "Karatepe-Aslantaş Açık Hava Müzesi, Kadirli, Osmaniye"}, {"title": "Kadirli Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde bulunan bu tarihi kale, Roma ve Bizans dönemlerinden izler taşır. Zirveye tırmananlar, Kadirli''nin panoramik manzarasını izleme fırsatı bulur.", "place_query": "Kadirli Kalesi, Kadirli, Osmaniye"}, {"title": "Savrun (Sarıkız) Şelalesi", "summary": "Doğayla iç içe bir kaçış noktası olan Savrun Şelalesi, yemyeşil bitki örtüsü ve serin sularıyla piknik ve doğa yürüyüşü için idealdir. Özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Savrun Şelalesi, Kadirli, Osmaniye"}, {"title": "Ağzıkara Han", "summary": "Selçuklu dönemine ait tarihi bir kervansaray olan Ağzıkara Han, taş işçiliği ve mimarisiyle dikkat çeker. Kadirli''nin kültürel mirasını yansıtan bu yapı, fotoğraf tutkunları için güzel bir duraktır.", "place_query": "Ağzıkara Han, Kadirli, Osmaniye"}, {"title": "Kadirli Kent Müzesi", "summary": "Şehrin tarihini, kültürünü ve geleneklerini yansıtan eserlerin sergilendiği Kent Müzesi, ziyaretçilere Kadirli''nin geçmişine dair kapsamlı bir bakış sunar. Girişin ücretsiz olması da cazibesini artırır.", "place_query": "Kadirli Kent Müzesi, Kadirli, Osmaniye"}, {"title": "Yedioluk Mesire Alanı", "summary": "Adını yedi ayrı kaynaktan çıkan suyundan alan bu mesire alanı, ağaçlar arasında serinlemek ve mangal keyfi yapmak için popülerdir. Doğa yürüyüşleri ve piknik için sık tercih edilen bir noktadır.", "place_query": "Yedioluk Mesire Alanı, Kadirli, Osmaniye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1efbe7f8-f57a-4ceb-966f-3439adee19d6'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kastabala Antik Kenti", "summary": "Osmaniye merkeze yaklaşık 12 km uzaklıkta bulunan bu antik kent, Roma dönemine ait kalıntıları ve etkileyici tiyatrosuyla tarih meraklıları için önemli bir duraktır. Hierapolis adıyla da bilinen kent, bölgenin en eski yerleşimlerinden biridir.", "place_query": "Kastabala Antik Kenti, Osmaniye Merkez"}, {"title": "Karatepe Aslantaş Açık Hava Müzesi", "summary": "Osmaniye''nin en ünlü tarihi alanlarından biri olan Karatepe, Geç Hitit dönemine ait kabartmaları ve Fenike alfabesiyle yazılmış çift dilli yazıtlarıyla ünlüdür. Aynı zamanda Aslantaş Baraj Gölü manzarası eşliğinde huzurlu bir gezi imkanı sunar.", "place_query": "Karatepe Aslantaş Açık Hava Müzesi, Kadirli, Osmaniye"}, {"title": "Osmaniye Kent Müzesi", "summary": "Şehir merkezinde yer alan bu modern müze, Osmaniye''nin tarihini, kültürünü ve yöresel yaşamını sergileyen eserlerle ziyaretçilerine kapsamlı bir şehir turu deneyimi yaşatır.", "place_query": "Osmaniye Kent Müzesi, Merkez, Osmaniye"}, {"title": "Savrun Çayı Mesire Alanı", "summary": "Osmaniye''nin doğal güzelliklerinden biri olan Savrun Çayı kenarındaki bu mesire alanı, piknik yapmak, serinlemek ve doğa yürüyüşü yapmak isteyenler için ideal bir kaçış noktasıdır. Özellikle yaz aylarında yoğun ilgi görür.", "place_query": "Savrun Çayı Mesire Alanı, Osmaniye"}, {"title": "Toprakkale Kalesi", "summary": "Osmaniye merkeze bağlı Toprakkale ilçesinde bulunan bu tarihi kale, stratejik konumu ve etkileyici mimarisiyle dikkat çeker. Bölgenin fethinden kalma bu yapı, çevredeki ovaya hakim bir tepede yer alır.", "place_query": "Toprakkale Kalesi, Toprakkale, Osmaniye"}, {"title": "Düziçi Yedi Göller", "summary": "Osmaniye''nin Düziçi ilçesinde yer alan bu doğal güzellik, birbirine bağlı yedi küçük göl ve çevresindeki yemyeşil ormanlık alanla doğaseverler için eşsiz bir ortam sunar. Kamp ve doğa yürüyüşü için popülerdir.", "place_query": "Düziçi Yedi Göller, Düziçi, Osmaniye"}, {"title": "Aslantaş Barajı ve Çevresi", "summary": "Osmaniye''nin en büyük baraj gölü olan Aslantaş, su sporları, balıkçılık ve piknik gibi aktiviteler için uygun bir alandır. Baraj çevresindeki yeşil alanlar ve dinlenme tesisleri ziyaretçilere huzurlu bir gün geçirme imkanı tanır.", "place_query": "Aslantaş Barajı, Kadirli, Osmaniye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bc6e7abb-74f8-4fff-b04d-dd4f187c1668'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sumbas Kalesi", "summary": "İlçe merkezine yakın bir tepede yer alan tarihi bir kaledir. Bölgenin hakimiyet mücadelesine tanıklık etmiş olup, çevresindeki doğal manzara ziyaretçilere keyifli bir seyir imkanı sunar.", "place_query": "Sumbas Kalesi, Sumbas, Osmaniye"}, {"title": "Karaçay Şelalesi", "summary": "Sumbas''ın doğal güzelliklerinden biri olan şelale, özellikle bahar ve yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler için popüler bir duraktır.", "place_query": "Karaçay Şelalesi, Sumbas, Osmaniye"}, {"title": "Sumbas Merkez Camii", "summary": "İlçenin en büyük ve en bilinen camisidir. Osmanlı ve modern mimari unsurlarını birleştiren yapısıyla hem ibadet hem de kültürel ziyaretler için önemli bir noktadır.", "place_query": "Sumbas Merkez Camii, Sumbas, Osmaniye"}, {"title": "Yeşilyayla Yaylası", "summary": "Sumbas''a bağlı Yeşilyayla köyünde bulunan bu yayla, yemyeşil doğası ve temiz havasıyla piknik ve kamp yapmak isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Yeşilyayla Yaylası, Sumbas, Osmaniye"}, {"title": "Sumbas Barajı", "summary": "İlçenin sulama ve enerji ihtiyacını karşılayan baraj, çevresindeki mesire alanıyla balık tutma, doğa yürüyüşü ve manzara fotoğrafçılığı için sıkça ziyaret edilir.", "place_query": "Sumbas Barajı, Sumbas, Osmaniye"}, {"title": "Mehmetli Köyü Tarihi Evleri", "summary": "Sumbas''ın Mehmetli köyünde bulunan bu geleneksel taş evler, bölgenin kırsal mimarisini ve geçmiş yaşam kültürünü yansıtan nadide örneklerdir.", "place_query": "Mehmetli Köyü Tarihi Evleri, Sumbas, Osmaniye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'caeb4c75-20ee-47c4-bb53-72cde16ff09e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Toprakkale Kalesi", "summary": "İlçeye adını veren tarihi kale, Osmaniye Ovası''na hakim bir tepe üzerinde yer alır. Hititler''den Osmanlı''ya kadar birçok medeniyete ev sahipliği yapmış olup, muhteşem manzarasıyla ziyaretçilerini büyüler.", "place_query": "Toprakkale Kalesi, Toprakkale, Osmaniye"}, {"title": "Toprakkale Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla bölge halkının ve ziyaretçilerin uğrak noktasıdır. Piknik alanları ve çevresindeki yeşil doku, doğayla iç içe huzurlu bir gün geçirmek için idealdir.", "place_query": "Toprakkale Şelalesi, Toprakkale, Osmaniye"}, {"title": "Tırmıl Höyüğü", "summary": "Osmaniye merkeze bağlı olup Toprakkale''ye yakın konumdaki bu höyük, Hitit dönemine ait önemli bir arkeolojik alandır. Bölgenin antik tarihine tanıklık etmek isteyenler için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Tırmıl Höyüğü, Osmaniye Merkez"}, {"title": "Karaçay Mesire Alanı", "summary": "Toprakkale sınırları içinde yer alan bu mesire alanı, özellikle yaz aylarında piknik ve doğa yürüyüşleri için tercih edilir. Çam ağaçları arasında huzur dolu bir kaçamak sunar.", "place_query": "Karaçay Mesire Alanı, Toprakkale, Osmaniye"}, {"title": "Aslantaş Barajı ve Mesire Alanı", "summary": "Toprakkale''ye kısa bir mesafede bulunan baraj, geniş su yüzeyi ve çevresindeki yeşil alanlarla doğa tutkunlarını cezbeder. Balık tutma, piknik ve manzara seyri için popüler bir noktadır.", "place_query": "Aslantaş Barajı, Osmaniye"}, {"title": "Kırıkhan Köprüsü", "summary": "Tarihi bir Osmanlı dönemi köprüsü olan yapı, ilçe merkezine yakın konumda yer alır. Mimarisi ve çevresindeki doğal doku, fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Kırıkhan Köprüsü, Toprakkale, Osmaniye"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f8370231-7f76-449d-8510-c111831b719f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zilkale", "summary": "Fırtına Deresi vadisinde yükselen bu tarihi kale, eşsiz manzarası ve etkileyici mimarisiyle Rize''nin en çok ziyaret edilen simgelerindendir. Orta Çağ''dan kalma yapı, doğayla iç içe bir tarih yolculuğu sunar.", "place_query": "Zilkale, Ardeşen, Rize"}, {"title": "Fırtına Deresi", "summary": "Yeşilin her tonunu barındıran vadiden akan bu coşkulu dere, rafting ve doğa yürüyüşleri için popüler bir noktadır. Çevresindeki yaylalara açılan yollarıyla Karadeniz''in kalbinde bir doğa harikasıdır.", "place_query": "Fırtına Deresi, Ardeşen, Rize"}, {"title": "Palovit Şelalesi", "summary": "Yemyeşil ormanların içinde gizlenmiş bu görkemli şelale, 15 metre yüksekten dökülen sularıyla büyüleyici bir manzara sunar. Özellikle doğa fotoğrafçıları ve huzur arayanlar için ideal bir kaçış noktasıdır.", "place_query": "Palovit Şelalesi, Ardeşen, Rize"}, {"title": "Hazindak Yaylası", "summary": "Ardeşen''in en bilinen yaylalarından biri olan Hazindak, serin havası, ahşap yayla evleri ve muhteşem yeşil manzaralarıyla yaz aylarında ziyaretçi akınına uğrar. Geleneksel Karadeniz kültürünü deneyimlemek için harika bir duraktır.", "place_query": "Hazindak Yaylası, Ardeşen, Rize"}, {"title": "Çamlıhemşin Yaylaları (Tunca, Elevit, Pokut)", "summary": "Ardeşen sınırlarına yakın bu ünlü yaylalar, sis bulutlarının üzerinde yürüyormuş hissi veren manzaralarıyla ünlüdür. Her biri farklı bir güzellik sunan bu noktalar, doğa tutkunlarının mutlaka görmesi gereken yerlerdir.", "place_query": "Tunca Yaylası, Çamlıhemşin, Rize"}, {"title": "Gito Yaylası", "summary": "Sessizliği ve el değmemiş doğasıyla öne çıkan Gito Yaylası, Ardeşen''in huzurlu köşelerinden biridir. Yemyeşil çayırlar ve serin yayla havası eşliğinde doğa yürüyüşü yapmak için idealdir.", "place_query": "Gito Yaylası, Ardeşen, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '75f4d496-fbb9-4c90-bc30-2cafee56e9fc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pokut Yaylası", "summary": "Rize''nin en popüler yaylalarından biri olan Pokut, özellikle gün doğumu ve gün batımında sis bulutlarının üzerinde seyretme imkanı sunan muhteşem manzarasıyla ünlüdür. Ziyaretçiler, ahşap yayla evleri arasında doğa yürüyüşü yapabilir ve unutulmaz fotoğraflar çekebilir.", "place_query": "Pokut Yaylası, Çamlıhemşin, Rize"}, {"title": "Zilkale", "summary": "Fırtına Deresi vadisinde yükselen bu tarihi kale, Orta Çağ''dan kalma etkileyici bir yapıdır. Vadiye hakim konumu ve çevresindeki yemyeşil doğayla birleşen Zilkale, bölgenin en çok ziyaret edilen tarihi simgelerindendir.", "place_query": "Zilkale, Çamlıhemşin, Rize"}, {"title": "Palovit Şelalesi", "summary": "Kaçkar Dağları''nın eteklerinde yer alan ve 15 metre yükseklikten dökülen Palovit Şelalesi, doğal güzelliği ve çevresindeki yemyeşil ormanlarla huzur verici bir atmosfere sahiptir. Şelaleye ulaşmak için kısa bir doğa yürüyüşü yapmak gerekir.", "place_query": "Palovit Şelalesi, Çamlıhemşin, Rize"}, {"title": "Fırtına Deresi", "summary": "Bölgenin can damarı olan Fırtına Deresi, berrak suları ve çevresindeki yemyeşil vadisiyle rafting, kano ve doğa yürüyüşü gibi aktiviteler için ideal bir noktadır. Dere kenarındaki tarihi taş köprüler de manzaraya ayrı bir güzellik katar.", "place_query": "Fırtına Deresi, Çamlıhemşin, Rize"}, {"title": "Elevit Yaylası", "summary": "Yüksek rakımı ve bozulmamış doğasıyla ünlü Elevit Yaylası, özellikle yaz aylarında yayla şenliklerine ev sahipliği yapar. Ziyaretçiler, geleneksel yayla yaşamını deneyimleyebilir ve Kaçkar Dağları''nın nefes kesen manzarasında huzur bulabilir.", "place_query": "Elevit Yaylası, Çamlıhemşin, Rize"}, {"title": "Çamlıhemşin Tarihi Taş Köprüler", "summary": "Fırtına Deresi üzerinde yer alan ve Osmanlı döneminden kalma bu taş köprüler, bölgenin kültürel mirasının önemli bir parçasıdır. Özellikle Şenyuva Köprüsü ve Kemerli Köprü, fotoğraf tutkunları için eşsiz kareler sunar.", "place_query": "Şenyuva Köprüsü, Çamlıhemşin, Rize"}, {"title": "Kaçkar Dağları Milli Parkı", "summary": "Doğa sporları ve dağcılık için Türkiye''nin en önemli noktalarından biri olan Kaçkar Dağları, zengin flora ve faunasıyla keşfedilmeyi bekler. Milli park sınırları içinde trekking, kamp ve dağ bisikleti gibi aktiviteler yapılabilir.", "place_query": "Kaçkar Dağları Milli Parkı, Çamlıhemşin, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7ef125d2-5746-48cc-b681-45bbaeef8471'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çayeli Sahili ve Plajları", "summary": "Rize''nin en uzun sahil şeritlerinden birine sahip olan Çayeli Sahili, yürüyüş yapmak, deniz havası almak ve Karadeniz''in eşsiz manzarasını izlemek için ideal bir noktadır. Özellikle yaz aylarında yerli halkın ve turistlerin uğrak yeridir.", "place_query": "Çayeli Sahili, Rize"}, {"title": "Gito Yaylası", "summary": "Çayeli''nin en popüler yaylalarından biri olan Gito Yaylası, yeşilin her tonunu barındıran doğası, serin havası ve geleneksel yayla evleriyle doğa severler için harika bir kaçış noktasıdır. Yaylada yapılan festivaller de bölgeye ayrı bir renk katar.", "place_query": "Gito Yaylası, Çayeli, Rize"}, {"title": "Pazaryolu (Haremtepe) Yaylası", "summary": "Yemyeşil çimenler ve sisle kaplı manzarasıyla ünlü Pazaryolu Yaylası, özellikle doğa yürüyüşleri ve kampçılık için tercih edilen bir bölgedir. Yayla, şehir hayatından uzaklaşmak isteyenler için huzur dolu bir atmosfer sunar.", "place_query": "Pazaryolu Yaylası, Çayeli, Rize"}, {"title": "Çayeli Çay Fabrikası", "summary": "Rize denilince akla gelen ilk şey çaydır ve Çayeli Çay Fabrikası, bölgenin çay üretim sürecini yakından görmek isteyenler için önemli bir duraktır. Fabrikada çayın toplanmasından paketlenmesine kadar olan aşamaları yerinde inceleyebilirsiniz.", "place_query": "Çayeli Çay Fabrikası, Rize"}, {"title": "Kendirli Kalesi", "summary": "Çayeli ilçe merkezine yaklaşık 10 km uzaklıkta bulunan Kendirli Kalesi, tarihi kalıntıları ve etkileyici Karadeniz manzarasıyla dikkat çeker. Kale, bölgenin tarihine tanıklık etmek ve güzel fotoğraflar çekmek için ideal bir rota sunar.", "place_query": "Kendirli Kalesi, Çayeli, Rize"}, {"title": "Sırt Yaylası", "summary": "Çayeli''nin yüksek kesimlerinde yer alan Sırt Yaylası, bakir doğası ve sakin ortamıyla öne çıkar. Yaylada yapılan geleneksel etkinlikler ve yöresel lezzetler, ziyaretçilere unutulmaz bir deneyim yaşatır.", "place_query": "Sırt Yaylası, Çayeli, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'da93fc24-f3d2-4a61-b0ae-394fc0546d7b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Derepazarı Merkez Camii", "summary": "İlçe merkezinde yer alan tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve bölge halkı için önemli bir ibadet ve buluşma noktasıdır.", "place_query": "Derepazarı Merkez Camii, Derepazarı, Rize"}, {"title": "Fırtına Deresi", "summary": "Derepazarı sınırlarından geçen Fırtına Deresi, doğal güzelliği ve çevresindeki yemyeşil vadilerle ünlüdür; özellikle rafting ve doğa yürüyüşleri için popülerdir.", "place_query": "Fırtına Deresi, Derepazarı, Rize"}, {"title": "Derepazarı Yaylaları (Örnek: Çiçekli Yaylası)", "summary": "İlçeye bağlı yaylalar, serin havası, ahşap evleri ve muhteşem manzaralarıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Çiçekli Yaylası, Derepazarı, Rize"}, {"title": "Derepazarı Çay Bahçeleri", "summary": "Rize''nin meşhur çayını yudumlarken yeşilin her tonunu görebileceğiniz çay bahçeleri, yöresel lezzetleri denemek için de harika bir duraktır.", "place_query": "Derepazarı Çay Bahçeleri, Derepazarı, Rize"}, {"title": "Kendirli Mahallesi Tarihi Evleri", "summary": "Bölgeye özgü ahşap ve taş mimariyi yansıtan tarihi evler, geleneksel Karadeniz yaşamını yakından görmek isteyenler için önemli bir kültürel rotadır.", "place_query": "Kendirli Mahallesi Tarihi Evler, Derepazarı, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '51cc76cc-ee01-42f6-89c1-5041bc2a3cea'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Fındıklı Sahili", "summary": "Rize''nin en güzel sahil şeritlerinden biri olan Fındıklı Sahili, yürüyüş yapmak, deniz keyfi yaşamak ve gün batımını izlemek için ideal bir yerdir.", "place_query": "Fındıklı Sahili, Fındıklı, Rize"}, {"title": "Çağlayan Şelalesi", "summary": "Yeşillikler içinde gizlenmiş bu şelale, doğa yürüyüşleri ve piknik için popüler bir noktadır; serin suları ve huzur veren atmosferiyle ziyaretçileri büyüler.", "place_query": "Çağlayan Şelalesi, Fındıklı, Rize"}, {"title": "Gürcü Kalesi", "summary": "Tarihi bir yapı olan Gürcü Kalesi, bölgenin geçmişine ışık tutar ve tepeden Fındıklı manzarasını izleme imkanı sunar.", "place_query": "Gürcü Kalesi, Fındıklı, Rize"}, {"title": "Fındıklı Yaylaları (Örn: Çağrankaya Yaylası)", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü Fındıklı yaylaları, doğa turizmi ve kampçılık için harika rotalar sunar.", "place_query": "Çağrankaya Yaylası, Fındıklı, Rize"}, {"title": "Hazindere Şelalesi", "summary": "Etkileyici yüksekliği ve çevresindeki sık ormanlık alanla dikkat çeken Hazindere Şelalesi, fotoğrafçılar ve doğa severler için görülmeye değerdir.", "place_query": "Hazindere Şelalesi, Fındıklı, Rize"}, {"title": "Fındıklı Merkez Camii ve Çarşısı", "summary": "İlçe merkezinde yer alan bu cami ve çevresindeki çarşı, yöresel ürünler almak ve bölgenin kültürel dokusunu hissetmek için uğranması gereken bir noktadır.", "place_query": "Fındıklı Merkez Camii, Fındıklı, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9d1d0ea2-0d31-46c0-8afa-fa44095c5e39'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güneysu Yaylaları (Handüzü Yaylası)", "summary": "Rize''nin en popüler yaylalarından biri olan Handüzü, yeşilin binbir tonunu barındıran doğası, temiz havası ve geleneksel yayla evleriyle huzurlu bir kaçış noktasıdır. Ziyaretçiler, yayla şenliklerine katılabilir ve eşsiz manzaralar eşliğinde yürüyüş yapabilir.", "place_query": "Handüzü Yaylası, Güneysu, Rize"}, {"title": "Güneysu Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, yemyeşil bitki örtüsü arasından dökülen sularıyla serinletici bir doğa harikasıdır. Piknik alanları ve dinlenme imkanları ile aileler için ideal bir günübirlik gezi rotasıdır.", "place_query": "Güneysu Şelalesi, Güneysu, Rize"}, {"title": "Güneysu Kalesi", "summary": "Tarihi bir gözetleme kulesi olan Güneysu Kalesi, bölgeye hakim bir tepe üzerinde yer alır ve çevresine muhteşem bir vadi manzarası sunar. Kaleye tırmanış, doğa yürüyüşü sevenler için keyifli bir deneyimdir.", "place_query": "Güneysu Kalesi, Güneysu, Rize"}, {"title": "Güneysu Merkez Camii ve Çevresi", "summary": "İlçenin simge yapılarından olan bu tarihi cami, mimarisi ve huzur veren atmosferiyle dikkat çeker. Çevresindeki çay bahçeleri ve yerel dükkanlar, ziyaretçilere yöresel lezzetleri tatma ve dinlenme fırsatı sunar.", "place_query": "Güneysu Merkez Camii, Güneysu, Rize"}, {"title": "Güneysu Çay Bahçeleri ve Yayla Evleri", "summary": "Bölgenin simgesi olan çay bahçeleri arasında yürüyüş yapabilir, geleneksel yayla evlerinde konaklama deneyimi yaşayabilirsiniz. Bu rotada yöre halkının misafirperverliği eşliğinde taze demlenmiş çayın tadını çıkarmak unutulmaz bir anı bırakır.", "place_query": "Güneysu Yayla Evleri, Güneysu, Rize"}, {"title": "Güneysu Mesire Alanı", "summary": "Şehir gürültüsünden uzak, ağaçlarla çevrili bu mesire alanı, piknik ve kamp yapmak isteyenler için idealdir. Dere kenarında kurulan bu alan, özellikle yaz aylarında doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Güneysu Mesire Alanı, Güneysu, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c8347004-294c-42db-8eb8-864abb47e324'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pokut Yaylası", "summary": "Doğa yürüyüşleri ve kamp için ideal, sislerle kaplı manzarasıyla ünlü bir yayla. Zirveden izlenen gün doğumu ve sis denizi unutulmaz bir deneyim sunar.", "place_query": "Pokut Yaylası, Hemşin, Rize"}, {"title": "Elevit Yaylası", "summary": "Yeşilin her tonunu barındıran, geleneksel ahşap yayla evleriyle çevrili bir doğa harikası. Özellikle yaz aylarında düzenlenen yayla şenlikleriyle de bilinir.", "place_query": "Elevit Yaylası, Hemşin, Rize"}, {"title": "Ambarlı Yaylası", "summary": "El değmemiş doğası ve sakin atmosferiyle huzur arayanların tercihi. Yayla evlerinde konaklama imkanı ve eşsiz karaçayır manzaraları sunar.", "place_query": "Ambarlı Yaylası, Hemşin, Rize"}, {"title": "Palovit Şelalesi", "summary": "Muhteşem doğal güzelliğiyle dikkat çeken, yemyeşil ormanlar arasında gizlenmiş bir şelale. Soğuk ve berrak suları, doğa fotoğrafçıları için harika kareler vaat eder.", "place_query": "Palovit Şelalesi, Hemşin, Rize"}, {"title": "Gito Yaylası", "summary": "Hemşin''in en yüksek yaylalarından biri olup, zorlu trekking rotalarıyla macera severleri cezbeder. Zirvede bulunan küçük göl, bölgeye ayrı bir mistik hava katar.", "place_query": "Gito Yaylası, Hemşin, Rize"}, {"title": "Aşağı Hemşin Köprüsü", "summary": "Tarihi taş köprü, bölgenin kültürel mirasını yansıtan önemli bir yapıdır. Çevresindeki doğal dokuyla bütünleşen köprü, fotoğrafçılar için popüler bir duraktır.", "place_query": "Aşağı Hemşin Köprüsü, Hemşin, Rize"}, {"title": "Meydan Yaylası", "summary": "Geniş ve düz yapısıyla çadır kampı için uygun, manzarasıyla büyüleyen bir yayla. Özellikle yaz aylarında yerli ve yabancı turistlerin uğrak noktasıdır.", "place_query": "Meydan Yaylası, Hemşin, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6d210956-b60d-4a32-85c7-3e78029cfd75'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Anzer Yaylası", "summary": "Rize''nin en meşhur yaylalarından biri olan Anzer Yaylası, eşsiz doğası, tertemiz havası ve dünyaca ünlü Anzer balı ile tanınır. Ziyaretçiler, yemyeşil çayırlarda yürüyüş yapabilir ve yöresel lezzetleri tadabilir.", "place_query": "Anzer Yaylası, İkizdere, Rize"}, {"title": "Cimil Yaylası", "summary": "Yüksek rakımı ve bozulmamış doğal güzellikleriyle ünlü Cimil Yaylası, doğa yürüyüşleri ve kampçılık için ideal bir noktadır. Yayla evlerinde konaklayarak geleneksel Karadeniz yaşamını deneyimleyebilirsiniz.", "place_query": "Cimil Yaylası, İkizdere, Rize"}, {"title": "İkizdere Vadisi", "summary": "Derin vadiler, çağlayan dereler ve yemyeşil ormanlarla çevrili İkizdere Vadisi, doğa fotoğrafçıları ve trekking severler için muhteşem bir rotadır. Vadi boyunca uzanan patikalarda huzur dolu bir yürüyüş yapabilirsiniz.", "place_query": "İkizdere Vadisi, Rize"}, {"title": "Ovit Dağı", "summary": "İkizdere ile Erzurum arasında yer alan Ovit Dağı, muhteşem manzaraları ve zengin florasıyla ünlüdür. Özellikle yaz aylarında yaylacılık ve doğa sporları için popüler bir destinasyondur.", "place_query": "Ovit Dağı, İkizdere, Rize"}, {"title": "Sivrikaya Tepesi", "summary": "İkizdere''nin en yüksek noktalarından biri olan Sivrikaya Tepesi, nefes kesen bir panoramik manzara sunar. Zirveye ulaşmak için yapılan doğa yürüyüşü, macera arayanlar için unutulmaz bir deneyimdir.", "place_query": "Sivrikaya Tepesi, İkizdere, Rize"}, {"title": "Güneyce Köyü ve Tarihi Evleri", "summary": "İkizdere''nin tarihi köylerinden Güneyce, geleneksel Karadeniz mimarisini yansıtan ahşap evleriyle dikkat çeker. Köyde yürüyüş yaparak bölgenin kültürel dokusunu yakından görebilirsiniz.", "place_query": "Güneyce Köyü, İkizdere, Rize"}, {"title": "Çağrankaya Yaylası", "summary": "Sakin ve huzurlu atmosferiyle bilinen Çağrankaya Yaylası, doğa ile baş başa kalmak isteyenler için harika bir kaçış noktasıdır. Yaylada yöresel ürünler satın alabilir ve doğal güzelliklerin tadını çıkarabilirsiniz.", "place_query": "Çağrankaya Yaylası, İkizdere, Rize"}, {"title": "Kurt Köyü Şelalesi", "summary": "İkizdere''nin saklı kalmış doğal güzelliklerinden Kurt Köyü Şelalesi, yemyeşil bitki örtüsü arasından dökülen serin sularıyla görülmeye değerdir. Şelaleye ulaşmak için kısa bir doğa yürüyüşü yapmanız gerekmektedir.", "place_query": "Kurt Köyü Şelalesi, İkizdere, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f3a17217-ccd9-4281-bc79-167d5e359c86'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İyidere Plajı", "summary": "Rize''nin Karadeniz kıyısındaki nadir plajlarından biri olan İyidere Plajı, yaz aylarında serinlemek ve deniz keyfi yapmak için ziyaret edilir. Çakıl taşlı sahili ve çevresindeki yeşil doğasıyla huzurlu bir atmosfer sunar.", "place_query": "İyidere Plajı, İyidere, Rize"}, {"title": "İyidere Merkez Camii", "summary": "İlçenin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve bölge halkı için önemli bir ibadet ve kültür merkezidir. Ziyaretçiler, caminin sade ama etkileyici yapısını görebilir.", "place_query": "İyidere Merkez Camii, İyidere, Rize"}, {"title": "İyidere Deresi", "summary": "İlçeden geçen bu doğal dere, çevresindeki yemyeşil bitki örtüsü ve şelalelerle ünlüdür. Özellikle doğa yürüyüşü ve piknik yapmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "İyidere Deresi, İyidere, Rize"}, {"title": "İyidere Yaylası", "summary": "Karadeniz''in serin ve yeşil yaylalarından biri olan İyidere Yaylası, doğa tutkunları için ideal bir rotadır. Yayla evleri, zengin florası ve muhteşem manzarasıyla ziyaretçilere huzur dolu bir deneyim sunar.", "place_query": "İyidere Yaylası, İyidere, Rize"}, {"title": "İyidere Kalesi", "summary": "Tarihi bir gözetleme kulesi olan İyidere Kalesi, ilçenin yüksek bir noktasında yer alır. Kale kalıntılarından çevredeki vadi ve deniz manzarasını izlemek mümkündür.", "place_query": "İyidere Kalesi, İyidere, Rize"}, {"title": "İyidere Köprüsü", "summary": "Tarihi bir taş köprü olan İyidere Köprüsü, ilçenin simgelerindendir. Dere üzerindeki bu yapı, hem mimari güzelliği hem de çevresindeki doğal peyzajıyla fotoğrafçılar için popüler bir noktadır.", "place_query": "İyidere Köprüsü, İyidere, Rize"}, {"title": "İyidere Çamlığı", "summary": "İlçe merkezine yakın konumdaki bu çam ormanı, yürüyüş parkurları ve piknik alanlarıyla doğaseverlerin uğrak noktasıdır. Temiz havası ve gölgelik alanlarıyla yaz sıcağında serinlemek için idealdir.", "place_query": "İyidere Çamlığı, İyidere, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '95ad12f4-425a-42e5-bee0-4afd07bd1982'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kalkandere Merkez Camii ve Çarşı", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki çarşı, yöresel ürünleri ve sakin atmosferiyle ziyaretçileri cezbeder.", "place_query": "Kalkandere Merkez Camii, Rize"}, {"title": "Kalkandere Yaylaları (Örnek: Şimşirli Yaylası)", "summary": "Yeşilin her tonunu barındıran yaylalar, doğa yürüyüşleri ve piknik için idealdir; özellikle Şimşirli Yaylası manzarasıyla ünlüdür.", "place_query": "Şimşirli Yaylası, Kalkandere, Rize"}, {"title": "Kalkandere Şelalesi", "summary": "İlçe sınırlarındaki bu şelale, serin suları ve çevresindeki doğal güzelliklerle fotoğrafçılar ve doğaseverler için popüler bir duraktır.", "place_query": "Kalkandere Şelalesi, Rize"}, {"title": "Kalkandere Kalesi Kalıntıları", "summary": "Tarihi bir kale kalıntısı olan bu alan, bölgenin geçmişine ışık tutar ve tepeden ilçe manzarası sunar.", "place_query": "Kalkandere Kalesi, Rize"}, {"title": "Kalkandere Çay Bahçeleri", "summary": "Rize''nin meşhur çayını tadabileceğiniz bu bahçeler, yeşil örtü içinde huzurlu bir mola vermek için idealdir.", "place_query": "Kalkandere çay bahçeleri, Rize"}, {"title": "Kalkandere Yüksek Dağ Gölleri (Örnek: Büyük Göl)", "summary": "Çevre yaylalarda yer alan doğal göller, trekking rotalarının önemli noktalarındandır; Büyük Göl berrak sularıyla dikkat çeker.", "place_query": "Büyük Göl, Kalkandere, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd7775017-a0c7-4598-ade5-e70ab9414539'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Rize Kalesi", "summary": "Şehir merkezinde yüksek bir tepe üzerinde yer alan tarihi kale, Rize manzarasının en güzel izlendiği noktalardan biridir. Ziyaretçiler hem tarihi dokuyu keşfeder hem de şehri kuşbakışı izleme fırsatı bulur.", "place_query": "Rize Kalesi, Merkez, Rize"}, {"title": "Zil Castle (Zil Kalesi)", "summary": "Deniz kenarında, yalçın kayalar üzerine inşa edilmiş bu küçük ama etkileyici kale, fotoğrafçılar için eşsiz bir manzara sunar. Özellikle gün batımında ziyaret edildiğinde büyüleyici bir atmosfer yakalayabilirsiniz.", "place_query": "Zil Castle, Merkez, Rize"}, {"title": "Rize Müzesi", "summary": "Eski bir konakta hizmet veren müze, bölgenin etnografik ve arkeolojik zenginliklerini sergiler. Karadeniz kültürüne dair otantik objeleri ve yöresel kıyafetleri yakından görmek için ideal bir duraktır.", "place_query": "Rize Müzesi, Merkez, Rize"}, {"title": "Rize Sahil Yolu ve Seyir Terasları", "summary": "Şehrin kıyı şeridi boyunca uzanan sahil yolu, yürüyüş ve bisiklet turları için popülerdir. Yol üzerindeki seyir terasları sayesinde Karadeniz''in dalgalarını ve yeşil dağları aynı anda izleyebilirsiniz.", "place_query": "Rize Sahil Yolu, Merkez, Rize"}, {"title": "Gündoğdu (Potamya) Yaylası", "summary": "Şehir merkezine yaklaşık 20 km mesafedeki bu yayla, yemyeşil çayırları ve geleneksel yayla evleriyle huzurlu bir kaçış noktasıdır. Doğa yürüyüşü yapabilir ve yöresel peynirlerin tadına bakabilirsiniz.", "place_query": "Gündoğdu Yaylası, Merkez, Rize"}, {"title": "Tophane Çay Bahçesi", "summary": "Rize''nin simgesi haline gelmiş bu çay bahçesi, demli çay eşliğinde şehir manzarasını izlemek için en bilinen noktalardan biridir. Yerli ve yabancı turistlerin uğramadan geçmediği keyifli bir mekandır.", "place_query": "Tophane Çay Bahçesi, Merkez, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bbf5fdb7-df43-4d7b-9196-f2a1271a390a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pazar Ayder Yaylası", "summary": "Rize''nin en ünlü yaylalarından biri olan Ayder, şifalı kaplıcaları, doğal güzellikleri ve yöresel lezzetleriyle ziyaretçilerine eşsiz bir deneyim sunar. Özellikle kış aylarında termal turizmin merkezi haline gelir.", "place_query": "Ayder Yaylası, Çamlıhemşin, Rize"}, {"title": "Pazar Kalesi", "summary": "Tarihi bir yapı olan Pazar Kalesi, ilçe merkezinde yer alır ve Karadeniz''in eşsiz manzarasını seyretme imkanı sunar. Kale, bölgenin tarihine ışık tutan önemli bir kültürel mirastır.", "place_query": "Pazar Kalesi, Pazar, Rize"}, {"title": "Pazar Sahili ve Plajları", "summary": "Pazar''ın uzun sahil şeridi, yürüyüş yapmak ve denizin tadını çıkarmak için idealdir. Özellikle yaz aylarında yerli ve yabancı turistlerin uğrak noktasıdır.", "place_query": "Pazar Sahili, Pazar, Rize"}, {"title": "Zilkale", "summary": "Fırtına Deresi vadisinde yer alan Zilkale, eşsiz doğa manzarası ve tarihi dokusuyla dikkat çeker. Orta Çağ''dan kalma bu kale, bölgenin en çok fotoğraflanan noktalarından biridir.", "place_query": "Zilkale, Çamlıhemşin, Rize"}, {"title": "Fırtına Deresi", "summary": "Pazar ve Çamlıhemşin arasında uzanan Fırtına Deresi, berrak suları ve çevresindeki yeşil doğasıyla ünlüdür. Rafting ve doğa yürüyüşü gibi aktiviteler için popüler bir destinasyondur.", "place_query": "Fırtına Deresi, Çamlıhemşin, Rize"}, {"title": "Pazar Merkez Camii", "summary": "Osmanlı döneminden kalma tarihi bir cami olan Pazar Merkez Camii, mimarisi ve süslemeleriyle dikkat çeker. İlçenin en önemli dini yapılarından biridir.", "place_query": "Pazar Merkez Camii, Pazar, Rize"}, {"title": "Pokut Yaylası", "summary": "Rize''nin en yüksek yaylalarından biri olan Pokut, sislerle kaplı manzarası ve huzurlu atmosferiyle ünlüdür. Özellikle gün doğumu ve gün batımında eşsiz fotoğraf kareleri sunar.", "place_query": "Pokut Yaylası, Çamlıhemşin, Rize"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5db16853-56f1-441e-a338-af4026d8f615'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sakarya Müzesi", "summary": "Kentin merkezinde yer alan bu müze, bölgenin arkeolojik ve etnografik zenginliğini sergiliyor. Roma, Bizans ve Osmanlı dönemlerine ait eserlerle Sakarya''nın tarihine dair kapsamlı bir bakış sunuyor.", "place_query": "Sakarya Müzesi, Adapazarı, Sakarya"}, {"title": "Kent Park", "summary": "Adapazarı''nın en büyük ve en popüler parkı olan Kent Park, yürüyüş yolları, göleti, bisiklet parkuru ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme ve eğlence noktasıdır.", "place_query": "Kent Park, Adapazarı, Sakarya"}, {"title": "Orman Park (Sakarya Orman Parkı)", "summary": "Şehir merkezine yakın bu geniş yeşil alan, piknik masaları, yürüyüş parkurları ve temiz havasıyla doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Sakarya Orman Parkı, Adapazarı, Sakarya"}, {"title": "Adapazarı Saat Kulesi", "summary": "Şehrin simgelerinden biri olan bu tarihi saat kulesi, 19. yüzyıl sonlarında inşa edilmiştir. Merkezi bir meydanda yer alır ve çevresi kafe ve restoranlarla doludur.", "place_query": "Adapazarı Saat Kulesi, Sakarya"}, {"title": "Poyrazlar Gölü Tabiat Parkı", "summary": "Adapazarı''na yaklaşık 10 km uzaklıktaki bu doğal göl, kuş gözlemi, doğa yürüyüşleri ve piknik için popülerdir. Göl çevresindeki ahşap yürüyüş yolları ve seyir terasları ziyaretçilere huzurlu bir deneyim sunar.", "place_query": "Poyrazlar Gölü Tabiat Parkı, Adapazarı, Sakarya"}, {"title": "Sakarya Büyükşehir Belediyesi Bilim Merkezi", "summary": "Özellikle çocuklu aileler için ilgi çekici olan bu merkez, interaktif bilim deneyleri, planetaryum ve atölye çalışmalarıyla eğlenceli ve öğretici bir gün geçirme imkanı tanır.", "place_query": "Sakarya Bilim Merkezi, Adapazarı"}, {"title": "Sakarya Nehri Kenarı (Sakarya Sahili)", "summary": "Şehir merkezinden geçen Sakarya Nehri boyunca uzanan yürüyüş ve bisiklet yolları, özellikle akşam saatlerinde keyifli bir gezinti rotasıdır. Nehir kenarındaki çay bahçeleri ve restoranlar da ziyaretçilere hizmet verir.", "place_query": "Sakarya Nehri kenarı, Adapazarı"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b4615b5f-2ced-44a0-b039-aa71f5d97ba4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sülüklü Göl Tabiat Parkı", "summary": "Sakarya''nın en popüler doğal güzelliklerinden biri olan bu göl, çevresindeki yürüyüş yolları ve piknik alanlarıyla huzurlu bir doğa kaçamağı sunar. Özellikle hafta sonları aileler ve doğa severler tarafından yoğun olarak ziyaret edilir.", "place_query": "Sülüklü Göl Tabiat Parkı, Akyazı, Sakarya"}, {"title": "Acarlar Longozu", "summary": "Türkiye''nin en büyük subasar ormanlarından biri olan Acarlar Longozu, eşsiz bitki örtüsü ve kuş gözlemciliği için ideal bir noktadır. Akyazı sınırları içinde yer alan bu doğa harikası, ziyaretçilere kanalda tekne turu yapma imkanı da sunar.", "place_query": "Acarlar Longozu, Akyazı, Sakarya"}, {"title": "Sakarya İl Ormanı", "summary": "Geniş çam ormanları ve temiz havasıyla ünlü bu mesire alanı, yürüyüş, bisiklet ve piknik için en çok tercih edilen yerlerdendir. Şehir merkezine yakın konumuyla doğayla iç içe vakit geçirmek isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Sakarya İl Ormanı, Akyazı, Sakarya"}, {"title": "Hacı Yakup Camii (Tarihi Akyazı Camii)", "summary": "Akyazı''nın en eski ve tarihi yapılarından biri olan bu cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Şehir merkezinde yer alan cami, hem ibadet hem de tarihi dokuya tanıklık etmek için ziyaret edilmektedir.", "place_query": "Hacı Yakup Camii, Akyazı, Sakarya"}, {"title": "Akyazı Kent Ormanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için düzenlenmiş bu ormanlık alan, yürüyüş parkurları ve dinlenme banklarıyla donatılmıştır. Özellikle hafta sonu aile piknikleri ve doğa yürüyüşleri için sıkça tercih edilen bir noktadır.", "place_query": "Akyazı Kent Ormanı, Akyazı, Sakarya"}, {"title": "Dokurcun Göleti", "summary": "Sakarya''nın doğal güzelliklerinden biri olan bu gölet, çevresindeki yeşil alanlar ve sakin atmosferiyle huzurlu bir gün geçirmek isteyenlerin uğrak noktasıdır. Balık tutma ve piknik yapma imkanı da sunar.", "place_query": "Dokurcun Göleti, Akyazı, Sakarya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c9180dbe-0c54-4132-a2c7-5bd97973a801'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sakarya İl Ormanı", "summary": "Şehir merkezine yakın, geniş yürüyüş parkurları ve piknik alanlarıyla ünlü, huzurlu bir doğal yaşam alanıdır.", "place_query": "Sakarya İl Ormanı, Arifiye, Sakarya"}, {"title": "Arifiye Kent Ormanı", "summary": "Bisiklet ve yürüyüş yolları, göleti ve yeşil alanlarıyla aileler için ideal bir günübirlik dinlenme noktasıdır.", "place_query": "Arifiye Kent Ormanı, Arifiye, Sakarya"}, {"title": "Sakarya Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen, tarihe ilgi duyanlar için önemli bir kültür durağıdır.", "place_query": "Sakarya Müzesi, Adapazarı, Sakarya"}, {"title": "Sakarya Nehri Kıyısı", "summary": "Nehir kenarında yürüyüş yapabileceğiniz, doğayla iç içe vakit geçirebileceğiniz sakin bir alandır.", "place_query": "Sakarya Nehri, Arifiye, Sakarya"}, {"title": "Sapanca Gölü", "summary": "Arifiye''ye oldukça yakın olan bu doğal göl, muhteşem manzarası, yürüyüş yolları ve su sporlarıyla ünlüdür.", "place_query": "Sapanca Gölü, Sapanca, Sakarya"}, {"title": "Arifiye Cumhuriyet Parkı", "summary": "İlçe merkezinde bulunan, çocuk oyun alanları ve oturma gruplarıyla yerel halkın uğrak noktalarından biridir.", "place_query": "Arifiye Cumhuriyet Parkı, Arifiye, Sakarya"}, {"title": "Sakarya Uzun Çarşı", "summary": "Yöresel ürünler, hediyelik eşyalar ve el sanatları almak isteyenler için canlı bir alışveriş caddesidir.", "place_query": "Sakarya Uzun Çarşı, Adapazarı, Sakarya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e12d79a8-968a-4dc5-9198-65ae2060fe96'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sakarya Müzesi", "summary": "Eski bir hükümet konağında hizmet veren müze, bölgenin arkeolojik ve etnografik zenginliğini sergiliyor. Hitit, Frig, Roma ve Osmanlı dönemlerine ait eserler görebilirsiniz.", "place_query": "Sakarya Müzesi, Adapazarı, Sakarya"}, {"title": "Sakarya Kent Park", "summary": "Şehrin en büyük ve en popüler parkı olan Kent Park, yürüyüş yolları, göleti ve yeşil alanlarıyla aileler için ideal bir dinlenme ve piknik noktasıdır.", "place_query": "Sakarya Kent Park, Adapazarı, Sakarya"}, {"title": "Deprem Müzesi (Kültür ve Sanat Merkezi)", "summary": "1999 depreminin izlerini taşıyan bu müze, deprem bilincini artırmak ve anıları yaşatmak amacıyla ziyarete açılmıştır. Etkileyici bir anma ve eğitim alanıdır.", "place_query": "Deprem Müzesi, Adapazarı, Sakarya"}, {"title": "Orman Park (Sakarya Orman Parkı)", "summary": "Şehir merkezine yakın bu geniş ormanlık alan, doğa yürüyüşleri, bisiklet turları ve kamp yapmak için harika bir seçenektir. Temiz havası ve huzurlu atmosferiyle öne çıkar.", "place_query": "Sakarya Orman Parkı, Adapazarı, Sakarya"}, {"title": "Atatürk Stadyumu ve Spor Kompleksi", "summary": "Modern spor tesisleri ve geniş yeşil alanlarıyla dikkat çeken bu kompleks, spor yapmak veya maç izlemek isteyenler için popüler bir buluşma noktasıdır.", "place_query": "Sakarya Atatürk Stadyumu, Adapazarı, Sakarya"}, {"title": "Erenler Pazarı (Yerel Halk Pazarı)", "summary": "Her hafta kurulan bu renkli pazar, yöresel ürünler, taze meyve-sebze ve el işi ürünler bulabileceğiniz canlı bir alışveriş deneyimi sunar.", "place_query": "Erenler Pazarı, Sakarya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a5e5f2f0-3088-4361-a1f7-bce3ab29ff32'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sakarya İl Ormanı (Ferizli Mevkii)", "summary": "Ferizli sınırları içinde yer alan bu geniş ormanlık alan, özellikle piknik ve doğa yürüyüşleri için idealdir. Temiz havası ve yeşil doğasıyla ziyaretçilere huzurlu bir kaçış sunar.", "place_query": "Sakarya İl Ormanı, Ferizli, Sakarya"}, {"title": "Ferizli Merkez Camii ve Külliyesi", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Çevresindeki külliye yapılarıyla birlikte bölgenin dini ve kültürel mirasını yansıtır.", "place_query": "Ferizli Merkez Camii, Ferizli, Sakarya"}, {"title": "Sakarya Nehri Kenarı (Ferizli Kesimi)", "summary": "Sakarya Nehri''nin Ferizli''den geçen bölümü, balık tutma ve doğa ile baş başa kalma imkanı sunar. Nehir kenarındaki yürüyüş yolları ve dinlenme alanları ziyaretçiler için keyifli bir ortam oluşturur.", "place_query": "Sakarya Nehri Ferizli, Sakarya"}, {"title": "Ferizli Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumdaki bu gölet, çevresindeki piknik alanları ve yeşil dokusuyla aileler için popüler bir hafta sonu kaçamağıdır. Gölet manzarası eşliğinde huzurlu vakit geçirebilirsiniz.", "place_query": "Ferizli Göleti, Ferizli, Sakarya"}, {"title": "Taşlık Köyü Yaylası", "summary": "Ferizli''ye bağlı Taşlık Köyü sınırlarındaki bu yayla, yemyeşil çayırları ve temiz havasıyla doğaseverler için idealdir. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için tercih edilir.", "place_query": "Taşlık Köyü Yaylası, Ferizli, Sakarya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '798536a7-2414-45c4-ac4d-4090d7ca769d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Geyve Boğazı", "summary": "Sakarya Nehri''nin oluşturduğu bu dar ve derin vadi, muhteşem manzaraları ve yemyeşil doğasıyla ünlüdür. Özellikle sonbahar aylarında yaprak dökümüyle birlikte eşsiz bir renk cümbüşü sunar ve fotoğrafçılar için ideal bir noktadır.", "place_query": "Geyve Boğazı, Geyve, Sakarya"}, {"title": "Geyve Tarihi Evleri", "summary": "Osmanlı döneminden kalma ahşap ve kagir yapıların bulunduğu bu tarihi evler, Geyve''nin kültürel mirasını yansıtır. Dar sokakları ve geleneksel mimarisiyle ziyaretçilere geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Geyve Tarihi Evleri, Geyve, Sakarya"}, {"title": "Geyve Alifuatpaşa Köprüsü", "summary": "Mimar Sinan tarafından yapıldığı rivayet edilen bu tarihi taş köprü, Sakarya Nehri üzerinde yer alır. Alifuatpaşa Mahallesi''ndeki köprü, hem tarihi dokusu hem de çevresindeki doğal güzelliklerle dikkat çeker.", "place_query": "Alifuatpaşa Köprüsü, Geyve, Sakarya"}, {"title": "Geyve Ayva Bahçeleri", "summary": "Geyve, Türkiye''nin en kaliteli ayvalarının yetiştiği bölge olarak bilinir. İlçe geneline yayılmış ayva bahçeleri, özellikle hasat döneminde (Eylül-Kasım) ziyaretçilere hem doğal güzellik hem de taze meyve tadımı imkanı sunar.", "place_query": "Geyve Ayva Bahçeleri, Geyve, Sakarya"}, {"title": "Geyve Merkez Camii", "summary": "Cumhuriyet döneminin erken yıllarında inşa edilen bu camii, sade ve etkileyici mimarisiyle ilçe merkezinde önemli bir simgedir. İbadete açık olan cami, çevresindeki tarihi çarşıyla birlikte görülmeye değerdir.", "place_query": "Geyve Merkez Camii, Geyve, Sakarya"}, {"title": "Sakarya Nehri Kenarı", "summary": "Geyve ilçe merkezinden geçen Sakarya Nehri''nin kenarı, yürüyüş yapmak ve doğayla baş başa kalmak için popüler bir mekandır. Nehir kenarındaki kafelerde oturup huzurlu bir vakit geçirebilirsiniz.", "place_query": "Sakarya Nehri, Geyve, Sakarya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '04f80cd7-ab61-49ee-b17c-c7cf8be132dd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saklı Göl", "summary": "Hendek''in doğal güzelliklerinden biri olan Saklı Göl, piknik alanları ve yürüyüş parkurlarıyla doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Saklı Göl, Hendek, Sakarya"}, {"title": "Çamlıca Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü Çamlıca Yaylası, kamp ve doğa yürüyüşü yapmak isteyenler için popüler bir duraktır.", "place_query": "Çamlıca Yaylası, Hendek, Sakarya"}, {"title": "Hendek Merkez Camii", "summary": "Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, Hendek''in merkezinde yer alır ve şehrin önemli dini yapılarından biridir.", "place_query": "Hendek Merkez Camii, Sakarya"}, {"title": "Soğuksu Parkı", "summary": "Aileler için huzurlu bir ortam sunan Soğuksu Parkı, piknik alanları ve çocuk oyun alanlarıyla hafta sonu gezileri için tercih edilir.", "place_query": "Soğuksu Parkı, Hendek, Sakarya"}, {"title": "Hendek Şelalesi", "summary": "Doğa ile iç içe bir deneyim sunan Hendek Şelalesi, özellikle yaz aylarında serinlemek ve fotoğraf çekmek için ziyaret edilir.", "place_query": "Hendek Şelalesi, Sakarya"}, {"title": "Bağrıaçık Göleti", "summary": "Balık tutma ve piknik yapma imkanı sunan Bağrıaçık Göleti, sakin atmosferiyle doğa tutkunlarının uğrak noktasıdır.", "place_query": "Bağrıaçık Göleti, Hendek, Sakarya"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3be42b12-8ea2-4cff-b684-1623bf74db8b'::uuid;
