UPDATE location_pages SET travel_ideas_json = '[{"title": "Atakum Sahili", "summary": "Samsun''un en uzun ve en popüler sahil şerididir. Yürüyüş ve bisiklet yolları, kafeleri ve deniz manzarasıyla hem yerli halkın hem de turistlerin uğrak noktasıdır.", "place_query": "Atakum Sahili, Samsun"}, {"title": "Atakum Kent Meydanı", "summary": "Şehrin modern yüzünü yansıtan bu meydan, çevresindeki alışveriş merkezleri, restoranlar ve sosyal alanlarıyla canlı bir buluşma noktasıdır.", "place_query": "Atakum Kent Meydanı, Samsun"}, {"title": "Amisos Tepesi", "summary": "Samsun''un kurulduğu antik yerleşimlerden biri olan tepe, Helenistik döneme ait kral mezarları ve muhteşem şehir manzarası sunar. Teleferikle ulaşım da mümkündür.", "place_query": "Amisos Tepesi, Samsun"}, {"title": "Atakum Sahil Bandı", "summary": "Sahil boyunca uzanan bu yürüyüş yolu, bisiklet sürmek, koşu yapmak veya deniz kenarında dinlenmek için idealdir. Özellikle gün batımında büyüleyici bir atmosfere sahiptir.", "place_query": "Atakum Sahil Bandı, Samsun"}, {"title": "Baruthane Millet Bahçesi", "summary": "Eski bir baruthanenin restore edilmesiyle oluşturulan bu geniş yeşil alan, piknik alanları, yürüyüş yolları ve çocuk oyun parklarıyla aileler için popüler bir kaçış noktasıdır.", "place_query": "Baruthane Millet Bahçesi, Atakum, Samsun"}, {"title": "Samsun Amazon Köyü", "summary": "Mitolojiye göre Karadeniz kıyısında yaşadığına inanılan Amazon kadın savaşçılarının hikayesini anlatan tematik bir açık hava müzesidir. Heykeller ve canlandırmalarla ziyaretçilere farklı bir deneyim sunar.", "place_query": "Samsun Amazon Köyü, Atakum"}, {"title": "Atakum Kapalı Pazar Yeri", "summary": "Yöresel ürünler, taze meyve ve sebzeler ile el işi ürünlerini bulabileceğiniz renkli bir pazardır. Yerel halkın günlük yaşamına tanıklık etmek için idealdir.", "place_query": "Atakum Kapalı Pazar Yeri, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd5f1b0e1-b778-4708-8c0a-ecaa612a31fe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayvacık Barajı", "summary": "Doğal güzelliği ve huzurlu atmosferiyle bilinen Ayvacık Barajı, piknik yapmak ve doğa yürüyüşleri için ideal bir noktadır. Baraj çevresindeki yeşil alanlar ziyaretçilere sakin bir kaçış imkanı sunar.", "place_query": "Ayvacık Barajı, Ayvacık, Samsun"}, {"title": "Çınarcık Yaylası", "summary": "Yemyeşil ormanlarla çevrili Çınarcık Yaylası, temiz havası ve muhteşem manzarasıyla doğaseverlerin uğrak noktasıdır. Yaylada kamp kurup doğayla baş başa vakit geçirebilirsiniz.", "place_query": "Çınarcık Yaylası, Ayvacık, Samsun"}, {"title": "Şahinkaya Kanyonu", "summary": "Ayvacık sınırları içinde yer alan Şahinkaya Kanyonu, etkileyici kaya oluşumları ve yeşil doğasıyla dikkat çeker. Kanyon boyunca yürüyüş yapabilir ve fotoğrafçılık için eşsiz kareler yakalayabilirsiniz.", "place_query": "Şahinkaya Kanyonu, Ayvacık, Samsun"}, {"title": "Ayvacık Şelalesi", "summary": "Sessiz ve sakin bir ortamda akan Ayvacık Şelalesi, özellikle yaz aylarında serinlemek isteyenler için popüler bir duraktır. Şelalenin çevresindeki doğal havuzlar yüzme imkanı sunar.", "place_query": "Ayvacık Şelalesi, Ayvacık, Samsun"}, {"title": "Kızılot Yaylası", "summary": "Yüksek rakımı ve serin iklimiyle bilinen Kızılot Yaylası, doğa yürüyüşleri ve kamp için idealdir. Yaylada yerel flora ve fauna gözlemi yapabilirsiniz.", "place_query": "Kızılot Yaylası, Ayvacık, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ee5331de-8fa4-499f-9692-c4f42e93800c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bafra Kızılırmak Deltası Kuş Cenneti", "summary": "Türkiye''nin en önemli sulak alanlarından biri olan bu delta, yüzlerce kuş türüne ev sahipliği yapar. Doğa fotoğrafçıları ve kuş gözlemcileri için eşsiz bir rotadır; ayrıca bisiklet ve yürüyüş parkurlarıyla doğayla iç içe vakit geçirebilirsiniz.", "place_query": "Bafra Kızılırmak Deltası Kuş Cenneti, Bafra, Samsun"}, {"title": "Bafra Müzesi", "summary": "Bölgenin zengin tarihini yansıtan bu müze, arkeolojik ve etnografik eserlerle doludur. Hitit, Roma ve Osmanlı dönemlerine ait buluntuları yakından görebilir, yöresel kültürü keşfedebilirsiniz.", "place_query": "Bafra Müzesi, Bafra, Samsun"}, {"title": "Bafra Saathane Meydanı ve Saat Kulesi", "summary": "Şehrin merkezinde bulunan bu tarihi meydan, Bafra''nın simgelerinden biri olan saat kulesiyle çevrilidir. Çevresindeki kafelerde soluklanabilir, yöresel lezzetleri tadabilirsiniz.", "place_query": "Bafra Saat Kulesi, Bafra, Samsun"}, {"title": "Şeyh Nasreddin Türbesi", "summary": "Bafra''da manevi bir atmosfer arayanlar için önemli bir duraktır. 13. yüzyılda yaşamış olan Şeyh Nasreddin''in türbesi, hem tarihi dokusu hem de huzur veren ortamıyla ziyaretçilerini ağırlar.", "place_query": "Şeyh Nasreddin Türbesi, Bafra, Samsun"}, {"title": "Bafra Çetinkaya Köprüsü (Tarihi Taş Köprü)", "summary": "Kızılırmak üzerinde bulunan bu tarihi taş köprü, Osmanlı döneminden kalma bir mühendislik harikasıdır. Çevresindeki yeşil alanlarla birlikte güzel bir gezi ve fotoğraf noktasıdır.", "place_query": "Bafra Çetinkaya Köprüsü, Bafra, Samsun"}, {"title": "Bafra Kapıkaya Tabiat Parkı", "summary": "Kızılırmak Deltası yakınında yer alan bu tabiat parkı, piknik alanları ve yürüyüş yolları ile doğaseverler için idealdir. Gölet çevresinde huzurlu bir gün geçirebilir, kamp yapabilirsiniz.", "place_query": "Bafra Kapıkaya Tabiat Parkı, Bafra, Samsun"}, {"title": "Bafra Yörgüç Paşa Camii", "summary": "Bafra''nın en eski camilerinden biri olan bu yapı, 15. yüzyılda inşa edilmiştir. Osmanlı mimarisinin güzel bir örneği olan cami, tarihi dokusuyla dikkat çeker.", "place_query": "Bafra Yörgüç Paşa Camii, Bafra, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '18649aa4-185c-45f6-8c9c-3b66b5ff9e35'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Samsun Amazon Köyü", "summary": "Amazon kadın savaşçılarının efsanesini yaşatan bu tematik köy, heykeller, ahşap evler ve gösteri alanlarıyla ziyaretçilere farklı bir deneyim sunar.", "place_query": "Samsun Amazon Köyü, Canik, Samsun"}, {"title": "Canik Belediyesi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun parklarıyla aileler için huzurlu bir dinlenme ve piknik noktasıdır.", "place_query": "Canik Belediyesi Millet Bahçesi, Canik, Samsun"}, {"title": "Ondokuz Mayıs Üniversitesi Kampüsü", "summary": "Samsun''un en büyük üniversite kampüsü olan bu alan, göleti, ormanlık bölgesi ve spor tesisleriyle doğa yürüyüşü ve gezinti için idealdir.", "place_query": "OMÜ Kampüsü, Canik, Samsun"}, {"title": "Canik Yıldız Dağı Seyir Terası", "summary": "Samsun ve Karadeniz manzarasını kuşbakışı gören bu seyir noktası, özellikle gün batımında muhteşem bir fotoğraf karesi sunar.", "place_query": "Yıldız Dağı Seyir Terası, Canik, Samsun"}, {"title": "Karasu Sahili", "summary": "Canik ilçe sınırları içinde yer alan bu uzun kumsal, dalgasız denizi ve doğal yapısıyla yaz aylarında serinlemek için tercih edilir.", "place_query": "Karasu Sahili, Canik, Samsun"}, {"title": "Canik Kültür Merkezi ve Sanat Sokağı", "summary": "Tiyatro, sergi ve konserlerin düzenlendiği bu merkez, çevresindeki renkli sokak sanatı ve kafelerle kültürel bir gezinti alanıdır.", "place_query": "Canik Kültür Merkezi, Canik, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fcd12523-70c7-4761-a1ca-4be9818105b2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çarşamba Kızılırmak Deltası Kuş Cenneti", "summary": "Türkiye''nin en önemli sulak alanlarından biri olan bu delta, yüzlerce kuş türüne ev sahipliği yapar. Doğa yürüyüşleri ve kuş gözlemi için eşsiz bir noktadır.", "place_query": "Kızılırmak Deltası Kuş Cenneti, Çarşamba, Samsun"}, {"title": "Çarşamba Saat Kulesi", "summary": "İlçenin simgesi haline gelmiş bu tarihi kule, 19. yüzyıldan kalma mimarisiyle dikkat çeker. Şehir merkezinde yer alan kule, fotoğrafçılar için popüler bir duraktır.", "place_query": "Çarşamba Saat Kulesi, Çarşamba, Samsun"}, {"title": "Göğceli Camii (Tarihi Ahşap Cami)", "summary": "Anadolu''nun en eski ahşap camilerinden biri olan Göğceli Camii, 13. yüzyıldan kalma eşsiz mimarisiyle ziyaretçilerini büyüler. Oyma süslemeleri ve tarihi atmosferiyle görülmeye değerdir.", "place_query": "Göğceli Camii, Çarşamba, Samsun"}, {"title": "Çarşamba Yaylaları (Salıpazarı Yaylası)", "summary": "Çarşamba''nın yüksek kesimlerinde yer alan yaylalar, yeşil doğası ve temiz havasıyla doğa severler için idealdir. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için tercih edilir.", "place_query": "Salıpazarı Yaylası, Çarşamba, Samsun"}, {"title": "Çarşamba Pazarı (Cuma Pazarı)", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu pazar, ilçenin en hareketli noktalarından biridir. Ziyaretçiler, taze meyve sebze ve yöresel lezzetleri burada bulabilir.", "place_query": "Çarşamba Cuma Pazarı, Çarşamba, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '914a3713-acc8-4230-9f27-114a32fbd76f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Havza Atatürk Evi ve Kurtuluş Savaşı Müzesi", "summary": "Mustafa Kemal Atatürk''ün Milli Mücadele''yi başlatmak üzere Samsun''a çıktıktan sonra ilk konakladığı ve 18 gün kaldığı tarihi evdir. Müze olarak düzenlenen yapı, Kurtuluş Savaşı''nın ilk adımlarının atıldığı bu önemli döneme ait eşyaları ve belgeleri sergilemektedir.", "place_query": "Atatürk Evi Müzesi, Havza, Samsun"}, {"title": "Havza Kaplıcaları (Havza Jeotermal Kaynakları)", "summary": "Romatizmal hastalıklar başta olmak üzere şifalı sularıyla ünlü olan Havza Kaplıcaları, Atatürk''ün de burada tedavi görmesiyle tarihi bir öneme sahiptir. Bölgede birçok otel ve termal tesis bulunmakta olup, şifalı suyun tadına bakmak ve dinlenmek için ideal bir duraktır.", "place_query": "Havza Kaplıcaları, Havza, Samsun"}, {"title": "Havza Şehir Parkı ve Atatürk Anıtı", "summary": "İlçe merkezinde yer alan geniş ve yeşil bir park olan Şehir Parkı, içerisinde bulunan Atatürk Anıtı ve yürüyüş yollarıyla ziyaretçilere huzurlu bir ortam sunar. Ailece piknik yapmak veya dinlenmek için sıkça tercih edilen bir mekandır.", "place_query": "Havza Şehir Parkı, Havza, Samsun"}, {"title": "İncesu Kanyonu Tabiat Parkı", "summary": "Havza ilçe merkezine yaklaşık 15 km uzaklıkta bulunan bu tabiat parkı, eşsiz kanyon manzarası, yürüyüş parkurları ve piknik alanlarıyla doğa severler için harika bir kaçış noktasıdır. Özellikle hafta sonları doğayla iç içe vakit geçirmek isteyenlerin uğrak yeridir.", "place_query": "İncesu Kanyonu Tabiat Parkı, Havza, Samsun"}, {"title": "Havza Kalesi", "summary": "İlçe merkezinde bulunan tarihi bir kale olup, günümüze sadece kalıntıları ulaşmıştır. Tarihi yapıyı görmek ve çevredeki manzarayı izlemek için kısa bir ziyaret yapılabilir.", "place_query": "Havza Kalesi, Havza, Samsun"}, {"title": "Bekdiğin Şelalesi", "summary": "Havza ilçesine bağlı Bekdiğin Mahallesi''nde bulunan bu şelale, özellikle yaz aylarında serinlemek ve doğal güzelliğin tadını çıkarmak isteyenler tarafından ziyaret edilmektedir. Çevresi piknik yapmaya uygun olup, huzurlu bir atmosfere sahiptir.", "place_query": "Bekdiğin Şelalesi, Havza, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8b12646b-9ec1-4a0f-811e-efd1e6a7ef58'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bandırma Vapuru ve Milli Mücadele Parkı", "summary": "Mustafa Kemal Atatürk''ün 19 Mayıs 1919''da Samsun''a çıktığı tarihi vapurun birebir kopyası ve çevresindeki açık hava müzesi. Kurtuluş Savaşı''nın başlangıcına tanıklık etmek için en önemli durak.", "place_query": "Bandırma Vapuru, İlkadım, Samsun"}, {"title": "Samsun Arkeoloji ve Etnoğrafya Müzesi", "summary": "Bölgenin zengin tarihini sergileyen müze, Hitit, Roma, Bizans ve Osmanlı dönemine ait eserlerle dolu. Özellikle Amisos hazineleri ve yöresel etnoğrafik objeler dikkat çekiyor.", "place_query": "Samsun Arkeoloji Müzesi, İlkadım, Samsun"}, {"title": "Amisos Tepesi", "summary": "Samsun''un simgelerinden olan bu tepe, Helenistik döneme ait kral mezar odaları ve muhteşem şehir manzarası sunuyor. Teleferikle çıkılan tepe, özellikle gün batımında büyüleyici.", "place_query": "Amisos Tepesi, İlkadım, Samsun"}, {"title": "Samsun Saathane Meydanı ve Büyük Camii", "summary": "Şehrin tarihi merkezinde bulunan meydan, Osmanlı döneminden kalma saat kulesi ve Büyük Camii ile çevrilidir. Alışveriş ve yeme-içme için de popüler bir buluşma noktasıdır.", "place_query": "Saathane Meydanı, İlkadım, Samsun"}, {"title": "Gazi Müzesi (Atatürk Evi)", "summary": "Atatürk''ün Samsun ziyaretlerinde kaldığı tarihi bina, bugün müze olarak hizmet veriyor. İçinde Atatürk''e ait kişisel eşyalar ve o döneme ait fotoğraflar sergileniyor.", "place_query": "Gazi Müzesi, İlkadım, Samsun"}, {"title": "Samsun Kent Müzesi", "summary": "Modern müzecilik anlayışıyla tasarlanan bu müze, Samsun''un tarih öncesinden günümüze kadar olan hikayesini interaktif bir şekilde anlatıyor. Şehri tanımak için ideal bir başlangıç noktası.", "place_query": "Samsun Kent Müzesi, İlkadım, Samsun"}, {"title": "Sahil Park ve Atatürk Parkı", "summary": "Samsun''un uzun sahil şeridinde yer alan bu parklar, yürüyüş, bisiklet ve deniz manzarası keyfi için en popüler alanlar. İçinde kafeler, oyun alanları ve Atatürk anıtı bulunuyor.", "place_query": "Atatürk Parkı, İlkadım, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8e9a558a-09cf-455f-a828-569acc8e2b58'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kavak Yaylaları", "summary": "Samsun''un en yeşil ve serin bölgelerinden biri olan Kavak yaylaları, doğa yürüyüşleri ve piknik için idealdir. Özellikle yaz aylarında şehrin gürültüsünden kaçmak isteyenler için huzurlu bir kaçış noktasıdır.", "place_query": "Kavak Yaylaları, Kavak, Samsun"}, {"title": "Kavak Kalesi", "summary": "Tarihi bir geçmişe sahip olan Kavak Kalesi, bölgenin en önemli tarihi yapılarından biridir. Kale, muhteşem manzarası ve fotoğrafçılık için uygun atmosferiyle ziyaretçilerini bekliyor.", "place_query": "Kavak Kalesi, Kavak, Samsun"}, {"title": "Çakallı Şelalesi", "summary": "Kavak ilçesinde yer alan Çakallı Şelalesi, doğal güzelliği ve çevresindeki yeşil alanlarla ünlüdür. Şelalenin serin suları ve doğal havuzları, özellikle yaz aylarında serinlemek isteyenler için popüler bir duraktır.", "place_query": "Çakallı Şelalesi, Kavak, Samsun"}, {"title": "Kavak Müzesi", "summary": "Kavak''ın kültürel ve tarihi mirasını sergileyen bu müze, yöresel kıyafetler, tarım aletleri ve geçmişe ait eşyalarla doludur. Bölge tarihine ilgi duyanlar için küçük ama etkileyici bir durak.", "place_query": "Kavak Müzesi, Kavak, Samsun"}, {"title": "Kavak Göleti", "summary": "Şehir merkezine yakın konumuyla bilinen Kavak Göleti, balık tutma ve doğa ile baş başa vakit geçirme imkanı sunar. Gölet çevresindeki yürüyüş yolları ve banklar, ziyaretçilere sakin anlar yaşatır.", "place_query": "Kavak Göleti, Kavak, Samsun"}, {"title": "Kavak Kaplıcaları", "summary": "Termal sularıyla bilinen Kavak Kaplıcaları, sağlık turizmi açısından önemli bir yerdir. Romatizma ve cilt rahatsızlıklarına iyi geldiği düşünülen bu kaplıcalar, şifalı sularıyla ziyaretçilerine huzur verir.", "place_query": "Kavak Kaplıcaları, Kavak, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8d2792b4-545a-4fe8-82d1-be24a0c6fd8a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ladik Gölü", "summary": "Samsun''un önemli doğal göllerinden biri olan Ladik Gölü, çevresindeki yürüyüş parkurları ve piknik alanlarıyla doğa severler için huzurlu bir kaçış noktasıdır. Kuş gözlemi yapmak ve göl manzarasında dinlenmek için idealdir.", "place_query": "Ladik Gölü, Ladik, Samsun"}, {"title": "Ladik Akdağ Tabiat Parkı", "summary": "Zengin bitki örtüsü ve temiz havasıyla ünlü Akdağ Tabiat Parkı, kampçılık ve doğa yürüyüşleri için popüler bir destinasyondur. Yemyeşil ormanlar arasında huzurlu bir gün geçirebilirsiniz.", "place_query": "Akdağ Tabiat Parkı, Ladik, Samsun"}, {"title": "Ladik Kaplıcaları", "summary": "Termal sularıyla şifa dağıtan Ladik Kaplıcaları, romatizmal hastalıklara iyi geldiği bilinen şifalı suları ve modern tesisleriyle yıl boyunca ziyaretçi çekmektedir.", "place_query": "Ladik Kaplıcaları, Ladik, Samsun"}, {"title": "Ladik Müzesi", "summary": "Bölgenin tarihine ışık tutan Ladik Müzesi, arkeolojik ve etnografik eserlerin sergilendiği küçük ama etkileyici bir müzedir. Hitit, Roma ve Bizans dönemine ait buluntuları görebilirsiniz.", "place_query": "Ladik Müzesi, Ladik, Samsun"}, {"title": "Ladik Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan Ladik Kalesi, günümüze sadece kalıntıları ulaşmış olsa da zirvesinden Ladik Ovası''nın muhteşem manzarasını izleme fırsatı sunar.", "place_query": "Ladik Kalesi, Ladik, Samsun"}, {"title": "Ladik Şelalesi", "summary": "Akdağ eteklerinde yer alan bu şelale, özellikle bahar aylarında karların erimesiyle coşkun akan suları ve çevresindeki yeşil doğasıyla fotoğrafçıların ve doğa tutkunlarının uğrak noktasıdır.", "place_query": "Ladik Şelalesi, Ladik, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '504bc631-c5c2-43d2-a7a2-9ff0972a3839'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ondokuzmayıs Sahili", "summary": "Uzun ve geniş kumsalıyla Karadeniz''in en güzel sahillerinden biridir. Özellikle yaz aylarında denize girmek ve gün batımını izlemek için ideal bir noktadır.", "place_query": "Ondokuzmayıs Sahili, Samsun"}, {"title": "Çarşamba Çayı (Ondokuzmayıs bölümü)", "summary": "Bölgeden geçerek Karadeniz''e dökülen bu akarsu, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popülerdir.", "place_query": "Çarşamba Çayı, Ondokuzmayıs, Samsun"}, {"title": "Ballıca Mağarası (Ondokuzmayıs sınırları içindeki mağaralar)", "summary": "Bölgede bulunan doğal mağara oluşumları, sarkıt ve dikitleriyle ziyaretçilerine eşsiz bir yeraltı dünyası sunar. Keşfetmek isteyenler için ilgi çekicidir.", "place_query": "Ballıca Mağarası, Ondokuzmayıs, Samsun"}, {"title": "Kızılırmak Deltası Kuş Cenneti (Ondokuzmayıs yakını)", "summary": "Samsun''un önemli doğal alanlarından biri olan bu delta, yüzlerce kuş türüne ev sahipliği yapar. Kuş gözlemciliği ve doğa fotoğrafçılığı için harika bir yerdir.", "place_query": "Kızılırmak Deltası Kuş Cenneti, Samsun"}, {"title": "Ondokuzmayıs Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve ailece vakit geçirmek için idealdir. Yeşil alanları ve yürüyüş yollarıyla huzurlu bir atmosfer sunar.", "place_query": "Ondokuzmayıs Belediye Parkı, Samsun"}, {"title": "Sahil Yürüyüş Yolu (Ondokuzmayıs)", "summary": "Deniz kenarında uzanan bu yürüyüş yolu, bisiklet sürmek ve koşu yapmak için de popülerdir. Manzarasıyla özellikle akşam saatlerinde tercih edilir.", "place_query": "Ondokuzmayıs Sahil Yürüyüş Yolu, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7872ed5e-b82e-4fae-96ff-23e6a11e68e1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Salıpazarı Yaylaları", "summary": "Salıpazarı''nın yemyeşil doğasını keşfetmek için en güzel rotalardan biri. Yaylalar, temiz havası, çam ormanları ve doğa yürüyüşleri için harika bir ortam sunar.", "place_query": "Salıpazarı Yaylaları, Samsun"}, {"title": "Salıpazarı Mesire Alanı", "summary": "Aileler ve piknik severler için ideal bir dinlenme noktasıdır. Şehrin gürültüsünden uzak, akarsu kenarında huzurlu bir gün geçirmek için tercih edilir.", "place_query": "Salıpazarı Mesire Alanı, Samsun"}, {"title": "Salıpazarı Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale kalıntıları, bölgenin stratejik önemini gözler önüne seriyor. Çevresindeki doğal manzara ile birlikte ziyaretçilere keyifli bir atmosfer sunar.", "place_query": "Salıpazarı Kalesi, Samsun"}, {"title": "Salıpazarı Şelalesi", "summary": "Doğal güzellikleriyle ünlü bu şelale, özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar. Serin suları ve yeşil çevresi, fotoğrafçılar ve doğa tutkunları için eşsiz bir mekandır.", "place_query": "Salıpazarı Şelalesi, Samsun"}, {"title": "Salıpazarı Göleti", "summary": "Balık tutma, piknik ve doğa yürüyüşü gibi aktiviteler için popüler bir duraktır. Sakin ve huzurlu ortamı sayesinde hafta sonu kaçamakları için idealdir.", "place_query": "Salıpazarı Göleti, Samsun"}, {"title": "Salıpazarı Tarihi Çeşmeleri", "summary": "İlçenin çeşitli noktalarında bulunan tarihi çeşmeler, Osmanlı dönemi mimarisinin izlerini taşır. Bu yapılar, kısa bir tarih yolculuğu yapmak isteyenler için görülmeye değerdir.", "place_query": "Salıpazarı Tarihi Çeşmeleri, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'fa16be0d-b1ba-4467-9660-ae0b5f410887'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tekkeköy Mağaraları", "summary": "Tarih öncesi dönemlere ait yerleşim izlerinin bulunduğu bu mağaralar, arkeoloji ve doğa tutkunları için eşsiz bir keşif noktasıdır.", "place_query": "Tekkeköy Mağaraları, Tekkeköy, Samsun"}, {"title": "Şahinkaya Kanyonu", "summary": "Doğal güzelliği ve etkileyici kaya oluşumlarıyla ünlü bu kanyon, tekne turları ve yürüyüş parkurlarıyla ziyaretçilere unutulmaz bir deneyim sunar.", "place_query": "Şahinkaya Kanyonu, Tekkeköy, Samsun"}, {"title": "Tekkeköy Belediyesi Kent Müzesi", "summary": "Bölgenin tarihini, kültürünü ve geçmiş yaşam tarzını yansıtan eserlerin sergilendiği bu müze, ziyaretçilere keyifli bir kültürel yolculuk vadediyor.", "place_query": "Tekkeköy Belediyesi Kent Müzesi, Tekkeköy, Samsun"}, {"title": "Fener Adası", "summary": "Tekkeköy kıyılarında yer alan bu küçük ada, deniz manzarası ve huzurlu atmosferiyle piknik ve dinlenme için ideal bir kaçış noktasıdır.", "place_query": "Fener Adası, Tekkeköy, Samsun"}, {"title": "Çınaraltı Sahil Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve deniz kenarındaki konumuyla aileler ve doğaseverler için popüler bir mesire ve dinlenme alanıdır.", "place_query": "Çınaraltı Sahil Parkı, Tekkeköy, Samsun"}, {"title": "Karanlık Mağara", "summary": "Doğal oluşumu ve gizemli atmosferiyle dikkat çeken bu mağara, macera arayan ziyaretçiler için keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "Karanlık Mağara, Tekkeköy, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3306051a-e3ad-43c3-90dc-cd7df1d99a43'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Terme Gölü", "summary": "Terme ilçe merkezine yakın konumdaki bu doğal göl, piknik alanları ve çevresindeki yeşil doku ile hafta sonu ziyaretçilerinin uğrak noktasıdır. Kuş gözlemi ve doğa yürüyüşü için de idealdir.", "place_query": "Terme Gölü, Terme, Samsun"}, {"title": "Terme Kaplıcaları (Termal Tesisleri)", "summary": "Romatizmal hastalıklara iyi geldiğine inanılan şifalı sularıyla ünlü Terme Kaplıcaları, bölgenin en önemli sağlık turizmi merkezlerinden biridir. Modern tesisleriyle konforlu bir termal deneyim sunar.", "place_query": "Terme Kaplıcaları, Terme, Samsun"}, {"title": "Terme Müzesi", "summary": "İlçe merkezinde yer alan müze, bölgedeki arkeolojik kazılardan çıkarılan Helenistik, Roma ve Bizans dönemine ait eserleri sergilemektedir. Tarih meraklıları için küçük ama değerli bir duraktır.", "place_query": "Terme Müzesi, Terme, Samsun"}, {"title": "Terme Yaylaları (Akbaba Yaylası vb.)", "summary": "Terme''nin yüksek kesimlerinde yer alan yaylalar, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler tarafından tercih edilir. Akbaba Yaylası en bilinenlerindendir.", "place_query": "Akbaba Yaylası, Terme, Samsun"}, {"title": "Terme Şelalesi", "summary": "İlçe merkezine kısa bir mesafede bulunan bu şelale, çevresindeki mesire alanıyla birlikte piknik ve doğa gezintisi için popüler bir noktadır. Özellikle bahar aylarında suyun debisi artar.", "place_query": "Terme Şelalesi, Terme, Samsun"}, {"title": "Kocaman Köyü Kaya Mezarları", "summary": "Terme''nin tarihi dokusunu yansıtan Kocaman Köyü''ndeki kaya mezarları, Helenistik ve Roma dönemine ait izler taşır. Tarih ve arkeoloji meraklıları için keşfedilmeyi bekleyen bir alandır.", "place_query": "Kocaman Köyü Kaya Mezarları, Terme, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '79aeca97-7f46-4579-b2dc-ed68b48e730b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şahinkaya Kanyonu", "summary": "Türkiye''nin en büyük ikinci kanyonu olan Şahinkaya Kanyonu, Vezirköprü sınırlarında yer alır. Tekne turlarıyla gezilebilen kanyon, muhteşem doğal manzaraları ve yürüyüş parkurlarıyla doğa severler için ideal bir destinasyondur.", "place_query": "Şahinkaya Kanyonu, Vezirköprü, Samsun"}, {"title": "Vezirköprü Evleri", "summary": "Tarihi ahşap ve taş mimarinin en güzel örneklerini barındıran Vezirköprü Evleri, Osmanlı döneminden kalma dar sokakları ve cumbalı yapılarıyla ziyaretçilere nostaljik bir atmosfer sunar.", "place_query": "Vezirköprü Tarihi Evleri, Samsun"}, {"title": "Oymaağaç Höyüğü (Nerik Antik Kenti)", "summary": "Hitit döneminin kutsal kenti Nerik olarak bilinen Oymaağaç Höyüğü, arkeolojik kazılarıyla tarih meraklıları için önemli bir duraktır. Bölge, antik kalıntıları ve höyük yapısıyla dikkat çeker.", "place_query": "Oymaağaç Höyüğü Nerik, Vezirköprü, Samsun"}, {"title": "Kunduz Dağı Tabiat Parkı", "summary": "Zengin bitki örtüsü ve yaban hayatıyla Kunduz Dağı Tabiat Parkı, piknik alanları ve yürüyüş rotalarıyla doğa ile iç içe vakit geçirmek isteyenler için popüler bir mekandır.", "place_query": "Kunduz Dağı Tabiat Parkı, Vezirköprü, Samsun"}, {"title": "Vezirköprü Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan Vezirköprü Ulu Camii, tarihi dokusu ve zarif taş işçiliğiyle ilçenin en önemli dini yapılarından biridir.", "place_query": "Vezirköprü Ulu Camii, Samsun"}, {"title": "Kızılkaya Mağarası", "summary": "Doğal oluşumu ve içindeki sarkıt-dikit yapılarıyla dikkat çeken Kızılkaya Mağarası, mağara turizmi için keşfedilmeyi bekleyen bir noktadır. Çevresindeki ormanlık alan da doğa yürüyüşlerine olanak tanır.", "place_query": "Kızılkaya Mağarası, Vezirköprü, Samsun"}, {"title": "Gölköy Barajı ve Mesire Alanı", "summary": "Gölköy Barajı çevresinde yer alan mesire alanı, piknik ve kamp yapmak isteyenler için sakin bir ortam sunar. Baraj gölü manzarası eşliğinde huzurlu bir gün geçirebilirsiniz.", "place_query": "Gölköy Barajı, Vezirköprü, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '28fcae65-e8c6-4f98-98fd-b343f217da84'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yakakent Plajı", "summary": "Samsun''un en uzun ve bakir plajlarından biri olan Yakakent Plajı, ince kumu ve temiz deniziyle yaz aylarında serinlemek ve güneşlenmek için idealdir. Sahil şeridinde yürüyüş yapabilir, denizin tadını çıkarabilirsiniz.", "place_query": "Yakakent Plajı, Yakakent, Samsun"}, {"title": "Yakakent Kalesi", "summary": "Tarihi bir gözetleme kulesi olan Yakakent Kalesi, bölgeye hakim bir tepede yer alır ve muhteşem Karadeniz manzarası sunar. Kaleyi ziyaret ederek hem tarihe tanıklık edebilir hem de eşsiz fotoğraflar çekebilirsiniz.", "place_query": "Yakakent Kalesi, Yakakent, Samsun"}, {"title": "Kozköy Şelalesi", "summary": "Yakakent''e bağlı Kozköy''de bulunan bu şelale, yemyeşil doğa içinde huzurlu bir kaçış noktasıdır. Şelalenin serin sularında ferahlayabilir, çevresindeki piknik alanında vakit geçirebilirsiniz.", "place_query": "Kozköy Şelalesi, Yakakent, Samsun"}, {"title": "Yakakent Yaylası (Kunduz Yaylası)", "summary": "Yakakent''in yüksek kesimlerinde yer alan bu yayla, yemyeşil çayırları ve temiz havasıyla doğa severler için mükemmel bir duraktır. Yayla evlerinde konaklayabilir, doğa yürüyüşleri yapabilirsiniz.", "place_query": "Kunduz Yaylası, Yakakent, Samsun"}, {"title": "Karaağaç Mahallesi Sahili", "summary": "Yakakent''in sakin ve huzurlu sahillerinden biri olan Karaağaç, kalabalıktan uzak bir deniz keyfi sunar. Özellikle doğayla iç içe bir gün geçirmek isteyenler için idealdir.", "place_query": "Karaağaç Mahallesi Sahili, Yakakent, Samsun"}, {"title": "Yakakent Merkez Camii", "summary": "İlçenin merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Hem ibadet hem de tarihi bir yapıyı görmek için ziyaret edilebilir.", "place_query": "Yakakent Merkez Camii, Yakakent, Samsun"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f4bfc1e8-b4dc-4ea6-8f9e-7472cafdcc05'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akçakale Kalesi", "summary": "İlçe merkezinde bulunan tarihi bir kaledir. Bölgenin stratejik önemini yansıtır ve çevresindeki tarihi doku ile ziyaretçilere farklı bir atmosfer sunar.", "place_query": "Akçakale Kalesi, Akçakale, Şanlıurfa"}, {"title": "Akçakale Sınır Kapısı", "summary": "Türkiye-Suriye sınırında yer alan önemli bir geçiş noktasıdır. Sınır ticaretinin canlı olduğu bölgede, sınırın hemen yanındaki hareketli yaşamı gözlemlemek mümkündür.", "place_query": "Akçakale Sınır Kapısı, Akçakale, Şanlıurfa"}, {"title": "Harran Evleri", "summary": "Akçakale''ye yakın konumdaki Harran ilçesinde bulunan, dünyaca ünlü konik kubbeli kerpiç evlerdir. Binlerce yıllık tarihi ve eşsiz mimarisiyle görülmeye değerdir.", "place_query": "Harran Evleri, Harran, Şanlıurfa"}, {"title": "Harran Örenyeri (Harran Antik Kenti)", "summary": "Akçakale yakınlarındaki Harran''da yer alan bu antik kent, Mezopotamya''nın en eski yerleşimlerinden biridir. Kalıntılar ve tarihi atmosferi ile tarih meraklıları için ideal bir duraktır.", "place_query": "Harran Örenyeri, Harran, Şanlıurfa"}, {"title": "Akçakale Belediyesi Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve ailece vakit geçirmek için popüler bir mekandır. Yeşil alanları ve yürüyüş yollarıyla sakin bir ortam sunar.", "place_query": "Akçakale Belediyesi Parkı, Akçakale, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd54d79cb-0fe8-4caa-8856-67a4f5f95fe0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Birecik Kelaynak Kuşları Üreme İstasyonu", "summary": "Dünyada nesli tükenme tehlikesi altındaki kelaynak kuşlarının korunduğu ve üretildiği bu istasyon, Birecik''in simgesi haline gelmiştir. Ziyaretçiler, bu nadir kuşları doğal ortamlarında gözlemleme fırsatı bulur.", "place_query": "Kelaynak Kuşları Üreme İstasyonu, Birecik, Şanlıurfa"}, {"title": "Birecik Kalesi", "summary": "Fırat Nehri kıyısında yükselen tarihi bir kale olup, Roma ve Bizans dönemlerinden izler taşır. Nehir manzarası eşliğinde tarihi bir yolculuk yapmak isteyenler için idealdir.", "place_query": "Birecik Kalesi, Birecik, Şanlıurfa"}, {"title": "Fırat Nehri Kıyısı ve Mesire Alanı", "summary": "Birecik''in en popüler dinlenme noktalarından biri olan nehir kıyısı, piknik yapmak ve doğayla iç içe vakit geçirmek için tercih edilir. Özellikle gün batımında eşsiz bir manzara sunar.", "place_query": "Fırat Nehri Kıyısı Mesire Alanı, Birecik, Şanlıurfa"}, {"title": "Birecik Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, şehrin merkezinde yer alır. Taş işçiliği ve sade mimarisiyle dikkat çeker.", "place_query": "Birecik Ulu Camii, Birecik, Şanlıurfa"}, {"title": "Birecik Müzesi", "summary": "Bölgenin arkeolojik ve etnografik eserlerini sergileyen müze, Birecik ve çevresinin tarihine ışık tutar. Küçük ama zengin koleksiyonuyla kültür turizmine katkı sağlar.", "place_query": "Birecik Müzesi, Birecik, Şanlıurfa"}, {"title": "Zeugma Mozaik Müzesi (Şanlıurfa Merkez)", "summary": "Birecik''e yaklaşık 80 km uzaklıkta olan bu dünyaca ünlü müze, Zeugma Antik Kenti''nden çıkarılan eşsiz mozaiklere ev sahipliği yapar. Çingene Kızı mozaiği en önemli eserlerindendir.", "place_query": "Zeugma Mozaik Müzesi, Şanlıurfa Merkez, Şanlıurfa"}, {"title": "Halfeti (Birecik''e Yakın Tekne Turları)", "summary": "Birecik''in komşusu Halfeti, Fırat Nehri üzerinde düzenlenen tekne turlarıyla ünlüdür. Sular altında kalan eski Halfeti ve gül bahçeleri, ziyaretçilere huzurlu bir atmosfer sunar.", "place_query": "Halfeti Tekne Turları, Halfeti, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '566f88f7-ca1b-4030-bd18-dd2687cc1f15'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Atatürk Barajı ve Hidroelektrik Santrali", "summary": "Dünyanın sayılı büyük barajlarından biri olan Atatürk Barajı, Bozova''nın hemen yanında yer alır. Devasa gövdesi ve etkileyici manzarasıyla ziyaretçilerine görsel bir şölen sunar; baraj gölünde tekne turları da yapılabilir.", "place_query": "Atatürk Barajı, Bozova, Şanlıurfa"}, {"title": "Halfeti Tekne Turu (Bozova Kıyıları)", "summary": "Bozova''nın baraj gölü kıyılarından başlayan tekne turları, sular altında kalan tarihi Halfeti''ye ve Rumkale''ye ulaşmanın en keyifli yoludur. Mavi yolculuk eşliğinde bölgenin eşsiz doğasını keşfedebilirsiniz.", "place_query": "Halfeti Tekne Turu, Bozova, Şanlıurfa"}, {"title": "Bozova Kalesi", "summary": "Bozova ilçe merkezinde yer alan tarihi kale, Fırat Nehri''ne hakim bir tepe üzerine kurulmuştur. Bölgenin stratejik önemini gözler önüne seren kale, özellikle gün batımında muhteşem bir manzara sunar.", "place_query": "Bozova Kalesi, Bozova, Şanlıurfa"}, {"title": "Fırat Nehri Kıyıları (Bozova)", "summary": "Bozova sınırları içinden geçen Fırat Nehri''nin yeşil ve mavinin buluştuğu kıyı şeridi, piknik ve doğa yürüyüşü için idealdir. Nehir kenarındaki mesire alanlarında huzurlu vakit geçirebilirsiniz.", "place_query": "Fırat Nehri, Bozova, Şanlıurfa"}, {"title": "Bozova İlçe Merkezi Tarihi Çarşı", "summary": "Bozova''nın eski çarşısı, yöresel el sanatları ve geleneksel Urfa lezzetlerini bulabileceğiniz otantik bir mekandır. Özellikle yöreye özgü baharatlar ve el dokuması ürünler ilgi çeker.", "place_query": "Bozova Çarşısı, Bozova, Şanlıurfa"}, {"title": "Bozova Mağaraları", "summary": "İlçe çevresinde bulunan doğal mağaralar, tarih öncesi dönemlerden beri yerleşim görmüş önemli alanlardır. Mağaralar, doğa sporları ve keşif meraklıları için ilgi çekici bir duraktır.", "place_query": "Bozova Mağaraları, Bozova, Şanlıurfa"}, {"title": "Bozova Mesire Alanı", "summary": "Baraj gölü kenarında yer alan mesire alanı, aileler ve doğa severler için ideal bir kaçış noktasıdır. Piknik masaları, yürüyüş yolları ve yeşil alanlarıyla huzurlu bir gün geçirebilirsiniz.", "place_query": "Bozova Mesire Alanı, Bozova, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'de13f999-e81f-4f83-bcc8-71d14bb03e1a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ceylanpınar Tarım İşletmesi (TİGEM)", "summary": "Türkiye''nin en büyük tarım işletmelerinden biri olan bu devasa alan, bozkırın ortasında adeta bir vaha gibidir. Ziyaretçiler burada modern tarım tekniklerini görebilir ve geniş arazilerde yapılan buğday, pamuk ekimini yerinde inceleyebilir.", "place_query": "Ceylanpınar TİGEM, Şanlıurfa"}, {"title": "Ceylanpınar Belediye Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenmek ve kısa bir yürüyüş yapmak için ideal bir noktadır. Özellikle akşam saatlerinde ailelerin uğrak yeri olan park, yeşil alanları ve sosyal tesisleriyle öne çıkar.", "place_query": "Ceylanpınar Belediye Parkı, Şanlıurfa"}, {"title": "Ceylanpınar Suriyeli Sığınmacı Kampı (Mevcut Durum)", "summary": "Bölgenin yakın tarihine tanıklık eden bu kamp alanı, insani yardım ve göç konularında farkındalık yaratmak isteyenler için anlamlı bir duraktır. Ziyaret öncesinde resmi izin ve güncel durumu kontrol etmek önemlidir.", "place_query": "Ceylanpınar Suriyeli Kampı, Şanlıurfa"}, {"title": "Ceylanpınar Kapalı Spor Salonu", "summary": "Modern bir spor kompleksi olan bu salon, ilçedeki sportif etkinliklerin ve turnuvaların merkezidir. Spor severler için hem izleme hem de aktif katılım imkanı sunar.", "place_query": "Ceylanpınar Kapalı Spor Salonu, Şanlıurfa"}, {"title": "Ceylanpınar Pazar Yeri (Halk Pazarı)", "summary": "Haftanın belirli günlerinde kurulan bu pazar, yöresel ürünleri ve taze meyve-sebzeleriyle ünlüdür. Ziyaretçiler, bölge halkının günlük yaşamına tanıklık ederken uygun fiyatlı alışveriş yapabilir.", "place_query": "Ceylanpınar Halk Pazarı, Şanlıurfa"}, {"title": "Ceylanpınar Devlet Hastanesi Çevresi", "summary": "İlçenin sağlık merkezi olmasının yanı sıra, hastanenin çevresinde bulunan küçük kafeler ve lokantalar, ziyaretçilere dinlenme ve yemek yeme imkanı sunar. Bölge, şehir hayatının nabzını tutan noktalardan biridir.", "place_query": "Ceylanpınar Devlet Hastanesi, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7b13ee4a-bb09-4fb3-a90c-57262d98928d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Balıklıgöl", "summary": "Şanlıurfa''nın en kutsal ve sembolik mekanı olan Balıklıgöl, Hz. İbrahim''in ateşe atıldığı yer olarak bilinir. İçindeki kutsal balıkları beslemek ve çevresindeki tarihi cami ile Hz. Eyüp Makamı''nı ziyaret etmek en popüler aktivitelerdendir.", "place_query": "Balıklıgöl, Eyyübiye, Şanlıurfa"}, {"title": "Göbeklitepe", "summary": "Dünyanın bilinen en eski tapınak kompleksi olan Göbeklitepe, 12.000 yıllık tarihiyle insanlık tarihine ışık tutar. T biçimli dikili taşları ve avlu yapılarıyla benzersiz bir arkeolojik alandır.", "place_query": "Göbeklitepe Örenyeri, Eyyübiye, Şanlıurfa"}, {"title": "Şanlıurfa Arkeoloji Müzesi", "summary": "Göbeklitepe ve Neolitik dönemden kalma eşsiz eserlerin sergilendiği bu modern müze, bölgenin zengin tarihini gözler önüne serer. Heykeller, mozaikler ve interaktif sergilerle ziyaretçilere unutulmaz bir deneyim sunar.", "place_query": "Şanlıurfa Arkeoloji Müzesi, Eyyübiye, Şanlıurfa"}, {"title": "Hz. Eyüp Makamı ve Mağarası", "summary": "Hz. Eyüp''ün hastalığına şifa bulduğu rivayet edilen bu kutsal mağara, hem yerli hem yabancı turistlerin uğrak noktasıdır. Mağaranın serin atmosferi ve çevresindeki ibadet alanları, manevi bir atmosfer sunar.", "place_query": "Hz. Eyüp Makamı, Eyyübiye, Şanlıurfa"}, {"title": "Urfa Kalesi", "summary": "Şehrin hakim bir tepesinde yer alan Urfa Kalesi, Roma ve Bizans dönemlerinden kalma surları ve iki sütunuyla dikkat çeker. Kaleden şehir manzarası izlemek ve tarihi atmosferi solumak mümkündür.", "place_query": "Urfa Kalesi, Eyyübiye, Şanlıurfa"}, {"title": "Rızvaniye Camii ve Külliyesi", "summary": "Balıklıgöl''ün hemen yanında bulunan bu Osmanlı dönemi camisi, zarif mimarisi ve avlusundaki havuzuyla huzur verir. Külliyenin içindeki medrese ve dükkanlar, geleneksel Urfa atmosferini yaşatır.", "place_query": "Rızvaniye Camii, Eyyübiye, Şanlıurfa"}, {"title": "Şanlıurfa Kapalı Çarşı", "summary": "Tarihi taş yapılar arasında uzanan bu kapalı çarşı, bakırcılık, baharat ve yöresel el sanatları ürünleriyle ünlüdür. Alışveriş yaparken Urfa''nın kadim ticaret kültürünü yakından deneyimleyebilirsiniz.", "place_query": "Şanlıurfa Kapalı Çarşı, Eyyübiye, Şanlıurfa"}, {"title": "Ayn Zeliha Gölü", "summary": "Balıklıgöl''ün hemen yanındaki bu küçük göl, Hz. İbrahim''in ateşe atıldığında Zeliha''nın gözyaşlarından oluştuğuna inanılır. Sakin ortamı ve yeşil çevresiyle dinlenmek için ideal bir noktadır.", "place_query": "Ayn Zeliha Gölü, Eyyübiye, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '568507e9-c790-451a-8979-f4c2b00a9748'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Halfeti Kalesi", "summary": "Fırat Nehri kıyısında yükselen tarihi bir kale olup, bölgenin en önemli simgelerindendir. Özellikle gün batımında nehir manzarası eşliğinde yapılan tekne turlarının vazgeçilmez durağıdır.", "place_query": "Halfeti Kalesi, Halfeti, Şanlıurfa"}, {"title": "Savaşan Köyü (Saklı Cennet)", "summary": "Birecik Barajı suları altında kalmasının ardından sadece evlerin çatılarının görülebildiği, eşsiz bir manzaraya sahip hayalet köydür. Tekneyle ulaşılan bu yer, fotoğrafçılar için eşsiz bir duraktır.", "place_query": "Savaşan Köyü, Halfeti, Şanlıurfa"}, {"title": "Halfeti Tekne Turu (Fırat Nehri)", "summary": "Nehir üzerinde yapılan bu turlar, sular altında kalan köyleri, tarihi Rumkale''yi ve eşsiz doğal güzellikleri görme imkanı sunar. Tur sırasında bölgenin meşhur siyah güllerini yakından gözlemleyebilirsiniz.", "place_query": "Halfeti Tekne Turu, Halfeti, Şanlıurfa"}, {"title": "Rumkale", "summary": "Fırat Nehri kıyısında sarp bir kaya üzerine kurulu bu tarihi kale, eşsiz konumuyla dikkat çeker. Tekneyle ulaşılan kale, hem tarihi hem de doğal güzellikleri bir arada sunar.", "place_query": "Rumkale, Halfeti, Şanlıurfa"}, {"title": "Halfeti Siyah Gül Bahçesi", "summary": "Sadece Halfeti''ye özgü olan ve dünyada başka bir yerde doğal olarak yetişmeyen siyah gülleri görmek için ideal bir noktadır. Bu eşsiz çiçek, bölgenin sembolü haline gelmiştir.", "place_query": "Halfeti Siyah Gül Bahçesi, Halfeti, Şanlıurfa"}, {"title": "Cumhuriyet Meydanı ve Tarihi Halfeti Evleri", "summary": "Yöresel taş mimarisinin en güzel örneklerini görebileceğiniz tarihi Halfeti evleri, meydan çevresinde sıralanmıştır. Dar sokaklarda yürüyüş yaparak bölgenin otantik atmosferini hissedebilirsiniz.", "place_query": "Cumhuriyet Meydanı, Halfeti, Şanlıurfa"}, {"title": "Halfeti Ulu Camii", "summary": "Tarihi taş işçiliğiyle dikkat çeken bu cami, Halfeti''nin en eski yapılarından biridir. Sade ve etkileyici mimarisiyle ziyaretçilerine huzurlu bir atmosfer sunar.", "place_query": "Halfeti Ulu Camii, Halfeti, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '329c8323-e1fc-4e4e-8b00-6614b0b85752'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şanlıurfa Arkeoloji Müzesi", "summary": "Dünyanın en eski tapınağı Göbeklitepe''den çıkarılan eserlerin sergilendiği bu modern müze, Neolitik dönemden günümüze uzanan zengin bir koleksiyon sunuyor. Ziyaretçiler, tarihin sıfır noktasına tanıklık eden eşsiz taş oymaları ve heykelleri yakından görebilir.", "place_query": "Şanlıurfa Arkeoloji Müzesi, Haliliye, Şanlıurfa"}, {"title": "Balıklıgöl", "summary": "Hz. İbrahim''in ateşe atıldığında düştüğü yer olarak kabul edilen bu kutsal göl, içindeki bereketli balıkları ve çevresindeki tarihi yapılarıyla şehrin en önemli sembolüdür. Ziyaretçiler, huzurlu atmosferde yürüyüş yapabilir ve çevredeki camileri gezebilir.", "place_query": "Balıklıgöl, Haliliye, Şanlıurfa"}, {"title": "Göbeklitepe Örenyeri", "summary": "MÖ 10.000 yılına tarihlenen ve insanlık tarihini yeniden yazan bu UNESCO Dünya Mirası alanı, dünyanın bilinen en eski anıtsal tapınak kompleksidir. T şeklindeki dikili taşlar ve üzerlerindeki hayvan kabartmaları, tarih öncesi insanın inanç sistemine ışık tutuyor.", "place_query": "Göbeklitepe Örenyeri, Haliliye, Şanlıurfa"}, {"title": "Rızvaniye Vakfı ve Ayn Zeliha Gölü", "summary": "Balıklıgöl''ün hemen yanında bulunan bu tarihi yapı, Osmanlı döneminden kalma zarif bir külliyedir. Ayn Zeliha Gölü ise Hz. İbrahim''in kızı Zeliha''nın gözyaşlarıyla oluştuğuna inanılan, balıklarıyla ünlü sakin bir göldür.", "place_query": "Rızvaniye Vakfı, Haliliye, Şanlıurfa"}, {"title": "Urfa Kalesi", "summary": "Şehrin tepesinde yer alan bu antik kale, iki büyük sütunu ve surlarıyla Şanlıurfa''nın simgelerindendir. Kaleye çıktığınızda Balıklıgöl ve çevresinin panoramik manzarası eşliğinde tarihi dokuyu hissedebilirsiniz.", "place_query": "Urfa Kalesi, Haliliye, Şanlıurfa"}, {"title": "Şanlıurfa Tarihi Çarşılar Bölgesi", "summary": "Kapalı çarşı, kazancılar çarşısı ve baharat çarşısı gibi geleneksel alışveriş noktalarını kapsayan bu bölge, Urfa''nın kültürel kalbidir. Bakırcı el sanatlarından yöresel lezzetlere kadar birçok otantik ürünü bulabilir, dar sokaklarda zamanda yolculuk yapabilirsiniz.", "place_query": "Tarihi Çarşılar Bölgesi, Haliliye, Şanlıurfa"}, {"title": "Hz. Eyüp Makamı ve Sabır Deresi", "summary": "Hz. Eyüp''ün hastalığı sırasında sığındığı mağara ve şifa bulduğu kutsal su kaynağı olarak bilinen bu yer, manevi bir atmosfere sahiptir. Ziyaretçiler, Sabır Deresi''nde yürüyüş yapabilir ve makamda dua edebilir.", "place_query": "Hz. Eyüp Makamı, Haliliye, Şanlıurfa"}, {"title": "Mevlid-i Halil Camii (Dergah Camii)", "summary": "Hz. İbrahim''in doğduğu mağara üzerine inşa edilen bu cami, Müslümanlar için önemli bir ziyaret noktasıdır. Mağaranın içindeki kutsal alanı görmek ve caminin etkileyici mimarisini keşfetmek için sıkça ziyaret edilir.", "place_query": "Mevlid-i Halil Camii, Haliliye, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'af126edf-1c3a-4d6c-9b16-cdf256a0877a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Harran Antik Kenti ve Örenyeri", "summary": "Dünyanın en eski sürekli yerleşimlerinden biri olan Harran Antik Kenti, konik kubbeli kerpiç evleri ve tarihi kalıntılarıyla ünlüdür. Ziyaretçiler, antik kentin surlarını, Ulu Camii''yi ve meşhur Harran Kümbet Evleri''ni görebilir.", "place_query": "Harran Antik Kenti, Harran, Şanlıurfa"}, {"title": "Harran Kümbet Evleri (Konik Kubbeli Evler)", "summary": "Harran''ın simgesi haline gelmiş bu kerpiç evler, eşsiz konik kubbeleriyle dikkat çeker. Binlerce yıllık bir mimari geleneğin yaşayan örneği olan bu yapılar, fotoğrafçılar için vazgeçilmez bir duraktır.", "place_query": "Harran Kümbet Evleri, Harran, Şanlıurfa"}, {"title": "Harran Ulu Camii", "summary": "Harran''ın tarihi merkezinde yer alan Ulu Camii, 8. yüzyılda inşa edilmiş olup, günümüze ulaşan yüksek minaresi ve geniş avlusuyla dikkat çeker. Bölgenin en eski İslami yapılarından biridir.", "place_query": "Harran Ulu Camii, Harran, Şanlıurfa"}, {"title": "Harran Kalesi", "summary": "Antik kentin hemen yanı başında yükselen Harran Kalesi, stratejik konumu ve etkileyici sur duvarlarıyla tarihe tanıklık eder. Kalenin tepesinden Harran Ovası''nın panoramik manzarası izlenebilir.", "place_query": "Harran Kalesi, Harran, Şanlıurfa"}, {"title": "Bazda Mağaraları", "summary": "Harran''a yaklaşık 10 km uzaklıkta bulunan Bazda Mağaraları, antik dönemlerde taş ocağı olarak kullanılmış devasa yeraltı odalarıdır. Mistik atmosferi ve serin havasıyla keşfedilmeyi bekleyen doğal bir oluşumdur.", "place_query": "Bazda Mağaraları, Harran, Şanlıurfa"}, {"title": "Harran Müzesi", "summary": "Harran Antik Kenti''nde bulunan küçük müze, bölgede yapılan kazılarda ortaya çıkarılan çivi yazılı tabletler, heykeller ve günlük kullanım eşyalarını sergiler. Tarih meraklıları için zengin bir duraktır.", "place_query": "Harran Müzesi, Harran, Şanlıurfa"}, {"title": "Göbeklitepe (Harran''a Yakın Konum)", "summary": "Harran''a yaklaşık 40 km mesafedeki Göbeklitepe, insanlık tarihinin bilinen en eski tapınak kompleksidir. UNESCO Dünya Mirası Listesi''nde yer alan bu eşsiz arkeolojik alan, Harran ziyaretine mutlaka eklenmelidir.", "place_query": "Göbeklitepe Örenyeri, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7269e24e-141e-455b-92c5-5d253e859afb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hilvan Kalesi", "summary": "İlçe merkezine hakim bir tepede yer alan tarihi kale, bölgenin stratejik önemini ve geçmişini yansıtan etkileyici bir yapıdır. Ziyaretçiler buradan Hilvan ve çevresinin panoramik manzarasını izleyebilir.", "place_query": "Hilvan Kalesi, Hilvan, Şanlıurfa"}, {"title": "Atatürk Barajı (Hilvan Kıyıları)", "summary": "Türkiye''nin en büyük barajlarından biri olan Atatürk Barajı''nın Hilvan sınırları içinde kalan kıyı şeridi, doğal güzelliği ve su sporlarına elverişli alanlarıyla dikkat çeker. Piknik ve dinlenme için ideal bir noktadır.", "place_query": "Atatürk Barajı Hilvan kıyıları, Şanlıurfa"}, {"title": "Hilvan Ulu Camii", "summary": "İlçenin en önemli tarihi ibadet yapılarından biri olan cami, mimari özellikleri ve manevi atmosferiyle ziyaretçilerini ağırlar. Özellikle ramazan aylarında yoğun ilgi görmektedir.", "place_query": "Hilvan Ulu Camii, Hilvan, Şanlıurfa"}, {"title": "Hilvan Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgede yapılan arkeolojik kazılardan çıkarılan eserleri sergiler. Hilvan ve çevresinin tarihine ışık tutan önemli bir kültür durağıdır.", "place_query": "Hilvan Müzesi, Hilvan, Şanlıurfa"}, {"title": "Karakoyun Deresi ve Mesire Alanı", "summary": "Doğal bir vadi içerisinde akan dere çevresinde düzenlenmiş mesire alanı, özellikle bahar aylarında yeşilin ve suyun tadını çıkarmak isteyenler için popüler bir kaçış noktasıdır. Ailece piknik yapmak için uygundur.", "place_query": "Karakoyun Deresi, Hilvan, Şanlıurfa"}, {"title": "Hilvan Çarşısı", "summary": "Yöresel ürünlerin, el sanatlarının ve günlük ihtiyaçların satıldığı canlı bir pazar yeridir. Ziyaretçiler burada Şanlıurfa''ya özgü baharat, dokuma ve hediyelik eşyaları bulabilir.", "place_query": "Hilvan Çarşısı, Hilvan, Şanlıurfa"}, {"title": "Sırrın Barajı", "summary": "Hilvan ilçe merkezine yaklaşık 20 km mesafede bulunan bu baraj, sakin suyu ve çevresindeki doğal alanlarla huzurlu bir atmosfer sunar. Balık tutma ve doğa yürüyüşü için tercih edilir.", "place_query": "Sırrın Barajı, Hilvan, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4371981b-fd05-4a51-af8a-1c42063ef712'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızılkoyun Mağaraları", "summary": "Karaköprü''de yer alan bu tarihi mağaralar, Roma dönemine ait kaya mezarları ve yer altı yapılarıyla dikkat çeker. Ziyaretçiler, antik dönem yaşamına dair izleri görebilir ve bölgenin tarihi dokusunu keşfedebilir.", "place_query": "Kızılkoyun Mağaraları, Karaköprü, Şanlıurfa"}, {"title": "Karaköprü Kent Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve göletiyle şehrin popüler dinlenme noktalarından biridir. Aileler ve doğa severler için huzurlu bir kaçış sunar.", "place_query": "Karaköprü Kent Parkı, Karaköprü, Şanlıurfa"}, {"title": "Karaköprü Belediyesi Kültür ve Kongre Merkezi", "summary": "Modern mimarisi ve çok amaçlı salonlarıyla bölgenin kültürel etkinliklerine ev sahipliği yapar. Konser, sergi ve konferans gibi organizasyonlara katılmak isteyenler için ideal bir mekandır.", "place_query": "Karaköprü Belediyesi Kültür ve Kongre Merkezi, Karaköprü, Şanlıurfa"}, {"title": "Göbeklitepe", "summary": "Karaköprü''ye yaklaşık 20 km mesafede bulunan bu UNESCO Dünya Mirası alanı, insanlık tarihinin bilinen en eski tapınak kompleksidir. MÖ 10.000 yılına tarihlenen yapılar, arkeoloji meraklıları için eşsiz bir deneyim sunar.", "place_query": "Göbeklitepe, Örencik, Şanlıurfa"}, {"title": "Şanlıurfa Arkeoloji Müzesi", "summary": "Karaköprü''den kısa bir araç yolculuğuyla ulaşılabilen müze, Göbeklitepe''den çıkarılan eserler de dahil olmak üzere geniş bir koleksiyona sahiptir. Tarih öncesi dönemden İslami döneme kadar uzanan zengin sergileriyle dikkat çeker.", "place_query": "Şanlıurfa Arkeoloji Müzesi, Şanlıurfa Merkez"}, {"title": "Balıklıgöl", "summary": "Karaköprü''ye yakın konumdaki bu kutsal alan, Hz. İbrahim''in ateşe atıldığı yer olarak bilinir ve içindeki balıklarla ünlüdür. Tarihi camileri ve huzur veren atmosferiyle hem dini hem de turistik bir merkezdir.", "place_query": "Balıklıgöl, Şanlıurfa Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'aa64cec1-bd3f-4817-9ffe-d926fd61b6b8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Siverek Kalesi", "summary": "Şehrin simgelerinden olan bu tarihi kale, Siverek''in ortasında yükselir ve çevresine hakim bir manzara sunar. Ziyaretçiler, bölgenin antik dönemlerine tanıklık eden bu yapıda tarihi atmosferi soluyabilir.", "place_query": "Siverek Kalesi, Siverek, Şanlıurfa"}, {"title": "Karabahçe Köyü ve Karabahçe Mağaraları", "summary": "Doğal kaya oluşumları ve tarihi mağaralarıyla ünlü bu köy, doğa yürüyüşleri ve keşif için idealdir. Mağaralar, geçmişte yerleşim yeri olarak kullanılmış olup etkileyici bir görüntü sunar.", "place_query": "Karabahçe Köyü, Siverek, Şanlıurfa"}, {"title": "Siverek Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, şehrin en önemli dini yapılarından biridir. Taş işçiliği ve sade iç mekanıyla huzurlu bir atmosfer sunar.", "place_query": "Siverek Ulu Camii, Siverek, Şanlıurfa"}, {"title": "Atatürk Barajı (Siverek Kıyıları)", "summary": "Türkiye''nin en büyük baraj göllerinden biri olan Atatürk Barajı''nın Siverek kıyıları, piknik alanları ve su sporları imkanı sunar. Özellikle gün batımında muhteşem manzaralar izlenebilir.", "place_query": "Atatürk Barajı, Siverek, Şanlıurfa"}, {"title": "Siverek Çarşısı ve Tarihi Hanlar", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu hareketli çarşı, Siverek''in kültürel dokusunu yansıtır. Tarihi hanlar ise geçmişte tüccarların konakladığı, günümüzde ise çay bahçeleriyle canlı mekanlardır.", "place_query": "Siverek Çarşısı, Siverek, Şanlıurfa"}, {"title": "Karahantepe (Siverek Yakınları)", "summary": "Göbeklitepe ile çağdaş olan bu önemli arkeolojik alan, Siverek sınırları içinde yer alır. Neolitik döneme ait dikili taşlar ve yapı kalıntıları, insanlık tarihine ışık tutar.", "place_query": "Karahantepe, Siverek, Şanlıurfa"}, {"title": "Siverek Müzesi", "summary": "Bölgedeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği müze, Siverek ve çevresinin zengin tarihini gözler önüne serer. Hitit, Roma ve İslam dönemlerine ait objeler dikkat çeker.", "place_query": "Siverek Müzesi, Siverek, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c38ba411-11f6-4602-969f-3c6f1368ab2c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Suruç Kalesi", "summary": "Tarihi bir kale olup bölgenin önemli simgelerindendir. Ziyaretçiler, kaleyi gezerek tarihi atmosferi soluyabilir ve çevredeki manzarayı seyredebilir.", "place_query": "Suruç Kalesi, Suruç, Şanlıurfa"}, {"title": "Suruç Ulu Camii", "summary": "Şehrin merkezinde yer alan tarihi bir camidir. Mimarisi ve manevi atmosferi ile ziyaretçilerin ilgisini çeker.", "place_query": "Suruç Ulu Camii, Suruç, Şanlıurfa"}, {"title": "Çobanbey Köprüsü", "summary": "Tarihi bir taş köprü olup, bölgenin geçmişine ışık tutar. Fotoğrafçılar ve tarih meraklıları için ideal bir duraktır.", "place_query": "Çobanbey Köprüsü, Suruç, Şanlıurfa"}, {"title": "Suruç Müzesi", "summary": "Küçük ama zengin bir müze olup, yöreye ait arkeolojik ve etnografik eserleri sergiler. Tarihe ilgi duyanlar için görülmeye değerdir.", "place_query": "Suruç Müzesi, Suruç, Şanlıurfa"}, {"title": "Göksu Çayı (Suruç Kesimi)", "summary": "Doğal güzelliği ile bilinen bir akarsudur. Piknik yapmak veya doğa yürüyüşü için tercih edilen sakin bir alandır.", "place_query": "Göksu Çayı, Suruç, Şanlıurfa"}, {"title": "Suruç Kapalı Çarşısı", "summary": "Yöresel ürünler ve el sanatlarının satıldığı tarihi bir çarşıdır. Alışveriş yaparken bölgenin kültürünü yakından tanıma fırsatı sunar.", "place_query": "Suruç Kapalı Çarşısı, Suruç, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5d612c47-f5b6-4bc3-b759-1b01390982a9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Viranşehir Kalesi", "summary": "Şehrin simgesi olan tarihi kale, bölgenin stratejik önemini gösteren kalıntıları ve geniş ova manzarasıyla ziyaretçilerine tarihi bir atmosfer sunar.", "place_query": "Viranşehir Kalesi, Viranşehir, Şanlıurfa"}, {"title": "Söğütlük Parkı", "summary": "Viranşehir''in en büyük yeşil alanlarından biri olan park, geniş çim alanları, yürüyüş yolları ve dinlenme alanlarıyla aileler için popüler bir kaçış noktasıdır.", "place_query": "Söğütlük Parkı, Viranşehir, Şanlıurfa"}, {"title": "Viranşehir Merkez Ulu Camii", "summary": "Modern ve geleneksel mimarinin harmanlandığı bu büyük cami, şehrin en önemli ibadet ve ziyaret mekanlarından biridir.", "place_query": "Viranşehir Merkez Ulu Camii, Viranşehir, Şanlıurfa"}, {"title": "Viranşehir Müzesi", "summary": "Bölgedeki arkeolojik kazılardan çıkarılan eserlerin sergilendiği müze, Viranşehir ve çevresinin binlerce yıllık tarihine ışık tutmaktadır.", "place_query": "Viranşehir Müzesi, Viranşehir, Şanlıurfa"}, {"title": "Harran Antik Kenti", "summary": "Viranşehir''e yaklaşık 40 km uzaklıktaki bu antik kent, konik kubbeli evleri ve dünyanın en eski yerleşimlerinden biri olmasıyla ünlüdür.", "place_query": "Harran Antik Kenti, Harran, Şanlıurfa"}, {"title": "Tek Tek Dağları Milli Parkı", "summary": "Viranşehir sınırları içinde yer alan bu milli park, eşsiz kaya oluşumları, mağaraları ve zengin bitki örtüsüyle doğa yürüyüşü sevenler için ideal bir rotadır.", "place_query": "Tek Tek Dağları Milli Parkı, Viranşehir, Şanlıurfa"}, {"title": "Kızılkoyun Nekropolü", "summary": "Viranşehir merkezde bulunan bu tarihi mezarlık alanı, Roma dönemine ait kaya mezarları ve lahitleriyle dikkat çeken önemli bir arkeolojik sit alanıdır.", "place_query": "Kızılkoyun Nekropolü, Viranşehir, Şanlıurfa"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1d2f9897-fc0e-4641-a30d-4b13fe9feb8c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Siirt Baykan Ziyaret (Selahaddin Eyyubi) Türbesi", "summary": "Baykan ilçesinin en önemli tarihi ve manevi merkezlerinden biridir. Selahaddin Eyyubi''nin babası olduğuna inanılan Necmeddin Eyyub''a ait türbe, hem yerli hem de yabancı ziyaretçiler tarafından sıkça ziyaret edilmektedir.", "place_query": "Selahaddin Eyyubi Türbesi, Baykan, Siirt"}, {"title": "Veysel Karani Türbesi ve Camii", "summary": "Baykan''a bağlı Ziyaret köyünde bulunan bu manevi mekan, İslam tarihinin önemli sahabelerinden Veysel Karani''ye atfedilmektedir. Her yıl yüz binlerce kişinin ziyaret ettiği bu yer, huzur veren atmosferiyle öne çıkar.", "place_query": "Veysel Karani Türbesi, Baykan, Siirt"}, {"title": "Siirt Baykan Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin stratejik önemini gözler önüne serer. Kaleye çıktığınızda Baykan Ovası''nın muhteşem manzarasını izleyebilirsiniz.", "place_query": "Baykan Kalesi, Baykan, Siirt"}, {"title": "Billoris Mağarası", "summary": "Baykan ilçesine bağlı Billoris köyünde yer alan bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Doğa yürüyüşü ve mağara keşfi yapmak isteyenler için ideal bir noktadır.", "place_query": "Billoris Mağarası, Baykan, Siirt"}, {"title": "Baykan Çayı ve Mesire Alanları", "summary": "Baykan Çayı çevresinde yer alan piknik ve mesire alanları, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popülerdir. Aileler için huzurlu bir kaçış noktasıdır.", "place_query": "Baykan Çayı, Baykan, Siirt"}, {"title": "Taşköprü (Baykan)", "summary": "Tarihi bir Osmanlı dönemi köprüsü olan Taşköprü, Baykan ilçesinden geçen önemli bir kültürel mirastır. Mimarisi ve çevresindeki doğal güzelliklerle fotoğrafçılar için güzel kareler sunar.", "place_query": "Taşköprü, Baykan, Siirt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5efc4c08-cb2f-4b66-ba4c-7b6bd5f64480'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eruh Şelalesi", "summary": "Eruh ilçe merkezine yakın bir konumda bulunan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popüler bir duraktır.", "place_query": "Eruh Şelalesi, Eruh, Siirt"}, {"title": "Küpeli Mağarası", "summary": "Eruh sınırları içinde yer alan bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker ve macera arayan ziyaretçiler için keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "Küpeli Mağarası, Eruh, Siirt"}, {"title": "Rüstem Paşa Camii", "summary": "Eruh ilçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisini yansıtan sade ama etkileyici yapısıyla yerli halk ve ziyaretçiler tarafından ilgi görmektedir.", "place_query": "Rüstem Paşa Camii, Eruh, Siirt"}, {"title": "Eruh Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan bu tarihi kale kalıntıları, bölgenin stratejik önemini ve geçmişine dair izleri gözler önüne serer.", "place_query": "Eruh Kalesi, Eruh, Siirt"}, {"title": "Bisbin (Bısbın) Yaylası", "summary": "Eruh''un yüksek kesimlerinde bulunan bu yayla, yemyeşil doğası, temiz havası ve geleneksel yayla yaşamını deneyimlemek isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Bisbin Yaylası, Eruh, Siirt"}, {"title": "Şeyh Nuh Türbesi", "summary": "Eruh''ta bulunan bu türbe, bölge halkı için manevi bir öneme sahiptir ve özellikle dini ziyaretler için sıkça uğranan bir mekandır.", "place_query": "Şeyh Nuh Türbesi, Eruh, Siirt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0ab1d14d-1504-4f36-b2cb-639e61dd1564'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kurtalan Kalesi", "summary": "Tarihi bir höyük üzerine kurulu olan kale, bölgenin en eski yerleşim izlerini taşır ve çevresine hakim manzarasıyla ziyaretçileri etkiler.", "place_query": "Kurtalan Kalesi, Kurtalan, Siirt"}, {"title": "Mor Yuhanna (Mar Yuhanna) Kilisesi", "summary": "Süryani mirasını yansıtan tarihi bir kilise olup, taş işçiliği ve dini atmosferiyle dikkat çeker.", "place_query": "Mor Yuhanna Kilisesi, Kurtalan, Siirt"}, {"title": "Kurtalan Müzesi", "summary": "Yöreye ait arkeolojik ve etnografik eserlerin sergilendiği müze, bölge tarihine ışık tutar.", "place_query": "Kurtalan Müzesi, Kurtalan, Siirt"}, {"title": "Kurtalan Çayı Kenarı Mesire Alanı", "summary": "Doğal bitki örtüsü ve akarsu boyunca uzanan piknik alanlarıyla halkın hafta sonu kaçış noktasıdır.", "place_query": "Kurtalan Çayı Mesire Alanı, Kurtalan, Siirt"}, {"title": "Kurtalan Eski Hamam", "summary": "Osmanlı dönemine ait tarihi bir hamam olup, mimari yapısıyla geçmişe yolculuk yapma fırsatı sunar.", "place_query": "Kurtalan Eski Hamam, Kurtalan, Siirt"}, {"title": "Dolunay Mağarası", "summary": "Doğal oluşumu ve içindeki sarkıt-dikitleriyle mağara turizmine ilgi duyanlar için keşfedilmeyi bekleyen bir noktadır.", "place_query": "Dolunay Mağarası, Kurtalan, Siirt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0b5d5bd0-80ce-407f-99d1-75c4056867c0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Siirt Ulu Camii", "summary": "Selçuklu dönemine ait bu tarihi cami, kesme taş işçiliği ve mimarisiyle dikkat çeker. Şehrin en eski yapılarından biri olup, özellikle minaresi ve iç süslemeleriyle ziyaretçileri büyüler.", "place_query": "Siirt Ulu Camii, Merkez, Siirt"}, {"title": "Tillo (Aydınlar) İlçesi", "summary": "Siirt''e 10 km uzaklıktaki bu tarihi ilçe, İslam alimleri ve türbeleriyle ünlüdür. İbrahim Hakkı ve İsmail Fakirullah''ın türbeleri, eşsiz gün doğumu manzarası ve taş evleriyle manevi bir atmosfer sunar.", "place_query": "Tillo, Aydınlar, Siirt"}, {"title": "İsmail Fakirullah Türbesi ve Işık Olayı", "summary": "Tillo''da bulunan bu türbe, her yıl 21 Mart''ta güneş ışınlarının özel bir düzenekle türbeyi aydınlatmasıyla ünlüdür. İbrahim Hakkı''nın tasarladığı bu mühendislik harikası, bilim ve inancın buluştuğu eşsiz bir noktadır.", "place_query": "İsmail Fakirullah Türbesi, Tillo, Siirt"}, {"title": "Siirt Kalesi", "summary": "Şehir merkezinde yüksek bir tepe üzerinde yer alan tarihi kale, Siirt''in simgelerindendir. Kaleyi çevreleyen surlar ve buradan izlenebilen şehir manzarası, ziyaretçilere keyifli bir gezi imkanı sunar.", "place_query": "Siirt Kalesi, Merkez, Siirt"}, {"title": "Sultan Memet Cami (Kale Camii)", "summary": "Siirt Kalesi''nin eteklerinde bulunan bu cami, 17. yüzyılda inşa edilmiş olup, sade fakat etkileyici bir mimariye sahiptir. Tarihi dokusu ve huzurlu atmosferiyle şehrin önemli ibadet noktalarındandır.", "place_query": "Sultan Memet Cami, Merkez, Siirt"}, {"title": "Siirt Müzesi", "summary": "Bölgenin arkeolojik ve etnografik zenginliklerini sergileyen müze, Siirt ve çevresinde bulunan eserlerle doludur. Özellikle Urartu ve Osmanlı dönemine ait kalıntılar, tarih meraklıları için ilgi çekicidir.", "place_query": "Siirt Müzesi, Merkez, Siirt"}, {"title": "Botan Çayı Vadisi", "summary": "Siirt''i ikiye bölen Botan Çayı''nın çevresindeki bu vadi, doğal güzelliği ve piknik alanlarıyla bilinir. Özellikle bahar aylarında yeşilin her tonunu görebileceğiniz huzurlu bir kaçış noktasıdır.", "place_query": "Botan Çayı Vadisi, Siirt Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '729bd90c-57c5-4f27-8332-71fcb1542481'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pervari Kalesi", "summary": "İlçe merkezine hakim bir tepede yer alan tarihi kale, bölgenin stratejik önemini ve geçmişine dair izleri gözler önüne seriyor. Kaleye çıktığınızda Pervari ve çevresinin etkileyici manzarasını izleyebilirsiniz.", "place_query": "Pervari Kalesi, Siirt"}, {"title": "Botan Çayı Vadisi", "summary": "Pervari''nin içinden geçen Botan Çayı''nın oluşturduğu derin ve yeşil vadi, doğa yürüyüşleri ve fotoğrafçılık için muhteşem bir ortam sunar. Vadinin dik yamaçları ve berrak suyu görülmeye değerdir.", "place_query": "Botan Çayı, Pervari, Siirt"}, {"title": "Bilinmeyen Mağaralar (Pervari Mağaraları)", "summary": "Pervari çevresinde keşfedilmeyi bekleyen birçok doğal mağara bulunur. Bu mağaralar, jeolojik yapıları ve gizemli atmosferleriyle macera arayan ziyaretçiler için ilgi çekici noktalardır.", "place_query": "Pervari mağaraları, Siirt"}, {"title": "Pervari Yaylaları", "summary": "Özellikle yaz aylarında serinlemek ve doğayla iç içe olmak isteyenler için Pervari''nin yüksek kesimlerindeki yaylalar ideal bir kaçış noktasıdır. Yemyeşil çayırlar ve temiz hava eşliğinde huzur bulabilirsiniz.", "place_query": "Pervari yaylaları, Siirt"}, {"title": "Pervari Merkez Camii ve Çevresi", "summary": "İlçe merkezinde bulunan tarihi cami, yöresel mimari özellikleri taşır ve çevresindeki eski çarşı dokusuyla birlikte ziyaret edilebilir. Bölgenin kültürel ve dini hayatına dair ipuçları verir.", "place_query": "Pervari Merkez Camii, Siirt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3243cb5a-1556-4634-9e06-d073d1d4e17f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şirvan Merkez Camii", "summary": "Şirvan''ın merkezinde bulunan bu tarihi cami, yöresel mimari özellikleri ve huzurlu atmosferiyle ziyaretçilerin ilgisini çeker.", "place_query": "Şirvan Merkez Camii, Şirvan, Siirt"}, {"title": "Şirvan Kalesi", "summary": "İlçe merkezine hakim bir tepede yer alan bu tarihi kale kalıntıları, bölgenin zengin geçmişine tanıklık eder ve muhteşem bir manzara sunar.", "place_query": "Şirvan Kalesi, Şirvan, Siirt"}, {"title": "Billoris Vadisi", "summary": "Doğal güzelliği ve yemyeşil bitki örtüsüyle ünlü bu vadi, doğa yürüyüşleri ve piknik için idealdir; özellikle bahar aylarında büyüleyici bir manzaraya sahiptir.", "place_query": "Billoris Vadisi, Şirvan, Siirt"}, {"title": "Küçük Kızıldağ (Kızıldağ Tepesi)", "summary": "Bölgenin yüksek noktalarından biri olan bu tepe, eşsiz bir panoramik seyir imkanı sunar ve fotoğrafçılar için vazgeçilmez bir duraktır.", "place_query": "Küçük Kızıldağ, Şirvan, Siirt"}, {"title": "Şirvan Mesire Alanı", "summary": "Şehir merkezine yakın, ağaçlarla çevrili bu mesire alanı, aileler ve gruplar için dinlendirici bir kaçış noktasıdır; mangal ve piknik yapmaya uygundur.", "place_query": "Şirvan Mesire Alanı, Şirvan, Siirt"}, {"title": "Güneyce Köyü Tarihi Evleri", "summary": "Taş ve ahşap mimarisiyle dikkat çeken bu köy evleri, geleneksel Siirt yaşamını yansıtarak kültürel bir gezi imkanı sunar.", "place_query": "Güneyce Köyü, Şirvan, Siirt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '294d350b-4e24-4137-b78c-038656d9d979'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tillo İç Kale ve Ulu Camii", "summary": "Tillo''nun simgesi olan İç Kale, bölgenin tarihi dokusunu yansıtan surlar ve Ulu Camii ile ziyaretçilere eşsiz bir manzara sunar.", "place_query": "Tillo İç Kale ve Ulu Camii, Siirt"}, {"title": "Tillo Şelalesi", "summary": "Doğal güzelliği ve serin sularıyla ünlü Tillo Şelalesi, piknik ve doğa yürüyüşü için ideal bir kaçış noktasıdır.", "place_query": "Tillo Şelalesi, Siirt"}, {"title": "Zerzevan Kalesi", "summary": "Tillo''ya yakın konumdaki Zerzevan Kalesi, Roma dönemine ait kalıntıları ve etkileyici manzarasıyla tarih meraklılarının ilgisini çeker.", "place_query": "Zerzevan Kalesi, Siirt"}, {"title": "Tillo Mağarası", "summary": "Doğal oluşumları ve mistik atmosferiyle Tillo Mağarası, keşif yapmak isteyenler için popüler bir duraktır.", "place_query": "Tillo Mağarası, Siirt"}, {"title": "Tillo Yaylası", "summary": "Yeşil doğası ve temiz havasıyla Tillo Yaylası, kamp ve doğa sporları için ideal bir mekandır.", "place_query": "Tillo Yaylası, Siirt"}, {"title": "Siirt İli Tillo İlçesi Tarihi Köprüler", "summary": "İlçe genelinde yer alan tarihi köprüler, Osmanlı ve Selçuklu mimarisinin izlerini taşıyarak fotoğrafçılar için harika kareler sunar.", "place_query": "Tillo Tarihi Köprüler, Siirt"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6d526769-7bd1-47e4-ab93-9bfdd763544d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ayancık Çamlığı Tabiat Parkı", "summary": "Muhteşem deniz manzarası ve zengin bitki örtüsüyle dikkat çeken bu tabiat parkı, piknik alanları ve yürüyüş parkurları ile doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Ayancık Çamlığı Tabiat Parkı, Ayancık, Sinop"}, {"title": "Çangal Ormanı", "summary": "Türkiye''nin en önemli oksijen depolarından biri olan Çangal Ormanı, endemik bitki türleri ve el değmemiş doğasıyla trekking ve doğa fotoğrafçılığı için eşsiz bir rotadır.", "place_query": "Çangal Ormanı, Ayancık, Sinop"}, {"title": "Ayancık Kilisesi", "summary": "19. yüzyıldan kalma tarihi bir Rum Ortodoks kilisesi olan yapı, kesme taş işçiliği ve dönemin mimari özelliklerini yansıtan detaylarıyla ziyaretçilerini geçmişe götürüyor.", "place_query": "Ayancık Kilisesi, Ayancık, Sinop"}, {"title": "İnaltı Mağarası", "summary": "Sarkıt ve dikitleriyle büyüleyici bir yer altı dünyası sunan İnaltı Mağarası, doğal oluşumları ve serin atmosferiyle keşfedilmeyi bekleyen bir doğa harikasıdır.", "place_query": "İnaltı Mağarası, Ayancık, Sinop"}, {"title": "Ayancık Sahili ve Plajları", "summary": "Karadeniz''in serin sularına kıyısı olan bu plajlar, sakin atmosferi ve doğal kumsallarıyla yaz aylarında yüzme ve güneşlenme keyfi sunar.", "place_query": "Ayancık Sahili, Ayancık, Sinop"}, {"title": "Yenikonak Yaylası", "summary": "Yeşilin her tonunu barındıran yayla, temiz havası, geleneksel yayla evleri ve muhteşem manzarasıyla doğa tutkunları için huzurlu bir duraktır.", "place_query": "Yenikonak Yaylası, Ayancık, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8ed473bc-6b94-4e72-b9df-54c6de8254eb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Boyabat Kalesi", "summary": "Görkemli bir tepe üzerinde yer alan bu tarihi kale, ilçenin simgesi haline gelmiştir. Helenistik dönemden izler taşıyan yapı, muhteşem Gökırmak Vadisi manzarası sunar.", "place_query": "Boyabat Kalesi, Boyabat, Sinop"}, {"title": "Gökırmak Vadisi", "summary": "Doğal güzellikleriyle ünlü bu vadi, yemyeşil doğası ve şırıl şırıl akan nehriyle huzur verici bir atmosfere sahiptir. Doğa yürüyüşleri ve piknik için ideal bir noktadır.", "place_query": "Gökırmak Vadisi, Boyabat, Sinop"}, {"title": "Boyabat Yıldızlı Tepe Seyir Terası", "summary": "Şehir merkezine hakim bir tepede konumlanan seyir terası, özellikle gün batımında Boyabat ve çevresinin panoramik fotoğraflarını çekmek için en popüler noktadır.", "place_query": "Yıldızlı Tepe Seyir Terası, Boyabat, Sinop"}, {"title": "Boyabat Kapalı Pazar Yeri", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu renkli pazar, ilçenin kültürel dokusunu yakından tanımak için harika bir duraktır. Özellikle haftalık kurulan pazar günleri oldukça canlıdır.", "place_query": "Boyabat Kapalı Pazar Yeri, Boyabat, Sinop"}, {"title": "Sarıağaç Yaylası", "summary": "Boyabat''a bağlı bu yayla, serin havası ve çam ormanlarıyla yaz aylarında kaçış noktasıdır. Doğa ile baş başa vakit geçirmek ve yayla şenliklerine katılmak için tercih edilir.", "place_query": "Sarıağaç Yaylası, Boyabat, Sinop"}, {"title": "Boyabat Müzesi", "summary": "İlçe merkezinde bulunan bu müze, bölgedeki arkeolojik kazılardan çıkarılan eserleri ve etnografik objeleri sergilemektedir. Tarih meraklıları için küçük ama değerli bir koleksiyon sunar.", "place_query": "Boyabat Müzesi, Boyabat, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd29eb989-e004-4b70-840e-dfd6759c2fcb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Dikmen Yaylası", "summary": "Sinop''un Dikmen ilçesinde yer alan bu yayla, doğal güzelliği ve temiz havasıyla ünlüdür. Özellikle yaz aylarında serinlemek ve doğa yürüyüşleri yapmak isteyenlerin uğrak noktasıdır.", "place_query": "Dikmen Yaylası, Dikmen, Sinop"}, {"title": "Dikmen Şelalesi", "summary": "İlçe merkezine yakın konumdaki şelale, yeşillikler arasında akan sularıyla huzur verici bir atmosfere sahiptir. Piknik ve fotoğrafçılık için ideal bir doğa harikasıdır.", "place_query": "Dikmen Şelalesi, Dikmen, Sinop"}, {"title": "Dikmen Kalesi", "summary": "Tarihi bir kalıntı olan Dikmen Kalesi, bölgenin geçmişine ışık tutar. Tepe üzerindeki konumu sayesinde çevreye hakim manzarasıyla ziyaretçilerini etkiler.", "place_query": "Dikmen Kalesi, Dikmen, Sinop"}, {"title": "Dikmen Göleti", "summary": "Doğayla iç içe bir ortam sunan gölet, balık tutma ve yürüyüş gibi aktiviteler için popülerdir. Sessiz ve sakin yapısıyla dinlenmek isteyenlerin tercihidir.", "place_query": "Dikmen Göleti, Dikmen, Sinop"}, {"title": "Dikmen Merkez Camii", "summary": "İlçenin tarihi camilerinden biri olan bu yapı, mimarisi ve manevi atmosferiyle dikkat çeker. Yöre halkı tarafından sıkça ziyaret edilen bir ibadet ve kültür noktasıdır.", "place_query": "Dikmen Merkez Camii, Dikmen, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '78a38618-7306-47db-9cfd-554eac6baa41'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Durağan Kaya Mezarları", "summary": "İlçe merkezine yakın konumda bulunan bu tarihi kaya mezarları, Helenistik ve Roma dönemlerine ait olup bölgenin antik tarihine ışık tutar. Ziyaretçiler, kayalara oyulmuş etkileyici mezar odalarını ve çevredeki doğal manzarayı görebilir.", "place_query": "Durağan Kaya Mezarları, Durağan, Sinop"}, {"title": "Durağan Şelalesi", "summary": "İlçenin en popüler doğal güzelliklerinden biri olan bu şelale, yemyeşil ormanlık alan içinde yer alır. Özellikle bahar ve yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için ideal bir noktadır.", "place_query": "Durağan Şelalesi, Durağan, Sinop"}, {"title": "Durağan Kalesi", "summary": "Tarihi bir kalıntı olan Durağan Kalesi, ilçeye hakim bir tepe üzerinde yer alır ve çevreye muhteşem bir manzara sunar. Kalenin geçmişi Bizans dönemine kadar uzanmakta olup, fotoğraf severler için harika bir duraktır.", "place_query": "Durağan Kalesi, Durağan, Sinop"}, {"title": "Gökçeören Köyü Tarihi Evleri", "summary": "Geleneksel Sinop mimarisinin güzel örneklerini barındıran bu köy, taş ve ahşap yapılarıyla dikkat çeker. Sakin atmosferi ve otantik dokusuyla kırsal bir kaçamak yapmak isteyenler için idealdir.", "place_query": "Gökçeören Köyü, Durağan, Sinop"}, {"title": "Kızılelma Yaylası", "summary": "Durağan''ın yüksek kesimlerinde yer alan bu yayla, temiz havası ve geniş çayırlarıyla ünlüdür. Yaylacılık geleneğini deneyimlemek ve doğa yürüyüşü yapmak için tercih edilen bir noktadır.", "place_query": "Kızılelma Yaylası, Durağan, Sinop"}, {"title": "Durağan Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de tarihi bir yapı olarak ziyaret edilebilir, özellikle ahşap işçiliği dikkat çeker.", "place_query": "Durağan Merkez Camii, Durağan, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5170ab29-55bd-49f5-9db2-4968e213fdd1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Erfelek Tatlıca Şelaleleri", "summary": "Doğal güzellikleriyle ünlü, birbirine bağlı 28 şelaleden oluşan bu doğa harikası, trekking ve fotoğrafçılık için ideal bir noktadır. Ziyaretçiler, yeşil ormanlar içinde yürüyüş yaparak serin suların keyfini çıkarabilir.", "place_query": "Erfelek Tatlıca Şelaleleri, Erfelek, Sinop"}, {"title": "İnaltı Mağarası", "summary": "Sarkıt ve dikitleriyle büyüleyici bir oluşuma sahip olan bu mağara, doğa severler için keşfedilmeyi bekleyen bir hazinedir. İçerideki yürüyüş yolları sayesinde ziyaretçiler rahatça gezebilir.", "place_query": "İnaltı Mağarası, Erfelek, Sinop"}, {"title": "Erfelek Barajı ve Mesire Alanı", "summary": "Piknik yapmak ve doğayla iç içe vakit geçirmek isteyenler için huzurlu bir ortam sunar. Baraj gölü manzarası eşliğinde yürüyüş yapabilir veya olta balıkçılığı deneyebilirsiniz.", "place_query": "Erfelek Barajı, Erfelek, Sinop"}, {"title": "Erfelek Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, bölgenin geçmişine ışık tutar ve çevresindeki doğal manzara ile etkileyici bir görüntü oluşturur. Tepeden Erfelek ve çevresini panoramik olarak izleyebilirsiniz.", "place_query": "Erfelek Kalesi, Erfelek, Sinop"}, {"title": "Sarıkum Gölü", "summary": "Kuş gözlemciliği ve doğa yürüyüşü için popüler bir sulak alan olan bu göl, birçok kuş türüne ev sahipliği yapar. Özellikle ilkbahar ve sonbahar aylarında ziyaretçilerine eşsiz bir deneyim sunar.", "place_query": "Sarıkum Gölü, Erfelek, Sinop"}, {"title": "Erfelek Yaylaları (Örneğin: Çangal Yaylası)", "summary": "Yemyeşil doğası ve temiz havasıyla yaylalar, şehir hayatından kaçmak isteyenler için harika bir kaçış noktasıdır. Yayla evlerinde konaklayabilir ve yöresel lezzetleri tadabilirsiniz.", "place_query": "Çangal Yaylası, Erfelek, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'de40196a-8a47-48b3-a795-4931dc98de97'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gerze Sahili ve İskele Meydanı", "summary": "Gerze''nin kalbi sayılan sahil şeridi, yürüyüş yapmak, deniz manzarası eşliğinde çay içmek ve balıkçı teknelerini izlemek için ideal bir noktadır. Özellikle akşam saatlerinde canlı bir atmosfere sahiptir.", "place_query": "Gerze Sahili, Sinop"}, {"title": "Gerze Kalesi", "summary": "Tarihi bir geçmişe sahip olan kale, şehre hakim bir tepede yer alır ve muhteşem bir deniz manzarası sunar. Ziyaretçiler için hem tarihi bir keşif hem de fotoğrafçılık açısından önemli bir duraktır.", "place_query": "Gerze Kalesi, Sinop"}, {"title": "Hamsilos Koyu", "summary": "Gerze''ye yaklaşık 20 km uzaklıkta bulunan bu benzersiz fiyort benzeri koy, yemyeşil doğası ve sakin deniziyle ünlüdür. Doğa ile baş başa kalmak ve yüzmenin tadını çıkarmak için en popüler yerlerden biridir.", "place_query": "Hamsilos Koyu, Sinop"}, {"title": "Sarıkum Tabiat Parkı ve Gölü", "summary": "Gerze sınırları içinde yer alan bu tabiat parkı, nadir bitki türleri ve kuş gözlemciliği için önemli bir alandır. Kumul yapısı, gölü ve ormanıyla eşsiz bir doğal güzellik sunar.", "place_query": "Sarıkum Tabiat Parkı, Gerze, Sinop"}, {"title": "Boyabat Kalesi", "summary": "Gerze''ye yaklaşık 40 km mesafedeki bu görkemli kale, Gökırmak Vadisi''ne hakim bir tepede yer alır. Helenistik dönemden kalma bu yapı, bölgenin en etkileyici tarihi eserlerinden biridir.", "place_query": "Boyabat Kalesi, Sinop"}, {"title": "İnaltı Mağarası", "summary": "Gerze ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu mağara, sarkıt ve dikitleriyle dikkat çeker. Doğal oluşumu ve serin atmosferiyle mağara turizmi sevenler için güzel bir keşif noktasıdır.", "place_query": "İnaltı Mağarası, Gerze, Sinop"}, {"title": "Gerze Müzesi", "summary": "İlçede bulunan bu küçük ama zengin müze, yöreye ait arkeolojik ve etnografik eserleri sergilemektedir. Bölgenin tarihine ve kültürüne dair kapsamlı bir bakış sunar.", "place_query": "Gerze Müzesi, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5bcdcbb4-f620-4a7a-8284-8108457df860'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sinop Kalesi", "summary": "Tarihi M.Ö. 7. yüzyıla kadar uzanan ve şehrin simgesi haline gelmiş bu görkemli kale, Karadeniz''in muhteşem manzarasına karşı konumlanmıştır. İçerisinde yer alan Tarihi Sinop Cezaevi ile birlikte ziyaretçilere eşsiz bir tarih ve kültür yolculuğu sunar.", "place_query": "Sinop Kalesi, Sinop Merkez"}, {"title": "Tarihi Sinop Cezaevi", "summary": "Ünlü şair ve yazarlara ev sahipliği yapmış, ''Anadolu''nun Alkatrazı'' olarak bilinen bu tarihi cezaevi, şimdi müze olarak hizmet vermektedir. Mahkum koğuşları, atölyeler ve etkileyici atmosferiyle ziyaretçileri geçmişe götürüyor.", "place_query": "Tarihi Sinop Cezaevi, Sinop Merkez"}, {"title": "Sinop Arkeoloji Müzesi", "summary": "Sinop ve çevresinde yapılan kazılarda ortaya çıkarılan Helenistik, Roma, Bizans ve Osmanlı dönemlerine ait zengin bir eser koleksiyonuna ev sahipliği yapmaktadır. Özellikle ''Sinoplu Diyojen''in heykeli ve antik dönem eserleri dikkat çekicidir.", "place_query": "Sinop Arkeoloji Müzesi, Sinop Merkez"}, {"title": "Erfelek Tatlıca Şelaleleri", "summary": "Sinop''un Erfelek ilçesinde yer alan ve 28 kademeli şelaleden oluşan bu doğa harikası, yemyeşil ormanlar içinde eşsiz bir yürüyüş ve piknik alanıdır. Şelalelerin serin suları ve doğal güzelliği, doğa severler için kaçırılmaz bir fırsattır.", "place_query": "Erfelek Tatlıca Şelaleleri, Sinop"}, {"title": "Hamsilos Koyu", "summary": "Karadeniz''in eşsiz doğal limanlarından biri olan ve ''Saklı Cennet'' olarak anılan Hamsilos Koyu, yemyeşil ormanların denizle kucaklaştığı büyüleyici bir koy. Sakin denizi ve doğal güzelliği ile yüzme, kamp ve doğa yürüyüşü için idealdir.", "place_query": "Hamsilos Koyu, Sinop Merkez"}, {"title": "İnaltı Mağarası", "summary": "Deniz seviyesinden 10 metre yükseklikte yer alan ve içerisinde sarkıt, dikit ve sütunların bulunduğu bu mağara, doğa turizmi için önemli bir noktadır. Mağaranın içindeki yürüyüş yolları ve aydınlatma sistemi sayesinde ziyaretçiler bu yer altı güzelliğini rahatça keşfedebilir.", "place_query": "İnaltı Mağarası, Sinop Merkez"}, {"title": "Akliman Plajı", "summary": "Sinop''un en popüler plajlarından biri olan Akliman, uzun kumsalı ve temiz deniziyle yaz aylarında yoğun ilgi görmektedir. Çevresindeki çam ormanları ve kamp alanlarıyla hem deniz hem de doğa tatili için mükemmel bir seçenektir.", "place_query": "Akliman Plajı, Sinop Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dfe837ed-23c9-495a-87d3-8578c9649eed'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saraydüzü Kanyonu", "summary": "Bölgenin en önemli doğal güzelliklerinden biri olan kanyon, yemyeşil doğası ve yürüyüş parkurlarıyla doğa severler için ideal bir rotadır.", "place_query": "Saraydüzü Kanyonu, Saraydüzü, Sinop"}, {"title": "Saraydüzü Şehitliği ve Anıtı", "summary": "Tarihi öneme sahip bu şehitlik, bölgeyi ziyaret edenler için manevi bir durak olup, çevresindeki düzenleme ile huzurlu bir ortam sunar.", "place_query": "Saraydüzü Şehitliği, Saraydüzü, Sinop"}, {"title": "Gölpınarı Yaylası", "summary": "Doğayla iç içe vakit geçirmek isteyenler için serin ve yeşil bir kaçış noktası olan yayla, piknik ve kamp için elverişlidir.", "place_query": "Gölpınarı Yaylası, Saraydüzü, Sinop"}, {"title": "Saraydüzü Merkez Camii", "summary": "İlçe merkezinde bulunan bu cami, Osmanlı dönemi mimarisinin izlerini taşıyan sade ve tarihi bir yapıdır.", "place_query": "Saraydüzü Merkez Camii, Saraydüzü, Sinop"}, {"title": "Kızılırmak Deltası Kuş Cenneti (Saraydüzü kesimi)", "summary": "Deltanın bu bölümü, kuş gözlemciliği ve doğa fotoğrafçılığı için zengin bir biyolojik çeşitlilik sunar; özellikle ilkbahar ve sonbaharda ziyaret edilir.", "place_query": "Kızılırmak Deltası Kuş Cenneti, Saraydüzü, Sinop"}, {"title": "Çamlıbel Yaylası", "summary": "Çam ormanlarıyla kaplı bu yayla, temiz havası ve doğal güzellikleriyle yürüyüş ve dinlenme için popüler bir mekandır.", "place_query": "Çamlıbel Yaylası, Saraydüzü, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c1e2ba58-a9d9-4831-a242-a78abb8fde3d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Türkeli Sahili ve Plajları", "summary": "Karadeniz''in serin sularına kıyısı olan Türkeli Sahili, özellikle yaz aylarında yerli halkın ve az sayıda turistin uğrak noktasıdır. Sakin denizi ve doğal kumsalıyla huzurlu bir yüzme ve dinlenme imkanı sunar.", "place_query": "Türkeli Sahili, Sinop"}, {"title": "Çaylı Köyü Şelalesi", "summary": "İlçe merkezine yaklaşık 15 km uzaklıkta, yeşillikler içinde gizlenmiş bu şelale, doğa yürüyüşü sevenler için ideal bir rotadır. Serin suları ve çevresindeki piknik alanıyla hafta sonu kaçamakları için popülerdir.", "place_query": "Çaylı Köyü Şelalesi, Türkeli, Sinop"}, {"title": "Hamsilos Koyu", "summary": "Türkeli sınırları içinde olmamakla birlikte ilçeye en yakın ve en ünlü doğal güzelliklerden biri olan Hamsilos Koyu, fiyort benzeri yapısıyla dikkat çeker. Tekne turları ve eşsiz manzarasıyla mutlaka görülmesi gereken bir yerdir.", "place_query": "Hamsilos Koyu, Sinop"}, {"title": "Türkeli Merkez Camii", "summary": "İlçenin simge yapılarından biri olan bu cami, Osmanlı dönemi mimarisinin izlerini taşır. Özellikle minaresi ve iç süslemeleriyle tarihi bir atmosfer sunar.", "place_query": "Türkeli Merkez Camii, Sinop"}, {"title": "Güzelkent Plajı", "summary": "Türkeli''ne bağlı Güzelkent beldesinde yer alan bu plaj, uzun kumsalı ve temiz deniziyle bilinir. Çevresindeki küçük restoran ve kafelerle keyifli bir gün geçirmek için idealdir.", "place_query": "Güzelkent Plajı, Türkeli, Sinop"}, {"title": "Türkeli Yaylaları (Örneğin: Dikmen Yaylası)", "summary": "İlçenin yüksek kesimlerinde bulunan yaylalar, yemyeşil doğası ve temiz havasıyla doğa turizmi için uygundur. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenler tarafından tercih edilir.", "place_query": "Dikmen Yaylası, Türkeli, Sinop"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '883c2ce9-e756-40e9-8a14-93f65340113d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cilo Dağı (Uludoruk Tepesi)", "summary": "Türkiye''nin en yüksek ikinci zirvesi olan Cilo Dağı, görkemli manzaraları ve buzullarıyla dağcılık ve doğa yürüyüşü tutkunlarının uğrak noktasıdır. Bölge, zorlu parkurları ve eşsiz doğasıyla macera arayanları kendine çeker.", "place_query": "Cilo Dağı, Beytüşşebap, Şırnak"}, {"title": "Beytüşşebap Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, yemyeşil doğa içinde serinletici bir kaçış noktasıdır. Özellikle yaz aylarında piknik ve doğa gezisi için tercih edilen popüler bir mekandır.", "place_query": "Beytüşşebap Şelalesi, Şırnak"}, {"title": "Kato Dağı", "summary": "Kato Dağı, zengin bitki örtüsü ve etkileyici kayalık yapısıyla doğa yürüyüşçüleri için ideal bir rotadır. Bölge, aynı zamanda endemik bitki türlerine ev sahipliği yapmasıyla da bilinir.", "place_query": "Kato Dağı, Beytüşşebap, Şırnak"}, {"title": "Beytüşşebap Ulu Camii", "summary": "Tarihi bir yapı olan bu cami, ilçenin merkezinde yer alır ve yöresel mimarinin güzel bir örneğidir. Ziyaretçiler, hem ibadet edebilir hem de tarihi dokuyu yakından görebilir.", "place_query": "Beytüşşebap Ulu Camii, Şırnak"}, {"title": "Ortabağ Köyü Yaylası", "summary": "Beytüşşebap''ın yüksek kesimlerinde bulunan bu yayla, tertemiz havası ve geniş otlaklarıyla huzur veren bir doğa kaçamağı sunar. Yaz aylarında yaylacılık kültürünü deneyimlemek için ideal bir yerdir.", "place_query": "Ortabağ Köyü Yaylası, Beytüşşebap, Şırnak"}, {"title": "Meydan Köyü Kaya Mezarları", "summary": "Bölgedeki tarihi kalıntılardan olan bu kaya mezarları, geçmiş uygarlıkların izlerini taşımaktadır. Tarih meraklıları için keşfedilmeyi bekleyen önemli bir arkeolojik alandır.", "place_query": "Meydan Köyü Kaya Mezarları, Beytüşşebap, Şırnak"}, {"title": "Beytüşşebap Merkez Çarşı", "summary": "İlçenin kalbindeki bu çarşı, yöresel ürünler ve el sanatlarını bulabileceğiniz canlı bir mekandır. Alışveriş yaparken bölgenin günlük yaşamına tanıklık edebilirsiniz.", "place_query": "Beytüşşebap Merkez Çarşı, Şırnak"}, {"title": "Meşhur Beytüşşebap Balı", "summary": "Beytüşşebap yöresine özgü bu doğal bal, zengin florası sayesinde eşsiz bir aromaya sahiptir. Bölgeyi ziyaret edenler için yerel üreticilerden taze bal almak popüler bir aktivitedir.", "place_query": "Beytüşşebap Balı, Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '17f57284-91d7-4b07-9337-bdf5af457967'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cizre Kalesi", "summary": "Dicle Nehri kıyısında yükselen tarihi kale, Cizre''nin simgesi olup bölgenin stratejik önemini gözler önüne serer. Kale içindeki yapılar ve nehir manzarası ziyaretçilere eşsiz bir atmosfer sunar.", "place_query": "Cizre Kalesi, Cizre, Şırnak"}, {"title": "Kırmızı Medrese (İsmail Ebul-İz Medresesi)", "summary": "Kırmızı tuğlalı mimarisiyle dikkat çeken bu tarihi medrese, Cizre''nin en önemli kültürel miraslarındandır. İslam bilim tarihinde önemli bir yere sahip olan Cezeri''nin eserlerine ev sahipliği yapmasıyla ünlüdür.", "place_query": "Kırmızı Medrese, Cizre, Şırnak"}, {"title": "Cizre Ulu Camii", "summary": "Selçuklu ve Artuklu dönemlerinden izler taşıyan bu tarihi cami, taş işçiliği ve süslemeleriyle dikkat çeker. Cizre''nin en eski ve en büyük camilerinden biri olarak ziyaretçilerini ağırlar.", "place_query": "Cizre Ulu Camii, Cizre, Şırnak"}, {"title": "Dicle Nehri Kenarı ve Mesire Alanı", "summary": "Cizre''nin ortasından geçen Dicle Nehri boyunca uzanan mesire alanı, piknik ve doğa yürüyüşleri için idealdir. Nehir kenarında huzurlu bir gün geçirmek isteyenler için popüler bir duraktır.", "place_query": "Dicle Nehri, Cizre, Şırnak"}, {"title": "Hz. Nuh Türbesi", "summary": "Cizre''de bulunan ve Hz. Nuh''a atfedilen bu türbe, inanç turizmi açısından büyük önem taşır. Bölgeye gelen birçok ziyaretçi tarafından ziyaret edilen kutsal bir mekandır.", "place_query": "Hz. Nuh Türbesi, Cizre, Şırnak"}, {"title": "Mem ü Zin Türbesi", "summary": "Kürt edebiyatının ünlü aşk hikayesi Mem ü Zin''in kahramanlarına ait olduğuna inanılan bu türbe, Cizre''nin kültürel simgelerindendir. Hikayesi ve mistik atmosferiyle ziyaretçileri cezbeder.", "place_query": "Mem ü Zin Türbesi, Cizre, Şırnak"}, {"title": "Abdaliye (Daliye) Köprüsü", "summary": "Tarihi bir taş köprü olan Abdaliye Köprüsü, Cizre''nin geçmişine tanıklık eden önemli bir yapıdır. Mimarisi ve çevresindeki doğal güzelliklerle fotoğrafçılar için ideal bir noktadır.", "place_query": "Abdaliye Köprüsü, Cizre, Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '11e94f6c-fe4c-4f5d-8a85-0fe0270dfefb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Güçlükonak Merkez Camii", "summary": "İlçe merkezinde yer alan bu cami, bölgenin dini ve kültürel hayatında önemli bir simgedir. Ziyaretçiler, sade mimarisi ve huzurlu atmosferiyle dikkat çeken bu yapıyı görebilirler.", "place_query": "Güçlükonak Merkez Camii, Şırnak"}, {"title": "Dicle Nehri Kıyıları", "summary": "Güçlükonak''tan geçen Dicle Nehri''nin kıyıları, doğal güzellikleri ve sakin yürüyüş alanlarıyla bilinir. Nehir kenarında piknik yapabilir veya manzaranın tadını çıkarabilirsiniz.", "place_query": "Dicle Nehri, Güçlükonak, Şırnak"}, {"title": "Güçlükonak Kalesi (Harabe)", "summary": "İlçe yakınlarında bulunan bu tarihi kale kalıntıları, bölgenin geçmişine ışık tutar. Tepeden çevreyi seyretmek için ideal bir noktadır.", "place_query": "Güçlükonak Kalesi, Şırnak"}, {"title": "Köprüler ve Tarihi Su Yapıları", "summary": "Güçlükonak çevresinde, özellikle kırsal alanlarda tarihi taş köprüler ve su kemerleri bulunur. Bu yapılar, fotoğrafçılık ve tarih meraklıları için keşfedilmeyi bekler.", "place_query": "Tarihi köprüler Güçlükonak, Şırnak"}, {"title": "Güçlükonak Yaylaları", "summary": "İlçenin yüksek kesimlerinde yer alan yaylalar, yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için popülerdir. Yürüyüş ve kamp için uygun alanlar sunar.", "place_query": "Güçlükonak yaylaları, Şırnak"}, {"title": "Cizre-Güçlükonak Karayolu Üzeri Seyir Noktaları", "summary": "Cizre ile Güçlükonak arasındaki karayolu boyunca Dicle Nehri ve dağ manzaralı seyir noktaları bulunur. Yolculuk sırasında kısa molalar vererek eşsiz manzaraları fotoğraflayabilirsiniz.", "place_query": "Cizre Güçlükonak yolu manzara, Şırnak"}, {"title": "Beytüşşebap Yolu Üzeri Tarihi Alanlar", "summary": "Güçlükonak''tan Beytüşşebap''a giden güzergahta, eski yerleşim kalıntıları ve mağaralar dikkat çeker. Doğa yürüyüşü sevenler için keşif rotası oluşturur.", "place_query": "Beytüşşebap yolu tarihi alanlar, Güçlükonak"}, {"title": "Güçlükonak Pazarı", "summary": "Haftalık kurulan ilçe pazarı, yöresel ürünler ve el sanatlarını bulabileceğiniz renkli bir alışveriş deneyimi sunar. Yerel halkla kaynaşmak için iyi bir fırsattır.", "place_query": "Güçlükonak pazar yeri, Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '985621ec-ece7-407f-a104-c02e2515129c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mor Malki Manastırı", "summary": "Tarihi bir Süryani manastırı olan Mor Malki, İdil''in en önemli dini ve kültürel miraslarından biridir. Taş işçiliği ve huzurlu atmosferiyle ziyaretçilerine eşsiz bir deneyim sunar.", "place_query": "Mor Malki Manastırı, İdil, Şırnak"}, {"title": "Mor Abrohom Manastırı", "summary": "İdil''in köklü Süryani tarihini yansıtan bu manastır, etkileyici mimarisi ve dini önemiyle dikkat çeker. Bölgeyi keşfedenler için görülmesi gereken bir duraktır.", "place_query": "Mor Abrohom Manastırı, İdil, Şırnak"}, {"title": "Dargeçit Kalesi", "summary": "İdil yakınlarındaki bu tarihi kale, bölgenin stratejik önemini ve geçmişini gözler önüne serer. Kalıntılar arasında yürürken eşsiz bir manzara eşliğinde tarihe tanıklık edebilirsiniz.", "place_query": "Dargeçit Kalesi, İdil, Şırnak"}, {"title": "İdil Ulu Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, geleneksel mimarisi ve huzur veren atmosferiyle bilinir. Ziyaretçilerin sıkça uğradığı manevi bir mekandır.", "place_query": "İdil Ulu Camii, İdil, Şırnak"}, {"title": "Cizre-İdil Yolu Üzerindeki Tarihi Köprüler", "summary": "İdil çevresindeki vadilerde bulunan eski taş köprüler, bölgenin tarihi ulaşım ağını yansıtır. Doğayla iç içe bu yapılar, fotoğraf severler için harika bir rotadır.", "place_query": "Tarihi köprüler, İdil, Şırnak"}, {"title": "İdil Çarşısı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı İdil Çarşısı, ziyaretçilere otantik bir alışveriş deneyimi sunar. Özellikle yöresel dokumalar ve baharatlar ilgi çeker.", "place_query": "İdil Çarşısı, İdil, Şırnak"}, {"title": "Habur Çayı Kenarı", "summary": "İdil''den geçen Habur Çayı''nın çevresi, piknik ve doğa yürüyüşü için popüler bir alandır. Sakin suları ve yeşil doğasıyla dinlenmek isteyenler için idealdir.", "place_query": "Habur Çayı, İdil, Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4182b468-d884-495b-9801-7f3d589d571c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şırnak Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin stratejik önemini gözler önüne seriyor. Kaleye çıktığınızda Şırnak''ın panoramik manzarasını izleyebilir, surlar arasında tarihi bir yolculuğa çıkabilirsiniz.", "place_query": "Şırnak Kalesi, Merkez, Şırnak"}, {"title": "Cizre İlçesi ve Ulu Camii", "summary": "Şırnak merkeze yakın Cizre ilçesinde bulunan tarihi Ulu Camii, Anadolu''nun en eski camilerinden biridir. Özellikle taş işçiliği ve mimari detaylarıyla ziyaretçileri büyüler.", "place_query": "Cizre Ulu Camii, Cizre, Şırnak"}, {"title": "Kasrik Boğazı", "summary": "Şırnak merkeze yaklaşık 20 km uzaklıkta bulunan bu doğal boğaz, Dicle Nehri''nin kıvrımları arasında muhteşem bir manzara sunar. Doğa yürüyüşü ve fotoğrafçılık için ideal bir noktadır.", "place_query": "Kasrik Boğazı, Merkez, Şırnak"}, {"title": "Şırnak Müzesi", "summary": "Şehir merkezinde yer alan müze, bölgedeki arkeolojik kazılardan çıkarılan eserleri ve yöresel etnografik objeleri sergiliyor. Bölge tarihine dair kapsamlı bilgi edinmek için mutlaka uğranmalı.", "place_query": "Şırnak Müzesi, Merkez, Şırnak"}, {"title": "Güçlükonak İlçesi ve Dicle Nehri Kenarı", "summary": "Merkeze bağlı Güçlükonak ilçesinden geçen Dicle Nehri kıyıları, piknik ve dinlenme alanlarıyla ünlüdür. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Güçlükonak, Dicle Nehri, Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5e60365e-7653-4c7b-b994-bcd82b04afd9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cizre-Silopi Yolu Üzerindeki Tarihi Köprüler", "summary": "Silopi çevresinde, özellikle Dicle Nehri kolları üzerinde bulunan tarihi taş köprüler, bölgenin eski medeniyetlerine ait izleri taşır. Ziyaretçiler, bu yapıların mimari güzelliklerini keşfedebilir ve nehir manzarasının tadını çıkarabilir.", "place_query": "Tarihi köprüler Silopi Şırnak"}, {"title": "Silopi Kapalı Çarşı", "summary": "Silopi''nin merkezinde yer alan bu kapalı çarşı, yöresel el sanatları, baharatlar ve tekstil ürünleriyle ünlüdür. Alışveriş yapmak ve bölgenin kültürel dokusunu hissetmek için ideal bir noktadır.", "place_query": "Silopi Kapalı Çarşı Şırnak"}, {"title": "Dicle Nehri Kıyıları", "summary": "Silopi''den geçen Dicle Nehri''nin kıyıları, piknik ve doğa yürüyüşü için popülerdir. Özellikle bahar aylarında yeşil doğası ve akarsu sesi eşliğinde huzurlu bir kaçamak sunar.", "place_query": "Dicle Nehri Silopi Şırnak"}, {"title": "Silopi Ulu Camii", "summary": "Modern mimariyle inşa edilmiş olan bu cami, Silopi''nin en büyük ibadethanesidir ve geniş avlusuyla dikkat çeker. Ziyaretçiler, caminin iç ve dış süslemelerini görebilir, manevi bir atmosfer yaşayabilir.", "place_query": "Silopi Ulu Camii Şırnak"}, {"title": "Kato Dağı Etekleri", "summary": "Silopi yakınlarındaki Kato Dağı''nın etekleri, doğa tutkunları için trekking ve kamp alanları sunar. Bölgenin zengin bitki örtüsü ve temiz havası, şehir hayatından uzaklaşmak isteyenler için idealdir.", "place_query": "Kato Dağı Silopi Şırnak"}, {"title": "Silopi Şelalesi", "summary": "İlçe merkezine kısa bir mesafede bulunan bu şelale, özellikle yaz aylarında serinlemek ve doğal güzellikleri fotoğraflamak için uğrak noktasıdır. Çevresindeki yeşil alanlar piknik için elverişlidir.", "place_query": "Silopi Şelalesi Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '318309bd-52c8-442f-b2dd-4cb85e345ee8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beyazsu (Beyaz Su) Mesire Alanı", "summary": "Uludere''nin en ünlü doğal güzelliklerinden biri olan Beyazsu, berrak ve soğuk sularıyla ünlüdür. Özellikle yaz aylarında piknik ve yüzme için yoğun ilgi gören bu alan, çevresindeki yemyeşil doğayla huzur verici bir atmosfer sunar.", "place_query": "Beyazsu Mesire Alanı, Uludere, Şırnak"}, {"title": "Cudi Dağı (Cudi Dağları)", "summary": "Nuh Tufanı''na ev sahipliği yaptığına inanılan Cudi Dağı, hem dini hem de doğal açıdan büyük öneme sahiptir. Dağcılık ve doğa yürüyüşü meraklıları için eşsiz rotalar sunan bu dağ, aynı zamanda muhteşem bir manzaraya sahiptir.", "place_query": "Cudi Dağı, Uludere, Şırnak"}, {"title": "Uludere Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, döküldüğü havuzu ve çevresindeki doğal bitki örtüsüyle görülmeye değerdir. Özellikle bahar aylarında suyun debisinin artmasıyla daha da etkileyici bir hale gelir.", "place_query": "Uludere Şelalesi, Uludere, Şırnak"}, {"title": "Kel Mehmet Kalesi", "summary": "Tarihi bir gözetleme kalesi olan Kel Mehmet Kalesi, Uludere''nin yüksek tepelerinden birinde yer alır. Kaleye çıktığınızda bölgenin panoramik manzarasını izleyebilir ve tarihi atmosferi hissedebilirsiniz.", "place_query": "Kel Mehmet Kalesi, Uludere, Şırnak"}, {"title": "Hani Harabesi (Hani Antik Kenti)", "summary": "Uludere sınırları içinde yer alan bu antik yerleşim, tarih öncesi dönemlere ait kalıntılarıyla dikkat çeker. Bölgenin zengin tarihine tanıklık etmek isteyenler için önemli bir durak noktasıdır.", "place_query": "Hani Harabesi, Uludere, Şırnak"}, {"title": "Şırnak Uludere Yaylaları (Örn: Merga Yaylası)", "summary": "Uludere''nin serin ve yeşil yaylaları, özellikle yaz aylarında şehir hayatından kaçmak isteyenler için idealdir. Yöresel kültürü yakından tanıma fırsatı bulacağınız bu yaylalarda doğa yürüyüşleri yapabilirsiniz.", "place_query": "Merga Yaylası, Uludere, Şırnak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4c8f6835-4990-4a85-baee-498db1f7ffa5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akıncılar Şelalesi", "summary": "Akıncılar ilçe merkezine yaklaşık 10 km uzaklıkta, doğal güzelliğiyle ünlü bir şelaledir. Çevresi piknik ve doğa yürüyüşü için idealdir, özellikle yaz aylarında serinlemek için ziyaret edilir.", "place_query": "Akıncılar Şelalesi, Akıncılar, Sivas"}, {"title": "Akıncılar Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir, bölgenin savunma yapılarından biridir. Kalıntıları günümüze ulaşan kale, tarih meraklıları için ilgi çekicidir.", "place_query": "Akıncılar Kalesi, Akıncılar, Sivas"}, {"title": "Aslanpınarı Mesire Alanı", "summary": "Akıncılar''a bağlı bir bölgede bulunan bu mesire alanı, yeşil doğası ve piknik olanaklarıyla bilinir. Aileler ve doğaseverler için huzurlu bir kaçış noktasıdır.", "place_query": "Aslanpınarı Mesire Alanı, Akıncılar, Sivas"}, {"title": "Karşıyaka Yaylası", "summary": "İlçenin yüksek kesimlerinde yer alan bu yayla, doğal bitki örtüsü ve temiz havasıyla ünlüdür. Yaz aylarında yaylacılar ve kampçılar için popüler bir duraktır.", "place_query": "Karşıyaka Yaylası, Akıncılar, Sivas"}, {"title": "Akıncılar Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi bir camidir, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de tarihi doku açısından ziyaret edilebilir.", "place_query": "Akıncılar Merkez Camii, Akıncılar, Sivas"}, {"title": "Sarıca Köyü Kaya Mezarları", "summary": "Akıncılar''a bağlı Sarıca Köyü''nde bulunan bu antik kaya mezarları, bölgenin tarih öncesi dönemlerine ışık tutar. Arkeoloji meraklıları için önemli bir duraktır.", "place_query": "Sarıca Köyü Kaya Mezarları, Akıncılar, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '288cf262-6278-4f86-b519-a2841110d1fa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kale Köyü (Divriği)", "summary": "Tarihi taş evleri ve dar sokaklarıyla ünlü bu köy, doğal güzellikleri ve huzurlu atmosferiyle ziyaretçilerine eşsiz bir deneyim sunar. Bölgenin en popüler kırsal turistik noktalarından biridir.", "place_query": "Kale Köyü, Divriği, Sivas"}, {"title": "Altınyayla Şelalesi", "summary": "Yemyeşil doğa içinde yer alan bu şelale, serin suları ve piknik alanlarıyla özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır. Doğa yürüyüşü ve fotoğrafçılık için idealdir.", "place_query": "Altınyayla Şelalesi, Sivas"}, {"title": "Tödürge Gölü", "summary": "Altınyayla ilçe merkezine yaklaşık 20 km mesafedeki bu doğal göl, kuş gözlemi ve doğa turizmi için popülerdir. Çevresindeki mesire alanlarıyla hafta sonu kaçamakları için tercih edilir.", "place_query": "Tödürge Gölü, Altınyayla, Sivas"}, {"title": "Altınyayla Merkez Camii", "summary": "Osmanlı dönemi mimarisinin izlerini taşıyan bu tarihi cami, ilçenin merkezinde yer alır ve sade ama etkileyici yapısıyla dikkat çeker. Ziyaretçiler için manevi bir durak noktasıdır.", "place_query": "Altınyayla Merkez Camii, Sivas"}, {"title": "Gürün Çamlığı Mesire Alanı", "summary": "Altınyayla''ya komşu Gürün ilçesinde bulunan bu geniş çam ormanı, piknik ve kamp yapmak isteyenler için ideal bir doğa kaçış noktasıdır. Temiz havası ve yürüyüş parkurlarıyla bilinir.", "place_query": "Gürün Çamlığı, Sivas"}, {"title": "Deliktaş Yaylası", "summary": "Yüksek rakımı ve serin iklimiyle yaz aylarında sıkça ziyaret edilen bu yayla, doğal güzellikleri ve geleneksel yayla şenlikleriyle ünlüdür. Doğa severler için keşfedilmeyi bekleyen bir rotadır.", "place_query": "Deliktaş Yaylası, Altınyayla, Sivas"}, {"title": "Altınyayla Kent Ormanı", "summary": "İlçe merkezine yakın konumdaki bu kent ormanı, yürüyüş yolları ve dinlenme alanlarıyla günübirlik ziyaretler için popülerdir. Şehir hayatından kaçmak isteyenler için huzurlu bir ortam sunar.", "place_query": "Altınyayla Kent Ormanı, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd3233f23-08f1-458c-8889-15220fb0f642'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Divriği Ulu Camii ve Darüşşifası", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu eşsiz yapı, Anadolu Selçuklu taş işçiliğinin en görkemli örneklerinden biridir. Muhteşem taç kapıları ve geometrik desenleriyle ziyaretçileri büyüler.", "place_query": "Divriği Ulu Camii ve Darüşşifası, Divriği, Sivas"}, {"title": "Divriği Kalesi", "summary": "Tarihi bir tepe üzerinde kurulu olan kale, Divriği''ye hakim bir manzara sunar. Bölgenin stratejik önemini gösteren kalıntıları ve çevresindeki doğal güzellikleri keşfedebilirsiniz.", "place_query": "Divriği Kalesi, Divriği, Sivas"}, {"title": "Çaltı Çayı ve Mesire Alanı", "summary": "Divriği''nin doğal güzelliklerinden biri olan Çaltı Çayı kenarı, piknik ve doğa yürüyüşü için idealdir. Serin suları ve yeşil doğasıyla huzurlu bir kaçış noktasıdır.", "place_query": "Çaltı Çayı Mesire Alanı, Divriği, Sivas"}, {"title": "Divriği Müzesi", "summary": "Yöresel tarih ve kültürü yansıtan eserlerin sergilendiği müze, Divriği''nin zengin geçmişine ışık tutar. Arkeolojik buluntular ve etnografik objeler görülmeye değerdir.", "place_query": "Divriği Müzesi, Divriği, Sivas"}, {"title": "Kesdoğan Köyü Kaya Mezarları", "summary": "Divriği yakınlarındaki bu antik kaya mezarları, Roma dönemine ait etkileyici yapılardır. Tarih meraklıları için keşfedilmeyi bekleyen önemli bir arkeolojik alandır.", "place_query": "Kesdoğan Köyü Kaya Mezarları, Divriği, Sivas"}, {"title": "Yukarı Çöplü Köyü Şelalesi", "summary": "Doğa severler için gizli bir cennet olan bu şelale, yemyeşil bir vadi içinde yer alır. Serinlemek ve doğanın tadını çıkarmak için ideal bir durak noktasıdır.", "place_query": "Yukarı Çöplü Köyü Şelalesi, Divriği, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cb3b618b-2699-4b6e-87a0-b5e96c63545e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Doğanşar Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin en önemli simgelerindendir. Kaleyi çevreleyen sur kalıntıları ve manzarası ziyaretçileri büyüler.", "place_query": "Doğanşar Kalesi, Doğanşar, Sivas"}, {"title": "Karasu Şelalesi", "summary": "Doğanşar''ın en popüler doğal güzelliklerinden biri olan şelale, yemyeşil doğa içinde serinletici bir kaçış noktası sunar. Piknik ve doğa yürüyüşü için idealdir.", "place_query": "Karasu Şelalesi, Doğanşar, Sivas"}, {"title": "Karşıyaka Yaylası", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü yayla, özellikle yaz aylarında doğa severlerin uğrak noktasıdır. Yöresel lezzetlerin tadılabileceği çadır ve karavan kampına uygundur.", "place_query": "Karşıyaka Yaylası, Doğanşar, Sivas"}, {"title": "Çatpınar Göleti", "summary": "Doğanşar merkeze yakın konumdaki bu gölet, huzurlu atmosferi ve çevresindeki piknik alanlarıyla aileler için popüler bir hafta sonu kaçamağıdır. Olta balıkçılığı da yapılabilir.", "place_query": "Çatpınar Göleti, Doğanşar, Sivas"}, {"title": "Doğanşar Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını yansıtan küçük ama etkileyici bir müzedir. Yöresel kıyafetler, el sanatları ve arkeolojik eserler sergilenmektedir.", "place_query": "Doğanşar Müzesi, Doğanşar, Sivas"}, {"title": "Alangör Mevkii", "summary": "Doğanşar''ın en yüksek noktalarından biri olan Alangör, nefes kesen vadi manzarası ve gün batımı seyri için idealdir. Doğa fotoğrafçıları için vazgeçilmez bir duraktır.", "place_query": "Alangör Mevkii, Doğanşar, Sivas"}, {"title": "Yeniköy Mağarası", "summary": "Doğanşar''a bağlı Yeniköy''de bulunan bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Keşfedilmeyi bekleyen bu yer, macera arayan ziyaretçiler için ilginç bir rotadır.", "place_query": "Yeniköy Mağarası, Doğanşar, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'faf84f95-272c-426a-9a94-36f3223cf519'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gemerek Kaya Mezarları", "summary": "Bölgenin önemli tarihi kalıntılarından olan kaya mezarları, Roma dönemine ait izler taşır. Tarih ve arkeoloji meraklıları için etkileyici bir durak noktasıdır.", "place_query": "Gemerek Kaya Mezarları, Sivas"}, {"title": "Çepni Köyü Camii", "summary": "Tarihi ahşap işçiliği ve mimarisiyle dikkat çeken bu cami, Gemerek''in kültürel mirasını yansıtan önemli bir yapıdır. Geleneksel Türk mimarisini yakından görmek isteyenler için ideal bir ziyaret noktasıdır.", "place_query": "Çepni Köyü Camii, Gemerek, Sivas"}, {"title": "Sızır Şelalesi", "summary": "Gemerek ilçe merkezine yaklaşık 25 km mesafede bulunan bu şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için popüler bir mekandır. Özellikle yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Sızır Şelalesi, Gemerek, Sivas"}, {"title": "Eğerci Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü bu yayla, doğa tatili yapmak ve şehir gürültüsünden uzaklaşmak isteyenler için harika bir seçenektir. Yayla şenlikleri de bölgenin kültürel zenginliğine katkı sağlar.", "place_query": "Eğerci Yaylası, Gemerek, Sivas"}, {"title": "Gemerek Barajı", "summary": "Çevresindeki yeşil alanlar ve huzurlu atmosferi ile olta balıkçılığı ve piknik yapmak isteyenlerin uğrak noktasıdır. Gün batımında manzarası oldukça etkileyicidir.", "place_query": "Gemerek Barajı, Sivas"}, {"title": "İnkışla Göleti", "summary": "Doğa ile iç içe sakin bir ortam arayanlar için ideal olan bu gölet, özellikle hafta sonu kaçamaklarında tercih edilir. Çevresinde yürüyüş yapabilir ve piknik yapabilirsiniz.", "place_query": "İnkışla Göleti, Gemerek, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '21b34061-0e78-4f0b-9aa4-43bb447784bc'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölova Barajı", "summary": "İlçe merkezine yakın konumda bulunan baraj gölü, piknik alanları ve doğal manzarasıyla ziyaretçilere huzurlu bir ortam sunar. Özellikle bahar ve yaz aylarında doğa yürüyüşleri ve fotoğrafçılık için idealdir.", "place_query": "Gölova Barajı, Gölova, Sivas"}, {"title": "Gölova Merkez Camii", "summary": "İlçenin tarihi dokusunu yansıtan bu cami, sade mimarisi ve çevresindeki eski evlerle dikkat çeker. Bölgenin kültürel mirasını görmek isteyenler için önemli bir duraktır.", "place_query": "Merkez Camii, Gölova, Sivas"}, {"title": "Gölova Şelalesi", "summary": "İlçe sınırları içinde yer alan bu şelale, özellikle ilkbaharda karların erimesiyle coşkun akar. Çevresi yeşilliklerle kaplı olup doğa severler için serinletici bir kaçış noktasıdır.", "place_query": "Gölova Şelalesi, Gölova, Sivas"}, {"title": "Akdağ Tabiat Parkı", "summary": "Gölova''ya yaklaşık 30 km mesafede bulunan bu tabiat parkı, zengin bitki örtüsü ve yürüyüş parkurlarıyla ünlüdür. Kamp yapmak ve doğayla iç içe vakit geçirmek için tercih edilen bir alandır.", "place_query": "Akdağ Tabiat Parkı, Sivas"}, {"title": "Gölova Yaylaları (Çamlıbel Yaylası)", "summary": "İlçenin yüksek kesimlerinde yer alan yaylalar, serin havası ve geniş otlaklarıyla bilinir. Özellikle yaz aylarında yayla şenlikleri ve doğa yürüyüşleri için popülerdir.", "place_query": "Çamlıbel Yaylası, Gölova, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3a0c33a9-3fee-4480-9fe7-096a4b2b0728'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hafik Gölü", "summary": "Hafik ilçe merkezinde yer alan doğal bir göldür. Çevresi mesire alanları ve yürüyüş yollarıyla donatılmış olup, piknik ve dinlenme için idealdir.", "place_query": "Hafik Gölü, Hafik, Sivas"}, {"title": "Hafik Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde bulunan tarihi bir kaledir. Kalıntıları günümüze ulaşan kale, bölgenin tarihine ışık tutar ve güzel bir manzara sunar.", "place_query": "Hafik Kalesi, Hafik, Sivas"}, {"title": "İncesu Köyü Kaya Kilisesi", "summary": "Hafik''e bağlı İncesu Köyü''nde yer alan tarihi bir kaya kilisesidir. Bizans dönemine ait olduğu düşünülen yapı, bölgedeki önemli kültürel miraslardandır.", "place_query": "İncesu Köyü Kaya Kilisesi, Hafik, Sivas"}, {"title": "Sivas - Hafik Karayolu Üzerindeki Tarihi Köprüler", "summary": "Hafik çevresinde, özellikle Kızılırmak üzerinde bulunan tarihi taş köprüler, Osmanlı dönemi mimarisini yansıtır ve fotoğrafçılar için ilgi çekicidir.", "place_query": "Tarihi köprüler Hafik Sivas"}, {"title": "Seyfe Köyü ve Çevresi", "summary": "Hafik''e bağlı Seyfe Köyü, doğal güzellikleri ve geleneksel köy yaşamını deneyimlemek isteyenler için sakin bir kaçış noktasıdır.", "place_query": "Seyfe Köyü, Hafik, Sivas"}, {"title": "Hafik Mesire Alanları", "summary": "Hafik Gölü çevresindeki mesire alanları, aileler ve doğa severler için mangal yapma, piknik ve doğa yürüyüşü imkanı sunar.", "place_query": "Hafik mesire alanı, Hafik, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a926c73e-2cd3-4c5e-bb13-dbcfeac72417'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "İmranlı Kaya Mezarları", "summary": "İlçe merkezine yakın kayalıklara oyulmuş, Urartu dönemine ait tarihi kaya mezarlarıdır. Tarih meraklıları için etkileyici bir durak olup, bölgenin antik geçmişine ışık tutar.", "place_query": "İmranlı Kaya Mezarları, İmranlı, Sivas"}, {"title": "Kösedağı", "summary": "İmranlı sınırları içinde yer alan Kösedağı, doğal güzelliği ve yaylalarıyla ünlüdür. Ayrıca 1243 Kösedağ Savaşı''na ev sahipliği yapmasıyla tarihi öneme sahiptir; doğa yürüyüşleri ve manzara fotoğrafçılığı için idealdir.", "place_query": "Kösedağı, İmranlı, Sivas"}, {"title": "İmranlı Yaylaları (Sarıçiçek Yaylası vb.)", "summary": "Bölge, yemyeşil yaylaları ve serin havasıyla yaz aylarında doğa turizmi için popülerdir. Sarıçiçek Yaylası başta olmak üzere birçok yayla, kamp ve piknik için tercih edilir.", "place_query": "Sarıçiçek Yaylası, İmranlı, Sivas"}, {"title": "İmranlı Göleti", "summary": "İlçe merkezine yakın konumdaki bu gölet, piknik alanları ve sakin atmosferiyle yerli halkın uğrak noktasıdır. Çevresinde yürüyüş yapabilir ve doğayla iç içe vakit geçirebilirsiniz.", "place_query": "İmranlı Göleti, İmranlı, Sivas"}, {"title": "İmranlı Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde bulunan tarihi cami ve Osmanlı döneminden kalma taş çeşmeler, İmranlı''nın kültürel dokusunu yansıtır. Kısa bir şehir turuyla bu yapıları görebilirsiniz.", "place_query": "İmranlı Merkez Camii, İmranlı, Sivas"}, {"title": "Karasu Nehri Kenarı", "summary": "İmranlı''dan geçen Karasu Nehri''nin çevresi, özellikle bahar aylarında yeşilin her tonunu sunar. Nehir kenarında yürüyüş yapabilir ve huzurlu bir gün geçirebilirsiniz.", "place_query": "Karasu Nehri, İmranlı, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1ad29c86-4e3d-497b-ab5a-1cd7b68f8035'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kangal Balıklı Kaplıca", "summary": "Dünyaca ünlü Kangal Balıklı Kaplıcası, sedef hastalığı başta olmak üzere çeşitli cilt rahatsızlıklarına iyi gelen doktor balıklarıyla tanınır. 36°C''deki termal suda yüzen bu balıklar, ölü deri hücrelerini temizleyerek doğal bir tedavi sunar.", "place_query": "Kangal Balıklı Kaplıca, Kangal, Sivas"}, {"title": "Kangal Köpeği Çiftliği", "summary": "Asil duruşu ve koruyucu yapısıyla bilinen Kangal köpeklerini doğal ortamlarında görmek için en ideal noktalardan biridir. Ziyaretçiler, bu görkemli hayvanların günlük yaşamına yakından tanıklık edebilir.", "place_query": "Kangal Köpeği Çiftliği, Kangal, Sivas"}, {"title": "Kangal Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan Kangal Kalesi, bölgeye hakim manzarasıyla dikkat çeker. Kalıntıları arasında dolaşırken hem tarihi dokuyu hissedebilir hem de çevredeki doğal güzellikleri izleyebilirsiniz.", "place_query": "Kangal Kalesi, Kangal, Sivas"}, {"title": "Kangal Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisinin izlerini taşıyan bu tarihi cami, ilçe merkezinde yer alır. Taş işçiliği ve sade iç mekanıyla huzurlu bir atmosfer sunar.", "place_query": "Kangal Ulu Camii, Kangal, Sivas"}, {"title": "Gürpınar Şelalesi", "summary": "Kangal''a bağlı Gürpınar köyü yakınlarında bulunan bu şelale, doğa yürüyüşü sevenler için ideal bir rotadır. Çevresindeki yeşil alanlar ve serin sularıyla piknik ve dinlenme imkanı sağlar.", "place_query": "Gürpınar Şelalesi, Kangal, Sivas"}, {"title": "Kangal Müzesi", "summary": "İlçenin tarihini, kültürünü ve özellikle Kangal köpeği ile balıklı kaplıca gibi değerlerini tanıtan küçük ama bilgilendirici bir müzedir. Ziyaretçilere bölgenin geçmişine dair keyifli bir yolculuk sunar.", "place_query": "Kangal Müzesi, Kangal, Sivas"}, {"title": "Alacahan Kervansarayı", "summary": "Kangal ilçe sınırları içinde yer alan bu tarihi Selçuklu kervansarayı, ihtişamlı taş yapısıyla dikkat çeker. Tarihi İpek Yolu üzerinde konumlanan yapı, günümüzde restore edilerek ziyarete açılmıştır.", "place_query": "Alacahan Kervansarayı, Kangal, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'defd5419-de11-4209-9671-8730768be132'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Koyulhisar Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin stratejik önemini gözler önüne serer ve muhteşem bir manzara sunar.", "place_query": "Koyulhisar Kalesi, Koyulhisar, Sivas"}, {"title": "Koyulhisar Çağlayan Şelalesi", "summary": "Yeşillikler içinde akan bu şelale, doğa yürüyüşleri ve piknik için ideal bir noktadır; serin suları ve huzur veren atmosferiyle ziyaretçilerini cezbeder.", "place_query": "Çağlayan Şelalesi, Koyulhisar, Sivas"}, {"title": "Koyulhisar Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, ilçenin tarih öncesi dönemlerden Osmanlı''ya kadar uzanan kültürel mirasını sergiler.", "place_query": "Koyulhisar Müzesi, Koyulhisar, Sivas"}, {"title": "Yukarıkale Köyü Tarihi Evleri", "summary": "Geleneksel Sivas mimarisinin güzel örneklerini barındıran bu köy, taş ve ahşap yapılarıyla zamanda yolculuk hissi verir.", "place_query": "Yukarıkale Köyü, Koyulhisar, Sivas"}, {"title": "Koyulhisar Yaylaları (Örneğin: Çiçekli Yaylası)", "summary": "Yemyeşil çayırları ve temiz havasıyla ünlü yaylalar, doğa severler için kamp ve yürüyüş rotaları sunar; özellikle yaz aylarında serinlemek için idealdir.", "place_query": "Çiçekli Yaylası, Koyulhisar, Sivas"}, {"title": "Koyulhisar Ulu Camii", "summary": "Osmanlı döneminden kalma bu tarihi cami, sade mimarisi ve huzur veren atmosferiyle ilçenin önemli dini yapılarındandır.", "place_query": "Koyulhisar Ulu Camii, Koyulhisar, Sivas"}, {"title": "Kılıçkaya Baraj Gölü", "summary": "İlçe sınırları içinde yer alan baraj gölü, su sporları ve balıkçılık için popüler bir alandır; çevresindeki doğal güzelliklerle görülmeye değerdir.", "place_query": "Kılıçkaya Baraj Gölü, Koyulhisar, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '89069aea-3ffc-43e9-b4cb-d90480e30fb7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sivas Kalesi", "summary": "Şehir merkezinde yer alan tarihi kale, Selçuklu döneminden kalma kalıntıları ve şehre hakim manzarasıyla ziyaretçilerine tarihi bir atmosfer sunuyor.", "place_query": "Sivas Kalesi, Merkez, Sivas"}, {"title": "Atatürk Kongre Müzesi", "summary": "Sivas Kongresi''ne ev sahipliği yapmış bu tarihi bina, Milli Mücadele dönemine ait belgeler ve eşyalarla dolu bir müze olarak önemli bir kültürel durak.", "place_query": "Atatürk Kongre Müzesi, Merkez, Sivas"}, {"title": "Divriği Ulu Camii ve Darüşşifası", "summary": "UNESCO Dünya Mirası Listesi''nde yer alan bu eşsiz yapı, taş işçiliğindeki benzersiz motifleri ve Anadolu Selçuklu mimarisinin en özel örneklerinden birini oluşturuyor.", "place_query": "Divriği Ulu Camii ve Darüşşifası, Merkez, Sivas"}, {"title": "Sivas 4 Eylül Heykeli ve Kent Meydanı", "summary": "Şehrin sembolü haline gelmiş bu meydan, Sivas Kongresi''nin ruhunu yansıtan heykeli ve çevresindeki tarihi yapılarla buluşma noktasıdır.", "place_query": "Sivas 4 Eylül Heykeli, Merkez, Sivas"}, {"title": "Palandöken Kayak Merkezi (Erzurum yolu üzeri)", "summary": "Sivas merkeze yakın olmamakla birlikte bölgedeki en popüler kış turizmi noktalarından biri olan Palandöken, kayak ve snowboard için idealdir.", "place_query": "Palandöken Kayak Merkezi, Erzurum"}, {"title": "Sivas Arkeoloji Müzesi", "summary": "Hitit, Roma ve Bizans dönemlerine ait eserlerin sergilendiği müze, bölgenin zengin tarihine ışık tutan önemli bir kültür merkezidir.", "place_query": "Sivas Arkeoloji Müzesi, Merkez, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd144d3e4-1ab6-4ae4-ba6c-b16cb2f79061'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şarkışla Kaya Mezarları", "summary": "Hitit ve Roma dönemlerine ait bu kaya mezarları, ilçe merkezine yakın bir tepede yer alır. Tarihi dokuyu ve bölgenin antik geçmişini yakından görmek isteyenler için etkileyici bir duraktır.", "place_query": "Şarkışla Kaya Mezarları, Şarkışla, Sivas"}, {"title": "Altınyayla (Tecer) Kaplıcaları", "summary": "Şarkışla ilçe sınırlarına yakın olan bu kaplıcalar, şifalı termal suları ve doğal ortamıyla ünlüdür. Romatizmal hastalıklara iyi geldiğine inanılan sularında yüzebilir veya dinlenebilirsiniz.", "place_query": "Altınyayla Kaplıcaları, Şarkışla, Sivas"}, {"title": "Kızılırmak Vadisi (Şarkışla Bölümü)", "summary": "Kızılırmak''ın Şarkışla''dan geçen bölümü, yemyeşil doğası ve kuş cıvıltılarıyla huzurlu bir kaçış noktasıdır. Özellikle piknik ve doğa yürüyüşü için idealdir.", "place_query": "Kızılırmak Vadisi Şarkışla, Sivas"}, {"title": "Çamlıca Göleti ve Mesire Alanı", "summary": "Şarkışla''ya yaklaşık 15 km uzaklıktaki bu gölet, çam ağaçları arasında yer alan piknik alanları ve yürüyüş parkurlarıyla hafta sonu kaçamaklarının favorisidir. Gölet manzarası eşliğinde huzur bulabilirsiniz.", "place_query": "Çamlıca Göleti, Şarkışla, Sivas"}, {"title": "Şarkışla Ulu Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Selçuklu ve Osmanlı mimarisinin izlerini taşır. Ahşap işçiliği ve sade atmosferiyle hem ibadet hem de tarihi bir ziyaret noktasıdır.", "place_query": "Şarkışla Ulu Camii, Şarkışla, Sivas"}, {"title": "Şarkışla Eski Hamam", "summary": "Osmanlı döneminden kalma bu tarihi hamam, geleneksel Türk hamam kültürünü deneyimlemek isteyenler için idealdir. Restore edilmiş yapısıyla hem mimari hem de dinlenme açısından değerlidir.", "place_query": "Şarkışla Eski Hamam, Şarkışla, Sivas"}, {"title": "Karaçayır Yaylası", "summary": "Şarkışla''nın yüksek kesimlerinde yer alan bu yayla, yemyeşil çayırları ve temiz havasıyla yayla turizmi için biçilmiş kaftandır. Yaz aylarında doğa yürüyüşü ve kamp için tercih edilir.", "place_query": "Karaçayır Yaylası, Şarkışla, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '203d4565-c955-49bd-b150-5c2c68632fe7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Suşehri Şelalesi", "summary": "İlçe merkezine yaklaşık 15 km uzaklıkta, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır. Özellikle bahar ve yaz aylarında ziyaretçi akınına uğrar.", "place_query": "Suşehri Şelalesi, Suşehri, Sivas"}, {"title": "Kurtlapa Yaylası", "summary": "Şehir hayatından kaçmak isteyenler için huzur dolu bir yayla deneyimi sunar. Yemyeşil çayırları, temiz havası ve geleneksel yayla evleriyle ünlüdür.", "place_query": "Kurtlapa Yaylası, Suşehri, Sivas"}, {"title": "Suşehri Kalesi", "summary": "Tarihi bir tepe üzerinde yer alan kale, bölgenin stratejik önemini yansıtan kalıntılarıyla dikkat çeker. Zirveden ilçe ve çevresinin panoramik manzarası izlenebilir.", "place_query": "Suşehri Kalesi, Suşehri, Sivas"}, {"title": "Eğriçayır Göleti", "summary": "Doğa ile iç içe bir gün geçirmek isteyenler için popüler bir mesire alanıdır. Gölet çevresinde yürüyüş yapabilir, piknik yapabilir veya olta balıkçılığı deneyebilirsiniz.", "place_query": "Eğriçayır Göleti, Suşehri, Sivas"}, {"title": "Suşehri Ulu Camii", "summary": "Osmanlı dönemi mimarisinin güzel örneklerinden biri olan cami, taş işçiliği ve sade iç mekanıyla huzur verici bir atmosfere sahiptir. İlçenin tarihi dokusunu yansıtır.", "place_query": "Suşehri Ulu Camii, Suşehri, Sivas"}, {"title": "Yeniköy Mağarası", "summary": "Suşehri’ne bağlı Yeniköy sınırlarında yer alan bu mağara, sarkıt ve dikitleriyle doğa sporları ve macera tutkunlarını cezbeder. İçerideki serin hava ve sessizlik benzersiz bir deneyim sunar.", "place_query": "Yeniköy Mağarası, Suşehri, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6c1da19b-458d-4a9b-b985-df9f6945c341'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ulaş Gölü (Ulaş Göleti)", "summary": "İlçe merkezine yakın, piknik ve doğa yürüyüşü için popüler bir mesire alanıdır. Kuş gözlemi yapmak ve huzurlu bir gün geçirmek isteyenler için idealdir.", "place_query": "Ulaş Gölü, Ulaş, Sivas"}, {"title": "Karataş Tepesi", "summary": "Bölgenin en yüksek noktalarından biri olup Sivas Ovası ve çevre dağların muhteşem manzarasını sunar. Doğa yürüyüşçüleri ve fotoğrafçılar için keşfedilmeyi bekleyen bir seyir noktasıdır.", "place_query": "Karataş Tepesi, Ulaş, Sivas"}, {"title": "Gürün-Ulaş Yolu Üzerindeki Tarihi Köprüler", "summary": "Ulaş ilçesi sınırlarında bulunan Selçuklu ve Osmanlı döneminden kalma taş köprüler, tarihi doku ve mimari açıdan ilgi çekicidir. Özellikle Çerçin Köprüsü ve çevresindeki yapılar görülmeye değerdir.", "place_query": "Çerçin Köprüsü, Ulaş, Sivas"}, {"title": "Sivas İç Anadolu Bölgesi Doğal Yaşam Alanları", "summary": "Ulaş çevresindeki bozkır ve ormanlık alanlar, yabani hayvanları gözlemlemek ve kamp yapmak için uygun doğal ortamlar sunar. Bölge, sessizlik arayan doğa severler için kaçış noktasıdır.", "place_query": "Ulaş doğal yaşam alanları, Sivas"}, {"title": "Ulaş Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki Osmanlı dönemi çeşmeler, kültürel bir rota oluşturur. Kısa bir şehir turu sırasında ziyaret edilebilir.", "place_query": "Ulaş Merkez Camii, Ulaş, Sivas"}, {"title": "Yamaç Paraşütü ve Doğa Sporları Alanları", "summary": "Ulaş''ın rüzgarlı tepeleri, özellikle yamaç paraşütü gibi ekstrem sporlar için elverişli alanlar barındırır. Macera arayanların ilgisini çeken bu noktalar, adrenalin dolu anlar vaat eder.", "place_query": "Ulaş yamaç paraşütü alanı, Sivas"}, {"title": "Kızılırmak Kenarı Mesire Alanı", "summary": "Ulaş sınırları içinden geçen Kızılırmak''ın kıyısında yer alan mesire alanı, olta balıkçılığı ve piknik için tercih edilir. Sakin atmosferiyle hafta sonu kaçamaklarına uygundur.", "place_query": "Kızılırmak mesire alanı, Ulaş, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8fe7dc63-5ebd-4eb2-b665-8845eb6697ae'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yıldız Dağı Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard tutkunlarının uğrak noktası olan bu merkez, doğal pistleri ve eşsiz manzarasıyla ziyaretçilerine keyifli bir deneyim sunar.", "place_query": "Yıldız Dağı Kayak Merkezi, Yıldızeli, Sivas"}, {"title": "Tödürge Gölü", "summary": "Yıldızeli sınırları içinde yer alan bu krater gölü, çevresindeki yemyeşil doğası ve piknik alanlarıyla hafta sonu kaçamakları için idealdir.", "place_query": "Tödürge Gölü, Yıldızeli, Sivas"}, {"title": "Kurtlapa Köyü Kaya Mezarları", "summary": "Tarihi Roma dönemine kadar uzanan bu kaya mezarları, bölgenin antik geçmişine ışık tutan önemli bir arkeolojik alandır.", "place_query": "Kurtlapa Köyü Kaya Mezarları, Yıldızeli, Sivas"}, {"title": "Çubuklu Göleti ve Mesire Alanı", "summary": "Doğa yürüyüşleri ve piknik yapmak isteyenler için huzurlu bir ortam sunan gölet, özellikle yaz aylarında serinlemek için tercih edilir.", "place_query": "Çubuklu Göleti, Yıldızeli, Sivas"}, {"title": "Yıldızeli Ulu Camii", "summary": "Osmanlı dönemi mimarisinin izlerini taşıyan bu tarihi cami, ilçenin merkezinde yer alır ve hem ibadet hem de kültürel ziyaretler için önemli bir noktadır.", "place_query": "Yıldızeli Ulu Camii, Yıldızeli, Sivas"}, {"title": "Kızılkaya Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikit yapılarıyla dikkat çeken bu mağara, macera arayan doğa severler için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Kızılkaya Mağarası, Yıldızeli, Sivas"}, {"title": "Yıldızeli Çarşı Hamamı", "summary": "Tarihi bir Osmanlı hamamı olan bu yapı, geleneksel mimarisi ve sıcak atmosferiyle yöresel kültürü deneyimlemek isteyenlere hitap eder.", "place_query": "Yıldızeli Çarşı Hamamı, Yıldızeli, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1a8ea205-00d4-4a44-99c4-e67cad5bd8c0'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zara Gölü (Kızılırmak''ın Kaynağı)", "summary": "Kızılırmak Nehri''nin doğduğu bu doğal göl, çevresindeki yemyeşil ormanlar ve mesire alanlarıyla piknik ve doğa yürüyüşü için ideal bir yerdir. Sivas''ın en önemli su kaynaklarından biridir.", "place_query": "Zara Gölü, Zara, Sivas"}, {"title": "Hafik Gölü", "summary": "Zara ilçe merkezine yaklaşık 15 km uzaklıkta bulunan bu krater gölü, berrak suları ve çevresindeki doğal güzelliklerle ünlüdür. Özellikle yaz aylarında kamp ve fotoğrafçılık için popüler bir duraktır.", "place_query": "Hafik Gölü, Hafik/Sivas"}, {"title": "Kösedağı Kayak Merkezi", "summary": "Sivas merkeze yakın olmasına rağmen Zara sınırları içinde yer alan bu kayak merkezi, kış sporları sevenler için idealdir. Pistleri ve konaklama tesisleriyle bölgenin önemli kış turizmi noktalarındandır.", "place_query": "Kösedağı Kayak Merkezi, Sivas"}, {"title": "Zara Taşhan", "summary": "Tarihi bir Osmanlı dönemi kervansarayı olan Taşhan, restore edilerek kültürel etkinliklere ev sahipliği yapmaktadır. Zara''nın tarihi dokusunu yansıtan önemli bir yapıdır.", "place_query": "Zara Taşhan, Zara, Sivas"}, {"title": "İmranlı Cüruflu Kaplıcası", "summary": "Zara''ya yakın konumdaki bu kaplıca, romatizma ve cilt hastalıklarına iyi geldiğine inanılan şifalı sularıyla tanınır. Doğal bir termal havuz deneyimi sunar.", "place_query": "İmranlı Cüruflu Kaplıcası, İmranlı/Sivas"}, {"title": "Kızıldağ Tabiat Parkı", "summary": "Zara sınırları içinde yer alan bu tabiat parkı, zengin bitki örtüsü ve yaban hayatıyla doğa severler için keşfedilmeyi bekleyen bir cennettir. Yürüyüş parkurları ve kamp alanları bulunur.", "place_query": "Kızıldağ Tabiat Parkı, Zara, Sivas"}, {"title": "Zara Ulu Camii", "summary": "Selçuklu ve Osmanlı mimarisi izlerini taşıyan tarihi cami, ilçenin merkezinde yer alır. Sade ama etkileyici yapısıyla ziyaretçilerini geçmişe götürür.", "place_query": "Zara Ulu Camii, Zara, Sivas"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8110a3dd-2ece-452c-a8bd-5029fe32521a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çerkezköy Atatürk Evi Müzesi", "summary": "Çerkezköy''ün kurtuluşunda önemli rol oynayan ve Atatürk''ün bir süre konakladığı bu tarihi bina, günümüzde müze olarak ziyaretçilere açıktır. İçerisinde Atatürk''e ait eşyalar ve yöresel etnografik eserler sergilenmektedir.", "place_query": "Çerkezköy Atatürk Evi Müzesi, Tekirdağ"}, {"title": "Çerkezköy Belediyesi Kent Ormanı", "summary": "Şehir merkezine yakın, geniş yeşil alanları ve yürüyüş parkurlarıyla doğayla iç içe vakit geçirmek isteyenler için ideal bir dinlenme ve piknik alanıdır. Aileler ve spor yapmak isteyenler tarafından sıkça tercih edilir.", "place_query": "Çerkezköy Kent Ormanı, Tekirdağ"}, {"title": "Çerkezköy Kapalı Pazar Yeri", "summary": "Modern ve ferah yapısıyla haftanın belirli günlerinde kurulan bu pazar, yöresel ürünlerden taze meyve sebzeye kadar geniş bir ürün yelpazesi sunar. Alışveriş yaparken yöre halkının günlük yaşamına tanıklık edebilirsiniz.", "place_query": "Çerkezköy Kapalı Pazar Yeri, Tekirdağ"}, {"title": "Çerkezköy Organize Sanayi Bölgesi (OSB) Gezisi", "summary": "Türkiye''nin önemli sanayi bölgelerinden biri olan Çerkezköy OSB, modern fabrikaları ve lojistik altyapısıyla dikkat çeker. Sanayi turizmi açısından ilgi çekici olup, bölgenin ekonomik gücünü yerinde gözlemleme fırsatı sunar.", "place_query": "Çerkezköy Organize Sanayi Bölgesi, Tekirdağ"}, {"title": "Çerkezköy Merkez Camii", "summary": "Şehrin simgelerinden biri olan bu cami, Osmanlı ve modern mimari unsurları bir araya getiren etkileyici yapısıyla dikkat çeker. Hem ibadet hem de mimari açıdan ziyaret edilmeye değer bir mekandır.", "place_query": "Çerkezköy Merkez Camii, Tekirdağ"}, {"title": "Velimeşe Göleti ve Mesire Alanı", "summary": "Çerkezköy''e yaklaşık 10 km uzaklıktaki bu gölet, piknik alanları ve doğal güzelliğiyle hafta sonu kaçamakları için popüler bir noktadır. Gölet çevresinde yürüyüş yapabilir ve kuş sesleri eşliğinde huzur bulabilirsiniz.", "place_query": "Velimeşe Göleti, Çerkezköy, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '19841e9b-e2b0-4f7a-b97b-0a82980a7359'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çorlu Kent Ormanı", "summary": "Şehrin gürültüsünden kaçmak için ideal, geniş yürüyüş parkurları ve piknik alanlarıyla doğayla iç içe huzurlu bir ortam sunar.", "place_query": "Çorlu Kent Ormanı, Çorlu, Tekirdağ"}, {"title": "Çorlu Müzesi", "summary": "Bölgenin tarihine ışık tutan arkeolojik eserler ve etnografik objelerin sergilendiği, kültürel bir durak.", "place_query": "Çorlu Müzesi, Çorlu, Tekirdağ"}, {"title": "Mehmetçik Parkı", "summary": "Geniş yeşil alanları, yürüyüş yolları ve çocuk oyun alanlarıyla ailelerin uğrak noktası olan büyük bir şehir parkı.", "place_query": "Mehmetçik Parkı, Çorlu, Tekirdağ"}, {"title": "Çorlu Atatürk Evi", "summary": "Atatürk''ün Çorlu ziyaretlerinde konakladığı, restore edilmiş tarihi ev; günümüzde müze olarak ziyaretçilere açıktır.", "place_query": "Atatürk Evi Müzesi, Çorlu, Tekirdağ"}, {"title": "Çorlu Pazarı (Cuma Pazarı)", "summary": "Yöresel ürünler, taze meyve-sebze ve tekstil ürünlerinin satıldığı renkli ve hareketli bir pazar yeri.", "place_query": "Çorlu Cuma Pazarı, Çorlu, Tekirdağ"}, {"title": "Hıdırağa Köyü Korusu", "summary": "Çorlu''ya yakın mesafede, mesire alanı ve göletiyle hafta sonu kaçamakları için popüler bir doğa noktası.", "place_query": "Hıdırağa Köyü Korusu, Çorlu, Tekirdağ"}, {"title": "Çorlu Belediyesi Su Parkı", "summary": "Sıcak yaz günlerinde serinlemek için tercih edilen, kaydırak ve havuzlarıyla eğlenceli bir su parkı.", "place_query": "Çorlu Belediyesi Su Parkı, Çorlu, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '562cccf1-24cd-4b54-97c2-752d73d2befd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ergene Havzası Tabiat Parkı", "summary": "Şehir merkezine yakın, piknik ve doğa yürüyüşü için ideal bir alandır. Gölet çevresinde dinlenebilir, yeşil alanların tadını çıkarabilirsiniz.", "place_query": "Ergene Havzası Tabiat Parkı, Ergene, Tekirdağ"}, {"title": "Ulaş Göleti Mesire Alanı", "summary": "Sessiz ve huzurlu bir ortamda piknik yapmak isteyenler için popüler bir noktadır. Gölet manzarası eşliğinde yürüyüş yapabilirsiniz.", "place_query": "Ulaş Göleti, Ergene, Tekirdağ"}, {"title": "Marmara Ereğlisi Sahili", "summary": "Ergene ilçesine bağlı olmasa da yakın konumuyla bilinen bu sahil, deniz keyfi ve yürüyüş için tercih edilir. Güneş batımı manzaraları ünlüdür.", "place_query": "Marmara Ereğlisi Sahili, Tekirdağ"}, {"title": "Ergene Merkez Camii", "summary": "İlçenin tarihi dokusunu yansıtan önemli bir dini yapıdır. Osmanlı mimarisi etkileri taşıyan cami, ziyaretçilerin ilgisini çeker.", "place_query": "Ergene Merkez Camii, Tekirdağ"}, {"title": "Velimeşe Osmanlı Çeşmesi", "summary": "Tarihi bir su yapısı olan çeşme, geçmiş dönem izlerini günümüze taşır. Fotoğrafçılar ve tarih meraklıları için güzel bir duraktır.", "place_query": "Velimeşe Osmanlı Çeşmesi, Ergene, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'bff6704c-0e8f-4c2b-b48c-74da9002d8e3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hayrabolu Saat Kulesi", "summary": "Hayrabolu''nun sembol yapılarından olan bu tarihi saat kulesi, ilçe merkezinde yer alır ve 19. yüzyıl Osmanlı mimarisinin güzel bir örneğidir. Ziyaretçiler hem tarihi dokuyu hissedebilir hem de çevresindeki alışveriş olanaklarından faydalanabilir.", "place_query": "Hayrabolu Saat Kulesi, Hayrabolu, Tekirdağ"}, {"title": "Hayrabolu Hamamı", "summary": "Tarihi bir Osmanlı hamamı olan bu yapı, ilçenin en eski yapılarından biridir ve halen kullanılmaktadır. Geleneksel hamam kültürünü deneyimlemek isteyenler için ideal bir noktadır.", "place_query": "Hayrabolu Hamamı, Hayrabolu, Tekirdağ"}, {"title": "Hıdırağa Korusu", "summary": "Hayrabolu''nun doğal güzelliklerinden biri olan bu koru, piknik ve yürüyüş yapmak için popüler bir mekandır. Şehir merkezine yakın konumuyla doğayla iç içe huzurlu bir kaçamak sunar.", "place_query": "Hıdırağa Korusu, Hayrabolu, Tekirdağ"}, {"title": "Hayrabolu Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını sergileyen bu müze, arkeolojik eserler ve etnografik objelerle zengin bir koleksiyona sahiptir. Hayrabolu''nun geçmişine ilgi duyanlar için mutlaka görülmesi gereken bir yerdir.", "place_query": "Hayrabolu Müzesi, Hayrabolu, Tekirdağ"}, {"title": "Çerkezmüsellim Göleti", "summary": "Hayrabolu ilçe sınırları içinde yer alan bu gölet, doğal manzarası ve temiz havasıyla doğa severler için ideal bir kaçış noktasıdır. Özellikle hafta sonları piknik ve olta balıkçılığı için tercih edilmektedir.", "place_query": "Çerkezmüsellim Göleti, Hayrabolu, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '191e2b89-dc66-4341-b7de-5eda0b460de8'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kapaklı Belediyesi Parkı", "summary": "İlçe merkezinde yer alan bu park, yürüyüş yolları ve yeşil alanlarıyla aileler için popüler bir dinlenme ve piknik noktasıdır.", "place_query": "Kapaklı Belediyesi Parkı, Kapaklı, Tekirdağ"}, {"title": "Karaevli Tabiat Parkı", "summary": "Kapaklı''ya yaklaşık 10 km mesafedeki bu tabiat parkı, gölet çevresinde yürüyüş ve piknik yapma imkanı sunan huzurlu bir doğa kaçamağıdır.", "place_query": "Karaevli Tabiat Parkı, Karaevli, Kapaklı, Tekirdağ"}, {"title": "Kapaklı Merkez Camii", "summary": "Modern mimarisi ve geniş avlusuyla ilçenin en büyük camilerinden biri olup, dini turizm açısından da ilgi çeker.", "place_query": "Kapaklı Merkez Camii, Kapaklı, Tekirdağ"}, {"title": "Pınar Mahallesi Mesire Alanı", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için ideal olan bu mesire alanı, mangal yapma ve doğa yürüyüşü için sık tercih edilir.", "place_query": "Pınar Mahallesi Mesire Alanı, Kapaklı, Tekirdağ"}, {"title": "Kapaklı Gençlik Merkezi", "summary": "Gençler ve çocuklar için çeşitli etkinliklerin düzenlendiği bu merkez, spor ve kültürel faaliyetlerle sosyal bir buluşma noktasıdır.", "place_query": "Kapaklı Gençlik Merkezi, Kapaklı, Tekirdağ"}, {"title": "Çerkezköy Organize Sanayi Bölgesi Gezi Rotası", "summary": "Kapaklı''ya komşu Çerkezköy''deki bu sanayi bölgesi, endüstriyel turizm meraklıları için dev fabrikaları ve lojistik yapılarıyla farklı bir deneyim sunar.", "place_query": "Çerkezköy Organize Sanayi Bölgesi, Çerkezköy, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ea93bd14-dd6c-42bc-b927-074805c41d33'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Malkara Kapalı Pazar Yeri", "summary": "Malkara''nın en bilinen noktalarından biri olan tarihi kapalı pazar yeri, yöresel ürünler ve el işi hediyelikler bulmak için idealdir. Özellikle cumartesi günleri kurulan semt pazarıyla ünlüdür.", "place_query": "Malkara Kapalı Pazar Yeri, Malkara, Tekirdağ"}, {"title": "Hora Köyü Şelalesi", "summary": "Malkara''ya yaklaşık 20 km uzaklıktaki Hora Köyü''nde yer alan bu şelale, doğa yürüyüşü ve piknik için popüler bir duraktır. Çevresi yeşilliklerle kaplı olup serinlemek için idealdir.", "place_query": "Hora Köyü Şelalesi, Malkara, Tekirdağ"}, {"title": "Malkara Müzesi", "summary": "İlçe merkezinde bulunan bu küçük müze, bölgenin arkeolojik ve etnografik eserlerini sergiler. Özellikle Trakya dönemine ait buluntular ilgi çekicidir.", "place_query": "Malkara Müzesi, Malkara, Tekirdağ"}, {"title": "Kınık Köyü Mağarası", "summary": "Malkara''nın Kınık köyü yakınlarında bulunan bu doğal mağara, keşfedilmeyi bekleyen bir doğa harikasıdır. Mağara içindeki sarkıt ve dikitler ziyaretçileri büyüler.", "place_query": "Kınık Köyü Mağarası, Malkara, Tekirdağ"}, {"title": "Malkara Merkez Camii", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan Malkara Merkez Camii, mimarisi ve avlusundaki çınar ağaçlarıyla dikkat çeker. Şehir merkezinde kolayca ziyaret edilebilir.", "place_query": "Malkara Merkez Camii, Malkara, Tekirdağ"}, {"title": "Süleymanpaşa Tabiat Parkı", "summary": "Malkara''nın kırsal kesiminde yer alan bu tabiat parkı, yürüyüş rotaları ve piknik alanlarıyla doğaseverler için idealdir. Göleti ve kuş gözlem noktaları meşhurdur.", "place_query": "Süleymanpaşa Tabiat Parkı, Malkara, Tekirdağ"}, {"title": "Malkara Yaylası", "summary": "Şehir merkezine yaklaşık 15 km mesafedeki bu yayla, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak için tercih edilir. Geniş çayırlıkları ve manzarası ünlüdür.", "place_query": "Malkara Yaylası, Malkara, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9b025f7f-79ab-406e-8fa0-762f0882e06e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Marmaraereğlisi Sahili", "summary": "Marmara Denizi kıyısında uzanan bu sahil, yürüyüş yapmak, deniz kenarında dinlenmek ve gün batımını izlemek için ideal bir noktadır. Özellikle yaz aylarında yerli turistlerin uğrak noktasıdır.", "place_query": "Marmaraereğlisi Sahili, Marmaraereğlisi, Tekirdağ"}, {"title": "Herakleia Antik Kenti", "summary": "Marmaraereğlisi sınırları içinde yer alan bu antik kent, tarihi kalıntıları ve surlarıyla ziyaretçilere Geç Antik Dönem ve Bizans izlerini sunar. Tarih meraklıları için önemli bir duraktır.", "place_query": "Herakleia Antik Kenti, Marmaraereğlisi, Tekirdağ"}, {"title": "Marmaraereğlisi Kalesi", "summary": "Bizans döneminden kalma bu kale, deniz kenarında stratejik bir konumda yer alır. Günümüze kısmen ulaşan surları ve manzarasıyla fotoğrafçılar ve tarih severler için caziptir.", "place_query": "Marmaraereğlisi Kalesi, Marmaraereğlisi, Tekirdağ"}, {"title": "Sultançayırı Tabiat Parkı", "summary": "Marmaraereğlisi''ne yaklaşık 15 km uzaklıkta bulunan bu tabiat parkı, yeşil alanları ve piknik alanlarıyla doğa ile iç içe vakit geçirmek isteyenler için idealdir. Yürüyüş parkurları da mevcuttur.", "place_query": "Sultançayırı Tabiat Parkı, Marmaraereğlisi, Tekirdağ"}, {"title": "Marmaraereğlisi Merkez Camii", "summary": "İlçe merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır. Hem ibadet hem de kültürel ziyaret için önemli bir yapıdır.", "place_query": "Marmaraereğlisi Merkez Camii, Marmaraereğlisi, Tekirdağ"}, {"title": "Marmaraereğlisi Halk Plajı", "summary": "Ücretsiz ve düzenli bir plaj olan Marmaraereğlisi Halk Plajı, sığ denizi ve temiz kumsalıyla aileler için güvenli bir yüzme alanı sunar. Yaz aylarında yoğun ilgi görür.", "place_query": "Marmaraereğlisi Halk Plajı, Marmaraereğlisi, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '61507202-c331-447b-9268-538519d81df7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Muratlı Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Ziyaretçiler, huzurlu atmosferi ve dini önemi nedeniyle burayı sıkça ziyaret eder.", "place_query": "Muratlı Merkez Camii, Tekirdağ"}, {"title": "Muratlı Atatürk Anıtı", "summary": "Cumhuriyet Meydanı''nda yer alan anıt, ilçenin sembol yapılarından biridir. Mustafa Kemal Atatürk''ün anısına dikilmiş olup, çevresi dinlenme alanlarıyla donatılmıştır.", "place_query": "Muratlı Atatürk Anıtı, Tekirdağ"}, {"title": "Muratlı Halk Plajı", "summary": "Marmara Denizi kıyısında yer alan plaj, yaz aylarında serinlemek ve deniz keyfi yapmak isteyenler için idealdir. Temiz suyu ve geniş kumsalıyla aileler tarafından tercih edilir.", "place_query": "Muratlı Halk Plajı, Tekirdağ"}, {"title": "Muratlı Kent Ormanı", "summary": "Doğa yürüyüşleri ve piknik için popüler bir alan olan kent ormanı, zengin bitki örtüsü ve temiz havasıyla ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Muratlı Kent Ormanı, Tekirdağ"}, {"title": "Muratlı Tarihi Çeşmesi", "summary": "Osmanlı döneminden kalma tarihi çeşme, ilçenin kültürel mirasının önemli bir parçasıdır. Restore edilmiş yapısıyla hem yerli hem de yabancı turistlerin ilgisini çeker.", "place_query": "Muratlı Tarihi Çeşme, Tekirdağ"}, {"title": "Muratlı Mesire Alanı", "summary": "Yeşillikler içinde yer alan mesire alanı, mangal ve piknik yapmak isteyenler için ideal bir mekandır. Ayrıca çocuk oyun parkları ve yürüyüş yollarıyla aileler için uygundur.", "place_query": "Muratlı Mesire Alanı, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'df1953c8-3894-4342-bf7e-b0eb339537ab'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saray İçmeler Tabiat Parkı", "summary": "Temiz havası ve yeşil doğasıyla ünlü bu tabiat parkı, piknik alanları ve yürüyüş yollarıyla ziyaretçilere huzurlu bir gün geçirme imkanı sunar. İçmeleri ve mesire alanıyla özellikle yaz aylarında yoğun ilgi görür.", "place_query": "Saray İçmeler Tabiat Parkı, Saray, Tekirdağ"}, {"title": "Kastro Kalesi (Heraion Teikhos)", "summary": "Antik çağda Trakya''nın önemli yerleşimlerinden biri olan bu tarihi kale, deniz manzarası ve sur kalıntılarıyla dikkat çeker. Tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "Kastro Kalesi Heraion Teikhos, Saray, Tekirdağ"}, {"title": "Saray Merkez Camii", "summary": "Osmanlı dönemi mimarisinin güzel örneklerinden biri olan bu cami, ilçenin merkezinde yer alır ve dini mimarisiyle ziyaretçilerini etkiler. Restore edilmiş yapısıyla ibadete ve ziyarete açıktır.", "place_query": "Saray Merkez Camii, Saray, Tekirdağ"}, {"title": "Güneşkaya Mağarası", "summary": "Doğal oluşumu ve sarkıt-dikitleriyle ilgi çeken bu mağara, doğa sporları ve mağara keşfi sevenler için idealdir. Çevresindeki ormanlık alan da doğa yürüyüşleri için uygundur.", "place_query": "Güneşkaya Mağarası, Saray, Tekirdağ"}, {"title": "Saray Atatürk Evi Müzesi", "summary": "Atatürk''ün bir dönem konakladığı bu tarihi ev, günümüzde müze olarak hizmet vermektedir. İçerisinde Atatürk''e ait eşyalar ve o döneme ait fotoğraflar sergilenmektedir.", "place_query": "Saray Atatürk Evi Müzesi, Saray, Tekirdağ"}, {"title": "Çayla Deresi Mesire Alanı", "summary": "Serin suları ve gölgelik ağaçlarıyla piknik ve kamp yapmak için popüler bir noktadır. Şehir gürültüsünden uzaklaşıp doğayla baş başa kalmak isteyenler için idealdir.", "place_query": "Çayla Deresi Mesire Alanı, Saray, Tekirdağ"}, {"title": "Saray Müzesi", "summary": "İlçenin tarihini ve kültürel mirasını yansıtan eserlerin sergilendiği bu küçük müze, bölgenin geçmişine dair ilginç bilgiler sunar. Ziyaretçiler için öğretici bir duraktır.", "place_query": "Saray Müzesi, Saray, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ba2b2d1f-f309-4dfd-9730-b77ef914ad72'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gölcük Plajı", "summary": "Şarköy''ün en popüler plajı olan Gölcük, berrak denizi ve ince kumlu sahiliyle yaz aylarında yerli ve yabancı turistlerin akınına uğrar. Çevresindeki restoran ve kafelerle keyifli bir deniz tatili sunar.", "place_query": "Gölcük Plajı, Şarköy, Tekirdağ"}, {"title": "Şarköy Merkez Plajı", "summary": "İlçe merkezinde yer alan bu plaj, kolay ulaşımı ve mavi bayraklı temiz deniziyle aileler için idealdir. Sahil şeridi boyunca yürüyüş yapabilir, balık restoranlarında yöresel lezzetleri tadabilirsiniz.", "place_query": "Şarköy Merkez Plajı, Şarköy, Tekirdağ"}, {"title": "Kumbağ Plajı", "summary": "Şarköy''e bağlı Kumbağ köyünde bulunan bu plaj, sakin atmosferi ve doğal güzelliğiyle öne çıkar. Deniz keyfinin yanı sıra zeytinlikler arasında huzurlu bir kaçamak yapmak isteyenler için biçilmiş kaftandır.", "place_query": "Kumbağ Plajı, Şarköy, Tekirdağ"}, {"title": "Mürefte Sahili", "summary": "Şarköy''ün şirin beldelerinden Mürefte, bağları ve şaraplarıyla ünlüdür. Sahil boyunca uzanan yürüyüş yolu, şarap evleri ve deniz manzaralı restoranlarıyla ziyaretçilere eşsiz bir deneyim yaşatır.", "place_query": "Mürefte Sahili, Şarköy, Tekirdağ"}, {"title": "Hoşköy Plajı", "summary": "Şarköy''ün batısında yer alan Hoşköy, sakin ve temiz plajıyla bilinir. Köyün taş evleri ve dar sokakları arasında yapacağınız bir gezinti, bölgenin otantik havasını hissettirir.", "place_query": "Hoşköy Plajı, Şarköy, Tekirdağ"}, {"title": "Şarköy Şarap Rotası", "summary": "Tekirdağ''ın üzüm bağlarıyla ünlü Şarköy ilçesinde, yerel şarap üreticilerini ziyaret ederek tadım yapabilir ve bağlar arasında keyifli bir gün geçirebilirsiniz. Özellikle Mürefte ve Hoşköy çevresi bu rota için idealdir.", "place_query": "Şarköy Şarap Rotası, Şarköy, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'cdb86696-d201-46a5-b076-85271a2f5db5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Rüstem Paşa Camii", "summary": "Mimar Sinan''ın eseri olan bu tarihi cami, Süleymanpaşa''nın simge yapılarından biridir. 16. yüzyıldan kalma zarif mimarisi ve iç süslemeleriyle ziyaretçilerini büyüler.", "place_query": "Rüstem Paşa Camii, Süleymanpaşa, Tekirdağ"}, {"title": "Tekirdağ Arkeoloji ve Etnografya Müzesi", "summary": "Eski bir hükümet konağında hizmet veren müze, bölgenin zengin tarihine ışık tutan eserler sunar. Trakya''dan çıkarılan arkeolojik buluntular ve etnografik objeler ilgi çekicidir.", "place_query": "Tekirdağ Arkeoloji ve Etnografya Müzesi, Süleymanpaşa, Tekirdağ"}, {"title": "Süleymanpaşa Sahili ve Sahil Yolu", "summary": "Marmara Denizi kıyısında uzanan bu geniş yürüyüş yolu, şehrin en canlı noktalarından biridir. Deniz manzarası eşliğinde yürüyüş yapabilir, bisiklete binebilir veya kafelerde vakit geçirebilirsiniz.", "place_query": "Süleymanpaşa Sahili, Tekirdağ"}, {"title": "Namık Kemal Evi", "summary": "Ünlü vatan şairi Namık Kemal''in doğduğu ev, günümüzde müze olarak ziyarete açıktır. Osmanlı dönemi sivil mimarisini yansıtan yapı, şairin hayatına dair eşyalar ve belgeler barındırır.", "place_query": "Namık Kemal Evi, Süleymanpaşa, Tekirdağ"}, {"title": "Heraion Teikhos Antik Kenti", "summary": "Süleymanpaşa sınırlarındaki bu antik Trak yerleşimi, sur kalıntıları ve kazı alanıyla tarih meraklılarını cezbeder. Bölgenin antik çağdaki önemli savunma noktalarından biriydi.", "place_query": "Heraion Teikhos Antik Kenti, Süleymanpaşa, Tekirdağ"}, {"title": "Rakoczi Müzesi", "summary": "Macar bağımsızlık kahramanı II. Ferenc Rakoczi''nin sürgün yıllarını geçirdiği bu tarihi ev, Macar-Türk dostluğunun sembolüdür. Müze, dönemin yaşam tarzını yansıtan eşyalarla döşenmiştir.", "place_query": "Rakoczi Müzesi, Süleymanpaşa, Tekirdağ"}, {"title": "Tekirdağ Atatürk Evi", "summary": "Atatürk''ün 1928 yılında Tekirdağ''ı ziyareti sırasında kaldığı bu iki katlı ahşap ev, bugün anı evi olarak düzenlenmiştir. Kurtuluş Savaşı ve Cumhuriyet dönemine ait fotoğraflar ve objeler sergilenmektedir.", "place_query": "Tekirdağ Atatürk Evi, Süleymanpaşa, Tekirdağ"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8887a140-dda8-4893-89a2-45b67998e011'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Almus Baraj Gölü ve Mesire Alanı", "summary": "Tokat''ın en büyük yapay gölü olan Almus Baraj Gölü, piknik alanları, yürüyüş parkurları ve tekne turlarıyla hafta sonu kaçamaklarının vazgeçilmezidir. Doğa ile iç içe huzurlu bir gün geçirmek isteyenler için ideal bir noktadır.", "place_query": "Almus Baraj Gölü, Almus, Tokat"}, {"title": "Almus Kalesi", "summary": "Yeşilırmak vadisine hakim bir tepe üzerinde kurulu olan tarihi kale, bölgenin savunma tarihine ışık tutar. Kaleye tırmanan ziyaretçiler, baraj gölü ve çevrenin muhteşem manzarasıyla karşılaşır.", "place_query": "Almus Kalesi, Almus, Tokat"}, {"title": "Çevreli Mağarası", "summary": "Almus ilçe merkezine yakın konumdaki bu doğal mağara, sarkıt ve dikitleriyle dikkat çeker. Mağara içindeki serin hava ve ilginç kaya oluşumları, doğa ve macera tutkunlarını cezbeder.", "place_query": "Çevreli Mağarası, Almus, Tokat"}, {"title": "Gölgeli Yaylası", "summary": "Yemyeşil çam ormanları ve temiz havasıyla ünlü Gölgeli Yaylası, özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak isteyenlerin uğrak noktasıdır. Yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Gölgeli Yaylası, Almus, Tokat"}, {"title": "Almus Müzesi", "summary": "İlçe merkezinde yer alan bu küçük müze, yöresel etnografik eserler ve arkeolojik buluntular sergiler. Ziyaretçiler, Almus ve çevresinin kültürel geçmişine dair keyifli bir yolculuk yapabilir.", "place_query": "Almus Müzesi, Almus, Tokat"}, {"title": "Ataköy Şelalesi", "summary": "Almus''a bağlı Ataköy yakınlarındaki bu şelale, özellikle bahar aylarında karların erimesiyle coşkun bir görüntü sunar. Çevresindeki yeşil alan, piknik ve fotoğrafçılık için elverişlidir.", "place_query": "Ataköy Şelalesi, Almus, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4855d9fe-94d9-4f46-b51e-e6592e02f183'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Artova Çamlığı Mesire Alanı", "summary": "İlçe merkezine yakın, yeşil örtüsü ve piknik alanlarıyla doğa severler için ideal bir dinlenme ve mesire noktasıdır.", "place_query": "Artova Çamlığı Mesire Alanı, Artova, Tokat"}, {"title": "Çamlık Göleti", "summary": "Çam ağaçlarıyla çevrili bu küçük gölet, huzurlu atmosferi ve doğal güzelliğiyle özellikle yaz aylarında ziyaretçilerin uğrak noktasıdır.", "place_query": "Çamlık Göleti, Artova, Tokat"}, {"title": "Artova Kaya Mezarları", "summary": "İlçe sınırları içinde bulunan bu tarihi kaya mezarları, bölgenin antik dönemlerine ışık tutan önemli arkeolojik kalıntılardandır.", "place_query": "Artova Kaya Mezarları, Artova, Tokat"}, {"title": "Ballıca Mağarası", "summary": "Tokat''ın Pazar ilçesinde yer almakla birlikte Artova''ya da yakın mesafede bulunan bu dünyaca ünlü mağara, sarkıt ve dikitleriyle büyüleyici bir doğa harikasıdır.", "place_query": "Ballıca Mağarası, Pazar, Tokat"}, {"title": "Tokat Kalesi", "summary": "Artova''ya arabayla yaklaşık 30 dakika mesafedeki bu tarihi kale, Tokat şehir merkezine hakim bir tepede yer alır ve muhteşem bir manzara sunar.", "place_query": "Tokat Kalesi, Tokat Merkez, Tokat"}, {"title": "Mahperi Hatun Kervansarayı", "summary": "Selçuklu dönemine ait bu tarihi kervansaray, Artova yolu üzerinde yer alır ve etkileyici mimarisiyle fotoğrafçıların ve tarih meraklılarının ilgisini çeker.", "place_query": "Mahperi Hatun Kervansarayı, Pazar, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '687af214-198c-4666-895a-77de62818e8a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Başçiftlik Yaylası", "summary": "Doğa yürüyüşleri ve kamp için ideal olan bu yayla, yeşilin her tonunu barındıran muhteşem manzaralar sunar. Temiz havası ve sakin atmosferiyle şehir hayatından kaçış noktasıdır.", "place_query": "Başçiftlik Yaylası, Başçiftlik, Tokat"}, {"title": "Çamlıbel Yaylası", "summary": "Çam ormanlarıyla çevrili bu yayla, piknik ve doğa yürüyüşleri için popüler bir mekandır. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Çamlıbel Yaylası, Başçiftlik, Tokat"}, {"title": "Başçiftlik Şelalesi", "summary": "Sarp kayalıklardan dökülen bu şelale, çevresindeki yeşil doğayla birlikte görsel bir şölen sunar. Ziyaretçilerine huzur veren sesi ve serin sularıyla ünlüdür.", "place_query": "Başçiftlik Şelalesi, Başçiftlik, Tokat"}, {"title": "Karaçam Tabiat Parkı", "summary": "Zengin bitki örtüsü ve yaban hayatıyla dikkat çeken bu tabiat parkı, doğa severler için keşfedilmeyi bekleyen bir cennettir. Yürüyüş parkurları ve piknik alanlarıyla ziyaretçilerine keyifli anlar yaşatır.", "place_query": "Karaçam Tabiat Parkı, Başçiftlik, Tokat"}, {"title": "Hıdırlık Tepesi", "summary": "Başçiftlik''in en yüksek noktalarından biri olan bu tepe, ilçe merkezine ve çevreye hakim nefis bir manzara sunar. Özellikle gün batımında izlenebilecek eşsiz bir seyir noktasıdır.", "place_query": "Hıdırlık Tepesi, Başçiftlik, Tokat"}, {"title": "Başçiftlik Merkez Camii", "summary": "Tarihi dokusu ve mimarisiyle dikkat çeken bu cami, ilçenin önemli dini yapılarından biridir. Ziyaretçiler, caminin huzur veren atmosferinde ibadet edebilir ve tarihi dokuyu yakından görebilir.", "place_query": "Başçiftlik Merkez Camii, Başçiftlik, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b9ecdd69-576e-4f4a-8e58-7f92f6b9a03d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamlık Mesire Alanı ve Gölet", "summary": "Erbaa''nın en popüler piknik ve mesire alanlarından biridir. Yemyeşil çam ağaçları arasında yürüyüş yapabilir, gölet kenarında dinlenebilir ve ailece keyifli vakit geçirebilirsiniz.", "place_query": "Çamlık Mesire Alanı, Erbaa, Tokat"}, {"title": "Erbaa Müzesi", "summary": "Bölgenin tarihini ve kültürel mirasını yansıtan önemli bir müzedir. Hitit, Roma, Bizans ve Osmanlı dönemlerine ait arkeolojik eserler ile etnografik objeler sergilenmektedir.", "place_query": "Erbaa Müzesi, Erbaa, Tokat"}, {"title": "Kelkit Çayı", "summary": "Erbaa''nın ortasından geçen ve şehre ayrı bir güzellik katan Kelkit Çayı, özellikle yaz aylarında serinlemek ve doğal manzaranın tadını çıkarmak için ideal bir noktadır. Çay kenarında yürüyüş yapabilirsiniz.", "place_query": "Kelkit Çayı, Erbaa, Tokat"}, {"title": "Karakaya Tepesi Seyir Noktası", "summary": "Erbaa''yı kuşbakışı görebileceğiniz en güzel noktalardan biridir. Özellikle gün batımında eşsiz bir manzara sunar ve fotoğraf tutkunları için harika bir duraktır.", "place_query": "Karakaya Tepesi, Erbaa, Tokat"}, {"title": "Evci Köyü Kaya Mezarları", "summary": "Erbaa''ya bağlı Evci Köyü''nde bulunan bu tarihi kaya mezarları, Roma dönemine ait önemli kalıntılardır. Tarih ve arkeoloji meraklıları için keşfedilmeyi bekleyen bir hazinedir.", "place_query": "Evci Köyü Kaya Mezarları, Erbaa, Tokat"}, {"title": "Doğanyurt Yaylası", "summary": "Erbaa''nın serin ve temiz havasını soluyabileceğiniz yaylalarından biridir. Doğa yürüyüşü yapmak, yöresel lezzetler tatmak ve şehir gürültüsünden uzaklaşmak için harika bir alternatiftir.", "place_query": "Doğanyurt Yaylası, Erbaa, Tokat"}, {"title": "Gümüşalan Şelalesi", "summary": "Erbaa ilçe sınırları içerisinde yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla ziyaretçilerine huzurlu bir ortam sunar. Özellikle bahar aylarında suyun debisi artar ve görsel bir şölen oluşur.", "place_query": "Gümüşalan Şelalesi, Erbaa, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '85b30950-803d-4c8d-9e7b-ec9bce8691b5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tokat Kalesi", "summary": "Şehre hakim bir tepe üzerinde yer alan tarihi kale, muhteşem manzarası ve antik kalıntılarıyla ziyaretçilerini büyülüyor.", "place_query": "Tokat Kalesi, Merkez, Tokat"}, {"title": "Ballıca Mağarası", "summary": "Dünyanın en büyük ve en görkemli mağaralarından biri olan Ballıca, eşsiz sarkıt ve dikit oluşumlarıyla doğa harikası bir gezi noktasıdır.", "place_query": "Ballıca Mağarası, Pazar, Tokat"}, {"title": "Gök Medrese", "summary": "Selçuklu dönemine ait bu tarihi medrese, turkuaz çinileri ve zarif mimarisiyle şehrin simge yapılarından biridir.", "place_query": "Gök Medrese, Merkez, Tokat"}, {"title": "Tokat Müzesi", "summary": "Eski bir medrese binasında hizmet veren müze, yöresel etnografik eserler ve arkeolojik buluntularla Tokat''ın kültürel zenginliğini gözler önüne seriyor.", "place_query": "Tokat Müzesi, Merkez, Tokat"}, {"title": "Ali Paşa Camii ve Hanı", "summary": "Osmanlı döneminden kalma tarihi cami ve han kompleksi, şehrin en işlek noktalarından biri olup hem ibadet hem de alışveriş için ziyaret ediliyor.", "place_query": "Ali Paşa Camii, Merkez, Tokat"}, {"title": "Sulusaray (Sebastopolis) Antik Kenti", "summary": "Roma dönemine ait bu antik kent, sıcak su kaynakları ve kalıntılarıyla tarih ve doğa tutkunlarına hitap ediyor.", "place_query": "Sulusaray Antik Kenti, Tokat"}, {"title": "Kaz Gölü", "summary": "Kuş gözlemciliği ve doğa yürüyüşleri için ideal olan bu sulak alan, zengin biyolojik çeşitliliğiyle huzurlu bir kaçış noktasıdır.", "place_query": "Kaz Gölü, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '06f62912-6563-41bc-bc28-3fb27c15bbf5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Niksar Kalesi", "summary": "Şehre hakim bir tepe üzerinde yer alan tarihi kale, Roma, Bizans, Danişmend ve Osmanlı dönemlerine tanıklık etmiştir. Kaleyi çevreleyen surlar ve içindeki yapı kalıntıları ziyaretçilere eşsiz bir tarih ve manzara sunar.", "place_query": "Niksar Kalesi, Niksar, Tokat"}, {"title": "Çöreği Büyük Camii (Ulu Camii)", "summary": "Anadolu Selçuklu dönemine ait bu tarihi cami, zarif mimarisi ve ahşap işçiliğiyle dikkat çeker. Niksar''ın en önemli dini yapılarından biri olup, şehrin tarihi dokusunu yansıtır.", "place_query": "Çöreği Büyük Camii, Niksar, Tokat"}, {"title": "Niksar Müzesi", "summary": "Küçük ama zengin koleksiyonuyla bölgenin arkeolojik ve etnografik eserlerini sergileyen müze, ziyaretçilere Niksar ve çevresinin tarihine dair kapsamlı bir bakış sunar.", "place_query": "Niksar Müzesi, Niksar, Tokat"}, {"title": "Kırkkızlar Türbesi", "summary": "Danişmendli dönemine ait olduğu düşünülen bu türbe, efsaneleri ve mistik atmosferiyle bilinir. Bölgenin manevi değerlerinden biri olan yapı, tarihi dokuyu hissetmek isteyenler için idealdir.", "place_query": "Kırkkızlar Türbesi, Niksar, Tokat"}, {"title": "Gökçeli Şelalesi", "summary": "Niksar''a yaklaşık 20 km uzaklıkta, yeşillikler içinde gizlenmiş bu şelale, doğa yürüyüşü ve piknik için popüler bir noktadır. Serin suları ve huzurlu ortamıyla doğaseverleri kendine çeker.", "place_query": "Gökçeli Şelalesi, Niksar, Tokat"}, {"title": "Yağcılar Konağı (Etnografya Evi)", "summary": "Restore edilmiş geleneksel bir Türk evi olan konak, Osmanlı dönemi yaşam tarzını yansıtan eşyalarla döşenmiştir. Ziyaretçilere geçmişe yolculuk yapma imkanı tanır.", "place_query": "Yağcılar Konağı, Niksar, Tokat"}, {"title": "Karakaya Mağarası", "summary": "Niksar''ın doğal güzelliklerinden biri olan bu mağara, sarkıt ve dikitleriyle ilgi çeker. Keşfedilmeyi bekleyen bu doğal oluşum, macera arayan ziyaretçiler için uygun bir rotadır.", "place_query": "Karakaya Mağarası, Niksar, Tokat"}, {"title": "Çamiçi Yaylası", "summary": "Şehir merkezine yaklaşık 30 km mesafedeki bu yayla, serin havası, çam ormanları ve muhteşem manzarasıyla yaz aylarında kaçış noktasıdır. Doğa yürüyüşleri ve kamp için idealdir.", "place_query": "Çamiçi Yaylası, Niksar, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '57db4c67-e73f-4e88-af41-2fe7496bcbb2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ballıca Mağarası", "summary": "Dünyanın en büyük ve en görkemli mağaralarından biri olan Ballıca Mağarası, sarkıt, dikit ve traverten oluşumlarıyla büyüleyici bir doğa harikasıdır. Ziyaretçilerine eşsiz bir yeraltı keşif deneyimi sunar.", "place_query": "Ballıca Mağarası, Pazar, Tokat"}, {"title": "Mahmut Dede Türbesi ve Külliyesi", "summary": "Pazar ilçesinin manevi merkezlerinden biri olan bu külliye, Osmanlı döneminden kalma tarihi yapıları ve huzur veren atmosferiyle ziyaretçilerini ağırlamaktadır.", "place_query": "Mahmut Dede Türbesi, Pazar, Tokat"}, {"title": "Pazar İlçe Merkezi ve Tarihi Evler", "summary": "Tokat''ın şirin ilçelerinden Pazar''ın merkezinde, geleneksel Osmanlı mimarisini yansıtan tarihi ahşap evler ve dar sokaklar arasında keyifli bir yürüyüş yapabilirsiniz.", "place_query": "Pazar Merkez, Tokat"}, {"title": "Almus Baraj Gölü (Pazar Kıyıları)", "summary": "Almus Baraj Gölü''nün Pazar ilçesi sınırları içinde kalan kıyı şeridi, piknik alanları ve doğal güzelliğiyle hafta sonu kaçamakları için idealdir. Gölet manzarası eşliğinde huzur bulabilirsiniz.", "place_query": "Almus Baraj Gölü Pazar Kıyısı, Tokat"}, {"title": "Pazar Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, Pazar''ın simge yapılarından biridir ve çevresindeki alan sosyalleşme noktası olarak öne çıkar.", "place_query": "Pazar Saat Kulesi, Tokat"}, {"title": "Kaz Gölü Yaban Hayatı Geliştirme Sahası", "summary": "Pazar ilçesi yakınlarında yer alan bu doğal sulak alan, göçmen kuşların uğrak noktasıdır. Doğa fotoğrafçıları ve kuş gözlemcileri için eşsiz bir rotadır.", "place_query": "Kaz Gölü, Pazar, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8a83dce8-3d52-498f-8a43-e1f6e983d8ba'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kızılkaya Mağarası", "summary": "Reşadiye''nin en önemli doğal güzelliklerinden biri olan Kızılkaya Mağarası, sarkıt ve dikitleriyle görülmeye değer bir oluşumdur. Mağara içindeki doğal havuz ve serin atmosfer, ziyaretçilere huzurlu bir deneyim sunar.", "place_query": "Kızılkaya Mağarası, Reşadiye, Tokat"}, {"title": "Reşadiye Zıkkım Deresi", "summary": "Doğal güzelliğiyle ünlü Zıkkım Deresi, yemyeşil bitki örtüsü ve akan berrak suyuyla piknik ve doğa yürüyüşü için ideal bir mekandır. Özellikle yaz aylarında serinlemek için bölge halkı ve turistler tarafından sıkça tercih edilir.", "place_query": "Zıkkım Deresi, Reşadiye, Tokat"}, {"title": "Reşadiye Yaylaları (Örneğin Göllü Yaylası)", "summary": "Reşadiye''nin yaylaları, özellikle Göllü Yaylası, muhteşem manzaraları ve temiz havasıyla doğa severleri kendine çeker. Yaylalarda geleneksel yaşamı gözlemleyebilir, yöresel ürünlerin tadına bakabilirsiniz.", "place_query": "Göllü Yaylası, Reşadiye, Tokat"}, {"title": "Reşadiye Atatürk Evi", "summary": "Tarihi bir yapı olan Reşadiye Atatürk Evi, Mustafa Kemal Atatürk''ün bölgeyi ziyareti sırasında kullandığı ev olarak bilinir. Müze olarak hizmet veren ev, döneme ait eşyaları ve fotoğrafları sergileyerek ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Atatürk Evi, Reşadiye, Tokat"}, {"title": "Reşadiye Şelalesi", "summary": "Reşadiye Şelalesi, yemyeşil doğa içinde kendini gösteren etkileyici bir doğa harikasıdır. Şelalenin serin suları ve çevresindeki piknik alanları, doğayla iç içe bir gün geçirmek isteyenler için idealdir.", "place_query": "Reşadiye Şelalesi, Reşadiye, Tokat"}, {"title": "Reşadiye Kaplıcaları", "summary": "Şifalı sularıyla ünlü Reşadiye Kaplıcaları, romatizma ve cilt hastalıkları başta olmak üzere birçok rahatsızlığa iyi geldiği düşünülen termal kaynaklara ev sahipliği yapar. Modern tesisleriyle hem sağlık turizmi hem de dinlenme amaçlı ziyaret edilmektedir.", "place_query": "Reşadiye Kaplıcaları, Reşadiye, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '05798cd1-5cc7-45fd-bbc6-3f921f3ca8fd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sulusaray (Sebastopolis) Antik Kenti", "summary": "Roma ve Bizans dönemlerine ait önemli bir antik kenttir. Kazılarda ortaya çıkarılan mozaikler, sütunlar ve yapı kalıntıları ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Sulusaray Antik Kenti, Sulusaray, Tokat"}, {"title": "Kaplıcalar (Sulusaray Termal Tesisleri)", "summary": "Şifalı sularıyla ünlü termal tesisler, romatizma ve cilt hastalıklarına iyi geldiği bilinen sıcak su kaynaklarına ev sahipliği yapar. Dinlenmek ve sağlık turizmi için idealdir.", "place_query": "Sulusaray Termal Tesisleri, Sulusaray, Tokat"}, {"title": "Sulusaray Müzesi (Açık Hava Müzesi)", "summary": "Antik kent kazılarında bulunan eserlerin sergilendiği küçük ama etkileyici bir müzedir. Tarihi kalıntıları yakından görmek isteyenler için önemli bir duraktır.", "place_query": "Sulusaray Müzesi, Sulusaray, Tokat"}, {"title": "Kızılırmak Vadisi (Sulusaray Bölümü)", "summary": "Kızılırmak Nehri''nin oluşturduğu bu vadi, doğa yürüyüşleri ve fotoğrafçılık için huzurlu bir ortam sunar. Yeşil ve mavinin buluştuğu manzaralarıyla bilinir.", "place_query": "Kızılırmak Vadisi, Sulusaray, Tokat"}, {"title": "Gökçeçat Göleti", "summary": "Sulusaray yakınlarında bulunan bu gölet, piknik ve olta balıkçılığı için popüler bir yerdir. Sakin atmosferi ve çevresindeki doğal güzelliklerle hafta sonu kaçamaklarına uygundur.", "place_query": "Gökçeçat Göleti, Sulusaray, Tokat"}, {"title": "Yörüklü Köprüsü", "summary": "Tarihi taş köprü, Osmanlı döneminden kalma mimarisiyle dikkat çeker. Kızılırmak üzerinde yer alan köprü, bölgenin kültürel mirasını yansıtır.", "place_query": "Yörüklü Köprüsü, Sulusaray, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dfc3425f-c51c-47f5-bc6f-7b1e11b7eef9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Turhal Şelalesi", "summary": "Tokat''ın Turhal ilçesinde yer alan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popüler bir destinasyondur.", "place_query": "Turhal Şelalesi, Turhal, Tokat"}, {"title": "Turhal Kalesi", "summary": "Tarihi bir tepe üzerinde konumlanan bu kale, bölgeye hakim manzarası ve geçmiş dönemlere ait izleriyle tarih meraklılarının ilgisini çeker.", "place_query": "Turhal Kalesi, Turhal, Tokat"}, {"title": "Zile Kalesi", "summary": "Turhal''a yakın mesafedeki Zile ilçesinde bulunan bu antik kale, Pontus Krallığı''ndan kalma kalıntıları ve muhteşem şehir manzarasıyla ünlüdür.", "place_query": "Zile Kalesi, Zile, Tokat"}, {"title": "Ballıca Mağarası", "summary": "Turhal''a komşu Pazar ilçesinde yer alan bu mağara, dünyanın en büyük ve en iyi korunmuş mağaralarından biri olup sarkıt ve dikitleriyle büyüleyicidir.", "place_query": "Ballıca Mağarası, Pazar, Tokat"}, {"title": "Tokat Kalesi", "summary": "Şehir merkezinde yükselen bu tarihi kale, Tokat''ın simgelerinden olup içindeki yapılar ve geniş surlarıyla ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Tokat Kalesi, Tokat Merkez, Tokat"}, {"title": "Turhal Eski Hamam", "summary": "Osmanlı döneminden kalma bu tarihi hamam, geleneksel mimarisi ve hala kullanılan orijinal yapısıyla kültürel bir durak olarak öne çıkar.", "place_query": "Turhal Eski Hamam, Turhal, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'dc8afc1e-2ab8-45d6-92ce-53d3ac69bfe7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ballıca Mağarası", "summary": "Dünyanın en büyük ve en görkemli mağaralarından biri olan Ballıca, sarkıt ve dikitleri, gölleri ve renkli oluşumlarıyla ziyaretçilerini büyüler. Yeşilyurt ilçe sınırları içinde yer alan bu doğa harikası, mutlaka görülmesi gereken bir noktadır.", "place_query": "Ballıca Mağarası, Yeşilyurt, Tokat"}, {"title": "Çamlıbel Yaylası", "summary": "Tokat''ın en popüler yaylalarından biri olan Çamlıbel, yeşil doğası, temiz havası ve muhteşem manzarasıyla doğa severler için ideal bir kaçış noktasıdır. Yaylada piknik yapabilir, doğa yürüyüşlerine çıkabilirsiniz.", "place_query": "Çamlıbel Yaylası, Yeşilyurt, Tokat"}, {"title": "Yeşilyurt Şelalesi", "summary": "İlçe merkezine yakın konumdaki bu şelale, özellikle bahar ve yaz aylarında akan suyu ve çevresindeki yeşilliklerle huzur verici bir atmosfer sunar. Serinlemek ve doğayla iç içe vakit geçirmek için güzel bir duraktır.", "place_query": "Yeşilyurt Şelalesi, Yeşilyurt, Tokat"}, {"title": "Sulusaray (Sebastopolis Antik Kenti)", "summary": "Yeşilyurt ilçesine bağlı Sulusaray beldesinde yer alan bu antik kent, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklıları için önemli bir duraktır. Özellikle antik tiyatro ve mozaikleri dikkat çekicidir.", "place_query": "Sebastopolis Antik Kenti, Sulusaray, Yeşilyurt, Tokat"}, {"title": "Kuşçu Köyü Kaya Mezarları", "summary": "Yeşilyurt''un Kuşçu köyünde bulunan bu kaya mezarları, bölgenin antik dönem yerleşimine ışık tutan etkileyici tarihi yapılardır. Kayalara oyulmuş bu mezarlar, görülmeye değer bir tarihi mirastır.", "place_query": "Kuşçu Köyü Kaya Mezarları, Yeşilyurt, Tokat"}, {"title": "Dökmetepe Göleti ve Mesire Alanı", "summary": "Yeşilyurt''a bağlı Dökmetepe köyü yakınlarındaki bu gölet, piknik alanları ve doğal güzelliğiyle hafta sonu kaçamakları için popüler bir mekandır. Gölet çevresinde yürüyüş yapabilir ve manzaranın tadını çıkarabilirsiniz.", "place_query": "Dökmetepe Göleti, Yeşilyurt, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '65533bf3-6deb-43bf-b78b-486a9294e02f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Zile Kalesi", "summary": "Şehir merkezinde yüksek bir tepenin üzerinde yer alan tarihi kale, Hititlerden Osmanlı''ya birçok medeniyete ev sahipliği yapmıştır. Zile manzarasını kuşbakışı izleyebileceğiniz en popüler noktadır.", "place_query": "Zile Kalesi, Zile, Tokat"}, {"title": "Zile Ulu Camii", "summary": "Selçuklu döneminden kalma bu tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Şehrin en eski ve en önemli ibadet yapılarından biridir.", "place_query": "Zile Ulu Camii, Zile, Tokat"}, {"title": "Zile Müzesi", "summary": "Hitit, Frig, Roma ve Osmanlı dönemlerine ait eserlerin sergilendiği müze, bölgenin zengin tarihini keşfetmek için ideal bir duraktır. Özellikle sikke koleksiyonu ilgi çekicidir.", "place_query": "Zile Müzesi, Zile, Tokat"}, {"title": "Zile Kaya Mezarları", "summary": "Antik dönemde kaya oyularak yapılmış bu mezarlar, Zile''nin tarihi dokusunu gözler önüne serer. Şehir merkezine yakın konumuyla kolayca ziyaret edilebilir.", "place_query": "Zile Kaya Mezarları, Zile, Tokat"}, {"title": "Yazmacılar Çarşısı", "summary": "Zile''nin ünlü yazma baskılı bezlerinin satıldığı bu tarihi çarşı, hediyelik eşya almak ve yöresel el sanatlarını görmek için en doğru adrestir. Renkli desenleriyle ünlüdür.", "place_query": "Yazmacılar Çarşısı, Zile, Tokat"}, {"title": "Çekerek Irmağı Kenarı (Zile Mesire Alanı)", "summary": "Şehrin hemen dışında Çekerek Irmağı boyunca uzanan bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek için popülerdir. Özellikle bahar aylarında canlı bir atmosfere sahiptir.", "place_query": "Çekerek Irmağı Mesire Alanı, Zile, Tokat"}, {"title": "Zile Kervansarayı", "summary": "Selçuklu dönemine ait bu tarihi kervansaray, eski ticaret yolları üzerinde önemli bir konaklama noktasıydı. Günümüzde restore edilmiş haliyle tarihe tanıklık etmek isteyenleri ağırlar.", "place_query": "Zile Kervansarayı, Zile, Tokat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f32752ed-6871-4282-87a2-7365166c3f58'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sümela Manastırı", "summary": "Karadeniz''in en ikonik yapılarından biri olan Sümela Manastırı, Maçka ilçesi sınırlarında olmasına rağmen Akçaabat''a da oldukça yakındır. Dik bir kaya yamacına oyulmuş bu tarihi manastır, eşsiz manzarası ve freskleriyle ziyaretçilerini büyüler.", "place_query": "Sümela Manastırı, Maçka, Trabzon"}, {"title": "Akçaabat Sahili ve Yürüyüş Yolu", "summary": "Uzun sahil şeridi ve düzenlenmiş yürüyüş yoluyla Akçaabat''ın en popüler buluşma noktasıdır. Deniz kenarında yürüyüş yapabilir, kafelerde vakit geçirebilir ve gün batımını izleyebilirsiniz.", "place_query": "Akçaabat Sahil Yolu, Akçaabat, Trabzon"}, {"title": "Akçaabat Müzesi (Ortamahalle)", "summary": "Tarihi Ortamahalle''de yer alan bu müze, restore edilmiş geleneksel bir Karadeniz evinde hizmet vermektedir. Yöresel kültür ve tarihe dair zengin bir koleksiyon sunar.", "place_query": "Akçaabat Müzesi, Ortamahalle, Akçaabat, Trabzon"}, {"title": "Ortamahalle Evleri", "summary": "Tarihi ahşap ve taş yapılarıyla ünlü Ortamahalle, Akçaabat''ın en eski yerleşim bölgelerinden biridir. Dar sokaklarında yürüyerek geçmişe yolculuk yapabilirsiniz.", "place_query": "Ortamahalle, Akçaabat, Trabzon"}, {"title": "Akçaabat Belediye Plajı", "summary": "Şehir merkezine yakın, temiz ve düzenli bir halk plajıdır. Yaz aylarında denize girmek ve güneşlenmek için ideal bir seçenektir.", "place_query": "Akçaabat Belediye Plajı, Akçaabat, Trabzon"}, {"title": "Kireçhane Mağarası", "summary": "Akçaabat''a bağlı Kireçhane köyünde bulunan bu mağara, etkileyici sarkıt ve dikitleriyle doğa severler için keşfedilmeyi bekleyen bir güzelliktir.", "place_query": "Kireçhane Mağarası, Akçaabat, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ed0a9b82-7c9b-4983-baaf-4baa227f3887'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Araklı Şelalesi", "summary": "Araklı ilçe merkezine yaklaşık 10 km uzaklıkta bulunan bu şelale, doğal güzelliği ve çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için popüler bir duraktır.", "place_query": "Araklı Şelalesi, Araklı, Trabzon"}, {"title": "Araklı Kalesi", "summary": "Tarihi bir yapı olan Araklı Kalesi, ilçeye hakim bir tepe üzerinde yer alır ve bölgenin tarihi dokusunu yansıtan önemli bir kültürel mirastır.", "place_query": "Araklı Kalesi, Araklı, Trabzon"}, {"title": "Çamlıktepe Yaylası", "summary": "Araklı sınırları içinde yer alan Çamlıktepe Yaylası, yemyeşil doğası, temiz havası ve geleneksel yayla evleriyle doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Çamlıktepe Yaylası, Araklı, Trabzon"}, {"title": "Taşönü Plajı", "summary": "Karadeniz kıyısında yer alan Taşönü Plajı, sakin atmosferi ve deniz keyfi yapma imkanıyla Araklı''da yaz aylarında tercih edilen bir dinlenme alanıdır.", "place_query": "Taşönü Plajı, Araklı, Trabzon"}, {"title": "Araklı Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşıyan yapısıyla dikkat çeker ve ibadet ile ziyaret amaçlı uğranan bir mekandır.", "place_query": "Araklı Merkez Camii, Araklı, Trabzon"}, {"title": "Sürmene-Araklı Sahil Yolu", "summary": "Karadeniz''in eşsiz manzarasını sunan bu sahil yolu, araçla veya yürüyerek keyifli bir gezi rotası olup deniz ve dağ manzaralarını bir arada sunar.", "place_query": "Sürmene Araklı Sahil Yolu, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '6de413d6-586f-486d-b943-885826c4d014'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Arsin Sahili ve Yürüyüş Yolu", "summary": "Karadeniz''in serin sularına nazır uzanan sahil şeridi ve yürüyüş yolu, özellikle akşam saatlerinde halkın ve ziyaretçilerin uğrak noktasıdır. Deniz manzarası eşliğinde yürüyüş yapabilir, sahildeki çay bahçelerinde dinlenebilirsiniz.", "place_query": "Arsin Sahil Yolu, Arsin, Trabzon"}, {"title": "Çamlıca Mahallesi Yaylası", "summary": "Arsin''in yüksek kesimlerinde yer alan bu yayla, doğal güzelliği ve temiz havasıyla ünlüdür. Yeşilin her tonunu görebileceğiniz yaylada geleneksel Karadeniz mimarisine ait evler ve geniş çayırlar bulunur.", "place_query": "Çamlıca Yaylası, Arsin, Trabzon"}, {"title": "Atatürk Köşkü (Arsin)", "summary": "Tarihi bir yapı olan bu köşk, Atatürk''ün bölgeyi ziyareti sırasında kullandığı mekan olarak bilinir. Restore edilmiş yapı, hem tarihi atmosferi hem de çevresindeki yeşil alanıyla dikkat çeker.", "place_query": "Atatürk Köşkü, Arsin, Trabzon"}, {"title": "Arsin Kapıköy Şelalesi", "summary": "Doğa yürüyüşü sevenler için ideal bir rota olan şelale, yemyeşil ormanlık alan içinde gizlenmiştir. Serin suları ve etkileyici manzarasıyla fotoğrafçıların da ilgisini çeker.", "place_query": "Kapıköy Şelalesi, Arsin, Trabzon"}, {"title": "Yokuşlu Mahallesi Tarihi Çeşmeler", "summary": "Arsin''in kırsal mahallelerinde bulunan Osmanlı dönemine ait taş çeşmeler, bölgenin tarihi su mimarisini yansıtır. Bu çeşmeler, özellikle kültür turizmiyle ilgilenenler için keşfedilmeyi bekleyen duraklardır.", "place_query": "Yokuşlu Mahallesi Tarihi Çeşmeler, Arsin, Trabzon"}, {"title": "Arsin Merkez Camii ve Çevresi", "summary": "İlçe merkezinde yer alan bu tarihi cami, mimari detayları ve huzurlu avlusuyla öne çıkar. Caminin çevresindeki çarşı ve sokaklar, yöresel ürünler almak isteyenler için keyifli bir gezi rotası sunar.", "place_query": "Arsin Merkez Camii, Arsin, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ad58633e-9c3f-4fbb-be82-ba55d6ee46af'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Beşikdüzü Sahili ve Yürüyüş Yolu", "summary": "Karadeniz''in huzur veren manzarası eşliğinde yürüyüş yapabileceğiniz, denize sıfır konumda düzenlenmiş bir sahil bandıdır. Özellikle gün batımında eşsiz bir atmosfere sahiptir.", "place_query": "Beşikdüzü Sahili, Trabzon"}, {"title": "Vikilale Yaylası", "summary": "Beşikdüzü''ne bağlı, yemyeşil doğası ve temiz havasıyla ünlü bir yayladır. Doğa yürüyüşleri ve piknik için idealdir.", "place_query": "Vikilale Yaylası, Beşikdüzü, Trabzon"}, {"title": "Çeşmeönü Plajı", "summary": "Merkeze yakın, tertemiz denizi ve kumsalı ile yerli halkın ve turistlerin uğrak noktasıdır. Denize girmek ve güneşlenmek için popüler bir seçenektir.", "place_query": "Çeşmeönü Plajı, Beşikdüzü, Trabzon"}, {"title": "Beşikdüzü Merkez Cami ve Tarihi Çevre", "summary": "İlçe merkezinde bulunan tarihi cami ve çevresindeki geleneksel yapılar, bölgenin kültürel dokusunu yansıtır. Kısa bir şehir turu için uygundur.", "place_query": "Beşikdüzü Merkez Cami, Trabzon"}, {"title": "Küçük Yayla (Beşikdüzü)", "summary": "Şehir gürültüsünden uzaklaşmak isteyenler için sakin bir doğa kaçış noktasıdır. Çam ormanları ve serin havasıyla özellikle yaz aylarında tercih edilir.", "place_query": "Küçük Yayla, Beşikdüzü, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f27fe62b-1065-449e-82fe-29a59408a251'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çarşıbaşı Sahili ve Yürüyüş Yolu", "summary": "Karadeniz''in serin sularına nazır uzanan sahil şeridi, özellikle yaz akşamlarında yürüyüş yapmak ve deniz manzarası eşliğinde çay içmek için idealdir.", "place_query": "Çarşıbaşı Sahil Yolu, Çarşıbaşı, Trabzon"}, {"title": "Kovancılar Köyü Yaylası", "summary": "Yeşilin her tonunu barındıran bu yayla, doğa yürüyüşleri ve piknik için sık tercih edilir; özellikle haziran-temmuz aylarında yayla şenliklerine ev sahipliği yapar.", "place_query": "Kovancılar Yaylası, Çarşıbaşı, Trabzon"}, {"title": "Çarşıbaşı Merkez Camii ve Tarihi Çeşmeler", "summary": "İlçe merkezinde yer alan Osmanlı dönemi camisi ve çevresindeki tarihi taş çeşmeler, bölgenin kültürel dokusunu yansıtan önemli yapılar arasındadır.", "place_query": "Çarşıbaşı Merkez Camii, Trabzon"}, {"title": "Taşönü Göleti ve Mesire Alanı", "summary": "Doğal güzelliğiyle dikkat çeken bu gölet çevresi, aileler için piknik alanları ve yürüyüş parkurları sunar; huzurlu bir gün geçirmek için idealdir.", "place_query": "Taşönü Göleti, Çarşıbaşı, Trabzon"}, {"title": "Kireçhane Köyü Şelalesi", "summary": "Yemyeşil bir vadi içinde saklı kalmış bu şelale, özellikle doğa fotoğrafçıları ve sessizlik arayan ziyaretçiler için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Kireçhane Şelalesi, Çarşıbaşı, Trabzon"}, {"title": "Çarşıbaşı Kalesi (Kale-i Bala)", "summary": "Tarihi bir Bizans kalesi olan bu yapı, ilçeye hakim bir tepede yer alır; günümüze sadece kalıntıları ulaşsa da manzarasıyla etkileyicidir.", "place_query": "Çarşıbaşı Kalesi, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '296afcc4-0afd-43af-94e0-1b7c581147e5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Uzungöl", "summary": "Trabzon''un en ünlü doğal güzelliklerinden biri olan Uzungöl, çam ormanlarıyla çevrili muhteşem göl manzarası ve huzur veren atmosferiyle ziyaretçilerini büyüler. Göl çevresinde yürüyüş yapabilir, yöresel lezzetleri tadabilir ve eşsiz fotoğraflar çekebilirsiniz.", "place_query": "Uzungöl, Çaykara, Trabzon"}, {"title": "Uzungöl Seyir Terası", "summary": "Uzungöl''ün kuşbakışı manzarasını izlemek için en ideal nokta olan seyir terası, göl ve çevresindeki yeşil vadinin panoramik fotoğraflarını çekmek isteyenler için harika bir durak.", "place_query": "Uzungöl Seyir Terası, Çaykara, Trabzon"}, {"title": "Sultan Murat Yaylası", "summary": "Trabzon''un en yüksek ve en etkileyici yaylalarından biri olan Sultan Murat Yaylası, zengin bitki örtüsü, serin havası ve geleneksel yayla evleriyle doğa severler için mükemmel bir kaçış noktasıdır. Özellikle yaz aylarında düzenlenen şenliklerle de ünlüdür.", "place_query": "Sultan Murat Yaylası, Çaykara, Trabzon"}, {"title": "Demirkapı Yaylası", "summary": "Yemyeşil doğası ve sakin ortamıyla bilinen Demirkapı Yaylası, trekking ve kamp yapmak isteyenler için idealdir. Yayla evlerinde konaklayarak yöresel yaşamı deneyimleyebilirsiniz.", "place_query": "Demirkapı Yaylası, Çaykara, Trabzon"}, {"title": "Haldizen Deresi", "summary": "Uzungöl''e akan buz gibi sularıyla ünlü Haldizen Deresi, çevresindeki yürüyüş parkurları ve şelaleleriyle doğa yürüyüşçülerinin favori rotalarından biridir. Dere boyunca yürüyüş yaparken eşsiz manzaralar eşliğinde huzur bulabilirsiniz.", "place_query": "Haldizen Deresi, Çaykara, Trabzon"}, {"title": "Çaykara Merkez Camii ve Tarihi Evler", "summary": "Çaykara ilçe merkezinde bulunan tarihi cami ve geleneksel Karadeniz mimarisini yansıtan ahşap evler, bölgenin kültürel dokusunu yakından tanımak isteyenler için görülmeye değer duraklardır.", "place_query": "Çaykara Merkez Camii, Çaykara, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '572d1941-2f91-4bd1-ba95-af810a24531f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Taşönü Yaylası", "summary": "Dernekpazarı''nın en popüler yaylalarından biri olan Taşönü, yemyeşil doğası ve temiz havasıyla özellikle yaz aylarında ziyaretçi akınına uğrar. Yayla evleri ve doğa yürüyüşü rotaları ile huzurlu bir kaçamak sunar.", "place_query": "Taşönü Yaylası, Dernekpazarı, Trabzon"}, {"title": "Çal Mağarası", "summary": "Dernekpazarı sınırları içinde yer alan Çal Mağarası, etkileyici sarkıt ve dikitleriyle dikkat çeker. Doğal oluşumu ve serin atmosferi ile mağara turizmi için önemli bir duraktır.", "place_query": "Çal Mağarası, Dernekpazarı, Trabzon"}, {"title": "Zigana Dağı", "summary": "İlçenin kuzeyinde yükselen Zigana Dağı, kış aylarında kayak ve doğa sporları için ideal bir noktadır. Yazın ise yaylacılık ve trekking rotalarıyla doğaseverleri ağırlar.", "place_query": "Zigana Dağı, Dernekpazarı, Trabzon"}, {"title": "Dernekpazarı Merkez Camii ve Çevresi", "summary": "İlçe merkezinde bulunan tarihi cami ve çevresi, yöresel mimariyi yansıtan yapılarıyla gezginlerin ilgisini çeker. Caminin avlusu ve çevresindeki eski evler, kısa bir yürüyüş için idealdir.", "place_query": "Dernekpazarı Merkez Camii, Dernekpazarı, Trabzon"}, {"title": "Beşikdüzü Sahili (Yakın Bölge)", "summary": "Dernekpazarı''na komşu Beşikdüzü ilçesinin sahil şeridi, Karadeniz''in mavi sularına nazır piknik ve dinlenme alanları sunar. Özellikle yaz akşamlarında yürüyüş yapmak için tercih edilir.", "place_query": "Beşikdüzü Sahili, Beşikdüzü, Trabzon"}, {"title": "Köknar Yaylası", "summary": "Dernekpazarı''nın yüksek kesimlerinde yer alan Köknar Yaylası, bakir doğası ve geleneksel yayla kültürüyle bilinir. Yayla şenlikleri ve doğa yürüyüşleri için popüler bir duraktır.", "place_query": "Köknar Yaylası, Dernekpazarı, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e8ba0aef-3dff-4066-a79a-8518f8ef0ac5'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çal Mağarası", "summary": "Trabzon''un en etkileyici mağaralarından biri olan Çal Mağarası, sarkıt ve dikitleriyle büyüleyici bir doğal oluşumdur. İçerisindeki yürüyüş yolları ve aydınlatma sistemi sayesinde ziyaretçiler kolayca gezebilir.", "place_query": "Çal Mağarası, Düzköy, Trabzon"}, {"title": "Haçka Yaylası", "summary": "Düzköy''ün en popüler yaylalarından biri olan Haçka Yaylası, yemyeşil doğası ve temiz havasıyla huzur veren bir kaçış noktasıdır. Özellikle yaz aylarında düzenlenen şenlikler ve geleneksel yayla evleriyle ünlüdür.", "place_query": "Haçka Yaylası, Düzköy, Trabzon"}, {"title": "Aydınlık Yaylası", "summary": "Doğal güzellikleri ve geniş otlak alanlarıyla bilinen Aydınlık Yaylası, doğa yürüyüşleri ve kamp için idealdir. Yayla, eşsiz manzarası ve zengin bitki örtüsüyle ziyaretçilerine unutulmaz anlar sunar.", "place_query": "Aydınlık Yaylası, Düzköy, Trabzon"}, {"title": "Taşönü Yaylası", "summary": "Düzköy''ün sakin ve bakir yaylalarından Taşönü, özellikle doğa fotoğrafçıları ve huzur arayanlar için harika bir duraktır. Yayla, çevresindeki ormanlık alanlar ve derelerle doğal bir güzelliğe sahiptir.", "place_query": "Taşönü Yaylası, Düzköy, Trabzon"}, {"title": "Düzköy Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan Düzköy Şelalesi, çağlayan suları ve çevresindeki piknik alanlarıyla aileler için popüler bir gezi noktasıdır. Şelalenin serin suları ve doğal ortamı, özellikle yaz sıcağında ferahlatıcı bir mola imkanı tanır.", "place_query": "Düzköy Şelalesi, Düzköy, Trabzon"}, {"title": "Cevizli Yaylası", "summary": "Yemyeşil çayırları ve geleneksel yayla mimarisiyle Cevizli Yaylası, Düzköy''ün keşfedilmeyi bekleyen güzelliklerindendir. Yayla, doğa yürüyüşleri ve yöresel lezzetleri tatmak için ideal bir duraktır.", "place_query": "Cevizli Yaylası, Düzköy, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'e10640d4-adb4-4caa-b932-4bf9aadf6071'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hayrat Yaylaları (Özellikle Hıdırnebi Yaylası)", "summary": "Trabzon''un en yeşil ve bakir yaylalarından biri olan Hıdırnebi, muhteşem manzarası, serin havası ve yayla şenlikleriyle ünlüdür. Ziyaretçiler, doğa yürüyüşleri yapabilir ve yöresel lezzetlerin tadına bakabilir.", "place_query": "Hıdırnebi Yaylası, Hayrat, Trabzon"}, {"title": "Köprübaşı Şelalesi", "summary": "Hayrat ilçe merkezine yakın konumda bulunan bu şelale, çevresindeki piknik alanları ve doğal havuzlarıyla serinlemek ve doğayla iç içe vakit geçirmek için ideal bir noktadır.", "place_query": "Köprübaşı Şelalesi, Hayrat, Trabzon"}, {"title": "Hayrat Merkez Camii ve Tarihi Çevre", "summary": "İlçe merkezinde yer alan cami ve çevresindeki tarihi yapılar, bölgenin kültürel dokusunu yansıtır. Ziyaretçiler, sakin bir atmosferde yöre halkının günlük yaşamına tanıklık edebilir.", "place_query": "Hayrat Merkez Camii, Trabzon"}, {"title": "Sarmaşık Yaylası", "summary": "Doğal güzelliği ve sakin atmosferiyle bilinen Sarmaşık Yaylası, özellikle yaz aylarında kamp ve doğa yürüyüşü meraklılarının uğrak noktasıdır.", "place_query": "Sarmaşık Yaylası, Hayrat, Trabzon"}, {"title": "Hayrat Göknar Ormanları", "summary": "Bölgenin zengin bitki örtüsüne ev sahipliği yapan bu ormanlık alan, temiz havası ve yürüyüş parkurları ile doğaseverler için keşfedilmeyi bekleyen bir cennettir.", "place_query": "Hayrat Göknar Ormanları, Trabzon"}, {"title": "Taşönü Yaylası", "summary": "Yüksek rakımı ve bozulmamış doğasıyla dikkat çeken Taşönü Yaylası, muhteşem manzara eşliğinde huzurlu bir gün geçirmek isteyenler için harika bir seçenektir.", "place_query": "Taşönü Yaylası, Hayrat, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '76d28f82-994f-4306-a57b-06ef8002e3de'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Köprübaşı Şelalesi", "summary": "Trabzon''un doğal güzelliklerinden biri olan bu şelale, etkileyici manzarası ve çevresindeki yeşil doğa ile ziyaretçilerine huzurlu bir atmosfer sunar. Piknik ve doğa yürüyüşü için idealdir.", "place_query": "Köprübaşı Şelalesi, Köprübaşı, Trabzon"}, {"title": "Beşirli Yaylası", "summary": "Yemyeşil çayırları ve serin havasıyla ünlü olan Beşirli Yaylası, özellikle yaz aylarında doğa severlerin ve kampçıların uğrak noktasıdır. Yöresel lezzetleri tatma imkanı da bulabilirsiniz.", "place_query": "Beşirli Yaylası, Köprübaşı, Trabzon"}, {"title": "Köprübaşı Merkez Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşımaktadır. Sade ve huzur verici atmosferi ile ibadet ve ziyaret için önemli bir noktadır.", "place_query": "Köprübaşı Merkez Camii, Köprübaşı, Trabzon"}, {"title": "Çifteköprü Köyü", "summary": "Doğal güzellikleri ve geleneksel Karadeniz mimarisiyle dikkat çeken bu köy, köprüleri ve akarsuları ile fotoğraf tutkunları için harika bir mekandır. Köy yaşamını yakından gözlemleme fırsatı sunar.", "place_query": "Çifteköprü Köyü, Köprübaşı, Trabzon"}, {"title": "Güneşli Yaylası", "summary": "Köprübaşı''nın en yüksek yaylalarından biri olan Güneşli Yaylası, muhteşem manzaraları ve temiz havasıyla ünlüdür. Yayla şenliklerine ev sahipliği yapmasıyla da bilinir.", "place_query": "Güneşli Yaylası, Köprübaşı, Trabzon"}, {"title": "Köprübaşı Kent Ormanı", "summary": "Şehir merkezine yakın konumuyla kolay ulaşılabilen bu ormanlık alan, yürüyüş parkurları ve piknik alanları ile aileler için ideal bir dinlenme noktasıdır. Doğayla iç içe vakit geçirmek isteyenler için biçilmiş kaftandır.", "place_query": "Köprübaşı Kent Ormanı, Köprübaşı, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1ec82ff5-6fa1-4a31-beb7-e0509fe58edb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sümela Manastırı", "summary": "Karadeniz''in simgesi haline gelmiş bu tarihi manastır, Altındere Vadisi''ndeki sarp bir kaya yamacına inşa edilmiş olup hem dini hem de mimari açıdan büyüleyici bir atmosfere sahiptir.", "place_query": "Sümela Manastırı, Maçka, Trabzon"}, {"title": "Altındere Vadisi Milli Parkı", "summary": "Sümela Manastırı''na giden yol üzerinde yer alan bu milli park, yemyeşil doğası, yürüyüş parkurları ve şelaleleriyle doğa severler için eşsiz bir kaçış noktasıdır.", "place_query": "Altındere Vadisi Milli Parkı, Maçka, Trabzon"}, {"title": "Çal Mağarası", "summary": "Dünyanın en büyük ikinci mağarası olarak bilinen Çal Mağarası, içindeki dev sarkıt ve dikitleri, yürüyüş yolları ve aydınlatmasıyla ziyaretçilerine benzersiz bir yeraltı deneyimi sunar.", "place_query": "Çal Mağarası, Maçka, Trabzon"}, {"title": "Maçka Belediye Parkı ve Seyir Terası", "summary": "İlçe merkezinde yer alan bu park, özellikle seyir terasından Karadeniz''in yemyeşil vadilerine ve Zigana Dağları''na karşı sunduğu manzara ile ünlüdür.", "place_query": "Maçka Belediye Parkı, Maçka, Trabzon"}, {"title": "Zigana Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard tutkunlarının uğrak noktası olan bu merkez, yazın ise doğa yürüyüşleri ve kamp için ideal bir yayla ortamına dönüşür.", "place_query": "Zigana Kayak Merkezi, Maçka, Trabzon"}, {"title": "Karagöl Nature Park", "summary": "Yemyeşil ormanlarla çevrili bu doğal krater gölü, huzur veren atmosferi, yürüyüş parkurları ve piknik alanlarıyla doğa ile baş başa kalmak isteyenler için mükemmel bir duraktır.", "place_query": "Karagöl Nature Park, Maçka, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0e2708bb-89fc-4bc8-a4ac-494f227ab570'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Of Sahili", "summary": "Karadeniz''in serin sularına kıyısı olan bu uzun sahil şeridi, yürüyüş yapmak ve deniz manzarası eşliğinde dinlenmek için idealdir. Özellikle yaz akşamlarında yerel halkın uğrak noktasıdır.", "place_query": "Of Sahili, Of, Trabzon"}, {"title": "Sarmaşık Şelalesi", "summary": "Yeşillikler arasında gizlenmiş bu şelale, doğa yürüyüşü sevenler için huzurlu bir kaçış noktasıdır. Çevresindeki piknik alanlarıyla hafta sonu gezileri için popülerdir.", "place_query": "Sarmaşık Şelalesi, Of, Trabzon"}, {"title": "Bölümlü Kalesi", "summary": "Tarihi bir gözetleme kulesi olan bu yapı, Of''un yüksek kesimlerinde yer alır ve etkileyici bir vadi manzarası sunar. Tarih ve doğayı bir arada görmek isteyenler için önerilir.", "place_query": "Bölümlü Kalesi, Of, Trabzon"}, {"title": "Gürpınar Yaylası", "summary": "Yemyeşil çayırları ve serin havasıyla ünlü bu yayla, doğa ile baş başa kalmak isteyenlerin tercihidir. Yayla şenlikleri ve geleneksel Karadeniz kültürünü deneyimlemek için idealdir.", "place_query": "Gürpınar Yaylası, Of, Trabzon"}, {"title": "Uğurlu Köyü Tarihi Camii", "summary": "Ahşap işçiliği ve tarihi dokusuyla dikkat çeken bu cami, Osmanlı döneminden kalma önemli bir ibadet yapısıdır. Köyün sakin atmosferiyle birlikte ziyaret edilebilir.", "place_query": "Uğurlu Köyü Tarihi Camii, Of, Trabzon"}, {"title": "Ballıca Mağarası", "summary": "Of ilçe sınırları içinde yer alan bu mağara, sarkıt ve dikitleriyle doğa meraklılarını cezbeder. Keşfedilmeyi bekleyen bu doğal oluşum, bölgedeki alternatif rotalar arasındadır.", "place_query": "Ballıca Mağarası, Of, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a9738699-6529-46d1-bda7-6daf23b4c116'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sümela Manastırı", "summary": "Trabzon''un en ünlü tarihi yapısı olan Sümela Manastırı, Karadağ''ın dik yamacına oyulmuş etkileyici bir Rum Ortodoks manastırıdır. Freskleri ve doğayla iç içe konumuyla her yıl yerli ve yabancı binlerce turisti ağırlar.", "place_query": "Sümela Manastırı, Maçka, Trabzon"}, {"title": "Trabzon Ayasofya Müzesi", "summary": "13. yüzyılda inşa edilen bu tarihi kilise, günümüzde müze olarak hizmet vermektedir. Eşsiz freskleri, mozaikleri ve Bizans mimarisinin güzel bir örneği olarak ziyaretçilerin ilgisini çeker.", "place_query": "Trabzon Ayasofya Müzesi, Ortahisar, Trabzon"}, {"title": "Boztepe", "summary": "Trabzon şehir merkezine hakim bir tepe olan Boztepe, muhteşem Karadeniz ve şehir manzarası sunar. Özellikle gün batımında çay bahçelerinde oturup manzaranın tadını çıkarmak popüler bir aktivitedir.", "place_query": "Boztepe, Ortahisar, Trabzon"}, {"title": "Trabzon Kalesi", "summary": "Tarihi Trabzon Kalesi, şehir merkezinde yer alan ve Bizans döneminden kalma surlardan oluşur. Yukarı, Orta ve Aşağı Hisar olmak üzere üç bölümden oluşan kale, şehrin tarihine tanıklık etmek isteyenler için ideal bir duraktır.", "place_query": "Trabzon Kalesi, Ortahisar, Trabzon"}, {"title": "Atatürk Köşkü", "summary": "19. yüzyılda yapılmış bu tarihi köşk, Atatürk''ün Trabzon ziyaretlerinde kullandığı ve günümüzde müze olarak hizmet veren bir yapıdır. Dönemin mimarisini ve Atatürk''e ait eşyaları görmek mümkündür.", "place_query": "Atatürk Köşkü, Ortahisar, Trabzon"}, {"title": "Trabzon Botanik Parkı", "summary": "Geniş yeşil alanları, göletleri ve yürüyüş yollarıyla şehir merkezinde doğayla iç içe vakit geçirmek isteyenler için huzurlu bir ortam sunar. Aileler ve doğa severler için popüler bir dinlenme noktasıdır.", "place_query": "Trabzon Botanik Parkı, Ortahisar, Trabzon"}, {"title": "Gülbahar Hatun Camii ve Türbesi", "summary": "Fatih Sultan Mehmet''in eşi ve Yavuz Sultan Selim''in annesi Gülbahar Hatun adına 16. yüzyılda yaptırılmıştır. Tarihi cami ve türbesi, Osmanlı mimarisinin güzel bir örneği olarak ziyaret edilebilir.", "place_query": "Gülbahar Hatun Camii, Ortahisar, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4f950914-c645-4621-9418-9a87b9f56b8d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamburnu Yaylası", "summary": "Şalpazarı''nın en popüler yaylalarından biri olan Çamburnu, doğal güzelliği ve temiz havasıyla ünlüdür. Özellikle yaz aylarında serinlemek ve doğa yürüyüşü yapmak için ideal bir noktadır.", "place_query": "Çamburnu Yaylası, Şalpazarı, Trabzon"}, {"title": "Gürgenli Yaylası", "summary": "Yemyeşil ormanlarla çevrili Gürgenli Yaylası, huzurlu atmosferi ve geleneksel yayla evleriyle ziyaretçilerine eşsiz bir deneyim sunar. Yayla şenliklerine de ev sahipliği yapar.", "place_query": "Gürgenli Yaylası, Şalpazarı, Trabzon"}, {"title": "Şalpazarı Merkez Camii", "summary": "Tarihi mimarisi ve manevi atmosferiyle dikkat çeken Şalpazarı Merkez Camii, ilçenin önemli dini yapılarından biridir. Cami, yöresel mimari özellikleri yansıtır.", "place_query": "Şalpazarı Merkez Camii, Trabzon"}, {"title": "Ağasar Vadisi", "summary": "Doğal güzellikleri ve zengin bitki örtüsüyle ünlü Ağasar Vadisi, trekking ve doğa fotoğrafçılığı için ideal bir rotadır. Vadi boyunca şelaleler ve akarsular bulunur.", "place_query": "Ağasar Vadisi, Şalpazarı, Trabzon"}, {"title": "Şalpazarı Yayla Evleri", "summary": "Bölgeye özgü ahşap mimariyle yapılmış geleneksel yayla evleri, kültürel bir miras olarak öne çıkar. Ziyaretçiler yöresel yaşam tarzını yakından gözlemleyebilir.", "place_query": "Şalpazarı Yayla Evleri, Trabzon"}, {"title": "Sis Dağı Yaylası", "summary": "Yüksek rakımı ve muhteşem manzarasıyla Sis Dağı Yaylası, doğaseverler için keşfedilmeyi bekleyen bir cennettir. Yaylada kamp yapmak da mümkündür.", "place_query": "Sis Dağı Yaylası, Şalpazarı, Trabzon"}, {"title": "Şalpazarı İçmeleri (Doğal Kaynak Suları)", "summary": "Şifalı olduğuna inanılan doğal kaynak suları, ilçenin sağlık turizmi açısından önemli bir değeridir. Bölge halkı tarafından sıkça ziyaret edilir.", "place_query": "Şalpazarı doğal kaynak suları, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '87857ca6-91e7-4d47-89b0-d4bac3d8eda4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sürmene Kalesi", "summary": "Denize hakim bir tepede yer alan tarihi kale, muhteşem Karadeniz manzarası sunar. Bölgenin savunma tarihine tanıklık etmek ve eşsiz fotoğraflar çekmek için idealdir.", "place_query": "Sürmene Kalesi, Sürmene, Trabzon"}, {"title": "Çamburnu Plajı", "summary": "İnce kumlu ve uzun sahiliyle Sürmene''nin en popüler denize girme noktasıdır. Özellikle yaz aylarında yerli halk ve turistler tarafından sıkça tercih edilir.", "place_query": "Çamburnu Plajı, Sürmene, Trabzon"}, {"title": "Sürmene Bıçakçılık Müzesi", "summary": "Dünyaca ünlü Sürmene bıçaklarının yapımını ve tarihini anlatan bu müze, zanaatkarlığın inceliklerini gözler önüne seriyor. Bıçak severler için kaçırılmaz bir duraktır.", "place_query": "Sürmene Bıçakçılık Müzesi, Sürmene, Trabzon"}, {"title": "Araklı-Sürmene Yaylaları", "summary": "Yeşilin her tonunu barındıran bu yaylalar, doğa yürüyüşleri ve kamp için mükemmel rotalar sunar. Özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak için idealdir.", "place_query": "Sürmene yaylaları, Trabzon"}, {"title": "Sürmene Merkez Camii (Küçük Ayasofya)", "summary": "Tarihi bir kiliseden camiye çevrilen bu yapı, Osmanlı ve Bizans mimarisinin izlerini taşır. Hem dini hem de tarihi bir atmosfer arayanlar için önemli bir duraktır.", "place_query": "Sürmene Merkez Camii, Sürmene, Trabzon"}, {"title": "Kastel Köyü Şelalesi", "summary": "Doğal güzelliğiyle büyüleyen bu şelale, yemyeşil ormanlar arasında gizlenmiş bir cennettir. Huzurlu bir piknik veya doğa yürüyüşü için harika bir seçenektir.", "place_query": "Kastel Köyü Şelalesi, Sürmene, Trabzon"}, {"title": "Sürmene Sahil Yolu ve Yürüyüş Parkuru", "summary": "Deniz kenarında uzanan bu parkur, yürüyüş ve bisiklet keyfi için idealdir. Gün batımında eşsiz manzaralar sunan bu yol, dinlenmek ve spor yapmak için sıkça kullanılır.", "place_query": "Sürmene sahil yolu, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '13b3c51e-2789-491c-bb28-6d45243cddc3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Tonya Yaylaları (Sis Dağı ve Haçka Yaylası)", "summary": "Tonya''nın yeşil örtüsüyle ünlü yaylaları, özellikle Sis Dağı eteklerindeki Haçka Yaylası, doğa yürüyüşleri ve kamp için idealdir. Bölge, yemyeşil çayırları, serin havası ve muhteşem Karadeniz manzarasıyla ziyaretçilerini büyüler.", "place_query": "Tonya Yaylaları, Tonya, Trabzon"}, {"title": "Tonya Şelalesi", "summary": "Tonya merkezine yakın konumdaki bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla yerli halkın ve gezginlerin uğrak noktasıdır. Özellikle bahar aylarında suyun debisi artar ve görsel bir şölen sunar.", "place_query": "Tonya Şelalesi, Tonya, Trabzon"}, {"title": "Tonya Tarihi Taş Köprüler", "summary": "Tonya ilçe merkezi ve çevresinde bulunan Osmanlı dönemine ait taş köprüler, bölgenin tarihi dokusunu yansıtır. Bu köprüler, fotoğrafçılık ve tarih meraklıları için keşfedilmeyi bekleyen önemli yapılardır.", "place_query": "Tonya Tarihi Taş Köprüler, Tonya, Trabzon"}, {"title": "Tonya Merkez Camii ve Çevresi", "summary": "Tonya''nın merkezinde yer alan tarihi cami ve etrafındaki geleneksel Karadeniz mimarisi, ilçenin kültürel kimliğini yansıtır. Cami ve çevresi, kısa bir şehir turu için idealdir.", "place_query": "Tonya Merkez Camii, Tonya, Trabzon"}, {"title": "Tonya Hoşoba Yaylası", "summary": "Tonya''nın en popüler yaylalarından biri olan Hoşoba, zengin bitki örtüsü ve temiz havasıyla doğaseverlerin gözdesidir. Yaylada geleneksel yayla evleri ve manzara seyir noktaları bulunur.", "place_query": "Hoşoba Yaylası, Tonya, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c3e69e45-5d5f-4f63-bbbe-92a313ee6c74'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Vakfıkebir Sahili ve Plajları", "summary": "Karadeniz''in serin sularına girmek ve sahil şeridinde yürüyüş yapmak için ideal olan Vakfıkebir sahilleri, özellikle yaz aylarında yerli halkın uğrak noktasıdır. Dalgalı denizi ve doğal plajlarıyla dikkat çeker.", "place_query": "Vakfıkebir Sahili, Trabzon"}, {"title": "Çamlık Mesire Alanı", "summary": "Şehir merkezine yakın, yemyeşil çam ağaçlarıyla çevrili bu mesire alanı, piknik yapmak ve doğayla iç içe vakit geçirmek için popüler bir yerdir. Aileler ve gruplar için ideal bir kaçış noktasıdır.", "place_query": "Çamlık Mesire Alanı, Vakfıkebir, Trabzon"}, {"title": "Vakfıkebir Kalesi", "summary": "Tarihi bir kalıntı olan Vakfıkebir Kalesi, ilçeye hakim bir tepede yer alır ve muhteşem bir Karadeniz manzarası sunar. Bölgenin tarihine tanıklık etmek isteyenler için görülmeye değer bir noktadır.", "place_query": "Vakfıkebir Kalesi, Trabzon"}, {"title": "Sazak Yaylası", "summary": "Vakfıkebir''in en bilinen yaylalarından biri olan Sazak Yaylası, yemyeşil doğası, temiz havası ve geleneksel yayla evleriyle huzur verici bir atmosfere sahiptir. Yaz aylarında serinlemek ve doğa yürüyüşü yapmak için idealdir.", "place_query": "Sazak Yaylası, Vakfıkebir, Trabzon"}, {"title": "Köşk Yaylası", "summary": "Doğal güzellikleri ve zengin bitki örtüsüyle ünlü Köşk Yaylası, özellikle doğa fotoğrafçıları ve kampçılar için cazip bir destinasyondur. Yayla şenliklerine de ev sahipliği yapar.", "place_query": "Köşk Yaylası, Vakfıkebir, Trabzon"}, {"title": "Vakfıkebir Merkez Cami", "summary": "İlçenin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin izlerini taşır ve dini turizm açısından önemli bir noktadır. Caminin çevresindeki çarşı da gezilebilir.", "place_query": "Vakfıkebir Merkez Cami, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a4e0bbd6-2c9b-419d-8f5f-b63d2fe6bf55'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yomra Sahil Parkı", "summary": "Yomra''nın deniz kıyısında yer alan bu park, yürüyüş yolları, oturma alanları ve deniz manzarasıyla yerli halkın ve ziyaretçilerin uğrak noktasıdır. Özellikle gün batımında huzurlu bir atmosfer sunar.", "place_query": "Yomra Sahil Parkı, Trabzon"}, {"title": "Yomra Kalesi", "summary": "Tarihi bir Bizans kalesi olan Yomra Kalesi, denize hakim bir tepede konumlanmıştır. Kalıntıları ve çevresindeki doğal manzarasıyla tarih ve fotoğraf meraklıları için ilgi çekicidir.", "place_query": "Yomra Kalesi, Trabzon"}, {"title": "Çınarlı Cami", "summary": "Yomra merkezinde bulunan bu tarihi cami, adını avlusundaki büyük çınar ağacından alır. Osmanlı dönemi mimarisinin izlerini taşıyan yapı, hâlen ibadete açıktır.", "place_query": "Çınarlı Cami, Yomra, Trabzon"}, {"title": "Yomra Yaylası (Özdil Yaylası)", "summary": "Yomra''nın yüksek kesimlerinde yer alan bu yayla, yeşil doğası, serin havası ve geleneksel yayla evleriyle doğa yürüyüşleri ve kamp için idealdir. Özellikle yaz aylarında kaçış noktasıdır.", "place_query": "Özdil Yaylası, Yomra, Trabzon"}, {"title": "Kaşüstü Plajı", "summary": "Yomra sahilinde yer alan Kaşüstü Plajı, temiz denizi ve kumlu sahiliyle yüzme ve güneşlenmek için popüler bir noktadır. Çevresindeki kafe ve restoranlarla da keyifli vakit geçirme imkânı sunar.", "place_query": "Kaşüstü Plajı, Yomra, Trabzon"}, {"title": "Yomra Merkez Camii", "summary": "Modern ve geleneksel mimari ögeleri birleştiren bu cami, Yomra''nın simge yapılarındandır. Geniş avlusu ve minaresiyle dikkat çeker, ibadet ve ziyaret amaçlı kullanılır.", "place_query": "Yomra Merkez Camii, Trabzon"}, {"title": "Taşönü Göleti", "summary": "Yomra kırsalında yer alan bu küçük gölet, çevresindeki yeşil alanlarla piknik ve doğa yürüyüşü için sakin bir ortam sunar. Özellikle hafta sonu kaçamakları için tercih edilir.", "place_query": "Taşönü Göleti, Yomra, Trabzon"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2a4b3738-f23d-4d09-a484-742d602887fe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çemişgezek Kalesi", "summary": "Şehir merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin en eski yapılarından biridir ve ziyaretçilere eşsiz bir manzara sunar.", "place_query": "Çemişgezek Kalesi, Çemişgezek, Tunceli"}, {"title": "Munzur Vadisi Milli Parkı", "summary": "Çemişgezek sınırları içinde kalan bu milli park, Munzur Dağları''nın eteklerinde yer alır ve zengin flora-faunası, yürüyüş rotaları ve şelaleleriyle doğa tutkunlarının uğrak noktasıdır.", "place_query": "Munzur Vadisi Milli Parkı, Tunceli"}, {"title": "Çemişgezek Ulu Camii", "summary": "Selçuklu dönemine ait bu tarihi cami, kesme taş işçiliği ve sade mimarisiyle dikkat çeker; şehrin en önemli dini yapılarındandır.", "place_query": "Çemişgezek Ulu Camii, Çemişgezek, Tunceli"}, {"title": "Gözlüce Barajı ve Mesire Alanı", "summary": "Baraj gölü çevresinde piknik alanları ve yürüyüş parkurları bulunan bu bölge, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için idealdir.", "place_query": "Gözlüce Barajı, Çemişgezek, Tunceli"}, {"title": "Çemişgezek Tarihi Evleri", "summary": "Taş ve ahşap mimarinin iç içe geçtiği bu geleneksel evler, dar sokakları ve otantik dokusuyla ziyaretçileri geçmişe götüren bir atmosfer sunar.", "place_query": "Çemişgezek Tarihi Evleri, Çemişgezek, Tunceli"}, {"title": "Kale Mahallesi Seyir Terası", "summary": "Kale Mahallesi''nde yer alan bu seyir noktasından Çemişgezek''in panoramik manzarasını izleyebilir, özellikle gün batımında unutulmaz fotoğraflar çekebilirsiniz.", "place_query": "Kale Mahallesi Seyir Terası, Çemişgezek, Tunceli"}, {"title": "Çemişgezek Köprüsü", "summary": "Tarihi bir taş köprü olan bu yapı, ilçeyi çevreleyen dereler üzerinde yer alır ve bölgenin geçmişteki ulaşım ağının önemli bir parçasıdır.", "place_query": "Çemişgezek Köprüsü, Çemişgezek, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c18b3c0f-5a4a-4e39-9cab-d13be714ea67'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Hozat Kalesi", "summary": "İlçe merkezinde yer alan tarihi kale, Hozat''a hakim bir tepe üzerinde kuruludur. Bölgenin tarihi dokusunu yansıtan kaleyi ziyaret ederek çevrenin panoramik manzarasını izleyebilirsiniz.", "place_query": "Hozat Kalesi, Hozat, Tunceli"}, {"title": "Hozat Ulu Camii", "summary": "Osmanlı döneminden kalma tarihi bir yapı olan cami, ilçenin merkezinde yer alır ve mimari özellikleriyle dikkat çeker.", "place_query": "Hozat Ulu Camii, Hozat, Tunceli"}, {"title": "Hozat Çarşı Hamamı", "summary": "Tarihi hamam, ilçenin eski çarşı bölgesinde bulunur ve geçmişten günümüze ulaşan önemli bir kültürel mirastır.", "place_query": "Hozat Çarşı Hamamı, Hozat, Tunceli"}, {"title": "Hozat Şelalesi", "summary": "İlçe merkezine yaklaşık 15 km uzaklıkta bulunan şelale, doğal güzelliği ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır.", "place_query": "Hozat Şelalesi, Hozat, Tunceli"}, {"title": "Mercan Dağları", "summary": "Hozat sınırları içinde yer alan Mercan Dağları, zengin bitki örtüsü ve yaban hayatıyla doğa sporları ve trekking için popüler bir rotadır.", "place_query": "Mercan Dağları, Hozat, Tunceli"}, {"title": "Hozat Yaylaları", "summary": "İlçenin çevresinde bulunan yaylalar, yemyeşil doğası ve temiz havasıyla yaz aylarında kamp ve doğa turizmi için sıkça tercih edilir.", "place_query": "Hozat Yaylaları, Hozat, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b634d21f-56b8-4493-b831-a680ed21912f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mazgirt Kalesi", "summary": "Tarihi bir kaya kalesi olup, Peri Çayı vadisinde etkileyici bir konuma sahiptir. Kalenin içindeki mağara ve yapı kalıntıları ziyaretçilere tarihi bir atmosfer sunar.", "place_query": "Mazgirt Kalesi, Mazgirt, Tunceli"}, {"title": "Peri Çayı Vadisi", "summary": "Doğal güzelliği ve yemyeşil vadisiyle ünlüdür. Özellikle yaz aylarında doğa yürüyüşleri ve piknik için ideal bir noktadır.", "place_query": "Peri Çayı Vadisi, Mazgirt, Tunceli"}, {"title": "Dedebağ Köprüsü", "summary": "Tarihi bir taş köprü olup, Peri Çayı üzerinde yer alır. Mimari yapısı ve çevresindeki doğal manzara fotoğrafçılar için popüler bir duraktır.", "place_query": "Dedebağ Köprüsü, Mazgirt, Tunceli"}, {"title": "Mazgirt Merkez Camii", "summary": "İlçe merkezinde bulunan tarihi bir camidir. Osmanlı dönemi mimari özelliklerini taşıyan yapı, dini ve kültürel bir ziyaret noktasıdır.", "place_query": "Mazgirt Merkez Camii, Mazgirt, Tunceli"}, {"title": "Kale Mahallesi (Tarihi Evler)", "summary": "Mazgirt''in eski mahallelerinden olan bu bölge, geleneksel taş evleri ve dar sokaklarıyla dikkat çeker. Tarihi doku yürüyüş yapmak isteyenler için uygundur.", "place_query": "Kale Mahallesi, Mazgirt, Tunceli"}, {"title": "Mazgirt Şelalesi", "summary": "İlçe sınırları içinde yer alan doğal bir şelaledir. Çevresi yeşilliklerle kaplı olup, serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Mazgirt Şelalesi, Mazgirt, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd3fdb2b2-998f-4c96-97c6-fe7d6697286e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Munzur Vadisi Milli Parkı", "summary": "Tunceli''nin simgesi olan bu milli park, Munzur Dağları''nın eteklerinde yemyeşil vadiler, şelaleler ve berrak akarsularla doğa tutkunlarına eşsiz bir deneyim sunar. Yürüyüş, kamp ve piknik için ideal bir yerdir.", "place_query": "Munzur Vadisi Milli Parkı, Tunceli Merkez"}, {"title": "Peri Mağaraları", "summary": "Tunceli Merkez''e yakın konumdaki bu doğal mağaralar, tarih öncesi dönemlerden izler taşıyan etkileyici kaya oluşumları ve sarkıtlarıyla ziyaretçileri büyüler. Mağara keşfi ve fotoğrafçılık için popüler bir noktadır.", "place_query": "Peri Mağaraları, Tunceli Merkez"}, {"title": "Tunceli Kalesi", "summary": "Şehir merkezinde yüksek bir tepe üzerinde yer alan bu tarihi kale, Urartu dönemine kadar uzanan bir geçmişe sahiptir. Kaleye tırmanarak Tunceli''nin panoramik manzarasını izleyebilirsiniz.", "place_query": "Tunceli Kalesi, Tunceli Merkez"}, {"title": "Kırklar Dağı", "summary": "Alevi-Bektaşi inancında kutsal kabul edilen bu dağ, doğal güzelliği ve mistik atmosferiyle öne çıkar. Zirveye yapılan yürüyüşler, ziyaretçilere hem manevi bir deneyim hem de muhteşem bir doğa manzarası sunar.", "place_query": "Kırklar Dağı, Tunceli Merkez"}, {"title": "Ovacık Yolu ve Pülümür Vadisi", "summary": "Tunceli Merkez''den Ovacık''a giden bu yol boyunca uzanan Pülümür Vadisi, rengarenk çiçeklerle kaplı yaylaları ve çağlayan dereleriyle ünlüdür. Özellikle ilkbahar ve yaz aylarında doğa yürüyüşleri ve fotoğraf safarileri için idealdir.", "place_query": "Pülümür Vadisi, Tunceli"}, {"title": "Mazgirt Kalesi ve Çelebi Ali Paşa Camii", "summary": "Tunceli Merkez''e bağlı Mazgirt ilçesinde bulunan bu tarihi kale ve yanındaki cami, bölgenin Orta Çağ''daki önemini yansıtır. Kale kalıntıları ve caminin mimarisi tarih meraklılarını cezbeder.", "place_query": "Mazgirt Kalesi, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '9101563c-3b2a-4b84-922a-a314cc64972b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Mercan Dağları", "summary": "Nazımiye''nin en önemli doğal güzelliklerinden olan Mercan Dağları, yemyeşil ormanları, berrak dereleri ve eşsiz manzaralarıyla doğa yürüyüşü ve kamp için idealdir. Bölge, özellikle bahar aylarında rengarenk çiçeklerle kaplanır.", "place_query": "Mercan Dağları, Nazımiye, Tunceli"}, {"title": "Nazımiye Şelalesi", "summary": "İlçe merkezine yakın konumda bulunan Nazımiye Şelalesi, serin suları ve çevresindeki piknik alanlarıyla yaz aylarında yerli halkın ve ziyaretçilerin uğrak noktasıdır. Doğal havuzunda yüzmek mümkündür.", "place_query": "Nazımiye Şelalesi, Tunceli"}, {"title": "Kırklar Dağı", "summary": "Nazımiye''nin simgelerinden biri olan Kırklar Dağı, hem doğal güzelliği hem de yöre halkı için manevi önemiyle bilinir. Dağın zirvesinden ilçe ve çevresinin panoramik manzarası izlenebilir.", "place_query": "Kırklar Dağı, Nazımiye, Tunceli"}, {"title": "Nazımiye Merkez Camii ve Tarihi Evler", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki geleneksel mimariye sahip Nazımiye evleri, yörenin kültürel dokusunu yansıtır. Dar sokaklarda yapılacak bir yürüyüş, zamanda yolculuk hissi verir.", "place_query": "Nazımiye Merkez Camii, Tunceli"}, {"title": "Gözlüce Yaylası", "summary": "Nazımiye''ye bağlı Gözlüce köyü yakınlarındaki bu yayla, yemyeşil çayırları ve temiz havasıyla doğa severler için huzurlu bir kaçış noktasıdır. Yaylada geleneksel yayla şenlikleri de düzenlenmektedir.", "place_query": "Gözlüce Yaylası, Nazımiye, Tunceli"}, {"title": "Pülümür Vadisi (Nazımiye kesimi)", "summary": "Pülümür Çayı boyunca uzanan bu vadi, Nazımiye sınırları içinde de etkileyici kanyonlar ve doğal manzaralar sunar. Özellikle trekking ve fotoğrafçılık için popüler bir rotadır.", "place_query": "Pülümür Vadisi, Nazımiye, Tunceli"}, {"title": "Kutudere Köyü ve Tarihi Köprüsü", "summary": "Nazımiye''nin Kutudere köyünde bulunan tarihi taş köprü, bölgenin geçmişine ışık tutan önemli bir yapıdır. Köyün doğal dokusuyla birleşen köprü, fotoğraf tutkunları için güzel bir karedir.", "place_query": "Kutudere Köyü Tarihi Köprü, Nazımiye, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '8647607e-2310-43c4-8868-b700831f8d14'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Munzur Vadisi Milli Parkı", "summary": "Türkiye''nin en büyük milli parklarından biri olan bu vadi, Munzur Dağları''nın eteklerinde yer alır. Kristal berraklığındaki akarsuları, şelaleleri, yürüyüş parkurları ve zengin bitki örtüsüyle doğa tutkunları için eşsiz bir cennettir.", "place_query": "Munzur Vadisi Milli Parkı, Ovacık, Tunceli"}, {"title": "Ovacık Merkez Parkı ve Mesire Alanı", "summary": "İlçe merkezinde yer alan bu park, Munzur Çayı''nın kenarında piknik yapmak ve dinlenmek için ideal bir noktadır. Özellikle yaz aylarında serin suların sesi eşliğinde huzurlu vakit geçirebilirsiniz.", "place_query": "Ovacık Merkez Parkı, Ovacık, Tunceli"}, {"title": "Kırkmerdiven Şelalesi", "summary": "Munzur Vadisi içinde bulunan bu şelale, doğal havuzları ve çevresindeki yemyeşil doğasıyla fotoğrafçıların ve doğa yürüyüşçülerinin uğrak noktasıdır. Bölgeye ulaşım için kısa bir doğa yürüyüşü yapmanız gerekir.", "place_query": "Kırkmerdiven Şelalesi, Ovacık, Tunceli"}, {"title": "Munzur Çayı", "summary": "Ovacık''tan doğarak Munzur Vadisi''ni besleyen bu berrak akarsu, kano ve rafting gibi su sporları için idealdir. Çevresindeki yürüyüş yolları ve piknik alanlarıyla doğayla iç içe bir gün geçirmek isteyenlerin favorisidir.", "place_query": "Munzur Çayı, Ovacık, Tunceli"}, {"title": "Dinar Dağı ve Seyir Tepesi", "summary": "Ovacık''ın simgelerinden biri olan Dinar Dağı, zirvesinden ilçeyi ve Munzur Vadisi''ni kuşbakışı görebileceğiniz nefes kesici bir manzara sunar. Doğa yürüyüşü ve kampçılık için de popüler bir rotadır.", "place_query": "Dinar Dağı, Ovacık, Tunceli"}, {"title": "Koyungölü", "summary": "Munzur Dağları''nın zirvelerinde yer alan bu krater gölü, bozulmamış doğası ve sakin atmosferiyle huzur arayanların keşfetmesi gereken bir yerdir. Bölgeye ulaşım biraz zorlu olsa da manzarası tüm yorgunluğu unutturur.", "place_query": "Koyungölü, Ovacık, Tunceli"}, {"title": "Yelmaniye Köyü ve Tarihi Taş Evler", "summary": "Ovacık''a bağlı bu köy, geleneksel Tunceli taş mimarisini yansıtan tarihi evleri ve doğal güzellikleriyle dikkat çeker. Köy çevresinde yapacağınız yürüyüşlerde bölgenin kültürel dokusunu yakından gözlemleyebilirsiniz.", "place_query": "Yelmaniye Köyü, Ovacık, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2f271438-f226-40f2-a2d6-62467f2dca81'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pertek Kalesi", "summary": "Keban Baraj Gölü kıyısında, bir yarımada üzerinde yükselen bu tarihi kale, Urartu dönemine kadar uzanan köklü bir geçmişe sahiptir. Göl manzarası eşliğinde yapılan bir gezi, hem tarih hem de doğa severler için unutulmaz bir deneyim sunar.", "place_query": "Pertek Kalesi, Pertek, Tunceli"}, {"title": "Pertek Çarşı Camii", "summary": "16. yüzyılda inşa edilen bu Osmanlı dönemi camii, kesme taş işçiliği ve sade mimarisiyle dikkat çeker. Tarihi çarşı içinde yer alması sayesinde camiyi ziyaret ederken geleneksel dükkanları da keşfedebilirsiniz.", "place_query": "Pertek Çarşı Camii, Pertek, Tunceli"}, {"title": "Keban Baraj Gölü (Pertek Kıyıları)", "summary": "Pertek ilçesinin kıyı şeridinde uzanan baraj gölü, huzurlu manzarası ve doğal güzelliğiyle öne çıkar. Özellikle gün batımında yapılan tekne turları ve piknik alanları, ziyaretçilere keyifli anlar yaşatır.", "place_query": "Keban Baraj Gölü Pertek kıyıları, Tunceli"}, {"title": "Pertek Müzesi", "summary": "Eski bir hükümet konağında hizmet veren bu küçük müze, yöreye ait arkeolojik buluntular ve etnografik eserler sergiler. Tunceli''nin kültürel mirasını yakından tanımak isteyenler için ideal bir duraktır.", "place_query": "Pertek Müzesi, Pertek, Tunceli"}, {"title": "Pertek Köprüsü", "summary": "Karasu Çayı üzerinde yer alan bu tarihi taş köprü, Osmanlı döneminden günümüze ulaşan önemli bir yapıdır. Çevresindeki yeşil alanlar ve akan suyun sesi eşliğinde yürüyüş yapmak, ziyaretçilere huzur verir.", "place_query": "Pertek Köprüsü, Pertek, Tunceli"}, {"title": "Mazgirt Kalesi (Pertek Yakınları)", "summary": "Pertek''e yaklaşık 20 km uzaklıkta bulunan bu kale, sarp bir kaya üzerine inşa edilmiş olup Urartu ve Orta Çağ izlerini taşır. Zirveye çıkıldığında Munzur Dağları ve çevre vadilerin nefes kesen manzarası sizi bekler.", "place_query": "Mazgirt Kalesi, Mazgirt, Tunceli"}, {"title": "Pertek Saat Kulesi", "summary": "Cumhuriyet döneminin simgelerinden biri olan bu saat kulesi, ilçe merkezinde kolayca fark edilir. Etrafındaki küçük park ve çay bahçeleri, kısa bir mola verip çevreyi izlemek için idealdir.", "place_query": "Pertek Saat Kulesi, Pertek, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '63750c2f-671a-411b-82e3-80f63783aa67'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Pülümür Vadisi", "summary": "Muhteşem doğal güzelliği ve yemyeşil vadisiyle ünlüdür. Munzur Dağları''nın eteklerinde uzanan vadi, trekking ve doğa yürüyüşleri için idealdir.", "place_query": "Pülümür Vadisi, Pülümür, Tunceli"}, {"title": "Pülümür Çayı", "summary": "Buz gibi suları ve çevresindeki piknik alanlarıyla yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için popüler bir noktadır.", "place_query": "Pülümür Çayı, Pülümür, Tunceli"}, {"title": "Kırmızı Köprü (Pülümür Köprüsü)", "summary": "Tarihi taş köprü, bölgenin geçmişine tanıklık eden önemli bir yapıdır. Fotoğrafçılar ve tarih meraklıları için ilgi çekicidir.", "place_query": "Kırmızı Köprü, Pülümür, Tunceli"}, {"title": "Munzur Dağları Milli Parkı (Pülümür Kesimi)", "summary": "Zengin flora ve faunasıyla ünlü milli parkın Pülümür sınırları içindeki bölümü, doğa yürüyüşleri ve kampçılık için keşfedilmeyi bekliyor.", "place_query": "Munzur Dağları Milli Parkı, Pülümür, Tunceli"}, {"title": "Pülümür Merkez Camii ve Çevresi", "summary": "İlçe merkezinde yer alan cami ve çevresindeki geleneksel yapılar, yöresel mimariyi görmek ve kısa bir şehir turu atmak için idealdir.", "place_query": "Pülümür Merkez Camii, Pülümür, Tunceli"}, {"title": "Sarıkaya Mağarası", "summary": "Pülümür yakınlarında bulunan bu doğal mağara, sarkıt ve dikitleriyle ilgi çekicidir. Macera arayanlar için keşif rotasıdır.", "place_query": "Sarıkaya Mağarası, Pülümür, Tunceli"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f1754f8a-e731-40ec-ac1a-160dbe59306c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Banaz Mavi Göl (Banaz Barajı)", "summary": "Doğal güzelliği ve huzur veren atmosferiyle bilinen yapay bir göldür. Piknik alanları, yürüyüş parkurları ve muhteşem manzarasıyla hafta sonu kaçamakları için idealdir.", "place_query": "Banaz Barajı, Banaz, Uşak"}, {"title": "Murat Dağı Kaplıcaları", "summary": "Şifalı termal sularıyla ünlü olan bu kaplıcalar, romatizma ve cilt hastalıklarına iyi gelmektedir. Doğa içinde dinlenmek ve sağlık bulmak isteyenlerin uğrak noktasıdır.", "place_query": "Murat Dağı Kaplıcaları, Banaz, Uşak"}, {"title": "Banaz İlçe Merkezi Tarihi Çarşı", "summary": "Osmanlı döneminden kalma tarihi dükkanları ve el yapımı ürünleriyle ünlüdür. Özellikle bakırcılar ve yöresel lezzetlerin satıldığı dükkanlar ziyaretçilerin ilgisini çeker.", "place_query": "Banaz Çarşı, Banaz, Uşak"}, {"title": "Akkaya Köyü Kaya Mezarları", "summary": "Frig dönemine ait olduğu düşünülen bu kaya mezarları, tarih meraklıları için büyüleyici bir duraktır. Kayalara oyulmuş bu yapılar, bölgenin antik geçmişine ışık tutar.", "place_query": "Akkaya Köyü Kaya Mezarları, Banaz, Uşak"}, {"title": "Banaz Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale kalıntıları, çevreye hakim manzarasıyla dikkat çeker. Gün batımında eşsiz bir fotoğraf karesi sunar.", "place_query": "Banaz Kalesi, Banaz, Uşak"}, {"title": "Sorkun Göleti Mesire Alanı", "summary": "Yeşillikler içindeki bu mesire alanı, aileler ve doğa severler için popüler bir piknik noktasıdır. Gölet kenarında yürüyüş yapabilir ve temiz havada vakit geçirebilirsiniz.", "place_query": "Sorkun Göleti, Banaz, Uşak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '52e69dc3-eec9-48f6-9f64-93927102cab1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Eşme Merkez Camii (Kurşunlu Camii)", "summary": "Tarihi Osmanlı dönemine uzanan, kesme taş işçiliği ve kurşun kaplı kubbesiyle dikkat çeken bir yapıdır. İlçe merkezinde yer alır ve dini mimariyi yakından görmek isteyenler için idealdir.", "place_query": "Eşme Merkez Camii, Uşak"}, {"title": "Eşme Halı ve Kilim Atölyeleri", "summary": "Yöreye özgü Eşme halılarının dokunduğu atölyeler, el sanatları ve geleneksel dokuma kültürünü tanımak için en iyi noktalardır. Ziyaretçiler halı dokuma sürecini yerinde izleyebilir.", "place_query": "Eşme halı atölyeleri, Uşak"}, {"title": "Karahisar Kalesi (Eşme)", "summary": "Eşme''nin yüksek bir tepesinde bulunan tarihi kale kalıntısı, bölgeye hakim manzarasıyla fotoğrafçılar ve tarih meraklıları için popüler bir duraktır.", "place_query": "Karahisar Kalesi, Eşme, Uşak"}, {"title": "Eşme Barajı ve Çevresi", "summary": "Doğal güzelliği ve sakin atmosferiyle piknik, yürüyüş ve olta balıkçılığı için uygun bir alandır. Özellikle bahar aylarında yeşil doğasıyla huzurlu bir kaçış noktası sunar.", "place_query": "Eşme Barajı, Uşak"}, {"title": "Güney Köyü Kaya Mezarları", "summary": "Eşme ilçesine bağlı Güney köyünde yer alan antik kaya mezarları, Frig veya Roma dönemine ait olduğu düşünülen tarihi kalıntılardır. Tarih öncesi döneme ilgi duyanlar için keşfedilmeyi bekleyen bir alandır.", "place_query": "Güney Köyü Kaya Mezarları, Eşme, Uşak"}, {"title": "Eşme Saat Kulesi", "summary": "İlçe merkezinde bulunan bu tarihi saat kulesi, Eşme''nin simgelerinden biridir. Çevresindeki çarşıyla birlikte kısa bir şehir turu için ideal bir başlangıç noktasıdır.", "place_query": "Eşme Saat Kulesi, Uşak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2da262a3-6e5a-40b7-a602-45df2b84cefa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Karahallı Kaya Mezarları", "summary": "Karahallı ilçe merkezine yakın konumda bulunan bu antik kaya mezarları, Frig dönemine ait izler taşır. Ziyaretçiler, kayalara oyulmuş bu etkileyici yapıları görerek bölgenin binlerce yıllık tarihine tanıklık edebilir.", "place_query": "Karahallı Kaya Mezarları, Karahallı, Uşak"}, {"title": "Karahallı Kaplıcaları", "summary": "Termal sularıyla ünlü bu kaplıcalar, romatizma ve cilt rahatsızlıklarına iyi geldiği düşünülen şifalı sularıyla ziyaretçileri ağırlar. Doğal bir ortamda dinlenmek ve termal banyo yapmak için ideal bir noktadır.", "place_query": "Karahallı Kaplıcaları, Karahallı, Uşak"}, {"title": "Karahallı Barajı ve Mesire Alanı", "summary": "Şehir merkezine yakın bu baraj gölü çevresinde piknik yapabilir, yürüyüş yollarında doğayla iç içe vakit geçirebilirsiniz. Özellikle hafta sonları aileler için huzurlu bir kaçış noktasıdır.", "place_query": "Karahallı Barajı, Karahallı, Uşak"}, {"title": "Karahallı Merkez Camii", "summary": "İlçenin tarihi camilerinden biri olan Merkez Camii, Osmanlı dönemi mimari özelliklerini yansıtır. Hem dini bir ziyaret noktası hem de tarihi dokuya tanıklık etmek isteyenler için önemli bir duraktır.", "place_query": "Karahallı Merkez Camii, Karahallı, Uşak"}, {"title": "Karahallı Pazarı", "summary": "Özellikle cumartesi günleri kurulan halk pazarı, yöresel ürünler, taze sebze-meyve ve el işi ürünlerle doludur. Yerel halkla kaynaşmak ve organik alışveriş yapmak için canlı bir ortam sunar.", "place_query": "Karahallı Pazarı, Karahallı, Uşak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2c469bd5-925c-4f24-9710-d06d57d185a2'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Uşak Arkeoloji Müzesi", "summary": "Uşak ve çevresindeki antik bölgelerden çıkarılan eserlerin sergilendiği bu müze, özellikle Karun Hazineleri ile ünlüdür. Lidya uygarlığına ait altın takılar, sikkeler ve günlük kullanım eşyaları ziyaretçileri büyüler.", "place_query": "Uşak Arkeoloji Müzesi, Uşak Merkez"}, {"title": "Atatürk ve Milli Mücadele Müzesi", "summary": "Kurtuluş Savaşı''nda önemli bir karargah olarak kullanılan bu tarihi bina, günümüzde müze olarak hizmet vermektedir. İçerideki balmumu heykeller ve döneme ait belgeler, ziyaretçilere duygusal bir tarih yolculuğu yaşatır.", "place_query": "Atatürk ve Milli Mücadele Müzesi, Uşak"}, {"title": "Clandıras Şelalesi", "summary": "Uşak merkeze yaklaşık 40 km uzaklıkta bulunan bu şelale, yemyeşil doğası ve serin sularıyla piknik ve doğa yürüyüşü için idealdir. Özellikle yaz aylarında şehrin gürültüsünden kaçmak isteyenlerin uğrak noktasıdır.", "place_query": "Clandıras Şelalesi, Uşak"}, {"title": "Uşak Kenti Tarihi Evleri (Küçük Menderes Mahallesi)", "summary": "Osmanlı döneminden kalma ahşap ve kerpiç yapılı bu tarihi evler, dar sokaklarıyla geçmişe yolculuk hissi verir. Özellikle fotoğraf meraklıları için eşsiz kareler sunan bu bölge, şehrin kültürel dokusunu yansıtır.", "place_query": "Uşak Tarihi Evler, Uşak Merkez"}, {"title": "Blaundos Antik Kenti", "summary": "Uşak merkeze bağlı Sülümenli köyü yakınlarında yer alan bu antik kent, Roma dönemine ait iyi korunmuş tiyatrosu ve tapınak kalıntılarıyla dikkat çeker. Tarih ve arkeoloji meraklıları için keşfedilmeyi bekleyen önemli bir noktadır.", "place_query": "Blaundos Antik Kenti, Uşak"}, {"title": "Ulucak Köyü ve Göleti", "summary": "Şehir merkezine kısa bir mesafede bulunan bu gölet, çevresindeki çam ormanları ve mesire alanlarıyla hafta sonu kaçamakları için popülerdir. Balık tutma ve doğa yürüyüşü gibi aktiviteler için de uygundur.", "place_query": "Ulucak Göleti, Uşak"}, {"title": "Elmacık Dağı ve Seyir Terası", "summary": "Uşak''ın en yüksek noktalarından biri olan Elmacık Dağı, şehri kuşbakışı gören manzarasıyla ünlüdür. Yeni yapılan seyir terası sayesinde gün batımında eşsiz fotoğraflar çekmek mümkündür.", "place_query": "Elmacık Dağı Seyir Terası, Uşak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '21cfcebd-3e2d-4f9b-ae30-9668be70c947'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sivaslı Atatürk Evi Müzesi", "summary": "Kurtuluş Savaşı''nda önemli bir rol oynayan ve Atatürk''ün bir süre konakladığı tarihi yapı, günümüzde müze olarak ziyaretçilere açıktır. O döneme ait eşyalar ve belgeler sergilenmektedir.", "place_query": "Sivaslı Atatürk Evi Müzesi, Uşak"}, {"title": "Sivaslı Kanyonu", "summary": "Muhteşem doğal kaya oluşumları ve yemyeşil bitki örtüsüyle çevrili bu kanyon, doğa yürüyüşleri ve fotoğrafçılık için idealdir. Huzurlu atmosferiyle ziyaretçilerini büyüler.", "place_query": "Sivaslı Kanyonu, Uşak"}, {"title": "Ulubey Kanyonu (Sivaslı Girişi)", "summary": "Dünyanın en büyük ikinci kanyonu olan Ulubey Kanyonu''nun Sivaslı ilçesi sınırları içinde kalan bölümü, eşsiz manzaralar sunar. Cam teras ve yürüyüş parkurlarıyla keşfedilmeyi bekler.", "place_query": "Ulubey Kanyonu Sivaslı girişi, Uşak"}, {"title": "Sivaslı Höyüğü", "summary": "Bölgenin tarih öncesi dönemlerine ışık tutan önemli bir arkeolojik alandır. Höyükte yapılan kazılarda çeşitli antik kalıntılar ve eserler gün yüzüne çıkarılmıştır.", "place_query": "Sivaslı Höyüğü, Uşak"}, {"title": "Selçikler Köyü ve Antik Kalıntılar", "summary": "Sivaslı''ya bağlı Selçikler köyünde, Roma ve Bizans dönemlerine ait antik kalıntılar ve tarihi yapılar bulunmaktadır. Tarih meraklıları için keşfedilmeyi bekleyen bir duraktır.", "place_query": "Selçikler Köyü antik kalıntılar, Sivaslı, Uşak"}, {"title": "Sivaslı Şehitliği ve Anıtı", "summary": "Kurtuluş Savaşı''nda şehit düşen askerler anısına yapılmış bu anıt ve şehitlik, tarihi bir saygı duruşu noktasıdır. Çevresi düzenlenmiş olup ziyaretçilerine manevi bir atmosfer sunar.", "place_query": "Sivaslı Şehitliği, Uşak"}, {"title": "Bulgaz Dağı Yaylaları", "summary": "Sivaslı''nın yüksek kesimlerinde yer alan Bulgaz Dağı yaylaları, serin havası ve doğal güzellikleriyle yaz aylarında kaçış noktasıdır. Yayla evleri ve doğa yürüyüşleri popülerdir.", "place_query": "Bulgaz Dağı yaylaları, Sivaslı, Uşak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '63b6acf1-8dfc-4d09-ae27-d03277e0d015'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Ulubey Kanyonu", "summary": "Dünyanın en büyük ikinci kanyonu olan bu doğa harikası, eşsiz manzaraları ve yürüyüş parkurlarıyla ziyaretçilerini büyüler. Kanyonun içinden geçen cam seyir terası, adrenalin arayanlar için unutulmaz bir deneyim sunar.", "place_query": "Ulubey Kanyonu, Ulubey, Uşak"}, {"title": "Ulubey Cam Teras", "summary": "Kanyonun en etkileyici noktalarından birinde yer alan cam seyir terası, 135 metre yükseklikten kanyonun derinliklerine bakma imkanı verir. Ziyaretçilere hem heyecan hem de muhteşem fotoğraf kareleri vaat eder.", "place_query": "Ulubey Cam Teras, Ulubey, Uşak"}, {"title": "Blaundos Antik Kenti", "summary": "Ulubey ilçe merkezine yaklaşık 20 km uzaklıktaki bu antik kent, Roma ve Bizans dönemlerine ait kalıntılarıyla tarih meraklıları için önemli bir duraktır. Özellikle tiyatro ve tapınak kalıntıları dikkat çeker.", "place_query": "Blaundos Antik Kenti, Ulubey, Uşak"}, {"title": "Ulubey Kent Müzesi", "summary": "İlçenin tarihini ve kültürünü yansıtan bu müze, arkeolojik eserler ve etnografik objelerle zengin bir koleksiyona sahiptir. Ziyaretçilere Ulubey''in geçmişine dair kapsamlı bir bakış sunar.", "place_query": "Ulubey Kent Müzesi, Ulubey, Uşak"}, {"title": "Göğem Göleti", "summary": "Doğayla iç içe bir piknik ve dinlenme alanı olan Göğem Göleti, çam ormanlarıyla çevrili huzurlu atmosferiyle bilinir. Balık tutma ve yürüyüş gibi aktiviteler için idealdir.", "place_query": "Göğem Göleti, Ulubey, Uşak"}, {"title": "Ulubey Şelalesi", "summary": "Kanyonun içinde yer alan bu şelale, özellikle bahar aylarında suyun coşkusuyla görsel bir şölen sunar. Çevresindeki doğal yürüyüş yolları, doğa severler için keşfedilmeyi bekleyen bir rotadır.", "place_query": "Ulubey Şelalesi, Ulubey, Uşak"}, {"title": "Hasköy Kaplıcaları", "summary": "Şifalı termal sularıyla ünlü bu kaplıcalar, romatizma ve cilt hastalıklarına iyi geldiği düşünülen doğal kaynaklara sahiptir. Dinlenmek ve sağlık turizmi için popüler bir destinasyondur.", "place_query": "Hasköy Kaplıcaları, Ulubey, Uşak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3a16fb5d-647f-4696-8bde-2cb23ab1765a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Bahçesaray Şelalesi", "summary": "Bahçesaray''ın simgesi haline gelmiş, yemyeşil doğa içinde çağlayan bu şelale, piknik ve doğa yürüyüşü için ideal bir noktadır.", "place_query": "Bahçesaray Şelalesi, Bahçesaray, Van"}, {"title": "Müküs Çayı Vadisi", "summary": "Bahçesaray''dan geçen Müküs Çayı''nın oluşturduğu bu derin vadi, muhteşem manzaraları ve doğal güzellikleriyle ünlüdür; kamp ve trekking için popülerdir.", "place_query": "Müküs Çayı Vadisi, Bahçesaray, Van"}, {"title": "Kambos Yaylası", "summary": "Bahçesaray''ın en yüksek ve en yeşil yaylalarından biri olan Kambos, yaz aylarında serin havası, rengarenk çiçekleri ve eşsiz doğasıyla ziyaretçilerini büyüler.", "place_query": "Kambos Yaylası, Bahçesaray, Van"}, {"title": "Narlıca Köprüsü (Tarihi Taş Köprü)", "summary": "Bahçesaray ilçe merkezinde bulunan bu tarihi taş köprü, yöresel mimarinin güzel bir örneği olup Müküs Çayı üzerinde yer almaktadır.", "place_query": "Tarihi Taş Köprü, Bahçesaray, Van"}, {"title": "Ulu Pamuk Şelalesi", "summary": "Bahçesaray''a bağlı Ulu Pamuk köyünde yer alan bu şelale, yüksekten dökülen suları ve çevresindeki el değmemiş doğasıyla görülmeye değerdir.", "place_query": "Ulu Pamuk Şelalesi, Bahçesaray, Van"}, {"title": "Sütey Yaylası", "summary": "Yemyeşil çimenler ve doğal su kaynaklarıyla bezeli Sütey Yaylası, Bahçesaray''ın sakin ve huzurlu atmosferini yaşamak isteyenler için harika bir kaçış noktasıdır.", "place_query": "Sütey Yaylası, Bahçesaray, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '37175ba8-395c-4d3a-88b3-188234247734'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Başkale Kalesi", "summary": "Tarihi bir Urartu kalesi olup bölgenin en önemli arkeolojik yapılarından biridir. Ziyaretçiler kaleyi gezerken çevredeki dağ manzaralarını da izleyebilir.", "place_query": "Başkale Kalesi, Başkale, Van"}, {"title": "Güzeldere Şelalesi", "summary": "Başkale ilçe merkezine yaklaşık 20 km uzaklıkta bulunan bu şelale, doğal güzelliği ve serin sularıyla piknik ve fotoğrafçılık için popüler bir duraktır.", "place_query": "Güzeldere Şelalesi, Başkale, Van"}, {"title": "İspiriz Dağı", "summary": "Bölgenin en yüksek zirvelerinden biri olan İspiriz Dağı, doğa yürüyüşü ve dağcılık için idealdir. Temiz havası ve eşsiz panoramik manzaralarıyla dikkat çeker.", "place_query": "İspiriz Dağı, Başkale, Van"}, {"title": "Başkale Ulu Camii", "summary": "Tarihi bir Osmanlı dönemi camisi olup, mimari detayları ve taş işçiliğiyle ilgi çeker. Hem ibadet hem de kültürel ziyaret için önemli bir noktadır.", "place_query": "Başkale Ulu Camii, Başkale, Van"}, {"title": "Aksu Çayı", "summary": "Başkale''den geçen bu doğal akarsu, çevresindeki yeşil alanlarla mesire yeri olarak kullanılır. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Aksu Çayı, Başkale, Van"}, {"title": "Başkale Eski Evleri", "summary": "Taş ve ahşap mimarisiyle dikkat çeken tarihi Başkale evleri, yöresel kültürü yansıtan sokaklarıyla fotoğraf meraklıları için güzel bir rotadır.", "place_query": "Başkale Eski Evleri, Başkale, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'de171b4a-da2b-468d-a923-af6625ddaf4f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çaldıran Ovası ve Tarihi Savaş Alanı", "summary": "Osmanlı ile Safevi Devleti arasında 1514 yılında gerçekleşen meşhur Çaldıran Savaşı''nın yapıldığı tarihi ovadır. Tarih meraklıları için büyük önem taşıyan bu alan, geniş düzlükleri ve çevresindeki dağ manzarasıyla dikkat çeker.", "place_query": "Çaldıran Ovası, Çaldıran, Van"}, {"title": "Çaldıran Şehitliği ve Anıtı", "summary": "Çaldıran Savaşı''nda hayatını kaybeden askerler anısına yapılmış olan şehitlik ve anıt, bölgenin en önemli tarihi sembollerindendir. Ziyaretçiler burada hem saygı duruşunda bulunabilir hem de savaşın izlerini görebilir.", "place_query": "Çaldıran Şehitliği, Çaldıran, Van"}, {"title": "Süphan Dağı", "summary": "Van Gölü''nün kuzeyinde yükselen ve 4.058 metre yüksekliğiyle bölgenin en büyük dağlarından biri olan Süphan Dağı, doğa yürüyüşü ve dağcılık için idealdir. Eteklerindeki volkanik araziler ve krater gölleri görülmeye değerdir.", "place_query": "Süphan Dağı, Çaldıran, Van"}, {"title": "Çaldıran Kaplıcaları", "summary": "Termal su kaynaklarıyla bilinen Çaldıran Kaplıcaları, romatizmal hastalıklara iyi gelen şifalı sularıyla ünlüdür. Doğal bir ortamda dinlenmek ve termal banyo yapmak isteyenler için popüler bir duraktır.", "place_query": "Çaldıran Kaplıcaları, Çaldıran, Van"}, {"title": "Ahlat Selçuklu Mezarlığı", "summary": "Çaldıran''a yakın konumdaki bu tarihi mezarlık, Selçuklu dönemine ait anıtsal mezar taşları ve kümbetleriyle ünlüdür. Tarihi doku ve taş işçiliğine ilgi duyanlar için önemli bir açık hava müzesi niteliğindedir.", "place_query": "Ahlat Selçuklu Mezarlığı, Ahlat, Bitlis"}, {"title": "Çaldıran Kayak Merkezi", "summary": "Kış aylarında kayak ve kış sporları yapmak isteyenler için hizmet veren bu merkez, doğal karla kaplı pistleri ve temiz havasıyla dikkat çeker. Özellikle hafta sonu kaçamakları için idealdir.", "place_query": "Çaldıran Kayak Merkezi, Çaldıran, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a2bc7665-3baf-4200-80d2-e64340336d94'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çatak Şelalesi", "summary": "İlçe merkezine yaklaşık 10 km uzaklıkta bulunan bu şelale, doğal güzelliği ve çevresindeki yemyeşil doğasıyla ziyaretçilerine huzurlu bir kaçış sunar. Özellikle bahar ve yaz aylarında suyun akışıyla büyüleyici bir manzara oluşturur.", "place_query": "Çatak Şelalesi, Çatak, Van"}, {"title": "Çatak Kalesi", "summary": "Tarihi bir Urartu kalesi olan bu yapı, ilçe merkezine hakim bir tepede yer alır. Hem tarihi dokusu hem de Van Gölü ve çevresine bakan muhteşem manzarasıyla fotoğrafçılar ve tarih meraklıları için ideal bir duraktır.", "place_query": "Çatak Kalesi, Çatak, Van"}, {"title": "Dalaklı Mahallesi (Tarihi Evler)", "summary": "Çatak''ın en eski yerleşim alanlarından biri olan Dalaklı Mahallesi, geleneksel Van taş mimarisini yansıtan tarihi evleriyle dikkat çeker. Dar sokaklarında yürüyüş yaparak bölgenin kültürel geçmişine tanıklık edebilirsiniz.", "place_query": "Dalaklı Mahallesi, Çatak, Van"}, {"title": "Çatak Yaylaları (Gevaş Yolu Üzeri)", "summary": "Çatak''ın yüksek kesimlerinde yer alan yaylalar, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popülerdir. Bölgedeki yaylalar arasında en bilinenleri Kıratlı ve Sıçanlı yaylalarıdır.", "place_query": "Çatak Yaylaları, Van"}, {"title": "Çatak Ulu Camii", "summary": "İlçe merkezinde bulunan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Sade ve etkileyici yapısıyla hem ibadet hem de tarihi bir mekan olarak ziyaret edilebilir.", "place_query": "Çatak Ulu Camii, Van"}, {"title": "Güzeldere Şelalesi (Çatak Sınırları)", "summary": "Van''ın en yüksek şelalelerinden biri olan Güzeldere Şelalesi, Çatak ilçe sınırları içinde yer alır. Doğa yürüyüşleri ve piknik için ideal olan bu alan, özellikle yaz aylarında yoğun ilgi görür.", "place_query": "Güzeldere Şelalesi, Çatak, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '829d60f9-fc6a-4f05-bbea-5c84589f9ac7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Edremit Sahili ve Yürüyüş Yolu", "summary": "Van Gölü kıyısında uzanan bu sahil şeridi, özellikle akşam yürüyüşleri ve gün batımı manzarasıyla ünlüdür. Çay bahçeleri ve dinlenme alanlarıyla yerli halkın ve turistlerin uğrak noktasıdır.", "place_query": "Edremit Sahili, Edremit, Van"}, {"title": "Akdamar Adası ve Kilisesi", "summary": "Van Gölü''ndeki bu tarihi ada, 10. yüzyıldan kalma Akdamar Kilisesi ile ünlüdür. Tekne turlarıyla ulaşılan ada, hem dini mimarisi hem de eşsiz göl manzarasıyla mutlaka görülmelidir.", "place_query": "Akdamar Adası, Gevaş, Van"}, {"title": "Van Kalesi", "summary": "Urartu Krallığı''ndan kalma bu görkemli kale, Van şehir merkezine hakim bir tepede yer alır. Tarihi yazıtları ve panoramik Van Gölü manzarasıyla en popüler turistik noktalardan biridir.", "place_query": "Van Kalesi, İpekyolu, Van"}, {"title": "Edremit Belediyesi Millet Bahçesi", "summary": "Geniş yeşil alanları, yürüyüş parkurları ve çocuk oyun alanlarıyla aileler için ideal bir dinlenme noktasıdır. Van Gölü kıyısında huzurlu bir atmosfer sunar.", "place_query": "Edremit Millet Bahçesi, Edremit, Van"}, {"title": "Van Müzesi", "summary": "Urartu dönemine ait eserlerin sergilendiği bu müze, bölgenin zengin tarihini keşfetmek için en iyi yerdir. Çivi yazılı tabletler, heykeller ve günlük yaşam objeleri dikkat çekicidir.", "place_query": "Van Müzesi, İpekyolu, Van"}, {"title": "Muradiye Şelalesi", "summary": "Van''a yaklaşık 80 km uzaklıktaki bu etkileyici şelale, doğa severler için harika bir kaçış noktasıdır. Yemyeşil çevresi ve serin sularıyla piknik ve fotoğrafçılık için idealdir.", "place_query": "Muradiye Şelalesi, Muradiye, Van"}, {"title": "Hüsrev Paşa Külliyesi", "summary": "Edremit ilçe merkezinde bulunan bu tarihi külliye, 16. yüzyılda Osmanlı döneminde inşa edilmiştir. Cami, medrese ve hamamdan oluşan yapı, bölgenin önemli tarihi miraslarındandır.", "place_query": "Hüsrev Paşa Külliyesi, Edremit, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1f0c79a6-52dd-42c3-967a-b204c720b668'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Van Kalesi", "summary": "Urartu Krallığı''na başkentlik yapmış bu görkemli kale, Van Gölü kıyısında yükselir. Tarihi surları ve bölgeye hakim manzarasıyla mutlaka görülmeli.", "place_query": "Van Kalesi, İpekyolu, Van"}, {"title": "Akdamar Adası ve Kilisesi", "summary": "Van Gölü''ndeki bu büyüleyici adada yer alan Akdamar Kilisesi, eşsiz taş işçiliği ve rölyefleriyle ünlüdür. Göl manzarası eşliğinde huzurlu bir gezi sunar.", "place_query": "Akdamar Adası, Gevaş, Van"}, {"title": "Muradiye Şelalesi", "summary": "Van''ın Muradiye ilçesinde bulunan bu şelale, yemyeşil doğası ve serin sularıyla piknik ve doğa yürüyüşü için ideal bir noktadır.", "place_query": "Muradiye Şelalesi, Muradiye, Van"}, {"title": "Van Gölü Sahili", "summary": "Türkiye''nin en büyük gölü olan Van Gölü''nün Erciş kıyıları, yürüyüş yapmak ve gün batımını izlemek için popülerdir. Özellikle yaz aylarında keyifli bir kaçış noktasıdır.", "place_query": "Van Gölü Sahili, Erciş, Van"}, {"title": "Erciş Kalesi", "summary": "İlçe merkezine yakın bir tepede yer alan bu tarihi kale, Urartu döneminden kalma kalıntıları ve çevresine hakim panoramik manzarasıyla dikkat çeker.", "place_query": "Erciş Kalesi, Erciş, Van"}, {"title": "Çelebibağı Mesire Alanı", "summary": "Erciş''e bağlı Çelebibağı Mahallesi''nde yer alan bu mesire alanı, Van Gölü kıyısında piknik yapmak, yüzmek ve kamp kurmak için tercih edilen bir doğa harikasıdır.", "place_query": "Çelebibağı Mesire Alanı, Erciş, Van"}, {"title": "Van Müzesi", "summary": "Urartu, Selçuklu ve Osmanlı dönemlerine ait zengin bir arkeolojik koleksiyona ev sahipliği yapan müze, bölge tarihini yakından tanımak için ideal bir duraktır.", "place_query": "Van Müzesi, İpekyolu, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '0790f8b5-88ef-41f4-b5a7-dc0b0684efb3'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akdamar Adası ve Akdamar Kilisesi (Kutsal Haç Kilisesi)", "summary": "Van Gölü''nün ortasındaki bu tarihi ada, 10. yüzyıldan kalma muhteşem Ermeni Katedrali ve taş kabartmalarıyla ünlüdür. Van Gölü manzarası eşliğinde yapılacak tekne turu ve ada yürüyüşü, bölgenin en popüler gezi deneyimlerinden biridir.", "place_query": "Akdamar Adası, Gevaş, Van"}, {"title": "Van Gölü Kıyıları (Gevaş Sahil Şeridi)", "summary": "Gevaş ilçe merkezinden başlayan sahil şeridi, Van Gölü''nün masmavi sularına karşı yürüyüş yapmak, piknik yapmak ve gün batımını izlemek için idealdir. Özellikle yaz aylarında yerli turistlerin uğrak noktasıdır.", "place_query": "Gevaş Sahil, Van Gölü Kıyısı, Gevaş"}, {"title": "Gevaş Selçuklu Mezarlığı", "summary": "Anadolu''daki en büyük Türk-İslam mezarlıklarından biri olan bu alan, 13. yüzyıldan kalma kümbetler, mezar taşları ve kitabeleriyle tarih meraklıları için eşsiz bir açık hava müzesidir. Akdamar yolunda kolayca ziyaret edilebilir.", "place_query": "Gevaş Selçuklu Mezarlığı, Gevaş, Van"}, {"title": "Çarpanak Adası ve Kilisesi", "summary": "Van Gölü''ndeki dört adadan biri olan Çarpanak Adası, 9. yüzyıldan kalma manastır kalıntıları ve huzurlu atmosferiyle dikkat çeker. Tekne turlarıyla ulaşılan ada, doğa ve tarih iç içe bir kaçamak sunar.", "place_query": "Çarpanak Adası, Gevaş, Van"}, {"title": "Artos Dağı", "summary": "Van Gölü''nün güneyinde yükselen 3.500 metrelik bu dağ, trekking ve doğa yürüyüşü tutkunları için popüler bir rotadır. Zirveden Van Gölü ve çevresinin panoramik manzarası görülmeye değerdir.", "place_query": "Artos Dağı, Gevaş, Van"}, {"title": "Gevaş Merkez Camii ve Tarihi Çarşı", "summary": "İlçe merkezinde yer alan tarihi cami ve çevresindeki geleneksel çarşı, yöresel el sanatları ve Van kahvaltısı için uğrak noktaları sunar. Kısa bir şehir turu için idealdir.", "place_query": "Gevaş Merkez Camii, Gevaş, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f35828b3-8dca-464b-a3c2-05295c6778dd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çavuştepe Kalesi (Sardurihinili)", "summary": "Urartu Kralı II. Sarduri tarafından M.Ö. 8. yüzyılda inşa edilen bu etkileyici kale, Gürpınar''ın en önemli tarihi hazinelerindendir. Tapınak, saray ve depo kalıntılarıyla Urartu medeniyetinin ihtişamını gözler önüne serer.", "place_query": "Çavuştepe Kalesi, Gürpınar, Van"}, {"title": "Hoşap Kalesi", "summary": "Gürpınar ilçe merkezine yaklaşık 60 km uzaklıkta, görkemli bir kaya üzerine kurulu bu Orta Çağ kalesi, bölgenin en fotojenik yapılarındandır. Mahmudi Beyleri tarafından yaptırılan kale, ihtişamlı surları ve dar geçitleriyle ziyaretçileri büyüler.", "place_query": "Hoşap Kalesi, Gürpınar, Van"}, {"title": "Gürpınar Kapalı Çarşısı", "summary": "İlçe merkezinde yer alan bu tarihi çarşı, yöresel el sanatları, Van otlu peyniri ve yöresel dokuma ürünleri almak için ideal bir durak noktasıdır. Otantik atmosferiyle alışveriş yaparken bölge kültürünü de yakından tanıma fırsatı sunar.", "place_query": "Gürpınar Kapalı Çarşısı, Gürpınar, Van"}, {"title": "Zernek Barajı ve Mesire Alanı", "summary": "Gürpınar sınırları içindeki Zernek Barajı, piknik yapmak ve doğa yürüyüşleri için popüler bir mekandır. Baraj gölü manzarası eşliğinde huzurlu bir gün geçirmek isteyenler için biçilmiş kaftandır.", "place_query": "Zernek Barajı, Gürpınar, Van"}, {"title": "Gürpınar Kayak Merkezi (Abalı Kayak Tesisi)", "summary": "Van Gölü''ne yakın konumuyla kış turizmi için gelişmekte olan bu tesis, doğal karla kaplı yamaçları ve temel pistleriyle kayak severlere hitap eder. Kış aylarında bölgeye gelenler için keyifli bir alternatif sunar.", "place_query": "Abalı Kayak Tesisi, Gürpınar, Van"}, {"title": "Gürpınar Doğa Yürüyüşü Rotaları (Güzeldere Geçidi)", "summary": "İlçenin yüksek rakımlı bölgeleri, özellikle Güzeldere Geçidi çevresi, eşsiz dağ manzaraları ve yayla atmosferiyle doğa yürüyüşçüleri için idealdir. Temiz hava ve el değmemiş doğa, bu rotaların en büyük çekiciliğidir.", "place_query": "Güzeldere Geçidi, Gürpınar, Van"}, {"title": "Muradiye Şelalesi (Gürpınar''a yakın)", "summary": "Gürpınar ilçe merkezine yaklaşık 40 km uzaklıktaki Muradiye Şelalesi, Bendimahi Çayı üzerinde yer alan ve yıl boyunca akan görkemli bir doğa harikasıdır. Özellikle bahar aylarında coşan şelale, çevresindeki mesire alanıyla piknik ve fotoğrafçılık için popülerdir.", "place_query": "Muradiye Şelalesi, Muradiye, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '4c7d1c4e-f1d4-47a0-b5ea-4a9cd9676014'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Van Kalesi", "summary": "Urartu Krallığı''nın başkenti olan bu görkemli kale, Van Gölü manzarasıyla büyüler. Tarihi surlar, tuğla yazıtlar ve açık hava müzesi atmosferiyle mutlaka görülmeli.", "place_query": "Van Kalesi, İpekyolu, Van"}, {"title": "Van Müzesi", "summary": "Urartu dönemine ait eşsiz eserler, mumyalar ve arkeolojik buluntular sergilenir. Van''ın binlerce yıllık tarihine ışık tutan en önemli kültür duraklarından biridir.", "place_query": "Van Müzesi, İpekyolu, Van"}, {"title": "Akdamar Adası ve Kilisesi", "summary": "Van Gölü''ndeki bu büyüleyici adada yer alan Akdamar Kilisesi, eşsiz taş kabartmaları ve manzarasıyla ünlüdür. Tekne turuyla ulaşılan ada, doğa ve tarih severler için idealdir.", "place_query": "Akdamar Adası, Gevaş, Van"}, {"title": "Van Gölü Sahili ve İskele Meydanı", "summary": "Şehir merkezine yakın bu sahil şeridi, yürüyüş yapmak ve gün batımını izlemek için popülerdir. Çay bahçeleri ve feribot iskelesiyle hareketli bir buluşma noktasıdır.", "place_query": "Van Gölü Sahili, İpekyolu, Van"}, {"title": "Cumhuriyet Caddesi", "summary": "İpekyolu''nun en işlek caddesi olan bu güzergâh, alışveriş ve yerel lezzetler için idealdir. Tarihi yapılar ve modern dükkanlar arasında keyifli bir gezinti sunar.", "place_query": "Cumhuriyet Caddesi, İpekyolu, Van"}, {"title": "Van Kedisi Evi (Van Kedi Villası)", "summary": "Dünyaca ünlü Van kedilerini yakından görebileceğiniz bu merkez, onların doğal yaşam alanını sunar. Özellikle hayvanseverler için eşsiz bir deneyimdir.", "place_query": "Van Kedisi Evi, İpekyolu, Van"}, {"title": "Edremit Sahili", "summary": "İpekyolu''na komşu Edremit ilçesindeki bu sahil, plajları ve piknik alanlarıyla hafta sonu kaçamakları için popülerdir. Van Gölü''nde yüzme imkânı da sunar.", "place_query": "Edremit Sahili, Edremit, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '1d7ca236-fd59-40ff-a0fd-e7b75f4de1fa'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Muradiye Şelalesi", "summary": "Van''ın en ünlü doğal güzelliklerinden biri olan bu şelale, Bendimahi Çayı üzerinde yer alır ve özellikle bahar aylarında eriyen karlarla birlikte muhteşem bir manzara sunar. Çevresindeki mesire alanı piknik ve dinlenme için idealdir.", "place_query": "Muradiye Şelalesi, Muradiye, Van"}, {"title": "Muradiye Kalesi", "summary": "Tarihi bir Urartu kalesi olan bu yapı, ilçe merkezine hakim bir tepe üzerinde kuruludur. Bölgenin stratejik önemini gözler önüne seren kale, ziyaretçilere hem tarih hem de eşsiz bir Van Gölü manzarası sunar.", "place_query": "Muradiye Kalesi, Muradiye, Van"}, {"title": "Bendimahi Çayı", "summary": "Muradiye Şelalesi''ni oluşturan bu çay, doğal yürüyüş ve fotoğrafçılık için popüler bir noktadır. Çevresindeki yeşil alanlar ve akan suyun sesi huzur verici bir atmosfer yaratır.", "place_query": "Bendimahi Çayı, Muradiye, Van"}, {"title": "Muradiye Mesire Alanı", "summary": "Şelale çevresinde konumlanmış bu mesire alanı, aileler ve doğa severler için piknik, kamp ve dinlenme imkanı sağlar. Temiz havası ve doğal güzelliğiyle hafta sonu kaçamakları için idealdir.", "place_query": "Muradiye Mesire Alanı, Muradiye, Van"}, {"title": "Çaldıran Ovası (Muradiye Sınırı)", "summary": "Tarihi Çaldıran Savaşı''na ev sahipliği yapmış bu geniş ova, Muradiye sınırlarına da yakındır. Doğal yapısı ve tarihi önemiyle keşfedilmeye değer bir açık alan gezisidir.", "place_query": "Çaldıran Ovası, Muradiye, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '675464e2-4a65-4489-91d6-b0eb4db9f9c4'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Özalp Kayak Merkezi", "summary": "Kış aylarında kayak ve snowboard yapmak isteyenler için popüler bir destinasyondur. Doğal pistleri ve temiz havasıyla ziyaretçilerine keyifli bir deneyim sunar.", "place_query": "Özalp Kayak Merkezi, Özalp, Van"}, {"title": "Özalp Çarşı Camii", "summary": "İlçe merkezinde bulunan tarihi bir camidir. Mimari yapısı ve manevi atmosferiyle hem yerli halkın hem de ziyaretçilerin uğrak noktasıdır.", "place_query": "Özalp Çarşı Camii, Özalp, Van"}, {"title": "Özalp Gölü", "summary": "Doğal güzelliği ve çevresindeki yeşil alanlarıyla piknik ve yürüyüş yapmak için idealdir. Kuş gözlemciliği için de uygun bir ortam sunar.", "place_query": "Özalp Gölü, Özalp, Van"}, {"title": "Özalp Kalesi", "summary": "Tarihi bir kalıntı olan bu yapı, bölgenin geçmişine ışık tutar. Tepe üzerinde yer alan kale, çevreye hakim manzarasıyla fotoğrafçılar için caziptir.", "place_query": "Özalp Kalesi, Özalp, Van"}, {"title": "Özalp Kapalı Spor Salonu", "summary": "Modern bir spor tesisi olup, çeşitli spor etkinliklerine ve turnuvalara ev sahipliği yapar. Spor severler için aktif bir buluşma noktasıdır.", "place_query": "Özalp Kapalı Spor Salonu, Özalp, Van"}, {"title": "Özalp Şehitlik Anıtı", "summary": "Vatan uğruna can veren şehitler anısına yapılmıştır. Anıt, ziyaretçilere duygusal bir atmosfer sunarken tarihi bir saygı duruşu imkanı verir.", "place_query": "Özalp Şehitlik Anıtı, Özalp, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '71d0ac0f-b008-4224-88d9-986b86dc2b10'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saray İlçe Merkezi", "summary": "Van''ın doğusunda, İran sınırında yer alan Saray, bölgenin en otantik ilçelerinden biridir. Gümrük kapısına yakınlığı ve sakin atmosferi ile dikkat çeker.", "place_query": "Saray, Van"}, {"title": "Muradiye Şelalesi", "summary": "Saray ilçe merkezine yaklaşık 30 km uzaklıkta bulunan bu etkileyici şelale, Bendimahi Çayı üzerinde yer alır. Özellikle bahar ve yaz aylarında doğa tutkunlarının uğrak noktasıdır.", "place_query": "Muradiye Şelalesi, Muradiye, Van"}, {"title": "Saray Göleti ve Mesire Alanı", "summary": "İlçe merkezine yakın konumdaki bu gölet, piknik ve doğa yürüyüşü için idealdir. Sakin ortamı ve yeşil alanlarıyla hafta sonu kaçamakları için popülerdir.", "place_query": "Saray Göleti, Saray, Van"}, {"title": "İran Sınır Kapısı (Kapıköy Gümrük Kapısı)", "summary": "Saray ilçesine bağlı Kapıköy''de bulunan bu sınır kapısı, İran''a açılan önemli bir geçiş noktasıdır. Bölgenin ticari ve kültürel hareketliliğini gözlemlemek için ilginç bir duraktır.", "place_query": "Kapıköy Gümrük Kapısı, Saray, Van"}, {"title": "Saray Eski Camii", "summary": "İlçe merkezinde yer alan tarihi cami, yöresel mimari özellikler taşır. Geçmişten günümüze ibadete açık olan yapı, tarih meraklıları için görülmeye değerdir.", "place_query": "Saray Eski Camii, Saray, Van"}, {"title": "Bendimahi Çayı Vadisi", "summary": "Saray ve Muradiye arasında uzanan bu vadi, doğal güzellikleri ve yürüyüş rotalarıyla bilinir. Özellikle fotoğrafçılar ve doğa sporları sevenler için keşfedilmeyi bekleyen bir bölgedir.", "place_query": "Bendimahi Çayı, Saray, Van"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'b7cafb49-b20b-45de-ac91-a68fba8f4fc7'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Van Kalesi", "summary": "Urartu Krallığı''nın başkenti Tuşba''nın üzerine kurulduğu bu görkemli kale, Van Gölü manzarasıyla büyüler. Tarihi surlar, kaya mezarları ve açık hava müzesi niteliğiyle bölgenin en önemli simgesidir.", "place_query": "Van Kalesi, Tuşba, Van"}, {"title": "Akdamar Adası ve Kilisesi", "summary": "Van Gölü''ndeki bu büyüleyici ada, eşsiz taş işçiliği ve freskleriyle ünlü Akdamar Kilisesi''ne ev sahipliği yapar. Tekne turlarıyla ulaşılan ada, hem tarih hem doğa tutkunları için unutulmaz bir duraktır.", "place_query": "Akdamar Adası, Gevaş, Van"}, {"title": "Van Müzesi", "summary": "Urartu dönemine ait çivi yazılı tabletler, bronz eserler ve bölge arkeolojisinin en değerli parçalarını sergileyen modern bir müzedir. Van''ın tarihine dair kapsamlı bir bakış sunar.", "place_query": "Van Müzesi, Tuşba, Van"}, {"title": "Hoşap Kalesi", "summary": "Gürpınar ilçesinde yer alan bu Orta Çağ kalesi, sarp kayalıklar üzerindeki etkileyici duruşuyla dikkat çeker. Osmanlı dönemine ait izler taşıyan kale, Van''ın en fotojenik yapılarından biridir.", "place_query": "Hoşap Kalesi, Gürpınar, Van"}, {"title": "Van Gölü Sahili ve İskele Meydanı", "summary": "Tuşba merkezinde yer alan bu sahil şeridi, yürüyüş yolları, kafeler ve göl manzarasıyla hem yerli halkın hem turistlerin uğrak noktasıdır. Özellikle gün batımında büyüleyici bir atmosfer sunar.", "place_query": "Van Gölü Sahili, Tuşba, Van"}, {"title": "Cumhuriyet Caddesi", "summary": "Van''ın en hareketli caddesi olan Cumhuriyet Caddesi, alışveriş olanakları, tarihi yapıları ve canlı atmosferiyle şehir turu için idealdir. Bölgedeki kafe ve restoranlarda yöresel lezzetleri tatma fırsatı bulabilirsiniz.", "place_query": "Cumhuriyet Caddesi, Tuşba, Van"}, {"title": "Edremit Sahili", "summary": "Van Gölü kıyısındaki bu huzurlu sahil, plajları, yürüyüş parkurları ve piknik alanlarıyla serinlemek ve dinlenmek isteyenler için popüler bir kaçış noktasıdır. Özel