UPDATE location_pages SET travel_ideas_json = '[{"title": "Taşköprü (Çiftlikköy)", "summary": "Tarihi bir Roma köprüsü olan Taşköprü, Çiftlikköy''ün en önemli simgelerinden biridir. Günümüzde hala ayakta olan yapı, fotoğrafçılar ve tarih meraklıları için popüler bir durak noktasıdır.", "place_query": "Taşköprü, Çiftlikköy, Yalova"}, {"title": "Kılıç Köyü Plajı", "summary": "Çiftlikköy sınırları içinde yer alan Kılıç Köyü Plajı, sakin ve temiz deniziyle bilinir. Özellikle yaz aylarında yerli halkın ve tatilcilerin uğrak noktasıdır.", "place_query": "Kılıç Köyü Plajı, Çiftlikköy, Yalova"}, {"title": "Göztepe Sahil Parkı", "summary": "Marmara Denizi kıyısında uzanan bu park, yürüyüş yolları, banklar ve yeşil alanlarıyla dinlenmek isteyenler için idealdir. Deniz manzarası eşliğinde huzurlu vakit geçirebilirsiniz.", "place_query": "Göztepe Sahil Parkı, Çiftlikköy, Yalova"}, {"title": "Çiftlikköy Belediyesi Kent Ormanı", "summary": "Şehir merkezine yakın bu ormanlık alan, piknik ve doğa yürüyüşü yapmak isteyenler için popüler bir kaçış noktasıdır. Temiz havası ve gölgelik alanlarıyla aileler tarafından sıkça tercih edilir.", "place_query": "Çiftlikköy Belediyesi Kent Ormanı, Yalova"}, {"title": "Sahil Bandı ve Yürüyüş Yolu", "summary": "Çiftlikköy sahil şeridi boyunca uzanan yürüyüş yolu, bisiklet sürmek ve deniz kenarında yürümek için idealdir. Gün batımında eşsiz manzaralar sunar.", "place_query": "Çiftlikköy Sahil Bandı, Yalova"}, {"title": "Burhaniye Koyu", "summary": "Çiftlikköy''e bağlı Burhaniye köyü sınırlarındaki bu koy, doğal güzelliği ve sakin atmosferiyle bilinir. Yüzme ve güneşlenmek için sakin bir alternatif arayanların tercihidir.", "place_query": "Burhaniye Koyu, Çiftlikköy, Yalova"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '33c1e34d-07e9-46b4-8bc6-de57768e2201'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çınarcık Plajı", "summary": "Yalova''nın en popüler denize girme noktalarından biri olan Çınarcık Plajı, ince kumu ve temiz deniziyle yaz aylarında yoğun ilgi görür. Sahil şeridinde yürüyüş yapabilir, çevredeki kafe ve restoranlarda vakit geçirebilirsiniz.", "place_query": "Çınarcık Plajı, Yalova"}, {"title": "Erikli Plajı", "summary": "Çınarcık''ın en bilinen doğal plajlarından Erikli, sakin denizi ve yeşil alanlarıyla aileler için idealdir. Kamp ve piknik yapmak isteyenlerin de sıkça tercih ettiği bir yerdir.", "place_query": "Erikli Plajı, Çınarcık, Yalova"}, {"title": "Kocadere Şelalesi", "summary": "Yemyeşil doğa içinde yer alan Kocadere Şelalesi, özellikle hafta sonu kaçamaklarında doğayla baş başa kalmak isteyenler için harika bir rotadır. Şelale çevresinde piknik yapabilir ve serin sularında ferahlayabilirsiniz.", "place_query": "Kocadere Şelalesi, Çınarcık, Yalova"}, {"title": "Taşköprü", "summary": "Tarihi bir Osmanlı dönemi köprüsü olan Taşköprü, Çınarcık''ın simge yapılarından biridir. Çevresindeki doğal güzelliklerle birlikte fotoğrafçılar ve tarih meraklıları için ilgi çekici bir duraktır.", "place_query": "Taşköprü, Çınarcık, Yalova"}, {"title": "Esenköy", "summary": "Çınarcık''a bağlı şirin bir sahil beldesi olan Esenköy, uzun plajı ve huzurlu atmosferiyle tatilcilerin gözdesidir. Deniz, kum ve güneşin tadını çıkarırken balık restoranlarında yöresel lezzetleri deneyebilirsiniz.", "place_query": "Esenköy, Çınarcık, Yalova"}, {"title": "Çınarcık Kent Ormanı", "summary": "Şehir merkezine yakın konumuyla doğa yürüyüşleri ve piknik için ideal bir alan olan Çınarcık Kent Ormanı, temiz havası ve yeşil örtüsüyle ziyaretçilerine huzur verir. Manzara seyir noktaları da mevcuttur.", "place_query": "Çınarcık Kent Ormanı, Yalova"}, {"title": "Teşvikiye Köyü", "summary": "Yalova''nın en eski ve en güzel köylerinden biri olan Teşvikiye, tarihi ahşap evleri ve doğal güzellikleriyle ünlüdür. Köy meydanında mola verip yöresel ürünler satın alabilirsiniz.", "place_query": "Teşvikiye Köyü, Çınarcık, Yalova"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f8d09a07-49dc-4a72-98fb-2c073eb67a3f'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yürüyen Köşk", "summary": "Mustafa Kemal Atatürk''ün talimatıyla bir çınar ağacına zarar vermemek için raylar üzerinde kaydırılan tarihi köşk, hem ilginç hikayesi hem de gölgesinde dinlenebileceğiniz eşsiz bir atmosfer sunar.", "place_query": "Yürüyen Köşk, Yalova Merkez, Yalova"}, {"title": "Termal Şelalesi", "summary": "Yalova Termal ilçesinde yer alan bu şelale, çevresindeki piknik alanları ve doğal güzelliğiyle hafta sonu kaçamaklarının vazgeçilmez adresidir.", "place_query": "Termal Şelalesi, Yalova"}, {"title": "Kurşunlu Şelalesi Tabiat Parkı", "summary": "Yemyeşil ormanlar arasında çağlayan şelalesi, yürüyüş parkurları ve mesire alanlarıyla doğa severler için huzurlu bir kaçış noktasıdır.", "place_query": "Kurşunlu Şelalesi Tabiat Parkı, Yalova Merkez"}, {"title": "Yalova Atatürk Köşkü", "summary": "Atatürk''ün Yalova''da kullandığı bu tarihi köşk, orijinal eşyaları ve bahçesiyle ziyaretçilerine Cumhuriyet dönemine ait bir yolculuk yaşatır.", "place_query": "Yalova Atatürk Köşkü, Yalova Merkez"}, {"title": "Yalova Sahil Bandı ve Yürüyüş Yolu", "summary": "Marmara Denizi kıyısında uzanan bu modern yürüyüş yolu, bisiklet parkuru, kafeleri ve deniz manzarasıyla şehir merkezinde keyifli bir gezinti imkanı sunar.", "place_query": "Yalova Sahil Bandı, Yalova Merkez"}, {"title": "Yalova Kent Müzesi", "summary": "Eski bir hükümet konağında hizmet veren müze, Yalova''nın tarihini, kültürünü ve doğal zenginliklerini etkileyici bir koleksiyonla sergiler.", "place_query": "Yalova Kent Müzesi, Yalova Merkez"}, {"title": "Gökçe Barajı Mesire Alanı", "summary": "Baraj gölü çevresinde kurulu bu mesire alanı, piknik yapmak, doğa yürüyüşü yapmak ve huzurlu bir gün geçirmek için idealdir.", "place_query": "Gökçe Barajı Mesire Alanı, Yalova"}, {"title": "Rüstem Paşa Camii", "summary": "Mimar Sinan''ın eseri olan bu tarihi cami, sade ama etkileyici mimarisi ve şehir merkezindeki konumuyla Yalova''nın önemli kültürel miraslarından biridir.", "place_query": "Rüstem Paşa Camii, Yalova Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'ae9ac9b3-5e91-4c04-951a-3a1abc2e1ab1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Termal Kaplıcaları (Yalova Termal Kaplıcaları)", "summary": "Yalova''nın en ünlü şifa kaynağı olan bu kaplıcalar, romatizma ve cilt rahatsızlıklarına iyi gelen sıcak sularıyla ünlüdür. Tarihi Roma dönemine uzanan tesisler, doğal güzellikler içinde huzurlu bir termal tatil deneyimi sunar.", "place_query": "Yalova Termal Kaplıcaları, Termal, Yalova"}, {"title": "Kara Göbek Şelalesi", "summary": "Yemyeşil ormanlar arasında gizlenmiş bu şelale, özellikle yaz aylarında serinlemek ve doğayla baş başa kalmak isteyenler için popüler bir piknik ve yürüyüş noktasıdır. Şelalenin çevresindeki ahşap seyir terasları eşsiz manzaralar sunar.", "place_query": "Kara Göbek Şelalesi, Termal, Yalova"}, {"title": "Erikli Yaylası", "summary": "Termal ilçesine bağlı bu yayla, yüksek rakımı ve temiz havasıyla doğa tutkunlarının uğrak noktasıdır. Yayla evleri, çam ormanları ve muhteşem manzarasıyla kampçılar ve günübirlikçiler için idealdir.", "place_query": "Erikli Yaylası, Termal, Yalova"}, {"title": "Termal Atatürk Köşkü", "summary": "Mustafa Kemal Atatürk''ün Termal''i ziyaretlerinde kullandığı tarihi köşk, günümüzde müze olarak hizmet vermektedir. Köşk, dönemin mimarisini ve Atatürk''e ait eşyaları görmek isteyen ziyaretçiler için önemli bir kültürel duraktır.", "place_query": "Atatürk Köşkü, Termal, Yalova"}, {"title": "Gökçedere Göleti ve Mesire Alanı", "summary": "Doğa içinde huzurlu bir gün geçirmek isteyenler için ideal olan bu gölet, çevresindeki piknik alanları ve yürüyüş yollarıyla ünlüdür. Gölet kenarında balık tutabilir veya sadece manzaranın tadını çıkarabilirsiniz.", "place_query": "Gökçedere Göleti, Termal, Yalova"}, {"title": "Termal Belediye Parkı", "summary": "İlçe merkezinde yer alan bu büyük park, rengarenk çiçekleri, havuzları ve dinlenme alanlarıyla özellikle aileler için popülerdir. Park içindeki yürüyüş yolları ve kafeler, termal sonrası keyifli bir mola imkanı sunar.", "place_query": "Termal Belediye Parkı, Termal, Yalova"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '18e2f2db-0d9f-4834-b496-ca25d50b2638'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Akdağmadeni Ormanları ve Yaylaları", "summary": "Yemyeşil çam ormanları ve temiz havasıyla ünlü bu bölge, doğa yürüyüşleri ve piknik için ideal bir kaçış noktasıdır. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler tarafından sıkça tercih edilir.", "place_query": "Akdağmadeni Ormanları, Yozgat"}, {"title": "Akdağmadeni Kalesi", "summary": "Tarihi bir geçmişe sahip olan bu kale, ilçeye hakim bir tepe üzerinde yer alır ve çevresine muhteşem bir manzara sunar. Ziyaretçiler, hem tarihi dokuyu hissedebilir hem de bölgenin panoramik fotoğraflarını çekebilir.", "place_query": "Akdağmadeni Kalesi, Yozgat"}, {"title": "Kazankaya Mağarası", "summary": "Doğal oluşumu ve etkileyici sarkıt-dikit yapılarıyla dikkat çeken bu mağara, macera ve doğa tutkunları için keşfedilmeyi bekleyen bir hazinedir. İçerideki serin hava ve eşsiz görüntüler ziyaretçilere unutulmaz bir deneyim yaşatır.", "place_query": "Kazankaya Mağarası, Akdağmadeni, Yozgat"}, {"title": "Ulu Camii (Akdağmadeni)", "summary": "Osmanlı döneminden kalma bu tarihi cami, zarif mimarisi ve huzur veren atmosferiyle ilçenin önemli dini yapılarındandır. Hem ibadet hem de kültürel bir ziyaret için uygun bir durak noktasıdır.", "place_query": "Ulu Camii, Akdağmadeni, Yozgat"}, {"title": "Akdağmadeni Taş Köprü", "summary": "Tarihi bir taş köprü olan bu yapı, ilçenin geçmişine tanıklık eden önemli bir kültür varlığıdır. Köprünün çevresindeki doğal doku, fotoğrafçılar ve tarih meraklıları için güzel bir fon oluşturur.", "place_query": "Akdağmadeni Taş Köprü, Yozgat"}, {"title": "Gedikli Yaylası", "summary": "Yemyeşil çayırları ve berrak havasıyla bilinen Gedikli Yaylası, özellikle yaz aylarında doğa severlerin ve kampçıların uğrak noktasıdır. Yaylada yürüyüş yapabilir, yöresel lezzetlerin tadına bakabilirsiniz.", "place_query": "Gedikli Yaylası, Akdağmadeni, Yozgat"}, {"title": "Çamlık Mesire Alanı", "summary": "Şehir merkezine yakın konumuyla kolay ulaşılabilen bu mesire alanı, aileler ve gruplar için piknik ve dinlenme imkanı sunar. Çam ağaçları arasında huzurlu bir gün geçirmek için idealdir.", "place_query": "Çamlık Mesire Alanı, Akdağmadeni, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5a41c649-b62d-44e8-a83e-a7f27799ce34'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Aydıncık Şelalesi", "summary": "Doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilere huzurlu bir ortam sunan şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenlerin uğrak noktasıdır.", "place_query": "Aydıncık Şelalesi, Yozgat"}, {"title": "Aydıncık Kalesi", "summary": "Tarihi bir yapı olan kale, bölgenin geçmişine ışık tutarken tepeden sunduğu manzarasıyla da fotoğrafçılar ve tarih meraklıları için ideal bir duraktır.", "place_query": "Aydıncık Kalesi, Yozgat"}, {"title": "Kazankaya Mağarası", "summary": "Doğal oluşumu ve ilginç kaya yapılarıyla dikkat çeken mağara, doğa yürüyüşü ve keşif yapmak isteyen macera severler için popüler bir noktadır.", "place_query": "Kazankaya Mağarası, Aydıncık, Yozgat"}, {"title": "Aydıncık Barajı", "summary": "Çevresindeki yeşil alanlar ve sakin su yüzeyiyle balık tutma, piknik ve doğa yürüyüşü gibi aktiviteler için tercih edilen huzurlu bir mesire yeridir.", "place_query": "Aydıncık Barajı, Yozgat"}, {"title": "Karaahmetli Köyü Camii", "summary": "Osmanlı dönemi mimarisini yansıtan tarihi cami, ahşap işçiliği ve sade yapısıyla kültürel bir miras olarak öne çıkar ve ziyaretçilerini geçmişe yolculuğa çıkarır.", "place_query": "Karaahmetli Köyü Camii, Aydıncık, Yozgat"}, {"title": "Aydıncık Merkez Parkı", "summary": "İlçe merkezinde yer alan bu park, dinlenme bankları, yürüyüş yolları ve çocuk oyun alanlarıyla ailelerin ve yerel halkın günlük gezileri için keyifli bir mekandır.", "place_query": "Aydıncık Merkez Parkı, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'f96472c2-b296-4cbe-897f-c83173bc7634'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Boğazlıyan Şehitler Parkı", "summary": "İlçe merkezinde yer alan bu park, Boğazlıyan''ın simgelerinden biridir ve özellikle Mehmetçik anıtı ile dikkat çeker. Yürüyüş yapmak ve dinlenmek için halkın uğrak noktasıdır.", "place_query": "Boğazlıyan Şehitler Parkı, Boğazlıyan, Yozgat"}, {"title": "Boğazlıyan Merkez Camii", "summary": "Osmanlı dönemi mimarisinin izlerini taşıyan bu tarihi cami, ilçenin en önemli dini yapılarındandır. Şehir merkezinde kolayca ziyaret edilebilir.", "place_query": "Merkez Camii, Boğazlıyan, Yozgat"}, {"title": "Yozgat Çamlık Milli Parkı", "summary": "Boğazlıyan''a yaklaşık 30 km uzaklıktaki bu milli park, Türkiye''nin ilk milli parklarından biridir. Binlerce çam ağacıyla kaplı alan, piknik ve doğa yürüyüşü için idealdir.", "place_query": "Yozgat Çamlık Milli Parkı, Yozgat Merkez"}, {"title": "Boğazlıyan Halk Eğitim Merkezi Sergi Salonu", "summary": "Yöresel el sanatları ve kültürel ürünlerin sergilendiği bu mekan, Boğazlıyan''ın geleneksel dokusunu yakından tanımak isteyenler için güzel bir duraktır.", "place_query": "Boğazlıyan Halk Eğitim Merkezi, Boğazlıyan, Yozgat"}, {"title": "Kazankaya Vadisi", "summary": "Boğazlıyan ilçe sınırları içinde kalan bu vadi, doğal kaya oluşumları ve yeşil dokusuyla doğa fotoğrafçıları için keşfedilmeyi bekleyen bir alandır.", "place_query": "Kazankaya Vadisi, Boğazlıyan, Yozgat"}, {"title": "Sorgun Kaplıcaları", "summary": "Boğazlıyan''a yaklaşık 20 km mesafedeki Sorgun ilçesinde yer alan bu kaplıcalar, şifalı suları ve termal tesisleriyle bölgenin en popüler sağlık turizmi noktalarındandır.", "place_query": "Sorgun Kaplıcaları, Sorgun, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'd7c63ffd-7b2d-4cf1-9ec6-406714bbd28a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çandır Kalesi", "summary": "İlçe merkezine hakim bir tepe üzerinde yer alan tarihi kale, bölgenin en önemli simgelerindendir. Kaleye çıktığınızda Çandır ve çevresinin panoramik manzarasını izleyebilirsiniz.", "place_query": "Çandır Kalesi, Çandır, Yozgat"}, {"title": "Çandır Saat Kulesi", "summary": "Cumhuriyet döneminde inşa edilen bu şirin saat kulesi, ilçe merkezinde buluşma noktası olarak bilinir. Çevresindeki çay bahçelerinde dinlenip yöresel lezzetleri tadabilirsiniz.", "place_query": "Çandır Saat Kulesi, Çandır, Yozgat"}, {"title": "Çandır Göleti ve Mesire Alanı", "summary": "Doğayla iç içe vakit geçirmek isteyenler için ideal olan gölet, piknik alanları ve yürüyüş yollarıyla donatılmıştır. Hafta sonu aile gezileri için sıkça tercih edilir.", "place_query": "Çandır Göleti, Çandır, Yozgat"}, {"title": "Yozgat Çamlığı Milli Parkı (Çandır yolu üzeri)", "summary": "Yozgat merkeze yaklaşık 20 km mesafedeki bu milli park, endemik bitki örtüsü ve temiz havasıyla ünlüdür. Çandır''dan kısa bir araç yolculuğuyla ulaşabilir, doğa yürüyüşü yapabilirsiniz.", "place_query": "Yozgat Çamlığı Milli Parkı, Yozgat"}, {"title": "Çandır Eski Hamamı", "summary": "Geçmişi Osmanlı dönemine uzanan tarihi hamam, ilçenin kültürel miraslarından biridir. Restore edilmiş yapısıyla hem tarihi dokuyu hisseder hem de geleneksel hamam keyfi yaşayabilirsiniz.", "place_query": "Çandır Eski Hamamı, Çandır, Yozgat"}, {"title": "Kazankaya Kanyonu (Çandır yakınları)", "summary": "Çandır ilçe sınırlarına yakın konumdaki bu etkileyici kanyon, doğa sporları ve fotoğrafçılık için popülerdir. Sarp kayalıkları ve yeşil doğasıyla görülmeye değer bir noktadır.", "place_query": "Kazankaya Kanyonu, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '33df4c86-e615-43c3-8d1e-0c8ca7b51a8e'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çayıralan Kalesi", "summary": "Tarihi bir kaledir ve bölgenin en önemli tarihi yapılarından biridir. Ziyaretçiler, kaleyi gezerken hem tarihi dokuyu hissedebilir hem de çevredeki doğal manzarayı seyredebilir.", "place_query": "Çayıralan Kalesi, Çayıralan, Yozgat"}, {"title": "Çayıralan Şelalesi", "summary": "Doğal güzelliği ile ünlü olan bu şelale, özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek isteyenler için popüler bir duraktır. Çevresindeki yeşil alanlar piknik için idealdir.", "place_query": "Çayıralan Şelalesi, Çayıralan, Yozgat"}, {"title": "Çayıralan Göleti", "summary": "Yapay bir gölet olmasına rağmen doğal bir görünüme sahiptir. Balık tutma, yürüyüş ve piknik gibi aktiviteler için sıkça tercih edilir, özellikle hafta sonları ailelerin uğrak noktasıdır.", "place_query": "Çayıralan Göleti, Çayıralan, Yozgat"}, {"title": "Çayıralan Mesire Alanı", "summary": "Şehir merkezine yakın, geniş yeşil alanlara sahip bir mesire yeridir. Ağaçlık alanları ve temiz havasıyla doğa yürüyüşleri ve piknik için idealdir.", "place_query": "Çayıralan Mesire Alanı, Çayıralan, Yozgat"}, {"title": "Çayıralan Merkez Camii", "summary": "İlçenin merkezinde bulunan bu tarihi cami, mimarisi ve manevi atmosferiyle dikkat çeker. Hem ibadet hem de tarihi bir yapıyı görmek isteyenler tarafından ziyaret edilir.", "place_query": "Çayıralan Merkez Camii, Çayıralan, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a5e1ef02-9c73-4ee4-952a-28a554d60612'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çekerek Şelalesi", "summary": "İlçe merkezine yakın konumda yer alan bu şelale, doğal güzelliği ve çevresindeki piknik alanlarıyla ziyaretçilerine huzurlu bir gün geçirme imkanı sunar.", "place_query": "Çekerek Şelalesi, Çekerek, Yozgat"}, {"title": "Çekerek Kalesi", "summary": "Tarihi bir tepe üzerinde kurulu olan kale, bölgenin stratejik önemini gözler önüne serer ve çevresine hakim manzarasıyla fotoğrafçılar için idealdir.", "place_query": "Çekerek Kalesi, Çekerek, Yozgat"}, {"title": "Kazankaya Mağarası", "summary": "Doğal oluşumlu bu mağara, ilçe sınırları içerisinde keşfedilmeyi bekleyen önemli bir doğa harikasıdır ve mağara turizmi meraklıları için ilgi çekicidir.", "place_query": "Kazankaya Mağarası, Çekerek, Yozgat"}, {"title": "Çekerek Barajı", "summary": "Bölgenin en büyük su kaynaklarından biri olan baraj, çevresindeki yeşil alanlar ve mesire yerleri ile doğa yürüyüşü ve piknik için popüler bir duraktır.", "place_query": "Çekerek Barajı, Çekerek, Yozgat"}, {"title": "Gedikli Köyü Tarihi Evleri", "summary": "Geleneksel mimariyi yansıtan bu tarihi evler, yöresel yaşam kültürünü yakından tanımak isteyen ziyaretçiler için eşsiz bir atmosfer sunar.", "place_query": "Gedikli Köyü Tarihi Evleri, Çekerek, Yozgat"}, {"title": "Çekerek Yaylası", "summary": "Yemyeşil doğası, temiz havası ve serin yayla iklimi ile özellikle yaz aylarında şehir gürültüsünden uzaklaşmak isteyenler için ideal bir kaçış noktasıdır.", "place_query": "Çekerek Yaylası, Çekerek, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '90b19012-5c1d-4c71-86a6-4118f581bdfd'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Kadışehri Kalesi", "summary": "İlçe merkezinde yer alan tarihi bir kaledir. Bölgenin savunma yapılarından biri olarak bilinir ve çevresindeki manzarasıyla ziyaretçilerine keyifli bir seyir imkanı sunar.", "place_query": "Kadışehri Kalesi, Kadışehri, Yozgat"}, {"title": "Kadışehri Ulu Camii", "summary": "İlçenin en önemli tarihi ibadet yapılarından biridir. Osmanlı dönemi mimarisinin izlerini taşıyan cami, sade ve huzurlu atmosferiyle dikkat çeker.", "place_query": "Kadışehri Ulu Camii, Kadışehri, Yozgat"}, {"title": "Kadışehri Kapalı Pazar Yeri", "summary": "Yöre halkının alışveriş için buluştuğu canlı bir merkezdir. Özellikle haftalık kurulan pazarında yöresel ürünleri ve el emeği eşyaları bulabilirsiniz.", "place_query": "Kadışehri Kapalı Pazar Yeri, Kadışehri, Yozgat"}, {"title": "Çeşka Köprüsü", "summary": "Kadışehri yakınlarındaki tarihi bir köprüdür. Taş işçiliği ve kemer yapısıyla dikkat çeken köprü, fotoğrafçılar ve tarih meraklıları için güzel bir durak noktasıdır.", "place_query": "Çeşka Köprüsü, Kadışehri, Yozgat"}, {"title": "Kadışehri Mesire Alanı", "summary": "İlçe merkezine yakın, yeşil alanları ve piknik imkanlarıyla bilinen bir dinlenme yeridir. Doğayla iç içe vakit geçirmek isteyenler için idealdir.", "place_query": "Kadışehri Mesire Alanı, Kadışehri, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '7e0511e2-317e-4f0f-ac65-0e514c1b0dee'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yozgat Çamlığı Milli Parkı", "summary": "Türkiye''nin ilk milli parkı olma özelliğini taşıyan bu doğal alan, şehir merkezine yürüme mesafesindedir. Binlerce çam ağacı, yürüyüş yolları ve piknik alanlarıyla doğayla iç içe huzurlu bir kaçış noktasıdır.", "place_query": "Yozgat Çamlığı Milli Parkı, Merkez, Yozgat"}, {"title": "Yozgat Saat Kulesi", "summary": "1908 yılında II. Abdülhamid döneminde inşa edilen bu tarihi kule, şehrin simgelerinden biridir. Altıgen gövdeli yapısı ve Osmanlı mimarisiyle şehir merkezinde dikkat çeker.", "place_query": "Yozgat Saat Kulesi, Merkez, Yozgat"}, {"title": "Yozgat Arkeoloji Müzesi", "summary": "Bölgedeki kazılardan çıkarılan Hitit, Frig, Roma ve Bizans dönemlerine ait eserlerin sergilendiği müze, tarih meraklıları için önemli bir duraktır. Özellikle Pişmiş Toprak Eserler Koleksiyonu dikkat çekicidir.", "place_query": "Yozgat Arkeoloji Müzesi, Merkez, Yozgat"}, {"title": "Büyüknefes Sultan Şehri (Tavium Antik Kenti)", "summary": "Yozgat merkeze bağlı Büyüknefes köyünde yer alan bu antik kent, Hititlerden Roma''ya kadar birçok medeniyete ev sahipliği yapmıştır. Roma döneminde Galatia eyaletinin başkenti olan Tavium''un kalıntıları görülmeye değerdir.", "place_query": "Tavium Antik Kenti, Büyüknefes, Yozgat"}, {"title": "Çapanoğlu Cami", "summary": "1779 yılında Çapanoğlu Mustafa Paşa tarafından yaptırılan bu tarihi cami, Osmanlı taş işçiliğinin güzel örneklerindendir. Kesme taştan yapılmış kubbesi ve zarif minaresiyle şehrin en önemli dini yapılarındandır.", "place_query": "Çapanoğlu Cami, Merkez, Yozgat"}, {"title": "Yozgat Kalesi", "summary": "Şehir merkezine 10 km uzaklıkta bir tepe üzerinde yer alan kale, Roma ve Bizans dönemlerine tarihlenmektedir. Günümüze ulaşan sur kalıntıları ve burçlarıyla tarihi bir atmosfer sunar; ayrıca tepeden şehir manzarası izlenebilir.", "place_query": "Yozgat Kalesi, Merkez, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3048e81c-19fe-434c-92a0-e43caaac046a'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Saraykent Kalesi", "summary": "Tarihi bir kale olup, bölgenin geçmişine ışık tutan önemli bir yapıdır. Ziyaretçiler, kaleyi gezerek tarihi atmosferi soluyabilir ve çevredeki manzarayı izleyebilir.", "place_query": "Saraykent Kalesi, Saraykent, Yozgat"}, {"title": "Çamlık Milli Parkı", "summary": "Doğal güzellikleriyle ünlü bu milli park, piknik ve doğa yürüyüşleri için idealdir. Zengin bitki örtüsü ve temiz havasıyla ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Çamlık Milli Parkı, Saraykent, Yozgat"}, {"title": "Saraykent Şelalesi", "summary": "Doğal bir şelale olup, serin suları ve çevresindeki yeşil alanlarla doğa severlerin uğrak noktasıdır. Özellikle yaz aylarında serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Saraykent Şelalesi, Saraykent, Yozgat"}, {"title": "Saraykent Müzesi", "summary": "Yöresel tarih ve kültürü yansıtan eserlerin sergilendiği küçük ama etkileyici bir müzedir. Ziyaretçiler, bölgenin geçmişine dair önemli bilgiler edinebilir.", "place_query": "Saraykent Müzesi, Saraykent, Yozgat"}, {"title": "Yozgat Çamlığı Tabiat Parkı", "summary": "Saraykent''e yakın konumda bulunan bu tabiat parkı, geniş çam ormanları ve yürüyüş parkurlarıyla ünlüdür. Doğa ile baş başa kalmak ve kamp yapmak isteyenler için harika bir seçenektir.", "place_query": "Yozgat Çamlığı Tabiat Parkı, Yozgat"}, {"title": "Kazankaya Kanyonu", "summary": "Saraykent ilçe sınırları içinde yer alan bu etkileyici kanyon, jeolojik yapısı ve doğal güzelliği ile dikkat çeker. Doğa yürüyüşü ve fotoğrafçılık için popüler bir noktadır.", "place_query": "Kazankaya Kanyonu, Saraykent, Yozgat"}, {"title": "Saraykent Seyir Tepesi", "summary": "İlçeye hakim bir tepede bulunan bu seyir noktası, muhteşem manzarasıyla ziyaretçilerini büyüler. Özellikle gün batımında eşsiz bir görsel şölen sunar.", "place_query": "Saraykent Seyir Tepesi, Saraykent, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c007d6e1-91be-462f-9216-535f44ac569b'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Sarıkaya Roma Hamamı", "summary": "Roma döneminden kalma bu antik hamam, ilçenin en önemli tarihi yapısıdır. Frigya bölgesinin önemli merkezlerinden biri olan yapı, günümüze kadar büyük ölçüde sağlam kalmıştır.", "place_query": "Sarıkaya Roma Hamamı, Sarıkaya, Yozgat"}, {"title": "Sarıkaya Kaplıcaları", "summary": "Şifalı sularıyla ünlü bu kaplıcalar, romatizma ve cilt hastalıklarına iyi geldiği bilinen termal kaynaklara ev sahipliği yapar. Doğal güzellikler içinde şifa bulmak isteyenler için ideal bir duraktır.", "place_query": "Sarıkaya Kaplıcaları, Sarıkaya, Yozgat"}, {"title": "Sarıkaya Kalesi", "summary": "Tarihi bir tepe üzerine kurulu olan bu kale, bölgeye hakim bir manzaraya sahiptir. Geçmişte savunma amaçlı kullanılan yapı, günümüzde ziyaretçilere tarihi bir yolculuk sunar.", "place_query": "Sarıkaya Kalesi, Sarıkaya, Yozgat"}, {"title": "Çokradan Köprüsü", "summary": "Tarihi bir Osmanlı köprüsü olan Çokradan Köprüsü, taş işçiliği ve mimarisiyle dikkat çeker. Çevresindeki doğal alan, piknik ve dinlenme için uygun bir ortam sağlar.", "place_query": "Çokradan Köprüsü, Sarıkaya, Yozgat"}, {"title": "Sarıkaya Müzesi", "summary": "İlçenin tarihini ve kültürünü yansıtan eserlerin sergilendiği bu müze, arkeolojik buluntular ve etnografik objelerle ziyaretçilerine zengin bir deneyim sunar.", "place_query": "Sarıkaya Müzesi, Sarıkaya, Yozgat"}, {"title": "Yozgat Çamlığı Milli Parkı", "summary": "Sarıkaya''ya yaklaşık 30 km mesafede bulunan bu milli park, Türkiye''nin ilk milli parkı olma özelliğini taşır. Çam ormanları, yürüyüş parkurları ve temiz havasıyla doğa severler için harika bir kaçış noktasıdır.", "place_query": "Yozgat Çamlığı Milli Parkı, Yozgat Merkez, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3ee1bca8-b126-4ce8-abdd-ee140f7ce5ae'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Şefaatli Kalesi", "summary": "İlçe merkezine yakın bir tepede yer alan tarihi bir kaledir. Bölgenin hakimiyet tarihine ışık tutan yapı, çevresindeki doğal manzarasıyla da ziyaretçilerine keyifli bir seyir imkanı sunar.", "place_query": "Şefaatli Kalesi, Şefaatli, Yozgat"}, {"title": "Paşa Hanı", "summary": "Osmanlı dönemine ait tarihi bir handır. İlçenin eski ticaret ve konaklama kültürünü yansıtan yapı, mimarisiyle dikkat çeker.", "place_query": "Paşa Hanı, Şefaatli, Yozgat"}, {"title": "Şefaatli Ulu Camii", "summary": "İlçenin en büyük ve tarihi camilerinden biridir. Kesme taş işçiliği ve sade mimarisiyle dikkat çeken yapı, ibadet ve ziyaret için önemli bir noktadır.", "place_query": "Şefaatli Ulu Camii, Şefaatli, Yozgat"}, {"title": "Karahöyük Höyüğü", "summary": "İlçe sınırları içinde yer alan arkeolojik bir höyüktür. Bölgedeki eski yerleşimlere dair izler taşıyan höyük, tarih meraklıları için keşfedilmeyi bekleyen bir alandır.", "place_query": "Karahöyük Höyüğü, Şefaatli, Yozgat"}, {"title": "Şefaatli Barajı", "summary": "İlçe merkezine yakın konumdaki baraj, piknik ve doğa yürüyüşü için ideal bir alandır. Kuş gözlemi ve huzurlu bir gün geçirmek isteyenler için sakin bir kaçış noktasıdır.", "place_query": "Şefaatli Barajı, Şefaatli, Yozgat"}, {"title": "Şefaatli Saat Kulesi", "summary": "İlçe merkezinde bulunan bu küçük saat kulesi, Şefaatli''nin sembol yapılarından biridir. Çevresindeki alan, dinlenmek ve fotoğraf çekmek için uygundur.", "place_query": "Şefaatli Saat Kulesi, Şefaatli, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '5a6f5e98-c067-4a41-be61-4c8e62d96de9'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yozgat Çamlığı Milli Parkı", "summary": "Türkiye''nin ilk milli parkı olma özelliğini taşıyan bu alan, Sorgun ilçe merkezine yaklaşık 30 km uzaklıktadır. Binlerce ağaçtan oluşan eşsiz doğası ve yürüyüş parkurlarıyla piknik ve doğa severler için ideal bir kaçış noktasıdır.", "place_query": "Yozgat Çamlığı Milli Parkı, Yozgat"}, {"title": "Sorgun Kent Ormanı", "summary": "Sorgun ilçe merkezinde yer alan bu rekreasyon alanı, yürüyüş yolları ve yeşil alanlarıyla halkın en çok tercih ettiği dinlenme noktalarından biridir. Özellikle hafta sonları aileler tarafından yoğun olarak ziyaret edilir.", "place_query": "Sorgun Kent Ormanı, Sorgun, Yozgat"}, {"title": "Sorgun Taşköprü", "summary": "Tarihi bir Osmanlı dönemi köprüsü olan Taşköprü, Sorgun''un önemli kültürel mirasları arasında yer alır. Bölgeye gelen ziyaretçilerin mutlaka görmesi gereken bu yapı, fotoğrafçılar için de güzel bir durak noktasıdır.", "place_query": "Taşköprü, Sorgun, Yozgat"}, {"title": "Sorgun Çatak Göleti", "summary": "Sorgun ilçesine bağlı bir alanda bulunan bu gölet, çevresindeki piknik alanları ve doğal güzelliği ile bilinir. Balık tutma ve doğa yürüyüşü gibi aktiviteler için sıkça ziyaret edilen bir mekandır.", "place_query": "Çatak Göleti, Sorgun, Yozgat"}, {"title": "Sorgun Yeraltı Şehri", "summary": "Sorgun ilçe sınırları içinde keşfedilen bu tarihi yeraltı şehri, bölgenin zengin tarihine ışık tutmaktadır. Hitit ve Roma dönemlerine ait olduğu düşünülen bu yapı, tarih meraklıları için etkileyici bir keşif alanı sunar.", "place_query": "Sorgun Yeraltı Şehri, Sorgun, Yozgat"}, {"title": "Sorgun Merkez Cami", "summary": "Sorgun ilçe merkezinde yer alan bu tarihi cami, mimarisi ve manevi atmosferi ile dikkat çeker. Osmanlı döneminden kalma bu yapı, bölgenin dini ve kültürel tarihine tanıklık etmek isteyenler için önemli bir duraktır.", "place_query": "Sorgun Merkez Cami, Sorgun, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '3dc971b0-6246-4639-b39e-6af0403d4e53'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Çamlık Milli Parkı", "summary": "Yozgat''ın en önemli mesire alanlarından biri olan Çamlık, piknik yapmak ve doğa yürüyüşleri için idealdir. Bol oksijenli havası ve yeşil doğasıyla ziyaretçilerine huzurlu bir ortam sunar.", "place_query": "Çamlık Milli Parkı, Yozgat"}, {"title": "Yozgat Saat Kulesi", "summary": "Yozgat''ın simgesi haline gelmiş olan bu tarihi saat kulesi, şehir merkezinde yer alır. 19. yüzyıldan kalma yapı, hem mimarisiyle hem de şehrin manzarasını izleme noktası olarak ilgi çeker.", "place_query": "Yozgat Saat Kulesi, Yozgat Merkez"}, {"title": "Yozgat Müzesi", "summary": "Bölgedeki arkeolojik ve etnografik eserlerin sergilendiği müze, Hitit ve Roma dönemlerine ait buluntularla tarihe ışık tutar. Ziyaretçiler için eğitici bir deneyim sunar.", "place_query": "Yozgat Müzesi, Yozgat Merkez"}, {"title": "Kerkenes Harabeleri", "summary": "Yozgat yakınlarındaki bu antik kent, Demir Çağı''na ait surları ve kalıntılarıyla dikkat çeker. Tarih meraklıları için keşfedilmeyi bekleyen önemli bir arkeolojik alandır.", "place_query": "Kerkenes Harabeleri, Yozgat"}, {"title": "Akdağmadeni Ormanları", "summary": "Yozgat''ın Akdağmadeni ilçesinde yer alan bu geniş ormanlık alan, doğa yürüyüşleri ve kampçılık için popülerdir. Zengin bitki örtüsü ve temiz havasıyla doğa severleri kendine çeker.", "place_query": "Akdağmadeni Ormanları, Yozgat"}, {"title": "Sorgun Göleti", "summary": "Yozgat''ın Sorgun ilçesinde bulunan bu yapay gölet, piknik ve balık tutma imkanı sunar. Çevresindeki yeşil alanlar, hafta sonu kaçamakları için sakin bir ortam sağlar.", "place_query": "Sorgun Göleti, Yozgat"}, {"title": "Bozok Yaylası", "summary": "Yozgat''ın yüksek kesimlerinde yer alan Bozok Yaylası, yaz aylarında serin havası ve manzarasıyla ünlüdür. Yayla turizmi için ideal bir nokta olup, geleneksel yaşamı gözlemleme fırsatı verir.", "place_query": "Bozok Yaylası, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'c72bb0fb-de5d-45db-adde-2b3ba3e9e2fe'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Yerköy Şelalesi", "summary": "Yozgat''ın doğal güzelliklerinden biri olan bu şelale, özellikle yaz aylarında serinlemek ve piknik yapmak için ideal bir noktadır. Çevresindeki yeşil alanlar ve akan suyun sesi huzur verici bir atmosfer sunar.", "place_query": "Yerköy Şelalesi, Yerköy, Yozgat"}, {"title": "Yerköy Kalesi", "summary": "Tarihi bir kalıntı olan Yerköy Kalesi, bölgenin geçmişine ışık tutar ve ziyaretçilere etkileyici bir manzara sunar. Kalenin bulunduğu tepe, çevreyi kuşbakışı görmek için harika bir seyir noktasıdır.", "place_query": "Yerköy Kalesi, Yerköy, Yozgat"}, {"title": "Yerköy Kapalı Çarşısı", "summary": "Yöresel ürünlerin ve el sanatlarının satıldığı bu tarihi çarşı, alışveriş yapmak ve Yozgat kültürünü yakından tanımak için popüler bir duraktır. Özellikle hafta sonları canlı ve hareketli bir atmosfere sahiptir.", "place_query": "Yerköy Kapalı Çarşısı, Yerköy, Yozgat"}, {"title": "Yerköy Müzesi", "summary": "Küçük ama zengin bir koleksiyona sahip olan müze, bölgedeki arkeolojik buluntuları ve etnografik eserleri sergiler. Tarih meraklıları için Yerköy''ün geçmişine dair önemli bilgiler sunar.", "place_query": "Yerköy Müzesi, Yerköy, Yozgat"}, {"title": "Yerköy Göleti ve Mesire Alanı", "summary": "Doğa ile iç içe vakit geçirmek isteyenler için ideal bir mekandır. Gölet çevresinde yürüyüş yapabilir, piknik yapabilir veya sadece manzaranın tadını çıkarabilirsiniz.", "place_query": "Yerköy Göleti, Yerköy, Yozgat"}, {"title": "Yerköy Ulu Camii", "summary": "Mimari açıdan dikkat çeken bu tarihi cami, şehrin merkezinde yer alır ve ibadet ile ziyaret için önemli bir noktadır. Sade ve etkileyici yapısıyla fotoğrafçılar için de güzel bir karedir.", "place_query": "Yerköy Ulu Camii, Yerköy, Yozgat"}, {"title": "Yerköy Tren Garı", "summary": "Tarihi bir yapı olan gar, demiryolu tutkunları ve nostalji sevenler için ilgi çekicidir. Gar binası ve çevresi, eski dönemlerin atmosferini yansıtır.", "place_query": "Yerköy Tren Garı, Yerköy, Yozgat"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '08b7e903-f388-4a89-b186-a3ad423b2c70'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Alaplı Çayı ve Mesire Alanı", "summary": "Alaplı ilçe merkezinden geçen çayın etrafında piknik yapabileceğiniz, doğayla iç içe vakit geçirebileceğiniz huzurlu bir mesire alanıdır. Özellikle yaz aylarında serinlemek ve dinlenmek için yerel halkın uğrak noktasıdır.", "place_query": "Alaplı Çayı Mesire Alanı, Alaplı, Zonguldak"}, {"title": "Kocaman Tepesi", "summary": "Alaplı''nın yüksek noktalarından biri olan Kocaman Tepesi, eşsiz Karadeniz manzarası ve yeşilin her tonunu görebileceğiniz bir seyir noktasıdır. Doğa yürüyüşü ve fotoğrafçılık için idealdir.", "place_query": "Kocaman Tepesi, Alaplı, Zonguldak"}, {"title": "Alaplı Merkez Camii", "summary": "İlçenin en bilinen tarihi yapılarından biri olan bu cami, Osmanlı dönemi mimarisinin izlerini taşır ve merkezi konumuyla ziyaretçilerin ilgisini çeker.", "place_query": "Alaplı Merkez Camii, Alaplı, Zonguldak"}, {"title": "Alaplı Sahil Bandı", "summary": "Karadeniz kıyısında uzanan bu sahil bandı, yürüyüş yapmak, deniz havası almak ve gün batımını izlemek için popüler bir yerdir. Yakınındaki kafe ve restoranlar sayesinde keyifli vakit geçirebilirsiniz.", "place_query": "Alaplı Sahil Bandı, Alaplı, Zonguldak"}, {"title": "Gümeli Yaylası", "summary": "Alaplı''ya bağlı Gümeli köyü sınırlarında yer alan bu yayla, zengin bitki örtüsü ve serin havasıyla doğa tutkunları için kaçış noktasıdır. Yayla evlerinde konaklama imkanı da bulunur.", "place_query": "Gümeli Yaylası, Alaplı, Zonguldak"}, {"title": "Alaplı Eski Hamam", "summary": "Geçmişten günümüze ulaşan bu tarihi hamam, ilçenin kültürel mirasını yansıtır. Restore edilmiş yapısıyla hem tarihi dokuyu hissetmek hem de geleneksel hamam keyfi yapmak için uğranabilir.", "place_query": "Alaplı Eski Hamam, Alaplı, Zonguldak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '27762878-f7c8-4e67-be39-15c22adb38e1'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Filyos Antik Kenti (Teion)", "summary": "MÖ 7. yüzyıla kadar uzanan tarihiyle Karadeniz''in önemli antik kentlerinden biridir. Kazılarda ortaya çıkarılan tiyatro, tapınak kalıntıları ve surlar ziyaretçilere açıktır.", "place_query": "Filyos Antik Kenti, Çaycuma, Zonguldak"}, {"title": "Filyos Plajı", "summary": "Karadeniz''in en uzun ve bakir plajlarından biri olan Filyos Plajı, ince kumlu sahili ve dalgasız deniziyle aileler için idealdir. Plaj boyunca yürüyüş yapabilir veya denizin tadını çıkarabilirsiniz.", "place_query": "Filyos Plajı, Çaycuma, Zonguldak"}, {"title": "Çaycuma Kent Ormanı", "summary": "Şehir merkezine yakın, yeşil alanları ve yürüyüş parkurlarıyla piknik ve doğa yürüyüşü için popüler bir noktadır. Çocuk oyun alanları ve dinlenme bankları bulunur.", "place_query": "Çaycuma Kent Ormanı, Çaycuma, Zonguldak"}, {"title": "Gökçebey Şelalesi", "summary": "Çaycuma''ya bağlı Gökçebey ilçesinde yer alan bu şelale, doğal havuzları ve çevresindeki yemyeşil ormanla serinlemek ve doğayla iç içe vakit geçirmek için tercih edilir.", "place_query": "Gökçebey Şelalesi, Zonguldak"}, {"title": "Çaycuma Tarihi Saat Kulesi", "summary": "Cumhuriyet döneminin simge yapılarından olan saat kulesi, ilçe merkezinde yer alır ve çevresindeki tarihi çarşıyla birlikte gezilebilir. Özellikle akşam saatlerinde ışıklandırmasıyla dikkat çeker.", "place_query": "Çaycuma Saat Kulesi, Çaycuma, Zonguldak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a83d4ae1-5227-4bfa-b781-ab74ea6485cb'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Devrek Bastonu ve El Sanatları Müzesi", "summary": "Devrek''in dünyaca ünlü bastonlarının yapımını ve tarihini yakından görebileceğiniz bu müze, aynı zamanda ilçenin kültürel mirasını en iyi yansıtan noktalardan biridir.", "place_query": "Devrek Bastonu ve El Sanatları Müzesi, Devrek, Zonguldak"}, {"title": "Devrek Kaya Mezarları", "summary": "Antik dönemden kalma bu etkileyici kaya mezarları, ilçe merkezine yakın bir konumda yer alır ve tarih meraklıları için eşsiz bir keşif sunar.", "place_query": "Devrek Kaya Mezarları, Devrek, Zonguldak"}, {"title": "Gürcüoluk Yaylası", "summary": "Yemyeşil doğası ve temiz havasıyla ünlü bu yayla, doğa yürüyüşleri ve piknik için ideal bir kaçış noktasıdır.", "place_query": "Gürcüoluk Yaylası, Devrek, Zonguldak"}, {"title": "Devrek Merkez Camii", "summary": "Osmanlı dönemi mimarisinin güzel örneklerinden biri olan bu cami, ilçenin tarihi dokusunu yansıtan önemli bir yapıdır.", "place_query": "Devrek Merkez Camii, Devrek, Zonguldak"}, {"title": "Çomaklı Mağarası", "summary": "Devrek sınırları içinde yer alan bu doğal mağara, sarkıt ve dikitleriyle ziyaretçilerine görsel bir şölen sunar.", "place_query": "Çomaklı Mağarası, Devrek, Zonguldak"}, {"title": "Devrek Çarşı ve Tarihi Evler", "summary": "İlçe merkezindeki tarihi ahşap evler ve çarşı, yöresel lezzetleri tatmak ve baston alışverişi yapmak için uğranması gereken bir yerdir.", "place_query": "Devrek Çarşı, Devrek, Zonguldak"}, {"title": "Kızılelma Mağarası", "summary": "Doğa sporları ve mağaracılık meraklıları için popüler bir durak olan bu mağara, etkileyici oluşumlarıyla dikkat çeker.", "place_query": "Kızılelma Mağarası, Devrek, Zonguldak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '737a8e33-4879-4df0-bc1e-7ce4bdb54c10'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cehennemağzı Mağaraları", "summary": "Mitolojiye konu olmuş, Herkül''ün görevlerinden birini gerçekleştirdiğine inanılan bu tarihi mağaralar, eşsiz doğal oluşumları ve serin atmosferiyle ziyaretçileri büyülüyor.", "place_query": "Cehennemağzı Mağaraları, Ereğli, Zonguldak"}, {"title": "Gökgöl Mağarası", "summary": "Zonguldak''ın en ünlü mağaralarından biri olan Gökgöl, sarkıt ve dikitleriyle görsel bir şölen sunarken, içinde yürüyüş yapma imkanı da sağlıyor.", "place_query": "Gökgöl Mağarası, Zonguldak"}, {"title": "Ereğli Müzesi (Arkeoloji ve Etnoğrafya Müzesi)", "summary": "Bölgenin zengin tarihini yansıtan eserlerin sergilendiği müze, antik dönemden Osmanlı''ya uzanan geniş bir koleksiyona ev sahipliği yapıyor.", "place_query": "Ereğli Müzesi, Zonguldak"}, {"title": "Kdz. Ereğli Sahil Bandı ve Plajları", "summary": "Karadeniz''in serin sularında yüzmek veya sahil boyunca yürüyüş yapmak isteyenler için ideal olan bu bölge, şehrin en popüler dinlenme alanlarından biridir.", "place_query": "Ereğli Sahil Bandı, Zonguldak"}, {"title": "Antik Herakleia Pontika (Ereğli Antik Kenti)", "summary": "M.Ö. 6. yüzyıla kadar uzanan tarihiyle antik Herakleia Pontika, sur kalıntıları ve antik tiyatrosuyla tarih meraklıları için eşsiz bir keşif noktasıdır.", "place_query": "Herakleia Pontika Antik Kenti, Ereğli, Zonguldak"}, {"title": "Kestaneci Kalesi", "summary": "Denize hakim bir tepede konumlanan bu tarihi kale, muhteşem manzarası ve Bizans döneminden kalma yapısıyla fotoğrafçıların ve doğa yürüyüşçülerinin uğrak noktasıdır.", "place_query": "Kestaneci Kalesi, Ereğli, Zonguldak"}, {"title": "Filyos Çayı ve Mesire Alanı", "summary": "Şehrin gürültüsünden uzaklaşmak isteyenler için doğayla iç içe bir kaçış noktası olan Filyos Çayı kenarı, piknik ve olta balıkçılığı için idealdir.", "place_query": "Filyos Çayı, Ereğli, Zonguldak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '22e3f5d9-d6f4-4fb0-bc80-3703eae6848c'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gökçebey Atatürk Kültür Parkı", "summary": "İlçe merkezinde yer alan bu park, yeşil alanları ve yürüyüş yollarıyla halkın dinlenme ve piknik yapma noktasıdır. İçerisinde Atatürk büstü ve çocuk oyun alanları bulunur.", "place_query": "Atatürk Kültür Parkı, Gökçebey, Zonguldak"}, {"title": "Gökçebey Çarşı Camii", "summary": "İlçenin tarihi camilerinden biri olup Osmanlı dönemi mimarisini yansıtan sade ve huzurlu bir yapıdır. Merkezi konumuyla ziyaretçilerin ilgisini çeker.", "place_query": "Çarşı Camii, Gökçebey, Zonguldak"}, {"title": "Gökçebey Halk Plajı", "summary": "Filyos Çayı kenarında yer alan bu plaj, yaz aylarında serinlemek ve piknik yapmak için tercih edilen doğal bir alandır. Sakin atmosferiyle aileler için idealdir.", "place_query": "Gökçebey Halk Plajı, Zonguldak"}, {"title": "Gökçebey Kalesi Kalıntıları", "summary": "Tarihi bir kale kalıntısı olan bu alan, bölgenin savunma tarihine ışık tutar. Çevresindeki doğal manzara, fotoğrafçılar için güzel kareler sunar.", "place_query": "Gökçebey Kalesi, Zonguldak"}, {"title": "Filyos Çayı Kenarı", "summary": "İlçeden geçen Filyos Çayı''nın kıyısı, yürüyüş ve balık tutma gibi aktiviteler için popülerdir. Özellikle bahar aylarında doğa yürüyüşçülerinin uğrak noktasıdır.", "place_query": "Filyos Çayı, Gökçebey, Zonguldak"}, {"title": "Gökçebey Mesire Alanı", "summary": "Şehir merkezine yakın bu mesire alanı, mangal ve piknik yapmak isteyenler için düzenlenmiş bir rekreasyon bölgesidir. Çam ağaçları arasında huzurlu bir ortam sağlar.", "place_query": "Gökçebey Mesire Alanı, Zonguldak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = 'a1225f29-7e72-4965-818d-24bf75b0a20d'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Cehennemağzı Mağaraları", "summary": "Tarihi ve mitolojik öneme sahip bu mağaralar, Herkül''ün görevlerinden birine ev sahipliği yapmasıyla bilinir. İçerisinde gezi platformları ve aydınlatma bulunan mağaralar, etkileyici sarkıt ve dikitleriyle ziyaretçileri büyüler.", "place_query": "Cehennemağzı Mağaraları, Kilimli, Zonguldak"}, {"title": "Gökgöl Mağarası", "summary": "Türkiye''nin en uzun mağaralarından biri olan Gökgöl, muhteşem sarkıt, dikit ve sütun oluşumlarıyla ünlüdür. Ziyaretçiler, aydınlatmalı yürüyüş yolu boyunca bu doğal güzelliği keşfedebilir.", "place_query": "Gökgöl Mağarası, Zonguldak"}, {"title": "Kilimli Plajı", "summary": "Zonguldak''ın gözde plajlarından biri olan Kilimli Plajı, özellikle yaz aylarında denize girmek ve güneşlenmek için idealdir. Çevresindeki kafeterya ve tesisler sayesinde keyifli bir gün geçirebilirsiniz.", "place_query": "Kilimli Plajı, Kilimli, Zonguldak"}, {"title": "Filyos Antik Kenti (Tieion)", "summary": "MÖ 7. yüzyıla kadar uzanan tarihiyle Filyos Antik Kenti, Roma, Bizans ve Osmanlı dönemlerine ait kalıntıları barındırır. Antik tiyatro, surlar ve akropolis kalıntıları görülmeye değerdir.", "place_query": "Filyos Antik Kenti Tieion, Filyos, Zonguldak"}, {"title": "Filyos Plajı", "summary": "Uzun ve geniş kumsalıyla bilinen Filyos Plajı, Karadeniz''in serin sularında yüzmek için popüler bir noktadır. Plaj çevresinde yürüyüş yapabilir ve gün batımını izleyebilirsiniz.", "place_query": "Filyos Plajı, Filyos, Zonguldak"}, {"title": "Kilimli Merkez Camii", "summary": "Kilimli''nin merkezinde yer alan bu tarihi cami, Osmanlı dönemi mimarisinin güzel bir örneğidir. Cami, sade ve huzurlu atmosferiyle ziyaretçileri cezbeder.", "place_query": "Kilimli Merkez Camii, Kilimli, Zonguldak"}, {"title": "Zonguldak Maden Müzesi", "summary": "Kilimli''ye yakın konumdaki bu müze, bölgenin kömür madenciliği tarihini ve kültürünü sergiler. Madencilik ekipmanları, fosiller ve interaktif sergilerle ziyaretçilere eşsiz bir deneyim sunar.", "place_query": "Zonguldak Maden Müzesi, Zonguldak"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '2a382045-48f7-4891-9765-4f34807eac59'::uuid;
UPDATE location_pages SET travel_ideas_json = '[{"title": "Gökgöl Mağarası", "summary": "Zonguldak şehir merkezine 5 km uzaklıkta, 875 metre uzunluğuyla Türkiye''nin en büyük mağaralarından biridir. İçindeki sarkıt, dikit ve sütun oluşumları ile doğa harikası bir oluşumdur.", "place_query": "Gökgöl Mağarası, Zonguldak Merkez"}, {"title": "Zonguldak Maden Müzesi", "summary": "Türkiye''nin ilk ve tek maden müzesi olan bu yapı, 19. yüzyıldan kalma tarihi bir binada hizmet vermektedir. Kömür madenciliğinin tarihini ve madencilerin yaşamını anlatan eşsiz bir kültür durağıdır.", "place_query": "Zonguldak Maden Müzesi, Merkez, Zonguldak"}, {"title": "Zonguldak Sahil Bandı ve Plajları", "summary": "Şehir merkezinden başlayan uzun sahil şeridi, yürüyüş ve bisiklet yollarıyla dinlenme alanı sunar. Özellikle Kapuz Plajı ve çevresi yaz aylarında deniz keyfi için popülerdir.", "place_query": "Kapuz Plajı, Zonguldak Merkez"}, {"title": "Karaelmas Kayak Merkezi", "summary": "Zonguldak merkeze yaklaşık 25 km mesafedeki bu kayak merkezi, kış aylarında kayak ve snowboard yapmak isteyenler için idealdir. Doğal güzellikleri ve telesiyej hattıyla dikkat çeker.", "place_query": "Karaelmas Kayak Merkezi, Zonguldak"}, {"title": "İncivez Mağarası", "summary": "Zonguldak merkeze 10 km uzaklıkta bulunan bu mağara, 800 metre uzunluğu ve etkileyici jeolojik yapısıyla keşfedilmeyi bekleyen bir doğa harikasıdır. İçindeki göl ve sarkıtlar büyüleyicidir.", "place_query": "İncivez Mağarası, Zonguldak Merkez"}, {"title": "Zonguldak Atatürk Anıtı ve Kent Müzesi", "summary": "Şehir merkezindeki Atatürk Anıtı çevresinde yer alan Kent Müzesi, Zonguldak''ın tarihini ve kültürel mirasını sergiler. Bölgenin sanayi ve madencilik geçmişine dair zengin koleksiyonlar sunar.", "place_query": "Zonguldak Kent Müzesi, Merkez"}]'::jsonb, service_pois_json = '[]'::jsonb WHERE id = '87e2db7f-c0cd-4617-a183-ede0868241b1'::uuid;

